/*
CITYDEAIL '1','ACC2017_2018.DBO.',2,'##2310'
*/
CREATE PROCEDURE [dbo].[CITYDEAIL]
( 
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    
 @CRITERIA int,
       @TEMPTABLE NVARCHAR(20)
    
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)

SET @SQL =""

IF @CRITERIA =1
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.state_id"
else
SET @JOINSQL=""

BEGIN		
    SET @SQL ="  
                  SELECT City_Pincode,City_Name,City_Pincode,DISTANCE,state_name,STATE_CODE
                  FROM "+@DATABASENAME+"CITY_MASTER PCM
                  left JOIN "+@DATABASENAME+"STATE_MASTER ALM ON ALM.State_Id=PCM.State_Id
                  "+@JOINSQL+"
                 
            
               
                  "
   SET @SQL1 ="  
"


END
EXECUTE (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

