CREATE PROCEDURE [dbo].[INSERTQRCODE] 
(
	@IRN AS NVARCHAR(1500),
	@ACK_NO AS BIGINT,
	@ACK_DATE AS NVARCHAR(50),
	@IMAGE AS IMAGE,
	@BILLNO AS INT,
	@CMP_CODE AS INT,
	@TYPE AS NVARCHAR(20)
	
)
AS 
IF @TYPE = "SALESINVOICE"
BEGIN 
	          UPDATE SALES_INVOICE SET 
             IRN= @IRN ,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE SAL_INV_BILL_NO = @BILLNO AND CMP_CODE = @CMP_CODE
END

IF @TYPE = "JOBSALES"
BEGIN 
	          UPDATE Job_SalesInvoice_Master SET 
             IRN= @IRN ,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE Job_Sal_Inv_Bill_No = @BILLNO AND CMP_CODE = @CMP_CODE
END


IF @TYPE = "SALESRETURN"
BEGIN 
	        UPDATE SALES_RETURN_MASTER SET 
             IRN= @IRN,
             EINVNO=  @ACK_NO  ,
             ACK_DATE= @ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE DocNo =  @BILLNO AND CMP_CODE = @CMP_CODE
END


IF @TYPE = "CREDITNOTE"
BEGIN 
	        UPDATE CreditNoteAcc_Master SET 
             IRN= @IRN,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE Tran_DocNo = @BILLNO  AND CMP_CODE = @CMP_CODE
END



IF @TYPE = "DEBITNOTE"
BEGIN 
	          UPDATE DebitNoteAcc_Master SET 
             IRN= @IRN,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE Tran_DocNo= @BILLNO AND CMP_CODE = @CMP_CODE
END

IF @TYPE = "GRAYSALES"
BEGIN 
	          UPDATE SALES_INVOICE SET 
             IRN= @IRN ,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE SAL_INV_BILL_NO = @BILLNO AND CMP_CODE = @CMP_CODE AND FLAG = 'GSN'
END

IF @TYPE = "MSALES"
BEGIN 
	          UPDATE SALES_INVOICE SET 
             IRN= @IRN ,
             EINVNO=@ACK_NO,
             ACK_DATE=@ACK_DATE,
             SIGNED_QR_CODE= @IMAGE WHERE SAL_INV_BILL_NO = @BILLNO AND CMP_CODE = @CMP_CODE AND FLAG = 'MS'
END









