GO




















CREATE PROCEDURE [dbo].[PRO_CHECKLOGIN]
(
	@username varchar(100),
	@password varchar(100),
	@userId int output 
)
as
begin
	IF Exists(Select *  from UserMaster where dbo.fn_DecryptString(Username) COLLATE Latin1_General_CS_AS = @username and dbo.fn_DecryptString(Password) COLLATE Latin1_General_CS_AS = @password)
	begin
		Select @userId = userid   from UserMaster where dbo.fn_DecryptString(Username) COLLATE Latin1_General_CS_AS = @username
		and dbo.fn_DecryptString(Password) COLLATE Latin1_General_CS_AS = @password
	end 
	else
	begin
		set @userId  = 0
	end

end




















GO

