CREATE PROCEDURE [dbo].[PRO_CREATE_NEW_USER] ( @userId as int, @userName as varchar(50), @Password as varchar(50), @blockDate as smalldatetime, @userCount as int output, @formType as varchar(20), @IsAdmin as int ) As begin if (@userId = 0) begin IF Exists(Select * from UserMaster where upper(dbo.fn_DecryptString(Username)) = upper(@username)) begin set @userCount = 0 end else begin insert into userMaster(Username, Password, blockDate,IsAdmin) values (dbo.fn_EncryptString(@userName),dbo.fn_EncryptString(@Password),@blockDate,@IsAdmin) set @userCount = 1 end end else begin IF Exists(Select * from UserMaster where upper(dbo.fn_DecryptString(Username)) = upper(@username) and userId <> @userId ) begin set @userCount = 0 end else begin if(upper(@formType) = Upper('ChangePassword')) begin update userMaster set Password = dbo.fn_EncryptString(@Password), IsAdmin=@IsAdmin where userId = @userId end else begin update userMaster set blockDate = @blockDate, Username = dbo.fn_EncryptString(@userName), IsAdmin=@IsAdmin where userId = @userId end set @userCount = 1 end end end


























GO

