SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PRO_GET_MENU_DATA]
(
	@menuName  varchar(50),
	@cmp_code  int,
	@userId int,
	@menuData varchar(50) output
)
As

	begin
	
		select @menuData =  CAST(ur.canAdd as varchar) + ',' + CAST(ur.canEdit as varchar) 
		+ ',' + CAST(ur.canDelete as varchar) + ',' + CAST(ur.canSearch as varchar)
		+ ',' + CAST(ur.canReport as varchar) 
		from userRights ur left join menumaster mm on ur.menuId = mm.menuId
		where userId = @userId and mm.menuName = @menuName  and cmp_code = @cmp_code

	end




















GO

