CREATE PROCEDURE [dbo].[PRO_INSERT_COMPANY_MASTER] ( @CMP_CODE AS INT, @CMP_NAME AS NVARCHAR(100), @CMP_TIN_NO AS NVARCHAR(18), @CMP_SERVICETAX_NO AS NVARCHAR(18), @CMP_TDS_NO AS NVARCHAR(18), @CMP_PAN_NO AS NVARCHAR(18), @CMP_ALIAS AS NVARCHAR(50), @CMP_INV_HADING AS NVARCHAR(80), @CMP_ITEM_HADING AS NVARCHAR(80), @CMP_SPECIFICATION AS NVARCHAR(100), @CMP_REGISTRATION_NO AS NVARCHAR(18), @CMP_JURISDICTION AS NVARCHAR(150), @CMP_INTERESTRATE FLOAT, @CMP_CONTACT_PERSON AS NVARCHAR(50), @CMP_ADD1 AS NVARCHAR(100), @CMP_ADD2 AS NVARCHAR(100), @CMP_CITY AS NVARCHAR(30), @CMP_PINCODE AS NVARCHAR(6), @CMP_STATE AS NVARCHAR(30), @CMP_PHONE1 AS NVARCHAR(20), @CMP_PHONE2 AS NVARCHAR(20), @CMP_MOBILE AS NVARCHAR(20), @CMP_FAX AS NVARCHAR(20), @CMP_EMAIL AS NVARCHAR(60), @CMP_WEB AS NVARCHAR(60), @CMP_FC_ADD1 AS NVARCHAR(100), @CMP_FC_ADD2 AS NVARCHAR(100), @CMP_FC_CITY AS NVARCHAR(30), @CMP_FC_PINCODE AS NVARCHAR(6), @CMP_FC_STATE AS NVARCHAR(30), @CMP_BANK_ACCNO1 AS NVARCHAR(200), @CMP_BANK_ACCNO2 AS NVARCHAR(200), @CMP_BANK_ACCNO3 AS NVARCHAR(200), @CMP_ROUND_OFF AS INT, @CMP_STARTYEAR AS SMALLDATETIME, @CMP_ENDYEAR AS SMALLDATETIME, @DATABASENAME AS VARCHAR(50), @FYEAR AS VARCHAR(10), @OLDDATABASENAME AS VARCHAR(50), @IS_DEFAULT AS INT, @BEDIT AS INT , @CMP_TDSAPP AS NVARCHAR(50), @CMP_TDSLMT AS NUMERIC(18,2), @CMP_S_BILL_LMT AS NUMERIC(18,2), @DEDUCTED_TYPE AS NVARCHAR(50), @CINNO AS NVARCHAR(50), @INVOICE_LINE AS INT , @INVOICE_LIMIT AS NUMERIC(18,2), @GSTINNO AS NVARCHAR(15), @CMP_STATECODE AS NVARCHAR(2), @IECNO AS NVARCHAR(20), @BINNO AS NVARCHAR(20), @ARNNO AS NVARCHAR(20) ,@Cmp_TCSApp as NVARCHAR(20)) AS DECLARE @ITEM_ID AS INT DECLARE @SQL AS NVARCHAR(4000) DECLARE @CMP_COUNT AS INT BEGIN IF(@BEDIT = 0) BEGIN SELECT @CMP_COUNT = COUNT(*) FROM ACC_MASTER.DBO.DATABASEINFO IF(@CMP_COUNT = 0) BEGIN INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(1,"Expenses(Indirect/Admn)") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(2,"Income(Direct/Operational)") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(3,"Income(Indirect)") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(4,"Purchase") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(5,"Sales") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(6,"Expenses(Direct/Mfgr.)") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(7,"Current Assets") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(8,"Current Liability") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(9,"Fixed Assets") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(10,"Investment") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(11,"Loans(Liabilities)") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(12,"Profit And Loss") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(13,"Capital") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(14,"Suspense Account") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(15,"Bank") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(16,"Bank o/d Account") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(17,"Cash In Hand") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(18,"Duties And Taxes") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(19,"Loans And Advances") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(20,"Provisions/Expense Payable") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(21,"Reserves And Surplus") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(22,"Secured Loans") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(23,"Security And Deposits") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(24,"Stock In Hand") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(25,"Sundry Creditors") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(26,"Sundry Debtors") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(27,"Unsecured Loans") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(28,"JobSales") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(29,"SalesReturn") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(30,"PurchaseReturn") INSERT INTO ACC_MASTER.DBO.GROUP_MASTER(GRP_ID, GRP_NAME) VALUES(31,"Creditors For Services") SET @SQL = "" SET @SQL = " INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(1,'Expenses(Indirect/Admn)','M','P',1,1,'Expenses(Indirect/Admn)') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(2,'Income(Direct/Operational)','M','T',1,2,'Income(Direct/Operational)') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(3,'Income(Indirect)','M','P',1,3,'Income(Indirect)') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(4,'Purchase','M','T',1,4,'Purchase') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(5,'Sales','M','T',1,5,'Sales') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(6,'Expenses(Direct/Mfgr.)','M','T',1,6,'Expenses(Direct/Mfgr.)') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(7,'Current Assets','M','A',1,7,'Current Assets') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(8,'Current Liability','M','L',1,8,'Current Liability') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(9,'Fixed Assets','M','A',1,9,'Fixed Assets') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(10,'Investment','M','A',1,10,'Investment')" EXECUTE SP_EXECUTESQL @SQL SET @SQL = "" SET @SQL = " INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(11,'Loans(Liabilities)','M','L',1,11,'Loans(Liabilities)') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(12,'Profit And Loss','M','P',1,12,'Profit And Loss') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(13,'Capital','M','L',1,13,'Capital' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(14,'Suspense Account','M','P',1,14,'Suspense Account')" EXECUTE SP_EXECUTESQL @SQL SET @SQL = "" SET @SQL = " INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(15,'Bank','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(16,'Bank o/d Account','S','L',1,11,'Loans(Liabilities)' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(17,'Cash In Hand','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(18,'Duties And Taxes','S','L',1,8,'Current Liability') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(19,'Loans And Advances','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(20,'PROVISIONS/EXPENSE PAYABLE','S','L',1,8,'CURRENT LIABILITY' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(21,'Reserves And Surplus','S','L',1,13,'Capital')" EXECUTE SP_EXECUTESQL @SQL SET @SQL = "" SET @SQL = " INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(22,'Secured Loans','S','L',1,11,'Loans(Liabilities)' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(23,'Security And Deposits','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(24,'Stock In Hand','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(25,'Sundry Creditors','S','L',1,8,'Current Liability' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(26,'Sundry Debtors','S','A',1,7,'Current Assets' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(27,'Unsecured Loans','S','L',1,11,'Loans(Liabilities)' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(28,'JOBSALES','M','T',1,28,'JOBSALES' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(29,'SalesReturn','M','T',1,29,'SalesReturn' ) INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(30,'PurchaseReturn','M','T',1,30,'PurchaseReturn') INSERT INTO GROUP_MASTER(GRP_ID, GRP_NAME, GRP_TYPE, GRP_ACC_TYPE, GRP_DEFAULT, GRP_MAIN_ID, GRP_MAIN_NAME) VALUES(31,'Creditors For Services','S','L',1,8,'Current Liability') " EXECUTE SP_EXECUTESQL @SQL SET @SQL=" INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(1,'KILOGRAMS') INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(2,'DOZEN') INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(3,'METERS') INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(4,'PIECES') INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(5,'LITRE') INSERT INTO ACC_MASTER.DBO.UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(6,'BALES') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(1,'KILOGRAMS') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(2,'DOZEN') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(3,'METERS') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(4,'PIECES') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(5,'LITRE') INSERT INTO UNIT_MASTER(UNIT_ID, UNIT_NAME) VALUES(6,'BALES') " EXECUTE SP_EXECUTESQL @SQL SET @SQL=" INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(1,'SALES INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(2,'PURCHASE INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(3,'CHEMICAL INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(4,'FINISH PURCHASE INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(5,'GRAY SALES INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(6,'YARN SALES INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(7,'YARN FIBER INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(8,'JOB PURCHASE INVOICE') INSERT INTO ACC_MASTER.DBO.INVOICEFORMTABLE(INVOICEFORM_ID,INVOICEFORM) VALUES(9,'MACHINARY PURCHASE INVOICE') " EXECUTE SP_EXECUTESQL @SQL END INSERT INTO ACC_MASTER.DBO.DATABASEINFO(DATABASENAME, CMP_NAME, CMP_CODE, FYEAR,IS_DEFAULT) VALUES (@DATABASENAME,@CMP_NAME,@CMP_CODE,@FYEAR,@IS_DEFAULT) INSERT INTO COMPANY_MASTER(CMP_CODE, CMP_NAME, CMP_TIN_NO, CMP_SERVICETAX_NO, CMP_TDS_NO, CMP_PAN_NO, CMP_ALIAS, CMP_INV_HADING , CMP_ITEM_HADING, CMP_SPECIFICATION, CMP_REGISTRATION_NO, CMP_JURISDICTION, CMP_INTERESTRATE, CMP_CONTACT_PERSON , CMP_ADD1, CMP_ADD2, CMP_CITY, CMP_PINCODE, CMP_STATE, CMP_PHONE1, CMP_PHONE2, CMP_MOBILE, CMP_FAX, CMP_EMAIL, CMP_WEB, CMP_FC_ADD1 , CMP_FC_ADD2, CMP_FC_CITY, CMP_FC_PINCODE, CMP_FC_STATE, CMP_BANK_ACCNO1, CMP_BANK_ACCNO2, CMP_BANK_ACCNO3, CMP_ROUND_OFF, CMP_STARTYEAR, CMP_ENDYEAR,CMP_TDSAPP,CMP_TDSLMT,CMP_S_BILL_LMT,DEDUCTED_TYPE,CINNO,INVOICE_LINE,INVOICE_LIMIT,GSTINNO,CMP_STATECODE,IECNO ,BINNO,ARNNO) VALUES (@CMP_CODE, @CMP_NAME, @CMP_TIN_NO, @CMP_SERVICETAX_NO, @CMP_TDS_NO, @CMP_PAN_NO, @CMP_ALIAS, @CMP_INV_HADING , @CMP_ITEM_HADING, @CMP_SPECIFICATION, @CMP_REGISTRATION_NO, @CMP_JURISDICTION, @CMP_INTERESTRATE, @CMP_CONTACT_PERSON , @CMP_ADD1, @CMP_ADD2, @CMP_CITY, @CMP_PINCODE, @CMP_STATE, @CMP_PHONE1, @CMP_PHONE2, @CMP_MOBILE, @CMP_FAX, @CMP_EMAIL, @CMP_WEB, @CMP_FC_ADD1 , @CMP_FC_ADD2, @CMP_FC_CITY, @CMP_FC_PINCODE, @CMP_FC_STATE, @CMP_BANK_ACCNO1, @CMP_BANK_ACCNO2, @CMP_BANK_ACCNO3, @CMP_ROUND_OFF, @CMP_STARTYEAR, @CMP_ENDYEAR,@CMP_TDSAPP,@CMP_TDSLMT, @CMP_S_BILL_LMT,@DEDUCTED_TYPE,@CINNO,@INVOICE_LINE,@INVOICE_LIMIT,@GSTINNO,@CMP_STATECODE,@IECNO,@BINNO,@ARNNO) IF(@OLDDATABASENAME <> NULL OR @OLDDATABASENAME <> "") BEGIN SET @SQL = "" END DECLARE ITEMCUR CURSOR FAST_FORWARD FOR SELECT ITEM_ID FROM ITEM_MASTER OPEN ITEMCUR FETCH NEXT FROM ITEMCUR INTO @ITEM_ID WHILE @@FETCH_STATUS = 0 BEGIN INSERT INTO ITEM_OPENING_STOCK(ITEM_ID, CMP_CODE, ITEM_OP_STOCK) VALUES(@ITEM_ID,@CMP_CODE, 0) FETCH NEXT FROM ITEMCUR INTO @ITEM_ID END CLOSE ITEMCUR DEALLOCATE ITEMCUR END ELSE BEGIN UPDATE ACC_MASTER.DBO.DATABASEINFO SET CMP_NAME = @CMP_NAME WHERE DATABASENAME = @DATABASENAME AND FYEAR = @FYEAR AND CMP_CODE = @CMP_CODE UPDATE COMPANY_MASTER SET CMP_NAME = @CMP_NAME, CMP_TIN_NO = @CMP_TIN_NO, CMP_SERVICETAX_NO = @CMP_SERVICETAX_NO, CMP_TDS_NO= @CMP_TDS_NO, CMP_PAN_NO = @CMP_PAN_NO, CMP_ALIAS = @CMP_ALIAS, CMP_INV_HADING = @CMP_INV_HADING, CMP_ITEM_HADING = @CMP_ITEM_HADING, CMP_SPECIFICATION = @CMP_SPECIFICATION, CMP_REGISTRATION_NO = @CMP_REGISTRATION_NO, CMP_JURISDICTION = @CMP_JURISDICTION, CMP_INTERESTRATE = @CMP_INTERESTRATE, CMP_CONTACT_PERSON = @CMP_CONTACT_PERSON, CMP_ADD1 = @CMP_ADD1, CMP_ADD2 = @CMP_ADD2, CMP_CITY = @CMP_CITY, CMP_PINCODE = @CMP_PINCODE, CMP_STATE = @CMP_STATE, CMP_PHONE1 = @CMP_PHONE1, CMP_PHONE2 = @CMP_PHONE2, CMP_MOBILE = @CMP_MOBILE, CMP_FAX = @CMP_FAX, CMP_EMAIL = @CMP_EMAIL, CMP_WEB = @CMP_WEB, CMP_FC_ADD1 = @CMP_FC_ADD1, CMP_FC_ADD2 = @CMP_FC_ADD2, CMP_FC_CITY = @CMP_FC_CITY, CMP_FC_PINCODE = @CMP_FC_PINCODE, CMP_FC_STATE = @CMP_FC_STATE, CMP_BANK_ACCNO1 = @CMP_BANK_ACCNO1, CMP_BANK_ACCNO2 = @CMP_BANK_ACCNO2, CMP_BANK_ACCNO3 = @CMP_BANK_ACCNO3, CMP_ROUND_OFF = @CMP_ROUND_OFF ,CMP_TDSAPP=@CMP_TDSAPP,CMP_TDSLMT=@CMP_TDSLMT,CMP_S_BILL_LMT=@CMP_S_BILL_LMT,DEDUCTED_TYPE=@DEDUCTED_TYPE ,CINNO=@CINNO ,INVOICE_LINE=@INVOICE_LINE ,INVOICE_LIMIT=@INVOICE_LIMIT,GSTINNO=@GSTINNO, CMP_STATECODE = @CMP_STATECODE,IECNO = @IECNO ,BINNO=@BINNO,ARNNO = @ARNNO,Cmp_TCSApp=@Cmp_TCSApp WHERE CMP_CODE = @CMP_CODE END END






