/*
PROC_ACC_CONFNOTE '1', 'ACC2018_2019.DBO.','01/APR/2018','20/OCT/2019','##2928','01/APR/2018'
*/
CREATE PROCEDURE [dbo].[PROC_ACC_CONFNOTE] 
(
@CMP_CODE AS  NVARCHAR(50),
@DATABASENAME AS NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@STARTDATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)

DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL =""
SET @SQL1 =""
SET @SQL2 =""
SET @SQL5 =""

SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"


BEGIN

SET @SQL="SELECT DETAIL.ORD,DETAIL.VCODE, DETAIL.DOCNO,CHEQUEINT,DETAIL.PARTYNAME,DETAIL.PARTYID,
DETAIL.LGR_ADD1,DETAIL.LGR_ADD2,DETAIL.LGR_ADD3,DETAIL.CITY_NAME,DETAIL.STATE_NAME,
DETAIL.VOUCHER_DATE AS DATE, DETAIL.DRAMOUNT,DETAIL.CRAMOUNT, DETAIL.TYPE, DETAIL.ACCOUNTNAME,
DETAIL.ACC_ID,REMARK,DETAIL.LGR_PANO,CONVERT(NVARCHAR,DDDATE,103) AS DDDATE FROM(
 
SELECT 2 AS ORD,
(CASE WHEN TM.TRAN_TYPE IN ('S','GS','P','FP','JP','CHP','YP') THEN  TM.TRAN_DOCNO ELSE TD.CHEQUENO END) AS DOCNO,
CONVERT(NVARCHAR,CASE WHEN TM.TRAN_TYPE IN ('S') THEN TM.TRAN_DOCNO ELSE 0 END) AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,PCM.CITY_NAME,SM.STATE_NAME,
TM.TRAN_MASTER_ID AS PARTYID,  TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT, 
TM.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,
(CASE WHEN ISNULL(TD.NARRATION,'')='' THEN TM.NARRATION ELSE (TD.NARRATION) END) AS REMARK,
LM.LGR_PANO,TD.DDDATE
FROM "+@DATABASENAME +"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME +"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE  
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID  
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
LEFT JOIN "+@DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
"+@JOINSQL+" 
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN ('J','VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP','FPR')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'

UNION ALL 
SELECT 2 AS ORD,
(CASE WHEN TM.TRAN_TYPE IN ('S','GS','P','FP','JP','CHP','YP') THEN  TM.TRAN_DOCNO ELSE TD.CHEQUENO END) AS DOCNO,
CONVERT(NVARCHAR,CASE WHEN TM.TRAN_TYPE IN ('S') THEN TM.TRAN_DOCNO ELSE 0 END) AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,PCM.CITY_NAME,SM.STATE_NAME,
TD.TRAN_DETAIL_ID AS PARTYID,TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE, 
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT, 
TD.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,
(CASE WHEN ISNULL(TD.NARRATION,'')='' THEN TM.NARRATION ELSE (TD.NARRATION) END) AS REMARK,
LM.LGR_PANO,TD.DDDATE 
FROM "+@DATABASENAME +"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME +"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID  
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
LEFT JOIN "+@DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
"+@JOINSQL+" 
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN ('J','VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP','FPR')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'
UNION ALL  "

SET @SQL1="    SELECT 2 AS ORD,'' AS DOCNO,'' AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,PCM.CITY_NAME,SM.STATE_NAME,
LM.LGR_ID AS PARTYID,AJ.ENTRYCODE AS VCODE,AJ.VDATE AS VOUCHER_DATE,AJ.DRAMOUNT AS DRAMOUNT,
AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE,
LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,'' AS REMARK ,LM.LGR_PANO,AJ.VDATE AS DDDATE
FROM "+@DATABASENAME +"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME +"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH= AJ.ENTRYMATCH  
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID  
LEFT JOIN "+@DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
"+@JOINSQL+" 
WHERE AJ.VDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'AND AJ.CMP_CODE="+@CMP_CODE+"  
UNION ALL  
SELECT 2 AS ORD,
(CASE WHEN TM.TRAN_TYPE IN ('S','GS','P','FP','JP','CHP','YP') THEN  TM.TRAN_DOCNO ELSE TD.CHEQUENO END) AS DOCNO,
CONVERT(NVARCHAR,CASE WHEN TM.TRAN_TYPE IN ('S') THEN TM.TRAN_DOCNO ELSE 0 END) AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,PCM.CITY_NAME,SM.STATE_NAME,
TD.TRAN_DETAIL_ID AS PARTYID,TD.TRAN_ID,TM.TRAN_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, 
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TYPE, LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,(CASE WHEN ISNULL(TD.NARRATION,'')='' THEN TM.NARRATION ELSE ( TD.NARRATION) END) AS REMARK ,LM.LGR_PANO,TD.DDDATE
FROM "+@DATABASENAME +"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME +"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME +"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR 
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID 
LEFT JOIN "+@DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
"+@JOINSQL+" 
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
 AND TM.TRAN_TYPE  IN ('J','DN','CN')
UNION ALL "
SET @SQL2="  
SELECT 1 AS ORD,'' AS DOCNO,'' AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,PCM.CITY_NAME AS PATRYCITY,SM.STATE_NAME,
LM.LGR_ID AS PARTYID,0 AS TRAN_ID ,'"+@STARTDATE+"' AS TRAN_DATE,
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT,
'OP' AS TYPE,'' AS ACCOUNTNAME,0 AS ACC_ID,'OPNG BAL' AS REMARK  ,LM.LGR_PANO,'' AS DDDATE
FROM "+@DATABASENAME+"LEDGER_MASTER LM 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
"+@JOINSQL+" 
WHERE LD.CMP_CODE="+@CMP_CODE +""
SELECT @SQL5=" UNION ALL
SELECT  DISTINCT 1 AS ORD, TM.TRAN_DOCNO AS DOCNO,
CONVERT(NVARCHAR,CASE WHEN TM.TRAN_TYPE IN ('BR','CR','BP','CP') THEN TD.CHEQUENO ELSE TM.TRAN_DOCNO END) AS CHEQUEINT,
LM1.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,ACM.CITY_NAME AS PARTYCITY,SM.STATE_NAME,LM1.LGR_ID AS PARTYID,TD.TRAN_ID,TM.TRAN_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE, LM.LGR_NAME AS ACCOUNTNAME,LM.LGR_ID AS ACC_ID,
(CASE WHEN ISNULL(TD.NARRATION,'')='' THEN TM.NARRATION ELSE ( TD.NARRATION) END) AS REMARK,LM.LGR_PANO,TD.DDDATE AS DDDATE

FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE AND TM.EFFECT_CODE=TD.TRAN_DETAIL_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID   
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID  
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID 
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID

WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE IN ('VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP','FPR') 
and TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
UNION ALL 
SELECT 1 AS ORD, TM.Tran_DocNo as DocNo,
CONVERT(NVARCHAR,CASE WHEN TM.TRAN_TYPE IN ('S','GS','P','FP','JP','CHP','MIP','YP','CS','CRS','SPJ','EPJ','SR','GSR','CA','CO','T','GSN','MS') THEN TM.TRAN_DOCNO  ELSE TD.CHEQUENO END) As ChequeInt,LM.Lgr_Name as PartyName,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,ACM.CITY_NAME AS PARTYCITY,SM.STATE_NAME,TD.Tran_DETAIL_ID as PartyId,
TM.TRan_ID,TM.Tran_Date,(CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT ,
(CASE WHEN TD.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT,TD.Tran_Type as TYPE,LM1.Lgr_Name as AccountName,LM.Lgr_ID as ACC_ID,
TD.NARRATION as Remark,LM.LGR_PANO,TD.DDDATE
From "+@DATABASENAME+"Tran_Master TM 
Inner Join "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_Id = TD.Tran_Id And TM.Cmp_Code= TD.Cmp_Code AND TM.Tran_Type = TD.Tran_Type 
INNER JOIN "+ @TEMPTABLE + " TT on TT.Code=TD.Tran_DETAIL_Id
INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.TRan_DETAIL_Id = LM.Lgr_Id   
INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON   TM.Tran_MASTER_ID= LM1.Lgr_Id

LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_ID=PCM.City_Id
LEFT JOIN "+@DATABASENAME+"City_Master ACM ON LM1.City_ID=ACM.City_Id
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
Where TM.Cmp_Code = "+@CMP_CODE+" And TM.Tran_Type IN ('VAT','PV','VPR','VSR','S','GS','P','FP','JP','CHP','MIP','YP','CS','CRS','SPJ','EPJ','SR','CPR','GSR','CA','CO','T','GSN','JS','SNJ','RP','PR','MS','FPR') 
And TM.TRan_Date Between '"+@FROMDATE+"' And '"+@TODATE+"'


) AS DETAIL WHERE DRAMOUNT<>0 OR CRAMOUNT<>0 ORDER BY ORD,VOUCHER_DATE,TYPE,VCODE
"



END
EXEC (@SQL+@SQL1+@SQL2+@SQL5)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL5



















GO

/****** Object:  StoredProcedure [dbo].[PROC_ACCLGR_DATE_MONTH]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
SELECT * FROM ##1972
PROC_ACCLGR_DATE_MONTH N'1', N'ACC2016_2017.DBO.', N'01/APR/2016', N'31/MAR/2017', N'','###2216', 2,1
*/
CREATE PROCEDURE [dbo].[PROC_ACCLGR_DATE_MONTH]
(
@CMP_CODE AS NVARCHAR(50),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@PARTYID AS NVARCHAR(10),
@TEMPTABLE AS NVARCHAR(30),
@RPT_TYPE AS INT,
@CRITERIA AS INT
)	
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)


DECLARE @SELSQL AS NVARCHAR(2000)
DECLARE @GRPSQL AS NVARCHAR(1000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)
DECLARE @JOINSQL  AS NVARCHAR(4000)
DECLARE @MAINFIELDSQL AS NVARCHAR(4000)
DECLARE @STRTEMTABLE AS NVARCHAR(4000)
DECLARE @DATE_MONTH AS NVARCHAR(2000)
DECLARE @GRPBY_NAME AS NVARCHAR(2000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SELSQL=""
SET @GRPSQL =""
SET @FIELDSQL=""
SET @ORDERBYSQL=""
SET @JOINSQL=""
SET @MAINFIELDSQL =""
SET @STRTEMTABLE=""
SET @DATE_MONTH=""
SET @SQL7=""
SET @SQL6=""
SET @GRPBY_NAME=""
SET @SQL8 =""
SET @SQL9 =""


BEGIN
IF @RPT_TYPE=1 
BEGIN
SET @SELSQL=" CONVERT(NVARCHAR,DETAIL1.DATE,103) AS DATE"
SET @GRPSQL ="GROUP BY DETAIL1.DATE,PARTY,PARTYID,PARTYCITY,MONTHORDER"
SET @DATE_MONTH="DATE"
END
ELSE IF @RPT_TYPE=2
BEGIN
SET @SELSQL=" UPPER(DATENAME(MONTH,DETAIL1.DATE))  AS DATE"
SET @GRPSQL =" GROUP BY DATENAME(MONTH,DETAIL1.DATE),PARTYID,PARTY,PARTYCITY,MONTHORDER "
SET @DATE_MONTH="MONTHORDER"
END

END 

IF @CRITERIA=1    /* ALL GROUPS */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LDS ON LM.LGR_ID=LDS.LGR_ID  AND LDS.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LDS.GRP_ID=MGM.GRP_ID"	
SET @FIELDSQL="	,MGM.GRP_NAME AS MAINGRP,MGM.GRP_ID AS MAIN_GRPID"
SET @ORDERBYSQL = "MAINGRP,MAIN_GRPID,PARTY,PARTYID"
SET @MAINFIELDSQL=",MAINGRP,MAIN_GRPID"
SET @STRTEMTABLE="INNER JOIN "+@TEMPTABLE+" TT ON CONVERT(NVARCHAR,TT.CODE) COLLATE SQL_LATIN1_GENERAL_CP1_CI_AS=MGM.GRP_ID"
SET @GRPBY_NAME=",MGM.GRP_NAME,MGM.GRP_ID"
END
IF @CRITERIA=0     /*  ALL ACCOUNTS */
BEGIN
SET @JOINSQL="" 
SET @FIELDSQL=",CONVERT(NVARCHAR(150),'') AS MAINGRP,0 AS MAIN_GRPID"
SET @ORDERBYSQL = "PARTY,PARTYID"
SET @MAINFIELDSQL=",MAINGRP,MAIN_GRPID"
SET @STRTEMTABLE="INNER JOIN "+@TEMPTABLE+" TT ON CONVERT(NVARCHAR,TT.CODE) COLLATE SQL_LATIN1_GENERAL_CP1_CI_AS=LM.LGR_ID"
SET @GRPBY_NAME=",LM.LGR_NAME,PARTYID"
END


BEGIN

SET @SQL="SELECT 'OPBAL' AS DATE,SUM(DEBITAMOUNT)AS DRAMOUNT,SUM(CREDITAMOUNT) AS CRAMOUNT ,PARTY,
PARTYCITY,0 AS MONTHORDER,PARTYID,0 AS FINAL_PUR_INNER,0 AS FINAL_PUR_OUTER, 0 AS FINAL_PUR_NULL
"+@MAINFIELDSQL+",0 AS ODR
FROM ( 
SELECT CASE WHEN TM.TRAN_DRCR = 'D' THEN TM.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT,
CASE WHEN TM.TRAN_DRCR = 'C' THEN TM.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT ,LM.LGR_NAME AS PARTY,
PCM.CITY_NAME AS PARTYCITY, LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE TM.TRAN_DATE <'"+@FROMDATE +"' AND TM.CMP_CODE IN ("+@CMP_CODE+") /*AND TM.TRAN_MASTER_ID ="+@PARTYID+"*/ AND TM.TRAN_TYPE <> 'J'
UNION ALL
SELECT CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT,
CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT ,LM.LGR_NAME AS PARTY,
PCM.CITY_NAME AS PARTYCITY, LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TD.TRAN_ID = TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE   AND TD.CMP_CODE = TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE  TM.TRAN_DATE < '"+@FROMDATE +"'  AND TD.CMP_CODE IN ("+@CMP_CODE+") /*AND TD.TRAN_DETAIL_ID ="+@PARTYID+"*/
UNION ALL
SELECT CASE WHEN AJ.DRAMOUNT IS NOT NULL THEN AJ.DRAMOUNT ELSE 0 END AS DEBITAMOUNT,
CASE WHEN AJ.CRAMOUNT IS NOT NULL THEN AJ.CRAMOUNT ELSE 0 END AS CREDITAMOUNT ,LM.LGR_NAME AS PARTY,
PCM.CITY_NAME AS PARTYCITY, LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AJ.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE AJ.VDATE <'"+@FROMDATE +"'  AND AJ.CMP_CODE IN ("+@CMP_CODE +")  /*AND AJ.LGR_ID ="+@PARTYID+" */
UNION ALL 
SELECT CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DEBITAMOUNT,
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CREDITAMOUNT 
,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY, LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"LEDGER_DETAIL LD 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE LD.CMP_CODE IN ("+@CMP_CODE +") /*AND LD.LGR_ID = "+@PARTYID+"*/
) AS DETAIL  GROUP BY PARTY,PARTYID,PARTYCITY"+@MAINFIELDSQL+"
having SUM(DEBITAMOUNT)<>0  or SUM(CREDITAMOUNT)<>0

UNION ALL 
"    

SET @SQL1="  SELECT "+@SELSQL+", SUM(DETAIL1.DRAMOUNT) AS DRAMOUNT,SUM(DETAIL1.CRAMOUNT) AS CRAMOUNT,PARTY,PARTYCITY,MONTHORDER,PARTYID,
0 AS FINAL_PUR_INNER,0 AS FINAL_PUR_OUTER, 0 AS FINAL_PUR_NULL"+@MAINFIELDSQL+",0 AS ODR
FROM (
SELECT  TM.TRAN_DATE AS DATE,(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM.LGR_NAME AS PARTY ,PCM.CITY_NAME AS PARTYCITY        
,CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12) ELSE DATEPART(M,TM.TRAN_DATE)  END AS MONTHORDER
,LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 
/*INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID */ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_TYPE <> 'J' /*AND TM.TRAN_MASTER_ID ="+@PARTYID+"*/ AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' 
UNION ALL   "
SET @SQL2="
SELECT TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
,CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12) ELSE DATEPART(M,TM.TRAN_DATE)  END AS MONTHORDER
,LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID 

INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_TYPE<> 'J'  /*AND TD.TRAN_DETAIL_ID="+@PARTYID+"*/ AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
UNION ALL   "
SET @SQL3=" 
SELECT AJ.VDATE AS VOUCHER_DATE,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
,CASE WHEN DATEPART(M,AJ.VDATE )<=3 THEN (DATEPART(M,AJ.VDATE )+12) ELSE DATEPART(M,AJ.VDATE )  END AS MONTHORDER
,LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"AUTOJOURNAL AJ
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH= AJ.ENTRYMATCH 
/*INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID */
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE AJ.VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'AND AJ.CMP_CODE IN ("+@CMP_CODE +") /*AND LM.LGR_ID="+@PARTYID+"*/
UNION ALL  "
SET @SQL4=" 
SELECT TM.TRAN_DATE,(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, 
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT
,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
,CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12) ELSE DATEPART(M,TM.TRAN_DATE)  END AS MONTHORDER,
LM.LGR_ID AS PARTYID"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
/*INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID*/
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"' /*AND TD.TRAN_DETAIL_ID="+@PARTYID+"*/ AND TM.TRAN_TYPE  IN ('J','DN','CN') 
) AS DETAIL1 "+@GRPSQL +""+@MAINFIELDSQL+"
/*ORDER BY "+@ORDERBYSQL+",MONTHORDER,DATE/*"+@DATE_MONTH+"*/*/
"
SET @SQL6="
UNION ALL

SELECT '' AS DATE,0 AS DRAMOUNT,0 AS CRAMOUNT,PARTY,PARTYCITY,MONTHORDER,PURACCID AS PARTYID,
(SUM(PURINNER)-SUM(PUR_RTN_INNER))FINAL_PUR_INNER,(SUM(PUROUTER)-SUM(PUR_RTN_OUTER))FINAL_PUR_OUTER, 
(SUM(PUR_NULL)-SUM(PUR_RTN_NULL))FINAL_PUR_NULL,MAINGRP,MAIN_GRPID,1 AS ODR
FROM (

SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTYCITY,100 AS MONTHORDER,PURACCID,
(CASE WHEN  PLM.JOB_TYPE='INNER' THEN SUM(NETTOTAL)ELSE 0 END) AS PURINNER,
(CASE WHEN  PLM.JOB_TYPE='OUTER' THEN SUM(NETTOTAL)ELSE 0 END) AS PUROUTER,
(CASE WHEN  ISNULL(PLM.JOB_TYPE,'')='' THEN SUM(NETTOTAL)ELSE 0 END) AS PUR_NULL,
0 AS PUR_RTN_INNER, 0 AS PUR_RTN_OUTER,0 AS PUR_RTN_NULL"+@FIELDSQL+"
FROM  "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PLM ON PLM.LGR_ID=PI.LGR_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.PURACCID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.Lgr_Id=LM.Lgr_Id  AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE PI.CMP_CODE IN ("+@CMP_CODE +")   AND 
PI.VCHDATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"'
GROUP BY VCHDATE,LM.LGR_NAME,CM.CITY_NAME,PURACCID,PLM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID

UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,100 AS MONTHORDER,LM.LGR_ID, 
(CASE WHEN  LM.JOB_TYPE='INNER' THEN SUM(TD.TRAN_AMOUNT)ELSE 0 END) AS PURINNER,
(CASE WHEN  LM.JOB_TYPE='OUTER' THEN SUM(TD.TRAN_AMOUNT)ELSE 0 END) AS PUROUTER,
(CASE WHEN  ISNULL(LM.JOB_TYPE,'')='' THEN SUM(TD.TRAN_AMOUNT)ELSE 0 END) AS PUR_NULL,
0 AS PUR_RTN_INNER, 0 AS PUR_RTN_OUTER,0 AS PUR_RTN_NULL"+@FIELDSQL+"
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
/*INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR*/
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
LEFT JOIN   "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LDS ON LM.LGR_ID=LDS.LGR_ID  AND LDS.CMP_CODE IN ("+@CMP_CODE +")
INNER JOIN  "+@DATABASENAME+"GROUP_MASTER MGM ON LDS.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"' /*AND TD.TRAN_DETAIL_ID=0*/ 
AND TM.TRAN_TYPE  IN ('J','DN','CN') AND TD.TRAN_DRCR='D' AND MGM.grp_Main_Name='PURCHASE'
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,LM.LGR_ID,LM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID
"
set @SQL7=" UNION ALL
SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTYCITY,100 AS MONTHORDER,PUR_ACC_ID,
0 AS PURINNER,0 AS PUROUTER,0 AS PUR_NULL,
(CASE WHEN  PLM.JOB_TYPE='INNER' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_INNER,
(CASE WHEN  PLM.JOB_TYPE='OUTER' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_OUTER,
(CASE WHEN  ISNULL(PLM.JOB_TYPE,'')='' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_NULL"+@FIELDSQL+"
FROM  "+@DATABASENAME+"PURCHASE_RETURN_MASTER PRM
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PLM ON PLM.LGR_ID=PRM.LGR_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PRM.PUR_ACC_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.Lgr_Id=LM.Lgr_Id  AND LD.CMP_CODE=PRM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE PRM.CMP_CODE IN ("+@CMP_CODE +") AND
PRM.Pur_Ret_Date BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"'
GROUP BY PUR_RET_DATE,LM.LGR_NAME,CM.CITY_NAME,PUR_ACC_ID,PLM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID


UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,100 AS MONTHORDER,LM.LGR_ID, 
0 AS PURINNER,0 AS PUROUTER,0 AS PUR_NULL,
(CASE WHEN  LM.JOB_TYPE='INNER' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_INNER,
(CASE WHEN  LM.JOB_TYPE='OUTER' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_OUTER,
(CASE WHEN  ISNULL(LM.JOB_TYPE,'')='' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_NULL"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
/*INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR*/
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LDS ON LM.LGR_ID=LDS.LGR_ID  AND LDS.CMP_CODE IN ("+@CMP_CODE +")
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LDS.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"' /*AND TD.TRAN_DETAIL_ID=0*/ 
AND TM.TRAN_TYPE  IN ('J','DN','CN') AND TD.TRAN_DRCR='C' AND MGM.grp_Main_Name IN ('PURCHASE','PURCHASERETURN')
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,LM.LGR_ID,LM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID

) AS DETAIL
GROUP BY PURACCID,PARTY,PARTYCITY,MONTHORDER,MAINGRP,MAIN_GRPID
"

SET @SQL8="
UNION ALL
SELECT '' AS DATE,0 AS DRAMOUNT,0 AS CRAMOUNT,PARTY,PARTYCITY,100 AS MONTHORDER,SAL_ACC_ID AS PARTYID,(SUM(PURINNER)-SUM(PUR_RTN_INNER))FINAL_PUR_INNER,(SUM(PUROUTER)-SUM(PUR_RTN_OUTER))FINAL_PUR_OUTER,
(SUM(PUR_NULL)-SUM(PUR_RTN_NULL))FINAL_PUR_NULL,
MAINGRP,MAIN_GRPID,2 AS ODR

FROM (

SELECT LM.LGR_NAME AS PARTY,CM.City_Name AS PARTYCITY,SAL_ACCID AS SAL_ACC_ID,
(CASE WHEN  PLM.JOB_TYPE='INNER' THEN SUM(SAL_INV_NETTOTAL)ELSE 0 END) AS PURINNER,
(CASE WHEN  PLM.JOB_TYPE='OUTER' THEN SUM(SAL_INV_NETTOTAL)ELSE 0 END) AS PUROUTER,
(CASE WHEN  ISNULL(PLM.JOB_TYPE,'')='' THEN SUM(SAL_INV_NETTOTAL)ELSE 0 END) AS PUR_NULL,
0 AS PUR_RTN_INNER, 0 AS PUR_RTN_OUTER,0 AS PUR_RTN_NULL"+@FIELDSQL+"
FROM "+@DATABASENAME+"SALES_INVOICE PI
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PLM ON PLM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.SAL_ACCID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.City_Id=LM.City_Id
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.Lgr_Id=LM.Lgr_Id  AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE PI.cmp_code IN ("+@CMP_CODE +") AND PI.Sal_Inv_Vdate  BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"'
GROUP BY LM.LGR_NAME,SAL_ACCID,PLM.JOB_TYPE,CM.City_Name,MGM.GRP_NAME,MGM.GRP_ID

UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.LGR_ID, 
(CASE WHEN  LM.JOB_TYPE='INNER' THEN SUM(TD.Tran_Amount)ELSE 0 END) AS PURINNER,
(CASE WHEN  LM.JOB_TYPE='OUTER' THEN SUM(TD.Tran_Amount)ELSE 0 END) AS PUROUTER,
(CASE WHEN  ISNULL(LM.JOB_TYPE,'')='' THEN SUM(TD.Tran_Amount)ELSE 0 END) AS PUR_NULL,

0 AS PUR_RTN_INNER, 0 AS PUR_RTN_OUTER,0 AS PUR_RTN_NULL"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
/*INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR*/
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LDS ON LM.LGR_ID=LDS.LGR_ID  AND LDS.CMP_CODE IN  ("+@CMP_CODE +")
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LDS.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN  ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"' /*AND TD.TRAN_DETAIL_ID=0*/ 
AND TM.TRAN_TYPE  IN ('J','DN','CN') AND TD.TRAN_DRCR='C'  AND MGM.grp_Main_Name IN ('JOBSALES','SALES')
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,LM.LGR_ID,LM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID

"
SET @SQL9="UNION ALL
SELECT LM.LGR_NAME AS PARTY,CM.City_Name AS PARTYCITY,SAL_ACC_ID,
0 AS PURINNER,0 AS PUROUTER,0 AS PUR_NULL,
(CASE WHEN  PLM.JOB_TYPE='INNER' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_INNER,
(CASE WHEN  PLM.JOB_TYPE='OUTER' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_OUTER,
(CASE WHEN  ISNULL(PLM.JOB_TYPE,'')='' THEN SUM(ROUNDEDAMOUNT) ELSE 0 END) AS PUR_RTN_NULL"+@FIELDSQL+"
FROM  "+@DATABASENAME+"SALES_RETURN_MASTER PRM
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PLM ON PLM.LGR_ID=PRM.LGR_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PRM.SAL_ACC_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.City_Id=LM.City_Id
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.Lgr_Id=LM.Lgr_Id  AND LD.CMP_CODE=PRM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE PRM.cmp_code IN ("+@CMP_CODE +") AND PRM.Sal_Ret_Date  BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"'
GROUP BY LM.LGR_NAME,SAL_ACC_ID,PLM.JOB_TYPE,CM.City_Name,MGM.GRP_NAME,MGM.GRP_ID

UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.LGR_ID, 
0 AS PURINNER,0 AS PUROUTER,0 AS PUR_NULL,

(CASE WHEN  LM.JOB_TYPE='INNER' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_INNER,
(CASE WHEN  LM.JOB_TYPE='OUTER' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_OUTER,
(CASE WHEN  ISNULL(LM.JOB_TYPE,'')='' THEN SUM(TD.TRAN_AMOUNT) ELSE 0 END) AS PUR_RTN_NULL"+@FIELDSQL+"
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
/*INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR*/
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LDS ON LM.LGR_ID=LDS.LGR_ID  AND LDS.CMP_CODE IN  ("+@CMP_CODE +")
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LDS.GRP_ID=MGM.GRP_ID
"+@STRTEMTABLE+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"' /*AND TD.TRAN_DETAIL_ID=0*/ 
AND TM.TRAN_TYPE  IN ('J','DN','CN') AND TD.TRAN_DRCR='D'   AND MGM.GRP_MAIN_NAME IN ('JOBSALES','SALES','SALESRETURN')
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,LM.LGR_ID,LM.JOB_TYPE,MGM.GRP_NAME,MGM.GRP_ID
) AS DETAIL
GROUP BY PARTY,SAL_ACC_ID,PARTYCITY,MAINGRP,MAIN_GRPID


ORDER BY "+@ORDERBYSQL+",MONTHORDER,DATE/*"+@DATE_MONTH+"*/
"
END

EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL6+@SQL7+@SQL8+@SQL9)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL6
PRINT @SQL7
PRINT @SQL8
PRINT @SQL9





















