/****** Object:  StoredProcedure [dbo].[PROC_ADVANCE_CHEQUE]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
   PROC_ADVANCE_CHEQUE 2,'ACC2010_2011.DBO.'
*/
CREATE PROCEDURE [dbo].[PROC_ADVANCE_CHEQUE]
(
     @CMP_CODE NVARCHAR(100),
     @DATABASENAME NVARCHAR(100),
     @TEMPTABLE NVARCHAR(50),
     @RPT_WISE INT,
     @RECEIPT_PAY INT
    
)	
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(4000)
BEGIN


IF @RPT_WISE=1 
    SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+ " TT ON TT.CODE=ACR.BANK_ID "
IF @RPT_WISE=1 
    SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+ " TT ON TT.CODE=ACR.LGR_ID "

IF @RECEIPT_PAY =1 
BEGIN
SET @SQL="
   	    	SELECT DOCNO,VCHDATE,CHEQUENO,CHEQUEDATE ,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,BLM.LGR_NAME AS BANK,BCM.CITY_NAME AS BANKCITY
            ,ACR.AMOUNT
    	    FROM "+@DATABASENAME+"ADVANCE_CHEQUE_RECEIPT ACR
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=ACR.LGR_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON BLM.LGR_ID=ACR.BANK_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER BCM ON BCM.CITY_ID=BLM.CITY_ID
            WHERE ACR.INUSED=0 AND ACR.CMP_CODE IN ("+@CMP_CODE +")
            ORDER BY VCHDATE,DOCNO
         "
END

IF @RECEIPT_PAY =2 
BEGIN
SET @SQL="
   	    	SELECT DOCNO,VCHDATE,CHEQUENO,CHEQUEDATE ,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,BLM.LGR_NAME AS BANK,BCM.CITY_NAME AS BANKCITY
            ,ACR.AMOUNT
    	    FROM "+@DATABASENAME+"ADVANCE_CHEQUE_PAYMENT ACR
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=ACR.LGR_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON BLM.LGR_ID=ACR.BANK_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER BCM ON BCM.CITY_ID=BLM.CITY_ID
            WHERE ACR.INUSED=0 AND ACR.CMP_CODE IN ("+@CMP_CODE +")
            ORDER BY VCHDATE,DOCNO
         "
END
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_AGENT_PARTYSALES]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_AGENT_PARTYSALES '2','ACC2010_2011.DBO.','01/APR/2010','27/JAN/2011','##2310'
*/
CREATE PROCEDURE [dbo].[PROC_AGENT_PARTYSALES]
( 
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20)
    
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
SET @SQL =""
SET @JOINSQL=""
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"

BEGIN		
    SET @SQL ="   SELECT AGENT,AGENTCITY,PARTY,PARTYCITY,SUM(SNTETOTAL) AS SNTETOTAL,SUM(EXSNTETOTAL) AS EXSNTETOTAL,SUM(SR_CREDIT_TOTAL)AS SR_CREDIT_TOTAL,CMP_ALIAS 
                  FROM(
                  SELECT ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,SUM(SAL_INV_NETTOTAL) AS SNTETOTAL,0 AS EXSNTETOTAL,0 AS SR_CREDIT_TOTAL
                  ,CMP.CMP_ALIAS
                  FROM "+@DATABASENAME+"SALES_INVOICE SI
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                  LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE                
                  "+@JOINSQL+"
                  WHERE NET_SNET='S.NET' AND SI.CMP_CODE IN("+@CMP_CODE+") AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"'
                  GROUP BY LM.LGR_NAME ,PCM.CITY_NAME ,ALM.LGR_NAME ,ACM.CITY_NAME,CMP.CMP_ALIAS 
               UNION ALL
                  SELECT ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS SNTETOTAL,SUM(SAL_INV_NETTOTAL) AS EXSNTETOTAL,0 AS SR_CREDIT_TOTAL
                  ,CMP.CMP_ALIAS
                  FROM "+@DATABASENAME+"SALES_INVOICE SI
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                  LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE                
                  "+@JOINSQL+"
                  WHERE (NET_SNET<>'S.NET' OR NET_SNET IS NULL) AND SI.CMP_CODE IN("+@CMP_CODE+") AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"'
                  GROUP BY LM.LGR_NAME ,PCM.CITY_NAME ,ALM.LGR_NAME ,ACM.CITY_NAME ,CMP.CMP_ALIAS
                  "
   SET @SQL1 ="  UNION ALL
                 SELECT ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS SNTETOTAL,0 AS EXSNTETOTAL,SUM(TD.TRAN_AMOUNT) AS SR_CREDIT_TOTAL
                 ,CMP.CMP_ALIAS
                 FROM "+@DATABASENAME+"TRAN_MASTER TM
                 INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TD.TRAN_TYPE=TM.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
				 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
				 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
				 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE                
                 "+@JOINSQL+"
				 WHERE TM.TRAN_TYPE='CN' AND TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"'
				 GROUP BY LM.LGR_NAME ,PCM.CITY_NAME ,ALM.LGR_NAME ,ACM.CITY_NAME ,CMP.CMP_ALIAS
             UNION ALL
                SELECT ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS SNTETOTAL,0 AS EXSNTETOTAL,SUM(SRM.ROUNDEDAMOUNT) AS SR_CREDIT_TOTAL
                ,CMP.CMP_ALIAS
                FROM "+@DATABASENAME+"SALES_RETURN_MASTER SRM
                INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON LM.LGR_ID=SRM.AGENT_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SRM.CMP_CODE                
                "+@JOINSQL+"
                WHERE SRM.CMP_CODE IN("+@CMP_CODE+") AND SRM.SAL_RET_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"'
                GROUP BY LM.LGR_NAME ,PCM.CITY_NAME ,ALM.LGR_NAME ,ACM.CITY_NAME ,CMP.CMP_ALIAS

      ) AS DETAIL
       GROUP BY AGENT,AGENTCITY,PARTY,PARTYCITY,CMP_ALIAS
"


END
EXECUTE (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















