/****** Object:  StoredProcedure [dbo].[PROC_AGENT_SALESINVOICEPREPRINTED]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





























/*
-- =============================================
-- AUTHOR:		<AUTHOR,,NAME>
-- CREATE_DATE: 23/MAY/2012
-- EDIT_DATE :  07/AUG/2012
-- DESCRIPTION:	SALESINVOICEPRINTOUTFOR'SIDDHI VINAYAK(PALI)'
-- =============================================
THIS PROC USED IN (SALINVOICE_RUBIA_PLAINPRINT.RPT)


PROC_SALES_INV_RUBIA_PRINTOUT_GST 1,'ACC2017_2018.DBO.','1009','1009',2,1,'01/APR/2019','31/MAR/2020'
*/

CREATE PROCEDURE [dbo].[PROC_AGENT_SALESINVOICEPREPRINTED]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPTWISE INT,
@SELALL  INT,
@TEMPTABLE NVARCHAR(20),
@FROMDATE NVARCHAR(50),
@TODATE   NVARCHAR(50)
)	
AS
DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @SQL1 AS NVARCHAR(4000) SET @SQL1= ""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""
DECLARE @SQLCOND AS NVARCHAR(4000) SET @SQLCOND=""


BEGIN
IF @RPTWISE = 1
BEGIN
	SET @SQLCOND=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
END

ELSE IF @RPTWISE = 3
BEGIN
	SET @SQLCOND=" INNER JOIN " + @TEMPTABLE + " TT ON SI.TRANSPORT_ID=TT.CODE"
END
ELSE IF @RPTWISE = 2
BEGIN
SET @SQLCOND=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
END
ELSE IF @RPTWISE = 4
BEGIN
SET @SQLCOND=" INNER JOIN " + @TEMPTABLE + " TT ON SI.Sal_Inv_Id=TT.CODE"
END
END

BEGIN
IF @SELALL = 1
SET @SQLCOND=""
END



BEGIN	
	SET NOCOUNT ON;
SET @SQL="  SELECT BILLNO,EWAYBILLNO,VEHICLENO,FLAG,VDATE,CONFNO,CONFDATE,CITY_PINCODE,PARTYNAME,PARTYCITY,LGR_ADD1,LGR_ADD2,LGR_ADD3,LGR_BRANCH,PATYSTATE,LGR_DISTRICT,LGR_CSTNO,AGENTNAME,AGENTCITY,DESTINATION,TRANSPORT_NAME,SAL_INV_LRNO,SAL_INV_LRDATE
,BALENO,ITEM,SCREEN_NAME,PACKINGSTYLE_NAME,PCS,QUANTITY,AMOUNT,RATE,NETTOTAL,SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,SAL_INV_LESSTOTAL,SAL_INV_GROSSTOTAL,CONVERSION,CUT_NAME,UNIT,AMT_WORD,ORDERNO,ORDERDATE,SAL_INV_ADD1,SAL_INV_ADD2
,SAL_INV_ADD3,SAL_INV_ADD4,SAL_INV_ADD5,SAL_INV_LESS1,SAL_INV_LESS2,SAL_INV_LESS3,SAL_INV_LESS4,SAL_INV_LESS5,CM.CMP_NAME,CM.CMP_ADD1,CM.CMP_ADD2,CM.CMP_CITY,CM.CMP_STATE,CM.CMP_PHONE1,CM.CMP_PHONE2,CM.CMP_MOBILE,CM.CMP_BANK_ACCNO1,CM.CMP_BANK_ACCNO2,CM.CMP_BANK_ACCNO3,
CM.CMP_EMAIL,ITEM_HADING,WEIGHT,FREIGHT,COLOR_CHART,CM.CMP_TIN_NO,CM.CMP_PAN_NO,'' AS DESCREPTION,SAL_CRDAYS,DUEDATE,LGR_INTERESTRATE,CM.CMP_INTERESTRATE,ADDPER1,ADDPER2,ADDPER3,ADDPER4,ADDPER5,LESSPER1,LESSPER2,LESSPER3
,LESSPER4,LESSPER5,SRNO,SAL_REMARK,ITEM_CUT,DOCUMENTS,NET_SNET,RATE_PER,COURIERNAME,NOTES,CM.CINNO CMP_CIN_NO,'' AS LOGOIMAGEBYTES,'' AS  SIGNIMAGEBYTES,REMARK,USERNAME,BILLDATE,CGSTINNO,LGSTINNO,HSN_NAME ,ADDBEFOREVALUE,TAXABLEAMT,CONSIGNEENAME, CONSIGNEE_ADD1,CONSIGNEE_ADD2, CONSIGNEE_ADD3,CONSIGNEE_CITY, CONSIGNEE_STATE, CONSIGNEE_STATECODE,CONSIGNEE_GSTNO,  consingee_phone,CONSINGEE_MOBILE,CONSIGNEE_COUNTRY,CONSIGNEE_PINCODE,CONSIGNEE_DISTRICT,LGR_STATECODE,CM.CMP_STATECODE,BILLNO1,PS_CONFNO,TCS_PER,TCS_AMT,EINVNO
 FROM (
SELECT DISTINCT SI.SAL_INV_BILL_NO AS BILLNO,ISNULL(SI.EWAYBILLNO,'')EWAYBILLNO,ISNULL(VEHICLENO,'')VEHICLENO,ISNULL(SALES_ALIAS,'')FLAG,SI.ADJDATE AS VDATE,SI.CONFNO,SI.CONFDATE,LM.CITY_PINCODE,
UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2 
,UPPER(LM.LGR_ADD3)AS LGR_ADD3,SI.LGR_BRANCH AS LGR_BRANCH,UPPER(SM.STATE_NAME) AS  PATYSTATE,LM.LGR_DISTRICT,LM.LGR_CSTNO
,UPPER(AGM.LGR_NAME) AS AGENTNAME,UPPER(ACM.CITY_NAME) AS AGENTCITY,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE
,SID.SAL_INV_BALENO AS BALENO,IM.ITEM_NAME AS ITEM,SCM.SCREEN_NAME,ISNULL(PKM.PACKINGSTYLE_NAME,'') AS  PACKINGSTYLE_NAME
,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
,SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,CTM.CONVERSION,CTM.CUT_NAME,UPPER(UM.UNIT_NAME) AS UNIT,SI.AMT_WORD,SI.ORDERNO,SI.ORDERDATE
,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,
UPPER(CMP.CMP_NAME)AS CMP_NAME,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATE,'') AS CMP_STATE
,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,CMP.CMP_EMAIL,CMP.CMP_ITEM_HADING ITEM_HADING,SI.WEIGHT,SI.FREIGHT,SID.COLOR_CHART,
CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,'' AS DESCREPTION,SI.SAL_CRDAYS,(SAL_INV_VDATE + SAL_CRDAYS) AS DUEDATE,LM.LGR_INTERESTRATE,CMP.CMP_INTERESTRATE,SI.SAL_INV_ADD1_SET AS ADDPER1,SI.SAL_INV_ADD2_SET AS ADDPER2,
SI.SAL_INV_ADD3_SET AS ADDPER3,SI.SAL_INV_ADD4_SET AS ADDPER4,SI.SAL_INV_ADD5_SET AS ADDPER5,SI.SAL_INV_LESS1_SET AS LESSPER1,SI.SAL_INV_LESS2_SET AS LESSPER2,SI.SAL_INV_LESS3_SET AS LESSPER3
,SI.SAL_INV_LESS4_SET AS LESSPER4,SI.SAL_INV_LESS5_SET AS LESSPER5,SID.SAL_INV_DTL_ID AS SRNO,SAL_REMARK,IM.ITEM_CUT,DOCUMENTS,ISNULL(SI.NET_SNET,'') AS NET_SNET,IM.RATE_PER,ISNULL(CURM.COURIERMASTER_NAME,'') AS COURIERNAME,NM.NOTES
,CMP.CINNO AS CMP_CIN_NO ,CMP.CMP_CODE,ISNULL(SID.REMARK,'') AS REMARK,ISNULL(ACC_MASTER.DBO.FN_DECRYPTSTRING(USM.USERNAME),'') AS USERNAME,SI.SAL_INV_VDATE AS BILLDATE,CMP.GSTINNO AS CGSTINNO,LM.GSTINNO AS LGSTINNO,"
SET @SQL1 = "HSN.HSN_NAME,(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)as ADDBEFOREVALUE ,(SI.Sal_Inv_GrossTotal-SI.Sal_Inv_LessTotal+(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)) AS TAXABLEAMT,
ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,CONVERT(NVARCHAR,CMM.PINCODE) AS CONSIGNEE_PINCODE,CMM.DISTRICT AS CONSIGNEE_DISTRICT,
SM.STATE_CODE AS LGR_STATECODE,
(CASE WHEN ISNULL(SI.SALES_ALIAS,'')='' THEN CONVERT(NVARCHAR,SI.SAL_INV_BILL_NO) ELSE (SI.SALES_ALIAS+'/'+CONVERT(NVARCHAR,SI.SAL_INV_BILL_NO))END)AS BILLNO1,
SID.SAL_CONFNO AS PS_CONFNO,ISNULL(SI.TCS_PER,0) TCS_PER , ISNULL(TCS_AMT,0) TCS_AMT,SI.EINVNO
FROM "+@DATABASENAME+" SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SI.FLAG=SID.FLAG 
 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN  "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
LEFT JOIN "+@DATABASENAME+" CUT_MASTER CTM ON CTM.CUT_ID=SID.CUT_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+" PACKINGSTYLE_MASTER PKM ON PKM.PACKINGSTYLE_ID=SID.PACKINGSTYLE_ID
LEFT JOIN "+@DATABASENAME+" COURIER_MASTER CURM ON CURM.COURIERMASTER_ID = LM.COURIERMASTER_ID
LEFT JOIN "+@DATABASENAME+" HSN_MASTER HSN ON HSN.HSN_ID = IM.HSN_ID
LEFT JOIN " + @DATABASENAME +"CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=SI.Consignee_Id	
LEFT JOIN " + @DATABASENAME +"STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id
LEFT JOIN "+@DATABASENAME+" NARRATION_MASTER NM  ON NM.CMP_CODE=SI.CMP_CODE AND NM.TYPE='BILL'
LEFT JOIN ACC_MASTER.DBO.USERMASTER USM ON USM.USERID = SI.USERID
" + @SQLCOND + "
WHERE SI.CMP_CODE="+@CMP_CODE+" AND SI.SAL_INV_TYPE IN ('B') AND SI.FLAG='S'
AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
) AS DETAIL INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON DETAIL.CMP_CODE= CM.CMP_CODE      
ORDER BY   CONVERT(INT,BILLNO),SRNO,BALENO "
    
END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1





















GO

/****** Object:  StoredProcedure [dbo].[PROC_AGENTCOMMISION2]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
