CREATE PROCEDURE [dbo].[PROC_AGENTCOMMISION2]
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@CRITERIA INT
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JOINSQL AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""

BEGIN
SET NOCOUNT ON;



SELECT @SQL="
SELECT SIM.AGENT_ID,SIM.SAL_INV_BILL_NO,SIM.SAL_INV_VDATE,SIM.SAL_INV_NETTOTAL,
PLM.LGR_ID AS PARTYID,PLM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
ALM.LGR_NAME AS AGENTNAME,ACM.CITY_NAME AS AGENTCITY,ALM.LGR_COMMITION,VWSRM.TOTALRET
FROM "+@DATABASENAME+"SALES_INVOICE SIM 
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SIM.AGENT_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON SIM.LGR_ID=PLM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON SIM.AGENT_ID=ALM.LGR_ID
LEFT JOIN "+@DATABASENAME+"VWSALESRETAMT VWSRM ON VWSRM.AGENT_ID=SIM.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
WHERE SIM.CMP_CODE="+@CMP_CODE+" AND SIM.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
ORDER BY  ALM.LGR_NAME,ALM.LGR_ID,SIM.SAL_INV_BILL_NO,PLM.LGR_NAME,PLM.LGR_ID  
"

END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

















GO

/****** Object:  StoredProcedure [dbo].[PROC_AGENTCOMMISSION_PUR]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_AGENTCOMMISSION1 '2','ACC2009_2010.DBO.','','01/APR/2010','31/MAR/2011','',2,2,'''CR''',19,1
*/
CREATE PROCEDURE [dbo].[PROC_AGENTCOMMISSION_PUR] 
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME  NVARCHAR(100),
   @NEXTDB NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @AGCOND INT,
   @ORDCOND INT,
   @TYPESQL NVARCHAR(100),
   @YEARCODE  NVARCHAR(10),
   @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @NEXTSQL AS NVARCHAR(4000)
DECLARE @AGSQL AS NVARCHAR(1000)
DECLARE @ORDSQL AS NVARCHAR(1000)
DECLARE @JOINSQL AS NVARCHAR(4000)


SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @NEXTSQL=""
SET @AGSQL=""
SET @ORDSQL=""
SET @JOINSQL=""


IF @RPT_WISE=1 
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.AGENT_ID"
  END
ELSE IF @RPT_WISE=2
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.LGR_ID"
  END
ELSE IF @RPT_WISE=3
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.AGENT_ID"
  END

/*
 TO GET RECORD FROM NEXT DATABASE
*/

BEGIN
   IF @NEXTDB!=""     
      BEGIN
	    SET @NEXTSQL="    UNION ALL
						SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,SUM(ISNULL(ADJ.ADJUSTAMT,0))AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID,0 AS OTHERAMOUNT ,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT
                       ,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
						FROM "+@NEXTDB+"PURADJMASTER ADJ
						INNER JOIN "+@DATABASENAME+"PURPARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.FLAG=ADJ.FLAG AND PD.BILLNO=ADJ.BILLNO
						WHERE PD.CMP_CODE IN ("+@CMP_CODE+") AND ADJ.TYPE NOT IN("+@TYPESQL +") AND SUBSTRING(CONVERT(NVARCHAR,ADJ.ENTRYCODE),3,2)>"+@YEARCODE+"
						GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID     
                          UNION ALL
						SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,0 AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID,SUM(ISNULL(ADJ.ADJUSTAMT,0)) AS OTHERAMOUNT ,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT
                       ,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
						FROM "+@NEXTDB+"PURADJMASTER ADJ
						INNER JOIN "+@DATABASENAME+"PURPARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.FLAG=ADJ.FLAG AND PD.BILLNO=ADJ.BILLNO
						WHERE PD.CMP_CODE IN ("+@CMP_CODE+") AND ADJ.TYPE  IN("+@TYPESQL +") AND SUBSTRING(CONVERT(NVARCHAR,ADJ.ENTRYCODE),3,2)>"+@YEARCODE+"
						GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID     
                      "              
 
     END
END
/*
TO GET AGENT FROM SALES/LEDGER
*/
BEGIN
	IF @AGCOND=1 
	   BEGIN
		   SET @AGSQL="INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID "                   
	   END 
	ELSE IF @AGCOND=2
	   BEGIN
		   SET @AGSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=PD.CMP_CODE
					   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID "                   
	   END 
END
/*
 TO SET ORDER BY COND
*/
BEGIN
    IF @ORDCOND=1 
      SET @ORDSQL="ORDER BY BILLNO"
    ELSE IF @ORDCOND=2
      SET @ORDSQL="ORDER BY LM.LGR_NAME,BILLDATE,BILLNO"
END 


BEGIN	
SET @SQL="
         SELECT  PD.LGR_ID,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
         PD.BILLNO AS BILLNO,PD.DATE AS BILLDATE,PD.AMOUNT AS BILLAMOUNT ,ISNULL(DETAIL.ADJUSTAMT,0) AS RECAMOUNT,ISNULL(DETAIL.OTHERAMOUNT,0) AS OTHERAMOUNT
         ,ISNULL(DETAIL.DISCOUNT,0) AS DISCOUNT,ISNULL(PD.INTEREST,0) AS PDINTEREST,ISNULL(DETAIL.INTEREST,0) AS ADJINTEREST
         ,ISNULL(DETAIL.INTREC,0) AS ADJINTREC
         ,PD.FLAG,PD.VCODE,CMP.CMP_ALIAS  
         FROM "+@DATABASENAME+"PURPARTYDETAIL PD
         LEFT JOIN ( 
                	SELECT BILLNO ,BILLDATE,SUM(ADJUSTAMT)AS ADJUSTAMT,FLAG,VCODE ,LGR_ID,SUM(OTHERAMOUNT)AS OTHERAMOUNT,SUM(DISCOUNT)AS DISCOUNT,SUM(INTEREST)AS INTEREST,SUM(INTREC)AS INTREC
                    FROM(
           			SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,SUM(ISNULL(ADJ.ADJUSTAMT,0))AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID 
                    ,0 AS OTHERAMOUNT,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
					FROM "+@DATABASENAME+"PURADJMASTER ADJ
					INNER JOIN "+@DATABASENAME+"PURPARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.FLAG=ADJ.FLAG AND PD.BILLNO=ADJ.BILLNO
                    WHERE PD.CMP_CODE IN ("+@CMP_CODE +") AND ADJ.TYPE  NOT IN("+@TYPESQL +")
					GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID
                    UNION ALL
                    SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,0 AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID,
                    SUM(ADJ.ADJUSTAMT) AS OTHERAMOUNT,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
					FROM "+@DATABASENAME+"PURADJMASTER ADJ
					INNER JOIN "+@DATABASENAME+"PURPARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.FLAG=ADJ.FLAG AND PD.BILLNO=ADJ.BILLNO
                    WHERE PD.CMP_CODE IN ("+@CMP_CODE +") AND ADJ.TYPE  IN("+@TYPESQL +")
					GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID
                    "+@NEXTSQL+"                    
                  ) AS DETAIL
                 GROUP BY BILLNO ,BILLDATE,FLAG,VCODE ,LGR_ID
				   ) "
SET @SQL1="  DETAIL ON DETAIL.VCODE=PD.VCODE  AND DETAIL.FLAG=PD.FLAG AND PD.BILLNO=DETAIL.BILLNO AND PD.LGR_ID=DETAIL.LGR_ID
			 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
             "+@AGSQL +"
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
             "+@JOINSQL+"
			 WHERE PD.FLAG  IN('P','CHP','YP','FP','JP') AND PD.CMP_CODE IN("+@CMP_CODE +") AND SUBSTRING(CONVERT(NVARCHAR,PD.VCODE),3,2)="+@YEARCODE+"
             AND PD.DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
         "+@ORDSQL+"

"



END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

/****** Object:  StoredProcedure [dbo].[PROC_AGENTCOMMISSION1]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

