/*
PROC_AGENTCOMMISSION3 '2','ACC2010_2011.DBO.','01/APR/2010','02/MAR/2011','##1234',1,''
*/
CREATE PROCEDURE [dbo].[PROC_AGENTCOMMISSION3]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@RPT_WISE INT ,
@CRNOTEACC NVARCHAR(4000)

)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @ORDERSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @ORDERSQL=""


BEGIN
IF @RPT_WISE=1 
BEGIN 
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERSQL="ORDER BY AGENT,AGENTID,PARTY,PARTYID"
END
ELSE IF @RPT_WISE=2 
BEGIN 
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=S_M.SALESMAN_ID"
SET @ORDERSQL="ORDER BY SALESMAN,SALESMANID,AGENT,AGENTID,PARTY,PARTYID"
END
ELSE IF @RPT_WISE=3 
BEGIN 
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=S_M.SALESMAN_ID"
SET @ORDERSQL="ORDER BY SALESMAN,SALESMANID,AGENT,AGENTID,PARTY,PARTYID"
END

END

BEGIN

SET @SQL="
SELECT PARTY,PARTYCITY,AGENT,AGENTCITY,SALESMAN,SUM(SNETTOTAL) AS SNETTOTAL,SUM(WOSNETTOTAL) AS WOSNETTOTAL,
SUM(SALESRETURN_CRNOTE) AS SALESRETURN_CRNOTE,COMMISION,CMP_ALIAS,PARTYID,AGENTID,SALESMANID FROM (

SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
S_M.SALESMAN_NAME AS SALESMAN,SUM(SI.SAL_INV_NETTOTAL) AS SNETTOTAL,0 AS WOSNETTOTAL,0 AS  SALESRETURN_CRNOTE,
ALM.LGR_COMMITION AS COMMISION,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID,
S_M.SALESMAN_ID as SALESMANID
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=ALM.SALESMAN_ID 
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL+"
WHERE SI.NET_SNET='S.NET' AND SI.CMP_CODE IN("+@CMP_CODE+") 
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
GROUP BY LM.LGR_NAME ,PCM.CITY_NAME ,ALM.LGR_NAME ,ACM.CITY_NAME,S_M.SALESMAN_NAME,ALM.LGR_COMMITION,
CMP.CMP_ALIAS,LM.LGR_ID,ALM.LGR_ID,S_M.SALESMAN_ID
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
S_M.SALESMAN_NAME AS SALESMAN,0 AS SNETTOTAL,SUM(SI.SAL_INV_NETTOTAL) AS WOSNETTOTAL,0 AS SALESRETURN_CRNOTE,
ALM.LGR_COMMITION AS COMMISION,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID,
S_M.SALESMAN_ID as SALESMANID
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL+"
WHERE SI.NET_SNET!='S.NET' AND SI.CMP_CODE IN("+@CMP_CODE+") 
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME,S_M.SALESMAN_NAME,ALM.LGR_COMMITION,
CMP.CMP_ALIAS,LM.LGR_ID,ALM.LGR_ID,S_M.SALESMAN_ID
"
SET @SQL1="     UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
S_M.SALESMAN_NAME AS SALESMAN,0 AS SNETTOTAL,0 AS WOSNETTOTAL,SUM(SRM.ROUNDEDAMOUNT) AS SALESRETURN_CRNOTE,
ALM.LGR_COMMITION AS COMMISION,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID,
S_M.SALESMAN_ID as SALESMANID
FROM "+@DATABASENAME+"SALES_RETURN_MASTER SRM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SRM.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SRM.CMP_CODE
"+@JOINSQL+"
WHERE  SRM.CMP_CODE IN("+@CMP_CODE+") AND SRM.SAL_RET_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME,S_M.SALESMAN_NAME,ALM.LGR_COMMITION,
CMP.CMP_ALIAS,LM.LGR_ID,ALM.LGR_ID,S_M.SALESMAN_ID
UNION ALL
SELECT CN_LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
S_M.SALESMAN_NAME AS SALESMAN,0 AS SNETTOTAL,0 AS WOSNETTOTAL,SUM(TD.TRAN_AMOUNT) AS SALESRETURN_CRNOTE,
ALM.LGR_COMMITION AS COMMISION,CMP.CMP_ALIAS,CN_LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID,
S_M.SALESMAN_ID as SALESMANID
FROM "+@DATABASENAME+"TRAN_DETAIL TD
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TD.TRAN_TYPE=TM.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE AND TD.TRAN_DETAIL_ID IN("+@CRNOTEACC+")
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL CN ON TM.TRAN_ID=CN.TRAN_ID AND CN.TRAN_TYPE=TM.TRAN_TYPE AND TM.CMP_CODE=CN.CMP_CODE AND TD.TRAN_DETAIL_ID<>CN.TRAN_DETAIL_ID				
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER CN_LM ON CN_LM.LGR_ID=CN.TRAN_DETAIL_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=CN_LM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON CN_LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE

"+@JOINSQL+"
WHERE TM.TRAN_TYPE IN('CN') AND TM.CMP_CODE IN("+@CMP_CODE+") 
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'

GROUP BY CN_LM.LGR_NAME,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME,S_M.SALESMAN_NAME,ALM.LGR_COMMITION,
CMP.CMP_ALIAS,CN_LM.LGR_ID,ALM.LGR_ID,S_M.SALESMAN_ID
) AS DETAIL
GROUP BY PARTY,PARTYCITY,AGENT,AGENTCITY,SALESMAN,COMMISION,CMP_ALIAS,PARTYID,AGENTID,SALESMANID "+@ORDERSQL+"
" 

END

PRINT @SQL
PRINT @SQL1
EXEC (@SQL+@SQL1)




















GO

