/*
PROC_AGENTCOMMISSION4 '1','ACC2017_2018.DBO.','01/APR/2017','31/MAR/2018','',2
*/
CREATE PROCEDURE [dbo].[PROC_AGENTCOMMISSION4] 
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME  NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @NEXTSQL AS NVARCHAR(4000)
DECLARE @AGSQL AS NVARCHAR(1000)
DECLARE @ORDSQL AS NVARCHAR(1000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @ORGORDERSQL AS NVARCHAR(4000)


SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @NEXTSQL=""
SET @AGSQL=""
SET @ORDSQL=""
SET @JOINSQL=""
SET @ORGORDERSQL=""


IF @RPT_WISE=1 
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.AGENT_ID"
	--IF @ORDCOND=1 
	--BEGIN
	--	SET @ORGORDERSQL="  ALM.LGR_NAME,AGENTID,BILLNO,BILLDATE,LM.LGR_NAME,LM.LGR_ID  "
	--END
	--ELSE IF @ORDCOND=2 
	--BEGIN
	--	SET @ORGORDERSQL=" ALM.LGR_NAME,AGENTID,LM.LGR_NAME,LM.LGR_ID,BILLNO,BILLDATE "
	--END	
  END
ELSE IF @RPT_WISE=2
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.LGR_ID"
 --  IF @ORDCOND=1 
	--BEGIN
	--	SET @ORGORDERSQL="LM.LGR_NAME,LM.LGR_ID"
	--END
	--ELSE IF @ORDCOND=2 
	--BEGIN
	--	SET @ORGORDERSQL="LM.LGR_NAME,LM.LGR_ID,BILLNO,BILLDATE,ALM.LGR_NAME,AGENTID "
	--END	
  END
ELSE IF @RPT_WISE=3
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.AGENT_ID"
 --  IF @ORDCOND=1 
	--BEGIN
	--	SET @ORGORDERSQL="ALM.LGR_NAME,AGENTID,BILLNO,BILLDATE,LM.LGR_NAME,LM.LGR_ID"
	--END
	--ELSE IF @ORDCOND=2
	--BEGIN
	--	SET @ORGORDERSQL="ALM.LGR_NAME,ALM.LGR_ID ,LM.LGR_NAME,LM.LGR_ID,BILLDATE,BILLNO"
	--END	
  END

/*
 TO GET RECORD FROM NEXT DATABASE
*/


/*
TO GET AGENT FROM SALES/LEDGER
*/

/* 
TO SET ORDER BY COND
*/
--BEGIN
--    IF @ORDCOND=1 
--      SET @ORDSQL=" ORDER BY "+@ORGORDERSQL+""
--    ELSE IF @ORDCOND=2
--      SET @ORDSQL=" ORDER BY "+@ORGORDERSQL+""
--END 


BEGIN	
SET @SQL="
          SELECT LGR_ID,max(PARTY) AS PARTY,max(ISNULL(PARTYCITY,'')) AS PARTYCITY,max(AGENT) AS AGENT,max(AGENTCITY) AS AGENTCITY,
       max(CMP_ALIAS)CMP_ALIAS,AGENTID AS AGENTID  , SUM(SALBILLAMOUNT) AS SALBILLAMOUNT,SUM(SALTOTALTAX) AS SALTOTALTAX,SUM( SRETBILLAMOUNT) AS SRETBILLAMOUNT, SUM(SRETTOTALTAX) AS SRETTOTALTAX,MAX(Sal_Inv_Commission)Sal_Inv_Commission
                    FROM( 
						SELECT  SI.LGR_ID,max(LM.LGR_NAME )AS PARTY,max(ISNULL(PCM.CITY_NAME,'')) AS PARTYCITY,max(ALM.LGR_NAME) AS AGENT,max(ISNULL(ACM.CITY_NAME,'')) AS AGENTCITY,
       max(CMP.CMP_ALIAS)CMP_ALIAS,ALM.LGR_ID AS AGENTID  ,  ISNULL(SUM(Sal_Inv_GrossTotal),0) +
						(ISNULL(SUM(SI.SAL_INV_ADD1),0) 
						+ISNULL(SUM(SI.SAL_INV_ADD2),0) 
						)-(+(ISNULL(SUM(SI.Sal_Inv_Less1),0) ) +(ISNULL(SUM(SI.Sal_Inv_Less2),0)) +(ISNULL(SUM(SI.Sal_Inv_Less3),0)) 
						+(ISNULL(SUM(SI.Sal_Inv_Less4),0)) +(ISNULL(SUM(SI.Sal_Inv_Less5),0)) ) AS SALTOTALTAX ,
						(ISNULL(SUM(Sal_Inv_NetTotal),0)) AS SALBILLAMOUNT ,0 AS SRETBILLAMOUNT,0 AS SRETTOTALTAX,MAX(Sal_Inv_Commission)Sal_Inv_Commission
						FROM "+@DATABASENAME+"SALES_INVOICE SI                            
					             
			 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
             INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID 
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID  
           --   "+@JOINSQL+"         
						WHERE SI.CMP_CODE IN ("+@CMP_CODE +")  AND SI.Sal_Inv_Vdate BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
						GROUP BY SI.LGR_ID,ALM.LGR_ID 
						UNION ALL
						SELECT   SI.LGR_ID,max(LM.LGR_NAME) AS PARTY,max(ISNULL(PCM.CITY_NAME,'')) AS PARTYCITY,max(ALM.LGR_NAME) AS AGENT,max(ISNULL(ACM.CITY_NAME,'')) AS AGENTCITY,
       max(CMP.CMP_ALIAS)CMP_ALIAS,ALM.LGR_ID AS AGENTID  , 0 AS SALTOTALTAX, 0 AS SALBILLAMOUNT,( ISNULL(SUM(SI.NetTotal ),0)) AS SRETBILLAMOUNT,
						((ISNULL(SUM(GrossTotal),0) +
						(ISNULL(SUM(SI.SAL_RET_ADD1),0) 
						+ ISNULL(SUM(SI.SAL_RET_ADD2),0) 
						)-                                         
						(
						+(ISNULL(SUM(SI.Sal_Ret_Less1),0))
						+(ISNULL(SUM(SI.Sal_Ret_Less2),0))
						+(ISNULL(SUM(SI.Sal_Ret_Less3),0))
						+(ISNULL(SUM(SI.Sal_Ret_Less4),0))
						+(ISNULL(SUM(SI.Sal_Ret_Less5),0))
						)))  AS SRETTOTALTAX,MAX(LM.Lgr_Commition) AS Sal_Inv_Commission
						FROM "+@DATABASENAME+"SALES_RETURN_MASTER SI
						           
			 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
             INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID 
             
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID       
            --  "+@JOINSQL+"
						WHERE SI.CMP_CODE IN ("+@CMP_CODE +")  AND SI.SAL_RET_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
						GROUP BY SI.LGR_ID,ALM.LGR_ID 
                  ) AS DETAIL
                 GROUP BY LGR_ID,AGENTID
				   "
SET @SQL1=" 
        

"



END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1


















GO

/****** Object:  StoredProcedure [dbo].[PROC_ANNEXUTE_BREPORT]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO















	/*
	-- =============================================
	-- AUTHOR :		<PATEL PRATIK>
	-- EDIT_DATE : <03/07/2020,16:52PM>
	-- REPORT_FORM : <rfrmStatement1A>
	-- CRYSTAL_REPORT : <STATEMENT1A.RPT>
	-- =============================================
	SELECT * FROM ACC2018_2019.DBO.LEDGER_MASTER WHERE LGR_NAME LIKE 'JOB%'
	SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
	PROC_ANNEXUTE_BREPORT N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'31/Mar/2019', 2, '##4344'
	*/ 
	CREATE PROCEDURE [dbo].[PROC_ANNEXUTE_BREPORT]
	(
	@CMP_CODE NVARCHAR(20),
	@DATABASENAME NVARCHAR(50),
	@FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),  
	@SAL_ACC_ID NVARCHAR(20)
	)
	AS
	DECLARE @SQL AS NVARCHAR(4000)
	DECLARE @SQL1 AS NVARCHAR(4000)
	DECLARE @SQL2 AS NVARCHAR(4000)
	DECLARE @ACCSQL AS NVARCHAR(4000)

	SET @SQL=""
	SET @SQL1=""
	SET @SQL2=""
	SET @ACCSQL=""

	BEGIN	
	
			SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=PI.PURACCID"
	
	END

	BEGIN
	SET NOCOUNT ON;

	SET @SQL="
	
	SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
	LM1.SUPPLY_TYPE AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC, MAX((NETTOTAL)) AS NETTOTAL,
	SUM(PID.Amount-((PID.Amount*(LessTotal-(ISNULL(Pur_Inv_Add1,0)+ISNULL(Pur_Inv_Add2,0)+ISNULL(Pur_Inv_Add3,0))))/GrossTotal))TAXABLEAMT,
	SUM(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD4,0))/ 
	(GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS CGST,
	SUM(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD5,0))/ 
	(GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS SGST, 
	SUM(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD6,0))/ 
	(GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))) AS IGST,
	HSM.HSN_NAME ,0 AS CESSAMT,
	MAX(ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0)) AS GSTPER,LM1.LGR_NAME AS PURCHASEACC
	FROM "+@DATABASENAME+"PURCHASEINVOICE PI
	INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID  ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+") AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND PI.FLAG IN ('P','FP')
	AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')
	GROUP BY LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE,HSM.HSN_NAME,LM1.SUPPLY_TYPE,LM1.LGR_NAME "

	SET @SQL1="
	UNION ALL
	SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
	LM1.SUPPLY_TYPE AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,NETTOTAL,
	(PI.GROSSTOTAL +(ISNULL(PI.PUR_INV_ADD1,0)+ISNULL(PI.PUR_INV_ADD2,0)+ISNULL(PI.PUR_INV_ADD3,0))-
	(ISNULL(PI.PUR_INV_LESS2,0)+ISNULL(PI.PUR_INV_LESS3,0)+ISNULL(PI.PUR_INV_LESS4,0)+ISNULL(PI.PUR_INV_LESS5,0))) AS TAXABLEAMT,
	(ISNULL(Pur_Inv_Add4,0)) AS CGST,(ISNULL(Pur_Inv_Add5,0)) AS SGST,(ISNULL(Pur_Inv_Add6,0)) AS IGST,HSM.HSN_NAME,0 AS CESSAMT,
	(ISNULL(Pur_Inv_Add4_Set,0)) + (ISNULL(Pur_Inv_Add5_Set,0)) + (ISNULL(Pur_Inv_Add6_Set,0)) AS GSTPER,LM1.LGR_NAME AS PURCHASEACC
	FROM "+@DATABASENAME+"PURCHASEINVOICE PI
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = PI.HSN_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+") AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND PI.FLAG IN ('JP')
	AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0') "
	SET @SQL2="

	UNION ALL

	SELECT LGR_NAME,GSTINNO,BILLNO,VCHDATE,SUPPLY_TYPE,ELIGIBILITY_OF_ITC,MAX (NetTotal) AS NETTOTAL,
	SUM(TAXABLEAMT)TAXABLEAMT,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST ,HSN_NAME,SUM(CESSAMT) AS CESSAMT,MAX(GSTPER) GSTPER,PURCHASEACC
	FROM (

	SELECT LM.LGR_NAME,LM.GSTINNO,(CONVERT(NVARCHAR,BILLNO))BILLNO,VCHDATE AS VCHDATE,
	LM1.SUPPLY_TYPE AS SUPPLY_TYPE ,
	(CASE WHEN PI.GST_TYPE = 'InEligible ITC' THEN 'InEligible' ELSE 'Eligible' END ) AS ELIGIBILITY_OF_ITC,(NetTotal) AS NETTOTAL,
	(PID.FINALAMOUNT-(ISNULL(VAT_AMT,0)+ISNULL(VATAMOUNT1,0)+ISNULL(VATAMOUNT2,0) + ISNULL(CESSAMT,0))) AS TAXABLEAMT,
	VAT_AMT AS CGST,VATAMOUNT1 AS SGST,VATAMOUNT2 AS IGST,HSN_NAME,CESSAMT,
	(ISNULL(VAT_PER,0)) + (ISNULL(VAT_PER1,0)) + (ISNULL(VAT_PER2,0)) AS GSTPER,LM1.LGR_NAME AS PURCHASEACC 
	FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
	INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+")  AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND
	((PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B' ))
	AND (ISNULL(VAT_AMT,0) + ISNULL(VATAMOUNT1,0) + ISNULL(VATAMOUNT2,0) )>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')
	) AS DETAIL
	GROUP BY LGR_NAME,GSTINNO,BILLNO,VCHDATE,SUPPLY_TYPE,ELIGIBILITY_OF_ITC,HSN_NAME,PURCHASEACC

	ORDER BY VCHDATE,BillNo,LGR_NAME,HSN_NAME

	"
	
	END	
	EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2













GO

