	/*
	-- =============================================
	-- AUTHOR :		<PATEL PRATIK>
	-- EDIT_DATE : <03/07/2020,16:52PM>
	-- REPORT_FORM : <rfrmStatement1A>
	-- CRYSTAL_REPORT : <STATEMENT1A.RPT>
	-- =============================================
	SELECT * FROM ACC2018_2019.DBO.LEDGER_MASTER WHERE LGR_NAME LIKE 'JOB%'
	SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
	PROC_ANNEXUTE_BREPORT_HSN N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'31/Mar/2019', 2, '##4344'
	*/ 
	CREATE PROCEDURE [dbo].[PROC_ANNEXUTE_BREPORT_HSN]
	(
	@CMP_CODE NVARCHAR(20),
	@DATABASENAME NVARCHAR(50),
	@FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),  
	@SAL_ACC_ID NVARCHAR(20)
	)
	AS
	DECLARE @SQL AS NVARCHAR(4000)
	DECLARE @SQL1 AS NVARCHAR(4000)
	DECLARE @SQL2 AS NVARCHAR(4000)
	DECLARE @ACCSQL AS NVARCHAR(4000)

	SET @SQL=""
	SET @SQL1=""
	SET @SQL2=""
	SET @ACCSQL=""

	BEGIN	
	
			SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=PI.PURACCID"
	
	END

	BEGIN
	SET NOCOUNT ON;

	SET @SQL="
	
	SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
	LM1.SUPPLY_TYPE AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,MAX (NETTOTAL) AS NETTOTAL,
	MAX(PI.GROSSTOTAL + (ISNULL(PI.PUR_INV_ADD1,0)+ISNULL(PI.PUR_INV_ADD2,0)+ISNULL(PI.PUR_INV_ADD3,0) -  ISNULL(LessTotal,0)))AS TAXABLEAMT,
	MAX(ISNULL(Pur_Inv_Add4,0)) AS CGST,MAX(ISNULL(Pur_Inv_Add5,0)) AS SGST,MAX(ISNULL(Pur_Inv_Add6,0)) AS IGST,MAX(HSM.HSN_NAME) HSN_NAME ,0 AS CESSAMT,LM1.LGR_NAME AS PURCHASEACC
	FROM "+@DATABASENAME+"PURCHASEINVOICE PI
	INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID  ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+") AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND PI.FLAG IN ('P','FP')
	AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')
	GROUP BY LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE,LM1.SUPPLY_TYPE,LM1.LGR_NAME "
	SET @SQL1="
	UNION ALL
	SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
	LM1.SUPPLY_TYPE AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,NETTOTAL,
	(PI.GROSSTOTAL +(ISNULL(PI.PUR_INV_ADD1,0)+ISNULL(PI.PUR_INV_ADD2,0)+ISNULL(PI.PUR_INV_ADD3,0))-
	(ISNULL(PI.PUR_INV_LESS2,0)+ISNULL(PI.PUR_INV_LESS3,0)+ISNULL(PI.PUR_INV_LESS4,0)+ISNULL(PI.PUR_INV_LESS5,0))) AS TAXABLEAMT,
	(ISNULL(Pur_Inv_Add4,0)) AS CGST,(ISNULL(Pur_Inv_Add5,0)) AS SGST,(ISNULL(Pur_Inv_Add6,0)) AS IGST,HSM.HSN_NAME,0 AS CESSAMT,LM1.LGR_NAME AS PURCHASEACC
	FROM "+@DATABASENAME+"PURCHASEINVOICE PI
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = PI.HSN_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+") AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND PI.FLAG IN ('JP')
	AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0') "
	SET @SQL2="

	UNION ALL

	SELECT LGR_NAME,GSTINNO,BILLNO,VCHDATE,SUPPLY_TYPE,ELIGIBILITY_OF_ITC,MAX (NetTotal) AS NETTOTAL,
	SUM(TAXABLEAMT)TAXABLEAMT,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST ,MIN(HSN_NAME) HSN_NAME,SUM(CESSAMT) AS CESSAMT,PURCHASEACC
	FROM (

	SELECT LM.LGR_NAME,LM.GSTINNO,(CONVERT(NVARCHAR,BILLNO))BILLNO,VCHDATE AS VCHDATE,
	(CASE WHEN PI.GST_TYPE = 'InEligible ITC' THEN 'InEligible' ELSE LM1.SUPPLY_TYPE END ) AS SUPPLY_TYPE ,
	(CASE WHEN PI.GST_TYPE = 'InEligible ITC' THEN 'InEligible' ELSE 'Eligible' END ) AS ELIGIBILITY_OF_ITC,(NetTotal) AS NETTOTAL,
	(PID.FINALAMOUNT-(ISNULL(VAT_AMT,0)+ISNULL(VATAMOUNT1,0)+ISNULL(VATAMOUNT2,0) + ISNULL(CESSAMT,0))) AS TAXABLEAMT,
	VAT_AMT AS CGST,VATAMOUNT1 AS SGST,VATAMOUNT2 AS IGST,CESSAMT ,HSM.HSN_NAME,LM1.LGR_NAME AS PURCHASEACC
	FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
	INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
	LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+"
	WHERE PI.CMP_CODE IN ("+@CMP_CODE+")  AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND
	((PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B' ))
	AND (ISNULL(VAT_AMT,0) + ISNULL(VATAMOUNT1,0) + ISNULL(VATAMOUNT2,0) )>0
	AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')
	) AS DETAIL
	GROUP BY LGR_NAME,GSTINNO,BILLNO,VCHDATE,SUPPLY_TYPE,ELIGIBILITY_OF_ITC,PURCHASEACC

	ORDER BY VCHDATE,BillNo,LGR_NAME,HSN_NAME

	"
	
	END	
	EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2













GO

/****** Object:  StoredProcedure [dbo].[PROC_ANNEXUTE_BREPORT_SALES]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






CREATE PROCEDURE [dbo].[PROC_ANNEXUTE_BREPORT_SALES]
(
    @CMP_CODE NVARCHAR(20),
	@DATABASENAME NVARCHAR(50),
	@FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20), 
	@RPT_WISE INT, 
	@SAL_ACC_ID NVARCHAR(20)
)
AS
    DECLARE @SQL AS NVARCHAR(4000)
	DECLARE @SQL1 AS NVARCHAR(4000)
	DECLARE @SQL2 AS NVARCHAR(4000)
	DECLARE @ACCSQL AS NVARCHAR(4000)

	SET @SQL=""
	SET @SQL1=""
	SET @SQL2=""
	SET @ACCSQL=""
	
	BEGIN	
	        if @RPT_WISE = 1
			SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=JOB_SALACCID"
			if @RPT_WISE in (2,3)
			SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=DEBITAC_ID "
			if @RPT_WISE = 4
			SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=SAL_ACC_ID "
			
			
	
	END


BEGIN
	
	SET NOCOUNT ON;
	IF @RPT_WISE =1
	BEGIN
	SET @SQL="
	
	SELECT LM.LGR_NAME,LM.GSTINNO,CONVERT(INT,JOB_SAL_INV_BILL_NO) AS BILLNO,JOB_SAL_INV_VDATE AS VCHDATE,
	LM.REGISTER_DEALER_TYPE  AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,MAX (NETAMT) AS TOTAL,
	MAX(JSI.TOTAL + (ISNULL(JSI.SAL_INV_ADD1,0)+ISNULL(JSI.SAL_INV_ADD2,0) -  ISNULL(LessTotal,0)))AS TAXABLEAMT,
    MAX(ISNULL(SAL_Inv_Add3,0)) AS CGST,MAX(ISNULL(SAL_Inv_Add4,0)) AS SGST,MAX(ISNULL(SAL_Inv_Add5,0)) AS IGST,
    HSM.HSN_NAME ,0 AS CESSAMT,
    MAX(ISNULL(Sal_Inv_Add3_Set,0)) + MAX(ISNULL(SaL_Inv_Add4_Set,0)) + MAX(ISNULL(Sal_Inv_Add5_Set,0)) AS GSTPER,JSI.Sales_Alias AS FLAG
    FROM "+@DATABASENAME+"JOB_SALESINVOICE_MASTER JSI
    INNER JOIN "+@DATABASENAME+"JOB_SALESINVOICE_DETAIL JID  ON JSI.JOB_SAL_INV_ID=JID.JOB_SAL_INV_ID AND JSI.FORM_FLAG=JID.FORM_FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=JSI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=JSI.JOB_SalAccId
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = JID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+"
	WHERE JSI.CMP_CODE IN ("+@CMP_CODE+") AND JOB_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND JSI.FORM_FLAG='JS' 
	GROUP BY LM.LGR_NAME,LM.GSTINNO,JOB_SAL_INV_BILL_NO,JOB_SAL_INV_VDATE,HSM.HSN_NAME,LM.REGISTER_DEALER_TYPE,JSI.Sales_Alias  "
	SET @SQL1="
	UNION ALL
	
	SELECT LM.LGR_NAME,LM.GSTINNO,CONVERT(INT,SAL_INV_BILL_NO) AS BILLNO,SAL_INV_VDATE AS VCHDATE,
	LM.REGISTER_DEALER_TYPE  AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,MAX(SAL_INV_NETTOTAL) AS TOTAL,
	SUM(SID.SAL_INV_AMOUNT-((SID.SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))AS TAXABLEAMT,
	SUM(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*ISNULL(SAL_INV_ADD3,0))/
	(SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS CGST_AMT,
	SUM(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*ISNULL(SAL_INV_ADD4,0))/
	(SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS SGST_AMT, 
	SUM(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*ISNULL(SAL_INV_ADD5,0))/
	(SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS IGST_AMT,
	HSM.HSN_NAME ,0 AS CESSAMT,
	MAX(ISNULL(Sal_Inv_Add3_Set,0)) + MAX(ISNULL(SaL_Inv_Add4_Set,0)) + MAX(ISNULL(Sal_Inv_Add5_Set,0)) AS GSTPER, SI.Sales_Alias AS FLAG
    FROM "+@DATABASENAME+"SALES_INVOICE SI
    INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID  ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=SI.SAL_ACCID
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = SID.ITEM_ID
	INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=SI.Sal_AccID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	WHERE SI.CMP_CODE IN ("+@CMP_CODE+") AND SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND SI.FLAG IN ('S','GSN','MS')
	GROUP BY LM.LGR_NAME,LM.GSTINNO,SAL_INV_BILL_NO,SAL_INV_VDATE,HSM.HSN_NAME,LM.REGISTER_DEALER_TYPE,SI.Sales_Alias 
	
	ORDER BY VCHDATE,BillNo,LGR_NAME,HSN_NAME
	
	"
	END
	IF @RPT_WISE =3
	BEGIN
	SET @SQL ="
	SELECT LM.LGR_NAME,LM.GSTINNO,CONVERT(INT,TRAN_DOCNO) AS BILLNO,TRAN_DATE AS VCHDATE,
	LM.REGISTER_DEALER_TYPE  AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,NETAMOUNT AS TOTAL,
	CM.TRAN_AMOUNT AS TAXABLEAMT,
    CM.CGST, CM.SGST, CM.IGST,HM.HSN_NAME ,0 AS CESSAMT,
    ISNULL(CM.CGSTPER,0) + ISNULL(CM.SGSTPER,0) + ISNULL(CM.IGSTPER,0) AS GSTPER,Alias AS FLAG
    FROM "+@DATABASENAME+"CreditNoteAcc_Master CM 
    INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CM.LGR_ID
    INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=CM.DEBITAC_ID
    INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	LEFT JOIN "+@DATABASENAME+" HSN_MASTER HM ON HM.HSN_ID=CM.HSN_ID
	"+@ACCSQL+""
	SET @SQL1="WHERE CM.CMP_CODE IN ("+@CMP_CODE+") AND TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND CM.NOTE = 'CR NOTE ISSUED AGAINST SALE' AND CM.TRAN_TYPE='GCN'
	"
	END
	IF @RPT_WISE =2
	BEGIN
	SET @SQL="
	SELECT LM.LGR_NAME,LM.GSTINNO,CONVERT(INT,TRAN_DOCNO) AS BILLNO,TRAN_DATE AS VCHDATE,
	LM.REGISTER_DEALER_TYPE  AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,NETAMOUNT AS TOTAL,
	CM.TRAN_AMOUNT AS TAXABLEAMT,
    CM.CGST, CM.SGST, CM.IGST,HM.HSN_NAME ,0 AS CESSAMT,
    ISNULL(CM.CGSTPER,0) + ISNULL(CM.SGSTPER,0) + ISNULL(CM.IGSTPER,0) AS GSTPER,Alias AS FLAG
    FROM "+@DATABASENAME+"DebitNoteAcc_Master CM
    INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CM.LGR_ID
    INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=CM.DEBITAC_ID
    INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	LEFT JOIN "+@DATABASENAME+" HSN_MASTER HM ON HM.HSN_ID=CM.HSN_ID
	"+@ACCSQL+""
	SET @SQL1="WHERE CM.CMP_CODE IN ("+@CMP_CODE+") AND TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND CM.NOTE = 'DR Note Issued Against Sale' AND CM.TRAN_TYPE='GDN'
	"
	END 
	IF @RPT_WISE =4
	BEGIN
	
	SET @SQL="
	SELECT LM.LGR_NAME,LM.GSTINNO,CONVERT(INT,DOCNO) AS BILLNO,SAL_RET_DATE AS VCHDATE,
	LM.REGISTER_DEALER_TYPE  AS SUPPLY_TYPE,'Eligible' AS ELIGIBILITY_OF_ITC,MAX (NETTOTAL) AS TOTAL,
	
	 
    SUM(JID.Sal_Ret_Amount-((JID.Sal_Ret_Amount*(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))/JSI.GrossTotal))AS TAXABLEAMT,
	SUM(((Sal_Ret_Amount-((Sal_Ret_Amount*(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))/JSI.GrossTotal))*ISNULL(SAL_RET_ADD3,0))/
	(JSI.GrossTotal-(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))) AS CGST,
	SUM(((Sal_Ret_Amount-((Sal_Ret_Amount*(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))/JSI.GrossTotal))*ISNULL(SAL_RET_ADD4,0))/
	(JSI.GrossTotal-(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))) AS SGST, 
	SUM(((Sal_Ret_Amount-((Sal_Ret_Amount*(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))/JSI.GrossTotal))*ISNULL(SAL_RET_ADD5,0))/
	(JSI.GrossTotal-(SAL_RET_LessTotal-(ISNULL(SAL_RET_ADD1,0)+ISNULL(SAL_RET_ADD2,0))))) AS IGST,
    
    
    HSM.HSN_NAME ,0 AS CESSAMT,
    MAX(ISNULL(Sal_RET_Add3_Set,0)) + MAX(ISNULL(SaL_RET_Add4_Set,0)) + MAX(ISNULL(Sal_RET_Add5_Set,0)) AS GSTPER,JSI.Alias AS FLAG
    FROM "+@DATABASENAME+"SALES_RETURN_MASTER JSI
    INNER JOIN "+@DATABASENAME+"SALES_RETURN_DETAIL JID  ON JSI.SAL_RET_ID=JID.SAL_RET_ID AND JSI.FLAG=JID.FLAG
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=JSI.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=JSI.SAL_ACC_ID 
	INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
	INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = JID.ITEM_ID
	LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
	"+@ACCSQL+""
	SET @SQL1="WHERE JSI.CMP_CODE IN ("+@CMP_CODE+") AND SAL_RET_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
	AND JSI.FLAG='SR' 
	GROUP BY LM.LGR_NAME,LM.GSTINNO,DOCNO,SAL_RET_DATE,HSM.HSN_NAME,LM.REGISTER_DEALER_TYPE,Alias  "
	END
	
END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1





GO

/****** Object:  StoredProcedure [dbo].[PROC_AUTOCREDITNOTE]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_AUTOCREDITNOTE]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @ItemId nvarchar(20),
	@criteria int
)
as
declare @Sql  Nvarchar(4000)
declare @joinsql  Nvarchar(500)
if @criteria=0
	set @joinsql=""
else if @criteria=1 
	set @joinsql="And SID.Item_Id="+@ItemId+""

begin
    	SET NOCOUNT ON;
        set @sql=" 
				Select Distinct(SIM.Sal_Inv_Id) As SalesId,SIM.Sal_Inv_Bill_No,SIM.Sal_Inv_Vdate,SIM.Lgr_Id,PLM.Lgr_Name As PartyName,
				PCM.City_Name,SIM.OrderNo, SIM.OrderDate,SIM.Sal_Inv_NetTotal
				From "+@DatabaseName+"Sales_Invoice SIM 
				INNER JOIN "+@DatabaseName+"Sales_Invoice_detail SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
				INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON SIM.Lgr_Id=PLM.Lgr_Id
				LEFT JOIN "+@DatabaseName+"City_Master PCM ON PLM.City_Id=PCM.City_Id
				Where SIM.cmp_code="+@Cmp_Code+"
				"+@joinsql+"
				And SIM.Sal_Inv_Id not In(Select case When sal_inv_id>0 Then sal_inv_id Else 0 End from "+@DatabaseName+"Tran_master where Tran_type='CN' And cmp_code="+@Cmp_Code+")
				And SIM.Sal_Inv_Vdate BETWEEN '"+@FromDate+"' And '"+@ToDate+"'
					"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

/****** Object:  StoredProcedure [dbo].[PROC_AUTOJOURNALREGISTER]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
EXEC [PROC_AUTOJOURNALREGISTER] 2,'ACC2010_2011.DBO.','02/APR/2010','02/JUN/2010'
*/



CREATE PROCEDURE [dbo].[PROC_AUTOJOURNALREGISTER]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20)
)
AS
DECLARE @SQL  NVARCHAR(4000)

BEGIN
SET NOCOUNT ON;
SET @SQL=" 				
SELECT AJ.VCODE,LM.LGR_NAME AS PARTYNAME,AJ.VDATE, AJ.DRAMOUNT,AJ.CRAMOUNT,AJ.ENTRYMATCH
FROM "+@DATABASENAME+"AUTOJOURNAL AJ
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID	
WHERE AJ.VDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' AND AJ.CMP_CODE="+@CMP_CODE+" 
ORDER BY VCODE,ENTRYMATCH,AJ.VDATE

"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_AVGDAY]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
EXEC	[PROC_AVGDAY] '3','01/APR/2010','01/APR/2010','11/NOV/2010','ACC2010_2011.DBO.','##3956',2
*/

CREATE PROCEDURE [dbo].[PROC_AVGDAY] 
@CMP_CODE  VARCHAR(52), 	
@STARTDATE VARCHAR(15), 
@FROMDATE VARCHAR(15), 
@TODATE VARCHAR(15), 	
@DATABASENAME NVARCHAR(30)	,
@TABLENAME SYSNAME, 
@QUERYNO SMALLINT
AS
DECLARE @SQL1 NVARCHAR(4000)
DECLARE @SQL2 NVARCHAR(4000)
DECLARE @SQL3 NVARCHAR(4000)
DECLARE @CONDITIONALFIELD AS NVARCHAR(4000)
DECLARE @CONDITIONALJOIN AS NVARCHAR(4000)
DECLARE @CONDITIONALGROUPING AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)

SET @CONDITIONALJOIN="''''"
SET @CONDITIONALFIELD=' '
SET @CONDITIONALGROUPING=' '
SET @ORDERBYSQL = ""

IF @QUERYNO=0 	 /* ALL ACCOUNT WISE [PARTY WISE] */
BEGIN
SET @CONDITIONALFIELD=" TT3.PARTYNAME HEADERNAME,TT3.PARTYCODE AS HEADERID "
SET @CONDITIONALJOIN=""
SET @CONDITIONALGROUPING=""
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID"
END

IF @QUERYNO=1		/* CUSTOMER GROUP WISE */
BEGIN
SET @CONDITIONALFIELD=" CGM.CUST_GRP_NAME HEADERNAME,CGM.CUST_GRP_ID AS HEADERID "
SET @CONDITIONALJOIN=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LD.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " 	
INNER JOIN  "+@DATABASENAME + "LEDGER_MASTER LM ON LD.LGR_ID=LM.LGR_ID 
INNER JOIN  "+@DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON LM.CUST_GRP_ID=CGM.CUST_GRP_ID "
SET @CONDITIONALGROUPING="CGM.CUST_GRP_NAME,CGM.CUST_GRP_ID,"
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID,PARTYNAME,PARTYCODE"
END
IF @QUERYNO=2		/* AGENT WISE */
BEGIN
SET @CONDITIONALFIELD="(LM_1.LGR_NAME + '' ['' + CCM.CITY_NAME + '']'') AS  HEADERNAME,LM_1.LGR_ID AS HEADERID "
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LD.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM_1 ON LD.AGENT_ID=LM_1.LGR_ID
INNER JOIN  "+@DATABASENAME+"CITY_MASTER CCM ON CCM.CITY_ID=LM_1.CITY_ID"
SET @CONDITIONALGROUPING="LM_1.LGR_NAME + '' ['' + CCM.CITY_NAME + '']'',LM_1.LGR_ID,"
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID,PARTYNAME,PARTYCODE"
END

IF @QUERYNO=3	 /* CITY WISE */
BEGIN
SET @CONDITIONALFIELD=" CMM.CITY_NAME HEADERNAME,CMM.CITY_ID AS HEADERID "
SET @CONDITIONALJOIN=""
SET @CONDITIONALGROUPING=""
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID,PARTYNAME,PARTYCODE"
END


IF @QUERYNO=4		/* ALL GROUP WISE */
BEGIN
SET @CONDITIONALFIELD="GM.GRP_NAME HEADERNAME,GM.GRP_ID AS HEADERID "
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LD.LGR_ID 
					   AND LD.CMP_CODE=" + @CMP_CODE + "
					   INNER JOIN  "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID"
SET @CONDITIONALGROUPING="GM.GRP_NAME,GM.GRP_ID,"
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID,PARTYNAME,PARTYCODE"
END

IF @QUERYNO=5		/* CATEGORY WISE */
BEGIN
SET @CONDITIONALFIELD="GM.CATEGORY_NAME HEADERNAME,GM.CATEGORY_ID AS HEADERID"
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME + "LEDGER_MASTER LM ON TT3.PARTYCODE=LM.LGR_ID 
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + "
INNER JOIN  "+@DATABASENAME+"CATEGORY_MASTER GM ON LM.CATEGORY_ID=GM.CATEGORY_ID "
SET @CONDITIONALGROUPING="GM.CATEGORY_NAME,GM.CATEGORY_ID,"
SET @ORDERBYSQL = "ORDER BY HEADERNAME,HEADERID,PARTYNAME,PARTYCODE"
END

SELECT @SQL1="

SELECT    " + @CONDITIONALFIELD + ", TT3.PARTYCODE, TT3.PARTYNAME, SUM(TT3.DEBIT) DEBIT, SUM(TT3.CREDIT) AS CREDIT,
SUM(TT3.DRPRODUCT) DRPR, SUM(TT3.CRPRODUCT) AS CRPR, SUM(TT3.CREDIT) - SUM(TT3.DEBIT) AS CLOBAL,
CASE WHEN SUM(TT3.CREDIT) - SUM(TT3.DEBIT) > 0 THEN ''C'' ELSE ''D'' END AS CL_DRCR, CTM.CITY_ID PARTYCITY,CMM.CITY_NAME,CMM.CITY_ID,
ISNULL(TT4.JSALESAMT,0) + ISNULL(TT5.SALESAMT,0) - ISNULL(TT6.SALESRETURNAMT,0) TOTALSALESAMT, ISNULL(TT7.PURAMT,0) - ISNULL(TT8.PURRETURNAMT,0) TOTALPURAMT, ISNULL(TT9.BILLAMOUNT,0) SALESBILLAMOUNT, ISNULL(TT9.DISCOUNT,0) SALESDISCOUNT, ISNULL(TT10.BILLAMOUNT,0) PURBILLAMOUNT, ISNULL(TT10.DISCOUNT,0) PURDISCOUNT

FROM 
(SELECT TT1.PARTYCODE, TT1.PARTYNAME,TT1.CITY_ID, TT1.DEBIT, TT1.CREDIT,
DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1 INTDIFFDAYS, ((TT1.DEBIT * (DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1)/30)) DRPRODUCT, 
((TT1.CREDIT * (DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1)/30)) CRPRODUCT
FROM 

(SELECT   LM.LGR_ID AS  PARTYCODE,  LM.LGR_NAME PARTYNAME, LM.CITY_ID,
CASE WHEN TD.TRAN_DRCR = ''D'' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBIT, CASE WHEN TD.TRAN_DRCR = ''C'' THEN TD.TRAN_AMOUNT ELSE 0 END CREDIT, TM.TRAN_DATE AS VDATE
FROM 
"+@DATABASENAME+"TRAN_MASTER TM INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE = TD.CMP_CODE AND TM.TRAN_TYPE=TD.TRAN_TYPE 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON  LM.LGR_ID=TD.TRAN_DETAIL_ID 
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE TM.CMP_CODE=" + @CMP_CODE + " AND TM.TRAN_DATE>=''" + @FROMDATE + "'' AND TM.TRAN_DATE<=''" + @TODATE + "'' 

UNION ALL

SELECT    LM.LGR_ID AS PARTYCODE,  LM.LGR_NAME AS PARTYNAME, LM.CITY_ID,
CASE WHEN TD.TRAN_DRCR = ''D'' THEN 0 ELSE TD.TRAN_AMOUNT END DEBIT, CASE WHEN TD.TRAN_DRCR = ''C'' THEN 0 ELSE TD.TRAN_AMOUNT END CREDIT, TM.TRAN_DATE AS VDATE
FROM   "+@DATABASENAME+"TRAN_MASTER TM INNER JOIN   "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE = TD.CMP_CODE AND TM.TRAN_TYPE=TD.TRAN_TYPE 
INNER JOIN   "+@DATABASENAME+"LEDGER_MASTER LM ON  LM.LGR_ID=TM.TRAN_MASTER_ID
INNER JOIN   "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE 
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE TD.TRAN_TYPE <> ''JR'' AND TM.CMP_CODE=" + @CMP_CODE + " AND TM.TRAN_DATE>=''" + @FROMDATE + "''  AND TM.TRAN_DATE<=''" + @TODATE + "''" 


SELECT @SQL2="
UNION ALL
SELECT   LM.LGR_ID AS  PARTYCODE,  LM.LGR_NAME PARTYNAME, LM.CITY_ID CITYCODE,  ISNULL(AJ.DRAMOUNT,0) DEBIT, 
ISNULL(AJ.CRAMOUNT,0) AS CREDIT, AJ.VDATE
FROM   "+@DATABASENAME+"AUTOJOURNAL AJ INNER JOIN   "+@DATABASENAME+"AUTOJOURNAL AJ_1 ON AJ.ENTRYTYPE = AJ_1.ENTRYTYPE AND AJ.ENTRYCODE = AJ_1.ENTRYCODE AND AJ.CMP_CODE = AJ_1.CMP_CODE AND AJ.LGR_ID <> AJ_1.LGR_ID AND 	AJ.VCODE = AJ_1.VCODE AND AJ.ENTRYMATCH = AJ_1.ENTRYMATCH 
INNER JOIN   "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = AJ.LGR_ID 
INNER JOIN   "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND AJ.CMP_CODE = LD.CMP_CODE 
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE AJ.CMP_CODE=" + @CMP_CODE + " AND AJ.VDATE>=''" + @FROMDATE + "'' AND AJ.VDATE<=''" + @TODATE + "'' 
) TT1


UNION ALL

SELECT TT2.PARTYCODE, TT2.PARTYNAME, TT2.CITY_ID, TT2.DEBIT, TT2.CREDIT, TT2.INTDIFFDAYS,
((TT2.DEBIT * TT2.INTDIFFDAYS)/30) DRPRODUCT,
((CREDIT * TT2.INTDIFFDAYS)/30) CRPRODUCT
FROM(
SELECT   LM.LGR_ID AS PARTYCODE,  LM.LGR_NAME AS PARTYNAME, LM.CITY_ID, CASE WHEN LGR_OP_DRCR = ''D'' THEN LGR_OP_BAL ELSE 0 END DEBIT,
CASE WHEN LGR_OP_DRCR = ''C'' THEN LGR_OP_BAL ELSE 0 END CREDIT,
(DATEDIFF(DD,''" + @STARTDATE + "'',''" + @TODATE + "'')+ 1) INTDIFFDAYS	
FROM   "+@DATABASENAME+"LEDGER_MASTER LM INNER JOIN   "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE LD.CMP_CODE=" + @CMP_CODE + ")TT2

) TT3
LEFT OUTER JOIN  "+@DATABASENAME+"CITY_MASTER CTM ON TT3.CITY_ID=CTM.CITY_ID

/* JOB SALE AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(NETAMT) AS JSALESAMT, COT_SALACCID AS ACCCODE
FROM   "+@DATABASENAME+"COTTON_SALESINVOICE_MASTER	SIM
INNER JOIN " + @TABLENAME + " ON SIM.COT_SALACCID=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND COT_SAL_INV_VDATE>=''" + @FROMDATE + "'' AND COT_SAL_INV_VDATE<=''" + @TODATE + "''
GROUP BY COT_SALACCID) TT4
ON TT4.ACCCODE=TT3.PARTYCODE

/* SALES AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(SAL_INV_NETTOTAL) SALESAMT, LGR_ID AS PARTY_CODE
FROM "+@DATABASENAME+"SALES_INVOICE SIM2
INNER JOIN " + @TABLENAME + " ON SIM2.LGR_ID=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND SAL_INV_VDATE>=''" + @FROMDATE + "'' AND SAL_INV_VDATE<=''" + @TODATE + "''
GROUP BY LGR_ID) TT5
ON TT5.PARTY_CODE=TT3.PARTYCODE


/* SALES RETURN AMOUNT*/

LEFT OUTER JOIN
(SELECT SUM(NETTOTAL) SALESRETURNAMT, SAL_ACC_ID AS ACCCODE
FROM  "+@DATABASENAME+"SALES_RETURN_MASTER SRM
INNER JOIN " + @TABLENAME + " ON SRM.SAL_ACC_ID=" + @TABLENAME + ".CODE 
WHERE CMP_CODE=" + @CMP_CODE + " AND SAL_RET_DATE>=''" + @FROMDATE + "'' AND SAL_RET_DATE<=''" + @TODATE + "'' 
GROUP BY SAL_ACC_ID) TT6
ON TT6.ACCCODE=TT3.PARTYCODE"

/* PUR AMOUNT */
SELECT @SQL3="
LEFT OUTER JOIN
(SELECT SUM(NETTOTAL) PURAMT, PIM.LGR_ID AS  ACCCODE
FROM    "+ @DATABASENAME +"PURCHASEINVOICE PIM
INNER JOIN " + @TABLENAME + " ON PIM.LGR_ID=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND VCHDATE>=''" + @FROMDATE + "'' AND VCHDATE<=''" + @TODATE + "'' 
GROUP BY LGR_ID) TT7
ON TT7.ACCCODE=TT3.PARTYCODE


/* PUR RETURN AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(NETTOTAL) PURRETURNAMT,PUR_ACC_ID AS  ACCCODE
FROM    "+ @DATABASENAME +"PURCHASE_RETURN_MASTER PRM
INNER JOIN " + @TABLENAME + " ON PRM.PUR_ACC_ID=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND PUR_RET_DATE>=''" + @FROMDATE + "'' AND PUR_RET_DATE<=''" + @TODATE + "'' 
GROUP BY PUR_ACC_ID) TT8
ON TT8.ACCCODE=TT3.PARTYCODE

/* BILL AMOUNT + DISCOUNT FROM ADJUSTMASTER */



LEFT OUTER JOIN
(SELECT ACCCODE, SUM(BILLAMOUNT) BILLAMOUNT,SUM(DISCOUNT+RD) DISCOUNT
FROM
(
SELECT AM.TYPE AS ENTRYTYPE, AM.LGR_ID AS ACCCODE, AM.BILLNO AS BNO, AM.AMOUNT AS BILLAMOUNT, SUM(AM.DISCOUNT) AS DISCOUNT, SUM(0) AS RD
FROM    "+ @DATABASENAME +"ADJMASTER AM 
INNER JOIN    "+ @DATABASENAME +"PARTYDETAIL PD ON AM.VCODE=PD.VCODE AND AM.BILLNO=PD.BILL_NO AND AM.LGR_ID=PD.LGR_ID AND AM.FLAG=PD.JOBFLAG
WHERE PD.CMP_CODE=" + @CMP_CODE + " AND AM.DATE>=''" + @FROMDATE + "''  AND AM.DATE<=''" + @TODATE + "'' 
GROUP BY AM.LGR_ID, AM.BILLNO, AM.AMOUNT, AM.TYPE
)TT1
GROUP BY TT1.ACCCODE)TT9
ON TT3.PARTYCODE=TT9.ACCCODE




LEFT OUTER JOIN
(SELECT ACCCODE, SUM(BILLAMOUNT) BILLAMOUNT,SUM(DISCOUNT+RD) DISCOUNT
FROM
(
SELECT AM.TYPE AS ENTRYTYPE, AM.LGR_ID AS ACCCODE, AM.BILLNO AS BNO, AM.AMOUNT AS BILLAMOUNT, SUM(AM.DISCOUNT) AS DISCOUNT, SUM(PD.RD) AS RD
FROM    "+ @DATABASENAME +"PURADJMASTER AM 
INNER JOIN    "+ @DATABASENAME +"PURPARTYDETAIL PD ON AM.VCODE=PD.VCODE AND AM.BILLNO=PD.BILLNO AND AM.LGR_ID=PD.LGR_ID  AND AM.FLAG=PD.FLAG
WHERE PD.CMP_CODE=" + @CMP_CODE + " AND AM.DATE>=''" + @FROMDATE + "'' AND AM.DATE<=''" + @TODATE + "'' 
GROUP BY AM.LGR_ID, AM.BILLNO, AM.AMOUNT, AM.TYPE
)TT1
GROUP BY TT1.ACCCODE)TT10
ON TT3.PARTYCODE=TT10.ACCCODE " + @CONDITIONALJOIN + "
INNER JOIN  "+ @DATABASENAME +"CITY_MASTER CMM ON CTM.CITY_ID = CMM.CITY_ID
GROUP BY " + @CONDITIONALGROUPING + "TT3.PARTYCODE, TT3.PARTYNAME, TT3.CITY_ID, CTM.CITY_ID,CMM.CITY_NAME,CMM.CITY_ID,TT4.JSALESAMT, TT5.SALESAMT, TT6.SALESRETURNAMT, TT7.PURAMT, TT8.PURRETURNAMT,TT9.BILLAMOUNT,
TT9.DISCOUNT,TT10.BILLAMOUNT, TT10.DISCOUNT
HAVING SUM(TT3.DRPRODUCT) > 0 OR SUM(TT3.CRPRODUCT) > 0"

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @ORDERBYSQL
EXEC ('EXEC SP_EXECUTESQL N''' + @SQL1 + @SQL2 +@SQL3+@ORDERBYSQL+N'''')




















GO

/****** Object:  StoredProcedure [dbo].[PROC_AVGDAYS]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO

















/*
PROC_AVGDAYS '10','01/APR/2010','30/AUG/2010','30/AUG/2010','ACC2010_2011.DBO.','','1'
*/
CREATE PROCEDURE [dbo].[PROC_AVGDAYS] 
@CMP_CODE  VARCHAR(52), 	
@STARTDATE VARCHAR(15), 
@FROMDATE VARCHAR(15), 
@TODATE VARCHAR(15), 	
@DATABASENAME NVARCHAR(30)	,
@TABLENAME SYSNAME, 
@QUERYNO SMALLINT

AS
DECLARE @SQL1 NVARCHAR(4000)
DECLARE @SQL2 NVARCHAR(4000)
DECLARE @SQL3 NVARCHAR(4000)
DECLARE @CONDITIONALFIELD AS NVARCHAR(100)
DECLARE @CONDITIONALJOIN AS NVARCHAR(350)
DECLARE @CONDITIONALGROUPING AS NVARCHAR(50)

SET @CONDITIONALJOIN="''''"
SET @CONDITIONALFIELD="' '"
SET @CONDITIONALGROUPING="' '"

IF @QUERYNO=0 	/* ALL ACCOUNT WISE [PARTY WISE] */
BEGIN
SET @CONDITIONALFIELD=" TT3.PARTYNAME HEADERNAME"
SET @CONDITIONALJOIN=""
SET @CONDITIONALGROUPING=""
END

IF @QUERYNO=1		/* CUSTOMER GROUP WISE */
BEGIN
SET @CONDITIONALFIELD=" CGM.NAME HEADERNAME"
SET @CONDITIONALJOIN=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LM.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " INNER JOIN  "+@DATABASENAME+"CUSTOMERGROUPMASTER CGM ON LD.CGCODE=CGM.CODE"
SET @CONDITIONALGROUPING="CGM.NAME,"
END

IF @QUERYNO=2		/* CITY_ID WISE */
BEGIN
SET @CONDITIONALFIELD=" CTM.CITY_ID HEADERNAME"
SET @CONDITIONALJOIN=""
SET @CONDITIONALGROUPING=""
END

IF @QUERYNO=3		/* AGENT WISE */
BEGIN
SET @CONDITIONALFIELD="LM_1.NAME HEADERNAME"
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LM.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM_1 ON LD.AGCODE=LM_1.CODE"
SET @CONDITIONALGROUPING="LM_1.NAME,"
END

IF @QUERYNO=4		/* ALL GROUP WISE */
BEGIN
SET @CONDITIONALFIELD="GM.NAME HEADERNAME"
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LM.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " INNER JOIN  "+@DATABASENAME+"GROUPMASTER GM ON LD.SGRCODE=GM.CODE"
SET @CONDITIONALGROUPING="GM.NAME,"
END

IF @QUERYNO=5		/* CATEGORY WISE */
BEGIN
SET @CONDITIONALFIELD="GM.NAME HEADERNAME"
SET @CONDITIONALJOIN=" INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON TT3.PARTYCODE=LM.LGR_ID AND LD.CMP_CODE=" + @CMP_CODE + " INNER JOIN  "+@DATABASENAME+"GROUPMASTER GM ON LD.SGRCODE=GM.CODE"
SET @CONDITIONALGROUPING="GM.NAME,"
END

SELECT @SQL1="
SELECT " + @CONDITIONALFIELD + ", TT3.PARTYCODE, TT3.PARTYNAME, SUM(TT3.DEBIT) DEBIT, SUM(TT3.CREDIT) AS CREDIT,
SUM(TT3.DRPRODUCT) DRPR, SUM(TT3.CRPRODUCT) AS CRPR, SUM(TT3.CREDIT) - SUM(TT3.DEBIT) AS CLOBAL,
CASE WHEN SUM(TT3.CREDIT) - SUM(TT3.DEBIT) > 0 THEN ''CR'' ELSE ''DR'' END AS CL_DRCR, CTM.CITY_ID PARTYCITY,
ISNULL(TT4.JSALESAMT,0) + ISNULL(TT5.SALESAMT,0) - ISNULL(TT6.SALESRETURNAMT,0) TOTALSALESAMT, ISNULL(TT7.PURAMT,0) - ISNULL(TT8.PURRETURNAMT,0) TOTALPURAMT, ISNULL(TT9.BILLAMOUNT,0) SALESBILLAMOUNT, ISNULL(TT9.DISCOUNT,0) SALESDISCOUNT, ISNULL(TT10.BILLAMOUNT,0) PURBILLAMOUNT, ISNULL(TT10.DISCOUNT,0) PURDISCOUNT

FROM 
(SELECT TT1.PARTYCODE, TT1.PARTYNAME,TT1.CITY_ID, TT1.DEBIT, TT1.CREDIT,
DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1 INTDIFFDAYS, ROUND(((TT1.DEBIT * DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1)/30),2) DRPRODUCT, 
ROUND(((TT1.CREDIT * DATEDIFF(DD,TT1.VDATE,''"+ @TODATE + "'')+1)/30),2) CRPRODUCT
FROM 
(SELECT LM.LGR_ID PARTYCODE,  LM.LGR_NAME PARTYNAME, LM.CITY_ID,
CASE WHEN TD.TRAN_TDCR = ''DR'' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBIT, CASE WHEN TD.TRAN_TDCR = ''CR'' THEN TD.TRAN_AMOUNT ELSE 0 END CREDIT, TM.TRAN_DATE AS VDATE
FROM 
"+@DATABASENAME+"TRAN_MASTER TM INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE = TD.CMP_CODE AND TM.TRAN_TYPE=TD.TRAN_TYPE 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON  LM.LGR_ID=TD.TRAN_DETAIL_ID 
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LM.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE TM.CMP_CODE=" + @CMP_CODE + " AND TM.TRAN_DATE>=''" + @FROMDATE + "'' AND TM.TRAN_DATE<=''" + @TODATE + "'' 

UNION ALL

SELECT LM.LGR_ID AS PARTYCODE,  LM.LGR_NAME AS PARTYNAME, LM.CITY_ID,
CASE WHEN TD.TRAN_TDCR = ''DR'' THEN 0 ELSE TD.TRAN_AMOUNT END DEBIT, CASE WHEN TD.TRAN_TDCR = ''CR'' THEN 0 ELSE TD.TRAN_AMOUNT END CREDIT, TM.TRAN_DATE AS VDATE
FROM  "+@DATABASENAME+"TRAN_MASTER TM INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE = TD.CMP_CODE AND TM.TRAN_TYPE=TD.TRAN_TYPE 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON  LM.LGR_ID=TM.TRAN_MASTER_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LM.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE 
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE TD.TRAN_TYPE <> ''JR'' AND TM.CMP_CODE=" + @CMP_CODE + " AND TM.TRAN_DATE>=''" + @FROMDATE + "'' AND TM.TRAN_DATE<=''" + @TODATE + "''" 

SELECT @SQL2="
UNION ALL

SELECT LM.LGR_ID PARTYCODE,  LM.LGR_NAME PARTYNAME, LM.CITY_ID CITYCODE,  ISNULL(AJ.DRAMOUNT,0) DEBIT, 
ISNULL(AJ.CRAMOUNT,0) AS CREDIT, AJ.VDATE
FROM  "+@DATABASENAME+"AUTOJOURNAL AJ INNER JOIN  "+@DATABASENAME+"AUTOJOURNAL AJ_1 ON AJ.ENTRYTYPE = AJ_1.ENTRYTYPE AND AJ.ENTRYCODE = AJ_1.ENTRYCODE AND AJ.CMP_CODE = AJ_1.CMP_CODE AND AJ.LGR_ID <> AJ_1.LGR_ID AND 	AJ.VCODE = AJ_1.VCODE AND AJ.ENTRYMATCH = AJ_1.ENTRYMATCH 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = AJ.LGR_ID 
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LM.LGR_ID AND AJ.CMP_CODE = LD.CMP_CODE 
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE AJ.CMP_CODE=" + @CMP_CODE + " AND AJ.VDATE>=''" + @FROMDATE + "'' AND AJ.VDATE<=''" + @TODATE + "'' 
) TT1


UNION ALL

SELECT TT2.PARTYCODE, TT2.PARTYNAME, TT2.CITY_ID, TT2.DEBIT, TT2.CREDIT, TT2.INTDIFFDAYS,
((TT2.DEBIT * TT2.INTDIFFDAYS)/30) DRPRODUCT,
((CREDIT * TT2.INTDIFFDAYS)/30) CRPRODUCT
FROM(
SELECT DISTINCT LM.LGR_ID AS PARTYCODE,  LM.LGR_NAME AS PARTYNAME, LM.CITY_ID, CASE WHEN LGR_OP_DRCR = ''DR'' THEN LGR_OP_BAL ELSE 0 END DEBIT,
CASE WHEN LGR_OP_DRCR = ''CR'' THEN LGR_OP_BAL ELSE 0 END CREDIT,
(DATEDIFF(DD,''" + @STARTDATE + "'',''" + @TODATE + "'')+ 1) INTDIFFDAYS	
FROM  "+@DATABASENAME+"LEDGER_MASTER LM INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LM.LGR_ID
INNER JOIN " + @TABLENAME + " ON LM.LGR_ID=" + @TABLENAME + ".CODE
WHERE LD.CMP_CODE=" + @CMP_CODE + ")TT2
) TT3
LEFT OUTER JOIN  "+@DATABASENAME+"CITYMASTER CTM ON TT3.CITY_ID=CTM.CITY_ID

/* JOB SALE AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(ROUNDEDAMT) AS JSALESAMT, ACCCODE
FROM  "+@DATABASENAME+"SALESINVOICEMASTER SIM
INNER JOIN " + @TABLENAME + " ON SIM.ACCCODE=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND BILLDATE>=''" + @FROMDATE + "'' AND BILLDATE<=''" + @TODATE + "'' 
GROUP BY ACCCODE) TT4
ON TT4.ACCCODE=TT3.PARTYCODE

/* SALES AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(GAMT) SALESAMT, PARTY_CODE
FROM  "+@DATABASENAME+"SALESINVOICEMASTER2 SIM2
INNER JOIN " + @TABLENAME + " ON SIM2.PARTY_CODE=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND BILL_DATE>=''" + @FROMDATE + "'' AND BILL_DATE<=''" + @TODATE + "'' 
GROUP BY PARTY_CODE) TT5
ON TT5.PARTY_CODE=TT3.PARTYCODE

/* SALES RETURN AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(NETAMT) SALESRETURNAMT, ACCCODE
FROM  "+@DATABASENAME+"SALESRETURNMASTER SRM
INNER JOIN " + @TABLENAME + " ON SRM.ACCCODE=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND DOCDATE>=''" + @FROMDATE + "'' AND DOCDATE<=''" + @TODATE + "'' 
GROUP BY ACCCODE) TT6
ON TT6.ACCCODE=TT3.PARTYCODE"

/* PUR AMOUNT */
SELECT @SQL3="

LEFT OUTER JOIN
(SELECT SUM(TOTAL) PURAMT, PARTY_CODE ACCCODE
FROM  "+@DATABASENAME+"PURINVOICEMASTER PIM
INNER JOIN " + @TABLENAME + " ON PIM.PARTY_CODE=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND BILL_DATE>=''" + @FROMDATE + "'' AND BILL_DATE<=''" + @TODATE + "'' 
GROUP BY PARTY_CODE) TT7
ON TT7.ACCCODE=TT3.PARTYCODE

/* PUR RETURN AMOUNT */
LEFT OUTER JOIN
(SELECT SUM(NETAMT) PURRETURNAMT, ACCCODE
FROM  "+@DATABASENAME+"PURRETURNMASTER PRM
INNER JOIN " + @TABLENAME + " ON PRM.ACCCODE=" + @TABLENAME + ".CODE
WHERE CMP_CODE=" + @CMP_CODE + " AND DOCDATE>=''" + @FROMDATE + "'' AND DOCDATE<=''" + @TODATE + "'' 
GROUP BY ACCCODE) TT8
ON TT8.ACCCODE=TT3.PARTYCODE


LEFT OUTER JOIN
(SELECT ACCCODE, SUM(BILLAMOUNT) BILLAMOUNT,SUM(DISCOUNT+RD) DISCOUNT
FROM
(
SELECT AM.ENTRYTYPE, AM.ACCCODE, AM.BNO, AM.AMOUNT AS BILLAMOUNT, SUM(AM.DISCOUNT) AS DISCOUNT, SUM(AM.RD) AS RD
FROM  "+@DATABASENAME+"ADJMASTER AM INNER JOIN  "+@DATABASENAME+"PARTYDETAIL PD ON AM.VCODE=PD.VCODE AND AM.BNO=PD.BILL_NO AND AM.ACCCODE=PD.ACCCODE AND AM.JOBFLAG=PD.JOBFLAG
WHERE PD.CMP_CODE=" + @CMP_CODE + " AND AM.VDATE>=''" + @FROMDATE + "'' AND AM.VDATE<=''" + @TODATE + "'' 
GROUP BY AM.ACCCODE, AM.BNO, AM.AMOUNT, AM.ENTRYTYPE
)TT1
GROUP BY TT1.ACCCODE)TT9
ON TT3.PARTYCODE=TT9.ACCCODE


LEFT OUTER JOIN
(SELECT ACCCODE, SUM(BILLAMOUNT) BILLAMOUNT,SUM(DISCOUNT+RD) DISCOUNT
FROM
(
SELECT AM.ENTRYTYPE, AM.ACCCODE, AM.BNO, AM.AMOUNT AS BILLAMOUNT, SUM(AM.DISCOUNT) AS DISCOUNT, SUM(AM.RD) AS RD
FROM  "+@DATABASENAME+"PURADJMASTER AM INNER JOIN  "+@DATABASENAME+"PURPARTYDETAIL PD ON AM.VCODE=PD.VCODE AND AM.BNO=PD.BILL_NO AND AM.ACCCODE=PD.ACCCODE  AND AM.JOBFLAG=PD.JOBFLAG
WHERE PD.CMP_CODE=" + @CMP_CODE + " AND AM.VDATE>=''" + @FROMDATE + "'' AND AM.VDATE<=''" + @TODATE + "'' 
GROUP BY AM.ACCCODE, AM.BNO, AM.AMOUNT, AM.ENTRYTYPE
)TT1
GROUP BY TT1.ACCCODE)TT10
ON TT3.PARTYCODE=TT10.ACCCODE

" + 

@CONDITIONALJOIN + "

GROUP BY " + @CONDITIONALGROUPING + "TT3.PARTYCODE, TT3.PARTYNAME, TT3.CITY_ID, CTM.CITY_ID,TT4.JSALESAMT, TT5.SALESAMT, TT6.SALESRETURNAMT, TT7.PURAMT, TT8.PURRETURNAMT,TT9.BILLAMOUNT, TT9.DISCOUNT,TT10.BILLAMOUNT, TT10.DISCOUNT
HAVING SUM(TT3.DRPRODUCT) > 0 OR SUM(TT3.CRPRODUCT) > 0"

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
EXEC ('EXEC SP_EXECUTESQL N''' + @SQL1 + @SQL2 +@SQL3+N'''')




















GO

/****** Object:  StoredProcedure [dbo].[PROC_BALANCENOTE]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_BALANCENOTE 'ACC2013_2014.DBO.','2','17/aPR/2013',0,'##1488',6072,4
*/


CREATE PROCEDURE [dbo].[PROC_BALANCENOTE] 
(
@DATABASENAME AS NVARCHAR(200),
@CONDITION AS NVARCHAR(4000),
@RECDATE AS NVARCHAR(20),
@WOEXCISE AS INT,
@TEMPTABLE AS NVARCHAR(200),
@PARTYID AS NVARCHAR(20),
@CMP_CODE AS NVARCHAR(20)
)


AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)

DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @DATECOND AS NVARCHAR(100)
DECLARE @SQLJOIN AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQLJOIN=""
SET @DATECOND=""

BEGIN 
IF @WOEXCISE=0
SET @DATECOND = " AM.RECDATE='"+ @RECDATE + "' AND "
ELSE IF @WOEXCISE=1
SET @DATECOND = ""
END

BEGIN
IF @CONDITION='1'
	SET @SQLJOIN=""
ELSE if @CONDITION='2'
	if @TEMPTABLE != ""
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=(CONVERT(NVARCHAR,AM.VCODE)+AM.FLAG+CONVERT(NVARCHAR,AM.BILLNO))"
	else	
		set @SQLJOIN=""
END


BEGIN
SET NOCOUNT ON;
IF @CONDITION='2' 
SET @SQL="  
SELECT DISTINCT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,0 AS SRNO,0 AS ENTRYCODE,AM.VCODE,AM.LGR_ID,
AM.BILLNO,'' AS TYPE,AM.FLAG,AM.DATE,'' AS RECDATE,'' AS CHEQUENO,'' AS CHEQUEDATE,AM.AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,
0 AS OTHERLESS,0 AS TOTAL,0 AS ADJUSTAMT,0 AS INTEREST,0 AS INTREC,0 AS PAID,AM.CMP_CODE,'' AS REMARK, 0 AS RECEIPT_ID,
('BILL NO : ' + AM.BILLNO + ' BILL DATE : ' + CONVERT(NVARCHAR(20),AM.DATE,103) ) AS NARRATION,
1 AS ORD 
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE "+@DATECOND+"AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+"  
AND AM.TYPE IN ('BR','CR')

UNION ALL
"
SET @SQL1="
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,AM.SRNO,AM.ENTRYCODE,AM.VCODE,AM.LGR_ID,
AM.BILLNO,AM.TYPE,AM.FLAG,AM.DATE,AM.RECDATE,AM.CHEQUENO,AM.CHEQUEDATE,AM.INTEREST AS AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,
0 AS OTHERLESS,0 AS TOTAL,0 AS ADJUSTAMT,0 AS INTEREST,0 AS INTREC,AM.PAID,AM.CMP_CODE,AM.REMARK,AM.RECEIPT_ID,
('INTEREST @ 24 % FOR ' + CONVERT(NVARCHAR(20),(DATEDIFF(DAY,PD.DATE,CASE WHEN AM.RECDATE IS NULL THEN AM.DATE
ELSE AM.RECDATE END)+1 -  
(CASE WHEN LD.AGENT_ID = 0 OR LM.LGR_NAME = 'DIRECT' THEN

(CASE WHEN (SELECT COUNT(SM.DAYS) FROM "+@DATABASENAME+"SCHEME_MASTER SM
WHERE SM.START_DATE <= PD.DATE AND SM.END_DATE >= PD.DATE  AND SM.CMP_CODE = "+@CMP_CODE+"
AND SM.DISCOUNT = 0) > 0 THEN  

(SELECT MIN(SM.DAYS) FROM "+@DATABASENAME+"SCHEME_MASTER SM
WHERE SM.START_DATE <= PD.DATE AND SM.END_DATE >= PD.DATE  AND SM.CMP_CODE = "+@CMP_CODE+"
AND SM.DISCOUNT = 0)  

WHEN (SELECT COUNT(SM.DAYS) FROM "+@DATABASENAME+"SCHEME_MASTER SM
WHERE SM.START_DATE <= PD.DATE AND SM.END_DATE >= PD.DATE  AND SM.CMP_CODE = "+@CMP_CODE+" 
AND SM.AGENT_DISCOUNT = 0) > 0 THEN  

(SELECT MIN(SM.DAYS) FROM "+@DATABASENAME+"SCHEME_MASTER SM
WHERE SM.START_DATE <= PD.DATE AND SM.END_DATE >= PD.DATE  AND SM.CMP_CODE = "+@CMP_CODE+" 
AND SM.AGENT_DISCOUNT = 0)  END) ELSE 0
END)))	) AS NARRATION,
2 AS ORD 
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"PARTYDETAIL PD ON  AM.BILLNO=PD.BILL_NO AND AM.FLAG=PD.JOBFLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE  AM.RECDATE='"+@RECDATE+"' AND AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+"  
AND AM.TYPE IN ('BR','CR') AND AM.INTEREST > 0
UNION ALL
"
IF @WOEXCISE=0
SET @SQL2="
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,AM.SRNO,AM.ENTRYCODE ,AM.VCODE,AM.LGR_ID,
AM.BILLNO,AM.TYPE,AM.FLAG,AM.DATE,AM.RECDATE,AM.CHEQUENO,AM.CHEQUEDATE,0 as AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,
AM.OTHERLESS,AM.TOTAL,AM.ADJUSTAMT,AM.INTEREST,AM.INTREC,AM.PAID,AM.CMP_CODE,AM.REMARK,AM.RECEIPT_ID,
(CASE WHEN AM.TYPE IN('CN') THEN ('** RATE DIFFRENCE ** CR NO : ' + CONVERT(NVARCHAR(20),AM.CHEQUENO))
WHEN AM.TYPE IN('DN') THEN ('** RATE DIFFRENCE ** DR NO : ' + CONVERT(NVARCHAR(20),AM.CHEQUENO)) 
ELSE ('DD/CHQ. ' + AM.CHEQUENO + ' DATE : ' + CONVERT(NVARCHAR(20),AM.RECDATE,103) + 'JV NO ' +CONVERT(NVARCHAR(20),AM.CHEQUENO) ) END) AS NARRATION,
3 AS ORD
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"ADJMASTER ADJ ON ADJ.FLAG = AM.FLAG AND ADJ.DATE = AM.DATE
AND ADJ.VCODE = AM.VCODE AND ADJ.LGR_ID = AM.LGR_ID AND ADJ.BILLNO = AM.BILLNO 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE ADJ.RECDATE='"+@RECDATE+"' and AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+" /*AND AM.RECDATE='"+@RECDATE+"' */ 
AND AM.TYPE IN ('J','CN','DN') 

UNION ALL
"
ELSE 
SET @SQL2="
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,AM.SRNO,AM.ENTRYCODE ,AM.VCODE,AM.LGR_ID,
AM.BILLNO,AM.TYPE,AM.FLAG,AM.DATE,AM.RECDATE,AM.CHEQUENO,AM.CHEQUEDATE,0 as AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,
AM.OTHERLESS,AM.TOTAL,AM.ADJUSTAMT,AM.INTEREST,AM.INTREC,AM.PAID,AM.CMP_CODE,AM.REMARK,AM.RECEIPT_ID,
(CASE WHEN AM.TYPE IN('CN') THEN ('** RATE DIFFRENCE ** CR NO : ' + CONVERT(NVARCHAR(20),AM.CHEQUENO))
WHEN AM.TYPE IN('DN') THEN ('** RATE DIFFRENCE ** DR NO : ' + CONVERT(NVARCHAR(20),AM.CHEQUENO)) 
ELSE ('DD/CHQ. ' + AM.CHEQUENO + ' DATE : ' + CONVERT(NVARCHAR(20),AM.RECDATE,103) + 'JV NO ' +CONVERT(NVARCHAR(20),AM.CHEQUENO) ) END) AS NARRATION,
3 AS ORD
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+"  
AND AM.TYPE IN ('J','CN','DN') 

UNION ALL
"
IF @CONDITION='2'
SET @SQL3="

SELECT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,AM.SRNO,AM.ENTRYCODE,AM.VCODE,AM.LGR_ID,
AM.BILLNO,AM.TYPE,AM.FLAG,AM.DATE,AM.RECDATE,AM.CHEQUENO,AM.CHEQUEDATE,0 as AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,
AM.OTHERLESS,AM.TOTAL,(AM.ADJUSTAMT+AM.INTREC) AS ADJUSTAMT,AM.INTEREST,AM.INTREC,AM.PAID,AM.CMP_CODE,AM.REMARK,AM.RECEIPT_ID,
('DD/CHQ. ' + AM.CHEQUENO + ' DATE : ' + CONVERT(NVARCHAR(20),AM.RECDATE,103) ) AS NARRATION,
4 AS ORD
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+"  
AND AM.TYPE IN ('BR','CR') 

UNION ALL

SELECT LM.LGR_NAME AS PARTY,LM.LGR_ADD1 AS ADD1,LM.LGR_ADD2 AS ADD2,LM.LGR_ADD3 AS ADD3,CM.CITY_NAME AS PARTYCITY,
SM.STATE_NAME AS STATE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,AM.SRNO,AM.ENTRYCODE,AM.VCODE,AM.LGR_ID,
AM.BILLNO,AM.TYPE,AM.FLAG,AM.DATE,AM.RECDATE,AM.CHEQUENO,AM.CHEQUEDATE,0 as AMOUNT,AM.DISC_PER,AM.DISCOUNT,
AM.OTHERLESS,AM.TOTAL,AM.DISCOUNT AS ADJUSTAMT,AM.INTEREST,AM.INTREC,AM.PAID,AM.CMP_CODE,AM.REMARK,AM.RECEIPT_ID,
('DISCOUNT A/C              PERCENTAGE ' +CONVERT(NVARCHAR(20),AM.DISC_PER) ) AS NARRATION,
5 AS ORD
FROM "+@DATABASENAME+"ADJMASTER AM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AM.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN +"
WHERE AM.LGR_ID = "+@PARTYID+" AND AM.CMP_CODE="+@CMP_CODE+" 
AND AM.TYPE IN ('BR','CR') AND AM.DISCOUNT > 0
ORDER BY AM.DATE,AM.BILLNO,ORD
"




EXEC (@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
END




















GO

