/* 
PROC_BALANCENOTE2 'ACC2010_2011.DBO.',1,1,10 
*/
CREATE PROCEDURE [dbo].[PROC_BALANCENOTE2]	
(
   @DATABASENAME AS NVARCHAR(50),   
   @CMP_CODE as NVARCHAR(20),
   @FROMBALNOTENO as NVARCHAR(20),
   @TOBALNOTENO as NVARCHAR(20)
)
AS

DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
BEGIN
     SET @SQL1="
                SELECT BNOTENO,BNOTEDATE,BILLNO,FLAG,DATE,TYPE,AMOUNT ,ISNULL(INTEREST,0) AS INTEREST,ISNULL(DISCOUNT,0) AS DISCOUNT,ISNULL(OTHER,0)AS OTHER,ISNULL(INTREC,0) AS INTREC 
                       ,ISNULL(TOTAL,0)AS TOTAL,CHEQUENO,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT
                       FROM  "+@DATABASENAME+"BALANCENOTE BN
                       LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=BN.LGR_ID
                       LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
                       LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.CMP_CODE=BN.CMP_CODE AND LM.LGR_ID=LD.LGR_ID AND FLAG='BILL'
                       LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                       WHERE BN.CMP_CODE IN("+@CMP_CODE+") AND  BN.BNOTENO BETWEEN "+ @FROMBALNOTENO +" AND "+@TOBALNOTENO+"
                       ORDER BY BNOTENO,DATE,BILLNO
                       "
END
EXEC (@SQL1)
PRINT @SQL1




















GO

