/*

PROC_BALANCESHEET '1','ACC2012_2013.DBO.','31/MAR/2013'
*/
CREATE PROCEDURE [dbo].[PROC_BALANCESHEET]
(
    @CMP_CODE NVARCHAR(10),
    @DATABASENAME NVARCHAR(50),
    @TODATE AS NVARCHAR(20)
	
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""


BEGIN
SET NOCOUNT ON;
        
		SELECT @SQL=" 
SELECT MAINGRP,SUBGRP,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY,
CONVERT(NUMERIC(18,2),DRAMOUNT) AS DRAMOUNT,CONVERT(NUMERIC(18,2),CRAMOUNT) AS CRAMOUNT,
(CASE WHEN MAINGRP = 'CAPITAL' THEN 1 WHEN MAINGRP = 'CURRENT LIABILITY' THEN 2 
WHEN MAINGRP = 'LOANS(LIABILITIES)' THEN 3 WHEN MAINGRP = 'FIXED ASSETS' THEN 4
WHEN MAINGRP = 'CURRENT ASSETS' THEN 5 END) AS ORD					
 FROM (
SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,
	LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
	CASE WHEN LGR_OP_DRCR='D' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
	CASE WHEN LGR_OP_DRCR='C' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS CRAMOUNT,'' AS ORD
FROM "+@DATABASENAME+"LEDGER_MASTER LM INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID
	INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE LD.CMP_CODE="+@CMP_CODE+" AND LD.LGR_OP_BAL>0 AND GM.GRP_ACC_TYPE IN ('L','A') AND GM.GRP_NAME NOT IN('STOCK IN HAND')
UNION ALL

SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,
	TM.TRAN_MASTER_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
	(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
	(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,'' AS ORD
FROM "+@DATABASENAME+"TRAN_MASTER TM  
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
	INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
	INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE <> 'J' 
	AND TM.TRAN_DATE <= '"+@TODATE+"' AND GM.GRP_ACC_TYPE IN ('L','A') AND TM.TRAN_AMOUNT>0

UNION ALL

SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, 
	TD.TRAN_DETAIL_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
	(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
	(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,'' AS ORD
FROM "+@DATABASENAME+"TRAN_MASTER TM INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID 
	AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE 
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
	INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE<> 'J'  
	AND TM.TRAN_DATE <= '"+@TODATE+"' AND GM.GRP_ACC_TYPE IN ('L','A') AND TD.TRAN_AMOUNT>0

UNION ALL
"
		
	SELECT @SQL1="	SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, 
	AJ.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
	AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,'' AS ORD
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
	INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AJ.CMP_CODE=LD.CMP_CODE
	INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE AJ.VDATE <='"+@TODATE+"'
	AND AJ.CMP_CODE ="+@CMP_CODE+" AND GM.GRP_ACC_TYPE IN ('L','A') AND (AJ.DRAMOUNT>0  OR  AJ.CRAMOUNT > 0)

UNION ALL

SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, 
	TD.TRAN_DETAIL_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
	(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT  ELSE 0 END ) AS DRAMOUNT,
	(CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT   ELSE 0 END ) AS CRAMOUNT,'' AS ORD
FROM "+@DATABASENAME+"TRAN_MASTER TM INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID 
	AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
	INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
	INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE TM.CMP_CODE="+@CMP_CODE+"  AND TM.TRAN_DATE <='"+@TODATE+"' 
	AND TM.TRAN_TYPE  IN ('J','DN','CN') AND GM.GRP_ACC_TYPE IN ('L','A') AND TD.TRAN_AMOUNT>0
UNION ALL
					"

SELECT @SQL2="	 SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,
                 PCM.CITY_NAME AS PARTYCITY, VE.AMOUNT AS DRAMOUNT,  0 AS CRAMOUNT,'' AS ORD
       
       FROM  "+@DATABASENAME+"LEDGER_MASTER LM
       INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
       INNER JOIN  "+@DATABASENAME+"VALUATIONENTRY VE ON LD.LGR_ID=VE.LGR_ID AND LD.CMP_CODE=VE.CMP_CODE 
       INNER JOIN  "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID 
LEFT JOIN   "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
WHERE LD.CMP_CODE="+@CMP_CODE+" AND GM.GRP_NAME IN ('STOCK IN HAND')  AND  VE.MONTH  = MONTH('"+@TODATE+"') AND VE.AMOUNT>0
) AS DETAIL 
ORDER BY ORD,PARTYNAME,PARTYID
"

END
EXEC(@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2



















GO

/****** Object:  StoredProcedure [dbo].[PROC_BALANCESHEET_WITH_OPGRP]    Script Date: 03/30/2023 12:08:10 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/*
PROC_BALANCESHEET_WITH_OPGRP '2','acc2010_2011.dbo.','12/jan/2010'
*/
CREATE PROCEDURE [dbo].[PROC_BALANCESHEET_WITH_OPGRP]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @TODATE NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
BEGIN
	SET NOCOUNT ON;
    SET @SQL="
                SELECT (CASE WHEN  BALANCE<0 THEN OPPGROUPMAIN ELSE MainGrp END ) AS MAINGROUP,(CASE WHEN BALANCE<0 THEN OPPGROUP ELSE SUBGRP END) AS SUB_GROUP
                ,(CASE WHEN  (BALANCE<0 AND GRPTYPE='L') THEN 'A' WHEN (BALANCE<0 AND GRPTYPE='A') THEN 'L' ELSE GRPTYPE  END ) AS GRPTYPE
               ,PARTYID,PARTYNAME,PARTYCITY,ABS(BALANCE)  AS BALANCE
                FROM(
                SELECT MainGrp,OPPGROUP,OPPGROUPMAIN,SUBGRP,GrpType,PARTYID,PARTYNAME,PARTYCITY,
                (CASE WHEN GRPTYPE='L' THEN (SUM(CRAMOUNT) -SUM(DRAMOUNT))ELSE (SUM(DRAMOUNT) -SUM(CRAMOUNT)) END)AS BALANCE,SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT
                FROM(
                        Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType,
						LM.Lgr_Id As PartyId,LM.Lgr_Name As PartyName,PCM.City_Name As PartyCity,
						Case When Lgr_Op_DrCr='D' Then Lgr_Op_Bal When Lgr_Op_DrCr='' Then Lgr_Op_Bal Else 0 End As DrAMOUNT,
						Case When Lgr_Op_DrCr='C' Then Lgr_Op_Bal When Lgr_Op_DrCr='' Then Lgr_Op_Bal Else 0 End As CrAMOUNT
					    From "+@DATABASENAME+"Ledger_Master LM 
                        INNER JOIN "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id
						INNER JOIN "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID                        
						LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_Id=PCM.City_Id
					    Where LD.Cmp_code in("+@CMP_CODE+") And LD.Lgr_Op_Bal>0 And GM.Grp_ACC_Type in ('L','A') AND GM.grp_Name NOT IN('Stock In Hand')
					  UNION ALL
					    Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType,
						TM.TRan_Master_Id As PartyId,LM.Lgr_Name as PartyName,PCM.City_Name As PartyCity,
						(CASE WHEN TM.Tran_DrCr = 'D' THEN  TM.Tran_Amount ELSE 0 END) as DrAMOUNT ,
						(CASE WHEN TM.Tran_DrCr= 'C' THEN TM.Tran_Amount ELSE 0 END) as CrAMOUNT
					    From "+@DATABASENAME+"Tran_Master TM 
						INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TM.TRan_Master_Id = LM.Lgr_Id  
						INNER JOIN "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id And TM.Cmp_Code=LD.Cmp_Code
						INNER JOIN "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID
						LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_ID=PCM.City_Id
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID
					    Where TM.Cmp_Code in("+@CMP_CODE+") And TM.Tran_Type <> 'J' 
						And TM.TRan_Date <= '"+@TODATE+"' And GM.Grp_ACC_Type in ('L','A') And TM.Tran_Amount>0
                        "
SET @SQL1="             UNION ALL
					    Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType, 					
						TD.Tran_Detail_Id As PartyId,LM.Lgr_Name as PartyName,PCM.City_Name As PartyCity,
						(CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT ,
						(CASE WHEN TD.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT
					    From "+@DATABASENAME+"Tran_Master TM INNER JOIN "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_ID= TD.Tran_ID 
						AND TM.Tran_Type= TD.Tran_Type AND TM.Cmp_Code= TD.Cmp_Code 
						INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON TM.Tran_Master_Id= LM1.Lgr_Id
						INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_Id= LM.Lgr_Id
						INNER JOIN "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id And TM.Cmp_Code=LD.Cmp_Code
						INNER JOIN "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID
						LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_ID=PCM.City_Id
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID
					    Where TM.Cmp_Code in("+@CMP_CODE+") And TM.Tran_Type<> 'J'  
						And TM.Tran_Date <= '"+@TODATE+"' And GM.Grp_ACC_Type in ('L','A') And TD.Tran_Amount>0
					UNION ALL
						Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType, 
						AJ.Lgr_Id As PartyId,LM.Lgr_Name as PartyName,PCM.City_Name As PartyCity,
						AJ.DrAmount AS DrAMOUNT,AJ.CrAmount AS CrAMOUNT
					    From "+@DATABASENAME+"AutoJournal AJ 
						INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON AJ.Lgr_Id = LM.Lgr_Id  
						INNER JOIN "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id And AJ.Cmp_Code=LD.Cmp_Code
						INNER JOIN "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID
						LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_ID=PCM.City_Id
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID
					    Where AJ.VDate <='"+@TODATE+"'
						And AJ.Cmp_Code in("+@CMP_CODE+") And GM.Grp_ACC_Type in ('L','A') And (AJ.DrAmount>0  or  AJ.CrAmount > 0)
  "
SET @SQL2="				UNION ALL
    					Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType, 
						TD.Tran_Detail_Id As PartyId,LM.Lgr_Name as PartyName,PCM.City_Name As PartyCity,
						(CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount  ELSE 0 END ) AS DrAMOUNT,
						(CASE WHEN TD.Tran_drcr = 'C' THEN TD.Tran_Amount   ELSE 0 END ) AS CrAMOUNT
	    				From "+@DATABASENAME+"Tran_Master TM INNER JOIN "+@DATABASENAME+"Tran_Detail TD ON TD.TRan_Id= TM.TRan_Id 
						And TD.Tran_Type = TM.Tran_Type AND TD.Cmp_Code= TM.Cmp_Code  
						INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_Id= LM.Lgr_Id 
						INNER JOIN "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id And TM.Cmp_Code=LD.Cmp_Code
						INNER JOIN "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID
						LEFT JOIN "+@DATABASENAME+"City_Master PCM ON LM.City_ID=PCM.City_Id
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID
		    			Where TM.Cmp_Code in("+@CMP_CODE+")  And TM.Tran_Date <='"+@TODATE+"' 
						And TM.Tran_Type  In ('J','DN','CN') And GM.Grp_ACC_Type in ('L','A') And TD.Tran_Amount>0
                     union all					
	                    Select GM.Grp_Main_Name As MainGrp,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.grp_Name As SubGrp,GM.Grp_ACC_Type As GrpType, LM.Lgr_Id As PartyId,LM.Lgr_Name As PartyName,
                        PCM.City_Name As PartyCity, VE.Amount as DrAMOUNT,  0 as CrAMOUNT                            
                        From  "+@DATABASENAME+"Ledger_Master LM
                        INNER JOIN  "+@DATABASENAME+"Ledger_Detail LD ON LM.Lgr_Id=LD.Lgr_Id 
                        INNER JOIN  "+@DATABASENAME+"ValuationEntry VE ON LD.Lgr_Id=VE.Lgr_Id and ld.cmp_Code=ve.cmp_Code 
                        INNER JOIN  "+@DATABASENAME+"Group_Master GM ON LD.Grp_ID=GM.Grp_ID 
                        LEFT JOIN   "+@DATABASENAME+"City_Master PCM ON LM.City_Id=PCM.City_Id 
                        INNER JOIN "+@DATABASENAME+"Group_Master OGM ON OGM.Grp_ID=GM.OP_GRP_MAIN_ID
                        INNER JOIN "+@DATABASENAME+"Group_Master OGMM ON OGMM.Grp_ID=OGM.GRP_MAIN_ID
                        Where LD.Cmp_code in("+@CMP_CODE+") And GM.grp_Name in ('Stock In Hand')  And  VE.Month  = month('"+@TODATE+"') And VE.Amount>0
             
)AS DETAIL

GROUP BY MAINGRP,SUBGRP,OPPGROUP,OPPGROUPMAIN,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY
HAVING (SUM(CRAMOUNT) -SUM(DRAMOUNT))<>0
) AS DETAIL
ORDER BY PARTYNAME
  "   
END

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2





















GO

