/*
=============================================
ALTER_AUTHOR  : <BIREN>
ALTER_DATE    : <06/11/2012,5:39 PM>
EDIT_DATE      : <01/08/2013,11:17 PM>
EDIT_AUTHOE    : <BIREN>
CRYSTAL_REPORT : <PROC_BALANCESHEETSUMMWITHOPGRP>
REPORT_FORM    : <RFRMBALANCESHEETSUMMARY>
=============================================
PROC_BALANCESHEETSUMMWITHOPGRP '1','ACC2012_2013.DBO.','31/MAR/2013'
*/
CREATE PROCEDURE [dbo].[PROC_BALANCESHEETSUMMWITHOPGRP]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@TODATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""


BEGIN
SET NOCOUNT ON;

SELECT @SQL = " 
				SELECT MAINGROUP,SUBGRP,FIN_GRPTYPE,SUM(BALANCE) AS BALANCE,ORD FROM (
				SELECT MAINGROUP,SUB_GROUP AS SUBGRP,GRPTYPE AS FIN_GRPTYPE,PARTYID AS PARTYID,PARTYNAME AS PARTYNAME,PARTYCITY AS PARTYCITY,
				CONVERT(NUMERIC(18,2),BALANCE) AS BALANCE,
				(CASE WHEN MAINGROUP = 'CAPITAL' THEN 1 WHEN MAINGROUP = 'CURRENT LIABILITY' THEN 2 
				WHEN MAINGROUP = 'LOANS(LIABILITIES)' THEN 3 WHEN MAINGROUP = 'FIXED ASSETS' THEN 4  
				WHEN MAINGROUP = 'CURRENT ASSETS' THEN 5 END) AS ORD  FROM (

				SELECT (CASE WHEN  BALANCE<0 AND ISNULL(OPPGROUPMAIN,'')<>'' THEN OPPGROUPMAIN ELSE MAINGRP END ) AS MAINGROUP,
				(CASE WHEN BALANCE<0 AND ISNULL(OPPGROUPMAIN,'')<>'' THEN OPPGROUP ELSE SUBGRP END) AS SUB_GROUP  ,
				(CASE WHEN  (BALANCE<0 AND GRPTYPE='L') THEN 'A' WHEN (BALANCE<0 AND GRPTYPE='A') THEN 'L' ELSE GRPTYPE  END ) AS GRPTYPE  ,
				PARTYID,PARTYNAME,PARTYCITY,ABS(BALANCE)  AS BALANCE,'' AS ORD  FROM(  

				SELECT MAINGRP,OPPGROUP,OPPGROUPMAIN,SUBGRP,GRPTYPE,
				PARTYID AS PARTYID,PARTYNAME AS PARTYNAME,PARTYCITY AS PARTYCITY,  
				(CASE WHEN GRPTYPE='L' THEN (SUM(CRAMOUNT) -SUM(DRAMOUNT))ELSE (SUM(DRAMOUNT) -SUM(CRAMOUNT)) END)AS BALANCE,
				SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT  FROM(  

				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,
				GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,  LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,
				PCM.CITY_NAME AS PARTYCITY,  
				CASE WHEN LGR_OP_DRCR='D' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS DRAMOUNT, 
				CASE WHEN LGR_OP_DRCR='C' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS CRAMOUNT 

				FROM "+@DATABASENAME+"LEDGER_MASTER LM  
				INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
				INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID 
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID 
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID  
				WHERE LD.CMP_CODE IN("+@CMP_CODE+") AND LD.LGR_OP_BAL>0 AND GM.GRP_ACC_TYPE IN ('L','A') 
				AND GM.GRP_NAME NOT IN('STOCK IN HAND')

				UNION ALL

				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,
				GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,  TM.TRAN_MASTER_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,
				PCM.CITY_NAME AS PARTYCITY,  (CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT , 
				(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
  
				FROM "+@DATABASENAME+"TRAN_MASTER TM  
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID    
				INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE  
				INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID  
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID 
				WHERE TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_TYPE <> 'J'   AND TM.TRAN_DATE <= '"+@TODATE+"'
				AND GM.GRP_ACC_TYPE IN ('L','A') AND TM.TRAN_AMOUNT>0  
				"

SELECT @SQL1 = " UNION ALL
				  
				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,GM.GRP_NAME AS SUBGRP,
				GM.GRP_ACC_TYPE AS GRPTYPE, TD.TRAN_DETAIL_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,  
				(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
				(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT  
				FROM "+@DATABASENAME+"TRAN_MASTER TM 
				INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID   AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE   
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID  
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID  
				INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE  
				INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID  
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID  
				WHERE TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_TYPE<> 'J'    AND TM.TRAN_DATE <= '"+@TODATE+"'
				AND GM.GRP_ACC_TYPE IN ('L','A') AND TD.TRAN_AMOUNT>0  

				UNION ALL
				  
				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,
				GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,   AJ.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,  AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT  
				FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
				INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AJ.CMP_CODE=LD.CMP_CODE 
				INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID  LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID 
				WHERE AJ.VDATE <='"+@TODATE+"'  AND AJ.CMP_CODE IN("+@CMP_CODE+") AND GM.GRP_ACC_TYPE IN ('L','A') 
				AND (AJ.DRAMOUNT>0  OR  AJ.CRAMOUNT > 0) 

				UNION ALL 

				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,
				GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,TD.TRAN_DETAIL_ID AS PARTYID,
				LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
				(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT  ELSE 0 END ) AS DRAMOUNT,
				(CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT   ELSE 0 END ) AS CRAMOUNT  

				FROM "+@DATABASENAME+"TRAN_MASTER TM
				INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
				INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE 
				INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID 
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID 
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID 
				WHERE TM.CMP_CODE IN("+@CMP_CODE+")  AND TM.TRAN_DATE <='"+@TODATE+"'
				AND TM.TRAN_TYPE  IN ('J','DN','CN') AND GM.GRP_ACC_TYPE IN ('L','A') AND TD.TRAN_AMOUNT>0  
				"

SELECT @SQL2 = " UNION ALL

				SELECT GM.GRP_MAIN_NAME AS MAINGRP,OGM.GRP_NAME AS OPPGROUP,OGMM.GRP_NAME AS OPPGROUPMAIN,
				GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,  
				PCM.CITY_NAME AS PARTYCITY, VE.AMOUNT AS DRAMOUNT,  0 AS CRAMOUNT  
				FROM "+@DATABASENAME+"LEDGER_MASTER LM
				INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID  
				INNER JOIN  "+@DATABASENAME+"VALUATIONENTRY VE ON LD.LGR_ID=VE.LGR_ID AND LD.CMP_CODE=VE.CMP_CODE   
				INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID   
				LEFT JOIN  "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID   
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGM ON OGM.GRP_ID=GM.OP_GRP_MAIN_ID  
				LEFT JOIN "+@DATABASENAME+"GROUP_MASTER OGMM ON OGMM.GRP_ID=OGM.GRP_MAIN_ID  
				WHERE LD.CMP_CODE IN("+@CMP_CODE+") AND GM.GRP_NAME IN ('STOCK IN HAND')  
				AND  VE.MONTH  = MONTH('"+@TODATE+"') AND VE.AMOUNT>0 

				) AS FIRST_DETAIL 
					GROUP BY MAINGRP,SUBGRP,OPPGROUP,OPPGROUPMAIN,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY  
					HAVING (SUM(CRAMOUNT) -SUM(DRAMOUNT))<>0  
				) AS SECOND_DETAIL  
				) AS THIRD_DETAIL 
					GROUP BY MAINGROUP,SUB_GROUP,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY,BALANCE 
					HAVING CONVERT(NUMERIC(18,2),BALANCE) <> 0
				) AS MAINDETAIL
					GROUP BY ORD,MAINGROUP,SUBGRP,FIN_GRPTYPE
					ORDER BY ORD,MAINGROUP,SUBGRP
				"

END
EXEC(@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2





















GO

