/*
PROC_BALECHK_PCK '0,1,2', N'Acc2010_2011.Dbo.', N'01/Apr/2010', N'27/Oct/2010', N'##3100', 1
*/



CREATE PROCEDURE [dbo].[PROC_BALECHK_PCK]
(
   @CMP_CODE  NVARCHAR(50),
   @DATABASENAME  NVARCHAR(100),
   @FROMDATE  NVARCHAR(20),
   @TODATE  NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @SELECTION AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @SELECTION=""


   BEGIN
        IF @RPT_WISE =1 
           BEGIN
			 SET @SELECTION="  BCM.BALECHECKER_NAME AS MAINNAME,"
			 SET @JOINSQL=" INNER  JOIN "+@DATABASENAME+"BALECHECKER_MASTER  BCM ON BCM.BALECHECKER_ID=PS.BALECHECKER_ID
						    INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=BCM.BALECHECKER_ID
							"        
           END
        IF @RPT_WISE =2
           BEGIN
			 SET @SELECTION="  BPM.BALEPACK_NAME AS MAINNAME, "
			 SET @JOINSQL=" INNER  JOIN "+@DATABASENAME+"BALEPACK_MASTER  BPM ON BPM.BALEPACK_ID=PS.BALEPACK_ID
						    INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=BPM.BALEPACK_ID
						  "     
           END
   END
BEGIN	
	SET NOCOUNT ON;
SET @SQL="
          SELECT  "+@SELECTION+" PS.SERIALNO AS BALENO,PS.VCH_DATE AS DATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,
          IM.ITEM_NAME,PSD.TOTALPCS AS PCS,PSD.TOTAL AS MTRS,CMP.CMP_ALIAS,PS.SERIAL_ALIAS
          FROM "+@DATABASENAME+"PACKINGSLIP PS
         "+@JOINSQL+"
          INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
          INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
          INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
          LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
          LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
          
          WHERE PS.VCH_DATE  BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND PS.CMP_CODE IN ("+@CMP_CODE+")
          ORDER BY PS.SERIALNO,PS.VCH_DATE
       "
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_BALES_WISE_CLOSING_STOCK]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_BALES_WISE_CLOSING_STOCK  2,'ACC2010_2011.dbo.',##3024,'31/mar/2011',2,4,1
*/
CREATE PROCEDURE [dbo].[PROC_BALES_WISE_CLOSING_STOCK]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@TempTable nvarchar(50),
@AsOnDate nvarchar(50),
@RptWise int,
@RptType int,
@SumDel int
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""
DECLARE @RPTTYPESQL AS NVARCHAR(4000) SET @RPTTYPESQL=""
DECLARE @GROUPBY AS NVARCHAR(4000) SET @GROUPBY=""

BEGIN	
IF @RptWise=1 
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.BALENO "
		SET @GROUPBY=" GROUP BY IM.Item_Name,STD.BALENO,STD.RATE Order by convert(int,STD.BALENO),IM.Item_Name "
	END
ELSE IF @RptWise=2
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID "
		SET @GROUPBY=" GROUP BY IM.Item_Name,STD.RATE Order by IM.Item_Name "
	END
ELSE IF @RptWise=3
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=SM.SCREEN_ID "
		SET @GROUPBY=" GROUP BY IM.Item_Name,SM.Screen_Name,STD.RATE Order by IM.Item_Name  "
	END
ELSE IF @RptWise=4
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id "
		SET @GROUPBY=" GROUP BY IM.Item_Name,IG.Item_Grp_NAME,STD.RATE  Order by IM.Item_Name "
	END
ELSE IF @RptWise=5
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IT.Item_Type_Id "
		SET @GROUPBY=" GROUP BY IM.Item_Name,IT.Item_Type_Name,STD.RATE  Order by IM.Item_Name "
	END
ELSE IF @RptWise in (6,7,8)
	BEGIN
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.RATE "
		SET @GROUPBY=" GROUP BY IM.Item_Name,STD.RATE  Order by STD.RATE,IM.Item_Name "
	END
END

BEGIN
IF @RptType=1
	SET @RPTTYPESQL=" AND STM.STOCKIN_TYPE='C' "
ELSE IF @RptType=2
	SET @RPTTYPESQL=" AND STM.STOCKIN_TYPE='O' "
ELSE IF @RptType=3
	SET @RPTTYPESQL=" AND STM.STOCKIN_TYPE='FP' "
ELSE IF @RptType=4
	SET @RPTTYPESQL=" AND STM.STOCKIN_TYPE='E' "
ELSE IF @RptType=5
	SET @RPTTYPESQL=""
END

BEGIN	
	SET NOCOUNT ON;
if @SumDel=1
	BEGIN	
		SET @SQL="
		select DISTINCT IM.Item_Name,STD.BALENO,STD.BALENO as BALES,STD.QUANTITY as QUANTITY,STD.RATE,STD.AMOUNT as AMOUNT,SM.Screen_Name,
		IG.Item_Grp_NAME as ItemGroup,IT.Item_Type_Name,STD.PIECES as PIECES,STD.ITEM_ID
		from "+@DataBase+" STOCKIN_MASTER STM
		INNER JOIN "+@DataBase+" STOCKIN_DETAIL STD ON STM.STOCKIN_ID=STD.STOCKIN_ID AND STD.STOCKIN_TYPE=STM.STOCKIN_TYPE
		left join "+@DataBase+" Item_Master IM ON STD.Item_Id=IM.Item_Id
		left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
		left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
		left join "+@DataBase+" Item_Type_Master IT on IT.Item_Type_Id=IM.Item_Type_Id
		"+@JOIN+"
		where STM.Cmp_Code in ("+@CmpCode+") and STM.VCHDATE<='"+@AsOnDate+"'
        AND STD.PENDINGQUANTITY>0
		"+@RPTTYPESQL+"
		Order by STD.BALENO
		"
	END
ELSE IF @SumDel=2
	BEGIN	
		SET @SQL="select IM.Item_Name,count(STD.BALENO) as BALENO,max(STD.BALENO) as BALES,sum(STD.QUANTITY) as QUANTITY,max(STD.RATE) as RATE
		,sum(STD.AMOUNT) as AMOUNT,max(SM.Screen_Name) as Screen_Name,max(IG.Item_Grp_NAME) as ItemGroup,max(IT.Item_Type_Name) as Item_Type_Name
		,sum(STD.PIECES) as PIECES,max(STD.ITEM_ID) as ITEM_ID
		from "+@DataBase+" STOCKIN_MASTER STM
		INNER JOIN "+@DataBase+" STOCKIN_DETAIL STD ON STM.STOCKIN_ID=STD.STOCKIN_ID
		left join "+@DataBase+" Item_Master IM ON STD.Item_Id=IM.Item_Id
		left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
		left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
		left join "+@DataBase+" Item_Type_Master IT on IT.Item_Type_Id=IM.Item_Type_Id
		"+@JOIN+"
		where STM.Cmp_Code in ("+@CmpCode+") and STM.VCHDATE<='"+@AsOnDate+"'
        AND STD.PENDINGQUANTITY>0
		"+@RPTTYPESQL+"
		"+@GROUPBY+"
		
		"
	END




END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

