CREATE PROCEDURE [dbo].[PROC_BANKHUNDI]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)

begin
    	SET NOCOUNT ON;
        set @sql=" 
				Select SIM.Sal_Inv_id,SIM.Sal_Inv_HundiNo,SIM.Sal_Inv_Bill_No,SIM.Sal_Inv_vdate,SIM.Sal_Inv_LrNo,SIM.Sal_Inv_LrDate,
				UPPER(SIM.Lgr_Bank) as Lgr_Bank,UPPER(SIM.Lgr_Post) as Lgr_Post,UPPER(SIM.Lgr_Branch) as Lgr_Branch,UPPER(SIM.Our_Bank) AS Our_Bank,UPPER(SIM.Our_Branch) AS Our_Branch,UPPER(SIM.Our_Post)AS Our_Post,
				SIM.Sal_Inv_NetTotal,UPPER(LM.Lgr_Name) As Partyname,UPPER(PCM.City_Name) As PartyCity,
				UPPER(TM.Transport_Name) as Transport_Name,UPPER(LM.Lgr_add1)as Lgr_add1,UPPER(LM.Lgr_add2)as Lgr_add2,UPPER(LM.Lgr_add3) as Lgr_add3, 
				UPPER(STM.City_Name) As Station,UPPER(CMP.cmp_Name)as cmp_Name,Cmp_Jurisdiction,cmp_Phone1,cmp_Phone2,cmp_fax,NM.Narration
				From "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Ledger_Master LM ON SIM.Lgr_id=LM.Lgr_Id
				INNER JOIN "+@DatabaseName+"Company_Master CMP ON CMP.cmp_code=SIM.Cmp_Code
				INNER JOIN "+ @TempTable + " TT on TT.Code=SIM.Sal_Inv_id 
				LEFT JOIN "+@DatabaseName+"Transport_Master TM ON SIM.Transport_Id=TM.Transport_Id
				LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_Id=PCM.City_Id
				LEFT JOIN "+@DatabaseName+"City_Master STM ON SIM.Station_Id=STM.City_Id
				LEFT JOIN "+@DatabaseName+"Narration_Master NM ON SIM.cmp_code=NM.cmp_code And NM.Type='BANK HUNDI'
				Where SIM.Cmp_Code = "+@Cmp_Code+"
					"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

