SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- AUTHOR:		<MAYAL SADHU>
-- CREATE_DATE: <15/OCT/2020>
-- DESCRIPTION:	<FOR BANK RECEIP>
-- REPORT NAME: <BANKRECEIP.RPT>
-- =============================================
PROC_BANKRECEIPTREG '01/APR/2020', N'15/oct/2020',  N'ACC2020_2021.DBO.',N'1	', N'##5136',2,0,5000
*/

CREATE PROCEDURE [dbo].[PROC_BANKRECEIPTREG]
(
	@FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100),    
    @TEMPTABLE NVARCHAR(20),
	@RPT_WISE INT,
	@RPTTYPE AS INT,
	@TotalAmt NVARCHAR(50)

	
)
AS

DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @SQLCOND AS NVARCHAR(100)


SET @SELECTED=""
SET @SQL=""
SET @SQLCOND = ""

BEGIN
	IF @RPTTYPE = 0 /* ALL */
		SET @SQLCOND = " AND  TD.TRAN_TYPE IN('BR','CR')  "
	ELSE IF @RPTTYPE = 1 /* PENDING */
		SET @SQLCOND = " AND  TD.TRAN_TYPE IN ('BP','CP') "

END


SET NOCOUNT ON;
BEGIN

	IF @RPT_WISE IN (1)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON LD.AGENT_ID=TT.CODE"
			 END 
	ELSE IF @RPT_WISE IN (2)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON  LM.CUST_GRP_ID=TT.CODE"
			 END 
	ELSE IF @RPT_WISE IN (3)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON  LD.grp_Id=TT.CODE"
			 END 
    ELSE IF @RPT_WISE IN (4)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON  LM.LGR_ID=TT.CODE"
			 END 


			 
SET @SQL="	SELECT  ISNULL(TM.TRAN_DOCNO,'') AS DOCNO,CONVERT(NVARCHAR,TM.TRAN_DATE,103) AS DATE,ISNULL(TD.CHEQUENO,0) AS CHEQUENO,ISNULL(TM.TRAN_AMOUNT,0) AS AMOUNT,BLM.LGR_NAME AS BANKNAME,
    LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,LM.LGR_PANO AS PANNO,ALG.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.NARRATION,TD.REMARK,
	COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
    COMP.CMP_MOBILE,COMP.CMP_FAX,COMP.CMP_ALIAS,GP.GRP_NAME AS ACCOUNTNAME,TM.TRAN_TYPE,A.TOTALRCPT
	FROM "+@DATABASENAME+"TRAN_MASTER TM
	INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID  AND TD.CMP_CODE=TM.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON BLM.LGR_ID=TM.TRAN_MASTER_ID
	INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
	INNER JOIN (SELECT TRAN_DETAIL_ID, SUM(ISNULL(TD.TRAN_AMOUNT,0)) AS TOTALRCPT FROM "+@DATABASENAME+"TRAN_MASTER TM INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID  AND TD.CMP_CODE=TM.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE  WHERE TD.CMP_CODE IN ("+ @CMP_CODE +") " + @SQLCOND + " AND TM.TRAN_DATE  BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' GROUP BY TRAN_DETAIL_ID  ) AS A ON  TD.TRAN_DETAIL_ID = A.TRAN_DETAIL_ID
	LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID =LM.CITY_ID
    LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE=TM.CMP_CODE
	INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
    LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALG ON ALG.LGR_ID=LD.AGENT_ID
	LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALG.CITY_ID
	LEFT JOIN "+@DATABASENAME+"GROUP_MASTER GP ON GP.grp_Id = LD.grp_Id
	 " + @SELECTED +"
   	WHERE TM.TRAN_DATE  BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'  " + @SQLCOND + "
	AND TM.CMP_CODE IN ("+ @CMP_CODE +") AND  A.TOTALRCPT >="+@TOTALAMT+"
    ORDER BY TM.TRAN_DATE"

END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL
	





















GO

