/* 
PROC_BANKSLIPNEW 2,'acc2010_2011.dbo.',922,'C','01/apr/2010','31/mar/2011','##2588'
*/
CREATE PROCEDURE [dbo].[PROC_BANKSLIPNEW]  
 (
  @CMP_CODE NVARCHAR(10),
  @DATABASENAME NVARCHAR(50),
  @BANKID NVARCHAR(20),
  @TYPE NVARCHAR(20),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20)
 ) 
 AS 
DECLARE @SQL  NVARCHAR(4000)    
BEGIN  
     SET NOCOUNT ON;   
       SET @SQL="
              SELECT BS.SLIPNO,BS.SLIPDATE,LM.LGR_NAME AS BANKNAME,BS.DDNO,BS.DDDATE,BS.CITY_ID,CM.CITY_NAME,BS.TYPE,BS.AMOUNT,BS.BANK,
              PLM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.LGR_CSTNO AS BANK_ACCNO,LM.LGR_ADD1 AS BANK_ADD1,LM.LGR_ADD2 AS BANK_ADD2,
			  LM.LGR_PHONE1 AS BANK_PHONE1,LM.LGR_PHONE2 AS BANK_PHONE2,LM.LGR_MOBILE AS BANK_MOBILE
              FROM "+@DATABASENAME+"BANKSLIP BS
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON BS.BANK_ID=LM.LGR_ID
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON BS.LGR_ID=PLM.LGR_ID
              INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=BS.SLIPNO
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON BS.CITY_ID=CM.CITY_ID
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
              WHERE BS.CMP_CODE="+@CMP_CODE+" AND BS.TYPE='"+@TYPE+"' AND BS.BANK_ID="+@BANKID+" 
              AND   BS.SLIPDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
              "  

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL 
END      










































