CREATE PROCEDURE [dbo].[PROC_BANKSLIPREPORT]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @AsOnDate as Nvarchar(20),
    @TempTable as Nvarchar(20),
    @BankId nvarchar(20),
	@Type nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)

begin
    	SET NOCOUNT ON;
        set @sql=" SELECT BS.SlipNo,BS.SlipDate,LM.Lgr_Name As BankName,BS.DDNo,BS.DDDate,
					BS.City_id,CM.City_Name,BS.Type,BS.Amount,BS.Bank
			    	FROM "+@DatabaseName+"BankSlip BS
                    INNER JOIN "+@DatabaseName+"Ledger_Master LM ON BS.BANK_Id=LM.Lgr_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=BS.SlipNo
					LEFT JOIN "+@DatabaseName+"City_Master CM ON BS.City_Id=CM.City_Id
				WHERE BS.cmp_code="+@Cmp_Code+" And BS.Type='"+@Type+"' And BS.BANK_Id="+@BankId+" And
					BS.SlipDate = '"+@AsOnDate+"' Order By BS.SrNo
					"
        execute Sp_Executesql @sql
        Print @sql
end






















































































































GO

