/*  
-- =============================================
-- CREEATE_AUTHOR    : <BIREN>
-- ALTER_DATE       : <12/06/2015 2:43 PM>
-- REPORT_FORM       : <RFRMBILLPARTYCHANGEREPORT.CS>
-- CRYSTAL_REPORT    : <BILLPARTYCHANGEREG.RPT>
-- =============================================  
PROC_BILLPARTYCHANGEREG '1','ACC2015_2016.DBO.',1,'01/APR/2015','01/MAR/2016','##6012'
*/   
CREATE PROCEDURE [dbo].[PROC_BILLPARTYCHANGEREG]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)

SET @SQL = ""
SET @SQL1=""
SET @SQL2=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL=""

IF @RPT_WISE = 1 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM_N.LGR_ID "
SET @ORDERSQL = "LM_N.LGR_NAME,LM_N.LGR_ID,"
END

ELSE IF @RPT_WISE = 2 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM_O.LGR_ID "
SET @ORDERSQL = "LM_O.LGR_NAME,LM_O.LGR_ID,"
END

ELSE IF @RPT_WISE = 3
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CM_N.CITY_ID "
SET @ORDERSQL = "CM_N.CITY_NAME,CM_N.CITY_ID,"
END

ELSE IF @RPT_WISE = 4
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CM_O.CITY_ID "
SET @ORDERSQL = "CM_O.CITY_NAME,CM_O.CITY_ID,"
END

ELSE IF @RPT_WISE = 5
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM_N.LGR_ID "
SET @ORDERSQL = "ALM_N.LGR_NAME,ALM_N.LGR_ID,"
END

ELSE IF @RPT_WISE = 6
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM_O.LGR_ID "
SET @ORDERSQL = "ALM_O.LGR_NAME,ALM_O.LGR_ID,"
END

ELSE IF @RPT_WISE = 7
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM_N.TRANSPORT_ID "
SET @ORDERSQL = "TM_N.TRANSPORT_NAME,TM_N.TRANSPORT_ID,"
END

ELSE IF @RPT_WISE = 8	
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM_O.TRANSPORT_ID "
SET @ORDERSQL = "TM_O.TRANSPORT_NAME,TM_O.TRANSPORT_ID,"
END

ELSE IF @RPT_WISE = 9 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM_N.CITY_ID "
SET @ORDERSQL = "SM_N.CITY_NAME,SM_N.CITY_ID,"
END

ELSE IF @RPT_WISE = 10 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM_O.CITY_ID "
SET @ORDERSQL = "SM_O.CITY_NAME,SM_O.CITY_ID,"
END

ELSE IF @RPT_WISE = 11
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=BPC.SAL_INV_ID "
SET @ORDERSQL = ""
END

ELSE IF @RPT_WISE = 12
BEGIN
SET @JOINSQL=" "
SET @ORDERSQL = ""
END



BEGIN
SET NOCOUNT ON;

BEGIN
SET @SQL =  "
SELECT SAL_INV_ID,SAL_INV_BILL_NO,ISNULL(CONFNO,0) AS CONFNO,ISNULL(REMARK,'') AS REMARK,
CONVERT(NVARCHAR,ADJDATE,103) AS ADJDATE,
ISNULL(LM_O.LGR_ID,0) AS OLD_PARTYID,ISNULL(LM_N.LGR_ID,0) AS NEW_PARTYID,
ISNULL(CM_O.CITY_ID,0) AS OLD_PARTY_CITYID,ISNULL(CM_N.CITY_ID,0) AS NEW_PARTY_CITYID,
ISNULL(ALM_O.LGR_ID,0) AS OLD_AGENTID,ISNULL(ALM_N.LGR_ID,0) AS NEW_AGENTID,
ISNULL(TM_O.TRANSPORT_ID,0) AS OLD_TRANSPORTID,ISNULL(TM_N.TRANSPORT_ID,0) AS NEW_TRANSPORTID,
ISNULL(SM_O.CITY_ID,0) AS OLD_STATIONID,ISNULL(SM_N.CITY_ID,0) AS NEW_STATIONID,
ISNULL(LM_O.LGR_NAME,'') AS OLD_PARTY,ISNULL(LM_N.LGR_NAME,'') AS NEW_PARTY,
ISNULL(CM_O.CITY_NAME,'') AS OLD_PARTY_CITY,ISNULL(CM_N.CITY_NAME,'') AS NEW_PARTY_CITY,
ISNULL(ALM_O.LGR_NAME,'') AS OLD_AGENT,ISNULL(ALM_N.LGR_NAME,'') AS NEW_AGENT,
ISNULL(TM_O.TRANSPORT_NAME,'') AS OLD_TRANSPORT,ISNULL(TM_N.TRANSPORT_NAME,'') AS NEW_TRANSPORT,
ISNULL(SM_O.CITY_NAME,'') AS OLD_STATION,ISNULL(SM_N.CITY_NAME,'') AS NEW_STATION,
ISNULL(UM.USERID,0) AS USERID,ACC_MASTER.DBO.FN_DECRYPTSTRING(USERNAME) AS USERNAME,
ISNULL(COMP.CMP_ALIAS,'') AS CMP_ALIAS,
ISNULL(ACM_O.CITY_ID,0) AS OLD_AGENT_CITYID,ISNULL(ALM_N.CITY_ID,0) AS NEW_AGENT_CITYID,
ISNULL(ACM_O.CITY_NAME,'') AS OLD_AGENT_CITY,ISNULL(ACM_N.CITY_NAME,'') AS NEW_AGENT_CITY

FROM "+@DATABASENAME+"BILLPARTYCHANGE BPC
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM_O ON BPC.OLD_LGR_ID = LM_O.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM_N ON BPC.NEW_LGR_ID = LM_N.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM_O ON LM_O.CITY_ID = CM_O.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM_N ON LM_N.CITY_ID = CM_N.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM_O ON BPC.OLD_AGENT_ID = ALM_O.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM_N ON BPC.NEW_AGENT_ID = ALM_N.LGR_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM_O ON BPC.OLD_TRANSPORT_ID = TM_O.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM_N ON BPC.NEW_TRANSPORT_ID = TM_N.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SM_O ON BPC.OLD_STATION_ID = SM_O.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SM_N ON BPC.NEW_STATION_ID = SM_N.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON BPC.CMP_CODE = COMP.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM_O ON ALM_O.CITY_ID = ACM_O.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM_N ON ALM_N.CITY_ID = ACM_N.CITY_ID

LEFT JOIN ACC_MASTER.DBO.USERMASTER UM ON UM.USERID = BPC.USERID
WHERE BPC.CMP_CODE IN ("+@CMP_CODE+") AND ADJDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
ORDER BY "+@ORDERSQL+"CONVERT(INT,SAL_INV_BILL_NO )
"



END	

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_BRANCH_STOCK_REPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author:		<PRATIK PATEL>
-- Create_date: <26/06/2013>
-- Description:	<THIS PROC USED IN BRANCH STOCK REPORT>
-- =============================================
PROC_BRANCH_STOCK_REPORT   1,'ACC2013_2014.dbo.','01/apr/2013','31/mar/2014',##3364,1


*/

CREATE PROCEDURE [dbo].[PROC_BRANCH_STOCK_REPORT]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int
)
AS

DECLARE @StrSql as NVARCHAR(4000) set @STRSQL=""
DECLARE @StrJOIN as NVARCHAR(4000) set @StrJOIN=""
DECLARE @GRPBY as NVARCHAR(4000) set @GRPBY=""
DECLARE @MAINGRPBY as NVARCHAR(4000) set @MAINGRPBY=""
BEGIN 
IF 	@RptWise=1 
		BEGIN
		SET @StrJOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID"
		SET @GRPBY=" "
        SET @MAINGRPBY=" "
		END
else IF @RptWise=2
		BEGIN
		SET  @StrJOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IGM.ITEM_GRP_ID"
		SET @GRPBY=" ,IGM.ITEM_GRP_NAME "
        SET @MAINGRPBY=" ,ITEMGRP"
		END
else IF @RptWise=3
		BEGIN
		SET  @StrJOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
		SET @GRPBY=" ,ITM.ITEM_TYPE_NAME "
        SET @MAINGRPBY=" ,ITEMTYPE"
		END
else IF @RptWise=4
		BEGIN
		SET  @StrJOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IGM.ITEM_GRP_ID"
		SET @GRPBY=" ,IGM.ITEM_GRP_NAME "
        SET @MAINGRPBY=" ,ITEMGRP"
		END
else IF @RptWise=5
		BEGIN
		SET  @StrJOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
		SET @GRPBY=" ,ITM.ITEM_TYPE_NAME "
        SET @MAINGRPBY=" ,ITEMTYPE"
		END
END 

BEGIN
	SET NOCOUNT ON;
BEGIN
     SET @StrSql="SELECT ITEM,SUM(OPENINGSTOCK)OPENINGSTOCK,SUM(STOCKIN)STOCKIN,SUM(STOCKOUT)STOCKOUT,MAX(ITEMGRP)ITEMGRP,MAX(ITEMTYPE)ITEMTYPE 
FROM
(
SELECT ITEM_NAME AS ITEM,SUM(ISNULL(BRANCH_STOCK,0)) AS OPENINGSTOCK,0 AS STOCKIN,0 AS STOCKOUT,MAX(IGM.ITEM_GRP_NAME)ITEMGRP,MAX(ITM.ITEM_TYPE_NAME)ITEMTYPE 
 FROM "+@DataBase+"ITEM_OPENING_STOCK IOS
INNER JOIN "+@DataBase+"ITEM_MASTER IM ON IOS.ITEM_ID=IM.ITEM_ID 
INNER JOIN "+@DataBase+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DataBase+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
"+@StrJOIN+"
WHERE IOS.CMP_CODE IN ('"+@CmpCode+"') AND ISNULL(BRANCH_STOCK,0)<>0
GROUP BY ITEM_NAME"+@GRPBY+"
UNION ALL
SELECT ITEM_NAME AS ITEM,0 AS OPENINGSTOCK,SUM(QUANTITY) AS STOCKIN,0 AS STOCKOUT,MAX(IGM.ITEM_GRP_NAME)ITEMGRP,MAX(ITM.ITEM_TYPE_NAME)ITEMTYPE  
FROM "+@DataBase+"STOCKOUT_MASTER STM
INNER JOIN "+@DataBase+"STOCKOUT_DETAIL STD ON STD.STOCKOUT_ID=STM.STOCKOUT_ID
INNER JOIN "+@DataBase+"ITEM_MASTER IM ON IM.ITEM_ID = STD.ITEM_ID
INNER JOIN "+@DataBase+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DataBase+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
"+@StrJOIN+"
WHERE STM.CMP_CODE IN ('"+@CmpCode+"') AND VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
GROUP BY ITEM_NAME"+@GRPBY+"
UNION ALL
SELECT ITEM_NAME AS ITEM,0 AS OPENINGSTOCK,SUM(QUANTITY) AS STOCKIN,0 AS STOCKOUT,MAX(IGM.ITEM_GRP_NAME)ITEMGRP,MAX(ITM.ITEM_TYPE_NAME)ITEMTYPE   
FROM "+@DataBase+"STOCKOUT_MASTER STM
INNER JOIN "+@DataBase+"STOCKOUT_DETAIL STD ON STD.STOCKOUT_ID=STM.STOCKOUT_ID
INNER JOIN "+@DataBase+"ITEM_MASTER IM ON IM.ITEM_ID = STD.ITEM_ID
INNER JOIN "+@DataBase+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DataBase+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
"+@StrJOIN+"
WHERE STM.CMP_CODE IN ('"+@CmpCode+"') AND VCHDATE < '"+@FromDate+"'
GROUP BY ITEM_NAME"+@GRPBY+"
UNION ALL
SELECT IM.ITEM_NAME AS ITEM,0 AS OPENINGSTOCK,0 AS STOCKIN,SUM(SAL_INV_QTY) AS STOCKOUT,MAX(IGM.ITEM_GRP_NAME)ITEMGRP,MAX(ITM.ITEM_TYPE_NAME)ITEMTYPE  
 FROM "+@DataBase+"SALES_INVOICE SI
INNER JOIN "+@DataBase+"SALES_INVOICE_DETAIL SOD ON SOD.SAL_INV_ID=SI.SAL_INV_ID  
INNER JOIN "+@DataBase+"SERIES_MASTER SM ON SM.SERIES_ID=SI.SERIES_ID AND SM.CMP_CODE=SI.CMP_CODE  
INNER JOIN "+@DataBase+"ITEM_MASTER IM ON IM.ITEM_ID = SOD.ITEM_ID
INNER JOIN "+@DataBase+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DataBase+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
"+@StrJOIN+"
WHERE SI.SAL_INV_TYPE='B' AND SM.BRANCH_STOCK='1' AND SI.SAL_INV_VDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND SI.CMP_CODE IN ('"+@CmpCode+"')
GROUP BY IM.ITEM_NAME"+@GRPBY+"
UNION ALL
SELECT IM.ITEM_NAME AS ITEM,0 AS OPENINGSTOCK,0 AS STOCKIN,SUM(SAL_INV_QTY) AS STOCKOUT,MAX(IGM.ITEM_GRP_NAME)ITEMGRP,MAX(ITM.ITEM_TYPE_NAME)ITEMTYPE  
 FROM "+@DataBase+"SALES_INVOICE SI
INNER JOIN "+@DataBase+"SALES_INVOICE_DETAIL SOD ON SOD.SAL_INV_ID=SI.SAL_INV_ID  
INNER JOIN "+@DataBase+"SERIES_MASTER SM ON SM.SERIES_ID=SI.SERIES_ID AND SM.CMP_CODE=SI.CMP_CODE  
INNER JOIN "+@DataBase+"ITEM_MASTER IM ON IM.ITEM_ID = SOD.ITEM_ID
INNER JOIN "+@DataBase+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DataBase+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
"+@StrJOIN+"
WHERE SI.SAL_INV_TYPE='B' AND SM.BRANCH_STOCK='1' AND SI.SAL_INV_VDATE < '"+@FromDate+"' AND SI.CMP_CODE IN ('"+@CmpCode+"')
GROUP BY IM.ITEM_NAME"+@GRPBY+"

) AS DETAIL
GROUP BY ITEM"+@MAINGRPBY+""
END

END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @StrSql




















GO

