/*
-- =============================================
-- ALTER_AUTHOR  :	<PRATIK PATEL>
-- ALTER_DATE    : <11-08-2016 11:36 AM>
-- REPORT_FORM    :	<PRINT REPORT>
-- CRYSTAL_REPORT :	<BUNCH_PREPARATION_PLAIN_PRINT_REPORT.RPT>
-- =============================================

PROC_BUNCH_PREPARATION_DESIGN_REPORT 2,'ACC2016_2017.DBO.',16817,16817
*/
CREATE PROCEDURE [dbo].[PROC_BUNCH_PREPARATION_DESIGN_REPORT]
(
	@Cmp_Code nvarchar(50), 
	@DatabaseName nvarchar(50),
	@FromBillNo nvarchar(50),
	@ToBillNo nvarchar(50)
)
AS
DECLARE @SQL nvarchar(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT BPDS.BUNCHNO,BPDS.VCHDATE,BPDS.YEARFLAG,BPDS.BunchName_Id,BNM.BUNCHNAME,BPDS.REMARKS,DM.DESIGN_NAME,BPDS.DESIGN_THAN,BPDS.DESIGN_METER
FROM ACC2016_2017.DBO.BUNCHPREPARATION_DESIGNDETAIL BPDS
INNER JOIN ACC2016_2017.DBO.BUNCHPREPARATION BP ON BPDS.BunchPreId=BP.BunchPreId 
INNER JOIN ACC2016_2017.DBO.BUNCHNAME_MASTER BNM ON BNM.BUNCHNAME_ID=BPDS.BUNCHNAME_ID
INNER JOIN ACC2016_2017.DBO.DESIGN_MASTER DM ON DM.DESIGN_ID = BPDS.DESIGN_ID
WHERE BPDS.BUNCHNO BETWEEN "+@FromBillNo+" AND "+@ToBillNo+" AND BPDS.CMP_CODE="+@Cmp_Code+"
ORDER BY CONVERT(INT,BPDS.BUNCHNO),BPDS.SRNO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL





















GO

/****** Object:  StoredProcedure [dbo].[PROC_BUNCH_PREPARATION_PRINT_REPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/*
-- =============================================
-- ALTER_AUTHOR  :	<PRATIK PATEL>
-- ALTER_DATE    : <11-08-2016 11:36 AM>
-- REPORT_FORM    :	<PRINT REPORT>
-- CRYSTAL_REPORT :	<BUNCH_PREPARATION_PLAIN_PRINT_REPORT.RPT>
-- =============================================

PROC_BUNCH_PREPARATION_PRINT_REPORT 2,'ACC2016_2017.DBO.',3,3
*/
CREATE PROCEDURE [dbo].[PROC_BUNCH_PREPARATION_PRINT_REPORT]
(
	@Cmp_Code nvarchar(50), 
	@DatabaseName nvarchar(50),
	@FromBillNo nvarchar(50),
	@ToBillNo nvarchar(50)
)
AS
DECLARE @SQL nvarchar(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT BP.BUNCHNO,BP.VCHDATE,BP.YEARFLAG,LOT_NAME AS MARKANAME,CUT_NAME AS CUTNAME,
PM.PROCESS_NAME AS FROMPROCESS,TPM.PROCESS_NAME AS TOPROCESS,FLM.LGR_NAME AS FROMPARTY,
TLM.LGR_NAME AS TOPARTY,MM.MACHINE_NAME AS MACHINNAME,CTM.CONTRACTOR_NAME AS CONTRACTOR,
BP.NARRATION,LOM.LORIWALA_NAME AS LORIWALANAME,BATCHFINAL,
LOTNO,LO_FLAG,ENTRYTYPE,P2PMDOCNO,REFNO,BUNCHNAME,LRNO,LOTTHAN,LOTMETER,ISSUETHAN,ISSUEMETER,REMARKS
FROM "+@DatabaseName+"BUNCHPREPARATION BP
INNER JOIN "+@DatabaseName+"LOT_MASTER LM ON LM.LOT_ID=BP.LOT_ID
INNER JOIN "+@DatabaseName+"CUT_MASTER CM ON CM.CUT_ID=BP.CUT_ID 
INNER JOIN "+@DatabaseName+"PROCESS_MASTER PM ON PM.PROCESS_ID=BP.PROCESS_ID
INNER JOIN "+@DatabaseName+"PROCESS_MASTER TPM ON TPM.PROCESS_ID=BP.TO_PROCESS_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER FLM ON FLM.LGR_ID=BP.FROM_LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER TLM ON TLM.LGR_ID=BP.TO_LGR_ID
INNER JOIN "+@DatabaseName+"MACHINE_MASTER MM ON MM.MACHINE_ID=BP.MACHINE_ID
INNER JOIN "+@DatabaseName+"CONTRACTOR_MASTER CTM ON CTM.CONTRACTOR_ID =BP.CONTRACTOR_ID
INNER JOIN "+@DatabaseName+"LORIWALA_MASTER LOM ON LOM.LORIWALA_ID=BP.LORIWALA_ID
INNER JOIN "+@DatabaseName+"BUNCHPREPARATION_LRDETAIL BPL ON BPL.BUNCHPREID=BP.BUNCHPREID AND BPL.CMP_CODE=BP.CMP_CODE 
AND BPL.YEARFLAG=BP.YEARFLAG  AND BPL.BUNCHNO=BP.BUNCHNO 
INNER JOIN "+@DatabaseName+"BUNCHNAME_MASTER BNM ON BNM.BUNCHNAME_ID=BPL.BUNCHNAME_ID
WHERE BP.BUNCHNO BETWEEN "+@FromBillNo+" AND "+@ToBillNo+" AND BP.CMP_CODE="+@Cmp_Code+"
ORDER BY CONVERT(INT,BP.BUNCHNO),SRNO

"

    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL





















GO

/****** Object:  StoredProcedure [dbo].[PROC_BUNCHCOSTINGREPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/*
-- =============================================
-- AUTHOR:		<PRATIK PATEL>
-- ALTER DATE: <29-12-2016>
-- DESCRIPTION:	<BUNCHCOSTINGREPORT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_BUNCHCOSTINGREPORT 4,'ACC2016_2017.DBO.','01/APR/2016','31/MAR/2017','##2244',5,'###2244'
*/

CREATE PROCEDURE [dbo].[PROC_BUNCHCOSTINGREPORT]
(
  @CMP_CODE AS NVARCHAR(20),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE	AS NVARCHAR(100),
  @RPT_WISE AS INT,
  @TEMPTABLE1 	AS NVARCHAR(100)
  
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLJOIN1 AS NVARCHAR(4000)
SET @SQL=""                
SET @SQLJOIN=""
SET @SQLJOIN1=""

BEGIN
	IF @RPT_WISE=1 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PM.PROCESS_ID"
	ELSE IF @RPT_WISE=2 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2PD.BUNCHNO"
	ELSE IF @RPT_WISE=3 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=DM.DESIGN_ID"
	ELSE IF @RPT_WISE=4 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
	ELSE IF @RPT_WISE=5 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2PD.BUNCHNO"
	ELSE IF @RPT_WISE=6 
		SET @SQLJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
		
						
END
	
BEGIN
	IF @RPT_WISE=5 
		SET @SQLJOIN1="INNER JOIN "+@TEMPTABLE1+" TT1 ON TT1.CODE=DM.DESIGN_ID"
	ELSE IF @RPT_WISE=6 
		SET @SQLJOIN1="INNER JOIN "+@TEMPTABLE1+" TT1 ON TT1.CODE=P2PD.BUNCHNO"
	ELSE
		SET @SQLJOIN1=""
END

BEGIN	
	SET NOCOUNT ON;
       SET @SQL=" SELECT MAX(VCHDATE)VCHDATE,(PM.PROCESS_NAME) AS FROMPROCESS,MAX(TPM.PROCESS_NAME) AS TOPROCESS,MAX(LM.LGR_NAME) AS TOPARTY,
MAX(JLM.LGR_NAME) AS PROCESSPARTY,BUNCHNO,DM.DESIGN_ID,DM.DESIGN_NAME AS DESIGNNO,MAX(MM.LOT_NAME) AS GREYMARKA,
MAX(AMM.MACHINE_NAME)MACHINE_NAME,MAX(TOTALTHAN)TOTALTHAN,MAX(TOTALMETER)TOTALMETER,MAX(ISSUETHAN)ISSUETHAN,
MAX(ISSUEMETER)ISSUEMETER,IM.ITEM_NAME AS ITEM,UM.UNIT_NAME,MAX(QTY)QTY,MAX(ISNULL(IOS.PUR_RATE,0))PUR_RATE,
IM.ITEM_TYPE,MAX((QTY/TotalThan)*ISSUETHAN)AVG_QTY,CMP.CMP_ALIAS 
FROM "+@DATABASENAME+"PROCESS2PROCESS_DETAIL P2PD
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2PD.FROM_PROCESS_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER TPM ON TPM.PROCESS_ID=P2PD.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2PD.TO_LGR_ID
LEFT  JOIN "+@DATABASENAME+"LEDGER_MASTER JLM ON JLM.LGR_ID=P2PD.LGR_ID
INNER JOIN "+@DATABASENAME+"DESIGN_MASTER DM ON DM.DESIGN_ID=P2PD.DESIGN_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER MM ON MM.LOT_ID=P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+"MACHINE_MASTER AMM ON AMM.MACHINE_ID=P2PD.MACHINE_ID
INNER JOIN "+@DATABASENAME+"P2P_CHEMICALDETAIL CD ON CD.PROCESSID=P2PD.PROCESSID AND CD.FLAG=P2PD.FLAG AND CD.CMP_CODE=P2PD.CMP_CODE
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=CD.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=CD.UNIT_ID
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2PD.CMP_CODE
"+@SQLJOIN+"
"+@SQLJOIN1+"
WHERE P2PD.FLAG='P2PD'AND P2PD.CMP_CODE IN ("+@CMP_CODE+") 
AND VchDate BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'

GROUP BY BUNCHNO,DM.DESIGN_ID,DM.DESIGN_NAME,PM.PROCESS_NAME,ITEM_TYPE,ITEM_NAME,UNIT_NAME,CMP.CMP_ALIAS
ORDER BY BUNCHNO,DM.DESIGN_ID,DM.DESIGN_NAME,ITEM_TYPE
"
        
    
END
EXEC SP_EXECUTESQL @SQL
PRINT @SQL






















GO

