/*
-- =============================================
-- AUTHOR:		<PRATIK PATEL>
-- ALTER_DATE: 20/AUG/2016
-- DESCRIPTION:	PRINT OUT OF CASH VOUCHER PRINTOUT
-- =============================================
PROC_CASH_VOUCHER_PRINT_OUT '2','ACC2016_2017.DBO.','1','10'
*/
CREATE PROCEDURE [dbo].[PROC_CASH_VOUCHER_PRINT_OUT]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(20),
@FROMNO NVARCHAR(10),
@TONO NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""


BEGIN
SET NOCOUNT ON;
SET @SQL="
SELECT TRAN_DOCNO AS DOCNO,TRAN_DATE,LM.LGR_NAME AS PARTY,PART_BILL,PM.TRAN_AMOUNT,
PARTAMOUNT,CM.CITY_NAME AS PARTYCITY,REMARK,NARRATION,EM.EMPLOYEE_NAME AS EMPLOYEENAME,
BILLNO,DATE AS BILLDATE,DAYS,CRDAYS,PD.AMOUNT AS BILLAMOUNT,DISC_PER,DISCOUNT,RD,TOTAL,
ADJUSTAMT,INT_PER,INTEREST,INTREC,PAID,CMP_PHONE1,CMP_PHONE2,CMP_MOBILE,CMP_EMAIL,
LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,SM.STATE_NAME AS PARTY_STATE,CM.CITY_PINCODE,ALM.LGR_NAME AS AGENT
FROM "+@DATABASENAME+"PAYMENTVOUCHER_MASTER PM
LEFT JOIN "+@DATABASENAME+"PAYMENTVOUCHER_DETAIL PD ON PD.ENTRYCODE=PM.TRAN_ID AND PD.TYPE=PM.TRAN_TYPE  AND PD.CMP_CODE=PM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PM.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"EMPLOYEE_MASTER EM ON EM.EMPLOYEE_ID=PM.EMPLOYEE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=PM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
WHERE PM.CMP_CODE="+@CMP_CODE+" AND TRAN_DOCNO BETWEEN "+@FROMNO+" AND "+@TONO+"
AND TRAN_TYPE='CP'
ORDER BY TRAN_DOCNO
"

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL






















GO

