/*
PROC_CASHBANKDAYWISEBOOK N'1', N'Acc2015_2016.Dbo.', N'01/Apr/2015', N'22/Aug/2015', N'1742', N'2728616.21', N'Dr',2
*/
CREATE PROCEDURE [dbo].[PROC_CASHBANKDAYWISEBOOK]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@BANKID NVARCHAR(20),
@DBLOPBAL NVARCHAR(20),
@STROPSTATUS NVARCHAR(20),
@PAYTYPE NVARCHAR(20)
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1 NVARCHAR(4000)
DECLARE @PAYSQL NVARCHAR(4000)

SET @PAYSQL = ""

BEGIN
IF @PAYTYPE = 1 
BEGIN
SET @PAYSQL = " AND TM.TRAN_TYPE IN ('BR','CR') "
END
ELSE IF @PAYTYPE = 2 
BEGIN
SET @PAYSQL = " AND TM.TRAN_TYPE IN ('BP','CP') "
end
END



BEGIN
SET NOCOUNT ON;
SET @SQL = "  SELECT VDATE,CHEQUENO,BANKCODE,BANKNAME, PARTYCODE,PARTYNAME,PARTYCITY,DEBITAMT,
CREDITAMT,NARR,TRAN_TYPE,FLAG FROM ( "

SET @SQL1 =" SELECT TM.TRAN_DATE AS VDATE,CASE WHEN TM.TRAN_TYPE IN('P','S','PR','SR') THEN CAST(TM.TRAN_DOCNO AS NVARCHAR) ELSE TD.CHEQUENO END AS CHEQUENO,
TM.TRAN_MASTER_ID AS BANKCODE,BLM.LGR_NAME AS BANKNAME,TD.TRAN_DETAIL_ID AS PARTYCODE,PLM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
CASE WHEN TM.TRAN_DRCR='D' THEN TM.TRAN_AMOUNT ELSE 0 END AS DEBITAMT,
CASE WHEN TM.TRAN_DRCR='C' THEN TM.TRAN_AMOUNT ELSE 0 END AS CREDITAMT,
TM.TRAN_TYPE,TD.NARRATION AS NARR,
CASE WHEN TM.TRAN_TYPE = 'BR' THEN 1
WHEN TM.TRAN_TYPE = 'CP' THEN 2 
WHEN TM.TRAN_TYPE = 'BP' THEN 3
WHEN TM.TRAN_TYPE = 'CR' THEN 4 ELSE 0 END AS FLAG
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON TM.TRAN_MASTER_ID=BLM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID=PLM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
WHERE TM.TRAN_MASTER_ID="+@BANKID+" AND TM.TRAN_TYPE<>'J'
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND TM.CMP_CODE="+@CMP_CODE+" "+@PAYSQL+"

UNION ALL

SELECT TM.TRAN_DATE AS VDATE,CASE WHEN TM.TRAN_TYPE IN('P','S','PR','SR') THEN CAST(TM.TRAN_DOCNO AS NVARCHAR) ELSE TD.CHEQUENO END AS CHEQUENO,
TD.TRAN_DETAIL_ID AS BANKCODE,BLM.LGR_NAME AS BANKNAME,TM.TRAN_MASTER_ID AS PARTYCODE,PLM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
CASE WHEN TD.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBITAMT,
CASE WHEN TD.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END AS CREDITAMT,
TD.TRAN_TYPE,TD.NARRATION AS NARR,
CASE WHEN TD.TRAN_TYPE = 'BR' THEN 1
WHEN TD.TRAN_TYPE = 'CP' THEN 2 
WHEN TD.TRAN_TYPE = 'BP' THEN 3
WHEN TD.TRAN_TYPE = 'CR' THEN 4 ELSE 0 END AS FLAG
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TM.TRAN_MASTER_ID=PLM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON TD.TRAN_DETAIL_ID=BLM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
WHERE TD.TRAN_DETAIL_ID="+@BANKID+" AND TM.TRAN_TYPE<>'J'
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND TM.CMP_CODE="+@CMP_CODE+" "+@PAYSQL+"
AND TD.TRAN_DETAIL_ID NOT IN 
(SELECT LM.LGR_ID FROM "+@DATABASENAME+"LEDGER_MASTER LM 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID = LM.LGR_ID
WHERE LD.GRP_ID =  15)

UNION ALL

SELECT TM.TRAN_DATE AS VDATE,'' AS CHEQUENO,
TD.TRAN_DETAIL_ID AS BANKCODE,BLM.LGR_NAME AS BANKNAME,JD.TRAN_DETAIL_ID AS PARTYCODE,PLM.LGR_NAME AS PARTYNAME, PCM.CITY_NAME AS PARTYCITY,
CASE WHEN TD.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBITAMT,
CASE WHEN TD.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END AS CREDITAMT,
TD.TRAN_TYPE,TD.NARRATION AS NARR,
CASE WHEN TD.TRAN_TYPE = 'BR' THEN 1
WHEN TD.TRAN_TYPE = 'CP' THEN 2 
WHEN TD.TRAN_TYPE = 'BP' THEN 3
WHEN TD.TRAN_TYPE = 'CR' THEN 4 ELSE 0 END AS FLAG
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON TD.TRAN_DETAIL_ID=BLM.LGR_ID
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL JD ON TD.TRAN_ID=JD.TRAN_ID AND TD.TRAN_TYPE=JD.TRAN_TYPE AND TD.TRAN_DETAIL_ID <> JD.TRAN_DETAIL_ID	AND TM.CMP_CODE=JD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON JD.TRAN_DETAIL_ID=PLM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
WHERE TD.TRAN_DETAIL_ID="+@BANKID+" AND TD.TRAN_TYPE='J'
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND TM.CMP_CODE="+@CMP_CODE+"  "+@PAYSQL+"
"

EXEC (@SQL + @SQL1 + ") AS DETAIL ORDER BY FLAG ")
PRINT @SQL
PRINT @SQL1
print ") AS DETAIL ORDER BY FLAG "
END




















GO

