-- =============================================
-- ALTER_AUTHOR  : <BIREN>
-- ALTER_DATE    : <30-05-2015 11:12 AM>
-- REPORT_FORM    : <DESCRIPTION,,>
-- CRYSTAL_REPORT : <DESCRIPTION,,>
-- PROC_CASHBOOKSUMMARY 1,'acc2015_2016.dbo.','01/apr/2015','31/mar/2016',2
-- =============================================
CREATE PROCEDURE [dbo].[PROC_CASHBOOKSUMMARY]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@RPTWISE AS INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @TYPESQL  NVARCHAR(4000)

BEGIN
IF @RPTWISE = 1 /* FROM DATE */
SET @TYPESQL = " AND TM.TRAN_TYPE = 'CR' "
ELSE IF @RPTWISE = 2 /* AS ON DATE */
SET @TYPESQL = " AND TM.TRAN_TYPE = 'CP' "
END

BEGIN
SET NOCOUNT ON;
SET @SQL = " SELECT TM.TRAN_ID, TM.TRAN_DOCNO AS DOCNO,ISNULL(TM.VOUCHERNO,0) AS VOUCHERNO,
CONVERT(NVARCHAR,TM.TRAN_DATE,106) AS DATE,ISNULL(LM.LGR_NAME,'') AS PARTY,
ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(TD.NARRATION,'') AS NARRATION,ISNULL(TM.TRAN_AMOUNT,0) AS AMOUNT 
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.TRAN_TYPE = TD.TRAN_TYPE
AND TM.CMP_CODE = TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  "+@TYPESQL+"
ORDER BY CONVERT(NVARCHAR,TM.TRAN_DATE,103),CONVERT(INT,TRAN_DOCNO)"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

