-- =============================================
-- AUTHOR:		SUMIT
-- ALTER_DATE: 05-08-2013
-- DESCRIPTION:	SP FOR CASHPAYMENT
-- REPORT_NAME : CASHPAYMENT.RPT
-- PROC_CASHPAYMENT '1','ACC2012_2013.DBO','01/APR/2012','31/MAR/2013',1000
-- =============================================
CREATE PROCEDURE [dbo].[PROC_CASHPAYMENT]
(
@CMPCODE NVARCHAR(20),
@DATABASENAME NVARCHAR(20),
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),
@CAMOUNT NVARCHAR(20)
)
AS
DECLARE @SQL NVARCHAR(4000)
SET @SQL=""
BEGIN

SET NOCOUNT ON;
SET @SQL="SELECT TD.TRAN_ID,LM.LGR_NAME,
TD.TRAN_AMOUNT,ISNULL(LM.LGR_ADD1,'') AS ADD1,ISNULL(LM.LGR_ADD2,'') AS ADD2
,ISNULL(LM.LGR_ADD3,'') AS ADD3,ISNULL(CM.CITY_NAME,'') AS CITY,
ISNULL(LM.LGR_DISTRICT,'') AS DISTRICT,ISNULL(SM.STATE_NAME,'') AS STATE
,LM.LGR_PANO,TD.CMP_CODE ,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(TM.TRAN_DOCNO,'') AS DOCNO,
CONVERT(NVARCHAR,TM.TRAN_DATE,103) AS VCHDATE,ISNULL(TM.NARRATION,'') AS NARRATION
FROM "+@DATABASENAME+" TRAN_DETAIL TD
INNER JOIN "+@DATABASENAME+" TRAN_MASTER TM ON TD.TRAN_ID = TM.TRAN_ID AND TD.CMP_CODE = TM.CMP_CODE
AND TD.TRAN_TYPE = TM.TRAN_TYPE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID=LM.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID = SM.STATE_ID
WHERE TD.TRAN_TYPE = 'CP' AND TD.TRAN_AMOUNT >= "+@CAMOUNT+" AND TD.CMP_CODE IN ("+@CMPCODE+")
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
ORDER BY TM.TRAN_DATE,LM.LGR_NAME,LM.LGR_ID


"

EXEC (@SQL)
PRINT @SQL

END






















GO

