/*
PROC_CASHRECEIPT_REGISTER_DETAIL '1','Acc2017_2018.dbo.',1,'01/APR/2017','31/MAR/2018','##1320',1000,0,'ALL'

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/
CREATE PROCEDURE [dbo].[PROC_CASHRECEIPT_REGISTER_DETAIL] 	
(
	@Cmp_Code nvarchar(50),
	@DatabaseName nvarchar(50),
	@Rpt_Type int,
	@FromDate nvarchar(20),
	@ToDate nvarchar(20),
	@TempTable nvarchar(20),
	@CAMOUNT NVARCHAR(20),
	@BANKID NVARCHAR(20),
	@BANKNAME NVARCHAR(20)
)
AS
Declare @sql as nvarchar(4000)
declare @sqlJoin as nvarchar(4000)
declare @Id as nvarchar(200)
declare @CRAMT_SQL as nvarchar(200)

set @sql =""
set @sqlJoin =""
SET @CRAMT_SQL=""

  BEGIN  
		if @Rpt_Type=1     
			Begin
				   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON LM.Lgr_ID=TT.CODE"
			end
        ELSE 
			Begin
				   SET @sqlJoin=""
			end
  END
    BEGIN  
		if @BankName='ALL'    
			Begin
				   SET @Id="  "
			end
        ELSE 
			Begin
				   SET @Id="and Tran_Master_Id ="+@BANKID+""
			end
  END
  
  BEGIN
	IF @CAMOUNT>0
		SET @CRAMT_SQL=" AND TD.TRAN_AMOUNT >= "+@CAMOUNT+""
  END


BEGIN	
	SET NOCOUNT ON;	

	 set @SQL="
			SELECT LM.Lgr_Name as PARTY,TD.TRAN_TYPE as TRANTYPE,TM.Tran_Date as DATE,ISNULL(TD.DEPOSITETYPE,'') AS DEPOSITETYPE,TD.Tran_Amount as AMOUNT 
,TM.Tran_DocNo,CM.CITY_NAME,ISNULL(LGR_ADD1,'')LGR_ADD1,ISNULL(LGR_ADD2,'')LGR_ADD2,ISNULL(LGR_ADD3,'')LGR_ADD3,ISNULL(LGR_PANO,'')LGR_PANO

FROM "+ @DatabaseName+"  TRAN_DETAIL TD
INNER JOIN "+ @DatabaseName+" TRAN_MASTER TM ON TM.Tran_Id=TD.Tran_Id
INNER JOIN "+ @DatabaseName+" LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_DETAIL_Id
LEFT JOIN "+ @DatabaseName+" CITY_MASTER CM ON LM.CITY_Id=CM.CITY_ID
 " + @sqlJoin +"       
WHERE TD.TRAN_TYPE = 'CR'AND TM.Tran_Type = 'CR' and TD.cmp_code IN ("+ @Cmp_Code +") "+@CRAMT_SQL+" AND 
TM.Tran_Date >= '" + @FromDate + "' and TM.Tran_Date <= '" + @TODate + "'  "+@Id+"
			

UNION ALL

SELECT  
LM.Lgr_Name as PARTY,TD.TRAN_TYPE as TRANTYPE,TM.Tran_Date as DATE,
TD.DEPOSITETYPE as DEPOSITETYPE,TD.Tran_Amount as AMOUNT 
,TM.Tran_DocNo,CM.CITY_NAME,ISNULL(LGR_ADD1,'')LGR_ADD1,ISNULL(LGR_ADD2,'')LGR_ADD2,ISNULL(LGR_ADD3,'')LGR_ADD3,ISNULL(LGR_PANO,'')LGR_PANO
FROM "+ @DatabaseName+" TRAN_DETAIL TD
INNER JOIN "+ @DatabaseName+" TRAN_MASTER TM ON TM.Tran_id=TD.Tran_Id
INNER JOIN "+ @DatabaseName+" LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_DETAIL_Id
LEFT JOIN "+ @DatabaseName+" CITY_MASTER CM ON LM.CITY_Id=CM.CITY_ID
" + @sqlJoin +"              
WHERE TD.TRAN_TYPE = 'BR' AND TM.Tran_Type = 'BR' and TD.DEPOSITETYPE='CASH' 
AND TD.cmp_code IN ("+ @Cmp_Code +") AND
TM.Tran_Date >= '" + @FromDate + "' "+@CRAMT_SQL+" and TM.Tran_Date <='" + @TODate + "' "+@Id+"
Order by TM.Tran_Date, LM.Lgr_Name
"			             
END

exec sp_executesql @SQL 
print @SQL



















GO

