BEGIN  
     SET NOCOUNT ON;   
       SET @SQL="
              SELECT CS.SLIPNO,CS.SLIPDATE,LM.LGR_NAME AS CASHACCOUNT,CS.AMOUNT,CS.NARRATION
              ,PLM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
              FROM "+@DATABASENAME+"CASHSLIP CS
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON CS.ACCOUNT_ID=LM.LGR_ID
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON CS.LGR_ID=PLM.LGR_ID
              INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CS.SLIPNO                            
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
              WHERE CS.CMP_CODE="+@CMP_CODE+" AND CS.ACCOUNT_ID="+@ACCOUNTID+" 
              AND   CS.SLIPDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
              "  

EXECUTE SP_EXECUTESQL @SQL
