/*
PROC_CFORM '10','acc2014_2015.dbo.','01/apr/2010','31/mar/2015','##1400',2,'CFORM',1
*/
CREATE PROCEDURE [dbo].[PROC_CFORM]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @RPT_WISE AS INT,
  @FORM AS NVARCHAR(50),
  @HEADID AS NVARCHAR(20)
) 	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @HEADSQL AS NVARCHAR(1000)
SET @SQL="" 
SET @JOINSQL="" 
SET @HEADSQL=""
  
  BEGIN
        IF @RPT_WISE=1
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID "
        ELSE IF @RPT_WISE=2
          SET @JOINSQL=""
  END
BEGIN
		if @HEADID=0
			SET @HEADSQL=""
		ELSE 
			SET @HEADSQL=" AND PI.PURACCID="+@HEADID +" "
END

BEGIN   
SET @SQL="
SELECT PI.BILLNO,PI.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,PI.NETTOTAL
,CMP.CMP_ALIAS,LM.LGR_CSTNO,LM.LGR_ID
FROM "+@DATABASENAME+"PURCHASEINVOICE PI              
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID              
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
"+@JOINSQL +" 
WHERE PI.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND PI.CMP_CODE IN("+@CMP_CODE +")
AND PI.FORM='"+@FORM +"'  
"+@HEADSQL+"
ORDER BY LM.LGR_NAME,LM.LGR_ID,PI.VCHDATE,PI.BILLNO 
         "	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL


















GO

/****** Object:  StoredProcedure [dbo].[PROC_CFORMPENDING]    Script Date: 03/30/2023 12:08:11 ******/
