/*
-- =============================================
-- Author:		<BHARATBHAI>
-- Create_date: 05-05-2014
-- Description:	THIS REPORT IS USED TO DATA DISPLAY IN CFORM PANDING REPORT  AND HFORM PANDING REPORT AND USED 
-- REPORT NAME: FORMPENDINGLETTER_REPORT,BILLPENDINREPORT,FORMRECEIVEDREPORT
select * from TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
-- =============================================
PROC_CFORMPENDING 1,'ACC2014_2015.DBO.','01/APR/2013','31/MAR/2015','CFORM' ,'##2072',1
*/
CREATE PROCEDURE [dbo].[PROC_CFORMPENDING]
(
		@Cmp_Code nvarchar(10),
		@DatabaseName nvarchar(50),
        @FromDate nvarchar(20), 
        @ToDate nvarchar(20),
        @FromType nvarchar(20),
		@TEMPTB nvarchar(50),
		@RptWise INT
)		
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @STRRPTWISE NVARCHAR(500)
SET @SQL =""
SET @STRRPTWISE =""

BEGIN

IF @RptWise =1
SET @STRRPTWISE ="AND ( ISNULL(FORM_NO,'')='' OR FORM_NO= '')"
ELSE IF @RptWise =2
SET @STRRPTWISE ="AND (NOT ISNULL(FORM_NO,'')='' OR NOT FORM_NO= '')"
else
SET @STRRPTWISE =""

END

BEGIN
SET @SQL ="
SELECT VCODE AS PurchaseInvId,DATE,convert(int,SI.BILLNO) AS BILLNO,LGR_NAME AS PARYNAME,CT.CITY_NAME AS CITY,AMOUNT,FORM_NO,
FORM_DATE,LGR.Lgr_Add1 AS ADD1,lgr.Lgr_Add2 AS ADD2,Lgr_Cstno AS PARTY_TINNO,cmp_Tin_No AS CMP_TINNO,SI.LGR_ID,LGR.CITY_ID
 FROM  "+@DATABASENAME+"PURPARTYDETAIL SI 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LGR ON LGR.LGR_ID=SI.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CT ON  CT.CITY_ID=LGR.CITY_ID
inner join "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE =SI.CMP_CODE
INNER JOIN "+@TEMPTB+" TT ON TT.CODE =SI.LGR_ID
WHERE FLAG in('CHP','MIP') AND (PUR_FORM  ='"+@FromType+"')  AND SI.CMP_CODE IN("+@Cmp_Code+")
AND  DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'   "+@STRRPTWISE+" ORDER BY LGR_NAME, LGR.LGR_ID,DATE,BILLNO  "

END
PRINT @SQL
execute Sp_Executesql @SQL




















GO

