/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 15-04-2015
-- DESCRIPTION:	THIS PROCEDURE IS USED IN CHEMICAL,MACHINARY CHALLAN PRINT OUT REPORT 
-- =============================================
PROC_CHALLANINWARD 'ACC2015_2016.DBO.',1,500,'CHP',1,'##4872'
*/
CREATE PROCEDURE [dbo].[PROC_CHALLANINWARD]
(
@DATABASENAME AS NVARCHAR(100),
@FROMNO AS NVARCHAR(100),
@TONO AS NVARCHAR(100),
@RPT_TYPE AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(10),
@TEMPTABLE NVARCHAR(20)
)
AS
BEGIN
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
SET @STRSQL=""
SET @JOINSQL=""
SET @FIELDSQL=""

IF @TEMPTABLE <> "" 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CM.CMP_CODE"
	SET @FIELDSQL = "TT.TYPE"
END	
ELSE
BEGIN
	SET @FIELDSQL = "'' AS TYPE"
END

SET @STRSQL="SELECT DOCNO,VCHDATE AS DATE,CONFNO,DATE AS CONDATE,ORDERNO, ORDERDATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,
DM.DRIVER_NAME AS DRIVER,CHALLANNO,OUT_GATEPASS_NO,CM.LRNO,IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT ,CD.BAGS,CD.PACKING,CD.QUANTITY,
RATE,VEHICLENO,SM.SIZE_NAME,DM.DRIVER_NAME,SGM.SUPP_GRP_NAME,"+@FIELDSQL+"
FROM "+@DATABASENAME+"CHEMICALCHALLAN CM
INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CD ON CD.CHALLANID=CM.CHALLANID 
AND CM.CMP_CODE=CD.CMP_CODE AND CM.FLAG=CD.FLAG 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID =CM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=CM.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =CD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"UNIT_MASTER	UM ON UM.UNIT_ID=CD.UNIT_ID
LEFT JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID=CD.SIZE_ID
LEFT JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID =CM.DRIVER_ID
"+@JOINSQL+"
WHERE CM.CMP_CODE="+@CMP_CODE+" AND DOCNO >= "+ @FROMNO +" AND DOCNO <="+@TONO+" AND  CM.FLAG='"+@RPT_TYPE+"'
ORDER BY CM.DOCNO,TYPE,CD.SRNO
"
	
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

