/*
PROC_CHEMICAL_ORDER_PRINT 2,'ACC2010_2011.DBO.',1,1000
*/
CREATE PROCEDURE [dbo].[PROC_CHEMICAL_ORDER_PRINT]
(
@CMPCODE NVARCHAR(50),
@DATABASE NVARCHAR(50),
@FROMDOCNO NVARCHAR(50),
@TODOCNO NVARCHAR(50),
@FYEAR NVARCHAR(50)
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="
SELECT DOCNO,PONO,GDATE,PO_DATE,START_DATE,END_DATE,SG.SUPP_GRP_NAME AS SUPPGRPNAME,ISNULL(CM.CITY_NAME,'') AS CITY_NAME
,ALM.LGR_NAME AS AGENTNAME,TM.TRANSPORT_NAME,DISC,CRDAYS,
IM.ITEM_NAME,UM.UNIT_NAME,POD.QUANTITY,POD.SCHEDULE,POD.SCHQUANTITY,POD.RATE,POD.SRNO,
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(LCM.CITY_NAME,'') AS PARTYCITY,ISNULL(POD.PACKING,0) AS PACKING,
ISNULL(POD.BAGS,0) AS BAGS,ISNULL(POD.REMARKS,'') AS REMARKS,
ISNULL(WITH_TRANSPORTATION,0) AS WITH_TRANSPORTATION
FROM "+@DATABASE+" PURCHASEORDER PO
INNER JOIN "+@DATABASE+" PURCHASEORDER_DETAIL POD ON POD.PUR_ORDER_ID=PO.PUR_ORDER_ID AND POD.FLAG=PO.FLAG AND POD.CMP_CODE=PO.CMP_CODE
LEFT JOIN "+@DATABASE+" SUPPLIER_GROUP_MASTER SG ON PO.SUPP_GRP_ID=SG.SUPP_GRP_ID
LEFT JOIN "+@DATABASE+" LEDGER_MASTER ALM ON PO.AGENT_ID=ALM.LGR_ID
LEFT JOIN "+@DATABASE+" CITY_MASTER CM ON ALM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASE+" TRANSPORT_MASTER TM ON PO.TRANSPORT_ID=TM.TRANSPORT_ID
LEFT JOIN "+@DATABASE+" ITEM_MASTER IM ON POD.ITEM_ID=IM.ITEM_ID
LEFT JOIN "+@DATABASE+" UNIT_MASTER UM ON UM.UNIT_ID=POD.UNIT_ID
INNER JOIN "+@DATABASE+" LEDGER_MASTER LM ON LM.LGR_ID=PO.LGR_ID
LEFT JOIN "+@DATABASE+" CITY_MASTER LCM ON LM.CITY_ID=LCM.CITY_ID
WHERE PO.ORDER_APPROVAL = 1 AND PO.CMP_CODE IN ("+@CMPCODE+") AND PO.DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
AND PO.FLAG='CHP' AND PO.FYEAR IN ('"+@FYEAR+"')
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

