/*    
 PROC_CHEMICLE_PURCHASE_RETURN '1','10','1','acc2017_2018.dbo.'
*/   

CREATE PROCEDURE [dbo].[PROC_CHEMICLE_PURCHASE_RETURN]
(
@FromBillNo  nvarchar(20),
@ToBillNo nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="	 
		SELECT PR.DOCNO AS BILLNO,PR.PUR_RET_DATE AS RETDATE,PR.PUR_RET_LRNO,
		PR.PUR_RET_LRDATE,PR.CMP_CODE,PR.PUR_RET_ADD1,PR.PUR_RET_ADD2,PR.PUR_RET_ADD3,PR.PUR_RET_ADDTOTAL,PR.PUR_RET_LESS1,PR.PUR_RET_LESS2,PR.PUR_RET_LESS3,
		PR.PUR_RET_LESSTOTAL,PUR_RET_ROUNDOFF ,PR.ROUNDEDAMOUNT AS ROUNDEDAMOUNT,PR.GROSSTOTAL,PR.NETTOTAL AS NETTOTAL,PR.FLAG,PR.BILLNO AS BNO,
		PRD.LOTNO,PR.NARR,PR.RETURN_TYPE,
		PRD.PUR_RET_DTL_ID,PRD.PUR_RET_BALE_NO AS BALENO,PRD.ITEM_ID,PRD.UNIT_ID,PRD.ITEM_CUT ,PRD.PUR_RET_PCS AS PCS,PRD.PUR_RET_QTY AS QUANTITY,PUR_RET_AMOUNT AS TAXABLE,
		PRD.PUR_RET_RATE AS RATE,PRD.LOT_ID,PRD.SIZE_ID,PRD.SCREEN_ID,CMP_STATECODE AS CMPSTCODE,CMP.GSTINNO AS CGSTIN,LM.GSTINNO AS LGSTIN,
		UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,
		UPPER(LM.LGR_ADD2) AS LGR_ADD2,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(AGM.LGR_NAME) AS AGENTNAME ,IM.ITEM_NAME AS ITEM,
		CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,UM.UNIT_NAME,UPPER(SM.STATE_NAME) AS  PATYSTATE,SM.STATE_CODE AS ST_CODE,UPPER(PCM.CITY_DISTRICT)AS CITY_DISTRICT,
		LM.CITY_PINCODE,UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,CMP.CMP_ADD1,CMP.CMP_ADD2,CMP.cmp_ServiceTax_No,
		CMP.CMP_CITY,CMP.CMP_STATE,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,
		UPPER(ACM.CITY_NAME) AS AGENTCITY,SCM.SCREEN_NAME,LOT.LOT_NAME,SZM.SIZE_NAME,PRD.VAT_PER AS CGSTPER,PRD.VATAMOUNT AS CGSTAMT,PRD.VAT_PER1 AS SGSTPER,
		PRD.VATAMOUNT1 AS SGSTAMT,PRD.VAT_PER2 AS IGSTPER,PRD.VATAMOUNT2 IGSTAMT,HM.HSN_NAME AS HSN_CODE,CMP.cmp_Email AS MAIL,
		PRD.LESSAMOUNT AS DISC,PRD.ADDAMOUNT AS ADDITION,PRD.GROSSAMOUNT AS AMOUNT,PR.CESSAMOUNT,PR.EWAYBILLNO
		
		
		
		 FROM "+ @DatabaseName +"PURCHASE_RETURN_MASTER PR
		INNER JOIN "+ @DatabaseName +"PURCHASE_RETURN_DETAIL PRD ON PR.PUR_RET_ID = PRD.PUR_RET_Id  AND PR.FLAG = PRD.FLAG
		INNER JOIN "+ @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=PR.LGR_ID
		LEFT JOIN  "+ @DatabaseName +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PR.TRANSPORT_ID
		LEFT JOIN  "+ @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=PR.AGENT_ID
		INNER JOIN "+ @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
		LEFT JOIN "+ @DatabaseName +"HSN_MASTER HM ON HM.HSN_ID=IM.HSN_ID
		INNER JOIN "+ @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=PRD.UNIT_ID
		INNER JOIN "+ @DatabaseName +"COMPANY_MASTER CMP ON PR.Cmp_Code= CMP.Cmp_Code     
		LEFT JOIN  "+ @DatabaseName +"CITY_MASTER CM ON CM.CITY_ID=PR.STATION_ID
		LEFT JOIN  "+ @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN  "+ @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN  "+ @DatabaseName +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID     
		LEFT JOIN  "+ @DatabaseName +"SCREEN_MASTER SCM ON PRD.SCREEN_ID =SCM.SCREEN_ID     
		LEFT JOIN  "+ @DatabaseName +"LOT_MASTER LOT ON PRD.LOT_ID = LOT.LOT_ID    
		LEFT JOIN  "+ @DatabaseName +"SIZE_MASTER SZM ON PRD.SIZE_ID = SZM.SIZE_ID    
		/* LEFT JOIN  "+ @DatabaseName +"NARRATION_MASTER NM ON NM.CMP_CODE=PR.CMP_CODE AND NM.TYPE='BILL' */
		WHERE PR.Cmp_Code="+ @Cmp_Code +" and  PR.DOCNO BETWEEN '" + @FromBillNo + "' and '" + @ToBillNo + "'
		AND PR.FLAG = 'CPR' 
		ORDER BY   PR.DOCNO, PRD.PUR_RET_DTL_ID
		"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

















GO

