CREATE PROCEDURE [dbo].[PROC_CHEQUEBILLDETAIL_RECEIPT]
(
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    @FROMDATE NVARCHAR(50),
    @TODATE NVARCHAR(50),
    @RPT_WISE INT,
    @TEMPTABLE NVARCHAR(50)
    
)	
AS

DECLARE @SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""

BEGIN
      IF @RPT_WISE=1 
         SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+ " TT ON TT.CODE=TM.TRAN_MASTER_ID"
      ELSE IF @RPT_WISE=2
         SET @JOINSQL=" "
END


BEGIN
SET @SQL="   
           SELECT TM.TRAN_ID,TM.TRAN_TYPE,TM.TRAN_DOCNO,TM.TRAN_DATE,TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,LM.LGR_NAME AS BANK,PLM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
           ,TM.TRAN_AMOUNT,ADJ.BILLNO,ADJ.ADJUSTAMT,ADJ.DISCOUNT,ADJ.INTEREST,ADJ.INTREC,CMP.CMP_ALIAS
           FROM "+@DATABASENAME+"TRAN_MASTER TM
           INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE
           INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
           INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON PLM.LGR_ID=TD.TRAN_DETAIL_ID
           LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
           LEFT JOIN "+@DATABASENAME+"ADJMASTER ADJ ON ADJ.LGR_ID=TD.TRAN_DETAIL_ID AND ADJ.ENTRYCODE=TM.TRAN_ID AND ADJ.TYPE=TM.TRAN_TYPE
           INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
           "+@JOINSQL+"
           WHERE TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_TYPE='BR'
           AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
           ORDER BY TM.TRAN_DATE,TM.TRAN_DOCNO,CMP.CMP_ALIAS
        "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

