/*
PROC_CHEQUECANCEL 2,'ACC2010_2011.DBO.',1,'01/APR/2010','01/APR/2011',''
*/
CREATE PROCEDURE [dbo].[PROC_CHEQUECANCEL]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @RPT_WISE INT,
   @FROMDATE  NVARCHAR(100),
   @TODATE  NVARCHAR(100),
   @TEMPTABLE NVARCHAR(100)   
)
AS

DECLARE @SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(4000)
SET @SQL=""
SET @JOINSQL=""
BEGIN 
   IF @RPT_WISE=1 
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=CC.LGR_ID"
   ELSE IF @RPT_WISE=2 
      SET @JOINSQL="" 
END

BEGIN
         SET @SQL=" SELECT CC.DOCNO AS DOCNO,CC.VCHDATE AS DATE,CC.CHEQUENO,CC.CHEQUEDATE,LM.LGR_NAME AS BANK,CC.AMOUNT ,CMP.CMP_ALIAS
                    FROM "+@DATABASENAME+"CHEQUE_CANCELLAED CC 
                    INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CC.LGR_ID 
                    INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=CC.CMP_CODE 
                    "+@JOINSQL+"
                    WHERE CC.CMP_CODE IN ("+@CMP_CODE +") AND CC.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                    ORDER BY LM.LGR_NAME,CC.CHEQUEDATE,CC.DOCNO
                  "
END

PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

