/*
-- =============================================
-- AUTHOR:	GAMI DIPAK
-- ALTER_DATE: 25-03-2015
-- DESCRIPTION:	THIS REPORT IS USED TO REPORT COLOR STOCK` REPORT 
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_COLCHEMICALSOTCK 'ACC2014_2015.DBO.','##4664','1','20/JUL/2014','26/MAR/2015',3,0,2
*/
CREATE PROCEDURE [dbo].[PROC_COLCHEMICALSOTCK]
(
@DATABASENAME AS NVARCHAR(100),
@TEMPTB AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(100),
@TODATE AS NVARCHAR(100),
@RPT_WISE AS INT,
@RPT_TYPE AS INT,
@RPT_OPTION AS INT
)

AS
BEGIN
DECLARE  @STRSQL AS NVARCHAR(4000)
DECLARE  @STRSQL1 AS NVARCHAR(4000)

DECLARE  @STRJOIN AS NVARCHAR(200)
DECLARE  @STRGROUPBY AS NVARCHAR(100)
DECLARE  @STRCONDITION AS NVARCHAR(200)
DECLARE @STRSELECT AS NVARCHAR(400)  
DECLARE @STROPTION AS NVARCHAR(100)
DECLARE @STRTYPE AS NVARCHAR(100)
DECLARE @STRORDERBY AS NVARCHAR(150)

SET @STRSQL=""
SET @STRSQL1=""

SET @STRJOIN=""
SET @STRGROUPBY=""
SET @STRCONDITION=""
SET @STRSELECT =""
SET @STROPTION=""
SET @STRTYPE=""
SET @STRORDERBY=""

BEGIN

IF @RPT_OPTION=1 
BEGIN
SET @STROPTION=" AND CC.FLAG='CHP'"
SET @STRTYPE=" AND ITEM_TYPE IN('CHL','COL')   "
END
ELSE
BEGIN
SET @STROPTION=" AND CC.FLAG='MIP'"
SET @STRTYPE="  AND ITEM_TYPE IN('OTH')"
END


IF @RPT_WISE = 1 OR @RPT_WISE = 3
BEGIN
	SET @STRJOIN=" INNER JOIN "+ @TEMPTB  +" TT ON TT.CODE=IM.ITEM_ID "
	SET @STRGROUPBY=" GROUP BY ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME "
	SET @STRSELECT =" ITEM_NAME,ITEM_ID,ITEM_GRP_NAME AS ITEM_GRP_NAME,ITEM_GRP_ID AS ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME"
	SET @STRORDERBY=" ORDER BY ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME"
END
ELSE IF @RPT_WISE =2 
BEGIN
	SET @STRJOIN=" INNER JOIN "+ @TEMPTB  +" TT ON TT.CODE=IM.ITEM_GRP_ID "
	SET @STRGROUPBY=" GROUP BY ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME "
	SET @STRSELECT =" ITEM_NAME AS ITEM_NAME,ITEM_ID AS ITEM_ID,ITEM_GRP_NAME AS ITEM_GRP_NAME,ITEM_GRP_ID AS ITEM_GRP_ID,NICKNAME,ITEM_TYPE,Item_type_Id"
		SET @STRORDERBY=" ORDER BY ITEM_GRP_NAME,ITEM_GRP_ID,ITEM_NAME,ITEM_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME"
END
ELSE IF  @RPT_WISE = 3
BEGIN
	SET @STRJOIN=" INNER JOIN "+ @TEMPTB  +" TT ON TT.CODE=IM.ITEM_ID "
	SET @STRGROUPBY=" GROUP BY ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME "
	SET @STRSELECT =" ITEM_NAME,ITEM_ID,ITEM_GRP_NAME AS ITEM_GRP_NAME,ITEM_GRP_ID AS ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME"
	SET @STRORDERBY=" ORDER BY NICKNAME,ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,Item_type_Id,ITEM_TYPE_NAME"
END
ELSE IF  @RPT_WISE = 4
BEGIN
	SET @STRJOIN=" INNER JOIN "+ @TEMPTB  +" TT ON TT.CODE=IM.Item_type_Id "
	SET @STRGROUPBY=" GROUP BY ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME "
	SET @STRSELECT =" ITEM_NAME,ITEM_ID,ITEM_GRP_NAME AS ITEM_GRP_NAME,ITEM_GRP_ID AS ITEM_GRP_ID,NICKNAME,Item_type_Id,ITEM_TYPE_NAME"
	SET @STRORDERBY=" ORDER BY NICKNAME,ITEM_NAME,ITEM_ID,ITEM_GRP_NAME,ITEM_GRP_ID,Item_type_Id,ITEM_TYPE_NAME"
END
END


IF @RPT_TYPE =1
	SET @STRCONDITION=" AND (SUM(OPNINGSTOCK)+SUM(STOCKIN) -SUM(STOCKOUT)) <= SUM(MINQTY)   "

IF @TEMPTB =''
SET @STRJOIN=""


SET @STRSQL ="SELECT "+@STRSELECT+",SUM(OPNINGSTOCK) AS OPNINGSTOCK,SUM(STOCKIN) AS STOCKIN,SUM(STOCKOUT) AS STOCKOUT,SUM(MINQTY) AS MINQTY  FROM (
SELECT IM.ITEM_ID,IM.ITEM_NAME,IGM.ITEM_GRP_ID,IGM.ITEM_GRP_NAME,ITEM_OP_STOCK AS OPNINGSTOCK,0 AS STOCKIN,0 AS STOCKOUT ,ISNULL(ITEM_MIN_QTY,0) AS MINQTY,ISNULL(IM.NICK_NAME,'') AS NICKNAME,IM.Item_type_Id,ITM.ITEM_TYPE_NAME
FROM "+@DATABASENAME+"ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOP ON IOP.ITEM_ID=IM.ITEM_ID 
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID 
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.Item_Type_Id=IM.Item_type_Id 
"+@STRJOIN+"
WHERE CMP_CODE="+@CMP_CODE +" "+@STRTYPE+"
UNION ALL 
SELECT IM.ITEM_ID,IM.ITEM_NAME,IGM.ITEM_GRP_ID,IGM.ITEM_GRP_NAME,0 AS OPNINGSTOCK,CD.QUANTITY  AS STOCKIN,0 AS STOCKOUT ,0 AS MINQTY,ISNULL(IM.NICK_NAME,'') AS NICKNAME,IM.Item_type_Id,ITM.ITEM_TYPE_NAME
FROM "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CD
INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN CC ON CC.CHALLANID=CD.CHALLANID AND CC.CMP_CODE=CD.CMP_CODE AND CC.FLAG=CD.FLAG
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON CD.ITEM_ID =IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.Item_Type_Id=IM.Item_type_Id 
"+@STRJOIN+"
WHERE  VCHDATE >= '"+@FROMDATE+"' AND VCHDATE <='"+@TODATE+"' AND CC.CMP_CODE="+@CMP_CODE +" "+@STROPTION+"
UNION ALL 
SELECT IM.ITEM_ID,IM.ITEM_NAME,IGM.ITEM_GRP_ID,IGM.ITEM_GRP_NAME,CD.QUANTITY AS OPNINGSTOCK,0  AS STOCKIN,0 AS STOCKOUT ,0 AS MINQTY,ISNULL(IM.NICK_NAME,'') AS NICKNAME,IM.Item_type_Id,ITM.ITEM_TYPE_NAME
FROM "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CD
INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN CC ON CC.CHALLANID=CD.CHALLANID AND CC.CMP_CODE=CD.CMP_CODE AND CC.FLAG=CD.FLAG
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON CD.ITEM_ID =IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.Item_Type_Id=IM.Item_type_Id 
"+@STRJOIN+"
WHERE  CC.VCHDATE<'"+@FROMDATE+"'  AND CC.CMP_CODE="+@CMP_CODE +"  "+@STROPTION+"  "

SET @STRSQL1 ="
UNION ALL 
SELECT IM.ITEM_ID,IM.ITEM_NAME,IGM.ITEM_GRP_ID,IGM.ITEM_GRP_NAME,0 AS OPNINGSTOCK,0 AS STOCKIN,CD.QTY AS STOCKOUT ,0 AS MINQTY,ISNULL(IM.NICK_NAME,'') AS NICKNAME,IM.Item_type_Id,ITM.ITEM_TYPE_NAME
FROM "+@DATABASENAME+"GODOWN_INOUT_DETAIL CD
INNER JOIN "+@DATABASENAME+"GODOWN_INOUT_MASTER CC ON CC.GODOWNINOUT_ID=CD.GODOWNINOUT_ID AND CC.CMP_CODE=CD.CMP_CODE AND CD.INOUT_TYPE=CC.INOUT_TYPE AND CD.FLAG=CC.FLAG
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON CD.ITEM_ID =IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.Item_Type_Id=IM.Item_type_Id 
"+@STRJOIN+"
WHERE CC.INOUT_TYPE='IN' AND CC.VCHDATE >= '"+@FROMDATE+"' AND  CC.VCHDATE <= '"+@TODATE+"' AND CC.CMP_CODE="+@CMP_CODE +"  "+@STROPTION+"
UNION ALL 
SELECT IM.ITEM_ID,IM.ITEM_NAME,IGM.ITEM_GRP_ID,IGM.ITEM_GRP_NAME,(0-CD.QTY) AS OPNINGSTOCK,0 AS STOCKIN,0 AS STOCKOUT ,0 AS MINQTY,ISNULL(IM.NICK_NAME,'') AS NICKNAME,IM.Item_type_Id,ITM.ITEM_TYPE_NAME
FROM "+@DATABASENAME+"GODOWN_INOUT_DETAIL CD
INNER JOIN "+@DATABASENAME+"GODOWN_INOUT_MASTER CC ON CC.GODOWNINOUT_ID=CD.GODOWNINOUT_ID AND CC.CMP_CODE=CD.CMP_CODE AND CD.INOUT_TYPE=CC.INOUT_TYPE AND CD.FLAG=CC.FLAG
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON CD.ITEM_ID =IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.Item_Type_Id=IM.Item_type_Id 
"+@STRJOIN+"
WHERE CC.INOUT_TYPE='IN' AND CC.VCHDATE <'"+@FROMDATE+"' AND CC.CMP_CODE="+@CMP_CODE +"  "+@STROPTION+"
) DETAIL
"+@STRGROUPBY+" HAVING (SUM(OPNINGSTOCK)+SUM(STOCKIN)) >0 "+@STRCONDITION+""
 

END
PRINT @STRSQL
PRINT @STRSQL1
EXEC (@STRSQL+@STRSQL1)






















GO

