/*
PROC_COTTONSALESINV '2','acc2010_2011.dbo.',1,5
*/
CREATE PROCEDURE [dbo].[PROC_COTTONSALESINV]
  (
       @CMP_CODE AS NVARCHAR(50),
       @DATABASENAME AS NVARCHAR(20),
       @FROMDOCNO AS NVARCHAR(20),
       @TODOCNO AS NVARCHAR(20)
       
   )	
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
	  
SET @SQL=" 
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.CITY_PINCODE AS CITYPINCODE, CSM.COT_SAL_INV_BILL_NO AS INVOICENO,CONVERT(NVARCHAR,CSM.COT_SAL_INV_VDATE,103) AS INVOICEDATE,
CONVERT(NVARCHAR,CSM.COT_SAL_FRDATE,103) AS FROMDATE,CONVERT(NVARCHAR,CSM.COT_SAL_TODATE,103) AS TODATE
,CSD.INVOICENO AS INWARDNO,CSD.GOODSINDATE AS LOTDATE,CSD.LOTNO,FTM.FINISHTYPE_NAME,CSD.THAN,CSD.RATE,CSD.AMOUNT,
CSM.ADDTOTAL,CSM.DISPER,CSM.DISAMT,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_FAX,CSM.ROFF,CSM.NETAMT,
CSM.RATE_TYPE,CSD.MTRS,ISNULL(CSM.CENTERTHAN,0) AS CENTERTHAN,ISNULL(CSM.CENTERRATE,0) AS CENTERRATE,ISNULL(CSM.CENTERCHARGE,0) AS CENTERCHARGE,ISNULL(CSM.OTHERTHAN,0) AS OTHERTHAN,ISNULL(CSM.OTHERRATE,0) AS OTHERRATE,ISNULL(CSM.OTHERCHARGE,0) AS OTHERCHARGE
FROM "+@DATABASENAME+"COTTON_SALESINVOICE_MASTER CSM
INNER JOIN "+@DATABASENAME+"COTTON_SALESINVOICE_DETAIL CSD ON CSD.COT_SAL_INV_ID =CSM.COT_SAL_INV_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CSM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"FINISHTYPE_MASTER FTM ON FTM.FINISHTYPE_ID=CSD.FINISHTYPE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=CSM.CMP_CODE
WHERE CSM.CMP_CODE IN("+@CMP_CODE+") AND CSM.COT_SAL_INV_BILL_NO BETWEEN "+@FROMDOCNO+" AND "+ @TODOCNO +"
ORDER BY CSM.COT_SAL_INV_BILL_NO,CSM.COT_SAL_INV_VDATE,CSD.GOODSINDATE , CSD.INVOICENO,FTM.FINISHTYPE_NAME
"



END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

