/*
PROC_CRDAYSREPORT '10','ACC2010_2011.DBO.','01/APR/2010','23/FEB/2011',1,0,'##5249','1'
*/
CREATE PROCEDURE [dbo].[PROC_CRDAYSREPORT]
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(50),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @RPT_WISE INT,
   @CRDAYS NVARCHAR(10),
   @TEMPTABLE NVARCHAR(50),
   @HEADID NVARCHAR(10)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @DAYSSQL AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @DAYSSQL=""

	BEGIN
          IF @RPT_WISE =1 
              BEGIN
                 SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
              END
          ELSE IF @RPT_WISE =2 
              BEGIN
                 SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SGM.SUPP_GRP_ID"
              END
	END


   IF @CRDAYS!=""
       BEGIN
          SET @DAYSSQL="  AND PI.PUR_CRDAYS="+@CRDAYS
       END
       
 

BEGIN  
    SET @SQL="
           SELECT HLM.LGR_NAME AS PURCHASEHEAD,PI.BILLNO,PI.VCHDATE AS BILLDATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                  ,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,ISNULL(PI.PUR_CRDAYS,0) AS CRDAYS,PI.NETTOTAL,CMP.CMP_ALIAS                  
                  FROM "+@DATABASENAME+"PURCHASEINVOICE PI
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                  LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER HLM ON HLM.LGR_ID=PI.PURACCID AND PI.PURACCID IN("+@HEADID+")
                  LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
                  "+@JOINSQL+"
                  WHERE PI.CMP_CODE IN("+@CMP_CODE+") AND PI.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                   "+@DAYSSQL+"
                  ORDER BY PI.VCHDATE ,PI.BILLNO
              "
  
	
END
PRINT @SQL
EXEC SP_EXECUTESQL @SQL




















GO

