/*
Proc_CrediNote '2','ACC2010_2011.DBO.','1','2'
*/
CREATE PROCEDURE [dbo].[PROC_CREDINOTE]
(
     @CMP_CODE AS NVARCHAR(100),
     @DATABASENAME AS NVARCHAR(100),     
     @FROMDOCNO AS NVARCHAR(100),
     @TODOCNO AS NVARCHAR(100)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL="" 

BEGIN
	SET NOCOUNT ON;    
SELECT @SQL="
                SELECT LM.LGR_NAME AS PARTY ,LM.LGR_ADD1 AS ADDRESS1,LM.LGR_ADD2 AS ADDRESS2,LM.LGR_ADD3 AS ADDRESS3,CM.CITY_NAME AS PARTYCITY,
                SM.STATE_NAME AS PARTYSTATE,LM.LGR_DISTRICT,LM.CITY_PINCODE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,TM.NARRATION,TM.TRAN_DOCNO ,TD.TRAN_AMOUNT,TM.TRAN_DATE,
				COM.GSTINNO AS CMP_GSTNO,LM.GSTINNO AS PARTYGSTNO,TM.NOTE,COM.CMP_PHONE1,COM.CMP_MOBILE,TM.REC_AMT,TM.TCS_PER,TM.TCS_AMT,TM.BRANCHNAME AS BRDOCNO
                FROM "+ @DATABASENAME+ "TRAN_MASTER TM
                INNER JOIN "+ @DATABASENAME+ "TRAN_DETAIL TD  ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
                INNER JOIN  "+ @DATABASENAME+ "LEDGER_MASTER LM  ON LM.LGR_ID=TD.TRAN_DETAIL_ID 
                INNER JOIN "+ @DATABASENAME+ "LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
                LEFT JOIN "+ @DATABASENAME+ "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID                
                LEFT JOIN "+ @DATABASENAME+ "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                LEFT JOIN "+ @DATABASENAME+ "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                LEFT JOIN "+ @DATABASENAME+ "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
				INNER JOIN  "+ @DATABASENAME+ "COMPANY_MASTER COM  ON TM.CMP_CODE= COM.CMP_CODE
                WHERE TM.CMP_CODE="+ @CMP_CODE + " AND TM.TRAN_DOCNO BETWEEN "+ @FROMDOCNO +" AND "+ @TODOCNO +" AND TD.TRAN_TYPE='CN' AND TD.TRAN_DrCr='C' AND ISNULL(TM.BRANCHNAME,'') != 'CN MANUAL'"
                
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






























































































































GO

