/*
-- =============================================
-- AUTHOR:		HIREN B DOSHI
-- ALTER_DATE: 05/07/2013
-- DESCRIPTION:	THIS PROCEDURE USED FOR CREDIT NOTE MANUAL DATA SHOW
-- REPORTNAME : CREDITNOTEMANUAL.RPT
-- =============================================
PROC_CREDITNOTE_MANUAL 1,'ACC2012_2013.DBO.','01/APR/2012','31/MARCH/2013','##2348',0,3
*/
CREATE PROCEDURE [dbo].[PROC_CREDITNOTE_MANUAL]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@FROMDATE NVARCHAR(100),
@TODATE NVARCHAR(100),
@TEMPTABLE NVARCHAR(20),
@RPTWISE INT,
@RPTTYPE AS INT	
)

AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(2000)
DECLARE @SQLCOND AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SQLJOIN =""
SET @SQLCOND=""
SET @ORDERBYSQL = ""

BEGIN

IF @RPTWISE = 0
BEGIN
SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "LM.LGR_NAME,LM.LGR_ID,"
END

ELSE IF @RPTWISE = 1
BEGIN
SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "ALM.LGR_NAME,ALM.LGR_ID,LM.LGR_NAME,LM.LGR_ID,"
END

ELSE IF @RPTWISE = 2 	
BEGIN
SET @SQLJOIN = ""
SET @ORDERBYSQL = "LM.LGR_NAME,LM.LGR_ID,"
END

ELSE IF @RPTWISE = 3
BEGIN
SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "ALM.LGR_NAME,ALM.LGR_ID,LM.LGR_NAME,LM.LGR_ID,"
END
END

BEGIN
IF @RPTTYPE = 0 /* PAID */
SET @SQLCOND = " AND CRM.CCANCEL = 1"
ELSE IF @RPTTYPE = 1 /* PENDING */
SET @SQLCOND = " AND (CRM.CCANCEL = 0 OR CRM.CCANCEL IS NULL)"
ELSE IF @RPTTYPE = 2 /* ALL */
SET @SQLCOND = ""
END
BEGIN
SET NOCOUNT ON;
SET @SQL = " SELECT CRM.CREDITNOTENO AS CNNO,CRM.REFDATE AS CNDATE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,CRM.TOTALAMT AS BALANCE,
(CASE WHEN ISNULL(CRM.NOTE,'') = '' THEN CRM.BILLNO_NARRATION ELSE CRM.NOTE + ' ' + BILLNO_NARRATION END)
 AS NARRATION,LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID
FROM "+@DATABASENAME+" CREDITNOTE_MASTER CRM 
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=CRM.LGR_ID
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND LD.CMP_CODE = CRM.CMP_CODE
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@SQLJOIN+"
WHERE CRM.CMP_CODE IN ("+@CMP_CODE+") AND CRM.REFDATE BETWEEN '"+ @FROMDATE+"' AND '"+ @TODATE +"'
"+@SQLCOND+"
ORDER BY "+@ORDERBYSQL+"CRM.REFDATE,CRM.CREDITNOTENO "
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

