/*
PROC_CREDITNOTEGST '1','ACC2016_2017.DBO.','1','2'
*/
CREATE PROCEDURE [dbo].[PROC_CREDITNOTEGST]
(
     @CMP_CODE AS NVARCHAR(100),
     @DATABASENAME AS NVARCHAR(100),     
     @FROMDOCNO AS NVARCHAR(100),
     @TODOCNO AS NVARCHAR(100)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL="" 

BEGIN
	SET NOCOUNT ON;    
SELECT @SQL="
                SELECT A.*,AI.SIGNED_QR_CODE  FROM ( SELECT LM.LGR_NAME AS PARTY ,LM.LGR_ADD1 AS ADDRESS1,LM.LGR_ADD2 AS ADDRESS2,LM.LGR_ADD3 AS ADDRESS3,CM.CITY_NAME AS PARTYCITY,
                SM.STATE_NAME AS PARTYSTATE,LM.LGR_DISTRICT,LM.CITY_PINCODE,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,TM.NARRATION,TM.TRAN_DOCNO ,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,CMP.CMP_EMAIL,
				TM.TRAN_AMOUNT,TM.TRAN_DATE,CMP.CMP_STATECODE As CmpStateCOde,LM.GSTINNO as  LGR_CSTNO,CMP.GSTINNO AS CGSTINNO ,SM.STATE_CODE AS LGR_STATECODE,TYPE_ID, CGSTPER, SGSTPER ,IGSTPER ,CGST ,SGST ,IGST,TOTALDEBITAMOUNT ,reason,note,  Ref_BILLNO AS BILLNO,
				Ref_DATE AS DATE,NETAMOUNT,ROUNDOFF,TM.IRN,TM.EINVNO,TM.ACK_DATE,TM.CMP_CODE
                FROM "+ @DATABASENAME+ "CREDITNOTEACC_MASTER TM
                /*INNER JOIN "+ @DATABASENAME+ "CREDITNOTEACC_DETAIL TD  ON TM.CREDITNOTEACC_ID=TD.CREDITNOTEACC_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE*/
                INNER JOIN  "+ @DATABASENAME+ "LEDGER_MASTER LM  ON LM.LGR_ID=TM.LGR_ID 
                INNER JOIN "+ @DATABASENAME+ "LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
                LEFT JOIN "+ @DATABASENAME+ "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID                
                LEFT JOIN "+ @DATABASENAME+ "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                LEFT JOIN "+ @DATABASENAME+ "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON TM.CMP_CODE= CMP.CMP_CODE     
                LEFT JOIN "+ @DATABASENAME+ "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                WHERE TM.CMP_CODE="+ @CMP_CODE + " AND TM.TRAN_DOCNO BETWEEN "+ @FROMDOCNO +" AND "+ @TODOCNO +" AND TM.TRAN_TYPE='GCN' AND TM.TRAN_DrCr='C' AND ISNULL(TM.BRANCHNAME,'') != 'CN MANUAL') AS A
				INNER JOIN  " + @DATABASENAME +"CREDITNOTEACC_MASTER AI ON A.TRAN_DOCNO = AI.TRAN_DOCNO AND A.CMP_CODE = AI.CMP_CODE "
                
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






















































































































GO

