/*
/*
-- =============================================
-- Author:		<PRATIK PATEL>
-- Create_date: <05/07/2013>
-- Description:	<THIS PROC IS USED IN PAYMENTRECEIPTVOUCHER.RPT>
-- ReportName : CREDITNOTEMANUALREPORT.RPT
-- =============================================
PROC_CREDITNOTEMANUALREPORT '1','ACC2013_2014.DBO.',125,125
*/
*/

CREATE PROCEDURE [dbo].[PROC_CREDITNOTEMANUALREPORT]
(
@CMP_CODE	  AS NVARCHAR(20),
@DATABASENAME AS NVARCHAR(50),
@FROMNO		  AS NVARCHAR(20),
@TONO		  AS NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000) 
DECLARE @SQL1 AS NVARCHAR(4000)

SET @SQL = ""
SET @SQL1 = ""

BEGIN
SET NOCOUNT ON;

SET @SQL = "SELECT CREDITNOTE_ID,CREDITNOTENO,VCHDATE,REFDATE,LGR_NAME,GROSSTOTAL,DDAMT,TOTALAMT,PERCENTAGE,
NOTE,AMT_WORD,ADDRESS1,ADDRESS2,ADDRESS3,PARTYSTATE,LGR_DISTRICT,CITY_PINCODE,CMP_NAME,CMP_TIN_NO,
CMP_ALIAS,CMP_ADD1,CMP_ADD2,CMP_CITY,CMP_PINCODE,CMP_STATE,CMP_PHONE1,CMP_PHONE2,CMP_MOBILE,SRNO,
VCODE,BILLNO,BILL_DATE,BILLAMOUNT,DISC_PER,DISCOUNT,TOTALLESS,NOOFDAYS,INTEREST,AMOUNT,EXLESS,
REBATEDAYS,DDDATE,PARTYCITY,AGENT,AGENT_CITY,SAL_REB_PER,SAL_REBAMT,SAL_RATEDIFFAMT,SAL_INSURANCEAMT,
SCHEMEAMT,BROK_PER,BROK_PERAMT,OTHER_PER,OTHER_PERAMT,OTHER_DISC,FLAG,PNDOCNO,PNDATE,DETAILFLAG,INTERESTRATE,
SPRD,SPSWEET,ORDERRD,ORDERSWEET
FROM (
SELECT CRM.CREDITNOTE_ID,CREDITNOTENO,CONVERT(NVARCHAR,VCHDATE,103)VCHDATE,CONVERT(NVARCHAR,REFDATE,103)REFDATE,
LM.LGR_NAME,GROSSTOTAL,DDAMT,TOTALAMT,PERCENTAGE,NOTE,AMT_WORD,ISNULL(LM.LGR_ADD1,'') AS ADDRESS1,ISNULL(LM.LGR_ADD2,'') AS ADDRESS2,
ISNULL(LM.LGR_ADD3,'') AS ADDRESS3,STATE_NAME AS PARTYSTATE,LM.LGR_DISTRICT,LM.CITY_PINCODE,CMP_NAME,CMP_TIN_NO,
CMP_ALIAS,CMP_ADD1,CMP_ADD2,CMP_CITY,CMP_PINCODE,CMP_STATE,CMP_PHONE1,CMP_PHONE2,
CMP_MOBILE,CRD.SRNO,VCODE,BILLNO,CONVERT(NVARCHAR,BILL_DATE,103)BILL_DATE,BILLAMOUNT,DISC_PER,DISCOUNT,TOTALLESS,
NOOFDAYS,CRD.INTEREST,CRD.AMOUNT,CRD.EXLESS,CRD.REBATEDAYS,CONVERT(NVARCHAR,DDDATE,103)DDDATE,CM.CITY_NAME  AS PARTYCITY,LMM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENT_CITY,
ISNULL(CRD.SAL_REB_PER,0) AS SAL_REB_PER,ISNULL(CRD.SAL_REBAMT,0) AS SAL_REBAMT,ISNULL(CRD.SAL_RATEDIFFAMT,0) AS SAL_RATEDIFFAMT,ISNULL(CRD.SAL_INSURANCEAMT,0) AS SAL_INSURANCEAMT,ISNULL(CRD.SCHEMEAMT,0) AS SCHEMEAMT,ISNULL(CRD.BROK_PER,0) AS BROK_PER,ISNULL(CRD.BROK_PERAMT,0) AS BROK_PERAMT,ISNULL(CRD.OTHER_PER,0) AS OTHER_PER,ISNULL(CRD.OTHER_PERAMT,0) AS OTHER_PERAMT,ISNULL(CRD.OTHER_DISC,0) AS OTHER_DISC,'D' AS FLAG,ISNULL(CRM.RECDOCNO,0) AS PNDOCNO,ISNULL(CONVERT(NVARCHAR,CRM.RECVCHDATE,103),0) AS PNDATE,(CASE WHEN ISNULL(CRD.FLAG,'') = 'DN' THEN 'DN' ELSE 'B' END) AS DETAILFLAG,ISNULL(CRD.INT_PER,0) AS INTERESTRATE,
ISNULL(CRD.SPRD,0) AS SPRD,ISNULL(CRD.SPSWEET,0) AS SPSWEET,ISNULL(CRD.ORDERRD,0) AS ORDERRD,ISNULL(CRD.ORDERSWEET,0) AS ORDERSWEET
FROM "+@DATABASENAME+"CREDITNOTE_MASTER CRM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CRM.LGR_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=CRM.CMP_CODE
INNER JOIN "+@DATABASENAME+"CREDITNOTE_DETAIL CRD ON CRD.CREDITNOTE_ID=CRM.CREDITNOTE_ID AND CRD.CMP_CODE=CRM.CMP_CODE
INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LMM ON LMM.LGR_ID =CRM.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=LMM.CITY_ID
WHERE CRM.CMP_CODE IN ("+@CMP_CODE+") AND CREDITNOTENO BETWEEN '"+@FROMNO+"' AND '"+@TONO+"' "

SET @SQL1 = " UNION ALL
SELECT CRM.CREDITNOTE_ID,CREDITNOTENO,CONVERT(NVARCHAR,VCHDATE,103)VCHDATE,CONVERT(NVARCHAR,REFDATE,103)REFDATE,
LM.LGR_NAME,GROSSTOTAL,DDAMT,TOTALAMT,PERCENTAGE,NOTE,AMT_WORD,ISNULL(LM.LGR_ADD1,'') AS ADDRESS1,ISNULL(LM.LGR_ADD2,'') AS ADDRESS2,
ISNULL(LM.LGR_ADD3,'') AS ADDRESS3,STATE_NAME AS PARTYSTATE,LM.LGR_DISTRICT,LM.CITY_PINCODE,CMP_NAME,CMP_TIN_NO,
CMP_ALIAS,CMP_ADD1,CMP_ADD2,CMP_CITY,CMP_PINCODE,CMP_STATE,CMP_PHONE1,CMP_PHONE2,
CMP_MOBILE,CRP.SRNO,0 AS VCODE,CRP.CHEQUENO AS BILLNO,CONVERT(NVARCHAR,CRP.DATE,103)BILL_DATE,CRP.AMOUNT AS BILLAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS TOTALLESS,
CRP.DAYS AS NOOFDAYS,CRP.INTEREST,CRP.AMOUNT,0 AS EXLESS,0 AS REBATEDAYS,CONVERT(NVARCHAR,CRP.DATE,103)DDDATE,CM.CITY_NAME  AS PARTYCITY,LMM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENT_CITY,
0 AS SAL_REB_PER,0 AS SAL_REBAMT,0 AS SAL_RATEDIFFAMT,0 AS SAL_INSURANCEAMT,0 AS SCHEMEAMT,0 AS BROK_PER,0 AS BROK_PERAMT,0 AS OTHER_PER,0 AS OTHER_PERAMT,0 AS OTHER_DISC,'P' AS FLAG,ISNULL(CRM.RECDOCNO,0) AS PNDOCNO,ISNULL(CONVERT(NVARCHAR,CRM.RECVCHDATE,103),0) AS PNDATE,(CASE WHEN ISNULL(CRP.TRAN_TYPE,'') = 'CN' THEN 'CN' ELSE 'B' END) AS DETAILFLAG,0 AS INTERESTRATE,
0 AS SPRD,0 AS SPSWEET,0 AS ORDERRD,0 AS ORDERSWEET
FROM "+@DATABASENAME+" CREDITNOTE_MASTER CRM
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=CRM.LGR_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=CRM.CMP_CODE
INNER JOIN "+@DATABASENAME+" CREDITNOTE_DETAIL_PAYMENT CRP ON CRP.CREDITNOTE_ID = CRM.CREDITNOTE_ID AND CRP.CMP_CODE = CRM.CMP_CODE
INNER JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LMM ON LMM.LGR_ID =CRM.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID=LMM.CITY_ID
WHERE CRM.CMP_CODE IN ("+@CMP_CODE+") AND CREDITNOTENO BETWEEN '"+@FROMNO+"' AND '"+@TONO+"'
) AS DETAIL ORDER BY CREDITNOTENO,FLAG,SRNO"


END

EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

