/*
 PROC_CREDITNOTEREG 2,'ACC2010_2011.DBO.','01/APR/2010','09/MAY/2011','##2310',1
*/
CREATE PROCEDURE [dbo].[PROC_CREDITNOTEREG]
(
  @CMP_CODE NVARCHAR(100),
  @DATABASENAME NVARCHAR(100),
  @FROMDATE NVARCHAR(100),
  @TODATE NVARCHAR(100),
  @TEMPTABLE NVARCHAR(20),
  @RPTWISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(2000)
SET @SQL=""
SET @SQLJOIN =""

SET @SQLJOIN=""

BEGIN
	
	if @RPTWISE = 0
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
	if @RPTWISE = 1
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
	if @RPTWISE = 2 	
		SET @SQLJOIN = ""
    if @RPTWISE = 3
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
END


BEGIN
         SET @SQL="
                   SELECT TM.TRAN_DOCNO AS CNNO,TM.TRAN_DATE AS CNDATE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
                   PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS PARTYCITY,TD.TRAN_AMOUNT AS BALANCE,TD.NARRATION
                   FROM "+@DATABASENAME+"TRAN_MASTER TM 
             	   INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE
				   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
				   INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TD.CMP_CODE
				   LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				   LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
				   LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                   "+@SQLJOIN+"
				   WHERE TM.TRAN_TYPE='CN' AND  TM.CMP_CODE="+  @CMP_CODE +" AND TM.TRAN_DATE BETWEEN '"+ @FROMDATE+"' AND '"+ @TODATE +"'
                   ORDER BY TM.TRAN_DATE,CONVERT(INT,TM.TRAN_DOCNO)
                  "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

