/*
 PROC_CREDITNOTEREGST 2,'ACC2018_2019.DBO.','01/APR/2018','31/mar/2018','',2,''
*/
CREATE PROCEDURE [dbo].[PROC_CREDITNOTEREGST]
(
  @CMP_CODE NVARCHAR(100),
  @DATABASENAME NVARCHAR(100),
  @FROMDATE NVARCHAR(100),
  @TODATE NVARCHAR(100),
  @TEMPTABLE NVARCHAR(20),
  @RPTWISE INT,
  @NOTE AS NVARCHAR(100)

)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(2000)
DECLARE @SQLNOTE AS NVARCHAR(1000)

SET @SQL=""
SET @SQLJOIN =""
SET @SQLNOTE = ""

SET @SQLJOIN=""

BEGIN
	
	if @RPTWISE = 0
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
	if @RPTWISE = 1
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
	if @RPTWISE = 2 	
		SET @SQLJOIN = ""
    if @RPTWISE = 3
		SET @SQLJOIN = " INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
END
BEGIN
	if @Note <> "ALL"
		SET @SQLNOTE = "AND NOTE = '" + @NOTE + "'"
	ELSE
		SET @SQLNOTE = "";
END



BEGIN
         SET @SQL="
                   SELECT TM.ALIAS,TM.SALES_ALIAS,ISNULL(REFNO,'')AS REFNO,TM.TRAN_DOCNO AS CNNO,TM.TRAN_DATE AS CNDATE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
                   PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS PARTYCITY,TM.NARRATION,TM.TRAN_DOCNO ,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,CMP.CMP_EMAIL,
				TM.TRAN_AMOUNT,TM.TRAN_DATE,CMP.CMP_STATECODE As CmpStateCode,LM.GSTINNO AS  LGR_CSTNO,CMP.GSTINNO AS CGSTINNO ,
				SM.STATE_CODE AS LGR_STATECODE,TYPE_ID, CGSTPER, SGSTPER ,IGSTPER ,CGST ,SGST ,IGST,TOTALDEBITAMOUNT ,reason,note,
				Ref_BILLNO,Ref_DATE,ISNULL(ROUNDOFF,0)ROUNDOFF,ISNULL(NETAMOUNT,0)NETAMOUNT,NOTE
                   FROM "+@DATABASENAME+"CREDITNOTEACC_MASTER TM 
				   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.LGR_ID
				   INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
				   LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				   LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
              LEFT JOIN "+ @DATABASENAME+ "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
				   LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
				INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON TM.CMP_CODE= CMP.CMP_CODE   
                   "+@SQLJOIN+"
				   WHERE TM.CMP_CODE="+  @CMP_CODE +" AND TM.TRAN_DATE BETWEEN '"+ @FROMDATE+"' AND '"+ @TODATE +"' " + @SQLNOTE + "
                   ORDER BY TM.TRAN_DATE,CONVERT(INT,TM.TRAN_DOCNO)
                  "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL








































GO

