/*
Proc_Current_Bale_StockReport 2,'Acc2012_2013.dbo.','31/Mar/2013',1
*/
CREATE PROCEDURE [dbo].[Proc_Current_Bale_StockReport]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@AsOnDate nvarchar(50),
@RptType INT
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @COND AS NVARCHAR(4000) SET @COND=""

BEGIN
if @RptType=1
	SET @COND=" AND STM.STOCKIN_TYPE='C'"
else if @RptType=2
	SET @COND=" AND STM.STOCKIN_TYPE='O'"
else if @RptType=3
	SET @COND=" AND STM.STOCKIN_TYPE='FP' "
else if @RptType=4
	SET @COND=" AND STM.STOCKIN_TYPE='E'"
else if @RptType=5
	SET @COND=" "

END

BEGIN
	SET NOCOUNT ON;
SET @SQL="
select IM.ITEM_NAME,SM.Screen_Name,DESIGN_COL_CHART,Count(BALENO) as BALES,STM.STOCKIN_TYPE
from "+@DataBase+" STOCKIN_MASTER STM 
inner join "+@DataBase+" STOCKIN_DETAIL STD on STM.STOCKIN_ID=STD.STOCKIN_ID  AND STD.STOCKIN_TYPE=STM.STOCKIN_TYPE
left join "+@DataBase+" Item_Master IM on STD.Item_Id=IM.ITem_Id
left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
where STM.Cmp_Code in ("+@CmpCode+") and STM.VCHDATE <= '"+@AsOnDate+"'
and std.PENDINGQUANTITY>0
"+@COND+"
group by IM.ITEM_NAME,SM.Screen_Name,DESIGN_COL_CHART,STM.STOCKIN_TYPE
ORDER BY IM.ITEM_NAME,SM.Screen_Name
"
END
EXECUTE Sp_ExecuteSql @SQL
PRINT @SQL




















GO

