SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO









/*-- =============================================
-- Author:		<NITESH DAN CHARAN>
-- Create date: <24/01/2020,04:07,AM>
-- Description:	<PROC_DAILY_EXPENSES_REPORT IS USED TO DAILY EXPENSES DAY REPORT,FOR LERNING PURPOSE ONLY,>

PROC_DAILY_EXPENSES_REPORT 1,'ACC2019_2020.DBO.','01/APR/2019','31/MAR/2020','##4196','1'

select * from tempdb..sysobjects
-- =============================================*/
CREATE PROCEDURE [dbo].[PROC_DAILY_EXPENSES_REPORT]
(
@Cmp_Code nvarchar(100),    
@DatabaseName nvarchar(50),   
@FromDate  nvarchar(20),
@ToDate nvarchar(20),
@Temptable AS NVARCHAR(20),
@Rpt_Wise int
--@HEADID AS NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(3999)	
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @JOINSQL AS NVARCHAR(1000)
--DECLARE @HEADSQL AS NVARCHAR(1000)


SET @SQL=""
SET @SELECTED=""
SET @JOINSQL=""
--SET @HEADSQL=""

 BEGIN
         IF @RPT_WISE=1
          SET @JOINSQL="INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"
        ELSE IF @RPT_WISE=2
          SET @JOINSQL=""
  END
--  BEGIN
--		if @HEADID=0
--			SET @HEADSQL=""
--		ELSE 
--			SET @HEADSQL=" AND LM.LGR_ID="+@HEADID +" "
--END

BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

  SET @SQL="
			SELECT DATE,AMOUNT,HEAD,LGR_ID,TRAN_TYPE FROM(
			SELECT TM.Tran_Date AS DATE,TD.TRAN_AMOUNT as Amount,LM.LGR_NAME as Head,LM.LGR_ID,TD.TRAN_TYPE
			FROM "+@DatabaseName+" TRAN_DETAIL TD
			INNER JOIN "+@DatabaseName+"   TRAN_MASTER TM ON TD.TRAN_ID = TM.TRAN_ID AND TD.CMP_CODE = TM.CMP_CODE
			AND TD.TRAN_TYPE = TM.TRAN_TYPE
			INNER JOIN "+@DatabaseName+"  LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID=LM.LGR_ID
			INNER JOIN "+@DatabaseName+"  LEDGER_DETAIL LD ON  LM.LGR_ID = LD.LGR_ID
			LEFT JOIN  "+@DatabaseName+"  CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  "+@DatabaseName+"  STATE_MASTER SM ON LM.STATE_ID = SM.STATE_ID
			INNER JOIN "+@DatabaseName+"  GROUP_MASTER AC ON  AC.GRP_ID=ld.grp_Id
			"+@JOINSQL+"
			WHERE TD.TRAN_TYPE IN ('CP','BP') AND TD.CMP_CODE IN ("+@Cmp_Code+") AND AC.grp_name in ('Expenses(Indirect/Admn)','Expenses(Direct/Mfgr.)','Purchase')
			AND TM.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
			)AS A GROUP BY DATE,HEAD,LGR_ID,AMOUNT,TRAN_TYPE
			ORDER BY DATE,HEAD
"     
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL







GO

