/*
-- =============================================
-- AUTHOR:		PRATIK PATEL
-- ALTER_DATE: 15-10-2018
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESS PENDING REGISTER BUNCH NO WISE
-- REPORTNAME : PROCESSPENDING_BUNCHREG.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_DAILYPRODUCTIONBUNCHREPORT 1,'ACC2018_2019.DBO.',2,'01/APR/2018','31/MARCH/2019','##4244'
*/
CREATE PROCEDURE [dbo].[PROC_DAILYPRODUCTIONBUNCHREPORT]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20)

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""


BEGIN
IF @RPT_WISE = 1 /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " PROCESS_NAME,ISNULL(PROCESS_ID,0),VCHDATE,BUNCHNO,SRNO "
END
ELSE IF @RPT_WISE = 2/*PARTY NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 3 /*CONTRACTOR NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = CM.CONTRACTOR_ID "
SET @STRORDERBY = " CM.CONTRACTOR_NAME,ISNULL(CM.CONTRACTOR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 4 /*MACHINE NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = MM.MACHINE_ID "
SET @STRORDERBY = " MM.MACHINE_NAME,ISNULL( MM.MACHINE_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE  = 5 /*LORRYWALA NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LRM.LORIWALA_ID "
SET @STRORDERBY = " LRM.LORIWALA_NAME,ISNULL(LRM.LORIWALA_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 6 /*BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 7 /*GREY MARKA NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 8 /*PROCESS / PARTY WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 9 /*PROCESS / BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL( TPM.PROCESS_ID ,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 10 /*PROCESS / GREY MARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 11 /*PARTY / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 12 /*BUNCHNAME / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
