ELSE IF @RPT_WISE = 29 /*DESIGN / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
