[PROC_DAILYPRODUCTIONREPORT] 1,'ACC2018_2019.DBO.',31,'01/APR/2018','31/MARCH/2019','##2176'
*/
CREATE PROCEDURE [dbo].[PROC_DAILYPRODUCTIONREPORT]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20)

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""



BEGIN
IF @RPT_WISE = 1 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
