END
IF @RPT_WISE = 8 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
