IF @RPT_WISE = 9 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),BM.BUNCHNAME,ISNULL( BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
IF @RPT_WISE = 10 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
