ELSE IF  @RPT_WISE = 12 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
