SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),BM.BUNCHNAME,ISNULL( BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 35 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
