--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,TLM.LGR_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 9 /* PROCESS - BUNCH NAME */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,BM.BUNCHNAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 10 /* PROCESS - GREY MARKA */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,LM.LOT_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 11  /* PARTY - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
--SET @STRORDERBY = " TLM.LGR_NAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 12 /* BUNCH NAME - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
--SET @STRORDERBY = " BM.BUNCHNAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END

END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = " SELECT P2P.PROCESSID,P2P.DOCNO,P2P.VCHDATE,P2PD.LRNO,CONVERT(NVARCHAR,P2PD.LOTNO) AS LOTNO,FPM.PROCESS_NAME AS FROMPROCESS, TPM.PROCESS_NAME AS TOPROCESS,
ISNULL(FLM.LGR_NAME,'') AS FROMPARTY,ISNULL(TLM.LGR_NAME,'') AS TOPARTY,CM.CONTRACTOR_NAME AS CONTRACTOR,
MM.MACHINE_NAME AS MACHINE,LRM.LORIWALA_NAME AS LORIWALA,ISNULL(DM.DRIVER_NAME,'') AS DRIVERNAME,
LM.LOT_NAME AS GREYMARKA,BM.BUNCHNAME,P2PD.THAN,P2PD.METER,P2PD.ISSUETHAN,P2PD.ISSUEMETER,P2PD.PENDINGTHAN,P2PD.PENDINGMETER,
P2P.TOTALTHAN,P2P.TOTALMETER, CMP.CMP_ALIAS,
ISNULL(TPM.PROCESS_ID,0) TOPROCESS_ID,ISNULL(FPM.PROCESS_ID,0)  AS FROMPROCESS_ID,
ISNULL(TLM.LGR_ID,0) AS TOPARTYID,ISNULL(FLM.LGR_ID,0) AS FROMPARTY_ID,ISNULL(CM.CONTRACTOR_ID,0) AS CONTRACTOR_ID,
ISNULL(MM.MACHINE_ID,0) AS MACHINE_ID,ISNULL(LRM.LORIWALA_ID,0) AS LORIWALA_ID,ISNULL(DM.DRIVER_ID,0) AS DRIVER_ID, ISNULL(LM.LOT_ID,0) AS LOT_ID,
ISNULL(BM.BUNCHNAME_ID,0) AS BUNCHNAME_ID,ISNULL(DSM.DESIGN_ID,0) DESIGN_ID ,ISNULL(DSM.DESIGN_NAME,'') AS DESIGN_NAME

FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS_DETAIL P2PD ON P2P.PROCESSID = P2PD.PROCESSID AND P2P.CMP_CODE = P2PD.CMP_CODE AND P2P.FLAG = P2PD.FLAG
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON TPM.PROCESS_ID = P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2P.FROM_PROCESS_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER TLM ON TLM.LGR_ID = P2P.TO_LGR_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+" CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID = P2P.CONTRACTOR_ID
INNER JOIN "+@DATABASENAME+" MACHINE_MASTER MM ON MM.MACHINE_ID = P2P.MACHINE_ID 
INNER JOIN "+@DATABASENAME+" LORIWALA_MASTER LRM ON LRM.LORIWALA_ID = P2P.LORIWALA_ID
LEFT JOIN  "+@DATABASENAME+" DRIVER_MASTER DM ON DM.DRIVER_ID = P2P.DRIVER_ID
INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2P.CMP_CODE
LEFT JOIN "+@DATABASENAME+" DESIGN_MASTER DSM ON P2PD.DESIGN_ID  = DSM.DESIGN_ID
"+@SQLJOIN+"
WHERE P2P.CMP_CODE IN ("+@CMP_CODE+") AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND P2P.FLAG IN ('P2P') "+@STRCOND+@INOUTTYPE+"  ORDER BY "+@STRORDERBY+" "
END
PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL























GO

/****** Object:  StoredProcedure [dbo].[PROC_DAYBOOK_REPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO









/*
-- =============================================
-- EDIT_AUTHOR    : <NITESH CHARAN>
-- EDIT_DATE      : <28/01/2020>
-- REPORT_FORM    :	<RFRMDAYBOOK_REPORT>
-- CRYSTAL_REPORT : <DAYBOOK_REPORT.RPT>
-- =============================================
PROC_DAYBOOK_REPORT '1','ACC2019_2020.DBO.','01/APR/2019','31/MAR/2020'
*/

CREATE PROCEDURE [dbo].[PROC_DAYBOOK_REPORT]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20) 
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""

BEGIN
SET @SQL=" 

		SELECT TM.TRAN_DOCNO AS DOCNO,TM.TRAN_TYPE,TM.TRAN_DATE, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
		(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
		(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM1.LGR_ID,TM.Tran_Id
		FROM "+@DATABASENAME+"  TRAN_MASTER TM  
		--INNER JOIN "+@DATABASENAME+" TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 	
		INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID 
		INNER JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
		INNER JOIN "+@DATABASENAME+"  GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID  
		LEFT JOIN "+@DATABASENAME+"   CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID  
		WHERE TM.CMP_CODE IN("+@CMP_CODE+")  AND TM.TRAN_TYPE NOT IN ('J','DN','DN') AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'	
		--GROUP BY TM.TRAN_DOCNO,TM.TRAN_TYPE,TM.TRAN_DATE,LM1.LGR_NAME,CM.CITY_NAME,TM.TRAN_DRCR,LM1.LGR_ID,TM.TRAN_ID,TM.TRAN_AMOUNT,TD.TRAN_AMOUNT	
		union all 
		SELECT TM.TRAN_DOCNO AS DOCNO,TM.TRAN_TYPE,TM.TRAN_DATE, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
		(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
		(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM1.LGR_ID,TM.Tran_Id
		FROM "+@DATABASENAME+"  TRAN_MASTER TM 
		INNER JOIN "+@DATABASENAME+"  TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
		INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
		INNER JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
		INNER JOIN "+@DATABASENAME+"  GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID           
		LEFT JOIN "+@DATABASENAME+"  CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID 
		WHERE TM.CMP_CODE IN("+@CMP_CODE+")  AND TM.TRAN_TYPE NOT IN('J','DN','CN') AND  TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
		UNION ALL"
		
	    SET @SQL1="		
		SELECT  TM.TRAN_DOCNO AS DOCNO,TM.TRAN_TYPE,TM.TRAN_DATE,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT ,LM1.LGR_ID,TM.TRAN_ID
		FROM "+@DATABASENAME+"  AUTOJOURNAL AJ 
		INNER JOIN "+@DATABASENAME+"  TRAN_MASTER TM ON TM.TRAN_TYPE= AJ.EntryType AND TM.TRAN_ID = AJ.VCODE
		INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
		INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM1 ON AJ.LGR_ID= LM1.LGR_ID
		INNER JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
		INNER JOIN "+@DATABASENAME+"  GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
		LEFT JOIN "+@DATABASENAME+"  CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID  
		WHERE AJ.VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND AJ.CMP_CODE IN("+@CMP_CODE+")
		
		UNION ALL
		
		SELECT TM.TRAN_DOCNO AS DOCNO,TM.TRAN_TYPE,TM.TRAN_DATE, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, (CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT ,LM.LGR_ID,TM.TRAN_ID
		FROM "+@DATABASENAME+"  TRAN_MASTER TM 
		INNER JOIN "+@DATABASENAME+"  TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
		INNER JOIN "+@DATABASENAME+"  TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  AND JD.CMP_CODE= TM.CMP_CODE 
		INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
		INNER JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
		INNER JOIN "+@DATABASENAME+"  GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
		LEFT JOIN "+@DATABASENAME+"  CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID     		
		WHERE TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND TM.TRAN_TYPE  IN ('J','DN','CN')
		ORDER BY TRAN_DATE,TRAN_TYPE,TM.Tran_Id,LGR_ID

	
"
END
PRINT @SQL
PRINT @SQL1
EXEC(@SQL+ @SQL1)

  
  







GO

/****** Object:  StoredProcedure [dbo].[PROC_DAYSUMMARY_ACCOUNT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_DAYSUMMARY_ACCOUNT]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20) 
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""

BEGIN
SET @SQL=" 

SELECT HEADING,TRAN_DATE,UPPER(ACCOUNTGROUP)AS ACCOUNTGROUP,SUM(TRAN_AMOUNT) AS TRAN_AMOUNT,ORD,ACCGRPID  FROM( 
SELECT (CASE WHEN TM.TRAN_TYPE='BR' THEN 'BANK RECEIPT' WHEN TM.TRAN_TYPE='BP' THEN 'BANK PAYMENT' 
WHEN TM.TRAN_TYPE='CR' THEN 'CASH RECEIPT' WHEN TM.TRAN_TYPE='CP' THEN 'CASH PAYMENT'
WHEN TM.TRAN_TYPE='J' THEN 'JOURNAL' 
WHEN TM.TRAN_TYPE='DN' THEN 'DEBIT NOTE' WHEN TM.TRAN_TYPE='CN' THEN 'CREDIT NOTE'
WHEN TM.TRAN_TYPE='SR' THEN 'SALES RETURN' WHEN TM.TRAN_TYPE='PR' THEN 'PURCHASE RETURN' ELSE '' END) AS HEADING
,TM.TRAN_DATE,GM.GRP_NAME AS ACCOUNTGROUP,TM.TRAN_AMOUNT
,(CASE WHEN TM.TRAN_TYPE='BR' THEN 1 WHEN TM.TRAN_TYPE='BP' THEN 2
WHEN TM.TRAN_TYPE='CR' THEN 3 WHEN TM.TRAN_TYPE='CP' THEN 4
WHEN TM.TRAN_TYPE='J' THEN 5
WHEN TM.TRAN_TYPE='DN' THEN 6 WHEN TM.TRAN_TYPE='CN' THEN 7
WHEN TM.TRAN_TYPE='SR' THEN 8 WHEN TM.TRAN_TYPE='PR' THEN 9 ELSE 0 END) AS ORD,GM.GRP_ID AS ACCGRPID
FROM "+@DATABASENAME+"TRAN_MASTER TM      
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=TM.TRAN_MASTER_ID AND TM.CMP_CODE=LD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
WHERE TM.TRAN_DRCR='CRD' AND TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
AND TM.TRAN_TYPE IN ('BR','BP','CR','CP','J','DN','CN','SR','PR') 
"
SET @SQL1=" UNION ALL 
SELECT (CASE WHEN TM.TRAN_TYPE='BR' THEN 'BANK RECEIPT' WHEN TM.TRAN_TYPE='BP' THEN 'BANK PAYMENT' 
WHEN TM.TRAN_TYPE='CR' THEN 'CASH RECEIPT' WHEN TM.TRAN_TYPE='CP' THEN 'CASH PAYMENT'
WHEN TM.TRAN_TYPE='J' THEN 'JOURNAL' 
WHEN TM.TRAN_TYPE='DN' THEN 'DEBIT NOTE' WHEN TM.TRAN_TYPE='CN' THEN 'CREDIT NOTE'
WHEN TM.TRAN_TYPE='SR' THEN 'SALES RETURN' WHEN TM.TRAN_TYPE='PR' THEN 'PURCHASE RETURN' ELSE '' END) AS HEADING
,TM.TRAN_DATE,GM.GRP_NAME AS ACCOUNTGROUP,TD.TRAN_AMOUNT
,(CASE WHEN TM.TRAN_TYPE='BR' THEN 1 WHEN TM.TRAN_TYPE='BP' THEN 2
WHEN TM.TRAN_TYPE='CR' THEN 3 WHEN TM.TRAN_TYPE='CP' THEN 4
WHEN TM.TRAN_TYPE='J' THEN 5
WHEN TM.TRAN_TYPE='DN' THEN 6 WHEN TM.TRAN_TYPE='CN' THEN 7
WHEN TM.TRAN_TYPE='SR' THEN 8 WHEN TM.TRAN_TYPE='PR' THEN 9 ELSE 0 END) AS ORD,GM.GRP_ID AS ACCGRPID
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE	  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=TD.TRAN_DETAIL_ID AND TD.CMP_CODE=LD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
WHERE   TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' 
AND  TM.TRAN_TYPE IN ('BR','BP','CR','CP','J','DN','CN','SR','PR')
UNION ALL
SELECT 'DISCOUNT/INTEREST' AS HEADING,AJ.VDATE,LM.LGR_NAME AS ACCOUNTGROUP,
(CASE WHEN AJ.DRAMOUNT>0THEN AJ.DRAMOUNT ELSE AJ.CRAMOUNT END) AS TRAN_AMOUNT,11 AS ORD,LM.LGR_ID AS ACCGRPID
FROM "+@DATABASENAME+"AUTOJOURNAL AJ
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID=LM.LGR_ID 	  
WHERE AJ.CMP_CODE IN("+@CMP_CODE+") AND AJ.VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' 
) AS DETAIL
GROUP BY  HEADING,TRAN_DATE,ACCOUNTGROUP,ACCGRPID,ORD
ORDER BY  TRAN_DATE,ORD,HEADING,ACCOUNTGROUP,ACCGRPID
"
END
PRINT @SQL
PRINT @SQL1
EXEC(@SQL+@SQL1)




















GO

