/*
PROC_DAYSUMMARY_PROCESS '10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011'
REPORT NAME :- DAYWISESUMM_PROCESS.RPT
*/
CREATE PROCEDURE [dbo].[PROC_DAYSUMMARY_PROCESS]
(
 @CMP_CODE AS NVARCHAR(100),
 @DATABASENAME AS NVARCHAR(100),
 @FROMDATE AS NVARCHAR(20),
 @TODATE AS NVARCHAR(20) 
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
SET @SQL="
		SELECT UPPER(HEADING) AS HEADING,VCHDATE,SUM(THAN)AS THAN,SUM(METER)AS METER ,PROCESSID
		FROM(
		SELECT PI.VCHDATE,PID.PIECES AS THAN,PID.QUANTITY AS METER ,'PURCHASE' AS HEADING,1 AS ORD, 0 AS PROCESSID
		FROM "+@DATABASENAME+"PURCHASEINVOICE PI
		INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID AND IM.ITEM_TYPE='RM'
		WHERE PI.CMP_CODE IN("+@CMP_CODE +") AND PI.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
		UNION ALL
		SELECT LA.VCHDATE,LA.TOTALTHAN AS THAN,LA.TOTALMETER AS METER,'LOT ALLOCATION ' AS HEADING,2 AS ORD, 0 AS PROCESSID
		FROM "+@DATABASENAME+"LOTALLOCATION LA
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID AND IM.ITEM_TYPE='RM'
		WHERE LA.CMP_CODE IN("+@CMP_CODE +") AND LA.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
		UNION ALL
		SELECT P2P.VCHDATE,P2P.DELTHAN  AS THAN,P2P.DELMETER AS METER,PM.PROCESS_NAME AS HEADING,3 AS ORD, P2P.TO_PROCESS_ID AS PROCESSID
		FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
		INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID AND IM.ITEM_TYPE='RM'
		WHERE P2P.CMP_CODE IN("+@CMP_CODE +") AND P2P.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
		UNION ALL
		SELECT F2F.VCHDATE,FTGR.GRAYTHAN AS THAN,FTGR.GRAYMETER AS METER,'SHORTAGE' AS HEADING,4 AS ORD, 0 AS PROCESSID
		FROM "+@DATABASENAME+"FINISH2GODOWN F2F
		INNER JOIN "+@DATABASENAME+"FTGRECDETAIL FTGR ON F2F.FTGID=FTGR.FTGID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=F2F.ITEM_ID AND IM.ITEM_TYPE='RM'
		WHERE F2F.CMP_CODE IN("+@CMP_CODE +") AND F2F.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
		)AS DETAIL
		GROUP BY VCHDATE,HEADING,ORD,PROCESSID
		ORDER BY ORD,VCHDATE,PROCESSID
"
END

PRINT @SQL
EXEC (@SQL)




















GO

