                SELECT LM.LGR_NAME AS PARTY ,LM.LGR_ADD1 AS ADDRESS1,LM.LGR_ADD2 AS ADDRESS2,LM.LGR_ADD3 AS ADDRESS3,CM.CITY_NAME AS PARTYCITY,
                SM.STATE_NAME AS PARTYSTATE,ALM.LGR_NAME AS AGENT,LM.LGR_DISTRICT,LM.CITY_PINCODE,ACM.CITY_NAME AS AGENTCITY,TM.NARRATION,TM.TRAN_DOCNO ,
				TD.TRAN_AMOUNT,TM.TRAN_DATE,COM.GSTINNO AS CMP_GSTNO,LM.GSTINNO AS PARTYGSTNO,TM.NOTE,COM.CMP_PHONE1,COM.CMP_MOBILE,TM.REC_AMT,TM.TCS_PER,TM.TCS_AMT
                FROM "+ @DATABASENAME+ "TRAN_MASTER TM
                INNER JOIN "+ @DATABASENAME+ "TRAN_DETAIL TD  ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
                INNER JOIN  "+ @DATABASENAME+ "LEDGER_MASTER LM  ON LM.LGR_ID=TD.TRAN_DETAIL_ID 
                INNER JOIN "+ @DATABASENAME+ "LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
                LEFT JOIN "+ @DATABASENAME+ "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID                
                LEFT JOIN "+ @DATABASENAME+ "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                LEFT JOIN "+ @DATABASENAME+ "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
