CREATE PROCEDURE [dbo].[PROC_DEBITNOTE_MANUAL]
(
@CMP_CODE AS NVARCHAR(20),
@DATABASENAME AS NVARCHAR(50),
@FROMNO AS NVARCHAR(20),
@TONO AS NVARCHAR(20)

)

AS
/*

*/
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
BEGIN
SET @SQL1="  SELECT DM.DEBITNOTE_ID,DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,SM.STATE_NAME,
DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
'' AS BILLNO,'' AS BILLDATE,0 AS BILLAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS OTHERLESS,0 AS DAYS, 0 AS INTEREST,'M' AS FLAG,DM.REBATEDAYS,DM.REMARK,INT_PER,0 AS SRNO,1 AS ORD,DM.REFDATE,
0 AS SPRD,0 AS SPSWEET,0 AS ORDERRD,0 AS ORDERSWEET,0 AS NETDAYS,'' AS ITEMDETAIL, 0 AS CRDAYS
FROM  "+@DATABASENAME+"DEBITNOTE_MASTER DM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
WHERE DM.CMP_CODE="+  @CMP_CODE +" AND DM.DEBITNOTENO BETWEEN "+ @FROMNO +" AND "+ @TONO +"
UNION ALL   "
SET @SQL2="  SELECT DM.DEBITNOTE_ID,DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,SM.STATE_NAME,
DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
DDB.BILLNO,DDB.BILL_DATE,DDB.BILLAMOUNT,DDB.DISC_PER,DDB.DISCOUNT,DDB.OTHERLESS,DDB.DAYS,DDB.INTEREST,'D' AS FLAG,DM.REBATEDAYS,DM.REMARK,DM.INT_PER,DDB.SRNO,2 AS ORD,DM.REFDATE,
ISNULL(DDB.SPRD,0) AS SPRD,ISNULL(DDB.SPSWEET,0) AS SPSWEET,ISNULL(DDB.ORDERRD,0) AS ORDERRD,ISNULL(DDB.ORDERSWEET,0) AS ORDERSWEET
,ISNULL(NETDAYS,0) AS NETDAYS,ITEMDETAIL,DDB.CRDAYS
FROM "+@DATABASENAME+"DEBITNOTE_MASTER DM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN "+@DATABASENAME+"DEBITNOTE_DETAIL_BILL DDB ON DDB.DEBITNOTE_ID=DM.DEBITNOTE_ID
INNER JOIN "+@DATABASENAME+"PARTYDETAIL PD ON PD.BILL_NO=DDB.BILLNO AND PD.VCODE=DDB.VCODE AND PD.JOBFLAG = DDB.FLAG
WHERE DM.CMP_CODE="+  @CMP_CODE +" AND DM.DEBITNOTENO BETWEEN "+ @FROMNO +" AND "+ @TONO +" 
UNION ALL "
SET @SQL3="  SELECT DM.DEBITNOTE_ID,DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,SM.STATE_NAME,
DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
DDP.CHEQUENO,DDP.DATE,DDP.AMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS OTHERLESS,DDP.DAYS,DDP.INTEREST,'P' AS FLAG,DM.REBATEDAYS,DM.REMARK,INT_PER,DDP.SRNO,3 AS ORD,DM.REFDATE,
0 AS SPRD,0 AS SPSWEET,0 AS ORDERRD,0 AS ORDERSWEET,0 AS NETDAYS,'' AS ITEMDETAIL,0 AS CRDAYS
FROM "+@DATABASENAME+"DEBITNOTE_MASTER DM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN "+@DATABASENAME+"DEBITNOTE_DETAIL_PAYMENT DDP ON DDP.DEBITNOTE_ID=DM.DEBITNOTE_ID
WHERE DM.CMP_CODE="+  @CMP_CODE +" AND DM.DEBITNOTENO BETWEEN "+ @FROMNO +" AND "+ @TONO +" 
ORDER BY DEBITNOTE_ID,ORD,BILLDATE,BILLNO,SRNO
"

END


EXEC (@SQL1+@SQL2+@SQL3)
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

