CREATE PROCEDURE [dbo].[PROC_DEBITNOTE_REPORT]
(
@CMP_CODE AS NVARCHAR(20),
@DATABASENAME AS NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@RPTWISE AS INT,
@RPTTYPE AS INT
)
AS
/*
EXEC PROC_DEBITNOTE_REPORT 1,'ACC2014_2015.DBO.','01-APR-2014','09-OCT-2014','##2564',2,3
*/
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(100)
DECLARE @SQLCOND AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)

SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQLJOIN=""
SET @SQLCOND = ""
SET @ORDERBYSQL = ""

BEGIN

IF @RPTWISE = 0
BEGIN
SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "LM.LGR_NAME,LM.LGR_ID,"
END
IF @RPTWISE = 1
BEGIN
SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON ALM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "ALM.LGR_NAME,ALM.LGR_ID,LM.LGR_NAME,LM.LGR_ID,"
END
IF @RPTWISE = 2 	
BEGIN
SET @SQLJOIN = ""
SET @ORDERBYSQL = "LM.LGR_NAME,LM.LGR_ID,"
END
IF @RPTWISE = 3
BEGIN
SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON ALM.LGR_ID=TT.CODE"
SET @ORDERBYSQL = "ALM.LGR_NAME,ALM.LGR_ID,LM.LGR_NAME,LM.LGR_ID,"
END
END

BEGIN
IF @RPTTYPE = 0 /* PAID */
SET @SQLCOND = " AND DM.INUSE = 1"
ELSE IF @RPTTYPE = 1 /* PENDING */
SET @SQLCOND = " AND (DM.INUSE = 0 OR DM.INUSE IS NULL)"
ELSE IF @RPTTYPE = 2 /* ALL */
SET @SQLCOND = ""
END
BEGIN
SET @SQL1="  
SELECT DM.CMP_CODE,DM.DEBITNOTE_ID,DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS DBDATE,
DM.BALAMT,DM.REMARK,INT_PER,DM.REBATEDAYS,DM.LGR_ID,LM.LGR_NAME AS PARTY,CM.CITY_NAME,
CMA.CITY_NAME ACITYNAME,LD.AGENT_ID,ALM.LGR_NAME AS AGENT,
DM.REBATEDAYS,DM.REMARK,DM.BILLNO_NARRATION
FROM  "+@DATABASENAME+"DEBITNOTE_MASTER DM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID					                      
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CMA ON ALM.CITY_ID=CMA.CITY_ID
"+ @SQLJOIN +"                    
WHERE DM.CMP_CODE="+  @CMP_CODE +" AND DM.VCHDATE BETWEEN '"+ @FROMDATE+"' AND '"+ @TODATE +"'
"+@SQLCOND+"
ORDER BY "+@ORDERBYSQL+"DM.VCHDATE,DM.DEBITNOTENO"
END
EXEC (@SQL1)
PRINT @SQL1




















GO

