CREATE PROCEDURE [dbo].[PROC_DEBITNOTE_VOUCHER]
(	
	@CMP_CODE	  AS NVARCHAR(20),
	@DATABASENAME AS NVARCHAR(50),
	@FROMNO		  AS NVARCHAR(20),
	@TONO		  AS NVARCHAR(20)
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
SET @SQL1 = ""
SET @SQL2 = ""
SET @SQL3 = ""



BEGIN
	SET NOCOUNT ON;
	
	SET @SQL1 = " SELECT DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				  SM.STATE_NAME,DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				  '' AS BILLNO,'' AS BILLDATE,0 AS CHEQUENO,0 AS DAYS,0 AS CRDAYS,0 AS AMOUNT,0  AS DIS,
				  0 AS DISCOUNT,0 AS RD,0 AS SR,0 AS SRAMT,0 AS INSURANCE,0 AS SCHEME,0 AS OLESS,0 AS TOTAL,
				  0 AS ADJUST,DM.INT_PER AS INT,0 AS INTREC,DM.REMARK,'M' AS FLAG,
				  0 AS MAINAMOUNT,0 AS MAININTERESTTOTAL,0 AS FINALTOTAL,DM.REBATEDAYS AS REBATEDAYS
				  
				  FROM "+@DATABASENAME+" DEBITNOTE_MASTER DM
                  INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
                  LEFT JOIN  "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                  LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                  LEFT JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                  WHERE DM.CMP_CODE= "+@CMP_CODE+" AND DM.DEBITNOTENO BETWEEN "+@FROMNO+" AND "+@TONO+"
				  UNION ALL "

	SET @SQL2= "  SELECT DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				 SM.STATE_NAME,DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				 DDB.BILLNO,DDB.BILL_DATE AS BILLDATE,0 AS CHEQUENO,DDB.DAYS, 
				 DATEDIFF(DAY,DDB.BILL_DATE,DM.VCHDATE) AS CRDAYS,
				 DDB.BILLAMOUNT AS AMOUNT,DDB.DISC_PER AS DIS,
				 DDB.DISCOUNT,DDB.SAL_RATEDIFFAMT AS RD,DDB.SAL_REB_PER AS SR,DDB.SAL_REBAMT AS SRAMT,
				 DDB.SAL_INSURANCEAMT AS INSURANCE,DDB.SCHEMEAMT AS SCHEME,DDB.OTHERLESS AS OLESS,
				 0 AS TOTAL,0 AS ADJUST,DDB.INTEREST AS INT,0 AS INTREC,'' AS REMARK,
				 'D' AS FLAG,DM.TOTALAMT AS MAINAMOUNT,DM.DDAMT AS MAININTERESTTOTAL,DM.BALAMT,0 AS REBATEDAYS

				 FROM "+@DATABASENAME+" DEBITNOTE_MASTER DM 
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = DM.LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
				 LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
				 LEFT JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
				 LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				 INNER JOIN "+@DATABASENAME+"  DEBITNOTE_DETAIL_BILL DDB ON DDB.DEBITNOTE_ID = DM.DEBITNOTE_ID 
				  WHERE DM.CMP_CODE= "+@CMP_CODE+" AND DM.DEBITNOTENO BETWEEN "+@FROMNO+" AND "+@TONO+"
				 UNION ALL "

	SET @SQL3= " SELECT DM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				 SM.STATE_NAME,DM.DEBITNOTENO,CONVERT(NVARCHAR,DM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				 '' AS BILLNO,DDP.DATE AS BILLDATE,DDP.CHEQUENO AS CHEQUENO,DATEDIFF(DAY,DDP.DATE,DM.VCHDATE) AS DAYS,
				 DDP.DAYS AS CRDAYS,DDP.AMOUNT,0 AS DIS,0 AS DISCOUNT,0 AS RD,0 AS SR,0 AS SRAMT,0 AS INSURANCE,
				 0 AS SCHEME,0 AS OLESS,0 AS TOTAL,0 AS ADJUST,DDP.INTEREST AS INT,0 AS INTREC,'' AS REMARK,
				 'P' AS FLAG,0 AS MAINAMOUNT,0 AS MAININTERESTTOTAL,0 AS FINALTOTAL	,0 AS REBATEDAYS						

				 FROM "+@DATABASENAME+" DEBITNOTE_MASTER DM
                 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
                 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                 LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                 LEFT JOIN "+@DATABASENAME+"  LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
                 LEFT JOIN "+@DATABASENAME+"  LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                 INNER JOIN "+@DATABASENAME+" DEBITNOTE_DETAIL_PAYMENT DDP ON DDP.DEBITNOTE_ID = DM.DEBITNOTE_ID
                 WHERE DM.CMP_CODE= "+@CMP_CODE+" AND DM.DEBITNOTENO BETWEEN "+@FROMNO+" AND "+@TONO+" "
					

END

EXEC (@SQL1+@SQL2+@SQL3)
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

