CREATE PROCEDURE [dbo].[PROC_DEBITNOTEGST_REPORT]
(
@CMP_CODE AS NVARCHAR(20),
@DATABASENAME AS NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@RPTWISE AS INT,
@RPTTYPE AS INT,
@Note AS NVARCHAR(100)

)
	
AS
/*
PROC_DEBITNOTEGST_REPORT N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'31/Mar/2019', N'##1068', 0, 0, N'DR Note Issued Against Sale'

select * from tempdb..sysobjects

*/
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(100)
DECLARE @SQLCOND AS NVARCHAR(1000)
DECLARE @SQLNOTE AS NVARCHAR(1000)


SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQLJOIN=""
SET @SQLCOND = ""
SET @SQLNOTE = ""
BEGIN
	
	if @RPTWISE = 0
		SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
	if @RPTWISE = 1
		SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
	if @RPTWISE = 2 	
		SET @SQLJOIN = ""
    if @RPTWISE = 3
		SET @SQLJOIN = "INNER JOIN " + @TEMPTABLE + " TT ON ALM.Lgr_ID=TT.Code"
END

BEGIN
	IF @RPTTYPE = 0 /* PAID */
		SET @SQLCOND = " "
	ELSE IF @RPTTYPE = 1 /* PENDING */
		SET @SQLCOND = " "
	ELSE IF @RPTTYPE = 2 /* ALL */
		SET @SQLCOND = ""
END
BEGIN
	if @Note <> "ALL"
		SET @SQLNOTE = "AND NOTE = '" + @NOTE + "'"
	ELSE
		SET @SQLNOTE = "";
END
BEGIN
         SET @SQL1="  
SELECT ISNULL(DM.REFNO,'')REFNO,DM.CMP_CODE,DM.DebitNoteAcc_Id,DM.Tran_DocNo AS DebitNoteNo,CONVERT(NVARCHAR,DM.TRAN_DATE,103) AS DBDATE,DM.Lgr_Id,LM.LGR_NAME AS PARTY,CM.CITY_NAME,CMA.CITY_NAME ACITYNAME,LD.AGENT_ID,ALM.LGR_NAME AS AGENT,
DM.TRAN_AMOUNT,CMP.CMP_STATECODE As CmpStateCOde,LM.GSTINNO as LGR_CSTNO,CMP.GSTINNO AS CGSTINNO ,SM.STATE_CODE AS LGR_STATECODE,TYPE_ID, CGSTPER, 
SGSTPER ,IGSTPER ,CGST ,SGST ,IGST,TOTALDEBITAMOUNT ,reason,note,Ref_BILLNO,Ref_DATE,ISNULL(ROUNDOFF,0)ROUNDOFF,ISNULL(NETAMOUNT,0)NETAMOUNT,
DM.SALES_ALIAS,DM.ALIAS AS ALIAS,Note
FROM  "+@DATABASENAME+"DebitNoteAcc_MASTER DM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=CM.STATE_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=DM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID					                      
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CMA ON ALM.CITY_ID=CMA.CITY_ID
INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON DM.CMP_CODE= CMP.CMP_CODE 
"+ @SQLJOIN +"                  
WHERE DM.CMP_CODE="+  @CMP_CODE +" AND DM.TRAN_DATE BETWEEN '"+ @FROMDATE+"' AND '"+ @TODATE +"'
"+@SQLCOND+" " + @SQLNOTE + "
ORDER BY DM.Tran_DocNo"

                     
         
END
EXEC (@SQL1)
PRINT @SQL1






























































































































GO

/****** Object:  StoredProcedure [dbo].[PROC_DESIGN_RECEIPT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO























/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'

PROC_DESIGN_RECEIPT '3','ACC2016_2017.DBO.',N'01/Apr/2016', N'08/Jan/2017','',1
*/
CREATE PROCEDURE [dbo].[PROC_DESIGN_RECEIPT]
(
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromDate NVARCHAR(50),
@ToDate NVARCHAR(50),
@TempTable NVARCHAR(50),
@RptWise int,
@TempTable1 NVARCHAR(50)


)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""

declare @JoinSql  Nvarchar(500)
declare @joinsql1  Nvarchar(4000)



set @joinsql1=""
set @JoinSql=""

 If @RptWise=0 /* Item */
	set @JoinSql="INNER JOIN "+@TempTable+" TT ON TT.code=DRM.BUNCH_NO"
if @TempTable1<>''
	set @joinsql1="INNER JOIN "+@TempTable1+" TT1 ON TT1.code=DRM.DESIGN_NO"	

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="

SELECT QUALITY AS ITEM,BUNCH_NO,DESIGN_NO,SUM(TOTAL_PASTE)TOTAL_PASTE,SUM(THAN)THAN,SUM(PER_THAN_METER)PER_THAN_METER,
SUM(TOTAL_PER_THAN_METER)TOTAL_PER_THAN_METER,SUM(TOTAL_COST)TOTAL_COST,
ISNULL(SUM(KHADI_WEIGHT),0)KHADI_WEIGHT,(ISNULL(SUM(KHADI_WEIGHT),0)*MAX(ISNULL(PUR_RATE,0)))KHADI_AMT
FROM "+@DatabaseName+"DESIGN_RECIPE_MASTER DRM 
LEFT JOIN "+@DatabaseName+"ITEM_OPENING_STOCK IM ON IM.ITEM_ID=DRM.KHADI_ID and IM.cmp_code=DRM.cmp_code
/*INNER JOIN "+@DatabaseName+"DESIGN_RECIPE_DETAIL DRD ON  DRD.DESIGN_RECIPE_ID=DRM.DESIGN_RECIPE_ID AND DRD.CMP_CODE=DRM.CMP_CODE  
INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID = DRD.ITEM_ID */
"+@JoinSql+"
"+@joinsql1+"
WHERE DRM.CMP_CODE IN ("+@Cmp_Code+") and DRM.DOC_DATE Between '"+@FromDate+"' And '"+@ToDate+"'
group by QUALITY,BUNCH_NO,DESIGN_NO
ORDER BY DRM.BUNCH_NO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL























GO

/****** Object:  StoredProcedure [dbo].[PROC_DESIGN_RECEIPT_PRINT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/*
[PROC_DESIGN_RECEIPT_PRINT] 3,'ACC2016_2017.DBO.',1,1
*/
CREATE PROCEDURE [dbo].[PROC_DESIGN_RECEIPT_PRINT]
(
@CMPCODE NVARCHAR(50),
@DATABASE NVARCHAR(50),
@FROMDOCNO NVARCHAR(50),
@TODOCNO NVARCHAR(50)
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="

SELECT DRM.DESIGN_RECIPE_ID,CONVERT(NVARCHAR,DOCNO) AS DOCNO,QUALITY,
CONVERT(NVARCHAR,DOC_DATE,103) AS DOCDATE,CUT,THAN,MATCHING,PASTE_ITEM,
BUNCH_NO,DESIGN_NO,REPEAT,PER_THAN_METER,TOTAL_PER_THAN_METER,TOTAL_PASTE,
PASTE_COST,TOTAL_AMOUNT,
TOTAL_COST,COLOR_NAME,	DESIGN_DATE	,FRAME,DYES_NAME,RATIO,COLOR_PASTE,GRAM,PER_KG,PASTE_KG,CALCULATE,ITEM,FINAL,TOTALKG,RATE,AMOUNT,SRNO,
KIM.ITEM_NAME AS KHADINAME,KHADI_WEIGHT,(ISNULL(KHADI_WEIGHT,0)*ISNULL(PUR_RATE,0))KHADIAMT
FROM "+@DATABASE+"DESIGN_RECIPE_MASTER DRM 
INNER JOIN "+@DATABASE+"DESIGN_RECIPE_DETAIL DRD ON  DRD.DESIGN_RECIPE_ID=DRM.DESIGN_RECIPE_ID AND DRD.CMP_CODE=DRM.CMP_CODE  
INNER JOIN "+@DATABASE+"ITEM_MASTER IM ON IM.ITEM_ID = DRD.ITEM_ID 
LEFT JOIN "+@DATABASE+"ITEM_MASTER KIM ON KIM.ITEM_ID = DRM.KHADI_ID
LEFT JOIN "+@DATABASE+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID = DRM.KHADI_ID AND IOS.CMP_CODE = DRM.CMP_CODE 

WHERE DRM.CMP_CODE IN ("+@CMPCODE+") AND DRM.DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
ORDER BY DRD.SRNO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL






















GO

/****** Object:  StoredProcedure [dbo].[PROC_DESIGN_RECEIPT_WITHMATCHING]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO























/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_DESIGN_RECEIPT_WITHMATCHING '3','ACC2016_2017.DBO.',N'01/Apr/2016', N'08/Jan/2017','##4204',1,'###4204'
*/
CREATE PROCEDURE [dbo].[PROC_DESIGN_RECEIPT_WITHMATCHING]
(
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromDate NVARCHAR(50),
@ToDate NVARCHAR(50),
@TempTable NVARCHAR(50),
@RptWise int,
@TempTable1 NVARCHAR(50)

)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""

declare @JoinSql  Nvarchar(500)
declare @joinsql1  Nvarchar(4000)


set @JoinSql=""
set @joinsql1=""

 If @RptWise=0 /* Item */
	set @JoinSql="INNER JOIN "+@TempTable+" TT ON TT.code=DRM.BUNCH_NO"
if @TempTable1<>''
	set @joinsql1="INNER JOIN "+@TempTable1+" TT1 ON TT1.code=DRM.DESIGN_NO"

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="
SELECT DISTINCT BUNCH_NO,DESIGN_NO,MATCHING,IM.ITEM_NAME AS QUALITY,THAN,TOTAL_PER_THAN_METER AS METER,
((ISNULL(TOTAL_PASTE,0)/ TOTAL_PER_THAN_METER)*100)TOTALPASTE,((ISNULL(KHADI_WEIGHT,0)/TOTAL_PER_THAN_METER)*100)AVG_KHADIWEI,
(((TOTAL_KG)/ TOTAL_PER_THAN_METER)*100)COLOR_WEIGHT,((ISNULL(PASTE_COST,0)/TOTAL_PER_THAN_METER)*100)PASTE_COST,
(((MAX(ISNULL(KHADI_WEIGHT,0))*MAX(ISNULL(IOS.PUR_RATE,0)))/TOTAL_PER_THAN_METER)*100)KHADI_COST,
((TOTAL_COST/TOTAL_PER_THAN_METER)*100)TOTALCOST,((TOTAL_AMOUNT/TOTAL_PER_THAN_METER)*100)POWDER_COST
FROM "+@DatabaseName+"DESIGN_RECIPE_MASTER DRM 
LEFT JOIN "+@DatabaseName+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=DRM.KHADI_ID and IOS.cmp_code=DRM.cmp_code
/*INNER JOIN "+@DatabaseName+"DESIGN_RECIPE_DETAIL DRD ON  DRD.DESIGN_RECIPE_ID=DRM.DESIGN_RECIPE_ID AND DRD.CMP_CODE=DRM.CMP_CODE  */
INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID =DRM.QUA_ITEMID
"+@JoinSql+"
"+@joinsql1+"
WHERE DRM.CMP_CODE IN ("+@Cmp_Code+") AND DRM.DOC_DATE BETWEEN '"+@FromDate+"' And '"+@ToDate+"'
GROUP BY BUNCH_NO,DESIGN_NO,MATCHING,IM.ITEM_NAME,THAN,TOTAL_PER_THAN_METER,TOTAL_PASTE,KHADI_WEIGHT,PASTE_COST,TOTAL_COST,TOTAL_AMOUNT,TOTAL_KG
ORDER BY DRM.BUNCH_NO,DESIGN_NO,IM.ITEM_NAME,MATCHING


"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL























GO

/****** Object:  StoredProcedure [dbo].[PROC_DESIGN_WISE_ORDER_PENDING_RPT]    Script Date: 03/30/2023 12:08:11 ******/
