/*
Author : Sanju Parmar
Created Date : 13/05/2019,5:27 PM.
PROC_DESIGN_WISE_ORDER_PENDING_RPT 1,'ACC2018_2019.DBO.','01/APR/2018','31/MAR/2019','##2948',7

Select NAME  from TempDb..SysObjects WHERE NAME LIKE '##%'
*/
CREATE PROCEDURE [dbo].[PROC_DESIGN_WISE_ORDER_PENDING_RPT]
(
@Cmp_Code Nvarchar(100),
@DatabaseName Nvarchar(500),
@FromDate  Nvarchar(20),
@ToDate Nvarchar(20),
@TempTable Nvarchar(20),	
@RptWise Int
)
AS
DECLARE @STRSQL1 AS NVARCHAR(3999)
DECLARE @RECEIVE AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(3999)
DECLARE @STRORDERBY AS NVARCHAR(3999)
SET @STRSQL1=""
SET @SELECTED=""
SET @STRORDERBY=""


BEGIN

	IF @RptWise IN (1)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON IM.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="IM.ITEM_NAME,IM.ITEM_ID,DM.DESIGN_NAME,DM.DESIGN_ID,"
		END	
	ELSE IF @RptWise IN (2)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="LM.LGR_NAME,LM.LGR_ID,DM.DESIGN_NAME,DM.DESIGN_ID,"
		END
	ELSE IF @RptWise IN (3)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON DM.DESIGN_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="DM.DESIGN_NAME,DM.DESIGN_ID,"
		END
	IF @RptWise IN (4)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON DM.DESIGN_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="DM.DESIGN_NAME,DM.DESIGN_ID,LM.LGR_NAME,LM.LGR_ID,"
		END	
	ELSE IF @RptWise IN (5)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON ALM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" ALM.LGR_NAME,ALM.LGR_ID,DM.DESIGN_NAME,DM.DESIGN_ID,"
		END		
	ELSE IF @RptWise IN (6)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON DM.DESIGN_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="DM.DESIGN_NAME,DM.DESIGN_ID,ALM.LGR_NAME,ALM.LGR_ID,"
		END			
	ELSE IF @RptWise IN (7)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" ALM.LGR_NAME,ALM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,DM.DESIGN_NAME,DM.DESIGN_ID,"
		END		
	ELSE IF @RptWise IN (8)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON ALM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="ALM.LGR_NAME,ALM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,DM.DESIGN_NAME,DM.DESIGN_ID,"
		END
		

SET NOCOUNT ON;
SET @STRSQL1="
SELECT CMP.CMP_CODE,SrNo,SO.SAL_ORDER_ID,SO.CONFNO,CONVERT(NVARCHAR,SO.VCH_DATE,103)VCH_DATE,
LM.LGR_NAME AS PARTY,SO.LGR_ID AS PARTY_ID,ALM.LGR_NAME AS AGNET,SO.AGENT_ID,
SID.ITEM_ID,IM.ITEM_NAME,SOA.DESIGN_ID,DM.DESIGN_NAME,
ISNULL(SOA.PCS,0)ORDER_PCS,(ISNULL(SOA.PCS,0)-ISNULL(SOA.PENDINGPCS,0)) AS DEL_PCS,ISNULL(SOA.PENDINGPCS,0)PENDING_PCS
FROM "+ @DATABASENAME+ "SALES_ORDER SO
INNER JOIN  "+ @DATABASENAME+ "SALES_ORDER_DETAIL SID ON SID.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SO.FLAG=SID.FLAG
INNER JOIN  "+ @DATABASENAME+ "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN  "+ @DATABASENAME+ "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
INNER JOIN  "+ @DATABASENAME+ "ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN  "+ @DATABASENAME+ "SALES_ORDER_ASSORT SOA ON SOA.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SID.ITEM_ID=SOA.ITEM_ID
INNER JOIN  "+ @DATABASENAME+ "DESIGN_MASTER DM ON DM.DESIGN_ID=SOA.DESIGN_ID
INNER JOIN "+ @DATABASENAME+ "COMPANY_MASTER CMP ON SO.CMP_CODE= CMP.CMP_CODE     	
"+@SELECTED+"
WHERE SO.CMP_CODE in ("+ @CMP_CODE +") AND SO.vch_Date BETWEEN '" + @FromDate + "' AND '" + @ToDate + "'
ORDER BY "+@STRORDERBY+"SO.SAL_ORDER_ID,SrNo"      
END	
PRINT @STRSQL1
EXEC (@STRSQL1)




















GO

