CREATE PROCEDURE [dbo].[PROC_DESPATCHREPORT]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@CRITERIA INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(500)
DECLARE @orderSQL  NVARCHAR(500)

SET @JOINSQL=""
IF @CRITERIA=0 /* PARTY WISE */
SET @JOINSQL="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PS.LGR_ID"
ELSE IF @CRITERIA=1 /* AGENT WISE */
SET @JOINSQL="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PS.AGENT_ID"
ELSE IF @CRITERIA=2  /* SCEEN WISE */
SET @JOINSQL="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SM.SCREEN_ID"
ELSE IF @CRITERIA=3 /* ITEM WISE */
SET @JOINSQL="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
ELSE IF @CRITERIA=4
SET @JOINSQL="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID AND IM.ITEM_ID=SM.ITEM_ID"
ELSE IF @CRITERIA=5
SET @JOINSQL=""

BEGIN
SET NOCOUNT ON;
SET @SQL=" 
SELECT PS.PACKINGSLIPID,PS.BALENO,PS.VCH_DATE,PS.CONFNO,PS.CONF_DATE,PS.ORDERNO,PS.ORDER_DATE,
PLM.LGR_NAME AS PARTYNAME ,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENTNAME,ACM.CITY_NAME AS AGENTCITY,
TM.TRANSPORT_NAME,SCM.CITY_NAME AS STATION,SM.SCREEN_NAME,IM.ITEM_NAME,
ISNULL(PLM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(SCM.CITY_ID,0) AS STATIONID,
ISNULL(SM.SCREEN_ID,0) AS SCREENID,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ACM.CITY_ID,0) AS AGENCT_CITYID

FROM "+@DATABASENAME+"PACKINGSLIP PS
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON PS.LGR_ID=PLM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL PLD ON PLM.LGR_ID=PLD.LGR_ID AND PS.CMP_CODE=PLD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON PS.AGENT_ID=ALM.LGR_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON PS.TRANSPORT_ID=TM.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER SCM ON PS.STATION_ID=SCM.CITY_ID                    
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON PSD.SCREEN_ID=SM.SCREEN_ID                    
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON PSD.ITEM_ID=IM.ITEM_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
"+@JOINSQL+"
WHERE PS.CMP_CODE="+@CMP_CODE+" 
AND PS.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
ORDER BY PS.BALENO
"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

