/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 04-11-2014
-- DESCRIPTION:	THIS REPORT IS USED TO 
-- =============================================
PROC_DESPATCHSALESREPORT N'01/APR/2014', N'31/MAR/2015', N'ACC2014_2015.DBO.', N'1', N'##4816', 9 

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/
CREATE PROCEDURE [dbo].[PROC_DESPATCHSALESREPORT]
(
	@FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100),    
    @TEMPTABLE NVARCHAR(20),
    @RPT_WISE INT
)
AS

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @SQLORDERBY AS NVARCHAR(500)

SET @STRSQL=""
SET @SQLJOIN=""
SET @SQLORDERBY=""


IF @RPT_WISE =1 
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =LM.LGR_ID"
SET @SQLORDERBY=" LM.LGR_NAME,ISNULL(LM.LGR_ID,0),SAL_INV_VDATE"
END

ELSE IF @RPT_WISE =2 
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =ALM.LGR_ID"
SET @SQLORDERBY=" ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =3
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =ALM.LGR_ID"
SET @SQLORDERBY=" ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =4
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =IM.ITEM_ID"
SET @SQLORDERBY=" IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =5
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =SM.SCREEN_ID"
SET @SQLORDERBY=" ISNULL(SM.SCREEN_NAME,''),SM.SCREEN_ID,SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =6
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =LM.LGR_ID"
SET @SQLORDERBY=" LM.LGR_NAME,ISNULL(LM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =7
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =LM.LGR_ID"
SET @SQLORDERBY=" LM.LGR_NAME,ISNULL(LM.LGR_ID,0),SM.SCREEN_NAME,SM.SCREEN_ID,SAL_INV_VDATE,SAL_INV_BILL_NO"
END

ELSE IF @RPT_WISE =8
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =IM.ITEM_ID"
SET @SQLORDERBY=" IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),SAL_INV_VDATE,SAL_INV_BILL_NO"
END

BEGIN

SET @STRSQL="SELECT  SAL_INV_BILL_NO AS BILLNO,SAL_INV_VDATE AS DATE,CONFNO,CONFDATE,
SID.SAL_INV_BALENO AS BALENO,LM.LGR_NAME ,IM.ITEM_NAME,ISNULL(ALM.LGR_NAME,'') AS AGENT,
ISNULL(SM.SCREEN_NAME,'') AS SCREEN_NAME,ISNULL(PCM.CITY_NAME,'') AS CITY_NAME,SID.SAL_INV_RATE, SID.ITEM_CUT ,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_QTY) END ) AS QUANTITY,
SAL_INV_RATE AS RATE,SID.SAL_INV_AMOUNT AS AMOUNT,SAL_INV_PCS,IM.RATE_PER,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(SM.SCREEN_ID,0) AS SCREENID,ISNULL(UM.UNIT_ID,0) AS UNITID

FROM "+@DATABASENAME+"SALES_INVOICE SI 
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID  ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SI.CMP_CODE=SID.CMP_CODE AND SI.FLAG=SID.FLAG 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID =SI.LGR_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =SID.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
"+ @SQLJOIN+"
WHERE SI.CMP_CODE="+@CMP_CODE+" AND SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SAL_INV_TYPE='B'
ORDER BY
"+@SQLORDERBY+"
"

PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL


END




















GO

