GO




















/*
=============================================
AUTHOR:		  <SANKET>
ALTER_DATE:  <17/DEC/2012>
DESCRIPTION:  <DISCOUNT GIVEN AND RECEIVED REPORT>
REPORT NAME:  <DISCOUNTGIVEN_REC_REPORT.RPT>
PROC_DISCOUNT_GIVEN_REC_REPORT 2,'ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011',1,'##3124'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_DISCOUNT_GIVEN_REC_REPORT]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(100),
  @TODATE AS NVARCHAR(100),
  @RPT_WISE AS INT,
  @TEMPTABLE AS NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000) SET @SQL =""
DECLARE @SQL1 AS NVARCHAR(4000) SET @SQL1 =""
DECLARE @CONDSQL AS NVARCHAR(1000) SET @CONDSQL=""

BEGIN
	
	SET NOCOUNT ON;
SET @SQL="
SELECT PartyName,PartyId,SUM(DrAMOUNT) AS DrAMOUNT,SUM(CrAMOUNT) AS CrAMOUNT,AccountName,ACC_ID,GRP_NAME,CITY_NAME,MAX(CMP_ALIAS)CMP_ALIAS
FROM (
Select LM.Lgr_Name as PartyName,TD.Tran_Detail_Id AS PartyId,
(CASE WHEN TD.Tran_DrCr = 'D' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS DrAMOUNT, 
(CASE WHEN TD.Tran_drcr = 'C' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS CrAMOUNT
,TM.Tran_Type as A_TYPE, LM1.Lgr_Name AS AccountName,LM1.Lgr_ID as ACC_ID,GM.GRP_NAME,PCM.CITY_NAME,CMP_ALIAS
From "+@DATABASENAME+" Tran_Master TM 
INNER JOIN "+@DATABASENAME+"Tran_Detail TD ON TD.TRan_Id= TM.TRan_Id And TD.Tran_Type = TM.Tran_Type AND TD.Cmp_Code= TM.Cmp_Code  
INNER JOIN "+@DATABASENAME+"Tran_Detail as Jd ON TD.Tran_Type = JD.Tran_Type AND TD.Tran_Id= Jd.Tran_Id and TD.Tran_Detail_Id<> Jd.Tran_Detail_Id And TD.Tran_DrCr <> Jd.Tran_DrCr  
INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_Id= LM.Lgr_Id 
INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON Jd.Tran_Detail_Id = LM1.Lgr_Id  
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM1.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
INNER JOIN "+@DATABASENAME+"COMPANYSETTING CM ON CM.DISCOUNTGROUPID=TD.Tran_Detail_Id AND CM.SETTINGNAME='PARAMETER'
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMM ON CMM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM1.Lgr_Id
Where TM.Cmp_Code="+@CMP_CODE+" And TM.Tran_Date Between '"+@FROMDATE+"' And  '"+@TODATE+"' "

SET @SQL1=" 
union all  
Select LM.Lgr_Name AS PARTYNAME,LM.Lgr_ID AS PartyId,AJ.DrAmount AS DrAMOUNT,AJ.CrAmount AS CrAMOUNT,AJ.entrytype AS A_Type
,LM1.Lgr_Name AS AccountName,LM1.Lgr_ID AS ACC_ID,GM.GRP_NAME,PCM.CITY_NAME,CMP_ALIAS
From "+@DATABASENAME+"AutoJournal AJ 
INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON AJ.Lgr_Id = LM.Lgr_Id  
INNER JOIN "+@DATABASENAME+"AutoJournal AJ1 ON AJ.Cmp_Code=AJ1.Cmp_Code And AJ.EntryCode=AJ1.EntryCode And AJ.entrytype = AJ1.entrytype  And AJ.Lgr_ID<> AJ1.Lgr_ID And AJ1.VCode = AJ.VCode and AJ1.entrymatch= AJ.entrymatch  
INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON AJ1.Lgr_Id= LM1.Lgr_Id  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM1.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANYSETTING CM ON CM.DISCOUNTGROUPID=LM.Lgr_ID AND CM.SETTINGNAME='PARAMETER'
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMM ON CMM.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM1.Lgr_Id
Where AJ.VDate Between '"+@FROMDATE+"' And '"+@TODATE+"'And AJ.Cmp_Code= "+@CMP_CODE+"
) AS  A
GROUP BY PartyName,PartyId,AccountName,ACC_ID,GRP_NAME,CITY_NAME
ORDER BY PARTYNAME
" 
END
PRINT @SQL
PRINT @SQL1

EXEC (@SQL+@SQL1)




















GO

