CREATE PROCEDURE [dbo].[PROC_DUPLICATEBILL]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)

begin
    	SET NOCOUNT ON;
        set @sql=" 
				Select SIM.Sal_Inv_id,SIM.Sal_Inv_Bill_No,SIM.Sal_Inv_vdate,SIM.Sal_Inv_LrNo,SIM.Sal_Inv_LrDate,
				SIM.Sal_Inv_NetTotal,LM.Lgr_Name As Partyname,PCM.City_Name As PartyCity,
				TM.Transport_Name,LM.Lgr_add1,LM.Lgr_add2,LM.Lgr_add3, 
				STM.City_Name As Station,CMP.cmp_Name,Cmp_Jurisdiction,cmp_Phone1,cmp_Phone2,cmp_fax,NM.Narration
				From "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Ledger_Master LM ON SIM.Lgr_id=LM.Lgr_Id
				INNER JOIN "+@DatabaseName+"Company_Master CMP ON CMP.cmp_code=SIM.Cmp_Code
				INNER JOIN "+ @TempTable + " TT on TT.Code=SIM.Sal_Inv_id 
				LEFT JOIN "+@DatabaseName+"Transport_Master TM ON SIM.Transport_Id=TM.Transport_Id
				LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_Id=PCM.City_Id
				LEFT JOIN "+@DatabaseName+"City_Master STM ON SIM.Station_Id=STM.City_Id
				LEFT JOIN "+@DatabaseName+"Narration_Master NM ON SIM.cmp_code=NM.cmp_code And NM.Type='DUPLICATE BILL'
				Where SIM.Cmp_Code = "+@Cmp_Code+"
					"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

