/*
PROC_EMPLOYEE 2,'ACC2010_2011.DBO.','01/APR/2010','01/APR/2011'
*/
CREATE PROCEDURE [dbo].[PROC_EMPLOYEE]	
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(50),
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20)
)
AS
SET NOCOUNT ON;

DECLARE @SQL NVARCHAR(4000)
SET @SQL=""

BEGIN

SET @SQL="	SELECT EMP.EMPLOYEE_NAME AS EMPLOYEE,TM.TRAN_DOCNO,TM.TRAN_DATE,TD.CHEQUENO
,TM.TRAN_TYPE,TD.TRAN_AMOUNT,TD.NARRATION ,LM.LGR_NAME AS HEAD,CMP.CMP_ALIAS,LM.LGR_ID AS HEADID,
EMP.EMPLOYEE_ID AS EMPLOYEEID
FROM "+@DATABASENAME+"TRAN_DETAIL TD
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
INNER JOIN "+@DATABASENAME+"EMPLOYEE_MASTER EMP ON EMP.EMPLOYEE_ID=TD.EMPLOYEE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TD.CMP_CODE
WHERE TM.TRAN_TYPE IN('BP','CP','EX') AND TM.CMP_CODE IN ("+@CMP_CODE +") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+ @TODATE +"'
ORDER BY TM.TRAN_DATE,LM.LGR_NAME,LM.LGR_ID,EMP.EMPLOYEE_NAME,EMP.EMPLOYEE_ID
"
END
PRINT @SQL
EXEC (@SQL)




















GO

