/* 
PROC_ENTRYTAXREGISTER '2','ACC2010_2011.DBO.','01/APR/2010','29/JAN/2011','1792','OUTER'
*/
CREATE PROCEDURE [dbo].[PROC_ENTRYTAXREGISTER]
 (
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @PURACCID NVARCHAR(10),
    @IN_OUT NVARCHAR(20)
  )	
AS
DECLARE @SQL NVARCHAR(4000)
SET @SQL=""
BEGIN
    SET @SQL="
              SELECT PI.BILLNO,PI.VCHDATE AS BILLDATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,PI.NETTOTAL
              ,CMP.CMP_ALIAS 
              FROM "+@DATABASENAME+"PURCHASEINVOICE PI
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
              WHERE  PI.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND
              PI.CMP_CODE IN("+@CMP_CODE+") AND PURACCID="+@PURACCID+" AND IN_OUTER_STATE='"+@IN_OUT +"'
              ORDER BY PI.VCHDATE ,PI.DOCNO,PI.BILLNO
              "
	
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















