/* 
-- =============================================
-- ALTER_AUTHOR    : <BIREN>
-- ALTER_DATE      : <22/10/2013,4:23>
-- EDIT_AUTHOR		: <BIREN>
-- EDIT_DATE		: <29/10/2013,5:00>
-- REPORT_NAME		: <PACKINGSLIPEMAIL.RPT>
-- REPORT_FORM		: <RFRMSALESINVOICEEMAIL.CS>
-- =============================================
PROC_EXTRACOLOREMAIL '1','ACC2012_2013.DBO.','31/MAR/2013','31/MAR/2013',1,149,1,1,'19314,19315,19316'
*/
CREATE PROCEDURE [dbo].[PROC_EXTRACOLOREMAIL]
(
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(50),
	@FROMDATE NVARCHAR(20),
	@TODATE NVARCHAR(20),
	@CRITERIA INT,
	@ACCID NVARCHAR(20),
	@RPTWISE INT,
	@BILL_WISE INT,
	@BALE_NO NVARCHAR(4000)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @BALENOSQL AS NVARCHAR(4000)
DECLARE @RPTSQL AS NVARCHAR(4000)
SET @SQL =""
SET @SQL1 =""
SET @BALENOSQL =""
SET @RPTSQL =""

BEGIN
	IF @RPTWISE = 1 
		BEGIN
			IF @BILL_WISE = 0 
				BEGIN		
					IF @CRITERIA = 1 
						BEGIN		
							SET @RPTSQL = " AND PS.LGR_ID = "+@ACCID
						END
					ELSE IF @CRITERIA = 2
						BEGIN
							SET @RPTSQL = " AND PS.AGENT_ID = "+@ACCID
						END
				END
			ELSE IF @BILL_WISE = 1
				BEGIN 
					SET @BALENOSQL = " AND BALENO IN ("+@BALE_NO+") "
				END
		END
END
BEGIN
	SET @SQL =  "
				SELECT  PSE.PACKINGSLIPID,PSD.ITEM_ID,PSD.DETAILROWNO,PSE.SRNO,PSE.ROWNO,PSE.COLNO,PSE.PCS,PSE.MTRS,PSE.TOTAL
				FROM "+@DATABASENAME+"PACKINGSLIP_EXTRACOLOR PSE 
				INNER JOIN "+@DATABASENAME+"PACKINGSLIP PS ON PS.PACKINGSLIPID = PSE.PACKINGSLIPID
				INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PSD.PACKINGSLIPID = PSE.PACKINGSLIPID 
					AND PSD.DETAILROWNO=PSE.ROWNO
				WHERE PS.CMP_CODE IN ("+@CMP_CODE+") AND PS.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
				"+@RPTSQL+" "+@BALENOSQL+"
				ORDER BY PSE.SRNO
                "

END
EXEC SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_FABRIC_OUTGATEPASS_REPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO

















/*
-- =============================================
-- ALTER_AUTHOR      :	BIREN
-- ALTER_DATE        : 24-08-2015 4:47 PM
-- DESCRIPTION:	THIS PROCEDURE IS USED IN CHEMICAL,MACHINARY CHALLAN PRINT OUT REPORT 
-- =============================================
PROC_FABRIC_OUTGATEPASS_REPORT 'ACC2015_2016.DBO.',1,500,2,1,'##5836' 
*/
CREATE PROCEDURE [dbo].[PROC_FABRIC_OUTGATEPASS_REPORT]
(
@DATABASENAME AS NVARCHAR(100),
@FROMNO AS NVARCHAR(100),
@TONO AS NVARCHAR(100),
@RPT_TYPE AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(10),
@TEMPTABLE NVARCHAR(20)
)
AS
BEGIN
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
DECLARE @FLAGSQL AS NVARCHAR(4000)
SET @STRSQL=""
SET @JOINSQL=""
SET @FIELDSQL=""
SET @FLAGSQL = ""

IF @RPT_TYPE = 1 
BEGIN
SET @FLAGSQL = " AND GOM.FLAG = 'OUT' "
END
ELSE IF @RPT_TYPE = 2
BEGIN
SET @FLAGSQL = " AND GOM.FLAG = 'IN' "
END




IF @TEMPTABLE <> "" 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GOM.CMP_CODE"
	SET @FIELDSQL = "TT.TYPE"
END	
ELSE
BEGIN
	SET @FIELDSQL = "'' AS TYPE"
END

SET @STRSQL = " SELECT ISNULL(GOM.OUTGATEPASS_ID,0) AS OUTGATEPASSID,ISNULL(GOM.DOCNO,0) AS DOCNO,CONVERT(NVARCHAR,GOM.VCHDATE,103) AS VCHDATE,
ISNULL(GOM.VEHICLENO,'') AS VEHICLENO,ISNULL(GOM.CMP_CODE,0) AS CMPCODE,ISNULL(GOM.BUNCHNO,0) AS BUNCHNO,
ISNULL(GOM.OUTWARDNO,'') AS OUTWARDNO,ISNULL(GOM.THANTOTAL,0) AS THANTOTAL,ISNULL(GOM.ENTRYCODE,0) AS ENTRYCODE,
ISNULL(GOD.SRNO,0) AS SRNO,ISNULL(CMM.COLORMATCHING_NAME,'') AS COLORMATCHING,ISNULL(GOD.THAN,0) AS THAN,
ISNULL(GOD.TP,0) AS TP,ISNULL(GOD.METER,0) AS METER,ISNULL(GOD.DYEING,'') AS DYEING,
ISNULL(GOD.REMARK,'') AS REMARK,ISNULL(GOD.PENDTHAN,0) AS PENDTHAN,ISNULL(GOD.DELITHAN,0) AS DELITHAN,
ISNULL(LM.LGR_ID,'') AS PARTYID,ISNULL(BM.BUNCHNAME_ID,'') AS BUNCHNAMEID,ISNULL(HM.HASTE_ID,'') AS HASTEID,
ISNULL(LOM.LOT_ID,'') AS GREYMARKAID,ISNULL(PM.PROCESS_ID,'') AS PROCESSID,ISNULL(GOD.DESIGN_ID,0) AS DESIGNID,

ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(BM.BUNCHNAME,'') AS BUNCHNAME,ISNULL(HM.HASTE_NAME,'') AS HASTE,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,ISNULL(PM.PROCESS_NAME,'') AS PROCESS,ISNULL(DM.DESIGN_NAME,'') AS DESIGN,"+@FIELDSQL+"
FROM "+@DATABASENAME+"FABRIC_OUTGATEPASS_MASTER GOM
INNER JOIN "+@DATABASENAME+"FABRIC_OUTGATEPASS_DETAIL GOD ON GOD.OUTGATEPASS_ID = GOM.OUTGATEPASS_ID AND GOD.CMP_CODE = GOM.CMP_CODE
AND GOD.FLAG = GOM.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GOM.LGR_ID 
INNER JOIN "+@DATABASENAME+"BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = GOM.BUNCHNAME_ID 
INNER JOIN "+@DATABASENAME+"HASTE_MASTER HM ON HM.HASTE_ID = GOM.HASTE_ID 
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = GOM.LOT_ID 
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM  ON PM.PROCESS_ID = GOM.PROCESS_ID 
INNER JOIN "+@DATABASENAME+"DESIGN_MASTER DM  ON DM.DESIGN_ID = GOD.DESIGN_ID
LEFT JOIN "+@DATABASENAME+"COLORMATCHING_MASTER CMM  ON CMM.COLORMATCHING_ID = GOD.COLORMATCHING_ID
"+@JOINSQL+"
WHERE GOM.CMP_CODE="+@CMP_CODE+" AND GOM.DOCNO >= "+ @FROMNO +" AND GOM.DOCNO <="+@TONO+" "+@FLAGSQL+"
ORDER BY GOM.OUTGATEPASS_ID,TYPE,GOD.SRNO
"
	
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL

















GO

/****** Object:  StoredProcedure [dbo].[PROC_FIBERISSUE]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
