/*
PROC_FIBERISSUE 2,'Acc2010_2011.dbo.','01/apr/2010','31/mar/2012',##2712,2,2,1
*/
CREATE PROCEDURE [dbo].[PROC_FIBERISSUE]
( 
        @CMP_CODE AS NVARCHAR(100),
        @DATABASENAME AS NVARCHAR(100),
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
        @TEMPTABLE AS  NVARCHAR(20),
        @RPT_WISE AS  int,       
        @RPT_TYPE as Int,
		@RPT_PENDING as int
)
AS
BEGIN
	DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @GRPSQL AS NVARCHAR(4000)
DECLARE @Cond AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""	
SET @GRPSQL=""
set @Cond=""

BEGIN  
        IF @RPT_WISE=1
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=PM.LGR_ID"
		   SET @GRPSQL=" group by PM.lgr_Name "
        IF @RPT_WISE=2
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
		   SET @GRPSQL=" group by IM.Item_Name "
        IF @RPT_WISE=3
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=PM.LGR_ID"
		   SET @GRPSQL=" group by PM.lgr_Name,IM.Item_Name "
        IF @RPT_WISE=4
           SET @JOINSQL=" "
		   SET @GRPSQL="  "
END 
BEGIN
		IF @RPT_WISE=1
		   SET @GRPSQL=" group by PM.lgr_Name "
        IF @RPT_WISE=2
		   SET @GRPSQL=" group by IM.Item_Name "
        IF @RPT_WISE=3
		   SET @GRPSQL=" group by PM.lgr_Name,IM.Item_Name "
        IF @RPT_WISE=4           
		   SET @GRPSQL="  "
END


BEGIN
	if @RPT_PENDING=1 
		set @Cond=""
	else if @RPT_PENDING=2
		set @Cond=" and PENDINGQTY>0 "
END

	SET NOCOUNT ON;
if @RPT_TYPE=1

	SET @SQL="
select DOCNO,VCHDATE,LOT_NO,LR_NO,BAGS,PENDINGBAGS,QTY,PENDINGQTY,PM.Lgr_Name as PARTYNAME,MM.Mill_Name,IM.Item_Name
from "+@DATABASENAME+" RMIssue_Master RM 
inner join "+@DATABASENAME+" RMIssue_Detail RD on RM.RMIssue_ID=RD.RMIssue_ID
left join "+@DATABASENAME+" Ledger_Master PM on PM.lgr_Id=To_Lgr_Id
left join "+@DATABASENAME+" Item_Master Im On RD.Item_Id=IM.Item_Id
left join "+@DATABASENAME+" Mill_Master MM on RD.Mill_Id=MM.Mill_Id
"+@JOINSQL+"
where RM.Cmp_Code in ("+@CMP_CODE+") and RM.VCHDATE between '"+@FROMDATE+"' and '"+@TODATE+"'
"+@Cond+"
"
else
set @SQL="
select max(DOCNO)as DOCNO,max(VCHDATE)as VCHDATE,max(LOT_NO) as LOT_NO,max(LR_NO) as LR_NO,sum(BAGS) as BAGS,sum(PENDINGBAGS) as PENDINGBAGS
,sum(QTY) as QTY,sum(PENDINGQTY) as PENDINGQTY,max(PM.Lgr_Name) as PARTYNAME,max(MM.Mill_Name) as Mill_Name,max(IM.Item_Name) as Item_Name
from "+@DATABASENAME+" RMIssue_Master RM 
inner join "+@DATABASENAME+" RMIssue_Detail RD on RM.RMIssue_ID=RD.RMIssue_ID
left join "+@DATABASENAME+" Ledger_Master PM on PM.lgr_Id=To_Lgr_Id
left join "+@DATABASENAME+" Item_Master Im On RD.Item_Id=IM.Item_Id
left join "+@DATABASENAME+" Mill_Master MM on RD.Mill_Id=MM.Mill_Id
"+@JOINSQL+"
where RM.Cmp_Code in ("+@CMP_CODE+") and RM.VCHDATE between '"+@FROMDATE+"' and '"+@TODATE+"'
"+@Cond+"
"+@GRPSQL+"
"

    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

