-- =============================================
-- Author:		<BIREN> 
-- Create_date: <11/09/2012,5:05>
-- Report Form:	<rfrmFiberStockReport>
-- Report :	<FIBERSTOCKREPORT>
-- Proc_Name : <PROC_FIBERSTOCK>
-- =============================================
/*
PROC_FIBERSTOCK '1', N'Acc2012_2013.Dbo.', N'01/apr/2012',N'30/Sep/2012', N'##6020',1,2
*/

CREATE PROCEDURE [dbo].[PROC_FIBERSTOCK] 
	
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromDate NVARCHAR(20),
@ToDate NVARCHAR(20),
@TempTable NVARCHAR(20),
@Criteria INT,
@RptType INT

AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(500)
DECLARE @SELECTSQL AS NVARCHAR(500)
DECLARE @GROUPSQL AS NVARCHAR(500)
DECLARE @MSELECTSQL AS NVARCHAR(500)
DECLARE @MGROUPSQL AS NVARCHAR(500)

SET @SQL = ""
SET @SQL1 = ""
SET @SQL2 = ""
SET @SQL3 = ""
SET @SQL4 = ""
SET @SQL5 = ""
SET @JOINSQL = ""
SET @SELECTSQL = ""
SET @GROUPSQL = ""
SET @MSELECTSQL = ""
SET @MGROUPSQL = ""

BEGIN
	IF @Criteria = 1 
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TempTable+" TT ON TT.CODE = IM.ITEM_ID "
		END
	ELSE IF @Criteria = 2 OR @Criteria = 3
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TempTable+" TT ON TT.CODE = IGM.ITEM_GRP_ID "
		END
	ELSE IF @Criteria = 4
		BEGIN
			SET @JOINSQL = ""
		END
END

BEGIN
	IF @Criteria = 1 OR @Criteria = 3
		BEGIN
			SET @SELECTSQL = ",ITEM,ITEM_ID,MAX(ITEMGROUP) AS ITEMGROUP,MAX(ITEMGRPID) AS ITEMGRPID,"
			SET @GROUPSQL = " GROUP BY VDATE,ITEM,ITEM_ID "
			SET @MSELECTSQL = ",ITEM,ITEM_ID,MAX(ITEMGROUP) AS ITEMGROUP,MAX(ITEMGRPID) AS ITEMGRPID,"
			SET @MGROUPSQL = " GROUP BY MONTHNAME,ITEM,ITEM_ID,ORD "
		END
	ELSE IF @Criteria = 2 
		BEGIN
			SET @SELECTSQL = ",MAX(ITEM) AS ITEM,MAX(ITEM_ID) AS ITEM_ID,ITEMGROUP AS ITEMGROUP,ITEMGRPID AS ITEMGRPID, "
			SET @GROUPSQL = " GROUP BY VDATE,ITEMGROUP,ITEMGRPID "
			SET @MSELECTSQL = ",MAX(ITEM) AS ITEM,MAX(ITEM_ID) AS ITEM_ID,ITEMGROUP AS ITEMGROUP,ITEMGRPID AS ITEMGRPID, "
			SET @MGROUPSQL = " GROUP BY MONTHNAME,ITEMGROUP,ITEMGRPID,ORD "
		END
	ELSE IF @Criteria = 4
		BEGIN
			SET @SELECTSQL = ",MAX(ITEM) AS ITEM,MAX(ITEM_ID) AS ITEM_ID,MAX(ITEMGROUP) AS ITEMGROUP,MAX(ITEMGRPID) AS ITEMGRPID, "
			SET @GROUPSQL = " GROUP BY VDATE "
			SET @MSELECTSQL = ",MAX(ITEM) AS ITEM,MAX(ITEM_ID) AS ITEM_ID,MAX(ITEMGROUP) AS ITEMGROUP,MAX(ITEMGRPID) AS ITEMGRPID, "
			SET @MGROUPSQL = " GROUP BY MONTHNAME,ORD "
		END
END

SET @SQL = ""

IF @RptType = 1
	BEGIN
		SET @SQL = "SELECT  MAX(MONTHNAME) AS MONTHNAME,VDATE "+@SELECTSQL+" SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,
					SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(PURRETURN) AS PURRETURN,SUM(ISSUE2JOB) AS ISSUE2JOB,SUM(SHORTAGE) AS SHORTAGE,
					(SUM(OPSTOCK)+SUM(PURCHASE)+SUM(SALESRETURN))- (SUM(SALES)+SUM(PURRETURN)+SUM(ISSUE2JOB)) AS CLOSING,0 AS ORD
					FROM (

					SELECT 'JANUARY' AS MONTHNAME,YOM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,	
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					YOD.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"YARNOPENING_DETAIL YOD ON IM.ITEM_ID = YOD.ITEM_ID
					INNER JOIN "+@DatabaseName+"YARNOPENING_MASTER YOM ON YOM.INWARDID =  YOD.INWARDID
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE YOD.CMP_CODE IN ("+@Cmp_Code+") AND YOM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'

					UNION ALL
	
					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,	
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					YOD.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"YARNOPENING_DETAIL YOD ON IM.ITEM_ID = YOD.ITEM_ID
					INNER JOIN "+@DatabaseName+"YARNOPENING_MASTER YOM ON YOM.INWARDID =  YOD.INWARDID
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE YOD.CMP_CODE IN ("+@Cmp_Code+") AND YOM.VCHDATE < '"+@FromDate+"' 
					"

		SET @SQL1 = "UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,PRM.PUR_RET_DATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,PRD.PUR_RET_QTY AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_DETAIL PRD ON PRD.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_MASTER PRM ON PRM.PUR_RET_ID =  PRD.PUR_RET_ID
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PRD.CMP_CODE IN ("+@Cmp_Code+") AND PRM.PUR_RET_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'

					UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					(0-PRD.PUR_RET_QTY) AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_DETAIL PRD ON PRD.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_MASTER PRM ON PRM.PUR_RET_ID =  PRD.PUR_RET_ID
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PRD.CMP_CODE IN ("+@Cmp_Code+") AND PRM.PUR_RET_DATE <'"+@FromDate+"'  
					"

		SET @SQL2 = "UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,SRM.SAL_RET_DATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,0.00 AS PURCHASE,SRD.SAL_RET_QTY AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"SALES_RETURN_DETAIL SRD ON SRD.ITEM_ID = IM.ITEM_ID 
					INNER JOIN "+@DatabaseName+"SALES_RETURN_MASTER SRM ON SRM.SAL_RET_ID =  SRD.SAL_RET_ID AND SRM.CMP_CODE = SRD.CMP_CODE AND SRM.FLAG = SRD.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE SRD.CMP_CODE IN ("+@Cmp_Code+") AND SRM.SAL_RET_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND SRM.FLAG = 'YSR'
			
					UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					SRD.SAL_RET_QTY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"SALES_RETURN_DETAIL SRD ON SRD.ITEM_ID = IM.ITEM_ID 
					INNER JOIN "+@DatabaseName+"SALES_RETURN_MASTER SRM ON SRM.SAL_RET_ID =  SRD.SAL_RET_ID AND SRM.CMP_CODE = SRD.CMP_CODE AND SRM.FLAG = SRD.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE SRD.CMP_CODE IN ("+@Cmp_Code+") AND SRM.SAL_RET_DATE < '"+@FromDate+"' AND SRM.FLAG = 'YSR'
					"

		SET @SQL3 = " UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,SIM.SAL_INV_VDATE AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,SID.SAL_INV_QTY AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"SALES_INVOICE_DETAIL SID ON SID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"SALES_INVOICE SIM ON SIM.SAL_INV_ID =  SID.SAL_INV_ID AND SIM.CMP_CODE = SID.CMP_CODE AND SIM.FLAG = SID.FLAG 
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE SID.CMP_CODE IN ("+@Cmp_Code+") AND SIM.SAL_INV_VDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND SIM.FLAG = 'YS'

					UNION ALL

					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					(0-SID.SAL_INV_QTY) AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"SALES_INVOICE_DETAIL SID ON SID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"SALES_INVOICE SIM ON SIM.SAL_INV_ID =  SID.SAL_INV_ID AND SIM.CMP_CODE = SID.CMP_CODE AND SIM.FLAG = SID.FLAG 
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE SID.CMP_CODE IN ("+@Cmp_Code+") AND SIM.SAL_INV_VDATE <'"+@FromDate+"' AND SIM.FLAG = 'YS'
					"

		SET @SQL4 = "UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,PIM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,PID.QUANTITY AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID =  PID.PURCHASEINVID AND PIM.CMP_CODE = PID.CMP_CODE AND PIM.FLAG = PID.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PID.CMP_CODE IN ("+@Cmp_Code+") AND PIM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PIM.FLAG = 'YP'

					UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					PID.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID =  PID.PURCHASEINVID AND PIM.CMP_CODE = PID.CMP_CODE AND PIM.FLAG = PID.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PID.CMP_CODE IN ("+@Cmp_Code+") AND PIM.VCHDATE <'"+@FromDate+"' AND PIM.FLAG = 'YP'
					"

		SET @SQL5 = "UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,YRJM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					(YRJLD.QTY+YRJLD.EXCEEDQTY) AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"YARNRECJOBLOT_DETAIL YRJLD ON YRJLD.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"YARNRECJOB_MASTER YRJM ON YRJM.YanRecJob_Id =  YRJLD.YanRecJob_Id
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE YRJM.CMP_CODE IN ("+@Cmp_Code+") AND YRJM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'

					UNION ALL 

					SELECT 'JANUARY' AS MONTHNAME,'"+@FromDate+"' AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					(0-(YRJLD.QTY+YRJLD.EXCEEDQTY)) AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"YARNRECJOBLOT_DETAIL YRJLD ON YRJLD.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"YARNRECJOB_MASTER YRJM ON YRJM.YanRecJob_Id =  YRJLD.YanRecJob_Id
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE YRJM.CMP_CODE IN ("+@Cmp_Code+") AND YRJM.VCHDATE <'"+@FromDate+"'
	 
					) AS FIBERSTOCK

					"+@GROUPSQL+"
					HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(PURRETURN)<>0 OR SUM(ISSUE2JOB)<>0 OR SUM(SHORTAGE)<>0)
					ORDER BY VDATE,ITEM
					"
		END

ELSE IF @RptType = 2
	BEGIN
		SET @SQL = "SELECT  MAX(MONTHNAME) AS MONTHNAME,GETDATE() AS VDATE "+@MSELECTSQL+" SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,
					SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(PURRETURN) AS PURRETURN,SUM(ISSUE2JOB) AS ISSUE2JOB,SUM(SHORTAGE) AS SHORTAGE,
					(SUM(OPSTOCK)+SUM(PURCHASE)+SUM(SALESRETURN))- (SUM(SALES)+SUM(PURRETURN)+SUM(ISSUE2JOB)) AS CLOSING,ORD 
					FROM (

					SELECT UPPER(DATENAME(MM,YOM.VCHDATE)) AS MONTHNAME,YOM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,	
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					YOD.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					,(CASE WHEN DATEPART(M,YOM.VCHDATE)<=3 THEN  (DATEPART(M,YOM.VCHDATE)+12)ELSE DATEPART(M,YOM.VCHDATE) END) AS ORD 
					FROM "+@DatabaseName+"ITEM_MASTER IM
