					YOD.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					,(CASE WHEN DATEPART(M,'"+@FromDate+"')<=3 THEN  (DATEPART(M,'"+@FromDate+"')+12)ELSE DATEPART(M,'"+@FromDate+"') END) AS ORD 
