					INNER JOIN "+@DatabaseName+"YARNOPENING_MASTER YOM ON YOM.INWARDID =  YOD.INWARDID
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE YOD.CMP_CODE IN ("+@Cmp_Code+") AND YOM.VCHDATE < '"+@FromDate+"'
