					WHERE SRD.CMP_CODE IN ("+@Cmp_Code+") AND SRM.FLAG = 'YSR' AND SRM.SAL_RET_DATE < '"+@FromDate+"'
					"

		SET @SQL3 = " UNION ALL 

					SELECT UPPER(DATENAME(MM,SIM.SAL_INV_VDATE)) AS MONTHNAME,SIM.SAL_INV_VDATE AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
