					,(CASE WHEN DATEPART(M,SIM.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SIM.SAL_INV_VDATE)+12)ELSE DATEPART(M,SIM.SAL_INV_VDATE) END) AS ORD 
