					UNION ALL 

					SELECT UPPER(DATENAME(MM,'"+@FromDate+"')) AS MONTHNAME,SIM.SAL_INV_VDATE AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					(0-SID.SAL_INV_QTY) AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					,(CASE WHEN DATEPART(M,'"+@FromDate+"')<=3 THEN  (DATEPART(M,'"+@FromDate+"')+12)ELSE DATEPART(M,'"+@FromDate+"') END) AS ORD 
					FROM "+@DatabaseName+"ITEM_MASTER IM
					INNER JOIN "+@DatabaseName+"SALES_INVOICE_DETAIL SID ON SID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"SALES_INVOICE SIM ON SIM.SAL_INV_ID =  SID.SAL_INV_ID AND SIM.CMP_CODE = SID.CMP_CODE AND SIM.FLAG = SID.FLAG 
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE SID.CMP_CODE IN ("+@Cmp_Code+") AND SIM.FLAG = 'YS' AND SIM.SAL_INV_VDATE < '"+@FromDate+"'
