					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID =  PID.PURCHASEINVID AND PIM.CMP_CODE = PID.CMP_CODE AND PIM.FLAG = PID.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PID.CMP_CODE IN ("+@Cmp_Code+") AND PIM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PIM.FLAG = 'YP'

					UNION ALL 

					SELECT UPPER(DATENAME(MM,'"+@FromDate+"')) AS MONTHNAME,PIM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,
					IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					PID.QUANTITY AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
					0.00 AS ISSUE2JOB,0.00 AS SHORTAGE,0.00 AS CLOSING
					,(CASE WHEN DATEPART(M,'"+@FromDate+"')<=3 THEN  (DATEPART(M,'"+@FromDate+"')+12)ELSE DATEPART(M,'"+@FromDate+"') END) AS ORD 
