					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DatabaseName+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID =  PID.PURCHASEINVID AND PIM.CMP_CODE = PID.CMP_CODE AND PIM.FLAG = PID.FLAG
					INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
					INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
					"+@JOINSQL+"
					WHERE PID.CMP_CODE IN ("+@Cmp_Code+") AND PIM.FLAG = 'YP' AND PIM.VCHDATE < '"+@FromDate+"'
					"

		SET @SQL5 = "UNION ALL 

					SELECT UPPER(DATENAME(MM,YRJM.VCHDATE)) AS MONTHNAME,YRJM.VCHDATE AS VDATE,IM.ITEM_NAME AS ITEM,
					IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID AS ITEMGRPID,
					0.00 AS OPSTOCK,0.00 AS PURCHASE,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS PURRETURN,
