-- =============================================
PROC_FIBERSTOCK_MONTHLY 1,'ACC2012_2013.DBO.','1','01/APR/2012','31/MAR/2013','##464'
*/
CREATE PROCEDURE [dbo].[PROC_FIBERSTOCK_MONTHLY]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE NVARCHAR(50),
@TODATE NVARCHAR(50),
@TEMPTABLE NVARCHAR(50)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET  @STRSQL =""
DECLARE @STRSQL1 AS NVARCHAR(4000) SET  @STRSQL1 =""
DECLARE @SQLJOIN As NVARCHAR(200) SET @SQLJOIN=""


BEGIN
	IF @Rpt_Wise = 1 
		SET @SQLJOIN= " INNER JOIN "+@TEMPTABLE+" TT On IM.Item_ID = TT.Code  " 
	ELSE IF @Rpt_Wise = 2 OR @Rpt_Wise = 4
		SET @SQLJOIN= " INNER JOIN "+@TEMPTABLE+" TT On IGM.ITEM_GRP_ID = TT.Code  " 
	ELSE IF @Rpt_Wise = 3 OR @Rpt_Wise = 5
		SET @SQLJOIN= " INNER JOIN "+@TEMPTABLE+" TT On ITM.Item_Type_Id = TT.Code  " 	

END
BEGIN	
	SET NOCOUNT ON;
SET @STRSQL ="
SELECT MONTHNAME,ITEM,ITEM_ID,ITEMGROUP,ITEM_GRP_ID,TYPENAME,ITEM_TYPE_ID,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE)AS PURCHASE,SUM(CONSUMED) AS CONSUMED,SUM(TRANSFER) AS TRANSFER,ORD  FROM
(
SELECT UPPER(DATENAME(MM,'"+@FROMDATE+"')) AS MONTHNAME,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,ITM.ITEM_TYPE_NAME AS TYPENAME,ITM.ITEM_TYPE_ID,SUM(QUANTITY) AS OPSTOCK,
0 AS PURCHASE,0 AS CONSUMED,0 AS TRANSFER,
(CASE WHEN DATEPART(M,'"+@FROMDATE+"')<=3 THEN  (DATEPART(M,'"+@FROMDATE+"')+12)ELSE DATEPART(M,'"+@FROMDATE+"') END) AS ORD
FROM "+@DATABASENAME+" YARNOPENING_DETAIL YOP 
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON YOP.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID = ITM.ITEM_TYPE_ID
"+@SQLJOIN+"
WHERE YOP.PROCESS = 'FIBER'
AND YOP.CMP_CODE IN ("+@CMP_CODE+") AND YOP.QUANTITY >  0 
GROUP BY IM.ITEM_NAME,IM.ITEM_ID,IGM.ITEM_GRP_NAME ,IGM.ITEM_GRP_ID,ITM.ITEM_TYPE_NAME ,ITM.ITEM_TYPE_ID

UNION ALL

SELECT UPPER(DATENAME(MM,SIM.VCHDATE)) AS MONTHNAME,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,ITM.ITEM_TYPE_NAME AS TYPENAME,ITM.ITEM_TYPE_ID,
0 AS OPSTOCK,                
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.QUANTITY  WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION  IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS PURCHASE,0 AS CONSUMED,0 AS TRANSFER,
(CASE WHEN DATEPART(M,SIM.VCHDATE)<=3 THEN  (DATEPART(M,SIM.VCHDATE)+12)ELSE DATEPART(M,SIM.VCHDATE) END) AS ORD
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE SIM ON SID.PURCHASEINVID=SIM.PURCHASEINVID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID = ITM.ITEM_TYPE_ID
"+@SQLJOIN+"
WHERE SIM.CMP_CODE IN ("+@CMP_CODE+") AND SIM.FLAG = 'YP' 
"
SET @STRSQL1="
UNION ALL

SELECT UPPER(DATENAME(MM,SIM.VCHDATE)) AS MONTHNAME,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,ITM.ITEM_TYPE_NAME AS TYPENAME,ITM.ITEM_TYPE_ID,                
0 AS OPSTOCK,0 AS PURCHASE,SID.QTY AS CONSUMED,0 AS TRANSFER,
(CASE WHEN DATEPART(M,SIM.VCHDATE)<=3 THEN  (DATEPART(M,SIM.VCHDATE)+12)ELSE DATEPART(M,SIM.VCHDATE) END) AS ORD
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" YARNRECJOBLOT_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" YARNRECJOB_MASTER SIM ON SID.YANRECJOB_ID=SIM.YANRECJOB_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID = ITM.ITEM_TYPE_ID
"+@SQLJOIN+"
WHERE SIM.CMP_CODE IN ("+@CMP_CODE+")
) AS FIBERSTOCK
GROUP BY MONTHNAME,ITEM,ITEM_ID,ITEMGROUP,ITEM_GRP_ID,TYPENAME,ITEM_TYPE_ID,ORD
"
    
END
PRINT @STRSQL 
PRINT @STRSQL1
EXECUTE (@STRSQL + @STRSQL1)




















GO

