/*
PROC_FIN_STOCK_REPORT '10','ACC2010_2011.DBO.','01/APR/2010','07/OCT/2010','##848','01/APR/2010'
*/
CREATE PROCEDURE [dbo].[PROC_FIN_STOCK_REPORT]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @STARTDATE AS NVARCHAR(20),
  @OPENINGDATE AS NVARCHAR(20)
  
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @SQL7=""
SET @SQL8=""
SET @SQL9=""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "  


BEGIN	

SET @SQL=" SELECT  DATE, SUM(IT_OP_STOCK) AS IT_OP_STOCK,SUM(QTY_MFG) AS QTY_MFG,SUM(PUR_RET) AS PUR_RET,SUM(SAL_RET) AS SAL_RET, SUM(PUR_QTY) AS PUR_QTY, SUM(PUR_AMT) AS PUR_AMT,SUM(SAL_QTY) AS SAL_QTY,SUM(SAL_AMT) AS SAL_AMT,SUM(OTHER) AS OTHER
           FROM (
           SELECT '"+@OPENINGDATE+"' AS DATE, IOS.ITEM_OP_STOCK AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
           FROM "+@DATABASENAME+"ITEM_OPENING_STOCK IOS
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=IOS.ITEM_ID
           "+@JOINSQL+"
           WHERE IOS.CMP_CODE="+@CMP_CODE+" AND  IOS.ITEM_OP_STOCK>0
UNION ALL
           SELECT FTGI.ITEMDATE AS DATE, 0 IT_OP_STOCK,FTGI.METER AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
           FROM "+@DATABASENAME+"FTGITEMDETAIL FTGI           
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTGI.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGI.ITEMDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND FTGI.METER>0
           AND FTGI.CMP_CODE="+@CMP_CODE+"
UNION ALL
           SELECT '"+@OPENINGDATE+"' AS DATE, FTGI.METER IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
           FROM "+@DATABASENAME+"FTGITEMDETAIL FTGI           
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTGI.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGI.ITEMDATE<'"+@FROMDATE+"' AND FTGI.ITEMDATE>'"+@STARTDATE+"'  AND FTGI.CMP_CODE="+@CMP_CODE+" AND FTGI.METER>0
UNION ALL "
SET @SQL1 =" SELECT SRM.SAL_RET_DATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,
           (CASE  WHEN UM.UNIT_NAME='METERS' THEN SRD.SAL_RET_QTY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SRD.SAL_RET_QTY   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SRD.SAL_RET_PCS  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )
             AS SAL_RET
             , 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+"SALES_RETURN_DETAIL SRD
             INNER JOIN "+@DATABASENAME+"SALES_RETURN_MASTER SRM ON SRM.SAL_RET_ID=SRD.SAL_RET_ID 
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SRD.ITEM_ID
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
             "+@JOINSQL+"
             WHERE SRM.SAL_RET_DATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SRM.CMP_CODE="+@CMP_CODE+" AND SRD.SAL_RET_QTY >0
UNION ALL
             SELECT '"+@OPENINGDATE+"' AS DATE, (CASE  WHEN UM.UNIT_NAME='METERS' THEN SRD.SAL_RET_QTY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SRD.SAL_RET_QTY   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SRD.SAL_RET_PCS  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+"SALES_RETURN_DETAIL SRD
             INNER JOIN "+@DATABASENAME+"SALES_RETURN_MASTER SRM ON SRM.SAL_RET_ID=SRD.SAL_RET_ID 
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SRD.ITEM_ID
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
             "+@JOINSQL+"
             WHERE SRM.SAL_RET_DATE  <'"+@FROMDATE+"'  AND SRM.SAL_RET_DATE>'"+@STARTDATE+"' AND SRM.CMP_CODE="+@CMP_CODE+" AND SRD.SAL_RET_QTY>0
UNION ALL
             SELECT PI.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET,
             (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (PID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )
             AS PUR_QTY,
              0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM  "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
             INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE  PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID AND IM.ITEM_TYPE='FG'
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
              "+@JOINSQL+"
             WHERE PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE+" AND PID.QUANTITY>0
UNION ALL
           SELECT DISTINCT PI.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET,
             0 AS PUR_QTY,
              PI.NETTOTAL AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,PI.BILLNO AS BILLNO,PI.LGR_ID AS PARTYID
             FROM  "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
             INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE  PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID AND IM.ITEM_TYPE='FG'               
             "+@JOINSQL+"
             WHERE PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE+" 

UNION ALL   "


SET @SQL3="
SELECT '"+@OPENINGDATE+"' AS DATE, (0-STD.QUANTITY) AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID           
        FROM "+@DATABASENAME+"STOCK_TRANSFER_DETAIL STD
		INNER JOIN "+@DATABASENAME+"STOCK_TRANSFER_MASTER STM ON STM.TRANSFER_ID=STD.TRANSFER_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=STD.ITEM_ID
		INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
        "+@JOINSQL+"
        WHERE STM.CMP_CODE in ("+@CMP_CODE+") AND STM.VCHDATE<'"+@FROMDATE+"' --AND STM.VCHDATE>'"+@STARTDATE+"'
UNION ALL
SELECT '"+@OPENINGDATE+"' AS DATE, STD.QUANTITY AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID           
        FROM "+@DATABASENAME+"STOCK_TRANSFER_DETAIL STD
		INNER JOIN "+@DATABASENAME+"STOCK_TRANSFER_MASTER STM ON STM.TRANSFER_ID=STD.TRANSFER_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=STD.TO_ITEM_ID
		INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
        "+@JOINSQL+"
        WHERE STM.CMP_CODE in ("+@CMP_CODE+") AND STM.VCHDATE<'"+@FROMDATE+"' --AND STM.VCHDATE>'"+@STARTDATE+"'
UNION ALL
SELECT STM.VCHDATE AS DATE, 0 AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,STD.QUANTITY AS OTHER,'' AS BILLNO,0 AS PARTYID           
        FROM "+@DATABASENAME+"STOCK_TRANSFER_DETAIL STD
		INNER JOIN "+@DATABASENAME+"STOCK_TRANSFER_MASTER STM ON STM.TRANSFER_ID=STD.TRANSFER_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=STD.ITEM_ID
		INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
        "+@JOINSQL+"
        WHERE STM.CMP_CODE in ("+@CMP_CODE+") AND STM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
UNION ALL

SELECT STM.VCHDATE AS DATE, 0 AS IT_OP_STOCK,STD.QUANTITY AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID           
        FROM "+@DATABASENAME+"STOCK_TRANSFER_DETAIL STD
		INNER JOIN "+@DATABASENAME+"STOCK_TRANSFER_MASTER STM ON STM.TRANSFER_ID=STD.TRANSFER_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=STD.TO_ITEM_ID
		INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
        "+@JOINSQL+"
        WHERE STM.CMP_CODE in ("+@CMP_CODE+") AND STM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
"



SET @SQL4=" 
UNION ALL
SELECT '"+@OPENINGDATE+"' AS DATE,
      (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (PID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) IT_OP_STOCK
            ,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM  "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
            INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE  PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID AND IM.ITEM_TYPE='FG'
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+" 
            WHERE PI.RECDATE < '"+@FROMDATE+"' AND PI.VCHDATE>'"+@STARTDATE+"' AND PI.CMP_CODE="+@CMP_CODE+" AND PID.QUANTITY>0
UNION ALL
            SELECT SI.SAL_INV_VDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY     WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SID.SAL_INV_PCS   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS SAL_QTY
            ,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"SALES_INVOICE_DETAIL SID
            INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SI.SAL_INV_VDATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE="+@CMP_CODE+" AND SID.SAL_INV_QTY>0 AND (WIPSALE=0 OR WIPSALE IS NULL)
UNION ALL
           SELECT DISTINCT SI.SAL_INV_VDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,
           0 AS SAL_QTY,SI.SAL_INV_NETTOTAL AS SAL_AMT,0 AS OTHER,SI.SAL_INV_BILL_NO AS BILLNO,SI.LGR_ID AS PARTYID
           FROM "+@DATABASENAME+"SALES_INVOICE_DETAIL SID
           INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID            
           "+@JOINSQL+"
           WHERE SI.SAL_INV_VDATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE="+@CMP_CODE+" AND SID.SAL_INV_QTY>0 AND (WIPSALE=0 OR WIPSALE IS NULL)
  
UNION ALL
            SELECT '"+@OPENINGDATE+"' AS DATE, (0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY     WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SID.SAL_INV_PCS   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) IT_OP_STOCK,
            0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"SALES_INVOICE_DETAIL SID
            INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SI.SAL_INV_VDATE  <'"+@FROMDATE+"'  AND SI.SAL_INV_VDATE>'"+@STARTDATE+"' AND SI.CMP_CODE="+@CMP_CODE+" AND SID.SAL_INV_QTY>0 AND (WIPSALE=0 OR WIPSALE IS NULL)


"

SET @SQL5="
UNION ALL
SELECT '"+@OPENINGDATE+"' AS DATE,
      (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) IT_OP_STOCK
            ,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"STOCKIN_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID AND IM.ITEM_TYPE='FG'
                INNER JOIN "+@DATABASENAME+"STOCKIN_MASTER SI ON SI.STOCKIN_ID=SID.STOCKIN_ID
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+" 
            WHERE SI.VCHDATE< '"+@FROMDATE+"' AND SI.VCHDATE>'"+@STARTDATE+"' AND SI.CMP_CODE="+@CMP_CODE+" AND SID.QUANTITY>0
UNION ALL
SELECT '"+@OPENINGDATE+"' AS DATE,
      (CASE  WHEN UM.UNIT_NAME='METERS' THEN GID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (GID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (GID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) IT_OP_STOCK
            ,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
            INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_DETAIL GID ON GID.ITEM_ID=IM.ITEM_ID AND IM.ITEM_TYPE='FG'
            INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_MASTER GIM ON GIM.GreyStockTrans_Id=GID.GreyStockTrans_Id
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+" 
            WHERE GIM.VCHDATE< '"+@FROMDATE+"' AND GIM.VCHDATE>'"+@STARTDATE+"' AND GIM.CMP_CODE="+@CMP_CODE+" AND GID.QUANTITY>0
  "
SET @SQL6="
        UNION ALL
             SELECT SI.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET,
             (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )
              AS PUR_QTY,
              0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"STOCKIN_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID AND IM.ITEM_TYPE='FG'
                INNER JOIN "+@DATABASENAME+"STOCKIN_MASTER SI ON SI.STOCKIN_ID=SID.STOCKIN_ID
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
              "+@JOINSQL+"
             WHERE SI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE="+@CMP_CODE+" AND SID.QUANTITY>0
UNION ALL
             SELECT GIM.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET,
             (CASE  WHEN UM.UNIT_NAME='METERS' THEN GID.QUANTITY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (GID.QUANTITY    * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (GID.PIECES  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )
              AS PUR_QTY,
              0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+"ITEM_MASTER IM
             INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_DETAIL GID ON GID.ITEM_ID=IM.ITEM_ID AND IM.ITEM_TYPE='FG'
             INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_MASTER GIM ON GIM.GreyStockTrans_Id=GID.GreyStockTrans_Id
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
              "+@JOINSQL+"
             WHERE GIM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND GIM.CMP_CODE="+@CMP_CODE+" AND GID.QUANTITY>0
            "

SET @SQL7="
         UNION ALL
            SELECT '"+@OPENINGDATE+"' AS DATE, (0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN SD.QUANTITY     WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SD.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SD.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) IT_OP_STOCK,
            0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"STOCKOUT_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
                INNER JOIN "+@DATABASENAME+"STOCKOUT_MASTER SM ON SM.STOCKOUT_ID=SD.STOCKOUT_ID
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SM.VCHDATE<'"+@FROMDATE+"'  AND SM.VCHDATE>'"+@STARTDATE+"' AND SM.CMP_CODE="+@CMP_CODE+" AND SD.QUANTITY>0
   UNION ALL
            SELECT '"+@OPENINGDATE+"' AS DATE, (0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN SD.QUANTITY     WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SD.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SD.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) IT_OP_STOCK,
            0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_MASTER SM ON SM.GreyStockTrans_Id=SD.GreyStockTrans_Id
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SM.VCHDATE<'"+@FROMDATE+"'  AND SM.VCHDATE>'"+@STARTDATE+"' AND SM.CMP_CODE="+@CMP_CODE+" AND SD.QUANTITY>0
"
SET @SQL8="
UNION ALL
            SELECT SM.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,
            (CASE  WHEN UM.UNIT_NAME='METERS' THEN SD.QUANTITY WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SD.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SD.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS SAL_QTY
            ,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
            INNER JOIN "+@DATABASENAME+"STOCKOUT_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
            INNER JOIN "+@DATABASENAME+"STOCKOUT_MASTER SM ON SM.STOCKOUT_ID=SD.STOCKOUT_ID
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SM.CMP_CODE="+@CMP_CODE+" AND SD.QUANTITY>0
UNION ALL
            SELECT SM.VCHDATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,
            (CASE  WHEN UM.UNIT_NAME='METERS' THEN SD.QUANTITY WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SD.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (SD.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS SAL_QTY
            ,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
            FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_MASTER SM ON SM.GreyStockTrans_Id=SD.GreyStockTrans_Id
            INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            "+@JOINSQL+"
            WHERE SM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SM.CMP_CODE="+@CMP_CODE+" AND SD.QUANTITY>0
"
SET @SQL9=" UNION ALL
SELECT PRM.PUR_RET_DATE AS DATE, 0 IT_OP_STOCK,0 AS QTY_MFG,
           (CASE  WHEN UM.UNIT_NAME='METERS' THEN PRD.PUR_RET_QTY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PRD.PUR_RET_QTY   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (PRD.PUR_RET_PCS  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )
             AS PUR_RET,0 AS SAL_RET
             , 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD
             INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRM.PUR_RET_ID = PRD.PUR_RET_ID 
             INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
             "+@JOINSQL+"
             WHERE PRM.PUR_RET_DATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PRM.CMP_CODE="+@CMP_CODE+" AND PRD.PUR_RET_QTY >0
UNION ALL
             SELECT '"+@OPENINGDATE+"' AS DATE, (CASE  WHEN UM.UNIT_NAME='METERS' THEN PRD.PUR_RET_QTY    WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PRD.PUR_RET_QTY   * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
              ELSE  (PRD.PUR_RET_PCS  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS IT_OP_STOCK,0 AS QTY_MFG,0 AS PUR_RET,0 AS SAL_RET, 0 AS PUR_QTY, 0 AS PUR_AMT,0 AS SAL_QTY,0 AS SAL_AMT,0 AS OTHER,'' AS BILLNO,0 AS PARTYID
             FROM "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD
             INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRM.PUR_RET_ID = PRD.PUR_RET_ID 
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
             INNER JOIN UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
             "+@JOINSQL+"
             WHERE PRM.PUR_RET_DATE  <'"+@FROMDATE+"'  AND PRM.PUR_RET_DATE>'"+@STARTDATE+"' AND PRM.CMP_CODE="+@CMP_CODE+" AND PRD.PUR_RET_QTY>0

) AS DETAIL GROUP BY DATE ORDER BY DATE "

    
END

EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6+@SQL7+@SQL8+@SQL9)

PRINT @SQL 
PRINT @SQL1 
PRINT @SQL2 
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5 
PRINT @SQL6 
PRINT @SQL7
PRINT @SQL8
PRINT @SQL9




















GO

