/*
PROC_FOLD_CONFIRMATION_REPORT 2,'ACC2010_2011.dbo.','01/apr/2010','31/mar/2011','',14,3
*/

CREATE PROCEDURE [dbo].[PROC_FOLD_CONFIRMATION_REPORT]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int,
@RptType int
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""
DECLARE @RPT_TYPE_SQL AS NVARCHAR(4000) SET @RPT_TYPE_SQL=""


IF @RptWise in (1,5,12)
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=LM.LGR_ID "
ELSE IF @RptWise in (2,3,4)
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=ALM.Lgr_Id "
ELSE IF @RptWise in (6,11,13)
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID "
ELSE IF @RptWise in (7,8)
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=CG.Cust_Grp_Id "
ELSE IF @RptWise=9
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IGI.Item_Grp_Id "
ELSE IF @RptWise=10
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=SM.Screen_Id "
ELSE IF @RptWise=14
	SET @JOIN=""

IF @RptType =1
	SET @RPT_TYPE_SQL=" AND SOD.PENDINGBALES>0  "
ELSE IF @RptType =2
	SET @RPT_TYPE_SQL=" AND SOD.PENDINGBALES=0  "
ELSE IF @RptType =3
	SET @RPT_TYPE_SQL=" "

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="select SO.ConfNo,SO.vch_Date,SO.Sales_OrderNo,IM.Item_Name,SM.Screen_Name,IGI.Item_Grp_NAME,ITM.Item_Type_Name,
SOD.Bales,SOD.PendingBales,SOD.Rate,FE.FoldNo,FE.Bales as FoldBales,CG.Cust_Grp_NAME,FE.PendingBales as FoldPendingBales,
LM.Lgr_Name as PartyName,ALM.Lgr_Name as AgentName,LCM.CIty_Name as PartyCity,ACM.City_Name as AgentCity
from "+@DataBase+" Sales_Order SO
inner join "+@DataBase+" Sales_Order_Detail SOD on SO.Sal_Order_Id=SOD.Sal_Order_Id and SO.FLAG=SOD.FLAG
LEFT JOIN "+@DataBase+" FoldEntry  FE on SO.CONFNO=FE.CONFNO and SO.CMP_CODE=FE.CMP_CODE AND FE.ITEM_ID=SOD.ITEM_ID
LEFT JOIN "+@DataBase+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
left join "+@DataBase+" City_Master LCM on LCM.City_Id=LM.City_Id
LEFT JOIN "+@DataBase+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
left join "+@DataBase+" City_Master ACM on ACM.City_Id=ALM.City_Id
left join "+@DataBase+" ITEM_MASTER IM on SOD.Item_Id=IM.Item_Id 
left join "+@DataBase+" Screen_master SM on SOD.Screen_Id=SM.SCreen_Id
left join "+@DataBase+" Item_Group_Master IGI on IM.Item_Grp_Id=IGI.Item_Grp_Id
left join "+@DataBase+" Item_Type_Master ITM on ITM.Item_Type_Id=IM.Item_Type_Id
left join Customer_Group_Master CG on CG.Cust_Grp_Id=LM.Cust_Grp_Id
"+@JOIN+"
where SO.CMP_CODE in ("+@CmpCode+") and SO.vch_Date between '"+@FromDate+"' and '"+@ToDate+"' 
and SOD.Bales>0
 "+@RPT_TYPE_SQL+"
ORDER BY SO.ConfNo
"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL  @SQL




















GO

