/*
PROC_FOLD_PENDING_REPORT 2,'Acc2010_2011.dbo.','01/apr/2010','31/mar/2011','##3424',1,1,4,2
*/
CREATE PROCEDURE [dbo].[PROC_FOLD_PENDING_REPORT]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int,
@PoplinPrint int,
@Fold int,
@ReportType int
)
AS

DECLARE @SQL as NVARCHAR(4000) SET @SQL=""
DECLARE @JOIN as NVARCHAR(4000) SET @JOIN=""
DECLARE @FOLD_CON as NVARCHAR(4000) SET @FOLD_CON=""
DECLARE @PoplinPrint_Str as NVARCHAR(4000) SET @PoplinPrint_Str=""
DECLARE @ReportTypeStr as NVARCHAR(4000) SET @ReportTypeStr=""
DECLARE @StrFiled as NVARCHAR(4000) SET @StrFiled=""

BEGIN 
IF @RptWise in (1,5,12) /*PARTY WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=LM.LGR_ID "

IF @RptWise in (2,3,4) /*AGENT WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=ALM.LGR_ID "

IF @RptWise in (6,11,13) /* ITEM WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID "

IF @RptWise in (7,8) /* CUSTOMER GROUP  WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=CGM.Cust_Grp_Id "

IF @RptWise=9 /* ITEM GROUP  WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id "

IF @RptWise=10 /* SCREEN  WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=SM.SCREEN_ID "

IF @RptWise=14 /* ALL WISE */
	SET @JOIN=" "
END

BEGIN
IF @PoplinPrint=1
	SET @PoplinPrint_Str=" AND FE.FORMFLAG='POPLIN'"
ELSE IF @PoplinPrint=2
	SET @PoplinPrint_Str=" AND FE.FORMFLAG='PRINT'"
END

BEGIN
IF @Fold=1
	SET @FOLD_CON=" WHERE PENDING>0 "
ELSE IF @Fold=2
	SET @FOLD_CON=" WHERE VCHDATE>End_Date "
ELSE IF @Fold=3
	SET @FOLD_CON=" WHERE PENDING=0 "
ELSE IF @Fold=4
	SET @FOLD_CON=""
END

BEGIN	
IF @ReportType=1
	BEGIN	
	SET @ReportTypeStr=" LEFT JOIN "+@DataBase+" PackingSlip STD on FE.FOLDNO=STD.FOLDNO and FE.Cmp_Code=STD.Cmp_Code"	
	SET @StrFiled=" COUNT(STD.FOLDNO)as SIBALES,FE.PendingBales as PENDING "
	END
else if @ReportType=2
	BEGIN	
	SET @ReportTypeStr=" LEFT JOIN "+@DataBase+" STOCKIN_DETAIL STD on FE.FOLDNO=STD.FOLD and FE.CMP_CODE=STD.CMP_CODE "
	SET @StrFiled=" COUNT(STD.FOLD)as SIBALES,FE.BALES-COUNT(STD.FOLD) as PENDING "
	END
END

BEGIN	
	SET NOCOUNT ON;
SET @SQL="select FOLDNO,VCHDATE,Party,PartyCity,Item_Name,Screen_Name,BALES,SIBALES,Pending,PendingBales,REMARK,AgentName,
AgentCity,CustGrpName,ItemGrpName,End_Date
FROM(
SELECT FE.FOLDNO,FE.VCHDATE,LM.Lgr_Name as Party,CM.CIty_Name as PartyCity,IM.Item_Name,SM.Screen_Name,'' as REMARK,
ALM.Lgr_Name as AgentName,ACM.CITY_NAME as AgentCity,CGM.Cust_Grp_NAME as CustGrpName,IG.Item_Grp_Name as ItemGrpName,FE.End_Date,
FE.BALES,FE.PendingBales,"+@StrFiled+"
FROM "+@DataBase+" FOLDENTRY FE 
"+@ReportTypeStr+"
left join "+@DataBase+" Ledger_Master LM on FE.Lgr_Id=LM.Lgr_Id
left join "+@DataBase+" City_Master CM on CM.CIty_Id=LM.City_Id
left join "+@DataBase+" Item_Master IM ON FE.Item_Id=IM.Item_Id
left join "+@DataBase+" Screen_Master SM on FE.Screen_Id=SM.Screen_Id
left join "+@DataBase+" Ledger_Master ALM on FE.Agent_Id=ALM.Lgr_Id
left join "+@DataBase+" City_Master ACM on ACM.CIty_Id=ALM.City_Id
left join "+@DataBase+" Customer_Group_Master CGM on LM.Cust_Grp_Id=CGM.Cust_Grp_Id
left join "+@DataBase+" Item_Group_Master IG on IG.Item_Grp_Id=IM.Item_Grp_Id
"+@JOIN+"
WHERE FE.Cmp_CODE in ("+@CmpCode+") and FE.VCHDATE between '"+@FromDate+"' and '"+@ToDate+"'
"+@PoplinPrint_Str+"
GROUP by FE.FOLDNO,FE.VCHDATE,LM.Lgr_Name,CM.CIty_Name,IM.Item_Name,SM.Screen_Name,FE.BALES,FE.PendingBales,
ALM.Lgr_Name,ACM.CITY_NAME,CGM.Cust_Grp_NAME,IG.Item_Grp_Name,FE.End_Date
) as A

"+@FOLD_CON+"
order by FoldNo
"
    
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_FOLD_STOCK_REPORT]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
