/*
PROC_FOLD_STOCK_REPORT 2,'Acc2010_2011.dbo.','31/Mar/2011','##2524',1,2
*/

CREATE PROCEDURE [dbo].[PROC_FOLD_STOCK_REPORT]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@AsOnDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int,
@FoldType int
)
AS

DECLARE @SQL as NVARCHAR(4000) SET @SQL =""
DECLARE @JOIN as NVARCHAR(4000) SET @JOIN =""
DECLARE @COND as NVARCHAR(4000) SET @COND =""

BEGIN
IF @RptWise in (1,2)/*party wise*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=LM.Lgr_Id"
ELSE IF @RptWise in (3,4)/* AGENT WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=ALM.Lgr_Id "
ELSE IF @RptWise in (5,6)/*Customer Grp */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=CGM.Cust_Grp_Id  "
ELSE IF @RptWise in (7,8,10)/*ITEM WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID  "
ELSE IF @RptWise in (9,11)/* SCREEN WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=SM.Screen_Id  "

END

BEGIN
IF @FoldType=1
	SET @COND=" AND FormFlag='POPLIN'"	
ELSE IF @FoldType=2
	SET @COND=" AND FormFlag='PRINT'"	

END

BEGIN
	
	SET NOCOUNT ON;
SET @SQL= "
select IM.Item_Name,SM.Screen_Name,STM.VchDate,STD.DESIGN_COL_CHART,STD.FOLD,STD.LOTNO,sum(FM.Bales) as Bales,max(STM.REMARK) as REMARK,
max(LM.Lgr_Name) as Party,max(CM.City_Name) as PartyCity,max(ALM.Lgr_Name) as AgentName,max(ACM.City_Name) as AgentCity,
max(CGM.Cust_Grp_Name) as CustGrpName
from "+@DataBase+" STOCKIN_MASTER STM
inner join "+@DataBase+" STOCKIN_DETAIL STD on STM.STOCKIN_ID=STD.STOCKIN_ID
inner join "+@DataBase+" FoldEntry FM on STD.FOLD=FM.FoldNo and STD.Cmp_Code=FM.CMp_Code "+@COND+"
left join "+@DataBase+" Item_Master IM on STD.Item_Id=IM.ITem_Id
left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
left join "+@DataBase+" Ledger_Master LM on LM.Lgr_Id=FM.Lgr_Id
left join "+@DataBase+" City_Master CM on LM.City_Id=CM.City_Id
left join "+@DataBase+" Ledger_Master ALM on ALM.Lgr_Id=FM.Agent_Id
left join "+@DataBase+" City_Master ACM on ACM.CITY_ID=ALM.CITY_ID
left join "+@DataBase+" Customer_Group_Master CGM on CGM.Cust_Grp_Id=LM.Cust_Grp_Id
"+@JOIN+"
where STM.Cmp_Code in ("+@CmpCode+") and STM.VCHDATE<='"+@AsOnDate+"'
group by IM.Item_Name,SM.Screen_Name,STM.VchDate,STD.DESIGN_COL_CHART,STD.FOLD,STD.LOTNO
Order by STD.FOLD
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

