/*
PROC_FOLDING_PENDING '10','ACC2010_2011.DBO.','01/APR/2010','30/NOV/2010','##2310',1,'1','30/NOV/2010'
*/
CREATE PROCEDURE [dbo].[PROC_FOLDING_PENDING]
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(50),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT,
   @RPT_TYPE INT,
   @ASONDATE NVARCHAR(20)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @DATESQL AS NVARCHAR(1000)
DECLARE @PENDSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""
SET @DATESQL=""
SET @PENDSQL=""
BEGIN
        IF @RPT_WISE=1
          SET @JOINSQL="  INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
        ELSE IF @RPT_WISE=2
          SET @JOINSQL="  INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
        ELSE IF @RPT_WISE=3
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
        ELSE IF @RPT_WISE=4
          SET @JOINSQL=""        
END

BEGIN 
     IF @RPT_TYPE=1
         BEGIN
          SET @DATESQL="<='"+@ASONDATE+"'"        
          SET @PENDSQL=" HAVING (SUM(FOLDINGTHAN)-SUM(SHORTTHAN))>0"
         END
    ELSE IF @RPT_TYPE=2
         BEGIN
           SET @DATESQL=" BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'"
           SET @PENDSQL=""
         END
END


BEGIN
SET @SQL="
            SELECT LOTNO,ITEM,VIEWER,ITEMGROUP,ITEMTYPE,SUM(FOLDINGTHAN) AS FOLDINGTHAN,SUM(FOLDINGMTRS) AS FOLDINGMTRS,SUM(SHORTTHAN) AS SHORTTHAN,SUM(SHORTMTR) AS SHORTMTR,CMP_ALIAS
            FROM (
			SELECT F2F.LOTNO,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,WM.WEAVER_NAME AS VIEWER
            ,F2F.RECTHAN AS FOLDINGTHAN,F2F.RECMETER AS FOLDINGMTRS,0 AS SHORTTHAN,0.00 AS SHORTMTR,CMP.CMP_ALIAS
			FROM "+@DATABASENAME+"FINISHTOFOLDING F2F
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=F2F.ITEM_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=F2F.WEAVER_ID
            INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
            INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=F2F.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
            "+@JOINSQL+"
            WHERE F2F.VCHDATE"+ @DATESQL +" AND F2F.CMP_CODE IN ("+@CMP_CODE+")
			"
SET @SQL1="	UNION ALL  SELECT  FRD.LOTNO,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,WM.WEAVER_NAME AS VIEWER
            ,0 AS FOLDINGTHAN,0.00 AS FOLDINGMTRS,FRD.GRAYTHAN AS SHORTTHAN,FRD.GRAYMETER AS SHORTMTR,CMP.CMP_ALIAS
			FROM "+@DATABASENAME+"FTGRECDETAIL FRD            
			INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FRD.FTGID            
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=FTG.WEAVER_ID
            INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
            INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=FRD.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
            "+@JOINSQL+"
            WHERE FTG.CMP_CODE IN ("+@CMP_CODE+") AND FRD.RECDATE"+ @DATESQL +" "
SET @SQL2="	) AS DETAIL 
            GROUP BY LOTNO,ITEM,VIEWER,CMP_ALIAS,ITEMGROUP,ITEMTYPE
            "+@PENDSQL+"
            ORDER BY LOTNO

"
END
IF @RPT_TYPE=2
SET @SQL1=""	

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

