/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 22/11/2012
-- Description:	THIS PROCEDURE USED FOR FORM26Q DETAIL DATA
-- REPORT_NAME: FORM26Q.RPT --> FORM26Q_DETAIL.RPT
-- =============================================
   PROC_FORM26Q_DETAIL 1,'ACC2012_2013.DBO.','##560',4,'01/APR/2012','30/june/2012'   

*/
CREATE PROCEDURE [dbo].[PROC_FORM26Q_DETAIL]
(
	 @CMP_CODE NVARCHAR(100),
     @DATABASENAME NVARCHAR(100),
	 @TEMPTABLE    NVARCHAR(20),
	 @RPTWISE		INT,
	 @STARTDATE    NVARCHAR(20),
	 @ENDDATE	   NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLCONDITION AS NVARCHAR(4000)

BEGIN
	IF @RPTWISE = 0 /* QUARTER - 1 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 1 /* QUARTER - 2 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 2 /* QUARTER - 3 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 3 /* QUARTER - 4 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 4 /* ALL */
	BEGIN
		SET @SQLCONDITION = "  "		
	END
END

BEGIN
	
	SET NOCOUNT ON;

	SET @SQL = " SELECT MAX(JM.BSRCODE) AS BSRCODE,MAX(JM.CHEQUE_DATE) AS DEPOSITE_DATE,MAX(JM.CHALLANNO) AS CHALLANNO
				 ,JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,SUM(JCD.TDS_AMOUNT) AS TDS,0 AS SURCHARGE,0 AS EDU_CESS,
				 0 AS HIG_CESS,0 AS INTEREST,0 AS OTHER ,SUM(JCD.TDS_AMOUNT) AS TOTALTAX,
				 CM.CMP_NAME AS NAMEOFDEDUCTOR,'A' AS FLAG,0 AS DEDUCTEE_CODE,'A' AS LGR_PANO,'A' AS LGR_NAME,
				 '' AS BILLDATE,0 AS BILL_AMT,0 AS TDS_AMOUNT, 0 AS TOTALTAX_DEDUCTED,0 AS TOTALTAX_DEPOSITED,
				 0 AS DEDUCTED_DATE,0 AS RATEDEDUCTED

				 FROM "+@DATABASENAME+" JOBCHALLAN_MASTER JM
				 INNER JOIN "+@DATABASENAME+" TDSCATEGORY_MASTER TCM ON JM.TDS_ID = TCM.TDS_ID
				 INNER JOIN "+@DATABASENAME+" JOBCHALLAN_DETAIL JCD ON JM.JOBCHALLAN_ID  = JCD.JOBCHALLAN_ID AND JM.CMP_CODE = JCD.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON JM.CMP_CODE = CM.CMP_CODE
			     INNER JOIN "+@TEMPTABLE +"  TT ON TT.CODE = TCM.TDS_ID
				 WHERE JM.CMP_CODE IN ( "+@CMP_CODE+" ) "+@SQLCONDITION+"
				 GROUP BY JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,CM.CMP_NAME

				 UNION ALL

				 SELECT JM.BSRCODE AS BSRCODE,JM.CHEQUE_DATE AS DEPOSITE_DATE,JM.CHALLANNO AS CHALLANNO,
				 JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,0 AS TDS,0 AS SURCHARGE,0 AS EDU_CESS,
				 0 AS HIG_CESS,0 AS INTEREST,0 AS OTHER,0 AS TOTALTAX,CM.CMP_NAME AS NAMEOFDEDUCTOR,'B' AS FLAG,
				 MAX(LM.DEDUCTEE_CODE) AS DEDUCTEE_CODE,MAX(LM.LGR_PANO) AS LGR_PANO,LM.LGR_NAME,JM.END_DATE AS BILLDATE,SUM(JCD.BILL_AMT) AS BILL_AMT
				,SUM(JCD.TDS_AMOUNT) AS TDS_AMOUNT , SUM(JCD.TDS_AMOUNT) AS TOTALTAX_DEDUCTED,SUM(JCD.TDS_AMOUNT) AS TOTALTAX_DEPOSITED,
				MAX(JCD.BILL_AMT) AS DEDUCTED_DATE,JCD.TDS_PER AS RATEDEDUCTED

				FROM "+@DATABASENAME+" JOBCHALLAN_DETAIL JCD
				INNER JOIN "+@DATABASENAME+" JOBCHALLAN_MASTER JM ON JM.JOBCHALLAN_ID  = JCD.JOBCHALLAN_ID AND JM.CMP_CODE = JCD.CMP_CODE
				INNER JOIN "+@DATABASENAME+" TDSCATEGORY_MASTER TCM ON JM.TDS_ID = TCM.TDS_ID
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON JCD.LGR_ID = LM.LGR_ID
				INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON JM.CMP_CODE = CM.CMP_CODE
				INNER JOIN "+@TEMPTABLE +"  TT ON TT.CODE = TCM.TDS_ID
				WHERE JM.CMP_CODE IN ( "+@CMP_CODE+" ) "+@SQLCONDITION+"
				GROUP BY JM.END_DATE,JM.CHALLANNO,JM.BSRCODE ,JM.CHEQUE_DATE,JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,CM.CMP_NAME,
				LM.LGR_NAME,JCD.TDS_PER
				ORDER BY JM.TDS_ID,FLAG,LGR_NAME"
   
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

