	 @STARTDATE    NVARCHAR(20),
	 @ENDDATE	   NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLCONDITION AS NVARCHAR(4000)

BEGIN
	IF @RPTWISE = 0 /* QUARTER - 1 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 1 /* QUARTER - 2 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 2 /* QUARTER - 3 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 3 /* QUARTER - 4 */
	BEGIN
		SET @SQLCONDITION = " AND JM.END_DATE BETWEEN '"+@STARTDATE+"' AND '"+@ENDDATE+"' "		
	END
	ELSE IF @RPTWISE = 4 /* ALL */
	BEGIN
		SET @SQLCONDITION = "  "		
	END
END
BEGIN
	SET NOCOUNT ON;

	
	SET @SQL = " SELECT CM.CMP_NAME,CM.DEDUCTED_TYPE,CM.CMP_TIN_NO,CM.CMP_TDS_NO,CM.CMP_PAN_NO,CM.CMP_ADD1,CM.CMP_ADD2,
			 CM.CMP_CITY,CM.CMP_PINCODE,CM.CMP_STATE,CM.CMP_EMAIL,CM.CMP_PHONE1,CM.CMP_PHONE2,CM.CMP_MOBILE,
			 JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,SUM(JCD.TDS_AMOUNT) AS TDS,0 AS SURCHARGE,0 AS EDU_CESS,
			 0 AS HIG_CESS,0 AS INTEREST,0 AS OTHER ,SUM(JCD.TDS_AMOUNT) AS TOTALTAX,MAX(JM.CHEQUENO) AS CHEQUENO,
			 MAX(JM.BSRCODE) AS BSRCODE,
			 MAX(JM.CHEQUE_DATE) AS DEPOSITE_DATE,MAX(JM.CHALLANNO) AS CHALLANNO,
			 CONVERT(NVARCHAR,YEAR(CM.CMP_STARTYEAR)) + '-' + CONVERT(NVARCHAR,YEAR(CM.CMP_ENDYEAR)) AS FYEAR
			FROM "+@DATABASENAME+" JOBCHALLAN_MASTER JM
			INNER JOIN "+@DATABASENAME+" TDSCATEGORY_MASTER TCM ON JM.TDS_ID = TCM.TDS_ID
			INNER JOIN "+@DATABASENAME+" JOBCHALLAN_DETAIL JCD ON JM.JOBCHALLAN_ID  = JCD.JOBCHALLAN_ID AND JM.CMP_CODE = JCD.CMP_CODE
			INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON JM.CMP_CODE = CM.CMP_CODE
			INNER JOIN "+@TEMPTABLE +"  TT ON TT.CODE = TCM.TDS_ID
			WHERE JM.CMP_CODE IN ( "+@CMP_CODE+" ) "+@SQLCONDITION+"
			GROUP BY 
			CM.CMP_NAME,CM.DEDUCTED_TYPE,CM.CMP_TIN_NO,CM.CMP_TDS_NO,CM.CMP_PAN_NO,CM.CMP_ADD1,CM.CMP_ADD2,CM.CMP_CITY,
			CM.CMP_PINCODE,CM.CMP_STATE,CM.CMP_EMAIL,CM.CMP_PHONE1,CM.CMP_PHONE2,CM.CMP_MOBILE,
			JM.TDS_ID,TCM.TDS_NAME,TCM.SECTIONCODE,CM.CMP_STARTYEAR,CM.CMP_ENDYEAR "
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















