			WHERE JM.CMP_CODE IN ( "+@CMP_CODE+" ) "+@SQLCONDITION+" AND JM.FLAG = 'TCS'
			GROUP BY 
			CM.CMP_NAME,CM.DEDUCTED_TYPE,CM.CMP_TIN_NO,CM.CMP_TDS_NO,CM.CMP_PAN_NO,CM.CMP_ADD1,CM.CMP_ADD2,CM.CMP_CITY,
			CM.CMP_PINCODE,CM.CMP_STATE,CM.CMP_EMAIL,CM.CMP_PHONE1,CM.CMP_PHONE2,CM.CMP_MOBILE,
			JM.TDS_ID,CM.CMP_STARTYEAR,CM.CMP_ENDYEAR,JM.TDSAMOUNT,JM.CHALLANNO,JM.INTEREST  
			ORDER BY DEPOSITE_DATE,CHALLANNO"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




































GO

