/*
-- =============================================
-- Author         : <BIREN,>
-- Create_date    : <22/11/2012>
-- Report_Form    :	<rfrmFormNo16A>
-- Crystal_Report : <FORMNO_16A.RPT>
-- =============================================
PROC_FORMNO_16A 1,'Acc2013_2014.dbo.','##1800',1,4,'01/JAN/2014','31/MAR/2014'
PROC_FORMNO_16A 1,'ACC2014_2015.DBO.','##1992',1,1,'01/APR/2014','31/MAR/2015'
*/
CREATE PROCEDURE [dbo].[PROC_FORMNO_16A]
(
	@Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
	@TempTable nvarchar(20),
	@Rpt_Wise int,
	@Qtr_Type int,
	@QrtStartDate nvarchar(20),
	@QrtEndDate nvarchar(20)
)
AS

DECLARE @SQL as NVARCHAR(4000) SET @SQL =""
DECLARE @JOINSQL as NVARCHAR(4000) SET @JOINSQL =""
DECLARE @QTRSQL as NVARCHAR(4000) SET @QTRSQL =""
DECLARE @RECQUARTER AS NVARCHAR(1000) SET @RECQUARTER=""
DECLARE @SQLGRPQUARTER AS NVARCHAR(1000) SET @SQLGRPQUARTER = ""
BEGIN
	IF @Rpt_Wise = 1 
		BEGIN
			set @JOINSQL=" INNER JOIN "+ @TempTable + " TT on TT.Code=LM.LGR_ID"
		END
END
BEGIN
	 IF @Qtr_Type = 5 /* ALL QUARTER  */
		BEGIN
			set @QTRSQL="JCM.END_DATE BETWEEN '"+@QrtStartDate+"' AND '"+@QrtEndDate+"'"
			SET @RECQUARTER = ",'' AS QUARTERRECEIPT,'' AS QUARTERDATE "
			SET @SQLGRPQUARTER = ""
		END
	ELSE IF @Qtr_Type = 1 /* QUARTER 1 */
		BEGIN
			set @QTRSQL="JCM.END_DATE BETWEEN '"+@QrtStartDate+"' AND '"+@QrtEndDate+"'"
			SET @RECQUARTER = ",ISNULL(TDS.QUARTER1,'') AS QUARTERRECEIPT,TDS.QUARTER1DATE AS QUARTERDATE "
			SET @SQLGRPQUARTER = ",TDS.QUARTER1,TDS.QUARTER1DATE"
		END
	ELSE IF @Qtr_Type = 2 /* QUARTER 2 */
		BEGIN
			set @QTRSQL="JCM.END_DATE BETWEEN '"+@QrtStartDate+"' AND '"+@QrtEndDate+"'"
			SET @RECQUARTER = ",ISNULL(TDS.QUARTER2,'') AS QUARTERRECEIPT ,TDS.QUARTER2DATE AS QUARTERDATE"
			SET @SQLGRPQUARTER = ",TDS.QUARTER2,TDS.QUARTER2DATE"
		END
	ELSE IF @Qtr_Type = 3 /* QUARTER 3 */
		BEGIN
			set @QTRSQL="JCM.END_DATE BETWEEN '"+@QrtStartDate+"' AND '"+@QrtEndDate+"'"
			SET @RECQUARTER = ",ISNULL(TDS.QUARTER3,'') AS QUARTERRECEIPT ,TDS.QUARTER3DATE AS QUARTERDATE"
			SET @SQLGRPQUARTER = ",TDS.QUARTER3,TDS.QUARTER3DATE"
		END
	ELSE IF @Qtr_Type = 4 /* QUARTER 4 */
		BEGIN
			set @QTRSQL="JCM.END_DATE BETWEEN '"+@QrtStartDate+"' AND '"+@QrtEndDate+"'"
			SET @RECQUARTER = ",ISNULL(TDS.QUARTER4,'') AS QUARTERRECEIPT ,TDS.QUARTER4DATE AS QUARTERDATE"
			SET @SQLGRPQUARTER = ",TDS.QUARTER4,TDS.QUARTER4DATE"
		END
	
END

BEGIN
	set @sql="
			SELECT MAX(CONVERT(NVARCHAR,JCM.VCHDATE,103)) AS VCHDATE,CHALLANNO,CONVERT(NVARCHAR,CHALLAN_DATE,103) AS CHDATE,
			CONVERT(NVARCHAR,START_DATE,103) AS SDATE,CONVERT(NVARCHAR,END_DATE,103) AS EDATE,
			BSRCODE,MAX(CONVERT(NVARCHAR,JCD.BILLDATE,103)) AS BILLDATE,SUM(JCD.BILL_AMT) AS BILLAMT,
			SUM(JCD.TDS_AMOUNT) AS TDS_AMOUNT,
			MAX(COMP.CMP_NAME) AS CMPNAME ,MAX(COMP.CMP_PAN_NO) AS CPANNO,
			MAX(COMP.CMP_TDS_NO) AS CTDSNO,LM.LGR_NAME AS PARTY,LM.LGR_PANO,TDSM.SECTIONCODE,
			(SUBSTRING(CONVERT(NVARCHAR,CMP_STARTYEAR,103),7,10) +'-'+ SUBSTRING(CONVERT(NVARCHAR,CMP_ENDYEAR,103),7,10)) AS FYEAR,
			LGR_ADD1 AS ADD1,LGR_ADD2 AS ADD2,CM.CITY_NAME AS CITY,STATE_NAME AS STATE,TDSM.TDS_NAME,
			MAX(COMP.CMP_CONTACT_PERSON) AS CONTACTPERSON,MAX(COMP.DEDUCTED_TYPE) AS DEDUCTEDTYPE,
			SUBSTRING(CONVERT(NVARCHAR,CMP_STARTYEAR,103),7,10) AS CMP_STARTYEAR,
			SUBSTRING(CONVERT(NVARCHAR,CMP_ENDYEAR,103),7,10) AS CMP_ENDYEAR,ISNULL(COMP.DEDUCTED_TYPE,'') AS DESIGNATION "+@RECQUARTER+"
			,ISNULL(LM.LGR_ID,0) AS PARTYID
			FROM "+@DatabaseName+"JOBCHALLAN_MASTER JCM
			INNER JOIN "+@DatabaseName+"JOBCHALLAN_DETAIL JCD ON JCD.JOBCHALLAN_ID = JCM.JOBCHALLAN_ID
			INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID = JCD.LGR_ID
			LEFT JOIN "+@DatabaseName+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DatabaseName+"STATE_MASTER SM ON SM.STATE_ID = LM.STATE_ID
			INNER JOIN "+@DatabaseName+"TDSCATEGORY_MASTER TDSM ON TDSM.TDS_ID = JCM.TDS_ID
			INNER JOIN "+@DatabaseName+"COMPANY_MASTER COMP ON COMP.CMP_CODE=JCM.CMP_CODE
			LEFT JOIN "+@DatabaseName+"TDSCONFIGURATION TDS ON TDS.CMP_CODE = JCM.CMP_CODE
			"+@JOINSQL+"
			WHERE JCM.CMP_CODE IN (" + @Cmp_Code + ") AND "+@QTRSQL+"
			GROUP BY JCM.END_DATE,CHALLANNO,CHALLAN_DATE,START_DATE,BSRCODE,LGR_NAME,LGR_PANO,SECTIONCODE,
			CMP_STARTYEAR,CMP_ENDYEAR,LGR_ADD1,LGR_ADD2,CITY_NAME,STATE_NAME,TDS_NAME,CMP_STARTYEAR,CMP_ENDYEAR,COMP.DEDUCTED_TYPE,LM.LGR_ID "+@SQLGRPQUARTER+"
			ORDER BY PARTY,PARTYID
			"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL






















GO

