/****** Object:  StoredProcedure [dbo].[PROC_FRESH_SECOND_ANALYSIS]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_FRESH_SECOND_ANALYSIS '2','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##3228',1,1,'ALL'
*/
CREATE PROCEDURE [dbo].[PROC_FRESH_SECOND_ANALYSIS]
( 
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE AS  NVARCHAR(20),
@RPT_WISE AS  INT,
@HEADID AS  NVARCHAR(20),
@GOODS_TYPE  NVARCHAR(50)

)
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @MAINSQL AS NVARCHAR(2000)
DECLARE @GRPSQL AS NVARCHAR(2000)
DECLARE @GTYPESQL AS NVARCHAR(2000)
DECLARE @ORDERSQL AS NVARCHAR(2000)

SET @SQL=""	
SET @MAINSQL=""	
SET @GRPSQL=""	
SET @JOINSQL=""	
SET @GTYPESQL=""
SET @ORDERSQL=""

BEGIN
IF  @GOODS_TYPE="ALL" 
SET @GTYPESQL=""
ELSE
SET @GTYPESQL=" AND IM.ITEM_GOODS_TYPE='" + @GOODS_TYPE +"'"
END

BEGIN  
IF @RPT_WISE=1
BEGIN
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
SET @MAINSQL="SELECT GOODSTYPE,ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,SUM(QUANTITY) AS QUANTITY,
			  SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES,
			  ITEMGRPID,ITEMTYPEID,ITEMID,MAX(SCREENID) AS SCREENID "	
SET @GRPSQL=" GROUP BY GOODSTYPE,ITEMGROUP,ITEMGRPID,ITEMTYPE,ITEMTYPEID,ITEM,ITEMID,UNIT,CMP_ALIAS "
SET @ORDERSQL=" ORDER BY GOODSTYPE,ITEM,ITEMID,UNIT,CMP_ALIAS "	
END
IF @RPT_WISE=2
BEGIN 
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
SET @MAINSQL="SELECT GOODSTYPE,ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,SUM(QUANTITY) AS QUANTITY,
	          SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES,
	          ITEMGRPID,ITEMTYPEID,ITEMID,MAX(SCREENID) AS SCREENID "	
SET @GRPSQL=" GROUP BY GOODSTYPE,ITEMGROUP,ITEMGRPID,ITEMTYPE,ITEMTYPEID,ITEM,ITEMID,UNIT,CMP_ALIAS "
SET @ORDERSQL=" ORDER BY GOODSTYPE,ITEMGROUP,ITEMGRPID,ITEMTYPE,ITEMTYPEID,ITEM,ITEMID,UNIT,CMP_ALIAS "		
END        
IF @RPT_WISE=3
BEGIN
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=ITM.ITEM_TYPE_ID"
SET @MAINSQL="SELECT GOODSTYPE,ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,SUM(QUANTITY) AS QUANTITY,
		      SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES,
		      ITEMGRPID,ITEMTYPEID,ITEMID,MAX(SCREENID) AS SCREENID "	
SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMGRPID,ITEMTYPE,ITEMTYPEID,ITEM,ITEMID,UNIT,CMP_ALIAS,GOODSTYPE "
SET @ORDERSQL=" ORDER BY GOODSTYPE,ITEMGROUP,ITEMGRPID,ITEMTYPE,ITEMTYPEID,ITEM,ITEMID,UNIT,CMP_ALIAS "		
END        
END 
SET @SQL=@MAINSQL +" 
FROM(
SELECT ISNULL(IM.ITEM_GOODS_TYPE,'') AS GOODSTYPE,ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGROUP,
isnull(ITM.ITEM_TYPE_NAME,'') AS ITEMTYPE,
IM.ITEM_NAME AS ITEM,isnull(SM.SCREEN_NAME,'') AS SCREEN,IOS.SAL_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT,
(CASE WHEN UM.UNIT_NAME='PIECES' THEN SID.SAL_INV_PCS ELSE SID.SAL_INV_QTY END)AS QUANTITY,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,
CMP.CMP_ALIAS,
ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEMGRPID,ISNULL(ITM.ITEM_TYPE_ID,0) AS ITEMTYPEID
,ISNULL(SM.SCREEN_ID,0) AS SCREENID
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN  "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID
LEFT JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=SI.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
"+ @JOINSQL +" 
WHERE SI.SAL_ACCID="+@HEADID+" AND SI.SAL_INV_VDATE>='"+@FROMDATE+"' AND SI.SAL_INV_VDATE<='"+@TODATE+"'
AND SI.CMP_CODE IN("+@CMP_CODE+ ")"+ @GTYPESQL + "
) AS DETAIL 
"+@GRPSQL+""+@ORDERSQL+""



END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

