/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 12/12/2012
-- Description:	THIS PROCEDURE USED FOR FROM PROCESS ISSUE REPORT
-- ReportName:  FROMPROCESSISSUE.RPT
-- =============================================
PROC_FROMPROCESSISSUE '20/MAY/2012','20/MAY/2012',1,'ACC2012_2013.DBO.',1,'##3540',1,0
*/
CREATE PROCEDURE [dbo].[PROC_FROMPROCESSISSUE]
(
	@FROMDATE NVARCHAR(50),
	@TODATE	  NVARCHAR(50),
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),   
	@PROCESSID NVARCHAR(50),
	@TEMPTABLE NVARCHAR(50),
	@RPT_WISE INT,
	@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @REPORTSQL AS NVARCHAR(4000)

SET @SQL = ""
SET @JOINSQL = ""
SET @REPORTSQL = ""

BEGIN	
	IF @PROCESSID = 0 
		SET @REPORTSQL = ""
	ELSE IF @PROCESSID <> 0 
		SET @REPORTSQL = " P2P.FROM_PROCESS_ID = "+@PROCESSID+" AND "
END


BEGIN
	IF @RPT_WISE = 1 OR @RPT_WISE = 5 OR  @RPT_WISE = 6  /* ITEM,ITEM-PARTY,ITEM-ITEMGROUP */
	BEGIN
		 SET @JOINSQL="INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
	END
	 ELSE IF @RPT_WISE =2 OR @RPT_WISE =8 OR @RPT_WISE = 9 /* PARTY,PARTY-ITEM */
	BEGIN
		SET @JOINSQL = "INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID"
	END
	 ELSE IF @RPT_WISE =3 OR @RPT_WISE =7 /* ITEM GROUP,ITEMGROUP-ITEM */
	BEGIN
		SET @JOINSQL = "INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE = IGM.ITEM_GRP_ID"
	END
	 IF @RPT_WISE = 4 /* LOT WISE */
	BEGIN
		SET @JOINSQL = "INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE=P2P.LOTNO"
	END
END
BEGIN

	SET NOCOUNT ON;
		IF @RPTTYPE = 0 
		BEGIN
		SET @SQL = " SELECT CONVERT(INT,P2P.LOTNO) AS LOTNO,P2P.VCHDATE,P2P.ITEM_ID,IM.ITEM_NAME AS ITEM,LM.LGR_NAME AS PARTY,
FPM.PROCESS_NAME AS FROMPROCESS,TPM.PROCESS_NAME AS TOPROCESS,IGM.ITEM_GRP_NAME AS ITEMGROUP,
P2P.DELTHAN AS THAN,P2P.DELMETER AS METER,CMP.CMP_ALIAS
FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON P2P.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON P2P.TO_LGR_ID = LM.LGR_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON P2P.FROM_PROCESS_ID = FPM.PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON P2P.TO_PROCESS_ID = TPM.PROCESS_ID
"+@JOINSQL+"
WHERE "+@REPORTSQL+" P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE IN ("+@CMP_CODE +")  
ORDER BY P2P.LOTNO,P2P.VCHDATE "
		END
		ELSE IF @RPTTYPE = 1
		BEGIN
			SET @SQL = " SELECT MAX(CONVERT(INT,P2P.LOTNO)) AS LOTNO,MAX(P2P.VCHDATE) AS VCHDATE,P2P.ITEM_ID,IM.ITEM_NAME AS ITEM,LM.LGR_NAME AS PARTY,
FPM.PROCESS_NAME AS FROMPROCESS,TPM.PROCESS_NAME AS TOPROCESS,IGM.ITEM_GRP_NAME AS ITEMGROUP,
SUM(P2P.DELTHAN) AS THAN,SUM(P2P.DELMETER) AS METER,CMP.CMP_ALIAS
FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON P2P.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON P2P.TO_LGR_ID = LM.LGR_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON P2P.FROM_PROCESS_ID = FPM.PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON P2P.TO_PROCESS_ID = TPM.PROCESS_ID
"+@JOINSQL+"
WHERE "+@REPORTSQL+" P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE IN ("+@CMP_CODE +")  
GROUP BY P2P.ITEM_ID,IM.ITEM_NAME,LM.LGR_NAME,FPM.PROCESS_NAME,TPM.PROCESS_NAME,IGM.ITEM_GRP_NAME,CMP.CMP_ALIAS "
END

END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_FTGRECDETAIL]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_FTGRECDETAIL '1,2,10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##1276',5,'##1276'
*/
CREATE PROCEDURE [dbo].[PROC_FTGRECDETAIL]
(
 @CMP_CODE NVARCHAR(100),
 @DATABASENAME NVARCHAR(100),
 @FROMDATE NVARCHAR(20),
 @TODATE NVARCHAR(20),
 @TEMPTABLE NVARCHAR(20),
 @RPT_WISE INT,
 @LotTable nvarchar(20)
)	
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @JOINSQL AS NVARCHAR(4000) SET @JOINSQL=""
DECLARE @MainGrpSql AS NVARCHAR(4000) SET @MainGrpSql=""
DECLARE @PartySql AS NVARCHAR(4000) SET @PartySql=""



BEGIN
        IF @RPT_WISE=1 /*ITEM WISE*/
			BEGIN
				SET @JOINSQL="  INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
				SET @PartySql=",'' as PartyName"
			END
        ELSE IF @RPT_WISE=2/*ITEM GRP WISE*/
			BEGIN
				SET @JOINSQL="  INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
				SET @PartySql=",'' as PartyName"
			END
        ELSE IF @RPT_WISE=3/*ITEM TYPE*/
			BEGIN
				SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
				SET @PartySql=",'' as PartyName"
			END
		ELSE IF @RPT_WISE=4/*VIEWER WISE*/
			BEGIN	
				SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=WM.WEAVER_ID"
				SET @PartySql=",'' as PartyName"
			END
		ELSE IF @RPT_WISE=5/*PARTY WISE*/
			BEGIN
				SET @JOINSQL=" INNER JOIN "+@LotTable+" LT ON FTG.LotNo=LT.Code  
                  INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON LM.Lgr_Id=Lt.Lgr_Id"
				SET @PartySql=",LM.Lgr_Name as PartyName"
			END
        ELSE IF @RPT_WISE=6/*ALL WISE */
			BEGIN
				SET @JOINSQL=""
				SET @PartySql=",'' as PartyName"
			END	
END

BEGIN 

IF @RPT_WISE=1 /*ITEM WISE*/
		SET @MainGrpSql=",IM.Item_Name as MainGrp "
ELSE IF @RPT_WISE=2 /*ITEM GRP WISE*/
		SET @MainGrpSql=",IGM.ITEM_GRP_Name as MainGrp "
ELSE IF @RPT_WISE=3 /*ITEM TYPE WISE*/
		SET @MainGrpSql=",ITM.ITEM_TYPE_NAME as MainGrp "
ELSE IF @RPT_WISE=4 /*VIEWER WISE*/
		SET @MainGrpSql=",WM.Weaver_Name as MainGrp "
ELSE IF @RPT_WISE=5 /*PARTY WISE*/
		SET @MainGrpSql=",LM.Lgr_Name as MainGrp "


END

BEGIN
	SET @SQL=" 

SELECT IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,
FTGR.LOTNO,FTGR.RECDATE,FTGR.GRAYTHAN,FTGR.GRAYMETER,FTGR.FINISHTHAN,FTGR.FINISHMETER
,FTGR.SHORTMTR,FTGR.SHORTMTR_PER,CMP.CMP_ALIAS,WM.Weaver_NAME
"+@MainGrpSql+"
"+@PartySql+"
FROM "+@DATABASENAME+"FTGRECDETAIL FTGR
INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FTGR.FTGID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=FTG.CMP_CODE
LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
LEFT JOIN  "+@DATABASENAME+" Weaver_Master WM on WM.Weaver_Id=FTG.Weaver_Id
"+@JOINSQL+"
WHERE FTG.CMP_CODE IN ("+@CMP_CODE+") AND FTGR.RECDATE BETWEEN '" +@FROMDATE +"' AND '"+@TODATE +"'
ORDER BY FTGR.LOTNO,FTGR.RECDATE
             "
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

