SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















-- =============================================
-- Author:		<Biren>
-- Create_date: <05/09/2012,11:30 AM,>
-- Report Form:	<rfrmGdwnChemclStock>
-- =============================================

/*
PROC_GODOWNCHEMICALSTOCK '0,1,2', N'Acc2012_2013.Dbo.', N'06/Sep/2012', N'##5840', 3
*/

CREATE PROCEDURE [dbo].[PROC_GODOWNCHEMICALSTOCK]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @AsOnDate as Nvarchar(20),
    @TempTable nvarchar(20),
	@Criteria int
)
as

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JoinSql AS NVARCHAR(500)
DECLARE @FieldSql AS NVARCHAR(500)
DECLARE @GroupSql AS NVARCHAR(500)
DECLARE @MasterSql AS NVARCHAR(500)


set @SQL=""
set @SQL1=""
set @JoinSql=""
set @FieldSql=""
set @GroupSql=""

SET @JoinSql=""
	BEGIN
		IF @Criteria = 1
			BEGIN
				SET @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.ITEM_ID"
			END
		ELSE IF @Criteria = 2
			BEGIN
				SET @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IGM.ITEM_GRP_ID"
			END
		ELSE IF @Criteria = 3
			BEGIN
				SET @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IGM.ITEM_GRP_ID"
			END
	END	
SET @GroupSql=""
	BEGIN
		IF @Criteria = 1 OR @Criteria = 2
			BEGIN
				SET @MasterSql=" SELECT ITEM,UNIT, "				
				SET @GroupSql=" GROUP BY ITEM,UNIT,ITEMGRP,ALIAS ORDER BY ITEM "
			END
		ELSE IF @Criteria = 3
			BEGIN
				SET @MasterSql=" SELECT MAX(ITEM) AS ITEM,MAX(UNIT) AS UNIT, "
				SET @GroupSql=" GROUP BY ITEMGRP,ALIAS ORDER BY ITEMGRP "
			END
	END	
BEGIN
	SET @SQL = "
				"+@MasterSql+"ITEMGRP,SUM(INQTY) AS INQTY, SUM(OUTQTY) AS OUTQTY,(SUM(ISNULL(INQTY,0))- SUM(ISNULL(OUTQTY,0))) AS PENDQTY,ALIAS
				FROM (
				SELECT PID.ITEM_ID,IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,IGM.ITEM_GRP_NAME AS ITEMGRP,PID.QUANTITY AS INQTY,0 AS OUTQTY,COMP.CMP_ALIAS AS ALIAS
				FROM "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID
				INNER JOIN "+@DatabaseName+"PURCHASEINVOICE PI ON PI.PurchaseInvId = PID.PurchaseInvId AND PI.CMP_CODE = PID.CMP_CODE AND PI.FLAG = PID.FLAG
				INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
				INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
				LEFT JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
				INNER JOIN "+@DatabaseName+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PID.CMP_CODE
				"+@JoinSql+"
				WHERE  PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.FLAG = 'CHP 'AND IM.ITEM_TYPE IN ('COL', 'CHL') AND PI.VCHDATE <='"+@AsOnDate+"' 
				GROUP BY PID.ITEM_ID,IM.ITEM_NAME,UM.UNIT_NAME,PID.QUANTITY,IGM.ITEM_GRP_NAME,PI.VCHDATE,COMP.CMP_ALIAS

				UNION ALL

				SELECT GID.ITEM_ID,IM.ITEM_NAME ,UM.UNIT_NAME AS UNIT,IGM.ITEM_GRP_NAME AS ITEMGRP,0 AS INQTY,GID.QTY AS OUTQTY,COMP.CMP_ALIAS AS ALIAS
				FROM "+@DatabaseName+"GODOWNISSUE_DETAIL GID
				INNER JOIN "+@DatabaseName+"GODOWNISSUE_MASTER GIM ON GIM.GODOWNISSUE_ID = GID.GODOWNISSUE_ID AND GIM.CMP_CODE = GID.CMP_CODE
				INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID = GID.ITEM_ID
				INNER JOIN "+@DatabaseName+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
				LEFT JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
				INNER JOIN "+@DatabaseName+"COMPANY_MASTER COMP ON COMP.CMP_CODE = GID.CMP_CODE
				"+@JoinSql+"
				WHERE GIM.CMP_CODE IN ("+@Cmp_Code+") AND IM.ITEM_TYPE IN ('COL', 'CHL') AND GIM.VCHDATE <='"+@AsOnDate+"' 
				)AS DETAIL "+@GroupSql+"
				"
EXEC(@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1
END




















GO

