/*
-- =============================================
-- ALTER_AUTHOR  :	<BIREN>
-- ALTER_DATE    : <21-08-2015 4:10 PM>
-- REPORT_FORM    :	<RFRMPENDINGBILLCHALLANREPORT.CS>
-- CRYSTAL_REPORT :	<PENDINGBILLCHALLANREPORT.RPT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_GODOWNISSUEREGISTER '01/APR/2015','31/MAR/2016','1',12,'ACC2015_2016.DBO.','##5488',3,1
*/
CREATE PROCEDURE [dbo].[PROC_GODOWNISSUEREGISTER]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(50),
@RPT_WISE INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE  INT,
@ISSUE_TYPE  INT
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)
DECLARE @ISSUESQL NVARCHAR(100)
DECLARE @STRORDERBY NVARCHAR(200)

SET @SQL=""
SET @SELECTED=""
SET @CONDSQL=""
SET @ISSUESQL = ""
SET @STRORDERBY = ""

BEGIN
IF @RPT_TYPE = 1
SET @CONDSQL = " AND ISNULL(GOM.INUSE,0) = 1"
IF @RPT_TYPE = 2
SET @CONDSQL = " AND ISNULL(GOM.INUSE,0) <> 1"
IF @RPT_TYPE = 3
SET @CONDSQL = ""
END

IF @ISSUE_TYPE = 1
	SET @ISSUESQL = "AND GOM.FLAG='CHP'"
ELSE IF @ISSUE_TYPE = 2
	SET @ISSUESQL = "AND GOM.FLAG='MIP'"

BEGIN

BEGIN    
IF @RPT_WISE IN (1)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.MAIN_GODOWNID=TT.CODE"
SET @STRORDERBY = " ISNULL(MGM.GODOWN_NAME,''),ISNULL(GOM.MAIN_GODOWNID,0),"
END
IF @RPT_WISE IN (2)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.SUB_GODOWNID=TT.CODE"
SET @STRORDERBY = " ISNULL(SGM.GODOWN_NAME,''),ISNULL(GOM.SUB_GODOWNID,0), "
END
IF @RPT_WISE IN (3)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IGM.ITEM_GRP_ID=TT.CODE"
SET @STRORDERBY = " ISNULL(IGM.ITEM_GRP_NAME,''),ISNULL(IGM.ITEM_GRP_ID,0), "
END
IF @RPT_WISE IN (4)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IM.ITEM_ID=TT.CODE"
SET @STRORDERBY = " ISNULL(IM.ITEM_NAME,'') , ISNULL(IM.ITEM_ID,0), "
END
IF @RPT_WISE IN (5)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IM.ITEM_ID=TT.CODE"
SET @STRORDERBY =  "  ISNULL(IM.NICK_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (6)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOD.SIZE_ID=TT.CODE"
SET @STRORDERBY = " ISNULL(SM.SIZE_NAME,''),ISNULL( GOD.SIZE_ID,0),"
END
IF @RPT_WISE IN (7)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.MAIN_GODOWNID=TT.CODE"
SET @STRORDERBY = "  ISNULL(MGM.GODOWN_NAME,''), ISNULL(GOM.MAIN_GODOWNID,0),ISNULL(IM.ITEM_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.SUB_GODOWNID=TT.CODE"
SET @STRORDERBY = " ISNULL(SGM.GODOWN_NAME,''),ISNULL(GOM.SUB_GODOWNID,0),ISNULL(IM.ITEM_NAME,''),ISNULL( IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (9)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IGM.ITEM_GRP_ID=TT.CODE"
SET @STRORDERBY = " ISNULL(IGM.ITEM_GRP_NAME,''),ISNULL(IGM.ITEM_GRP_ID,0),ISNULL(IM.ITEM_NAME,''),ISNULL( IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (10)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IM.ITEM_ID=TT.CODE"
SET @STRORDERBY = "  ISNULL(IM.ITEM_NAME,''),ISNULL( IM.ITEM_ID,0),ISNULL(SM.SIZE_NAME,''),ISNULL( GOD.SIZE_ID,0),"
END
IF @RPT_WISE IN (11)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.GODOWNINOUT_ID=TT.CODE"
SET @STRORDERBY = " ISNULL(GOM.SLIPNO,''),"
END
IF @RPT_WISE IN (12)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON GOM.GODOWNINOUT_ID=TT.CODE"
SET @STRORDERBY = " "
END


END
SET @SQL="
SELECT ISNULL(GOM.GODOWNINOUT_ID,0) AS GODOWNINOUT_ID,ISNULL(GOM.DOCNO,0) AS DOCNO,CONVERT(NVARCHAR,GOM.VCHDATE,103) AS VCHDATE,
ISNULL(GOM.SLIPNO,'') AS SLIPNO,ISNULL(GOM.INOUT_TYPE,'') AS INOUTTYPE,ISNULL(GOM.TOTALQTY,0) AS TOTALQTY,
ISNULL(GOD.QTY,0) AS QTY,ISNULL(GOD.PENDQTY,0) AS PENDQTY,ISNULL(GOD.DELIQTY,0) AS DELIQTY,ISNULL(GOD.DRUMNO,'') AS DRUMNO,
ISNULL(GOD.SRNO,0) AS SRNO,ISNULL(GOD.PACKING,0) AS PACKING,ISNULL(GOD.NOS,0) AS NOS,ISNULL(GOD.NETQTY,0) AS NETQTY,
ISNULL(GOM.FLAG,'') AS FLAG,ISNULL(IOS.Pur_Rate,0) AS RATE ,
ISNULL(GOM.MAIN_GODOWNID,0) AS MAIN_GODOWNID,ISNULL(GOM.SUB_GODOWNID,0) AS SUB_GODOWNID,ISNULL(GOM.ITEM_GRP_ID,0) AS ITEMGRPID,
ISNULL(GOD.ITEM_ID,0) AS ITEMID,ISNULL(GOD.SIZE_ID,0) AS SIZEID,
ISNULL(MGM.GODOWN_NAME,'' ) AS MAIN_GODOWN,ISNULL(SGM.GODOWN_NAME,'' ) AS SUB_GODOWN,ISNULL(IGM.ITEM_GRP_NAME,'' ) AS ITEMGRPNAME,
ISNULL(IM.ITEM_NAME,'' ) AS ITEM,ISNULL(SM.SIZE_NAME,'' ) AS SIZE,ISNULL(IM.NICK_NAME,'') AS NICKNAME,ISNULL(COMP.CMP_ALIAS,'') AS CMP_ALIAS

FROM "+@DATABASENAME+"GODOWN_INOUT_MASTER GOM
INNER JOIN "+@DATABASENAME+"GODOWN_INOUT_DETAIL GOD ON GOM.GODOWNINOUT_ID = GOD.GODOWNINOUT_ID AND GOM.CMP_CODE = GOD.CMP_CODE AND GOM.FLAG = GOD.FLAG
LEFT JOIN "+@DATABASENAME+"GODOWN_MASTER MGM ON MGM.GODOWN_ID = GOM.MAIN_GODOWNID
LEFT JOIN "+@DATABASENAME+"GODOWN_MASTER SGM ON SGM.GODOWN_ID = GOM.SUB_GODOWNID
LEFT JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = GOM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IM.ITEM_ID = IOS.ITEM_ID AND IOS.CMP_CODE = GOM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = GOD.SIZE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = GOD.CMP_CODE
"+ @SELECTED +"
WHERE GOM.CMP_CODE IN ("+@CMP_CODE+") AND GOM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@ISSUESQL+"
ORDER BY "+@STRORDERBY+"GOM.DOCNO,GOM.VCHDATE"

END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL





















GO

