/*
-- =============================================
-- Author      : <BIREN>		
-- Create_date : <25-06-2013 12:12 PM>
-- Description : THIS PROCEDURE USED FOR GODOWN PENDING REPORT
-- ReportName  : <GodownPendingReport.rpt>
-- ReportForm  : <rfrmGodownPendingReport.cs>
-- =============================================
PROC_GODOWNPENDINGREPORT 1,'ACC2010_2011.DBO.',4,'##4992'
*/
CREATE PROCEDURE [dbo].[PROC_GODOWNPENDINGREPORT]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),   
	@PROCESSID NVARCHAR(50),
	@TEMPTABLE NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @REPORTSQL AS NVARCHAR(4000)

SET @SQL = ""
SET @JOINSQL = ""
SET @REPORTSQL = ""

BEGIN	
	IF @PROCESSID = 0 
		SET @REPORTSQL = ""
	ELSE IF @PROCESSID <> 0 
		SET @REPORTSQL = " P2P.TO_PROCESS_ID = "+@PROCESSID+" AND "
END

BEGIN	
	SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2P.TO_GODOWN_ID"
END

BEGIN

	SET NOCOUNT ON;
		BEGIN
		SET @SQL = "SELECT CONVERT(INT,P2P.LOTNO) AS LOTNO,P2P.VCHDATE,IM.ITEM_NAME AS ITEM,
					FPM.PROCESS_NAME AS FROMPROCESS,GM.GODOWN_NAME AS GODOWN,
					P2P.PENDINGTHAN AS PENDINGTHAN,P2P.PENDINGMETER AS PENDINGMETER,CMP.CMP_ALIAS,IGM.ITEM_GRP_NAME AS ITEMGROUP
					FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
					INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON P2P.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
					INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON P2P.TO_PROCESS_ID = FPM.PROCESS_ID
					INNER JOIN "+@DATABASENAME+" GODOWN_MASTER GM ON GM.GODOWN_ID = P2P.TO_GODOWN_ID
				    INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
					"+@JOINSQL+"
					WHERE "+@REPORTSQL+" P2P.CMP_CODE IN ("+@CMP_CODE +") AND P2P.PENDINGTHAN > 0 
					ORDER BY P2P.LOTNO,P2P.VCHDATE "
		END
END
exec(@SQL)
PRINT @SQL




















GO

