/*
-- =============================================
-- Author      : <BIREN>		
-- Create_date : <25-06-2013 06:00 PM>
-- Description : THIS PROCEDURE USED FOR GODOWN PRODUCTION DETAIL
-- ReportName  : <GodownProductionDetail.rpt>
-- ReportForm  : <rfrmGodownProductionDetSumm.cs>
-- =============================================
PROC_GODOWNPRODUCTIONDETAIL '01/APR/2012','31/MAR/2013',1,'ACC2013_2014.DBO.',1,'##3148'
*/
CREATE PROCEDURE [dbo].[PROC_GODOWNPRODUCTIONDETAIL]
(
	@FROMDATE NVARCHAR(20),
	@TODATE	NVARCHAR(20),
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),   
	@PROCESSID NVARCHAR(50),
	@TEMPTABLE NVARCHAR(50),
	@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @REPORTSQL AS NVARCHAR(4000)

SET @SQL = ""
SET @SQL1 = ""
SET @JOINSQL = ""
SET @REPORTSQL = ""

BEGIN	
	IF @PROCESSID = 0 
		SET @REPORTSQL = ""
	ELSE IF @PROCESSID <> 0 
		SET @REPORTSQL = " P2P.FROM_PROCESS_ID = "+@PROCESSID+" AND "
END

BEGIN	
	IF @RPTTYPE = 1 
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IGM.ITEM_GRP_ID"
		END
	ELSE IF @RPTTYPE = 2 
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = GM.GODOWN_ID"
		END
END

BEGIN

	SET NOCOUNT ON;
		BEGIN
		
		SET @SQL = " SELECT  CONVERT(INT,POUT.LOTNO) AS LOTNO,POUT.VCHDATE,IM.ITEM_NAME AS ITEM,
					PM.PROCESS_NAME AS FROMPROCESS,GM.GODOWN_NAME AS GODOWN,IGM.ITEM_GRP_NAME AS ITEMGROUP,
					POUT.DELTHAN  AS PENDINGTHAN,POUT.DELMETER AS PENDINGMETER,CMP.CMP_ALIAS
					FROM "+@DATABASENAME+" PROCESSOUT POUT
					INNER JOIN  "+@DATABASENAME+" PROCESS_MASTER PM ON POUT.OUT_PROCESS_ID = PM.PROCESS_ID 
					INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON POUT.ITEM_ID = IM.ITEM_ID
					INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=POUT.CMP_CODE
					INNER JOIN "+@DATABASENAME+" GODOWN_MASTER GM ON GM.GODOWN_ID = POUT.OUT_GODOWN_ID
					INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
					"+@JOINSQL+"
					WHERE  PM.PROCESS_ID = "+@PROCESSID+" AND  POUT.CMP_CODE IN ("+@CMP_CODE +")
					AND PM.OUTSIDE <> 1  AND (POUT.DELTHAN>0 OR POUT.DELMETER>0)
					AND POUT.VCHDATE >='"+@FROMDATE+"' AND POUT.VCHDATE <='"+@TODATE+"'
					UNION ALL "

		SET @SQL1 = " SELECT  F2F.LOTNO,F2F.VCHDATE,IM.ITEM_NAME AS ITEM,
					PM.PROCESS_NAME AS FROMPROCESS,GM.GODOWN_NAME AS GODOWN,IGM.ITEM_GRP_NAME AS ITEMGROUP,
					F2F.RECTHAN AS PENDINGTHAN,F2F.RECMETER AS PENDINGMETER,CMP.CMP_ALIAS
					FROM  "+@DATABASENAME+" FINISHTOFOLDING F2F 
					INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID = F2F.PROCESS_ID  
					INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID   
					INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON F2F.LGR_ID = LM.LGR_ID   		 
					INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON F2F.CMP_CODE = CMP.CMP_CODE 		
					LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
					INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
					INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS P2P ON P2P.LOTNO = F2F.LOTNO AND P2P.GPASSNO = F2F.GPASSNO  AND F2F.PROCESS_ID = P2P.TO_PROCESS_ID
												AND F2F.CMP_CODE = P2P.CMP_CODE
					INNER JOIN "+@DATABASENAME+" GODOWN_MASTER GM ON GM.GODOWN_ID = P2P.TO_GODOWN_ID
                    "+@JOINSQL+"
					WHERE F2F.VCHDATE >='"+@FROMDATE+"' AND F2F.VCHDATE <='"+@TODATE+"' AND F2F.CMP_CODE IN ("+@CMP_CODE +")
					AND PM.PROCESS_ID = "+@PROCESSID+" ORDER BY LOTNO,VCHDATE"
		END
END
exec(@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

