/*
 Proc_GoodsInRpt '10','Acc2010_2011.dbo.',1,'01/sep/2010','30/Sep/2010',''
*/
CREATE PROCEDURE [dbo].[PROC_GOODSINRPT] 	
(
	@Cmp_Code nvarchar(50),
	@DatabaseName nvarchar(50),
	@Rpt_Type int,
	@FromDate nvarchar(20),
	@ToDate nvarchar(20),
	@TempTable nvarchar(20)
)
AS
Declare @sql as nvarchar(4000)
declare @sqlJoin as nvarchar(4000)

set @sql =""
set @sqlJoin =""

  BEGIN  
		if @Rpt_Type=1     
			Begin
				   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON GIN.Lgr_ID=TT.CODE"
			end
        ELSE if @Rpt_Type=2
			Begin
				   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON FM.FinishType_ID=TT.CODE"
			end
  END


BEGIN	
	SET NOCOUNT ON;
	

    
	

	 set @SQL="
			select GIN.* ,LM.Lgr_Name as PartyName ,FM.FinishType_NAME as FinishTypeName,CM.City_Name as City,CMP.CMP_ALIAS
			from "+ @DatabaseName+"goodsInward GIN
			INNER JOIN "+ @DatabaseName+"Ledger_Master LM ON GIN.Lgr_ID = LM.Lgr_ID
			left join "+ @DatabaseName+"city_master CM on LM.City_id = CM.City_Id
			left JOIN "+ @DatabaseName+"FinishType_Master FM ON GIN.FinishType_ID = FM.FinishType_ID
            LEFT JOIN "+ @DatabaseName+"COMPANY_Master CMP ON CMP.CMP_CODE=GIN.CMP_CODE
			" + @sqlJoin +"            
			Where GIN.vchDate >= '" + @FromDate + "' and GIN.vchDate <='" + @ToDate + "'  and GIN.Cmp_Code IN(" + @Cmp_Code +")
			Order by GIN.VchDate, GIN.LotNo
			"			             
END

exec sp_executesql @SQL 
print @SQL




















GO

