/*
  Proc_GoodsInSummaryRpt '10','Acc2010_2011.dbo.',1,'01/jan/2010','30/Sep/2010','',1
*/
CREATE PROCEDURE [dbo].[PROC_GOODSINSUMMARYRPT] 	
(
	@Cmp_Code nvarchar(50),
	@DatabaseName nvarchar(50),
	@Rpt_Type int,
	@FromDate nvarchar(20),
	@ToDate nvarchar(20),
	@TempTable nvarchar(20),
    @FinSumm int
)
AS
Declare @sql as nvarchar(4000)
declare @sqlJoin as nvarchar(4000)

DECLARE @SELSQL AS NVARCHAR(2000)
DECLARE @GRPSQL AS NVARCHAR(2000)

BEGIN
   IF @FinSumm=0 
       BEGIN
         SET @SELSQL =" GIN.VchDate as GIDate,MIN(FTM.FINISHTYPE_NAME) AS FINISHTYPE "
         SET @GRPSQL="  Group By GIN.VchDate ,CMP.CMP_ALIAS "
       END           
   ELSE
     BEGIN
         SET @SELSQL =" MIN(GIN.VchDate) as GIDate,FTM.FINISHTYPE_NAME AS FINISHTYPE "
         SET @GRPSQL=" Group By FTM.FINISHTYPE_NAME,CMP.CMP_ALIAS "
       END    
      
END

set @sqlJoin =""
begin
	if @Rpt_Type=1     
	     Begin
		   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON GIN.Lgr_ID=TT.CODE"
           SET @SELSQL= @SELSQL+",LM.LGR_NAME AS MAINGROUP"
           SET @GRPSQL= @GRPSQL +", LM.LGR_NAME"
	    end
  else if @Rpt_Type=2     
	     Begin
		   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON GIN.FINISHTYPE_ID=TT.CODE"
           SET @SELSQL= @SELSQL+",FTM.FINISHTYPE_NAME AS MAINGROUP"
           SET @GRPSQL= @GRPSQL +", FTM.FINISHTYPE_NAME"
	    end
  else if @Rpt_Type=3
	     Begin		   
           SET @SELSQL= @SELSQL+",'' AS MAINGROUP"           
	    end
end

BEGIN	
	SET NOCOUNT ON;


	 set @SQL="
			select "+@SELSQL+",SUM(isnull(GIN.Than,0)) as Than,SUM(isnull(GIN.TP,0)) as TP,SUM(isnull(GIN.TotalThan,0)) as TotalThan
            ,CMP.CMP_ALIAS
			from  "+ @DatabaseName+"goodsInward GIN
			INNER JOIN  "+ @DatabaseName+"Ledger_Master LM ON GIN.Lgr_ID = LM.Lgr_ID			
            INNER JOIN "+ @DatabaseName+"FINISHTYPE_MASTER FTM ON FTM.FINISHTYPE_ID=GIN.FINISHTYPE_ID
            LEFT JOIN "+ @DatabaseName+"COMPANY_Master CMP ON CMP.CMP_CODE=GIN.CMP_CODE
			" + @sqlJoin +"            
			Where GIN.vchDate >= '" + @FromDate + "' and GIN.vchDate <='" + @ToDate + "'  and GIN.Cmp_Code IN (" + @Cmp_Code +")				
			" +@GRPSQL
END

exec sp_executesql @SQL 
print @SQL




















GO

