/*
-- =============================================
-- ALTER_AUTHOR  : SHUBHAM RAVAL
-- ALTER_DATE    : 08/06/2016 11:41 AM
-- REPORT_FORM	  :	
-- CRYSTAL_REPORT :	GRAYOUTWARDHALF_PRINT.rpt
-- =============================================
PROC_GRAY_OUTGATEPASS_PRINTOUT 'ACC2015_2016.DBO.',1,10,'1',1,''
*/
CREATE PROCEDURE [dbo].[PROC_GRAY_OUTGATEPASS_PRINTOUT]
(
@DATABASENAME AS NVARCHAR(100),
@FROMNO AS NVARCHAR(100),
@TONO AS NVARCHAR(100),
@RPT_TYPE AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(10),
@TEMPTABLE NVARCHAR(20)
)
AS
BEGIN

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
SET @STRSQL=""
SET @JOINSQL=""
SET @FIELDSQL=""

IF @TEMPTABLE <> "" 
begin
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GPM.CMP_CODE"
	SET @FIELDSQL = "TT.TYPE"
end	
ELSE
begin
	SET @FIELDSQL = "'' AS TYPE"
end


SET @STRSQL="SELECT GPM.OUTGATEPASS_ID,GPM.DOCNO,CONVERT(NVARCHAR,GPM.VCHDATE,103) AS VCHDATE,
ISNULL(GPM.LGR_ID,0) AS PARTY_ID,ISNULL(GPM.VEHICLENO,'') AS VEHICLENO,GPM.THANTOTAL,GPM.METERTOTAL,
ISNULL(GPM.FLAG,'') AS FLAG,ISNULL(LM.LGR_NAME,'') AS PARTY,

ISNULL(GPD.SRNO,0) AS SR_NO,ISNULL(GPD.ITEM_ID,0) AS ITEM_ID,
ISNULL(GPD.THAN,0) AS THAN,ISNULL(GPD.METER,0) AS METER,
ISNULL(GPD.REMARK,'') AS REMARKS,
ISNULL(GPD.LOT_ID,0) AS GRAYMARKA_ID,ISNULL(IM.ITEM_NAME,0) AS ITEM,
ISNULL(LOM.Lot_Name,0) AS GRAYMARKA,"+@FIELDSQL+"

FROM "+@DATABASENAME+"GRAY_OUTGATEPASS_MASTER GPM 
INNER JOIN "+@DATABASENAME+"GRAY_OUTGATEPASS_DETAIL GPD ON GPM.OUTGATEPASS_ID = GPD.OUTGATEPASS_ID AND GPM.CMP_CODE = GPD.CMP_CODE AND GPM.FLAG = GPD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GPM.LGR_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GPD.ITEM_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.Lot_Id = GPD.LOT_ID

"+@JOINSQL+"
WHERE GPM.CMP_CODE="+@CMP_CODE+" AND GPM.DOCNO >= "+ @FROMNO +" AND GPM.DOCNO <="+@TONO+" 
ORDER BY GPM.OUTGATEPASS_ID,TYPE,GPD.SRNO
"
	
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL























GO

