/*
PROC_GRAY_PENDING_REPORT 10,'ACC2010_2011.DBO.'
*/

CREATE PROCEDURE [dbo].[PROC_GRAY_PENDING_REPORT]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""

BEGIN	
	SET NOCOUNT ON;
	SET @STRSQL="
SELECT BillNo,VchDate AS BILL_DATE,PID.Pieces AS THAN,PID.Quantity AS MTR,LM.LGR_NAME,PIV.LOTNO,IM.ITEM_NAME,CM.CITY_NAME
FROM "+@DATABASENAME+" PURCHASEINVOICE PIV
INNER JOIN "+@DATABASENAME+" PurchaseInvoice_Detail PID on PIV.PurchaseInvId=PID.PurchaseInvId and PID.FLAG=PIV.FLAG
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON PIV.LGR_ID=LM.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID=IM.ITEM_ID
INNER JOIN 
(
	SELECT LOTNO,SUM(PUR_THAN)-SUM(PROC_THAN) AS DIFF_THAN,SUM(PUR_MTR)-SUM(PROC_MTR) AS DIFF_MTR,CMP_CODE
	FROM (
	select PIV.LOTNO,SUM(Pieces) AS PUR_THAN,SUM(Quantity) AS PUR_MTR,0 AS PROC_THAN,0 AS PROC_MTR,PIV.CMP_CODE
	from "+@DATABASENAME+" PURCHASEINVOICE PIV
	inner join "+@DATABASENAME+" PurchaseInvoice_Detail PID on PIV.PurchaseInvId=PID.PurchaseInvId and PID.FLAG=PIV.FLAG
	WHERE ISNULL(PIV.LOTNO,0) >0 AND PIV.CMP_CODE IN ("+@CMP_CODE+")
	GROUP BY PIV.LOTNO,PIV.CMP_CODE
	UNION ALL
	SELECT LOTNO,0 AS PUR_THAN,0 AS PUR_MTR,SUM(DELThan) AS PROC_THAN,SUM(DELMeter) AS PROC_MTR,CMP_CODE
	FROM "+@DATABASENAME+" Process2Process 
	WHERE ISNULL(LOTNO,0) >0
	AND From_Process_Id=1 AND CMP_CODE IN ("+@CMP_CODE+")
	GROUP BY LOTNO,CMP_CODE
	UNION ALL
	SELECT LOTNO,0 AS PUR_THAN,0 AS PUR_MTR,SUM(Pcs) AS PROC_THAN,SUM(GrayMtrs) AS PROC_MTR,CMP_CODE
	FROM "+@DATABASENAME+" GRAYSTOCKOUT GRS
	WHERE ISNULL(LOTNO,0) >0 AND CMP_CODE IN ("+@CMP_CODE+")
	GROUP BY LOTNO,CMP_CODE
	) AS A
	GROUP BY LOTNO,CMP_CODE
	HAVING SUM(PUR_THAN)-SUM(PROC_THAN)>0
) AS DETAIL ON DETAIL.LOTNO=PIV.LOTNO AND PIV.CMP_CODE=DETAIL.CMP_CODE

WHERE PIV.CMP_CODE IN ("+@CMP_CODE+") AND ISNULL(PIV.LOTNO,0)>0 AND IM.ITEM_TYPE='RM'
UNION ALL
SELECT DOCNO AS BILLNO,VCHDATE AS BILL_DATE,PIECES AS THAN,QUANTITY AS MTR,LM.LGR_NAME,STM.LOTNO,IM.ITEM_NAME,CM.CITY_NAME
FROM "+@DATABASENAME+" GREYSTOCKTRANS_IN_MASTER STM
INNER JOIN "+@DATABASENAME+" GreyStockTrans_IN_Detail STD ON STM.GreyStockTrans_Id=STD.GreyStockTrans_Id
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON STM.LGR_ID=LM.LGR_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON STD.ITEM_ID=IM.ITEM_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
WHERE STM.CMP_CODE IN ("+@CMP_CODE+") AND ISNULL(STM.LOTNO,0)>0 and IM.Item_Type='RM'
ORDER BY VchDate,BillNo
"
    
END
	
PRINT @STRSQL
EXEC SP_EXECUTESQL @STRSQL




















GO

