CREATE PROCEDURE [dbo].[PROC_GRAY_PURCHASE_LOTNO]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""

BEGIN	
	SET NOCOUNT ON;
SET @STRSQL="
SELECT PIM.BillNo,PIM.VchDate,PIM.LotNo,PIM.LrNo,LM.Lgr_Name as Party,IM.Item_Name as ITEM,
PID.Pieces as Than,PID.Quantity as MTR
FROM "+@DATABASENAME+" PURCHASEINVOICE PIM
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID on PIM.PurchaseInvId=PID.PurchaseInvId and PIM.Flag=PID.Flag
inner join "+@DATABASENAME+" Ledger_Master LM ON PIM.LGR_Id=LM.Lgr_Id
INNER JOIN "+@DATABASENAME+" Item_Master IM ON IM.Item_Id= PID.Item_Id
where PIM.Flag='P' and IM.Item_type='RM'
and PIM.CMp_COde="+@CMP_CODE+" AND
PIM.LotNo not in (select LotNo from "+@DATABASENAME+" LotAllocation LA
		inner join "+@DATABASENAME+" Item_Master IM on LA.Item_Id=IM.Item_Id
		where Cmp_Code="+@CMP_CODE+"  and IM.Item_Type='RM')
union all
select DocNo as BillNo,VchDate,GRM.LotNo,GRM.LrNo,LM.Lgr_Name as PARTY,IM.ITEM_NAME as ITEM,sum(PIECES) as Than,
sum(QUANTITY) as MTR
from "+@DATABASENAME+" GREYSTOCKTRANS_IN_MASTER GRM
inner join "+@DATABASENAME+" GreyStockTrans_IN_Detail GRD ON GRM.GreyStockTrans_Id=GRD.GreyStockTrans_Id
inner join "+@DATABASENAME+" Item_Master IM On GRD.Item_Id=IM.Item_Id
inner join "+@DATABASENAME+" Ledger_Master LM on LM.Lgr_Id=GRM.Lgr_Id
WHERE IM.Item_type='RM'
and GRM.CMp_COde="+@CMP_CODE+"  AND
GRM.LotNo not in (
		select LotNo from "+@DATABASENAME+" LotAllocation LA
		inner join "+@DATABASENAME+" Item_Master IM on LA.Item_Id=IM.Item_Id
		where Cmp_Code="+@CMP_CODE+"  and IM.Item_Type='RM')
group by GRM.DocNo,GRM.VchDate,GRM.LotNo,GRM.LrNo,LM.Lgr_Name,IM.ITEM_NAME 
"
    
END
PRINT @STRSQL
EXEC SP_EXECUTESQL @STRSQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GRAY_SALESREG_DAILY_MONTHLY]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*    
PROC_GRAY_SALESREG_DAILY_MONTHLY '2','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011',4457,11,2
*/
CREATE PROCEDURE [dbo].[PROC_GRAY_SALESREG_DAILY_MONTHLY]
(
   @Cmp_Code NVARCHAR(50),
   @DatabaseName NVARCHAR(100),
   @FromDate NVARCHAR(20),
   @ToDate NVARCHAR(20),
   @HEADID NVARCHAR(20),
   @RPT_WISE INT,
   @CONVERSION INT    
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
SET @SQL=""
SET @QUANTITYSQL=""


BEGIN 
   
  IF @RPT_WISE=5
   BEGIN
   SET @QUANTITYSQL=" SUM(SID.SAL_INV_QTY )  AS QUANTITY "   
       IF @CONVERSION=1           
           SET @QUANTITYSQL="
                    SUM((CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
                     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) AS QUANTITY "
    END

 IF @RPT_WISE=6
   BEGIN
   SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "   
       IF @CONVERSION=1           
           SET @QUANTITYSQL="
                    (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
                     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "
    END

END


BEGIN
	SET NOCOUNT ON;    

       IF @RPT_WISE=5
          BEGIN  
              SET @SQL="SELECT 'JANUARY' AS MONTHNAME,SI.SAL_INV_VDATE AS VDATE,
                       "+@QUANTITYSQL+",
                       SUM((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL)) AS NETTOTAL,0 AS ORD     
                       ,MIN(CMP.CMP_ALIAS) AS CMP_ALIAS
                       FROM "+@DATABASENAME+"SALES_INVOICE SI
                       INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
                       INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
                       INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
                       LEFT JOIN " + @DatabaseName + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
                       WHERE SI.SAL_ACCID="+@HEADID+" AND SI.FLag='GS' AND SI.Cmp_Code IN ("+@CMP_CODE+") and  SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
                       GROUP BY SI.SAL_INV_VDATE
                       ORDER BY SI.SAL_INV_VDATE
                    "
          END
     ELSE IF @RPT_WISE=6
             SET @SQL="SELECT MONTHNAME,getdate()  AS VDATE,SUM(QUANTITY)AS QUANTITY,SUM(NETTOTAL) AS NETTOTAL,ORD,MIN(CMP_ALIAS) AS CMP_ALIAS  FROM (
                       SELECT UPPER(DATENAME(MM,SI.SAL_INV_VDATE)) AS MONTHNAME,
                       "+@QUANTITYSQL+",
                       (SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS NETTOTAL,
                       (CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS     ORD
                       ,CMP.CMP_ALIAS
                       FROM "+@DATABASENAME+"SALES_INVOICE SI
                       INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
                       INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
                       INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
                       LEFT JOIN " + @DatabaseName + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
                       WHERE SI.SAL_ACCID="+@HEADID+" AND SI.FLag='GS' AND SI.Cmp_Code IN ("+@CMP_CODE+") and  SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
                       
                       ) AS DETAIL
                      GROUP BY MONTHNAME,ORD
                      ORDER BY ORD
                      "
	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GRAYDETAIL]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
