/*
PROC_GRAYDETAIL '1','ACC2013_2014.DBO.','##2980',1,2,''
*/
CREATE PROCEDURE [dbo].[PROC_GRAYDETAIL]
( 
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @TEMPTABLE AS NVARCHAR(50),
  @RPT_WISE AS INT,
  @RPT_TYPE AS INT,
  @ASONDATE AS NVARCHAR(50)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""
SET @CONDSQL=""

    BEGIN 
        IF @RPT_WISE=1
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
        ELSE IF @RPT_WISE=2
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID "
        ELSE IF @RPT_WISE=3
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
        ELSE IF @RPT_WISE=4
              SET @JOINSQL=""        
    END
   
    BEGIN 
         IF @RPT_TYPE=1
            SET @CONDSQL=" HAVING (SUM(PURCHASEMTRS)-SUM(PROCESSMTRS))<>0 OR (SUM(PURCHASETHAN)-SUM(PROCESSTHAN))<>0"                  
    END

BEGIN
     SET @SQL="                
				SELECT DETAIL.BILLNO,DATE,PARTY,PARTYCITY,DETAIL.LOTNO,ITEM_NAME,ITEMGROUP,ITEMTYPE,SUM(PURCHASETHAN)AS PURCHASETHAN,SUM(PURCHASEMTRS)AS PURCHASEMTRS,SUM(PROCESSTHAN)AS PROCESSTHAN,SUM(PROCESSMTRS) AS PROCESSMTRS,
                SUM(PURCHASETHAN)-SUM(PROCESSTHAN) AS DIFFTHAN,SUM(PURCHASEMTRS)-SUM(PROCESSMTRS) AS DIFFMTRS,CMP_ALIAS
				FROM(
				SELECT PI.BILLNO,PI.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY
				,PI.LOTNO,
				IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
				,PID.Pieces AS PURCHASETHAN,PID.Quantity AS PURCHASEMTRS,0 AS PROCESSTHAN,0 AS PROCESSMTRS,
				CMP.CMP_ALIAS
				--FROM "+@DATABASENAME+"LOTALLOCATION LA
				FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
				LEFT JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG AND PI.FLAG='P'
				LEFT JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID AND IM.ITEM_TYPE='RM'
				LEFT JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
                LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID                
                "+@JOINSQL+"
				WHERE PI.CMP_CODE IN("+@CMP_CODE +") AND PI.LOTNO <> 0  AND PI.VCHDATE <= '"+@ASONDATE+"'
                UNION "
SET @SQL1="                
               
				SELECT PI.BILLNO,PI.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,P2P.LOTNO,IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
				,0 AS PURCHASETHAN,0 AS PURCHASEMTRS,P2P.DELTHAN AS PROCESSTHAN,P2P.DELMETER AS PROCESSMTRS,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
				INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE                
                LEFT JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.CMP_CODE=P2P.CMP_CODE AND PI.LOTNO=P2P.LOTNO 
                LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                "+@JOINSQL+"
				WHERE P2P.FROM_PROCESS_ID=1 AND P2P.CMP_CODE IN("+@CMP_CODE +")
				UNION "
SET @SQL2=" 	SELECT PI.BILLNO,PI.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,GS.LOTNO,IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
				,0 AS PURCHASETHAN,0 AS PURCHASEMTRS,GS.PCS AS PROCESSTHAN,GS.GRAYMTRS AS PROCESSMTRS,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"GRAYSTOCKOUT GS
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID
				INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=GS.CMP_CODE
                LEFT JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.CMP_CODE=GS.CMP_CODE AND PI.LOTNO=GS.LOTNO 
                LEFT  JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                "+@JOINSQL+"
                WHERE GS.CMP_CODE IN("+@CMP_CODE +") 
				) AS DETAIL  
				INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON DETAIL.LOTNO = PI.LOTNO
				LEFT JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG AND PI.FLAG='P'
				GROUP BY DETAIL.BILLNO,DATE,PARTY,PARTYCITY,DETAIL.LOTNO,ITEM_NAME,ITEMGROUP,ITEMTYPE,CMP_ALIAS
               "+@CONDSQL+"


               ORDER BY LOTNO
              "
    
END

EXEC  (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

