/*
 PROC_GRAYDISPATCH 1,'ACC2012_2013.DBO.','01/APR/2012','09/AUG/2012',0,##3312
	
	AUTHOR       :- HIREN DOSHI
	ALTERD_DATE :- 07/08/2012
	REPORT NAME  :- GRAYDISPATCH.RPT
	THIS PROCE USED FOR YARN GRAY DISPATCH REPORT
*/
CREATE PROCEDURE [dbo].[PROC_GRAYDISPATCH]
(
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(200),
	@FROMDATE AS NVARCHAR(50),
	@TODATE   AS NVARCHAR(50),
	@RPT_WISE AS INT,
	@TEMPTABLE	AS NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @ORDERBY AS NVARCHAR(100)
DECLARE @JOINSQL AS NVARCHAR(100)

SET @SQL = ""
SET @JOINSQL = ""

BEGIN
		IF @RPT_WISE IN (0,5) /* PARTY WISE,PARTY - ITEM WISE */
			BEGIN
				SET @JOINSQL = " INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = LM.LGR_ID"
				SET @ORDERBY = " ORDER BY LM.LGR_NAME,GM.VCHDATE,GM.DOCNO "
			END
		ELSE IF @RPT_WISE IN (1,10) /* GODOWN , GODOWN - ITEM WISE */
			BEGIN
				SET @JOINSQL = " INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = GM.GODOWN_ID"
				SET @ORDERBY = " ORDER BY GDM.GODOWN_NAME,GM.VCHDATE,GM.DOCNO "
			END
		ELSE IF @RPT_WISE IN (2,6) /* TRANSPORT , TRANSPORT - ITEM WISE */
			BEGIN
				SET @JOINSQL = " INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = TM.TRANSPORT_ID"
				SET @ORDERBY = " ORDER BY TM.TRANSPORT_NAME,GM.VCHDATE,GM.DOCNO "
			END
		ELSE IF @RPT_WISE IN (3,4) /* ITEM,ITEM - PARTY WISE */
			BEGIN
				SET @JOINSQL = " INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = IM.ITEM_ID "
				SET @ORDERBY = " ORDER BY IM.ITEM_NAME,GM.VCHDATE,GM.DOCNO "
			END
		ELSE IF @RPT_WISE IN (9) /* GRADIATION */
			BEGIN
				SET @JOINSQL = " INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = GD.GRADIATION "
				SET @ORDERBY = " ORDER BY GD.GRADIATION,GM.VCHDATE,GM.DOCNO "
			END
		END
BEGIN
	SET NOCOUNT ON;

	SET @SQL = " SELECT GM.DOCNO AS BILLNO,GM.VCHDATE AS DATE,GDM.GODOWN_NAME AS FROMGODOWN,LM.LGR_NAME AS PARTY,
				 PCM.CITY_NAME AS PARTYCITY,GM.LRNO,GD.CHALLANNO,IM.ITEM_NAME AS ITEM,GD.THAN,GD.METERS,GD.AVG_MTR,
				 GD.GRADIATION,GM.GADINO,TM.TRANSPORT_NAME AS TRANSPORT,GM.FREIGHT_BILLNO AS FREIGHTBILLNO,
				 GM.MPL_BILLNO AS MPLBILLNO,CMP.CMP_ALIAS

				 FROM "+@DATABASENAME+" GRAYDISPATCH_MASTER GM
				 INNER JOIN "+@DATABASENAME+" GRAYDISPATCH_DETAIL GD ON GM.GDISPATCH_ID = GD.GDISPATCH_ID 
																		   AND GM.CMP_CODE = GD.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" GODOWN_MASTER GDM ON GM.GODOWN_ID = GDM.GODOWN_ID
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON GM.LGR_ID = LM.LGR_ID
				 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON GM.TRANSPORT_ID = TM.TRANSPORT_ID
				 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON GD.ITEM_ID = IM.ITEM_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON GM.CMP_CODE = CMP.CMP_CODE
				 " + @JOINSQL + " 

				 WHERE GM.VCHDATE BETWEEN  '" + @FROMDATE+ "' AND  '" +@TODATE+ "'
				 AND GM.CMP_CODE IN (" + @CMP_CODE + ")

				 " + @ORDERBY

EXEC SP_EXECUTESQL @SQL
	PRINT @SQL

END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GRAYDISPATCH_DAILY_MONTHLY]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















-- =============================================
-- AUTHOR:		HIREN DOSHI
-- ALTER_DATE: 07/08/2012
-- DESCRIPTION:	THIS PROCEDURE USED FOR YARN GRAY DISPATCH REPORT SHOW DAILY AND MONTHLY 
--				REPORT CRITERIA
-- REPORT NAME : GRAYDISPATCH_DAILY_MONTHLY
-- =============================================
/*
	PROC_GRAYDISPATCH_DAILY_MONTHLY 1,'ACC2012_2013.DBO.' ,'01/APR/2012','07/AUG/2012',7
*/

CREATE PROCEDURE [dbo].[PROC_GRAYDISPATCH_DAILY_MONTHLY]
(
	@CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = ""
BEGIN
	SET NOCOUNT ON;
		IF @RPT_WISE = 7 /* DAILY */
		BEGIN
			
			SET @SQL = " SELECT MAX(MONTHNAME) AS MONTHNAME,VCHDATE,GADINO AS GADI,LRNO AS LR,GODOWN_NAME AS GODOWN,
						 ITEM_NAME,
						 SUM(THAN) AS THAN,SUM(METERS) AS METERS,
						 SUM(AVG_MTR) AS AVG_MTR,CMP_ALIAS  FROM (
						 SELECT 'JANUARY' AS MONTHNAME, GM.VCHDATE ,GM.GADINO,GM.LRNO,PGM.GODOWN_NAME,IM.ITEM_NAME,
						 GD.THAN ,GD.METERS , 
						 (GD.METERS/GD.THAN) AS AVG_MTR ,CMP.CMP_ALIAS
						 FROM "+@DATABASENAME+" GRAYDISPATCH_MASTER GM
						 INNER JOIN "+@DATABASENAME+" GRAYDISPATCH_DETAIL GD ON GM.GDISPATCH_ID = GD.GDISPATCH_ID 
																  AND GM.CMP_CODE = GD.CMP_CODE 
						 INNER JOIN "+@DATABASENAME+" GODOWN_MASTER PGM ON GM.GODOWN_ID = PGM.GODOWN_ID
						 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON GD.ITEM_ID = IM.ITEM_ID
						 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON GM.CMP_CODE = CMP.CMP_CODE 
						 WHERE GM.CMP_CODE IN ("+@CMP_CODE+ ") 
						 AND GM.VCHDATE BETWEEN '"+@FROMDATE + "' AND '" +@TODATE+ "'
						 ) AS DETAIL
						
						GROUP BY MONTHNAME,VCHDATE,GADINO,LRNO,GODOWN_NAME,ITEM_NAME,CMP_ALIAS  
						ORDER BY VCHDATE "

		END
		
		IF @RPT_WISE = 8 /*  MONTHLY  */ 
		BEGIN
			
			SET @SQL = " SELECT MONTHNAME,GETDATE() AS VCHDATE,
						 MAX(GADINO) AS GADI,MAX(LRNO) AS LR,MAX(GODOWN_NAME) AS GODOWN,ITEM_NAME,
						 SUM(THAN) AS THAN,SUM(METERS) AS METERS,
						 SUM(AVG_MTR) AS AVG_MTR ,CMP_ALIAS FROM (
						 SELECT UPPER(DATENAME(MM,GM.VCHDATE)) AS MONTHNAME, NULL AS VCHDATE ,
						 GM.GADINO AS GADINO, GM.LRNO AS LRNO,PGM.GODOWN_NAME AS GODOWN_NAME,IM.ITEM_NAME,
						 GD.THAN ,GD.METERS , (GD.METERS/GD.THAN) AS AVG_MTR,CMP.CMP_ALIAS
						 
						 FROM "+@DATABASENAME+" GRAYDISPATCH_MASTER GM
						 INNER JOIN "+@DATABASENAME+" GRAYDISPATCH_DETAIL GD ON GM.GDISPATCH_ID = GD.GDISPATCH_ID 
																  AND GM.CMP_CODE = GD.CMP_CODE
						 INNER JOIN "+@DATABASENAME+" GODOWN_MASTER PGM ON GM.GODOWN_ID = PGM.GODOWN_ID
						 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON GD.ITEM_ID = IM.ITEM_ID
						 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON GM.CMP_CODE = CMP.CMP_CODE 
						 WHERE GM.CMP_CODE IN ("+@CMP_CODE+ ") 
						 AND GM.VCHDATE BETWEEN '"+@FROMDATE + "' AND '" +@TODATE+ "'
						 ) AS DETAIL
						GROUP BY MONTHNAME,ITEM_NAME,CMP_ALIAS "
		END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

