/*
-- =============================================
-- AUTHOR:		deepal patel
-- ALTER_DATE: 18-03-2017
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESS PENDING REGISTER BUNCH NO WISE
-- REPORTNAME : PROCESSPENDING_BUNCHREG.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
	PROC_GRAYRECEIPT 3,'ACC2016_2017.DBO.',2,'01/APR/2016','31/MARCH/2017','',2


*/
CREATE PROCEDURE [dbo].[PROC_GRAYRECEIPT]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),	
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(GD.Pending_Bales,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(GD.Pending_Bales,0) > 0 "
END



BEGIN
IF @RPT_WISE = 1 /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = GD.TRANSPORT_ID "
END
ELSE IF @RPT_WISE = 2/*PARTY NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = GD.CITY_ID "
END


ELSE IF @RPT_WISE =3 /*BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = GM.GrayReceipt_Id "
END









END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = "

SELECT GD.PURCHASEINVID,SR_NO,GD.LRNO,BALENO,BALES,REMARKS,RECEIVE_BALES,GD.CITY_ID, 
CONVERT(NVARCHAR,LRDATE,103)LRDATE,GD.MANUAL_RECEIPT_NO,PIECES,LOT_ID,ITEM_ID,ENTRYTYPE,GD.CMP_CODE,LOTNO, 
GM.Doc_No,GM.DATE,GM.CHALLAN_DATE,GM.Challan_No,cm.City_Name as STATION_NAME,TM.Transport_Name,GRAY_CHALLAN_DATE,GRAY_CHALLAN_NO,GRAY_CHALLAN_LGR_ID,GREY_DELIVERY_CHALLAN_ID
FROM  "+@DATABASENAME+"GRAYRECEIPT_DETAIL GD
INNER JOIN "+@DATABASENAME+"GRAYRECEIPT_MASTER GM ON GM.CMP_CODE = GD.CMP_CODE and GM.GrayReceipt_Id = GD.GrayReceipt_Id AND GM.FLAG = GD.FLAG     
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE = GD.CMP_CODE
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.Transport_Id=GD.Transport_Id
INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=GD.CITY_ID

"+@SQLJOIN+" 
WHERE  GD.FLAG IN ('GR','P')  AND  GD.CMP_CODE IN ("+@CMP_CODE+") AND GM.DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@STRCOND+"  


 order by  GM.GrayReceipt_Id"

END

EXEC (@STRSQL+@STRSQL1)

PRINT @STRSQL
PRINT @STRSQL1






















GO

