/*
PROC_GRAYRECEIPT_PRINT '1','ACC2019_2020.dbo.',1,20
*/
CREATE PROCEDURE [dbo].[PROC_GRAYRECEIPT_PRINT]
(
     @CMP_CODE AS NVARCHAR(100),
     @DATABASENAME AS NVARCHAR(100),
     @FROMDOCNO AS NVARCHAR(100),
     @TODOCNO AS NVARCHAR(100)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL="" 

BEGIN
	SET NOCOUNT ON;    
SELECT @SQL="

				SELECT GRM.YEARFLAG,GRM.GrayReceipt_Id , GRM.Doc_No,GRM.Date,GRM.Vehicle_No ,
				GRM.Driver_Id,GRM.Transport_Id,GRM.Challan_No,GRM.Challan_Date,GRM.MANUAL_RECEIPT_NO,
				GRM.LRTOTALBALES,GRM.LRRECTOTALBALES,GRD.LrNo,GRD.BaleNo,GRD.BALES,GRD.RECEIVE_BALES,GRD.REMARKS,TM.TRANSPORT_NAME,
				DRM.DRIVER_NAME,UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.GSTINNO AS CGSTINNO,ISNULL(CMP.CMP_STATECODE,'') AS CMP_STATE
				FROM "+ @DATABASENAME+ "GrayReceipt_Master GRM
				INNER JOIN "+ @DATABASENAME+ "GrayReceipt_detail GRD ON GRM.GrayReceipt_Id = GRD.GrayReceipt_Id AND GRM.CMP_CODE = GRD.CMP_CODE
				INNER JOIN "+ @DATABASENAME+ "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GRM.TRANSPORT_ID
				INNER JOIN "+ @DATABASENAME+ "DRIVER_MASTER DRM ON DRM.DRIVER_ID = GRM.DRIVER_ID
				INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON GRM.CMP_CODE= CMP.CMP_CODE 
				WHERE GRM.Doc_No BETWEEN "+ @FROMDOCNO +" AND "+ @TODOCNO +" AND  GRM.CMP_CODE = "+ @CMP_CODE + " AND GRM.YEARFLAG = 'C' AND GRM.FLAG = 'GR'
				ORDER BY GRM.Doc_No
               "
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL


























































































































GO

/****** Object:  StoredProcedure [dbo].[PROC_GRAYSALES_AVGRATE_SUMM]    Script Date: 03/30/2023 12:08:11 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_GRAYSALES_AVGRATE_SUMM '2','ACC2010_2011.dbo.','01/apr/2010','31/Mar/2011',##2128,1,1
*/
CREATE PROCEDURE [dbo].[PROC_GRAYSALES_AVGRATE_SUMM]
(
	@CMP_CODE nvarchar(50),
    @DATABASENAME NVARCHAR(50),        
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
    @RPT_WISE INT,
    @RPT_TYPE INT    
)
AS

DECLARE @SQL NVARCHAR(4000) set @SQL=""
DECLARE @JOINSQL NVARCHAR(1000) Set @JOINSQL=""
DECLARE @TYPESQL NVARCHAR(1000) SET @TYPESQL=""
DECLARE @FIELDSQL NVARCHAR(1000) Set @FIELDSQL=""
DECLARE @SELSQL AS NVARCHAR(2000) SET @SELSQL=""
DECLARE @GROUPSQL AS NVARCHAR(2000) SET @GROUPSQL=""

BEGIN
	IF @RPT_WISE=1
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=IM.ITEM_ID"               
               SET @GROUPSQL=" GROUP BY PartyName,ITEM_NAME,PARTYCITY"
            END
   ELSE IF @RPT_WISE=2
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=IGM.ITEM_GRP_ID"               
               SET @GROUPSQL=" GROUP BY PartyName,ITEMGROUP,PARTYCITY"
            END
  ELSE IF @RPT_WISE=3
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=ITM.ITEM_TYPE_ID"               
               SET @GROUPSQL=" GROUP BY PartyName,ITEMTYPE,PARTYCITY"
            END
	ELSE IF @RPT_WISE=4
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=LM.Lgr_Id"               
               SET @GROUPSQL=" GROUP BY ITEM_NAME ORDER BY ITEM_NAME"
            END
	ELSE IF @RPT_WISE=5
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=WM.WEAVER_ID"               
               SET @GROUPSQL=" GROUP BY WEAVER_NAME ORDER BY WEAVER_NAME"
            END
END

BEGIN
	IF @RPT_TYPE=1	
       BEGIN
	      SET @FIELDSQL="  SOD.PendingQty "
          SET @TYPESQL=" AND SOD.PendingQty >0"
       END 
	ELSE IF @RPT_TYPE=2
       BEGIN
	    SET @FIELDSQL=" SOD.Quantity" 
        SET @TYPESQL=" AND SOD.Quantity>0"
       END
END


BEGIN
	
	SET NOCOUNT ON;
SET @SQL="
SELECT  MAX(PartyName) as PartyName,max(ITEM_NAME) as ITEM_NAME,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,
SUM(PENDINGQTY) AS PENDINGQTY,CASE WHEN SUM(PENDINGQTY)>0 THEN(SUM(AMOUNT)/SUM(PENDINGQTY)) ELSE 0 END  AS RATE
,maX(WEAVER_NAME) as WEAVER_NAME,MAX(PARTYCITY) AS PARTYCITY
FROM (   
SELECT LM.Lgr_Name AS PartyName,IM.ITEM_NAME ,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,  
"+@FIELDSQL+"  AS PENDINGQTY,(  "+@FIELDSQL+" *SOD.RATE) AS AMOUNT,WM.WEAVER_NAME as WEAVER_NAME,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+" Sales_Order SO
INNER JOIN "+@DATABASENAME+" Sales_Order_Detail SOD ON SO.Sal_Order_Id=SOD.Sal_Order_Id AND SO.FLAG=SOD.FLAG
LEFT JOIN  "+@DATABASENAME+" Ledger_Master LM ON SO.Lgr_Id=LM.Lgr_Id
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+" WEAVER_MASTER WM ON WM.WEAVER_ID=SOD.WEAVER_ID                   
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JOINSQL+"
WHERE SO.CMP_CODE IN ("+@CMP_CODE+") AND SO.vch_Date BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND SO.FLAG='GS'
"+@TYPESQL+"
)AS DETAIL
"+@GROUPSQL+"  
"
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[Proc_GraySalesBillDueReport]    Script Date: 03/30/2023 12:08:11 ******/
