/*
PROC_GraySalesOrderRateSumm '2','Acc2010_2011.dbo.','01/apr/2010','31/mar/2011',##2128,4,1
*/
CREATE PROCEDURE [dbo].[PROC_GraySalesOrderRateSumm]
(
    @CMP_CODE nvarchar(50),
    @DATABASENAME NVARCHAR(50),        
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
    @RPT_WISE INT,
    @RPT_TYPE INT    
)
AS
DECLARE @SQL NVARCHAR(4000) SET @SQL=""
DECLARE @JOINSQL NVARCHAR(1000) set @JOINSQL=""
DECLARE @TYPESQL NVARCHAR(1000) Set @TYPESQL=""
DECLARE @FIELDSQL NVARCHAR(1000) Set @FIELDSQL=""
DECLARE @SELSQL AS NVARCHAR(2000) SET @SELSQL=""
DECLARE @GROUPSQL AS NVARCHAR(2000) SET @GROUPSQL=""


BEGIN
	IF @RPT_TYPE=1	
       BEGIN
	      SET @FIELDSQL="  SOD.PendingQty "
          SET @TYPESQL=" AND SOD.PendingQty >0"
       END 
	ELSE IF @RPT_TYPE=2
       BEGIN
	    SET @FIELDSQL=" SOD.Quantity " 
        SET @TYPESQL=" "
       END
END

BEGIN
	IF @RPT_WISE=1
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=LM.LGR_ID"
			  SET @GROUPSQL=" Group By LM.LGR_NAME ,PCM.CITY_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE "
            END
	ELSE IF @RPT_WISE=2
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=ALM.LGR_ID"
			  SET @GROUPSQL=" GROUP BY ALM.LGR_NAME ,ACM.CITY_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE"
            END
	ELSE IF @RPT_WISE=3
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=IM.ITEM_ID"
			   SET @GROUPSQL=" GROUP BY LM.Lgr_Name,IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE"
            END
	ELSE IF @RPT_WISE=4
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+@TempTable+" TT on TT.CODE=WM.Weaver_Id "
			  SET @GROUPSQL=" GROUP BY IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE"
            END
	ELSE IF @RPT_WISE=5
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+@TempTable+" TT on TT.CODE=IGM.Item_Grp_Id "
			  SET @GROUPSQL=" GROUP BY IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE,IGM.Item_Grp_Name"
            END
	ELSE IF @RPT_WISE=6
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+@TempTable+" TT on TT.CODE=ITM.Item_Type_Id"
			  SET @GROUPSQL=" GROUP BY IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE,ITM.Item_Type_NAME"
            END
	ELSE IF @RPT_WISE=7
            BEGIN
	          SET @JOINSQL=""
			  SET @GROUPSQL=" GROUP BY IM.ITEM_NAME ,WM.WEAVER_NAME,SOD.RATE"
            END
END


BEGIN
	
	SET NOCOUNT ON;
SET @SQL="
select max(LM.Lgr_Name) as Party,max(PCM.City_Name) as PartyCity,max(ALM.Lgr_Name) as Agent,max(ACM.City_Name) as AgentCIty,
max(IM.Item_Name) as Item_Name,max(WM.WEAVER_NAME) as WEAVER_NAME,SUm("+@FIELDSQL+") as PENDINGQTY,SOD.Rate,
max(IGM.Item_Grp_Name)as Item_Grp_Name,max(ITM.Item_Type_NAME) as Item_Type_NAME
from "+@DATABASENAME+"  Sales_Order SO
INNER JOIN "+@DATABASENAME+" Sales_Order_Detail SOD ON SO.Sal_Order_Id=SOD.Sal_Order_Id and SO.Flag=SOD.Flag
LEFT JOIN "+@DATABASENAME+" Ledger_Master LM ON LM.lgr_id=SO.lgr_id
LEFT JOIN "+@DATABASENAME+" City_Master PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"Ledger_Master ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"City_Master ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
LEFT JOIN "+@DATABASENAME+" WEAVER_MASTER WM ON WM.WEAVER_ID=SOD.WEAVER_ID
left join "+@DATABASENAME+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
left join "+@DATABASENAME+" Item_Type_Master  ITM on ITM.Item_Type_Id=IM.Item_Type_Id
"+@JOINSQL+"
WHERE SO.Cmp_Code in ("+@CMP_CODE+") and SO.vch_Date between '"+@FROMDATE+"' and '"+@TODATE+"'
and SO.Flag='GS'
"+@TYPESQL+"
"+@GROUPSQL+"
"
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

