CREATE PROCEDURE [dbo].[PROC_GRAYSALESORDERREG]
(
@Cmp_Code nvarchar(50),
@DatabaseName nvarchar(50),
@Rpt_Type int,
@Rpt_Wise int,
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50)
)
AS
BEGIN

DECLARE @SQL nvarchar(4000) SET @SQL=""
DECLARE @JOIN nvarchar(4000) SET @JOIN=""
DECLARE @CONN nvarchar(4000) SET @CONN=""

BEGIN 
	if @Rpt_Wise=1
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=LM.LGR_ID "
	if 	@Rpt_Wise=2
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=CG.Cust_Grp_Id "
	if 	@Rpt_Wise=3
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID"
	if 	@Rpt_Wise=4
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=WM.Weaver_Id"
	if 	@Rpt_Wise=5
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IGM.Item_Grp_Id"
	if 	@Rpt_Wise=6
		SET @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=ITM.Item_Type_Id"
	if 	@Rpt_Wise=7
		SET @JOIN=""

END

BEGIN 
	if @Rpt_Type=1
		SET @CONN="  AND SOD.PendingQty=0"
	if @Rpt_Type=2
		SET @CONN="  AND SOD.PendingQty>0"
	if @Rpt_Type=3
		SET @CONN=""
	
END
	
	SET NOCOUNT ON;

SET @SQL="
select ConfNo,vch_Date,Sales_OrderNo,IM.Item_Name,SO.Start_Date,SO.End_Date,Rate,SOD.Quantity,SOD.DeliveredQty,SOD.PendingQty
,LM.Lgr_Name as PartyName,pcm.city_name as partycity,CG.Cust_Grp_Name,WM.Weaver_Name,IGM.Item_Grp_Name,ITM.Item_Type_NAME
from "+@DatabaseName+" Sales_Order SO
inner join "+@DatabaseName+" Sales_Order_Detail SOD on SO.Sal_Order_Id=SOD.Sal_Order_Id and SO.Flag=SOD.FLag
left join "+@DatabaseName+" Item_Master Im on SOD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Ledger_Master LM on LM.Lgr_Id=SO.Lgr_Id
left join "+@DatabaseName+" Weaver_Master WM on WM.Weaver_Id=SOD.Weaver_Id
left join "+@DatabaseName+" Customer_Group_Master CG on CG.Cust_Grp_Id=SO.Cust_Grp_Id
left join "+@DatabaseName+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
left join "+@DatabaseName+" Item_Type_Master  ITM on ITM.Item_Type_Id=IM.Item_Type_Id
left join "+@DatabaseName+" city_Master pcm on pcm.city_id=lm.city_id
"+@JOIN+"
where SO.Flag='GS' and SO.Cmp_Code in ("+@Cmp_Code+")
"+@CONN+"
ORDER BY vch_Date,ConfNo
"
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















