/*

PROC_GRAYSALESORDERREPORT '2','Acc2010_2011.dbo.',3,7,'01/apr/2010','31/Mar/2011','##3136'
*/

CREATE PROCEDURE [dbo].[PROC_GRAYSALESORDERREPORT]
(
@Cmp_Code nvarchar(50),
@DatabaseName nvarchar(50),
@Rpt_Type int,
@Rpt_Wise int,
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50)
)
AS

DECLARE @Str NVARCHAR(4000) SET @Str=""
DECLARE @Str1 NVARCHAR(4000) SET @Str1=""
DECLARE @Str2 NVARCHAR(4000) SET @Str2=""
DECLARE @JOIN NVARCHAR(4000) SET @JOIN=""
DECLARE @CONDSQL NVARCHAR(1000) set @CONDSQL=""


BEGIN
        IF @Rpt_Wise=1 
           SET @JOIN=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID "
        ELSE IF @Rpt_Wise=2
           SET @JOIN=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID "
        ELSE IF @Rpt_Wise=3
           SET @JOIN=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
		ELSE IF @RPT_WISE=4
	          SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=WM.Weaver_Id "
		ELSE IF @RPT_WISE=5
	          SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=IGM.Item_Grp_Id "
		ELSE IF @RPT_WISE=6
	          SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=ITM.Item_Type_Id"
        ELSE IF @Rpt_Wise=7
			SET @JOIN=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CGM.Cust_Grp_ID "
		ELSE IF @Rpt_Wise=8
			SET @JOIN=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=SO.CONFNO "
		
END      

BEGIN
        IF @Rpt_Type=1 
          begin
           SET @CONDSQL=" AND SOD.PENDINGQTY=0"        
          end
        ELSE IF @Rpt_Type=2
           begin
           SET @CONDSQL=" AND SOD.PENDINGQTY>0"           
           end
        ELSE IF @Rpt_Type=3
             begin
           SET @CONDSQL=""
              end
END

BEGIN
SET NOCOUNT ON;
SET @Str="
select DOCNO,DATE,BILLNO,PARTY,AGENT,PartyCity,AgentCity,STATIONNAME,Weaver,ITEM,ORDQTY,USSEDQTY,FLAG,FYEAR,
Item_Type_NAME,Item_Grp_Name,Cust_Grp_NAME
FROM(
SELECT DISTINCT SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,CONVERT(NVARCHAR,SO.CONFNO) AS BILLNO
,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CIty_Name as PartyCity,ACM.City_Name as AgentCity,
CM.CITY_NAME as STATIONNAME,WM.Weaver_NAME AS Weaver,IM.ITEM_NAME AS ITEM,
SOD.Quantity AS ORDQTY,0 AS USSEDQTY,'OD' AS FLAG,SO.FYEAR,ITM.Item_Type_NAME,IGM.Item_Grp_Name,CGM.Cust_Grp_Name
,1 as ORDERWISE
FROM "+@DatabaseName+" SALES_ORDER SO
INNER JOIN "+@DatabaseName+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID and SO.Flag=SOD.FLag
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
left JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DatabaseName+" Weaver_Master WM on WM.Weaver_Id=SOD.Weaver_Id 
left join "+@DatabaseName+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
left join "+@DatabaseName+" Item_Type_Master  ITM on ITM.Item_Type_Id=IM.Item_Type_Id
left join "+@DatabaseName+" Customer_Group_Master CGM on SO.Cust_Grp_Id=CGM.Cust_Grp_Id
"+@JOIN+"
WHERE SO.VCH_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND SO.CMP_CODE IN ("+@Cmp_Code+") and 
SO.Flag='GS'
"+@CONDSQL+"
UNION ALL
"
SET @Str1="
SELECT DISTINCT SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,CONVERT(NVARCHAR,SI.Sal_Inv_Bill_No) AS BILLNO
,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CIty_Name as PartyCity,ACM.City_Name as AgentCity,
CM.CITY_NAME as STATIONNAME,WM.Weaver_NAME AS Weaver,IM.ITEM_NAME AS ITEM,0 AS ORDQTY,
(CASE  SOD.BalesPcsMtr WHEN 'BALES' THEN  SID.SAL_INV_BALES WHEN 'PCS' THEN SID.Sal_Inv_Pcs WHEN 'MTR' THEN SID.Sal_Inv_Qty ELSE 0 END) AS USSEDQTY, 
'INV' AS FLAG,SO.FYEAR,ITM.Item_Type_NAME,IGM.Item_Grp_Name,CGM.Cust_Grp_Name,2 as ORDERWISE
FROM "+@DatabaseName+" SALES_ORDER SO
INNER JOIN "+@DatabaseName+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID and SO.Flag=SOD.FLag
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
left JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DatabaseName+" Weaver_Master WM on WM.Weaver_Id=SOD.Weaver_Id 
INNER JOIN "+@DatabaseName+" SALES_INVOICE SI ON SI.ConfNo=SO.ConfNo and SO.CMp_COde=SI.CMp_CODE and SI.Flag=SO.FLag and SI.Sal_Fyear=SO.Fyear
INNER JOIN "+@DatabaseName+" SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID and SOD.ITEM_ID=SID.Item_Id
left join "+@DatabaseName+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
left join "+@DatabaseName+" Item_Type_Master  ITM on ITM.Item_Type_Id=IM.Item_Type_Id
left join "+@DatabaseName+" Customer_Group_Master CGM on SO.Cust_Grp_Id=CGM.Cust_Grp_Id
"+@JOIN+"
WHERE SO.VCH_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND SO.CMP_CODE in ("+@Cmp_Code+") 
and SO.Flag='GS'
"+@CONDSQL+"
UNION ALL
"
SET @Str2="
SELECT DISTINCT SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,CONVERT(NVARCHAR,GI.DocNo) AS BILLNO
,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CIty_Name as PartyCity,ACM.City_Name as AgentCity,
CM.CITY_NAME as STATIONNAME,WM.Weaver_NAME AS Weaver,IM.ITEM_NAME AS ITEM,0 AS ORDQTY,
(CASE  SOD.BalesPcsMtr WHEN 'BALES' THEN  GID.BALES WHEN 'PCS' THEN GID.PIECES WHEN 'MTR' THEN GID.QUANTITY ELSE 0 END) AS USSEDQTY, 
'STK' AS FLAG,SO.FYEAR,ITM.Item_Type_NAME,IGM.Item_Grp_Name,CGM.Cust_Grp_Name,3 as ORDERWISE
FROM "+@DatabaseName+" SALES_ORDER SO
INNER JOIN "+@DatabaseName+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID and SO.Flag=SOD.FLag
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DatabaseName+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
left JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DatabaseName+" Weaver_Master WM on WM.Weaver_Id=SOD.Weaver_Id 
INNER JOIN "+@DatabaseName+" GREYSTOCKTRANS_MASTER GI ON GI.Conf_No=SO.ConfNo and SO.CMp_COde=GI.CMp_CODE and GI.FYEAR=SO.Fyear
INNER JOIN "+@DatabaseName+" GREYSTOCKTRANS_DETAIL GID ON GI.GreyStockTrans_Id=GID.GreyStockTrans_Id and SOD.ITEM_ID=GID.Item_Id
left join "+@DatabaseName+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
left join "+@DatabaseName+" Item_Type_Master  ITM on ITM.Item_Type_Id=IM.Item_Type_Id 
left join "+@DatabaseName+" Customer_Group_Master CGM on SO.Cust_Grp_Id=CGM.Cust_Grp_Id
"+@JOIN+"
WHERE SO.VCH_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND GI.CMP_CODE in ("+@Cmp_Code+")
"+@CONDSQL+"
) as A
ORDER BY DOCNO,FYEAR,ITEM,WEAVER,ORDERWISE

"


    
END
exec (@Str+@Str1+@Str2)
print @Str
Print @Str1
Print @Str2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GRAYSALESREGISTER]    Script Date: 03/30/2023 12:08:12 ******/
