/*
PROC_GRAYSALESREGISTER '01/apr/2010','31/Mar/2011','2',1,'Acc2012_2013.dbo.','##3328',0,4457,2
*/
CREATE PROCEDURE [dbo].[PROC_GRAYSALESREGISTER]
(
		@FromDate  nvarchar(20),
		@ToDate nvarchar(20),
		@Cmp_Code nvarchar(10),
		@QueryNo int,
		@DatabaseName nvarchar(50),
		@TempTable nvarchar(20),
		@SelAll  int,
		@SalAccID nvarchar(20),
		@CONVERSION int
)

AS

DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SELECTED=""
SET @QUANTITYSQL=""

IF @SelAll=0  /* FOR ALL OPTION SELECTION */
  BEGIN    
	   IF @QueryNo=1
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
	   IF @QueryNo=2
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON CG.Cust_Grp_Id=" + @TempTable + ".CODE"
	   IF @QueryNo=3
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON ALM.Lgr_Id=" + @TempTable + ".CODE"
	   IF @QueryNo=4
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON SI.Sal_Inv_Bill_No=" + @TempTable + ".CODE"
	   IF @QueryNo=7
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON TM.TRANSPORT_ID=" + @TempTable + ".CODE"
   END
SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "
IF @CONVERSION=1 
   SET @QUANTITYSQL="
                    (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
                     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "

BEGIN	
	SET NOCOUNT ON;

SET @SQL="
select SI.Sal_inv_Id,Sal_Inv_Vdate,Sal_Inv_Bill_No,LM.Lgr_name as PartyName,Sal_Inv_LrNo,IM.Item_Name,wM.weaver_Name,Sal_Inv_Pcs,
"+@QUANTITYSQL+",SID.Sal_Inv_Rate,SID.Sal_Inv_Amount,ALM.Lgr_Name as AgentName,CG.Cust_Grp_Name,
(Sal_Inv_AddTotal-Sal_Inv_LessTotal) as ADDLESS,Sal_Inv_NetTotal,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
TM.TRANSPORT_NAME
from "+@DatabaseName+" Sales_Invoice SI
INNER JOIN "+@DatabaseName+" SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
LEFT JOIN "+@DatabaseName+" Ledger_Master LM on LM.Lgr_Id=SI.Lgr_Id
LEFT JOIN "+@DatabaseName+" ITEM_MASTER IM ON SID.ITEM_ID=IM.ITEM_ID
LEFT JOIN "+@DatabaseName+" UNIT_MASTER UM on IM.UNIT_ID=UM.Unit_Id
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
left join "+@DatabaseName+" CUSTOMER_GROUP_MASTER CG ON CG.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN "+@DatabaseName+" weaver_MASTER wM on wM.weaver_id=SID.weaver_id
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM on PCM.CITY_id=LM.CITY_id
LEFT JOIN "+@DatabaseName+" CITY_MASTER ACM on ACM.CITY_id=ALM.CITY_id
LEFT JOIN "+@DatabaseName+" TRANSPORT_MASTER TM on TM.TRANSPORT_ID=SI.TRANSPORT_ID
"+@SELECTED+"
where SI.FLag='GS' and SI.Cmp_Code in ("+@Cmp_Code+")
and Sal_Inv_Vdate between '"+@FromDate+"' and '"+@ToDate+"'
and SI.Sal_AccID="+ @SalAccID +" 
ORDER BY Sal_Inv_Bill_No
"

    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

