/* 
PROC_GRAYSALESSUMMARY '2','Acc2010_2011.dbo.',1,'01/apr/2010','31/Mar/2011','##1840'
*/


CREATE PROCEDURE [dbo].[PROC_GRAYSALESSUMMARY]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),
	@ToDate as Nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=1
Begin
	SET @TypeSql=" ,ITM.Item_Type_NAME  as MainGroup"	
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =ITM.ITem_Type_ID"
END

if @Rpt_Wise=2
	BEGIN
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IGM.Item_Grp_ID"
	SET @TypeSql=" ,IGM.Item_Grp_NAME  as MainGroup"	
END

begin
    	SET NOCOUNT ON;
set @Sql="
Select SI.SAl_Inv_Id,SI.Sal_Inv_Bill_No as BillNo,SID.Sal_Inv_Pcs,LM.Lgr_Name,pcm.city_name as partycity
"+@TypeSql+"
FROM "+@DatabaseName+" Sales_Invoice SI
INNER JOIN "+@DatabaseName+" Sales_Invoice_Detail SID on SI.SAl_Inv_Id=SID.SAl_Inv_Id and SID.Flag=SI.Flag
INNER JOIN "+@DatabaseName+" Ledger_Master LM on SI.Lgr_Id=LM.Lgr_Id
Inner Join "+@DatabaseName+" Item_Master IM ON SID.item_Id = IM.item_Id  
left Join "+ @DatabaseName+ "Item_Type_Master ITM ON IM.Item_Type_Id = ITM.Item_Type_Id  
Inner Join "+@DatabaseName+" Item_Group_Master IGM ON IM.item_Grp_Id = IGM.item_Grp_Id  
left Join "+@DatabaseName+" city_Master pcm on pcm.city_id=lm.city_id
"+@JoinSql+"	
where  SI.RecDate>='"+@FromDate+"' and SI.RecDate<='"+@ToDate+"' and SI.Cmp_Code in ("+ @Cmp_Code +") 
and SI.Flag='GS'
" 

execute Sp_Executesql @sql
Print @sql
end




















GO

