-- =============================================
-- ALTER_AUTHOR  :	<BIREN>
-- ALTER_DATE    : <26/02/2015 4:30 PM>
-- REPORT_FORM	  :	<rfrmPrintingDocRpt.cs>
-- CRYSTAL_REPORT : <GREYDELIVERYCHALLAN_FULL_PRINT.RPT,GREYDELIVERYCHALLAN_HALF_PRINT.RPT>
-- PROC_GREYDELIVERY_CHALLAN_PRINT 1,'ACC2014_2015.DBO.','1','10'
-- =============================================
CREATE PROCEDURE [dbo].[PROC_GREYDELIVERY_CHALLAN_PRINT] 

(
@CMP_CODE NVARCHAR(5),
@DATABASENAME NVARCHAR(100),
@FROMDOCNO NVARCHAR(10),
@TODOCNO NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = ""
	

BEGIN
SET NOCOUNT ON;
SET @SQL = "
SELECT GCM.GREY_DELIVERY_CHALLAN_ID,ISNULL(GCM.DOCNO,0) AS CHALLANONO,
CONVERT(NVARCHAR,GCM.CHALLAN_DATE,103) AS CHALLANDATE,
GCM.TOTAL_THAN,GCM.TOTAL_LR,ISNULL(GCM.VEHICLENO,'') AS VEHICLENO,
GCD.SRNO,GCD.LRNO,GCD.THAN,ISNULL(GCD.REMARK,'') AS REMARK,
ISNULL(GCD.LOTNO,0) AS LOTNO,ISNULL(LM.LGR_NAME,'') AS PARTY,UPPER(CM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,
UPPER(LM.LGR_ADD2) AS LGR_ADD2 ,UPPER(LM.LGR_ADD3)AS LGR_ADD3,LM.CITY_PINCODE,UPPER(SM.STATE_NAME) AS  PATYSTATE,LM.LGR_DISTRICT,
SM.STATE_CODE AS LGR_STATECODE,ISNULL(LOM.LORIWALA_NAME,'') AS LORIWALA,ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(CURM.COURIERMASTER_NAME,'') AS COURIERNAME,
ISNULL(MM.LOT_NAME,'') AS GREYMARKA,ISNULL(PM.PROCESS_NAME,'') AS PROCESS,LM.GSTINNO AS LGSTINNO,lm.Lgr_Pano,
ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(DM.DRIVER_NAME,'') AS DRIVER,
ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,GCM.CHALLANONO AS DOCNO,GCD.METER,
ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,CONVERT(NVARCHAR,CMM.PINCODE) AS CONSIGNEE_PINCODE,CMM.DISTRICT AS CONSIGNEE_DISTRICT
FROM "+@DATABASENAME+"GREY_DELIVERY_CHALLAN_MASTER GCM
INNER JOIN "+@DATABASENAME+"GREY_DELIVERY_CHALLAN_DETAIL GCD ON GCM.GREY_DELIVERY_CHALLAN_ID = GCD.GREY_DELIVERY_CHALLAN_ID AND GCM.CMP_CODE = GCD.CMP_CODE	
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GCM.LGR_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LORIWALA_MASTER LOM ON LOM.LORIWALA_ID = GCM.LORIWALA_ID
LEFT JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID = GCM.PROCESS_ID
LEFT JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GCD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER MM ON MM.LOT_ID = GCD.LOT_ID
LEFT JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID = GCM.DRIVER_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GCD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+" COURIER_MASTER CURM ON CURM.COURIERMASTER_ID = LM.COURIERMASTER_ID
LEFT JOIN "+@DATABASENAME+" CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=GCM.Consignee_Id
LEFT JOIN "+@DATABASENAME+" CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id	
LEFT JOIN "+@DATABASENAME+" STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
WHERE GCM.CMP_CODE = "+@CMP_CODE+" AND  GCM.DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

