/*
-- =============================================
-- ALTER_AUTHOR    : <BIREN>
-- ALTER_DATE      : <21-03-2015 2:00 PM>
-- EDIT_AUTHOR		: <BIREN>
-- EDIT_DATE		: <13-04-2015 4:00 PM>
-- REPORT_FORM      : <RFRMGREYDELIVERYCHALLANREGISTER.CS>
-- CRYSTAL_REPORT   : <GREYDELIVERYCHALLANREGISTER.RPT>
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE'##%'
[PROC_GREYDELIVERYCHALLAN_REGISTER] '1','ACC2015_2016.DBO.',1,'01/APR/2014','30/APR/2015','##1848', 1,1
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GREYDELIVERYCHALLAN_REGISTER]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT,
@FLAG INT
)
AS
DECLARE @STRSQL NVARCHAR(4000)
DECLARE @STRJOIN NVARCHAR(500)
DECLARE @STRORDER  NVARCHAR(500)
DECLARE @RPTTYPESQL  NVARCHAR(500)
DECLARE @SQLORDERBY NVARCHAR(200)

SET @STRJOIN=""
SET @STRSQL=""
SET @STRORDER=""
SET @RPTTYPESQL=""
SET @SQLORDERBY=""

IF @FLAG = 1
BEGIN
IF @RPT_TYPE = 1 
BEGIN
SET @RPTTYPESQL = " AND GDCD.PURCHASEINVID IN 
					(SELECT PURCHASEINVID FROM "+@DATABASENAME+"GrayReceipt_Detail WHERE GDCM.CMP_CODE IN("+@CMP_CODE+"))"
END
IF @RPT_TYPE = 2
BEGIN
SET @RPTTYPESQL = " AND GDCD.PURCHASEINVID NOT IN 
					(SELECT PURCHASEINVID FROM "+@DATABASENAME+"GrayReceipt_Detail WHERE GDCM.CMP_CODE IN("+@CMP_CODE+"))"
END
IF @RPT_TYPE = 3
BEGIN
SET @RPTTYPESQL = ""
END
END

IF @FLAG = 2
BEGIN
IF @RPT_TYPE = 1 
BEGIN
SET @RPTTYPESQL = " AND GDCD.PURCHASEINVID IN 
					(SELECT PURCHASEINVID FROM "+@DATABASENAME+"LOTNOENTRY WHERE GDCM.CMP_CODE IN("+@CMP_CODE+"))"
END
IF @RPT_TYPE = 2
BEGIN
SET @RPTTYPESQL = " AND GDCD.PURCHASEINVID NOT IN 
					(SELECT PURCHASEINVID FROM "+@DATABASENAME+"LOTNOENTRY WHERE GDCM.CMP_CODE IN("+@CMP_CODE+"))"
END
IF @RPT_TYPE = 3
BEGIN
SET @RPTTYPESQL = ""
END
END



BEGIN
IF @RPT_WISE IN(1) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
SET @SQLORDERBY=" ISNULL(LM.LGR_NAME,''),ISNULL(LM.LGR_ID,0),"
END
IF @RPT_WISE IN(2) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PM.PROCESS_ID"
SET @SQLORDERBY=" ISNULL(PM.PROCESS_NAME,''),ISNULL(PM.PROCESS_ID,0),"
END
IF @RPT_WISE IN(3)
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LRM.LORIWALA_ID"
SET @SQLORDERBY=" ISNULL(LRM.LORIWALA_NAME,''),ISNULL(LRM.LORIWALA_ID,0),"
END
IF @RPT_WISE IN(4 )
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=DM.DRIVER_ID"
SET @SQLORDERBY=" ISNULL(DM.DRIVER_NAME,''),ISNULL(DM.DRIVER_ID,0),"
END
IF @RPT_WISE IN (5) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID"
SET @SQLORDERBY=" ISNULL(TM.TRANSPORT_NAME,''),ISNULL(TM.TRANSPORT_ID,0),"
END
IF @RPT_WISE =6 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
SET @SQLORDERBY=" ISNULL(IM.ITEM_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (7) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LOM.LOT_ID"
SET @SQLORDERBY=" ISNULL(LOM.LOT_NAME,''),ISNULL(LOM.LOT_ID,0),"
END
IF @RPT_WISE IN(8) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
SET @SQLORDERBY=" ISNULL(LM.LGR_NAME,''),ISNULL(LM.LGR_ID,0),ISNULL(IM.ITEM_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN(9) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
SET @SQLORDERBY=" ISNULL(LM.LGR_NAME,''),ISNULL(LM.LGR_ID,0),ISNULL(LOM.LOT_NAME,''),ISNULL(LOM.LOT_ID,0),"
END
IF @RPT_WISE IN (10) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID"
SET @SQLORDERBY=" ISNULL(TM.TRANSPORT_NAME,''),ISNULL(TM.TRANSPORT_ID,0),ISNULL(IM.ITEM_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (11) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID"
SET @SQLORDERBY=" ISNULL(TM.TRANSPORT_NAME,''),ISNULL(TM.TRANSPORT_ID,0),ISNULL(LOM.LOT_NAME,''),ISNULL(LOM.LOT_ID,0),"
END
IF (@RPT_WISE =12 ) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=GDCD.PURCHASEINVID"
END
IF @RPT_WISE =13 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=GDCM.GREY_DELIVERY_CHALLAN_ID"
END
IF @RPT_WISE IN(14) 
BEGIN
SET @STRJOIN =""
END


SET @STRSQL="SELECT GDCM.GREY_DELIVERY_CHALLAN_ID,ISNULL(GDCM.CHALLANONO, 0) AS CHALLANONO,
CONVERT	(NVARCHAR,GDCM.CHALLAN_DATE,103) AS VCHDATE,ISNULL(GDCM.TOTAL_THAN,0) AS TOTAL_THAN,
ISNULL(GDCM.TOTAL_LR,0) AS TOTAL_LR,ISNULL(GDCM.VEHICLENO,'') AS VEHICLENO,
GDCM.DOCNO,ISNULL(GDCD.PURCHASEINVID,0) AS PURCHASEINVID,ISNULL(GDCD.LRNO,0) AS LRNO,
ISNULL(GDCD.THAN,0) AS THAN,ISNULL(GDCD.REMARK,'') AS REMARK,GDCD.FLAG,
ISNULL(GDCD.LOTNO,0) AS LOTNO,ISNULL(GDCD.METER,0) AS METER,ISNULL(LM.LGR_NAME,'') AS PARTY,
ISNULL(PM.PROCESS_NAME,'') AS PROCESS,ISNULL(LRM.LORIWALA_NAME,'') AS LORIWALA,
ISNULL(DM.DRIVER_NAME,'') AS DRIVER,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,
ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(LOM.LOT_NAME,'') AS GREYMAEKA,ISNULL(COMP.CMP_ALIAS,'') AS CMP_ALIAS,
ISNULL(GDCD.BALES,0) AS BALES,ISNULL(LM.LGR_ID,0) AS LGR_ID, ISNULL(PM.PROCESS_ID,0) AS PROCESS_ID,ISNULL(LRM.LORIWALA_ID,0) AS LORIWALA_ID  ,
ISNULL(DM.DRIVER_ID,0) AS DRIVER_ID, ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORT_ID, ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(LOM.LOT_ID,0) AS LOT_ID,ISNULL(CM.CITY_NAME,'') AS PARTYCITY

FROM "+@DATABASENAME+"GREY_DELIVERY_CHALLAN_MASTER GDCM
INNER JOIN "+@DATABASENAME+"GREY_DELIVERY_CHALLAN_DETAIL GDCD ON GDCM.GREY_DELIVERY_CHALLAN_ID = GDCD.GREY_DELIVERY_CHALLAN_ID
AND GDCM.CMP_CODE= GDCD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GDCM.LGR_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID = GDCM.PROCESS_ID
INNER JOIN "+@DATABASENAME+"LORIWALA_MASTER LRM ON LRM.LORIWALA_ID = GDCM.LORIWALA_ID
INNER JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID = GDCM.DRIVER_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GDCD.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GDCD.ITEM_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = GDCD.LOT_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = GDCM.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
"+@STRJOIN+"
WHERE GDCM.CMP_CODE IN("+@CMP_CODE+")  AND GDCM.CHALLAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@RPTTYPESQL+"
ORDER BY GDCM.DOCNO "
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL


















GO

