/*
-- =============================================
-- Author     :		<PRATIK PATEL>
-- Create_date: 03/07/2014
-- Description:	rfrmPrintingDocRpt.cs
-- CryStalReport : GREYPURCHASEORDER_PRINT.rpt
-- =============================================
PROC_GREYPURCHASEORDER_PRINTOUT 1,'ACC2013_2014.DBO.',1,2
*/
CREATE PROCEDURE [dbo].[PROC_GREYPURCHASEORDER_PRINTOUT]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMCONFNO NVARCHAR(50),
@TOCONFNO NVARCHAR(50)
)
AS

DECLARE @SQL NVARCHAR(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT ISNULL(PI.PUR_ORDER_ID,0)PUR_ORDER_ID,ISNULL(PI.DOCNO,0)DOCNO,ISNULL(PI.PONO,'')PONO,ISNULL(SM.SUPP_GRP_NAME,'') AS SUPP_GRP,
ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,ISNULL(CONVERT(NVARCHAR,PI.GDATE,103),'')GDATE,
ISNULL(CONVERT(NVARCHAR,PI.PO_DATE,103),'')PO_DATE,
ISNULL(CONVERT(NVARCHAR,PI.START_DATE,103),'')STARTDATE,ISNULL(CONVERT(NVARCHAR,PI.END_DATE,103),'')END_DATE,
ISNULL(PI.DISC,0)DISC,ISNULL(PI.CRDAYS,0)CRDAYS,ISNULL(PI.FLAG,'')FLAG,ISNULL(PI.FYEAR,'')FYEAR,ISNULL(PI.QTYTOTAL,0)QTYTOTAL,
ISNULL(PI.DELIV,'')DELIV,ISNULL(PI.DELIVPERIOD,0)DELIVPERIOD,ISNULL(PI.DELIVDAYS,0)DELIVDAYS,ISNULL(PI.PURCHASEBY,'')PURCHASEBY,
ISNULL(PI.REMARKS,'')REMARKS,ISNULL(PI.INT_RATE,0)REMARKS,ISNULL(PI.TAP_LENGTH,0)TAP_LENGTH,ISNULL(CTM.CLOTH_TYPE_NAME,'')CLOTH_TYPE_NAME,
ISNULL(PI.ENTRYTYPE,'')ENTRYTYPE,ISNULL(CM.CITY_NAME,'')FROMCITY,WITH_TRANSPORTATION,ISNULL(PD.SRNO,0)SRNO,ISNULL(IM.ITEM_NAME,'')ITEM,
ISNULL(UM.UNIT_NAME,'')UNIT,ISNULL(WM.WEAVER_NAME,'')WEAVERNAME,ISNULL(QUANTITY,0)QUANTITY,ISNULL(DELIVEREDQTY,0)DELIVEREDQTY,
ISNULL(PENDINGQTY,0)PENDINGQTY,ISNULL(BALESPCSMTR,'')BALESPCSMTR,
ISNULL(SCHEDULE,0)SCHEDULE,ISNULL(SCHQUANTITY,0)SCHQUANTITY,ISNULL(RATE,0)RATE,ISNULL(PD.ITEM_READS,0)RATE,ISNULL(PD.ITEM_PEAK,0),
ISNULL(PD.ITEM_GWEIGHT,0)ITEM_GWEIGHT,ISNULL(PD.ITEM_GWIDTH,0)ITEM_GWIDTH,ISNULL(PD.ITEM_DWEIGHT,0)ITEM_DWEIGHT,PD.CANCEL,ISNULL(TAX,0)TAX,ISNULL(TAX_PER,0)TAX_PER,
ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP,ISNULL(TOKEN,'')TOKEN,ISNULL(PD.FOLD_TYPE,'')FOLD_TYPE,ISNULL(PCS,0)PCS,ISNULL(TOTALPCS,0)TOTALPCS,
ISNULL(BALES,0)BALES,ISNULL(FGIM.ITEM_NAME,'')FGITEMNAME,
ISNULL(PD.ENTRYTYPE,'')ENTRYTYPE,ISNULL(PD.REMARKS,'')REMARKS,ISNULL(LOM.LOT_NAME,'')LOTNAME
FROM "+@DATABASENAME+"PURCHASEORDER PI 
INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SM ON SM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID=PI.CLOTH_TYPE_ID
INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=PI.FROM_CITY_ID
INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL PD ON PD.PUR_ORDER_ID=PI.PUR_ORDER_ID AND PD.CMP_CODE=PI.CMP_CODE AND PD.FLAG=PI.FLAG
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID=PD.LOT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=PD.UNIT_ID
INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=PD.WEAVER_ID
LEFT JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=PD.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_MASTER FGIM ON FGIM.ITEM_ID=PD.FG_ITEM_ID
WHERE PI.FLAG='P' AND PI.ORDER_APPROVAL = 1 AND PI.DOCNO BETWEEN "+@FROMCONFNO+" AND "+@TOCONFNO+" AND PI.CMP_CODE IN ("+@CMP_CODE+")
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GREYSALESREG_DAILY_MONTHLY]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/* 
-- =============================================
-- Author:		HIREN DOSHI
-- ALTER date: 11/11/2014
-- Description:	THIS PROCEDURE USED FOR GREY SALES NORMAL DAILY MONTHLY
-- ReportName : GREYSALESREGISTER_NORMAL_MONTHLY_DAILY.RPT
-- =============================================
PROC_GREYSALESREG_DAILY_MONTHLY 2,'ACC2014_2015.DBO.','01/APR/2014','11/NOV/2014',3685,2
*/
CREATE PROCEDURE [dbo].[PROC_GREYSALESREG_DAILY_MONTHLY]
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @HEADID NVARCHAR(20),
   @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
	IF @RPT_WISE=1
          BEGIN  
              SET @SQL="SELECT 'JANUARY' AS MONTHNAME,SI.SAL_INV_VDATE AS VDATE,
				SUM(SID.SAL_INV_QTY )  AS QUANTITY,SUM((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL)) AS NETTOTAL,0 AS ORD     
				,MIN(CMP.CMP_ALIAS) AS CMP_ALIAS
				FROM "+@DATABASENAME+"SALES_INVOICE SI
				INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID  AND SI.FLAG=SID.FLAG
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
				INNER JOIN " + @DatabaseName + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
				WHERE SI.SAL_ACCID="+@HEADID+" AND SI.Cmp_Code IN ("+@CMP_CODE+") and  SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
				AND SI.FLAG='GSN' AND SI.SAL_INV_TYPE='N' 
				GROUP BY SI.SAL_INV_VDATE,CMP.CMP_CODE
				ORDER BY SI.SAL_INV_VDATE "
END
     ELSE IF @RPT_WISE=2
             SET @SQL="SELECT MONTHNAME,getdate()  AS VDATE,SUM(QUANTITY)AS QUANTITY,SUM(NETTOTAL) AS NETTOTAL,ORD,MIN(CMP_ALIAS) AS CMP_ALIAS  FROM (
						SELECT UPPER(DATENAME(MM,SI.SAL_INV_VDATE)) AS MONTHNAME,SID.SAL_INV_QTY  AS QUANTITY,
						(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS NETTOTAL,
						(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS     ORD
						,CMP.CMP_ALIAS
						FROM "+@DATABASENAME+"SALES_INVOICE SI
						INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SI.FLAG=SID.FLAG
						INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
						INNER JOIN " + @DatabaseName + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
						WHERE SI.SAL_ACCID="+@HEADID+" AND SI.Cmp_Code IN ("+@CMP_CODE+") and  SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
						AND SI.FLAG='GSN' AND SI.SAL_INV_TYPE='N' 
						) AS DETAIL
						GROUP BY MONTHNAME,CMP_ALIAS,ORD
						ORDER BY ORD "
	
	END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL





















GO

