/*
-- =============================================
-- AUTHOR:		HIREN DOSHI
-- ALTER_DATE: 11/11/2014
-- DESCRIPTION:	THIS PROCEDURE USED FOR GREY SALES NORMAL REGISTER
-- REPORTNAME : GREYSALESREGISTER_NORMAL.RPT
-- ============================================= 
PROC_GREYSALESREGISTER_NORMAL N'01/Apr/2018', N'31/Mar/2019', N'Acc2018_2019.Dbo.', N'1', N'##1760', 0, N'14336', 20

 select * from tempdb..sysobjects
*/
CREATE PROCEDURE [dbo].[PROC_GREYSALESREGISTER_NORMAL]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),    
@DATABASENAME NVARCHAR(50),
@CMP_CODE NVARCHAR(100),    
@TEMPTABLE NVARCHAR(20),
@SELALL  INT,
@HEADID NVARCHAR(20),
@RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @ORDERSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SELECTED=""
BEGIN


IF @RPT_WISE IN (1) /* AGENT WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE IN (9) /* AGENT/PARTY WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE IN (10) /* AGENT/ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END 

ELSE IF @RPT_WISE IN (15) /* AGENT/PARTY/ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END 

ELSE IF @RPT_WISE IN (16) /* AGENT/SALESMAN WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),"
END 


ELSE IF @RPT_WISE IN (2) /* PARTY WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @ORDERSQL="LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE IN (11) /* PARTY/ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @ORDERSQL="LM.LGR_NAME,ISNULL(LM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END

ELSE IF @RPT_WISE IN (3) /* ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SID.ITEM_ID=TT.CODE"
SET @ORDERSQL="IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END 

ELSE IF @RPT_WISE IN (4) /* SALESMAN WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON S_M.SALESMAN_ID=TT.CODE"
SET @ORDERSQL="S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),"
END 

ELSE IF @RPT_WISE IN (14) /* SALESMAN/AGENT WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON S_M.SALESMAN_ID=TT.CODE"
SET @ORDERSQL="S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE IN (5) /* ITEM GROUP WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IG.ITEM_GRP_ID=TT.CODE"
SET @ORDERSQL="IG.ITEM_GRP_NAME,ISNULL(IM.ITEM_GRP_ID,0),"
END 

ELSE IF @RPT_WISE IN (12) /* ITEM GROUP/ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IG.ITEM_GRP_ID=TT.CODE"
SET @ORDERSQL="IG.ITEM_GRP_NAME,ISNULL(IM.ITEM_GRP_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END 

ELSE IF @RPT_WISE = 6 /* CUSTOMER GROUP WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON CGM.CUST_GRP_ID=TT.CODE"
SET @ORDERSQL="CGM.CUST_GRP_NAME,ISNULL(CGM.CUST_GRP_ID,0),"
END 

ELSE IF @RPT_WISE IN (7) /* CITY WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON PCM.CITY_ID=TT.CODE"
SET @ORDERSQL="PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),"
END 

ELSE IF @RPT_WISE IN (13) /* CITY/PARTY WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON PCM.CITY_ID=TT.CODE"
SET @ORDERSQL="PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE IN (20) /* CITY/PARTY WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON Ns.Lot_Id=TT.CODE"
SET @ORDERSQL="Ns.Lot_Name,SID.Lot_Id,"
END 



ELSE IF @RPT_WISE = 8 /* STATE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.STATE_ID=TT.CODE"
SET @ORDERSQL="SM.STATE_NAME,ISNULL(SM.STATE_ID,0),"
END 

ELSE IF @RPT_WISE = 17 /* BILL BY BILL */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
SET @ORDERSQL=""
END 


BEGIN
IF @SELALL = 1
SET @SELECTED=""
END

SET NOCOUNT ON;
SET @SQL = " SELECT  isnull(Ns.Lot_Name,'')GrayMarka,isnull(Sid.Lot_Id,0)Lot_ID,SI.SAL_INV_ID,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,
LM.LGR_NAME AS PARTYNAME,AGM.LGR_NAME AS AGENTNAME ,SID.SAL_INV_CHALLANNO AS CHALLANNO,
(CASE WHEN SID.SERIALNO IS NULL THEN SID.SAL_INV_BALENO ELSE SID.SERIALNO END) AS SERIALNO,IM.ITEM_NAME AS ITEM,
SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL,
PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,
((SI.SAL_INV_ADDTOTAL-SI.SAL_INV_LESSTOTAL)+ SI.SAL_INV_ROUNDOFF) AS ADDLESSTOTAL,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,
COMP.CMP_PHONE2,COMP.CMP_MOBILE,COMP.CMP_FAX,S_M.SALESMAN_NAME AS SALESMAN,
CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,IG.ITEM_GRP_NAME,
ISNULL(LM.LGR_ID,0) AS PARTYID,
ISNULL(AGM.LGR_ID,0) AS AGENTID,
ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(UM.UNIT_ID,0) AS UNITID,
ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.STATE_ID,0) AS STATEID,
ISNULL(S_M.SALESMAN_ID,0) AS SALESMANID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(IM.ITEM_GRP_ID,0) AS ITEMGRPID

FROM "+ @DATABASENAME+ " SALES_INVOICE SI
INNER JOIN "+ @DATABASENAME+ " SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG 
INNER JOIN "+ @DATABASENAME+ " LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+ @DATABASENAME+ " LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
INNER JOIN "+ @DATABASENAME+ " ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN  "+ @DATABASENAME+ " UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN  "+ @DATABASENAME+ " COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN  "+ @DATABASENAME+ " CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+ @DATABASENAME+ " CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN  "+ @DATABASENAME+ " STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID     
LEFT JOIN  "+ @DATABASENAME+ " SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AGM.SALESMAN_ID
LEFT JOIN  "+ @DATABASENAME+ " CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN  "+ @DATABASENAME+ " ITEM_GROUP_MASTER IG ON IM.ITEM_GRP_ID =IG.ITEM_GRP_ID 
LEFT JOIN  "+ @DATABASENAME+ " LOT_MASTER NS ON NS.LOT_ID=SID.LOT_ID
" + @SELECTED +"
WHERE SI.SAL_ACCID="+@HEADID+"  AND SI.CMP_CODE IN("+ @CMP_CODE +")  AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
AND SI.FLAG='GSN' AND SI.SAL_INV_TYPE='N'  	 
ORDER BY "+@ORDERSQL+"CONVERT(INT,SI.SAL_INV_BILL_NO),SI.SAL_INV_VDATE,SID.SAL_INV_DTL_ID "
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

