/*
PROC_GREYSTOCKINREGI '2','ACC2010_2011.dbo.','##2916','01/apr/2010','31/Mar/2011',1,2
*/
CREATE PROCEDURE [dbo].[PROC_GREYSTOCKINREGI]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@TempTable nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@RptWise int,
@DelSumm int
)
AS

DECLARE @SQL nvarchar(4000) set @SQL=""
DECLARE @JOIN nvarchar(4000) set @JOIN=""
DECLARE @GROUPBY nvarchar(4000) set @GROUPBY=""
DECLARE @Del nvarchar(4000) set @Del=""

BEGIN
	IF @RptWise=1 
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.Item_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY="GROUP BY IM.Item_name"
		END
	ELSE IF @RptWise=2
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=WM.WEAVER_ID "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP BY WM.WEAVER_NAME "
		END
	ELSE IF @RptWise=3
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP BY PM.Lgr_Name "
		END
	ELSE IF @RptWise=4
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=TM.Transport_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP BY TM.Transport_Name "
		END
	ELSE IF @RptWise=5
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=SCM.City_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP by SCM.City_Name"
		END
ELSE IF @RptWise=6
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PCM.City_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP by PCM.City_Name"
		END
ELSE IF @RptWise=7
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.Item_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP by IM.Item_Name,WM.Weaver_Name"
		END
ELSE IF @RptWise=8
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP by PM.Lgr_Name,WM.Weaver_Name"
		END
ELSE IF @RptWise=9
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" GROUP by PM.Lgr_Name,IM.Item_Name"
		END
ELSE IF @RptWise=10
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_Id "
			SET @Del="select max(GIM.DocNo) as DocNo,max(GIM.VchDate) as VchDate,Count(GID.BaleNo) as BaleNo,sum(GID.BALES) as BALES,sum(GID.PIECES) as PIECES,sum(GID.QUANTITY) as QUANTITY
,max(GID.RATE) as RATE,max(IM.Item_Name) as Item_Name,max(WM.Weaver_Name) as Weaver_Name,max(PM.Lgr_Name) as PartyName
,max(PCM.City_Name) as CityParty,max(TM.Transport_Name) as Transport_Name,max(SCM.City_Name) as StationName"
			SET @GROUPBY=" "
		END
END	

BEGIN
	SET NOCOUNT ON;
If @DelSumm=1
BEGIN
SET @SQL="
select GIM.DocNo,GIM.VchDate,GID.BaleNo,GID.BALES ,GID.PIECES,GID.QUANTITY,GID.RATE,IM.Item_Name,WM.Weaver_Name,PM.Lgr_Name as PartyName,PCM.City_Name as CityParty
,TM.Transport_Name,SCM.City_Name as StationName
From "+@DataBase+" GREYSTOCKTRANS_IN_MASTER GIM
INNER JOIN "+@DataBase+" GREYSTOCKTRANS_IN_DETAIL GID on GID.GreyStockTrans_Id=GIM.GreyStockTrans_Id
LEFT JOIN "+@DataBase+" Item_Master IM on GID.Item_Id=IM.Item_Id
LEFT JOIN "+@DataBase+" WEAVER_MASTER WM on GID.WEAVER_ID=WM.WEAVER_ID
LEFT join "+@DataBase+" Ledger_Master PM on GIM.Lgr_Id=PM.Lgr_Id
LEFT JOIN "+@DataBase+" City_Master PCM on PCM.City_Id=PM.City_Id
LEFT JOIN "+@DataBase+" TRANSPORT_MASTER TM on GIM.Transport_Id=TM.Transport_Id
LEFT JOIN "+@DataBase+" CITY_MASTER SCM on SCM.City_Id=GIM.Station_Id
"+@JOIN+"
WHERE GIM.CMP_CODE in ("+@CmpCode+") and GIM.VchDate between '"+@FromDate+"' and '"+@ToDate+"'
"
END
else
SET @SQL=" "+@Del+"
From "+@DataBase+" GREYSTOCKTRANS_IN_MASTER GIM
INNER JOIN "+@DataBase+" GREYSTOCKTRANS_IN_DETAIL GID on GID.GreyStockTrans_Id=GIM.GreyStockTrans_Id
LEFT JOIN "+@DataBase+" Item_Master IM on GID.Item_Id=IM.Item_Id
LEFT JOIN "+@DataBase+" WEAVER_MASTER WM on GID.WEAVER_ID=WM.WEAVER_ID
LEFT join "+@DataBase+" Ledger_Master PM on GIM.Lgr_Id=PM.Lgr_Id
LEFT JOIN "+@DataBase+" City_Master PCM on PCM.City_Id=PM.City_Id
LEFT JOIN "+@DataBase+" TRANSPORT_MASTER TM on GIM.Transport_Id=TM.Transport_Id
LEFT JOIN "+@DataBase+" CITY_MASTER SCM on SCM.City_Id=GIM.Station_Id
"+@JOIN+"
WHERE GIM.CMP_CODE in ("+@CmpCode+") and GIM.VchDate between '"+@FromDate+"' and '"+@ToDate+"'
"+@GROUPBY+"
"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

