/*
PROC_GREYSTOCKOUTREGI '2','Acc2010_2011.dbo.','','01/apr/2010','31/mar/2011','6',1
*/
CREATE PROCEDURE [dbo].[PROC_GREYSTOCKOUTREGI]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@TempTable nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@RptWise int,
@DelSumm int
)
AS

DECLARE @SQL nvarchar(4000) set @SQL=""
DECLARE @JOIN nvarchar(4000) set @JOIN=""
DECLARE @GROUPBY nvarchar(4000) set @GROUPBY=""
DECLARE @Del nvarchar(4000) set @Del=""

BEGIN
	IF @RptWise=1 
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.Item_Id "
			SET @Del=" Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal
"
			SET @GROUPBY="GROUP BY IM.Item_name"
		END
	ELSE IF @RptWise=2
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=WM.WEAVER_ID "
			SET @Del=" Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal
"
			SET @GROUPBY=" GROUP BY WM.WEAVER_NAME "
		END
	ELSE IF @RptWise=3
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_Id "
			SET @Del=" Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP BY PM.Lgr_Name "
		END
	ELSE IF @RptWise=4
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=TM.Transport_Id "
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP BY TM.Transport_Name "
		END
	ELSE IF @RptWise=5
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=SCM.City_Id "
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP by SCM.City_Name"
		END
	ELSE IF @RptWise=6
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PCM.City_Id "
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP by PCM.City_Name"
		END
	ELSE IF @RptWise=7
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID"
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP by IM.ITEM_NAME,WM.WEAVER_NAME"
		END
ELSE IF @RptWise=8
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_ID"
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP by PM.Lgr_Name,WM.WEAVER_NAME"
		END
ELSE IF @RptWise=9
		BEGIN
			SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.Lgr_ID"
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" GROUP by PM.Lgr_Name,IM.Item_Name"
		END
ELSE IF @RptWise=10
		BEGIN
			SET @JOIN=""
			SET @Del="Select MAX(GST.GreyStockTrans_Id)GreyStockTrans_Id,max(GST.DocNo) as DocNo,max(GST.VchDate) as VchDate,max(PM.Lgr_Name) as PartyName,max(TM.Transport_Name)as Transport_Name
,max(SCM.City_Name) as StationName,max(IM.ITEM_NAME) as ITEM_NAME,max(WM.WEAVER_NAME) as WEAVER_NAME,Count(GSD.BaleNo) as BaleNo
,sum(GSD.BALES)as BALES,sum(GSD.PIECES)as PIECES,sum(GSD.QUANTITY) as QUANTITY,max(GSD.RATE)as RATE,max(GSD.AMOUNT) as AMOUNT,max(PCM.City_Name) as PartyCity
,SUM(GST.GrossTotal)GrossTotal,SUM(GST.AddTotal)AddTotal,SUM(GST.LessTotal)LessTotal,SUM(GST.NetTotal)NetTotal"
			SET @GROUPBY=" "
		END

END	


BEGIN
	SET NOCOUNT ON;
if @DelSumm=1
BEGIN
SELECT @SQL="
Select GST.GreyStockTrans_Id,GST.DocNo,GST.VchDate,PM.Lgr_Name as PartyName,TM.Transport_Name,SCM.City_Name as StationName,
IM.ITEM_NAME,WM.WEAVER_NAME,GSD.BaleNo,GSD.BALES,GSD.PIECES,GSD.QUANTITY,GSD.RATE,GSD.AMOUNT,PCM.City_Name as PartyCity
,GST.GrossTotal,GST.AddTotal,GST.LessTotal,GST.NetTotal
From "+@DataBase+" GreyStockTrans_Master GST
INNER JOIN "+@DataBase+" GreyStockTrans_Detail GSD on GST.GreyStockTrans_Id=GSD.GreyStockTrans_Id
LEFT join "+@DataBase+" Ledger_Master PM on GST.Lgr_Id=PM.Lgr_Id
left join "+@DataBase+" City_Master PCM on PCM.City_Id=PM.City_Id
LEFT JOIN "+@DataBase+" TRANSPORT_MASTER TM on GST.Transport_Id=TM.Transport_Id
LEFT JOIN "+@DataBase+" CITY_MASTER SCM on SCM.City_Id=GST.Station_Id
LEFT JOIN "+@DataBase+" ITEM_MASTER IM on GSD.Item_Id=IM.Item_Id
LEFT JOIN "+@DataBase+" WEAVER_MASTER WM on GSD.WEAVER_ID=WM.WEAVER_ID
"+@JOIN+"
WHERE GST.CMP_CODE IN ("+@CmpCode+") AND GST.VchDate BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
ORDER BY GST.DocNo,GST.VchDate

"
END
else 
SELECT @SQL="
"+@Del+"
From "+@DataBase+" GreyStockTrans_Master GST
INNER JOIN "+@DataBase+" GreyStockTrans_Detail GSD on GST.GreyStockTrans_Id=GSD.GreyStockTrans_Id
LEFT join "+@DataBase+" Ledger_Master PM on GST.Lgr_Id=PM.Lgr_Id
left join "+@DataBase+" City_Master PCM on PCM.City_Id=PM.City_Id
LEFT JOIN "+@DataBase+" TRANSPORT_MASTER TM on GST.Transport_Id=TM.Transport_Id
LEFT JOIN "+@DataBase+" CITY_MASTER SCM on SCM.City_Id=GST.Station_Id
LEFT JOIN "+@DataBase+" ITEM_MASTER IM on GSD.Item_Id=IM.Item_Id
LEFT JOIN "+@DataBase+" WEAVER_MASTER WM on GSD.WEAVER_ID=WM.WEAVER_ID
"+@JOIN+"
WHERE GST.CMP_CODE IN ("+@CmpCode+") AND GST.VchDate BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
"+@GROUPBY+"
"



END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GREYSTOCKOUTTRAN]    Script Date: 03/30/2023 12:08:12 ******/
