CREATE PROCEDURE [dbo].[PROC_GREYSTOCKOUTTRAN]
(
@Cmp_Code nvarchar(50), 
@DatabaseName nvarchar(50),
@FromDocNo nvarchar(50),
@ToDocNo nvarchar(50)
)
AS
DECLARE @SQL nvarchar(4000) SET @SQL=""

BEGIN
	
	SET NOCOUNT ON;
SET @SQL="
Select GST.DocNo,GST.VchDate,GST.Conf_No,GST.Conf_Date,GST.OrderNo,GST.Order_Date,PM.Lgr_Name as PartyName,
TM.Transport_Name,GST.LOTNO,GST.REMARK,GST.Result,GST.GrossTotal,GST.PiecesTotal,GST.QuantityTotal,GST.BalesTotal,GST.Add1
,GST.Add2,GST.AddTotal,GST.Less1,GST.Less2,GST.LessTotal,GST.NetTotal,GST.RoundOff,SCM.City_Name as StationName,
IM.ITEM_NAME,WM.WEAVER_NAME,GSD.BaleNo,GSD.BALES,GSD.PIECES,GSD.QUANTITY,GSD.RATE,GSD.AMOUNT,GSD.PBALENO,PCM.City_Name as PartyCity
From "+@DatabaseName+" GreyStockTrans_Master GST
INNER JOIN "+@DatabaseName+" GreyStockTrans_Detail GSD on GST.GreyStockTrans_Id=GSD.GreyStockTrans_Id
LEFT join "+@DatabaseName+" Ledger_Master PM on GST.Lgr_Id=PM.Lgr_Id
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM ON PCM.CITY_ID=PM.CITY_ID
LEFT JOIN "+@DatabaseName+" TRANSPORT_MASTER TM on GST.Transport_Id=TM.Transport_Id
LEFT JOIN "+@DatabaseName+" CITY_MASTER SCM on SCM.City_Id=GST.Station_Id
LEFT JOIN "+@DatabaseName+" ITEM_MASTER IM on GSD.Item_Id=IM.Item_Id
LEFT JOIN "+@DatabaseName+" WEAVER_MASTER WM on GSD.WEAVER_ID=WM.WEAVER_ID
WHERE GST.CMP_CODE IN ("+@Cmp_Code+") AND GST.DOCNO BETWEEN ("+@FromDocNo+") AND ("+@ToDocNo+")
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GREYSTOCKREPORT]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/* -- ============================================= 
-- ALTER_AUTHOR : BIREN 
-- ALTER_DATE   : 04/12/2014 
-- REPORT_FORM	 : RFRMGREYSTOCKREPORT.CS
-- REPORT_NAME	 : STOCKPAPERREPORT.RPT 
-- GODOWN QTY    : IF ENTRY HAS DONE IN GREY RECEIPT BUT NOT IN LOT NO ENTRY
-- TRANSPORT QTY : IF ENTRY HAS DONE IN GREY PURCHASE INVOICE BUT NOT IN GREY RECEIPT 
-- TOTAL		 : GODOWN + TRANSPORT
-- ============================================= 
SELECT * FROM TEMPDB..SYSOBJECTS
PROC_GREYSTOCKREPORT N'Acc2016_2017.DBO.', N'1', N'01/APR/2016', N'14/oct/2016', 5, N'##440' 
*/ 
CREATE PROCEDURE [dbo].[PROC_GREYSTOCKREPORT] 
( 
@DATABASENAME NVARCHAR(50), 
@CMP_CODE NVARCHAR(50), 
@FROMDATE NVARCHAR(20), 
@TODATE NVARCHAR(20), 
@RPT_TYPE INT, 
@TEMPTABLE NVARCHAR(50)
) 
AS 

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @STRJOIN AS NVARCHAR(4000) 
DECLARE @ORDERBYSQL AS NVARCHAR(4000) 
DECLARE @MAINFIELDNAME AS NVARCHAR(4000) 
DECLARE @MAINGROUPBY AS NVARCHAR(4000) 
DECLARE @SUBFIELDNAME AS NVARCHAR(4000) 
DECLARE @SUBGROUPBY AS NVARCHAR(4000) 

SET @STRSQL = "" 
SET @SQL = "" 
SET @STRJOIN= "" 
SET @ORDERBYSQL=""
SET @MAINFIELDNAME = "" 
SET @MAINGROUPBY = "" 
SET @SUBFIELDNAME= "" 
SET @SUBGROUPBY="" 



IF @RPT_TYPE=1 /* MARKA */
BEGIN SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID " 
SET @ORDERBYSQL="LOT_NAME,LOT_ID" 
SET @MAINFIELDNAME = "MAX(TRANSPORT_NAME) AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,MAX(TRANSPORT_ID) AS TRANSPORT_ID,MAX(CLOTH_TYPE_ID) AS CLOTH_TYPE_ID,LOT_ID,MAX(LRNO) AS LRNO," 
SET @MAINGROUPBY = "LOT_NAME,LOT_ID" 
SET @SUBFIELDNAME= "MAX(TM.TRANSPORT_NAME) AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,MAX(ISNULL(TM.TRANSPORT_ID,0)) AS TRANSPORT_ID,MAX(ISNULL(CTM.CLOTH_TYPE_ID,0)) AS CLOTH_TYPE_ID,MAX(TLD.LRNO) AS LRNO," 
SET @SUBGROUPBY="LM.LOT_NAME,LM.LOT_ID"
END 

IF @RPT_TYPE=2  /* TRANSPORT */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TM.TRANSPORT_ID " 
SET @ORDERBYSQL="TRANSPORT_NAME,TRANSPORT_ID,LOT_NAME,LOT_ID "
SET @MAINFIELDNAME = "TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,TRANSPORT_ID AS TRANSPORT_ID,MAX(CLOTH_TYPE_ID) AS CLOTH_TYPE_ID,LOT_ID,MAX(LRNO) AS LRNO," 
SET @MAINGROUPBY = "TRANSPORT_NAME,TRANSPORT_ID,LOT_NAME,LOT_ID" 
SET @SUBFIELDNAME= "TM.TRANSPORT_NAME AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORT_ID,MAX(ISNULL(CTM.CLOTH_TYPE_ID,0)) AS CLOTH_TYPE_ID,MAX(TLD.LRNO) AS LRNO," 
SET @SUBGROUPBY="TM.TRANSPORT_NAME,ISNULL(TM.TRANSPORT_ID,0),LM.LOT_NAME,LM.LOT_ID"  
END 

IF @RPT_TYPE=3  /* CLOTHTYPE */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.CLOTH_TYPE_ID " 
SET @ORDERBYSQL="CLOTH_TYPE_NAME,CLOTH_TYPE_ID,LOT_NAME,LOT_ID "
SET @MAINFIELDNAME = "MAX(TRANSPORT_NAME) AS TRANSPORT_NAME,CLOTH_TYPE_NAME,MAX(TRANSPORT_ID) AS TRANSPORT_ID,CLOTH_TYPE_ID AS CLOTH_TYPE_ID,LOT_ID,MAX(LRNO) AS LRNO," 
SET @MAINGROUPBY = "CLOTH_TYPE_NAME,CLOTH_TYPE_ID,LOT_NAME,LOT_ID" 
SET @SUBFIELDNAME= "MAX(TM.TRANSPORT_NAME) AS TRANSPORT_NAME,CTM.CLOTH_TYPE_NAME AS CLOTH_TYPE_NAME,MAX(ISNULL(TM.TRANSPORT_ID,0)) AS TRANSPORT_ID,ISNULL(CTM.CLOTH_TYPE_ID,0) AS CLOTH_TYPE_ID,MAX(TLD.LRNO) AS LRNO," 
SET @SUBGROUPBY="CTM.CLOTH_TYPE_NAME,ISNULL(CTM.CLOTH_TYPE_ID,0),LM.LOT_NAME,LM.LOT_ID "  
END 


IF @RPT_TYPE=4  /* LR NO, TRANSPORT */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLD.LRNO +'$'+CONVERT(NVARCHAR, TM.TRANSPORT_ID) " 
SET @ORDERBYSQL="   LRNO,TRANSPORT_NAME,TRANSPORT_ID,LOT_NAME,LOT_ID "
SET @MAINFIELDNAME = "TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,TRANSPORT_ID AS TRANSPORT_ID,MAX(CLOTH_TYPE_ID) AS CLOTH_TYPE_ID,LOT_ID,LRNO AS LRNO," 
SET @MAINGROUPBY = "TRANSPORT_NAME,TRANSPORT_ID,LOT_NAME,LOT_ID,LRNO" 
SET @SUBFIELDNAME= "TM.TRANSPORT_NAME AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORT_ID,MAX(ISNULL(CTM.CLOTH_TYPE_ID,0)) AS CLOTH_TYPE_ID,TLD.LRNO AS LRNO," 
SET @SUBGROUPBY=" TM.TRANSPORT_NAME,ISNULL(TM.TRANSPORT_ID,0),LM.LOT_NAME,LM.LOT_ID,TLD.LRNO  "  
END 

IF @RPT_TYPE=5 /* MARKA,LR NO */
BEGIN SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID " 
SET @ORDERBYSQL="LOT_NAME,LOT_ID" 
SET @MAINFIELDNAME = "MAX(TRANSPORT_NAME) AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,MAX(TRANSPORT_ID) AS TRANSPORT_ID,MAX(CLOTH_TYPE_ID) AS CLOTH_TYPE_ID,LOT_ID,LRNO," 
SET @MAINGROUPBY = "LOT_NAME,LOT_ID,LRNO" 
SET @SUBFIELDNAME= "MAX(TM.TRANSPORT_NAME) AS TRANSPORT_NAME,MAX(ISNULL(CLOTH_TYPE_NAME,'')) AS CLOTH_TYPE_NAME,MAX(ISNULL(TM.TRANSPORT_ID,0)) AS TRANSPORT_ID,MAX(ISNULL(CTM.CLOTH_TYPE_ID,0)) AS CLOTH_TYPE_ID,TLD.LRNO AS LRNO," 
SET @SUBGROUPBY="LM.LOT_NAME,LM.LOT_ID,TLD.LRNO"
END 


IF @TEMPTABLE=''
BEGIN
set @STRJOIN=""
END


BEGIN 
SET NOCOUNT ON; 

SET @SQL = "SELECT "+@MAINFIELDNAME+"LOT_NAME,SUM(GODOWN) AS GODOWN,SUM(TRANSPORT) AS TRANSPORT,
(SUM(GODOWN)+SUM(TRANSPORT)) AS TOTAL FROM (
SELECT SUM(GRD.PIECES) AS GODOWN,0 AS TRANSPORT,"+@SUBFIELDNAME+"LM.LOT_NAME,LM.LOT_ID
FROM "+@DATABASENAME+"GRAYRECEIPT_DETAIL GRD
INNER JOIN "+@DATABASENAME+"TRANSPORT_LR_DETAIL TLD ON TLD.PURCHASEINVID = GRD.PURCHASEINVID 
AND TLD.CMP_CODE = GRD.CMP_CODE AND TLD.LRNO = GRD.LRNO AND TLD.ENTRYTYPE = GRD.ENTRYTYPE
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GRD.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID = GRD.LOT_ID
LEFT JOIN "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON LM.CLOTH_TYPE_ID = CTM.CLOTH_TYPE_ID
"+@STRJOIN+"
WHERE GRD.CMP_CODE IN ("+@CMP_CODE+") AND GRD.LRNO+'$'+GRD.ENTRYTYPE+'$'+CONVERT(NVARCHAR,GRD.PURCHASEINVID) NOT IN (
SELECT LRNO+'$'+ENTRYTYPE+'$'+CONVERT(NVARCHAR,PURCHASEINVID) FROM "+@DATABASENAME+"LOTNOENTRY WHERE CMP_CODE IN ("+@CMP_CODE+"))
GROUP BY "+@SUBGROUPBY+" 
UNION ALL 
SELECT 0 AS GODOWN,SUM(TLD.PCS) AS TRANSPORT,"+@SUBFIELDNAME+"LM.LOT_NAME ,LM.LOT_ID
FROM "+@DATABASENAME+"TRANSPORT_LR_DETAIL TLD
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TLD.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID = TLD.LOT_ID
LEFT JOIN "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON LM.CLOTH_TYPE_ID = CTM.CLOTH_TYPE_ID
"+@STRJOIN+"
WHERE TLD.LRNO+'$'+CONVERT(NVARCHAR,TLD.TRANSPORT_ID)+TLD.ENTRYTYPE+'$'+CONVERT(NVARCHAR,TLD.PURCHASEINVID) 
NOT IN (SELECT GRD.LRNO+'$'+CONVERT(NVARCHAR,GRD.TRANSPORT_ID)+GRD.ENTRYTYPE+'$'+CONVERT(NVARCHAR,GRD.PURCHASEINVID)
FROM "+@DATABASENAME+"GRAYRECEIPT_DETAIL GRD 
WHERE CMP_CODE IN ("+@CMP_CODE+")) AND  TLD.CMP_CODE IN ("+@CMP_CODE+")
GROUP BY "+@SUBGROUPBY+"
) AS A GROUP BY "+@MAINGROUPBY+" ORDER BY "+@ORDERBYSQL+"
"
 
END 
PRINT @SQL EXECUTE 
SP_EXECUTESQL @SQL






















GO

