CREATE PROCEDURE [dbo].[PROC_GROUPREPORT]
(
   @CMP_CODE AS NVARCHAR(100),
   @DATABASENAME AS NVARCHAR(50),
   @ASONDATE AS NVARCHAR(15),
   @RPT_WISE AS INT,
   @TEMPTABLE AS NVARCHAR(15)
   
)
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @RPTSQL AS NVARCHAR(200)
DECLARE @JOINSQL AS NVARCHAR(200)

SET @RPTSQL=""
SET @SQL=""
SET @SQL1=""

IF @RPT_WISE =1   
 BEGIN
    SET  @RPTSQL="SG.SUPP_GRP_NAME AS MAINGROUP"
    SET  @JOINSQL="INNER JOIN  "+@DATABASENAME+" SUPPLIER_GROUP_MASTER SG ON SG.SUPP_GRP_ID=LM.SUPP_GRP_ID   INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=SG.SUPP_GRP_ID"
  END

ELSE IF @RPT_WISE =2  
  BEGIN
    SET @RPTSQL="CG.CUST_GRP_NAME AS MAINGROUP"
    SET  @JOINSQL="INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CG ON CG.CUST_GRP_ID=LM.CUST_GRP_ID   INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=CG.CUST_GRP_ID"
  END
ELSE IF @RPT_WISE =3
BEGIN
  SET @RPTSQL="GM.GRP_NAME AS MAINGROUP"
         SET  @JOINSQL=" INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID     INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=LD.GRP_ID"
END
	SET NOCOUNT ON;
     SET @SQL="                 
                 SELECT PARTYNAME,CODE,((SUM(DEBITAMOUNT)+SUM(OPDEBIT))-(SUM(CREDITAMOUNT)+SUM(OPCREDIT)))
                  AS BALANCE,CMP_ALIAS ,CITY,MAINGROUP,(CASE WHEN ((SUM(DEBITAMOUNT)+SUM(OPDEBIT))-(SUM(CREDITAMOUNT)+SUM(OPCREDIT)))>0 THEN 'DR' ELSE 'CR' END)AS DRCR FROM( 
                  SELECT LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS CODE,0 AS OPDEBIT,0 AS OPCREDIT,
                  (CASE WHEN TM.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END )AS DEBITAMOUNT,
                  (CASE WHEN TM.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END )AS CREDITAMOUNT,
                  0 AS LEDDEBIT,0 AS LEDCREDIT,CMP.CMP_ALIAS,CM.CITY_NAME AS CITY,"+@RPTSQL+"
                  FROM "+@DATABASENAME+"TRAN_MASTER TM
                  INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
                  INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
                  INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                   " +@JOINSQL+ "
                  WHERE TM.CMP_CODE IN ("+ @CMP_CODE +") AND TM.TRAN_TYPE<>'J' AND TM.TRAN_DATE<='"+@ASONDATE+"'
                  UNION ALL
                  SELECT  LM.LGR_NAME AS PARTYNAME, TD.TRAN_DETAIL_ID AS  CODE,0 AS OPDEBIT,0 AS OPCREDIT,
                  (CASE  WHEN TD.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END) AS DEBITAMOUNT,
                  (CASE  WHEN TD.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CREDITAMOUNT,
                  0 AS LEDDEBIT,0 AS LEDCREDIT,CMP.CMP_ALIAS,CM.CITY_NAME AS CITY,"+@RPTSQL+"
                  FROM  "+@DATABASENAME+"TRAN_MASTER TM
                  INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
                  INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TD.CMP_CODE
                  INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TD.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                  " +@JOINSQL+ "
                  WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +") AND TM.TRAN_DATE<='"+@ASONDATE+"'
                  UNION ALL "

SET @SQL1="
                  SELECT LM.LGR_NAME AS PARTYNAME,AJ.LGR_ID AS CODE,0 AS OPDEBIT,0 AS OPCREDIT,
                  AJ.DRAMOUNT AS DEBITAMOUNT,AJ.CRAMOUNT AS CREDITAMOUNT,0 AS LEDDEBIT,0 AS LEDCREDIT,CMP.CMP_ALIAS,CM.CITY_NAME AS CITY,"+@RPTSQL+"
                  FROM "+@DATABASENAME+"AUTOJOURNAL AJ
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID=LM.LGR_ID
                  INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AJ.CMP_CODE
                  INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                  " +@JOINSQL+ "
                  WHERE AJ.CMP_CODE IN ("+ @CMP_CODE +") AND AJ.VDATE<='"+@ASONDATE+"'
                  UNION ALL
                  SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ID,
                  (CASE WHEN LD.LGR_OP_DRCR='D' OR  LD.LGR_OP_DRCR='' THEN LD.LGR_OP_BAL ELSE 0 END) AS OPDEBIT,
                  (CASE WHEN LD.LGR_OP_DRCR='C' OR  LD.LGR_OP_DRCR='' THEN LD.LGR_OP_BAL ELSE 0 END) AS OPCREDIT,
                  0 AS DEBITAMOUNT,0 AS CREDITAMOUNT,0 AS LEDDEBIT,0 AS LEDCREDIT,CMP.CMP_ALIAS,CM.CITY_NAME AS CITY,"+@RPTSQL+"
                  FROM "+@DATABASENAME+"LEDGER_MASTER LM 
                  INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID
                  INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LD.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                  " +@JOINSQL+ "
                  WHERE LD.CMP_CODE IN ("+ @CMP_CODE +")
                  ) AS BALANCE  GROUP BY PARTYNAME,CODE,CMP_ALIAS,CITY,MAINGROUP
                HAVING ((SUM(DEBITAMOUNT)+SUM(OPDEBIT))-(SUM(CREDITAMOUNT)+SUM(OPCREDIT)))<>0"


    
END
EXEC ( @SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

