/*
PROC_GROUPREPORT_SUMMARY '1','ACC2012_2013.DBO.','03/OCT/2012',1,'##1680','01/APR/2011',2
*/
CREATE PROCEDURE [dbo].[PROC_GROUPREPORT_SUMMARY]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(50),
@ASONDATE AS NVARCHAR(15),
@RPT_WISE AS INT,
@TEMPTABLE AS NVARCHAR(15),
@STARTDATE AS NVARCHAR(15),
@RECVCHDATE INT   
)
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @RPTSQL AS NVARCHAR(200)
DECLARE @JOINSQL AS NVARCHAR(200)
DECLARE @NETSQL AS NVARCHAR(4000)
DECLARE @STRRECVCHDATE AS NVARCHAR(4000) SET @STRRECVCHDATE =""
DECLARE @STRRPTWISE AS NVARCHAR(4000)

SET @RPTSQL=""
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @NETSQL=""
SET @STRRPTWISE = ""

IF @RECVCHDATE=1-- RECDATE
SET @STRRECVCHDATE=" AND PI.RECDATE <='"+@ASONDATE+"'"
ELSE IF @RECVCHDATE=2-- VCHDATE
SET @STRRECVCHDATE=" AND PI.VCHDATE <='"+@ASONDATE+"'"

IF @RPT_WISE =1   
BEGIN
SET  @RPTSQL="SG.SUPP_GRP_NAME AS MAINGROUP, SG.SUPP_GRP_ID as MAINGROUPID "
SET  @JOINSQL="INNER JOIN  "+@DATABASENAME+" SUPPLIER_GROUP_MASTER SG ON SG.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=SG.SUPP_GRP_ID"
SET @NETSQL=" UNION ALL
SELECT 0 AS BALANCE,MAINGROUP,MAINGROUPID, (CASE WHEN SUM(NETTOTAL)>0 THEN 'DR' ELSE 'CR' END) AS DRCR,SUM(NETTOTAL) AS NETTOTAL,0 AS DEBITAMOUNT ,0 AS CREDITAMOUNT ,0 AS DRPRODUCT,0 AS CRPRODUCT 
FROM(
SELECT SUM(NETTOTAL) AS NETTOTAL,SG.SUPP_GRP_NAME AS MAINGROUP, SG.SUPP_GRP_ID as MAINGROUPID
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID            
" +@JOINSQL+ "
WHERE PI.CMP_CODE IN  ("+ @CMP_CODE +") "+@STRRECVCHDATE+"
GROUP BY SG.SUPP_GRP_NAME, SG.SUPP_GRP_ID
UNION ALL
SELECT (0-SUM(NETTOTAL)) AS NETTOTAL,SG.SUPP_GRP_NAME AS MAINGROUP,SG.SUPP_GRP_ID as MAINGROUPID
FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PR
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PR.LGR_ID            
" +@JOINSQL+ "
WHERE PR.CMP_CODE IN  ("+ @CMP_CODE +") AND PR.PUR_RET_DATE<='"+@ASONDATE+"'
GROUP BY SG.SUPP_GRP_NAME,SG.SUPP_GRP_ID) AS D1 GROUP BY MAINGROUP,MAINGROUPID"

SET @STRRPTWISE = "  SELECT SUM(BALANCE)AS BALANCE,MAINGROUP,MAINGROUPID,(CASE WHEN SUM(BALANCE)>0 THEN 'DR'ELSE 'CR' END)AS DRCR,SUM(NETSALE_PURCHAE)AS NETSALE_PURCHAE,
SUM(DEBITAMOUNT) AS DEBITAMOUNT ,SUM(CREDITAMOUNT) AS CREDITAMOUNT,
(CASE WHEN SUM(NETSALE_PURCHAE)>0 THEN (((SUM(CRPRODUCT)-SUM(DRPRODUCT)))*30/SUM(NETSALE_PURCHAE))  ELSE 0  END)AS  AVGDAYS
FROM(  "
END

ELSE IF @RPT_WISE =2  
BEGIN
SET @RPTSQL="CG.CUST_GRP_NAME AS MAINGROUP, CG.CUST_GRP_ID as MAINGROUPID "
SET  @JOINSQL="INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CG ON CG.CUST_GRP_ID=LM.CUST_GRP_ID  
INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=CG.CUST_GRP_ID"
SET @NETSQL=" UNION ALL
SELECT 0 AS BALANCE,MAINGROUP,MAINGROUPID,(CASE WHEN SUM(NETTOTAL)>0 THEN 'DR' ELSE 'CR' END)  AS DRCR,SUM(NETTOTAL) AS NETTOTAL,0 AS DEBITAMOUNT ,0 AS CREDITAMOUNT,0 AS DRPRODUCT,0 AS CRPRODUCT  
FROM(
SELECT SUM(SAL_INV_NETTOTAL) AS NETTOTAL,CG.CUST_GRP_NAME AS MAINGROUP, CG.CUST_GRP_ID as MAINGROUPID
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID                 
" +@JOINSQL+ "
WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +") AND SI.SAL_INV_VDATE<='"+@ASONDATE+"'
GROUP BY CG.CUST_GRP_NAME, CG.CUST_GRP_ID
UNION ALL
SELECT (0-SUM(NETTOTAL)) AS NETTOTAL,CG.CUST_GRP_NAME AS MAINGROUP,CG.CUST_GRP_ID as MAINGROUPID
FROM "+@DATABASENAME+"SALES_RETURN_MASTER SR
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SR.LGR_ID                 
" +@JOINSQL+ "
WHERE SR.CMP_CODE IN  ("+ @CMP_CODE +") AND SR.SAL_RET_DATE<='"+@ASONDATE+"'
GROUP BY CG.CUST_GRP_NAME, CG.CUST_GRP_ID) AS D1 GROUP BY MAINGROUP,MAINGROUPID"


SET @STRRPTWISE = "  SELECT SUM(BALANCE)AS BALANCE,MAINGROUP,MAINGROUPID,(CASE WHEN SUM(BALANCE)>0 THEN 'DR'ELSE 'CR' END)AS DRCR,SUM(NETSALE_PURCHAE)AS NETSALE_PURCHAE,
SUM(DEBITAMOUNT) AS DEBITAMOUNT ,SUM(CREDITAMOUNT) AS CREDITAMOUNT,
(CASE WHEN SUM(NETSALE_PURCHAE)>0 THEN (((SUM(DRPRODUCT)-SUM(CRPRODUCT)))*30/SUM(NETSALE_PURCHAE))  ELSE 0  END)AS  AVGDAYS
FROM(  "
END
ELSE IF @RPT_WISE =3
BEGIN
SET @RPTSQL="GM.GRP_NAME AS MAINGROUP, GM.GRP_ID as MAINGROUPID "
SET  @JOINSQL=" INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=LD.GRP_ID"

SET @STRRPTWISE = "  SELECT SUM(BALANCE)AS BALANCE,MAINGROUP,MAINGROUPID,(CASE WHEN SUM(BALANCE)>0 THEN 'DR'ELSE 'CR' END)AS DRCR,SUM(NETSALE_PURCHAE)AS NETSALE_PURCHAE,
SUM(DEBITAMOUNT) AS DEBITAMOUNT ,SUM(CREDITAMOUNT) AS CREDITAMOUNT,
(CASE WHEN SUM(NETSALE_PURCHAE)>0 THEN (((SUM(DRPRODUCT)-SUM(CRPRODUCT)))*30/SUM(NETSALE_PURCHAE))  ELSE 0  END)AS  AVGDAYS
FROM(  "
END


SET NOCOUNT ON;
SET @SQL="      
"+@STRRPTWISE+"           
SELECT (SUM(DEBITAMOUNT)-SUM(CREDITAMOUNT))
AS BALANCE,MAINGROUP,MAINGROUPID,(CASE WHEN ((SUM(DEBITAMOUNT))-(SUM(CREDITAMOUNT)))>0 THEN 'DR' ELSE 'CR' END)AS DRCR,0 AS NETSALE_PURCHAE                  
,(SUM(DEBITAMOUNT)) AS DEBITAMOUNT ,(SUM(CREDITAMOUNT)) AS CREDITAMOUNT  
,SUM(DRPRODUCT) AS DRPRODUCT,SUM(CRPRODUCT) AS CRPRODUCT
FROM( 
SELECT LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS CODE,
(CASE WHEN TM.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END )AS DEBITAMOUNT,
(CASE WHEN TM.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END )AS CREDITAMOUNT,
"+@RPTSQL+" 
,CASE WHEN TM.TRAN_DRCR = 'D' THEN ((DATEDIFF(DAY, TM.TRAN_DATE ,'" + @ASONDATE + "')+1)*TM.TRAN_AMOUNT)/30  ELSE 0 END DRPRODUCT, 
CASE WHEN TM.TRAN_DRCR = 'C' THEN ((DATEDIFF(DAY, TM.TRAN_DATE ,'" + @ASONDATE + "')+1)*TM.TRAN_AMOUNT)/30  ELSE 0 END AS CRPRODUCT
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID                  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE                  
" +@JOINSQL+ "
WHERE TM.CMP_CODE IN ("+ @CMP_CODE +") AND TM.TRAN_TYPE<>'J' AND TM.TRAN_DATE<='"+@ASONDATE+"'
UNION ALL
SELECT  LM.LGR_NAME AS PARTYNAME, TD.TRAN_DETAIL_ID AS  CODE,
(CASE  WHEN TD.TRAN_DRCR='D' THEN TD.TRAN_AMOUNT ELSE 0 END) AS DEBITAMOUNT,
(CASE  WHEN TD.TRAN_DRCR='C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CREDITAMOUNT,
"+@RPTSQL+"
,CASE WHEN TD.TRAN_DRCR = 'D' THEN ((DATEDIFF(DAY, TM.TRAN_DATE ,'" + @ASONDATE + "')+1)*TD.TRAN_AMOUNT)/30  ELSE 0 END DRPRODUCT, 
CASE WHEN TD.TRAN_DRCR = 'C' THEN ((DATEDIFF(DAY, TM.TRAN_DATE ,'" + @ASONDATE + "')+1)*TD.TRAN_AMOUNT)/30  ELSE 0 END AS CRPRODUCT
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID                  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TD.CMP_CODE                  
" +@JOINSQL+ "
WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +") AND TM.TRAN_DATE<='"+@ASONDATE+"'
UNION ALL "

SET @SQL1="
SELECT LM.LGR_NAME AS PARTYNAME,AJ.LGR_ID AS CODE,
AJ.DRAMOUNT AS DEBITAMOUNT,AJ.CRAMOUNT AS CREDITAMOUNT,"+@RPTSQL+"
,CASE WHEN AJ.DRAMOUNT>=0 THEN ((DATEDIFF(DAY,AJ.VDATE,'" + @ASONDATE + "')+1)*AJ.DRAMOUNT)/30 ELSE 0 END DRPRODUCT,
CASE WHEN AJ.CRAMOUNT>0 THEN ((DATEDIFF(DAY,AJ.VDATE,'" + @ASONDATE + "')+1)*AJ.CRAMOUNT)/30 ELSE 0 END AS CRPRODUCT
FROM "+@DATABASENAME+"AUTOJOURNAL AJ
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID=LM.LGR_ID                  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE                  
" +@JOINSQL+ "
WHERE AJ.CMP_CODE IN ("+ @CMP_CODE +") AND AJ.VDATE<='"+@ASONDATE+"'
UNION ALL
SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ID,
(CASE WHEN LD.LGR_OP_DRCR='D' OR  LD.LGR_OP_DRCR='' THEN LD.LGR_OP_BAL ELSE 0 END) AS DEBITAMOUNT,
(CASE WHEN LD.LGR_OP_DRCR='C' OR  LD.LGR_OP_DRCR='' THEN LD.LGR_OP_BAL ELSE 0 END) AS CREDITAMOUNT,
"+@RPTSQL+"
,CASE WHEN LD.LGR_OP_DRCR = 'D' THEN ((DATEDIFF(DAY, '"+ @STARTDATE +"','" + @ASONDATE + "')+1)*LD.LGR_OP_BAL)/30  ELSE 0 END DRPRODUCT, 
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN ((DATEDIFF(DAY,'"+ @STARTDATE +"','" + @ASONDATE + "')+1)*LD.LGR_OP_BAL)/30  ELSE 0 END AS CRPRODUCT
FROM "+@DATABASENAME+"LEDGER_MASTER LM 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID                 

" +@JOINSQL+ "
WHERE LD.CMP_CODE IN ("+ @CMP_CODE +")
) AS BALANCE  GROUP BY MAINGROUP,MAINGROUPID
HAVING ((SUM(DEBITAMOUNT))-(SUM(CREDITAMOUNT)))<>0                
" +@NETSQL+ ""

SET @SQL2=") AS DETAIL1 GROUP BY MAINGROUP,MAINGROUPID ORDER BY MAINGROUP,MAINGROUPID"

END
EXEC ( @SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_3B_EXPENCES_DETAIL]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*
-- =============================================
-- Author:		PRATIK PATEL
-- Create_date: 02-06-2018
-- Description:	THIS PROCEDURE USED IN GST 3B EXPENCES DETAIL REPORT
-- REPORT NAME:  GST_SUMMARY_3B
PROC_GST_3B_EXPENCES_DETAIL N'01/APR/2018', N'02/JUN/2018', N'ACC2018_2019.Dbo.', N'1','COMPOSITION DEALER'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_3B_EXPENCES_DETAIL]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100),
	@GST_TYPE NVARCHAR(100)     
)
AS
SET NOCOUNT ON;

DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @GSTTYPESQL AS NVARCHAR(4000)

SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @GSTTYPESQL="" 

BEGIN
	IF @GST_TYPE="ALL"
		SET @GSTTYPESQL=""
	ELSE
		SET @GSTTYPESQL	=" AND GST_TYPE='"+@GST_TYPE+"'"
		
END

BEGIN 
	SET @SQL1="SELECT * FROM (
SELECT PUR.GST_TYPE,BILLNO,VCHDATE,LM.LGR_NAME,NETTOTAL,NETTOTAL AS OUTERSTATE ,0 AS INNERSTATE,PUR.FLAG,LCM.CITY_NAME
FROM  "+@DATABASENAME+"PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PUR.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'
"+@GSTTYPESQL+"
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND ((PUR.FLAG IN ('CHP')AND PUR.PUR_FORM_TYPE = 'A') OR PUR.FLAG IN ('MIP')) 
AND ISNULL(CM.CMP_STATECODE,'')<>ISNULL(SM.STATE_CODE,'')

UNION ALL

SELECT PUR.GST_TYPE,BILLNO,VCHDATE,LM.LGR_NAME,NETTOTAL,0 AS OUTERSTATE, NETTOTAL AS INNERSTATE,PUR.FLAG,LCM.CITY_NAME
FROM  "+@DATABASENAME+"PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PUR.LGR_ID 
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'
"+@GSTTYPESQL+"
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND ((PUR.FLAG IN ('CHP')AND PUR.PUR_FORM_TYPE = 'A') OR PUR.FLAG IN ('MIP')) 
AND ISNULL(CM.CMP_STATECODE,'')=ISNULL(SM.STATE_CODE,'')

"

	SET @SQL2="UNION ALL
SELECT TM.GST_TYPE,TM.TRAN_DOCNO,TRAN_DATE,LM.LGR_NAME,TM.TRAN_AMOUNT,/*TM.TRAN_AMOUNT AS OUTERSTATE,*/
(CASE WHEN TM.GST_TYPE='NON GST SUPPLY' THEN 0 ELSE TM.TRAN_AMOUNT END)OUTERSTATE,
(CASE WHEN TM.GST_TYPE='NON GST SUPPLY' THEN TM.TRAN_AMOUNT ELSE 0 END)INNERSTATE,
/*0 AS INNERSTATE,*/TM.TRAN_TYPE,LCM.CITY_NAME
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD  ON TD.TRAN_ID=TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE
INNER JOIN  "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
INNER JOIN  "+@DATABASENAME+" LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE = TD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND TM.TRAN_TYPE IN('CP','BP')
"+@GSTTYPESQL+"
AND ISNULL(CM.CMP_STATECODE,'')<>ISNULL(SM.STATE_CODE,'')
--AND TM.GST_TYPE IN ('NIL RATED SUPPLY','GST EXEMPTED SUPPLY')
AND  TM.CMP_CODE IN("+@CMP_CODE+") 

 UNION ALL
SELECT TM.GST_TYPE,TM.TRAN_DOCNO,TRAN_DATE,LM.LGR_NAME,TM.TRAN_AMOUNT,
0 AS OUTERSTATE,TM.TRAN_AMOUNT AS INNERSTATE,TM.TRAN_TYPE,LCM.CITY_NAME
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD  ON TD.TRAN_ID=TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE = TD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND TM.TRAN_TYPE IN('CP','BP')
"+@GSTTYPESQL+"
AND ISNULL(CM.CMP_STATECODE,'')=ISNULL(SM.STATE_CODE,'')
AND  TM.CMP_CODE IN("+@CMP_CODE+") 
"

	SET @SQL3="UNION ALL
SELECT TM.GST_TYPE,TM.TRAN_DOCNO,TRAN_DATE,LM.LGR_NAME,TM.TRAN_AMOUNT,/*TM.TRAN_AMOUNT AS OUTERSTATE,*/
(CASE WHEN TM.GST_TYPE='NON GST SUPPLY' THEN 0 ELSE TM.TRAN_AMOUNT END)OUTERSTATE,
(CASE WHEN TM.GST_TYPE='NON GST SUPPLY' THEN TM.TRAN_AMOUNT ELSE 0 END)INNERSTATE,
/*0 AS INNERSTATE,*/TM.TRAN_TYPE,LCM.CITY_NAME
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD  ON TD.TRAN_ID=TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE = TD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND TM.TRAN_TYPE IN('J') AND TD.TRAN_DRCR ='D'
"+@GSTTYPESQL+"
AND ISNULL(CM.CMP_STATECODE,'')<>ISNULL(SM.STATE_CODE,'')
AND  TM.CMP_CODE IN("+@CMP_CODE+") 

 UNION ALL
SELECT TM.GST_TYPE,TM.TRAN_DOCNO,TRAN_DATE,LM.LGR_NAME,TM.TRAN_AMOUNT,0 AS OUTERSTATE,TM.TRAN_AMOUNT AS INNERSTATE,TM.TRAN_TYPE,LCM.CITY_NAME
FROM  "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
INNER JOIN  "+@DATABASENAME+"TRAN_DETAIL TD  ON TD.TRAN_ID=TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE = TD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
WHERE TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND TM.TRAN_TYPE IN('J') AND TD.TRAN_DRCR ='D'
"+@GSTTYPESQL+"
AND ISNULL(CM.CMP_STATECODE,'')=ISNULL(SM.STATE_CODE,'')
AND  TM.CMP_CODE IN("+@CMP_CODE+") 
 
 
 ) AS DETAIL
 ORDER BY GST_TYPE,VCHDATE,BILLNO/*CONVERT(INT,BILLNO)*/
 "


END

EXEC (@SQL1+@SQL2+@SQL3)

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3













GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_INNER_STATEWISE_SUMMARY]    Script Date: 03/30/2023 12:08:12 ******/
