/*
-- =============================================
-- Author:		SHUBHAM RAVAL
-- Create_date: 16-09-2017
-- Description:	THIS PROCEDURE USED IN GST SUMMARY  REPORT
-- REPORT NAME:  GST_SUMMARY_3B_STATEWISE SUBREPORT
PROC_GST_PAYMENTOFTAX N'01/MAR/2018', N'31/MAR/2018', N'ACC2017_2018.Dbo.', N'1'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_PAYMENTOFTAX]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100)    
)
AS
DECLARE @SQL1A AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL7A AS NVARCHAR(4000)
DECLARE @SQL7B AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL9A AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
DECLARE @SQL12 AS NVARCHAR(4000)
DECLARE @SQL13 AS NVARCHAR(4000)
DECLARE @SQL14 AS NVARCHAR(4000)
DECLARE @SQL15 AS NVARCHAR(4000)
DECLARE @SQL16 AS NVARCHAR(4000)
DECLARE @SQL17 AS NVARCHAR(4000)
DECLARE @SQLMONTH AS NVARCHAR(4000)

		BEGIN	
		set @SQLMONTH="( SELECT (DATEPART(month,DATEADD(month, -1, '"+@FROMDATE+"'))) ) " 		
		END
BEGIN

SET @SQL1A = "
SELECT (SUM(IGSTOUT) - SUM(IGSTITC)) AS IGST,MAX(IGSTITC)IGSTITC,MAX(IGSTOUT)IGSTOUT,(SUM(CGSTOUT) - SUM(CGSTITC)) AS CGST,MAX(CGSTITC)CGSTITC,MAX(CGSTOUT)CGSTOUT
,(SUM(SGSTOUT) - SUM(SGSTITC)) AS SGST,MAX(SGSTITC)SGSTITC,MAX(SGSTOUT)SGSTOUT,
0 AS CGSTRP,0 AS SGSTRP,0 AS IGSTRP
 FROM ( "
 SET @SQL1 = " /* -- PART 1 FOR A+B  */ 
  SELECT MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,
(SUM(CGSTAA) + SUM(CGSTDD)) AS CGSTITC,
(SUM(SGSTAA)  + SUM(SGSTDD)) AS SGSTITC,(SUM(IGSTAA) + SUM(IGSTDD)) AS IGSTITC,(SUM(TOTALTAXAA)+SUM(TOTALTAXDD)) TOTALTAXITC,
0 AS CGSTOUT,0 AS SGSTOUT,0 AS IGSTOUT,0 AS TOTALTAXOUT,
'P' FLAG,8 as TYPE,'E' DATATYPE
 ,'Inward' AS SDS,'AA' AS BLOCK
FROM ( "
SET @SQL2 = "SELECT   MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,
SUM(OUTER_STATE_SUPPLY)OUTER_STATE_SUPPLY,SUM(INTER_STATE_SUPPLY)INTER_STATE_SUPPLY,
SUM(AMOUNTAA)AMOUNTAA,SUM(CGSTAA)CGSTAA,SUM(SGSTAA)SGSTAA,SUM(IGSTAA)IGSTAA,SUM(TOTALTAXAA)TOTALTAXAA,
SUM(AMOUNTDD)AMOUNTDD,SUM(CGSTDD)CGSTDD,SUM(SGSTDD)SGSTDD,SUM(IGSTDD)IGSTDD,SUM(TOTALTAXDD)TOTALTAXDD,
MAX(FLAG)FLAG,TYPE,MAX(DATATYPE)DATATYPE
 ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE ,0 AS TOTAL,'(3)Inward supplies liable to reverse charge (other
than 1 & 2 above)' AS SDS,'AA' AS BLOCK
FROM (
"
SET @SQL3 = "
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
(ISNULL(SUM(TOTALFARE_AMOUNT),0)) AS AMOUNTAA,
ISNULL(SUM(TRM.CGST),0) AS CGSTAA, ISNULL(SUM(TRM.SGST ),0)  AS SGSTAA , ISNULL(SUM(TRM.IGST ),0)  AS IGSTAA ,
(ISNULL(SUM(TRM.CGST),0) + ISNULL(SUM(TRM.SGST ),0) + ISNULL(SUM(TRM.IGST ),0)) TOTALTAXAA,
0 AS AMOUNTDD,0 AS  CGSTDD,0 AS  SGSTDD,0 AS IGSTDD,0 AS TOTALTAXDD,
'P' AS FLAG,3 TYPE ,'C' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
FROM "+@DATABASENAME+" TRANSPORT_PAYMENT TRM		
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=TRM.CMP_CODE 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=TRM.PurAccount_Id
WHERE DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  TRM.CMP_CODE IN("+@CMP_CODE+")
GROUP BY CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME UNION  ALL

"
SET @SQL4 = " 	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNTAA,
  ISNULL(SUM(PURD.vat_amt),0)  AS CGSTAA,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGSTAA ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGSTAA 	,
(ISNULL(SUM(PURD.vat_amt),0) + ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) AS TOTALTAXAA,
0 AS AMOUNTDD,0 AS  CGSTDD,0 AS  SGSTDD,0 AS IGSTDD,0 AS TOTALTAXDD,
'P' AS FLAG,3 TYPE ,'C' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='RP'
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
) AS DETAIL1
GROUP BY TYPE
"
SET @SQL5 = "UNION ALL  
 SELECT MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,
SUM(OUTER_STATE_SUPPLY)OUTER_STATE_SUPPLY,SUM(INTER_STATE_SUPPLY)INTER_STATE_SUPPLY,
(SUM(AMOUNTPUR)- SUM(AMOUNTPURRE))AMOUNTAA,
(SUM(CGSTPUR) - SUM(CGSTPURRE))CGSTAA,(SUM(SGSTPUR) - SUM(SGSTPURRE))SGSTAA,(SUM(IGSTPUR) - SUM(IGSTPURRE))IGSTAA,
(SUM(TOTALTAXPUR) - SUM(TOTALTAXPURRE))TOTALTAXAA,
0 AS AMOUNTDD,0 AS CGSTDD,0 AS SGSTDD,0 AS IGSTDD,0 AS TOTALTAXDD,
MAX(FLAG)FLAG,TYPE,MAX(DATATYPE)DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE ,0 AS TOTAL,'(5)All other ITC' AS SDS,'AA' AS BLOCK
FROM ( SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,ISNULL(SUM(GrossTotal),0) +
		  (ISNULL(SUM(PUR.PUR_INV_ADD1),0) 
 + ISNULL(SUM(PUR.PUR_INV_ADD2),0) 
 + ISNULL(SUM(PUR.PUR_INV_ADD3),0) )
-(
+(ISNULL(SUM(PUR.Pur_Inv_Less1),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less2),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less3),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less4),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less5),0)) 
) AS AMOUNTPUR,
(ISNULL(SUM(PUR.PUR_INV_ADD4),0)) AS CGSTPUR,(ISNULL(SUM(PUR.PUR_INV_ADD5 ),0)) AS SGSTPUR ,
(ISNULL(SUM(PUR.PUR_INV_ADD6 ),0)) AS IGSTPUR ,(ISNULL(SUM(PUR.PUR_INV_ADD4),0) + ISNULL(SUM(PUR.PUR_INV_ADD5 ),0) + ISNULL(SUM(PUR.PUR_INV_ADD6 ),0)) AS TOTALTAXPUR,0 AS AMOUNTPURRE,0 AS CGSTPURRE,0 AS SGSTPURRE,0 AS IGSTPURRE,0 AS TOTALTAXPURRE,
'P' AS FLAG,5 TYPE ,'E' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
		FROM "+@DATABASENAME+"PURCHASEINVOICE PUR
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PUR.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('P','JP','FP')
		GROUP BY CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
"
SET @SQL6 = "UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNTPUR, ISNULL(SUM(PURD.vat_amt),0)  AS CGSTPUR,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGSTPUR ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGSTPUR 	,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAXPUR,
0 AS AMOUNTPURRE,0 AS CGSTPURRE,0 AS SGSTPURRE,0 AS IGSTPURRE,0 AS TOTALTAXPURRE,
'P' AS FLAG,5 TYPE ,'E' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND (PUR.GST_TYPE <> 'InEligible ITC' or ISNULL(PUR.GST_TYPE,'') = '')
		GROUP BY  PUR.In_Outer_State,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO
"
SET @SQL7 = " UNION  ALL
 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
0 AS AMOUNTPUR,0 AS CGSTPUR,0 AS SGSTPUR,0 AS IGSTPUR,0 AS TOTALTAXPUR,
ISNULL(SUM(GrossTotal),0) +
		(ISNULL(SUM(PURRET.PUR_RET_ADD1),0) 
		+ISNULL(SUM(PURRET.PUR_RET_ADD2),0)
		+ISNULL(SUM(PURRET.PUR_RET_ADD3),0)
)-(+(ISNULL(SUM(PURRET.Pur_Ret_Less1),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less2),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less3),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less4),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less5),0))
 ) AS AMOUNTPURRE,
(ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0)) AS CGSTPURRE,
		(ISNULL(SUM(PURRET.PUR_RET_ADD5 ),0)) AS SGSTPURRE, 
		(ISNULL(SUM(PURRET.PUR_RET_ADD6 ),0)) AS IGSTPURRE,
