SET @SQL11 = " SELECT MAX(CMPNAME) AS CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX
(CSTNNO)CSTNNO, SUM(INTER_STATE_SUPPLYCOMPO) AS SUPPLYCOMPO
,SUM(INTER_STATE_SUPPLYEXEMPTED) AS SUPPLYEXEMPTED,
SUM(INTER_STATE_SUPPLYNILRATED) AS SUPPLYNILRATED,
SUM(INTER_STATE_SUPPLYNONGST) AS SUPPLYNONGST ,'Inter-State Supply' AS TYPE
FROM(
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
ISNULL(SUM(NETTOTAL),0) AS 'INTER_STATE_SUPPLYCOMPO',0 AS 'INTER_STATE_SUPPLYEXEMPTED',
0 AS 'INTER_STATE_SUPPLYNILRATED', 0 AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',	
(ISNULL(SUM(PUR.GrossTotal),0) +ISNULL(SUM(PUR.Pur_Inv_Add1),0) + ISNULL(SUM(PUR.Pur_Inv_Add2),0)+ ISNULL(SUM(PUR.Pur_Inv_Add3),0) -( ISNULL(SUM(PUR.Pur_Inv_Less1),0)
+ ISNULL(SUM(PUR.Pur_Inv_Less2),0) + ISNULL(SUM(PUR.Pur_Inv_Less3),0) + ISNULL(SUM(PUR.Pur_Inv_Less4),0)+ ISNULL(SUM(PUR.Pur_Inv_Less5),0))) AS AMOUNT ,0 AS CGST,0  AS SGST ,0  AS IGST ,0 AS TOTALTAX,'P' AS FLAG,1 AS TYPE,'A' DATATYPE
FROM  "+@DATABASENAME+"     PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"     COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"      LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id 
left JOIN   "+@DATABASENAME+"      LEDGER_MASTER LM1 ON LM1.LGR_ID=PUR.PurACcId
LEFT JOIN  "+@DATABASENAME+"      STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('CHP') AND  PUR.PUR_FORM_TYPE = 'A' AND PUR.GST_TYPE IN ('COMPOSITION DEALER')
AND CM.CMP_STATECODE <> SM.STATE_CODE 
GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO
"
SET @SQL12="UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS 'INTER_STATE_SUPPLYCOMPO',ISNULL(SUM(NETTOTAL),0) AS 'INTER_STATE_SUPPLYEXEMPTED',
0 AS 'INTER_STATE_SUPPLYNILRATED', 0 AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',
(ISNULL(SUM(PUR.GrossTotal),0) +ISNULL(SUM(PUR.Pur_Inv_Add1),0) + ISNULL(SUM(PUR.Pur_Inv_Add2),0)+ ISNULL(SUM(PUR.Pur_Inv_Add3),0) -( ISNULL(SUM(PUR.Pur_Inv_Less1),0)
+ ISNULL(SUM(PUR.Pur_Inv_Less2),0) + ISNULL(SUM(PUR.Pur_Inv_Less3),0) + ISNULL(SUM(PUR.Pur_Inv_Less4),0)+ ISNULL(SUM(PUR.Pur_Inv_Less5),0))) AS AMOUNT ,0 AS CGST,0  AS SGST ,0  AS IGST ,0 AS TOTALTAX,'P' AS FLAG,1 AS TYPE,'A' DATATYPE
FROM  "+@DATABASENAME+"     PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"     COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"      LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id 
left JOIN   "+@DATABASENAME+"      LEDGER_MASTER LM1 ON LM1.LGR_ID=PUR.PurACcId
LEFT JOIN  "+@DATABASENAME+"      STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('CHP') AND  PUR.PUR_FORM_TYPE = 'A' AND PUR.GST_TYPE IN ('GST EXEMPTED SUPPLY')
AND CM.CMP_STATECODE <> SM.STATE_CODE 
GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO

"
SET @SQL13 =" UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS 'INTER_STATE_SUPPLYCOMPO',0 AS 'INTER_STATE_SUPPLYEXEMPTED',
ISNULL(SUM(NETTOTAL),0) AS 'INTER_STATE_SUPPLYNILRATED', 0 AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',	
(ISNULL(SUM(PUR.GrossTotal),0) +ISNULL(SUM(PUR.Pur_Inv_Add1),0) + ISNULL(SUM(PUR.Pur_Inv_Add2),0)+ ISNULL(SUM(PUR.Pur_Inv_Add3),0) -( ISNULL(SUM(PUR.Pur_Inv_Less1),0)
+ ISNULL(SUM(PUR.Pur_Inv_Less2),0) + ISNULL(SUM(PUR.Pur_Inv_Less3),0) + ISNULL(SUM(PUR.Pur_Inv_Less4),0)+ ISNULL(SUM(PUR.Pur_Inv_Less5),0))) AS AMOUNT ,0 AS CGST,0  AS SGST ,0  AS IGST ,0 AS TOTALTAX,'P' AS FLAG,1 AS TYPE,'A' DATATYPE
FROM  "+@DATABASENAME+"     PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"     COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"      LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id 
left JOIN   "+@DATABASENAME+"      LEDGER_MASTER LM1 ON LM1.LGR_ID=PUR.PurACcId
LEFT JOIN  "+@DATABASENAME+"      STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('CHP') AND  PUR.PUR_FORM_TYPE = 'A' AND PUR.GST_TYPE IN ('NIL RATED SUPPLY')
AND CM.CMP_STATECODE <> SM.STATE_CODE 
GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO
"

SET @SQL14 ="
UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS 'INTER_STATE_SUPPLYCOMPO',0 AS 'INTER_STATE_SUPPLYEXEMPTED',
0 AS 'INTER_STATE_SUPPLYNILRATED', ISNULL(SUM(NETTOTAL),0) AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',
(ISNULL(SUM(PUR.GrossTotal),0) +ISNULL(SUM(PUR.Pur_Inv_Add1),0) + ISNULL(SUM(PUR.Pur_Inv_Add2),0)+ ISNULL(SUM(PUR.Pur_Inv_Add3),0) -( ISNULL(SUM(PUR.Pur_Inv_Less1),0)
+ ISNULL(SUM(PUR.Pur_Inv_Less2),0) + ISNULL(SUM(PUR.Pur_Inv_Less3),0) + ISNULL(SUM(PUR.Pur_Inv_Less4),0)+ ISNULL(SUM(PUR.Pur_Inv_Less5),0))) AS AMOUNT ,0 AS CGST,0  AS SGST ,0  AS IGST ,0 AS TOTALTAX,'P' AS FLAG,2 AS TYPE,'B' DATATYPE
FROM  "+@DATABASENAME+"    PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"    COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"    LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id 
left JOIN  "+@DATABASENAME+"      LEDGER_MASTER LM1 ON LM1.LGR_ID=PUR.PurACcId
LEFT JOIN  "+@DATABASENAME+"     STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('CHP') 
 AND PUR.PUR_FORM_TYPE = 'A' AND
CM.CMP_STATECODE <> SM.STATE_CODE AND PUR.GST_TYPE = 'NON GST SUPPLY'
--AND lm1.Gst_Supply_Type IN('Non Gst Inward Supplies')
GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO
"

SET @SQL14A=" UNION ALL

SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS 'INTER_STATE_SUPPLYCOMPO',0 AS 'INTER_STATE_SUPPLYEXEMPTED',
ISNULL(SUM(PURD.Amount),0) AS 'INTER_STATE_SUPPLYNILRATED', 0 AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST ,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAX,
'P' AS FLAG,9 TYPE ,'I' DATATYPE 
		FROM  "+@DATABASENAME+"  PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+"  PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id
		LEFT JOIN  "+@DATABASENAME+"    STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		LEFT JOIN  "+@DATABASENAME+"    Item_Master IM ON PURD.Item_Id=IM.Item_Id
		LEFT JOIN  "+@DATABASENAME+"    Hsn_Master HSM ON HSM.Hsn_Id = IM.HSN_ID
		WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND PUR.GST_TYPE = 'Eligible ITC' AND HSM.GST_TYPE IN ('Nil Rated','Zero Rated')
		AND  CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 

"

SET @SQL14B=" UNION ALL 			
		SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS 'INTER_STATE_SUPPLYCOMPO',ISNULL(SUM(PURD.Amount),0) AS 'INTER_STATE_SUPPLYEXEMPTED',
0 AS 'INTER_STATE_SUPPLYNILRATED', 0 AS 'INTER_STATE_SUPPLYNONGST', 
0 AS 'OUTER_STATE_SUPPLYCOMPO',0 AS 'OUTER_STATE_SUPPLYEXEMPTED',0 AS 'OUTER_STATE_SUPPLYNILRATED',	
0 AS 'OUTER_STATE_SUPPLYNONGST',
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST ,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAX,
'P' AS FLAG,9 TYPE ,'I' DATATYPE 
		FROM  "+@DATABASENAME+"  PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+"  PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id
		LEFT JOIN  "+@DATABASENAME+"    STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		LEFT JOIN  "+@DATABASENAME+"    Item_Master IM ON PURD.Item_Id=IM.Item_Id
		LEFT JOIN  "+@DATABASENAME+"    Hsn_Master HSM ON HSM.Hsn_Id = IM.HSN_ID
		WHERE VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND PUR.GST_TYPE = 'Eligible ITC' AND HSM.GST_TYPE IN ('Exempted')
		AND  CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
) DDDD
"

--SDSD
END
EXEC (@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6+@SQL7+@SQL8+@SQL9+@SQL10+@SQL10A+@SQL10B+@SQL11+@SQL12+@SQL13+@SQL14+@SQL14A+@SQL14B)

