-- CRYSTAL_REPORT   : <GST R2_3A_INWARD.RPT>
-- =============================================
PROC_GST_R2_13_HSN_SUMMARY '1','acc2017_2018.dbo.','07'
*/
CREATE PROCEDURE [dbo].[PROC_GST_R2_13_HSN_SUMMARY]	
(
 @CMP_CODE AS NVARCHAR(50),
 @DATABASENAME AS  NVARCHAR(100),
 @FROMMONTHNAME AS  NVARCHAR(50),
 @TOMONTHNAME AS  NVARCHAR(50)
 
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLA AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)



DECLARE @REPORT_SQL AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""

SET @REPORT_SQL=""
SET @SQLA=""


BEGIN	
	SET NOCOUNT ON;
SET @SQL="      SELECT HSN_NAME,MAX(ITEMNAME)ITEMNAME,MAX(UQC)UQC,SUM(QTY)QTY,SUM(TOTALVALUES)TOTALVALUES,SUM(ITEM_TAXABLEVAL)ITEM_TAXABLEVAL, 
 SUM(CGST_AMT)CGST_AMT,SUM(SGST_AMT)SGST_AMT,SUM(IGST_AMT)IGST_AMT,SUM(CESS) AS CESS
 FROM (
 
 
 SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME,HSM.DESCRIPTION AS ITEMNAME,UM.UQC AS UQC,
  (CASE WHEN UM.UNIT_NAME ='PIECES' THEN PID.PIECES  ELSE PID.QUANTITY END)QTY, 
((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)++ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL)) +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL))*PUR_INV_ADD6)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0))))/GROSSTOTAL))*PUR_INV_ADD5)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL))*PUR_INV_ADD4)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  )AS TOTALVALUES,
 (PID.Amount-((PID.Amount*(LessTotal-(ISNULL(Pur_Inv_Add1,0)+ISNULL(Pur_Inv_Add2,0)+ISNULL(Pur_Inv_Add3,0))))/GrossTotal))ITEM_TAXABLEVAL,
  (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD4,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS CGST_AMT,
  (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD5,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS SGST_AMT, 
 (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD6,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))) AS IGST_AMT,0 AS CESS
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
 LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID=IM.HSN_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  (ISNULL(Pur_Inv_Add4,0) + ISNULL(Pur_Inv_Add5,0) + ISNULL(Pur_Inv_Add6,0)) > 0
AND PI.FLAG IN ('P','FP')"


SET @SQLA=" union all  SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME,HSM.DESCRIPTION AS ITEMNAME,UM.UQC AS UQC,
  (CASE WHEN UM.UNIT_NAME ='PIECES' THEN PID.PIECES  ELSE PID.QUANTITY END)QTY, 
((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)++ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL)) +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL))*PUR_INV_ADD6)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0))))/GROSSTOTAL))*PUR_INV_ADD5)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  +(((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))/GROSSTOTAL))*PUR_INV_ADD4)/ (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0)))))  )AS TOTALVALUES,
 (PID.Amount-((PID.Amount*(LessTotal-(ISNULL(Pur_Inv_Add1,0)+ISNULL(Pur_Inv_Add2,0)+ISNULL(Pur_Inv_Add3,0))))/GrossTotal))ITEM_TAXABLEVAL,
  (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD4,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS CGST_AMT,
  (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD5,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(PUR_INV_ADD3,0))))) AS SGST_AMT, 
 (((PID.AMOUNT-((PID.AMOUNT*(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))/GROSSTOTAL))*ISNULL(PUR_INV_ADD6,0))/
 (GROSSTOTAL-(LESSTOTAL-(ISNULL(PUR_INV_ADD1,0)+ISNULL(PUR_INV_ADD2,0)+ISNULL(Pur_Inv_Add3,0))))) AS IGST_AMT,0 AS CESS
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
left JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
 LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID=PI.HSN_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND  (ISNULL(Pur_Inv_Add4,0) + ISNULL(Pur_Inv_Add5,0) + ISNULL(Pur_Inv_Add6,0)) > 0
AND PI.FLAG IN ('JP')

 union all
 
SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME, ISNULL(HSM.Description,'') AS ITEMNAME,'MTR-METER' AS UQC,0 AS QTY, 
NETAMOUNT AS TOTALVALUES,Tran_Amount AS ITEM_TAXABLEVAL,DM.CGST AS CGST_AMT,
DM.SGST AS SGST_AMT, DM.IGST AS IGST_AMT,0 as cess
FROM "+@DATABASENAME+"CREDITNOTEAcc_MASTER DM
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = DM.HSN_ID
WHERE DM.CMP_CODE= "+@CMP_CODE+" AND TRAN_DATE between '"+@FROMMONTHNAME+"' AND '"+@TOMONTHNAME+"'
AND DM.note = 'DR Note Received Against Purchase'
AND (ISNULL(DM.CGST,0) + ISNULL(DM.SGST,0) + ISNULL(DM.IGST,0)) > 0

union all
SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME,ISNULL(HSM.Description,''),'MTR-METER' AS UQC,0 AS QTY, 
(0 - NETAMOUNT) AS TOTALVALUES, (0 - Tran_Amount) AS ITEM_TAXABLEVAL,(0-DM.CGST) AS CGST_AMT,
(0 - DM.SGST) AS SGST_AMT, (0 - DM.IGST) AS IGST_AMT,0 as cess
FROM "+@DATABASENAME+"DebitNoteAcc_Master  DM
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = DM.HSN_ID
WHERE DM.CMP_CODE= "+@CMP_CODE+" AND TRAN_DATE between '"+@FROMMONTHNAME+"' AND '"+@TOMONTHNAME+"'
AND DM.note = 'CR Note Received Against Purchase'
AND (ISNULL(DM.CGST,0) + ISNULL(DM.SGST,0) + ISNULL(DM.IGST,0)) > 0


"

SET @SQL1="
UNION ALL
 SELECT HSN_NAME,MAX(ITEMNAME)ITEMNAME,MAX(UQC)UQC,SUM(QTY)QTY,SUM(TOTALVALUES)TOTALVALUES,SUM(ITEM_TAXABLEVAL)ITEM_TAXABLEVAL, 
 SUM(CGST_AMT)CGST_AMT,SUM(SGST_AMT)SGST_AMT,SUM(IGST_AMT)IGST_AMT,SUM(CESS) AS CESS
 FROM (

SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME,HSM.DESCRIPTION AS ITEMNAME,UM.UQC AS UQC,
  (CASE WHEN UM.UNIT_NAME ='PIECES' THEN PID.PIECES  ELSE PID.QUANTITY END)QTY, 
  PID.FINALAMOUNT AS TOTALVALUES,
  (PID.AMOUNT) AS ITEM_TAXABLEVAL,
ISNULL(VAT_AMT,0) AS CGST_AMT,ISNULL(VATAMOUNT1,0) AS SGST_AMT,ISNULL(VATAMOUNT2,0) AS IGST_AMT ,0 AS CESS

FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
 LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID=IM.HSN_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND ((PID.FLAG IN ('CHP') AND PID.PUR_FORM_TYPE='B') OR PID.FLAG IN ('RP'))
 AND (ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0)) > 0

) AS DETAIL
 GROUP BY HSN_NAME
 
 "

SET @SQL3="
UNION ALL

SELECT HSN_NAME,MAX(ITEMNAME)ITEMNAME,MAX(UQC)UQC,SUM(QTY)QTY,SUM(TOTALVALUES)TOTALVALUES,SUM(ITEM_TAXABLEVAL)ITEM_TAXABLEVAL, 
SUM(CGST_AMT)CGST_AMT,SUM(SGST_AMT)SGST_AMT,SUM(IGST_AMT)IGST_AMT,SUM(CESS) AS CESS
FROM (
select ISNULL(HSM.HSN_NAME,'')HSN_NAME,HSM.DESCRIPTION AS ITEMNAME,'' AS UQC,1 AS QTY,
(ISNULL(TOTALFARE_AMOUNT,0) + ISNULL(PI.CGST,0) + ISNULL(PI.sGST,0) + ISNULL(PI.iGST,0)) AS TOTALVALUES,
(ISNULL((TOTALFARE_AMOUNT),0))AS ITEM_TAXABLEVAL,
ISNULL(PI.CGST,0) AS CGST_AMT,ISNULL(PI.SGST,0) AS SGST_AMT,ISNULL(PI.IGST,0) AS IGST_AMT  ,1 AS CESS
FROM "+@DATABASENAME+"TRANSPORT_PAYMENT PI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.PurAccount_Id
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID=PI.HSN_ID
WHERE PI.CMP_CODE= "+@CMP_CODE+" AND DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'  ) as detail
GROUP BY HSN_NAME
"
SET @SQL2="
UNION ALL

SELECT HSN_NAME,MAX(ITEMNAME)ITEMNAME,MAX(UQC)UQC,SUM(QTY)QTY,SUM(TOTALVALUES)TOTALVALUES,SUM(ITEM_TAXABLEVAL)ITEM_TAXABLEVAL, 
 SUM(CGST_AMT)CGST_AMT,SUM(SGST_AMT)SGST_AMT,SUM(IGST_AMT)IGST_AMT,SUM(CESS) AS CESS
 FROM (SELECT ISNULL(HSM.HSN_NAME,'')HSN_NAME,HSM.DESCRIPTION AS ITEMNAME,UM.UQC  AS UQC,
 (0 - PID.Pur_Ret_Qty) AS QTY, 
(0-((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)++ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL)) +(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL))*Pur_Ret_Add6)/ (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0)))))  +(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0))))/GROSSTOTAL))*Pur_Ret_Add5)/ (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0)))))  +(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL))*Pur_Ret_Add4)/ (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0)))))  ))AS TOTALVALUES,
 (0-(PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GrossTotal)))ITEM_TAXABLEVAL,
  (0-(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL))*ISNULL(Pur_Ret_Add4,0))/
 (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0)))))) AS CGST_AMT,
  (0-(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL))*ISNULL(Pur_Ret_Add5,0))/
 (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))) )AS SGST_AMT, 
 (0-(((PID.Pur_Ret_Amount-((PID.Pur_Ret_Amount*(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))/GROSSTOTAL))*ISNULL(Pur_Ret_Add6,0))/
 (GROSSTOTAL-(Pur_Ret_LessTotal-(ISNULL(Pur_Ret_Add1,0)+ISNULL(Pur_Ret_Add2,0)+ISNULL(Pur_Ret_Add3,0))))) )AS IGST_AMT,0 AS CESS
FROM "+@DATABASENAME+" PURCHASE_RETURN_MASTER PI
INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PID ON PI.Pur_Ret_Id=PID.Pur_Ret_Id AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
 LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID=IM.HSN_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID WHERE PI.CMP_CODE= "+@CMP_CODE+" 
 AND Pur_Ret_Date BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
 )AS SD GROUP BY HSN_NAME ) AS SUMMARY
  GROUP BY HSN_NAME"

/*EXEC SP_EXECUTESQL @SQL*/

		EXEC (@SQL+@SQLA +@SQL1 + @SQL2+ @SQL3)
		PRINT @SQL
	PRINT @SQLA
		PRINT @SQL1
		PRINT @SQL2
PRINT @SQL3

END































GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_R2_3A_INWARD]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/*
-- =============================================
-- ALTER_AUTHOR    : <PRATIK>
-- ALTER_DATE      : <28-08-2017 2:30 PM>
-- REPORT_FORM      : <RFRMGSTR2LIST.CS>
-- CRYSTAL_REPORT   : <GST R2_3A_INWARD.RPT>
-- =============================================
PROC_GST_R2_3A_INWARD '1','acc2017_2018.dbo.','10','10',3
*/
CREATE PROCEDURE [dbo].[PROC_GST_R2_3A_INWARD]	
(
 @CMP_CODE AS NVARCHAR(50),
 @DATABASENAME AS  NVARCHAR(100),
 @FROMMONTHNAME AS  NVARCHAR(50),
 @TOMONTHNAME AS  NVARCHAR(50),
 @REPORT_TYPE AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)

DECLARE @REPORT_SQL AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @REPORT_SQL=""

BEGIN
	IF @REPORT_TYPE=1
		SET @REPORT_SQL=" AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')"
	IF @REPORT_TYPE=2
		SET @REPORT_SQL=" AND (ISNULL(LM.GSTINNO,'')<>'' AND LM.GSTINNO<>'0')"
	IF @REPORT_TYPE=3
		SET @REPORT_SQL=" AND (ISNULL(LM.GSTINNO,'')='' OR LM.GSTINNO='0')"
		
END


BEGIN	
	SET NOCOUNT ON;
SET @SQL=" SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
(ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0)) AS RATE,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,LM1.SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,
MAX(PI.GROSSTOTAL + (ISNULL(PI.PUR_INV_ADD1,0)+ISNULL(PI.PUR_INV_ADD2,0)+ISNULL(PI.PUR_INV_ADD3,0) -  ISNULL(LessTotal,0)))AS TAXABLEAMT,
MAX(ISNULL(Pur_Inv_Add4,0)) AS CGST,MAX(ISNULL(Pur_Inv_Add5,0)) AS SGST,MAX(ISNULL(Pur_Inv_Add6,0)) AS IGST,MAX(HSM.HSN_NAME) as HSN_NAME ,0 AS CESSAMT
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID  ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND PI.FLAG IN ('P','FP')
AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
"+@REPORT_SQL+"
GROUP BY LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE,(ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0)) ,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) ,LM1.SUPPLY_TYPE 


UNION ALL" 

SET @SQL1=" SELECT LM.LGR_NAME,LM.GSTINNO,BILLNO,VCHDATE AS VCHDATE,
(ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0)) AS RATE,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,LM1.SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,
(PI.GROSSTOTAL +(ISNULL(PI.PUR_INV_ADD1,0)+ISNULL(PI.PUR_INV_ADD2,0)+ISNULL(PI.PUR_INV_ADD3,0))-
(ISNULL(PI.PUR_INV_LESS2,0)+ISNULL(PI.PUR_INV_LESS3,0)+ISNULL(PI.PUR_INV_LESS4,0)+ISNULL(PI.PUR_INV_LESS5,0))) AS TAXABLEAMT,
(ISNULL(Pur_Inv_Add4,0)) AS CGST,(ISNULL(Pur_Inv_Add5,0)) AS SGST,(ISNULL(Pur_Inv_Add6,0)) AS IGST,HSM.HSN_NAME,0 AS CESSAMT
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = PI.HSN_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND PI.FLAG IN ('JP')
AND (ISNULL(Pur_Inv_Add4_Set,0)+ISNULL(Pur_Inv_Add5_Set,0)+ISNULL(Pur_Inv_Add6_Set,0))>0
"+@REPORT_SQL+"

UNION ALL" 

SET @SQL2=" SELECT LGR_NAME,GSTINNO,BILLNO,VCHDATE,RATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,
SUM(TAXABLEAMT)TAXABLEAMT,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST ,HSN_NAME,SUM(CESSAMT) AS CESSAMT
FROM (

SELECT LM.LGR_NAME,LM.GSTINNO,(CONVERT(NVARCHAR,BILLNO))BILLNO,VCHDATE AS VCHDATE,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,
(CASE WHEN PI.GST_TYPE = 'InEligible ITC' THEN 'InEligible' ELSE LM1.SUPPLY_TYPE END ) AS ELIGIBILITY_OF_ITC,
(PID.FINALAMOUNT-(ISNULL(VAT_AMT,0)+ISNULL(VATAMOUNT1,0)+ISNULL(VATAMOUNT2,0) + ISNULL(CESSAMT,0))) AS TAXABLEAMT,(ISNULL(VAT_PER,0) + ISNULL(VAT_PER1,0) + ISNULL(VAT_PER2,0) ) AS RATE,
VAT_AMT AS CGST,VATAMOUNT1 AS SGST,VATAMOUNT2 AS IGST,HSN_NAME,CESSAMT 
FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID

WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND PID.FLAG IN ('CHP') AND PID.PUR_FORM_TYPE='B'
 AND (ISNULL(VAT_AMT,0) + ISNULL(VATAMOUNT1,0) + ISNULL(VATAMOUNT2,0) )>0
"+@REPORT_SQL+"
) AS DETAIL
GROUP BY LGR_NAME,GSTINNO,BILLNO,VCHDATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,RATE,HSN_NAME
ORDER BY VCHDATE,BillNo
"

SET @SQL3=" SELECT LGR_NAME,GSTINNO,BILLNO,VCHDATE,RATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,
SUM(TAXABLEAMT)TAXABLEAMT,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,HSN_NAME,SUM(CESSAMT) AS CESSAMT
FROM (

SELECT LM.LGR_NAME,LM.GSTINNO,('T'+'/'+ CONVERT(NVARCHAR,TRM.DOC_NO))AS BILLNO ,DATE AS VCHDATE,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,
LM.SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,
(ISNULL((TOTALFARE_AMOUNT),0)) - (ISNULL((SESKAR_AMT_TOTAL),0)) AS TAXABLEAMT,
ISNULL((TRM.CGST),0) AS CGST,ISNULL((TRM.SGST ),0)  AS SGST ,ISNULL((TRM.IGST ),0)  AS IGST ,
(ISNULL(CGSTPER,0) + ISNULL(SGSTPER,0) + ISNULL(IGSTPER,0) ) AS RATE,HSM.HSN_NAME,0 AS CESSAMT
FROM "+@DATABASENAME+"TRANSPORT_PAYMENT TRM
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=TRM.PurAccount_Id
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = TRM.HSN_ID
WHERE TRM.CMP_CODE="+@CMP_CODE+" AND DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND (ISNULL(CGSTPER,0) + ISNULL(SGSTPER,0) + ISNULL(IGSTPER,0) )>0
"+@REPORT_SQL+"
) AS DETAIL
GROUP BY LGR_NAME,GSTINNO,BILLNO,VCHDATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,RATE,HSN_NAME
"

SET @SQL4="
union all
SELECT LGR_NAME,GSTINNO,BILLNO,VCHDATE,RATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,
SUM(TAXABLEAMT)TAXABLEAMT,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,HSN_NAME ,SUM(CESSAMT)
FROM (

SELECT LM.LGR_NAME,LM.GSTINNO,('R'+'/'+ CONVERT(NVARCHAR,PI.docno))AS BILLNO ,VCHDATE AS VCHDATE,
(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,
LM1.SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,
ISNULL(PID.amount,0) AS TAXABLEAMT,(ISNULL(VAT_PER,0) + ISNULL(VAT_PER1,0) + ISNULL(VAT_PER2,0) ) AS RATE,
VAT_AMT AS CGST,VATAMOUNT1 AS SGST,VATAMOUNT2 AS IGST ,HSM.HSN_NAME,CESSAMT
FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"HSN_MASTER HSM ON HSM.HSN_ID = IM.HSN_ID
WHERE PI.CMP_CODE="+@CMP_CODE+" AND VCHDATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND PID.FLAG IN ('RP') 
 AND (ISNULL(VAT_PER,0) + ISNULL(VAT_PER1,0) + ISNULL(VAT_PER2,0) )>0
"+@REPORT_SQL+"
) AS DETAIL
GROUP BY LGR_NAME,GSTINNO,BILLNO,VCHDATE,PLACEOFSUPPLY,ELIGIBILITY_OF_ITC,RATE,HSN_NAME
ORDER BY VCHDATE,BillNo"


/*EXEC SP_EXECUTESQL @SQL*/

IF @REPORT_TYPE=1
	BEGIN
		EXEC (@SQL+@SQL1+@SQL2)
		PRINT @SQL
		PRINT @SQL1
		PRINT @SQL2
	END	
ELSE IF @REPORT_TYPE=2 OR @REPORT_TYPE=3
	BEGIN
		EXEC (@SQL3+@SQL4)
		PRINT @SQL3
		PRINT @SQL4
	END		
END






















GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_R2_7_SUPPLY_RECEIVED]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO
























/*
-- =============================================
-- ALTER_AUTHOR    : <PRATIK>
-- ALTER_DATE      : <28-08-2017 2:30 PM>
-- REPORT_FORM      : <RFRMGSTR2LIST.CS>
-- CRYSTAL_REPORT   : <GST R2_3A_INWARD.RPT>
-- =============================================
PROC_GST_R2_7_SUPPLY_RECEIVED '1',' acc2017_2018.dbo.','07'
*/
CREATE PROCEDURE [dbo].[PROC_GST_R2_7_SUPPLY_RECEIVED]	
(
 @CMP_CODE AS NVARCHAR(50),
 @DATABASENAME AS  NVARCHAR(100),
 @MONTHNAME AS  NVARCHAR(50)
 
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @REPORT_SQL AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @REPORT_SQL=""



BEGIN	
	SET NOCOUNT ON;
SET @SQL="     
--select
--CONVERT(NVARCHAR,VchDate,103)VchDate,CONVERT(NVARCHAR,BillNo) as DocNo,NetTotal, lm.Lgr_name,'Composition Dealer Type' as GST_SUPPLY_TYPE , '' as Grp_MAIN_ID 
-- from  "+@DATABASENAME+" PURCHASEINVOICE PI
--INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
--LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
--inner join  "+@DATABASENAME+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID and LD.cmp_code =PI.cmp_Code
--inner join  "+@DATABASENAME+"Group_MAster GM on GM.Grp_Id=LD.GRP_ID

--WHERE PI.CMP_CODE=1 AND MONTH(VCHDATE)="+@MONTHNAME+" AND(ISNULL(LM.REGISTER_DEALER_TYPE,'')='Composition Dealer') 
----group by REGISTER_DEALER_TYPE
--UNION ALL
-- select CONVERT(NVARCHAR,VchDate,103)VchDate,CONVERT(NVARCHAR,BillNo)  as DocNo,NetTotal,LM1.LGR_NAME,LM.GST_SUPPLY_TYPE , gm.grp_Name as Grp_MAIN_ID from  "+@DATABASENAME+" PURCHASEINVOICE PI
--left JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.PurACcId
--inner JOIN  "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.LGR_ID
--LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
--left join  "+@DATABASENAME+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID and LD.cmp_code =PI.cmp_Code
--left join  "+@DATABASENAME+"Group_MAster GM on GM.Grp_Id=LD.GRP_ID

--WHERE PI.CMP_CODE=1 AND MONTH(VCHDATE)="+@MONTHNAME+" AND(ISNULL(LM.REGISTER_DEALER_TYPE,'')<>'Composition Dealer')AND (ISNULL(LM.GST_SUPPLY_TYPE,'')<>'')
----group by Grp_MAIN_ID,GST_SUPPLY_TYPE
----group by Grp_MAIN_ID

select CONVERT(NVARCHAR,VchDate,103)VchDate,CONVERT(NVARCHAR,BillNo)  as DocNo,NetTotal,LM1.LGR_NAME,LM.GST_SUPPLY_TYPE , gm.grp_Name as Grp_MAIN_ID
FROM  "+@DATABASENAME+"    PURCHASEINVOICE PUR
INNER JOIN  "+@DATABASENAME+"    COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"     LEDGER_MASTER LM ON LM.Lgr_Id=PUR.Lgr_Id 
left JOIN   "+@DATABASENAME+"     LEDGER_MASTER LM1 ON LM1.LGR_ID=PUR.PurACcId
left join  "+@DATABASENAME+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID and LD.cmp_code =PUR.cmp_Code
left join  "+@DATABASENAME+"Group_MAster GM on GM.Grp_Id=LD.GRP_ID

WHERE MONTH(VCHDATE)="+@MONTHNAME+"  AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND
 PUR.FLAG IN ('CHP') AND  PUR.PUR_FORM_TYPE = 'A' AND PUR.GST_TYPE IN ('COMPOSITION DEALER','GST EXEMPTED SUPPLY','NIL RATED SUPPLY','NON GST SUPPLY')

"



/*EXEC SP_EXECUTESQL @SQL*/

		EXEC (@SQL+@SQL1)
		PRINT @SQL
		PRINT @SQL1

END






















GO

