SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




























/*
-- =============================================
-- ALTER_AUTHOR    : <PRATIK>
-- ALTER_DATE      : <28-08-2017 2:30 PM>
-- REPORT_FORM      : <RFRMGSTR2LIST.CS>
-- CRYSTAL_REPORT   : <GST R2_3A_INWARD.RPT>
-- =============================================
PROC_GST_R2_CR_DR '1','acc2017_2018.dbo.','03'
*/
CREATE PROCEDURE [dbo].[PROC_GST_R2_CR_DR]	
(
 @CMP_CODE AS NVARCHAR(50),
 @DATABASENAME AS  NVARCHAR(100),
 @FROMMONTHNAME AS  NVARCHAR(50),
 @TOMONTHNAME AS  NVARCHAR(50) 
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""




BEGIN	
SET NOCOUNT ON;
SET @SQL="   
SELECT   Pur_Ret_Id as id, CONVERT(NVARCHAR,ISNULL(LM.GSTINNO,0)) AS PARTYGSTINNO,('PR'+ '/' + CONVERT(NVARCHAR, SI.DOCNO)) AS BILLNO,CONVERT(NVARCHAR,PUR_RET_DATE,103) AS INVDATE,( CONVERT(NVARCHAR, SI.PURBILLNO ))AS BILLNO1, CONVERT(NVARCHAR,PURVCHDATE,103) AS INVDATE1,
SI.ROUNDEDAMOUNT AS INV_VALUE,(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,'N' AS REVERSE_CHARGE, 
'D' AS INV_TYPE,(ISNULL(PUR_RET_ADD4_SET,0) + ISNULL(PUR_RET_ADD5_SET,0) + ISNULL(PUR_RET_ADD6_SET,0) ) AS RATE,
((ISNULL(SI.GROSSTOTAL,0) + ISNULL(SI.PUR_RET_ADD1_SET,0) + ISNULL(SI.PUR_RET_ADD2_SET,0)+ISNULL(SI.PUR_RET_ADD3_SET,0))- (ISNULL(PUR_RET_LESS1,0) +ISNULL(PUR_RET_LESS2,0) +ISNULL(PUR_RET_LESS3,0) +ISNULL(PUR_RET_LESS4,0) + ISNULL(PUR_RET_LESS5,0) )
) AS TAXABLEAMT ,SI.DOCNO,SI.PurchaseReturnReason AS TYPE,'0.00' AS CESSAMOUNT,SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,ISNULL(PUR_RET_ADD4,0) AS CGST,ISNULL(PUR_RET_ADD5,0) AS SGST,ISNULL(PUR_RET_ADD6,0) AS IGST,LM.LGR_NAME AS PARTY
FROM "+@DATABASENAME+" PURCHASE_RETURN_MASTER SI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
WHERE PUR_RET_DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND SI.FLAG IN ('PR') AND SI.CMP_CODE  IN ("+@CMP_CODE +") 

UNION ALL
SELECT DM.DEBITNOTEACC_ID AS ID,LM.GSTINNO AS PARTYGSTINNO,( CONVERT(NVARCHAR, DM.TRAN_DOCNO ))AS BILLNO,CONVERT(NVARCHAR,TRAN_DATE,103) AS INVDATE,( CONVERT(NVARCHAR, DM.REF_BILLNO ))AS BILLNO1,CONVERT(NVARCHAR,REF_DATE,103) AS INVDATE1,
ISNULL(TOTALDEBITAMOUNT,0) AS INV_VALUE ,(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,'N' AS REVERSE_CHARGE,'D' AS INV_TYPE,(ISNULL(CGSTPER,0) + ISNULL(SGSTPER,0) + ISNULL(IGSTPER,0) ) AS RATE,ISNULL(DM.TRAN_AMOUNT,0) AS TAXABLEAMT,
DM.TRAN_DOCNO AS DOCNO,DM.REASON AS TYPE,'0.00' AS CESSAMOUNT	,SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,ISNULL(CGST,0)CGST,ISNULL(SGST,0)SGST,ISNULL(IGST,0)IGST,LM.LGR_NAME AS PARTY
FROM  "+@DATABASENAME+" DEBITNOTEACC_MASTER DM
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  DM.Lgr_ID = LM.LGR_ID  
LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID 
INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.NOTE = 'CR NOTE RECEIVED AGAINST PURCHASE'AND DM.TRAN_DRCR='D'
AND TRAN_DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"' AND DM.CMP_CODE  IN ("+@CMP_CODE +") 
"

SET @SQL1=" UNION ALL
SELECT DM.CREDITNOTEACC_ID AS ID,LM.GSTINNO AS PARTYGSTINNO,( CONVERT(NVARCHAR, DM.TRAN_DOCNO ))AS BILLNO,CONVERT(NVARCHAR,TRAN_DATE,103) AS INVDATE,( CONVERT(NVARCHAR, DM.REF_BILLNO ))AS BILLNO1,CONVERT(NVARCHAR,REF_DATE,103) AS INVDATE1,
ISNULL(TOTALDEBITAMOUNT,0) AS INV_VALUE ,(ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME ) AS PLACEOFSUPPLY,'N' AS REVERSE_CHARGE,'C' AS INV_TYPE,(ISNULL(CGSTPER,0) + ISNULL(SGSTPER,0) + ISNULL(IGSTPER,0) ) AS RATE,ISNULL(DM.TRAN_AMOUNT,0) AS TAXABLEAMT,
DM.TRAN_DOCNO AS DOCNO,DM.REASON AS TYPE,'0.00' AS CESSAMOUNT	,SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,ISNULL(CGST,0)CGST,ISNULL(SGST,0)SGST,ISNULL(IGST,0)IGST,LM.LGR_NAME AS PARTY
FROM  "+@DATABASENAME+" CREDITNOTEACC_MASTER DM
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON DM.Lgr_ID  = LM.LGR_ID  
LEFT JOIN   "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID 
INNER JOIN  "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
INNER JOIN "+@DATABASENAME+"   COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.NOTE = 'DR NOTE RECEIVED AGAINST PURCHASE'AND DM.TRAN_DRCR='C' 
AND TRAN_DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"' AND DM.CMP_CODE  IN ("+@CMP_CODE +") 

ORDER BY INVDATE,BILLNO,INV_TYPE
"

SET @SQL2=" UNION ALL
 SELECT PURRET.Pur_Ret_Id AS Id,MAX(CONVERT(NVARCHAR,ISNULL(LM.GSTINNO,0))) AS PARTYGSTINNO,MAX(('CPR'+ '/' + CONVERT(NVARCHAR, PURRET.DOCNO))) AS BILLNO,
 MAX(CONVERT(NVARCHAR,PURRET.Pur_Ret_Date,103)) AS INVDATE,MAX((CONVERT(NVARCHAR, PURRET.PURBILLNO )))AS BILLNO1,MAX(CONVERT(NVARCHAR,PURRET.PURVCHDATE,103)) AS INVDATE1,
MAX(PURRET.ROUNDEDAMOUNT) AS INV_VALUE,MAX((ISNULL(SM.STATE_CODE,0) + '-'+ SM.STATE_NAME )) AS PLACEOFSUPPLY,'N' AS REVERSE_CHARGE,  
'D' AS INV_TYPE,(isnull(PURDT.VAT_PER,0) + isnull(PURDT.VAT_PER1,0) +isnull(PURDT.VAT_PER2,0))as  RATE,
PURDT.Pur_Ret_Amount as TAXABLE,PURRET.DocNo,MAX(PURRET.PurchaseReturnReason) AS TYPE,
'0.00' AS CESSAMOUNT,SUPPLY_TYPE AS ELIGIBILITY_OF_ITC,ISNULL(SUM(PURDT.VATAMOUNT),0)AS CGST,ISNULL(SUM(PURDT.VATAMOUNT1),0)AS SGST,
ISNULL(SUM(PURDT.VATAMOUNT2),0)AS IGST,LM.LGR_NAME AS PARTY
FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PURRET		
INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PURDT ON PURDT.Pur_Ret_Id = PURRET.Pur_Ret_Id AND PURDT.FLAG=PURRET.FLAG		
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PURRET.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PURRET.Lgr_Id 
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE PUR_RET_DATE BETWEEN '"+ @FROMMONTHNAME +"' AND '"+ @TOMONTHNAME +"'
AND PURRET.Flag in ('CPR') AND PURRET.CMP_CODE  IN ("+@CMP_CODE +") 
GROUP BY PURRET.PUR_RET_ID,PURRET.DOCNO,SUPPLY_TYPE,PURDT.VAT_PER,PURDT.VAT_PER1,PURDT.VAT_PER2,PURDT.PUR_RET_AMOUNT,LM.LGR_NAME 
"



BEGIN
EXEC (@SQL+@SQL2+@SQL1)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
END
END

















GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_STATEWISE_SUMMARY]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/*
-- =============================================
-- Author:		SHUBHAM RAVAL
-- Create_date: 10-08-2017
-- Description:	THIS PROCEDURE USED IN GST SUMMARY  REPORT
-- REPORT NAME:  GST_SUMMARY_REPORT
PROC_GST_STATEWISE_SUMMARY N'01/Apr/2017', N'31/MAR/2018', N'ACC2017_2018.Dbo.', N'1'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_STATEWISE_SUMMARY]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100)
    
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL1A AS NVARCHAR(4000)

DECLARE @SQL2 AS NVARCHAR(4000)



BEGIN
		SET @SQL1 = "select * from ( SELECT CMPNAME ,TINNO ,CITY ,CSTNNO,CmpStateCode,state_name ,STATECODE ,sum(AMOUNT)AMOUNT,GSTINNO,sum(CGST)CGST,sum(SGST)SGST,sum(IGST)IGST,sum(TOTAL)TOTAL,RATE   FROM (
SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
CM.CMP_STATECODE as  CmpStateCode ,
SM.state_name,ISNULL(SM.STATE_CODE,0) AS STATECODE, ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,
(ISNULL(Sal_Inv_Add3_Set,0) + ISNULL(Sal_Inv_Add4_Set,0) + ISNULL(Sal_Inv_Add5_Set,0) ) AS RATE,

ISNULL(SUM(SAL_INV_NETTOTAL),0) -
		((CASE 	WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0)  ELSE 0 	END) 
 +(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0) ELSE 0 END) 
 +(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0) ELSE 0 END) 
) AS AMOUNT,ISNULL(MAX(CM.GSTINNO),0) AS GSTINNO,
		(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,'S' AS FLAG,3 TYPE 
		FROM "+@DATABASENAME+" SALES_INVOICE SI
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  LM.Lgr_Id = SI.Lgr_Id
		LEFT JOIN "+@DATABASENAME+"  STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.state_name,SM.STATE_CODE,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD
,
Sal_Inv_Add3_Set ,Sal_Inv_Add4_Set ,Sal_Inv_Add5_Set
"
SET @SQL1A = " UNION ALL SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
CM.CMP_STATECODE as  CmpStateCode ,
SM.state_name,ISNULL(SM.STATE_CODE,0) AS STATECODE, ISNULL(SUM(NETAMT),0) AS TOTAL,
(ISNULL(Sal_Inv_Add3_Set,0) + ISNULL(Sal_Inv_Add4_Set,0) + ISNULL(Sal_Inv_Add5_Set,0) ) AS RATE,

(ISNULL(SUM(SI.Total),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))
 AS AMOUNT,ISNULL(MAX(CM.GSTINNO),0) AS GSTINNO,
		(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,'S' AS FLAG,3 TYPE 
		FROM "+@DATABASENAME+" Job_SalesInvoice_Master SI
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  LM.Lgr_Id = SI.Lgr_Id
		LEFT JOIN "+@DATABASENAME+"  STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.state_name,SM.STATE_CODE,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD
,
Sal_Inv_Add3_Set ,Sal_Inv_Add4_Set ,Sal_Inv_Add5_Set"
SET @SQL2 = "  ) AS DETAIL  group by  CMPNAME ,TINNO ,CITY ,CSTNNO,CmpStateCode,state_name ,STATECODE ,GSTINNO,RATE  ) AS SD ORDER BY state_name "

END

EXEC (@SQL1+@SQL1A +@SQL2)
PRINT @SQL1
PRINT @SQL1A 
PRINT @SQL2
















GO

