/*
-- =============================================
-- Author:		SHUBHAM RAVAL
-- Create_date: 10-08-2017
-- Description:	THIS PROCEDURE USED IN GST SUMMARY  REPORT
-- REPORT NAME:  GST_SUMMARY_REPORT
PROC_GST_STATEWISE_SUMMARY_REGISTERDEALER N'01/Apr/2017', N'31/MAR/2018', N'ACC2017_2018.Dbo.', N'1'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_STATEWISE_SUMMARY_REGISTERDEALER]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100)
    
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL1A AS NVARCHAR(4000)


BEGIN
		SET @SQL1 = "select * from ( SELECT CMPNAME ,TINNO ,CITY ,CSTNNO,CmpStateCode,state_name ,STATECODE ,sum(AMOUNT)AMOUNT,GSTINNO,sum(CGST)CGST,sum(SGST)SGST,sum(IGST)IGST,sum(TOTAL)TOTAL,RATE   FROM (
SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
CM.CMP_STATECODE as  CmpStateCode ,
SM.state_name,ISNULL(SM.STATE_CODE,0) AS STATECODE, ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,
(ISNULL(Sal_Inv_Add3_Set,0) + ISNULL(Sal_Inv_Add4_Set,0) + ISNULL(Sal_Inv_Add5_Set,0) ) AS RATE,

(ISNULL(SUM(SI.SAL_INV_GROSSTOTAL),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))
 AS AMOUNT,ISNULL(MAX(CM.GSTINNO),0) AS GSTINNO,
		(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,'S' AS FLAG,3 TYPE 
		FROM "+@DATABASENAME+" SALES_INVOICE SI
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  LM.Lgr_Id = SI.Lgr_Id
		LEFT JOIN "+@DATABASENAME+"  STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='REGISTERED DEALER' )

/*AND CM.CMP_STATECODE <> SM.STATE_CODE */
GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.state_name,SM.STATE_CODE,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD
,
Sal_Inv_Add3_Set ,Sal_Inv_Add4_Set ,Sal_Inv_Add5_Set
"
SET @SQL1A = " UNION ALL  SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
CM.CMP_STATECODE as  CmpStateCode ,
SM.state_name,ISNULL(SM.STATE_CODE,0) AS STATECODE, ISNULL(SUM(NETAMT),0) AS TOTAL,
(ISNULL(Sal_Inv_Add3_Set,0) + ISNULL(Sal_Inv_Add4_Set,0) + ISNULL(Sal_Inv_Add5_Set,0) ) AS RATE,


(ISNULL(SUM(SI.Total),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))
 AS AMOUNT,ISNULL(MAX(CM.GSTINNO),0) AS GSTINNO,
		(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,'S' AS FLAG,3 TYPE 
		FROM "+@DATABASENAME+" Job_SalesInvoice_Master SI
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  LM.Lgr_Id = SI.Lgr_Id
		LEFT JOIN "+@DATABASENAME+"  STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='REGISTERED DEALER' )

/*AND CM.CMP_STATECODE <> SM.STATE_CODE */
GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.state_name,SM.STATE_CODE,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD
,
Sal_Inv_Add3_Set ,Sal_Inv_Add4_Set ,Sal_Inv_Add5_Set   "
SET @SQL2 = "  ) AS DETAIL  group by  CMPNAME ,TINNO ,CITY ,CSTNNO,CmpStateCode,state_name ,STATECODE ,GSTINNO,RATE  ) AS SD ORDER BY state_name "

END


EXEC (@SQL1+@SQL1A+@SQL2)
PRINT @SQL1
PRINT @SQL1A
PRINT @SQL2
















GO

