rated and exempted)' AS SDS FROM ("
SET  @SQL2=" SELECT	CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,ISNULL(SUM(Sal_Inv_GrossTotal),0) +
