BEGIN
SET @SQL111 = " SELECT * FROM ( SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST ,ISNULL(SUM(PURD.CESSAMT),0)CESS,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAX,
'P' AS FLAG,9 TYPE ,'I' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
,0 AS TOTAL,'(1) As per section 17(5)' AS SDS,'DD' AS BLOCK
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND PUR.GST_TYPE = 'InEligible ITC' 
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
		) AS DETAIL					
		--PUR.In_Outer_State,
"

SET @SQL111a = " WHERE EXISTS(SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST ,ISNULL(SUM(PURD.CESSAMT),0)CESS,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAX,
'P' AS FLAG,9 TYPE ,'I' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
,0 AS TOTAL,'(1) As per section 17(5)' AS SDS,'DD' AS BLOCK
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND PUR.GST_TYPE = 'InEligible ITC' 
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 	
		--PUR.In_Outer_State,
		)
"
SET @SQL111b = " UNION ALL

SELECT   '' CMPNAME,'' TINNO,'' CITY,'' CSTNNO,
0 AS  OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
0 AS AMOUNT,0 AS  CGST,0 AS  SGST,0 AS IGST,0 AS CESS,0 AS TOTALTAX,'' AS FLAG,'9' AS TYPE,'I' AS DATATYPE
 ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE ,0 AS TOTAL,
 '(1) As per section 17(5)' AS SDS,'DD' AS BLOCK
 WHERE NOT EXISTS ( SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
ISNULL(SUM(PURD.AMOUNT),0) 

 AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST,ISNULL(SUM(PURD.CESSAMT),0) AS CESS ,
(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) TOTALTAX,
'P' AS FLAG,9 TYPE ,'I' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
,0 AS TOTAL,'(1) As per section 17(5)' AS SDS,'DD' AS BLOCK
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND PUR.GST_TYPE = 'InEligible ITC' 
		GROUP BY  CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 		
		)
/*END (1) As per section 17(5) D(1)*/
"

SET @SQL111C = "/*PART 1 FOR A+B  START*/ UNION ALL SELECT MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,SUM(OUTER_STATE_SUPPLY)OUTER_STATE_SUPPLY,SUM(INTER_STATE_SUPPLY)INTER_STATE_SUPPLY,
(SUM(AMOUNTAA) + SUM(AMOUNTDD)) AS AMOUNT,(SUM(CGSTAA) + SUM(CGSTDD)) AS CGST,
(SUM(SGSTAA)  + SUM(SGSTDD)) AS SGST,(SUM(IGSTAA) + SUM(IGSTDD)) AS IGST,SUM(CESS)CESS,(SUM(TOTALTAXAA)+SUM(TOTALTAXDD)) TOTALTAX,
'P' FLAG,8 as TYPE,'H' DATATYPE
 ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE ,0 AS TOTAL,'(C) Net ITC Available (A) – (B)' AS SDS,'CC' AS BLOCK
FROM ( "
