SET @SQL4 = " /* NEW ALL OTHER ITC START A(5)*/  
UNION ALL  SELECT * FROM ( SELECT MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,
SUM(OUTER_STATE_SUPPLY)OUTER_STATE_SUPPLY,SUM(INTER_STATE_SUPPLY)INTER_STATE_SUPPLY,
(SUM(AMOUNTPUR)- SUM(AMOUNTPURRE))AMOUNT,
(SUM(CGSTPUR) - SUM(CGSTPURRE))CGST,(SUM(SGSTPUR) - SUM(SGSTPURRE))SGST,(SUM(IGSTPUR) - SUM(IGSTPURRE))IGST,SUM(CESS)CESS,
