		(ISNULL(SUM(PURRET.PUR_RET_ADD1),0) 
		+ISNULL(SUM(PURRET.PUR_RET_ADD2),0)
		+ISNULL(SUM(PURRET.PUR_RET_ADD3),0)
)-(+(ISNULL(SUM(PURRET.Pur_Ret_Less1),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less2),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less3),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less4),0))+(ISNULL(SUM(PURRET.Pur_Ret_Less5),0))
 ) AS AMOUNTPURRE,
(ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0)) AS CGSTPURRE,
