(ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0) + ISNULL(SUM(PURRET.PUR_RET_ADD5 ),0) +  ISNULL(SUM(PURRET.PUR_RET_ADD6 ),0)) AS TOTALTAXPURRE
,'P' AS FLAG,5 TYPE ,'E' DATATYPE ,'' AS SUPPLIER_TYPE,'' AS CMPSTATECODE,'' AS STATE_NAME ,'' AS STATECODE 
		FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PURRET
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PURRET.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PURRET.CMP_CODE
		LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PURRET.Pur_Acc_Id 
		WHERE PUR_RET_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  
		AND  PURRET.CMP_CODE IN("+@CMP_CODE+") AND PURRET.Flag in ('PR','VPR')
		GROUP BY CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 

"

SET @SQL10H = "UNION ALL SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,
