		BEGIN	
		set @SQLMONTH="( SELECT (DATEPART(month,DATEADD(month, -1, '"+@FROMDATE+"'))) ) " 		
		END
BEGIN

SET @SQL1 = " 

SELECT * FROM (SELECT CMPNAME ,TINNO ,CITY ,CSTNNO,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,sum(AMOUNT)AMOUNT,sum(CGST)CGST,sum(SGST)SGST,sum(IGST)IGST,0 AS TOTALTAX,'S' AS FLAG,4 AS TYPE,'E' DATATYPE,'SUPPLIES MADE TO UNREG. PERSONS' AS SUPPLIER_TYPE ,CMPSTATECODE,STATE_NAME ,STATECODE ,SUM(TOTAL)TOTAL
FROM (
SELECT   CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
(ISNULL(SUM(SI.SAL_INV_GROSSTOTAL),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO, ISNULL(SUM(SI.SAL_INV_ADD3),0) AS CGST,ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST ,ISNULL(SUM(SI.SAL_INV_ADD5),0)         IGST ,ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,'S' AS FLAG,4 AS TYPE,'E' DATATYPE
		FROM  "+@DATABASENAME+" SALES_INVOICE SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+") 
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE"

SET @SQL1A = "  UNION ALL  SELECT   CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
(ISNULL(SUM(Total),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO, ISNULL(SUM(SI.SAL_INV_ADD3),0) AS CGST,ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST ,ISNULL(SUM(SI.SAL_INV_ADD5),0)         IGST ,ISNULL(SUM(NETAMT),0) AS TOTAL,'S' AS FLAG,4 AS TYPE,'E' DATATYPE
		FROM  "+@DATABASENAME+" Job_SalesInvoice_Master SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+") 
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE

 ) AS DETAIL11     
GROUP BY CMPNAME ,TINNO ,CITY ,CSTNNO,CMPSTATECODE,STATE_NAME ,STATECODE 
) AS MAINDD
"
SET @SQL2 = "
WHERE EXISTS (SELECT   CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
(ISNULL(SUM(SI.SAL_INV_GROSSTOTAL),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO, ISNULL(SUM(SI.SAL_INV_ADD3),0) AS CGST,ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST ,ISNULL(SUM(SI.SAL_INV_ADD5),0)         IGST ,ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,'S' AS FLAG,4 AS TYPE,'E' DATATYPE
		FROM  "+@DATABASENAME+" SALES_INVOICE SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+") 
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE UNION ALL		

"
SET @SQL2A = " SELECT   CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
(ISNULL(SUM(SI.Total),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO, ISNULL(SUM(SI.SAL_INV_ADD3),0) AS CGST,ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST ,ISNULL(SUM(SI.SAL_INV_ADD5),0)         IGST ,ISNULL(SUM(NETAMT),0) AS TOTAL,'S' AS FLAG,4 AS TYPE,'E' DATATYPE
		FROM  "+@DATABASENAME+" Job_SalesInvoice_Master SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+") 
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UNREGISTERED DEALER' )  AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE)UNION ALL		 "
SET @SQL3 = " SELECT '' AS  CMPNAME , '' AS TINNO , '' AS CITY ,'' AS CSTNNO,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,0 AS AMOUNT, 0 AS CGST,0 AS SGST,0 AS IGST,0 AS TOTALTAX,'SS' AS FLAG,44 AS TYPE,'EE' DATATYPE,'SUPPLIES MADE TO UNREG. PERSONS' AS SUPPLIER_TYPE,0 AS CMPSTATECODE,'' AS STATE_NAME ,0 AS STATECODE ,0 AS TOTAL
WHERE NOT EXISTS (SELECT   CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
(ISNULL(SUM(SI.SAL_INV_GROSSTOTAL),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -
( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO, ISNULL(SUM(SI.SAL_INV_ADD3),0) AS CGST,ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST ,ISNULL(SUM(SI.SAL_INV_ADD5),0)         IGST ,ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,'S' AS FLAG,4 AS TYPE,'E' DATATYPE
		FROM  "+@DATABASENAME+" SALES_INVOICE SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
