0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, 
