( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO,	 ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    AS CGST,	 ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST , ISNULL(SUM(SI.SAL_INV_ADD5),0)  IGST ,
ISNULL(SUM(NETAMT),0) AS TOTAL,'S' AS FLAG,6 AS TYPE,'G' DATATYPE
		FROM   "+@DATABASENAME+"  Job_SalesInvoice_Master SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UIN HOLDER' )   AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE)
		UNION ALL"
SET @SQL9 = " SELECT '' AS  CMPNAME , '' AS TINNO , '' AS CITY ,'' AS CSTNNO,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,0 AS AMOUNT, 0 AS CGST,0 AS SGST,0 AS IGST,0 AS TOTALTAX,'SS' AS FLAG,66 AS TYPE,'GG' DATATYPE,'SUPPLIES MADE TO UIN HOLDER' AS SUPPLIER_TYPE,0 AS CMPSTATECODE,'' AS STATE_NAME ,0 AS STATECODE ,0 AS TOTAL
WHERE NOT EXISTS (SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,
SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, (ISNULL(SUM(SI.SAL_INV_GROSSTOTAL),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO,	 ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    AS CGST,	 ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST , ISNULL(SUM(SI.SAL_INV_ADD5),0)  IGST ,
ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,'S' AS FLAG,6 AS TYPE,'G' DATATYPE
		FROM   "+@DATABASENAME+"  SALES_INVOICE SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UIN HOLDER' )   AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE
"
SET @SQL9A = " UNION ALL SELECT  CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,0 AS OUTER_STATE_SUPPLY,0 AS INTER_STATE_SUPPLY,CM.CMP_STATECODE AS  CMPSTATECODE ,
SM.STATE_NAME,ISNULL(SM.STATE_CODE,0) AS STATECODE, (ISNULL(SUM(SI.Total),0) +ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.SAL_INV_ADD2),0) -( ISNULL(SUM(SI.SAL_INV_LESS1),0) + ISNULL(SUM(SI.SAL_INV_LESS2),0) + ISNULL(SUM(SI.SAL_INV_LESS3),0) + ISNULL(SUM(SI.SAL_INV_LESS4),0)+
 ISNULL(SUM(SI.SAL_INV_LESS5),0)))  AS AMOUNT,ISNULL(MAX(LM.GSTINNO),0) AS LGR_GSTINNO,	 ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    AS CGST,	 ISNULL(SUM(SI.SAL_INV_ADD4),0)  SGST , ISNULL(SUM(SI.SAL_INV_ADD5),0)  IGST ,
ISNULL(SUM(NETAMT),0) AS TOTAL,'S' AS FLAG,6 AS TYPE,'G' DATATYPE
		FROM   "+@DATABASENAME+"  Job_SalesInvoice_Master SI
		INNER JOIN   "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN   "+@DATABASENAME+"  LEDGER_MASTER LM ON  LM.LGR_ID = SI.LGR_ID
		LEFT JOIN   "+@DATABASENAME+"   STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
		INNER JOIN   "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  SI.CMP_CODE IN("+@CMP_CODE+")
AND (ISNULL(LM.REGISTER_DEALER_TYPE,'') ='UIN HOLDER' )   AND CM.CMP_STATECODE <> SM.STATE_CODE
		GROUP BY CM.CMP_NAME ,CM.GSTINNO,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CM.CMP_STATECODE,SM.STATE_NAME,SM.STATE_CODE )"
SET @SQL10 = "
 ORDER BY SUPPLIER_TYPE ,STATECODE
"

END
EXEC (@SQL1+@SQL1A+@SQL2+@SQL2A+@SQL3+@SQL3A+@SQL4+@SQL4A+@SQL5+@SQL5A+@SQL6+@SQL6A+@SQL7+@SQL7A+@SQL8+@SQL8A+@SQL9+@SQL9A+@SQL10)

PRINT @SQL1
PRINT @SQL1A
PRINT @SQL2
PRINT @SQL2A
PRINT @SQL3
PRINT @SQL3A
PRINT @SQL4
PRINT @SQL4A
PRINT @SQL5
PRINT @SQL5A
PRINT @SQL6
PRINT @SQL6A
PRINT @SQL7
PRINT @SQL7A
PRINT @SQL8
PRINT @SQL8A
PRINT @SQL9
PRINT @SQL9A
PRINT @SQL10

























GO

/****** Object:  StoredProcedure [dbo].[PROC_GST_SUMMARY]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS OFF
GO

