/*
-- =============================================
-- Author:		SHUBHAM RAVAL
-- ALTER_date: 10-08-2017
-- Description:	THIS PROCEDURE USED IN GST SUMMARY  REPORT
-- REPORT NAME:  GST_SUMMARY_REPORT
PROC_GST_SUMMARY N'01/APR/2018', N'31/MAR/2019', N'ACC2018_2019.Dbo.', N'1'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_SUMMARY]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100)
    
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
DECLARE @SQL12 AS NVARCHAR(4000)
DECLARE @SQL14 AS NVARCHAR(4000)
DECLARE @SQL15 AS NVARCHAR(4000)
DECLARE @SQL16 AS NVARCHAR(4000)
DECLARE @SQL17 AS NVARCHAR(4000)
DECLARE @SQL18 AS NVARCHAR(4000)


BEGIN

SET @SQL1 ="
SELECT  NAME,LGR_NAME AS LGR_NAME,MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,SUM(AMOUNT)AMOUNT,
SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,SUM(TOTAL)TOTAL,FLAG,PER,(TYPE)[TYPE],SUM(CESS)CESS
FROM 
(	SELECT NAME,LGR_NAME,CMPNAME ,TINNO ,CITY ,CSTNNO,AMOUNT,CGST,SGST,IGST,TOTAL,FLAG,PER,TYPE,CESS   FROM (
		SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.LGR_NAME,ISNULL(SUM(NETTOTAL),0) AS TOTAL,	
		(ISNULL(SUM(PUR.GrossTotal),0) +ISNULL(SUM(PUR.Pur_Inv_Add1),0) + ISNULL(SUM(PUR.Pur_Inv_Add2),0)+ ISNULL(SUM(PUR.Pur_Inv_Add3),0) -( ISNULL(SUM(PUR.Pur_Inv_Less1),0) + ISNULL(SUM(PUR.Pur_Inv_Less2),0) + ISNULL(SUM(PUR.Pur_Inv_Less3),0) + ISNULL(SUM(PUR.Pur_Inv_Less4),0)+ ISNULL(SUM(PUR.Pur_Inv_Less5),0)))  AS AMOUNT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 4' THEN ISNULL(SUM(PUR.PUR_INV_ADD4),0)ELSE 0
		END) AS CGST,
		(CASE 	WHEN VATR.ADDTAXEFFECTFIELD ='ADD 5' THEN ISNULL(SUM(PUR.PUR_INV_ADD5 ),0) ELSE 0
		END) AS SGST ,
		(CASE 	WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 6' THEN ISNULL(SUM(PUR.PUR_INV_ADD6 ),0) ELSE 0
		END) AS IGST ,(ISNULL(Pur_Inv_Add4_Set,0) + ISNULL(Pur_Inv_Add5_Set,0) + ISNULL(Pur_Inv_Add6_Set,0)) AS PER,'P' AS FLAG,1 TYPE,0 AS CESS 
		FROM "+@DATABASENAME+"PURCHASEINVOICE PUR
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PUR.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('P','JP','FP')
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Pur_Inv_Add4_Set,Pur_Inv_Add5_Set,Pur_Inv_Add6_Set,LM.Lgr_Name
"
SET  @SQL2=" UNION  ALL

 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.Lgr_Name,0 - ISNULL(SUM(ROUNDEDAMOUNT),0) AS TOTAL,
		0 - (ISNULL(SUM(PURRET.GrossTotal),0) +ISNULL(SUM(PURRET.Pur_Ret_Add1),0) + ISNULL(SUM(PURRET.Pur_Ret_Add2),0)+ ISNULL(SUM(PURRET.Pur_Ret_Add3),0) -( ISNULL(SUM(PURRET.Pur_Ret_Less1),0) + ISNULL(SUM(PURRET.Pur_Ret_Less2),0) + ISNULL(SUM(PURRET.Pur_Ret_Less3),0) + ISNULL(SUM(PURRET.Pur_Ret_Less4),0)+ ISNULL(SUM(PURRET.Pur_Ret_Less5),0)))  AS AMOUNT,
		0 - (CASE WHEN VATR.EFFECTFIELD ='ADD 4' THEN ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0) ELSE 0 END) AS CGST,
		0 - (CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 5' THEN ISNULL(SUM(PURRET.PUR_RET_ADD5 ),0) ELSE 0 END) AS SGST, 
		0 - (CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 6' THEN ISNULL(SUM(PURRET.PUR_RET_ADD6 ),0) ELSE 0 END) AS IGST,
( isnull(Pur_Ret_Add4_Set,0) + isnull(Pur_Ret_Add5_Set,0) + isnull(Pur_Ret_Add6_Set,0)) as  PER
,'P' AS FLAG,2 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PURRET
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PURRET.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PURRET.CMP_CODE
		LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PURRET.Pur_Acc_Id 
		WHERE PUR_RET_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  
		AND  PURRET.CMP_CODE IN("+@CMP_CODE+") AND PURRET.Flag in ('PR','VPR','FPR')
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Pur_Ret_Add4_Set,Pur_Ret_Add5_Set,Pur_Ret_Add6_Set,LM.Lgr_Name
	"	
SET  @SQL3=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,
LM.LGR_NAME,ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,
(ISNULL(SUM(SI.Sal_Inv_GrossTotal),0) + ISNULL(SUM(SI.Sal_Inv_Add1),0) + ISNULL(SUM(SI.Sal_Inv_Add2),0) -( ISNULL(SUM(SI.Sal_Inv_Less1),0) + ISNULL(SUM(SI.Sal_Inv_Less2),0) + ISNULL(SUM(SI.Sal_Inv_Less3),0) + ISNULL(SUM(SI.Sal_Inv_Less4),0)+ ISNULL(SUM(SI.Sal_Inv_Less5),0)))  AS AMOUNT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,
( isnull(Sal_Inv_Add3_Set,0) + isnull(Sal_Inv_Add4_Set,0) + isnull(Sal_Inv_Add5_Set,0)) as PER,
'S' AS FLAG,3 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"SALES_INVOICE SI
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=SI.Sal_AccID 
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Sal_Inv_Add3_Set,Sal_Inv_Add4_Set,Sal_Inv_Add5_Set,LM.LGR_NAME
	"
SET @SQL10 = " UNION  ALL	
SELECT 
CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO , LM.Lgr_Name AS NAME,LM.Lgr_Name,ISNULL(SUM(TM.Tran_Amount),0) AS TOTAL,ISNULL(SUM(TM.Tran_Amount),0) - (0 +0  +0) AS AMOUNT,0 AS CGST,	0 AS SGST ,	0 AS IGST ,
0 AS PER,'YEXP' AS FLAG,10 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+" TRAN_MASTER TM
		--INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
		INNER JOIN "+@DATABASENAME+"  TRAN_DETAIL TD  ON TD.Tran_Id=TM.Tran_Id AND TD.Tran_type = TM.Tran_type
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_Detail_ID
		INNER JOIN "+@DATABASENAME+" Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID  AND LD.CMP_CODE = TD.CMP_CODE
		WHERE Tran_Date BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  TM.CMP_CODE IN("+@CMP_CODE+") AND LD.GRP_ID IN (1,6) and TM.TRAN_TYPE IN ('BP','CP','EX')
		GROUP BY LM.Lgr_Name,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
"

SET @SQL11 = "  

UNION  ALL	
 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,LM.LGR_NAME AS NAME,LM.LGR_NAME,ISNULL(SUM(NETTOTAL),0) AS TOTAL,
		ISNULL(SUM(NETTOTAL),0) AS AMOUNT,0 AS CGST,0 SGST ,0 AS IGST ,0 AS PER,
'ZEXMPPUR' AS FLAG,11 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"PURCHASEINVOICE PUR
		LEFT JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PUR.VATTYPE_ID 
		LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON  LM.Lgr_Id = PUR.PurACcId 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
		WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('CHP') AND PUR.PUR_FORM_TYPE = 'A'
		GROUP BY LM.LGR_NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
"

/*SET  @SQL9=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,ISNULL(SUM(NetTotal),0) AS TOTAL,ISNULL(SUM(NetTotal),0) -
		((CASE 	WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SOM.SAL_INV_ADD3),0)  ELSE 0 	END) 
 +(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SOM.SAL_INV_ADD4),0) ELSE 0 END) 
 +(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SOM.SAL_INV_ADD5),0) ELSE 0 END) 
) AS AMOUNT,
		(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SOM.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SOM.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SOM.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,'S' AS FLAG,9 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"STOCKOUT_MASTER  SOM
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = SOM.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=SOM.CMP_CODE
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  SOM.CMP_CODE IN("+@CMP_CODE+")
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO 
	"*/
SET  @SQL5=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO, PUR.In_Outer_State AS NAME ,
LM.LGR_NAME,ISNULL(SUM(PURD.finalAmount),0) AS TOTAL,ISNULL(SUM(PURD.finalAmount),0) -
  (ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
) AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST 	,
(isnull(PURD.VAT_PER,0) + ISNULL( VAT_PER1,0) + ISNULL(PURD.VAT_PER2,0) ) AS PER,
'T' AS FLAG,5 TYPE ,0 AS CESS
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='RP'
		GROUP BY  PUR.In_Outer_State,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,VAT_PER,VAT_PER1,VAT_PER2,
LM.LGR_NAME
	"
SET  @SQL6=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO , PUR.In_Outer_State AS NAME ,LM.LGR_NAME,ISNULL(SUM(PURD.FinalAmount),0) AS TOTAL,ISNULL(SUM(PURD.FinalAmount),0) -
  (ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
) AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		 ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST 	,
(isnull(PURD.VAT_PER,0) + ISNULL( VAT_PER1,0) + ISNULL(PURD.VAT_PER2,0) ) AS PER,
'P' AS FLAG,6 TYPE ,ISNULL(SUM(PURD.CESSAMT),0) AS CESS
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND
		PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B'
		AND (PUR.GST_TYPE <> 'InEligible ITC' OR ISNULL(PUR.GST_TYPE,'')='')
		GROUP BY  PUR.In_Outer_State,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,VAT_PER,VAT_PER1,VAT_PER2,LM.LGR_NAME
		
		UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO , PUR.In_Outer_State AS NAME ,LM.LGR_NAME,ISNULL(SUM(PURD.FinalAmount),0) AS TOTAL,ISNULL(SUM(PURD.FinalAmount),0) -
		(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
		) AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
		ISNULL(SUM(PURD.VATAMOUNT1 ),0)  AS SGST ,
		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST 	,
		(isnull(PURD.VAT_PER,0) + ISNULL( VAT_PER1,0) + ISNULL(PURD.VAT_PER2,0) ) AS PER,
		'T' AS FLAG,12 TYPE ,ISNULL(SUM(PURD.CESSAMT),0) AS CESS
		FROM  "+@DATABASENAME+" PURCHASEINVOICE PUR
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUR.PurchaseInvId AND PURD.FLAG = PUR.FLAG 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PURD.FLAG ='CHP' AND PUR.PUR_FORM_TYPE = 'B' AND (PUR.GST_TYPE = 'InEligible ITC')
		GROUP BY  PUR.In_Outer_State,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,VAT_PER,VAT_PER1,VAT_PER2,LM.LGR_NAME
	"

SET  @SQL7=" UNION  ALL	 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.LGR_NAME,ISNULL(SUM(NetAmt),0) AS TOTAL,
(ISNULL(SUM(SI.Total),0) + ISNULL(SUM(SI.SAL_INV_ADD1),0) + ISNULL(SUM(SI.Sal_Inv_Add2),0) -( ISNULL(SUM(SI.Sal_Inv_Less1),0) + ISNULL(SUM(SI.Sal_Inv_Less2),0) + ISNULL(SUM(SI.Sal_Inv_Less3),0) + ISNULL(SUM(SI.Sal_Inv_Less4),0)+ ISNULL(SUM(SI.Sal_Inv_Less5),0)))  AS AMOUNT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,
( isnull(Sal_Inv_Add3_Set,0) + isnull(Sal_Inv_Add4_Set,0) + isnull(Sal_Inv_Add5_Set,0)) as PER,
'S' AS FLAG,7 TYPE ,0 AS CESS
		FROM  "+@DATABASENAME+" Job_SalesInvoice_Master SI
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=SI.Job_SalAccID 
		WHERE Job_Sal_Inv_VDate BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  SI.CMP_CODE IN("+@CMP_CODE+") 
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Sal_Inv_Add3_Set,Sal_Inv_Add4_Set,Sal_Inv_Add5_Set,LM.LGR_NAME
	"

SET  @SQL4=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.LGR_NAME, 0 - ISNULL(SUM(ROUNDEDAMOUNT),0) AS TOTAL,
		0 - (ISNULL(SUM(SIR.GrossTotal),0) + ISNULL(SUM(SIR.Sal_Ret_Add1),0) + ISNULL(SUM(SIR.Sal_Ret_Add2),0) -( ISNULL(SUM(SIR.Sal_Ret_Less1),0) + ISNULL(SUM(SIR.Sal_Ret_Less2),0) + ISNULL(SUM(SIR.Sal_Ret_Less3),0) + ISNULL(SUM(SIR.Sal_Ret_Less4),0)+ ISNULL(SUM(SIR.Sal_Ret_Less5),0)))  AS AMOUNT,
		0 - (CASE 	WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SIR.SAL_RET_ADD3),0) ELSE 0 END) AS CGST,
		0 - (CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SIR.SAL_RET_ADD4 ),0) ELSE 0 END) AS SGST ,
		0 - (CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SIR.SAL_RET_ADD5 ),0) ELSE 0 END) AS IGST ,
		0 AS PER,'S' AS FLAG,4 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"SALES_RETURN_MASTER SIR
		INNER JOIN "+@DATABASENAME+" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SIR.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=SIR.CMP_CODE
		INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=SIR.Sal_Acc_Id 
		WHERE  SAL_RET_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  
		AND  SIR.CMP_CODE IN("+@CMP_CODE+")
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,LM.LGR_NAME
		"


SET @SQL8 = " UNION  ALL	

SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,TRM.In_Outer_State AS NAME,
LM.LGR_NAME,
		(ISNULL(SUM(TOTALFARE_AMOUNT),0) + (ISNULL(SUM(TRM.CGST),0)   + ISNULL(SUM(TRM.SGST),0)
 + ISNULL(SUM(TRM.IGST),0))) AS TOTAL,(ISNULL(SUM(TOTALFARE_AMOUNT),0) -ISNULL(SUM(seskar_amt_total),0)) AS AMOUNT,
		ISNULL(SUM(TRM.CGST),0) AS CGST,
		 ISNULL(SUM(TRM.SGST ),0)  AS SGST ,
		 ISNULL(SUM(TRM.IGST ),0)  AS IGST ,
(ISNULL(CGSTPER,0) + ISNULL(SGSTPER,0) + ISNULL(IGSTPER,0) ) AS PER,
'T' AS FLAG,5 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+" TRANSPORT_PAYMENT TRM
		
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON CM.CMP_CODE=TRM.CMP_CODE 
		LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=TRM.PurAccount_Id
		WHERE  date BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  AND  TRM.CMP_CODE IN("+@CMP_CODE+") 
		GROUP BY TRM.In_Outer_State,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME"
		
SET @SQL14 = " UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,Name,
LM.LGR_NAME,
ISNULL(SUM(DM.TOTALDEBITAMOUNT),0) AS TOTAL , ISNULL(SUM(DM.TRAN_AMOUNT),0) AS AMOUNT,
 ISNULL(SUM(CGST),0) AS CGST, ISNULL(SUM(SGST),0) AS SGST, ISNULL(SUM(IGST),0) AS IGST,

(ISNULL(DM.CGSTPER,0) + ISNULL(DM.SGSTPER,0) + ISNULL(DM.IGSTPER ,0)) AS  PER
,'S' AS FLAG,14 TYPE ,0 AS CESS
 FROM  "+@DATABASENAME+"   DebitNoteAcc_Master DM
INNER JOIN  "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
 inner join "+@DATABASENAME+"  Ledger_Master LM on LM.Lgr_ID=DM.DEBITAC_ID 
INNER JOIN  "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.note = 'DR Note Issued Against Sale'
AND DM.Tran_Date BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND DM.CMP_CODE IN("+@CMP_CODE+")
GROUP BY Name,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME
		"

SET  @SQL15="UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,Name,
LM.LGR_NAME,
(0- ISNULL(SUM(DM.TOTALDEBITAMOUNT),0)) AS TOTAL , (0- ISNULL(SUM(DM.TRAN_AMOUNT),0)) AS AMOUNT,
 (0- ISNULL(SUM(CGST),0)) AS CGST, (0- ISNULL(SUM(SGST),0)) AS SGST,(0-  ISNULL(SUM(IGST),0)) AS IGST,
(ISNULL(DM.CGSTPER,0) + ISNULL(DM.SGSTPER,0) + ISNULL(DM.IGSTPER ,0)) AS  PER
,'P' AS FLAG,15 TYPE ,0 AS CESS
 FROM  "+@DATABASENAME+"  DebitNoteAcc_Master DM
INNER JOIN  "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
 inner join "+@DATABASENAME+"  Ledger_Master LM on LM.Lgr_ID=DM.DEBITAC_ID 
INNER JOIN  "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.note = 'CR Note Received Against Purchase' AND DM.Tran_Date BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND DM.CMP_CODE IN("+@CMP_CODE+")
GROUP BY Name,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME
	"
	
SET @SQL16 = "  UNION ALL
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,Name,
LM.LGR_NAME,
ISNULL(SUM(DM.TOTALDEBITAMOUNT),0) AS TOTAL , ISNULL(SUM(DM.TRAN_AMOUNT),0) AS AMOUNT,
 ISNULL(SUM(CGST),0) AS CGST, ISNULL(SUM(SGST),0) AS SGST, ISNULL(SUM(IGST),0) AS IGST,
(ISNULL(DM.CGSTPER,0) + ISNULL(DM.SGSTPER,0) + ISNULL(DM.IGSTPER ,0)) AS  PER
,'P' AS FLAG,16 TYPE ,0 AS CESS
 FROM  "+@DATABASENAME+" CreditNoteAcc_Master DM
INNER JOIN  "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
 inner join "+@DATABASENAME+"  Ledger_Master LM on LM.Lgr_ID=DM.DEBITAC_ID 
INNER JOIN  "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.note = 'DR Note Received Against Purchase' AND DM.Tran_Date BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND DM.CMP_CODE IN("+@CMP_CODE+")
GROUP BY Name,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME"

SET @SQL17 = " UNION ALL 
SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,Name,
LM.LGR_NAME,
(0-ISNULL(SUM(DM.TOTALDEBITAMOUNT),0)) AS TOTAL ,(0-ISNULL(SUM(DM.TRAN_AMOUNT),0)) AS AMOUNT,
(0- ISNULL(SUM(CGST),0)) AS CGST,(0- ISNULL(SUM(SGST),0)) AS SGST,(0- ISNULL(SUM(IGST),0)) AS IGST,
(ISNULL(DM.CGSTPER,0) + ISNULL(DM.SGSTPER,0) + ISNULL(DM.IGSTPER ,0)) AS  PER
,'S' AS FLAG,17 TYPE ,0 AS CESS
 FROM  "+@DATABASENAME+" CreditNoteAcc_Master DM
INNER JOIN  "+@DATABASENAME+"  VATCATEGORYMASTER VATR ON  VATR.DOCNO = DM.TYPE_ID 
inner join "+@DATABASENAME+"  Ledger_Master LM on LM.Lgr_ID=DM.DEBITAC_ID 
INNER JOIN  "+@DATABASENAME+"  COMPANY_MASTER CM ON CM.CMP_CODE=DM.CMP_CODE 
WHERE DM.note = 'CR Note Issued Against Sale' AND DM.Tran_Date BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND DM.CMP_CODE IN("+@CMP_CODE+")
GROUP BY Name,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO,CGSTPER,SGSTPER,IGSTPER ,LM.LGR_NAME"
SET @SQL12 = " ) AS DETAIL ) AS SDSD 
GROUP BY NAME,LGR_NAME,PER,FLAG,TYPE ORDER BY TYPE "


SET @SQL18=" UNION  ALL	 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO,PURRET.IN_OUTER_STATE AS NAME,LM.Lgr_Name,
		ISNULL(SUM(ROUNDEDAMOUNT),0) AS TOTAL,
		(ISNULL(SUM(PURRET.NetTotal),0)-(ISNULL(SUM(PURDT.VATAMOUNT),0) +ISNULL(SUM(PURDT.VATAMOUNT1),0)+ISNULL(SUM(PURDT.VATAMOUNT2),0)))  AS AMOUNT,
		ISNULL(SUM(PURDT.VATAMOUNT),0) AS CGST,
		ISNULL(SUM(PURDT.VATAMOUNT1),0) AS SGST, 
		ISNULL(SUM(PURDT.VATAMOUNT2),0) AS IGST,
		( isnull(SUM(PURDT.VAT_PER),0) + isnull(SUM(PURDT.VAT_PER1),0) + isnull(SUM(PURDT.VAT_PER2),0)) as  PER
		,'P' AS FLAG,2 TYPE ,0 AS CESS
		FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PURRET		
		INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PURDT ON PURDT.Pur_Ret_Id = PURRET.Pur_Ret_Id AND PURDT.FLAG=PURRET.FLAG		
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PURRET.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=PURRET.Pur_Acc_Id 
		WHERE PUR_RET_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"'  
		AND  PURRET.CMP_CODE IN("+@CMP_CODE+") AND PURRET.Flag in ('CPR')
		GROUP BY PURRET.IN_OUTER_STATE,CM.CMP_NAME,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO,VAT_PER,VAT_PER1,VAT_PER2,LM.Lgr_Name
		"
END

EXEC (@SQL1+@SQL2+@SQL18+@SQL3+@SQL4+@SQL5+@SQL6+@SQL7+@SQL8+@SQL9+@SQL10+@SQL11+@SQL14+@SQL15+@SQL16+@SQL17+@SQL12)
PRINT @SQL1
PRINT @SQL2
PRINT @SQL18
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @SQL7
PRINT @SQL8
PRINT @SQL9
PRINT @SQL10
PRINT @SQL11
PRINT @SQL14
PRINT @SQL15
PRINT @SQL16
PRINT @SQL17
