/*
-- =============================================
-- Author:		SHUBHAM RAVAL
-- Create_date: 10-08-2017
-- Description:	THIS PROCEDURE USED IN GST SUMMARY  REPORT
-- REPORT NAME:  GST_SUMMARY_REPORT
PROC_GST_SUMMARY_DETAIL N'23/mar/2018', N'23/mar/2018', N'ACC2017_2018.Dbo.', N'1'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_GST_SUMMARY_DETAIL]
(
    @FROMDATE  NVARCHAR(20),
	@TODATE NVARCHAR(20),    
    @DATABASENAME NVARCHAR(50),
	@CMP_CODE NVARCHAR(100)    
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL6D AS NVARCHAR(4000)

DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
DECLARE @SQL12 AS NVARCHAR(4000)
DECLARE @SQL13 AS NVARCHAR(4000)
DECLARE @SQL14 AS NVARCHAR(4000)
DECLARE @SQL15 AS NVARCHAR(4000)
DECLARE @SQL16 AS NVARCHAR(4000)
DECLARE @SQL17 AS NVARCHAR(4000)
DECLARE @SQL18 AS NVARCHAR(4000)
DECLARE @SQL19 AS NVARCHAR(4000)
DECLARE @SQLMONTH AS NVARCHAR(4000)


		BEGIN	
		set @SQLMONTH="( SELECT (DATEPART(month,DATEADD(month, -1, '"+@FROMDATE+"'))) ) " 		
		END


BEGIN

SET @SQL1 ="
SELECT  NAME,LGR_NAME,MAX(CMPNAME)CMPNAME,MAX(TINNO)TINNO,MAX(CITY)CITY,MAX(CSTNNO)CSTNNO,SUM(AMOUNT)AMOUNT,
SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,SUM(TOTAL)TOTAL,FLAG,SUM(TOTALTAX)TOTALTAX,PER,[TYPE]TYPE,SUM(CESS)CESS
FROM 
(	SELECT NAME,LGR_NAME,CMPNAME ,TINNO ,CITY ,CSTNNO,AMOUNT,CGST,SGST,IGST,TOTAL,FLAG,TOTALTAX,PER,TYPE,CESS   FROM (
		SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.LGR_NAME,ISNULL(SUM(NETTOTAL),0) AS TOTAL,
		ISNULL(SUM(GrossTotal),0) +
		  (ISNULL(SUM(PUR.PUR_INV_ADD1),0) 
 + ISNULL(SUM(PUR.PUR_INV_ADD2),0) 
 + ISNULL(SUM(PUR.PUR_INV_ADD3),0) )
-(
+(ISNULL(SUM(PUR.Pur_Inv_Less1),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less2),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less3),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less4),0)) 
+(ISNULL(SUM(PUR.Pur_Inv_Less5),0)) 
) AS AMOUNT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 4' THEN ISNULL(SUM(PUR.PUR_INV_ADD4),0) ELSE 0 END) AS CGST,
		(CASE 	WHEN VATR.ADDTAXEFFECTFIELD ='ADD 5' THEN ISNULL(SUM(PUR.PUR_INV_ADD5 ),0) ELSE 0
		END) AS SGST ,
		(CASE 	WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 6' THEN ISNULL(SUM(PUR.PUR_INV_ADD6 ),0) ELSE 0
		END) AS IGST ,
(ISNULL(SUM(PUR.PUR_INV_ADD4),0) + ISNULL(SUM(PUR.PUR_INV_ADD5 ),0) + ISNULL(SUM(PUR.PUR_INV_ADD6 ),0)) AS TOTALTAX,

(ISNULL(Pur_Inv_Add4_Set,0) + ISNULL(Pur_Inv_Add5_Set,0) + ISNULL(Pur_Inv_Add6_Set,0)) AS PER,'P' AS FLAG,1 TYPE, 0 AS CESS
		FROM "+@DATABASENAME+"PURCHASEINVOICE PUR
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PUR.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PUR.CMP_CODE 
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PUR.PurACcId 
		WHERE  VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  AND  PUR.CMP_CODE IN("+@CMP_CODE+") AND PUR.FLAG IN ('P','JP','FP')
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Pur_Inv_Add4_Set,Pur_Inv_Add5_Set,Pur_Inv_Add6_Set,LM.Lgr_Name
"
SET  @SQL2=" UNION  ALL

 SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,
 NAME,LM.Lgr_Name,(0 - ISNULL(SUM(ROUNDEDAMOUNT),0) ) AS TOTAL,
		(0 -(	ISNULL(SUM(GrossTotal),0) +
		(ISNULL(SUM(PURRET.PUR_RET_ADD1),0) 
		+ISNULL(SUM(PURRET.PUR_RET_ADD2),0)
		+ISNULL(SUM(PURRET.PUR_RET_ADD3),0)
)-
(
+(ISNULL(SUM(PURRET.Pur_Ret_Less1),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less2),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less3),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less4),0))
+(ISNULL(SUM(PURRET.Pur_Ret_Less5),0))
 ) ))AS AMOUNT,
	 	(0 - (CASE WHEN VATR.EFFECTFIELD ='ADD 4' THEN ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0) ELSE 0
		END)) AS CGST,
		(0 - (CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 5' THEN ISNULL(SUM(PURRET.PUR_RET_ADD5 ),0) ELSE 0
		END) )AS SGST, 
		(0 - (CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 6' THEN ISNULL(SUM(PURRET.PUR_RET_ADD6 ),0) ELSE 0
		END) )AS IGST,
(0 - (ISNULL(SUM(PURRET.PUR_RET_ADD4 ),0) + ISNULL(SUM(PURRET.PUR_RET_ADD5 ),0) +  ISNULL(SUM(PURRET.PUR_RET_ADD6 ),0))) AS TOTALTAX,
( isnull(Pur_Ret_Add4_Set,0) + isnull(Pur_Ret_Add5_Set,0) + isnull(Pur_Ret_Add6_Set,0)) as  PER
,'P' AS FLAG,3 TYPE, 0 AS CESS
		FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PURRET
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = PURRET.VATTYPE_ID 
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PURRET.CMP_CODE
		LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=PURRET.Pur_Acc_Id 
		WHERE PUR_RET_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'  
		AND  PURRET.CMP_CODE IN("+@CMP_CODE+")
		GROUP BY NAME,VATR.EFFECTFIELD,VATR.ADDTAXEFFECTFIELD,VATR.ADDTAX1EFFECTFIELD,CM.CMP_NAME ,CM.GSTINNO ,CM.CMP_CITY ,CM.CMP_SERVICETAX_NO ,Pur_Ret_Add4_Set,Pur_Ret_Add5_Set,Pur_Ret_Add6_Set,LM.Lgr_Name
	"
SET  @SQL3=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,NAME,LM.LGR_NAME,ISNULL(SUM(SAL_INV_NETTOTAL),0) AS TOTAL,
ISNULL(SUM(Sal_Inv_GrossTotal),0) +
		(ISNULL(SUM(SI.SAL_INV_ADD1),0) 
 +ISNULL(SUM(SI.SAL_INV_ADD2),0) 
)-(+(ISNULL(SUM(SI.Sal_Inv_Less1),0) ) +(ISNULL(SUM(SI.Sal_Inv_Less2),0)) +(ISNULL(SUM(SI.Sal_Inv_Less3),0)) 
+(ISNULL(SUM(SI.Sal_Inv_Less4),0)) +(ISNULL(SUM(SI.Sal_Inv_Less5),0)) ) AS AMOUNT,	(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SUM(SI.SAL_INV_ADD3),0) 
	    ELSE 0 END) AS CGST,
		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SUM(SI.SAL_INV_ADD4),0)
        ELSE 0 END) AS SGST ,
		(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SUM(SI.SAL_INV_ADD5),0)
        ELSE 0 END) AS IGST ,
(ISNULL(SUM(SI.SAL_INV_ADD3),0)  + ISNULL(SUM(SI.SAL_INV_ADD4),0) + ISNULL(SUM(SI.SAL_INV_ADD5),0)) AS TOTALTAX,
( isnull(Sal_Inv_Add3_Set,0) + isnull(Sal_Inv_Add4_Set,0) + isnull(Sal_Inv_Add5_Set,0)) as PER,
'S' AS FLAG,4 TYPE , 0 AS CESS
		FROM "+@DATABASENAME+"SALES_INVOICE SI
		INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=SI.CMP_CODE
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.Lgr_Id=SI.Sal_AccID 
		WHERE SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
		AND  SI.CMP_CODE IN("+@CMP_CODE+")
