	"
SET @SQL10 = " UNION  ALL	
SELECT CMPNAME ,TINNO,CITY,CSTNNO ,NAME ,Lgr_Name, ISNULL(SUM(DRAMT)- SUM(CRAMT) ,0) AS TOTAL,ISNULL(SUM(DRAMT)- SUM(CRAMT) ,0) - (0 +0  +0) AS AMOUNT ,0 AS CGST,	0 AS SGST ,	0 AS IGST ,0 AS TOTALTAX,0 AS PER,'YEXP' AS FLAG,10 TYPE, 0 AS CESS FROM (

SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO , LM.Lgr_Name AS NAME,'' AS Lgr_Name,( CASE WHEN TM.TRAN_TYPE IN ('CP','BP','EX') THEN ISNULL(TM.Tran_Amount,0) ELSE 0 END ) AS DRAMT,
( CASE WHEN TM.TRAN_TYPE IN ('CR','BR') THEN isnull(TM.Tran_Amount,0) ELSE 0 END ) AS CRAMT 
FROM "+@DATABASENAME+"TRAN_MASTER TM
--INNER JOIN "+@DATABASENAME+"VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE		
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD  ON TD.Tran_Id=TM.Tran_Id AND TD.Tran_type = TM.Tran_type
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_Detail_ID
INNER JOIN "+@DATABASENAME+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TD.CMP_CODE
WHERE Tran_Date BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND TM.TRAN_TYPE IN('CR','BR','CP','BP','EX')
AND  TM.CMP_CODE IN("+@CMP_CODE+") AND LD.GRP_ID IN (1,6)
) AS DEATIL GROUP BY NAME,Lgr_Name,CMPNAME ,TINNO ,CITY ,CSTNNO
"

SET @SQL12 = " UNION  ALL	
