WHERE TM.CMP_CODE IN ("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND TM.TRAN_TYPE= 'J'
And GM.Grp_Main_Name in('Expenses(Direct/Mfgr.)','Income(Direct/Operational)','Expenses(Indirect/Admn)','Income(Indirect)') ) AS A 
GROUP BY CMPNAME,TINNO,CITY,CSTNNO,NAME,Lgr_Name
"

