SET  @SQL5=" UNION  ALL	SELECT CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO, PUR.In_Outer_State AS NAME ,
LM.LGR_NAME,ISNULL(SUM(PURD.FINALAMOUNT),0) AS TOTAL,ISNULL(SUM(PURD.AMOUNT),0) 
  --(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)
 AS AMOUNT, ISNULL(SUM(PURD.vat_amt),0)  AS CGST,
