		ISNULL(SUM(PURD.VATAMOUNT2 ),0)  AS IGST 	,
(ISNULL(SUM(PURD.vat_amt),0) + ISNULL(SUM(PURD.VATAMOUNT1 ),0) + ISNULL(SUM(PURD.VATAMOUNT2 ),0)) AS TOTALTAX,
(isnull(PURD.VAT_PER,0) + ISNULL( VAT_PER1,0) + ISNULL(PURD.VAT_PER2,0) ) AS PER,
'T' AS FLAG,7 TYPE , 0 AS CESS
