/*
=============================================
-- Author:		<SANJU,M,PARMAR>
-- ALTER date: <14-05-2019,6:12,PM>
-- Description:	<This Procedure is use for fetch purchase data by head or month wise,PROC_HEAD_WISE_MONTLY_PURCHASE,>
=============================================

PROC_HEAD_WISE_MONTLY_PURCHASE N'01/apr/2018', N'31/mar/2019', N'Acc2018_2019.Dbo.', N'1', N'##3900', 1

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/

CREATE PROCEDURE [dbo].[PROC_HEAD_WISE_MONTLY_PURCHASE]
(
@FromDate  nvarchar(20),
@ToDate nvarchar(20),    
@DatabaseName nvarchar(50),
@Cmp_Code nvarchar(100),    
@TempTable nvarchar(20),
@SelAll int
)
AS
DECLARE @MIX AS NVARCHAR(3999)
DECLARE @RP AS NVARCHAR(3999)
DECLARE @MISC AS NVARCHAR(3999)
DECLARE @CHEM AS NVARCHAR(3999)
DECLARE @MIP AS NVARCHAR(3999)
DECLARE @TRAN AS NVARCHAR(3999)
DECLARE @GCN AS NVARCHAR(3999)
DECLARE @GDN AS NVARCHAR(3999)
DECLARE @AJ AS NVARCHAR(3999)
DECLARE @J AS NVARCHAR(3999)
DECLARE @TEMPLINK NVARCHAR(3999)
DECLARE @TEMPLINK_TRAN AS NVARCHAR(3999)
DECLARE @TEMPLINK_GCN AS NVARCHAR(3999)
DECLARE @TEMPLINK_AJ AS NVARCHAR(3999)
DECLARE @TEMPLINK_J AS NVARCHAR(3999)


SET @MIX=""
SET @RP=""
SET @MISC=""
SET @CHEM=""
SET @TRAN=""
SET @GCN=""
SET @GDN=""
SET @AJ=""
SET @J=""
SET @TEMPLINK=""
SET @TEMPLINK_TRAN=""
SET @TEMPLINK_GCN=""
SET @TEMPLINK_AJ=""
SET @TEMPLINK_J=""
SET @MIP=""

	IF @SelAll=0
		begin
			SET @TEMPLINK=""
			SET @TEMPLINK_TRAN=""
			SET @TEMPLINK_GCN=""
			SET @TEMPLINK_AJ=""
			SET @TEMPLINK_J=""
		end
	ELSE
		begin
			SET @TEMPLINK="INNER JOIN " + @TempTable + " TT ON PI.PURACCID=TT.CODE"
			SET @TEMPLINK_TRAN="INNER JOIN " + @TempTable + " TT ON TD.TRAN_DETAIL_ID=TT.CODE"
			SET @TEMPLINK_GCN="INNER JOIN " + @TempTable + " TT ON PI.DEBITAC_ID=TT.CODE"			
			SET @TEMPLINK_AJ="INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"			
			SET @TEMPLINK_J="INNER JOIN " + @TempTable + " TT ON TD.TRAN_DETAIL_ID=TT.CODE"
		end
BEGIN		
SET @MIX=" 
SELECT MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(TOTALTAX)TOTALTAX,SUM(ROFF)ROFF,(MONTHORD)MONTHORD,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST) IGST FROM (
SELECT PI.PURCHASEINVID,PI.BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'MIX' AS FLAG,UPPER(DATENAME(MM,PI.VCHDATE))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) + ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,MAX(ISNULL(PI.Pur_Inv_Add4,0) + ISNULL(PI.Pur_Inv_Add5,0) + ISNULL(PI.Pur_Inv_Add6,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF,
MAX(ISNULL((PI.PUR_INV_ADD4),0)) AS CGST , MAX(ISNULL((PI.PUR_INV_ADD5),0)) AS SGST , MAX(ISNULL((PI.PUR_INV_ADD6),0)) AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PI.FLAG IN ('P','FP','JP')
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE"

SET @RP=" UNION ALL 
SELECT PI.PURCHASEINVID,PI.BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'RP' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(PID.AMOUNT) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,SUM(ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF ,
SUM(ISNULL((PID.vat_amt),0))  AS CGST,  SUM(ISNULL((PID.VATAMOUNT1 ),0)) AS SGST, SUM(ISNULL((PID.VATAMOUNT2),0)) AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PI.FLAG IN ('RP')
GROUP BY  PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE "

SET @MISC=" UNION ALL 
SELECT PI.PURCHASEINVID,PI.BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'MISC' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PID.Amount,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,SUM(ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF ,
SUM(ISNULL((PID.vat_amt),0)) AS CGST , SUM(ISNULL((PID.VATAMOUNT1 ),0)) AS SGST , SUM(ISNULL((PID.VATAMOUNT2 ),0)) AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND (PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B') 
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE "

SET @CHEM=" UNION ALL 
SELECT PI.PURCHASEINVID,PI.BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'CHEM' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.NetTotal,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetTotal,0)) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF ,0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND (PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'A') 
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE"

SET @TRAN=" UNION ALL
SELECT PURCHASEINVID,BILLNO,MONTHORD,FLAG,MONTHS,HEAD,'UnRegistered Dealer' as Dealer,SUM(DRAMT - CRAMT)AS TAXABLEAMT,SUM(DRAMT - CRAMT)AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF,0 AS CGST,0 AS SGST , 0 AS IGST FROM (
SELECT TM.TRAN_ID AS PURCHASEINVID,TM.TRAN_DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END)AS MONTHORD,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
( CASE WHEN TM.TRAN_TYPE IN ('CP','BP','EX','CN') THEN ISNULL(TM.Tran_Amount,0) ELSE 0 END ) AS DRAMT,                
( CASE WHEN TM.TRAN_TYPE IN ('CR','BR','DN') THEN isnull(TM.Tran_Amount,0) ELSE 0 END ) AS CRAMT,'BPCP' AS FLAG,
LM.LGR_NAME AS HEAD
FROM "+@DatabaseName+"TRAN_MASTER TM                
INNER JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE                
INNER JOIN "+@DatabaseName+"TRAN_DETAIL TD  ON TD.Tran_Id=TM.Tran_Id AND TD.Tran_type = TM.Tran_type                
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_Detail_ID                
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TD.CMP_CODE                
"+@TEMPLINK_TRAN+"
WHERE TM.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'  AND TM.TRAN_TYPE IN('DN','CN','CR','BR','CP','BP','EX')                
AND  TM.CMP_CODE IN ("+@Cmp_Code+") ) AS DEATIL GROUP BY PURCHASEINVID,BILLNO,MONTHORD,MONTHS,FLAG,HEAD "

SET @GCN=" UNION ALL
SELECT PI.CreditNoteAcc_Id AS PURCHASEINVID,PI.TRAN_DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,PI.TRAN_DATE)<=3 THEN (DATEPART(M,PI.TRAN_DATE)+12)ELSE DATEPART(M,PI.TRAN_DATE) END)AS MONTHORD,'GCN' AS FLAG,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.TRAN_AMOUNT,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetAmount,0)) AS NETTOTAL,SUM(ISNULL(PI.CGST,0)+ISNULL(PI.SGST,0)+ISNULL(PI.IGST,0)) AS TOTALTAX,SUM(ISNULL(RoundOff,0)) AS ROFF ,
SUM(ISNULL((PI.CGST),0)) AS CGST , SUM(ISNULL((PI.SGST ),0)) AS SGST , SUM(ISNULL((PI.IGST ),0)) AS IGST
FROM "+@DatabaseName+"CREDITNOTEACC_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_GCN+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.TRAN_TYPE IN ('GCN') AND PI.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.CreditNoteAcc_Id,PI.TRAN_DOCNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,TRAN_DATE"

SET @GDN=" UNION ALL
SELECT PI.DebitNoteAcc_Id AS PURCHASEINVID,PI.TRAN_DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,PI.TRAN_DATE)<=3 THEN (DATEPART(M,PI.TRAN_DATE)+12)ELSE DATEPART(M,PI.TRAN_DATE) END)AS MONTHORD,'GCN' AS FLAG,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(0-ISNULL(PI.TRAN_AMOUNT,0)) AS TAXABLEAMT,
SUM(0-ISNULL(PI.NetAmount,0)) AS NETTOTAL,SUM((0-ISNULL(PI.CGST,0)+ISNULL(PI.SGST,0)+ISNULL(PI.IGST,0))) AS TOTALTAX,SUM(0-ISNULL(RoundOff,0)) AS ROFF ,
SUM(ISNULL((PI.CGST),0)) AS CGST , SUM(ISNULL((PI.SGST ),0)) AS SGST , SUM(ISNULL((PI.IGST ),0)) AS IGST

FROM "+@DatabaseName+"DEBITNOTEACC_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_GCN+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.TRAN_TYPE IN ('GDN') AND PI.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.DebitNoteAcc_Id,PI.TRAN_DOCNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,TRAN_DATE"

SET @AJ=" UNION ALL 
SELECT TM.VCODE AS PURCHASEINVID,TM.CODE AS BILLNO,(CASE WHEN DATEPART(M,TM.VDATE)<=3 THEN (DATEPART(M,TM.VDATE)+12)ELSE DATEPART(M,TM.VDATE) END)AS MONTHORD,'AJ' AS FLAG,
UPPER(DATENAME(M,VDATE))MONTHS,LM.Lgr_Name AS HEAD,'UnRegistered Dealer' AS DEALER,ISNULL(SUM(TM.DRAMOUNT) - SUM(TM.CRAMOUNT),0) AS TAXABLEAMT,
ISNULL(SUM(TM.DRAMOUNT - TM.CRAMOUNT),0) - (0 +0  +0) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF,0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"AUTOJOURNAL TM
LEFT JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=TM.LGR_ID 
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TM.CMP_CODE
"+@TEMPLINK_AJ+"
WHERE TM.CMP_CODE IN ("+@Cmp_Code+") AND TM.VDATE BETWEEN '"+@FromDate+"' AND  '"+@ToDate+"'  
GROUP BY VCODE,TM.CODE,VDATE,LM.Lgr_Name"

SET @J=" UNION ALL
SELECT PURCHASEINVID,BILLNO,MONTHORD,FLAG,MONTHS,HEAD,'UnRegistered Dealer' as Dealer,SUM(DRAMOUNT - CRAMOUNT)AS TAXABLEAMT,SUM(DRAMOUNT - CRAMOUNT)AS NETTOTAL,
0 AS TOTALTAX,0 AS ROFF,0 AS CGST , 0 AS SGST , 0 AS IGST FROM (
SELECT TM.TRAN_ID AS PURCHASEINVID,TM.TRAN_DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END)AS MONTHORD,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,
CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,LM.Lgr_Name AS HEAD,LM.Lgr_Name,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,0 AS CGST,	0 AS SGST ,	0 AS IGST ,0 AS TOTALTAX,0 AS PER,'J' AS FLAG,10 TYPE                
FROM "+@DatabaseName+"TRAN_MASTER TM                
INNER JOIN "+@DatabaseName+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
LEFT JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID 
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TD.CMP_CODE
"+@TEMPLINK_J+"
WHERE TM.CMP_CODE IN ("+@Cmp_Code+") AND TM.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND TM.TRAN_TYPE= 'J' ) AS A 
GROUP BY PURCHASEINVID,BILLNO,MONTHORD,MONTHS,FLAG,HEAD"

SET @MIP="  UNION ALL 
SELECT PI.PURCHASEINVID,PI.BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'MIP' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.NetTotal,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetTotal,0)) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF, 0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.FLAG ='MIP' AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'  
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE

)AS A
GROUP BY MONTHORD,MONTHS,HEAD,DEALER
ORDER BY MONTHORD,MONTHS,DEALER,HEAD "
END
EXEC (@MIX+@RP+@MISC+@CHEM+@TRAN+@GCN+@GDN+@AJ+@J+@MIP)
PRINT @MIX
PRINT @RP
PRINT @MISC
PRINT @CHEM
PRINT @TRAN
PRINT @GCN
PRINT @GDN
PRINT @AJ
PRINT @J
PRINT @MIP













GO

/****** Object:  StoredProcedure [dbo].[PROC_HEAD_WISE_MONTLY_PURCHASE_DETAIL]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO













/*
=============================================
-- Author:		<SANJU,M,PARMAR>
-- ALTER date: <14-05-2019,6:12,PM>
-- Description:	<This Procedure is use for fetch purchase detail data by head or month wise,PROC_HEAD_WISE_MONTLY_PURCHASE_DETAIL,>
=============================================

PROC_HEAD_WISE_MONTLY_PURCHASE_DETAIL N'01/MAR/2018', N'31/MAR/2019', N'Acc2018_2019.Dbo.', N'1', N'##4492', 1

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/

CREATE PROCEDURE [dbo].[PROC_HEAD_WISE_MONTLY_PURCHASE_DETAIL]
(
@FromDate  nvarchar(20),
@ToDate nvarchar(20),    
@DatabaseName nvarchar(50),
@Cmp_Code nvarchar(100),    
@TempTable nvarchar(20),
@SelAll int
)
AS
DECLARE @MIX AS NVARCHAR(3999)
DECLARE @RP AS NVARCHAR(3999)
DECLARE @MISC AS NVARCHAR(3999)
DECLARE @CHEM AS NVARCHAR(3999)
DECLARE @MIP AS NVARCHAR(3999)
DECLARE @TRAN AS NVARCHAR(3999)
DECLARE @GCN AS NVARCHAR(3999)
DECLARE @GDN AS NVARCHAR(3999)
DECLARE @AJ AS NVARCHAR(3999)
DECLARE @J AS NVARCHAR(3999)
DECLARE @TEMPLINK NVARCHAR(3999)
DECLARE @TEMPLINK_TRAN AS NVARCHAR(3999)
DECLARE @TEMPLINK_GCN AS NVARCHAR(3999)
DECLARE @TEMPLINK_AJ AS NVARCHAR(3999)
DECLARE @TEMPLINK_J AS NVARCHAR(3999)


SET @MIX=""
SET @RP=""
SET @MISC=""
SET @CHEM=""
SET @TRAN=""
SET @GCN=""
SET @GDN=""
SET @AJ=""
SET @J=""
SET @TEMPLINK=""
SET @TEMPLINK_TRAN=""
SET @TEMPLINK_GCN=""
SET @TEMPLINK_AJ=""
SET @TEMPLINK_J=""
SET @MIP=""

	IF @SelAll=0
		begin
			SET @TEMPLINK=""
			SET @TEMPLINK_TRAN=""
			SET @TEMPLINK_GCN=""
			SET @TEMPLINK_AJ=""
			SET @TEMPLINK_J=""
		end
	ELSE
		begin
			SET @TEMPLINK="INNER JOIN " + @TempTable + " TT ON PI.PURACCID=TT.CODE"
			SET @TEMPLINK_TRAN="INNER JOIN " + @TempTable + " TT ON TD.TRAN_DETAIL_ID=TT.CODE"
			SET @TEMPLINK_GCN="INNER JOIN " + @TempTable + " TT ON PI.DEBITAC_ID=TT.CODE"			
			SET @TEMPLINK_AJ="INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"			
			SET @TEMPLINK_J="INNER JOIN " + @TempTable + " TT ON TD.TRAN_DETAIL_ID=TT.CODE"
		end
BEGIN		
SET @MIX=" 
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,PI.FLAG AS FLAG,UPPER(DATENAME(MM,PI.VCHDATE))MONTHS,
ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) + ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,MAX(ISNULL(PI.Pur_Inv_Add4,0) + ISNULL(PI.Pur_Inv_Add5,0) + ISNULL(PI.Pur_Inv_Add6,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF,
SUM(ISNULL((PI.PUR_INV_ADD4),0)) AS CGST , SUM(ISNULL((PI.PUR_INV_ADD5),0)) AS SGST , SUM(ISNULL((PI.PUR_INV_ADD6),0)) AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PI.FLAG IN ('P','FP','JP')
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE,FLAG,LM.LGR_NAME"

SET @RP=" UNION ALL 
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'RP' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(PID.AMOUNT) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,SUM(ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF ,
SUM(ISNULL((PID.vat_amt),0))  AS CGST,  SUM(ISNULL((PID.VATAMOUNT1 ),0)) AS SGST, SUM(ISNULL((PID.VATAMOUNT2),0)) AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND PI.FLAG IN ('RP')
GROUP BY  PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE,LM.LGR_NAME"

SET @MISC=" UNION ALL 
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'MISC' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PID.Amount,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,SUM(ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))AS TOTALTAX,MAX(ISNULL(PI.PUR_INV_ROUNDOFF,0))AS ROFF,
SUM(ISNULL((PI.PUR_INV_ADD4),0)) AS CGST , SUM(ISNULL((PI.PUR_INV_ADD5),0)) AS SGST , SUM(ISNULL((PI.PUR_INV_ADD6),0)) AS IGST 
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND (PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B') 
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE,LM.LGR_NAME"

SET @CHEM=" UNION ALL 
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'CHEM' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.NetTotal,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetTotal,0)) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF ,0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND (PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'A') 
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE,LM.LGR_NAME"

SET @TRAN=" UNION ALL
SELECT PURCHASEINVID,CONVERT(NVARCHAR,BILLNO)BILLNO,MONTHORD,FLAG,MONTHS,PARTY,HEAD,'UnRegistered Dealer' as Dealer,SUM(DRAMT - CRAMT)AS TAXABLEAMT,SUM(DRAMT - CRAMT)AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF,0 AS CGST , 0 AS SGST , 0 AS IGST FROM (
SELECT TM.TRAN_ID AS PURCHASEINVID,TM.TRAN_DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END)AS MONTHORD,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
( CASE WHEN TM.TRAN_TYPE IN ('CP','BP','EX','CN') THEN ISNULL(TM.Tran_Amount,0) ELSE 0 END ) AS DRAMT,                
( CASE WHEN TM.TRAN_TYPE IN ('CR','BR','DN') THEN isnull(TM.Tran_Amount,0) ELSE 0 END ) AS CRAMT,'BPCP' AS FLAG,
ISNULL(LMP.LGR_NAME,'')AS PARTY,ISNULL(LM.LGR_NAME,'')AS HEAD
FROM "+@DatabaseName+"TRAN_MASTER TM                
INNER JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE                
INNER JOIN "+@DatabaseName+"TRAN_DETAIL TD  ON TD.Tran_Id=TM.Tran_Id AND TD.Tran_type = TM.Tran_type                
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.Lgr_Id=TD.Tran_Detail_ID                
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LMP ON LMP.Lgr_Id=TM.TRAN_MASTER_ID
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TD.CMP_CODE                
"+@TEMPLINK_TRAN+"
WHERE TM.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'  AND TM.TRAN_TYPE IN('DN','CN','CR','BR','CP','BP','EX')                
AND  TM.CMP_CODE IN ("+@Cmp_Code+") ) AS DEATIL GROUP BY PURCHASEINVID,BILLNO,MONTHORD,MONTHS,FLAG,PARTY,HEAD"

SET @GCN=" UNION ALL
SELECT PI.CreditNoteAcc_Id AS PURCHASEINVID,CONVERT(NVARCHAR,PI.TRAN_DOCNO)AS BILLNO,
(CASE WHEN DATEPART(M,PI.TRAN_DATE)<=3 THEN (DATEPART(M,PI.TRAN_DATE)+12)ELSE DATEPART(M,PI.TRAN_DATE) END)AS MONTHORD,'GCN' AS FLAG,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.TRAN_AMOUNT,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetAmount,0)) AS NETTOTAL,SUM(ISNULL(PI.CGST,0)+ISNULL(PI.SGST,0)+ISNULL(PI.IGST,0)) AS TOTALTAX,SUM(ISNULL(RoundOff,0)) AS ROFF ,
SUM(ISNULL((PI.CGST),0)) AS CGST , SUM(ISNULL((PI.SGST ),0)) AS SGST , SUM(ISNULL((PI.IGST ),0)) AS IGST
FROM "+@DatabaseName+"CREDITNOTEACC_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_GCN+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.TRAN_TYPE IN ('GCN') AND PI.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.CreditNoteAcc_Id,PI.TRAN_DOCNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,TRAN_DATE,LM.LGR_NAME"

SET @GDN=" UNION ALL
SELECT PI.DebitNoteAcc_Id AS PURCHASEINVID,CONVERT(NVARCHAR,PI.TRAN_DOCNO)AS BILLNO,
(CASE WHEN DATEPART(M,PI.TRAN_DATE)<=3 THEN (DATEPART(M,PI.TRAN_DATE)+12)ELSE DATEPART(M,PI.TRAN_DATE) END)AS MONTHORD,'GCN' AS FLAG,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(0-ISNULL(PI.TRAN_AMOUNT,0)) AS TAXABLEAMT,
SUM(0-ISNULL(PI.NetAmount,0)) AS NETTOTAL,SUM((0-ISNULL(PI.CGST,0)+ISNULL(PI.SGST,0)+ISNULL(PI.IGST,0))) AS TOTALTAX,SUM(0-ISNULL(RoundOff,0)) AS ROFF ,
SUM(ISNULL((PI.CGST),0)) AS CGST , SUM(ISNULL((PI.SGST ),0)) AS SGST , SUM(ISNULL((PI.IGST ),0)) AS IGST
FROM "+@DatabaseName+"DEBITNOTEACC_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_GCN+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.TRAN_TYPE IN ('GDN') AND PI.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.DebitNoteAcc_Id,PI.TRAN_DOCNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,TRAN_DATE,LM.LGR_NAME"

SET @AJ=" UNION ALL 
SELECT TM.VCODE AS PURCHASEINVID,CONVERT(NVARCHAR,TM.CODE)AS BILLNO,(CASE WHEN DATEPART(M,TM.VDATE)<=3 THEN (DATEPART(M,TM.VDATE)+12)ELSE DATEPART(M,TM.VDATE) END)AS MONTHORD,'AJ' AS FLAG,
UPPER(DATENAME(M,VDATE))MONTHS,LM.LGR_NAME AS PARTY,LM.Lgr_Name AS HEAD,'UnRegistered Dealer' AS DEALER,ISNULL(SUM(TM.DRAMOUNT) - SUM(TM.CRAMOUNT),0) AS TAXABLEAMT,
ISNULL(SUM(TM.DRAMOUNT - TM.CRAMOUNT),0) - (0 +0  +0) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF,
0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"AUTOJOURNAL TM
LEFT JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=TM.LGR_ID 
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TM.CMP_CODE
"+@TEMPLINK_AJ+"
WHERE TM.CMP_CODE IN ("+@Cmp_Code+") AND TM.VDATE BETWEEN '"+@FromDate+"' AND  '"+@ToDate+"'  
GROUP BY VCODE,TM.CODE,VDATE,LM.Lgr_Name"

SET @J=" UNION ALL
SELECT PURCHASEINVID,BILLNO,MONTHORD,FLAG,MONTHS,PARTY,HEAD,'UnRegistered Dealer' as Dealer,SUM(DRAMOUNT - CRAMOUNT)AS TAXABLEAMT,SUM(DRAMOUNT - CRAMOUNT)AS NETTOTAL,
0 AS TOTALTAX,0 AS ROFF,0 AS CGST , 0 AS SGST , 0 AS IGST FROM (
SELECT TM.TRAN_ID AS PURCHASEINVID,CONVERT(NVARCHAR,TM.TRAN_DOCNO)AS BILLNO,
(CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END)AS MONTHORD,UPPER(DATENAME(MM,TRAN_DATE))MONTHS,
CM.CMP_NAME AS CMPNAME ,CM.GSTINNO AS TINNO,
CM.CMP_CITY AS CITY,CM.CMP_SERVICETAX_NO AS CSTNNO ,LM.Lgr_Name AS HEAD,LMP.Lgr_Name AS PARTY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,0 AS CGST,	0 AS SGST ,	0 AS IGST ,0 AS TOTALTAX,0 AS PER,'J' AS FLAG,10 TYPE                
FROM "+@DatabaseName+"TRAN_MASTER TM                
INNER JOIN "+@DatabaseName+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
LEFT JOIN "+@DatabaseName+"COMPANY_MASTER CM ON CM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID 
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LMP ON LMP.LGR_ID=TM.TRAN_MASTER_ID
INNER JOIN "+@DatabaseName+"Ledger_Detail LD on LD.Lgr_ID=LM.Lgr_ID AND LD.CMP_CODE = TD.CMP_CODE
"+@TEMPLINK_J+"
WHERE TM.CMP_CODE IN ("+@Cmp_Code+") AND TM.TRAN_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' AND TM.TRAN_TYPE= 'J' ) AS A 
GROUP BY PURCHASEINVID,BILLNO,MONTHORD,MONTHS,FLAG,HEAD,PARTY"

SET @MIP="  UNION ALL 
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,'MIP' AS FLAG,UPPER(DATENAME(MM,VCHDATE))MONTHS,ISNULL(LM.LGR_NAME,'')AS PARTY,ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.NetTotal,0)) AS TAXABLEAMT,
SUM(ISNULL(PI.NetTotal,0)) AS NETTOTAL,0 AS TOTALTAX,0 AS ROFF ,0 AS CGST , 0 AS SGST , 0 AS IGST
FROM "+@DatabaseName+"PURCHASEINVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.PURACCID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.FLAG ='MIP' AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'  
GROUP BY PI.PURCHASEINVID,PI.BILLNO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,VCHDATE,LM.LGR_NAME

ORDER BY MONTHORD,MONTHS,DEALER,HEAD "
END
EXEC (@MIX+@RP+@MISC+@CHEM+@TRAN+@GCN+@GDN+@AJ+@J+@MIP)
PRINT @MIX
PRINT @RP
PRINT @MISC
PRINT @CHEM
PRINT @TRAN
PRINT @GCN
PRINT @GDN
PRINT @AJ
PRINT @J
PRINT @MIP













GO

/****** Object:  StoredProcedure [dbo].[PROC_HEAD_WISE_MONTLY_SALES]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO







/*
=============================================
-- Author:		<SANJU,M,PARMAR>
-- Create date: <14-05-2019,6:12,PM>
-- Description:	<This Procedure is use for fetch purchase data by head or month wise,PROC_HEAD_WISE_MONTLY_PURCHASE,>
=============================================

PROC_HEAD_WISE_MONTLY_SALES N'01/apr/2018', N'31/mar/2019', N'Acc2018_2019.Dbo.', N'1', N'', 0

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/

CREATE PROCEDURE [dbo].[PROC_HEAD_WISE_MONTLY_SALES]
(
@FromDate  nvarchar(20),
@ToDate nvarchar(20),    
@DatabaseName nvarchar(50),
@Cmp_Code nvarchar(100),    
@TempTable nvarchar(20),
@SelAll int,
@RPT_WISE INT

)
AS
DECLARE @SALES AS NVARCHAR(3999)
DECLARE @JOBSALES AS NVARCHAR(3999)
DECLARE @STOCKOUT AS NVARCHAR(3999)
DECLARE @SALESRETURN AS NVARCHAR(3999)
DECLARE @CRNOTE AS NVARCHAR(3999)
DECLARE @DRNOTE AS NVARCHAR(3999)


DECLARE @TEMPLINK NVARCHAR(3999)
DECLARE @TEMPLINK_JOB NVARCHAR(3999)
DECLARE @TEMPLINK_STOCK NVARCHAR(3999)
DECLARE @TEMPLINK_SALESRETURN NVARCHAR(3999)
DECLARE @TEMPLINK_CRNOTE NVARCHAR(3999)
DECLARE @TEMPLINK_DRNOTE NVARCHAR(3999)



SET @SALES=""
SET @JOBSALES=""
SET @STOCKOUT=""
SET @SALESRETURN=""
SET @CRNOTE=""
SET @DRNOTE=""

SET @TEMPLINK=""
SET @TEMPLINK_JOB=""
SET @TEMPLINK_STOCK=""
SET @TEMPLINK_SALESRETURN=""
SET @TEMPLINK_CRNOTE=""
SET @TEMPLINK_DRNOTE=""
	IF @SelAll=0
		begin
			SET @TEMPLINK=""
			SET @TEMPLINK_JOB=""
			SET @TEMPLINK_STOCK=""	
			SET @TEMPLINK_SALESRETURN=""
			SET @TEMPLINK_CRNOTE=""
			SET @TEMPLINK_DRNOTE=""
		end
	ELSE
		begin
			SET @TEMPLINK="INNER JOIN " + @TempTable + " TT ON PUR.LGR_ID=TT.CODE"
			SET @TEMPLINK_JOB="INNER JOIN " + @TempTable + " TT ON PUR.LGR_ID=TT.CODE"			
			SET @TEMPLINK_STOCK=""			
			SET @TEMPLINK_SALESRETURN="INNER JOIN " + @TempTable + " TT ON PUR.LGR_ID=TT.CODE"			
			SET @TEMPLINK_CRNOTE="INNER JOIN " + @TempTable + " TT ON PUR.LGR_ID=TT.CODE"			
			SET @TEMPLINK_DRNOTE="INNER JOIN " + @TempTable + " TT ON PUR.LGR_ID=TT.CODE"			
		end
BEGIN		
SET @SALES=" 
SELECT  MONTHORD,MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(CGST)AS CGST,SUM(SGST)AS SGST,SUM(IGST)AS IGST,SUM(ROFF)ROFF FROM (
SELECT PI.SAL_INV_ID,PI.SAL_INV_BILL_NO AS BILLNO,
(CASE WHEN DATEPART(M,PI.Sal_Inv_Vdate)<=3 THEN (DATEPART(M,PI.Sal_Inv_Vdate)+12)ELSE DATEPART(M,PI.Sal_Inv_Vdate) END)AS MONTHORD,
PI.FLAG,UPPER(DATENAME(MM,PI.Sal_Inv_Vdate))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.SAL_INV_GROSSTOTAL,0) +ISNULL(PI.SAL_INV_ADD1,0) + ISNULL(PI.SAL_INV_ADD2,0) -( ISNULL(PI.SAL_INV_LESS1,0) + ISNULL(PI.SAL_INV_LESS2,0) + ISNULL(PI.SAL_INV_LESS3,0) + ISNULL(PI.SAL_INV_LESS4,0)+ ISNULL(PI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.SAL_INV_NETTOTAL,0))NETTOTAL,MAX(ISNULL(PI.SAL_INV_ADD3,0)) AS CGST ,MAX(ISNULL(PI.SAL_INV_ADD4,0)) AS SGST ,MAX(ISNULL(PI.SAL_INV_ADD5,0))AS IGST,MAX(ISNULL(PI.SAL_INV_ROUNDOFF,0))AS ROFF
FROM "+@DatabaseName+"SALES_INVOICE PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.Sal_AccID
"+@TEMPLINK+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.Sal_Inv_Vdate BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.SAL_INV_ID,PI.SAL_INV_BILL_NO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,Sal_Inv_Vdate,PI.FLAG "

SET @JOBSALES=" UNION ALL
SELECT PI.JOB_SAL_INV_ID AS SAL_INV_ID,PI.JOB_SAL_INV_BILL_NO AS BILLNO,
(CASE WHEN DATEPART(M,PI.JOB_SAL_INV_VDATE)<=3 THEN (DATEPART(M,PI.JOB_SAL_INV_VDATE)+12)ELSE DATEPART(M,PI.JOB_SAL_INV_VDATE) END)AS MONTHORD,
PI.FORM_FLAG AS FLAG,UPPER(DATENAME(MM,PI.JOB_SAL_INV_VDATE))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.TOTAL,0) +ISNULL(PI.SAL_INV_ADD1,0) + ISNULL(PI.SAL_INV_ADD2,0) -( ISNULL(PI.SAL_INV_LESS1,0) + ISNULL(PI.SAL_INV_LESS2,0) + ISNULL(PI.SAL_INV_LESS3,0) + ISNULL(PI.SAL_INV_LESS4,0)+ ISNULL(PI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.NETAMT,0))NETTOTAL,MAX(ISNULL(PI.SAL_INV_ADD3,0)) AS CGST ,MAX(ISNULL(PI.SAL_INV_ADD4,0)) AS SGST ,MAX(ISNULL(PI.SAL_INV_ADD5,0))AS IGST,MAX(ISNULL(PI.ROFF,0))AS ROFF
FROM "+@DatabaseName+"Job_SalesInvoice_Master PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.JOB_SALACCID
"+@TEMPLINK_JOB+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.JOB_SAL_INV_VDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.JOB_SAL_INV_ID,PI.JOB_SAL_INV_BILL_NO,PUR.LGR_NAME,LM.REGISTER_DEALER_TYPE,JOB_SAL_INV_VDATE,PI.FORM_FLAG 
) AS A GROUP BY MONTHORD,MONTHS,HEAD,DEALER ORDER BY MONTHORD,MONTHS,HEAD,DEALER "


SET @STOCKOUT=" 

SELECT  MONTHORD,MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(CGST)AS CGST,SUM(SGST)AS SGST,SUM(IGST)AS IGST,SUM(ROFF)ROFF FROM (
SELECT PI.STOCKOUT_ID AS SAL_INV_ID,PI.DOCNO AS BILLNO,
(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END)AS MONTHORD,
'' FLAG,UPPER(DATENAME(MM,PI.VCHDATE))MONTHS,
'STOCK OUT' AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.GROSSTOTAL,0) +ISNULL(PI.SAL_INV_ADD1,0) + ISNULL(PI.SAL_INV_ADD2,0) -( ISNULL(PI.SAL_INV_LESS1,0) + ISNULL(PI.SAL_INV_LESS2,0) + ISNULL(PI.SAL_INV_LESS3,0) + ISNULL(PI.SAL_INV_LESS4,0)+ ISNULL(PI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.NETTOTAL,0))NETTOTAL,MAX(ISNULL(PI.SAL_INV_ADD3,0)) AS CGST ,MAX(ISNULL(PI.SAL_INV_ADD4,0)) AS SGST ,MAX(ISNULL(PI.SAL_INV_ADD5,0))AS IGST,MAX(ISNULL(PI.RoundOff,0))AS ROFF
FROM "+@DatabaseName+"STOCKOUT_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.STOCKOUT_ID,PI.DOCNO,LM.REGISTER_DEALER_TYPE,VCHDATE
) AS A GROUP BY MONTHORD,MONTHS,HEAD,DEALER ORDER BY MONTHORD,MONTHS,HEAD,DEALER "


SET @SALESRETURN=" 
SELECT  MONTHORD,MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(CGST)AS CGST,SUM(SGST)AS SGST,SUM(IGST)AS IGST,SUM(ROFF)ROFF FROM (

SELECT PI.Sal_Ret_Id AS SAL_INV_ID,PI.DocNo AS BILLNO,
(CASE WHEN DATEPART(M,PI.Sal_Ret_Date)<=3 THEN (DATEPART(M,PI.Sal_Ret_Date)+12)ELSE DATEPART(M,PI.Sal_Ret_Date) END)AS MONTHORD,
PI.FLAG AS FLAG,UPPER(DATENAME(MM,PI.Sal_Ret_Date))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Sal_Ret_Add1,0) + ISNULL(PI.Sal_Ret_Add2,0) -( ISNULL(PI.Sal_Ret_Less1,0) + ISNULL(PI.Sal_Ret_Less2,0) + ISNULL(PI.Sal_Ret_Less3,0) + ISNULL(PI.Sal_Ret_Less4,0)+ ISNULL(PI.Sal_Ret_Less5,0))) AS TAXABLEAMT,
SUM(ISNULL(PI.RoundedAmount,0))NETTOTAL,MAX(ISNULL(PI.Sal_Ret_Add3,0)) AS CGST ,MAX(ISNULL(PI.Sal_Ret_Add4,0)) AS SGST ,MAX(ISNULL(PI.Sal_Ret_Add5,0))AS IGST,MAX(ISNULL(PI.Sal_Ret_RoundOff,0))AS ROFF
FROM "+@DatabaseName+"SALES_RETURN_MASTER PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.Sal_Acc_Id
"+@TEMPLINK_SALESRETURN+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.Sal_Ret_Date BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
GROUP BY PI.Sal_Ret_Id,PI.DOCNO,LM.REGISTER_DEALER_TYPE,Sal_Ret_Date,PI.FLAG,PUR.LGR_NAME
) AS A GROUP BY MONTHORD,MONTHS,HEAD,DEALER ORDER BY MONTHORD,MONTHS,HEAD,DEALER "


SET @CRNOTE=" 
SELECT  MONTHORD,MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(CGST)AS CGST,SUM(SGST)AS SGST,SUM(IGST)AS IGST,SUM(ROFF)ROFF FROM (

SELECT PI.CreditNoteAcc_Id AS SAL_INV_ID,PI.Tran_DocNo AS BILLNO,
(CASE WHEN DATEPART(M,PI.Tran_Date)<=3 THEN (DATEPART(M,PI.Tran_Date)+12)ELSE DATEPART(M,PI.Tran_Date) END)AS MONTHORD,
'' AS FLAG,UPPER(DATENAME(MM,PI.Tran_Date))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.Tran_Amount,0) ) AS TAXABLEAMT,
SUM(ISNULL(PI.NETAMOUNT,0))NETTOTAL,MAX(ISNULL(PI.CGST,0)) AS CGST ,MAX(ISNULL(PI.SGST,0)) AS SGST ,MAX(ISNULL(PI.IGST,0))AS IGST,MAX(ISNULL(PI.ROUNDOFF,0))AS ROFF
FROM "+@DatabaseName+"CreditNoteAcc_Master PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_CRNOTE+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.Tran_Date BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
AND PI.NOTE = 'CR NOTE ISSUED AGAINST SALE'
GROUP BY PI.CreditNoteAcc_Id,PI.Tran_DocNo,LM.REGISTER_DEALER_TYPE,Tran_Date,PUR.LGR_NAME
) AS A GROUP BY MONTHORD,MONTHS,HEAD,DEALER ORDER BY MONTHORD,MONTHS,HEAD,DEALER "


SET @DRNOTE=" 
SELECT  MONTHORD,MONTHS,HEAD,DEALER,SUM(TAXABLEAMT)TAXABLEAMT,SUM(NETTOTAL)NETTOTAL,SUM(CGST)AS CGST,SUM(SGST)AS SGST,SUM(IGST)AS IGST,SUM(ROFF)ROFF FROM (

SELECT PI.DebitNoteAcc_Id AS SAL_INV_ID,PI.Tran_DocNo AS BILLNO,
(CASE WHEN DATEPART(M,PI.Tran_Date)<=3 THEN (DATEPART(M,PI.Tran_Date)+12)ELSE DATEPART(M,PI.Tran_Date) END)AS MONTHORD,
'' AS FLAG,UPPER(DATENAME(MM,PI.Tran_Date))MONTHS,
ISNULL(PUR.LGR_NAME,'')AS HEAD,ISNULL(LM.REGISTER_DEALER_TYPE,'')DEALER,SUM(ISNULL(PI.Tran_Amount,0) ) AS TAXABLEAMT,
SUM(ISNULL(PI.NETAMOUNT,0))NETTOTAL,MAX(ISNULL(PI.CGST,0)) AS CGST ,MAX(ISNULL(PI.SGST,0)) AS SGST ,MAX(ISNULL(PI.IGST,0))AS IGST,MAX(ISNULL(PI.ROUNDOFF,0))AS ROFF
FROM "+@DatabaseName+"DebitNoteAcc_Master PI
INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DatabaseName+"LEDGER_MASTER PUR ON PUR.LGR_ID=PI.DEBITAC_ID
"+@TEMPLINK_DRNOTE+"
WHERE PI.CMP_CODE IN ("+@Cmp_Code+") AND PI.Tran_Date BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
AND PI.NOTE = 'DR NOTE ISSUED AGAINST SALE' 
GROUP BY PI.DebitNoteAcc_Id,PI.Tran_DocNo,LM.REGISTER_DEALER_TYPE,Tran_Date,PUR.LGR_NAME 
) AS A GROUP BY MONTHORD,MONTHS,HEAD,DEALER ORDER BY MONTHORD,MONTHS,HEAD,DEALER "



IF @RPT_WISE=1
	BEGIN
		EXEC (@SALES+@JOBSALES)
		PRINT @SALES
		PRINT @JOBSALES
	END

ELSE IF @RPT_WISE=2 
	BEGIN
		EXEC SP_EXECUTESQL @STOCKOUT
		PRINT @STOCKOUT
	END		

ELSE IF @RPT_WISE= 3
	BEGIN
		EXEC SP_EXECUTESQL @SALESRETURN
		PRINT @SALESRETURN
	END		

ELSE IF @RPT_WISE= 4  
	BEGIN
		EXEC SP_EXECUTESQL @DRNOTE
		PRINT @DRNOTE
	END		

ELSE IF @RPT_WISE= 5 
	BEGIN
		EXEC SP_EXECUTESQL @CRNOTE
		PRINT @CRNOTE
	END	
END














GO

