CREATE PROCEDURE [dbo].[PROC_HEADWISECREDITNOTEREG]
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @SQLTYPE AS NVARCHAR(100)

SET @SQL=""
SET @JOINSQL=""
SET @SQLTYPE=""
BEGIN
IF @RPT_TYPE = 2
		BEGIN
			SET @SQLTYPE= " AND TM.NOTE = 'TCS' "
		END
ELSE IF @RPT_TYPE = 1
		BEGIN
			SET @SQLTYPE= " AND TM.NOTE= 'NOT APPLICABLE' "
		END
ELSE
		BEGIN
			SET @SQLTYPE=""
		END
END
BEGIN
SET NOCOUNT ON;



SELECT @SQL="
SELECT TM.TRAN_DOCNO,TM.TRAN_DATE AS VDATE,
TD.TRAN_DETAIL_ID AS ACCODE,BLM.LGR_NAME AS ACNAME,JD.TRAN_DETAIL_ID AS PARTYCODE,PLM.LGR_NAME AS PARTYNAME, PCM.CITY_NAME AS PARTYCITY,
TD.TRAN_AMOUNT,TD.TRAN_TYPE,TM.NARRATION AS NARR,ISNULL(TM.BRANCHNAME,'') AS BRDOCNO
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TD.TRAN_DETAIL_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON TD.TRAN_DETAIL_ID=BLM.LGR_ID
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL JD ON TD.TRAN_ID=JD.TRAN_ID AND TD.TRAN_TYPE=JD.TRAN_TYPE AND TD.TRAN_DETAIL_ID <> JD.TRAN_DETAIL_ID	AND TM.CMP_CODE=JD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON JD.TRAN_DETAIL_ID=PLM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
WHERE TD.TRAN_TYPE='CN' AND TM.CMP_CODE="+@CMP_CODE+"  "+ @SQLTYPE+"
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' ORDER BY BLM.LGR_NAME,TD.TRAN_DETAIL_ID,PLM.LGR_NAME,PLM.LGR_ID
"
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL























GO

