CREATE PROCEDURE [dbo].[PROC_HEADWISEDEBITNOTEREG]
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @SQLTYPE AS NVARCHAR(100)
SET @SQL=""
SET @JOINSQL=""
SET @SQLTYPE=""
BEGIN
IF @RPT_TYPE = 2
		BEGIN
			SET @SQLTYPE= " AND TM.NOTE = 'TCS' "
		END
ELSE IF @RPT_TYPE = 1
		BEGIN
			SET @SQLTYPE= " AND TM.NOTE= 'NOT APPLICABLE' "
		END
ELSE
		BEGIN
			SET @SQLTYPE=""
		END

END
BEGIN
SET NOCOUNT ON;
	

SELECT @SQL="
SELECT TM.TRAN_DOCNO,TM.TRAN_DATE AS VDATE,TD.TRAN_DETAIL_ID AS ACCODE,BLM.LGR_NAME AS ACNAME,
JD.TRAN_DETAIL_ID AS PARTYCODE,PLM.LGR_NAME AS PARTYNAME, PCM.CITY_NAME AS PARTYCITY,
TD.TRAN_AMOUNT,TD.TRAN_TYPE,TM.NARRATION AS NARR
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TD.TRAN_DETAIL_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER BLM ON TD.TRAN_DETAIL_ID=BLM.LGR_ID
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL JD ON TD.TRAN_ID=JD.TRAN_ID AND TD.TRAN_TYPE=JD.TRAN_TYPE AND TD.TRAN_DETAIL_ID <> JD.TRAN_DETAIL_ID	AND TM.CMP_CODE=JD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON JD.TRAN_DETAIL_ID=PLM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PLM.CITY_ID=PCM.CITY_ID
WHERE TD.TRAN_TYPE='DN' AND TM.CMP_CODE="+@CMP_CODE+"  "+@SQLTYPE+"
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' ORDER BY BLM.LGR_NAME,TD.TRAN_DETAIL_ID,PLM.LGR_NAME,PLM.LGR_ID
"
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






















GO

/****** Object:  StoredProcedure [dbo].[PROC_IN_OUT_REPORT_SP]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*
Author : Sanju Parmar
Created Date : 28/03/2019,4:15 PM.
PROC_IN_OUT_REPORT_SP 1,'ACC2018_2019.DBO.','01/APR/2018','31/MAR/2019','##3192',2,2
Select * from TempDb..SysObjects
*/
CREATE PROCEDURE [dbo].[PROC_IN_OUT_REPORT_SP]
(
@Cmp_Code Nvarchar(100),
@DatabaseName Nvarchar(500),
@FromDate  Nvarchar(20),
@ToDate Nvarchar(20),
@TempTable Nvarchar(20),	
@RptWise Int,
@Status Int
)
AS
DECLARE @ISSUE AS NVARCHAR(3999)
DECLARE @RECEIVE AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(3999)
DECLARE @STRORDERBY AS NVARCHAR(3999)
DECLARE @Stat as nvarchar(90)
SET @Stat=""
SET @ISSUE=""
SET @RECEIVE=""
SET @SELECTED=""
SET @STRORDERBY=""

IF @Status IN (1)
	BEGIN
		SET @Stat=" AND PID.PENDINGTHAN=0"
	END
ELSE IF @Status IN (2)
	BEGIN
		SET @Stat=" AND PID.PENDINGTHAN>0"
	END
ELSE
	BEGIN
		SET @Stat=""
	END

BEGIN
	IF @RptWise IN (1)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.DOCNO=" + @TempTable + ".CODE"
			SET @STRORDERBY="  "
		END
	ELSE  IF @RptWise IN (1)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise = 2
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise IN (3)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (4)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,LOM.LOT_NAME,LOM.LOT_ID,"
		END	
	ELSE IF @RptWise IN (5)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,PM.PROCESS_NAME,PM.PROCESS_ID,"
		END		

SET NOCOUNT ON;
SET @ISSUE="
SELECT PI.PROCESSISSUEID,PI.DOCNO,CONVERT(NVARCHAR,PI.VCHDATE,103)DATE,LM.LGR_NAME,LM.LGR_ID,PID.LOTNO,LOM.LOT_ID,
LOM.LOT_NAME AS MARKA,IM.ITEM_ID,IM.ITEM_NAME,HM.HSN_ID,HM.HSN_NAME,PM.PROCESS_NAME,PM.PROCESS_ID,PID.PCS,PID.QTY,PID.RATE,PID.AMOUNT
,ISNULL(PRM.DOCNO,0)AS RECDOCNO,CONVERT(NVARCHAR,PRM.VCHDATE,103)RECVCHDATE,PRD.QTY AS RECMETER,PRD.PCS AS RECPCS,'RECEIVE'AS FLAG
FROM "+ @DATABASENAME+ "PROCESSISSUE PI
INNER JOIN  "+ @DATABASENAME+ "PROCESSISSUE_DETAIL PID ON PID.PROCESSISSUEID=PI.PROCESSISSUEID 
LEFT JOIN  "+ @DATABASENAME+ "PROCESSRECEIVE_DETAIL PRD ON PRD.CHALLNNO=PI.DOCNO AND PID.ITEM_ID=PRD.ITEM_ID AND PID.LOT_ID=PRD.LOT_ID 
LEFT JOIN  "+ @DATABASENAME+ "PROCESSRECEIVE PRM ON PRM.PROCESSRECEIVEID=PRD.PROCESSRECEIVEID 
INNER JOIN "+ @DATABASENAME+ "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+ @DATABASENAME+ "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
LEFT  JOIN "+ @DATABASENAME+ "HSN_MASTER HM ON HM.HSN_ID=PID.HSN_ID
LEFT  JOIN "+ @DATABASENAME+ "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME+ "PROCESS_MASTER PM ON PI.PROCESS_ID=PM.PROCESS_ID
INNER JOIN "+ @DATABASENAME+ "COMPANY_MASTER CMP ON PI.CMP_CODE= CMP.CMP_CODE     	
"+@SELECTED+"
WHERE PI.CMP_CODE="+ @CMP_CODE +" "+@Stat+" AND PI.VchDate BETWEEN '" + @FromDate + "' AND '" + @ToDate + "'
ORDER BY "+@STRORDERBY+"PI.DocNo,PI.VchDate"      
END	


PRINT @ISSUE
EXEC (@ISSUE)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_INSURANCE_REPORT]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_INSURANCE_REPORT '01/APR/2012','31/Mar/2013',1,'ACC2012_2013.dbo.',2,1
REPORT_USED:-InsuranceRpt.rpt,InsuranceRpt_lrMaster.rpt

*/
CREATE PROCEDURE [dbo].[PROC_INSURANCE_REPORT]
(
@FromDate  nvarchar(20),
@ToDate nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50),
@RptType int,
@TredSales int
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""



BEGIN	
	SET NOCOUNT ON;
IF @RptType=1 /*TREDING SALES INV*/
BEGIN
	IF @TredSales=1
		BEGIN
			SET @STRSQL=" select SIM.Sal_Inv_Id AS CODE,Sal_Inv_Bill_No as BILLNO,Sal_Inv_Vdate as DATE,SIM.Sal_Inv_LrNo as LRNO,Sal_Inv_LrDate as LRDATE
		,(CASE WHEN InSured=1 THEN Sal_Inv_NetTotal ELSE 0 END)as NETTOTAL,
		TM.Transport_NAME,CM.City_Name as ToCity,CMP.CMP_CITY as FromCity,Sal_Inv_BalesTotal AS TOTAL_BALES
		FROM "+@DatabaseName+" SALES_INVOICE SIM
		INNER JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON SIM.TRANSPORT_ID=TM.TRANSPORT_ID
		LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SIM.STATION_ID
		inner join "+@DatabaseName+" COMPANY_MASTER CMP on CMP.CMP_CODE=SIM.CMP_CODE
		where SIM.Cmp_COde="+@Cmp_Code+"
		and SIM.FLAG='S' and SIM.SAL_INV_TYPE='E' 
		and SIM.Sal_Inv_Vdate between '"+@FromDate+"' and '"+@ToDate+"'
		order by Sal_Inv_Bill_No "
		END
	ELSE IF @TredSales=2
		BEGIN
			SET @STRSQL="
		SELECT SIM.Sal_Inv_Id AS CODE,Sal_Inv_Bill_No as BILLNO,Sal_Inv_Vdate as DATE,CONVERT(BIGINT,SID.Sal_LrNo) as LRNO,Sal_Inv_LrDate as LRDATE
		,(CASE WHEN InSured=1 THEN Sal_Inv_NetTotal ELSE 0 END)as NETTOTAL
		,TM.TRANSPORT_NAME,CM.CITY_NAME AS TOCITY,CMP.CMP_CITY as FROMCITY,SAL_INV_BALESTOTAL AS TOTAL_BALES
		FROM "+@DatabaseName+" SALES_INVOICE SIM
		INNER JOIN "+@DatabaseName+" SALES_INVOICE_DETAIL SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
		INNER JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON SIM.TRANSPORT_ID=TM.TRANSPORT_ID
		LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SIM.STATION_ID
		inner join "+@DatabaseName+" COMPANY_MASTER CMP on CMP.CMP_CODE=SIM.CMP_CODE
		where SIM.Cmp_COde="+@Cmp_Code+"
		and SIM.FLAG='S' and SIM.SAL_INV_TYPE='E' 
		and SIM.Sal_Inv_Vdate between '"+@FromDate+"' and '"+@ToDate+"'
		order by Sal_Inv_Bill_No,Sal_Inv_Dtl_Id
		"
		END
END 

 IF @RptType=2 /*Stock Out*/
BEGIN
	SET @STRSQL="
	SELECT SOM.STOCKOUT_ID AS CODE,DOCNO AS BILLNO,VchDate as DATE,STD.LRNO AS LRNO,LRDATE,NETTOTAL as NETTOTAL,TM.Transport_NAME
	,CM.City_Name as ToCity,CMP.CMP_CITY as FromCity,BALENO AS TOTAL_BALES
	FROM "+@DatabaseName+" STOCKOUT_MASTER SOM	
	INNER JOIN "+@DatabaseName+" STOCKOUT_DETAIL STD ON SOM.STOCKOUT_ID=STD.STOCKOUT_ID AND SOM.CMP_CODE=STD.CMP_CODE
	INNER JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON SOM.TRANSPORT_ID=TM.TRANSPORT_ID
	LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SOM.STATION_ID
	INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP on CMP.CMP_CODE=SOM.CMP_CODE
	WHERE SOM.CMP_CODE="+@Cmp_Code+"
	AND VchDate between '"+@FromDate+"' and '"+@ToDate+"' 
	AND SOM.STOCKOUT_TYPE='C'
	order by DOCNO,BALENO
"
END


   
END
EXEC SP_EXECUTESQL @StrSql
PRINT @StrSql




















GO

