/*
GetExamResults 1,'Acc2012_2013.dbo.','01/apr/2012','31/Mar/2013',1,1
*/
CREATE PROCEDURE [dbo].[PROC_INSURANCE_STOCK_OUT_REPORT] 
(
	@Cmp_Code varchar(100), 
	@DatabaseName varchar(30),
	@FromDate nvarchar(50),
	@ToDate nvarchar(50),
	@RptType nvarchar(50),
	@TredSales nvarchar(50)
)
as
BEGIN    
    
	DECLARE @STRLRNO varchar(100)	SET @STRLRNO =""
	DECLARE @ToLrNo int set @ToLrNo=0
	DECLARE @FromLrNo int set @FromLrNo=0
	DECLARE @PreFromLrNo int set @PreFromLrNo=0
	DECLARE @strFromLrNo varchar(50) set @strFromLrNo=''
	
	DECLARE @SQL varchar(4000) SET @SQL=''
	DECLARE @SQL1 varchar(4000) set @SQL1 =''
	DECLARE @PREV_DOCNO INT SET @PREV_DOCNO=0
	DECLARE @CURE_DOCNO INT SET @CURE_DOCNO=0

	DECLARE @STOCKOUT_ID INT 
		SET @STOCKOUT_ID=0
	DECLARE @PREV_STOCKOUT_ID INT 
		SET @PREV_STOCKOUT_ID=0
	DECLARE @BILLNO INT 
		SET @BILLNO=0
	DECLARE @LRNO INT
		SET @LRNO =0
	DECLARE @LRDATE VARCHAR(70) 
		SET @LRDATE=''
	DECLARE @DATE VARCHAR(70) 
		SET @DATE=''
	DECLARE @NETTOTAL INT 
		SET @NETTOTAL=0
	DECLARE @TRANSPORT_NAME VARCHAR(70) 
		SET @TRANSPORT_NAME=''
	DECLARE @TOCITY VARCHAR(70) 
		SET @TOCITY=''
	DECLARE @FROMCITY VARCHAR(70) 
		SET @FROMCITY=''
	DECLARE @BALENO INT 
		SET @BALENO=0
	DECLARE @BALENO_CNT INT 
		SET @BALENO_CNT=0


SET @SQL="DECLARE subject_cursor CURSOR FOR 
SELECT SOM.STOCKOUT_ID,DOCNO,VchDate as DATE,STD.LRNO,ISNULL(LRDATE,'') AS LRDATE
,NETTOTAL,TM.Transport_NAME,CM.City_Name as ToCity,CMP.CMP_CITY as FromCity,BALENO
FROM "+@DatabaseName+" STOCKOUT_MASTER SOM	
INNER JOIN "+@DatabaseName+" STOCKOUT_DETAIL STD ON SOM.STOCKOUT_ID=STD.STOCKOUT_ID AND SOM.CMP_CODE=STD.CMP_CODE
INNER JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON SOM.TRANSPORT_ID=TM.TRANSPORT_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SOM.STATION_ID
INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON CMP.CMP_CODE=SOM.CMP_CODE
WHERE SOM.CMP_CODE IN ('"+@Cmp_Code+"')
AND VCHDATE BETWEEN '"+@FromDate+"' and '"+@ToDate+"' 
AND SOM.STOCKOUT_TYPE='C'
ORDER BY SOM.DOCNO,STD.SRNO
"
	EXEC(@SQL)	
    OPEN subject_cursor
	
    FETCH NEXT FROM subject_cursor INTO @STOCKOUT_ID,@BILLNO,@DATE,@LRNO,@LRDATE,@NETTOTAL,@TRANSPORT_NAME,@TOCITY,@FROMCITY,@BALENO
    WHILE @@FETCH_STATUS = 0  
    BEGIN
		if @ToLrNo=0 set @ToLrNo=@LRNO
		if @PreFromLrNo=0 set @PreFromLrNo=@LRNO
		IF @PREV_DOCNO=0 SET @PREV_DOCNO=@BILLNO
		IF @PREV_STOCKOUT_ID=0 SET @PREV_STOCKOUT_ID=@STOCKOUT_ID
		set @FromLrNo=@LRNO	
		SET @CURE_DOCNO=@BILLNO

		if @FromLrNo- @PreFromLrNo>1
			BEGIN				
				SET @strFromLrNo= CONVERT(NVARCHAR,@ToLrNo) +'-'+CONVERT(NVARCHAR,@PreFromLrNo)
				SET @BALENO_CNT=@PreFromLrNo-@ToLrNo

				/*INSERT DATA IN TEMPTABLE*/
				SET @SQL1=" INSERT INTO "+@DatabaseName+" TEMPTABLE (CODE,LRNO,BILLNO,BALES)VALUES
				("+CONVERT(NVARCHAR,@PREV_STOCKOUT_ID)+",'"+@strFromLrNo+"',"+CONVERT(NVARCHAR,@PREV_DOCNO)+","+CONVERT(NVARCHAR,@BALENO_CNT+1)+")
				"								
				EXEC(@SQL1)	
				SET @FromLrNo=@LRNO
				SET @PreFromLrNo=@LRNO			
				SET @ToLrNo=@LRNO
				SET @PREV_DOCNO=@BILLNO				
				SET @PREV_STOCKOUT_ID=@STOCKOUT_ID
				/*PRINT @strFromLrNo*/

			END
		ELSE IF @CURE_DOCNO!=@PREV_DOCNO
			BEGIN				
				SET @strFromLrNo= CONVERT(NVARCHAR,@ToLrNo) +'-'+CONVERT(NVARCHAR,@PreFromLrNo)
				SET @BALENO_CNT=@PreFromLrNo-@ToLrNo

				/*INSERT DATA IN TEMPTABLE*/
				SET @SQL1=" INSERT INTO "+@DatabaseName+" TEMPTABLE (CODE,LRNO,BILLNO,BALES)VALUES
				("+CONVERT(NVARCHAR,@PREV_STOCKOUT_ID)+",'"+@strFromLrNo+"',"+CONVERT(NVARCHAR,@PREV_DOCNO)+","+CONVERT(NVARCHAR,@BALENO_CNT+1)+")
				"
								
				EXEC(@SQL1)
				SET @PreFromLrNo=@LRNO			
				SET @ToLrNo=@LRNO
				SET @PREV_DOCNO=@BILLNO
				SET @PREV_STOCKOUT_ID=@STOCKOUT_ID
				/*PRINT @strFromLrNo*/
			END
		ELSE 
			BEGIN
				SET @PreFromLrNo=@LRNO 
				SET @PREV_STOCKOUT_ID=@STOCKOUT_ID
				SET @PREV_DOCNO=@BILLNO
			END
        FETCH NEXT FROM subject_cursor INTO @STOCKOUT_ID,@BILLNO,@DATE,@LRNO,@LRDATE,@NETTOTAL,@TRANSPORT_NAME,@TOCITY,@FROMCITY,@BALENO
		
    End
	
    CLOSE subject_cursor;  
    DEALLOCATE subject_cursor;
	SET @strFromLrNo= CONVERT(NVARCHAR,@ToLrNo) +'-'+CONVERT(NVARCHAR,@PreFromLrNo)
	SET @BALENO_CNT=@PreFromLrNo-@ToLrNo
	
	/*INSERT DATA IN TEMPTABLE*/
	SET @SQL1=" INSERT INTO "+@DatabaseName+" TEMPTABLE (CODE,LRNO,BILLNO,BALES)VALUES
	("+CONVERT(NVARCHAR,@PREV_STOCKOUT_ID)+",'"+@strFromLrNo+"',"+CONVERT(NVARCHAR,@PREV_DOCNO)+","+CONVERT(NVARCHAR,@BALENO_CNT+1)+")
	"
	EXEC(@SQL1)
	SET @SQL1="
	SELECT TT.LRNO,STM.STOCKOUT_ID,STM.DOCNO AS BILLNO,STM.VCHDATE,TM.Transport_NAME,STM.LRDATE,
	STM.NETTOTAL as NETTOTAL,CM.City_Name as ToCity,CMP.CMP_CITY as FromCity,BALES AS TOTAL_BALES
	FROM "+@DatabaseName+" STOCKOUT_MASTER STM
	INNER JOIN "+@DatabaseName+" TEMPTABLE TT ON TT.CODE=STM.STOCKOUT_ID
	INNER JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON STM.TRANSPORT_ID=TM.TRANSPORT_ID
	LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=STM.STATION_ID
	INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP on CMP.CMP_CODE=STM.CMP_CODE
	WHERE STM.CMP_CODE="+@Cmp_Code+" AND VchDate between '"+@FromDate+"' and '"+@ToDate+"' 
	AND STM.STOCKOUT_TYPE='C'
	ORDER BY DOCNO
	"	
	EXEC (@SQL1)
	PRINT @SQL1
END




















GO

