/*
Proc_InsuranceReport '3','acc2010_2011.dbo.','01/apr/2010','01/jul/2010'
*/
CREATE PROCEDURE [dbo].[PROC_INSURANCEREPORT]	
(
 @CMP_CODE AS NVARCHAR(50),
 @DATABASENAME AS  NVARCHAR(100),
 @FROMDATE AS NVARCHAR(20),
 @TODATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN	
	SET NOCOUNT ON;
SET @SQL="     SELECT SI.SAL_INV_BILL_NO AS BILLNO ,COMP.CMP_CITY AS FROMCITY,CM.CITY_NAME AS TOCITY,SI.SAL_INV_LRNO AS LRNO,SI.SAL_INV_LRDATE AS LRDATE,
               SI.SAL_INV_BALESTOTAL AS TOTALBALES,TM.TRANSPORT_NAME AS TRANSPORT,SI.SAL_INV_GROSSTOTAL AS AMOUNT
               FROM  "+ @DATABASENAME + " SALES_INVOICE SI
               INNER JOIN  "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
               LEFT JOIN  "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID               
               INNER JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
               WHERE SI.SAL_INV_LRDATE BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' 
                      AND SI.CMP_CODE IN ("+ @CMP_CODE + ")
                     AND SI.Sal_Inv_Add2>0
               ORDER BY SI.SAL_INV_LRDATE,CONVERT(INT, SI.SAL_INV_BILL_NO),SI.SAL_INV_LRNO
"

EXEC SP_EXECUTESQL @SQL
PRINT @SQL

END




















GO

