/*

 PROC_INSURANCEREPORT_SPL N'1', N'Acc2014_2015.Dbo.', N'01/Apr/2014', N'31/Mar/2015', 0, N'0' 
*/


CREATE PROCEDURE [dbo].[PROC_INSURANCEREPORT_SPL]	
(
@CMP_CODE AS NVARCHAR(50),
@DATABASENAME AS  NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@CRITERIA AS INT,
@STATE_ID_STRING AS NVARCHAR(4000)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @DATECOND AS NVARCHAR(4000)

SET @DATECOND=""
SET @SQL=""

BEGIN
IF @CRITERIA=0 
SET @DATECOND="SI.SAL_INV_VDATE"

ELSE IF @CRITERIA =1 
SET    @DATECOND="SI.SAL_INV_LRDATE"

END



BEGIN	
SET NOCOUNT ON;
SET @SQL="     SELECT CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO ,COMP.CMP_CITY AS FROMCITY,CM.CITY_NAME AS TOCITY,SM.STATE_NAME AS STATE,SI.SAL_INV_LRNO AS LRNO,SI.SAL_INV_LRDATE AS LRDATE,
SI.SAL_INV_BALESTOTAL AS TOTALBALES,TM.TRANSPORT_NAME AS TRANSPORT,
SI.SAL_INV_GROSSTOTAL  AS AMOUNT,SI.INSURED ,0  AS EXCLUDE,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) as SAL_INV_BILL_NO,
ISNULL(SI.SAL_INV_NETTOTAL,0) AS BILLAMOUNT
FROM  "+ @DATABASENAME + " SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE 
LEFT JOIN  "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID                              
LEFT JOIN  "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=CM.STATE_ID
INNER JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
WHERE "+ @DATECOND + "  BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' AND SI.CMP_CODE IN ("+ @CMP_CODE + ")
AND CM.STATE_ID NOT IN ("+ @STATE_ID_STRING + ")
UNION ALL
SELECT CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO ,COMP.CMP_CITY AS FROMCITY,CM.CITY_NAME AS TOCITY,SM.STATE_NAME AS STATE,SI.SAL_INV_LRNO AS LRNO,SI.SAL_INV_LRDATE AS LRDATE,
SI.SAL_INV_BALESTOTAL AS TOTALBALES,TM.TRANSPORT_NAME AS TRANSPORT
,0  AS AMOUNT,SI.INSURED ,1  AS EXCLUDE,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) as SAL_INV_BILL_NO,
ISNULL(SI.SAL_INV_NETTOTAL,0) AS BILLAMOUNT
FROM  "+ @DATABASENAME + " SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE 
LEFT JOIN  "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID                              
LEFT JOIN  "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=CM.STATE_ID
INNER JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
WHERE "+ @DATECOND + "  BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' AND SI.CMP_CODE IN ("+ @CMP_CODE + ")
AND CM.STATE_ID  IN ("+ @STATE_ID_STRING + ")
ORDER BY SI.SAL_INV_VDATE, BILLNO,SI.SAL_INV_LRDATE



"

EXEC SP_EXECUTESQL @SQL
PRINT @SQL

END




















GO

