SM.STATE_NAME AS STATE,SI.SAL_INV_LRNO AS LRNO,SI.SAL_INV_LRDATE AS LRDATE,
SI.SAL_INV_BALESTOTAL AS TOTALBALES,TM.TRANSPORT_NAME AS TRANSPORT,
(CASE WHEN ISNULL(SI.INSURED,0)=0 THEN 0 ELSE SI.SAL_INV_NETTOTAL END) AS AMOUNT,SI.INSURED,
0 AS EXCLUDE,SI.SAL_INV_VDATE AS VCHDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) AS SAL_INV_BILL_NO,
ISNULL(SI.SAL_INV_NETTOTAL,0) AS BILLAMOUNT
FROM  "+ @DATABASENAME + " SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE 
