INNER JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
WHERE "+ @DATECOND + "  BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' 
AND SI.CMP_CODE IN ("+ @CMP_CODE + ")
"
SET @SQL1 = " 
/*			UNION ALL
SELECT SOM.DOCNO AS BILLNO,COMP.CMP_CITY AS FROMCITY,CM.CITY_NAME AS TOCITY,
SM.STATE_NAME AS STATE,SOM.LRNO AS LRNO,SOM.LRDATE AS LRDATE,
COUNT(SOD.BALENO) AS TOTALBALES,TM.TRANSPORT_NAME AS TRANSPORT,
(CASE WHEN ISNULL(SOM.INSURED,0)=0 THEN 0 ELSE SOM.NETTOTAL END) AS AMOUNT,SOM.INSURED,
0  AS EXCLUDE,SOM.VCHDATE AS VCHDATE,CONVERT(INT,SOM.DOCNO)
FROM "+ @DATABASENAME + "STOCKOUT_MASTER SOM
INNER JOIN "+ @DATABASENAME + "STOCKOUT_DETAIL SOD ON SOM.STOCKOUT_ID = SOD.STOCKOUT_ID AND SOM.CMP_CODE = SOD.CMP_CODE 
AND SOM.STOCKOUT_TYPE = SOD.STOCKOUT_TYPE  
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SOM.CMP_CODE 
LEFT JOIN  "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=SOM.STATION_ID                              
LEFT JOIN  "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=CM.STATE_ID
INNER JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SOM.TRANSPORT_ID
WHERE SOM.VCHDATE  BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' AND SOM.CMP_CODE IN ("+ @CMP_CODE + ")
GROUP BY SOM.DOCNO,COMP.CMP_CITY,CM.CITY_NAME,SM.STATE_NAME,SOM.LRNO,SOM.LRDATE,TM.TRANSPORT_NAME,
SOM.INSURED,SOM.VCHDATE,SOM.NETTOTAL*/
ORDER BY VCHDATE,BILLNO,LRDATE 
"

EXEC (@SQL+@SQL1)
