/****** Object:  StoredProcedure [dbo].[PROC_INTCALCGRP_PURCHASE]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_INTCALCGRP_PURCHASE '10','acc2010_2011.dbo.','01/apr/2010','31/mar/2011','14'
*/
CREATE PROCEDURE [dbo].[PROC_INTCALCGRP_PURCHASE]
(
   @CMP_CODE  NVARCHAR(50),
   @DATABASENAME  NVARCHAR(40),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @SUPP_GRP_ID  NVARCHAR(20)

)
	


AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
	
       SET @SQL="
				SELECT PARTYID,PARTY,SUPPLIER,SUM(THAN) AS THAN,SUM(BALES) AS BALES,SUM(QUANTITY)AS QUANTITY,SUM(TP)AS TP,SUM(SECOND)SECOND,SUM(SL)AS SL,SUM(PACK) AS PACK,SUM(PURRETAMT)PURRETAMT
				FROM (
				SELECT LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTY,SGM.SUPP_GRP_NAME AS SUPPLIER,SUM(PID.PIECES) AS THAN,SUM(PID.BALES) AS BALES,SUM(PID.QUANTITY) AS QUANTITY,PIM.PUR_INV_LESS2 AS TP,PIM.PUR_INV_LESS4 AS SECOND,PIM.PUR_INV_LESS3 AS SL,PIM.PUR_INV_LESS5 AS PACK
				,0 AS PURRETAMT
				 FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
				INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID=PID.PURCHASEINVID AND PIM.FLAG=PID.FLAG
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PIM.LGR_ID
				INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PIM.SUPP_GRP_ID
				WHERE PIM.VCHDATE BETWEEN '"+@FROMDATE+"'  AND '"+@TODATE+"' AND PIM.CMP_CODE IN("+@CMP_CODE+") AND PIM.SUPP_GRP_ID="+@SUPP_GRP_ID+"
				GROUP BY LM.LGR_ID, LM.LGR_NAME,SGM.SUPP_GRP_NAME ,PIM.PUR_INV_LESS2 ,PIM.PUR_INV_LESS4 ,PIM.PUR_INV_LESS3 ,PIM.PUR_INV_LESS5 
				UNION ALL
				SELECT LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTY,SGM.SUPP_GRP_NAME AS SUPPLIER,0 AS THAN,0 AS BALES,0 AS QUANTITY,0 AS TP,0 AS SECOND,0 AS SL,0 AS PACK
				,SUM(PRM.NETTOTAL) AS PURRETAMT
				FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PRM 
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PRM.LGR_ID
				INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
				WHERE PRM.PUR_RET_DATE BETWEEN '"+@FROMDATE+"'  AND '"+@TODATE+"' AND PRM.CMP_CODE IN("+@CMP_CODE+") AND SGM.SUPP_GRP_ID="+@SUPP_GRP_ID+"
				GROUP BY LM.LGR_ID, LM.LGR_NAME,SGM.SUPP_GRP_NAME 
				) AS DETAIL
				GROUP BY  PARTYID,PARTY,SUPPLIER
            
                "
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

