CREATE PROCEDURE [dbo].[PROC_INTCALCMULTILDGRGRPWISE]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@CRITERIA NVARCHAR(10),
@GROUPCODE NVARCHAR(10),
@ICHECKCRPERIOD AS INT,
@INTRATE AS NUMERIC(18,2),
@CRPERIOD AS NVARCHAR(10),
@YEARPERIOD AS NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)
DECLARE @SQL3 AS  NVARCHAR(4000)
DECLARE @SQL4 AS  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(500)
DECLARE @FIELDSQL NVARCHAR(500)
DECLARE @VCHDATE NVARCHAR(100)
DECLARE @SQLRATE AS  NVARCHAR(1000)
DECLARE @CONDITIONALGROUP NVARCHAR(100)
DECLARE @BASEYEAR AS  NVARCHAR(100)

DECLARE @PURDETAIL AS  NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @PURDETAIL=""


SET @JOINSQL=""
SET @FIELDSQL=""
SET @VCHDATE=""
SET @SQLRATE=""
BEGIN 
SET @SQLRATE=  @INTRATE 
END
SET @CONDITIONALGROUP=""

IF @CRITERIA=1 /* CUSTOMER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON LM.CUST_GRP_ID=CGM.CUST_GRP_ID AND CGM.CUST_GRP_ID="+ @GROUPCODE
SET @FIELDSQL="CGM.CUST_GRP_NAME AS MAINGRP,ISNULL(CGM.CUST_GRP_ID,0) AS MAINGRPID,"
SET @CONDITIONALGROUP=" CGM.CUST_GRP_NAME,CGM.CUST_GRP_ID,"

END


IF @CRITERIA=2 /* SUPPLIER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID AND SGM.SUPP_GRP_ID="+ @GROUPCODE
SET @FIELDSQL="SGM.SUPP_GRP_NAME AS MAINGRP,ISNULL(SGM.SUPP_GRP_ID,0) AS MAINGRPID,"
SET @CONDITIONALGROUP=" SGM.SUPP_GRP_NAME,SGM.SUPP_GRP_ID,"
SET @PURDETAIL="

UNION ALL
SELECT SGM.SUPP_GRP_NAME AS MAINGRP,ISNULL(SGM.SUPP_GRP_ID,0) AS MAINGRPID,LM.LGR_NAME AS PARTYNAME,
LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
0 AS DRAMOUNT,0 AS CRAMOUNT,'' AS TYPE,"+ @SQLRATE +" AS RATE,0 AS DRPRODUCT,0 AS CRPRODUCT,0 AS  SALESAMT,0 AS SALESRETURNAMT
,0 AS PURAMT,0 AS PURRETURNAMT,GM.GRP_NAME AS GROUPNAME ,COMP.CMP_ALIAS AS COMPANY
,SUM(PID.PIECES) AS THAN,SUM(PID.BALES) AS BALES,SUM(PID.QUANTITY) AS QUANTITY,
PIM.PUR_INV_LESS2 AS TP,PIM.PUR_INV_LESS5 AS SECOND,PIM.PUR_INV_LESS3 AS SL,PIM.PUR_INV_ADD2 AS PACK				
,PIM.PURCHASEINVID,ISNULL(PIM.ADDTOTAL,0) AS ADDTOTAL,ISNULL(PIM.PUR_INV_ADD1,0) AS PUR_INV_ADD2,ISNULL(PIM.PUR_INV_ADD3,0) AS PUR_INV_ADD3,
ISNULL(PIM.PUR_INV_ADD4,0) AS PUR_INV_ADD4,ISNULL(PIM.PUR_INV_ADD5,0) AS PUR_INV_ADD5,ISNULL(PIM.PUR_INV_ADD6,0) AS PUR_INV_ADD6
FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PIM ON PIM.PURCHASEINVID=PID.PURCHASEINVID AND PIM.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PIM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LM.LGR_ID=LD1.LGR_ID AND LD1.CMP_CODE=PIM.CMP_CODE
INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PIM.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD1.GRP_ID=GM.GRP_ID                      
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON LD1.CMP_CODE=COMP.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
WHERE PIM.VCHDATE BETWEEN '"+@FROMDATE+"'  AND '"+@TODATE+"' AND PIM.CMP_CODE IN("+@CMP_CODE+") AND PIM.SUPP_GRP_ID="+@GROUPCODE+"
GROUP BY LM.LGR_ID, LM.LGR_NAME,SGM.SUPP_GRP_NAME ,PCM.CITY_NAME,GM.GRP_NAME ,COMP.CMP_ALIAS,
PIM.PUR_INV_LESS2 ,PIM.PUR_INV_ADD1 ,PIM.PUR_INV_LESS3 ,PIM.PUR_INV_LESS5 
,PIM.PURCHASEINVID,PIM.ADDTOTAL,PIM.PUR_INV_ADD2,PIM.PUR_INV_ADD3,PIM.PUR_INV_ADD4,PIM.PUR_INV_ADD5,
PIM.PUR_INV_ADD6,ISNULL(SGM.SUPP_GRP_ID,0)  ORDER BY MAINGRP,MAINGRPID,PARTYNAME,PARTYID "   

END


BEGIN

SET @VCHDATE=" TM.TRAN_DATE "		   		

END


BEGIN
SET NOCOUNT ON;

SELECT @SQL="  
SELECT MAINGRP,MAINGRPID,PARTYNAME,PARTYID,PARTYCITY,DRAMOUNT,CRAMOUNT,TYPE,RATE,DRPRODUCT,CRPRODUCT,SALESAMT,SALESRETURNAMT,PURAMT,PURRETURNAMT,GROUPNAME,COMPANY
,0 AS THAN,0 AS BALES,0 AS QUANTITY,0 AS TP,0 AS SECOND,0 AS SL,0 AS PACK,0 AS PURCHASEINVID,0 AS ADDTOTAL,0 AS PUR_INV_ADD2,0 AS PUR_INV_ADD3,0 AS PUR_INV_ADD4,0 AS PUR_INV_ADD5,0 AS PUR_INV_ADD6
FROM(
SELECT "+@FIELDSQL+"					
LM.LGR_NAME AS PARTYNAME,TM.TRAN_DOCNO,TM.TRAN_MASTER_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,					
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TM.TRAN_TYPE AS TYPE,"+ @SQLRATE +" AS RATE,                    
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TM.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TM.TRAN_AMOUNT/365 ELSE 0 END)
ELSE (CASE WHEN TM.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TM.TRAN_AMOUNT/30 ELSE 0 END) END AS DRPRODUCT, 
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TM.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TM.TRAN_AMOUNT/365 ELSE 0 END)
ELSE(CASE WHEN TM.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TM.TRAN_AMOUNT/30 ELSE 0 END) END AS CRPRODUCT,                     
(CASE WHEN (TM.TRAN_TYPE IN('S','GS','CS','CRS','GSN','MS','JS') AND " + @CRITERIA+"=1)   THEN TM.TRAN_AMOUNT ELSE 0 END) AS  SALESAMT, 
(CASE WHEN (TM.TRAN_TYPE='SR' AND " + @CRITERIA+"=1) THEN TM.TRAN_AMOUNT ELSE 0 END) AS SALESRETURNAMT, 
(CASE WHEN (TM.TRAN_TYPE='P' AND " + @CRITERIA+"=2) THEN TM.TRAN_AMOUNT ELSE 0 END) AS PURAMT,
(CASE WHEN (TM.TRAN_TYPE='PR' AND " + @CRITERIA+"=2) THEN TM.TRAN_AMOUNT ELSE 0 END) AS  PURRETURNAMT,
GM.GRP_NAME AS GROUPNAME,COMP.CMP_ALIAS AS COMPANY
FROM "+@DATABASENAME+"TRAN_MASTER TM 
/*INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE*/
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON TM.CMP_CODE=COMP.CMP_CODE   										
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID					
WHERE TM.CMP_CODE IN("+ @CMP_CODE + ") AND TM.TRAN_TYPE <> 'J' 
AND "+ @VCHDATE + " BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
GROUP BY  "+ @CONDITIONALGROUP + "TM.TRAN_TYPE,LM.LGR_NAME,TM.TRAN_MASTER_ID,PCM.CITY_NAME,TM.TRAN_AMOUNT,"+ @VCHDATE + ",
TM.TRAN_DRCR,TM.TRAN_TYPE,TM.TRAN_TYPE,PCM.CITY_NAME ,GM.GRP_NAME,COMP.CMP_ALIAS,TM.TRAN_DOCNO

UNION ALL 
"
SELECT @SQL1="
SELECT  "+@FIELDSQL+"					
LM.LGR_NAME AS PARTYNAME,TM.TRAN_DOCNO,TD.TRAN_DETAIL_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,					
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TD.TRAN_TYPE AS TYPE,"+ @SQLRATE +"	AS RATE	,                    
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TD.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/365 ELSE 0 END) 
ELSE (CASE WHEN TD.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/30  ELSE 0 END)END DRPRODUCT, 
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TD.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/365 ELSE 0 END )
ELSE (CASE WHEN TD.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/30 END)END AS CRPRODUCT, 
(CASE WHEN (TM.TRAN_TYPE IN('S','GS','CS','CRS','GSN','MS','JS') AND " + @CRITERIA+"=1) THEN TM.TRAN_AMOUNT ELSE 0 END) AS  SALESAMT, 
(CASE WHEN (TM.TRAN_TYPE='SR' AND " + @CRITERIA+"=1) THEN TM.TRAN_AMOUNT ELSE 0 END) AS SALESRETURNAMT, 
(CASE WHEN (TM.TRAN_TYPE='P' AND " + @CRITERIA+"=2) THEN TM.TRAN_AMOUNT ELSE 0 END) AS PURAMT,
(CASE WHEN (TM.TRAN_TYPE='PR' AND " + @CRITERIA+"=2)THEN TM.TRAN_AMOUNT ELSE 0 END) AS  PURRETURNAMT,
GM.GRP_NAME AS GROUPNAME,COMP.CMP_ALIAS AS COMPANY		                    
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON TM.CMP_CODE=COMP.CMP_CODE   					
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE 					
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID					
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID                     
WHERE TM.CMP_CODE IN("+ @CMP_CODE + ") AND TM.TRAN_TYPE<> 'J'  
AND "+ @VCHDATE + " BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
GROUP BY  "+ @CONDITIONALGROUP + "TM.TRAN_TYPE,TM.TRAN_DOCNO,LM.LGR_NAME,TD.TRAN_DETAIL_ID,PCM.CITY_NAME,TM.TRAN_AMOUNT,
TD.TRAN_DRCR,TM.TRAN_DRCR,TD.TRAN_TYPE,TD.TRAN_AMOUNT,TM.TRAN_TYPE,PCM.CITY_NAME,GM.GRP_NAME,COMP.CMP_ALIAS,"+ @VCHDATE + "
UNION ALL "

SELECT @SQL2="	SELECT  "+@FIELDSQL+" LM.LGR_NAME,0 AS TRAN_DOCNO,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,					
AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE, "+ @SQLRATE +" AS RATE,                    
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN AJ.DRAMOUNT>=0 THEN (DATEDIFF(DAY,AJ.VDATE,'" + @TODATE + "')+1)*AJ.DRAMOUNT/365 ELSE 0 END)
ELSE  (CASE WHEN AJ.DRAMOUNT>=0 THEN (DATEDIFF(DAY,AJ.VDATE,'" + @TODATE + "')+1)*AJ.DRAMOUNT/30   ELSE 0 END)END  DRPRODUCT,
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN AJ.CRAMOUNT>0 THEN (DATEDIFF(DAY,AJ.VDATE,'" + @TODATE + "')+1)*AJ.CRAMOUNT/365 ELSE 0 END)
ELSE (CASE WHEN AJ.CRAMOUNT>0 THEN (DATEDIFF(DAY,AJ.VDATE,'" + @TODATE + "')+1)*AJ.CRAMOUNT/30   ELSE 0 END)END AS CRPRODUCT,
0 SALESAMT, 0 SALESRETURNAMT, 0 PURAMT, 0 PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,COMP.CMP_ALIAS AS COMPANY                    
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON AJ.CMP_CODE=COMP.CMP_CODE   					
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE 
AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  
AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ.ENTRYMATCH=AJ1.ENTRYMATCH 					
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID					
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID                      
WHERE AJ.VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND AJ.CMP_CODE  IN("+ @CMP_CODE + ")
GROUP BY  "+ @CONDITIONALGROUP + "LM.LGR_NAME,LM.LGR_ID ,PCM.CITY_NAME,AJ.ENTRYCODE,AJ.DRAMOUNT,AJ.CRAMOUNT,
AJ.ENTRYTYPE,GM.GRP_NAME,COMP.CMP_ALIAS,AJ.VDATE
UNION ALL "
SELECT @SQL3="
SELECT "+@FIELDSQL+" 					
LM.LGR_NAME AS PARTYNAME,TM.TRAN_DOCNO,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE,"+ @SQLRATE +" AS RATE,                    
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TD.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END )/365 ELSE 0 END)
ELSE (CASE WHEN TD.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END )/30 ELSE 0 END)END DRPRODUCT, 
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN TD.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END )/365  ELSE 0 END)
ELSE (CASE WHEN TD.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END )/30  ELSE 0 END) END AS CRPRODUCT, 
0 SALESAMT, 0 SALESRETURNAMT, 0 PURAMT, 0 PURRETURNAMT,GM.GRP_NAME AS GROUPNAME	,COMP.CMP_ALIAS AS COMPANY
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON TM.CMP_CODE=COMP.CMP_CODE   					
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TM.CMP_CODE=JD.CMP_CODE
AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 					
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID					
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 					
WHERE TM.CMP_CODE IN("+ @CMP_CODE + ")  AND "+ @VCHDATE + " BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND TM.TRAN_TYPE  IN ('J','DN','CN')
GROUP BY  "+ @CONDITIONALGROUP + " TM.TRAN_TYPE,TM.TRAN_DOCNO,LM.LGR_NAME,LM.LGR_ID ,PCM.CITY_NAME,
TD.TRAN_DRCR,TM.TRAN_DRCR,TM.TRAN_TYPE,TD.TRAN_AMOUNT,JD.TRAN_AMOUNT,GM.GRP_NAME ,"+ @VCHDATE + ",TM.TRAN_DATE,COMP.CMP_ALIAS            
UNION ALL "
SELECT @SQL4="
SELECT "+@FIELDSQL+" LM.LGR_NAME AS PARTYNAME,0 AS TRAN_DOCNO,LM.LGR_ID AS PARTYID, PCM.CITY_NAME AS PARTYCITY,
CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)>0 THEN SUM(OPDRAMT)-SUM(OPCRAMT) ELSE 0 END DRAMOUNT,
CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)<0 THEN SUM(OPCRAMT)-SUM(OPDRAMT) ELSE 0 END CRAMOUNT,
'OP' TYPE,"+ @SQLRATE +" AS RATE,                      
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)>=0 THEN ((DATEDIFF(DAY,'" + @FROMDATE + "' ,'" + @TODATE + "')+1)*(SUM(OPDRAMT)-SUM(OPCRAMT)))/365 ELSE 0 END)
ELSE (CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)>=0 THEN ((DATEDIFF(DAY,'" + @FROMDATE + "' ,'" + @TODATE + "')+1)*(SUM(OPDRAMT)-SUM(OPCRAMT)))/30 ELSE 0 END )END AS DRPRODUCT, 
CASE WHEN "+  @YEARPERIOD +"=365 THEN (CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)<0 THEN ((DATEDIFF(DAY,'" + @FROMDATE + "' ,'" + @TODATE + "')+1)*(SUM(OPCRAMT)-SUM(OPDRAMT)))/365 ELSE 0 END )
ELSE (CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)<0 THEN ((DATEDIFF(DAY,'" + @FROMDATE + "' ,'" + @TODATE + "')+1)*(SUM(OPCRAMT)-SUM(OPDRAMT)))/30  ELSE 0 END) END AS CRPRODUCT,
0 SALESAMT, 0 SALESRETURNAMT, 0 PURAMT, 0 PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,COMP.CMP_ALIAS AS COMPANY
FROM " + @DATABASENAME + "OPENINGSTOCK 
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LEDGERCODE=LM.LGR_ID
INNER JOIN " + @DATABASENAME + "LEDGER_DETAIL LD1 ON LM.LGR_ID=LD1.LGR_ID AND LD1.CMP_CODE=" + @DATABASENAME + "OPENINGSTOCK.CMP_CODE
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON LD1.CMP_CODE=COMP.CMP_CODE
LEFT OUTER JOIN " + @DATABASENAME + "CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN " + @DATABASENAME + "GROUP_MASTER GM ON LD1.GRP_ID=GM.GRP_ID                      
" + @JOINSQL + "
WHERE " + @DATABASENAME + "OPENINGSTOCK.CMP_CODE IN("+ @CMP_CODE + ") AND VDATE < '" + @FROMDATE + "'
GROUP BY " + @CONDITIONALGROUP + "LM.LGR_ID, LM.LGR_NAME,PCM.CITY_NAME,GM.GRP_NAME
,COMP.CMP_ALIAS
HAVING SUM(OPDRAMT) -SUM(OPCRAMT)<>0 ) AS DETAIL 
 "
END

EXEC(@SQL+@SQL1 +@SQL2 +@SQL3+@SQL4+@PURDETAIL)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3    
PRINT @SQL4
PRINT @PURDETAIL



















GO

/****** Object:  StoredProcedure [dbo].[PROC_INTCALCMULTILEDGER]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO



















/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_INTCALCMULTILEDGER N'1', N'ACC2017_2018.DBO.', N'01/APR/2017', N'31/MAR/2018', N'##788', 9, 0, 0, 0, 18, 0, 365, N'''''', 0, N'' 
*/

CREATE PROCEDURE [dbo].[PROC_INTCALCMULTILEDGER]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@CRITERIA INT,
@FROMDDD_DATE AS INT,
@CHECKLEDGERRATE AS INT,
@ICHECKCRPERIOD AS INT,
@INTRATE AS NUMERIC(18,2),
@CRPERIOD AS INT,
@YEARPERIOD AS INT,
@EXCLUDETYPE NVARCHAR(200),
@OPTIONS AS INT,
@NEWTEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)
DECLARE @SQL3 AS  NVARCHAR(4000)
DECLARE @SQL4 AS  NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(500)
DECLARE @FIELDSQL NVARCHAR(500)
DECLARE @VCHDATE NVARCHAR(1000)
DECLARE @SQLRATE AS  NVARCHAR(1000)
DECLARE @CONDITIONALGROUP NVARCHAR(100)
DECLARE @DATEGROUPBY NVARCHAR(100)
DECLARE @ORDERBYSQL NVARCHAR(1000)

DECLARE @STRJOINSQL  NVARCHAR(500)
DECLARE @STRJOINAUTOSQL  NVARCHAR(500)
DECLARE @STROPENINGSTOCKSQL NVARCHAR(500)


SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @JOINSQL=""
SET @FIELDSQL=""
SET @VCHDATE=""
SET @SQLRATE=""
SET @SQL6=""
SET @CONDITIONALGROUP=""
SET @DATEGROUPBY=""
SET @ORDERBYSQL=""

SET @STRJOINSQL=""
SET @STRJOINAUTOSQL = ""
SET @STROPENINGSTOCKSQL = ""



IF @CRITERIA=0  /* ALL ACCOUNTS */
BEGIN
SET @JOINSQL="" 
SET @FIELDSQL="'' AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @CONDITIONALGROUP=""
SET @ORDERBYSQL="ORDER BY PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END

ELSE IF @CRITERIA=1 /* SUPPLIER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID"
SET @CONDITIONALGROUP=" SGM.SUPP_GRP_NAME,SGM.SUPP_GRP_ID,"
SET @FIELDSQL="SGM.SUPP_GRP_NAME AS MAINGRP,SGM.SUPP_GRP_ID AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,SUPPGRPID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"

END

ELSE IF @CRITERIA=2 /* CUSTOMER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON LM.CUST_GRP_ID=CGM.CUST_GRP_ID"
SET @CONDITIONALGROUP=" CGM.CUST_GRP_NAME,CGM.CUST_GRP_ID,"
SET @FIELDSQL="CGM.CUST_GRP_NAME AS MAINGRP,0 AS SUPPGRPID,CGM.CUST_GRP_ID AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,CUSTGRPID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END

ELSE IF @CRITERIA=3 /* AGENT */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON LD.AGENT_ID=AGM.LGR_ID"	
SET @CONDITIONALGROUP=" AGM.LGR_NAME,AGM.LGR_ID, "
SET @FIELDSQL="AGM.LGR_NAME AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,AGM.LGR_ID AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,AGENTID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END

ELSE IF @CRITERIA=4 /* CITY */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CITY_MASTER MCM ON LM.CITY_ID=MCM.CITY_ID"
SET @CONDITIONALGROUP=" MCM.CITY_NAME,MCM.CITY_ID,"
SET @FIELDSQL="MCM.CITY_NAME AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
MCM.CITY_ID AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,PARTY_CITYID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END   

ELSE IF @CRITERIA=5 /* STATE */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"STATE_MASTER MSM ON LM.STATE_ID=MSM.STATE_ID"
SET @CONDITIONALGROUP=" MSM.STATE_NAME,MSM.STATE_ID,"
SET @FIELDSQL="MSM.STATE_NAME AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,MSM.STATE_ID AS STATEID,0 AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,STATEID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END

ELSE IF @CRITERIA=6 /* ALL GROUPS */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID  AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID"	
SET @CONDITIONALGROUP="MGM.GRP_NAME,MGM.GRP_ID,"
SET @FIELDSQL="MGM.GRP_NAME AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,MGM.GRP_ID AS MAINGRPID,0 AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,MAINGRPID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END 

ELSE IF @CRITERIA=7 /* CATEGORY */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CATEGORY_MASTER CAM ON LM.CATEGORY_ID=CAM.CATEGORY_ID"
SET @CONDITIONALGROUP="CAM.CATEGORY_NAME,CAM.CATEGORY_ID,"
SET @FIELDSQL="CAM.CATEGORY_NAME AS MAINGRP,0 AS SUPPGRPID,0 AS CUSTGRPID,0 AS AGENTID, 
0 AS PARTY_CITYID,0 AS STATEID,0 AS MAINGRPID,CAM.CATEGORY_ID AS CATEGORYID,"
SET @ORDERBYSQL="ORDER BY MAINGRP,CATEGORYID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO"
END

BEGIN

IF @FROMDDD_DATE IN (0)
BEGIN
SET @VCHDATE=" TM.TRAN_DATE "	
SET  @DATEGROUPBY=" TM.TRAN_DATE "	

END           	   
ELSE IF @FROMDDD_DATE=1
BEGIN
SET @VCHDATE=" (CASE WHEN TD.DDDATE IS NULL THEN TM.TRAN_DATE WHEN TD.DDDATE='1900-01-01 00:00:00' THEN TM.TRAN_DATE  ELSE TD.DDDATE END)"
SET  @DATEGROUPBY=" TM.TRAN_DATE,TD.DDDATE "	
END
ELSE IF @FROMDDD_DATE=2
BEGIN
/* SET @VCHDATE=" TD.CLEARINGDATE " */
SET @VCHDATE =  " (CASE WHEN TM.TRAN_TYPE IN ('BR','BP') THEN TD.CLEARINGDATE ELSE TM.TRAN_DATE END)  "
SET  @DATEGROUPBY=" TM.TRAN_DATE,TD.CLEARINGDATE "	

END
END

BEGIN 
IF @CHECKLEDGERRATE=1
SET @SQLRATE=" MAX(ISNULL(LM.LGR_INTERESTRATE,0))  "
ELSE 
SET @SQLRATE=  @INTRATE 
END 


BEGIN
IF @OPTIONS = 1
BEGIN
SET @STRJOINSQL = " INNER JOIN "+ @NEWTEMPTABLE + " TT1 ON TT1.CODE =TM.TRAN_ID AND TT1.FLAG = TM.TRAN_TYPE AND TT1.TRAN_ID = TM.TRAN_ID"
SET @STRJOINAUTOSQL = " INNER JOIN "+ @NEWTEMPTABLE + " TT1 ON TT1.CODE =AJ.ENTRYCODE AND TT1.FLAG =AJ.ENTRYTYPE "
SET @STROPENINGSTOCKSQL = " INNER JOIN "+ @NEWTEMPTABLE + " TT1 ON  TT1.FLAG = 'OP'" 
END

END


BEGIN
SET NOCOUNT ON;

SELECT @SQL="
SELECT "+@FIELDSQL+" TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') THEN CONVERT(NVARCHAR(20),TM.TRAN_DOCNO) ELSE TD.CHEQUENO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
TM.TRAN_ID AS VCODE,"+ @VCHDATE + " AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TM.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,
TM.TRAN_ID ,"+ @SQLRATE +" AS RATE,
DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1 AS DDIFF,
CASE WHEN TM.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + "   ELSE 0 END DRPRODUCT, 
CASE WHEN TM.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + "   ELSE 0 END AS CRPRODUCT, 
(CASE WHEN TM.TRAN_TYPE IN('S','GS','CS','CRS','GSN','MS','JS') THEN TM.TRAN_AMOUNT ELSE 0 END) AS  SALESAMT, 
(CASE WHEN TM.TRAN_TYPE='SR' THEN TM.TRAN_AMOUNT ELSE 0 END) AS SALESRETURNAMT, 
(CASE WHEN TM.TRAN_TYPE IN('P','CHP','YP','FP','JP') THEN TM.TRAN_AMOUNT ELSE 0 END) AS PURAMT,
(CASE WHEN TM.TRAN_TYPE='PR' THEN TM.TRAN_AMOUNT ELSE 0 END) AS  PURRETURNAMT,
GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,TM.TRAN_DOCNO AS BILLNO
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE   
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID
"+@STRJOINSQL+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE="+ @CMP_CODE + "
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID
WHERE TM.TRAN_TYPE NOT IN("+@EXCLUDETYPE+") AND  TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN ('J','VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
GROUP BY  "+ @CONDITIONALGROUP + "
TM.TRAN_DOCNO,TM.TRAN_TYPE,TD.CHEQUENO,LM.LGR_NAME,TM.TRAN_MASTER_ID,PCM.CITY_NAME,PCM.CITY_ID,TM.TRAN_ID,TM.TRAN_AMOUNT,
"+ @DATEGROUPBY + ",
TM.TRAN_DRCR,TD.TRAN_AMOUNT,LM1.LGR_NAME,LM1.LGR_ID,GM.GRP_NAME,GM.GRP_ID,GM.GRP_ACC_TYPE

/* TWO TIMES FIELD SHOW COMMENT AS ON 11-06-2015
TM.TRAN_DOCNO,
TM.TRAN_ID,
TM.TRAN_TYPE,
PCM.CITY_NAME,
*/

UNION ALL 
"
SELECT @SQL1="
SELECT  "+@FIELDSQL+" TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','SR','GS','CS','CRS','P','CHP','YP','FP','JP') THEN CONVERT(NVARCHAR(20),TM.TRAN_DOCNO) ELSE TD.CHEQUENO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
TM.TRAN_ID AS VCODE,"+ @VCHDATE + " AS VOUCHER_DATE, 
