SET @ORDERBYSQL=""

SET @STRJOINSQL=""
SET @STRJOINAUTOSQL = ""
SET @STROPENINGSTOCKSQL = ""



IF @CRITERIA=0  /* ALL ACCOUNTS */
BEGIN
SET @JOINSQL="" 
SET @JOINSQLPREVIOUS=""
