CASE WHEN SUM(OPDRAMT)-SUM(OPCRAMT)<0 THEN ((DATEDIFF(DAY,'" + @FROMDATE + "' ,'" + @TODATE + "')+1)*(SUM(OPCRAMT)-SUM(OPDRAMT)))/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + "  ELSE 0 END AS CRPRODUCT,
