"

SELECT @SQL6="
UNION ALL
SELECT "+@FIELDSQL+" TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') THEN CONVERT(NVARCHAR(20),TM.TRAN_DOCNO) ELSE TD.CHEQUENO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
TM.TRAN_ID AS VCODE,"+ @VCHDATE + " AS VOUCHER_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TM.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,
TM.TRAN_ID ,"+ @SQLRATE +" AS RATE,
DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1 AS DDIFF,
CASE WHEN TD.TRAN_DRCR = 'D' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + "   ELSE 0 END DRPRODUCT, 
CASE WHEN TD.TRAN_DRCR = 'C' THEN (DATEDIFF(DAY," + @VCHDATE + ",'" + @TODATE + "')+1)*TD.TRAN_AMOUNT/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + "   ELSE 0 END AS CRPRODUCT, 
(CASE WHEN TM.TRAN_TYPE IN('S','GS','CS','CRS','GSN','MS','JS') THEN TM.TRAN_AMOUNT ELSE 0 END) AS  SALESAMT, 
(CASE WHEN TM.TRAN_TYPE='SR' THEN TM.TRAN_AMOUNT ELSE 0 END) AS SALESRETURNAMT, 
(CASE WHEN TM.TRAN_TYPE IN('P','CHP','YP','FP','JP') THEN TM.TRAN_AMOUNT ELSE 0 END) AS PURAMT,
(CASE WHEN TM.TRAN_TYPE='PR' THEN TM.TRAN_AMOUNT ELSE 0 END) AS  PURRETURNAMT,
GM.GRP_NAME AS GROUPNAME,TM.TRAN_DOCNO AS BILLNO,PCM.CITY_ID,GM.GRP_ID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE="+ @CMP_CODE + "
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID
WHERE TM.TRAN_TYPE NOT IN("+@EXCLUDETYPE+") AND  TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE IN ('VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
GROUP BY  "+ @CONDITIONALGROUP + "
TM.TRAN_DOCNO,TM.TRAN_TYPE,TD.CHEQUENO,LM.LGR_NAME,TM.TRAN_MASTER_ID,PCM.CITY_NAME,PCM.CITY_ID,TM.TRAN_ID,TM.TRAN_AMOUNT,
"+ @DATEGROUPBY + ",
TD.TRAN_DRCR,TD.TRAN_AMOUNT,LM1.LGR_NAME,LM1.LGR_ID,GM.GRP_NAME,GM.GRP_ID

/* TWO TIMES FIELD SHOW COMMENT AS ON 11-06-2015
TM.TRAN_DOCNO,
TM.TRAN_ID,
TM.TRAN_TYPE,
PCM.CITY_NAME,
*/
) AS DETIL 
"+@MAINGRPBYSQL+"
"+@ORDERBYSQL+"
 
"






END

PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3    
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
EXEC(@SQL+@SQL1 +@SQL2 +@SQL3+@SQL4+@SQL5+@SQL6)



















GO

/****** Object:  StoredProcedure [dbo].[PROC_INTEREST_REC_REPORT]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*

-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 29/04/2013
-- Description:	THIS PROCEDURE USED FOR INTEREST RECEIVE REPORT
-- ReportName : INTERESTRECEIVE.RPT
-- =============================================
PROC_INTEREST_REC_REPORT 1,'ACC2012_2013.DBO.','01/APRIL/2012','29/APRIL/2013',1,'##3444'
*/
CREATE PROCEDURE [dbo].[PROC_INTEREST_REC_REPORT]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(100),
  @TODATE AS NVARCHAR(100),
  @RPT_WISE AS INT,
  @TEMPTABLE AS NVARCHAR(50)
)

AS
DECLARE @SQL AS NVARCHAR(4000) SET @SQL =""
DECLARE @SQL1 AS NVARCHAR(4000) SET @SQL1 =""
BEGIN
	SET NOCOUNT ON;
SET @SQL="
SELECT PartyName,PartyId,SUM(DrAMOUNT) AS DrAMOUNT,SUM(CrAMOUNT) AS CrAMOUNT,AccountName,ACC_ID,GRP_NAME,CITY_NAME,MAX(CMP_ALIAS)CMP_ALIAS
FROM (
Select LM.Lgr_Name as PartyName,TD.Tran_Detail_Id AS PartyId,
(CASE WHEN TD.Tran_DrCr = 'D' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS DrAMOUNT, 
(CASE WHEN TD.Tran_drcr = 'C' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS CrAMOUNT
,TM.Tran_Type as A_TYPE, LM1.Lgr_Name AS AccountName,LM1.Lgr_ID as ACC_ID,GM.GRP_NAME,PCM.CITY_NAME,CMP_ALIAS
From "+@DATABASENAME+" Tran_Master TM 
INNER JOIN "+@DATABASENAME+"Tran_Detail TD ON TD.TRan_Id= TM.TRan_Id And TD.Tran_Type = TM.Tran_Type AND TD.Cmp_Code= TM.Cmp_Code  
INNER JOIN "+@DATABASENAME+"Tran_Detail as Jd ON TD.Tran_Type = JD.Tran_Type AND TD.Tran_Id= Jd.Tran_Id and TD.Tran_Detail_Id<> Jd.Tran_Detail_Id And TD.Tran_DrCr <> Jd.Tran_DrCr  
INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_Id= LM.Lgr_Id 
INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON Jd.Tran_Detail_Id = LM1.Lgr_Id  
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM1.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
INNER JOIN "+@DATABASENAME+"COMPANYSETTING CM ON CM.INTERESTGROUPID=TD.Tran_Detail_Id AND CM.SETTINGNAME='PARAMETER'
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMM ON CMM.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM1.Lgr_Id
Where TM.Cmp_Code="+@CMP_CODE+" And TM.Tran_Date Between '"+@FROMDATE+"' And  '"+@TODATE+"' "

SET @SQL1=" 
union all  
Select LM.Lgr_Name AS PARTYNAME,LM.Lgr_ID AS PartyId,AJ.DrAmount AS DrAMOUNT,AJ.CrAmount AS CrAMOUNT,AJ.entrytype AS A_Type
,LM1.Lgr_Name AS AccountName,LM1.Lgr_ID AS ACC_ID,GM.GRP_NAME,PCM.CITY_NAME,CMP_ALIAS
From "+@DATABASENAME+"AutoJournal AJ 
INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON AJ.Lgr_Id = LM.Lgr_Id  
INNER JOIN "+@DATABASENAME+"AutoJournal AJ1 ON AJ.Cmp_Code=AJ1.Cmp_Code And AJ.EntryCode=AJ1.EntryCode And AJ.entrytype = AJ1.entrytype  And AJ.Lgr_ID<> AJ1.Lgr_ID And AJ1.VCode = AJ.VCode and AJ1.entrymatch= AJ.entrymatch  
INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON AJ1.Lgr_Id= LM1.Lgr_Id  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM1.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANYSETTING CM ON CM.INTERESTGROUPID=LM.Lgr_ID AND CM.SETTINGNAME='PARAMETER'
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMM ON CMM.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM1.Lgr_Id
Where AJ.VDate Between '"+@FROMDATE+"' And '"+@TODATE+"'And AJ.Cmp_Code= "+@CMP_CODE+"
) AS  A
GROUP BY PartyName,PartyId,AccountName,ACC_ID,GRP_NAME,CITY_NAME
ORDER BY PARTYNAME
" 

END
PRINT @SQL
PRINT @SQL1
EXEC (@SQL+@SQL1)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_INTERESTREPORT]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_INTERESTREPORT '2','ACC2010_2011.DBO.','01/APR/2010','12/JAN/2011','##2310'
*/
CREATE PROCEDURE [dbo].[PROC_INTERESTREPORT]
(
  @CMP_CODE NVARCHAR(100),
  @DATABASENAME NVARCHAR(100),
  @FROMDATE NVARCHAR(20),
  @TODATE NVARCHAR(20),
  @TEMPTABLE NVARCHAR(20)

  
)
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""

         SET @SQL=" SELECT PD.LGR_ID,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY ,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_DISTRICT,LM.CITY_PINCODE,PSM.STATE_NAME AS PARTYSTATE
                   ,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENT_CITY,PD.VCODE,PD.JOBFLAG
                   ,PD.BILL_NO,PD.DATE AS BILLDATE,PD.BILL_AMOUNT,ISNULL(PD.PAID,0) AS PAID,ISNULL(ADJ.ADJUSTAMT,0) AS RECDAMT,ADJ.RECDATE,DATEDIFF(DD,PD.DATE,ADJ.RECDATE) AS DAYS,
                   ISNULL(ADJ.DISCOUNT,0) AS DISCOUNT_ADJ,ISNULL(ADJ.INTEREST,0) AS INTEREST_ADJ,ISNULL(ADJ.INTREC,0) AS INTREC_ADJ,ISNULL(ADJ.OTHERLESS,0) AS OLESS_ADJ
                   ,CMP.CMP_ALIAS
                   FROM "+@DATABASENAME+"PARTYDETAIL PD
                   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
                   LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                   LEFT JOIN "+@DATABASENAME+"STATE_MASTER PSM ON PSM.STATE_ID=LM.STATE_ID
                   INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID  AND LD.CMP_CODE=PD.CMP_CODE
                   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID 
                   LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                   INNER JOIN "+@DATABASENAME+"ADJMASTER ADJ ON ADJ.LGR_ID=PD.LGR_ID AND ADJ.BILLNO=PD.BILL_NO AND PD.VCODE=ADJ.VCODE AND PD.JOBFLAG=ADJ.FLAG AND ADJ.CMP_CODE=PD.CMP_CODE
                   LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
                   INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID
                   WHERE PD.CMP_CODE IN ("+@CMP_CODE+") AND PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
                   ORDER BY PD.DATE,PD.BILL_NO,ADJ.RECDATE"
                   
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

