/****** Object:  StoredProcedure [dbo].[PROC_ITEMFOLDPARTY_SUMMARY]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO























/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 19-11-2014
-- DESCRIPTION:	THIS REPORT IS USED TO ITEM FOLD PARTY SUMMARY
MODIFIED 04/07/2016 SHUBHAM RAVAL
ITEM GROUP ADDED
-- =============================================

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_ITEMFOLDPARTY_SUMMARY '2','ACC2015_2016.DBO.',3,'01/apr/2015','31/mar/2016','##2212',0


*/
CREATE PROCEDURE [dbo].[PROC_ITEMFOLDPARTY_SUMMARY]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@WITHOS INT
)
AS

DECLARE @STRSQL NVARCHAR(4000)
DECLARE @STRSQL1 NVARCHAR(4000)
DECLARE @STRSQL2 NVARCHAR(4000)
DECLARE @STRJOIN NVARCHAR(500)
DECLARE @STRWITHOSSQL NVARCHAR(500)
DECLARE @STRWITHOSFIELDSQL NVARCHAR(500)
DECLARE @OSGROUPBYSQL NVARCHAR(500)
DECLARE @ORDERBYSQL NVARCHAR(500)

SET @STRSQL=""
SET @STRSQL1=""
SET @STRSQL2 =""
SET @STRJOIN=""
SET @STRWITHOSSQL=""
SET @STRWITHOSFIELDSQL=""
SET @OSGROUPBYSQL=""
SET @ORDERBYSQL=""

BEGIN

BEGIN
IF @RPT_WISE =1
BEGIN
SET @STRJOIN=" INNER JOIN "+ @TEMPTABLE +"  TT ON TT.CODE=IM.ITEM_ID"
SET @ORDERBYSQL=" ORDER BY ITEM,ITEMID,PACKINGSTYLE,PACKINGSTYLEID,STAMPGROUPNAME,STAMPGRPID,PNAME,PARTYID,CONFNO "
END
ELSE IF  @RPT_WISE =2
BEGIN
SET @STRJOIN=" INNER JOIN "+ @TEMPTABLE +"  TT ON TT.CODE=LM.LGR_ID"
SET @ORDERBYSQL=" ORDER BY PNAME,PARTYID,PACKINGSTYLE,PACKINGSTYLEID,STAMPGROUPNAME,STAMPGRPID,CONFNO "
END
ELSE IF  @RPT_WISE =3
BEGIN
SET @STRJOIN=" INNER JOIN "+ @TEMPTABLE +"  TT ON TT.CODE=LM1.LGR_ID"
SET @ORDERBYSQL=" ORDER BY AGNAME,AGENTID,PACKINGSTYLE,PACKINGSTYLEID,STAMPGROUPNAME,STAMPGRPID,PNAME,PARTYID,CONFNO "
END

END

IF @WITHOS = 1
BEGIN
SET @STRWITHOSSQL = "LEFT OUTER JOIN (
SELECT (ISNULL(SUM(PENDING),0) - (ISNULL(SUM(PARTCASHAMT),0)  + ISNULL(SUM(PARTADJAMT),0))) AS PENDING,MIN(DATE) AS VDATE,PARTY_ID AS PARTY_ID 
FROM  "+@DATABASENAME+"ONACCOUNT GROUP BY PARTY_ID 
) PD ON SO.LGR_ID =PD.PARTY_ID "
SET @STRWITHOSFIELDSQL="PD.PENDING,PD.VDATE,"
SET @OSGROUPBYSQL="PD.PENDING,PD.VDATE,"
END

ELSE
BEGIN
SET @STRWITHOSSQL = ""
SET @STRWITHOSFIELDSQL="0 AS PENDING,CONVERT(NVARCHAR(10),'') AS VDATE,"
SET @OSGROUPBYSQL=""
END


BEGIN
SET @STRSQL=" SELECT ABC.PBALES AS BILL_NO, SOD.SAL_ORDER_ID, SO.VCH_DATE, SO.SALES_ORDERNO,
SOD.BALES- (ISNULL(ABC.PBALES,0) + CASE WHEN SOD.BALES > 0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END) AS PENBALES,
SOD.PIECES-(ISNULL(ABC.PPCS,0)  + CASE WHEN SOD.PIECES>0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END) AS PENPCS,
SOD.QUANTITY- (ISNULL(ABC.PMTRS,0)  + CASE WHEN SOD.QUANTITY>0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END )  AS PENQTY,ISNULL(SOCD.CANCELS,0) AS SOCDQTY ,
SOD.BALES, SOD.PIECES, SOD.QUANTITY, SOD.RATE, LM.LGR_NAME AS PNAME, LM1.LGR_NAME AS AGNAME,ISNULL(ABC.PPCS,0) AS SPCS,ISNULL(ABC.PMTRS,0) AS SQTY,
ISNULL(ABC.PBALES,0) AS SBALES,
'' AS SGCODE, '' AS SGNAME, '' AS CGCODE, '' AS CGNAME,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEM_GRP_NAME, SO.CONFNO,"+@STRWITHOSFIELDSQL+"UPPER(STAMPGM.STAMPGRP_NAME) AS STAMPGROUPNAME,
CMDEST.CITY_NAME AS DESTINATIONSTATION,TM.TRANSPORT_NAME AS TRANSPORT,SOD.REMARK AS NARR,IM.ITEM_CUT,PACKSM.PACKINGSTYLE_NAME AS PACKINGSTYLE,
PCITY.CITY_NAME AS PCITYNAME,SOD.BALESPCSMTR,SM.SCREEN_NAME,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(LM1.LGR_ID,0) AS AGENTID,ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(SM.SCREEN_ID,0) AS SCREENID,
ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(CMDEST.CITY_ID,0) AS DESTINATIONID,ISNULL(PACKSM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID ,
ISNULL(STAMPGM.STAMPGRP_ID,0) AS STAMPGRPID,ISNULL(PCITY.CITY_ID,0) AS PARTY_CITYID

FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SO.CMP_CODE=SOD.CMP_CODE AND SO.FLAG =SOD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID 
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id 
LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
LEFT OUTER JOIN(
SELECT  SO.SAL_ORDER_ID,PS.CONFNO,PSD.ITEM_ID, CASE WHEN SOD.BALES> 0 THEN ISNULL(COUNT(PS.BALENO),0) ELSE 0 END AS PBALES,
CASE WHEN SOD.PIECES>0 THEN  ISNULL(SUM(PSD.TOTALPCS),0) ELSE 0 END  AS PPCS, CASE WHEN QUANTITY> 0 THEN  ISNULL(SUM(PSD.TOTAL),0)  ELSE 0 END AS PMTRS 
FROM "+@DATABASENAME+"PACKINGSLIP PS 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=PS.CONFNO AND SO.FYEAR=PS.FYEAR   /* AND SO.CMP_CODE = PS.CMP_CODE */
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND PSD.ITEM_ID=SOD.ITEM_ID  AND PSD.SCREEN_ID=SOD.SCREEN_ID  
AND SO.FLAG=SOD.FLAG    AND SO.CMP_CODE = SOD.CMP_CODE
WHERE SO.VCH_DATE <= '"+@TODATE+"' GROUP BY SO.SAL_ORDER_ID,PS.CONFNO,PSD.ITEM_ID,SOD.PIECES,SOD.QUANTITY,SOD.BALES
) ABC ON ABC.CONFNO=SO.CONFNO AND ABC.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SOD.ITEM_ID=ABC.ITEM_ID
LEFT OUTER JOIN ("

SET @STRSQL1="SELECT SO.SAL_ORDER_ID,SOCD.ITEM_ID,ISNULL(SUM(SOCD.CANCELBALES),0) AS CANCELS 
FROM "+@DATABASENAME+"SALESORDER_CANCELLATION SOC
INNER JOIN "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID AND SOC.FLAG=SOCD.FLAG 
INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.FYEAR=SOCD.FYEAR  AND SO.FLAG=SOCD.FLAG   /*  AND SO.CMP_CODE = SOCD.CMP_CODE */
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID AND SO.FLAG=SOD.FLAG  AND SO.CMP_CODE = SOD.CMP_CODE 
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOCD.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SOCD.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=SO.AGENT_ID
"+@STRJOIN+"
WHERE SO.VCH_DATE <= '"+@TODATE+"' GROUP BY SO.SAL_ORDER_ID,SOCD.ITEM_ID) SOCD ON SO.SAL_ORDER_ID = SOCD.SAL_ORDER_ID AND SOD.ITEM_ID = SOCD.ITEM_ID 

INNER JOIN   "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID
INNER JOIN   "+@DATABASENAME+"LEDGER_MASTER LM1 ON SO.LGR_ID = LM1.LGR_ID
"+@STRWITHOSSQL+"
LEFT OUTER JOIN  "+@DATABASENAME+"TRANSPORT_MASTER TM ON SO.TRANSPORT_ID= TM.TRANSPORT_ID
LEFT OUTER JOIN  "+@DATABASENAME+"CITY_MASTER CMDEST ON SO.STATION_ID= CMDEST.CITY_ID 
LEFT OUTER JOIN  "+@DATABASENAME+"PACKINGSTYLE_MASTER PACKSM ON SOD.PACKINGSTYLE_ID = PACKSM.PACKINGSTYLE_ID
LEFT OUTER JOIN  "+@DATABASENAME+"STAMPGROUP_MASTER STAMPGM ON STAMPGM.STAMPGRP_ID = SO.STAMPGRP_ID 
LEFT OUTER JOIN  "+@DATABASENAME+"CITY_MASTER PCITY ON LM.CITY_ID = PCITY.CITY_ID
"+@STRJOIN+"
WHERE  (SO.VCH_DATE <= '"+@TODATE+"')  AND  (SO.VCH_DATE >= '"+@FROMDATE+"')  AND (SOD.PENDINGBALES >0  OR SOD.PENDINGPIECES >0 OR SOD.PENDINGQTY > 0)
--AND (SOM.SOCANCEL = 0 OR SOM.SOCANCEL IS NULL )
GROUP BY SOD.SAL_ORDER_ID,SO.VCH_DATE,SO.SALES_ORDERNO,SOD.PENDINGBALES,SOD.PENDINGPIECES,SOD.PENDINGQTY,IM.ITEM_NAME,IGM.ITEM_GRP_NAME,SOD.SCREEN_ID, 
SOD.BALES, SOD.PIECES, SOD.QUANTITY, SOD.RATE,  LM.LGR_NAME, LM1.LGR_NAME,IM.ITEM_NAME,SO.CONFNO,
SO.VCH_DATE,"+@OSGROUPBYSQL+"STAMPGM.STAMPGRP_NAME,CMDEST.CITY_NAME,TM.TRANSPORT_NAME,SOD.REMARK,IM.ITEM_CUT,ABC.PBALES,
ABC.PPCS, ABC.PMTRS,PACKSM.PACKINGSTYLE_NAME,PCITY.CITY_NAME,SOCD.CANCELS,SOD.BALESPCSMTR,SM.SCREEN_NAME,
ISNULL(LM.LGR_ID,0),ISNULL(LM1.LGR_ID,0),ISNULL(IM.ITEM_ID,0),ISNULL(SM.SCREEN_ID,0),
ISNULL(TM.TRANSPORT_ID,0),ISNULL(CMDEST.CITY_ID,0),ISNULL(PACKSM.PACKINGSTYLE_ID,0),
ISNULL(STAMPGM.STAMPGRP_ID,0),ISNULL(PCITY.CITY_ID,0)
HAVING((SOD.BALES- (ISNULL(ABC.PBALES,0) + CASE WHEN SOD.BALES> 0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END))  > 0 OR (ISNULL(SOD.PIECES,0)- (ISNULL(ABC.PPCS,0) + CASE WHEN SOD.PIECES>0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END) ) >0 OR (SOD.QUANTITY- (ISNULL(ABC.PMTRS,0) + CASE WHEN SOD.QUANTITY>0 THEN ISNULL(SOCD.CANCELS,0) ELSE 0 END)) > 0)
"+@ORDERBYSQL+"
"	
END
END
EXEC  (@STRSQL +@STRSQL1)
PRINT @STRSQL
PRINT @STRSQL1























GO

