/*
-- =============================================
-- Author:		<BIREN> 
-- Create_date: <19/10/2012,5:05>
-- Report Form:	<rfrmItemSchemeReg>
-- Report :	<ITEMSCHEMEREG,ITEMSCHEMEREGWITHDISC>
-- Proc_Name : <PROC_ITEMSCHEMEREG>
-- ReportName: ITEMSCHEMEREG.rpt,ITEMSCHEMEREGWITHDISC.rpt
-- =============================================
PROC_ITEMSCHEMEREG '1','Acc2013_2014.Dbo.','01/Apr/2013','31/Mar/2014',##1916,1,3,2,###1916,2,10,00
*/
CREATE PROCEDURE [dbo].[PROC_ITEMSCHEMEREG]
(
	@Cmp_Code nvarchar(100),
	@DatabaseName nvarchar(50),	
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
	@TempTable nvarchar(20),
	@Rpt_Wise int,
	@Net_SNet int,
    @Item_Wise int,
	@TempTable_Item as nvarchar(100),
	@Rate_Wise int,
	@FormRate nvarchar(20),
	@DiscPer nvarchar(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @ITEMSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""
SET @NET_SNETSQL=""
SET @ITEMSQL = ""

SET NOCOUNT ON;

BEGIN
    IF @NET_SNET=1        /* SNET BILL*/
      SET @NET_SNETSQL=" AND SI.NET_SNET='S.NET'"      
   ELSE IF @NET_SNET=2    /*WITHOUT SNET BILL*/
      SET @NET_SNETSQL=" AND SI.NET_SNET !='S.NET'"          
   ELSE IF @NET_SNET=3    /*ALL*/
      SET @NET_SNETSQL=""      
END 
BEGIN
	IF @Item_Wise in (0) and @Rpt_Wise not in (3,9,10)
		 BEGIN
			SET @ITEMSQL = " INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=IM.ITEM_ID"
		 END 
	ELSE IF @Item_Wise in (1) and @Rpt_Wise not in (4,11,12)
		 BEGIN
			SET @ITEMSQL = " INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=IGM.ITEM_GRP_ID"
		 END
	ELSE IF @Item_Wise in (2) /*and @Rpt_Wise not in (4,11,12) */
		 BEGIN
			SET @ITEMSQL = " INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=ITM.ITEM_TYPE_ID"
		 END
END	

BEGIN
	IF @Rpt_Wise in (1,5,6)
		 BEGIN
		  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON  LM.LGR_ID=TT.CODE"
		 END 
	ELSE IF @Rpt_Wise in (2,7,8,13,14,15)
		 BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON ALM.LGR_ID=TT.CODE"
		 END 
	ELSE IF @Rpt_Wise in (3,9,10)
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON SID.ITEM_ID=TT.CODE"
		END 
	ELSE IF @Rpt_Wise in (4,11,12)
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON IGM.ITEM_GRP_ID=TT.CODE"
		END 
	ELSE IF @Rpt_Wise in (16,17)
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON SM.SALESMAN_ID=TT.CODE"
		END 
END
SET @SQL = ""	
BEGIN
	IF @Rate_Wise IN (0,1,2)
		BEGIN
			SET @SQL="
SELECT SI.SAL_INV_ID AS ID,SAL_INV_BILL_NO AS BILLNO,convert(nvarchar,SAL_INV_VDATE,103) AS DATE,
SID.SAL_INV_BALENO AS BALENO,SAL_INV_QTY AS QTY,SAL_INV_PCS AS PCS,
SID.SAL_INV_AMOUNT as AMOUNT,SI.SAL_INV_NETTOTAL AS NETTOTAL,
0 AS ADDLESS,0 AS AMOUNT_ADDLESS,0 AS DISC_AMT,0 AS NETAMT,0 AS SCHEMEAMT,
ABS(SI.SAL_INV_ADDTOTAL - SI.SAL_INV_LESSTOTAL) AS ADDLESS,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGRP,
COMP.CMP_ALIAS,SI.NET_SNET,LCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,
ITM.ITEM_TYPE_NAME AS ITEMTYPE
FROM "+ @DatabaseName+ "SALES_INVOICE SI 
INNER JOIN "+ @DatabaseName+ "SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID = SID.SAL_INV_ID AND SI.FLAG = SID.FLAG AND  SI.CMP_CODE = SID.CMP_CODE 
INNER JOIN "+ @DatabaseName+ "LEDGER_MASTER LM ON LM.LGR_ID = SI.LGR_ID
LEFT JOIN "+ @DatabaseName+ "LEDGER_MASTER ALM ON ALM.LGR_ID = SI.AGENT_ID
LEFT JOIN "+ @DatabaseName+ "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+ @DatabaseName+ "CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
INNER JOIN "+ @DatabaseName+ "ITEM_MASTER IM ON IM.ITEM_ID = SID.ITEM_ID
INNER JOIN "+ @DatabaseName+ "UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
LEFT JOIN "+ @DatabaseName+ "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
INNER JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN " + @DatabaseName + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+ @DatabaseName+ "ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID = IM.ITEM_TYPE_ID
"+@ITEMSQL+"			
"+@JOINSQL+"
WHERE SI.Cmp_Code IN("+ @Cmp_Code +") and SI.SAL_INV_VDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
and SI.FLAG='S'
"+@NET_SNETSQL+"
ORDER BY CONVERT(INT,SI.SAL_INV_BILL_NO),SI.SAL_INV_VDATE,SID.SAL_INV_DTL_ID
					" 
			END
	ELSE IF @Rate_Wise = 3
		BEGIN
		   SET @SQL="
					
SELECT SI.SAL_INV_ID AS ID,SAL_INV_BILL_NO AS BILLNO,CONVERT(NVARCHAR,SAL_INV_VDATE,103) AS DATE,
SID.SAL_INV_BALENO AS BALENO,SAL_INV_QTY AS QTY,SAL_INV_PCS AS PCS,
SID.SAL_INV_AMOUNT AS AMOUNT,
SI.SAL_INV_NETTOTAL AS NETTOTAL,
CONVERT(NUMERIC(18,2),(SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL)) AS ADDLESS,
CONVERT(NUMERIC(18,2),(SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL))
AS AMOUNT_ADDLESS,
CONVERT(NUMERIC(18,2),((SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL)
* CONVERT(NUMERIC(18,2),"+@DiscPer+") / 100)) 
AS DISC_AMT,
CONVERT(NUMERIC(18,2),(SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL-
(SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL)
* CONVERT(NUMERIC(18,2),"+@DiscPer+") / 100)) AS NETAMT,
CONVERT(NUMERIC(18,2),(SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL-
(SID.SAL_INV_AMOUNT + 
(SID.SAL_INV_AMOUNT * (SI.SAL_INV_NETTOTAL -  SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL)
* CONVERT(NUMERIC(18,2),"+@DiscPer+") / 100)
* CONVERT(NUMERIC(18,2),"+@FormRate+") /100) AS SCHEMEAMT,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGRP,
COMP.CMP_ALIAS,SI.NET_SNET,LCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,
ITM.ITEM_TYPE_NAME AS ITEMTYPE
FROM "+ @DatabaseName+ "SALES_INVOICE SI
INNER JOIN "+ @DatabaseName+ "SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID = SID.SAL_INV_ID AND SI.FLAG = SID.FLAG AND  SI.CMP_CODE = SID.CMP_CODE 
INNER JOIN "+ @DatabaseName+ "LEDGER_MASTER LM ON LM.LGR_ID = SI.LGR_ID
LEFT JOIN "+ @DatabaseName+ "LEDGER_MASTER ALM ON ALM.LGR_ID = SI.AGENT_ID
INNER JOIN "+ @DatabaseName+ "ITEM_MASTER IM ON IM.ITEM_ID = SID.ITEM_ID
INNER JOIN "+ @DatabaseName+ "UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
LEFT JOIN "+ @DatabaseName+ "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
INNER JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN "+ @DatabaseName+ "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+ @DatabaseName+ "CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DatabaseName + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+ @DatabaseName+ "ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID = IM.ITEM_TYPE_ID
"+@ITEMSQL+"			
"+@JOINSQL+"
WHERE SI.Cmp_Code IN("+ @Cmp_Code +") and SI.SAL_INV_VDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
and SI.FLAG='S'
"+@NET_SNETSQL+"
ORDER BY CONVERT(INT,SI.SAL_INV_BILL_NO),CONVERT(INT,SID.Sal_Inv_Dtl_Id)
"
		END
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_ITEMWISEPURCHASE]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_ITEMWISEPURCHASE '3','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##4012',1,1
*/
CREATE PROCEDURE [dbo].[PROC_ITEMWISEPURCHASE]
( 
        @CMP_CODE AS NVARCHAR(100),
        @DATABASENAME AS NVARCHAR(100),
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
        @TEMPTABLE AS  NVARCHAR(20),
        @RPT_WISE AS  int,       
        @PURHEAD AS NVARCHAR(20),
		@OPTIONS AS INT
 )
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @HEADSQL AS NVARCHAR(500)
DECLARE @SQLCOND AS NVARCHAR(500)

SET @SQL=""	
SET @JOINSQL=""	
SET @HEADSQL=""	
SET @SQLCOND = ""
   BEGIN  
        IF @RPT_WISE=1
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
        IF @RPT_WISE=2
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
        IF @RPT_WISE=3
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
        IF @RPT_WISE=4
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=ITM.ITEM_TYPE_ID"
   END 
  BEGIN 
      IF @PURHEAD=0
        SET @HEADSQL=""
      ELSE
         SET @HEADSQL=" AND PI.PURACCID="+@PURHEAD
     
  END 
  BEGIN
	 IF @OPTIONS = 1
		SET @SQLCOND = " AND PI.FLAG IN ('P','CHP','FP') "
	 ELSE  IF @OPTIONS = 2
		SET @SQLCOND = " AND PI.FLAG IN ('JP') "	
  END
           SET @SQL=" SELECT ITEMGROUP,ITEMTYPE,ITEM,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS FROM(
                      SELECT IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_NAME AS ITEM,IOS.PUR_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT, PID.QUANTITY AS QUANTITY,
                      (PID.AMOUNT)+(((PID.AMOUNT)*(PI.NETTOTAL- PI.GROSSTOTAL))/PI.GROSSTOTAL) AS AMOUNT,
                      (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
                       ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,CMP.CMP_ALIAS                      
                      FROM "+@DATABASENAME+"PURCHASEINVOICE PI
                      INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PID.FLAG=PI.FLAG
                      INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
                      INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
                      LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
                      INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
                      LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
                      INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=PI.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
                      "+ @JOINSQL +" 
                      WHERE PI.VCHDATE>='"+@FROMDATE+"' AND PI.VCHDATE<='"+@TODATE+"'
                      AND PI.CMP_CODE IN("+@CMP_CODE+") "+@SQLCOND+" "+@HEADSQL+"
                      ) AS DETAIL GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS ORDER BY ITEM"    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_ITEMWISESALES]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_ITEMWISESALES '2','ACC2012_2013.DBO.','01/APR/2012','31/MAR/2013','##3228',1,1
*/
CREATE PROCEDURE [dbo].[PROC_ITEMWISESALES]
	( 
        @CMP_CODE AS NVARCHAR(100),
        @DATABASENAME AS NVARCHAR(100),
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
        @TEMPTABLE AS  NVARCHAR(20),
        @RPT_WISE AS  int,
        @HEADID AS  NVARCHAR(20)
       
    )
AS
BEGIN
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @MAINSQL AS NVARCHAR(2000)
DECLARE @GRPSQL AS NVARCHAR(2000)

SET @SQL=""	
SET @MAINSQL=""	
SET @GRPSQL=""	
SET @JOINSQL=""	
   BEGIN  
        IF @RPT_WISE=1
           BEGIN
               SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
               SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
               SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS "	
           END
        IF @RPT_WISE=2
            BEGIN 
               SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
               SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
               SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS "	
            END
        IF @RPT_WISE=3
            BEGIN
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
               SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
               SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS "	
            END
        IF @RPT_WISE=4
           BEGIN
               SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=ITM.ITEM_TYPE_ID"
               SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
               SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS "	
           END
        IF @RPT_WISE=5
           BEGIN
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=SM.SCREEN_ID"
                SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM AS ITEM,SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
                SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,SCREEN,UNIT,ITEM,ITEMRATE,CMP_ALIAS "	
           END
		IF @RPT_WISE=6
           BEGIN
               SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
               SET @MAINSQL="SELECT ITEMGROUP,ITEMTYPE,ITEM,MIN(SCREEN)AS SCREEN,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES"	
               SET @GRPSQL=" GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS "	
           END
   END 

           SET @SQL=@MAINSQL +" FROM(
                      SELECT IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IOS.SAL_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT,
                      (CASE WHEN UM.UNIT_NAME='PIECES' THEN SID.SAL_INV_pcs ELSE SID.SAL_INV_QTY END)AS QUANTITY,
                      (SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
                      (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
                       ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,CMP.CMP_ALIAS
                      FROM "+@DATABASENAME+"SALES_INVOICE SI
                      INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
                      INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
                      INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
                      INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
                      LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
                      INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
                      LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
                      INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=SI.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
                      "+ @JOINSQL +" 
                      WHERE SI.SAL_ACCID="+@HEADID+" AND SI.SAL_INV_VDATE>='"+@FROMDATE+"' AND SI.SAL_INV_VDATE<='"+@TODATE+"'
                            AND SI.CMP_CODE IN("+@CMP_CODE+") AND SI.FLAG = 'S'
                      ) AS DETAIL 
                       
                      "+@GRPSQL+"
                      ORDER BY ITEM"

 
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_ITEMWISESALES_ONEOPT]    Script Date: 03/30/2023 12:08:12 ******/
