CREATE PROCEDURE [dbo].[PROC_ITEMWISESALES_ONEOPT]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(100),
  @TODATE AS NVARCHAR(100),
  @RPT_WISE AS INT,
  @ID AS INT 
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
    SET @SQL=" SELECT PARTY,PARTYCITY,AGENT,AGENTCITY,ITEMGROUP,ITEMTYPE,ITEM,ITEMRATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,COUNT(*) AS TOTALBALES
     FROM(
     SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT, SID.SAL_INV_QTY AS QUANTITY,
     (SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
     (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,CMP.CMP_ALIAS                      
     FROM "+@DATABASENAME+"SALES_INVOICE SI
     INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID
     INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
     LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
     INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID                      
     INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE                      
     INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
     INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
     LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
     WHERE SI.SAL_INV_VDATE>='"+@FROMDATE+"' AND SI.SAL_INV_VDATE<='"+@TODATE+"'
     AND SI.CMP_CODE IN("+@CMP_CODE+")
     ) AS DETAIL GROUP BY ITEMGROUP,ITEMTYPE,ITEM,UNIT,ITEMRATE,CMP_ALIAS ,
	 PARTY,PARTYCITY,AGENT,AGENTCITY
	 ORDER BY ITEM"	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

