/* 
Proc_ItemWiseStockReport 1,'ACC2013_2014.DBO.','01/APR/2013','14/DEC/2014',1000

REPORT NAME :- COSTING.RPT
FLAG :
CHP: CHEMICAL PURCHASE INVOICE,P: GREY PURCHASE INVOICE
GJC: GREY JOB CHALLAN , FP: FINISH PURCHASE INVOICE
S: SALES INVOICE COTTON ,SR: SALES RETURN RUBIA
GST: Grey OutWard,PR :- PURCHASE RETURN MASTER,F2G:- FINISH2GODOWN
GSR:- Grey Sales Return
	
*/
CREATE PROCEDURE [dbo].[PROC_ITEMWISESTOCKREPORT]
(
		@CMP_CODE AS NVARCHAR(100),
		@DATABASENAME AS NVARCHAR(100),
		@FROMDATE AS NVARCHAR(20),
		@TODATE AS NVARCHAR(20),
		@ITEM_ID as NVARCHAR(20)
)
AS
		DECLARE @SQL AS NVARCHAR(4000)
		DECLARE @SQL1 AS NVARCHAR(4000)
		DECLARE @SQL2 AS NVARCHAR(4000)
		DECLARE @SQL3 AS NVARCHAR(4000)
		DECLARE @SQL4 AS NVARCHAR(4000)
		DECLARE @SQL5 AS NVARCHAR(4000)
        DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
		set @SQL=""
		set @SQL1=""
		set @SQL2=""
		set @SQL3=""
		set @SQL4=""
		SET @SQL5 =""
        SET @SQL6 =""
SET @SQL7 =""
SET @SQL8 =""
SET @SQL9 =""
SET @SQL10 =""
SET @SQL11 = ""
BEGIN

	SET NOCOUNT ON;
SET @SQL="	SELECT DOCNO,DATE,ENT_TYPE, ITEM ,ITEM_ID ,ITEMGROUP,ITEM_GRP_ID,SUM(OPSTOCK) AS OPSTOCK,SUM(INQTY) AS INQTY,SUM(OUTQTY)AS OUTQYTY,FLAG,CODE
				from  (
SELECT null AS DOCNO,'' AS DATE,'OP' AS ENT_TYPE, IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,IOS.ITEM_OP_STOCK AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,'IM' AS FLAG,0 AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM 
INNER JOIN "+@DATABASENAME+" ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID 
WHERE IOS.CMP_CODE in ("+@CMP_CODE+") AND IM.ITEM_ID="+@ITEM_ID+"
UNION ALL 
SELECT SIM.DOCNO as DOCNO,SIM.VCHDATE as DATE,'OP' AS ENT_TYPE, IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.MTRS  WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.MTRS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
 ELSE  (SID.PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,'STIN' AS FLAG,SIM.STOCKINWARD_ID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" STOCKINWARD_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" STOCKINWARD_MASTER SIM ON SID.STOCKINWARD_ID=SIM.STOCKINWARD_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE SIM.CMP_CODE in ("+@CMP_CODE+") AND SIM.VCHDATE< '"+@FROMDATE+"'  AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL
			     SELECT SI.Sal_Inv_Bill_No as DOCNO,SI.Sal_Inv_Vdate as DATE,'OP' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
(0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
  ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ))AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,SI.FLAG AS FLAG,SI.SAL_INV_ID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
WHERE SI.CMP_CODE in ("+@CMP_CODE+")  AND SI.SAL_INV_VDATE< '"+@FROMDATE+"' AND IM.ITEM_ID= "+@ITEM_ID+" AND SI.FLAG NOT IN ('MS')
UNION ALL "
set @SQL1=" 
SELECT PRM.DocNo as DOCNO,PRM.Pur_Ret_Date as DATE,'OP' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
(0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN PUR_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PUR_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (PRD.PUR_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL  THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,PRM.FLAG AS FLAG,PRM.PUR_RET_ID AS FLAG
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD ON PRD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRD.PUR_RET_ID=PRM.PUR_RET_ID AND PRM.FLAG = PRD.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
WHERE PRM.CMP_CODE in ("+@CMP_CODE+") AND PRM.PUR_RET_DATE <  '"+@FROMDATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL   
			     SELECT PI.DocNo as DOCNO,PI.VchDate as DATE,'OP' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,               
(CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
 ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS OPSTOCK 
				,0.00 AS INQTY,0.00 AS OUTQTY,PI.FLAG AS FLAG,PI.PURCHASEINVID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID ON PID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
 WHERE PI.CMP_CODE in ("+@CMP_CODE+") AND PI.FLAG!='JP' AND PI.VCHDATE <  '"+@FROMDATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL "  
/*SELECT F2G.BATCH_NO AS DOCNO,F2G.VchDate AS DATE,'OP' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,(FTGI.METER)  AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,'F2G' AS FLAG,F2G.FTGID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM 
INNER JOIN "+@DATABASENAME+" FTGITEMDETAIL FTGI ON IM.ITEM_ID=FTGI.ITEM_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" FINISH2GODOWN F2G ON F2G.FTGID=FTGI.FTGID 
WHERE F2G.CMP_CODE in ("+@CMP_CODE+") AND FTGI.YEARFLAG='C' AND FTGI.ITEMDATE< '"+@FROMDATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL " */
set @SQL2=" 
SELECT SRM.DocNo AS DOCNO,SRM.Sal_Ret_Date AS DATE, 'OP' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SAL_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SAL_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) 
ELSE  (SAL_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS OPSTOCK
,0.00 AS INQTY,0.00 AS OUTQTY,SRM.FLAG AS FLAG,SRM.SAL_RET_ID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" SALES_RETURN_DETAIL SRD ON SRD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SALES_RETURN_MASTER SRM ON SRD.SAL_RET_ID=SRM.SAL_RET_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE SRM.CMP_CODE in ("+@CMP_CODE+") AND SRM.SAL_RET_DATE < '"+@FROMDATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL   
			    SELECT PI.DocNo AS DOCNO,PI.VchDate AS DATE,'P' AS ENT_TYPE, IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK ,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )  AS  INQTY,0.00 AS OUTQTY
,PI.FLAG AS FLAG,PI.PURCHASEINVID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID ON PID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
 WHERE PI.CMP_CODE in ("+@CMP_CODE+") AND PI.FLAG!='JP' AND PI.VCHDATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"	
UNION ALL   
SELECT SIM.DocNo AS DOCNO,SIM.VchDate AS DATE,'PRO' AS ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK, 
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.MTRS  WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.MTRS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) 
ELSE  (SID.PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )  AS INQTY,0.00 AS OUTQTY
,'STIN' AS FLAG,SIM.STOCKINWARD_ID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" STOCKINWARD_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" STOCKINWARD_MASTER SIM ON SID.STOCKINWARD_ID=SIM.STOCKINWARD_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE SIM.CMP_CODE in ("+@CMP_CODE+") AND SIM.VCHDATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"	
UNION ALL   "
set @SQL3=" 
/*
SELECT F2G.BATCH_NO AS DOCNO,F2G.VchDate AS DATE,'PRO' as ENT_TYPE ,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,0 AS OPSTOCK
,FTGI.METER AS INQTY,0.00 AS OUTQTY,'F2G' AS FLAG,F2G.FTGID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM 
INNER JOIN "+@DATABASENAME+" FTGITEMDETAIL FTGI ON IM.ITEM_ID=FTGI.ITEM_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" FINISH2GODOWN F2G ON F2G.FTGID=FTGI.FTGID
WHERE F2G.CMP_CODE in ("+@CMP_CODE+") AND FTGI.YEARFLAG='C' AND FTGI.ITEMDATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL   */
				SELECT  SRM.DocNo AS DOCNO,SRM.Sal_Ret_Date AS DATE,'SR' as ENT_TYPE, IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK,             
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SAL_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SAL_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (SAL_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS INQTY,0.00 AS OUTQTY
,SRM.FLAG AS FLAG,SRM.SAL_RET_ID AS CODE
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" SALES_RETURN_DETAIL SRD ON SRD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SALES_RETURN_MASTER SRM ON SRD.SAL_RET_ID=SRM.SAL_RET_ID
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE SRM.CMP_CODE in ("+@CMP_CODE+") AND SRM.SAL_RET_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' 
				AND IM.ITEM_ID= "+@ITEM_ID+"
UNION ALL   
SELECT SI.Sal_Inv_Bill_No AS DOCNO,SI.Sal_Inv_Vdate as DATE,'SA' as ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK ,0.00 AS INQTY  ,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS OUTQTY              
,SI.FLAG AS  FLAG,SI.SAL_INV_ID AS CODE 
FROM "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE SI.CMP_CODE in ("+@CMP_CODE+") AND SI.SAL_INV_VDATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"'
AND SI.FLAG NOT IN ('MS') AND IM.ITEM_ID= "+@ITEM_ID+" 
UNION ALL    "
set @SQL4=" 
SELECT PRM.DocNo AS DOCNO,PRM.Pur_Ret_Date AS DATE,'PR' as ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK,0.00 AS INQTY,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN PUR_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PUR_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) 
 ELSE  (PRD.PUR_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) as OUTQTY 
,PRM.FLAG AS FLAG,PRM.PUR_RET_ID AS CODE
FROM "+@DATABASENAME+"ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD ON PRD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRD.PUR_RET_ID=PRM.PUR_RET_ID AND PRM.FLAG = PRD.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE PRM.CMP_CODE in ("+@CMP_CODE+") AND PRM.PUR_RET_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' 
AND IM.ITEM_ID= "+@ITEM_ID+"               

/*

SELECT GJM.BATCH_NO AS DOCNO,GJM.VchDate AS DATE,'I2P' as ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
0 AS OPSTOCK,0.00 AS INQTY ,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN GJD.METER   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (GJD.METER  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (GJD.THAN * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) as OUTQTY
,'GJC' AS FLAG,GJM.GRAYJOBCHALLAN_ID AS CODE
FROM  "+@DATABASENAME+" ITEM_MASTER IM
INNER JOIN "+@DATABASENAME+"GrayJobChallan_Detail GJD ON GJD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"GrayJobChallan_Master GJM ON GJM.GrayJobChallan_Id=GJD.GrayJobChallan_Id
INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
WHERE GJM.PROCESS_ID=1 AND GJM.CMP_CODE in ("+@CMP_CODE+") AND GJM.VCHDATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"'  
AND IM.ITEM_ID= "+@ITEM_ID+"   
UNION ALL 
SELECT GJM.BATCH_NO AS DOCNO,GJM.VchDate AS DATE,'OP' as ENT_TYPE,IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
(0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN GJD.METER   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (GJD.METER  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
 ELSE  (GJD.THAN * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ))  AS OPSTOCK
