SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- AUTHOR:		<AUTHOR,,NAME>
-- ALTER_DATE: 14/JULY/2012
-- DESCRIPTION:	PRINT OUT OF JOB CHALLAN MASTER
-- =============================================
PROC_JOB_CHALLAN_PRINT_OUT '1','ACC2013_2014.DBO.','1','10'
*/
CREATE PROCEDURE [dbo].[PROC_JOB_CHALLAN_PRINT_OUT]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(20),
@FROMNO NVARCHAR(10),
@TONO NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""


BEGIN
SET NOCOUNT ON;
SET @SQL="
SELECT JM.DOCNO,JM.VCHDATE,JM.CHALLANNO,JM.CHALLAN_DATE,JM.CHEQUENO,JM.CHEQUE_DATE,JM.BSRCODE,
JM.BRANCH_NAME,START_DATE,JM.END_DATE,TDM.TDS_NAME,LM.LGR_NAME,PCM.CITY_NAME AS PARTYCITY,
JD.BILLNO,JD.FLAG,JD.BILLDATE,JD.BILL_AMT,JD.TDS_PER,JD.TDS_AMOUNT,ISNULL(LM.LGR_PANO,'') AS LGR_PANO,
ISNULL(COMP.CMP_PAN_NO,'') AS CMP_PAN_NO,ISNULL(COMP.CMP_TDS_NO,'') AS CMP_TDS_NO
FROM "+@DATABASENAME+"JOBCHALLAN_MASTER JM
INNER JOIN "+@DATABASENAME+"JOBCHALLAN_DETAIL JD ON JM.JOBCHALLAN_ID=JD.JOBCHALLAN_ID
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TDM ON JM.TDS_ID=TDM.TDS_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON JD.LGR_ID=LM.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE=JM.CMP_CODE
WHERE JM.CMP_CODE IN ("+@CMP_CODE+") AND JM.DOCNO BETWEEN "+@FROMNO+" AND "+@TONO+"
ORDER BY JM.DOCNO,JD.SRNO
"

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















