/*
PROC_JOB_CHARGES 2,'Acc2010_2011.dbo.','01/apr/2010','31/Mar/2011','##1536',2
*/
CREATE PROCEDURE [dbo].[PROC_JOB_CHARGES]
(
@CMP_CODE nvarchar(50),
@DATABASENAME nvarchar(50),
@FROMDATE nvarchar(50),
@ToDate nvarchar(50),
@TEMPTABLE nvarchar(50),
@RPT_WISE int
)
AS
declare @STR nvarchar(4000) set @STR=""
declare @JOIN nvarchar(4000) set @JOIN=""


BEGIN 
	if @RPT_WISE=1 
		SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=LM.Lgr_Id "
	else if @RPT_WISE=2
		SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=IM.ITEM_ID "
	ELSE IF @RPT_WISE=3
		SET @JOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=JC.JobCharges_Id"

END

BEGIN

	SET NOCOUNT ON;
SET @STR="
select JC.DOCNO,JD.DOCNO as DetailDocNo,jd.doc_date VCHDATE,JD.TAKA,JD.METER,JD.LESS_METER,JD.TOTALMETER,JD.RATE,JD.AMOUNT,
LESS_HAMALI,NET_AMOUNT,JD.AVG,IM.Item_Name,LM.Lgr_name as PartyName
from  "+@DATABASENAME+" Job_Charges JC
inner join  "+@DATABASENAME+" Job_ChargesDetail JD on JC.JobCharges_Id=JD.JobCHarges_Id
inner join "+@DATABASENAME+" Item_Master IM on IM.Item_Id=JD.Item_Id
inner join "+@DATABASENAME+" Ledger_Master LM on LM.Lgr_Id=JC.Lgr_Id

"+@JOIN+"
where VchDate between '"+@FROMDATE+"' and '"+@ToDate+"'
and JC.Cmp_Code in ("+@CMP_CODE+")
order by DocNo,srno
"


END
print @STR
execute Sp_ExecuteSql @STR




















