/*    
PROC_JOB_SALESREG_DAILY_MONTHLY '1','ACC2017_2018.DBO.','01/APR/2017','30/DEC/2018',7
*/
CREATE PROCEDURE [dbo].[PROC_JOB_SALESREG_DAILY_MONTHLY]
(
   @Cmp_Code NVARCHAR(50),
   @DatabaseName NVARCHAR(100),
   @FromDate NVARCHAR(20),
   @ToDate NVARCHAR(20),
   @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE @QUANTITYSQL1 AS NVARCHAR(4000)
SET @SQL=""
SET @QUANTITYSQL=""
SET @QUANTITYSQL1=""


BEGIN
	SET NOCOUNT ON;    

       IF @RPT_WISE=6
          BEGIN  
              SET @SQL="SELECT 'JANUARY' AS MONTHNAME,DATE,SUM(QTY)AS QUANTITY,SUM(PCS)AS PIECE,SUM(NETAMT)AS NETTOTAL,ORD,MIN(CMP_ALIAS)AS CMP_ALIAS,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,SUM(TAXABLE)AS TAXABLE,
			 SUM(ROFF)AS ROFF,SUM(GSTAMT)AS GSTAMT FROM (SELECT UPPER(DATENAME(MM,JSM.BILL_DATE))AS MONTHNAME,JSM.JOB_SAL_INV_ID,JSM.JOB_SAL_INV_BILL_NO AS BILLNO,
			JSM.BILL_DATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			ISNULL(JSM.TOTAL,0) AS GROSSTOTAL,ISNULL(JSM.SAL_INV_ADD3,0)AS CGST,ISNULL(JSM.SAL_INV_ADD4,0)AS SGST,ISNULL(JSM.SAL_INV_ADD5,0)AS IGST,(JSM.NETAMT - ISNULL(JSM.LESSTOTAL,0) + (ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))TAXABLE,
			(ISNULL(SAL_INV_ADD3,0)+ISNULL(SAL_INV_ADD4,0)+ isnull(SAL_INV_ADD5 ,0))AS GSTAMT,
			ISNULL(JSM.ADDTOTAL,0) AS ADDTOTAL,ISNULL(JSM.DISAMT,0) AS DISAMT,ISNULL(JSM.ROFF,0) AS ROFF,
			ISNULL(JSM.NETAMT,0) AS NETAMT,CMP.CMP_ALIAS,QTY_TOTAL QTY,THAN_TOTAL PCS,
			(CASE WHEN DATEPART(M,JSM.BILL_DATE)<=3 THEN  (DATEPART(M,JSM.BILL_DATE)+12)ELSE DATEPART(M,JSM.BILL_DATE) END) AS ORD
			FROM "+@DATABASENAME+" JOB_SALESINVOICE_MASTER JSM
			INNER JOIN "+@DATABASENAME+"JOB_SALESINVOICE_DETAIL JSD ON JSD.JOB_SAL_INV_ID=JSM.JOB_SAL_INV_ID AND JSD.CMP_CODE=JSM.CMP_CODE AND JSM.FORM_FLAG=JSD.FORM_FLAG
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = JSM.LGR_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = JSM.AGENT_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE = JSM.CMP_CODE
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=JSD.ITEM_ID 
			WHERE JSM.CMP_CODE IN ( "+@CMP_CODE+" ) AND JSM.JOB_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
			AND JSM.FORM_FLAG = 'JS') as detail GROUP BY MONTHNAME,DATE,ORD ORDER BY ORD"
          END
     ELSE IF @RPT_WISE=	7
             SET @SQL="SELECT MONTHNAME,GETDATE() AS DATE,SUM(QTY)AS QUANTITY,SUM(PCS)AS PIECE,SUM(NETAMT)AS NETTOTAL,ORD,MIN(CMP_ALIAS)AS CMP_ALIAS,SUM(CGST)CGST,SUM(SGST)SGST,SUM(IGST)IGST,SUM(TAXABLE)AS TAXABLE,
			 SUM(ROFF)AS ROFF,SUM(GSTAMT)AS GSTAMT FROM (SELECT UPPER(DATENAME(MM,JSM.BILL_DATE))AS MONTHNAME,JSM.JOB_SAL_INV_ID,JSM.JOB_SAL_INV_BILL_NO AS BILLNO,
			JSM.BILL_DATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			ISNULL(JSM.TOTAL,0) AS GROSSTOTAL,ISNULL(JSM.SAL_INV_ADD3,0)AS CGST,ISNULL(JSM.SAL_INV_ADD4,0)AS SGST,ISNULL(JSM.SAL_INV_ADD5,0)AS IGST,(JSM.NETAMT - ISNULL(JSM.LESSTOTAL,0) + (ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))TAXABLE,
			(ISNULL(SAL_INV_ADD3,0)+ISNULL(SAL_INV_ADD4,0)+ isnull(SAL_INV_ADD5 ,0))AS GSTAMT,
			ISNULL(JSM.ADDTOTAL,0) AS ADDTOTAL,ISNULL(JSM.DISAMT,0) AS DISAMT,ISNULL(JSM.ROFF,0) AS ROFF,
			ISNULL(JSM.NETAMT,0) AS NETAMT,CMP.CMP_ALIAS,QTY_TOTAL QTY,THAN_TOTAL PCS,
			(CASE WHEN DATEPART(M,JSM.BILL_DATE)<=3 THEN  (DATEPART(M,JSM.BILL_DATE)+12)ELSE DATEPART(M,JSM.BILL_DATE) END) AS ORD
			FROM "+@DATABASENAME+" JOB_SALESINVOICE_MASTER JSM
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = JSM.LGR_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = JSM.AGENT_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE = JSM.CMP_CODE
			WHERE JSM.CMP_CODE IN ( "+@CMP_CODE+" ) AND JSM.JOB_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
			AND JSM.FORM_FLAG = 'JS') as detail GROUP BY MONTHNAME,ORD ORDER BY ORD
			"
	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL



































































































GO

