/* 
PROC_JOBCARD '10','ACC2010_2011.DBO.',''
*/
CREATE PROCEDURE [dbo].[PROC_JOBCARD]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(50), 
  @TEMPTABLE AS NVARCHAR(50) ,
  @RPT_WISE AS INT
 )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""

BEGIN 
   IF @RPT_WISE =1 
      SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LA.LOTNO"
   ELSE IF @RPT_WISE =2 
      SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
END 
BEGIN	
 SET @SQL=" SELECT LA.LOTNO,IM.ITEM_NAME AS ITEM,LM.LGR_NAME,WM.WEAVER_NAME AS VIEWER,WM.TOKENNO ,LA.VCHDATE,LA.TOTALTHAN,LA.TOTALMETER,F2G.TotalRecThan AS FINISHTHAN,F2G.TotalRecMeter AS FINISHMETER,F2G.TotalShMeter AS SHORTMTR,F2G.TotalSh_Per AS SHORTMTR_PER,
            PM.PROCESS_NAME,P2P.VCHDATE AS JOBDATE,P2P.DELTHAN PIECES,P2P.DELMETER AS METER,P2P.GPASSNO,P2P.PARTYGPASSNO,'' AS UNIT,0 AS FTGMETER,0  AS PER,0 AS KG,0 AS MTR_KG
            ,1 AS DETAIL,CMP.CMP_ALIAS
            FROM "+@DATABASENAME+"LOTALLOCATION LA
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID
            INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=LA.WEAVER_ID
            INNER JOIN "+@DATABASENAME+"PROCESS2PROCESS P2P ON P2P.LOTNO=LA.LOTNO AND P2P.CMP_CODE=LA.CMP_CODE
            INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID 
            INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID
            INNER JOIN "+@DATABASENAME+"FINISH2GODOWN F2G ON F2G.LOTNO=LA.LOTNO AND F2G.CMP_CODE=LA.CMP_CODE
            INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LA.CMP_CODE
            "+@JOINSQL+"
            WHERE LA.CMP_CODE IN ("+@CMP_CODE+") 
UNION ALL
            "

SET @SQL1="
            SELECT F2F.LOTNO,IM.ITEM_NAME AS ITEM,'' AS PARTY,'' AS VIEWER,'' AS TOKENNO,F2F.VCHDATE,F2F.DLRDTHAN AS TOTALTAN,F2F.DLRDMTRS AS TOTALMETER,0 AS FINISHTHAN,0 AS FINISHMETER,0 AS SHORTMTR,0 AS SHORTMTR_PER,
            PM.PROCESS_NAME,NULL AS JOBDATE,0 AS PRO_PEICES,0 AS PRO_MTRS,F2F.DOCNO AS GPASSNO,0 AS PARTYGPASSNO ,'' AS UNIT,0 AS METER,0  AS PER,0 AS KG,0 AS MTR_KG
            ,2 AS DETAIL,CMP.CMP_ALIAS
            FROM "+@DATABASENAME+"FINISHTOFOLDING F2F
            INNER JOIN "+@DATABASENAME+"LOTALLOCATION LA ON LA.LOTNO=F2F.LOTNO  AND LA.CMP_CODE=F2F.CMP_CODE
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=F2F.ITEM_ID
            INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=F2F.PROCESS_ID
            INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=F2F.CMP_CODE
             "+@JOINSQL+"
            WHERE F2F.CMP_CODE IN ("+@CMP_CODE+") 
          UNION ALL 
 "
SET @SQL2=" SELECT FTGI.LOTNO,IM.ITEM_NAME AS ITEM,'' AS PRTY,'' AS VIEWER,'' AS TOKENNO,FTGI.ITEMDATE AS VCHDATE,0 AS TOTALTAN,0 AS TOTALMETER,0 AS FINISHTHAN,0 AS FINISHMETER,0 AS SHORTMTR,0 AS SHORTMTR_PER
            ,'' AS PROCESS_NAME,NULL AS JOBDATE,0 AS PRO_PEICES,0 AS PRO_MTRS,0 AS GPASSNO,0 AS PARTYGPASSNO 
            ,UM.UNIT_NAME,FTGI.METER,FTGI.PERCENTAGE,FTGI.KG,FTGI.MTR_KG,3 AS DETAIL,CMP.CMP_ALIAS
            FROM "+@DATABASENAME+"FTGITEMDETAIL FTGI
            INNER JOIN "+@DATABASENAME+"LOTALLOCATION LA ON LA.LOTNO=FTGI.LOTNO  AND LA.CMP_CODE=FTGI.CMP_CODE
            INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTGI.ITEM_ID
            INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=FTGI.UNIT_ID
            INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=FTGI.CMP_CODE
            "+@JOINSQL+"
            WHERE FTGI.CMP_CODE IN ("+@CMP_CODE+") 
           "

END
EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

