			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise IN (3)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,PM.PROCESS_NAME,PM.PROCESS_ID,"
