	ELSE IF @RptWise IN (5)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.LOT_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LOM.LOT_NAME,LOM.LOT_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (6)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise = 7
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (8)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,LOM.LOT_NAME,LOM.LOT_ID,"
		END
	ELSE IF @RptWise IN (9)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,PM.PROCESS_NAME,PM.PROCESS_ID,"
		END
	ELSE IF @RptWise IN (10)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.PROCESS_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  PM.PROCESS_NAME,PM.PROCESS_ID,"
		END
	ELSE IF @RptWise IN (11)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.PROCESS_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  PM.PROCESS_NAME,PM.PROCESS_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
		ELSE IF @RptWise IN (12)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.DOCNO=" + @TempTable + ".CODE"
			SET @STRORDERBY=" "
		END
		ELSE IF @RptWise IN (13)
		BEGIN
		    SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
		    SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,"
		END
		ELSE IF @RptWise IN (14)
		BEGIN
		    SET @SELECTED="INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
		    SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
		ELSE IF @RptWise IN (15)
		BEGIN
		    SET @SELECTED="INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
		    SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,LOM.LOT_NAME,LOM.LOT_ID,"
        END

SET NOCOUNT ON;
SET @ISSUE="
        SELECT (DOCNO)as Docno,MAX(DATE) AS Date,LGR_NAME,LGR_ID,max(CHALLANNO) as ChallanNo,MAX(LOT_ID) as LotId,MAX(MARKA) as MARKA,MAX(ITEM_ID) as ItemId,MAX(ITEM_NAME) as ItemName,MAX(HSN_ID) as HsnId,MAX(HSN_NAME) as HsnName,PROCESS_NAME,PROCESS_ID,SUM(RECQTY) AS RECQTY,SUM(ISSUEQTY) AS ISSUEQTY,max(SRNO) as SRNO,MAX(FTPARTY) as FTPARTY,MAX(UNITNAME) AS UNITNAME,(SUM(RECQTY)-SUM(ISSUEQTY))AS PENDINGQTY
        FROM(
    	SELECT PI.DOCNO,PI.VCHDATE DATE,LM.LGR_NAME,LM.LGR_ID,CHALLANNO,LOM.LOT_ID,
    	LOM.LOT_NAME AS MARKA,IM.ITEM_ID,IM.ITEM_NAME,HM.HSN_ID,HM.HSN_NAME,PM.PROCESS_NAME,PM.PROCESS_ID,PID.QTY AS RECQTY,0 AS ISSUEQTY,PID.SRNO,FLM.LGR_NAME AS FTPARTY,ULM.LGR_NAME AS UNITNAME
		FROM "+ @DATABASENAME+ "JOBGOODSRECEIPT PI
		INNER JOIN  "+ @DATABASENAME +"JOBGOODSRECEIPT_DETAIL PID ON PID.JOBGOODSREC_ID=PI.JOBGOODSREC_ID 
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
		INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
		LEFT  JOIN " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=PID.HSN_ID
		LEFT  JOIN " + @DATABASENAME +"LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
		LEFT  JOIN " + @DATABASENAME +"PROCESS_MASTER PM ON PI.PROCESS_ID=PM.PROCESS_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PI.CMP_CODE= CMP.CMP_CODE 
		LEFT  JOIN " + @DATABASENAME +"LEDGER_MASTER FLM ON PI.FRLGR_ID=FLM.LGR_ID 
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER ULM ON PI.LGR_ID=ULM.LGR_ID    
		"+@SELECTED+"
		
		WHERE PI.CMP_CODE="+ @CMP_CODE +" AND PI.VchDate <= '" + @ToDate + "'
		UNION ALL"
		  
SET @ISSUE1 = " SELECT PID.CHALLNNO,PI.VCHDATE DATE,LM.LGR_NAME,LM.LGR_ID,CHALLANNO,LOM.LOT_ID,
    	LOM.LOT_NAME AS MARKA,IM.ITEM_ID,IM.ITEM_NAME,HM.HSN_ID,HM.HSN_NAME,PM.PROCESS_NAME,PM.PROCESS_ID,0 AS RECQTY,PID.QTY AS ISSUEQTY,PID.SRNO,FLM.LGR_NAME AS FTPARTY,ULM.LGR_NAME AS UNITNAME
		FROM "+ @DATABASENAME+ "JOBGOODSISSUE PI
		INNER JOIN  "+ @DATABASENAME +"JOBGOODSISSUE_DETAIL PID ON PID.JOBGOODSISSUE_ID=PI.JOBGOODSISSUE_ID 
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
		INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
		LEFT  JOIN " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=PID.HSN_ID
		LEFT  JOIN " + @DATABASENAME +"LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
		LEFT  JOIN " + @DATABASENAME +"PROCESS_MASTER PM ON PI.PROCESS_ID=PM.PROCESS_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PI.CMP_CODE= CMP.CMP_CODE
		LEFT  JOIN " + @DATABASENAME +"LEDGER_MASTER FLM ON PI.ToLgr_Id=FLM.LGR_ID   
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER ULM ON PI.LGR_ID=ULM.LGR_ID       
		"+@SELECTED+"
		WHERE PI.CMP_CODE="+ @CMP_CODE +" AND PI.VCHDATE <='" + @ToDate + "'
		 ) AS DETAIL 
		GROUP BY LGR_NAME,LGR_ID,PROCESS_ID,PROCESS_NAME,DOCNO         
  "    
END	



IF @RptType=1
	BEGIN		
		PRINT @ISSUE
		PRINT @ISSUE1
		EXEC (@ISSUE + @ISSUE1)
	END




GO

