/*    
PROC_JOBGOODSISSUE '1','2','1','ACC2020_2021.dbo.'
*/   

CREATE PROCEDURE [dbo].[PROC_JOBGOODSISSUE]
(
@FromBillNo  nvarchar(20),
@ToBillNo nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)

)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="	

 SELECT JGM.JOBGOODSISSUE_ID,JGM.DOCNO,JGM.VCHDATE,JGM.ChallanNo,ISNULL(JGM.than,0) AS THAN,JGD.NETQTY AS mtrs ,JGM.EWAYBILLNO,JGM.VEHICLENO,
 PM.PROCESS_NAME,LM.LGR_NAME,LOM.LOT_NAME,IM.ITEM_NAME,HSN.HSN_NAME,CTM.CITY_NAME,COM.GSTINNO AS CMPGSTINNO,ISNULL(CMP_STATECODE,'') AS CMP_STATECODE,
 ISNULL(LM.LGR_ADD1, '') AS LGR_ADD1,ISNULL(LM.LGR_ADD2, '') AS LGR_ADD2,ISNULL(LM.LGR_ADD3, '') AS LGR_ADD3 , LM.GSTINNO AS LMGSTNO,
 ISNULL(JGM.NARRATION,'') AS NARRATION , ISNULL(JGD.REMARK,'')REMARK,TLM.LGR_NAME AS TOPARTY,TCTM.CITY_NAME AS TOCITY,
 ISNULL(TLM.LGR_ADD1, '') AS TLGR_ADD1,ISNULL(TLM.LGR_ADD2, '') AS TLGR_ADD2,ISNULL(TLM.LGR_ADD3, '') AS TLGR_ADD3 , TLM.GSTINNO AS TLMGSTNO, ISNULL(JGD.RATE,0) AS RATE , ISNULL(JGD.AMOUNT,0) AS AMOUNT,JGD.CHALLNNO AS RECCHALLANNO
 FROM "+ @DatabaseName +"JOBGOODSISSUE JGM
 INNER JOIN "+ @DatabaseName +"JOBGOODSISSUE_DETAIL JGD ON JGM.JOBGOODSISSUE_ID  = JGD.JOBGOODSISSUE_ID
 INNER JOIN "+ @DatabaseName +"PROCESS_MASTER PM ON JGM.PROCESS_ID  = PM.PROCESS_ID  
 INNER JOIN "+ @DatabaseName +"LEDGER_MASTER LM ON JGM.LGR_ID = LM.LGR_ID
 INNER JOIN "+ @DatabaseName +"LEDGER_MASTER TLM ON JGM.TOLGR_ID = TLM.LGR_ID
 INNER JOIN "+ @DatabaseName +"LOT_MASTER LOM ON JGD.LOT_ID = LOM.LOT_ID
 INNER JOIN "+ @DatabaseName +"ITEM_MASTER IM ON JGD.ITEM_ID = IM.ITEM_ID
 INNER JOIN "+ @DatabaseName +"HSN_MASTER HSN ON JGD.HSN_ID = HSN.HSN_ID
 INNER JOIN "+ @DatabaseName +"COMPANY_MASTER COM ON JGM.CMP_CODE = COM.CMP_CODE
 LEFT JOIN  "+ @DatabaseName +"CITY_MASTER CTM ON JGM.CITY_ID = CTM.CITY_ID
 LEFT JOIN  "+ @DatabaseName +"CITY_MASTER TCTM ON TLM.CITY_ID = TCTM.CITY_ID
 WHERE JGM.Cmp_Code="+ @Cmp_Code +" and  JGM.DOCNO BETWEEN '" + @FromBillNo + "' and '" + @ToBillNo + "'
 ORDER BY CONVERT(INT,JGM.DOCNO)
 
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






















GO

