/*
-- =============================================
-- Author:		HIREN DOSHI
-- Create_date: 20/05/2013
-- Description:	THIS PROCEDURE USED FOR JOB SALES INVOICE MANUAL DATA
-- ReportName : JOBGREYSALESINV_MANUAL_PRINT.RPT
-- =============================================
PROC_JOBGREYSALESINV_MANUAL_PRINT 1,'ACC2020_2021.DBO.',1,4,'JS'
*/
CREATE PROCEDURE [dbo].[PROC_JOBGREYSALESINV_MANUAL_PRINT]
(
       @CMP_CODE AS NVARCHAR(50),
       @DATABASENAME AS NVARCHAR(20),
       @FROMDOCNO AS NVARCHAR(20),
       @TODOCNO AS NVARCHAR(20),
	   @TYPE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""

BEGIN
	SET NOCOUNT ON;
	SET @SQL = " SELECT PARTY,PARTYCITY,CITYPINCODE,CMP_TIN_NO,CMP_PAN_NO,INVOICENO,INVOICEDATE,BILLDATE,LRDATE,
LOTNO,UNIT,THAN,CUT,QTY,RATE,AMOUNT,ADDTOTAL,DISPER,DISAMT,CMP_TIN_NO,CMP_PAN_NO,CMP_PHONE1,
CMP_PHONE2,CMP_MOBILE,CMP_FAX,CMP_EMAIL,ROFF,NETAMT,LGR_ADD1,LGR_ADD2,LGR_DISTRICT,CITY_PINCODE,PARTYSTATE
,ITEM_NAME,CMP_BANK_ACCNO1,CMP_BANK_ACCNO2,NARRATION,LR_NO,THAN_TOTAL,QTY_TOTAL,AGENT,AGENTCITY,EWAYBILLNO,EINVNO,TCS_PER,TCS_AMT FROM (
SELECT JSM.JOB_SAL_INV_BILL_NO AS BILLNO,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.CITY_PINCODE AS CITYPINCODE,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,
JSM.JOB_SAL_INV_BILL_NO AS INVOICENO,CONVERT(NVARCHAR,JSM.JOB_SAL_INV_VDATE,103) AS INVOICEDATE,
CONVERT(NVARCHAR,JSM.BILL_DATE,103) AS BILLDATE,CONVERT(NVARCHAR,JSM.LR_DATE,103) AS LRDATE,JSD.LOTNO,
UM.UNIT_NAME AS UNIT,JSD.THAN,JSD.CUT,JSD.QTY,JSD.RATE,JSD.AMOUNT,JSM.ADDTOTAL,JSM.DISPER,JSM.DISAMT,CMP.CMP_PHONE1,
CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_FAX,CMP.CMP_EMAIL,JSM.ROFF,JSM.NETAMT,
LM.LGR_ADD1,(LM.LGR_ADD2 + ISNULL(',' + LM.LGR_ADD3,'')) AS LGR_ADD2,LM.LGR_DISTRICT,LM.CITY_PINCODE,PSM.STATE_NAME AS PARTYSTATE
,IM.ITEM_NAME,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,JSD.NARRATION,JSM.LR_NO,
ISNULL(JSM.THAN_TOTAL,0) AS THAN_TOTAL,ISNULL(JSM.QTY_TOTAL,0) AS QTY_TOTAL,
ISNULL(ALM.Lgr_name,'')AGENT,ISNULL(ACM.City_Name,'')AGENTCITY,JSM.EWAYBILLNO,JSM.EINVNO,JSM.TCS_PER,JSM.TCS_AMT
FROM "+@DATABASENAME+" JOB_SALESINVOICE_MASTER JSM
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = JSM.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
INNER JOIN "+@DATABASENAME+" JOB_SALESINVOICE_DETAIL JSD ON JSD.JOB_SAL_INV_ID = JSM.JOB_SAL_INV_ID AND JSM.FORM_FLAG = JSD.FORM_FLAG
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = JSM.CMP_CODE
LEFT JOIN "+@DATABASENAME+" STATE_MASTER PSM ON LM.STATE_ID = PSM.STATE_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=JSD.ITEM_ID
LEFT JOIN "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID = JSM.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID

WHERE JSM.CMP_CODE IN ("+@CMP_CODE+") 
AND JSM.JOB_SAL_INV_BILL_NO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
AND JSM.FORM_FLAG='"+@TYPE+"'
) AS A
ORDER BY INVOICENO,INVOICEDATE,LOTNO  "
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL





















GO

