PROC_JOBGREYSALESINV_MANUAL_PRINT_GST 1,'ACC2020_2021.DBO.',1,4,'JS'
*/
CREATE PROCEDURE [dbo].[PROC_JOBGREYSALESINV_MANUAL_PRINT_GST]
(
       @CMP_CODE AS NVARCHAR(50),
       @DATABASENAME AS NVARCHAR(20),
       @FROMDOCNO AS NVARCHAR(20),
       @TODOCNO AS NVARCHAR(20),
	   @TYPE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
DECLARE @SQL1 AS NVARCHAR(4000)
SET @SQL1=""

BEGIN
	SET NOCOUNT ON;
	SET @SQL = " SELECT PARTY,PARTYCITY,CITYPINCODE,CMP_TIN_NO,CMP_PAN_NO,INVOICENO,INVOICEDATE,BILLDATE,LRDATE,
LOTNO,UNIT,THAN,CUT,QTY,RATE,AMOUNT,ADDTOTAL,DISPER,DISAMT,CMP_TIN_NO,CMP_PAN_NO,CMP_PHONE1,
CMP_PHONE2,CMP_MOBILE,CMP_FAX,CMP_EMAIL,ROFF,NETAMT,LGR_ADD1,LGR_ADD2,LGR_DISTRICT,CITY_PINCODE,PARTYSTATE
,ITEM_NAME,CMP_BANK_ACCNO1,CMP_BANK_ACCNO2,NARRATION,LR_NO,THAN_TOTAL,QTY_TOTAL,Total,SAL_INV_ADD1,SAL_INV_ADD2
,SAL_INV_ADD3,SAL_INV_ADD4,SAL_INV_ADD5,SAL_INV_LESS1,SAL_INV_LESS2,SAL_INV_LESS3,SAL_INV_LESS4,SAL_INV_LESS5,ADDPER1,ADDPER2,ADDPER3,ADDPER4,ADDPER5,LESSPER1,LESSPER2,LESSPER3
,LESSPER4,LESSPER5,CGSTINNO,LGSTINNO,HSN_NAME ,ADDBEFOREVALUE,TAXABLEAMT,LESSTOTAL,CONSIGNEENAME, CONSIGNEE_ADD1,CONSIGNEE_ADD2, CONSIGNEE_ADD3,CONSIGNEE_CITY, CONSIGNEE_STATE, CONSIGNEE_STATECODE,CONSIGNEE_GSTNO,  consingee_phone,CONSINGEE_MOBILE,CONSIGNEE_COUNTRY,CONSIGNEE_PINCODE,CONSIGNEE_DISTRICT,LGR_STATECODE,CMP_STATECODE,ALIAS,TRANSPORT_NAME,REMARK,EWAYBILLNO,
 EWAYBILLDTAE,EINVNO,TCS_PER,TCS_AMT,IRN,ACK_DATE FROM (
SELECT JSM.JOB_SAL_INV_BILL_NO AS BILLNO,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.CITY_PINCODE AS CITYPINCODE,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,
JSM.JOB_SAL_INV_BILL_NO AS INVOICENO,CONVERT(NVARCHAR,JSM.JOB_SAL_INV_VDATE,103) AS INVOICEDATE,
CONVERT(NVARCHAR,JSM.BILL_DATE,103) AS BILLDATE,CONVERT(NVARCHAR,JSM.LR_DATE,103) AS LRDATE,JSD.LOTNO,
UM.UNIT_NAME AS UNIT,JSD.THAN,JSD.CUT,JSD.QTY,JSD.RATE,JSD.AMOUNT,JSM.ADDTOTAL,JSM.DISPER,JSM.DISAMT,CMP.CMP_PHONE1,
CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_FAX,CMP.CMP_EMAIL,JSM.ROFF,JSM.NETAMT,
LM.LGR_ADD1,(LM.LGR_ADD2 + ISNULL(',' + LM.LGR_ADD3,'')) AS LGR_ADD2,LM.LGR_DISTRICT,LM.CITY_PINCODE,PSM.STATE_NAME AS PARTYSTATE
,IM.ITEM_NAME,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,JSD.NARRATION,JSM.LR_NO,
ISNULL(JSM.THAN_TOTAL,0) AS THAN_TOTAL,ISNULL(JSM.QTY_TOTAL,0) AS QTY_TOTAL,JSM.Total,JSM.SAL_INV_ADD1,JSM.SAL_INV_ADD2,JSM.SAL_INV_ADD3,JSM.SAL_INV_ADD4,JSM.SAL_INV_ADD5,JSM.SAL_INV_LESS1,JSM.SAL_INV_LESS2,JSM.SAL_INV_LESS3,JSM.SAL_INV_LESS4,JSM.SAL_INV_LESS5,JSM.SAL_INV_ADD1_SET AS ADDPER1,JSM.SAL_INV_ADD2_SET AS ADDPER2,
JSM.SAL_INV_ADD3_SET AS ADDPER3,JSM.SAL_INV_ADD4_SET AS ADDPER4,JSM.SAL_INV_ADD5_SET AS ADDPER5,JSM.SAL_INV_LESS1_SET AS LESSPER1,JSM.SAL_INV_LESS2_SET AS LESSPER2,JSM.SAL_INV_LESS3_SET AS LESSPER3
,JSM.SAL_INV_LESS4_SET AS LESSPER4,JSM.SAL_INV_LESS5_SET AS LESSPER5,CMP.GSTINNO AS CGSTINNO,LM.GSTINNO AS LGSTINNO,
ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
HSN.HSN_NAME,(JSM.SAL_INV_ADD1+JSM.SAL_INV_ADD2)as ADDBEFOREVALUE ,(JSM.Total-JSM.LESSTOTAL+(JSM.SAL_INV_ADD1+JSM.SAL_INV_ADD2)) AS TAXABLEAMT,JSM.LESSTOTAL,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,CONVERT(NVARCHAR,CMM.PINCODE) AS CONSIGNEE_PINCODE,CMM.DISTRICT AS CONSIGNEE_DISTRICT,
PSM.STATE_CODE AS LGR_STATECODE,CMP.CMP_STATECODE,JSM.SALES_ALIAS AS ALIAS,TM.TRANSPORT_NAME,JSM.REMARK,EWAYBILLNO,
 EWAYBILLDTAE,EINVNO,TCS_PER,TCS_AMT,JSM.CMP_CODE,JSM.IRN,JSM.ACK_DATE
"
SET @SQL1 ="FROM "+@DATABASENAME+" JOB_SALESINVOICE_MASTER JSM
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = JSM.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
INNER JOIN "+@DATABASENAME+" JOB_SALESINVOICE_DETAIL JSD ON JSD.JOB_SAL_INV_ID = JSM.JOB_SAL_INV_ID AND JSM.FORM_FLAG = JSD.FORM_FLAG
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = JSM.CMP_CODE
LEFT JOIN "+@DATABASENAME+" STATE_MASTER PSM ON LM.STATE_ID = PSM.STATE_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=JSD.ITEM_ID
LEFT JOIN "+@DATABASENAME+" HSN_MASTER HSN ON HSN.HSN_ID = IM.HSN_ID
LEFT JOIN " + @DATABASENAME +"CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=JSM.Consignee_Id	
LEFT JOIN " + @DATABASENAME +"STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id
LEFT JOIN "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
LEFT JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON JSM.TRANSPORT_ID = TM.TRANSPORT_ID
WHERE JSM.CMP_CODE IN ("+@CMP_CODE+") 
AND JSM.JOB_SAL_INV_BILL_NO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
AND JSM.FORM_FLAG='"+@TYPE+"'
) AS A
ORDER BY INVOICENO,INVOICEDATE,LOTNO  "
END
EXEC (@SQL+ @SQL1)
PRINT @SQL
PRINT @SQL1
























GO

