/*
-- =============================================
-- AUTHOR:		deepal patel
-- ALTER_DATE: 18-03-2017
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESS PENDING REGISTER BUNCH NO WISE
-- REPORTNAME : PROCESSPENDING_BUNCHREG.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
	PROC_JOBINWARD 3,'ACC2016_2017.DBO.',2,'01/APR/2016','31/MARCH/2017','',2


*/
CREATE PROCEDURE [dbo].[PROC_JOBINWARD]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),	
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND JI.LRLOOSE='LR'"
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND JI.LRLOOSE='LOOSE' "
END



BEGIN
IF @RPT_WISE IN (1,5,8) /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = JI.LGR_ID "
END
 IF @RPT_WISE IN(2,6) /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = JI.TRANSPORT_ID "
END


 IF @RPT_WISE IN (3,7) /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = JI.LOT_ID "
END

 IF @RPT_WISE =4/*PARTY NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = JI.CITY_ID "
END


 IF @RPT_WISE =9 /*BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = JI.JOBINWARDID "
END









END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = "
					SELECT JOBINWARDID, DOCNO,  DOCDATE, 
                     ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,LRNO, 
                      LRDATE,ISNULL(LM.LOT_NAME,'') AS GREYMARKA, 
                     ISNULL(IM.ITEM_NAME,'') AS ITEM,cm.City_Name as STATION_NAME,
                     ISNULL(PM.LGR_NAME,'') AS PARTY,LRNO,BALES,RECTHAN ,RECMETER,RETTHAN,
                     RETMETER,ACCTHAN,ACCMETER,FOLD,PENDINGMETER,PENDINGTHAN,LRLOOSE
                    
                     FROM "+@DATABASENAME+"JOBINWARD JI 
                     INNER JOIN "+@DATABASENAME+"Transport_MASTER TM ON TM.Transport_ID=JI.Transport_ID
                     INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PM ON PM.LGR_ID = JI.LGR_ID
                     INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID = JI.LOT_ID 
                     INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = JI.ITEM_ID
                    INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=JI.CITY_ID
"+@SQLJOIN+" 
WHERE   JI.CMP_CODE IN ("+@CMP_CODE+") AND JI.DOCDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@STRCOND+"  
 order by  JI.JOBINWARDID"

END

EXEC (@STRSQL+@STRSQL1)

PRINT @STRSQL
PRINT @STRSQL1





















GO

