/*
-- =============================================
-- ALTER_AUTHOR  :	<PRATIK>
-- ALTER_DATE    : <08/09/2016>
-- REPORT_FORM	  :	<rfrmPrintingDocRpt.cs>
-- CRYSTAL_REPORT : <JOBINWARD_PRINT_OUT.RPT
 PROC_JOBINWARD_PRINT 1,'ACC2016_2017.DBO.','1','10'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_JOBINWARD_PRINT] 

(
@CMP_CODE NVARCHAR(5),
@DATABASENAME NVARCHAR(100),
@FROMDOCNO NVARCHAR(10),
@TODOCNO NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = ""
	

BEGIN
SET NOCOUNT ON;
SET @SQL = "
SELECT JOBINWARDID,DOCNO,DOCDATE,ISNULL(TM.TRANSPORT_NAME,'') TRANSPORTNAME,ISNULL(LM.LOT_NAME,'')MARKANAME,
ISNULL(LRNO,'')LRNO,LRDATE,
ISNULL(IM.ITEM_NAME,'')ITEM,ISNULL(PM.LGR_NAME,'')PARTY,ISNULL(CM.CITY_NAME,'')PARTYCITY,ISNULL(WM.WEAVER_NAME,'')WEAVERNAME,
ISNULL(BALENO,'')BALENO,ISNULL(BALES,0)BALES,ISNULL(RECTHAN,0)RECTHAN,ISNULL(RECMETER,0)RECMETER,ISNULL(RETTHAN,0)RETTHAN,
ISNULL(RETMETER,0)RETMETER,ISNULL(ACCTHAN,0)ACCTHAN,ISNULL(ACCMETER,0)ACCMETER,ISNULL(FOLD,0)FOLD,ISNULL(SHORTMETER,0)SHORTMETER,
ISNULL(NETMETER,0)NETMETER,ISNULL(WEIGHT,0)WEIGHT,ISNULL(RATE,0)RATE,ISNULL(PENDINGMETER,0)PENDINGMETER,
ISNULL(PENDINGTHAN,0)PENDINGTHAN,ISNULL(PARTY_LOTNO,0)PARTY_LOTNO,ISNULL(LOTNO,0)LOTNO,ISNULL(LRLOOSE,'')LRLOOSE,
ISNULL(SM.CITY_NAME,'')STATENAME
FROM "+@DATABASENAME+"JOBINWARD JW
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=JW.TRANSPORT_ID 
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID=JW.LOT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=JW.ITEM_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PM ON PM.LGR_ID=JW.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=JW.CITY_ID
INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=JW.WEAVER_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SM ON SM.CITY_ID=JW.STATION_ID
WHERE DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+" AND JW.CMP_CODE="+@CMP_CODE+"
ORDER BY CONVERT(INT,DOCNO)
"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL





















GO

