/*
-- =============================================
-- Author:		PATEL PRATIK
-- Create_date: 16/07/2013
-- Description:	THIS PROCEDURE USED FOR JOB SALES INVOICE MANUAL LONG REPORT 
-- ReportName:  JOBSALESMANUALLONG.RPT
-- =============================================
PROC_JOBSALESINVMANUAL_LONG '1','01/APR/2012','31/MARCH/2013','ACC2012_2013.DBO.',1,''
*/
CREATE PROCEDURE [dbo].[PROC_JOBSALESINVMANUAL_LONG]
(
	@CMP_CODE AS NVARCHAR(20),
	@FROMDATE AS NVARCHAR(50),
	@TODATE   AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(50),
	@RPT_WISE AS INT,
	@TEMPTABLE NVARCHAR(100)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(1000)

SET @SQL = ""
SET @SQLJOIN = ""

BEGIN
	IF @RPT_WISE IN (1,4,7) /* PARTY WISE,PARTY-AGENT,PARTY-ITEM  */
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = LM.LGR_ID"
	ELSE IF @RPT_WISE IN (2,5) /* AGENT WISE,AGENT-PARTY */
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = ALM.LGR_ID"
	ELSE IF @RPT_WISE = 3 /* BILL NO */
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = JSM.JOB_SAL_INV_ID"
	ELSE IF @RPT_WISE = 6 /* ITEM WISE */
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = IM.ITEM_ID"
END
BEGIN
	SET NOCOUNT ON;
	SET @SQL = "SELECT JSM.JOB_SAL_INV_ID,JSM.JOB_SAL_INV_BILL_NO AS BILLNO,JSM.BILL_DATE AS DATE,
                LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,
				ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(JSM.TOTAL,0) AS GROSSTOTAL,
				ISNULL(JSM.ADDTOTAL,0) AS ADDTOTAL,ISNULL(JSM.DISAMT,0) AS DISAMT,ISNULL(JSM.ROFF,0) AS ROFF,
				ISNULL(JSM.NETAMT,0) AS NETAMT,CMP.CMP_ALIAS,LOTNO,ITEM_NAME AS ITEM,THAN,MTRS,RATE,AMOUNT,QTY,JSD.NARRATION,
				(( isnull(JSM.SAL_INV_ADD1,0) + isnull(JSM.SAL_INV_ADD2,0) +  - isnull(JSM.LESSTOTAL,0))+ JSM.Roff) as ADDLESSTOTAL,
				ISNULL(JSM.SAL_INV_ADD3,0)AS CGST,ISNULL(JSM.SAL_INV_ADD4,0)AS SGST,ISNULL(JSM.SAL_INV_ADD5,0)AS IGST,(JSM.TOTAL- isnull(JSM.LESSTOTAL,0)+(ISNULL(JSM.SAL_INV_ADD1,0)+ ISNULL(JSM.SAL_INV_ADD2,0))) AS TAXABLEAMT
				FROM "+@DATABASENAME+" JOB_SALESINVOICE_MASTER JSM
                INNER JOIN "+@DATABASENAME+" JOB_SALESINVOICE_DETAIL JSD ON JSD.JOB_SAL_INV_ID=JSM.JOB_SAL_INV_ID AND JSD.CMP_CODE=JSM.CMP_CODE AND JSM.FORM_FLAG=JSD.FORM_FLAG
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = JSM.LGR_ID
				LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID = JSM.AGENT_ID
				LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
				INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = JSM.CMP_CODE
                INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=JSD.ITEM_ID 
				"+@SQLJOIN+"
				WHERE JSM.CMP_CODE IN ( "+@CMP_CODE+" ) AND JSM.JOB_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
				AND JSM.FORM_FLAG = 'JS' ORDER BY DATE,BILLNO,LOTNO"
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






















GO

