/*
-- =============================================
-- AUTHOR         :	<BIREN>
-- ALTER_DATE    : <05-07-2013 1:12 PM>
-- REPORT_FORM    :	<rfrmPrintingDocRpt.cs>
-- CRYSTAL_REPORT :	<JOBNSALESINVPRINT.RPT>
-- =============================================
PROC_JOBSALESINVPRINT '1','ACC2012_2013.DBO.',1,8
*/
CREATE PROCEDURE [dbo].[PROC_JOBSALESINVPRINT]
(
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(20),
	@FROMDOCNO AS NVARCHAR(20),
	@TODOCNO AS NVARCHAR(20)
)	
AS

DECLARE @SQL AS NVARCHAR(4000)

SET @SQL=""
BEGIN
	  
SET @SQL =  " 
			SELECT JSM.JOB_SAL_INV_ID,JSM.JOB_SAL_INV_BILL_NO AS INVOICENO,
			CONVERT(NVARCHAR,JSM.JOB_SAL_INV_VDATE,103) AS INVOICEDATE,LM.LGR_NAME AS PARTY,AGM.LGR_NAME AS AGENT,
			ISNULL(LM.LGR_ADD1,'') AS LGR_ADD1,ISNULL(LM.LGR_ADD2,'') AS LGR_ADD2,
			ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(LM.CITY_PINCODE,0) AS CITYPINCODE,
			ISNULL(ACM.CITY_NAME,'') AS AGENTYCITY,CONVERT(NVARCHAR,JSM.JOB_SAL_FRDATE,103) AS FROMDATE,
			CONVERT(NVARCHAR,JSM.JOB_SAL_TODATE,103) AS TODATE,JSM.LR_NO,
			CONVERT(NVARCHAR,JSM.LR_DATE,103) AS LR_DATE,JSM.QTY_TOTAL,JSM.THAN_TOTAL,JSM.AMT_WORD,
			JSM.ROFF,JSM.TOTAL AS GROSSTOTAL,JSM.ADDTOTAL,JSM.NETAMT,JSM.DISPER,JSM.DISAMT,
			IM.ITEM_NAME ITEM,JSD.LOTNO,JSD.THAN,JSD.RATE,JSD.AMOUNT,JSD.QTY,JSD.CUT,
			CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_PHONE1,
			CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_FAX
			FROM "+@DATABASENAME+"JOB_SALESINVOICE_MASTER JSM
			INNER JOIN "+@DATABASENAME+"JOB_SALESINVOICE_DETAIL JSD ON JSD.JOB_SAL_INV_ID =JSM.JOB_SAL_INV_ID AND JSD.FORM_FLAG = JSM.FORM_FLAG
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=JSM.LGR_ID
			LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=JSM.AGENT_ID
			LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
			LEFT JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=JSD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=JSM.CMP_CODE
			WHERE JSM.CMP_CODE IN("+@CMP_CODE+") AND JSM.FORM_FLAG = 'JS'
			AND JSM.JOB_SAL_INV_BILL_NO BETWEEN "+@FROMDOCNO+"  AND "+ @TODOCNO +"
			ORDER BY JSM.JOB_SAL_INV_BILL_NO,JSM.JOB_SAL_INV_VDATE

			"
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

