/* 
PROC_COTTONSALESREGISTER '1','ACC2010_2011.DBO.','01/APR/2010','01/APR/2010',1,'##2010'
*/
CREATE PROCEDURE [dbo].[PROC_JOBSALESREGISTER]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @FROMDATE NVARCHAR(100),
   @TODATE NVARCHAR(100),
   @RPT_WISE INT,
   @TEMPTABLE NVARCHAR(100)
    
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
SET @SQL=""
SET @JOINSQL=""
 

BEGIN
       IF @RPT_WISE=1
        SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
       ELSE IF @RPT_WISE=2
        SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=FTM.FINISHTYPE_ID"
       ELSE IF @RPT_WISE=3
        SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=pCM.CITY_ID"
       ELSE IF @RPT_WISE=4
        SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PCM.CITY_ID"
       ELSE IF @RPT_WISE=5
        SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=CSI.COT_SAL_INV_BILL_NO"
END


BEGIN
     SET @SQL="
                	 SELECT CSI.COT_SAL_INV_BILL_NO AS BILLNO,CSI.COT_SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME,CSID.CHALLANNO AS CHALLANNO,
                     FTM.FINISHTYPE_NAME AS FINISHTYPE,CSID.THAN AS THAN,      
                     CSID.MTRS AS METERS, CSID.AMOUNT AS AMOUNT,CSID.RATE AS RATE,CSI.NETAMT AS NETTOTAL,
                     PCM.CITY_NAME AS PARTYCITY ,(ISNULL(CSI.AddTotal,0)-ISNULL(CSI.DISAMT,0)) as ADDLESSTOTAL,ISNULL(CSI.CENTERCHARGE,0) AS CENTERCHARGE,ISNULL(CSI.OTHERCHARGE,0) AS OTHERCHARGE
                     FROM "+@DATABASENAME+"COTTON_SALESINVOICE_MASTER  CSI
                     INNER JOIN  "+@DATABASENAME+"COTTON_SALESINVOICE_DETAIL CSID ON CSID.COT_SAL_INV_ID=CSI.COT_SAL_INV_ID
                     INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CSI.LGR_ID     
                     INNER JOIN "+@DATABASENAME+"FINISHTYPE_MASTER FTM ON FTM.FINISHTYPE_ID=CSID.FINISHTYPE_ID          
                      LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID               
                     "+@JOINSQL+"
                     WHERE CSI.CMP_CODE IN ("+@CMP_CODE +") and  CSI.COT_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
                     ORDER BY CSI.COT_SAL_INV_VDATE,CSI.COT_SAL_INV_BILL_NO,CSID.SRNO

          "
	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

