/* 
PROC_SHORTREPORT '10','ACC2010_2011.DBO.','01/APR/2010','01/APR/2011','##2310'
*/
CREATE PROCEDURE [dbo].[PROC_JOBSALESSHORTREPORT]
(
     @CMP_CODE NVARCHAR(100),
     @DATABASENAME NVARCHAR(100),
     @FROMDATE NVARCHAR(20),
     @TODATE NVARCHAR(20),
     @TEMPTABLE NVARCHAR(20)
     
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
SET @SQL=""
SET @JOINSQL=""
SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT  ON TT.CODE=HLM.LGR_ID"

BEGIN
	SET NOCOUNT ON;
SET @SQL ="    SELECT HLM.LGR_NAME AS HEADNAME,CS.COT_SAL_INV_BILL_NO AS BILLNO,CS.COT_SAL_INV_VDATE AS BILLDATE
                ,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
               ,CS.TOTAL AS GROSSTOTAL,ISNULL(CS.ADDTOTAL,0) AS ADDTOTAL,CS.DISAMT AS LESSTOTAL,CS.NETAMT AS NETTOTAL,LM.LGR_PHONE1,LM.LGR_PHONE2,SUM(CSD.THAN) AS THAN,MAX(ISNULL(RATE,0)) AS RATE
				,ISNULL(CS.CENTERCHARGE,0) AS CENTERCHARGE,ISNULL(CS.OTHERCHARGE,0) AS OTHERCHARGE,ISNULL(CS.CENTERTHAN,0) AS CENTERTHAN,ISNULL(CS.OTHERTHAN,0) AS OTHERTHAN,SUM(ISNULL(CSD.AMOUNT,0)) AS AMOUNT
               FROM "+@DATABASENAME+"COTTON_SALESINVOICE_MASTER CS
               INNER JOIN "+@DATABASENAME+"COTTON_SALESINVOICE_DETAIL CSD ON CS.COT_SAL_INV_ID=CSD.COT_SAL_INV_ID
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=CS.LGR_ID
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER HLM ON HLM.LGR_ID=CS.COT_SALACCID
               LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
               "+@JOINSQL+"
               WHERE CS.CMP_CODE IN("+@CMP_CODE +") AND CS.COT_SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                GROUP BY HLM.LGR_NAME ,CS.COT_SAL_INV_BILL_NO ,CS.COT_SAL_INV_VDATE 
                ,LM.LGR_NAME ,PCM.CITY_NAME ,CS.TOTAL,CS.ADDTOTAL,CS.DISAMT ,CS.NETAMT,LM.LGR_PHONE1,LM.LGR_PHONE2,CS.CENTERCHARGE,CS.OTHERCHARGE,RATE,CS.CENTERTHAN,CS.OTHERTHAN
               ORDER BY HLM.LGR_NAME, CS.COT_SAL_INV_VDATE,CS.COT_SAL_INV_BILL_NO,LM.LGR_NAME 
             "
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

