/* 
PROC_JOBWORKERBILL 2,'ACC2010_2011.DBO.','01/APR/2010','01/APR/2011',''
*/
CREATE PROCEDURE [dbo].[PROC_JOBWORKERBILL]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20)	
)
as
declare @Sql  Nvarchar(4000)
begin
    	SET NOCOUNT ON;
        set @sql=" 
				       select PS.PackingSlipId,PS.BaleNo,PS.Vch_Date,PLM.Lgr_Name As PartyName, 
					   PCM.City_Name As PartyCity,SM.Screen_Name,                       
					   PS.BalePack_id,BPM.BalePack_Name,IM.Rate_Per,psd.Item_cut,
                       CASE WHEN UM.UNIT_NAME='METERS' THEN PSD.Total ELSE 0 END AS Mtrs,
                       CASE WHEN UM.UNIT_NAME='PIECES' THEN PSD.TotalPcs ELSE 0 END AS TotalPcs,                       
                       CASE WHEN UM.UNIT_NAME='KILOGRAMS' THEN PSD.Total ELSE 0 END AS KGS,
                       (CASE WHEN UM.UNIT_NAME='METERS' THEN PSD.Total WHEN UM.UNIT_NAME='PIECES' THEN PSD.TotalPcs*ISNULL(IM.ITEM_CONVERSION,0) 
                             WHEN UM.UNIT_NAME='KILOGRAMS' THEN PSD.Total*ISNULL(IM.ITEM_CONVERSION,0) ELSE 0 END) AS NETMTRS
				       from "+@DatabaseName+"packingslip PS
					   INNER JOIN "+@DatabaseName+"packingslip_detail PSD ON PS.PackingSlipId=PSD.PackingSlipId
					   INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PS.lgr_id=PLM.Lgr_id
					   INNER JOIN "+@DatabaseName+"balepack_master BPM ON PS.BalePack_id=BPM.BalePack_id
					   LEFT JOIN "+@DatabaseName+"Screen_Master SM ON PSD.Screen_id=SM.Screen_Id
                       LEFT JOIN "+@DatabaseName+"Item_Master IM ON PSD.Item_id=IM.Item_id
                       LEFT JOIN "+@DatabaseName+"Unit_Master UM ON Im.Unit_id=UM.Unit_id
					   LEFT JOIN "+@DatabaseName+"City_Master PCM ON PLM.City_Id=PCM.City_Id
					   INNER JOIN "+@TempTable+" TT ON TT.Code=PS.BalePack_id
				Where PS.cmp_code="+@Cmp_Code+" 
					And PS.vch_Date between '"+@FromDate+"' And '"+@ToDate+"'
				"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

