REPORT_FORM    : BANK_PAYMENT,CASH_PAYMENT
CRYSTAL_REPORT : PAYMENT_NOTE_PRINT
=============================================
PROC_JOURNAL_VOUCHER_PRINT 1,'ACC2016_2017.DBO.','1','1',1
*/
CREATE PROCEDURE [dbo].[PROC_JOURNAL_VOUCHER_PRINT]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@FROMDOCNO NVARCHAR(50),
	@TODOCNO NVARCHAR(50),
	@RPT_TYPE NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @TYPESQL AS NVARCHAR(4000)

SET @SQL=""
SET @TYPESQL=""



BEGIN
SET NOCOUNT ON;

SET @SQL =	"

                 SELECT TD.SRNO,CONVERT(INT,TM.TRAN_DOCNO) AS TRAN_DOCNO,TM.TRAN_ID,TM.TRAN_DATE,LM.LGR_NAME,LM.LGR_ID, 
                 TD.TRAN_AMOUNT,TD.TRAN_DRCR,TM.NARRATION,TD.NARRATION AS DETAILNARR,TD.SHOWPARTAMT, 
                 TM.ADD_DATE,TM.EDIT_DATE,TM.USERID,ISNULL(TD.ADJUST,'NO') AS ADJUST,ISNULL(TD.JR_BILLNO,'') AS JR_BILLNO 
                 FROM "+@DATABASENAME+"TRAN_MASTER TM  
                 INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID = TM.TRAN_ID AND TM.TRAN_TYPE = TD.TRAN_TYPE 
                 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = TD.TRAN_DETAIL_ID
				WHERE TM.TRAN_DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+" 
				AND TM.TRAN_TYPE = 'J' AND TM.CMP_CODE = "+@CMP_CODE+" ORDER BY TRAN_DOCNO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL 





























