CREATE PROCEDURE [dbo].[PROC_JOURNALREGISTER]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
	@ToDate as Nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)

begin
    	SET NOCOUNT ON;
        set @sql=" 
				Select TM.Tran_DocNo As RefNo, AJ.entrycode AS Vcode,AJ.vdate AS voucher_date,AJ.Code As AJSrNo,
					LM.Lgr_Name As PartyName,LM.Lgr_ID AS PartyId,PCM.City_Name As PartyCity,
					AJ.DrAmount AS DrAMOUNT,AJ.CrAmount AS CrAMOUNT,AJ.entrytype AS Type,
					AJ.Narration As Narr
				    From "+@DatabaseName+"AutoJournal AJ
					INNER JOIN "+@DatabaseName+"Ledger_Master LM ON AJ.Lgr_Id = LM.Lgr_Id
					INNER JOIN "+@DatabaseName+"Tran_Master TM ON AJ.EntryCode=TM.Tran_Id And AJ.EntryType=TM.Tran_Type AND TM.CMP_CODE=AJ.CMP_CODE
					LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_Id=PCM.City_Id
				Where AJ.VDate Between '"+@FromDate+"' And '"+@ToDate+"' And AJ.Cmp_Code="+@Cmp_Code+"
				
				UNION ALL


				Select TM.Tran_DocNo AS RefNo,TM.Tran_Id As Vcode,TM.Tran_Date AS voucher_date,0 As AJSrNo,
					PLM.Lgr_Name as PartyName,PLM.Lgr_ID AS PartyId,PCM.City_Name As PartyCity,
					(CASE WHEN TD.Tran_DrCr = 'D' THEN TD.Tran_Amount ELSE 0 END) AS DrAMOUNT,
					(CASE WHEN TD.Tran_drcr = 'C' THEN TD.Tran_Amount ELSE 0 END) AS DrAMOUNT,
					TM.Tran_Type as TranType,TD.Narration As Narr
				From "+@DatabaseName+"Tran_Master TM
					INNER JOIN "+@DatabaseName+"Tran_Detail TD ON TD.TRan_Id= TM.TRan_Id And TD.Tran_Type = TM.Tran_Type AND TD.Cmp_Code= TM.Cmp_Code 
					INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON TD.Tran_Detail_Id= PLM.Lgr_Id
					LEFT JOIN "+@DatabaseName+"City_Master PCM ON PLM.City_Id=PCM.City_Id
				Where TM.Tran_Date Between '"+@FromDate+"' And  '"+@ToDate+"' And TM.Cmp_Code="+@Cmp_Code+" And  TM.Tran_Type In ('J') 

				"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

