SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*

SELECT * FROM TEMPDB..SYSOBJECTS
-- =============================================
-- AUTHOR:		<GAMI DIPAK>
-- ALTER_DATE: <16,10,2014>
-- DESCRIPTION:	<THIS REPORT IS USED TO LAST STAMPING REPORT>
SELECT * FROM TEMPDB..SYSOBJECTS  WHERE NAME LIKE '##%'
PROC_LASTSTAMPING '1','ACC2015_2016.DBO.','03/JUN/2015','##5304',1
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_LASTSTAMPING]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME  NVARCHAR(100),
@ASONDATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@RPT_WISE INT
)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(500)

SET @STRSQL=""
SET @STRJOIN=""
SET @STRORDERBY=""

IF @RPT_WISE=1 
BEGIN
SET @STRJOIN=" INNER JOIN  "+ @TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
SET @STRORDERBY=" LM.LGR_NAME,ISNULL(LM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),VCH_DATE DESC,BALENO DESC  "
END

ELSE IF @RPT_WISE=2 
BEGIN
SET @STRJOIN=" INNER JOIN  "+ @TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
SET @STRORDERBY=" ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),VCH_DATE DESC,BALENO DESC "
END

ELSE IF @RPT_WISE=3 
BEGIN
SET @STRJOIN=" INNER JOIN  "+ @TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
SET @STRORDERBY=" IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),STGM.STAMPGRP_NAME,ISNULL(STGM.STAMPGRP_ID,0),LM.LGR_NAME,VCH_DATE DESC,BALENO DESC "
END

ELSE IF @RPT_WISE=4 
BEGIN
SET @STRJOIN=" INNER JOIN  "+ @TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
SET @STRORDERBY=" SM.SCREEN_NAME,ISNULL(SM.SCREEN_ID,0),STGM.STAMPGRP_NAME,ISNULL(STGM.STAMPGRP_ID,0),VCH_DATE DESC,BALENO DESC "
END

ELSE IF @RPT_WISE=5 
BEGIN
SET @STRJOIN=" INNER JOIN  "+ @TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID"
SET @STRORDERBY=" TM.TRANSPORT_NAME,ISNULL(TM.TRANSPORT_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),VCH_DATE DESC,BALENO DESC "
END


BEGIN

SET @STRSQL="	SELECT BALENO,VCH_DATE,IM.ITEM_NAME AS ITEM, LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
STGM.STAMPGRP_NAME,SM.SCREEN_NAME,TM.TRANSPORT_NAME,ISNULL(CMP_ALIAS,'')CMP_ALIAS,LCM.CITY_NAME,
ISNULL(PSD.REMARK,'') AS REMARK,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(LCM.CITY_ID,0) AS CITYID,
ISNULL(STGM.STAMPGRP_ID,0) AS STAMPGRPID,ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(SM.SCREEN_ID,0) AS SCREENID,ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID, ACM.CITY_NAME AS AGENTCITY

FROM "+@DATABASENAME+"PACKINGSLIP PS
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PSD.PACKINGSLIPID =PS.PACKINGSLIPID AND PS.CMP_CODE=PSD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID =PS.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER	 LCM ON LCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"STAMPGROUP_MASTER STGM ON STGM.STAMPGRP_ID =PS.STAMPGRP_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =PSD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID =PS.AGENT_ID
LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID =PSD.SCREEN_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID =PS.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PS.CMP_CODE

LEFT JOIN "+@DATABASENAME+"CITY_MASTER	 ACM ON ACM.CITY_ID=ALM.CITY_ID

"+@STRJOIN+"
WHERE   PS.CMP_CODE IN("+@CMP_CODE  +") AND	VCH_DATE<='"+ @ASONDATE +"' ORDER BY "+@STRORDERBY+" "
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

