/* 
PROC_LORIWALA_GATEPASS '2','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##1192'
*/
CREATE PROCEDURE [dbo].[PROC_LORIWALA_GATEPASS]
( 
   @CMP_CODE  NVARCHAR(50),
   @DATABASENAME  NVARCHAR(100),
   @FROMDATE  NVARCHAR(20),
   @TODATE  NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
SET @SQL =""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TG.LORIWALA_ID "

BEGIN
    SET @SQL ="
				SELECT LM.LORIWALA_NAME, TG.DOCNO AS GATEPASS,TG.VCH_DATE AS DATE
                ,TGD.RUKKANO,TGD.BALES,TGD.BALENOSTRING,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"TRANSPORT_GATEPASS TG
				INNER JOIN "+@DATABASENAME+"TRANSPORT_GATEPASS_DETAIL TGD ON TGD.TRANS_GATEPASS_ID=TG.TRANS_GATEPASS_ID
				INNER JOIN "+@DATABASENAME+"LORIWALA_MASTER LM ON LM.LORIWALA_ID=TG.LORIWALA_ID                
                INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TG.CMP_CODE
                "+@JOINSQL+"
                WHERE TG.VCH_DATE  BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND TG.CMP_CODE IN ("+@CMP_CODE+")
                ORDER  BY TG.DOCNO,TG.VCH_DATE
              "
END
PRINT @SQL
EXECUTE SP_EXECUTESQL  @SQL




















