/****** Object:  StoredProcedure [dbo].[PROC_LOT_ISSUE_REC_REGI]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author:		<SANKET>
-- Create_date: <08/OCT/2012>
-- Description:	<ISSUE AND REC LOT DETAIL DATA FROM PROCESS IN AND OUT DATA>
-- REPORT NAME: LotIssueRecRegi.rpt
-- =============================================
PROC_LOT_ISSUE_REC_REGI '1','ACC2012_2013.DBO.','01/APR/2012','20/MAR/2013','##3076',1,8,3
*/
CREATE PROCEDURE [dbo].[PROC_LOT_ISSUE_REC_REGI]
(
	@Cmp_Code NVARCHAR(10),
	@DatabaseName NVARCHAR(20),
	@FromDate NVARCHAR(20),
	@ToDate NVARCHAR(20),
	@TempTable NVARCHAR(20),
	@TYPESQL INT,
	@RPT_WISE INT,
	@PROCESS_ID NVARCHAR(20)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""
DECLARE @PROCESSSQL AS NVARCHAR(1000) SET @PROCESSSQL = ""

BEGIN
IF @RPT_WISE IN (1,4,5,7,13,15) /*PARTY WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=LM.LGR_ID "
ELSE IF @RPT_WISE=2 /*ITEM WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID "
ELSE IF @RPT_WISE IN (3,6,10,14) /*PROCESS WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PM.PROCESS_ID "
ELSE IF @RPT_WISE=9 /*LOT WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=PIN.LOTNO "
ELSE IF @RPT_WISE = 8 /*  PROCESS-ITEM-PARTY */
	BEGIN
		SET @PROCESSSQL = "  AND PM.PROCESS_ID IN (" +@PROCESS_ID+ ") "
		SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID "
	END
ELSE IF @RPT_WISE IN (11,17) /*  PROCESS-PARTY-ITEM */
	BEGIN
		SET @PROCESSSQL = "  AND PM.PROCESS_ID IN (" +@PROCESS_ID+ ") "
		SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=LM.LGR_ID "
	END

ELSE IF @RPT_WISE = 12 /* ITEMGRP WISE */
		SET @JOIN = " INNER JOIN "+@TempTable+" TT ON TT.CODE=IGM.ITEM_GRP_ID "
ELSE IF @RPT_WISE = 16 /* PROCESS-ITEMGRP-PARTY */
	BEGIN
		SET @PROCESSSQL = "  AND PM.PROCESS_ID IN (" +@PROCESS_ID+ ") "
		SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IGM.ITEM_GRP_ID "	
	END

END

BEGIN
	SET NOCOUNT ON;

	SET @STRSQL=" SELECT  PIN.PROCESSID,PIN.DocNo,PIN.VCHDATE,IM.ITEM_NAME,WM.WEAVER_NAME,LM.LGR_NAME,
				  ISNULL(LCM.CITY_NAME,'') AS CITY_NAME, PM.PROCESS_NAME,CONVERT(NVARCHAR,PIN.LOTNO) AS LOTNO,PIN.DELTHAN AS THAN,
				  PIN.DELMETER AS MTR ,SUM(ISNULL((POUT.DelThan),0)) AS REC_THAN,
				  SUM(ISNULL((POUT.DelMeter),0)) AS REC_MTR,PIN.IN_LGR_ID,PIN.IN_PROCESS_ID,PIN.IN_GODOWN_ID,POUT.INPROCESS_ID,POUT.OUT_PROCESS_ID,POUT.OUT_GODOWN_ID,POUT.OUT_LGR_ID,IGM.ITEM_GRP_NAME AS ITEMGRP  
				  FROM "+@DatabaseName+" PROCESSIN PIN  
				  INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=PIN.ITEM_ID  
				  LEFT JOIN "+@DatabaseName+" WEAVER_MASTER WM ON WM.WEAVER_ID=PIN.WEAVER_ID  
				  INNER JOIN "+@DatabaseName+"  LEDGER_MASTER LM ON PIN.IN_LGR_ID=LM.LGR_ID  
				  LEFT JOIN "+@DatabaseName+" CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID  
				  INNER JOIN "+@DatabaseName+" PROCESS_MASTER PM ON PIN.IN_PROCESS_ID=PM.PROCESS_ID  
				  LEFT JOIN "+@DatabaseName+" PROCESSOUT POUT ON PIN.PROCESSID = POUT.INPROCESS_ID AND PIN.CMP_CODE = POUT.CMP_CODE
				  INNER JOIN "+@DatabaseName+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
				  "+@JOIN+"
				  WHERE PIN.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
				  AND PIN.CMP_CODE IN ("+@Cmp_Code+")
				  GROUP BY PIN.PROCESSID,PIN.DocNo,PIN.VCHDATE,IM.ITEM_NAME,WM.WEAVER_NAME,LM.LGR_NAME,
				  LCM.CITY_NAME, PM.PROCESS_NAME,PIN.LOTNO,PIN.DELTHAN,PIN.DELMETER  ,PIN.IN_LGR_ID,
				  PIN.IN_PROCESS_ID,PIN.IN_GODOWN_ID,POUT.INPROCESS_ID,POUT.OUT_PROCESS_ID,POUT.OUT_GODOWN_ID,POUT.OUT_LGR_ID,IGM.ITEM_GRP_NAME   ORDER BY PIN.LOTNO,VCHDATE,DOCNO  "
END
execute Sp_Executesql @STRSQL
Print @STRSQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_LOTALLOCATIONREG]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
