CREATE PROCEDURE [dbo].[PROC_LOTALLOCATIONREG]
(
	@FROMLOTNO  NVARCHAR(20),
	@TOLOTNO NVARCHAR(20),
	@CMP_CODE NVARCHAR(10),
	@DATABASENAME NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
SET NOCOUNT ON;
SET @SQL="

               SELECT LAM.LOTALLOCID, LAM.LOTNO, LAM.VCHDATE AS VDATE,  SHORTMETER,LAM.TOTALTHAN AS THAN, 
               LAM.TOTALMETER AS METER,LAM.TP AS TP ,[READ] AS RD,PEAK,
               LAM.GADDY,LAM.WIDTH,LAM.WEIGHT,LAM.SSTTHAN ,IM.ITEM_NAME AS ITEMNAME,LBD.BALENAME,LAM.YEARFLAG,
               LBQD.METERQTY,LBQD.SRNO,PIM.BILLNO,PIM.VCHDATE AS BILLDATE,PIM.LRNO,LM.LGR_NAME AS PARTYNAME,
               VM.WEAVER_NAME AS VIEWER,VM.TOKENNO,CMP.CMP_NAME,CMP_STATE,CMP_ADD1,CMP_ADD2 
               FROM  ((((( "+ @DATABASENAME +"LOTALLOCATION LAM 
               LEFT JOIN  "+ @DATABASENAME +"ITEM_MASTER IM ON  LAM.ITEM_ID  =   IM.ITEM_ID) 
               LEFT JOIN "+ @DATABASENAME +"LOTBALEDETAIL LBD ON LAM.LOTNO =  LBD.LOTID AND LAM.CMP_CODE =  LBD.CMP_CODE) 
               LEFT JOIN "+ @DATABASENAME +"LOTBALEQTYDETAIL LBQD ON  LBD.BALEID =  LBQD.BALEID AND 
               LBD.LOTID = LBQD.LOTID  AND  LBD.CMP_CODE =  LBQD.CMP_CODE) 
               INNER JOIN "+ @DATABASENAME +"PURCHASEINVOICE PIM ON LAM.LOTNO = PIM.LOTNO AND LAM.CMP_CODE = PIM.CMP_CODE) 
               INNER JOIN "+ @DATABASENAME +"LEDGER_MASTER LM ON PIM.LGR_ID = LM.LGR_ID) 
               INNER JOIN "+ @DATABASENAME +"WEAVER_MASTER  VM ON  LAM.WEAVER_ID = VM.WEAVER_ID
               INNER JOIN  "+ @DATABASENAME +"COMPANY_MASTER CMP ON LAM.CMP_CODE = CMP.CMP_CODE
               WHERE LAM.LOTNO BETWEEN " + @FROMLOTNO + "  AND " + @TOLOTNO + " AND LAM.CMP_CODE  ="+ @CMP_CODE +"  ORDER BY LAM.LOTNO 
		
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

