/* 
PROC_LOTBILLREPORT '10','ACC2010_2011.DBO.','##2310',4,'DYEING','PADING','P3','P4','P5','P6'
*/
CREATE PROCEDURE [dbo].[PROC_LOTBILLREPORT]
(
   @CMP_CODE  NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),   
   @TEMPTABLE NVARCHAR(100),
   @RPT_WISE INT,
   @PROCESS1 NVARCHAR(100),
   @PROCESS2 NVARCHAR(100),
   @PROCESS3 NVARCHAR(100),
   @PROCESS4 NVARCHAR(100),
   @PROCESS5 NVARCHAR(100),
   @PROCESS6 NVARCHAR(100)
)     
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @MAINSQL AS NVARCHAR(1000)
DECLARE @LOTJOINSQL AS NVARCHAR(1000)


SET @SQL=""
SET @JOINSQL=""
SET @MAINSQL=""

BEGIN 
        IF @RPT_WISE=1
              BEGIN
                   SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
                   SET @MAINSQL=" IM.ITEM_NAME AS MAINGROUP"                   
              END
        ELSE IF @RPT_WISE=2
             BEGIN
                   SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID "
                   SET @MAINSQL=" IGM.ITEM_GRP_NAME AS MAINGROUP"
                   
             END
        ELSE IF @RPT_WISE=3
             BEGIN
                   SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
                   SET @MAINSQL=" ITM.ITEM_TYPE_NAME AS MAINGROUP"
                   
             END
        ELSE IF @RPT_WISE=4
              BEGIN
                   SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PID.LOTNO "
                   SET @MAINSQL=" 'MAINGROUP'  AS MAINGROUP" 
                   
              END
END




BEGIN
   SET @SQL="
             SELECT MAINGROUP,PLOTNO,PBILLNO,PAMOUNT,JPLOTNO,PARTY,PARTYCITY,JPBILLNO,JPAMOUNT
             ,ISNULL("+@PROCESS1+",0)AS PROCESS1,ISNULL("+@PROCESS2+",0)AS PROCESS2,ISNULL("+@PROCESS3+",0)AS PROCESS3,ISNULL("+@PROCESS4+",0)AS PROCESS4,ISNULL("+@PROCESS5+",0)AS PROCESS5
              ,ISNULL("+@PROCESS6+",0)AS PROCESS6,CMP_ALIAS             
             FROM
            (
              SELECT MAINGROUP,PI.LOTNO AS PLOTNO,PI.BILLNO AS PBILLNO,PI.NETTOTAL AS PAMOUNT,DETAIL.JPLOTNO,DETAIL.JPTHAN,DETAIL.PARTY,DETAIL.PARTYCITY,DETAIL.JPBILLNO,DETAIL.JPAMOUNT,DETAIL.PROCESS,DETAIL.CMP_ALIAS
              FROM "+@DATABASENAME+"PURCHASEINVOICE PI
              INNER JOIN(
		         SELECT MAINGROUP,JPLOTNO,JPTHAN,JPAMOUNT,PARTY,PARTYCITY,JPBILLNO,PROCESS,CMP_CODE,CMP_ALIAS
		         FROM(
		         SELECT "+@MAINSQL+",PID.LOTNO AS JPLOTNO,PID.PIECES AS JPTHAN,PID.AMOUNT AS JPAMOUNT,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                 ,PI.BILLNO AS JPBILLNO,PM.PROCESS_NAME AS PROCESS,PI.CMP_CODE AS CMP_CODE,CMP.CMP_ALIAS
		         FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
		         INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PID.FLAG=PI.FLAG
		         INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
		         INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=PI.PROCESS_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                 LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
                 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
                 "+@JOINSQL+"
		         WHERE PI.CMP_CODE IN ("+@CMP_CODE+") AND  PID.FLAG='JP' AND
		         PID.LOTNO IN(SELECT PI.LOTNO FROM "+@DATABASENAME+"PURCHASEINVOICE PI WHERE PI.LOTNO>0 AND PI.CMP_CODE  IN ("+@CMP_CODE+") )
		            ) AS DETAIL 
                       ) DETAIL ON DETAIL.JPLOTNO=PI.LOTNO AND DETAIL.CMP_CODE=PI.CMP_CODE
                
          ) AS LOTDETAIL
       PIVOT (SUM(JPTHAN) FOR PROCESS IN("+@PROCESS1+","+@PROCESS2+","+@PROCESS3+","+@PROCESS4+","+@PROCESS5+","+@PROCESS6+")) AS PVT
         ORDER BY PLOTNO
            "
	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

