/*
-- =============================================
-- Author:		HIREN DOSHI
-- Create_date: 22-11-2014
-- Description:	THIS PROCEDURE USED FOR LOT ENTRY REPORT SHOW
-- ReportName : LOTENTRY_REG.RPT 
-- =============================================
 DECLARE @TEMP NVARCHAR(100)
SELECT @TEMP=NAME FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PRINT @TEMP
[PROC_LOTENTRYREG] 1,'ACC2014_2015.DBO.',1,'01/APR/2013','31/MARCH/2015','##2584',3
*/
CREATE PROCEDURE [dbo].[PROC_LOTENTRYREG]
(
	@CMP_CODE NVARCHAR(1000),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20), 
	@TEMPTABLE NVARCHAR(20),
	@RPT_TYPE INT
)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""

BEGIN
	IF @RPT_TYPE = 0 /* PAID */
		SET @STRCOND = " AND ISNULL(LE.PENDINGTHAN,0) = 0 "
	ELSE IF @RPT_TYPE = 1 /* PENDING */
		SET @STRCOND = " AND ISNULL(LE.PENDINGTHAN,0) > 0 "
END
BEGIN
	IF @RPT_WISE = 1 /* GREY MARKA */
	BEGIN
		SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
		SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),LE.VCHDATE,LE.DOCNO "
	END
	ELSE IF @RPT_WISE = 2 /* CONTRACTOR */
	BEGIN
		SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = CM.Contractor_Id "
		SET @STRORDERBY = " CM.Contractor_Name,ISNULL(CM.Contractor_Id,0),LE.VCHDATE,LE.DOCNO "
	END
	ELSE IF @RPT_WISE = 3 /* CHECKER */
	BEGIN
		SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = GC.GreyChecking_ID "
		SET @STRORDERBY = " GC.GreyChecking_Name,ISNULL(GC.GreyChecking_ID,0) ,LE.VCHDATE,LE.DOCNO "
	END
	ELSE IF @RPT_WISE = 4 /* BUNCH NAME */
	BEGIN
		SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BUM.BunchName_Id "
		SET @STRORDERBY = " BUM.BunchName, ISNULL(BUM.BunchName_Id,0),LE.VCHDATE,LE.DOCNO "
	END
	ELSE IF @RPT_WISE IN (5,6,7) /* LR NO,DOC NO,LOT NO */
	BEGIN
		SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LE.LotNoEntryId "
			IF @RPT_WISE = 5
			BEGIN
				SET @STRORDERBY = " LE.LRNO,LE.VCHDATE,LE.DOCNO "
			END
			ELSE IF @RPT_WISE = 6
			BEGIN
				SET @STRORDERBY = " LE.DOCNO,LE.VCHDATE "
			END
			ELSE IF @RPT_WISE = 7
			BEGIN
				SET @STRORDERBY = " LE.LOTNO,LE.VCHDATE,LE.DOCNO "
			END
	END
END
BEGIN
	SET NOCOUNT ON;
	SET @STRSQL = " SELECT LE.DOCNO,LE.VCHDATE AS DATE,LE.LrNo,CONVERT(NVARCHAR,LE.LotNo) AS LOTNO,LE.LrDate,LM.Lot_Name AS GREYMARKA,
					CM.Contractor_Name AS CONTRACTOR,GC.GreyChecking_Name AS  CHECKER,
					ISNULL(LE.LrThan,0) AS BILLTHAN,ISNULL(LE.LrMeter,0) AS BILLMETER,ISNULL(LE.RecThan,0) AS RECTHAN,
					ISNULL(LE.RetThan,0) AS	RETURNTHAN,ISNULL(LE.AccThan,0) AS ACCEPTTHAN,ISNULL(LE.RecMeter,0) AS RECMETER,
					ISNULL(LE.RetMeter,0) AS RETURNMTR,ISNULL(LE.ShortMeter,0) AS SHORTMTR,BUM.BunchName,
					ISNULL(LE.AccMeter,0) AS ACCEPTMTR,ISNULL(LE.Fold,0) AS FOLD,ISNULL(LE.NetMeter,0) AS NETMETER,LE.RATE,
					LE.BILLNO,LE.BALENO,LE.BALES,ISNULL(LE.PENDINGTHAN,0) AS PENDTHAN,ISNULL(LE.PENDINGMETER,0) AS PENDMETER,CMP.cmp_Alias,
					ISNULL(LM.LOT_ID,0) AS LOT_ID,ISNULL(GC.GREYCHECKING_ID,0) AS GREYCHECKING_ID,ISNULL(CM.CONTRACTOR_ID,0) AS CONTRACTOR_ID,
					ISNULL(BUM.BUNCHNAME_ID,0) AS BUNCHNAME_ID

					FROM "+@DATABASENAME+" LotNoEntry LE
					INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.Lot_Id = LE.LOT_ID
					INNER JOIN "+@DATABASENAME+" GREYCHECKING_MASTER GC ON GC.GreyChecking_ID = LE.GreyChecking_Id 
					INNER JOIN "+@DATABASENAME+" Contractor_Master CM ON CM.Contractor_Id = LE.CONTRACTOR_ID
					LEFT JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BUM ON BUM.BunchName_Id = LE.BunchName_Id 
					INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.cmp_Code = LE.Cmp_code
					"+@SQLJOIN+"
					WHERE LE.Cmp_code IN ("+@CMP_CODE+") AND LE.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
					"+@STRCOND+"  ORDER BY "+@STRORDERBY+"	"
END
PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL




















GO

