/* 
Proc_LotFinal_SUMMARY '1', N'Acc2012_2013.Dbo.', N'01/Apr/2012', N'31/mar/2013', N'##6132', 4, N'##6132'
*/

CREATE PROCEDURE [dbo].[PROC_LOTFINAL_SUMMARY]
(
    @Cmp_Code nvarchar(100),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20),
	@Criteria int,
	@LotTable nvarchar(20)
)
as
declare @SQL AS Nvarchar(4000)
declare @JoinSql  Nvarchar(500)
Declare @FieldSql Nvarchar(500)

set @SQL=""

set @JoinSql=""
Set @FieldSql=""

/* 
-------Start----@JoinSql
*/
If @Criteria=1 /*  Item */
	set @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=LAM.Item_Id
				  INNER JOIN "+@TempTable+" TT ON TT.code=LAM.Item_Id"
If @Criteria=2 /* Viewer */
	set @JoinSql="INNER JOIN "+@TempTable+" TT ON TT.code=LAM.Weaver_Id"
If @Criteria=3 /* ItemGroup */
	set @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON LAM.Item_Id=IM.Item_Id 
				  INNER JOIN "+@DatabaseName+"Item_Group_Master IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id
				  INNER JOIN "+@TempTable+" TT ON TT.code=IGM.Item_Grp_Id"
If @Criteria=4 /*  Party Wise */
	set @JoinSql="INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID = LAM.ITEM_ID
				  INNER JOIN "+@LotTable+" LT ON LAM.LotNo=LT.Code
				  INNER JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID = LT.LGR_ID"			  
If @Criteria=5 /*  All Item */
	set @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=LAM.Item_Id"
If @Criteria=6  /* Item Type */
	set @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=LAM.Item_Id
				  INNER JOIN "+@DatabaseName+"Item_Type_Master ITM ON IM.Item_Type_Id=ITM.Item_Type_Id
				  INNER JOIN "+@TempTable+" TT ON TT.code=ITM.Item_Type_Id"
/* -----End----@JoinSql */

/* -----Start----@FieldSql */
If @Criteria=1 /* Item */
	set @FieldSql=",IM.Item_Name As MainGrp,Convert(Nvarchar,'') As SubGrp "
If @Criteria=2 /* -Viewer */
	set @FieldSql=",VM.Weaver_Name As MainGrp,Convert(Nvarchar,'') As SubGrp "
If @Criteria=3 /* Item_Group */
	set @FieldSql=",IGM.Item_Grp_Name As MainGrp,Convert(Nvarchar,'') As SubGrp "
If @Criteria=4 /* Party */
	set @FieldSql=",LM.Lgr_Name As MainGrp,Convert(Nvarchar,IM.Item_Name) As SubGrp "
If @Criteria=5 /* All Item */
	set @FieldSql=",'' As MainGrp,Convert(Nvarchar,'') As SubGrp"
If @Criteria=6 /* Item Type */
	set @FieldSql=",ITM.Item_Type_Name As MainGrp,Convert(Nvarchar,'') As SubGrp"
/* -----End----@FieldSql */




BEGIN
SET NOCOUNT ON;
select @SQL=" 
               Select SUM(GrayMtr)AS GrayMtr,SUM(FinMtr) As FinMtr,
				SUM(ShortMtr) As ShortMtr,SUM(NetMtrs) AS NetMtrs
				, MainGrp,SubGrp FROM (
                Select GrayMtr,FTGID.Meter As FinMtr,
				(GrayMtr-FTGTD.TotalMeter) As ShortMtr,((GrayMtr-FTGTD.TotalMeter)*100/GrayMtr) As ShortPer,
				DateDiff("+'d'+",LAM.vchdate,FTGID.ItemDate) as DiffDay,(FTGID.Meter * DateDiff("+'d'+",LAM.vchdate,FTGID.ItemDate)) AS NetMtrs
				"+@FieldSql+"
			From "+@DatabaseName+"LotAllocation LAM  
				INNER JOIN (Select FTGRD.LotNo,sum(FTGRD.GrayMeter) As GrayMtr
							From  "+@DatabaseName+"FTGRecDetail FTGRD INNER JOIN "+@DatabaseName+"Finish2Godown F2G ON FTGRD.LotNo=F2G.LotNo
							Where FTGRD.cmp_code in("+@Cmp_Code+") Group by FTGRD.LotNo) As ABC ON ABC.LotNo=LAM.LotNo
				INNER JOIN "+@DatabaseName+"Finish2Godown F2G ON F2G.LotNo=ABC.LotNo
				INNER JOIN "+@DatabaseName+"FTGItemDetail FTGID ON FTGID.LotNo=ABC.LotNo 
				INNER JOIN "+@DatabaseName+"Item_Master FIM ON FTGID.Item_id=FIM.Item_Id
				INNER JOIN "+@DatabaseName+"FTGTotalDetail FTGTD ON FTGTD.LotNo=ABC.LotNo
				INNER JOIN "+@DatabaseName+"Weaver_Master VM ON LAM.Weaver_Id=VM.Weaver_Id
				"+@JoinSql+"
			Where LAM.vchdate Between '"+@FromDate+"' And '"+@ToDate+"'
				And LAM.cmp_code in("+@Cmp_Code+")
              ) AS DETAIL GROUP BY MainGrp,SubGrp ORDER BY MainGrp
			"

END
exec(@SQL)
Print @SQL




















GO

