/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 15-12-2012
-- Description:	THIS PROCEDURE USED FOR LOT FINAL JOB CARD REPORT
-- ReportName: LOTFINALJOBCARD.RPT
-- =============================================
PROC_LOTFINALJOBCARD 10,'ACC2010_2011.DBO.',929,929
*/
CREATE PROCEDURE [dbo].[PROC_LOTFINALJOBCARD]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@FROMLOTNO   NVARCHAR(20),
	@TOLOTNO	 NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = ""
BEGIN
	SET NOCOUNT ON;

    SET @SQL = " 
SELECT FTD.SRNO,CONVERT(NVARCHAR,FTD.LOTNO) AS LOTNO,FTD.GRAYMETER,FTD.FINISHMETER,FTD.SHORTMTR,
IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS WEAVER
FROM "+@DATABASENAME+" FTGDETAIL FTD
INNER JOIN "+@DATABASENAME+" FINISH2GODOWN F2G ON F2G.FTGID = FTD.FTGID AND F2G.CMP_CODE = FTD.CMP_CODE
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON F2G.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" WEAVER_MASTER WM ON F2G.WEAVER_ID = WM.WEAVER_ID
WHERE F2G.LOTNO BETWEEN "+@FROMLOTNO+" AND "+@TOLOTNO+"
AND F2G.CMP_CODE IN ( "+@CMP_CODE+" )
ORDER BY FTD.LOTNO,FTD.SRNO "

END
EXECUTE SP_EXECUTESQL @SQL
print @SQL




















GO

