/* PROC_LOTISSUEREG '10','ACC2010_2011.DBO.','01/APR/2010','16/FEB/2011',1,1,''
*/
CREATE PROCEDURE [dbo].[PROC_LOTISSUEREG_SUMMARY]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @RPT_TYPE INT,
   @RPT_WISE INT,
   @TEMPTABLE NVARCHAR(20)
 )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(2000)
DECLARE @MAINSQL AS NVARCHAR(1000)
DECLARE @SECONDSQL AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @MAINSQL=""
SET @SECONDSQL=""






BEGIN


  IF  @RPT_TYPE =1 
     BEGIN
		 SET @SQL="
				   SELECT IM.ITEM_NAME AS MAINGROUP,LA.VCHDATE,LA.LOTNO,IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS VIEWER,LA.TOTALTHAN AS THAN,LA.TOTALMETER AS METER
				   ,IM.ITEM_NAME AS PROCESS,IM.ITEM_NAME AS PARTY,LA.LOTNO AS GATEPASSNO,LA.LOTNO AS PARTYGPASSNO,CMP.CMP_ALIAS
				   FROM "+@DATABASENAME +"LOTALLOCATION LA
                   INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LA.LOTNO
				   INNER JOIN "+@DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID
				   INNER JOIN "+@DATABASENAME +"WEAVER_MASTER WM ON WM.WEAVER_ID=LA.WEAVER_ID
                   LEFT JOIN "+@DATABASENAME +"COMPANY_MASTER CMP ON CMP.CMP_CODE=LA.CMP_CODE
                   WHERE LA.CMP_CODE IN("+@CMP_CODE +") AND LA.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                   ORDER BY LA.VCHDATE,LA.LOTNO
				"	
      END
   ELSE IF  @RPT_TYPE =2
        BEGIN
				BEGIN   
                       IF @RPT_WISE=1 
                           BEGIN                 
				             SET @JOINSQL="INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
                             SET @MAINSQL="LM.LGR_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
                       ELSE IF @RPT_WISE=2 
                           BEGIN                 
				             SET @JOINSQL="INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
                             SET @MAINSQL="IM.ITEM_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
                       ELSE IF @RPT_WISE=3
                           BEGIN                 
				             SET @JOINSQL="INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=WM.WEAVER_ID"
                             SET @MAINSQL="WM.WEAVER_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
                       ELSE IF @RPT_WISE=4
                           BEGIN                 
				             SET @JOINSQL="INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=PM.PROCESS_ID"
                             SET @MAINSQL="PM.PROCESS_NAME AS MAINGROUP"
                             SET @SECONDSQL="LM.LGR_NAME AS SECONDGROUP"
                           END
                      ELSE IF @RPT_WISE=5
                           BEGIN                 
				             SET @JOINSQL=" INNER JOIN "+@DATABASENAME +" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                                           INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
                             SET @MAINSQL="IGM.ITEM_GRP_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
                      ELSE IF @RPT_WISE=6
                           BEGIN                 
				             SET @JOINSQL=" INNER JOIN "+@DATABASENAME +" ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
                                           INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
                             SET @MAINSQL="ITM.ITEM_TYPE_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
                     ELSE IF @RPT_WISE=7
                           BEGIN                 
				             SET @JOINSQL=" INNER JOIN "+@DATABASENAME +" SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID
                                           INNER JOIN " +@TEMPTABLE +" TT ON TT.CODE=SGM.SUPP_GRP_ID"
                             SET @MAINSQL="SGM.SUPP_GRP_NAME AS MAINGROUP"
                             SET @SECONDSQL="PM.PROCESS_NAME AS SECONDGROUP"
                           END
				END
				 SET @SQL="SELECT MAINGROUP,SECONDGROUP,SUM(THAN) AS THAN,SUM(METER) AS METER FROM (
						   SELECT  "+@MAINSQL+","+@SECONDSQL+",PIN.DELTHAN AS THAN,PIN.DELMETER AS METER
						   ,CMP.CMP_ALIAS
						   FROM "+@DATABASENAME +"PROCESSIN PIN
						   INNER JOIN "+@DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=PIN.ITEM_ID
						   LEFT JOIN "+@DATABASENAME +"WEAVER_MASTER WM ON WM.WEAVER_ID=PIN.WEAVER_ID
						   INNER JOIN "+@DATABASENAME +"PROCESS_MASTER PM ON PM.PROCESS_ID=PIN.IN_PROCESS_ID
						   INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PIN.IN_LGR_ID
                           LEFT JOIN "+@DATABASENAME +"COMPANY_MASTER CMP ON CMP.CMP_CODE=PIN.CMP_CODE
                           "+@JOINSQL+"
                           WHERE PIN.CMP_CODE IN("+@CMP_CODE +") AND PIN.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                           ) AS DETAIL GROUP BY MAINGROUP,SECONDGROUP ORDER BY MAINGROUP,SECONDGROUP
                           
				   "
        END




END

EXEC (@SQL)

PRINT @SQL




















GO

