-- =============================================
-- Author:		<SUMIT>
-- Create_date: <23/OCT/2013>
-- Description:	<SP USED FOR LOTMISTAKESUMMARY REPORT>
-- REPORTNAME : LOTMISTAKESUMMARYREPORT.RPT
-- PROC_LOTMISTAKESUMMARY 1,'01/APR/2012','31/MAR/2013','ACC2012_2013.DBO.',2,'##804',1
-- =============================================
CREATE PROCEDURE [dbo].[PROC_LOTMISTAKESUMMARY]
(
	@CMP_CODE NVARCHAR(20),
	@FROMDATE NVARCHAR(20),
	@TODATE NVARCHAR(20),
	@DATABASENAME NVARCHAR(20),
	@PROCESSID NVARCHAR(20),
	@TEMPTABLE NVARCHAR(20),
	@RPTTYPE INT
)
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @SQL1 NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(400)

SET @SQL=""
SET @SQL1=""
SET @JOINSQL=""

BEGIN
		IF @RPTTYPE = 1 
			BEGIN 
				SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID"
			END
END

BEGIN
	SET @SQL="
		SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTYCITY,LMM.LOTNO AS LOTNO,LMD.MISTAKE_THAN AS THAN,
		'NORMAL THAN' AS CATEGORY,LMD.REMARK AS REMARK,COM.CMP_ALIAS AS ALIAS,
		PM.PROCESS_NAME AS PROCESS
		FROM "+@DATABASENAME+" LOTMISTAKE_MASTER LMM 
		INNER JOIN "+@DATABASENAME+" LOTMISTAKE_DETAIL LMD ON LMD.LOTMISTAKE_ID = LMM.LOTMISTAKE_ID AND LMD.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = LMD.LGR_ID
		LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER COM ON COM.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID= LMD.PROCESS_ID
		"+@JOINSQL+"
		WHERE LMM.CMP_CODE IN ("+@CMP_CODE+") AND LMM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND 
		LMD.PROCESS_ID= "+@PROCESSID+" and LMD.MISTAKE_THAN >0
		

		UNION ALL

		SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTYCITY,LMM.LOTNO AS LOTNO,LMD.DAMAGE_THAN AS THAN,
		'DAMAGE THAN' AS CATEGORY,LMD.REMARK AS REMARK,COM.CMP_ALIAS AS ALIAS,
		PM.PROCESS_NAME AS PROCESS
		FROM "+@DATABASENAME+" LOTMISTAKE_MASTER LMM 
		INNER JOIN "+@DATABASENAME+" LOTMISTAKE_DETAIL LMD ON LMD.LOTMISTAKE_ID = LMM.LOTMISTAKE_ID AND LMD.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = LMD.LGR_ID
		LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER COM ON COM.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID= LMD.PROCESS_ID
		"+@JOINSQL+"
		WHERE LMM.CMP_CODE IN ("+@CMP_CODE+") AND LMM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND 
		LMD.PROCESS_ID= "+@PROCESSID+" and LMD.DAMAGE_THAN >0
		
"
SET @SQL1="
		UNION ALL

		SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTYCITY,LMM.LOTNO AS LOTNO,LMD.OVER_THAN AS THAN,
		'OVER THAN' AS CATEGORY,LMD.REMARK AS REMARK,COM.CMP_ALIAS AS ALIAS,
		PM.PROCESS_NAME AS PROCESS
		FROM "+@DATABASENAME+" LOTMISTAKE_MASTER LMM 
		INNER JOIN "+@DATABASENAME+" LOTMISTAKE_DETAIL LMD ON LMD.LOTMISTAKE_ID = LMM.LOTMISTAKE_ID AND LMD.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = LMD.LGR_ID
		LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
		INNER JOIN "+@DATABASENAME+" COMPANY_MASTER COM ON COM.CMP_CODE = LMM.CMP_CODE
		INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID= LMD.PROCESS_ID
		"+@JOINSQL+"
		WHERE LMM.CMP_CODE IN ("+@CMP_CODE+") AND LMM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND 
		LMD.PROCESS_ID= "+@PROCESSID+" and LMD.OVER_THAN>0
		
"
END
PRINT @SQL
PRINT @SQL1
EXEC(@SQL+@SQL1)




















GO

