/*
-- =============================================
-- ALTER_AUTHOR  : PRATIK PATEL
-- ALTER_DATE    : 20/08/2016 11:41 AM
-- REPORT_FORM	  :	RFRMLOTNOENTRYREPORT
-- CRYSTAL_REPORT :	LOTNOENTRYREPORT.rpt
-- =============================================
PROC_LOTNOENTRYREPORT 1,'ACC2016_2017.DBO.','01/apr/2016','31/mar/2017',1,''
*/
CREATE PROCEDURE [dbo].[PROC_LOTNOENTRYREPORT]
(
@CMP_CODE AS NVARCHAR(10),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(100),
@TODATE AS NVARCHAR(100),
@RPT_WISE AS INT,
@TEMPTABLE NVARCHAR(20)
)
AS
BEGIN

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @ORDERBY AS NVARCHAR(4000)

SET @STRSQL=""
SET @JOINSQL=""
SET @ORDERBY=""

BEGIN 
	IF @RPT_WISE = 1
		BEGIN
		    SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LOT_ID"
		    SET @ORDERBY=" ORDER BY LM.LOT_NAME,DATE,LOTNO"
		END
	ELSE IF @RPT_WISE = 2
		BEGIN
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CM.CONTRACTOR_ID"		
			SET @ORDERBY=" ORDER BY CM.CONTRACTOR_NAME,DATE,LOTNO"
		END
	ELSE
		BEGIN
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GCM.GREYCHECKING_ID"		
			SET @ORDERBY=" ORDER BY GCM.GREYCHECKING_NAME,DATE,LOTNO"
		END
END

SET @STRSQL="SELECT DOCNO,DATE,LRNO,LOTNO,LRDATE,LM.LOT_NAME AS MARKA,CONTRACTOR_NAME AS CONTRACTOR,
GCM.GREYCHECKING_NAME AS CHECKER,LRTHAN AS BILLTHAN,LRMETER AS BILLMETER,RECTHAN,
RECMETER,RETTHAN,RETMETER,ACCTHAN AS ACCEPTTHAN,ACCMETER AS ACCEPTMTR,SHORTMETER,FOLD,NETMETER
FROM "+@DATABASENAME+"LOTNOENTRY LE
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID=LE.LOT_ID
INNER JOIN "+@DATABASENAME+"CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID=LE.CONTRACTOR_ID
INNER JOIN "+@DATABASENAME+"GREYCHECKING_MASTER GCM ON GCM.GREYCHECKING_ID=LE.GREYCHECKING_ID
"+@JOINSQL+"
WHERE LE.CMP_CODE="+@CMP_CODE+" AND DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND LE.LO_FLAG='LE'
"+@ORDERBY+"

"
	
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL
























GO

/****** Object:  StoredProcedure [dbo].[PROC_LOTPENDINGDAYSREPORT]    Script Date: 03/30/2023 12:08:12 ******/
