/* 
PROC_LOTPENDINGDAYSREPORT '1','ACC2012_2013.DBO.',0,'##2096',6,0
*/
CREATE PROCEDURE [dbo].[PROC_LOTPENDINGDAYSREPORT]
 (
     @CMP_CODE AS NVARCHAR(100),
     @DATABASENAME AS NVARCHAR(100),
     @PROCESS_ID AS NVARCHAR(20),
     @TEMPTABLE AS NVARCHAR(20),
     @RPT_WISE AS INT,
     @Days AS NVARCHAR(20)
 )	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @PROCESSSQL AS NVARCHAR(400)
DECLARE @DAYSSQL AS NVARCHAR(400)
DECLARE @DESIGNSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""
SET @PROCESSSQL=""
SET @DAYSSQL=""
SET @DESIGNSQL = ""

BEGIN
       IF @Days!="0"
          SET @DAYSSQL=" WHERE DAYS>="+@Days
END

BEGIN 
  IF @PROCESS_ID!="0"
       SET @PROCESSSQL=" AND PM.PROCESS_ID IN("+@PROCESS_ID+")"
  ELSE
       SET @PROCESSSQL=""
END

BEGIN
     IF @RPT_WISE=1   
         BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"      
         END
     ELSE IF @RPT_WISE=2
         BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"      
         END
     ELSE IF @RPT_WISE=3
         BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LA.LOTNO"      
         END
     ELSE IF @RPT_WISE=4
         BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"      
         END
    ELSE IF @RPT_WISE=5
         BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"      
         END
	ELSE IF @RPT_WISE=6
		BEGIN
			SET @DESIGNSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=DM.DESIGN_ID "
			SET @JOINSQL = ""
		END
END       
 
     

BEGIN              
     SET @SQL="                  
            SELECT LOTNO,DATE,PARTY,ISNULL(CITY,'') AS CITY,ITEM,ITEMGROUP,ITEMTYPE,PROCESS,PROCESSID,
			SUM(PENDINGTHAN) AS PENDINGTHAN,DAYS,CMP_ALIAS,DESIGN
            FROM (

			SELECT P2P.LOTNO,P2P.VCHDATE AS DATE,LM.LGR_NAME  AS PARTY,PCM.CITY_NAME AS CITY,IM.ITEM_NAME AS ITEM,
			IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,PM.PROCESS_NAME AS PROCESS,
			P2P.TO_PROCESS_ID AS PROCESSID,SUM(P2P.PENDINGTHAN) AS PENDINGTHAN,
			DATEDIFF(DAY,LA.VCHDATE,P2P.VCHDATE) AS DAYS,CONVERT(NVARCHAR,DM.DESIGN_NAME) AS DESIGN,
			CMP.CMP_ALIAS

			FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
			INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID
			INNER JOIN "+@DATABASENAME+"LOTALLOCATION LA ON LA.LOTNO=P2P.LOTNO AND LA.CMP_CODE=P2P.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
			LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
			LEFT JOIN "+@DATABASENAME+" DESIGN_MASTER DM ON DM.DESIGN_ID = P2P.DESIGN_ID
            "+@JOINSQL+" "+@DESIGNSQL+"
			WHERE P2P.CMP_CODE IN ("+@CMP_CODE+")
            "+@PROCESSSQL+"
            
			GROUP BY P2P.LOTNO,LM.LGR_NAME ,PCM.CITY_NAME ,IM.ITEM_NAME ,IGM.ITEM_GRP_NAME,
			ITM.ITEM_TYPE_NAME ,LA.VCHDATE,P2P.VCHDATE,PM.PROCESS_NAME,P2P.TO_PROCESS_ID,
			CMP.CMP_ALIAS,DM.DESIGN_NAME
			HAVING SUM(P2P.PENDINGTHAN)>0

			UNION ALL

			SELECT F2F.LOTNO,F2F.VCHDATE,LM.LGR_NAME  AS PARTY,PCM.CITY_NAME AS CITY,IM.ITEM_NAME AS ITEM,
			IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,'FOLDING' AS PROCESS,
			6 AS PROCESSID,SUM(F2F.PENDINGTHAN) AS PENDINGTHAN,DATEDIFF(DAY,LA.VCHDATE,F2F.VCHDATE) AS DAYS,
			'' AS DESIGN,CMP.CMP_ALIAS

			FROM "+@DATABASENAME+"FINISHTOFOLDING F2F
			INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=F2F.PROCESS_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=F2F.LGR_ID
			INNER JOIN "+@DATABASENAME+"LOTALLOCATION LA ON LA.LOTNO=F2F.LOTNO AND LA.CMP_CODE=F2F.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=F2F.ITEM_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
			LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=F2F.CMP_CODE
            "+@JOINSQL+"
            WHERE F2F.CMP_CODE IN ("+@CMP_CODE+")
            "+@PROCESSSQL+"  
          
			GROUP BY F2F.LOTNO,LM.LGR_NAME ,PCM.CITY_NAME ,IM.ITEM_NAME ,IGM.ITEM_GRP_NAME
			,ITM.ITEM_TYPE_NAME ,LA.VCHDATE,F2F.VCHDATE,PM.PROCESS_NAME,F2F.PROCESS_ID,CMP.CMP_ALIAS
			HAVING SUM(F2F.PENDINGTHAN)>0
			) AS DETAIL  "+@DAYSSQL+"

			GROUP BY LOTNO,DATE,PARTY,CITY,ITEM,ITEMGROUP,ITEMTYPE,PROCESS,PROCESSID,DAYS,CMP_ALIAS,DESIGN
            ORDER BY LOTNO,PROCESSID
"
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

