/* 
PROC_LotPendingRateWise 10,'Acc2010_2011.dbo.','01/apr/2010','25/Feb/2011',##2044,3,1,2
*/
CREATE PROCEDURE [dbo].[PROC_LOTPENDINGRATEWISE] 
(
	  @CMP_CODE AS NVARCHAR(100),
	  @DATABASENAME AS NVARCHAR(100),
      @FROMDATE AS NVARCHAR(20),
      @TODATE AS NVARCHAR(20),
      @TEMPTABLE AS NVARCHAR(20),
      @RPT_WISE AS INT,
	  @Rpt_Com_Pen_Lot as INT,
	  @Rpt_Type as INT 	 	
)

AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @LOTSQL AS NVARCHAR(1000)
SET @SQL="" 
SET @JOINSQL="" 
SET @LOTSQL=""

BEGIN	
		/* ItemWise */
		IF @RPT_WISE=1
			BEGIN	
			  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID "
			End
		/* WEAVER wise	 */
        ELSE IF @RPT_WISE=2
			BEGIN
			  SET @JOINSQL=" INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE=WM.WEAVER_ID"
			End
		/* Item Group wise	 */
        ELSE IF @RPT_WISE=3
			BEGIN
			  SET @JOINSQL=" INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE=IGM.Item_Grp_Id"
			End
		/* Item TYPE wise	 */
        ELSE IF @RPT_WISE=4
			BEGIN
			  SET @JOINSQL=" INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE=ITM.Item_Type_Id"
			End

END

BEGIN
		if @Rpt_Com_Pen_Lot=2
			BEGIN
			  SET @LOTSQL=" and LA.TotalThan=LA.PendingThan "
			End
		else if @Rpt_Com_Pen_Lot=1
			BEGIN
			  SET @LOTSQL=" and LA.TotalThan<>LA.PendingThan "
			End
END

BEGIN

	SET NOCOUNT ON;
		if @Rpt_Type=1
			Begin
				set @SQL=" select LA.LotNo,LA.VchDate,LA.PendingThan,LA.PendingMeter,LA.Rate,IM.Item_Name,WM.WEAVER_NAME,ITM.Item_Type_Name,IGM.Item_Grp_Name
					from "+@DATABASENAME+" LotAllocation LA
					inner join "+@DATABASENAME+" FTGRECdetail FTGD on LA.LotNo=FTGD.LotNo and LA.Cmp_Code=FTGD.Cmp_Code
					left join "+@DATABASENAME+" Item_Master IM on LA.Item_Id=IM.Item_Id
					left join "+@DATABASENAME+" WEAVER_MASTER WM on LA.WEAVER_ID=WM.WEAVER_ID
					left join "+@DATABASENAME+" Item_Type_Master ITM on IM.Item_Type_Id=ITM.Item_Type_Id
					left join "+@DATABASENAME+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
					"+@JOINSQL+"
					where LA.Cmp_Code in ("+@CMP_CODE+") and LA.PendingThan>0	"+@LOTSQL+"	"
			
			end
		if @Rpt_Type=2
			Begin
				set @SQL=" select max(LotNo) as LotNo,max(VchDate) as VchDate,sum(PendingThan) as PendingThan,sum(PendingMeter) as PendingMeter,(SUM(AMOUNT)/sum(PendingMeter)) as rate ,Item_Name,WEAVER_NAME,Item_Type_Name,Item_Grp_Name
							from (
									select 0 as LotNo,max(LA.VchDate) as VchDate,sum(LA.PendingThan) as PendingThan,sum(LA.PendingMeter) as PendingMeter,LA.Rate as Rate,
                                    (sum(LA.PendingMeter)*LA.Rate) AS AMOUNT,
                                    IM.Item_Name,WM.WEAVER_NAME,ITM.Item_Type_Name,IGM.Item_Grp_Name
									from "+@DATABASENAME+" LotAllocation LA
									inner join "+@DATABASENAME+" FTGRECdetail FTGD on LA.LotNo=FTGD.LotNo and LA.Cmp_Code=FTGD.Cmp_Code
									left join "+@DATABASENAME+" Item_Master IM on LA.Item_Id=IM.Item_Id
									left join "+@DATABASENAME+" WEAVER_MASTER WM on LA.WEAVER_ID=WM.WEAVER_ID
									left join "+@DATABASENAME+" Item_Type_Master ITM on IM.Item_Type_Id=ITM.Item_Type_Id
									left join "+@DATABASENAME+" Item_Group_Master IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
									"+@JOINSQL+"
									where LA.Cmp_Code in ("+@CMP_CODE+") and LA.PendingThan>0 "+@LOTSQL+"
									Group by Item_Name,Item_Type_Name,WEAVER_NAME,IGM.Item_Grp_Name,LA.Rate
								  ) as A
								Group by Item_Name,WEAVER_NAME,Item_Type_Name,Item_Grp_Name
						"
					end
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

