/* PROC_LOTPROCESSDETIL '2','ACC2010_2011.DBO.'
*/
CREATE PROCEDURE [dbo].[PROC_LOTPROCESSDETIL]
(
  @CMP_CODE NVARCHAR(100),
  @DATABASENAME NVARCHAR(100)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @LOTNO AS NVARCHAR(20)
DECLARE @CURRLOTNO AS NVARCHAR(20)
DECLARE @PREVLOTNO AS NVARCHAR(20)
DECLARE @LOTDATE AS NVARCHAR(20)
DECLARE @ITEM AS NVARCHAR(500)
DECLARE @VIEWER AS NVARCHAR(500)
DECLARE @PROCESS_ID AS NVARCHAR(20)
DECLARE @PROCESS AS NVARCHAR(500)
DECLARE @ISSUEDATE AS NVARCHAR(20)
DECLARE @PARTY AS NVARCHAR(500)
DECLARE @GPASSNO AS NVARCHAR(20)
DECLARE @THAN AS NVARCHAR(20)
BEGIN  

SET NOCOUNT ON;
    /*  --TO DROP AND ALTER TABLE */
     BEGIN
        SET @SQL=""
        SET @SQL="DROP TABLE LOTREGISTERTABLE"
        EXEC(@SQL)
        SET @SQL="ALTER TABLE LOTREGISTERTABLE(MAINGROUP NVARCHAR(500),LOTNO INT,LOTDATE NVARCHAR(20),ITEM NVARCHAR(500),VIEWER NVARCHAR(500)
                  ,P1DATE NVARCHAR(500),P1PARTY NVARCHAR(500),P1GPASS INT,P1THAN INT
                  ,P2DATE NVARCHAR(500),P2PARTY NVARCHAR(500),P2GPASS INT,P2THAN INT
                  ,P3DATE NVARCHAR(500),P3PARTY NVARCHAR(500),P3GPASS INT,P3THAN INT
                  ,P4DATE NVARCHAR(500),P4PARTY NVARCHAR(500),P4GPASS INT,P4THAN INT
                  ,P5DATE NVARCHAR(500),P5PARTY NVARCHAR(500),P5GPASS INT,P5THAN INT
                  ,P6DATE NVARCHAR(500),P6PARTY NVARCHAR(500),P6GPASS INT,P6THAN INT)"
        EXEC(@SQL)        
    END 

      BEGIN /*  MAIN QRY */
       SET @SQL="  DECLARE FIRSTCUR CURSOR  FOR 
                   SELECT LA.LOTNO ,CONVERT(NVARCHAR,LA.VCHDATE,103) AS LOTDATE ,IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS WEAVER
                         ,PIN.IN_PROCESS_ID AS PROCESS_ID ,PM.PROCESS_NAME AS PROCESS,PIN.VCHDATE AS ISSUDATE,LM.LGR_NAME AS PARTY,PIN.PARTYGPASSNO,PIN.DELTHAN
                         FROM "+@DATABASENAME+"LOTALLOCATION LA
                         INNER JOIN "+@DATABASENAME+"PROCESSIN PIN ON PIN.LOTNO=LA.LOTNO
                         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PIN.ITEM_ID
                         INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=PIN.WEAVER_ID
                         INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=PIN.IN_PROCESS_ID
                         INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PIN.IN_LGR_ID                         
                         ORDER BY LA.LOTNO,PIN.IN_PROCESS_ID "
                    
        EXEC(@SQL)
        OPEN FIRSTCUR        
        FETCH NEXT FROM  FIRSTCUR INTO @LOTNO,@LOTDATE,@ITEM,@VIEWER,@PROCESS_ID,@PROCESS,@ISSUEDATE,@PARTY,@GPASSNO,@THAN
         WHILE @@FETCH_STATUS=0
          BEGIN                
               if @PROCESS_ID=2
                  BEGIN                       
                      SET @SQL="INSERT INTO LOTREGISTERTABLE(MAINGROUP,LOTNO,LOTDATE,ITEM,VIEWER,P1DATE,P1PARTY,P1GPASS,P1THAN)VALUES('',"+@LOTNO+",'"+@LOTDATE+"','"+@ITEM+"','"+@VIEWER+"'
                               ,'"+@ISSUEDATE+"','"+@PARTY+"','"+@GPASSNO+"','"+@THAN+"')"                      
                      EXEC(@SQL)
                  END
              ELSE IF @PROCESS_ID=3
                  BEGIN                       
                      SET @SQL="INSERT INTO LOTREGISTERTABLE(MAINGROUP,LOTNO,LOTDATE,ITEM,VIEWER,P2DATE,P2PARTY,P2GPASS,P2THAN)VALUES('',"+@LOTNO+",'"+@LOTDATE+"','"+@ITEM+"','"+@VIEWER+"'
                               ,'"+@ISSUEDATE+"','"+@PARTY+"','"+@GPASSNO+"','"+@THAN+"')"                      
                      EXEC(@SQL)
                  END
             ELSE IF @PROCESS_ID=4
                  BEGIN                       
                      SET @SQL="INSERT INTO LOTREGISTERTABLE(MAINGROUP,LOTNO,LOTDATE,ITEM,VIEWER,P3DATE,P3PARTY,P3GPASS,P3THAN)VALUES('',"+@LOTNO+",'"+@LOTDATE+"','"+@ITEM+"','"+@VIEWER+"'
                               ,'"+@ISSUEDATE+"','"+@PARTY+"','"+@GPASSNO+"','"+@THAN+"')"                      
                      EXEC(@SQL)
                  END
             ELSE IF @PROCESS_ID=5
                  BEGIN                       
                      SET @SQL="INSERT INTO LOTREGISTERTABLE(MAINGROUP,LOTNO,LOTDATE,ITEM,VIEWER,P4DATE,P4PARTY,P4GPASS,P4THAN)VALUES('',"+@LOTNO+",'"+@LOTDATE+"','"+@ITEM+"','"+@VIEWER+"'
                               ,'"+@ISSUEDATE+"','"+@PARTY+"','"+@GPASSNO+"','"+@THAN+"')"                      
                      EXEC(@SQL)
                  END
               FETCH NEXT FROM  FIRSTCUR INTO @LOTNO,@LOTDATE,@ITEM,@VIEWER,@PROCESS_ID,@PROCESS,@ISSUEDATE,@PARTY,@GPASSNO,@THAN
          END 
             DEALLOCATE FIRSTCUR
        
     END

SET @SQL="SELECT * FROM LOTREGISTERTABLE"
EXEC(@SQL)
PRINT @SQL

END




















GO

