CREATE PROCEDURE [dbo].[PROC_LOTREGISTER]
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMLOTNO NVARCHAR(10),
@TOLOTNO NVARCHAR(10)
AS

DECLARE @SQL AS NVARCHAR(4000)

BEGIN
	
SET @SQL=""
	SET NOCOUNT ON;
SET @SQL="
           SELECT LA.LOTNO ,LA.VCHDATE,LA.SHORTMETER,LBD.BALEID,LBQD.METERQTY,WM.WEAVER_NAME AS VIEWER,IM.ITEM_NAME AS ITEM,
           LM.LGR_NAME AS PARTY,LA.[READ],LA.WIDTH,LA.TOTALTHAN,LA.PEAK,LA.WEIGHT,LA.TOTALMETER,LA.GADDY,LA.SSTTHAN,
           PI.BILLNO,PI.VCHDATE AS BILLDATE
           FROM "+ @DATABASENAME + " LOTALLOCATION LA 
           INNER JOIN "+ @DATABASENAME + " WEAVER_MASTER WM ON WM.WEAVER_ID=LA.WEAVER_ID
           INNER JOIN "+ @DATABASENAME + " ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID
           LEFT JOIN "+ @DATABASENAME + " LOTBALEDETAIL LBD ON LBD.LOTALLOCID=LA.LOTALLOCID
           LEFT JOIN "+ @DATABASENAME + " LOTBALEQTYDETAIL LBQD ON LBQD.LOTALLOCID=LA.LOTALLOCID
           LEFT JOIN "+ @DATABASENAME + " PURCHASEINVOICE PI ON  PI.LOTNO=LA.LOTNO AND PI.CMP_CODE=LA.CMP_CODE
           LEFT JOIN "+ @DATABASENAME + " LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
           WHERE LA.LOTNO BETWEEN "+ @FROMLOTNO + " AND "+ @TOLOTNO +  "AND LA.CMP_CODE="+ @CMP_CODE +" ORDER BY LA.LOTNO"


EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

