/*  
PROC_LOTSHORT '1','ACC2010_2011.DBO.','01/APR/2010','01/MAR/2011',1,1,2,##3324
*/
CREATE PROCEDURE [dbo].[PROC_LOTSHORT] 
( 
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS  NVARCHAR(100),
@FROMDATE AS  NVARCHAR(20),
@TODATE AS  NVARCHAR(20),
@CONDITION_WISE AS INT,
@RPT_WISE AS INT,  
@RPT_TYPE AS INT,
@TEMPTABLE AS NVARCHAR(50)
)
	
AS
DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL = ""
DECLARE @STRCONDSQL AS NVARCHAR(1000) SET @STRCONDSQL = ""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""

BEGIN
	IF @CONDITION_WISE=1 
	 SET @STRCONDSQL ="WHERE (BILLMTRS-READMTRS)>0"
	ELSE IF @CONDITION_WISE=2
	 SET @STRCONDSQL ="WHERE (BILLMTRS-READMTRS)<0"
	ELSE IF @CONDITION_WISE=3
	 SET @STRCONDSQL =" WHERE (BILLMTRS-READMTRS)<>0"
	ELSE IF @CONDITION_WISE=4
	 SET @STRCONDSQL =""
END

BEGIN
	IF @RPT_WISE=1 
	 SET @JOIN=" LEFT JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
	ELSE IF @RPT_WISE=2
	 SET @JOIN=" LEFT JOIN "+@TEMPTABLE+" TT ON TT.CODE=SGM.SUPP_GRP_ID"
END

BEGIN
IF @RPT_TYPE = 1
	BEGIN
		SET @STRSQL="
		SELECT DETAIL.LOTNO,DETAIL.DATE,DETAIL.ITEM_NAME,DETAIL.BILLMTRS,DETAIL.READMTRS ,(BILLMTRS-READMTRS) AS SHORTAGE,CMP_ALIAS,RATE,
        LGR_NAME,SUPP_GRP_NAME
		FROM(		 
		SELECT LA.LOTNO,LA.VCHDATE AS DATE,IM.ITEM_NAME,LA.TOTALMETER AS  BILLMTRS,ISNULL(SUM(LBD.METERQTY),0) AS READMTRS 
		,CMP.CMP_ALIAS,RATE,LGR_NAME,SUPP_GRP_NAME
		FROM "+@DATABASENAME+"LOTALLOCATION LA
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID
		LEFT JOIN "+@DATABASENAME+"LOTBALEQTYDETAIL LBD ON LA.LOTALLOCID=LBD.LOTALLOCID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LA.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.LOTNO=LA.LOTNO AND PI.CMP_CODE=LA.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.Supp_Grp_Id = PI.Supp_Grp_Id
		INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON LM.Lgr_Id=PI.Lgr_Id
		"+@JOIN+"
		WHERE  LA.CMP_CODE IN ("+@CMP_CODE+")	AND LA.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'	          

		GROUP BY LA.LOTNO,LA.VCHDATE,IM.ITEM_NAME ,LA.TOTALMETER,CMP.CMP_ALIAS,LA.RATE,LM.LGR_NAME,SGM.SUPP_GRP_NAME
		)  AS DETAIL                
		"+@STRCONDSQL+" ORDER BY  DATE,LOTNO
		"	
	END
ELSE IF @RPT_TYPE = 2
	BEGIN 
SET @STRSQL="
	SELECT MAX(FINAL.LOTNO) AS LOTNO,MAX(FINAL.DATE) AS DATE,FINAL.ITEM_NAME,SUM(FINAL.BILLMTRS) AS BILLMTRS,SUM(FINAL.READMTRS) AS READMTRS,(BILLMTRS-READMTRS) AS SHORTAGE,CMP_ALIAS,MAX(RATE) AS RATE,
        SHORTAGE*RATE as AMOUNT,LGR_NAME,SUPP_GRP_NAME
		FROM(
		SELECT DETAIL.LOTNO,DETAIL.DATE,DETAIL.ITEM_NAME,DETAIL.BILLMTRS,DETAIL.READMTRS ,(BILLMTRS-READMTRS) AS SHORTAGE,CMP_ALIAS,RATE,
        LGR_NAME,SUPP_GRP_NAME
		FROM(		 
		SELECT LA.LOTNO,LA.VCHDATE AS DATE,IM.ITEM_NAME,LA.TOTALMETER AS  BILLMTRS,ISNULL(SUM(LBD.METERQTY),0) AS READMTRS 
		,CMP.CMP_ALIAS,RATE,LGR_NAME,SUPP_GRP_NAME
		FROM "+@DATABASENAME+"LOTALLOCATION LA
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=LA.ITEM_ID
		LEFT JOIN "+@DATABASENAME+"LOTBALEQTYDETAIL LBD ON LA.LOTALLOCID=LBD.LOTALLOCID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LA.CMP_CODE
		LEFT JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.LOTNO=LA.LOTNO AND PI.CMP_CODE=LA.CMP_CODE
		LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.Supp_Grp_Id = PI.Supp_Grp_Id
		INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON LM.Lgr_Id=PI.Lgr_Id
		"+@JOIN+"
		WHERE  LA.CMP_CODE IN ("+@CMP_CODE+")	AND LA.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'	          

		GROUP BY LA.LOTNO,LA.VCHDATE,IM.ITEM_NAME ,LA.TOTALMETER,CMP.CMP_ALIAS,LA.RATE,LM.LGR_NAME,SGM.SUPP_GRP_NAME
		)  AS DETAIL ) AS FINAL  
        "+@STRCONDSQL+" GROUP BY FINAL.ITEM_NAME,FINAL.BILLMTRS,FINAL.READMTRS,FINAL.CMP_ALIAS,FINAL.LGR_NAME,FINAL.SUPP_GRP_NAME,
		FINAL.RATE,FINAL.SHORTAGE        
		"	
	END
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

