/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 26/09/2013
-- Description:	THIS PROCEDURE USED FOR LRISSUE DATA
-- ReportName : LRISSUE_PRINT.RPT
-- =============================================
PROC_LRISSUE_PRINT 1,'ACC2012_2013.DBO.',1,4
*/
CREATE PROCEDURE [dbo].[PROC_LRISSUE_PRINT]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@FROMDOCNO NVARCHAR(50),
	@TODOCNO NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = " SELECT LIM.DOCNO,LIM.VCH_DATE,LORM.LORIWALA_NAME AS LORIWALANAME,
			 LID.SRNO,LID.LRNO,LID.LRDATE,LID.BILLNO,LID.BALENO,IM.ITEM_NAME AS ITEM,LM.LGR_NAME AS PARTY,
			 LID.BALES,LID.PIECES,LID.METERS,LIM.TOTALBALES,LIM.TOTALPIECES,LIM.TOTALMETERS,TM.TRANSPORT_NAME AS TRANSPORT,
			 CMP.CMP_ALIAS
			 
			 FROM  "+@DATABASENAME+" LRISSUE_DETAIL LID
			 INNER JOIN "+@DATABASENAME+" LRISSUE_MASTER LIM ON LIM.LRISSUEID = LID.LRISSUEID AND LIM.CMP_CODE = LID.CMP_CODE
			 INNER JOIN "+@DATABASENAME+" LORIWALA_MASTER LORM ON LORM.LORIWALA_ID = LIM.LORIWALA_ID
			 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = LID.ITEM_ID
			 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = LID.LGR_ID
			 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = LID.TRANSPORT_ID 
			 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = LIM.CMP_CODE
			 WHERE LIM.DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
			 AND LIM.CMP_CODE IN ("+@CMP_CODE+")
			 ORDER BY LIM.DOCNO,LID.SRNO "
BEGIN
	SET NOCOUNT ON;
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















