/*
-- =============================================
-- Author:		<PRATIK PATEL>
-- Create_date: <21/05/2013>
-- ReportName :	<PURCHASE_LR_ISSUE_PENDING_REPORT>
-- =============================================
PROC_LRISSUEPENDINGREPORT 1,'ACC2012_2013.dbo.','31/MAR/2013',1,##3584
*/
CREATE PROCEDURE [dbo].[PROC_LRISSUEPENDINGREPORT]
(
    @CMP_CODE NVARCHAR(50),
    @DATABASENAME NVARCHAR(50),
    @TODATE  NVARCHAR(50),
    @RPTTYPE INT,
    @TEMPTABLE NVARCHAR(50)
)
AS

		Declare @StrSql as nvarchar(4000)
		Declare @SqlJoin as nvarchar(4000)

		set @StrSql = ""
		set @SqlJoin = ""

BEGIN
	if @RPTTYPE = 1 or @RPTTYPE = 4                                  --PARTY
			begin
				set @SqlJoin = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID"
			end
		else if @RPTTYPE = 2             --AGENT
			begin
				set @SqlJoin = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IM.ITEM_ID"
			end
		else if @RPTTYPE = 3 or @RPTTYPE = 5 or @RPTTYPE = 6             --TRANSPORT
			begin
				set @SqlJoin = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TM.TRANSPORT_ID"
			end
END
BEGIN
	SET NOCOUNT ON;
         set @StrSql = "SELECT PI.LRNO,PI.BILLNO,PID.BALENO,IM.ITEM_NAME,PID.ITEM_ID,LM.LGR_NAME AS PARTY,PI.LGR_ID,PID.BALES,
						PID.PIECES,PID.QUANTITY,TM.TRANSPORT_NAME,PI.TRANSPORT_ID,PI.PURCHASEINVID,0 AS FLAG,0 AS INUSED
						FROM "+@DATABASENAME+"PURCHASEINVOICE PI
						INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
						INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
						INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON PI.LGR_ID=LM.LGR_ID
						INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID 
                        "+@SqlJoin+"
						WHERE PI.VCHDATE <= '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE+" AND PI.FLAG='P'
						AND ISNULL(PI.LRNO,'') <>'' AND ISNULL(LRISSUE,0)=0 "
    
END
PRINT @StrSql
execute Sp_Executesql @StrSql




















GO

