/*
-- =============================================
-- AUTHOR:		<PRATIK PATEL>
-- ALTER_DATE: <21/05/2013>
-- REPORTNAME :	<PLR_ISSUE_REGISTER.RPT>
-- REPORTFORM :	<RFRMLRISSUEREGISTRE>
-- =============================================
PROC_LRISSUEREGISTER 1,'ACC2013_2014.DBO.','01/APR/2013','31/MAR/2014',1,1,'##4664'
*/
CREATE PROCEDURE [dbo].[PROC_LRISSUEREGISTER]
(
    @CMP_CODE NVARCHAR(50),
    @DATABASENAME NVARCHAR(50),
    @FROMDATE  NVARCHAR(50),
    @TODATE  NVARCHAR(50),
    @RPTTYPE INT,
    @REPOTTYPE INT,
    @TEMPTABLE NVARCHAR(50)
)
AS

		DECLARE @STRSQL AS NVARCHAR(4000)
		DECLARE @SQLJOIN AS NVARCHAR(4000)

		SET @STRSQL = ""
		SET @SQLJOIN = ""

BEGIN
	IF @RPTTYPE = 1 OR @RPTTYPE = 3  OR @RPTTYPE = 4 OR @RPTTYPE = 5 /*LORIWALA*/
			BEGIN
				SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LORIWALA_ID"
			END
		ELSE IF @RPTTYPE = 2 OR @RPTTYPE = 6            /*TRANSPORT*/
			BEGIN
				SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TM.TRANSPORT_ID"
			END
		ELSE IF @RPTTYPE = 7            /*DOCNO*/
			BEGIN
				SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LIM.DOCNO"
			END
END
BEGIN
	SET NOCOUNT ON;
       IF @REPOTTYPE=1
         SET @STRSQL = "SELECT SRNO,LRNO,BILLNO,BALENO,ITEM_NAME,LID.ITEM_ID,LEM.LGR_NAME AS PARTY,
						LID.LGR_ID,BALES,PIECES,METERS,TM.TRANSPORT_NAME,LID.TRANSPORT_ID,LIM.LRISSUEID,
						DOCNO,VCH_DATE,LORIWALA_NAME AS LORIWALANAME,
						CONVERT(NVARCHAR,LID.LRDATE,103) AS LRDATE
						FROM "+@DATABASENAME+"LRISSUE_MASTER LIM
						INNER JOIN "+@DATABASENAME+"LORIWALA_MASTER LM ON LM.LORIWALA_ID=LIM.LORIWALA_ID
						INNER JOIN "+@DATABASENAME+"LRISSUE_DETAIL LID ON LID.LRISSUEID=LIM.LRISSUEID
						INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = LID.ITEM_ID
						INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LEM ON LEM.LGR_ID=LID.LGR_ID
						INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=LID.TRANSPORT_ID  
                        "+@SQLJOIN+"
						WHERE VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
                        AND LIM.CMP_CODE="+@CMP_CODE+"
						"
       ELSE IF @REPOTTYPE=2
         SET @STRSQL = "SELECT SRNO,LRNO,BILLNO,BALENO,ITEM_NAME,LID.ITEM_ID,LEM.LGR_NAME AS PARTY,
						LID.LGR_ID,BALES,PIECES,METERS,TM.TRANSPORT_NAME,LID.TRANSPORT_ID,LIM.LRRECEIPTID,
						DOCNO,VCH_DATE,LORIWALA_NAME AS LORIWALANAME,
						CONVERT(NVARCHAR,LID.LRDATE,103) AS LRDATE
						FROM "+@DATABASENAME+"LRRECEIPT_MASTER LIM
						INNER JOIN "+@DATABASENAME+"LORIWALA_MASTER LM ON LM.LORIWALA_ID=LIM.LORIWALA_ID
						INNER JOIN "+@DATABASENAME+"LRRECEIPT_DETAIL LID ON LID.LRRECEIPTID=LIM.LRRECEIPTID
						INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = LID.ITEM_ID
						INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LEM ON LEM.LGR_ID=LID.LGR_ID
						INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=LID.TRANSPORT_ID  
						"+@SQLJOIN+"
						WHERE VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
						AND LIM.CMP_CODE="+@CMP_CODE+"
						"
       ELSE IF @REPOTTYPE=3
         SET @STRSQL = "SELECT SRNO,LRNO,BILLNO,BALENO,ITEM_NAME,LID.ITEM_ID,LEM.LGR_NAME AS PARTY,
						LID.LGR_ID,BALES,PIECES,METERS,TM.TRANSPORT_NAME,LID.TRANSPORT_ID,LIM.LRISSUEID,
						DOCNO,VCH_DATE,LORIWALA_NAME AS LORIWALANAME,
						CONVERT(NVARCHAR,LID.LRDATE,103) AS LRDATE
						FROM "+@DATABASENAME+"LRISSUE_MASTER LIM
						INNER JOIN "+@DATABASENAME+"LORIWALA_MASTER LM ON LM.LORIWALA_ID=LIM.LORIWALA_ID
						INNER JOIN "+@DATABASENAME+"LRISSUE_DETAIL LID ON LID.LRISSUEID=LIM.LRISSUEID
						INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = LID.ITEM_ID
						INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LEM ON LEM.LGR_ID=LID.LGR_ID
						INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=LID.TRANSPORT_ID  
                        "+@SQLJOIN+"
						WHERE VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
                        AND LIM.CMP_CODE="+@CMP_CODE+"  AND LRRECEIPT=0 
						"
    
END
PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_LRPENDING]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/*  
PROC_LRPENDING '2','ACC2015_2016.DBO.','01/APR/2015','01/APR/2016','##5724',1,1
*/
CREATE PROCEDURE [dbo].[PROC_LRPENDING]
(
@CMP_CODE NVARCHAR(20),
@DATABASENAME NVARCHAR(50),
@FROMDATE NVARCHAR(20), 
@TODATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@RPTWISE INT,
@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @SQLCON AS NVARCHAR(1000)
DECLARE @SQLORDER AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @SQLCON = ""
SET @SQLORDER = ""


BEGIN
IF @RPTTYPE = 1 /* PAID */
SET @SQLCON = " AND SAL_INV_LRNO <> '' "
ELSE IF @RPTTYPE = 2 /* PENDING */
SET @SQLCON = " AND (SAL_INV_LRNO = '' OR SAL_INV_LRNO = '0' OR SAL_INV_LRNO = NULL) "
ELSE
SET @SQLCON = ""
END

BEGIN
IF @RPTWISE = 1 
SET @JOINSQL = " INNER JOIN " + @TempTable + " TT ON TM.TRANSPORT_ID=TT.CODE"
ELSE IF @RPTWISE = 2 
SET @JOINSQL = ""
END


BEGIN

SET NOCOUNT ON;

SET @SQL=" SELECT DISTINCT SI.SAL_INV_BILL_NO,SI.SAL_INV_VDATE,LM.LGR_NAME,CM.CITY_NAME,SID.SERIALNO AS SAL_INV_BALENO,
SM.SCREEN_NAME,SI.SAL_INV_NETTOTAL AS AMOUNT,TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANSPORT_ID,ISNULL(COMP.CMP_ALIAS,'') AS CMP_ALIAS
FROM "+@DATABASENAME+" SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
LEFT JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.CMP_CODE=SI.CMP_CODE AND SID.FLAG=SI.FLAG	
LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL+"
WHERE SI.CMP_CODE IN (" + @CMP_CODE + ") "+@SQLCON+"
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' 
ORDER BY TM.TRANSPORT_NAME,TM.TRANSPORT_ID,SI.SAL_INV_VDATE,SI.SAL_INV_BILL_NO
" 

END

EXECUTE SP_EXECUTESQL @SQL

















GO

