CREATE PROCEDURE [dbo].[PROC_LRTOBESENT]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
	@Criteria as int
    
)
as
declare @Sql  Nvarchar(4000)

begin
    	SET NOCOUNT ON;
        set @sql=" 
				Select SIM.Sal_Inv_Vdate,SIM.Sal_Inv_Bill_No,PLM.Lgr_Name As PartyName,PCM.City_Name As PartyCity,
				SIM.Sal_Inv_LrNo,SIM.Sal_Inv_LrDate,SIM.Sal_Inv_NetTotal
				From "+@DatabaseName+"Sales_Invoice SIM 
				INNER JOIN "+@DatabaseName+"PartyDetail PD ON SIM.Sal_Inv_Id=PD.vCode		
				INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON  SIM.Lgr_Id=PLM.Lgr_Id
				LEFT JOIN "+@DatabaseName+"City_Master PCM ON PLM.City_Id=PCM.City_Id
				Where SIM.Sal_Inv_Vdate between '"+@FromDate+"' And '"+@ToDate+"'
				And PD.JobFlag='S' 
				And SIM.Documents='Duplicate Bill'
				And SIM.Cmp_Code="+@Cmp_Code+"
					"
        execute Sp_Executesql @sql
        Print @sql
end




















GO

