-- Description:	<SP FOR MANUALINTEREST CALCULATION >
-- REPORT NAME: MANUALINTEREST_CALCULATION.RPT
-- PROC_MANUALINTCALC 1,'Acc2012_2013.DBO.',1,19,'',2
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_MANUALINTCALC]
(
	@CMP_CODE NVARCHAR(20),
	@DATABASENAME NVARCHAR(50),
	@FromBillNo NVARCHAR(20),
	@ToBillNo NVARCHAR(20),
	@DOCNO NVARCHAR(20),
	@RptType int
)

AS
DECLARE @SQL NVARCHAR(4000) SET @SQL=""
DECLARE @SQL1 AS NVARCHAR(4000) SET @SQL1=""
DECLARE @RptType_Sql AS NVARCHAR(4000) SET @RptType_Sql=""

BEGIN
 IF @RptType=1
	SET @RptType_Sql=" AND MI.DOCNO = "+@DOCNO+""
 IF @RptType=2
	SET @RptType_Sql=" AND MI.DOCNO BETWEEN "+@FromBillNo+" AND "+@ToBillNo+" "
 

END

BEGIN
	
	SET NOCOUNT ON;

 BEGIN   
	
SET @SQL="SELECT MI.DOCNO,CONVERT(NVARCHAR,MI.FROM_DATE,103) AS FROMDATE,CONVERT(NVARCHAR,MI.TO_DATE,103) AS TODATE,MI.PARTY_NAME,MI.DR_CR_TYPE,MI.INT_METHOD,
			MI.SAL_PUR_AMT,MI.CR_DAYS,MI.INTEREST,MI.DR_TOTAL,MI.CR_TOTAL,MI.TOTAL_DR_PRO,
			MI.TOTAL_CR_PRO,MI.NET_SALES,MI.BAL_ANKH,MI.CRD_ANKH,MI.NETBAL_ANKH,MI.GROSS_INT,
			MI.CREDIT_INT,MI.NET_INT,MI.BALANCE,MI.INT_AMT,MI.NET_BALANCE,MI.AVG_DAYS,
			MI.NET_AVGDAYS,CM.CMP_NAME,CM.CMP_ADD1,CM.CMP_ADD2,CM.CMP_CITY,CM.CMP_PINCODE,
			CM.CMP_STATE,MI.ManuInt_Id,CONVERT(nvarchar,MID.Dr_DATE,103) as DRDATE,MID.DR_BILLNO,MID.DR_AMOUNT,MID.DR_PRODUCT,MID.DR_DAYS,
			CONVERT(nvarchar,MID.CR_DATE,103) as CRDATE,MID.CR_BILLNO,MID.CR_AMOUNT,MID.CR_PRODUCTS,MID.CR_DAYS as Creditday,COMPANYNAME AS MCOMPANYNAME
			FROM "+@DATABASENAME+" MANINTMASTER MI
			INNER JOIN "+@DATABASENAME+" MAININTDETAIL MID ON MI.DOCNO = MID.DOCNO AND MI.CMP_CODE = MID.CMP_CODE AND MI.ManuInt_Id=MID.ManuInt_Id
			INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CM ON MI.CMP_CODE = CM.CMP_CODE
			WHERE MI.CMP_CODE = "+ @CMP_CODE +" "+@RptType_Sql+"
			order by MI.DOCNO
		 "



END

END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















