CREATE PROCEDURE [dbo].[PROC_MISSINGFIELD]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @RPT_WISE AS INT,
  @MINIMUM AS NVARCHAR(10),
  @MAXIMUM AS NVARCHAR(10)
  
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @CURSORSQL AS NVARCHAR(4000)
DECLARE @MISSDFIELD AS INT
DECLARE @BALENO AS INT

SET @SQL="" 

IF @RPT_WISE=2
        BEGIN  
           SET  @SQL ="SELECT DISTINCT BALENO AS RECORD FROM "+@DATABASENAME+"PACKINGSLIP WHERE CMP_CODE="+@CMP_CODE                       
        END

BEGIN       
      SET @CURSORSQL ="DECLARE RECORD_CURSOR CURSOR FOR " +@SQL       
       EXECUTE SP_EXECUTESQL  @CURSORSQL        
       PRINT @CURSORSQL        
          OPEN RECORD_CURSOR           
          FETCH NEXT FROM RECORD_CURSOR INTO @MISSDFIELD          
          WHILE @@FETCH_STATUS =0
             BEGIN
               PRINT @MISSDFIELD               
            END
        CLOSE RECORD_CURSOR 
        DEALLOCATE RECORD_CURSOR 
       CLOSE MIN_MAX_RECORD_CURSOR 
        DEALLOCATE MIN_MAX_RECORD_CURSOR 

END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_MONEYINSURANCE]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
   PROC_MONEYINSURANCE '2','ACC2012_2013.DBO.','01/APR/2012','01/APR/2013',0
*/
CREATE PROCEDURE [dbo].[PROC_MONEYINSURANCE]
( 
  @CMP_CODE NVARCHAR(200),
  @DATABASENAME NVARCHAR(200),
  @FROMDATE NVARCHAR(20),
  @TODATE NVARCHAR(20),
  @ACCID NVARCHAR(20)
)
AS
DECLARE @SQL NVARCHAR(4000)
SET @SQL=""
BEGIN
    SET @SQL="
SELECT TRAN_DATE,SUM(AMOUNT) AS AMOUNT
FROM (
SELECT TM.TRAN_DATE,TD.TRAN_AMOUNT AS AMOUNT
FROM  "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE
WHERE TM.TRAN_TYPE IN('BR') AND TM.CMP_CODE IN ("+@CMP_CODE+")
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
AND TD.TRAN_DETAIL_ID="+@ACCID+"
UNION ALL 
SELECT TM.TRAN_DATE,TD.TRAN_AMOUNT AS AMOUNT
FROM "+@DATABASENAME+" TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+" TRAN_DETAIL TD ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID=LM.LGR_ID
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.grp_Id=GM.grp_Id
WHERE TM.TRAN_TYPE IN('CP') AND UPPER(GM.GRP_NAME)='BANK'
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND TM.CMP_CODE IN ("+@CMP_CODE+")
) AS A
GROUP BY TRAN_DATE
ORDER BY TRAN_DATE
"
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_MONTHLYEXPENSE]    Script Date: 03/30/2023 12:08:12 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*  
PROC_MONTHLYEXPENSE '2', N'ACC2010_2011.DBO.', N'ACC2010_2011.DBO.', N'ACC2010_2011.DBO.', N'01/APR/2010', N'15/FEB/2011', N'##3176'
*/
CREATE PROCEDURE [dbo].[PROC_MONTHLYEXPENSE] 

(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@1PREVDB NVARCHAR(100),
@2PREVDB NVARCHAR(100),
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @ENDSQL AS NVARCHAR(4000)
SET @ENDSQL=""
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""

BEGIN


SET @SQL="   SELECT SUBSTRING(DBNAME,0,LEN(DBNAME)-4) AS DBNAME,PARTY,PARTYCITY,ENTRYMONTH,SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT,SUM(DRAMOUNT) -SUM(CRAMOUNT) AS BALANCE,SUM(OPBALANCE)AS OPBALANCE,CMP_ALIAS,PARTYID,PARTY_CITYID FROM (
SELECT '"+@DATABASENAME+"' AS DBNAME, PARTY,PARTYCITY,ENTRYMONTH,SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT
,SUM(DRAMOUNT) -SUM(CRAMOUNT) AS BALANCE,SUM(OPBALANCE)AS OPBALANCE,CMP_ALIAS,PARTYID,PARTY_CITYID
FROM(
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TM.TRAN_DRCR='D'THEN  TM.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
(CASE WHEN TM.TRAN_DRCR='C'THEN  TM.TRAN_AMOUNT ELSE 0 END )AS CRAMOUNT
,0 AS OPBALANCE,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRAN_MASTER_ID 
WHERE TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TM.TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TD.TRAN_DRCR='D'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS CRAMOUNT
,0 AS OPBALANCE,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TD.TRAN_DETAIL_ID 
WHERE TM.CMP_CODE IN("+@CMP_CODE+") AND TM.TRAN_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
UNION ALL
"
SET @SQL1="         SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(AJ.VDATE) AS ENTRYMONTH,
ISNULL(AJ.DRAMOUNT,0)AS DRAMOUNT,ISNULL(AJ.CRAMOUNT,0)AS CRAMOUNT,0 AS OPBALANCE,CMP.CMP_ALIAS
,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AJ.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=AJ.LGR_ID
WHERE AJ.CMP_CODE IN("+@CMP_CODE+") AND AJ.VDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS ENTRYMONTH,0 AS DRAMOUNT,0 AS CRAMOUNT
,(CASE WHEN LD.LGR_OP_DRCR ='C' THEN (0-ISNULL(LD.LGR_OP_BAL,0)) ELSE ISNULL(LD.LGR_OP_BAL,0) END) AS OPBALANCE,
CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@TEMPTABLE+" TT                     
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TT.CODE                       
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID                    
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LD.CMP_CODE AND LD.CMP_CODE=CMP.CMP_CODE
WHERE LD.CMP_CODE IN("+@CMP_CODE+") 

) AS DETAIL
GROUP BY PARTY,PARTYCITY,ENTRYMONTH,CMP_ALIAS,PARTYID,PARTY_CITYID
HAVING SUM(DRAMOUNT) -SUM(CRAMOUNT)<>0 OR SUM(OPBALANCE)<>0
"	


/*  
-FIRST PREVIOUS DATA
*/
IF @1PREVDB!="" 
BEGIN
SET @SQL2="  UNION ALL
SELECT '"+@1PREVDB+"' AS DBNAME, PARTY,PARTYCITY,ENTRYMONTH,SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT
,SUM(DRAMOUNT) -SUM(CRAMOUNT) AS BALANCE,SUM(OPBALANCE)AS OPBALANCE,CMP_ALIAS,PARTYID,PARTY_CITYID
FROM(
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TM.TRAN_DRCR='D'THEN  TM.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
