UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TM.TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TD.TRAN_DRCR='D'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS CRAMOUNT
,0 AS OPBALANCE,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@1PREVDB+"TRAN_MASTER TM 
INNER JOIN "+@1PREVDB+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@1PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@1PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@1PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TD.TRAN_DETAIL_ID 
WHERE TM.CMP_CODE IN("+@CMP_CODE+") 
UNION ALL
"
SET @SQL3="         SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(AJ.VDATE) AS ENTRYMONTH,
ISNULL(AJ.DRAMOUNT,0)AS DRAMOUNT,ISNULL(AJ.CRAMOUNT,0)AS CRAMOUNT,0 AS OPBALANCE,CMP.CMP_ALIAS
,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@1PREVDB+"AUTOJOURNAL AJ 
INNER JOIN "+@1PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=AJ.LGR_ID
LEFT JOIN "+@1PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@1PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=AJ.LGR_ID 
WHERE AJ.CMP_CODE IN("+@CMP_CODE+") 
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS ENTRYMONTH,0 AS DRAMOUNT,0 AS CRAMOUNT
,(CASE WHEN LD.LGR_OP_DRCR ='C' THEN (0-ISNULL(LD.LGR_OP_BAL,0)) ELSE ISNULL(LD.LGR_OP_BAL,0) END)  AS OPBALANCE,
CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@TEMPTABLE+" TT                     
INNER JOIN "+@1PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=TT.CODE                       
INNER JOIN "+@1PREVDB+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
LEFT JOIN "+@1PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID                    
LEFT JOIN "+@1PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LD.CMP_CODE AND LD.CMP_CODE=CMP.CMP_CODE
WHERE LD.CMP_CODE IN("+@CMP_CODE+") 
) AS DETAIL
GROUP BY PARTY,PARTYCITY,ENTRYMONTH,CMP_ALIAS,PARTYID,PARTY_CITYID
HAVING SUM(DRAMOUNT) -SUM(CRAMOUNT)<>0 OR SUM(OPBALANCE)<>0
"	

END



IF @2PREVDB!="" 
BEGIN
SET @SQL4="  UNION ALL
SELECT '"+@2PREVDB+"' AS DBNAME, PARTY,PARTYCITY,ENTRYMONTH,SUM(DRAMOUNT) AS DRAMOUNT,SUM(CRAMOUNT) AS CRAMOUNT
,SUM(DRAMOUNT) -SUM(CRAMOUNT) AS BALANCE,SUM(OPBALANCE)AS OPBALANCE,CMP_ALIAS,PARTYID,PARTY_CITYID
FROM(
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TM.TRAN_DRCR='D'THEN  TM.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
(CASE WHEN TM.TRAN_DRCR='C'THEN  TM.TRAN_AMOUNT ELSE 0 END )AS CRAMOUNT
,0 AS OPBALANCE,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@2PREVDB+"TRAN_MASTER TM 
INNER JOIN "+@2PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
LEFT JOIN "+@2PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRAN_MASTER_ID 
WHERE TM.CMP_CODE IN("+@CMP_CODE+") 
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(TM.TRAN_DATE) AS ENTRYMONTH,
(CASE WHEN TD.TRAN_DRCR='D'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN  TD.TRAN_AMOUNT ELSE 0 END )AS CRAMOUNT
,0 AS OPBALANCE,CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@2PREVDB+"TRAN_MASTER TM 
INNER JOIN "+@2PREVDB+"TRAN_DETAIL TD ON TD.TRAN_ID=TM.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@2PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@2PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@2PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TD.TRAN_DETAIL_ID 
WHERE TM.CMP_CODE IN("+@CMP_CODE+") 
UNION ALL
"
SET @SQL5="         SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,MONTH(AJ.VDATE) AS ENTRYMONTH,
ISNULL(AJ.DRAMOUNT,0)AS DRAMOUNT,ISNULL(AJ.CRAMOUNT,0)AS CRAMOUNT,0 AS OPBALANCE,CMP.CMP_ALIAS
,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@2PREVDB+"AUTOJOURNAL AJ 
INNER JOIN "+@2PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=AJ.LGR_ID
LEFT JOIN "+@2PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@2PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=AJ.LGR_ID 
WHERE AJ.CMP_CODE IN("+@CMP_CODE+") 
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,0 AS ENTRYMONTH,0 AS DRAMOUNT,0 AS CRAMOUNT
,(CASE WHEN LD.LGR_OP_DRCR ='C' THEN (0-ISNULL(LD.LGR_OP_BAL,0)) ELSE ISNULL(LD.LGR_OP_BAL,0) END)  AS OPBALANCE,
CMP.CMP_ALIAS,LM.LGR_ID AS PARTYID,PCM.CITY_ID AS PARTY_CITYID
FROM "+@TEMPTABLE+" TT                     
INNER JOIN "+@2PREVDB+"LEDGER_MASTER LM ON LM.LGR_ID=TT.CODE                       
INNER JOIN "+@2PREVDB+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
LEFT JOIN "+@2PREVDB+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID                    
LEFT JOIN "+@2PREVDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LD.CMP_CODE AND LD.CMP_CODE=CMP.CMP_CODE
