/*   
Proc_MonthlySales '2','ACC2010_2011.DBO.','01/APR/2010','01/FEB/2011','','11'
*/
CREATE PROCEDURE [dbo].[PROC_MONTHLYSALES]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20),
	@Criteria int
)
as
declare @SQL AS Nvarchar(4000)
declare @JoinSql  Nvarchar(500)
Declare @FieldSql Nvarchar(500)
Declare @groupby Nvarchar(500)
set @SQL=""
set @JoinSql=""
Set @FieldSql=""
Set @groupby=""

/*   -------Start----@JoinSql */
If @Criteria=0 /*  Party */
	set @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON SIM.Lgr_Id=PLM.Lgr_Id
				  INNER JOIN "+@TempTable+" TT ON TT.code=PLM.Lgr_Id"
Else If @Criteria=1 /*  Agent */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master ALM ON ALM.Lgr_Id=SIM.Agent_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=SIM.Agent_Id"
Else If @Criteria=2 /*  Agent-Party */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master ALM ON ALM.Lgr_Id=SIM.Agent_Id
					INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=SIM.Agent_Id"
Else If @Criteria=3 /*  City */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@DatabaseName+"City_Master PCM ON PCM.City_Id=PLM.City_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=PLM.City_Id"
Else If @Criteria=4 /*  City-Party */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@DatabaseName+"City_Master PCM ON PCM.City_Id=PLM.City_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=PLM.City_Id"
Else If @Criteria=5 /*  State */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@DatabaseName+"State_Master SM ON SM.State_Id=PLM.State_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=PLM.State_Id"
Else If @Criteria=6 /*  SalesMan */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
                    INNER JOIN "+@DatabaseName+"Ledger_MASTER ALM ON ALM.LGR_ID=SIM.AGENT_ID
					INNER JOIN "+@DatabaseName+"SalesMan_Master SLM ON SLM.SalesMan_Id=ALM.SalesMan_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=ALM.SalesMan_Id"
Else If @Criteria=7 /*  Item */
	set @JoinSql="  INNER JOIN "+@TempTable+" TT ON TT.code=SID.Item_Id"
Else If @Criteria=8 /*  Item-Party */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=SID.Item_Id"
Else If @Criteria=9 /*  Item-Agent */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master ALM ON ALM.Lgr_Id=SIM.Agent_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=SID.Item_Id"
Else If @Criteria=10 /*  Item-Agent-Party */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master ALM ON ALM.Lgr_Id=SIM.Agent_Id
					INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=SID.Item_Id"
Else If @Criteria=11 /*  ALL */
set @JoinSql="  "
Else If @Criteria=12 /*  SalesMan */
	set @JoinSql="  INNER JOIN "+@DatabaseName+"Ledger_Master PLM ON PLM.Lgr_Id=SIM.Lgr_Id
                    INNER JOIN "+@DatabaseName+"Ledger_MASTER ALM ON ALM.LGR_ID=SIM.AGENT_ID
					INNER JOIN "+@DatabaseName+"SalesMan_Master SLM ON SLM.SalesMan_Id=ALM.SalesMan_Id
					INNER JOIN "+@TempTable+" TT ON TT.code=ALM.SalesMan_Id"
/* -----End----@JoinSql */

/* -----Start----@FieldSql */
If @Criteria=0 /*  -Party */
	set @FieldSql="'' As MainGrp,PLM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=1 /* -Agent */
	set @FieldSql="'' As MainGrp,ALM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=2 /* -Agent-Party */
	set @FieldSql="ALM.Lgr_Name As MainGrp,PLM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=3 /* City */
	set @FieldSql="'' As MainGrp,PCM.City_Name As PartyName,'' As SubGrp"
Else If @Criteria=4 /* City-Party */
	set @FieldSql="PCM.City_Name As MainGrp,PLM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=5 /* State */
	set @FieldSql="'' As MainGrp,SM.State_Name As PartyName,'' As SubGrp"
Else If @Criteria=6 /*  SalesMan */
	set @FieldSql="'' As MainGrp,SLM.SalesMan_Name As PartyName,'' As SubGrp"
Else If @Criteria=7 /* Item */
	set @FieldSql="'' As MainGrp,IM.Item_Name As PartyName,'' As SubGrp"
Else If @Criteria=8 /*  Item-Party */
	set @FieldSql="IM.Item_Name As MainGrp,PLM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=9 /* Item-Agent */
	set @FieldSql="IM.Item_Name As MainGrp,ALM.Lgr_Name As PartyName,'' As SubGrp"
Else If @Criteria=10 /*  Item-Agent-Party */
	set @FieldSql="IM.Item_Name As MainGrp,ALM.Lgr_Name As PartyName,PLM.Lgr_Name As SubGrp"
Else If @Criteria=11 /* all */
	set @FieldSql="'' As MainGrp,'' As PartyName,'' As SubGrp"
Else If @Criteria=12 /*  SalesMan */
	set @FieldSql="SLM.SalesMan_Name As MainGrp,'' As PartyName,ALM.Lgr_Name  As SubGrp"

/* -----End----@FieldSql */

/* -----Start----@groupby */
If @Criteria=0 /* -Party */
	set @groupby="PLM.Lgr_Name"
Else if  @Criteria=1    /* -Agent */
	set @groupby="ALM.Lgr_Name"
Else if  @Criteria=2   /* -Agent-Party */
	set @groupby="ALM.Lgr_Name,PLM.Lgr_Name"
Else if  @Criteria=3   /* -City*/
	set @groupby="PCM.City_Name"
Else if  @Criteria=4   /* -City-Party */
	set @groupby="PCM.City_Name,PLM.Lgr_Name"
Else if  @Criteria=5   /* -State */
	set @groupby="SM.State_Name"
Else if  @Criteria =6   /*  -SalesMan */
	set @groupby="SLM.SalesMan_Name"
Else if  @Criteria=7   /*  -Item */
	set @groupby="IM.Item_Name"
Else if  @Criteria=8   /* -Item-Party */
	set @groupby="IM.Item_Name,PLM.Lgr_Name"
Else if  @Criteria=9   /*  -Item-Agent */
	set @groupby="IM.Item_Name,ALM.Lgr_Name"
Else if  @Criteria=10   /*  -Item-Agent-Party */
	set @groupby="IM.Item_Name,ALM.Lgr_Name,PLM.Lgr_Name"
Else if  @Criteria=11   /*  -Item-Agent-Party */
	set @groupby=""
Else if  @Criteria =12   /*  -SalesMan-agent */
	set @groupby="SLM.SalesMan_Name,ALM.Lgr_Name"
   /* -----End-----@groupby */

BEGIN
SET NOCOUNT ON;
If @Criteria=7 or  @Criteria=8 Or @Criteria=9 or @Criteria=10  
		select @SQL=" SELECT "+@FieldSql+",SUM(SID.Sal_Inv_Amount)+((SUM(SID.Sal_Inv_Amount)/SubAmt)*EffectiveCost) AS Amount,
					month(SIM.Sal_Inv_Vdate) As MonthNo
					FROM "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id
					INNER JOIN (
					SELECT SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal AS MainAmt, SUM(SID.Sal_Inv_Amount) AS SubAmt, 
					SIM.Sal_Inv_NetTotal-SUM(SID.Sal_Inv_Amount) AS EffectiveCost 
					FROM "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id 
					Where SIM.cmp_code = "+@Cmp_Code+" GROUP BY SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal) AS ABC ON SIM.Sal_Inv_Bill_No=ABC.Sal_Inv_Bill_No
					INNER JOIN "+@DatabaseName+"Item_Master IM ON SID.Item_Id=IM.Item_Id
					"+@JoinSql+"
					Where SIM.cmp_code="+@Cmp_Code+" And SIM.Sal_Inv_Vdate Between '"+@FromDate+"' And '"+@ToDate+"'
					Group by "+@groupby+",SubAmt,EffectiveCost,Month(SIM.Sal_Inv_Vdate)
					Order by PartyName,MonthNo
					"
Else If @Criteria=11        /* -------ALL */
		select @SQL=" SELECT "+@FieldSql+",sum(SIM.Sal_Inv_NetTotal) As Amount,
						month(SIM.Sal_Inv_Vdate) As MonthNo
					FROM "+@DatabaseName+"Sales_Invoice SIM 
						"+@JoinSql+"
					Where SIM.cmp_code="+@Cmp_Code+" And SIM.Sal_Inv_Vdate between '"+@FromDate+"' And '"+@ToDate+"'
					Group by Month(SIM.Sal_Inv_Vdate)					
					"
Else         /* -------Party,Agent,Agent-Party,City,City-Party,State,SalesMan */
		select @SQL=" SELECT "+@FieldSql+",sum(SIM.Sal_Inv_NetTotal) As Amount,
						month(SIM.Sal_Inv_Vdate) As MonthNo
					FROM "+@DatabaseName+"Sales_Invoice SIM 
						"+@JoinSql+"
					Where SIM.cmp_code="+@Cmp_Code+" And SIM.Sal_Inv_Vdate between '"+@FromDate+"' And '"+@ToDate+"'
					Group by "+@groupby+",Month(SIM.Sal_Inv_Vdate)
					Order by PartyName,MonthNo
					"
END
exec(@SQL)
Print @SQL




















GO

