/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '###%'
SELECT * FROM ###1888
PROC_MULTILEDGER N'1', N'Acc2017_2018.Dbo.', N'01/Apr/2017', N'31/Mar/2018', N'###932', 3, N'7,29,6,1' 
*/
CREATE PROCEDURE [dbo].[PROC_MULTILEDGER]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@CRITERIA INT,
@DEBTORS_BANK NVARCHAR(50)
)
AS
DECLARE @SQL      AS NVARCHAR(4000)
DECLARE @SQL1     AS NVARCHAR(4000)
DECLARE @SQL2     AS NVARCHAR(4000)
DECLARE @SQL3     AS NVARCHAR(4000)
DECLARE @SQL4     AS NVARCHAR(4000)
DECLARE @SQL5     AS NVARCHAR(4000)
DECLARE @JOINSQL  AS NVARCHAR(4000)
DECLARE @JOINSQL1 AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)



SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @JOINSQL=""
SET @FIELDSQL=""
SET @ORDERBYSQL=""
SET @SQL5=""
SET @JOINSQL1=""

IF @CRITERIA=0     /*  ALL ACCOUNTS */
BEGIN
SET @JOINSQL="" 
SET @JOINSQL1=""
SET @FIELDSQL=",'' AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,0 AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=1    /* SUPPLIER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON LM1.SUPP_GRP_ID=SGM.SUPP_GRP_ID"
SET @FIELDSQL=" ,SGM.SUPP_GRP_NAME AS MAINGRP,SGM.SUPP_GRP_ID AS SUPPGRPID, 0 AS CUSTGRPID,0 AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,SUPPGRPID,PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=2    /* CUSTOMER GROUP */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON LM.CUST_GRP_ID=CGM.CUST_GRP_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON LM1.CUST_GRP_ID=CGM.CUST_GRP_ID"
SET @FIELDSQL=" ,CGM.CUST_GRP_NAME AS MAINGRP,0 AS SUPPGRPID, CGM.CUST_GRP_ID AS CUSTGRPID,0 AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,CUSTGRPID,PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=3    /*  AGENT */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON LD.AGENT_ID=AGM.LGR_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON LD.AGENT_ID=AGM.LGR_ID"
SET @FIELDSQL=" ,AGM.LGR_NAME AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,AGM.LGR_ID AS AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"	
SET @ORDERBYSQL = "MAINGRP,AGENTID,PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=4    /*  CITY */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CITY_MASTER MCM ON LM.CITY_ID=MCM.CITY_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"CITY_MASTER MCM ON LM1.CITY_ID=MCM.CITY_ID"
SET @FIELDSQL="	,MCM.CITY_NAME AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,0 AS AGENTID,MCM.CITY_ID AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,PARTY_CITYID,PARTYNAME,PARTYID,"				
END

ELSE IF @CRITERIA=5    /* STATE */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"STATE_MASTER MSM ON LM.STATE_ID=MSM.STATE_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"STATE_MASTER MSM ON LM1.STATE_ID=MSM.STATE_ID"
SET @FIELDSQL="	,MSM.STATE_NAME AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,0 AS AGENTID,0 AS PARTY_CITYID,
				MSM.STATE_ID AS STATEID,0 AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,STATEID,PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=6    /* ALL GROUPS */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID  AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID  AND LD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"GROUP_MASTER MGM ON LD.GRP_ID=MGM.GRP_ID"	
SET @FIELDSQL="	,MGM.GRP_NAME AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,0 AS AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,MGM.GRP_ID AS MAIN_GRPID,0 AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,MAIN_GRPID,PARTYNAME,PARTYID,"
END

ELSE IF @CRITERIA=7    /* CATEGORY */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CATEGORY_MASTER CAM ON LM.CATEGORY_ID=CAM.CATEGORY_ID"
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"CATEGORY_MASTER CAM ON LM1.CATEGORY_ID=CAM.CATEGORY_ID"
SET @FIELDSQL=" ,CAM.CATEGORY_NAME AS MAINGRP,0 AS SUPPGRPID, 0 AS CUSTGRPID,0 AS AGENTID,0 AS PARTY_CITYID,
				0 AS STATEID,0 AS MAIN_GRPID,CAM.CATEGORY_ID AS CATEGORYID"
SET @ORDERBYSQL = "MAINGRP,CATEGORYID,PARTYNAME,PARTYID,"
END

 /* IF @CRITERIA=0    ALL ACCOUNTS 
ELSE IF @CRITERIA=1     SUPPLIER GROUP 
ELSE IF @CRITERIA=2     CUSTOMER GROUP 
ELSE IF @CRITERIA=3     AGENT 
ELSE IF @CRITERIA=4     CITY 
ELSE IF @CRITERIA=5     STATE
ELSE IF @CRITERIA=6     ALL GROUPS
ELSE IF @CRITERIA=7    ALL GROUPS */


BEGIN
SET NOCOUNT ON;

SELECT @SQL=" SELECT * FROM (
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('BR','CR','BP','CP') THEN TD.CHEQUENO ELSE TM.TRAN_DOCNO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TM.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,LM.LGR_ID AS ACC_ID,ACM.CITY_NAME AS ACCOUNTCITY,
(CASE WHEN ISNULL(TM.NARRATION,'')='' THEN TD.NARRATION ELSE (TD.NARRATION + ',' + TM.NARRATION) END) AS REMARK,TD.DDDATE 
"+@FIELDSQL+"
,(
CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') THEN 1 ELSE  ( 
CASE   WHEN TT.GRP_MAIN_ID IN ("+@DEBTORS_BANK+") THEN (CASE WHEN (TM.TRAN_DRCR='D') THEN 2 ELSE 3 END)
ELSE 
(CASE WHEN (TM.TRAN_DRCR='C') THEN 2 ELSE 3 END)END 
)END) AS ORD,0 AS SECOND_ORD,0 AS JOURNAL_ORD,LM.GSTINNO
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE   
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN ('J','VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "
SELECT @SQL1=" UNION ALL 
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('BR','CR','BP','CP') THEN TD.CHEQUENO  ELSE TM.TRAN_DOCNO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE, 
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
TD.TRAN_TYPE AS TYPE,LM1.LGR_NAME AS ACCOUNTNAME,LM.LGR_ID AS ACC_ID,ACM.CITY_NAME AS ACCOUNTCITY,
(CASE WHEN ISNULL(TM.NARRATION,'')='' THEN TD.NARRATION ELSE (TD.NARRATION + ',' + TM.NARRATION) END) AS REMARK,TD.DDDATE 
"+@FIELDSQL+"
,(
CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') THEN 1 ELSE  ( 
CASE   WHEN TT.GRP_MAIN_ID IN ("+@DEBTORS_BANK+") THEN (CASE WHEN (TD.TRAN_DRCR='D') THEN 2 ELSE 3 END)
ELSE 
(CASE WHEN (TD.TRAN_DRCR='C') THEN 2 ELSE 3 END)END 
)END) AS ORD,0 AS SECOND_ORD,0 AS JOURNAL_ORD,LM.GSTINNO
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID 
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN ('J','VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP')
AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
UNION ALL "


SET @SQL2="         SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('BR','CR','BP','CP') THEN TD.CHEQUENO ELSE TM.TRAN_DOCNO END AS CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,TD.TRAN_ID,TM.TRAN_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE, LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,ACM.CITY_NAME AS ACCOUNTCITY,
(CASE WHEN ISNULL(TM.NARRATION,'')='' THEN TD.NARRATION ELSE (TD.NARRATION + ',' + TM.NARRATION) END) AS REMARK,TD.DDDATE AS DDDATE
"+@FIELDSQL+"
,(
CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') THEN 1 ELSE  ( 
CASE   WHEN TT.GRP_MAIN_ID IN ("+@DEBTORS_BANK+") THEN (CASE WHEN (TD.TRAN_DRCR='D') THEN 2 ELSE 3 END)
ELSE 
(CASE WHEN (TD.TRAN_DRCR='C') THEN 2 ELSE 3 END)END 
)END) AS ORD

,2 AS SECOND_ORD,1 AS JOURNAL_ORD,LM.GSTINNO
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TM.CMP_CODE=JD.CMP_CODE
AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID   
WHERE TM.CMP_CODE="+@CMP_CODE+"  AND TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND  '"+@TODATE+"' 
AND TM.TRAN_TYPE  IN ('J','DN','CN') "
SELECT @SQL3="	UNION ALL
SELECT '' AS DOCNO,'' AS CHEQUEINT,LM.LGR_NAME,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,
AJ.ENTRYCODE AS VCODE,AJ.VDATE AS VOUCHER_DATE,
AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE, 
LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,ACM.CITY_NAME AS ACCOUNTCITY,
AJ.NARRATION AS REMARK,AJ.VDATE AS DDDATE
"+@FIELDSQL+",(CASE  WHEN AJ.ENTRYTYPE IN ('J','DN','CN') THEN 5 ELSE  3 END)AS ORD ,1 AS SECOND_ORD,0 AS JOURNAL_ORD,LM.GSTINNO
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE 
AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  
AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ.ENTRYMATCH=AJ1.ENTRYMATCH 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AJ.LGR_ID
"+@JOINSQL+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID   
WHERE AJ.VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND AJ.CMP_CODE ="+@CMP_CODE+"

"


SELECT @SQL4=" UNION ALL
SELECT '' AS DOCNO,'' CHEQUEINT,
LM.LGR_NAME AS PARTYNAME,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,0 TRAN_ID,NULL AS TRAN_DATE,
(CASE WHEN TT.OPDRCR = 'DR' THEN TT.OPBAL ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TT.OPDRCR = 'CR' THEN TT.OPBAL ELSE 0 END ) AS CRAMOUNT,
'OPENING BALANCE' AS TRANTYPE, 'OPENING BALANCE' AS ACCOUNTNAME,0 AS ACC_ID,NULL AS ACCOUNTCITY,
'' AS REMARK,NULL AS DDDATE"+@FIELDSQL+",3 AS ORD,1 AS SECOND_ORD,0 AS JOURNAL_ORD,LM.GSTINNO
FROM "+@DATABASENAME+"LEDGER_MASTER LM 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID
"+@JOINSQL+"                    
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID					
WHERE TT.OPBAL <>0 
"

SELECT @SQL5=" UNION ALL
SELECT DISTINCT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('BR','CR','BP','CP') THEN TD.CHEQUENO ELSE TM.TRAN_DOCNO END AS CHEQUEINT,
LM1.LGR_NAME AS PARTYNAME,LM1.LGR_ID AS PARTYID,ACM.CITY_NAME AS PARTYCITY,TD.TRAN_ID,TM.TRAN_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE, LM.LGR_NAME AS ACCOUNTNAME,LM.LGR_ID AS ACC_ID,PCM.CITY_NAME AS ACCOUNTCITY,
(CASE WHEN ISNULL(TM.NARRATION,'')='' THEN TD.NARRATION ELSE (TD.NARRATION + ',' + TM.NARRATION) END) AS REMARK,TD.DDDATE AS DDDATE
"+@FIELDSQL+"
,(CASE WHEN TM.TRAN_TYPE IN ('S','GS','MS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP','MS') THEN 1 ELSE  ( 
CASE   WHEN TT.GRP_MAIN_ID IN ("+@DEBTORS_BANK+") THEN (CASE WHEN (TD.TRAN_DRCR='D') THEN 2 ELSE 3 END)
ELSE (CASE WHEN (TD.TRAN_DRCR='C') THEN 2 ELSE 3 END)END )END) AS ORD,2 AS SECOND_ORD,1 AS JOURNAL_ORD,LM1.GSTINNO
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE AND TM.EFFECT_CODE=TD.TRAN_DETAIL_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID   
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID  
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON LM1.CITY_ID=ACM.CITY_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID
"+@JOINSQL1+"
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE IN ('VAT','PV','S','GS','MS','JS','P','FP','JP','CHP','MIP','YP','CS','CRS','SR','T','PR','CPR','GSN','ES','RP') 
and TM.TRAN_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
UNION ALL 
SELECT TM.Tran_DocNo as DocNo,CASE WHEN TM.TRAN_TYPE IN ('S','GS','P','FP','JP','CHP','MIP','YP','CS','CRS','SPJ','EPJ','SR','GSR','CA','CO','T','GSN','MS','ES','RP','CPR') THEN TM.TRAN_DOCNO  ELSE TD.CHEQUENO END As ChequeInt,LM.Lgr_Name as PartyName,TD.Tran_DETAIL_ID as PartyId,
PCM.City_Name As PartyCity,TM.TRan_ID,TM.Tran_Date,(CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT ,
(CASE WHEN TD.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT,TD.Tran_Type,LM1.Lgr_Name as AccountName,LM.Lgr_ID as ACC_ID,
ACM.City_Name As AccountCity,TD.NARRATION as Remark,TD.DDDATE"+@FieldSql+",1 AS ORD,0 AS SECOND_ORD,0 AS JOURNAL_ORD,LM.GSTINNO
From "+@DatabaseName+"Tran_Master TM 
Inner Join "+@DatabaseName+"Tran_Detail TD ON TM.Tran_Id = TD.Tran_Id And TM.Cmp_Code= TD.Cmp_Code AND TM.Tran_Type = TD.Tran_Type 
INNER JOIN "+ @TempTable + " TT on TT.Code=TD.Tran_DETAIL_Id
INNER JOIN "+@DatabaseName+"Ledger_Master LM ON TD.TRan_DETAIL_Id = LM.Lgr_Id   
INNER JOIN "+@DatabaseName+"Ledger_Master LM1 ON   TM.Tran_MASTER_ID= LM1.Lgr_Id
"+@JoinSql+"
LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_ID=PCM.City_Id
LEFT JOIN "+@DatabaseName+"City_Master ACM ON LM1.City_ID=ACM.City_Id
Where TM.Cmp_Code = "+@Cmp_Code+" And TM.Tran_Type IN ('VAT','PV','VPR','VSR','S','GS','P','FP','JP','CHP','MIP','YP','CS','CRS','SPJ','EPJ','SR','GSR','CA','CO','T','GSN','JS','SNJ','RP','PR','CPR','MS','ES') 
And TM.TRan_Date Between '"+@FromDate+"' And '"+@ToDate+"'
) AS D ORDER BY "+@ORDERBYSQL+"VOUCHER_DATE,ORD,JOURNAL_ORD,VCODE,SECOND_ORD	
"




END
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
EXEC(@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5)

















GO

/****** Object:  StoredProcedure [dbo].[PROC_MULTIYEARSALESREPORT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






/*
-- =============================================
-- Author:		<PATEL PRATIK>
-- Create date: <14-04-2015>
-- Description:	<THIS PROC USED IN MULTI YEAR SALES REPORT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_MULTIYEARSALESREPORT 1,'ACC2013_2014.DBO.','ACC2014_2015.DBO.','ACC2015_2016.DBO.','##4048',1
*/
CREATE PROCEDURE [dbo].[PROC_MULTIYEARSALESREPORT]	
(
	@CMP_CODE NVARCHAR(100),
    @DATABASENAME1 NVARCHAR(50),
	@DATABASENAME2 NVARCHAR(50),
	@DATABASENAME3 NVARCHAR(50),
	@TEMPTABLE NVARCHAR(50),
	@RPTWISE INT
)
AS


DECLARE @SQL1 NVARCHAR(4000) SET @SQL1=""
DECLARE @SQL2 NVARCHAR(4000) SET @SQL2=""
DECLARE @SQL3 NVARCHAR(4000) SET @SQL3=""
DECLARE @SQL4 NVARCHAR(4000) SET @SQL4=""
DECLARE @GROUPBY NVARCHAR(4000) SET @GROUPBY=""
DECLARE @STRJOIN NVARCHAR(4000) SET @STRJOIN=""
DECLARE @STRFIELD NVARCHAR(4000) SET @STRFIELD=""

BEGIN

	IF @RPTWISE=1
		BEGIN
				SET @GROUPBY="AGENT,AGENTCITY"
				SET @STRJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
				SET @STRFIELD="MAX(PARTY)PARTY,AGENT,MAX(PARTYCITY)PARTYCITY,AGENTCITY"
		END	
	ELSE IF @RPTWISE=2
		BEGIN
				SET @GROUPBY="PARTY,PARTYCITY"
				SET @STRJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
				SET @STRFIELD="PARTY,MAX(AGENT)AGENT,PARTYCITY,MAX(AGENTCITY)AGENTCITY"
		END	
	ELSE IF @RPTWISE=3
		BEGIN
				SET @GROUPBY="AGENT,PARTY,PARTYCITY,AGENTCITY"
				SET @STRJOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
				SET @STRFIELD="PARTY,AGENT,PARTYCITY,AGENTCITY"
		END	

END

BEGIN
	IF @DATABASENAME1<>''
SET @SQL1="	SELECT "+@STRFIELD+",SUM(DB1) AS DB1,SUM(DB2) AS DB2,SUM(DB3) AS DB3,CMP_ALIAS,SUM(CREDIT_DB1)CREDIT_DB1,SUM(CREDIT_DB2)CREDIT_DB2,
SUM(CREDIT_DB3)CREDIT_DB3 
FROM(
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,LCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,SAL_INV_NETTOTAL AS DB1,0 AS DB2,0 AS DB3,CMP.CMP_ALIAS,0 AS CREDIT_DB1,0 AS CREDIT_DB2,0 AS CREDIT_DB3
FROM "+@DATABASENAME1+"SALES_INVOICE SI
LEFT JOIN "+@DATABASENAME1+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME1+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@DATABASENAME1+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME1+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME1+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@STRJOIN+"
WHERE SI.CMP_CODE IN ("+@CMP_CODE+")

UNION ALL
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,0 AS DB1,0 AS DB2,0 AS DB3,CMP.CMP_ALIAS,SRM.ROUNDEDAMOUNT AS CREDIT_DB1,0 AS CREDIT_DB2, 0 AS CREDIT_DB3
FROM "+@DATABASENAME1+"SALES_RETURN_MASTER SRM
INNER JOIN "+@DATABASENAME1+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
LEFT JOIN "+@DATABASENAME1+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME1+"LEDGER_MASTER ALM ON ALM.LGR_ID=SRM.AGENT_ID
LEFT JOIN "+@DATABASENAME1+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME1+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SRM.CMP_CODE                
"+@STRJOIN+"
WHERE SRM.CMP_CODE IN ("+@CMP_CODE+")

        "
IF @DATABASENAME2<>''
SET @SQL2="UNION ALL
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,LCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,0 AS DB1 ,SAL_INV_NETTOTAL AS DB2,0 AS DB3,CMP.CMP_ALIAS,0 AS CREDIT_DB1,0 AS CREDIT_DB2,0 AS CREDIT_DB3
FROM "+@DATABASENAME2+"SALES_INVOICE SI
LEFT JOIN "+@DATABASENAME2+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME2+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
INNER JOIN "+@DATABASENAME2+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN "+@DATABASENAME2+"CITY_MASTER LCM ON LCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME2+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@STRJOIN+"
WHERE SI.CMP_CODE IN ("+@CMP_CODE+")

UNION ALL
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,0 AS DB1,0 AS DB2,0 AS DB3,CMP.CMP_ALIAS,0 AS CREDIT_DB1,SRM.ROUNDEDAMOUNT AS CREDIT_DB2,0 AS CREDIT_DB3
FROM "+@DATABASENAME2+"SALES_RETURN_MASTER SRM
INNER JOIN "+@DATABASENAME2+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
LEFT JOIN "+@DATABASENAME2+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME2+"LEDGER_MASTER ALM ON ALM.LGR_ID=SRM.AGENT_ID
LEFT JOIN "+@DATABASENAME2+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME2+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SRM.CMP_CODE     
       
"+@STRJOIN+"
WHERE SRM.CMP_CODE IN ("+@CMP_CODE+")

"

IF @DATABASENAME3<>''
SET @SQL3="UNION ALL
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,0 AS DB1 ,0 AS DB2,SAL_INV_NETTOTAL AS DB3,CMP.CMP_ALIAS,0 AS CREDIT_DB1,0 AS CREDIT_DB2,0 AS CREDIT_DB3
FROM "+@DATABASENAME3+"SALES_INVOICE SI
LEFT JOIN "+@DATABASENAME3+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME3+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
INNER JOIN "+@DATABASENAME3+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN "+@DATABASENAME3+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME3+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
"+@STRJOIN+"
WHERE SI.CMP_CODE IN ("+@CMP_CODE+")

UNION ALL
SELECT LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,0 AS DB1,0 AS DB2,0 AS DB3,CMP.CMP_ALIAS,0 AS CREDIT_DB1,0 AS CREDIT_DB2,SRM.ROUNDEDAMOUNT AS CREDIT_DB3
FROM "+@DATABASENAME3+"SALES_RETURN_MASTER SRM
INNER JOIN "+@DATABASENAME3+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
LEFT JOIN "+@DATABASENAME3+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME3+"LEDGER_MASTER ALM ON ALM.LGR_ID=SRM.AGENT_ID
LEFT JOIN "+@DATABASENAME3+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME3+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SRM.CMP_CODE 
"+@STRJOIN+"
WHERE SRM.CMP_CODE IN ("+@CMP_CODE+")

"

SET @SQL4=") AS DEATIL
GROUP BY "+@GROUPBY+",CMP_ALIAS
ORDER BY "+@GROUPBY+",CMP_ALIAS
"

END
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
EXEC (@SQL1+@SQL2+@SQL3+@SQL4)










GO

