/*
-- =============================================
-- Author:		GAMI DIPAK
-- Create_date: 06-02-2015
-- Description:	THIS REPORT IS USED IN ON ACCOUNT REPORT
-- =============================================
select * from tempdb..sysobjects where name like '##%'
SELECT * FROM ACC2014_2015.DBO.GROUP_MASTER
select * from ##1076
PROC_ONACCOUNT 'Acc2017_2018.DBO.',1,'',1,0,1,'25,8',0
PROC_ONACCOUNT N'Acc2017_2018.Dbo.', 1, N'##4384', N'5', 0, 1, N'25', 0
*/
CREATE PROCEDURE [dbo].[PROC_ONACCOUNT]
(
@DATABASENAME AS NVARCHAR(100),
@RPTWISE AS INT,
@TEMPTB AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(100),
@RPTCDTYPE AS INT,
@RPTSPTYPE AS INT,
@MAINGROUPID AS NVARCHAR(100),
@DETAILSUMMARY INT
)
AS

DECLARE @STRSQL NVARCHAR(4000)
DECLARE @STRCDTYPE NVARCHAR (400)
DECLARE @STRSPTYPE NVARCHAR(2000)
DECLARE @STRJOIN NVARCHAR(200)
DECLARE @STRORDERBY NVARCHAR(200)
DECLARE @STRGROUPBY NVARCHAR(200)
DECLARE @ALJOIN NVARCHAR(100)
DECLARE @STRSQL1 NVARCHAR(4000) 
DECLARE @STRSQL2 NVARCHAR(4000) 

DECLARE @ALCONDITION NVARCHAR(100)



SET @STRSQL =""
SET @STRCDTYPE =""
SET @STRSPTYPE =""
SET @STRJOIN =""
SET @STRSPTYPE=""
SET @ALCONDITION=""
SET @STRCDTYPE=""
 SET @ALJOIN=""



BEGIN 
	IF @RPTSPTYPE =1
	BEGIN
		SET @STRSPTYPE=" AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILLNO+FLAG FROM "+@DATABASENAME+"PURPARTYDETAIL PD WHERE PD.FLAG='J' AND PD.CMP_CODE IN ("+ @CMP_CODE  +"))
						 AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILLNO+FLAG FROM "+@DATABASENAME+"PURPARTYDETAIL PD WHERE PD.FLAG='DN' AND PD.CMP_CODE	IN ("+ @CMP_CODE  +"))"
	IF	@MAINGROUPID<>"0"
	BEGIN
	 	SET @STRCDTYPE ="  AND  GM.GRP_MAIN_ID IN ("+ @MAINGROUPID  +")"
	END
	END
ELSE 
	BEGIN
		SET @STRSPTYPE=" AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+"PARTYDETAIL PD WHERE PD.JOBFLAG='J' AND PD.CMP_CODE IN ("+ @CMP_CODE  +"))
				    	 AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+"PARTYDETAIL PD WHERE PD.JOBFLAG='DN' AND PD.CMP_CODE	IN ("+ @CMP_CODE  +"))
						 AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+"PARTYDETAIL PD WHERE PD.JOBFLAG='BP' AND PD.CMP_CODE	IN ("+ @CMP_CODE  +"))
						 AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+TD.TRAN_TYPE) NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+"PARTYDETAIL PD WHERE PD.JOBFLAG='CP' AND PD.CMP_CODE	IN ("+ @CMP_CODE  +"))
						"
			IF	@MAINGROUPID<>"0"
			BEGIN
				SET @STRCDTYPE ="  AND  LD.GRP_ID IN ("+ @MAINGROUPID  +")"
			END
	END
END

		BEGIN 
IF @RPTWISE=0 
BEGIN
SET @ALJOIN=" INNER JOIN "+@DATABASENAME+"LEDGER_MASTER  ALM ON ALM.LGR_ID =LD.AGENT_ID"
SET @STRJOIN=" INNER JOIN "+@TEMPTB+"  TT ON TT.CODE =LD.AGENT_ID"
SET @ALCONDITION=" AND ALM.LGR_TYPE='A'"
END
ELSE IF @RPTWISE=1 
BEGIN
SET @ALJOIN=" LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER  ALM ON ALM.LGR_ID =LD.AGENT_ID"
SET @STRJOIN=" INNER JOIN "+@TEMPTB+"  TT ON TT.CODE =LM.LGR_ID"
SET @ALCONDITION=" AND LM.LGR_TYPE='L'"
END
ELSE IF @RPTWISE=2 
BEGIN
SET @ALJOIN=" INNER JOIN "+@DATABASENAME+"LEDGER_MASTER  ALM ON ALM.LGR_ID =LD.AGENT_ID"
SET @STRJOIN=" INNER JOIN "+@TEMPTB+"  TT ON TT.CODE =LD.AGENT_ID"
SET @ALCONDITION=" AND ALM.LGR_TYPE='A'"
END
END


IF @TEMPTB=""
BEGIN
	SET @STRJOIN=""
END

/*
	
BEGIN
IF @RPTSPTYPE <>1
SET @ALCONDITION=""
END*/

BEGIN
  SET @STRSQL="  SELECT  TD.TRAN_ID AS TRAN_ID ,TD.TRAN_TYPE TRAN_TYPE, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, 
						TD.PARTAMOUNT AS ONACCOUNT ,TD.TRAN_AMOUNT as AMOUNT,TM.TRAN_DATE AS DATE,TD.TRAN_DRCR AS DRCR_DETAIL, 
						  (CASE WHEN ISNULL(TM.TRAN_DRCR,'') ='' THEN TD.TRAN_DRCR ELSE TM.TRAN_DRCR END) AS DRCR_MASTER,ISNULL(TD.Chequeno,'') AS CHEQUENO,TD.ShowPartAmt,TD.Reference,Tran_DocNo,TD.REC_TRANS
			FROM "+@DATABASENAME+"TRAN_DETAIL TD 
			INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE 
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
			INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
			"+@ALJOIN+"
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
			"+@STRJOIN+"
			WHERE TD.PARTAMOUNT>0  AND TD.CMP_CODE="+@CMP_CODE+" "+@STRSPTYPE+" "+@ALCONDITION+" "+@STRCDTYPE+"
			"

SET @STRSQL1="UNION ALL 
SELECT  TM.TRAN_ID AS TRAN_ID ,TM.TRAN_TYPE TRAN_TYPE, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, 
						TM.PARTAMOUNT AS ONACCOUNT ,TM.TRAN_AMOUNT as AMOUNT,TM.TRAN_DATE AS DATE,TM.TRAN_DRCR AS DRCR_DETAIL, 
						  (CASE WHEN ISNULL(TM.TRAN_DRCR,'') ='' THEN TM.TRAN_DRCR ELSE TM.TRAN_DRCR END) AS DRCR_MASTER,'' AS CHEQUENO,ISNULL(ShowPartAmt,0) as ShowPartAmt , isnull(Reference,0) as Reference ,Tran_DocNo,TM.REC_TRANS
			FROM "+@DATABASENAME+"TRAN_MASTER TM 
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.Tran_Master_Id
			INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
			INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
			"+@ALJOIN+""
SET @STRSQL2="			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
			"+@STRJOIN+"
			WHERE TM.PARTAMOUNT>0  AND TM.CMP_CODE="+@CMP_CODE+" AND TM.Tran_type IN('GCN','GDN','SR','PR') AND ISNULL(TM.Reference,0) <> 1 "+@ALCONDITION+""

END
EXEC  (@STRSQL+@STRSQL1+@STRSQL2)
PRINT @STRSQL
PRINT @STRSQL1
PRINT @STRSQL2





























GO

/****** Object:  StoredProcedure [dbo].[PROC_ORDER_CONFO_RUBIA]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*
-- =============================================
-- AUTHOR     :		<PRATIK PATEL>
-- ALTER_DATE: 25/05/2012
-- DESCRIPTION:	ORDER CONFORMATION REPORT DATA COMES FROM SALES ORDER THIS REPORT SAL_INV_RUBIA
-- CRYSTALREPORT : SALESORDER_RUBIA_BALAJI_PREPRINT.RPT
-- =============================================

PROC_ORDER_CONFO_RUBIA N'1', N'Acc2018_2019.Dbo.', N'11130', N'11134', N'2018-2019'

*/
CREATE PROCEDURE [dbo].[PROC_ORDER_CONFO_RUBIA]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMBILLNO NVARCHAR(50),
@TOBILLNO NVARCHAR(50),
@FYEAR NVARCHAR(50)
)
AS

DECLARE @SQL NVARCHAR(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT SOD.SRNO,LM.LGR_NAME,LM.LGR_DISTRICT,AGM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
CONFNO,VCH_DATE AS CONFDATE,SALES_ORDERNO,ORDER_DATE,TM.TRANSPORT_NAME,
IM.ITEM_NAME,ISNULL(SCM.SCREEN_NAME,'') AS SCREEN_NAME,ISNULL(SOD.BALES,0) AS BALES,UNIT_NAME,RATE,RATE_PER AS ITEMPER,STM.CITY_NAME AS STATION
,NARRATION1,NARRATION2,ACM.CITY_NAME AS AGENTCITY,SOD.REMARK,
LM.LGR_ADD1 AS ADRESS1,LM.LGR_ADD2 AS ADRESS2,LM.LGR_ADD3 AS ADRESS3,LM.GSTINNO AS TINNO,STATE_NAME AS STATE,
PACKINGSTYLE_NAME,SOD.COLOR_CHART,LM.CITY_PINCODE,ISNULL(SOD.PIECES,0) AS PIECES,SOD.ITEM_CUT,STGM.STAMPGRP_NAME,SO.NET_SNET,SO.THROUGH,ISNULL(SOD.QUANTITY,0) AS QUANTITY,ISNULL(ACC_MASTER.DBO.FN_DECRYPTSTRING(USM.USERNAME),'') AS USERNAME,
DM.DESIGN_NAME,SOA.PCS AS ASSORTPCS
FROM  "+@DATABASENAME+" SALES_ORDER SO
INNER JOIN  "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SO.FLAG=SOD.FLAG
LEFT JOIN  "+@DATABASENAME+" SALES_ORDER_ASSORT SOA ON SO.SAL_ORDER_ID=SOA.SAL_ORDER_ID AND SOA.ITEM_ID=SOD.ITEM_ID
LEFT JOIN  "+@DATABASENAME+" DESIGN_MASTER DM ON DM.DESIGN_ID=SOA.DESIGN_ID
INNER JOIN  "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN  "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SO.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER AGM ON AGM.LGR_ID=SO.AGENT_ID
INNER JOIN  "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
LEFT JOIN   "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+" SCREEN_MASTER SCM ON SCM.SCREEN_ID=SOD.SCREEN_ID
LEFT JOIN  "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+" CITY_MASTER STM ON SO.STATION_ID=STM.CITY_ID
LEFT JOIN  "+@DATABASENAME+" CITY_MASTER ACM ON AGM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+" PACKINGSTYLE_MASTER PKM ON PKM.PACKINGSTYLE_ID=SOD.PACKINGSTYLE_ID
LEFT JOIN "+@DATABASENAME+" STAMPGROUP_MASTER STGM ON STGM.STAMPGRP_ID=SO.STAMPGRP_ID
LEFT JOIN ACC_MASTER.DBO.USERMASTER USM ON USM.USERID = SO.USERID
WHERE SO.CMP_CODE="+@CMP_CODE+" AND   SO.CONFNO BETWEEN '"+@FROMBILLNO+"' AND '"+@TOBILLNO+"'
AND SO.FLAG='S' AND SO.ORDER_TYPE IN ('B') AND SO.FYEAR = '"+@FYEAR+"' ORDER BY SO.SAL_ORDER_ID,SOD.SRNO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL





















GO

/****** Object:  StoredProcedure [dbo].[PROC_ORDER_INV_AFTDATE]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_ORDER_INV_AFTDATE '2','ACC2010_2011.DBO.','01/APR/2010','13/MAR/2011',1,'##2310'
*/
CREATE PROCEDURE [dbo].[PROC_ORDER_INV_AFTDATE]
(
  @CMP_CODE NVARCHAR(100),
  @DATABASENAME NVARCHAR(100),
  @FROMDATE NVARCHAR(20),
  @TODATE NVARCHAR(20),  
  @TEMPTABLE NVARCHAR(20),
  @Criteria INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @JOINSQL=""

	BEGIN
           IF @Criteria=1 
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
                END
           ELSE IF @Criteria=2 or @Criteria=3
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
                END
          ELSE IF @Criteria=4
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
                END
          ELSE IF @Criteria=5
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
                END
          ELSE IF @Criteria=6
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
                END
         ELSE IF @Criteria=7
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
                END
		  ELSE IF @Criteria=10
                BEGIN
                  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=CGM.CUST_GRP_ID"
                END

	END

BEGIN

SET @SQL= "     
SELECT CONFNO,CONFDATE,SALES_ORDERNO,ORDER_DATE,ITEM_NAME,SCREEN,BILLNO ,BILLDATE
,PARTY,PARTYCITY,AGENT,AGENTCITY ,RATE,SUM(QUANTITY) AS QUANTITY,SUM(NETTOTAL) AS NETTOTAL,SALESMAN,CMP_ALIAS,CUSTOMEGROUP FROM(  
SELECT SO.CONFNO,SO.VCH_DATE AS CONFDATE,SO.SALES_ORDERNO,SO.ORDER_DATE
,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY
,IM.ITEM_NAME,SM.SCREEN_NAME AS SCREEN,CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO,SI.SAL_INV_VDATE AS BILLDATE
,0 AS RATE
,0 AS QUANTITY
,0  AS NETTOTAL,SAM.SALESMAN_NAME AS SALESMAN,CMP.CMP_ALIAS,CGM.CUST_GRP_NAME AS CUSTOMEGROUP
FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.CMP_CODE=SO.CMP_CODE AND SI.CONFNO=SO.CONFNO AND SI.ORDERNO=SO.SALES_ORDERNO AND SI.FLAG='S' AND SI.SAL_INV_VDATE>='"+@TODATE+"'
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG AND SO.FYEAR=SI.SAL_FYEAR
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
LEFT JOIN " +@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE SO.CMP_CODE IN("+@CMP_CODE+") AND SO.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'                                
               "

	

    SET @SQL1= " 
UNION ALL
SELECT SI.CONFNO,SI.CONFDATE AS CONFDATE,SI.ORDERNO,SI.ORDERDATE
,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY
,IM.ITEM_NAME,SM.SCREEN_NAME AS SCREEN,CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO,SI.SAL_INV_VDATE AS BILLDATE
,SID.SAL_INV_RATE AS RATE,SID.SAL_INV_QTY AS QUANTITY
,((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) ) AS NETTOTAL     
,SAM.SALESMAN_NAME AS SALESMAN,CMP.CMP_ALIAS,CGM.CUST_GRP_NAME AS CUSTOMEGROUP
FROM "+@DATABASENAME+"SALES_INVOICE SI                 
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID       
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID         
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN " +@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE SI.CMP_CODE IN("+@CMP_CODE+")  AND SI.FLAG='S' AND SI.SAL_INV_VDATE>='"+@TODATE+"'
AND SI.CONFDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
) AS DETAIL
GROUP BY  CONFNO,CONFDATE,SALES_ORDERNO,ORDER_DATE,ITEM_NAME,SCREEN,BILLNO ,BILLDATE
,PARTY,PARTYCITY,AGENT,AGENTCITY,RATE,SALESMAN,CMP_ALIAS,CUSTOMEGROUP
HAVING SUM(NETTOTAL)>0     
ORDER BY CONFNO,BILLDATE,BILLNO,ITEM_NAME
               "

	
	
END
PRINT @SQL
PRINT @SQL1
EXEC (@SQL+@SQL1)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_ORDERREPORT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_ORDERREPORT]
(
	@DATABASENAME AS NVARCHAR(50),
	@CMP_CODE AS NVARCHAR(20),
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20),
	@RPT_WISE AS INT,
	@RPT_TYPE AS INT,
	@TEMPTABLE AS NVARCHAR(100)
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINCOND AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
SET @SQL1=""
SET @SQL2=""
SET @JOINCOND=""
SET @SQLJOIN="" 
   BEGIN
       IF @RPT_TYPE=1
            SET @JOINCOND=" AND SOD.PENDINGBALES=0"
       ELSE IF @RPT_TYPE=2
            SET @JOINCOND=" AND SOD.PENDINGBALES>0"       
       ELSE IF @RPT_TYPE=3
            SET @JOINCOND=""

   END 
   BEGIN 
          IF @RPT_WISE=1
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
          ELSE IF @RPT_WISE=2 
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
          ELSE IF @RPT_WISE=3
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
          ELSE IF @RPT_WISE=4
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
          ELSE IF @RPT_WISE=5
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
         ELSE IF @RPT_WISE=6
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
         ELSE IF @RPT_WISE=7
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
   END
BEGIN	
	SET NOCOUNT ON;
    SET  @SQL1="
SELECT LGR_ID,PARTY,AGENT_ID,AGENT,STATION_ID,CITY_NAME,DOCNO,DATE,ORDERNO,ORDERDATE,SCREEN_ID,SCREEN,INVNO,INVDATE,
                  ORDERBALES,DESPATCHBALES,SAL_INV_LRNO,ITEM_ID,ITEM,ORDQTY,ISSQTY,FLAG,FYEAR,SALESMAN
FROM(

                  SELECT distinct SO.LGR_ID,LM.LGR_NAME AS PARTY,SO.AGENT_ID,ALM.LGR_NAME AS AGENT,SO.STATION_ID,CM.CITY_NAME,
                  SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,
                  SOD.SCREEN_ID,SM.SCREEN_NAME AS SCREEN,0 AS INVNO,'' AS INVDATE,
                  SOD.BALES AS ORDERBALES,SOD.DELIVEREDBALES AS DESPATCHBALES,'' SAL_INV_LRNO,SOD.ITEM_ID,IM.ITEM_NAME AS ITEM,
                  SOD.PIECES AS ORDQTY,((SOD.PIECES/SOD.BALES )*SOD.PENDINGBALES) AS ISSQTY,'OD' AS FLAG,SO.FYEAR,SAM.SALESMAN_NAME AS SALESMAN
                  FROM "+@DATABASENAME+"SALES_ORDER SO
			      INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
				  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
				  LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
				  INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
				  INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
				  INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID                  
                  LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
                  " + @SQLJOIN + "
				  WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+ @TODATE +"' AND SO.CMP_CODE="+@CMP_CODE                                
                  + @JOINCOND +"  UNION ALL       "
SET  @SQL2="

                  SELECT distinct SO.LGR_ID,LM.LGR_NAME AS PARTY,SO.AGENT_ID,ALM.LGR_NAME AS AGENT,SO.STATION_ID,CM.CITY_NAME,
                  SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,
                  SOD.SCREEN_ID,SM.SCREEN_NAME AS SCREEN,SI.SAL_INV_BILL_NO AS INVNO,SI.SAL_INV_VDATE AS INVDATE,
                  SOD.BALES AS ORDERBALES,SOD.DELIVEREDBALES AS DESPATCHBALES,SI.SAL_INV_LRNO,SOD.ITEM_ID,IM.ITEM_NAME AS ITEM,
                  SOD.PIECES AS ORDQTY,((SOD.PIECES/SOD.BALES )*SOD.PENDINGBALES) AS ISSQTY,'INV' AS FLAG,SO.FYEAR,SAM.SALESMAN_NAME AS SALESMAN
                  FROM "+@DATABASENAME+"SALES_ORDER SO
			      INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
				  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
				  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
				  INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
				  INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
				  INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
                  INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO AND SID.CMP_CODE=SO.CMP_CODE AND SOD.SCREEN_ID=SID.SCREEN_ID AND SOD.ITEM_ID=SID.ITEM_ID 
				  INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID	AND SI.SAL_FYEAR=SO.FYEAR
                  LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
                  " + @SQLJOIN + "
				  WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+ @TODATE +"' AND SO.CMP_CODE="+@CMP_CODE                                
                  + @JOINCOND +"
                 ) AS DETAIL ORDER  BY INVDATE
                "

    
	EXEC(@SQL1+@SQL2)
    PRINT @SQL1
    PRINT @SQL2
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_ORDERREPORT_NEW]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO













/*
-- =============================================
-- AUTHOR:		HIREN B DOSHI
-- ALTER_DATE: 18/10/2012
-- DESCRIPTION:	THIS PROCEDURE USED FOR ORDER REPORT RUBIA INVOICE TYPE IN SALES ORDER REPORT
-- REPORT_NAME: ORDERREPORTNEW.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
SELECT * FROM ##4692
PROC_ORDERREPORT_NEW 'ACC2014_2015.DBO.','1','01/APR/2014','31/MAR/2015',4,2,'##4572',''
*/
CREATE PROCEDURE [dbo].[PROC_ORDERREPORT_NEW]
(
@DATABASENAME AS NVARCHAR(50),
@CMP_CODE AS NVARCHAR(20),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@RPT_WISE AS INT,
@RPT_TYPE AS INT,
@TEMPTABLE AS NVARCHAR(100),
@INVTYPE  AS NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINCOND AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLSCREEN AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000) SET @SQL2=""
DECLARE @SQL3 AS NVARCHAR(4000) SET @SQL3=""
DECLARE @SQLINVOICE AS NVARCHAR(1000)
DECLARE @SQLORDERJOIN AS NVARCHAR(1000)
DECLARE @SQLORDER AS NVARCHAR(1000)

DECLARE @SQLORDERTYPE AS NVARCHAR(1000)

SET @SQL = ""
SET @SQL1 = ""
SET @JOINCOND=""
SET @SQLJOIN = ""
SET @SQLSCREEN = ""
SET @SQLINVOICE = ""
SET @SQLORDERJOIN = ""
SET @SQLORDERTYPE = ""
SET @SQLORDER = ""

BEGIN
IF @RPT_TYPE = 1 /* REPORT TYPE : PAID */
SET @JOINCOND = " AND SOD.PENDINGBALES = 0 "
ELSE IF @RPT_TYPE = 2 /*  REPORT TYPE : PENDING */
SET @JOINCOND = " AND SOD.PENDINGBALES > 0"
ELSE IF @RPT_TYPE = 3 /* REPORT TYPE: ALL */
SET @JOINCOND = ""
END
BEGIN
IF @RPT_WISE=1 /* PARTY WISE */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
	SET @SQLORDER = " PARTY,PARTYID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=2 /* AGENT WISE  */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
	SET @SQLORDER = " AGENT,AGENTID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=3 /* AGENT-PARTY WISE */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
	SET @SQLORDER = " AGENT,AGENTID,PARTY,PARTYID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=4 /* ITEM WISE */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
	SET @SQLORDER = " ITEM,ITEM_ID,SO.CONFNO,ORD"
END
ELSE IF @RPT_WISE=5 /* SCREEN WISE */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
	SET @SQLORDER = " SCREEN,SCREEN_ID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=6 /* SALES MAN */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
	SET @SQLORDER = " SALESMAN,SALESMANID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=7 /* SALES MAN - AGENT */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
	SET @SQLORDER = "SALESMAN,SALESMANID,AGENT,AGENTID,SO.CONFNO,IM.ITEM_NAME,ORD"
END
ELSE IF @RPT_WISE=8 /* CONFO NO WISE */
BEGIN
	SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SO.SAL_ORDER_ID"
	SET @SQLORDER = " SO.CONFNO,IM.ITEM_NAME,ORD "
END


END
BEGIN
IF @INVTYPE = "COTTON"
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
ELSE IF @INVTYPE = "RUBIA"
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID AND SOD.SCREEN_ID = SID.SCREEN_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
ELSE 
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
END
BEGIN
IF @INVTYPE = "RUBIA"
SET @SQLORDERTYPE = " AND SO.ORDER_TYPE = 'B' "
END
BEGIN
SET NOCOUNT ON;
SET @SQL = " SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
CM.CITY_NAME AS STATION,SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,
SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_ID,IM.ITEM_NAME AS ITEM,ISNULL(SM.SCREEN_ID,0) AS SCREEN_ID,SM.SCREEN_NAME AS SCREEN,
SOD.ITEM_CUT ,SAM.SALESMAN_NAME AS SALESMAN, /*SOD.BALES AS ORDERBALES,*/
(CASE SOD.BALESPCSMTR WHEN 'BALES' THEN SOD.BALES WHEN 'PCS' THEN SOD.PIECES ELSE SOD.QUANTITY END) AS  ORDERBALES,
ISNULL((CASE SOD.BALESPCSMTR WHEN 'MTR' THEN SUM(SAL_INV_QTY) WHEN 'PCS' THEN SUM(SAL_INV_PCS)
ELSE COUNT(SI.SAL_INV_ID) END),0) AS  DESPATCHBALES,
(CASE SOD.BALESPCSMTR WHEN 'BALES' THEN SOD.PENDINGBALES 
WHEN 'PCS' THEN SOD.PENDINGPIECES ELSE SOD.PENDINGQTY END) AS  PENDING,
/*,SOD.PENDINGBALES AS PENDING,*/
SI.SAL_INV_BILL_NO AS INVNO,SI.SAL_INV_VDATE AS INVDATE,MAX(SID.SAL_INV_BALENO) AS BALENO,SI.SAL_INV_LRNO,SO.CMP_CODE
,'SALES' AS O_FLAG,1 AS ORD,SOD.REMARK,ISNULL(CGM.CUST_GRP_NAME,'') AS CUST_GRP_NAME,ISNULL(SOD.RATE,0 ) AS RATE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(ALM.SALESMAN_ID,0) AS SALESMANID

FROM "+@DATABASENAME+" SALES_ORDER SO
INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
"+@SQLINVOICE+"
LEFT JOIN "+@DATABASENAME+" SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.SAL_FYEAR=SO.FYEAR
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID "

SET @SQL1 = " LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
INNER JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
"+@SQLSCREEN+"
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+" SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID

"+@SQLJOIN+"
WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
"+@SQLORDERTYPE+"
"+@JOINCOND+ " 
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME,
CM.CITY_NAME,SO.CONFNO,SO.VCH_DATE,
SO.SALES_ORDERNO,SO.ORDER_DATE,IM.ITEM_ID,IM.ITEM_NAME,ISNULL(SM.SCREEN_ID,0),SM.SCREEN_NAME,SAM.SALESMAN_NAME,SOD.BALES,SOD.PENDINGBALES,
SI.SAL_INV_BILL_NO,SI.SAL_INV_VDATE,SI.SAL_INV_LRNO,SO.CMP_CODE,SOD.REMARK,SOD.BALESPCSMTR,CGM.CUST_GRP_NAME,
SOD.BALES,SOD.PIECES,SOD.QUANTITY,SOD.PENDINGBALES,SOD.PENDINGPIECES,SOD.PENDINGQTY,SOD.ITEM_CUT,SOD.RATE
,LM.LGR_ID,ALM.LGR_ID,ALM.SALESMAN_ID
"
SET @SQL2=" UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
CM.CITY_NAME AS STATION,SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,
SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_ID,IM.ITEM_NAME AS ITEM,ISNULL(SM.SCREEN_ID,0) AS SCREEN_ID,SM.SCREEN_NAME AS SCREEN,
SOD.ITEM_CUT,SAM.SALESMAN_NAME AS SALESMAN,0 AS ORDERBALES,SOCD.CANCELBALES AS DESPATCHBALES,0 AS PENDING,
SOC.DOCNO AS INVNO,SOC.CANCELLATION_DATE AS INVDATE,'' AS BALENO,'' AS SAL_INV_LRNO,SO.CMP_CODE,'CANCEL' AS O_FLAG,2 AS ORD,
'' AS REMARK,ISNULL(CGM.CUST_GRP_NAME,'') AS CUST_GRP_NAME,ISNULL(SOD.RATE,0 ) AS RATE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(ALM.SALESMAN_ID,0) AS SALESMANID

FROM "+@DATABASENAME+"SALESORDER_CANCELLATION SOC 
INNER JOIN "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID
INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.FLAG=SOC.FLAG AND SO.LGR_ID=SOCD.LGR_ID AND SO.CONFNO=SOCD.CONFNO
"+@SQLORDERJOIN+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID 
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
"
SET @SQL3="
INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
"+@SQLSCREEN+"
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID

"+@SQLJOIN+"
WHERE 
SO.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SO.CMP_CODE IN ("+@CMP_CODE+")
"+@SQLORDERTYPE+"
"+@JOINCOND+ " 
ORDER BY "+@SQLORDER+" "

EXEC (@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL    
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
END





















GO

/****** Object:  StoredProcedure [dbo].[PROC_OS_RECONCILLATION]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
select * from tempdb..sysobjects where name like '##%'
PROC_OS_RECONCILLATION '1','ACC2013_2014.DBO.','31/MAR/2014','2013','##2652',1,1,''
PROC_OS_RECONCILLATION '1','ACC2017_2018.DBO.','30/mar/2018','2018','##5744',1,1,''
*/
CREATE PROCEDURE [dbo].[PROC_OS_RECONCILLATION]
(
@CMP_CODE AS NVARCHAR(50),
@DATABASENAME AS NVARCHAR(400),
@DATE AS NVARCHAR(20),
@YEAR AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(100),
@ALL_FIDD AS INT,
@RPT_WISE AS INT,
@PREVDATABASE AS NVARCHAR(50)
)	
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
DECLARE @SQL12 AS NVARCHAR(4000)
DECLARE @SQL13 AS NVARCHAR(4000)
DECLARE @SQL14 AS NVARCHAR(4000)
DECLARE @SQL15 AS NVARCHAR(4000)
DECLARE @SQLFINAL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @ALL_FIDDSQL AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)

SET @SQL1="" 
SET @SQL2="" 
SET @SQL3="" 
SET @SQL4="" 
SET @SQL5="" 
SET @SQL6="" 
SET @SQL7="" 
SET @SQL8="" 
SET @SQL9="" 
SET @SQL10="" 
SET @SQL15=""
SET @SQLJOIN=""
SET @ALL_FIDDSQL=""
SET @ORDERBYSQL=""

BEGIN 
IF @ALL_FIDD=1 
SET @ALL_FIDDSQL=""
ELSE IF @ALL_FIDD=0 
SET @ALL_FIDDSQL= " HAVING CONVERT(NUMERIC(18,2),SUM(LEDGERAMOUNT)-SUM(OUTSTANDINGAMOUNT))<>0"
END


BEGIN
IF @RPT_WISE=1     
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL="ORDER BY PARTYNAME,PARTYID,PARTYCITY,AGENT,AGENT_ID "
IF @RPT_WISE=2 
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL="ORDER BY AGENT,AGENT_ID,PARTYNAME,PARTYID,PARTYCITY "
END 





IF @PREVDATABASE<>""  
BEGIN
SET @SQL12=" UNION ALL
SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) END) AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@PREVDATABASE+"TRAN_DETAIL TD 
INNER JOIN "+@PREVDATABASE+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @PREVDATABASE + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID
" + @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@DATE+"' AND TD.PARTAMOUNT>0 AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")        
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL " 
    
SET @SQL13=" SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE TD.PARTAMOUNT END)AS  OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@PREVDATABASE+"TRAN_DETAIL TD 
INNER JOIN "+@PREVDATABASE+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID        
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @PREVDATABASE + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@DATE +"'  AND (TD.TRAN_TYPE='J')  AND TD.CMP_CODE IN("+@CMP_CODE +")    
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL "  

SET @SQL14=" SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,0-AE.PARTAMOUNT AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@PREVDATABASE+"ADVANCE_ENTRY AE         
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID        
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @PREVDATABASE + "GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE AE.VDATE<='"+@DATE+ "' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE +")                   
AND (AE.REC_TRANS=0 OR   AE.REC_TRANS IS NULL)  AND GM.GRP_ID=26
"
END

BEGIN	
SET NOCOUNT ON;
SET @SQL1=" SELECT PARTYNAME,PARTYID,PARTYCITY,SUM(LEDGERAMOUNT)AS LEDGERAMOUNT,SUM(OUTSTANDINGAMOUNT)AS OUTSTANDINGAMOUNT,AGENT,AGENT_ID,(CASE WHEN SUM(LEDGERAMOUNT)-SUM(OUTSTANDINGAMOUNT)>=0 THEN 'DR' ELSE 'CR' END ) AS DRCR  FROM (
SELECT PARTYNAME, PARTYID,PARTYCITY,(SUM(DETAIL.DRAMOUNT)-SUM(DETAIL.CRAMOUNT))  AS LEDGERAMOUNT,0 AS OUTSTANDINGAMOUNT,AGENT,AGENT_ID,
'L' AS FLAG
FROM( 
SELECT LM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"TRAN_MASTER TM  
/*INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE*/    
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID 
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.CMP_CODE ="+ @CMP_CODE +" AND TM.TRAN_TYPE <> 'J' AND TM.TRAN_DATE BETWEEN '01/APR/"+@YEAR+"' AND '"+@DATE+ "'
AND GM.GRP_ID=26
UNION ALL "

SET @SQL2=" SELECT  LM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID= LM1.LGR_ID 
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.CMP_CODE="+ @CMP_CODE + " AND TM.TRAN_TYPE<> 'J' AND TM.TRAN_DATE BETWEEN '01/APR/"+@YEAR+"' AND '"+@DATE+ "'
 AND GM.GRP_ID=26
UNION ALL 
SELECT LM.LGR_NAME,LM.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM  "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ.ENTRYMATCH=AJ1.ENTRYMATCH  AND AJ.NARRATION = AJ1.NARRATION
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AJ.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE AJ.VDATE  BETWEEN '01/APR/"+@YEAR+"' AND '"+@DATE+ "'  AND AJ.CMP_CODE="+ @CMP_CODE  +"  
AND LD.GRP_ID=26
UNION ALL "

SET @SQL3=" SELECT LM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM  "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  AND TM.CMP_CODE=JD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID    
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN  " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.CMP_CODE="+ @CMP_CODE +"  AND TM.TRAN_DATE BETWEEN '01/APR/"+@YEAR+"' AND '"+@DATE+ "'  AND TM.TRAN_TYPE  IN ('J','DN','CN')  
AND GM.GRP_ID=26
UNION ALL "
/* 
FOR OPENING BALANCE
*/
SET @SQL4=" SELECT  LM.LGR_NAME AS PARTY,TM.TRAN_MASTER_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
CASE WHEN TM.TRAN_DRCR = 'D' THEN TM.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT, 
CASE WHEN TM.TRAN_DRCR = 'C' THEN TM.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID 
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TM.TRAN_MASTER_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.TRAN_DATE <'01/APR/"+@YEAR+"' AND TM.CMP_CODE="+ @CMP_CODE +"  AND TM.TRAN_TYPE <> 'J' 
 AND GM.GRP_ID=26
UNION ALL   "

SET @SQL5=" SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT, 
CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID 
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TD.TRAN_ID = TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE   AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE  TM.TRAN_DATE <'01/APR/"+@YEAR+"'  AND TD.CMP_CODE ="+ @CMP_CODE  + " AND GM.GRP_ID=26
UNION ALL "

SET @SQL6=" SELECT LM.LGR_NAME AS PARTY,AJ.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
CASE WHEN AJ.DRAMOUNT IS NOT NULL THEN AJ.DRAMOUNT ELSE 0 END AS DEBITAMOUNT, 
CASE WHEN AJ.CRAMOUNT IS NOT NULL THEN AJ.CRAMOUNT ELSE 0 END AS CREDITAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID 
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AJ.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AJ.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE AJ.VDATE <'01/APR/"+@YEAR+"'  AND AJ.CMP_CODE ="+ @CMP_CODE + "  AND GM.GRP_ID=26
UNION ALL  "

SET @SQL7=" SELECT LM.LGR_NAME AS PARTY,LD.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
CASE WHEN LGR_OP_DRCR = 'D' THEN LGR_OP_BAL WHEN LGR_OP_DRCR = '' THEN LGR_OP_BAL ELSE 0 END AS DEBITAMOUNT,
CASE WHEN LGR_OP_DRCR = 'C' THEN LGR_OP_BAL WHEN LGR_OP_DRCR = '' THEN LGR_OP_BAL ELSE 0 END AS CREDITAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID 
FROM "+@DATABASENAME+"LEDGER_DETAIL LD 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID               
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE LD.CMP_CODE ="+ @CMP_CODE + "  AND GM.GRP_ID=26
) AS DETAIL GROUP BY PARTYNAME,PARTYID,PARTYCITY,AGENT,AGENT_ID
UNION ALL   
"
/* 
OUT STANDING 
*/
SET @SQL8=" SELECT  PARTY,PARTYID,PARTYCITY,0 AS LEDGERAMOUNT, (SUM(OUSTANDINGAMOUNT)) AS OUSTANDINGAMOUNT,AGENT,AGENT_ID
, 'O' AS FLAG
FROM(
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,(PD.BILL_AMOUNT+SUM((CASE WHEN AM.INTEREST IS NULL THEN 0 ELSE AM.INTEREST END ))-
SUM((CASE WHEN AM.ADJUSTAMT IS NULL THEN 0 ELSE AM.ADJUSTAMT END))-SUM((CASE WHEN AM.TOTAL IS NULL THEN 0 ELSE AM.TOTAL  END ) )-SUM((CASE WHEN AM.TDS_AMOUNT IS NULL THEN 0 ELSE AM.TDS_AMOUNT  END ) )
-SUM((CASE WHEN AM.INTREC IS NULL THEN 0 ELSE AM.INTREC END))) AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"PARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+"ADJMASTER AM ON AM.BILLNO=PD.BILL_NO AND AM.FLAG=PD.JOBFLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+@DATE +"'
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID           
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND PD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE  PD.DATE<='"+@DATE + "' AND PD.CMP_CODE IN("+ @CMP_CODE + ") AND GM.GRP_ID=26
GROUP BY LM.LGR_ID,LM.LGR_NAME,PD.BILL_AMOUNT,PD.BILL_NO,CM.CITY_NAME,PD.JOBFLAG,PD.VCODE,ALM.LGR_NAME ,ALM.LGR_ID
UNION ALL  "
SET @SQL9=" SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(
CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) END) AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@DATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0  AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")  AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)      
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM "+@DATABASENAME+" PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+" PARTYDETAIL WHERE JOBFLAG='DN')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+" PARTYDETAIL WHERE JOBFLAG='BP')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+" PARTYDETAIL WHERE JOBFLAG='CP')	
AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL " 
    
SET @SQL10=" SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE TD.PARTAMOUNT END)AS  OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID  
" + @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@DATE +"'  AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  AND  
(TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  
OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='DN') 
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='BP')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='CP')
AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL "  

SET @SQL15=" SELECT LM.LGR_NAME AS PARTY,TD.TRAN_DETAIL_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,
(
CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (0-TD.PARTAMOUNT) ELSE 0 END) END) AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE  AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@DATE+"' AND TD.PARTAMOUNT>0   AND 
(TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR 
TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  
AND TD.CMP_CODE IN(" + @CMP_CODE +")  AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)      
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_ID=26
UNION ALL "  

SET @SQL11=" SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PARTYID,CM.CITY_NAME AS PARTYCITY,0-AE.PARTAMOUNT AS OUSTANDINGAMOUNT,
ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID
FROM "+@DATABASENAME+"ADVANCE_ENTRY AE         
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
INNER JOIN " + @DATABASENAME + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
" + @SQLJOIN + "
WHERE AE.VDATE<='"+@DATE+ "' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE +")   AND GM.GRP_ID=26

"
SET @SQLFINAL="      ) AS A   GROUP BY PARTYID,PARTY,PARTYCITY ,AGENT_ID,AGENT
) AS B  GROUP BY PARTYNAME,PARTYID,PARTYCITY,AGENT_ID,AGENT  "+ @ALL_FIDDSQL + ""

END
EXECUTE (@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6+@SQL7+@SQL8+@SQL9+@SQL10+@SQL15+@SQL11+@SQL12+@SQL13+@SQL14+@SQLFINAL)

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @SQL7
PRINT @SQL8
PRINT @SQL9
PRINT @SQL10
PRINT @SQL15
PRINT @SQL11
PRINT @SQL12
PRINT @SQL13
PRINT @SQL14

PRINT @SQLFINAL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_OUTGATEPASS_PRINTOUT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
