/*
-- =============================================
-- ALTER_AUTHOR  : BIREN
-- ALTER_DATE    : 24/07/2015 7:15 PM
-- REPORT_FORM	  :	
-- CRYSTAL_REPORT :	
-- =============================================
PROC_OUTGATEPASS_PRINTOUT 'ACC2015_2016.DBO.',1,500,'MIP',1,'##1028'
*/
CREATE PROCEDURE [dbo].[PROC_OUTGATEPASS_PRINTOUT]
(
@DATABASENAME AS NVARCHAR(100),
@FROMNO AS NVARCHAR(100),
@TONO AS NVARCHAR(100),
@RPT_TYPE AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(10),
@TEMPTABLE NVARCHAR(20)
)
AS
BEGIN

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
SET @STRSQL=""
SET @JOINSQL=""
SET @FIELDSQL=""

IF @TEMPTABLE <> "" 
begin
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GPM.CMP_CODE"
	SET @FIELDSQL = "TT.TYPE"
end	
ELSE
begin
	SET @FIELDSQL = "'' AS TYPE"
end


SET @STRSQL="SELECT GPM.GATE_OUTPASS_ID,GPM.DOCNO,CONVERT(NVARCHAR,GPM.GDATE,103) AS VDATE,ISNULL(GPM.HEAD,'') AS HEAD,
ISNULL(GPM.PARTY_ID,0) AS PARTY_ID,ISNULL(GPM.AGENT_ID,0) AS AGENT_ID,ISNULL(GPM.TRANSPORT_ID,0) AS TRANSPORT_ID,
ISNULL(GPM.DRIVER_ID,0) AS DRIVER_ID,ISNULL(GPM.VEHICLENO,'') AS VEHICLENO,ISNULL(GPM.LRNO,'') AS LRNO,
ISNULL(GPM.PURPOSE_ID,0) AS PURPOSE_ID,ISNULL(GPM.RET_NO,'') AS RET_NO,ISNULL(GPM.NARRATION,'') AS NARRATION,
ISNULL(GPM.FLAG,'') AS FLAG,ISNULL(GPM.CHALLANNO,'') AS CHALLANNO,ISNULL(LM.LGR_NAME,'') AS PARTY,
ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,ISNULL(DM.DRIVER_NAME,'') AS DRIVER,
ISNULL(PM.PURPOSE_NAME,'') AS PURPOSE,
ISNULL(GPD.SR_NO,0) AS SR_NO,ISNULL(GPD.ITEM_ID,0) AS ITEM_ID,ISNULL(GPD.UNIT_ID,0) AS UNIT_ID,
ISNULL(GPD.PCS,0) AS PCS,ISNULL(GPD.QTY,0) AS QTY,ISNULL(GPD.DELIVEREDQTY,0) AS DELIVEREDQTY,
ISNULL(GPD.PENDINGQTY,0) AS PENDINGQTY,ISNULL(GPD.REMARKS,'') AS REMARKS,ISNULL(GPD.SIZE_ID,0) AS SIZE_ID,
ISNULL(GPD.LOT_ID,0) AS LOT_ID,ISNULL(GPD.PACKING,0) AS PACKING,ISNULL(IM.ITEM_NAME,0) AS ITEM,
ISNULL(SM.SIZE_NAME,0) AS SIZE,ISNULL(UM.UNIT_NAME,0) AS UNIT,"+@FIELDSQL+",
ISNULL(HM.HASTE_NAME,'') AS HASTE,ISNULL(HM.HASTE_ID,0) AS HASTEID

FROM "+@DATABASENAME+"GATE_OUTPASS_MASTER GPM 
INNER JOIN "+@DATABASENAME+"GATE_OUTPASS_DETAIL GPD ON GPM.GATE_OUTPASS_ID = GPD.GATE_OUTPASS_ID AND GPM.CMP_CODE = GPD.CMP_CODE AND GPM.FLAG = GPD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GPM.PARTY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = GPM.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"TRANSPORT_MASTER TM  ON TM.TRANSPORT_ID = GPM.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID = GPM.DRIVER_ID
LEFT JOIN  "+@DATABASENAME+"PURPOSE_MASTER PM  ON PM.PURPOSE_ID = GPM.PURPOSE_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GPD.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = GPD.SIZE_ID
LEFT JOIN "+@DATABASENAME+"HASTE_MASTER HM ON HM.HASTE_ID = GPM.HASTE_ID
"+@JOINSQL+"
WHERE GPM.CMP_CODE="+@CMP_CODE+" AND GPM.DOCNO >= "+ @FROMNO +" AND DOCNO <="+@TONO+" AND  GPM.FLAG='"+@RPT_TYPE+"'
ORDER BY GPM.GATE_OUTPASS_ID,TYPE,GPD.SR_NO
"
	
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

