/*  
-- =============================================
-- ALTER_AUTHOR    : <BIREN>
-- ALTER_DATE      : <14/04/2015 4:58 PM>
-- REPORT_FORM		: <RFRMOUTGATEPASSREG.CS>
-- CRYSTAL_REPORT	: <CHEMICALOUTGATEPASSREG.RPT,MACHINARYOUTGATEPASSREG.RPT>
-- =============================================  
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
 PROC_OUTGATEPASSREG N'1', N'Acc2015_2016.Dbo.', 17, 1, N'01/Apr/2015', N'10/Sep/2015', N'##2476', 2
*/   
CREATE PROCEDURE [dbo].[PROC_OUTGATEPASSREG]
(
    @CMP_CODE NVARCHAR(10),
    @DATABASENAME NVARCHAR(50),
    @RPT_WISE INT,
    @RPT_TYPE INT,	
    @FROMDATE AS NVARCHAR(20),
    @TODATE AS NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
	@GP_TYPE INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @GPSQL NVARCHAR(100)
DECLARE @SIZESQL NVARCHAR(100)
DECLARE @STRORDERBY NVARCHAR(200)
DECLARE @SQL3 NVARCHAR(4000)

SET @SQL = ""
SET @SQL1=""
SET @SQL2=""
SET @GPSQL = ""
SET @JOINSQL=""
SET @TYPESQL=""
SET @SIZESQL = ""
SET	@STRORDERBY=""
SET @SQL3=""

IF @RPT_WISE = 1 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
	SET	@STRORDERBY=" ORDER BY PARTY,PARTY_ID"
END	
ELSE IF @RPT_WISE = 2
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
	SET	@STRORDERBY=" ORDER BY AGENT,AGENT_ID"
END	
ELSE IF @RPT_WISE = 3
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRANSPORT_ID"
	SET	@STRORDERBY=" ORDER BY TRANSPORT,TRANSPORT_ID"
END	
ELSE IF @RPT_WISE = 4
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=DM.DRIVER_ID"
	SET	@STRORDERBY=" ORDER BY DRIVER,DRIVER_ID"
END	
ELSE IF @RPT_WISE = 5
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PM.PURPOSE_ID"
	SET	@STRORDERBY=" ORDER BY PURPOSE,PURPOSE_ID"
END
ELSE IF @RPT_WISE = 6
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GOM.HEAD"
	SET	@STRORDERBY=" ORDER BY HEAD"
END	
ELSE IF @RPT_WISE = 7 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET	@STRORDERBY=" ORDER BY ITEM,ITEM_ID"
END	
ELSE IF @RPT_WISE = 8 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
	SET	@STRORDERBY=" ORDER BY ITEMGRP,ITEM_GRP_ID"
END	
ELSE IF @RPT_WISE = 9
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM.SIZE_ID"
	SET	@STRORDERBY=" ORDER BY SIZE,SIZE_ID"
END	
ELSE IF @RPT_WISE = 10
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
	SET	@STRORDERBY=" ORDER BY PARTY,PARTY_ID,ITEM,ITEM_ID"
END	
ELSE IF  @RPT_WISE = 11
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
	SET	@STRORDERBY=" ORDER BY PARTY,PARTY_ID"
END	
ELSE IF  @RPT_WISE = 12 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET	@STRORDERBY=" ORDER BY ITEM,ITEM_ID,SIZE,SIZE_ID"
END	
ELSE IF  @RPT_WISE = 13
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
	SET	@STRORDERBY=" ORDER BY ITEMGRP,ITEM_GRP_ID,ITEM,ITEM_ID"
END	
ELSE IF @RPT_WISE = 14	
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GOM.GATE_OUTPASS_ID"
		SET	@STRORDERBY=" ORDER BY GPNO "
END	
ELSE IF @RPT_WISE = 15 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET	@STRORDERBY=" ORDER BY ITEM,ITEM_ID"
END	
ELSE IF @RPT_WISE = 16	
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ISNULL(GOM.CHALLANNO,0)"
	SET	@STRORDERBY=" ORDER BY CHALLANNO "
END	
ELSE IF @RPT_WISE = 17
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=HM.HASTE_ID "
	SET	@STRORDERBY=" ORDER BY HASTE,HASTEID"
END	
ELSE IF @RPT_WISE = 18
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID "
	SET	@STRORDERBY=" ORDER BY PARTY,PARTY_ID,HASTE,HASTEID"
END	


IF @RPT_TYPE=1
SET @TYPESQL=" AND GOD.PENDINGQTY=0 "
IF @RPT_TYPE=2
SET @TYPESQL=" AND GOD.PENDINGQTY>0 "
IF @RPT_TYPE=3
SET @TYPESQL=""

IF @GP_TYPE = 1
BEGIN
	SET @GPSQL = "AND GOD.FLAG='CHP'"
	SET @SIZESQL = ""
END
ELSE IF @GP_TYPE = 2
BEGIN
	SET @GPSQL = "AND GOD.FLAG='MIP'"
	SET @SIZESQL = " AND CCD.SIZE_ID = GOD.SIZE_ID " 
END	

BEGIN
SET NOCOUNT ON;
			

BEGIN
SET @SQL =  "
			SELECT GATE_OUTPASS_ID,GPNO,GPDATE,HEAD,VEHICLENO,LRNO,RETNO,NARRATION,SR_NO,NOS,REMARKS,CHALLANNO, PACKING,PARTY,AGENT,TRANSPORT,DRIVER,PURPOSE,ITEM,UNIT,SIZE,ITEMGRP,SUM(QTY) AS QTY,
			SUM(ISNULL(DELIQTY,0)) AS DELIQTY,(SUM(QTY)-SUM(ISNULL(DELIQTY,0))) AS PENDQTY,ALIAS,PARTYCITY,
			AGENTCITY,NICKNAME,PARTY_ID,AGENT_ID,TRANSPORT_ID,DRIVER_ID,PURPOSE_ID,ITEM_ID,SIZE_ID,ITEM_GRP_ID,HASTE,HASTEID
			FROM (
			SELECT GOM.GATE_OUTPASS_ID,ISNULL(DOCNO,0) AS GPNO,GOM.GDATE AS GPDATE,ISNULL(HEAD,'') AS HEAD,
			ISNULL(VEHICLENO,'') AS VEHICLENO,ISNULL(LRNO,'') AS LRNO,ISNULL(RET_NO,'') AS RETNO,
			ISNULL(NARRATION,'') AS NARRATION,ISNULL(SR_NO,0) AS SR_NO,ISNULL(PCS,0) AS NOS,
			ISNULL(REMARKS,'') AS REMARKS,ISNULL(GOM.CHALLANNO,0) AS CHALLANNO,ISNULL(PACKING,0) AS PACKING,
			ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,
			ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,ISNULL(DM.DRIVER_NAME,'') AS DRIVER,
			ISNULL(PM.PURPOSE_NAME,'') AS PURPOSE,
			ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(UM.UNIT_NAME,'') AS UNIT,
			ISNULL(SM.SIZE_NAME,'') AS SIZE,ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP, 
			ISNULL(QTY,0) AS QTY,0 AS DELIQTY,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS,
			ISNULL(LCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			ISNULL(IM.NICK_NAME,'') AS NICKNAME,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
			ISNULL(GOM.TRANSPORT_ID,0) AS TRANSPORT_ID,ISNULL(DM.DRIVER_ID,0) AS DRIVER_ID,ISNULL(PM.PURPOSE_ID,0) AS PURPOSE_ID,
			ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(SM.SIZE_ID,0) AS SIZE_ID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEM_GRP_ID,
			ISNULL(HM.HASTE_NAME,'') AS HASTE,ISNULL(HM.HASTE_ID,0) AS HASTEID
			
			FROM "+@DATABASENAME+"GATE_OUTPASS_MASTER GOM
			INNER JOIN "+@DATABASENAME+"GATE_OUTPASS_DETAIL GOD ON GOM.GATE_OUTPASS_ID = GOD.GATE_OUTPASS_ID
			AND GOM.CMP_CODE = GOD.CMP_CODE AND GOM.FLAG = GOD.FLAG
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GOM.PARTY_ID
			LEFT  JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = GOM.AGENT_ID
			LEFT  JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GOM.TRANSPORT_ID
			LEFT  JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID= GOM.DRIVER_ID
			LEFT  JOIN "+@DATABASENAME+"PURPOSE_MASTER PM ON PM.PURPOSE_ID= GOM.PURPOSE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GOD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
			LEFT  JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = GOD.SIZE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = GOM.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"HASTE_MASTER HM ON HM.HASTE_ID = GOM.HASTE_ID
			 "+ @JOINSQL +"
			WHERE GOM.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+" "+@GPSQL+" /*GOM.RET_NO = 'RETURN' AND */
			UNION ALL
			"
SET @SQL1 = "			
			SELECT GOM.GATE_OUTPASS_ID,ISNULL(GOM.DOCNO,0) AS GPNO,GOM.GDATE AS GPDATE,
			ISNULL(GOM.HEAD,'') AS HEAD,ISNULL(GOM.VEHICLENO,'') AS VEHICLENO,ISNULL(GOM.LRNO,'') AS LRNO,
			ISNULL(RET_NO,'') AS RETNO,ISNULL(GOM.NARRATION,'') AS NARRATION,ISNULL(SR_NO,0) AS SR_NO,
			ISNULL(PCS,0) AS NOS,ISNULL(GOD.REMARKS,'') AS REMARKS,
			ISNULL(GOM.CHALLANNO,0) AS CHALLANNO,ISNULL(GOD.PACKING,0) AS PACKING,ISNULL(LM.LGR_NAME,'') AS PARTY,
			ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,
			ISNULL(DM.DRIVER_NAME,'') AS DRIVER,ISNULL(PM.PURPOSE_NAME,'') AS PURPOSE,
			ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(UM.UNIT_NAME,'') AS UNIT,ISNULL(SM.SIZE_NAME,'') AS SIZE,
			ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP, 
			0 AS QTY,SUM(ISNULL(CCD.QUANTITY,0)) AS DELIQTY,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS,
			ISNULL(LCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			ISNULL(IM.NICK_NAME,'') AS NICKNAME,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
			ISNULL(GOM.TRANSPORT_ID,0) AS TRANSPORT_ID,ISNULL(DM.DRIVER_ID,0) AS DRIVER_ID,ISNULL(PM.PURPOSE_ID,0) AS PURPOSE_ID,
			ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(SM.SIZE_ID,0) AS SIZE_ID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEM_GRP_ID,
			ISNULL(HM.HASTE_NAME,'') AS HASTE,ISNULL(HM.HASTE_ID,0) AS HASTEID
			FROM "+@DATABASENAME+"CHEMICALCHALLAN CC 
			INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CCD ON CC.CHALLANID = CCD.CHALLANID 
				AND CC.CMP_CODE = CCD.CMP_CODE AND CC.FLAG = CCD.FLAG
			INNER JOIN "+@DATABASENAME+"GATE_OUTPASS_MASTER GOM ON GOM.DOCNO = CC.PARTYCHALLAN_NO 
				AND GOM.CMP_CODE = CC.CMP_CODE AND GOM.FLAG = CC.FLAG 
			INNER JOIN "+@DATABASENAME+"GATE_OUTPASS_DETAIL GOD ON GOM.GATE_OUTPASS_ID = GOD.GATE_OUTPASS_ID
				AND GOM.CMP_CODE = GOD.CMP_CODE AND GOM.FLAG = GOD.FLAG 
				AND CCD.CMP_CODE = GOD.CMP_CODE AND CCD.FLAG = GOD.FLAG AND CCD.ITEM_ID = GOD.ITEM_ID "+@SIZESQL+"
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = GOM.PARTY_ID
			LEFT  JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = GOM.AGENT_ID
			LEFT  JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = GOM.TRANSPORT_ID
			LEFT  JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID= GOM.DRIVER_ID
			LEFT  JOIN "+@DATABASENAME+"PURPOSE_MASTER PM ON PM.PURPOSE_ID= GOM.PURPOSE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = GOD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
			LEFT  JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = GOD.SIZE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = GOM.CMP_CODE
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER LCM ON LCM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"HASTE_MASTER HM ON HM.HASTE_ID = GOM.HASTE_ID
			"+ @JOINSQL +"
			WHERE GOM.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+" "+@GPSQL+" 
			
			"
			SET @SQL3=" GROUP BY GOM.GATE_OUTPASS_ID,ISNULL(GOM.DOCNO,0),GOM.GDATE,ISNULL(GOM.HEAD,''),
			ISNULL(GOM.VEHICLENO,''),ISNULL(GOM.LRNO,''),ISNULL(RET_NO,''),ISNULL(GOM.NARRATION,''),
			ISNULL(SR_NO,0),ISNULL(PCS,0),ISNULL(GOD.REMARKS,''),ISNULL(GOM.CHALLANNO,0),
			ISNULL(GOD.PACKING,0),ISNULL(LM.LGR_NAME,''),ISNULL(ALM.LGR_NAME,''),
			ISNULL(TM.TRANSPORT_NAME,''),ISNULL(DM.DRIVER_NAME,''),ISNULL(PM.PURPOSE_NAME,''),
			ISNULL(IM.ITEM_NAME,''),ISNULL(UM.UNIT_NAME,''),ISNULL(SM.SIZE_NAME,''),ISNULL(IGM.ITEM_GRP_NAME,''),
			ISNULL(COMP.CMP_ALIAS,''),ISNULL(LCM.CITY_NAME,''),ISNULL(ACM.CITY_NAME,''),ISNULL(IM.NICK_NAME,'')
			,ISNULL(LM.LGR_ID,0),ISNULL(ALM.LGR_ID,0) ,
			ISNULL(GOM.TRANSPORT_ID,0) ,ISNULL(DM.DRIVER_ID,0) ,ISNULL(PM.PURPOSE_ID,0) ,
			ISNULL(IM.ITEM_ID,0) ,ISNULL(SM.SIZE_ID,0) ,ISNULL(IGM.ITEM_GRP_ID,0),
			ISNULL(HM.HASTE_NAME,''),ISNULL(HM.HASTE_ID,0) ) AS DETAIL
			GROUP BY GATE_OUTPASS_ID,GPNO,GPDATE,HEAD,VEHICLENO,LRNO,RETNO,NARRATION,SR_NO,NOS,REMARKS,	CHALLANNO,PACKING,PARTY,AGENT,TRANSPORT,DRIVER,PURPOSE,ITEM,UNIT,SIZE,ITEMGRP,ALIAS,
			PARTYCITY,AGENTCITY,NICKNAME,PARTY_ID,AGENT_ID,TRANSPORT_ID,DRIVER_ID,PURPOSE_ID,ITEM_ID,SIZE_ID,ITEM_GRP_ID,HASTE,HASTEID 
			"+@STRORDERBY+""
END	


EXEC (@SQL+@SQL1+@SQL3)
PRINT @SQL
PRINT @SQL1
