/****** Object:  StoredProcedure [dbo].[PROC_OUTSTANDING_ASONDATE]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_OUTSTANDING_NEW 'ACC2010_2011.DBO.','22/FEB/2011','2','',1,''
select * from tempdb..sysobjects where name like '##%'

PROC_OUTSTANDING_ASONDATE N'Acc2015_2016.Dbo.', N'21/Jul/2015', N'21/Jul/2015', N'1', N'##5372', 1, N'Acc2014_2015.Dbo.' 
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDING_ASONDATE]	
(
@DATABASENAME AS NVARCHAR(50),
@BILLDATE AS NVARCHAR(20),
@ASONDATE AS NVARCHAR(20),
@CMP_CODE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@RPT_WISE AS INT,
@PREVDATABASE AS NVARCHAR(50)
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)

SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @SQL7=""
SET @SQL=""
SET @SQLJOIN=""
SET @ORDERBYSQL=""

BEGIN
IF @RPT_WISE=1   
BEGIN  
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL=" CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=2 
BEGIN
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL=" AGENT,AGENTID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=3 
BEGIN
SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=SM.SALESMAN_ID"
SET @ORDERBYSQL=" SALESMAN,SALESMANID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

IF @RPT_WISE=4 
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
SET @ORDERBYSQL=" CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=5 
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
SET @ORDERBYSQL=" CUSTOMERGROUP,CUSTGRPID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END
END

BEGIN
SET NOCOUNT ON;
SET @SQL1="

SELECT DOCNO,DATE,VCODE,BILL_NO,JOBFLAG,BILLAMOUNT,PARTAMOUNT,PARTY,AGENT,
SALESMAN,CITY,CUSTOMERGROUP,P_D,PARTICULAR,REMARK,OUTDAYS,PARTYMOBILENO,AGENTMOBILENO,
AGENTCITY,PARTYID,AGENTID,PARTY_CITYID,AGENT_CITYID,SALESMANID,CUSTGRPID,ITEMNAME,DISCOUNT,CMP_ALIAS,CHEQUEDATE AS CHEQUEDATE,ADJINTEREST,INTEREST,TRAN_ID,
RECAMOUNT,INTREC
FROM(

SELECT PD.BILL_NO AS DOCNO,PD.DATE,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,           
0 AS PARTAMOUNT,ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,
ISNULL(SM.SALESMAN_NAME,'') AS SALESMAN,ISNULL(CM.CITY_NAME,'') AS CITY,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,'D' AS P_D,'' AS PARTICULAR,AJ.REMARK AS REMARK,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE +"') AS OUTDAYS,
ISNULL((LM.LGR_MOBILE),'') AS PARTYMOBILENO,ISNULL((ALM.LGR_MOBILE),'') AS AGENTMOBILENO
,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,PD.BILL_AMOUNT  AS BILLAMOUNT,ISNULL(PD.ITEMNAME,'')AS ITEMNAME,ISNULL(AJ.TOTAL ,0) AS DISCOUNT,ISNULL(COM.CMP_ALIAS,'') AS CMP_ALIAS,CHEQUEDATE AS CHEQUEDATE,ISNULL(AJ.ADJINTEREST,0) AS ADJINTEREST,ISNULL(AJ.INTEREST,0)AS INTEREST,0 AS TRAN_ID,ISNULL(AJ.ADJUSTAMT,0) AS RECAMOUNT,0 AS TRAN_AMOUNT,ISNULL(AJ.INTREC,0) AS INTREC
FROM "+@DATABASENAME+"PARTYDETAIL PD
LEFT JOIN "+@DATABASENAME+"ADJMASTER AJ ON AJ.BILLNO=PD.BILL_NO AND AJ.FLAG=PD.JOBFLAG AND AJ.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AJ.VCODE 
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COM ON COM.CMP_CODE= PD.CMP_CODE               
"+ @SQLJOIN+ "
WHERE  PD.DATE<='"+@BILLDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+ ")            
AND  ISNULL( PD.Paid,0) =0 
UNION ALL"

SET @SQL2="
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,            
(CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
WHEN TD.TRAN_TYPE='DN' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(SM.SALESMAN_NAME,'') AS SALESMAN,ISNULL(CM.CITY_NAME,'') AS  CITY,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,'P' AS P_D,TD.NARRATION AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,ISNULL((LM.LGR_MOBILE),'') AS PARTYMOBILENO,ISNULL((ALM.LGR_MOBILE),'') AS AGENTMOBILENO
,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,0 AS BILL_AMOUNT,'' AS ITEMNAME,0 AS DISCOUNT,ISNULL(COM.CMP_ALIAS,'') AS CMP_ALIAS,TD.DDDATE AS CHEQUEDATE,0 AS ADJINTEREST,0 AS INTEREST,TD.TRAN_ID,0 AS RECAMOUNT ,TD.TRAN_AMOUNT,0 AS INTREC
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID         
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COM ON COM.CMP_CODE= TD.CMP_CODE 
"+ @SQLJOIN+ "
WHERE TM.TRAN_DATE<='"+@ASONDATE +"' AND  TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='BP'OR TD.TRAN_TYPE='CR'OR TD.TRAN_TYPE='CP' OR TD.TRAN_TYPE='J' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE+ ")          
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS' 
AND (TD.TRAN_DRCR='C')
UNION ALL
"

SET @SQL3="
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,                        
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END) AS PARTAMOUNT,
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(SM.SALESMAN_NAME,'') AS SALESMAN,ISNULL(CM.CITY_NAME,'') AS  CITY,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,'P' AS P_D,TD.REMARK AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,ISNULL((LM.LGR_MOBILE),'') AS PARTYMOBILENO,ISNULL((ALM.LGR_MOBILE),'') AS AGENTMOBILENO
,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,0 AS BILL_AMOUNT,'' AS ITEMNAME,0 AS DISCOUNT,ISNULL(COM.CMP_ALIAS,'') AS CMP_ALIAS,TD.DDDATE AS CHEQUEDATE,0 AS ADJINTEREST,0 AS INTEREST,TD.TRAN_ID,0 AS RECAMOUNT ,TD.TRAN_AMOUNT,0 AS INTREC
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
