WHERE AE.VDATE<='"+@ASONDATE +"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE+ ")
"

BEGIN
IF @PREVDATABASE <>''
BEGIN       
SET @SQL5="     
UNION ALL      
SELECT AE.DOCNO  AS DOCNO,AE.VDATE AS DATE,0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,AE.PARTAMOUNT,        
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(SM.SALESMAN_NAME,'') AS SALESMAN,ISNULL(CM.CITY_NAME,'') AS  CITY,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP ,'P' AS P_D,
AE.REMARK AS PARTICULAR,'' AS REMARK ,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE +"') AS OUTDAYS, ISNULL((LM.LGR_MOBILE),'') AS PARTYMOBILENO,ISNULL((ALM.LGR_MOBILE),'') AS AGENTMOBILENO 
,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,0 AS BILL_AMOUNT,'' AS ITEMNAME,0 AS DISCOUNT,ISNULL(COM.CMP_ALIAS,'') AS CMP_ALIAS,AE.CHQDATE AS CHEQUEDATE,0 AS ADJINTEREST,0 AS INTEREST,AE.ADV_ID AS TRAN_ID,0 AS RECAMOUNT ,AE.AMOUNT TRAN_AMOUNT,0 AS INTREC
FROM "+@PREVDATABASE+"ADVANCE_ENTRY AE         
