SET QUOTED_IDENTIFIER OFF
GO































  /* 
PROC_OUTSTANDING_BILL_MONTH '1','ACC2012_2013.DBO.',1,3,'##3448','08/FEB/2013',1,0,0,
PROC_OUTSTANDING_BILL_MONTH 1,'ACC2014_2015.DBO.',1,3,'##3808','19/AUG/2014',1,0,0,''
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDING_BILL_MONTH]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@RPT_TYPE INT,
	@TEMPTABLE NVARCHAR(20),
	@ASONDATE  NVARCHAR(20),
	@ONACCOUNT  INT,
	@DUEPENDING  INT,
    @DAYS NVARCHAR(4),
    @PREVDATABASE NVARCHAR(20)

)
AS



DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT1 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT2 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT3 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT4 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT5 AS NVARCHAR(4000)
DECLARE @CONDITION AS NVARCHAR(2000)
DECLARE @ORDERBY AS NVARCHAR(4000)
DECLARE @ALL AS NVARCHAR(50)


SET @CONDITION=""
SET @SQLJOIN =""
SET @SQLONACCOUNT3=""
SET @ALL=""

BEGIN
IF @RPT_WISE=1     
	   SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
IF @RPT_WISE=2 
    	SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
IF @RPT_WISE=3 
    	SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=SM.SALESMAN_ID"
IF @RPT_WISE=4 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
IF @RPT_WISE=5 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
IF @RPT_WISE=6 OR @RPT_WISE=7
        SET @SQLJOIN =""
END

BEGIN
IF @RPT_WISE=6
   SET @ORDERBY=" ORDER BY DATE,BILL_NO"
IF @RPT_WISE=7
   SET @ORDERBY=" ORDER BY ORD,DATE,BILL_NO"
END

BEGIN 
IF @ONACCOUNT=1
      SET @SQLONACCOUNT ="
                          UNION ALL
                          SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,'' AS JOBFLAG,TM.TRAN_DATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
                          0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
			   			  (CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
						  (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
						  TD.TRAN_ID,
						  LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.TRAN_TYPE,TD.TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
						  '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
						  DATENAME( MONTH , DATEADD( MONTH , MONTH(TM.TRAN_DATE) , 0 ) - 1 ) AS MONTHS,
                          (CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN  (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END) AS     ORD,0 AS TDS_AMOUNT
						  FROM " + @DATABASENAME + "TRAN_DETAIL TD 
                          INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
                          INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
                          LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
                          LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
                          LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                          LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                          LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
                          LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                          LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
						  INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                            
                          " +  @SQLJOIN + "
                          WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
                          AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")        
                          AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
						  AND (TD.TRAN_DRCR='C')
                          UNION ALL "

    SET @SQLONACCOUNT1 ="  
                          SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,'' AS JOBFLAG,TM.TRAN_DATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
                          0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
                          (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)AS PARTAMOUNT,TD.TRAN_ID,
                          LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.TRAN_TYPE,TD.TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
                          '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
                          DATENAME( MONTH , DATEADD( MONTH , MONTH(TM.TRAN_DATE) , 0 ) - 1 ) AS MONTHS,
                          (CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN  (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END) AS     ORD,0 AS TDS_AMOUNT
                          FROM " + @DATABASENAME + "TRAN_DETAIL TD 
                          INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
                          INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
                          LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
                          LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID  AND LM.LGR_TYPE = 'L'       
                          LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                          LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                          LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
                          LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                          LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
						  INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                            
                          " +  @SQLJOIN + "
                          WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
                          AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
                          AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='JR')
                          AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='DN')
						  AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='BP')
						  AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='CP')
                          AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
                          UNION ALL 
                          "
   SET @SQLONACCOUNT2 ="  
                         SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,AE.VDATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,AE.VDATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
                         0 AS INTREC,'P' AS FLAG, AE.CHQNO,AE.CHQDATE AS CHEQUEDATE,AE.PARTAMOUNT,AE.ADV_ID AS TRAN_ID,
                         LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,AE.ENTRYTYPE AS TRAN_TYPE,AE.AMOUNT TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
                         '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
                         DATENAME( MONTH , DATEADD( MONTH , MONTH(AE.VDATE) , 0 ) - 1 ) AS MONTHS,
                         (CASE WHEN DATEPART(M,AE.VDATE)<=3 THEN  (DATEPART(M,AE.VDATE)+12)ELSE DATEPART(M,AE.VDATE) END) AS     ORD,0 AS TDS_AMOUNT
                         FROM " + @DATABASENAME + "ADVANCE_ENTRY AE         
                         INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
                         LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
                         LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                         LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                         LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
                         LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                         LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID      
                         LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
                         " +  @SQLJOIN + "
                         WHERE AE.VDATE<='"+@ASONDATE+"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN(" + @CMP_CODE +")"

       BEGIN
           IF  @PREVDATABASE!=""
             BEGIN
                  SET @SQLONACCOUNT3 =" 
                               UNION ALL
                               SELECT SUBSTRING('"+@PREVDATABASE+"',1,LEN('"+@PREVDATABASE+"')-5) AS DATABASENAME,0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,AE.VDATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,AE.VDATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
					           0 AS INTREC,'P' AS FLAG, AE.CHQNO,AE.CHQDATE AS CHEQUEDATE,AE.PARTAMOUNT,AE.ADV_ID AS TRAN_ID,
					           LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,AE.ENTRYTYPE AS TRAN_TYPE,AE.AMOUNT TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
					           '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
                               DATENAME( MONTH , DATEADD( MONTH , MONTH(AE.VDATE) , 0 ) - 1 ) AS MONTHS,
                               (CASE WHEN DATEPART(M,AE.VDATE)<=3 THEN  (DATEPART(M,AE.VDATE)+12)ELSE DATEPART(M,AE.VDATE) END) AS     ORD,0 AS TDS_AMOUNT
					           FROM " + @PREVDATABASE + "ADVANCE_ENTRY AE         
					           INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
					           LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
					           LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
					           LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
					           LEFT JOIN " + @PREVDATABASE + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
					           LEFT JOIN " + @PREVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
					           LEFT JOIN " + @PREVDATABASE + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID      
                               LEFT JOIN " + @PREVDATABASE + "COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
					           " +  @SQLJOIN + "
					           WHERE AE.VDATE<='"+@ASONDATE+"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN(" + @CMP_CODE +")
                               AND (AE.REC_TRANS=0 OR   AE.REC_TRANS IS NULL)
                                "
                 SET @SQLONACCOUNT4 ="
                          UNION ALL
                          SELECT SUBSTRING('"+@PREVDATABASE+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,'' AS JOBFLAG,TM.TRAN_DATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
                          0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
			   			  (CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
						  (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
						  TD.TRAN_ID,
						  LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.TRAN_TYPE,TD.TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
						  '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
                          DATENAME( MONTH , DATEADD( MONTH , MONTH(TM.TRAN_DATE) , 0 ) - 1 ) AS MONTHS,
                          (CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN  (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END) AS     ORD,0 AS TDS_AMOUNT
						  FROM " + @PREVDATABASE + "TRAN_DETAIL TD 
                          INNER JOIN " + @PREVDATABASE + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
                          INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
                          LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
                          LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
                          LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                          LEFT JOIN " + @PREVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                          LEFT JOIN " + @PREVDATABASE + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
                          LEFT JOIN " + @PREVDATABASE + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                          LEFT JOIN " + @PREVDATABASE + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
						  INNER JOIN " + @PREVDATABASE + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                            
                          " +  @SQLJOIN + "
                          WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
                          AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")        
                          AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
						  AND (TD.TRAN_DRCR='C')
                          UNION ALL "

                SET @SQLONACCOUNT5 ="  
                          SELECT SUBSTRING('"+@PREVDATABASE+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,'' AS JOBFLAG,TM.TRAN_DATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
                          0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
                          (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)AS PARTAMOUNT,TD.TRAN_ID,
                          LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.TRAN_TYPE,TD.TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
                          '' AS LRNO,'' AS LRDATE,'' AS REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
                          DATENAME( MONTH , DATEADD( MONTH , MONTH(TM.TRAN_DATE) , 0 ) - 1 ) AS MONTHS,
                          (CASE WHEN DATEPART(M,TM.TRAN_DATE)<=3 THEN  (DATEPART(M,TM.TRAN_DATE)+12)ELSE DATEPART(M,TM.TRAN_DATE) END) AS     ORD,0 AS TDS_AMOUNT
                          FROM " + @PREVDATABASE + "TRAN_DETAIL TD 
                          INNER JOIN " + @PREVDATABASE + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
                          INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
                          LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
                          LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID   AND LM.LGR_TYPE = 'L'      
                          LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                          LEFT JOIN " + @PREVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                          LEFT JOIN " + @PREVDATABASE + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
                          LEFT JOIN " + @PREVDATABASE + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                          LEFT JOIN " + @PREVDATABASE + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
						  INNER JOIN " + @PREVDATABASE + " GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                            
                          " +  @SQLJOIN + "
                          WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
                          AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
                          AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='JR')
                          AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='DN')
						  AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + " PARTYDETAIL WHERE JOBFLAG='BP')
						  AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + " PARTYDETAIL WHERE JOBFLAG='CP')	 
                          AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'                         
                          "           
             END
       END /* END OF PREVIOUS YEAR CONDITION */
END /* END OF ONACCOUNT  CONDITION */
BEGIN
IF @ONACCOUNT=0
    BEGIN
    SET @SQLONACCOUNT =""
    SET @SQLONACCOUNT1 =""
    SET @SQLONACCOUNT2 =""
    SET @SQLONACCOUNT3=""
    SET @SQLONACCOUNT4=""
    SET @SQLONACCOUNT5=""    
  END
END
SET @SQL=""
BEGIN
  IF(@RPT_TYPE=1)
	SET @CONDITION=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE))   IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM " + @DATABASENAME + "ADJMASTER AM1 WHERE AM1.RECDATE<='"+ @ASONDATE + "' AND AM1.PAID=1  AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG)"
END
BEGIN
	IF(@RPT_TYPE=2)
	SET @CONDITION=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE)) NOT IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM " + @DATABASENAME + "ADJMASTER AM1 WHERE AM1.RECDATE<='"+ @ASONDATE +"' AND AM1.PAID=1 AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG) "
END
BEGIN
	IF(@DUEPENDING=1)
	SET @CONDITION=" AND PD.BILL_AMOUNT=PD.PENDING_AMOUNT "
END
IF @DAYS!="0" 
  BEGIN
 SET   @CONDITION=@CONDITION +" AND DATEDIFF(DAY,PD.DATE,'"+@ASONDATE+"')>="+@DAYS
  END

SET @SQL="
          SELECT DATABASENAME,VCODE,BILL_NO,DATE,JOBFLAG,BILL_AMOUNT,REC_AMOUNT,RECDATE,DISCOUNT,INTEREST,INTREC,FLAG,CHEQUENO,CHEQUEDATE,PARTAMOUNT,TRAN_ID,PARTY,AGENT,SALESMAN,CITY,CUSTOMERGROUP,TRAN_TYPE,TRAN_AMOUNT,ALIAS,LRNO,LRDATE,REMARK,AGENTCITTY,OUTDAYS,PARTYMOBILENO,AGENTMOBILENO,MONTHS,ORD,TDS_AMOUNT
           FROM(
           SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,PD.DATE,ISNULL(PD.BILL_AMOUNT,0)BILL_AMOUNT,ISNULL(AM.ADJUSTAMT,0) AS REC_AMOUNT,AM.RECDATE,ISNULL(AM.TOTAL,0)AS DISCOUNT,ISNULL(AM.INTEREST,0)AS INTEREST,ISNULL(AM.INTREC,0) AS INTREC,'D' AS FLAG,AM.CHEQUENO AS CHEQUENO,AM.CHEQUEDATE AS CHEQUEDATE, 0 AS PARTAMOUNT,0 AS TRAN_ID,
           LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'AA' AS TRAN_TYPE,0 AS TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
           PD.LRNO AS LRNO,PD.LRDATE AS LRDATE,AM.REMARK,ACM.CITY_NAME AS AGENTCITTY,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE+"') AS OUTDAYS,ISNULL(LM.Lgr_Mobile,'') AS PARTYMOBILENO,ISNULL(ALM.Lgr_Mobile,'') AS AGENTMOBILENO,
           UPPER(DATENAME( MONTH , DATEADD( MONTH , MONTH(PD.DATE) , 0 ) - 1 )) AS MONTHS,
           (CASE WHEN DATEPART(M,PD.DATE)<=3 THEN  (DATEPART(M,PD.DATE)+12)ELSE DATEPART(M,PD.DATE) END) AS     ORD,ISNULL(AM.TDS_AMOUNT,0) AS TDS_AMOUNT
           FROM " + @DATABASENAME + " PARTYDETAIL PD 
           LEFT JOIN " + @DATABASENAME + " ADJMASTER AM ON AM.BILLNO=PD.BILL_NO AND AM.FLAG=PD.JOBFLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+ @ASONDATE +"'
           LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
           LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
           LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
           LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
           LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
           LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
           LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
           " +  @SQLJOIN + "
           WHERE  PD.DATE<='"+@ASONDATE+"' AND PD.CMP_CODE IN("+ @CMP_CODE +")" +  @CONDITION  +"

           ) AS DETAIL
 "+@ORDERBY+"

           
       "
BEGIN
IF @RPT_TYPE=6 or  @RPT_TYPE=7
    BEGIN
    SET @SQLONACCOUNT =""
    SET @SQLONACCOUNT1 =""
    SET @SQLONACCOUNT2 =""
    SET @SQLONACCOUNT3=""
    SET @SQLONACCOUNT4=""
    SET @SQLONACCOUNT5=""    
  END
END
           
/*
EXEC(@SQL+ @SQLONACCOUNT+@SQLONACCOUNT1+@SQLONACCOUNT2+ @SQLONACCOUNT3+ @SQLONACCOUNT4+ @SQLONACCOUNT5+") AS DETAIL")
PRINT @SQL
PRINT @SQLONACCOUNT
PRINT @SQLONACCOUNT1
PRINT @SQLONACCOUNT2
PRINT @SQLONACCOUNT3
PRINT @SQLONACCOUNT4
PRINT @SQLONACCOUNT5
PRINT ') AS DETAIL'
PRINT  @ORDERBY*/

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL









































