/* 

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%' 
PROC_OUTSTANDING_NEW 'ACC2014_2015.DBO.','22/AUG/2014','22/AUG/2014',N'1,2,3,4,6,7,8,9,10,11','##5872',1,'ACC2013_2014.DBO.'
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDING_NEW]	
(
@DATABASENAME AS NVARCHAR(50),
@ASONDATE AS NVARCHAR(20),
@BILLDATE AS NVARCHAR(20),
@CMP_CODE AS NVARCHAR(50),
@TEMPTABLE AS NVARCHAR(20),
@RPT_WISE AS INT,
@PREVDATABASE AS NVARCHAR(50)
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(100)
DECLARE @ORDERBYSQL AS NVARCHAR(100)

SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @SQL7=""
SET @SQL=""
SET @SQLJOIN=""
SET @ORDERBYSQL=""

BEGIN
IF @RPT_WISE=1     
BEGIN
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL=" CITY,PARTY_CITYID,PARTY,PARTYID,"
END

IF @RPT_WISE=2 
BEGIN
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL=" AGENT,AGENTID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

IF @RPT_WISE=3 
BEGIN
SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=SM.SALESMAN_ID"
SET @ORDERBYSQL=" SALESMAN,SALESMANID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

IF @RPT_WISE=4 
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
SET @ORDERBYSQL=" CITY,PARTY_CITYID,PARTY,PARTYID,"
END

IF @RPT_WISE=5 
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
SET @ORDERBYSQL=" CUSTOMERGROUP,CUSTGRPID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END
END




BEGIN
SET NOCOUNT ON;
SET @SQL1="

SELECT DOCNO,DATE,VCODE,BILL_NO,JOBFLAG,PENDINGAMOUNT,PARTAMOUNT,PARTY,AGENT,AGENTCITY,
SALESMAN,CITY,CUSTOMERGROUP,P_D,PARTICULAR,REMARK,OUTDAYS,CMP_ALIAS,PARTYID,AGENTID,
PARTY_CITYID,AGENT_CITYID,SALESMANID,CUSTGRPID
FROM(
SELECT PD.BILL_NO AS DOCNO,PD.DATE,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,
(PD.BILL_AMOUNT + SUM( ISNULL(AJ.INTEREST ,0))) -(SUM(ISNULL(AJ.ADJUSTAMT ,0))+
SUM(ISNULL(AJ.TOTAL ,0))+SUM(ISNULL(AJ.INTREC ,0))) AS PENDINGAMOUNT,            
0 AS PARTAMOUNT,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'D' AS P_D,'' AS PARTICULAR,
MAX(AJ.REMARK) AS REMARK,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@DATABASENAME+"PARTYDETAIL PD
LEFT JOIN "+@DATABASENAME+"ADJMASTER AJ ON AJ.BILLNO=PD.BILL_NO AND AJ.FLAG=PD.JOBFLAG AND AJ.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AJ.VCODE AND AJ.RECDATE<='"+@ASONDATE +"'
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID           
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER PCM ON PCM.CMP_CODE = PD.CMP_CODE
"+ @SQLJOIN+ "
WHERE  PD.DATE<='"+@BILLDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+ ")            

GROUP BY PD.BILL_NO ,PD.DATE,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,PD.BILL_AMOUNT,LM.LGR_NAME ,ALM.LGR_NAME,ACM.CITY_NAME,
SM.SALESMAN_NAME ,CM.CITY_NAME ,CGM.CUST_GRP_NAME,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0),ISNULL(ALM.CITY_ID,0),
ISNULL(SM.SALESMAN_ID,0),ISNULL(CGM.CUST_GRP_ID,0),
ISNULL(LM.LGR_ID,0),ISNULL(ALM.LGR_ID,0)             
HAVING  (PD.BILL_AMOUNT + SUM( ISNULL(AJ.INTEREST ,0))) -(SUM(ISNULL(AJ.ADJUSTAMT ,0))+
SUM(ISNULL(AJ.TOTAL ,0))+SUM(ISNULL(AJ.INTREC ,0)))>0

UNION ALL"
SET @SQL2="
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,            
0  AS PENDINGAMOUNT,
(CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
WHEN TD.TRAN_TYPE='DN' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'P' AS P_D,TD.NARRATION AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER PCM ON PCM.CMP_CODE = TD.CMP_CODE  
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                            
"+ @SQLJOIN+ "
WHERE TM.TRAN_DATE<='"+@ASONDATE +"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='BP'OR TD.TRAN_TYPE='CR'OR TD.TRAN_TYPE='CP' OR TD.TRAN_TYPE='J' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE+ ")          
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL
"
SET @SQL3="
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,                        
0 AS PENDINGAMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END) AS PARTAMOUNT,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'P' AS P_D,TD.REMARK AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER PCM ON PCM.CMP_CODE = TD.CMP_CODE
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID                                                
"+ @SQLJOIN+ "
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'  OR TD.TRAN_TYPE='YSR'  OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL
"

SET @SQL4="

SELECT AE.DOCNO  AS DOCNO,AE.VDATE AS DATE,0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,0 AS PENDINGAMOUNT,AE.PARTAMOUNT,        
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP ,'P' AS P_D,
AE.REMARK AS PARTICULAR,'' AS REMARK ,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID    
FROM "+@DATABASENAME+"ADVANCE_ENTRY AE         
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER PCM ON PCM.CMP_CODE = AE.CMP_CODE                                 
"+ @SQLJOIN+ "
WHERE AE.VDATE<='"+@ASONDATE +"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE+ ") AND (AE.REC_TRANS=0 OR AE.REC_TRANS IS NULL)
"



BEGIN
IF @PREVDATABASE <>''
BEGIN       
SET @SQL5="     
UNION ALL      
SELECT AE.DOCNO  AS DOCNO,AE.VDATE AS DATE,0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,0 AS PENDINGAMOUNT,AE.PARTAMOUNT,        
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP ,'P' AS P_D,
AE.REMARK AS PARTICULAR,'' AS REMARK ,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE +"') AS OUTDAYS ,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@PREVDATABASE+"ADVANCE_ENTRY AE         
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN "+@PREVDATABASE+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@PREVDATABASE+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@PREVDATABASE+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
INNER JOIN "+@PREVDATABASE+" COMPANY_MASTER PCM ON PCM.CMP_CODE = AE.CMP_CODE                 
"+ @SQLJOIN+ "
WHERE AE.VDATE<='"+@ASONDATE +"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE+ ")
AND (AE.REC_TRANS=0 OR   AE.REC_TRANS IS NULL)
"

SET @SQL6="
UNION ALL
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,            
0  AS PENDINGAMOUNT,
(CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
WHEN TD.TRAN_TYPE='DN' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) 
ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'P' AS P_D,TD.NARRATION AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@PREVDATABASE+"TRAN_DETAIL TD 
INNER JOIN "+@PREVDATABASE+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@PREVDATABASE+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@PREVDATABASE+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@PREVDATABASE+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
INNER JOIN "+@PREVDATABASE+" COMPANY_MASTER PCM ON PCM.CMP_CODE = TD.CMP_CODE 
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID        
"+ @SQLJOIN+ "
WHERE TM.TRAN_DATE<='"+@ASONDATE +"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='BP'OR TD.TRAN_TYPE='CR'OR TD.TRAN_TYPE='CP' OR TD.TRAN_TYPE='J' OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE+ ")          
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
UNION ALL 
"
SET @SQL7="
SELECT TM.TRAN_DOCNO AS DOCNO, TM.TRAN_DATE AS DATE,TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_TYPE AS JOBFLAG,                        
0 AS PENDINGAMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END) AS PARTAMOUNT,
LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'P' AS P_D,TD.REMARK AS PARTICULAR,'' AS REMARK
,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE +"') AS OUTDAYS,PCM.CMP_ALIAS,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@PREVDATABASE+"TRAN_DETAIL TD 
INNER JOIN "+@PREVDATABASE+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@PREVDATABASE+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@PREVDATABASE+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@PREVDATABASE+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID         
INNER JOIN "+@PREVDATABASE+" COMPANY_MASTER PCM ON PCM.CMP_CODE = TD.CMP_CODE 
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID        
"+ @SQLJOIN+ "
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'  OR TD.TRAN_TYPE='YSR'  OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
"
END
END

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @SQL7
PRINT ') AS DETAIL'
PRINT 'ORDER BY'
PRINT @ORDERBYSQL
PRINT 'DATE ASC'
EXEC(@SQL1+@SQL2+@SQL3+@SQL4 +@SQL5+@SQL6+@SQL7 +") AS DETAIL ORDER BY "+@ORDERBYSQL+" DATE ASC")
END

















GO

