/* 
PROC_OUTSTANDING_NEW_SUMMARY 'ACC2010_2011.DBO.','01/APR/2010',1,'##2060',1
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDING_NEW_SUMMARY]	
(
		@DATABASENAME AS NVARCHAR(50),
		@ASONDATE AS NVARCHAR(20),
		@CMP_CODE AS NVARCHAR(20),
		@TEMPTABLE AS NVARCHAR(20),
		@Rpt_Wise AS INT
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @sqlJoin AS NVARCHAR(100)
DECLARE @sqlMain AS NVARCHAR(1000)
DECLARE @GrpSql AS NVARCHAR(1000)


SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL=""
SET @sqlJoin=""

Begin
if @Rpt_Wise=1     
	   SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON LM.Lgr_ID=TT.CODE"
if @Rpt_Wise=2 
    	set @sqlJoin ="inner join  " +  @TempTable + " TT on TT.Code=ALM.Lgr_ID"
if @Rpt_Wise=3 
    	set @sqlJoin ="inner join " +  @TempTable + " TT on TT.Code=SM.Salesman_ID"
if @Rpt_Wise=4 
    	set @sqlJoin ="inner join " + @TempTable + " TT on TT.Code=CM.City_ID"
if @Rpt_Wise=5 
    	set @sqlJoin ="inner join " + @TempTable + " TT on TT.Code=CGM.Cust_Grp_ID"
end

BEGIN
   IF @Rpt_Wise=1 
        BEGIN
          SET @sqlMain=" (CASE WHEN CITY IS NULL THEN PARTY ELSE PARTY +',' +CITY END) AS MAINGROUP,'' AS PARTY_CITY"
          SET @GrpSql=" GROUP BY PARTY,CITY"
        END
   ELSE IF @Rpt_Wise=2
        BEGIN
          SET @sqlMain=" AGENT AS MAINGROUP,'' AS PARTY_CITY"
          SET @GrpSql=" GROUP BY AGENT"
        END
   ELSE IF @Rpt_Wise=3
        BEGIN
          SET @sqlMain=" AGENT AS MAINGROUP,ISNULL(CITY,PARTY ,PARTY +',' +CITY) AS PARTY_CITY"
          SET @GrpSql=" GROUP BY AGENT, PARTY,CITY"
        END
   ELSE IF @Rpt_Wise=3
        BEGIN
          SET @sqlMain=" SALESMAN AS MAINGROUP,''  AS PARTY_CITY"
          SET @GrpSql=" GROUP BY SALESMAN"
        END
  ELSE IF @Rpt_Wise=4
        BEGIN
          SET @sqlMain=" CITY AS MAINGROUP,''  AS PARTY_CITY"
          SET @GrpSql=" GROUP BY CITY"
        END
 ELSE IF @Rpt_Wise=5
        BEGIN
          SET @sqlMain=" CITY AS CUSTOMERGROUP,''  AS PARTY_CITY"
          SET @GrpSql=" GROUP BY CUSTOMERGROUP"
        END

         
END



BEGIN
	SET NOCOUNT ON;
SET @SQL1="
           
            SELECT "+@sqlMain+" ,SUM(PENDINGAMOUNT)AS PENDINGAMOUNT,SUM(PARTAMOUNT) AS PARTAMOUNT,SUM(PENDINGAMOUNT)-SUM(PARTAMOUNT) AS BALANCE
             FROM(
            SELECT PD.BILL_NO AS DOCNO,PD.DATE,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,
            (PD.BILL_AMOUNT + SUM( CASE when AJ.INTEREST IS NULL THEN 0 ELSE AJ.INTEREST END)) -(SUM(CASE WHEN AJ.ADJUSTAMT IS NULL THEN 0 ELSE AJ.ADJUSTAMT END)+
            SUM(CASE WHEN AJ.TOTAL IS NULL THEN 0 ELSE AJ.TOTAL END)+SUM(CASE WHEN AJ.INTREC IS NULL THEN 0 ELSE AJ.INTREC END)) AS PENDINGAMOUNT,            
            0 AS PARTAMOUNT,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
            SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'D' AS P_D,'' AS PARTICULAR,MAX(AJ.REMARK) AS REMARK,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE +"') as OUTDAYS
            FROM "+@DATABASENAME+"PARTYDETAIL PD
            LEFT JOIN "+@DATABASENAME+"ADJMASTER AJ ON AJ.BILLNO=PD.BILL_NO AND AJ.FLAG=PD.JOBFLAG AND AJ.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AJ.VCODE AND AJ.RECDATE<='"+@ASONDATE +"'
            left join "+@DATABASENAME+"Ledger_Master LM on LM.Lgr_ID=PD.Lgr_ID
            left join "+@DATABASENAME+"Ledger_Master ALM on ALM.Lgr_ID=PD.Agent_ID
            left join "+@DATABASENAME+"SalesMan_Master SM on SM.SalesMan_Id=ALM.SalesMan_Id
            left join "+@DATABASENAME+"City_Master CM on CM.City_Id=LM.City_ID
            left join "+@DATABASENAME+"Customer_Group_Master CGM on CGM.Cust_Grp_ID=LM.Cust_Grp_ID           
            "+ @sqlJoin+ "
            WHERE  PD.DATE<='"+@ASONDATE +"' and PD.Cmp_Code in("+@CMP_CODE+ ")            
            GROUP BY PD.BILL_NO ,PD.DATE,PD.VCODE,PD.BILL_NO,PD.JOBFLAG,PD.BILL_AMOUNT,LM.LGR_NAME ,ALM.LGR_NAME,
            SM.SALESMAN_NAME ,CM.CITY_NAME ,CGM.CUST_GRP_NAME 
            
            HAVING  (PD.BILL_AMOUNT + SUM( CASE when AJ.INTEREST IS NULL THEN 0 ELSE AJ.INTEREST END)) -(SUM(CASE WHEN AJ.ADJUSTAMT IS NULL THEN 0 ELSE AJ.ADJUSTAMT END)+
            SUM(CASE WHEN AJ.TOTAL IS NULL THEN 0 ELSE AJ.TOTAL END)+SUM(CASE WHEN AJ.INTREC IS NULL THEN 0 ELSE AJ.INTREC END))>0
                  
          UNION ALL"
SET @SQL2="
            select TM.TRAN_DOCNO AS DOCNO, TM.Tran_Date AS DATE,TM.TRAN_ID as VCode,TM.TRAN_DOCNO as  BIll_No,TM.TRAN_TYPE as JobFlag,            
            0  as PENDINGAMOUNT,
            (CASE WHEN TD.TRAN_TYPE='J' THEN (case when Td.Tran_DrCr='C'then (TD.PartAmount) else 0 end) ELSE
            (case when Td.Tran_DrCr='C'then (TD.PartAmount) else 0 end) END)as PartAmount,
            LM.Lgr_Name as Party,ALM.Lgr_Name as Agent,SM.SalesMan_Name as Salesman,CM.City_Name as  CITY,CGM.Cust_Grp_Name as CustomerGroup,'P' AS P_D,TD.REMARK AS PARTICULAR,'' AS REMARK
            ,DATEDIFF(DAY,TM.Tran_Date,'"+@ASONDATE +"') as OUTDAYS
            from "+@DATABASENAME+"Tran_Detail TD 
            inner join "+@DATABASENAME+"Tran_Master TM on TM.Tran_ID=TD.Tran_ID and TM.Tran_Type=TD.Tran_Type and TD.Cmp_Code=TM.Cmp_Code
            inner join "+@DATABASENAME+"Ledger_Master LM on LM.Lgr_ID=TD.Tran_Detail_ID
            left join "+@DATABASENAME+"Ledger_Detail LD on LM.Lgr_ID=LD.Lgr_ID and TD.Cmp_Code=LD.Cmp_Code
            left join "+@DATABASENAME+"Ledger_Master ALM on ALM.Lgr_Id=LD.Agent_ID
            left join "+@DATABASENAME+"City_Master CM on LM.City_ID=CM.City_ID
            left join "+@DATABASENAME+"SalesMan_Master SM on SM.SalesMan_Id=ALM.SalesMan_Id
            left join "+@DATABASENAME+"Customer_Group_Master CGM on CGM.Cust_Grp_ID=LM.Cust_Grp_ID         
            "+ @sqlJoin+ "
            where TM.Tran_Date<='"+@ASONDATE +"' and (case when Td.Tran_DrCr='C'then (TD.PartAmount) else 0 end)<>0 and (TD.ShowPartAmt=1 OR TD.ShowPartAmt IS NULL) and (TD.Tran_Type='BR'or TD.Tran_Type='BP'or TD.Tran_Type='CR'or TD.Tran_Type='CP' or TD.Tran_Type='J' or TD.Tran_Type='SR' or TD.Tran_Type='BP' or TD.Tran_Type='DN' or TD.Tran_Type='CN' or TD.Tran_Type='J' )  and TD.Cmp_Code in("+@CMP_CODE+ ")          
            UNION ALL
              "
SET @SQL3="
            select TM.TRAN_DOCNO AS DOCNO, TM.Tran_Date AS DATE,TM.TRAN_ID as VCode,TM.TRAN_DOCNO as  BIll_No,TM.TRAN_TYPE as JobFlag,            
            
            0 AS PENDINGAMOUNT,
            (case when Td.Tran_DrCr='C'then 0 else 0-TD.PartAmount end) as PartAmount,
            LM.Lgr_Name as Party,ALM.Lgr_Name as Agent,SM.SalesMan_Name as Salesman,CM.City_Name as  CITY,CGM.Cust_Grp_Name as CustomerGroup,'P' AS P_D,TD.REMARK AS PARTICULAR,'' AS REMARK
            ,DATEDIFF(DAY,TM.Tran_Date,'"+@ASONDATE +"') as OUTDAYS
            from "+@DATABASENAME+"Tran_Detail TD 
            inner join "+@DATABASENAME+"Tran_Master TM on TM.Tran_ID=TD.Tran_ID and TM.Tran_Type=TD.Tran_Type and TD.Cmp_Code=TM.Cmp_Code
            inner join "+@DATABASENAME+"Ledger_Master LM on LM.Lgr_ID=TD.Tran_Detail_ID
            left join "+@DATABASENAME+"Ledger_Detail LD on LM.Lgr_ID=LD.Lgr_ID and TD.Cmp_Code=LD.Cmp_Code
            left join "+@DATABASENAME+"Ledger_Master ALM on ALM.Lgr_Id=LD.Agent_ID
            left join "+@DATABASENAME+"City_Master CM on LM.City_ID=CM.City_ID
            left join "+@DATABASENAME+"SalesMan_Master SM on SM.SalesMan_Id=ALM.SalesMan_Id
            left join "+@DATABASENAME+"Customer_Group_Master CGM on CGM.Cust_Grp_ID=LM.Cust_Grp_ID         
            "+ @sqlJoin+ "
            where TM.Tran_Date<='"+@AsOnDate+"' and (case when Td.Tran_DrCr='C'then 0 else 0-TD.PartAmount end)<>0 and (TD.ShowPartAmt=1 or TD.ShowPartAmt is null)   and (TD.Tran_Type='BR'or TD.Tran_Type='CR' or TD.Tran_Type='SR' or TD.Tran_Type='BP' or TD.Tran_Type='CP'  or TD.Tran_Type='DN' or TD.Tran_Type='CN' or TD.Tran_Type='J' )  and TD.Cmp_Code in(" + @Cmp_Code +")
            AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DatabaseName + "PARTYDETAIL WHERE JOBFLAG='JR')
            UNION ALL
              "

SET @SQL4="
            
            select AE.DocNo  AS DOCNO,AE.Vdate AS DATE,0 as VCode,'' as  BIll_No,'' as JobFlag,0 AS PENDINGAMOUNT,AE.PartAmount,        
            LM.Lgr_Name as Party,ALM.Lgr_Name as Agent,SM.SalesMan_Name as Salesman,CM.City_Name as  CITY,CGM.Cust_Grp_Name as CustomerGroup ,'P' AS P_D,
            AE.REMARK AS PARTICULAR,'' AS REMARK ,DATEDIFF(DAY,AE.Vdate,'"+@ASONDATE +"') as OUTDAYS  
            from "+@DATABASENAME+"Advance_Entry AE         
            inner join "+@DATABASENAME+"Ledger_Master LM on LM.Lgr_ID=AE.Lgr_ID
            left join "+@DATABASENAME+"Ledger_Detail LD on LM.Lgr_ID=LD.Lgr_ID and AE.Cmp_Code=LD.Cmp_Code
            left join "+@DATABASENAME+"Ledger_Master ALM on ALM.Lgr_Id=LD.Agent_ID
            left join "+@DATABASENAME+"City_Master CM on LM.City_ID=CM.City_ID
            left join "+@DATABASENAME+"SalesMan_Master SM on SM.SalesMan_Id=ALM.SalesMan_Id
            left join "+@DATABASENAME+"Customer_Group_Master CGM on CGM.Cust_Grp_ID=LM.Cust_Grp_ID                
            "+ @sqlJoin+ "
            where AE.Vdate<='"+@ASONDATE +"' and AE.PartAmount>0 and AE.Cmp_Code in("+@CMP_CODE+ ")
           
            ) AS DETAIL "+ @GrpSql +"
          "

    EXEC(@SQL1+@SQL2+@SQL3+@SQL4)

PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4


END




















GO

