INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID         
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
" +  @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL)
UNION ALL 
"
SET @SQLONACCOUNT2 ="  
SELECT 0 AS BILL_AMOUNT,0 AS REC_AMOUNT,0 AS DISCOUNT,0 AS INTEREST,0 AS INTREC,AE.PARTAMOUNT
,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(SM.SALESMAN_NAME,'') AS SALESMAN,
ISNULL(CM.CITY_NAME,'') AS  CITY,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP
,CMP.CMP_ALIAS AS ALIAS,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,LM.LGR_ID AS PARTYID,ALM.LGR_ID AS AGENTID,
ISNULL(SM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CM.CITY_ID,'') AS PARTY_CITYID,
ISNULL(ALM.CITY_ID,'') AS AGENT_CITYID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID

FROM " + @DATABASENAME + "ADVANCE_ENTRY AE         
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID      
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
" +  @SQLJOIN + "
