/*
PROC_OUTSTANDINGAGEING '1', N'ACC2010_2011.DBO.', N'01/APR/2010', N'08/AUG/2011', N'###2776', 0
*/




CREATE PROCEDURE [dbo].[PROC_OUTSTANDINGAGEING]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@OPNGDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@CRITERIA INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(500)
DECLARE @FIELDSQL NVARCHAR(500)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""
SET @FIELDSQL=""


BEGIN
IF @CRITERIA=0     /* PARTY */
BEGIN
SET @JOINSQL="" 
END
ELSE IF @CRITERIA=1    /* AGENT */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL ALD ON PLM.LGR_ID=ALD.LGR_ID AND ALD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON ALD.AGENT_ID=AGM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
"	
END
ELSE IF @CRITERIA=2    /* SALESMAN               */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL ALD ON PLM.LGR_ID=ALD.LGR_ID AND ALD.CMP_CODE="+@CMP_CODE+"
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALD.AGENT_ID=ALM.LGR_ID
INNER JOIN "+@DATABASENAME+"SALESMAN_MASTER SGM ON SGM.SALESMAN_ID=ALM.SALESMAN_ID"
END
ELSE IF @CRITERIA=3    /* CITY              */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CITY_MASTER P_CM ON P_CM.CITY_ID=PLM.CITY_ID"
END
ELSE IF @CRITERIA=4    /* CUSTOMER GROUP               */
BEGIN
SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=PLM.CUST_GRP_ID"
END


END


IF @CRITERIA=0    /* PARTY */
SET @FIELDSQL=",PLM.LGR_NAME AS MAINGRP,PLM.LGR_ID AS MAINGRPID,PCM.CITY_NAME AS MAINGRPCITY,
				PLM.LGR_NAME AS SECONDGROUP,PLM.LGR_ID AS SECONDGROUPID "
ELSE IF @CRITERIA=1    /* AGENT */
SET @FIELDSQL=",AGM.LGR_NAME AS MAINGRP,AGM.LGR_ID AS MAINGRPID,ACM.CITY_NAME AS MAINGRPCITY,
				AGM.LGR_NAME AS SECONDGROUP,AGM.LGR_ID AS SECONDGROUPID "
ELSE IF @CRITERIA=2    /* SALES MAN WISE */
SET @FIELDSQL=",SGM.SALESMAN_NAME AS MAINGRP,SGM.SALESMAN_ID AS MAINGRPID,CONVERT(NVARCHAR(200),'') AS MAINGRPCITY,
				ALM.LGR_NAME AS SECONDGROUP,ALM.LGR_ID AS SECONDGROUPID "
ELSE IF @CRITERIA=3    /* SUPPLIER GROUP */
SET @FIELDSQL=",PCM.CITY_NAME AS MAINGRP,PCM.CITY_ID AS MAINGRPID,CONVERT(NVARCHAR(200),'') AS MAINGRPCITY,
				PCM.CITY_NAME AS SECONDGROUP,PCM.CITY_ID AS SECONDGROUPID "
ELSE IF @CRITERIA=4    /* SUPPLIER GROUP */
SET @FIELDSQL=",CGM.CUST_GRP_NAME AS MAINGRP,CGM.CUST_GRP_ID AS MAINGRPID,CONVERT(NVARCHAR(200),'') AS MAINGRPCITY,
				CGM.CUST_GRP_NAME AS SECONDGROUP,CGM.CUST_GRP_ID AS SECONDGROUPID "


BEGIN
SET NOCOUNT ON;

SELECT @SQL=" 
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','VAT') THEN TM.TRAN_DOCNO ELSE '' END AS CHEQUEINT,
PLM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,  
TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,  
TM.TRAN_TYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TM.TRAN_MASTER_ID = PLM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID
"+@JOINSQL+"	
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN('J','VAT') 
AND TM.TRAN_DATE <='"+@TODATE+"' 

UNION ALL  

SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','VAT') THEN TM.TRAN_DOCNO ELSE 0 END AS CHEQUEINT,
PLM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,TM.TRAN_ID AS VCODE,
TM.TRAN_DATE AS VOUCHER_DATE, 
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT, 
TD.TRAN_TYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID= PLM.LGR_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@JOINSQL+"
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE NOT IN('J','VAT')  
AND TM.TRAN_DATE <='"+@TODATE+"' 

UNION ALL  "

SELECT @SQL1=" 				SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,AJ.ENTRYCODE AS VCODE,
AJ.VDATE AS VOUCHER_DATE,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE 
,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON AJ.LGR_ID = PLM.LGR_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PLM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@JOINSQL+"  
WHERE AJ.VDATE <='"+@TODATE+"' 
AND AJ.CMP_CODE="+@CMP_CODE+" 
UNION ALL 
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','VAT') THEN TM.TRAN_DOCNO ELSE 0 END AS CHEQUEINT,
PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,TD.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS DRAMOUNT, 
(CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID= PLM.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@JOINSQL+"
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_DATE <='"+@TODATE+"' AND TM.TRAN_TYPE IN ('J') 

UNION ALL "

SELECT @SQL2="	SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,0 AS VCODE,'"+@OPNGDATE+"' AS VOUCHER_DATE,
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT,
'OPNGBAL' AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+"	,PCM.CITY_NAME AS PARTYCITY			
FROM "+@DATABASENAME+"LEDGER_MASTER PLM 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON PLM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LD.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@JOINSQL+"
WHERE LD.LGR_OP_BAL>0 AND LD.CMP_CODE="+@CMP_CODE+" 
UNION ALL
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','VAT') THEN TM.TRAN_DOCNO ELSE '' END AS CHEQUEINT,
PLM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,  
TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,  
TM.TRAN_TYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER PLM ON TM.TRAN_MASTER_ID = PLM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID
"+@JOINSQL+"	
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE  IN('VAT') 
AND TM.TRAN_DATE <='"+@TODATE+"' 
ORDER BY MAINGRP,MAINGRPID,PARTYNAME,PARTYID,VOUCHER_DATE,DOCNO,DRAMOUNT
"


END
EXEC(@SQL+@SQL1+@SQL2 )
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















