FROM "+@PREVDATABASE+"TRAN_MASTER TM  
INNER JOIN "+@PREVDATABASE+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
