"+@PREJOINSQL+"
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE<> 'J'  
AND TM.TRAN_DATE <='"+@TODATE+"' 

UNION ALL  "

SELECT @SQL4=" 		SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,AJ.ENTRYCODE AS VCODE,
AJ.VDATE AS VOUCHER_DATE,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE 
,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY,1 AS ORD
FROM "+@PREVDATABASE+"AUTOJOURNAL AJ 
