SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('S','GS','VAT') THEN TM.TRAN_DOCNO ELSE 0 END AS CHEQUEINT,
PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,TD.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS DRAMOUNT, 
(CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS CRAMOUNT,
TM.TRAN_TYPE AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY,1 AS ORD
FROM "+@PREVDATABASE+"TRAN_MASTER TM 
INNER JOIN "+@PREVDATABASE+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID= PLM.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID
LEFT JOIN  "+@PREVDATABASE+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@PREJOINSQL+"	
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_DATE <='"+@TODATE+"' AND TM.TRAN_TYPE IN ('J') 

UNION ALL "

SELECT @SQL5="	   SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,0 AS VCODE,'01/APR/'+CONVERT(NVARCHAR,YEAR('"+@OPNGDATE+"') -1) AS VOUCHER_DATE, 
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT,
'OPNGBAL' AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+"	,PCM.CITY_NAME AS PARTYCITY,0 AS ORD			
FROM "+@PREVDATABASE+"LEDGER_MASTER PLM 
INNER JOIN "+@PREVDATABASE+"LEDGER_DETAIL LD ON PLM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LD.LGR_ID
LEFT JOIN  "+@PREVDATABASE+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@PREJOINSQL+"
WHERE LD.LGR_OP_BAL>0 AND LD.CMP_CODE="+@CMP_CODE+" 

"
END

END	

END
SET @FINALSQL=") AS DETAIL ORDER BY MAINGRP,MAINGRPID,PARTYNAME,PARTYID,ORD,VOUCHER_DATE,DOCNO,DRAMOUNT"
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @OPSQL
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @FINALSQL
EXEC(@SQL+@SQL1+@SQL2+@OPSQL+@SQL3+@SQL4+@SQL5+@FINALSQL)

















