INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LD.LGR_ID      
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID  
"+@JOINSQL+" 
WHERE LD.CMP_CODE="+@CMP_CODE+"  AND LD.LGR_OP_BAL>0 "
IF @PREDATABASE1<>""
SET @OPSQL = "AND PLM.LGR_ID NOT IN (SELECT LGR_ID FROM "+@PREDATABASE1+"LEDGER_MASTER PLM)

"   
--END


IF @PREDATABASE1<>"" 
BEGIN
SELECT @SQL6="   UNION  ALL
SELECT TM.TRAN_DOCNO AS DOCNO,
CASE WHEN TM.TRAN_TYPE IN ('P','FP','JP','YJP','T','CHP') THEN TM.TRAN_DOCNO ELSE '' END AS CHEQUEINT, 
PLM.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT , 
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,  
TM.TRAN_TYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY ,1 AS ORD
FROM "+@PREDATABASE1+"TRAN_MASTER TM
INNER JOIN "+@PREDATABASE1+"LEDGER_MASTER PLM ON TM.TRAN_MASTER_ID = PLM.LGR_ID  
LEFT JOIN  "+@PREDATABASE1+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID   
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRAN_MASTER_ID     
"+@JOINSQL+"  
WHERE TM.CMP_CODE = "+@CMP_CODE+" AND TM.TRAN_TYPE <> 'J'   
AND TM.TRAN_DATE <='"+@TODATE+"'  
"
SELECT @SQL7="        UNION ALL   
SELECT TM.TRAN_DOCNO AS DOCNO,CASE WHEN TM.TRAN_TYPE IN ('P','FP','JP','YJP','T','CHP') THEN TM.TRAN_DOCNO ELSE '' END AS CHEQUEINT, 
PLM.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,TM.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,  
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT, 
TD.TRAN_TYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY ,1 AS ORD
FROM "+@PREDATABASE1+"TRAN_MASTER TM    
INNER JOIN "+@PREDATABASE1+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+@PREDATABASE1+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID= PLM.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID      
LEFT JOIN  "+@PREDATABASE1+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID    
"+@JOINSQL+" 
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_TYPE<> 'J'      
AND TM.TRAN_DATE <='"+@TODATE+"'      
"     
SELECT @SQL8="     UNION ALL    
SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,AJ.ENTRYCODE AS VCODE,        AJ.VDATE AS VOUCHER_DATE,
AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY ,1 AS ORD
FROM "+@PREDATABASE1+"AUTOJOURNAL AJ   
INNER JOIN "+@PREDATABASE1+"LEDGER_MASTER PLM ON AJ.LGR_ID = PLM.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PLM.LGR_ID   
LEFT JOIN  "+@PREDATABASE1+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID
"+@JOINSQL+"
WHERE AJ.VDATE <='"+@TODATE+"'         AND AJ.CMP_CODE="+@CMP_CODE+"    
"
SELECT @SQL9="     UNION ALL         
SELECT TM.TRAN_DOCNO AS DOCNO,CASE WHEN TM.TRAN_TYPE IN ('P','FP','JP','YJP','T','CHP') THEN TM.TRAN_DOCNO ELSE '' END AS CHEQUEINT, 
PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,TD.TRAN_ID AS VCODE,TM.TRAN_DATE AS VOUCHER_DATE,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS DRAMOUNT,  
(CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END ) AS CRAMOUNT,   
TM.TRAN_TYPE AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY   ,1 AS ORD
FROM "+@PREDATABASE1+"TRAN_MASTER TM     
INNER JOIN "+@PREDATABASE1+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@PREDATABASE1+"LEDGER_MASTER PLM ON TD.TRAN_DETAIL_ID= PLM.LGR_ID   
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TD.TRAN_DETAIL_ID      
LEFT JOIN  "+@PREDATABASE1+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID      
"+@JOINSQL+"   
WHERE TM.CMP_CODE="+@CMP_CODE+" AND TM.TRAN_DATE <='"+@TODATE+"' AND TM.TRAN_TYPE IN ('J')   
"
SELECT @SQL10="     UNION ALL           
SELECT '' AS DOCNO,'' AS CHEQUEINT,PLM.LGR_NAME AS PARTYNAME,PLM.LGR_ID AS PARTYID,0 AS VCODE,'01/APR/'+CONVERT(NVARCHAR,YEAR('"+@OPNGDATE+"') -1) AS VOUCHER_DATE, 
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT, 
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT,
'OPNGBAL' AS TRANTYPE,TT.DEBIT,TT.CREDIT,TT.BAL "+@FIELDSQL+" ,PCM.CITY_NAME AS PARTYCITY     ,0 AS ORD
FROM "+@PREDATABASE1+"LEDGER_MASTER PLM  
INNER JOIN "+@PREDATABASE1+"LEDGER_DETAIL LD ON PLM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LD.LGR_ID      
LEFT JOIN  "+@PREDATABASE1+"CITY_MASTER PCM ON PCM.CITY_ID=PLM.CITY_ID  
"+@JOINSQL+" 
WHERE LD.CMP_CODE="+@CMP_CODE+"  AND LD.LGR_OP_BAL>0                               
" 
END


END  
SET @FINALSQL=" ORDER BY MAINGRP,MAINGRPID,PARTYNAME,PARTYID,VOUCHER_DATE,CHEQUEINT "
PRINT @SQL  
PRINT @SQL1  
PRINT @SQL2 
PRINT @SQL3  
PRINT @SQL4   
PRINT @SQL5
PRINT @SQL6  
PRINT @SQL7  
PRINT @SQL8  
PRINT @SQL9  
PRINT @SQL10 
PRINT @FINALSQL
EXEC(@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@OPSQL+@SQL6+@SQL7+@SQL8+@SQL9+@SQL10+@FINALSQL)




















GO

