-- =============================================
 PROC_OUTSTANDINGAVGDAYS N'1', N'ACC2015_2016.DBO.', 1, 3, N'##2216', N'01/APR/2014', N'16/NOV/2015', 0, 0, N'0', N'', 365, 0, 0, 0, 1, N'25' 
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDINGAVGDAYS_SUPP]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@RPT_TYPE INT,
@TEMPTABLE NVARCHAR(20),
@FROMDATE  NVARCHAR(20),
@ASONDATE  NVARCHAR(20),
@ONACCOUNT  INT,
@DUEPENDING  INT,
@DAYS NVARCHAR(4),
@PREVDATABASE NVARCHAR(20),
@YEARPERIOD INT,
@ONLYPENDING INT,	
@CRPERIOD INT ,
@ICHECKCRPERIOD INT,
@RPTSELE INT,
@CURRYEARCODE NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQLORDER AS NVARCHAR(4000)
DECLARE @SQLMAINGRP AS NVARCHAR(4000)

DECLARE @CONDITION AS NVARCHAR(2000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @FIELDSQL NVARCHAR(500)
DECLARE @CONDITION1 AS NVARCHAR(2000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""

SET @SQLORDER = ""
SET @SQLJOIN = ""
SET @FIELDSQL = ""
SET @CONDITION = ""
SET @SQLMAINGRP = ""
SET @CONDITION1 = ""
BEGIN
IF @RPT_WISE=1     /* PARTY */
BEGIN
SET @FIELDSQL = " (CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS MAINGRP,
				  ISNULL(LM.LGR_ID,0) AS MAINGRPID, "
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
END
IF @RPT_WISE=2    /* AGENT */
BEGIN
SET @FIELDSQL = " (CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS MAINGRP,
				  ISNULL(ALM.LGR_ID,0) AS MAINGRPID, "
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
END
IF @RPT_WISE=4   /* CITY */
BEGIN
SET @FIELDSQL = " CM.CITY_NAME AS MAINGRP,ISNULL(CM.CITY_ID,0) AS MAINGRPID, "
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
END
IF @RPT_WISE=5   /* CUSTOMER GROUP */
BEGIN	
SET @FIELDSQL = "CGM.SUPP_GRP_NAME AS MAINGRP,ISNULL(CGM.SUPP_GRP_ID,0) AS MAINGRPID, "
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.SUPP_GRP_ID"
END
END

BEGIN
IF(@RPT_TYPE=1) /* PAID */
SET @CONDITION=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE))   IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM " + @DATABASENAME + "PURADJMASTER AM1 WHERE AM1.RECDATE<='"+ @ASONDATE + "' AND AM1.PAID=1  AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG)"
END
BEGIN
IF(@RPT_TYPE=2) /* PENDING */
SET @CONDITION=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE)) NOT IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM " + @DATABASENAME + "PURADJMASTER AM1 WHERE AM1.RECDATE<='"+ @ASONDATE +"' AND AM1.PAID=1 AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG) "
END

BEGIN
IF @PREVDATABASE != ""
BEGIN
IF(@RPT_TYPE=1) /* PAID  AM1.RECDATE>'"+ @ASONDATE + "' */
BEGIN
SET @CONDITION1=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE))   IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM "+@PREVDATABASE+" PURADJMASTER AM1 WHERE  AM1.PAID=1  AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG)"
END

IF(@RPT_TYPE=2) /* PENDING AM1.RECDATE>'"+ @ASONDATE +"' AND */
BEGIN
SET @CONDITION1=" AND (AM.BILLNO+AM.FLAG+CONVERT(NVARCHAR(50),AM.VCODE)) NOT IN (SELECT (AM1.BILLNO+AM1.FLAG+CONVERT(NVARCHAR(50),AM1.VCODE)) FROM " +@PREVDATABASE+" PURADJMASTER AM1 WHERE AM1.PAID=1 AND AM1.CMP_CODE IN ("+@CMP_CODE+") AND AM.CMP_CODE=AM1.CMP_CODE AND AM.FLAG=AM1.FLAG) "
END
END
END
BEGIN
IF @RPTSELE = 1 /* DETAIL */
BEGIN
SET @SQLORDER = " ORDER BY MAINGRP,MAINGRPID,TRAN_DATE "
END
ELSE IF @RPTSELE = 2 /* SUMMARY */
BEGIN
IF @RPT_WISE = 1  /* PARTY */
BEGIN
SET @SQLMAINGRP = "  SELECT MAINGRP,MAINGRPID,PARTYID,PARTY,MAX(TRAN_DATE) AS TRAN_DATE,MAX(AGENT) AS AGENT,'' AS SALESMAN,MAX(CITY) AS CITY,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,
SUM(ISNULL(DRAMOUNT,0)) AS DRAMOUNT,SUM(ISNULL(CRAMOUNT,0)) AS CRAMOUNT,MAX(DDIFF) AS DDIFF,
SUM(ISNULL(DRPRODUCT,0)) AS DRPRODUCT,SUM(ISNULL(CRPRODUCT,0)) AS CRPRODUCT,MAX(TRAN_TYPE) AS TRAN_TYPE,
SUM(ISNULL(SALESAMT,0)) AS SALESAMT,SUM(ISNULL(SALESRETURNAMT,0)) AS SALESRETURNAMT,SUM(PURAMT) AS PURAMT,SUM(PURRETURNAMT) AS PURRETURNAMT,
GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS FROM ( "
SET @SQLORDER = " ) AS DETAIL GROUP BY MAINGRP,MAINGRPID,PARTYID,PARTY,GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS ORDER BY MAINGRP,MAINGRPID,PARTY,PARTYID "
END
ELSE IF @RPT_WISE = 2 /* AGENT */
BEGIN
SET @SQLMAINGRP = "  SELECT MAINGRP,MAINGRPID,PARTYID AS PARTYID,PARTY AS PARTY,MAX(TRAN_DATE) AS TRAN_DATE,AGENT AS AGENT,'' AS SALESMAN,MAX(CITY) AS CITY,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,
SUM(ISNULL(DRAMOUNT,0)) AS DRAMOUNT,SUM(ISNULL(CRAMOUNT,0)) AS CRAMOUNT,MAX(DDIFF) AS DDIFF,
SUM(ISNULL(DRPRODUCT,0)) AS DRPRODUCT,SUM(ISNULL(CRPRODUCT,0)) AS CRPRODUCT,MAX(TRAN_TYPE) AS TRAN_TYPE,
SUM(ISNULL(SALESAMT,0)) AS SALESAMT,SUM(ISNULL(SALESRETURNAMT,0)) AS SALESRETURNAMT,SUM(PURAMT) AS PURAMT,SUM(PURRETURNAMT) AS PURRETURNAMT,
GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS FROM ( "
SET @SQLORDER = " ) AS DETAIL GROUP BY MAINGRP,MAINGRPID,PARTYID,PARTY,AGENT,GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS ORDER BY MAINGRP,MAINGRPID,PARTY,PARTYID "
END
ELSE IF @RPT_WISE = 3 /* SALES MAN */
BEGIN
SET @SQLMAINGRP = "  SELECT MAINGRP,MAINGRPID,PARTYID AS PARTYID,PARTY AS PARTY,MAX(TRAN_DATE) AS TRAN_DATE,MAX(AGENT) AS AGENT,'' AS SALESMAN,MAX(CITY) AS CITY,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,
SUM(ISNULL(DRAMOUNT,0)) AS DRAMOUNT,SUM(ISNULL(CRAMOUNT,0)) AS CRAMOUNT,MAX(DDIFF) AS DDIFF,
SUM(ISNULL(DRPRODUCT,0)) AS DRPRODUCT,SUM(ISNULL(CRPRODUCT,0)) AS CRPRODUCT,MAX(TRAN_TYPE) AS TRAN_TYPE,
SUM(ISNULL(SALESAMT,0)) AS SALESAMT,SUM(ISNULL(SALESRETURNAMT,0)) AS SALESRETURNAMT,SUM(PURAMT) AS PURAMT,SUM(PURRETURNAMT) AS PURRETURNAMT,
GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS FROM ( "
SET @SQLORDER = " ) AS DETAIL GROUP BY MAINGRP,MAINGRPID,PARTYID,PARTY,SALESMAN,GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS ORDER BY MAINGRP,MAINGRPID,PARTY,PARTYID "
END
ELSE IF @RPT_WISE = 4 /* CITY */
BEGIN
SET @SQLMAINGRP = "  SELECT MAINGRP,MAINGRPID,PARTYID AS PARTYID,PARTY AS PARTY,MAX(TRAN_DATE) AS TRAN_DATE,MAX(AGENT) AS AGENT,'' AS SALESMAN,(CITY) AS CITY,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,
SUM(ISNULL(DRAMOUNT,0)) AS DRAMOUNT,SUM(ISNULL(CRAMOUNT,0)) AS CRAMOUNT,MAX(DDIFF) AS DDIFF,
SUM(ISNULL(DRPRODUCT,0)) AS DRPRODUCT,SUM(ISNULL(CRPRODUCT,0)) AS CRPRODUCT,MAX(TRAN_TYPE) AS TRAN_TYPE,
SUM(ISNULL(SALESAMT,0)) AS SALESAMT,SUM(ISNULL(SALESRETURNAMT,0)) AS SALESRETURNAMT,SUM(PURAMT) AS PURAMT,SUM(PURRETURNAMT) AS PURRETURNAMT,
GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS FROM ( "
SET @SQLORDER = " ) AS DETAIL GROUP BY MAINGRP,MAINGRPID,PARTYID,PARTY,CITY,GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS ORDER BY MAINGRP,MAINGRPID,PARTY,PARTYID "
END	
ELSE IF @RPT_WISE = 5 /* CUSTOMER GROUP */
BEGIN
SET @SQLMAINGRP = "  SELECT MAINGRP,MAINGRPID,PARTYID AS PARTYID,PARTY AS PARTY,MAX(TRAN_DATE) AS TRAN_DATE,MAX(AGENT) AS AGENT,'' AS SALESMAN,MAX(CITY) AS CITY,(CUSTOMERGROUP) AS CUSTOMERGROUP,
SUM(ISNULL(DRAMOUNT,0)) AS DRAMOUNT,SUM(ISNULL(CRAMOUNT,0)) AS CRAMOUNT,MAX(DDIFF) AS DDIFF,
SUM(ISNULL(DRPRODUCT,0)) AS DRPRODUCT,SUM(ISNULL(CRPRODUCT,0)) AS CRPRODUCT,MAX(TRAN_TYPE) AS TRAN_TYPE,
SUM(ISNULL(SALESAMT,0)) AS SALESAMT,SUM(ISNULL(SALESRETURNAMT,0)) AS SALESRETURNAMT,SUM(PURAMT) AS PURAMT,SUM(PURRETURNAMT) AS PURRETURNAMT,
GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS FROM ( "
SET @SQLORDER = " ) AS DETAIL GROUP BY MAINGRP,MAINGRPID,PARTYID,PARTY,CUSTOMERGROUP,GROUPNAME,GRP_ACC_TYPE,CMP_ALIAS ORDER BY MAINGRP,MAINGRPID,PARTY,PARTYID "
END	

END
END
BEGIN

SET @SQL = " SELECT DISTINCT "+@FIELDSQL+"  AM.BILLNO,AM.VCODE,AM.FLAG,PD.LGR_ID AS PARTYID,(CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS PARTY
,PD.DATE AS TRAN_DATE,(CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS AGENT
,'' AS SALESMAN,CM.CITY_NAME AS CITY,CGM.SUPP_GRP_NAME AS CUSTOMERGROUP,ISNULL(PD.AMOUNT,0) AS DRAMOUNT
,0  AS CRAMOUNT,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE+"') + 1 AS DDIFF
,(DATEDIFF(DAY, PD.DATE ,'"+@ASONDATE+"')+1)* ISNULL(PD.AMOUNT,0)/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS  DRPRODUCT
, (DATEDIFF(DAY, PD.DATE ,'"+@ASONDATE+"')+1)*0/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS CRPRODUCT,PD.FLAG AS TRAN_TYPE
,0 AS  SALESAMT,0 AS SALESRETURNAMT, 
ISNULL(PD.AMOUNT,0) AS PURAMT,0 AS  PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,CMP.CMP_ALIAS,PD.VCODE AS PARTYVCODE
FROM "+@DATABASENAME+" PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+" PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+@ASONDATE+"' 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID 
LEFT JOIN "+@DATABASENAME+" SUPPLIER_GROUP_MASTER CGM ON CGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=PD.CMP_CODE 
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@SQLJOIN+" 
WHERE  PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+") "+@CONDITION+" 
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.VCODE),3,2) < '"+@CURRYEARCODE+"'
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.ENTRYCODE),3,2) = '"+@CURRYEARCODE+"'
 UNION ALL "

SET @SQL1 = " SELECT "+@FIELDSQL+" (AM.BILLNO) AS BILLNO,(AM.VCODE) AS VCODE,(AM.FLAG) AS FLAG,PD.LGR_ID AS PARTYID,(CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS PARTY
,(AM.RECDATE) AS TRAN_DATE,(CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS AGENT
,'' AS SALESMAN,CM.CITY_NAME AS CITY,CGM.SUPP_GRP_NAME AS CUSTOMERGROUP,0 AS DRAMOUNT
,(ISNULL(AM.ADJUSTAMT,0) )  AS CRAMOUNT,DATEDIFF(DAY,(AM.RECDATE),'"+@ASONDATE+"') + 1 AS DDIFF
,(DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)* 0/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS DRPRODUCT
, (DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)*(ISNULL(AM.ADJUSTAMT,0) )/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS CRPRODUCT,PD.FLAG AS TRAN_TYPE
,0 AS  SALESAMT, 0 AS SALESRETURNAMT, 
0 AS PURAMT,(CASE WHEN (AM.TYPE) IN ('PR','CPR','MPR','FPR') THEN (AM.AMOUNT) ELSE 0 END) AS  PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,CMP.CMP_ALIAS,PD.VCODE AS PARTYVCODE
FROM "+@DATABASENAME+" PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+" PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+@ASONDATE+"' 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID 
LEFT JOIN "+@DATABASENAME+" SUPPLIER_GROUP_MASTER CGM ON CGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=PD.CMP_CODE 
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@SQLJOIN+" 
WHERE  PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+") "+@CONDITION+"
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.VCODE),3,2) < '"+@CURRYEARCODE+"'
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.ENTRYCODE),3,2) = '"+@CURRYEARCODE+"'
AND (ISNULL(AM.ADJUSTAMT,0)) > 0
UNION ALL "

SET @SQL2 = " SELECT "+@FIELDSQL+" AM.BILLNO,AM.VCODE,AM.FLAG,PD.LGR_ID AS PARTYID,(CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS PARTY
,AM.RECDATE AS TRAN_DATE,(CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS AGENT
,'' AS SALESMAN,CM.CITY_NAME AS CITY,CGM.SUPP_GRP_NAME AS CUSTOMERGROUP,0 AS DRAMOUNT
,(ISNULL(AM.TOTAL,0))  AS CRAMOUNT,DATEDIFF(DAY,AM.RECDATE,'"+@ASONDATE+"') + 1 AS DDIFF
,(DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)* 0/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS  DRPRODUCT
, (DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)*(ISNULL(AM.TOTAL,0))/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS CRPRODUCT,PD.FLAG AS TRAN_TYPE
,  0 AS  SALESAMT,0 AS SALESRETURNAMT, 
0 AS PURAMT,(CASE WHEN (AM.TYPE) IN ('PR','CPR','MPR','FPR') THEN (AM.AMOUNT) ELSE 0 END) AS  PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,CMP.CMP_ALIAS,PD.VCODE AS PARTYVCODE
FROM "+@DATABASENAME+" PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+" PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+@ASONDATE+"' 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID 
LEFT JOIN "+@DATABASENAME+" SUPPLIER_GROUP_MASTER CGM ON CGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=PD.CMP_CODE 
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@SQLJOIN+" 
WHERE  PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+") AND (ISNULL(AM.TOTAL,0)) > 0  "+@CONDITION+"  
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.VCODE),3,2) < '"+@CURRYEARCODE+"'
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.ENTRYCODE),3,2) = '"+@CURRYEARCODE+"' "


IF @PREVDATABASE != ""
BEGIN

SET @SQL4 = "UNION ALL SELECT "+@FIELDSQL+" (AM.BILLNO) AS BILLNO,(AM.VCODE) AS VCODE,(AM.FLAG) AS FLAG,PD.LGR_ID AS PARTYID,(CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS PARTY
,(AM.RECDATE) AS TRAN_DATE,(CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS AGENT
,'' AS SALESMAN,CM.CITY_NAME AS CITY,CGM.SUPP_GRP_NAME AS CUSTOMERGROUP,0 AS DRAMOUNT
,(ISNULL(AM.ADJUSTAMT,0))  AS CRAMOUNT,DATEDIFF(DAY,(AM.RECDATE),'"+@ASONDATE+"') + 1 AS DDIFF
,(DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)* 0/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS DRPRODUCT
, (DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)*(ISNULL(AM.ADJUSTAMT,0) )/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS CRPRODUCT,PD.FLAG AS TRAN_TYPE
,0 AS  SALESAMT, 0 AS SALESRETURNAMT, 
0 AS PURAMT,(CASE WHEN (AM.TYPE) IN ('PR','CPR','MPR','FPR') THEN (AM.AMOUNT) ELSE 0 END) AS  PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,CMP.CMP_ALIAS,PD.VCODE AS PARTYVCODE
FROM "+@PREVDATABASE+" PURPARTYDETAIL PD 
INNER JOIN "+@PREVDATABASE+" PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE

LEFT JOIN "+@PREVDATABASE+" LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
LEFT JOIN "+@PREVDATABASE+" LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@PREVDATABASE+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@PREVDATABASE+" CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID 
LEFT JOIN "+@PREVDATABASE+" SUPPLIER_GROUP_MASTER CGM ON CGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+@PREVDATABASE+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
INNER JOIN "+@PREVDATABASE+" LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=PD.CMP_CODE 
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@SQLJOIN+" 
WHERE  PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+") 
"+@CONDITION1+" 
AND (ISNULL(AM.ADJUSTAMT,0) ) > 0 
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.ENTRYCODE),3,2) > '"+@CURRYEARCODE+"'
UNION ALL "

SET @SQL5 = " SELECT "+@FIELDSQL+" AM.BILLNO,AM.VCODE,AM.FLAG,PD.LGR_ID AS PARTYID,(CASE WHEN ISNULL(CM.CITY_NAME,'') = '' THEN LM.LGR_NAME ELSE LM.LGR_NAME + ',' + CM.CITY_NAME END) AS PARTY
,AM.RECDATE AS TRAN_DATE,(CASE WHEN ISNULL(ACM.CITY_NAME,'')='' THEN ALM.LGR_NAME ELSE ALM.LGR_NAME + ',' + ACM.CITY_NAME END) AS AGENT
,'' AS SALESMAN,CM.CITY_NAME AS CITY,CGM.SUPP_GRP_NAME AS CUSTOMERGROUP,0 AS DRAMOUNT
,(ISNULL(AM.TOTAL,0))  AS CRAMOUNT,DATEDIFF(DAY,AM.RECDATE,'"+@ASONDATE+"') + 1 AS DDIFF
,(DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)* 0/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS  DRPRODUCT
, (DATEDIFF(DAY, AM.RECDATE ,'"+@ASONDATE+"')+1)*(ISNULL(AM.TOTAL,0))/" + CONVERT(NVARCHAR(5),@YEARPERIOD) + " AS CRPRODUCT,PD.FLAG AS TRAN_TYPE
,  0 AS  SALESAMT, 0 AS SALESRETURNAMT, 
0 AS PURAMT,(CASE WHEN (AM.TYPE) IN ('PR','CPR','MPR','FPR') THEN (AM.AMOUNT) ELSE 0 END) AS  PURRETURNAMT,GM.GRP_NAME AS GROUPNAME,GM.GRP_ACC_TYPE,CMP.CMP_ALIAS,PD.VCODE AS PARTYVCODE
FROM "+@PREVDATABASE+" PURPARTYDETAIL PD 
INNER JOIN "+@PREVDATABASE+" PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  

LEFT JOIN "+@PREVDATABASE+" LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
LEFT JOIN "+@PREVDATABASE+" LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@PREVDATABASE+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@PREVDATABASE+" CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID 
LEFT JOIN "+@PREVDATABASE+" SUPPLIER_GROUP_MASTER CGM ON CGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
INNER JOIN "+@PREVDATABASE+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
INNER JOIN "+@PREVDATABASE+" LEDGER_DETAIL LD1 ON LD1.LGR_ID=LM.LGR_ID AND LD1.CMP_CODE=PD.CMP_CODE 
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID=LD1.GRP_ID 
"+@SQLJOIN+" 
WHERE  PD.DATE BETWEEN '"+@FROMDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE+") AND (ISNULL(AM.TOTAL,0)) > 0  "+@CONDITION1+"  
AND SUBSTRING(CONVERT(NVARCHAR(20),AM.ENTRYCODE),3,2) > '"+@CURRYEARCODE+"'"
END

END

EXEC(@SQLMAINGRP+@SQL+@SQL1+@SQL2+@SQL3+@SQLORDER) /* @SQL4+@SQL5+ COMMENT FOR DATA NOT GET OF PREVIOUS YRAR 24-11-2015 */
PRINT @SQLMAINGRP
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
