/* 
-- =============================================
-- AUTHOR         : <BIREN>
-- ALTER_DATE    : <13/06/2013 5:20 PM>
-- REPORT_FORM    : <RFRMOUTSTANDDEBIT_CREDITNOTE.CS>
-- CRYSTAL_REPORT : <OUTSTANDDEBIT_CREDITNOTE.RPT>
-- =============================================
PROC_OUTSTANDINGDEBIT_CREDITNOTE '1','ACC2013_2014.DBO.',4,'##4764','12/JUL/2013','01/APR/2013','ACC2012_2013.DBO.'

AND SUBSTRING(CONVERT(NVARCHAR(20),PD.VCODE),3,2)='"+@PRVYEARCODE+"'  
TO GET PREVIOUS YEAR DATA FROM PREV DATABASE INSTEAD OF PREYEARCODE LINE 209
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDINGDEBIT_CREDITNOTE]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@TEMPTABLE NVARCHAR(20),
	@ASONDATE  NVARCHAR(20),
	@STARTDATE NVARCHAR(20),
	@PRVDATABASE NVARCHAR(50)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)

SET @SQLJOIN =""
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""

BEGIN
IF @RPT_WISE=1     
	   SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID = TT.CODE"
IF @RPT_WISE=2 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = ALM.LGR_ID"
IF @RPT_WISE=3 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = SM.SALESMAN_ID"
IF @RPT_WISE=4 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = CM.CITY_ID"
IF @RPT_WISE=5 
    	SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE = CGM.CUST_GRP_ID"
END

BEGIN 
SET @SQL =  "
			SELECT VCODE,PARTY,AGENT,SALESMAN,PARTYCITY,AGENTCITY,CUSTOMERGROUP,BILLNO,DATE,PD_BILL_AMOUNT,
			ISNULL(AJ_AMOUNT,0) AS AJ_AMOUNT,ISNULL(REC_AMOUNT,0) AS REC_AMOUNT,
			ISNULL(AJ_TOTAL,0) AS AJ_TOTAL,ISNULL(AJ_DISCOUNT,0) AS AJ_DISCOUNT,ISNULL(AJ_INTEREST,0) AS AJ_INTEREST,
			ISNULL(AJ_INTREC,0) AS AJ_INTREC,
			ISNULL((PD_BILL_AMOUNT + AJ_INTEREST) - (AJ_TOTAL + AJ_INTREC + REC_AMOUNT),0) AS PENDING,CMP_CODE,ALIAS,FLAG,
			PENDING_AMOUNT,2 AS ORD FROM ( 

			SELECT PD.VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
			PD.BILL_NO AS BILLNO,PD.DATE,ISNULL(PD.BILL_AMOUNT,0) AS PD_BILL_AMOUNT,AM.AMOUNT AS AJ_AMOUNT,
			ISNULL(SUM(AM.ADJUSTAMT),0) AS REC_AMOUNT,ISNULL(SUM(TOTAL),0) AS AJ_TOTAL,
			ISNULL(SUM(AM.DISCOUNT),0) AS AJ_DISCOUNT,
			ISNULL(SUM(AM.INTEREST),0) AS AJ_INTEREST,ISNULL(SUM(AM.INTREC),0) AS AJ_INTREC,
			PD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,PD.JOBFLAG AS FLAG,PD.PENDING_AMOUNT

			FROM " + @DATABASENAME + "PARTYDETAIL PD
			LEFT JOIN " + @DATABASENAME + "ADJMASTER AM ON AM.BILLNO = PD.BILL_NO AND AM.FLAG = PD.JOBFLAG 
				AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE AND AM.RECDATE<='"+ @ASONDATE +"' 
			LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID = PD.LGR_ID
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID = PD.AGENT_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID = ALM.SALESMAN_ID
			LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
			INNER JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE = PD.CMP_CODE
			"+@SQLJOIN+"
			WHERE PD.JOBFLAG IN ('O','S','GS','YS') AND PD.CMP_CODE IN("+ @CMP_CODE +")
			GROUP BY PD.VCODE,LM.LGR_NAME,ALM.LGR_NAME,SM.SALESMAN_NAME,CM.CITY_NAME,ACM.CITY_NAME,
			CGM.CUST_GRP_NAME,PD.CMP_CODE,
			PD.BILL_NO,PD.DATE,PD.BILL_AMOUNT,CMP.CMP_ALIAS,AMOUNT,PD.JOBFLAG,PD.PENDING_AMOUNT
			) AS DETAIL  WHERE ISNULL((PD_BILL_AMOUNT + AJ_INTEREST) - (AJ_TOTAL + AJ_INTREC + REC_AMOUNT),0) <> 0
        	AND ISNULL(PD_BILL_AMOUNT,0) <> PENDING_AMOUNT 
			AND DATE<='"+@ASONDATE+"'
			"

SET @SQL1 = " UNION ALL
			SELECT VCODE,PARTY,AGENT,SALESMAN,PARTYCITY,AGENTCITY,CUSTOMERGROUP,BILLNO,DATE,PD_BILL_AMOUNT,
			ISNULL(AJ_AMOUNT,0) AS AJ_AMOUNT,ISNULL(REC_AMOUNT,0) AS REC_AMOUNT,
			ISNULL(AJ_TOTAL,0) AS AJ_TOTAL,ISNULL(AJ_DISCOUNT,0) AS AJ_DISCOUNT,ISNULL(AJ_INTEREST,0) AS AJ_INTEREST,
			ISNULL(AJ_INTREC,0) AS AJ_INTREC,
			ISNULL((PD_BILL_AMOUNT + AJ_INTEREST) - (AJ_TOTAL + AJ_INTREC + REC_AMOUNT),0) AS PENDING,CMP_CODE,ALIAS,FLAG,
			PENDING_AMOUNT,2 AS ORD FROM ( 

			SELECT PD.VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
			PD.BILL_NO AS BILLNO,PD.DATE,ISNULL(PD.BILL_AMOUNT,0) AS PD_BILL_AMOUNT,AM.AMOUNT AS AJ_AMOUNT,
			ISNULL(SUM(AM.ADJUSTAMT),0) AS REC_AMOUNT,ISNULL(SUM(TOTAL),0) AS AJ_TOTAL,
			ISNULL(SUM(AM.DISCOUNT),0) AS AJ_DISCOUNT,
			ISNULL(SUM(AM.INTEREST),0) AS AJ_INTEREST,ISNULL(SUM(AM.INTREC),0) AS AJ_INTREC,
			PD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,PD.JOBFLAG AS FLAG,PD.PENDING_AMOUNT

			FROM " + @DATABASENAME + "PARTYDETAIL PD
			LEFT JOIN " + @DATABASENAME + "ADJMASTER AM ON AM.BILLNO = PD.BILL_NO AND AM.FLAG = PD.JOBFLAG 
				AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE AND AM.RECDATE<='"+ @ASONDATE +"' 
			LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID = PD.LGR_ID
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID = PD.AGENT_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID = ALM.SALESMAN_ID
			LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
			LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE = PD.CMP_CODE
			"+@SQLJOIN+"
			WHERE PD.JOBFLAG NOT IN ('O','S','GS','YS') AND PD.CMP_CODE IN("+ @CMP_CODE +")
			GROUP BY PD.VCODE,LM.LGR_NAME,ALM.LGR_NAME,SM.SALESMAN_NAME,CM.CITY_NAME,ACM.CITY_NAME,
			CGM.CUST_GRP_NAME,PD.CMP_CODE,
			PD.BILL_NO,PD.DATE,PD.BILL_AMOUNT,CMP.CMP_ALIAS,AMOUNT,PD.JOBFLAG,PD.PENDING_AMOUNT
			) AS DETAIL WHERE ISNULL((PD_BILL_AMOUNT + AJ_INTEREST) - (AJ_TOTAL + AJ_INTREC + REC_AMOUNT),0) > 0
			 AND DATE<='"+@ASONDATE+"'
			"

SET @SQL2 = " UNION ALL
			SELECT VCODE,PARTY,AGENT,SALESMAN,PARTYCITY,AGENTCITY,CUSTOMERGROUP,BILLNO,DATE,PD_BILL_AMOUNT,
			ISNULL(AJ_AMOUNT,0) AS AJ_AMOUNT,ISNULL(REC_AMOUNT,0) AS REC_AMOUNT,
			ISNULL(AJ_TOTAL,0) AS AJ_TOTAL,ISNULL(AJ_DISCOUNT,0) AS AJ_DISCOUNT,ISNULL(AJ_INTEREST,0) AS AJ_INTEREST,
			ISNULL(AJ_INTREC,0) AS AJ_INTREC,
			(0-ISNULL(PENDING_AMOUNT,0)) AS PENDING,CMP_CODE,ALIAS,FLAG,
			PENDING_AMOUNT,2 AS ORD FROM ( 

			SELECT 0 AS VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
			TM.TRAN_DOCNO AS BILLNO,TM.TRAN_DATE AS  DATE,TD.TRAN_TYPE AS FLAG,0 AS PD_BILL_AMOUNT,0 AS AJ_AMOUNT,
			0 AS REC_AMOUNT,0 AS AJ_TOTAL,0 AS AJ_DISCOUNT,0 AS AJ_INTEREST,
			0 AS AJ_INTREC,TD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,
			TD.PARTAMOUNT AS PENDING_AMOUNT

			FROM " + @DATABASENAME + "TRAN_DETAIL TD 
			INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
			INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
			LEFT JOIN  " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID         
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
			LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
			LEFT JOIN  " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
			INNER JOIN GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
			"+@SQLJOIN+"			
			WHERE (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) AND PARTAMOUNT<>0
			AND (TD.REC_TRANS=0 OR TD.REC_TRANS IS NULL)
			AND TD.TRAN_TYPE IN('CN') AND GRP_NAME='SUNDRY DEBTORS'
			) AS DETAIL WHERE CMP_CODE IN("+ @CMP_CODE +") AND DATE<='"+@ASONDATE+"'
			
			"
SET @SQL3 = " UNION ALL
			SELECT MAX(VCODE) AS VCODE,PARTY AS PARTY,MAX(AGENT) AS AGENT,MAX(SALESMAN) AS SALESMAN,
			MAX(PARTYCITY) AS PARTYCITY,MAX(AGENTCITY) AS AGENTCITY,
			MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,MAX(BILLNO) AS BILLNO,MAX(DATE) AS DATE,MAX(PD_BILL_AMOUNT) AS PD_BILL_AMOUNT,
			MAX(AJ_AMOUNT) AS AJ_AMOUNT,SUM(REC_AMOUNT) AS REC_AMOUNT,MAX(AJ_TOTAL)AS AJ_TOTAL,MAX(AJ_DISCOUNT) AS AJ_DISCOUNT,
			MAX(AJ_INTEREST) AS AJ_INTEREST,MAX(AJ_INTREC) AS AJ_INTREC,(SUM(BILL_AMOUNT) - SUM(LGR_OP_BAL)) AS PENDING,
			MAX(CMP_CODE) AS CMP_CODE,MAX(ALIAS) AS FLAG,MAX(FLAG) AS FLAG,MAX(PENDING_AMOUNT) AS PENDING_AMOUNT,1 AS ORD
			FROM (

			SELECT 0 AS VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'OPNG' AS BILLNO,'"+@STARTDATE+"' AS DATE,0 AS PD_BILL_AMOUNT,
			0 AS AJ_AMOUNT,0 AS REC_AMOUNT,0 AS AJ_TOTAL,0 AS AJ_DISCOUNT,
			0 AS AJ_INTEREST,0 AS AJ_INTREC,CONVERT(NUMERIC(18,2),LD.LGR_OP_BAL) AS LGR_OP_BAL,0 AS BILL_AMOUNT,
			LD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,'OPNG' AS FLAG,0 AS PENDING_AMOUNT,1 AS ORD
			FROM " + @DATABASENAME + "LEDGER_DETAIL LD
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID = LD.LGR_ID
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID = LD.AGENT_ID 
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID = ALM.SALESMAN_ID
			LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
			INNER JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE = LD.CMP_CODE
			"+@SQLJOIN+""
IF @PRVDATABASE <> ""	
	SET @SQL4 = " UNION ALL
			SELECT 0 AS VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
			CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'OPNG' AS BILLNO,'"+@STARTDATE+"' AS DATE,0 AS PD_BILL_AMOUNT,
			0 AS AJ_AMOUNT,0 AS REC_AMOUNT,0 AS AJ_TOTAL,0 AS AJ_DISCOUNT,
			0 AS AJ_INTEREST,0 AS AJ_INTREC,0 AS LGR_OP_BAL,SUM(PD.BILL_AMOUNT) AS BILL_AMOUNT,
			PD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,'OPNG' AS FLAG,0 AS PENDING_AMOUNT,1 AS ORD

			FROM " + @PRVDATABASE + "PARTYDETAIL PD
			LEFT JOIN  " + @PRVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID = PD.LGR_ID
			INNER JOIN " + @PRVDATABASE + "LEDGER_DETAIL LD ON PD.LGR_ID = LD.LGR_ID AND LD.CMP_CODE = PD.CMP_CODE			
			LEFT JOIN  " + @PRVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID = LD.AGENT_ID 
			LEFT JOIN  " + @PRVDATABASE + "CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  " + @PRVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
			LEFT JOIN  " + @PRVDATABASE + "SALESMAN_MASTER SM ON SM.SALESMAN_ID = ALM.SALESMAN_ID
			LEFT JOIN  " + @PRVDATABASE + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
			INNER JOIN " + @PRVDATABASE + "COMPANY_MASTER CMP ON CMP.CMP_CODE = PD.CMP_CODE
			"+@SQLJOIN+"
			WHERE PD.BILL_AMOUNT = PD.PENDING_AMOUNT 
			AND PD.CMP_CODE IN("+ @CMP_CODE +") AND PD.JOBFLAG <> 'DN'
			GROUP BY LM.LGR_NAME,ALM.LGR_NAME,SM.SALESMAN_NAME,CM.CITY_NAME,ACM.CITY_NAME,
			CGM.CUST_GRP_NAME,PD.CMP_CODE,LD.LGR_OP_BAL,CMP.CMP_ALIAS
"
SET @SQL5 = " ) AS DETAIL
			  GROUP BY PARTY HAVING (SUM(LGR_OP_BAL) - SUM(BILL_AMOUNT)) <> 0
			"
SET @SQL6 = " UNION ALL
			SELECT TD.TRAN_ID AS VCODE,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,
			ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
			TM.TRAN_DOCNO AS BILLNO,TM.TRAN_DATE AS DATE,ISNULL(TD.TRAN_AMOUNT,0) AS PD_BILL_AMOUNT,0 AS AJ_AMOUNT,
			0 AS REC_AMOUNT,0 AS AJ_TOTAL,
			0 AS AJ_DISCOUNT,
			0 AS AJ_INTEREST,0 AS AJ_INTREC,
			(CASE WHEN TD.TRAN_TYPE IN ('BP','CP') THEN (0-TD.TRAN_AMOUNT) 
			WHEN TD.TRAN_TYPE IN ('SR') THEN TD.TRAN_AMOUNT END) AS PENDING,
			TD.CMP_CODE,CMP.CMP_ALIAS AS ALIAS,TD.TRAN_TYPE AS FLAG,TD.TRAN_AMOUNT AS PENDING_AMOUNT ,2 AS ORD

			FROM " + @DATABASENAME + "TRAN_DETAIL TD 
			INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
			INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
			LEFT JOIN  " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
			LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
			LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
			LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
			LEFT JOIN  " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
			INNER JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
			"+@SQLJOIN+"
			WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
			AND (TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP') AND TD.CMP_CODE IN("+ @CMP_CODE +")        
			AND TD.ADJUST='NO'
			AND GRP_NAME='SUNDRY DEBTORS'
			ORDER BY ORD,DATE
			"
END
 
EXEC(@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6




















GO

/****** Object:  StoredProcedure [dbo].[PROC_OUTSTANDINGREMINDER]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_OUTSTANDINGREMINDER N'0,1,2,3,4,5,6', N'Acc2015_2016.Dbo.', N'0', N'25/Jul/2015', N'0', N'0', N'##468', N'Acc2014_2015.Dbo.', 0, 1
*/

CREATE PROCEDURE [dbo].[PROC_OUTSTANDINGREMINDER]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(50),
@CREDITDAYS NVARCHAR(50),    
@ASONDATE AS NVARCHAR(20),
@PENDINGALL NVARCHAR(10),
@LGR_ID AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@PREVDATABASE NVARCHAR(20),
@ONACCOUNT  INT,
@RPTWISE  INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SELSQL  NVARCHAR(1000)
DECLARE @WHERESQL NVARCHAR(1000)
DECLARE @ALLCONDSQL NVARCHAR(1000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2 NVARCHAR(4000)
DECLARE @SQL3  NVARCHAR(4000)
DECLARE @SQLJOIN  NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)

DECLARE @SQL4  NVARCHAR(4000)
DECLARE @SQL5 NVARCHAR(4000)
DECLARE @SQL6  NVARCHAR(4000)

SET @SELSQL=""
SET @WHERESQL =""
SET @ALLCONDSQL=""

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""

IF @CREDITDAYS=0
BEGIN
SET @SELSQL=" PD.DATE AS DUEDATE,"
SET @WHERESQL ="AND PD.DATE <='" + @ASONDATE + "'"
END
ELSE
BEGIN	
SET @SELSQL=" DATEADD(DAY,"+ @CREDITDAYS + ",PD.DATE) AS DUEDATE,"	
SET @WHERESQL =" AND DATEADD(DAY," + @CREDITDAYS + ",PD.DATE ) <='" + @ASONDATE  + "'"
END

IF @PENDINGALL="0"
BEGIN
SET @ALLCONDSQL=""
END
ELSE IF @PENDINGALL="1"
BEGIN
SET @ALLCONDSQL=" AND PD.PENDING_AMOUNT = PD.BILL_AMOUNT  "
END


IF @RPTWISE=1 
BEGIN    
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL=" ORDER BY CITY_NAME,PARTY_CITYID,PARTYNAME,PARTYID,FLAG,INVOICEDATE,INVOICENO"
END

ELSE IF @RPTWISE=2
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
SET @ORDERBYSQL="  ORDER BY CUSTOMERGROUP,CUSTGRPID,CITY_NAME,PARTY_CITYID,PARTYNAME,PARTYID,FLAG,INVOICEDATE,INVOICENO"
END

ELSE IF @RPTWISE=3
BEGIN
SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
SET @ORDERBYSQL="  ORDER BY CITY_NAME,PARTY_CITYID,PARTYNAME,PARTYID,FLAG,INVOICEDATE,INVOICENO"
END

ELSE IF @RPTWISE=4
BEGIN
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL="  ORDER BY AGENTNAME,AGENTID,CITY_NAME,PARTY_CITYID,PARTYNAME,PARTYID,FLAG,INVOICEDATE,INVOICENO"
END

 

BEGIN 
IF @ONACCOUNT=1
SET @SQL1 ="
UNION ALL
SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
TM.TRAN_ID AS VCODE, TM.TRAN_DOCNO AS INVOICENO, TM.TRAN_DATE AS INVOICEDATE,TM.TRAN_AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
(CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,TM.TRAN_DATE  AS RECDATE,'P' AS FLAG, TM.TRAN_TYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @DATABASENAME + "TRAN_DETAIL TD 
INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID   
LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE   
"+@SQLJOIN+"                      
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP' 
OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN (" + @CMP_CODE +")        
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
AND (TD.TRAN_DRCR='C') 
/* AND LM.LGR_ID = '" + @LGR_ID + "' */ 
UNION ALL "

SET @SQL2 ="  
SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
TM.TRAN_ID AS VCODE, TM.TRAN_DOCNO AS INVOICENO, TM.TRAN_DATE AS INVOICEDATE,TM.TRAN_AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)AS PARTAMOUNT,TM.TRAN_DATE  AS RECDATE,'P' AS FLAG, TM.TRAN_TYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @DATABASENAME + "TRAN_DETAIL TD 
INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID  AND LM.LGR_TYPE = 'L'       
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID    
LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID 
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
"+@SQLJOIN+"                       
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='BP')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @DATABASENAME + " PARTYDETAIL WHERE JOBFLAG='CP')
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS' 
/*  AND LM.LGR_ID = '" + @LGR_ID + "' */ 
UNION ALL 
"
SET @SQL3 ="  

SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
AE.ADV_ID AS VCODE, AE.DOCNO AS INVOICENO, AE.VDATE AS INVOICEDATE,AE.AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
AE.PARTAMOUNT,AE.VDATE  AS RECDATE,'P' AS FLAG, AE.ENTRYTYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @DATABASENAME + "ADVANCE_ENTRY AE         
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
"+@SQLJOIN+"
WHERE AE.VDATE<='"+@ASONDATE+"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN(" + @CMP_CODE +") 
/* AND LM.LGR_ID = '" + @LGR_ID + "' */  "	

BEGIN
IF  @PREVDATABASE!=""
BEGIN
SET @SQL4 ="
UNION ALL
SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
TM.TRAN_ID AS VCODE, TM.TRAN_DOCNO AS INVOICENO, TM.TRAN_DATE AS INVOICEDATE,TM.TRAN_AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
(CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,TM.TRAN_DATE  AS RECDATE,'P' AS FLAG, TM.TRAN_TYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @PREVDATABASE + "TRAN_DETAIL TD 
INNER JOIN " + @PREVDATABASE + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND LM.LGR_TYPE = 'L'
LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @PREVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID   
LEFT JOIN " + @PREVDATABASE +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID 
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE   
"+@SQLJOIN+"                     
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP' 
OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN (" + @CMP_CODE +")        
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS'
AND (TD.TRAN_DRCR='C') 
/* AND LM.LGR_ID = '" + @LGR_ID + "' */ 
UNION ALL "

SET @SQL5 ="  
SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
TM.TRAN_ID AS VCODE, TM.TRAN_DOCNO AS INVOICENO, TM.TRAN_DATE AS INVOICEDATE,TM.TRAN_AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)AS PARTAMOUNT,TM.TRAN_DATE  AS RECDATE,'P' AS FLAG, TM.TRAN_TYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,TM.TRAN_DATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @PREVDATABASE + "TRAN_DETAIL TD 
INNER JOIN " + @PREVDATABASE + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID  AND LM.LGR_TYPE = 'L'       
LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @PREVDATABASE + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@PREVDATABASE+" GROUP_MASTER GM ON GM.GRP_ID = LD.GRP_ID    
LEFT JOIN " + @PREVDATABASE +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID 
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE 
"+@SQLJOIN+"                      
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='JR')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'DN') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + "PARTYDETAIL WHERE JOBFLAG='DN')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'BP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + " PARTYDETAIL WHERE JOBFLAG='BP')
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'CP') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM " + @PREVDATABASE + " PARTYDETAIL WHERE JOBFLAG='CP')
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND GM.GRP_NAME = 'SUNDRY DEBTORS' 
/*  AND LM.LGR_ID = '" + @LGR_ID + "' */ 
UNION ALL 
"
SET @SQL6 ="  

SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
AE.ADV_ID AS VCODE, AE.DOCNO AS INVOICENO, AE.VDATE AS INVOICEDATE,AE.AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,
LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,'' AS DUEDATE,
0 AS REC_AMOUNT , 0 AS PENDING_AMOUNT,
AE.PARTAMOUNT,AE.VDATE  AS RECDATE,'P' AS FLAG, AE.ENTRYTYPE AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
CONVERT(NVARCHAR(100),'') AS LRNO,CONVERT(NVARCHAR(4000),'') AS ITEMNAME,DATEDIFF(DAY,AE.VDATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @PREVDATABASE + "ADVANCE_ENTRY AE         
INNER JOIN " + @PREVDATABASE + "LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN " + @PREVDATABASE + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @PREVDATABASE + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN " + @PREVDATABASE + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN " + @PREVDATABASE +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
"+@SQLJOIN+"
WHERE AE.VDATE<='"+@ASONDATE+"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN(" + @CMP_CODE +")
/*  AND LM.LGR_ID = '" + @LGR_ID + "' */ "	

END
END /* END OF PREVIOUS YEAR CONDITION */
END /* END OF ONACCOUNT  CONDITION */
IF @ONACCOUNT=0
BEGIN
SET @SQL1 =""
SET @SQL2 =""
SET @SQL3 =""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""    
END

SET @SQL=""
SET @SQL="SELECT LM.LGR_NAME AS PARTYNAME,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,CM.CITY_NAME, ALM.LGR_NAME AS AGENTNAME,
PD.VCODE, PD.BILL_NO AS INVOICENO, PD.DATE AS INVOICEDATE,PD.BILL_AMOUNT AS INVOICEAMT,LM.LGR_DISTRICT AS DISTRICT,LM.CITY_PINCODE AS PINCODE,SM.STATE_NAME AS PARTYSTATE,
" + @SELSQL + "	
PD.REC_AMOUNT , PD.PENDING_AMOUNT, 0 AS PARTAMOUNT,CONVERT(NVARCHAR(20),'') AS RECDATE,'D' AS FLAG, 'AA' AS TRANTYPE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ALM.LGR_ID AS AGENTID,ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTOMERGROUP,ISNULL(CMP.CMP_ALIAS,'') AS ALIAS
,ISNULL(ALM.LGR_ADD1,'') AS AD_ADD1,ISNULL(ALM.LGR_ADD2,'') AS AD_ADD2,ISNULL(ALM.LGR_ADD3,'') AS AD_ADD3,
ISNULL(ALM.CITY_PINCODE,0) AS AG_PINCODE,ISNULL(ASM.STATE_NAME,'') AS AGENTSTATE,
ISNULL(LM.LGR_PHONE1,'') AS LGR_PHONE1,ISNULL(LM.LGR_PHONE2,'') AS LGR_PHONE2,ISNULL(LM.LGR_MOBILE,'') AS LGR_MOBILE,
ISNULL(PD.LRNO,'') AS LRNO,ISNULL(PD.ITEMNAME,'') AS ITEMNAME,DATEDIFF(DAY,PD.DATE,'"+@ASONDATE+"') AS OUTDAYS
FROM " + @DATABASENAME +"PARTYDETAIL PD
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
INNER JOIN " + @DATABASENAME +"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PD.CMP_CODE
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER ALM ON PD.AGENT_ID=ALM.LGR_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER ASM ON ALM.STATE_ID=ASM.STATE_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
"+@SQLJOIN+"
WHERE PD.CMP_CODE IN (" + @CMP_CODE + ") 
" +  @WHERESQL + "	
" + @ALLCONDSQL + "
/* AND PD.LGR_ID = '" + @LGR_ID + "' */ 
AND PD.PENDING_AMOUNT > 0  				
AND ISNULL(PAID,0) = 0
"


EXEC(@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6+@ORDERBYSQL)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @ORDERBYSQL
















GO

/****** Object:  StoredProcedure [dbo].[PROC_OUTSTANDINGSELECTION]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author:		HIREN DOSHI
-- Create_date: 29/06/2013
-- Description:	THIS PROCEDURE USED FOR OUTSTANDING SELECTION 
-- ReportName : OutStandingSelection.RPT	
-- =============================================
PROC_OUTSTANDINGSELECTION 1,'ACC2012_2013.DBO.',1,3,'##2060','01/APR/2012','31/MAR/2013',1,0,0,'',''''''
*/
CREATE PROCEDURE [dbo].[PROC_OUTSTANDINGSELECTION]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@RPT_TYPE INT,
	@TEMPTABLE NVARCHAR(20),
	@FROMDATE  NVARCHAR(20),
	@TODATE    NVARCHAR(20),
	@ONACCOUNT  INT,
	@CHKDEBITNOTE INT,
	@CHKINVAMT INT,
	@PREVDATABASE NVARCHAR(20),
	@TYPESQL NVARCHAR(20),
	@PREVONACCOUNT INT
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT1 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT2 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT3 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT4 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT5 AS NVARCHAR(4000)
DECLARE @CONDITION AS NVARCHAR(2000)
DECLARE @ALL AS NVARCHAR(50)
DECLARE @SQLSETTLED AS NVARCHAR(1000)
DECLARE @SQLRECAMT AS NVARCHAR(100)
DECLARE @SQLDEBIT AS NVARCHAR(4000)

SET @SQL = ""
SET @SQLJOIN = ""
SET @SQLONACCOUNT = ""
SET @SQLONACCOUNT1= ""
SET @SQLONACCOUNT2 = ""
SET @SQLONACCOUNT3= ""
SET @SQLONACCOUNT4 = ""
SET @SQLONACCOUNT5 = ""
SET @CONDITION  = ""
SET @ALL = ""
SET @SQLSETTLED = ""
SET @SQLRECAMT=""
SET @SQLDEBIT = ""
BEGIN
	IF @RPT_WISE = 1 /* ALL ACCOUNT */
		SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
	ELSE IF @RPT_WISE = 2 /* CUSTOMER GROUP */
		SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
	ELSE IF @RPT_WISE = 3 /* CITY WISE */
		SET @SQLJOIN ="INNER JOIN " + @TEMPTABLE + " TT ON TT.CODE=CM.CITY_ID"
	ELSE IF @RPT_WISE IN (4,5) /* AGENT,AGENT CITY */
		SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
END

BEGIN
	IF @CHKINVAMT = 1 /* DUE TOTAL INVOICE AMOUNT TRUE */
		SET @SQLRECAMT=" AND AM.ADJUSTAMT = 0"
	ELSE IF @CHKINVAMT = 0 /* DUE TOTAL INVOICE AMOUNT FALSE */
		SET @SQLRECAMT=""
END
BEGIN
	IF @CHKDEBITNOTE = 1 /* PRINT DEBIT NOTE :- TRUE */
	BEGIN	
		SET @SQLDEBIT = " UNION ALL
	SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME ,0 AS VCODE,
	'*' + CONVERT(NVARCHAR,DNM.DEBITNOTENO) AS BILL_NO,'' AS JOBFLAG,DNM.VCHDATE,DNM.BALAMT AS BILL_AMOUNT,
	0 AS REC_AMOUNT,DNM.VCHDATE AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,0 AS INTREC,'D' FLAG,'' AS CHEQUENO,
	DNM.VCHDATE AS CHEQUEDATE,0 AS PARTYAMOUNT,DNM.DEBITNOTE_ID AS TRAN_ID,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
	SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,'' AS TRAN_TYPE,
	0 AS TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,'' AS LRNO,'' AS LRDATE,'' AS REMARK,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,DATEDIFF(DAY,DNM.VCHDATE,GETDATE()) AS DAYS
	FROM " + @DATABASENAME + " DEBITNOTE_MASTER DNM
 INNER JOIN " + @DATABASENAME + " LEDGER_MASTER LM ON LM.LGR_ID=DNM.LGR_ID
 LEFT JOIN " + @DATABASENAME + " LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND DNM.CMP_CODE=LD.CMP_CODE
 LEFT JOIN " + @DATABASENAME + " LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
 LEFT JOIN " + @DATABASENAME + " CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
 LEFT JOIN " + @DATABASENAME + " SALESMAN_MASTER SM ON SM.SALESMAN_ID=ALM.SALESMAN_ID
 LEFT JOIN " + @DATABASENAME + " CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
 LEFT JOIN " + @DATABASENAME + " CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID      
 LEFT JOIN " + @DATABASENAME + " COMPANY_MASTER CMP ON CMP.CMP_CODE=DNM.CMP_CODE
" +  @SQLJOIN + "
WHERE DNM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND DNM.CMP_CODE IN(" + @CMP_CODE +")   "
	END
	ELSE IF @CHKDEBITNOTE = 0 /* PRINT DEBIT NOTE :- FALSE */
	BEGIN
		SET @SQLDEBIT = " "
	END
END
BEGIN
	IF @ONACCOUNT = 1 /* PRINT ON ACCOUNT TRUE */
		BEGIN
			 SET @SQLONACCOUNT ="
UNION ALL
SELECT SUBSTRING('"+@DATABASENAME+"',1,LEN('"+@DATABASENAME+"')-5) AS DATABASENAME,0 AS VCODE,TM.TRAN_DOCNO AS  BILL_NO,'' AS JOBFLAG,TM.TRAN_DATE  AS DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
 (CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
  (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT,
  TD.TRAN_ID,
  LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SM.SALESMAN_NAME AS SALESMAN,CM.CITY_NAME AS  CITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,TD.TRAN_TYPE,TD.TRAN_AMOUNT,CMP.CMP_ALIAS AS ALIAS,
  '' AS LRNO,'' AS LRDATE,'' AS REMARK,ISNULL(ACM.CITY_NAME,'') AS AGENTCITTY,0 AS DAYS
  FROM " + @DATABASENAME + "TRAN_DETAIL TD 
INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
