/*
-- =============================================
-- Author:		GAMI DIPAK
-- Create_date: 22-11-2014
-- Description:	THIS PROCEDURE IS USED TO CONTRACTOR PROCESS RATE REPORT  IN PROCESS TO PROCESS
PROC_P2PWITHCONREPORT '1','ACC2013_2014.DBO.',10,'01/APR/2013','30/APR/2014','##3348'

select * from ##3348
select * from tempdb..sysobjects where name like '##%'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_P2PDWITHCONREPORT]
	(
	@CMP_CODE NVARCHAR(100),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@FROMDATE NVARCHAR(20),
	@TODATE NVARCHAR(20),
	@TEMPTABLE NVARCHAR(20)
	)
AS
DECLARE @STRSQL NVARCHAR(4000)
DECLARE @STRJOIN NVARCHAR(500)
DECLARE @STRORDER  NVARCHAR(500)
SET @STRJOIN=""
SET @STRSQL=""
SET @STRORDER=""


BEGIN 
BEGIN
IF @RPT_WISE in(1,11,12,13,14,15,16) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CONM.CONTRACTOR_ID"
END
IF @RPT_WISE in(2,17,18,19,20,21,22) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=FLM.LGR_ID"
END
IF @RPT_WISE in(3,23,24,25,26,27,28)
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TLM.LGR_ID"
END
IF @RPT_WISE in(4,29,30,31,32,33,34 )
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=FPM.PROCESS_ID"
END
IF @RPT_WISE in (5,35,36,37,38,39,40) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TPM.PROCESS_ID"
END
IF @RPT_WISE =6 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=MCM.MACHINE_ID"
END
IF @RPT_WISE =7 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LRM.LORIWALA_ID"
END
IF @RPT_WISE in(8,41,42,43,44,45,46) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=BNM.BUNCHNAME_ID"
END
IF @RPT_WISE in (9,47,48,49,50,51,52)
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LTM.LOT_ID"
END
IF @RPT_WISE =10 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2PD.BUNCHNO"
END
IF @RPT_WISE =53 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2P.DOCNO"
END
IF @RPT_WISE =54 
BEGIN
SET @STRORDER="  P2P.VCHDATE,P2P.DOCNO "
END
END
SET @STRORDER="  P2P.VCHDATE,P2P.DOCNO "
BEGIN
SET @STRSQL="SELECT P2P.DOCNO,P2P.VCHDATE,LRNO,LOTNO,DSM.DESIGN_NAME AS DESIGNNO,BNM.BUNCHNAME,LTM.LOT_NAME,BUNCHNO,FPM.PROCESS_NAME AS FROMPROCESS,TPM.PROCESS_NAME AS TOPROCESS,
FLM.LGR_NAME AS FROMPARTY,TLM.LGR_NAME AS TOPARTY,MCM.MACHINE_NAME,CONM.CONTRACTOR_NAME,LRM.LORIWALA_NAME,ISSUETHAN AS ITHAN,ISSUEMETER AS IMETER,CON_RATE,CON_AMOUNT
FROM "+@DATABASENAME+"PROCESS2PROCESS P2P 
INNER JOIN "+@DATABASENAME+"PROCESS2PROCESS_DETAIL P2PD ON P2P.PROCESSID=P2PD.PROCESSID AND P2P.CMP_CODE=P2PD.CMP_CODE
AND P2P.FLAG=P2PD.FLAG
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER FPM ON FPM.PROCESS_ID=P2P.FROM_PROCESS_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER TPM ON TPM.PROCESS_ID=P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER FLM ON FLM.LGR_ID=P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER TLM ON TLM.LGR_ID =P2P.TO_LGR_ID
LEFT JOIN "+@DATABASENAME+"MACHINE_MASTER MCM ON MCM.MACHINE_ID=P2P.MACHINE_ID
LEFT JOIN "+@DATABASENAME+"CONTRACTOR_MASTER  CONM ON CONM.CONTRACTOR_ID =P2P.CONTRACTOR_ID
LEFT JOIN "+@DATABASENAME+"LORIWALA_MASTER LRM ON LRM.LORIWALA_ID=P2P.LORIWALA_ID
INNER JOIN "+@DATABASENAME+"BUNCHNAME_MASTER BNM ON BNM.BUNCHNAME_ID=P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LTM ON LTM.LOT_ID=P2PD.LOT_ID
LEFT JOIN "+@DATABASENAME+"DESIGN_MASTER DSM ON DSM.Design_Id=P2PD.DESIGN_ID
"+@STRJOIN+"
WHERE P2P.FLAG='P2PD' AND P2P.CMP_CODE IN("+@CMP_CODE+")  AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'"	
END
END
 execute Sp_Executesql @STRSQL
        Print @STRSQL




















GO

