/*
-- =============================================
-- ALTER_AUTHOR  :	<PRATIK>
-- ALTER_DATE    : <08/09/2016>
-- REPORT_FORM	  :	<rfrmPrintingDocRpt.cs>
-- CRYSTAL_REPORT : <P2PLOTWISE_PRINT_OUT.RPT
 PROC_P2PLOTWISE_PRINT 1,'ACC2016_2017.DBO.','1','10'
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_P2PLOTWISE_PRINT] 

(
@CMP_CODE NVARCHAR(5),
@DATABASENAME NVARCHAR(100),
@FROMDOCNO NVARCHAR(10),
@TODOCNO NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL = ""
	

BEGIN
SET NOCOUNT ON;
SET @SQL = "
SELECT P2P.PROCESSID,P2P.DOCNO,P2P.VCHDATE,PM.PROCESS_NAME AS TOPROCESS,
LM.LGR_NAME AS TOPARTY,CM.CONTRACTOR_NAME AS CONTRACTOR,MM.MACHINE_NAME AS MACHINE ,
LO.LORIWALA_NAME AS LORIWALA,P2P.REMARK,P2P.INOUT_TYPE,P2P.SHIFT,LOTNO,LRNO,BM.BUNCHNAME,
LOT.LOT_NAME AS MARKA,ISSUETHAN,ISSUEMETER,THAN,METER,
FPM.PROCESS_NAME AS FROM_PROCESS,FLM.LGR_NAME AS FROM_PARTY
FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+"PROCESS2PROCESS_DETAIL P2PD ON P2PD.PROCESSID=P2P.PROCESSID AND P2PD.FLAG=P2P.FLAG 
			AND P2PD.LO_FLAG=P2P.LO_FLAG /*AND P2PD.ENTRYTYPE=P2P.ENTRYTYPE*/
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID	
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID	
INNER JOIN "+@DATABASENAME+"CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID=P2P.CONTRACTOR_ID	
INNER JOIN "+@DATABASENAME+"MACHINE_MASTER MM ON MM.MACHINE_ID=P2P.MACHINE_ID
LEFT JOIN "+@DATABASENAME+"LORIWALA_MASTER LO ON LO.LORIWALA_ID=P2P.LORIWALA_ID			
INNER JOIN "+@DATABASENAME+"BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID=P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOT ON LOT.LOT_ID=P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER FPM ON FPM.PROCESS_ID=P2P.From_Process_Id	
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER FLM ON FLM.LGR_ID=P2P.FROM_LGR_ID
WHERE P2P.DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+" AND P2P.CMP_CODE="+@CMP_CODE+" AND P2P.FLAG='P2P'
ORDER BY CONVERT(INT,P2P.DOCNO)
"
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL
























GO

