SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LTM.LOT_ID"
SET @STRORDERBY="ORDER BY LTM.LOT_NAME,LTM.LOT_ID,TPM.PROCESS_NAME,TPM.PROCESS_ID,"
END
ELSE IF @RPT_WISE IN (52)
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LTM.LOT_ID"
SET @STRORDERBY="ORDER BY LTM.LOT_NAME,LTM.LOT_ID,BNM.BUNCHNAME,BNM.BUNCHNAME_ID,"
END
ELSE IF @RPT_WISE =53 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2P.DOCNO"
SET @STRORDERBY="ORDER BY "
END
ELSE IF @RPT_WISE IN(56) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CTM.CLOTH_TYPE_ID"
SET @STRORDERBY="ORDER BY CTM.CLOTH_TYPE_NAME,CTM.CLOTH_TYPE_ID,"
END
ELSE IF @RPT_WISE IN(57) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CTM.CLOTH_TYPE_ID"
SET @STRORDERBY="ORDER BY CTM.CLOTH_TYPE_NAME,CTM.CLOTH_TYPE_ID,CONM.CONTRACTOR_NAME,CONM.CONTRACTOR_ID,"
