END
ELSE IF @RPT_WISE IN (60) 
BEGIN
SET @STRJOIN =" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LRM.LORIWALA_ID"
SET @STRORDERBY="ORDER BY LRM.LORIWALA_NAME,LRM.LORIWALA_ID,CTM.CLOTH_TYPE_NAME,CTM.CLOTH_TYPE_ID,"
END
ELSE IF @RPT_WISE =54 
BEGIN
SET @STRORDER="  P2P.VCHDATE,P2P.DOCNO "
SET @STRORDERBY="ORDER BY "
END
END



IF @FLAG = 1
BEGIN
SET @STRSQL="SELECT P2P.DOCNO,P2P.VCHDATE,P2PD.LRNO,P2PD.LOTNO,DSM.DESIGN_NAME AS DESIGNNO,BNM.BUNCHNAME,
LTM.LOT_NAME,P2PD.BUNCHNO,FPM.PROCESS_NAME AS FROMPROCESS,TPM.PROCESS_NAME AS TOPROCESS,
FLM.LGR_NAME AS FROMPARTY,TLM.LGR_NAME AS TOPARTY,MCM.MACHINE_NAME,CONM.CONTRACTOR_NAME,
LRM.LORIWALA_NAME,ISSUETHAN AS ITHAN,ISSUEMETER AS IMETER,CON_RATE,CON_AMOUNT,
(CASE WHEN P2P.FLAG = 'P2P' THEN 'LOT' END ) AS FLAG,
(CASE WHEN P2P.FLAG = 'P2P' THEN P2PD.LOTNO END) AS LOTNO_BUNCHNO,
(CASE WHEN P2P.FLAG = 'P2P' THEN P2PD.LRNO END) AS LRNO_DESIGNO,
ISNULL(CTM.CLOTH_TYPE_NAME,'') AS CLOTH_TYPE_NAME,
FPM.PROCESS_ID AS FROMPROCESS_ID,TPM.PROCESS_ID AS TOPROCESS_ID,FLM.LGR_ID AS FROMPARTY_ID,TLM.LGR_ID AS TOPARTY_ID,MCM.MACHINE_ID,CONM.CONTRACTOR_ID,
LRM.LORIWALA_ID,BNM.BUNCHNAME_ID, LTM.LOT_ID,DSM.DESIGN_ID,LTM.CLOTH_TYPE_ID

FROM "+@DATABASENAME+"PROCESS2PROCESS P2P 
INNER JOIN "+@DATABASENAME+"PROCESS2PROCESS_DETAIL P2PD ON P2P.PROCESSID=P2PD.PROCESSID 
AND P2P.CMP_CODE=P2PD.CMP_CODE AND P2P.FLAG=P2PD.FLAG
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER FPM ON FPM.PROCESS_ID=P2P.FROM_PROCESS_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER TPM ON TPM.PROCESS_ID=P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER FLM ON FLM.LGR_ID=P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER TLM ON TLM.LGR_ID =P2P.TO_LGR_ID
LEFT JOIN  "+@DATABASENAME+"MACHINE_MASTER MCM ON MCM.MACHINE_ID=P2P.MACHINE_ID
LEFT JOIN  "+@DATABASENAME+"CONTRACTOR_MASTER  CONM ON CONM.CONTRACTOR_ID =P2P.CONTRACTOR_ID
LEFT JOIN  "+@DATABASENAME+"LORIWALA_MASTER LRM ON LRM.LORIWALA_ID=P2P.LORIWALA_ID
INNER JOIN "+@DATABASENAME+"BUNCHNAME_MASTER BNM ON BNM.BUNCHNAME_ID=P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LTM ON LTM.LOT_ID=P2PD.LOT_ID
LEFT JOIN  "+@DATABASENAME+"DESIGN_MASTER DSM ON DSM.DESIGN_ID=P2PD.DESIGN_ID
LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON LTM.CLOTH_TYPE_ID=CTM.CLOTH_TYPE_ID
"+@STRJOIN+"
WHERE P2P.FLAG='P2P' AND P2P.CMP_CODE IN("+@CMP_CODE+")  
AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "	+ @STRORDERBY + " P2P.DOCNO"
END
ELSE IF @FLAG = 2
BEGIN
SET @STRSQL="SELECT P2P.DOCNO,P2P.VCHDATE,LRNO,P2PD.LOTNO,DSM.DESIGN_NAME AS DESIGNNO,BNM.BUNCHNAME,
