/*
-- =============================================
-- AUTHOR:		<AUTHOR,,NAME>
-- ALTER_DATE: 29/05/2012
-- DESCRIPTION:	PACKINGSLIPPRINTOUT
-- CRYSTAL : PACKINGSLIP_RUBIA_BALAJI_PREPRINT.RPT
-- =============================================
PROC_PACKINGALIP_RUBIA_PRINT N'1', N'Acc2018_2019.Dbo.', N'37884', N'37884', N''

*/
CREATE PROCEDURE [dbo].[PROC_PACKINGALIP_RUBIA_PRINT]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMBILLNO NVARCHAR(50),
@TOBILLNO NVARCHAR(50),
@TEMPTABLE NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @FIELDSQL AS NVARCHAR(4000)
SET @SQL=""
SET @JOINSQL=""
SET @FIELDSQL=""

IF @TEMPTABLE <> "" 

begin
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PS.CMP_CODE"
	SET @FIELDSQL = "TT.TYPE"
end	
ELSE
begin
	SET @FIELDSQL = "'' AS TYPE"
end

BEGIN	
	SET NOCOUNT ON;
SET @SQL ="
SELECT PS.PACKINGSLIPID,PS.BALENO,PS.VCH_DATE,PS.ORDERNO,PS.ORDER_DATE,
UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2
,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(SM.STATE_NAME) AS  PATYSTATE,LM.LGR_DISTRICT,ISNULL(LM.CITY_PINCODE,'') AS CITY_PINCODE
,UPPER(AGM.LGR_NAME) AS AGENTNAME,UPPER(ACM.CITY_NAME) AS AGENTCITY
,IM.ITEM_NAME AS ITEM,DM.DESIGN_NAME,PA.PCS as assortPcs,IM.ITEM_ID,SCM.SCREEN_NAME,PKM.PACKINGSTYLE_NAME,TM.TRANSPORT_NAME,
PD.TOTALPCS,PD.COLOR_CHART,PD.TOTAL AS QTY,PS.CONFNO,PS.CONF_DATE
,PDD.PCS AS DET_PCS,MTRS AS DET_MTR,CTM.CUT_NAME,UPPER(UM.UNIT_NAME)UNIT_NAME,PSCM.CITY_NAME AS STATIONNAME,PD.TOTAL AS METER,TOTALPCS AS PCS,
PKM.PACKINGSTYLE_NAME AS PACKINGSTYLENAME,PS.COLOURS,ISNULL(PD.ITEM_CUT,0) AS ITEM_CUT,ISNULL(PD.REMARK,0) AS REMARK,PDD.SRNO,
 ISNULL(PS.NARRATION,'') AS NARRATION,PS.EXP_LCNO,"+@FIELDSQL+"
FROM "+@DATABASENAME+" PACKINGSLIP PS
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PD ON PS.PACKINGSLIPID=PD.PACKINGSLIPID 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAILDETAIL PDD ON PDD.PACKINGSLIPID=PS.PACKINGSLIPID AND PDD.ITEM_ID=PD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"PACKINGSLIP_ASSORTMENT PA ON PA.PACKINGSLIPID=PS.PACKINGSLIPID AND PA.ITEM_ID=PD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"DESIGN_MASTER DM ON DM.DESIGN_ID=PA.DESIGN_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=PS.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PSCM ON PSCM.CITY_ID=PS.STATION_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PD.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID=PD.SCREEN_ID
LEFT JOIN "+@DATABASENAME+"CUT_MASTER CTM ON CTM.CUT_ID=PD.CUT_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"PACKINGSTYLE_MASTER PKM ON PKM.PACKINGSTYLE_ID=PD.PACKINGSTYLE_ID
"+@JOINSQL+"
WHERE PS.CMP_CODE="+@CMP_CODE+"
AND PS.FORMFLAG IN ('WC')
AND PS.BALENO BETWEEN '"+@FROMBILLNO+"' AND '"+@TOBILLNO+"'
ORDER BY PS.PACKINGSLIPID,TYPE,PDD.SRNO
" 
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL 


















GO

