LEFT JOIN "+@DATABASENAME+" CITY_MASTER PSCM ON PSCM.CITY_ID=PS.STATION_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=PD.ITEM_ID
LEFT JOIN  "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SCM ON SCM.SCREEN_ID=PD.SCREEN_ID
LEFT JOIN "+@DATABASENAME+" CUT_MASTER CTM ON CTM.CUT_ID=PD.CUT_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+" PACKINGSTYLE_MASTER PKM ON PKM.PACKINGSTYLE_ID=PD.PACKINGSTYLE_ID
"+@JOINSQL+"
WHERE PS.CMP_CODE="+@CMP_CODE+"
AND PS.FORMFLAG IN ('WC')
AND PS.BALENO BETWEEN '"+@FROMBILLNO+"' AND '"+@TOBILLNO+"'
ORDER BY PS.PACKINGSLIPID,TYPE,PDD.SRNO
" 
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL 
























GO

