CREATE PROCEDURE [dbo].[PROC_PACKINGSLIP_MARUDHARPREPRINTED]
(
	@Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
	@FromBaleNo nvarchar(10),
	@ToBaleNo nvarchar(10)
 )
AS
Declare @Sql1 As nvarchar(4000)
BEGIN
	SET NOCOUNT ON;
set @Sql1=" Select PS.PackingSlipId,PS.BaleNo,PS.Vch_date,PS.Lgr_Id,PLM.LGR_NAME AS PARTY,CM.CITY_NAME AS PARTY_CITY,
				PS.Agent_Id,ALM.Lgr_Name As AGENT,ACM.City_Name As AgentCity,PS.Transport_Id,TM.TRANSPORT_NAME AS TRANSPORT,
				PS.Station_Id,SM.City_Name As Station,PS.OrderNo,PS.Order_Date,
				PLM.LGR_ADD1 AS PARTY_ADD1,PLM.LGR_ADD2 AS PARTY_ADD2,
				STATE.STATE_NAME AS PARTY_STATE,CMP.CMP_CITY AS COMPANYCITY,
				IM.ITEM_NAME,PSD.Item_Id,IM.Rate_Per,IOS.SAL_Rate AS ITEM_RATE,SCR.SCREEN_NAME,PSD.TOTALPCS,PSD.TOTAL As TotMtr,
				PSDD.MTRS As Cut,PSDD.PCS As DDPCS,PSDD.Total As DDTotal,BPM.BalePack_Name
			    From "+@DatabaseName+"PackingSlip PS INNER JOIN "+@DatabaseName+"PackingSlip_Detail PSD ON PS.PackingSlipId=PSD.PackingSlipId
				INNER JOIN "+@DatabaseName+"PackingSlip_DetailDetail PSDD ON PSD.PackingSlipId=PSDD.PackingSlipId And PS.PackingSlipId=PSDD.PackingSlipId And PSD.Item_Id=PSDD.Item_ID
				INNER JOIN "+@DatabaseName+"LEDGER_MASTER PLM ON PLM.LGR_ID=PS.LGR_ID
				INNER JOIN "+@DatabaseName+"LEDGER_MASTER ALM ON ALM.LGR_ID=PS.AGENT_ID
				INNER JOIN "+@DatabaseName+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
				INNER JOIN "+@DatabaseName+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
				INNER JOIN "+@DatabaseName+"Item_Master IM on IM.Item_ID=PSD.Item_ID
                INNER JOIN "+@DatabaseName+"SCREEN_Master SCR on SCR.SCREEN_ID=PSD.SCREEN_ID
				LEFT JOIN "+@DatabaseName+"CITY_MASTER SM ON SM.CITY_ID=PS.STATION_ID
				LEFT JOIN "+@DatabaseName+"CITY_MASTER CM ON CM.CITY_ID=PLM.CITY_ID
				LEFT JOIN "+@DatabaseName+"City_Master ACM ON ACM.CITY_ID=ALM.CITY_ID
				LEFT JOIN "+@DatabaseName+"STATE_MASTER STATE ON STATE.STATE_ID=PLM.STATE_ID 
                left JOIN "+@DatabaseName+"BalePack_MASTER BPM ON BPM.BalePack_ID=PS.BalePack_ID
                INNER JOIN "+@DatabaseName+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=PS.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
			Where PS.BaleNo between "+@FromBaleNo+" and "+@ToBaleNo+" And PS.cmp_code="+@Cmp_Code+"
			"	
END
EXECUTE SP_EXECUTESQL @SQL1
PRINT @SQL1




















GO

