              PARTY,PARTYCITY,TRANSPORT_NAME,STATION,DETAILROWNO,ITEM_ID,ITEM,PCS,MTRS,TOTAL,ROWNO,TP,DDSRNO,COLNO,ASSORT_PCS,ASS_SRNO,FLAG,Narration,SCREEN,SELF_PARTY,OTHER,BALECHECKER_NAME
