              ,'D' AS FLAG,PS.NARRATION,SM.SCREEN_NAME AS SCREEN,PS.SELF_PARTY,PS.OTHER,BCM.BALECHECKER_NAME ,PS.FOLDNO,PS.LOTNO,PS.LRNO,PS.D_COLNO
