                PDD.DESIGNNO AS COLNO,PDD.PCS AS ACCORT_PCS,PDD.SRNO AS ASS_SRNO,'A' AS FLAG,PS.NARRATION,SM.SCREEN_NAME AS SCREEN,PS.SELF_PARTY,PS.OTHER
               ,BCM.BALECHECKER_NAME ,NULL AS FOLDNO,NULL AS LOTNO,NULL AS LRNO,NULL AS D_COLNO
                FROM "+@DATABASENAME+"PACKINGSLIP PS
