SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/*
-- =============================================
-- Author:		GAMI DIPAK
-- Create_date: 07-11-2014
-- Description:	THIS REPORT IS USED IN PACKING SLIP DISPATCH REPORT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_PACKINGSLIPDISPATCHREG '1','ACC2014_2015.DBO.',4,'01/MAR/2014','31/MAR/2015','##3768',0
*/
CREATE PROCEDURE [dbo].[PROC_PACKINGSLIPDISPATCHREG]
(
	@CMP_CODE NVARCHAR(1000),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20), 
	@TEMPTABLE NVARCHAR(20),
	@RPT_DATE INT
) 
AS

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @DATECON NVARCHAR(150)
DECLARE @SQLORDER NVARCHAR(1000)
SET @STRSQL=""
SET @STRORDERBY=""
SET @SQLJOIN=""
SET @DATECON=""
SET @SQLORDER = ""
BEGIN
BEGIN
IF @RPT_WISE =1
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = ALM.LGR_ID "
SET @STRORDERBY=" ALM.LGR_NAME,AGENTID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =2
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID "
SET @STRORDERBY=" LM.LGR_NAME,PARTYID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =3
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IM.ITEM_ID "
SET @STRORDERBY=" IM.ITEM_NAME,ITEMID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =4
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = SM.SCREEN_ID"
SET @STRORDERBY=" SM.SCREEN_NAME,SCREENID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =5
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = ALM.LGR_ID"
SET @STRORDERBY=" ALM.LGR_NAME,AGENTID,LM.LGR_NAME,PARTYID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =6
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = ALM.LGR_ID"
SET @STRORDERBY=" ALM.LGR_NAME,AGENTID,IM.ITEM_NAME,ITEMID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =7
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID"
SET @STRORDERBY=" LM.LGR_NAME,PARTYID,ALM.LGR_NAME,AGENTID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =8
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID"
SET @STRORDERBY=" LM.LGR_NAME,PARTYID,IM.ITEM_NAME,ITEMID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =9
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IM.ITEM_ID"
SET @STRORDERBY=" IM.ITEM_NAME,ITEMID,LM.LGR_NAME,PARTYID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =10
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IM.ITEM_ID"
SET @STRORDERBY=" IM.ITEM_NAME,ITEMID,ALM.LGR_NAME,AGENTID,BALENO,PS.VCH_DATE"
END
ELSE IF @RPT_WISE =11
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =PSM.PACKINGSTYLE_ID"
SET @STRORDERBY=" PSM.PACKINGSTYLE_NAME,PACKINGSTYLEID,BALENO,PS.VCH_DATE"
END
ELSE
SET @STRORDERBY=" BALENO,PS.VCH_DATE"
END
--SET @SQLJOIN=""

BEGIN
IF @RPT_DATE =1 
BEGIN
SET @DATECON=" AND PS.VCH_DATE ='"+ @TODATE +"'"
END
ELSE
BEGIN
SET @DATECON=" AND PS.VCH_DATE  BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE +"'"
END

BEGIN
SET @STRSQL="SELECT PS.CONFNO,PS.CONF_DATE,PS.VCH_DATE,BALENO,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,
IM.ITEM_NAME,SM.SCREEN_NAME,PSD.ITEM_RATE,PSD.ITEM_CUT,PSM.PACKINGSTYLE_NAME,PSD.TOTAL AS METER,PSD.TOTALPCS AS PCS,CM.CMP_ALIAS,
ISNULL(PSD.REMARK,'') AS REMARK,ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(SM.SCREEN_ID,0) AS SCREENID,ISNULL(PSM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID
FROM "+@DATABASENAME+"PACKINGSLIP PS 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.CMP_CODE=PSD.CMP_CODE AND PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID =PS.LGR_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =PSD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID =PS.AGENT_ID
LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER  SM ON SM.SCREEN_ID=PSD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CM ON CM.CMP_CODE=PS.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"PACKINGSTYLE_MASTER PSM ON PSM.PACKINGSTYLE_ID=PSD.PACKINGSTYLE_ID
 "+ @SQLJOIN +"
WHERE PS.FORMFLAG='WC' "+@DATECON+"  AND PS.CMP_CODE IN ("+ @CMP_CODE +") 
ORDER BY "+@STRORDERBY+""
END

END
PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL

END





















GO

