/* 
-- =============================================
-- ALTER_AUTHOR   : <BIREN>
-- ALTER_DATE     : <22/10/2013,4:23>
-- EDIT_AUTHOR	   : <BIREN>
-- EDIT_DATE	   : <29/10/2013,5:00>
-- REPORT_NAME     : <PACKINGSLIPEMAIL.RPT>
-- REPORT_FORM     : <RFRMSALESINVOICEEMAIL.CS>
-- =============================================
PROC_PACKINGSLIPEMAIL '1','ACC2012_2013.DBO.','31/MAR/2013','31/MAR/2013',2,149,1,0,''
*/
CREATE PROCEDURE [dbo].[PROC_PACKINGSLIPEMAIL] 
(
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(50),
	@FROMDATE NVARCHAR(20),
	@TODATE NVARCHAR(20),
	@CRITERIA INT,
	@ACCID NVARCHAR(20),
	@RPTWISE INT,
	@BILL_WISE INT,
	@BALE_NO NVARCHAR(4000)
)	

AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @BALENOSQL AS NVARCHAR(4000)
DECLARE @RPTSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @BALENOSQL=""
SET @RPTSQL=""

BEGIN
	IF @RPTWISE = 1 
		BEGIN
			IF @BILL_WISE = 0 
				BEGIN		
					IF @CRITERIA = 1 
						BEGIN		
							SET @RPTSQL = " AND PS.LGR_ID = "+@ACCID
						END
					ELSE IF @CRITERIA = 2
						BEGIN
							SET @RPTSQL = " AND PS.AGENT_ID = "+@ACCID
						END
				END
			ELSE IF @BILL_WISE = 1
				BEGIN 
					SET @BALENOSQL = " WHERE BALENO IN ("+@BALE_NO+") "
				END
		END
END

BEGIN
	SET 
       @SQL="
             SELECT PACKINGSLIPID,SERIALNO,BALENO,DATE,ORDERNO,ORDER_DATE,CONFNO,CONF_DATE,
              PARTY,PARTYCITY,TRANSPORT_NAME,STATION,DETAILROWNO,ITEM_ID,ITEM,PCS,MTRS,TOTAL,ROWNO,TP,DDSRNO,COLNO,ASSORT_PCS,ASS_SRNO,FLAG,NARRATION,SCREEN,SELF_PARTY,OTHER,BALECHECKER_NAME,USERNAME
              FROM(
              SELECT PS.PACKINGSLIPID,PS.SERIALNO, PS.BALENO,PS.VCH_DATE AS DATE,PS.ORDERNO,PS.ORDER_DATE,PS.CONFNO,PS.CONF_DATE,
              LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,TM.TRANSPORT_NAME,SCM.CITY_NAME AS STATION,
              PSD.DETAILROWNO,PSD.ITEM_ID,IM.ITEM_NAME AS ITEM,PSDD.PCS,PSDD.MTRS,PSDD.TOTAL,PSDD.ROWNO,PSDD.TP,PSDD.SRNO AS DDSRNO,0 AS COLNO,0 AS  ASSORT_PCS,0 AS ASS_SRNO
              ,'D' AS FLAG,PS.NARRATION,SM.SCREEN_NAME AS SCREEN,PS.SELF_PARTY,PS.OTHER,BCM.BALECHECKER_NAME,UPPER(DBO.FN_DECRYPTSTRING(USERNAME))USERNAME
              FROM "+@DATABASENAME+"PACKINGSLIP PS
              INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PSD.PACKINGSLIPID=PS.PACKINGSLIPID
              INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAILDETAIL PSDD ON PSDD.PACKINGSLIPID=PS.PACKINGSLIPID AND PSDD.ROWNO=PSD.DETAILROWNO
              INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
              INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
              LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
              LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=PS.STATION_ID              
              LEFT JOIN "+@DATABASENAME+"BALECHECKER_MASTER BCM ON BCM.BALECHECKER_ID=PS.BALECHECKER_ID             
			  INNER JOIN USERMASTER US ON US.USERID=PS.USERID
			  WHERE PS.CMP_CODE IN ("+@CMP_CODE+") AND PS.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
			  "+@RPTSQL+""
              
              
SET @SQL1="
UNION ALL
             SELECT PS.PACKINGSLIPID,PS.SERIALNO, PS.BALENO,PS.VCH_DATE AS DATE,PS.ORDERNO,PS.ORDER_DATE,PS.CONFNO,PS.CONF_DATE,
                LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,TM.TRANSPORT_NAME,SCM.CITY_NAME AS STATION,
                PSD.DETAILROWNO,PSD.ITEM_ID,IM.ITEM_NAME AS ITEM,0 AS PCS,0 AS MTRS,0 AS TOTAL,0 AS ROWNO,0 AS TP,0 AS DDSRNO,
                PA.COLNO,PA.PCS AS ACCORT_PCS,PA.SRNO AS ASS_SRNO,'A' AS FLAG,PS.NARRATION,SM.SCREEN_NAME AS SCREEN,PS.SELF_PARTY,PS.OTHER
               ,BCM.BALECHECKER_NAME,UPPER(DBO.FN_DECRYPTSTRING(USERNAME))USERNAME
                FROM "+@DATABASENAME+"PACKINGSLIP PS
                INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PSD.PACKINGSLIPID=PS.PACKINGSLIPID
                INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
                INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
                INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
                INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=PS.STATION_ID              
                LEFT JOIN "+@DATABASENAME+"PACKINGSLIP_ASSORTMENT PA ON PS.PACKINGSLIPID=PA.PACKINGSLIPID AND PA.ROWNO=PSD.DETAILROWNO
                LEFT JOIN "+@DATABASENAME+"BALECHECKER_MASTER BCM ON BCM.BALECHECKER_ID=PS.BALECHECKER_ID             
				INNER JOIN USERMASTER US ON US.USERID=PS.USERID
                WHERE PS.CMP_CODE IN ("+@CMP_CODE+") AND PS.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
				"+@RPTSQL+"
                ) AS DETAIL "
SET @SQL2	=	""+@BALENOSQL+" ORDER BY BALENO,ITEM,DETAILROWNO,FLAG DESC,DDSRNO"
END
EXEC ( @SQL+ @SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

