/*
-- =============================================
-- Author         : <Biren>
-- Create_date    : <03/11/2012,5:50 PM,>
-- Crystal_Report : <PACKINGSLIPREG_RUBIA>
-- Report_Form    : <rfrmPackingSlipReg>
-- =============================================
select * from tempdb..sysobjects where name like '##%'
PROC_PACKINGSLIPREG_RUBIA '1','Acc2014_2015.Dbo.','01/Apr/2014', N'01/Mar/2015','##4636',1,3
*/
CREATE PROCEDURE [dbo].[PROC_PACKINGSLIPREG_RUBIA]
(
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50), 	
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @TempTable nvarchar(20),
    @RptWise int,
	@RptType int
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @SQLCON AS NVARCHAR(1000)
DECLARE @SQLORDER AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @SQLCON = ""
SET @SQLORDER = ""

BEGIN 
	IF @RptWise = 1 /* PARTY */
		 BEGIN
		  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"
		  SET @SQLORDER = " PARTY,PARTYID,"
		 END 
		 ELSE IF @RptWise = 6 /* PARTY - ITEM  */
		 BEGIN
		  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"
		  SET @SQLORDER = " PARTY,PARTYID,ITEM,ITEMID,"
		 END
		  ELSE IF @RptWise = 8 /* PARTY - SCREEN  */
		 BEGIN
		  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON LM.LGR_ID=TT.CODE"
		  SET @SQLORDER = " PARTY,PARTYID,SCREEN,SCREENID,"
		 END 
	ELSE IF @RptWise = 2 /* AGENT */
		 BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.AGENT_ID=TT.CODE"
		   SET @SQLORDER = " AGENT,AGENTID,"
		 END 
		 ELSE IF @RptWise = 7 /* AGENT - ITEM */
		 BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.AGENT_ID=TT.CODE"
		   SET @SQLORDER = " AGENT,AGENTID,ITEM,ITEMID,"
		 END 
		 ELSE IF @RptWise = 9 /* AGENT - SCREEN */
		 BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.AGENT_ID=TT.CODE"
		   SET @SQLORDER = " AGENT,AGENTID,SCREEN,SCREENID,"
		 END 
		  ELSE IF @RptWise = 10 /* ALL */
		 BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.AGENT_ID=TT.CODE"
		 END 
	ELSE IF @RptWise = 3 /* ITEM */
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PSD.ITEM_ID=TT.CODE"
		   SET @SQLORDER = " ITEM,ITEMID,"
		END 
	ELSE IF @RptWise = 4 /* SCREEN */
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PSD.SCREEN_ID=TT.CODE"
		   SET @SQLORDER = " SCREEN,SCREENID,"
		END 
	ELSE IF @RptWise = (5) /* TRANSPORT */
		BEGIN
		   SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.TRANSPORT_ID=TT.CODE"
		   SET @SQLORDER = " TRANSPORT,TRANSPORTID,"
		END 
	ELSE IF @RptWise = (11)
		BEGIN
		   SET @JOINSQL=" "
		END 
	ELSE IF @RptWise = (12)
		BEGIN
			SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PS.CONFNO=TT.CODE"
		END 
	ELSE IF @RptWise = 13
		BEGIN
			SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PACKM.PACKINGSTYLE_ID=TT.CODE"
		END 
		ELSE IF @RptWise = 14 /* PACKINGSTYLE - CUT - ITEM */
		BEGIN
			SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PACKM.PACKINGSTYLE_ID=TT.CODE"
			SET @SQLORDER = " PACKSTYLE,PACKINGSTYLEID,ITEMCUT,ITEM,ITEMID,"
		END 
		ELSE IF @RptWise = 15 /* PACKINGSTYLE - ITEM - CUT */
		BEGIN
			SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PACKM.PACKINGSTYLE_ID=TT.CODE"
			SET @SQLORDER = " PACKSTYLE,PACKINGSTYLEID,ITEM,ITEMID,ITEMCUT"
		END 
	BEGIN
		IF @RptType = 1 /* PAID */
			SET @SQLCON = " AND PS.INUSE = 1 "
		ELSE IF @RptType = 2 /* PENDING */
			SET @SQLCON = " AND (PS.INUSE = 0 OR PS.INUSE IS NULL) "
		ELSE
			SET @SQLCON = "  "
		END
		
	END
BEGIN	
SET @SQL="
		SELECT PS.PACKINGSLIPID AS ID,PS.BALENO AS BALENO,ISNULL(PS.CONFNO,0) AS DOCNO,PS.ORDERNO AS ORDERNO,LM.LGR_NAME AS PARTY,CIM.CITY_NAME AS PARTYCITY,PS.VCH_DATE AS DATE,ALM.LGR_NAME AGENT,IM.ITEM_NAME ITEM,SC.SCREEN_NAME AS SCREEN,
		TM.TRANSPORT_NAME AS TRANSPORT,PACKM.PACKINGSTYLE_NAME AS PACKSTYLE,
		PSD.COLOR_CHART,PSD.TOTAL AS QTY,PSD.TOTALPCS AS PCS,PSD.ITEM_CUT AS ITEMCUT,
		COMP.CMP_ALIAS,PSD.ITEM_RATE,PS.CONFNO,ISNULL(STM.CITY_NAME,'') AS DESTINATION,
		ISNULL(NARRATION,'') AS NARRATION,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
		ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(SC.SCREEN_ID,0) AS SCREENID,
		ISNULL(PACKM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID
		FROM "+ @DatabaseName+ "PACKINGSLIP PS
		INNER JOIN "+ @DatabaseName+ "PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID AND PS.CMP_CODE=PS.CMP_CODE
		INNER JOIN "+ @DatabaseName+ "LEDGER_MASTER LM ON PS.LGR_ID=LM.LGR_ID		
		INNER JOIN "+ @DatabaseName+ "LEDGER_MASTER ALM ON ALM.LGR_ID=PS.AGENT_ID	
		INNER JOIN "+ @DatabaseName+ "ITEM_MASTER IM ON PSD.ITEM_ID=IM.ITEM_ID
		INNER JOIN "+ @DatabaseName+ "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
		LEFT JOIN "+ @DatabaseName+ "SCREEN_MASTER SC ON SC.SCREEN_ID=PSD.SCREEN_ID
		INNER JOIN "+ @DatabaseName+ "COMPANY_MASTER COMP ON COMP.CMP_CODE=PS.CMP_CODE
		
		LEFT JOIN  "+ @DatabaseName+ "PACKINGSTYLE_MASTER PACKM ON PACKM.PACKINGSTYLE_ID=PSD.PACKINGSTYLE_ID
		LEFT JOIN "+ @DatabaseName+ " CITY_MASTER CIM ON LM.CITY_ID = CIM.CITY_ID
		LEFT JOIN "+ @DatabaseName+ " CITY_MASTER STM ON PS.STATION_ID = STM.CITY_ID
	    " + @JOINSQL +"
		WHERE PS.FORMFLAG IN('WC') AND PS.Cmp_Code IN("+ @Cmp_Code +") and  PS.VCH_DATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
		" +@SQLCON+"
		ORDER BY "+@SQLORDER+" CONVERT(INT,PS.BALENO),PS.VCH_DATE,PSD.DETAILROWNO "      
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL





















GO

