/* 
PROC_PACKINGSLPPROG '2','acc2010_2011.dbo.','01/apr/2010','31/mar/2011','##336',0
*/
CREATE PROCEDURE [dbo].[PROC_PACKINGSLPPROG]
(
  @cmp_Code as nvarchar(20),
  @DatabaseName as nvarchar(100),
  @FromDate as nvarchar(20),
  @ToDate as nvarchar(20),
  @TempTable	as nvarchar(100),
  @Detail_Summary as int
)
AS
Declare @Sql as Nvarchar(4000)
Declare @SqlJOIN as Nvarchar(4000)
set @Sql=""                
SET @SqlJOIN=""
SET @SqlJOIN=" INNER JOIN "+ @TempTable + " TT ON TT.CODE=TM.TRANSPORT_ID"
BEGIN	
	SET NOCOUNT ON;
    if @Detail_Summary=1 
        begin 
              set @Sql=" SELECT PS.BALENO,PS.VCH_DATE AS BALEDATE,ST.CITY_NAME AS STATION,TM.TRANSPORT_NAME AS TRANSPORT,0 AS TOTALBALE
                         FROM "+ @DatabaseName + "PACKINGSLIP PS
                         INNER JOIN CITY_MASTER ST ON ST.CITY_ID=PS.STATION_ID 
                         INNER JOIN  "+ @DatabaseName + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
                         LEFT JOIN  "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=PS.STATION_ID 
                         "+  @SQLJOIN + "
                         WHERE PS.CMP_CODE="+@cmp_Code + "  AND PS.VCH_DATE BETWEEN '"+ @FromDate +"' AND '"+ @ToDate +"'        
                         ORDER BY TM.TRANSPORT_NAME"
        end
     if @Detail_Summary=0
        begin 
              set @Sql=" SELECT MIN(PS.BALENO) AS BALENO,MIN(PS.VCH_DATE) AS BALEDATE,ST.CITY_NAME AS STATION,TM.TRANSPORT_NAME AS TRANSPORT,COUNT(PS.BALENO) AS TOTALBALE
                         FROM "+ @DatabaseName + "PACKINGSLIP PS
                         INNER JOIN CITY_MASTER ST ON ST.CITY_ID=PS.STATION_ID 
                         INNER JOIN  "+ @DatabaseName + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID                         
                         "+  @SQLJOIN + "
                         WHERE PS.CMP_CODE="+@cmp_Code + "  AND PS.VCH_DATE BETWEEN '"+ @FromDate +"' AND '"+ @ToDate +"'        
                         GROUP BY ST.CITY_NAME,TM.TRANSPORT_NAME
                         ORDER BY TM.TRANSPORT_NAME"
        end
	exec sp_executesql @Sql
    print @Sql
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTY_STOCK_REPORT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_PARTY_STOCK_REPORT 10,'Acc2010_2011.dbo.','01/apr/2010','31/Mar/2011',##4060,1,1
*/
CREATE PROCEDURE [dbo].[PROC_PARTY_STOCK_REPORT]
(
@Cmp_Code nvarchar(50),
@DatabaseName nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TEMPTABLE nvarchar(50),
@Temp nvarchar(50),
@RPT_WISE int,
@RPT_TYPE int
)
AS
DECLARE @STRSQL as nvarchar(4000) SET @STRSQL=""
DECLARE @STRSQL1 as nvarchar(4000) SET @STRSQL1=""
DECLARE @STRSQL2 as nvarchar(4000) SET @STRSQL2=""
DECLARE @SQLJOIN as nvarchar(4000) SET @SQLJOIN=""
DECLARE @SQLSUMM as nvarchar(4000) SET @SQLSUMM=""
DECLARE @SQLGROP as nvarchar(4000) SET @SQLGROP=""
DECLARE @SUBJOIN as nvarchar(4000) SET @SUBJOIN=""

BEGIN
if @RPT_WISE=1 /* PARTY WISE */
	SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=LM.LGR_ID "
ELSE IF @RPT_WISE=2 /* ITEM WISE */
	--SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=LM.LGR_ID "
	  SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=IM.ITEM_ID "
if @RPT_WISE=3 /* PARTY ITEM WISE */
	BEGIN
	SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=IM.Item_ID "
	SET @SUBJOIN=" INNER JOIN "+@Temp+" TT1 on TT1.Code=LM.LGR_Id "
	END
ELSE IF @RPT_WISE=4 /* ITEM PARTY WISE */
	BEGIN
	SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE+" TT on TT.CODE=LM.LGR_ID "
	SET @SUBJOIN=" INNER JOIN "+@Temp+" TT1 on TT1.Code=IM.ITEM_ID"	
	END
END


BEGIN	
	SET NOCOUNT ON;
SET @STRSQL=" 
select 0 as DocNo,'"+@FromDate+"' as Date,POS.Lgr_Id,LM.Lgr_Name,IM.Item_Name,Um.Unit_Name,sum(POD.METER) as IssueMtr,
sum(POD.PCS) as IssuePcs,0 as RecMtr,0 as RecPcs,'OP' as FType
from "+@DatabaseName+"  PartyOpStock POS
inner join "+@DatabaseName+"  PartyOpStockDetail POD on POS.PartyOpStk_Id=POD.PartyOpStk_Id
inner join "+@DatabaseName+"  Ledger_master LM on POS.Lgr_Id=LM.Lgr_Id
inner join "+@DatabaseName+"  Item_Master IM On POD.Item_Id=IM.Item_Id
left join "+@DatabaseName+"  Unit_Master UM on POD.unit_Id=Um.Unit_Id
"+@SQLJOIN+"
"+@SUBJOIN+"
where  POS.Cmp_COde in ("+@Cmp_Code+")
group by POS.lgr_Id,Lgr_Name,Item_Name,Unit_Name
union all 
select JI.DocNo,JI.VchDate as Date,JI.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name,Mtr as IssueMtr,
PCS as IssuePcs,0 as RecMtr,0 as RecPcs,'ISSUE' as FType
from "+@DatabaseName+" JobIssue  JI
inner join "+@DatabaseName+" JobIssueDetail JD on JD.JobIssue_Id = JI.JobIssue_Id
inner join "+@DatabaseName+" Ledger_master LM on JI.Lgr_Id=LM.Lgr_Id
inner join "+@DatabaseName+" Item_Master IM On JD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Unit_Master UM on JD.unit_Id=Um.Unit_Id
"+@SQLJOIN+"
"+@SUBJOIN+"
where JI.Cmp_COde in ("+@Cmp_Code+") and JI.VchDate between '"+@FromDate+"' and '"+@ToDate+"'
union all "
set @STRSQL1=" select 0 as DocNo,'01/apr/2010' as Date,JI.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name,sum(Mtr) as IssueMtr,
sum(PCS) as IssuePcs,0 as RecMtr,0 as RecPcs,'OP' as FType
from "+@DatabaseName+" JobIssue  JI
inner join "+@DatabaseName+" JobIssueDetail JD on JD.JobIssue_Id = JI.JobIssue_Id
inner join "+@DatabaseName+" Ledger_master LM on JI.Lgr_Id=LM.Lgr_Id
inner join "+@DatabaseName+" Item_Master IM On JD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Unit_Master UM on JD.unit_Id=Um.Unit_Id
"+@SQLJOIN+"
"+@SUBJOIN+"
where JI.Cmp_COde in ("+@Cmp_Code+") and JI.VchDate < '"+@FromDate+"'
group by JI.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name
union all 
select JR.DocNo,JR.VchDate as Date,LM.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name,0 as IssueMtr,
0 as IssuePcs,Mtr as RecMtr,PCS as RecPcs,'RECEIPT' as FType
from "+@DatabaseName+" JobReceipt JR
inner join "+@DatabaseName+" JobReceiptDetailDetail JDD on Jr.JobReceipt_Id=JDD.JobReceipt_Id
inner join "+@DatabaseName+" Ledger_master LM on JR.Lgr_Id=LM.Lgr_Id
inner join "+@DatabaseName+" Item_Master IM On JDD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Unit_Master UM on JDD.unit_Id=Um.Unit_Id
"+@SQLJOIN+"
"+@SUBJOIN+"
where JR.Cmp_COde in ("+@Cmp_Code+") and JR.VchDate between '"+@FromDate+"' and '"+@ToDate+"'
union all "
set @STRSQL2="select 0 as DocNo,'01/apr/2010' as Date,LM.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name,0 as IssueMtr,
0 as IssuePcs,sum(MTR) as RecMtr,sum(PCS) as RecPcs,'OP' as FType
from "+@DatabaseName+" JobReceipt JR
inner join "+@DatabaseName+" JobReceiptDetailDetail JDD on Jr.JobReceipt_Id=JDD.JobReceipt_Id
inner join "+@DatabaseName+" Ledger_master LM on JR.Lgr_Id=LM.Lgr_Id
inner join "+@DatabaseName+" Item_Master IM On JDD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Unit_Master UM on JDD.unit_Id=Um.Unit_Id
"+@SQLJOIN+"
"+@SUBJOIN+"
where JR.Cmp_COde in ("+@Cmp_Code+") and JR.VchDate < '"+@FromDate+"'
group by LM.Lgr_Id,LM.Lgr_Name,IM.Item_Name,UM.Unit_Name

order by Lgr_Name,Item_Name,Date,DocNo
"    
END

print @STRSQL
print @STRSQL1
print @STRSQL2
EXEC (@STRSQL+@STRSQL1+@STRSQL2)




