/* 
EXEC PROC_PARTYBALANCE '01/AUG/2010','2,3,4,5,6,10','ACC2010_2011.DBO.','2',1
*/

CREATE PROCEDURE [dbo].[PROC_PARTYBALANCE]
(
@ASONDATE NVARCHAR(20),
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE NVARCHAR(10),
@GRP_ID NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SELECTED AS NVARCHAR(3000)
DECLARE @COND AS NVARCHAR(3000)
DECLARE @GRP AS NVARCHAR(3000)
DECLARE @CITYCOND AS NVARCHAR(3000)
DECLARE @STATECOND AS NVARCHAR(3000)
DECLARE @AGENTCOND AS NVARCHAR(3000)
DECLARE @GROUPCOND AS NVARCHAR(1000)
DECLARE @GROUPSQL AS NVARCHAR(1000)

SET @SELECTED=""
SET @COND=""
SET @GRP=""
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @CITYCOND=""
SET @STATECOND=""
SET @AGENTCOND=""
SET @GROUPCOND=""
SET @GROUPSQL=""
BEGIN
IF @RPT_WISE='2'
SET @GROUPSQL=" INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL  ALD ON ALD.LGR_ID=ALM.LGR_ID  AND ALD.CMP_CODE IN("+@CMP_CODE+")
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=ALD.GRP_ID  "

ELSE
SET @GROUPSQL=" INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID AND LD.CMP_CODE IN("+@CMP_CODE+") "

END

BEGIN
SET NOCOUNT ON;
IF @RPT_WISE ='1'    /*  PARTY WISE */
BEGIN
SET @SELECTED= " SELECT TOP 10 PARTYNAME AS NAME,MAINAMOUNT FROM (SELECT PARTYNAME,SUM(MAINAMOUNT) AS MAINAMOUNT FROM ("
SET @COND= " AND PARTYNAME IS NOT NULL "
SET @GRP= " ) AS MAIN GROUP BY PARTYNAME,PARTYID ) AS DTL ORDER BY MAINAMOUNT  DESC "
SET @AGENTCOND = " LEFT JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON LD.AGENT_ID=ALM.LGR_ID "
SET @CITYCOND = " LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID "
SET @STATECOND = " LEFT JOIN "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID "
SET @GROUPCOND=" AND GM.GRP_ID="+@GRP_ID
END     
IF @RPT_WISE ='2'    /*  AGENT WISE*/
BEGIN
SET @SELECTED= " SELECT TOP 10 AGENTNAME AS NAME,MAINAMOUNT FROM (SELECT AGENTNAME,SUM(MAINAMOUNT) AS MAINAMOUNT FROM ("
SET @COND= " AND AGENTNAME IS NOT NULL "
SET @GRP= " ) AS MAIN GROUP BY AGENTNAME,AGENTID ) AS DTL ORDER BY MAINAMOUNT  DESC "
SET @AGENTCOND = " INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON LD.AGENT_ID=ALM.LGR_ID "
SET @CITYCOND = " LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID "
SET @STATECOND = " LEFT JOIN "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID "
SET @GROUPCOND=" AND GM.GRP_ID="+@GRP_ID
END     
IF @RPT_WISE ='3'     /*  CITY WISE */
BEGIN
SET @SELECTED= " SELECT TOP 10 CITY AS NAME,MAINAMOUNT FROM (SELECT CITY,SUM(MAINAMOUNT) AS MAINAMOUNT FROM ("
SET @COND= " AND CITY IS NOT NULL "
SET @GRP= " ) AS MAIN GROUP BY CITY,CITYID ) AS DTL ORDER BY MAINAMOUNT  DESC "		 
SET @AGENTCOND = " LEFT JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON LD.AGENT_ID=ALM.LGR_ID "
SET @CITYCOND = " INNER JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID "
SET @STATECOND = " LEFT JOIN "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID "
END      
IF @RPT_WISE ='4'     /*  STATE WISE */
BEGIN
SET @SELECTED= " SELECT TOP 10 STATE AS NAME,MAINAMOUNT FROM (SELECT STATE,SUM(MAINAMOUNT) AS MAINAMOUNT FROM ("
SET @COND= " AND STATE IS NOT NULL "
SET @GRP= " ) AS MAIN GROUP BY STATE,STATEID ) AS DTL ORDER BY MAINAMOUNT  DESC "		 		
SET @AGENTCOND = " LEFT JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON LD.AGENT_ID=ALM.LGR_ID "
SET @CITYCOND = " INNER JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID "
SET @STATECOND = " INNER JOIN "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID "
END      

BEGIN

SELECT  @SQL1=
@SELECTED + " 
SELECT GROUPNAME,PARTYNAME,AGENTNAME,CITY,STATE ,(DRAMOUNT-ABS(CRAMOUNT))  AS MAINAMOUNT,PARTYID,AGENTID,CITYID,STATEID 
FROM(
SELECT GROUPNAME,PARTYNAME,AGENTNAME,CITY,STATE,CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))>0 THEN  (SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END AS DRAMOUNT ,CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))<0 THEN  (SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END AS CRAMOUNT
,PARTYID,AGENTID,CITYID,STATEID FROM(
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,CM.CITY_NAME AS CITY,SM.STATE_NAME AS STATE,CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT, CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT 
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(CM.CITY_ID,0) AS CITYID,ISNULL(SM.STATE_ID,0) AS STATEID
FROM "+ @DATABASENAME + "LEDGER_DETAIL LD
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID                 
" + @CITYCOND + "
" + @STATECOND + "
" + @AGENTCOND + "
"+ @GROUPSQL +"
WHERE LD.CMP_CODE IN (" + @CMP_CODE  +") "+@GROUPCOND+"

UNION ALL  "

SELECT  @SQL2=	"		SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,CM.CITY_NAME AS CITY,SM.STATE_NAME AS STATE,(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(CM.CITY_ID,0) AS CITYID,ISNULL(SM.STATE_ID,0) AS STATEID
FROM "+ @DATABASENAME + "TRAN_MASTER TM  
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE

" + @CITYCOND + "
" + @STATECOND + "
" + @AGENTCOND + "
"+ @GROUPSQL +"
WHERE TM.CMP_CODE IN (" + @CMP_CODE  +")  AND TM.TRAN_TYPE NOT IN ('J','DN','DN') AND TM.TRAN_DATE<='"+  @ASONDATE +"'  
"+@GROUPCOND+"
UNION ALL 

SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,CM.CITY_NAME AS CITY,SM.STATE_NAME AS STATE,(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(CM.CITY_ID,0) AS CITYID,ISNULL(SM.STATE_ID,0) AS STATEID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE

" + @CITYCOND + "
" + @STATECOND + "			   
" + @AGENTCOND + "
"+ @GROUPSQL +"
WHERE TM.CMP_CODE IN (" + @CMP_CODE  +") AND TM.TRAN_TYPE NOT IN('J','DN','CN') AND  TM.TRAN_DATE<='"+  @ASONDATE +"'  
"+@GROUPCOND+"
UNION ALL "

SELECT  @SQL3="
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,CM.CITY_NAME AS CITY,SM.STATE_NAME AS STATE,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT 
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(CM.CITY_ID,0) AS CITYID,ISNULL(SM.STATE_ID,0) AS STATEID
FROM "+ @DATABASENAME + "AUTOJOURNAL AJ 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH = AJ.ENTRYMATCH
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE			 
" + @CITYCOND + "
" + @STATECOND + "			   
" + @AGENTCOND + "
"+ @GROUPSQL +"
WHERE AJ.VDATE<='"+  @ASONDATE +"'   AND AJ.CMP_CODE IN (" + @CMP_CODE  +")
"+@GROUPCOND+"
UNION ALL 

SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,CM.CITY_NAME AS CITY,SM.STATE_NAME AS STATE,(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, (CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(CM.CITY_ID,0) AS CITYID,ISNULL(SM.STATE_ID,0) AS STATEID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 			  
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE

" + @CITYCOND + "
" + @STATECOND + "
" + @AGENTCOND + "	
"+ @GROUPSQL +"		   
WHERE TM.CMP_CODE IN (" + @CMP_CODE  +") AND TM.TRAN_DATE<='"+  @ASONDATE +"'   AND TM.TRAN_TYPE  IN ('J','DN','CN') 
"+@GROUPCOND+"
) AS DETAIL  
GROUP BY GROUPNAME,PARTYNAME,AGENTNAME,CITY,STATE,PARTYID,AGENTID,CITYID,STATEID  )  AS B WHERE  CRAMOUNT -DRAMOUNT  <> 0  " + @COND + " " + @GRP  + "  " 

END   
END	
EXEC(@SQL+ @SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTYGSTINQUERY]    Script Date: 03/30/2023 12:08:13 ******/
