/* PROC_PARTYHISTORY '2','ACC2010_2011.DBO.','##2968' */
CREATE PROCEDURE [dbo].[PROC_PARTYHISTORY]
(
    @CMP_CODE AS NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),
    @TEMPTABLE NVARCHAR(20)
    
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM1.LGR_ID "


BEGIN
	SET @SQL=" SELECT PARTY,PARTYID,PARTYCITY,SUM(SAL_TRANS)AS SAL_TRANS,SUM(PUR_TRANS) AS PUR_TRANS,CMP_CODE
               ,CMP_ALIAS ,SUM(ISNULL(OPENINGBAL,0)) AS OPENINGBAL,MAX(OPDRCR) AS OPDRCR,SUM(CLBAL)AS CLBAL,MAX(CL_DRCR)AS CL_DRCR
               FROM (
               SELECT PARTY,PARTYID,PARTYCITY,SUM(SAL_TRANS)AS SAL_TRANS,SUM(PUR_TRANS) AS PUR_TRANS,DETAIL.CMP_CODE
               ,CMP_ALIAS ,MAX(ISNULL(LD.LGR_OP_BAL,0)) AS OPENINGBAL,MIN(LD.LGR_OP_DRCR) AS OPDRCR,0 AS CLBAL,'' AS CL_DRCR
               FROM (
               SELECT LM1.LGR_NAME AS PARTY,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,ISNULL(SAL_INV_NETTOTAL,0) AS SAL_TRANS,0 AS PUR_TRANS,CMP.CMP_ALIAS,CMP.CMP_CODE
               FROM  "+@DATABASENAME+"SALES_INVOICE SI
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=SI.LGR_ID
		       LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
               INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
               "+@JOINSQL+"
               WHERE SI.CMP_CODE IN ("+@CMP_CODE +")               
               UNION ALL
               SELECT LM1.LGR_NAME AS PARTY,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,0 AS SAL_TRANS ,ISNULL(NETTOTAL,0) AS PUR_TRANS,CMP.CMP_ALIAS,CMP.CMP_CODE
               FROM  "+@DATABASENAME+"PURCHASEINVOICE PI
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.LGR_ID
			   LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
               INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
               "+@JOINSQL+"
               WHERE PI.CMP_CODE IN ("+@CMP_CODE +")                       
               ) AS DETAIL 
              INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.CMP_CODE=DETAIL.CMP_CODE AND LD.LGR_ID=DETAIL.PARTYID 
              GROUP BY PARTY,PARTYCITY,PARTYID,DETAIL.CMP_CODE,DETAIL.CMP_ALIAS,LD.LGR_OP_BAL
             "

   SET @SQL1=" UNION ALL
              SELECT PARTYNAME,PARTYID,PARTYCITY,0 AS SAL_TRANS,0 AS PUR_TRANS,CMP_CODE,CMP_ALIAS,0 AS OPENINGBAL,''AS OPDRCR,ABS(SUM(DEBITAMOUNT)-SUM(CREDITAMOUNT)) AS CLBAL,(CASE WHEN (SUM(DEBITAMOUNT)-SUM(CREDITAMOUNT))>=0 THEN 'DR' ELSE 'CR' END) AS CL_DRCR  FROM (
              SELECT LM1.LGR_NAME AS PARTYNAME,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY ,CASE WHEN TM.TRAN_DRCR = 'D' THEN TM.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT,  
              CASE WHEN TM.TRAN_DRCR = 'C' THEN TM.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT,CMP.CMP_CODE,CMP.CMP_ALIAS
              FROM "+@DATABASENAME+"TRAN_MASTER TM   
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=TM.TRAN_MASTER_ID 
              LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
              "+@JOINSQL+"
              WHERE  TM.CMP_CODE IN ("+@CMP_CODE +")  AND TM.TRAN_TYPE <> 'J'  
           UNION ALL   
              SELECT LM1.LGR_NAME AS PARTYNAME,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY ,CASE WHEN TD.TRAN_DRCR = 'D' THEN TD.TRAN_AMOUNT ELSE 0 END AS DEBITAMOUNT, 
              CASE WHEN TD.TRAN_DRCR = 'C' THEN TD.TRAN_AMOUNT ELSE 0 END AS CREDITAMOUNT  ,CMP.CMP_CODE,CMP.CMP_ALIAS
              FROM "+@DATABASENAME+"TRAN_DETAIL TD   
              INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TD.TRAN_ID = TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE 
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=TD.TRAN_DETAIL_ID 
              LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
              "+@JOINSQL+"
              WHERE  TD.CMP_CODE IN ("+@CMP_CODE +")  
           UNION ALL   "
SET @SQL2="   SELECT LM1.LGR_NAME AS PARTYNAME,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY ,ISNULL(AJ.DRAMOUNT,0) AS DEBITAMOUNT,
             ISNULL(AJ.CRAMOUNT,0) AS CREDITAMOUNT  ,CMP.CMP_CODE,CMP.CMP_ALIAS
              FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=AJ.LGR_ID 
              LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AJ.CMP_CODE
             "+@JOINSQL+" 
              WHERE AJ.CMP_CODE IN ("+@CMP_CODE +")  
           UNION ALL   
              SELECT LM1.LGR_NAME AS PARTYNAME,LM1.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY ,
              CASE WHEN LGR_OP_DRCR = 'D' THEN LGR_OP_BAL WHEN LGR_OP_DRCR = '' THEN LGR_OP_BAL ELSE 0 END AS DEBITAMOUNT,
              CASE WHEN LGR_OP_DRCR = 'C' THEN LGR_OP_BAL WHEN LGR_OP_DRCR = '' THEN LGR_OP_BAL ELSE 0 END AS CREDITAMOUNT  
              ,CMP.CMP_CODE,CMP.CMP_ALIAS
              FROM "+@DATABASENAME+"LEDGER_DETAIL LD  
              INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=LD.LGR_ID
              LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM1.CITY_ID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LD.CMP_CODE
              "+@JOINSQL+"
              WHERE LD.CMP_CODE IN ("+@CMP_CODE +")    
              ) AS DETAIL
              GROUP BY PARTYNAME,PARTYID,PARTYCITY,CMP_CODE,CMP_ALIAS
            ) AS MAIN
            GROUP BY PARTY,PARTYID,PARTYCITY,CMP_CODE
            ,CMP_ALIAS   ORDER BY PARTY,PARTYID,CMP_CODE
"

END
EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTYHISTORY_ACCOUNT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_PARTYHISTORY_ACCOUNT '2','ACC2010_2011.DBO.','##2956'
*/
CREATE PROCEDURE [dbo].[PROC_PARTYHISTORY_ACCOUNT]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@TEMPTABLE NVARCHAR(20)
)

AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @JOINSQL=""
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM1.LGR_ID"
BEGIN

SET @SQL="  SELECT DETAIL.PARTYNAME,DETAIL.PARTYID,PCM.CITY_NAME AS PARTYCITY, SUM(DETAIL.DRAMOUNT)AS DRAMOUNT, SUM(DETAIL.CRAMOUNT)AS CRAMOUNT, DETAIL.ACCOUNTNAME,DETAIL.CMP_CODE,CMP.CMP_ALIAS,ACCID
FROM(  
SELECT  LM1.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
LM.LGR_NAME AS ACCOUNTNAME,TM.CMP_CODE,LM.LGR_ID AS ACCID
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID   
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID  
"+@JOINSQL+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +")   AND TM.TRAN_TYPE <> 'J' 
UNION ALL  
SELECT  LM1.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT, 
LM.LGR_NAME AS ACCOUNTNAME,TM.CMP_CODE,LM.LGR_ID AS ACCID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID= LM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
"+@JOINSQL+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +")  AND TM.TRAN_TYPE<> 'J'  
UNION ALL   "
SET @SQL1="
SELECT LM1.LGR_NAME,LM1.LGR_ID AS PARTYID,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,LM.LGR_NAME AS ACCOUNTNAME,AJ.CMP_CODE ,LM.LGR_ID AS ACCID
FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON AJ.LGR_ID = LM1.LGR_ID  
INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH= AJ.ENTRYMATCH 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ1.LGR_ID= LM.LGR_ID  
"+@JOINSQL+"
WHERE AJ.CMP_CODE IN ("+@CMP_CODE +")  
UNION ALL 
SELECT LM1.LGR_NAME AS PARTYNAME,TD.TRAN_DETAIL_ID AS PARTYID,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT,
(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
LM.LGR_NAME AS ACCOUNTNAME,TM.CMP_CODE,LM.LGR_ID AS ACCID
FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON JD.TRAN_DETAIL_ID = LM.LGR_ID  
"+@JOINSQL+"
WHERE TM.CMP_CODE IN ("+@CMP_CODE +")   AND TM.TRAN_TYPE  IN ('J','DN','CN') 
) AS DETAIL 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=DETAIL.PARTYID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=DETAIL.CMP_CODE

GROUP BY PARTYNAME,PARTYID,ACCOUNTNAME,ACCID,PCM.CITY_NAME,DETAIL.CMP_CODE,CMP.CMP_ALIAS
ORDER BY PARTYNAME,PARTYID,ACCOUNTNAME,ACCID,PCM.CITY_NAME,DETAIL.CMP_CODE,CMP.CMP_ALIAS
"


END


EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTYHISTORYOFITEM]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
PROC_PARTYHISTORYOFITEM '2','ACC2010_2011.DBO.','##2956'
*/
CREATE PROCEDURE [dbo].[PROC_PARTYHISTORYOFITEM]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@TEMPTABLE NVARCHAR(20)
)


AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
SET @JOINSQL=""
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID "

SET @SQL=""
BEGIN
SET @SQL="SELECT PARTY,PARTYID,PARTYCITY,ITEM,SUM(SALESQTY)AS SALESQTY,SUM(PURCHASEQTY)AS PURCHASEQTY ,CMP_CODE,CMP_ALIAS,ITEMID
FROM(
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,LM.LGR_ID AS PARTYID,IM.ITEM_NAME AS ITEM,SID.SAL_INV_QTY AS SALESQTY,0 AS PURCHASEQTY,CMP.CMP_CODE,CMP.CMP_ALIAS,IM.ITEM_ID AS ITEMID
FROM  "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL  SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL+"
WHERE SI.CMP_CODE IN ("+@CMP_CODE +")
UNION ALL
SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS CITY,LM.LGR_ID AS PARTYID,IM.ITEM_NAME AS ITEM,0 AS SALESQTY ,PID.QUANTITY AS SALESQTY,CMP.CMP_CODE,CMP.CMP_ALIAS,IM.ITEM_ID AS ITEMID
FROM  "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL  PID ON PI.PURCHASEINVID=PI.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE
"+@JOINSQL+"
WHERE PI.CMP_CODE IN ("+@CMP_CODE +")
) AS DETAIL GROUP BY ITEM,ITEMID,PARTY,PARTYID,PARTYCITY,CMP_CODE,CMP_ALIAS 
ORDER BY ITEM,ITEMID,PARTY,PARTYID,PARTYCITY,CMP_CODE,CMP_ALIAS 
"

END

EXECUTE SP_EXECUTESQL  @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTYHISTORYOFPARTY]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_PARTYHISTORYOFPARTY]
@PartyID nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="
Select Ledger_Master.Lgr_name  as PartyName,
( case when Tran_Master.Tran_DrCr = 'D'  then  Tran_Detail.Tran_Amount else 0   end )as Debitamount,
(case when Tran_Master.Tran_DrCr = 'C' then Tran_Detail.Tran_Amount else 0 end ) as Creditamount  
From "+@DatabaseName+"Tran_Master 
Inner Join  "+@DatabaseName+"Tran_Detail ON Tran_Master.Tran_Id = Tran_Detail.Tran_Id   AND Tran_Master.Tran_type = Tran_Detail.Tran_type   AND Tran_Master.CMP_CODE=Tran_Detail.CMP_CODE
Inner Join "+@DatabaseName+"Ledger_Master   ON Tran_Detail.Tran_Detail_Id = Ledger_Master.lgr_ID  
Where Tran_Master.cmp_Code =  "+@Cmp_Code+" And Tran_Master.Tran_type Not In ('J','CN','DN')   
And Tran_Master.Tran_Master_Id = "+@PartyID+"

Union All  

Select Ledger_Master.Lgr_name  as PartyName, 
(case when Tran_Detail.Tran_DrCr = 'D' then Tran_Detail.Tran_Amount else 0 end ) as Debitamount, 
(case when Tran_Detail.Tran_DrCr = 'C' then Tran_Detail.Tran_Amount else 0 end ) as Creditamount  
From "+@DatabaseName+"Tran_Master 
INNER JOIN "+@DatabaseName+"Tran_Detail ON Tran_Master.Tran_Id = Tran_Detail.Tran_Id  AND Tran_Master.Tran_Type = Tran_Detail.Tran_Type AND Tran_Master.CMP_CODE=Tran_Detail.CMP_CODE
INNER JOIN "+@DatabaseName+"Ledger_Master   ON Tran_Master.Tran_Master_Id = Ledger_Master.lgr_ID  
Where Tran_Master.cmp_Code =  "+@Cmp_Code+" And Tran_Master.Tran_type Not In ('J','CN','DN')  
And Tran_Detail.Tran_Detail_Id = "+@PartyID+"

--Union All  
--
--Select Ledger_Master.Lgr_name  as PartyName,  JobInvoiceMaster.Total as DebitAmount,0 as CreditAmount  
--From "+@DatabaseName+"Ledger_Master,"+@DatabaseName+"JobInvoiceMaster  
--Where JobInvoiceMaster.lgr_ID = "+@PartyID+" And Ledger_Master.lgr_ID = JobInvoiceMaster.Effectlgr_ID  And JobInvoiceMaster.cmp_Code = "+@Cmp_Code+"
--Union All  
--
--Select Ledger_Master.Lgr_name  as PartyName,  0 as DebitAmount,JobInvoiceMaster.Total as CreditAmount   
--From "+@DatabaseName+"Ledger_Master,"+@DatabaseName+"JobInvoiceMaster  
--Where JobInvoiceMaster.Effectlgr_ID = "+@PartyID+"
--And Ledger_Master.lgr_ID = JobInvoiceMaster.lgr_ID  
--And JobInvoiceMaster.cmp_Code = "+@Cmp_Code+"

Union All  

Select Ledger_Master.Lgr_name  as PartyName,  
AutoJournal.DrAmount As DebitAmount,AutoJournal.CrAmount As CreditAmount 
From "+@DatabaseName+"AutoJournal,"+@DatabaseName+"Ledger_Master,"+@DatabaseName+"AutoJournal As A  
Where AutoJournal.lgr_ID = "+@PartyID+" And AutoJournal.cmp_Code = A.cmp_Code 
And AutoJournal.EntryCode = A.EntryCode And AutoJournal.EntryType = A.EntryType 
And A.lgr_ID = Ledger_Master.lgr_ID  And AutoJournal.cmp_Code = "+@Cmp_Code+"
And A.lgr_ID <> AutoJournal.lgr_ID And A.VCode = AutoJournal.VCode 
And A.EntryType = AutoJournal.EntryType 

Union All  

Select 'J.V.', 
(case when Tran_Detail.Tran_DrCr = 'D' then Tran_Detail.Tran_Amount else 0 end) AS Debitamount, 
(case when Tran_Detail.Tran_DrCr='C' then Tran_Detail.Tran_Amount else 0 end ) AS Creditamount  
From "+@DatabaseName+"Tran_Master
INNER JOIN  "+@DatabaseName+"Tran_Detail  ON  Tran_Detail.Tran_Id = Tran_Master.Tran_Id  and Tran_Detail.Tran_Type = Tran_Master.Tran_Type   AND Tran_Master.CMP_CODE=Tran_Detail.CMP_CODE
Where 
Tran_Detail.Tran_Detail_Id = "+@PartyID+"   
And Tran_Master.cmp_Code = "+@Cmp_Code+"  
And Tran_Master.Tran_type  In ('J','CN','DN') 
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PARTYLIST]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO























/*
MODIFIED BY: SHUBHAM RAVAL 
DATE  : 21/06/2016
CHANEG : TRANSPORT NAME AND CURIRIER NAME >> ADDED

 PROC_PARTYLIST N'1', N'Acc2015_2016.Dbo.', N'##5536', 0, 0, 0
 
 PROC_PARTYLIST N'1', N'Acc2015_2016.Dbo.', '', 0, 0, 0
*/
CREATE PROCEDURE [dbo].[PROC_PARTYLIST]
(
    @CMP_CODE NVARCHAR(10),
    @DATABASENAME NVARCHAR(50),
    @TEMPTABLE NVARCHAR(20),
	@CRITERIA INT,
	@RPT_TYPE INT,
	@RPT_OPTIONS INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @SQLSI NVARCHAR(1000)
DECLARE @STRCOND NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(4000)

SET @JOINSQL=""
SET @TYPESQL=""
SET @SQLSI = ""
SET @STRCOND=""
SET @ORDERSQL = ""

IF @CRITERIA=0
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LD.AGENT_ID"
SET @ORDERSQL = "ORDER BY ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=1
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.CITY_ID"
SET @ORDERSQL = "ORDER BY PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=2
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.STATE_ID"
SET @ORDERSQL = "ORDER BY STM.STATE_NAME,ISNULL(STM.STATE_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=3
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.SALESMAN_ID"
SET @ORDERSQL = "ORDER BY SLM.SALESMAN_NAME,ISNULL(SLM.SALESMAN_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=4
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=GM.GRP_ID"
SET @ORDERSQL = "ORDER BY GRP_NAME,ISNULL(GM.GRP_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=5
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CTM.CATEGORY_ID"
SET @ORDERSQL = "ORDER BY CTM.CATEGORY_NAME,ISNULL(CTM.CATEGORY_ID,0),LM.LGR_NAME,LM.LGR_ID "
END

ELSE IF @CRITERIA=6
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
SET @ORDERSQL = "ORDER BY LM.LGR_NAME,LM.LGR_ID "
END

IF @RPT_TYPE=0
	SET @STRCOND=" AND ISNULL(LM.LGR_MOBILE,'')>'' AND LM.LGR_MOBILE>'0' "
ELSE IF @RPT_TYPE=1
	SET @STRCOND=" AND ISNULL(CONVERT(NVARCHAR,LM.LGR_MOBILE),'')='' OR LM.LGR_MOBILE='0'"
ELSE IF @RPT_TYPE=2
	SET @STRCOND=" AND ISNULL(LM.LGR_EMAIL,'')<>'' "
ELSE IF @RPT_TYPE=3
	SET @STRCOND=" AND ISNULL(LM.LGR_EMAIL,'')=''"
ELSE IF @RPT_TYPE=4
	SET @STRCOND=" "

IF @RPT_OPTIONS = 1 /* SALES INVOICE */
	SET @SQLSI = " INNER JOIN "+@DATABASENAME+"  SALES_INVOICE SI ON SI.LGR_ID=LM.LGR_ID AND SI.CMP_CODE = LD.CMP_CODE " 
BEGIN
	SET NOCOUNT ON;
SET @SQL="
SELECT DISTINCT LM.LGR_ID,LM.LGR_NAME AS PARTYNAME,LM.CITY_ID,PCM.CITY_NAME AS PARTYCITY,
LD.AGENT_ID,ALM.LGR_NAME AS AGENTNAME,LM.STATE_ID,STM.STATE_NAME,LM.LGR_MOBILE,
LM.SALESMAN_ID,SLM.SALESMAN_NAME,GRP_NAME AS ACCGROUP,CTM.CATEGORY_NAME,
LM.LGR_PHONE1 AS PHONE1,LM.LGR_PHONE2 AS PHONE2,LM.LGR_EMAIL,TM.Transport_Name,LD.Transport_Id,CUM.CourierMaster_Name,LM.CourierMaster_Id,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(PCM.CITY_ID,0) AS CITYID,ISNULL(STM.STATE_ID,0) AS STATEID,
ISNULL(SLM.SALESMAN_ID,0) AS SALESMANID,ISNULL(GM.GRP_ID,0) AS MAIN_GRPID,
ISNULL(CTM.CATEGORY_ID,0) AS CATEGORYID

FROM "+@DATABASENAME+" LEDGER_MASTER LM 
INNER JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER ALM ON LD.AGENT_ID=ALM.LGR_ID
LEFT JOIN  "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN  "+@DATABASENAME+" COURIER_MASTER CUM ON LM.CourierMaster_Id=CUM.CourierMaster_Id
LEFT JOIN  "+@DATABASENAME+" STATE_MASTER STM ON LM.STATE_ID=STM.STATE_ID
LEFT JOIN  "+@DATABASENAME+" SALESMAN_MASTER SLM ON LM.SALESMAN_ID=SLM.SALESMAN_ID
LEFT JOIN  "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.Transport_Id=LD.Transport_Id
LEFT JOIN  "+@DATABASENAME+" GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN  "+@DATABASENAME+" CATEGORY_MASTER CTM ON LM.CATEGORY_ID=CTM.CATEGORY_ID	
"+@SQLSI+"
"+ @JOINSQL +"
WHERE LD.CMP_CODE ="+@CMP_CODE+" 
"+@STRCOND+" "+@ORDERSQL+"
"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

