/* 
PROC_PARTYLOTISSUERECREG '10','ACC2010_2011.DBO.','0','##596',1,'01/APR/2010','01/APR/2011'
*/
CREATE PROCEDURE [dbo].[PROC_PARTYLOTISSUERECREG]
(
  @CMP_CODE NVARCHAR(50),
  @DATABASENAME  NVARCHAR(50),   
  @PROCESSID NVARCHAR(50),
  @TEMPTABLE  NVARCHAR(50),
  @RPT_WISE INT,
  @FROMDATE   NVARCHAR(20),
  @TODATE   NVARCHAR(20)  
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @PROCESSSQL AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @PROCESSSQL =""


BEGIN
    IF @RPT_WISE=1
        BEGIN
             SET @JOINSQL="INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
        END


IF @PROCESSID!="0"
   BEGIN
        SET @PROCESSSQL =" AND PM.PROCESS_ID="+@PROCESSID
   END

END


BEGIN
	
	SET @SQL="
               SELECT  P2P.LOTNO,P2P.VCHDATE ,PM.PROCESS_NAME AS PROCESS,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,IM.ITEM_NAME AS ITEM
               ,P2P.GPASSNO,P2P.DELTHAN,P2P.DELMETER
                ,ISNULL(PO.VCHDATE,F2F.VCHDATE) AS RECDATE
               ,ISNULL(PO.FROM_GPASSNO,F2F.GPASSNO) AS FROM_GPASSNO
                ,CMP.CMP_ALIAS,P2P.TO_PROCESS_ID
               ,ISNULL(PO.PARTYGPASSNO,F2F.PartyGPassNo) AS PARTYGPASSNO,P2P.TO_LGR_ID,DETAIL.BILLNO
               FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID
               INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID
               LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
               INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
               LEFT JOIN "+@DATABASENAME+"PROCESS2PROCESS PO ON PO.LOTNO=P2P.LOTNO AND PO.CMP_CODE=P2P.CMP_CODE AND P2P.GPASSNO=PO.FROM_GPASSNO  AND P2P.TO_LGR_ID=PO.FROM_LGR_ID
               LEFT JOIN (
               SELECT DISTINCT BILLNO,CMP_CODE,LGR_ID,LOTNO,PROCESSID FROM(
	           SELECT PI.BILLNO ,PI.CMP_CODE , PI.LGR_ID,PID.LOTNO,P2P.TO_PROCESS_ID AS PROCESSID
	           FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
	           INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PID.LOTNO=P2P.LOTNO AND PID.CMP_CODE=P2P.CMP_CODE
	           INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG AND PI.LGR_ID=P2P.TO_LGR_ID AND PI.PROCESS_ID=P2P.TO_PROCESS_ID
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
               "+ @JOINSQL+" 
	           WHERE P2P.CMP_CODE IN("+@CMP_CODE +") ) AS DETAIL
                     ) 
              DETAIL ON DETAIL.CMP_CODE=P2P.CMP_CODE AND DETAIL.LOTNO=P2P.LOTNO AND DETAIL.LGR_ID=P2P.TO_LGR_ID AND P2P.TO_PROCESS_ID=DETAIL.PROCESSID
              LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
              LEFT JOIN "+@DATABASENAME+"FINISHTOFOLDING F2F  ON F2F.CMP_CODE=P2P.CMP_CODE AND F2F.LOTNO=P2P.LOTNO AND F2F.GPASSNO=P2P.GPASSNO
              "+ @JOINSQL+" 
              WHERE P2P.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"' AND P2P.CMP_CODE IN("+@CMP_CODE +")
               "+@PROCESSSQL+ " 
              ORDER BY P2P.LOTNO,P2P.VCHDATE,PO.VCHDATE,GPASSNO



	"    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PAYMENT_NOTE_PRINT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


























/*
=============================================
AUTHOR         : <BIREN>
ALTER_DATE    : 16/01/2013,3:30
REPORT_FORM    : BANK_PAYMENT,CASH_PAYMENT
CRYSTAL_REPORT : PAYMENT_NOTE_PRINT
=============================================
PROC_PAYMENT_NOTE_PRINT 1,'ACC2012_2013.DBO.','1','10000',1
*/
CREATE PROCEDURE [dbo].[PROC_PAYMENT_NOTE_PRINT]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@FROMDOCNO NVARCHAR(50),
	@TODOCNO NVARCHAR(50),
	@RPT_TYPE NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @TYPESQL AS NVARCHAR(4000)
DECLARE @SQLADJJOIN AS NVARCHAR(1000)
SET @SQL=""
SET @TYPESQL=""
SET @SQLADJJOIN = ""

BEGIN
	IF @RPT_TYPE =  1 
	BEGIN
		SET @TYPESQL = " AND TM.TRAN_TYPE = 'BP' "
		SET @SQLADJJOIN = " AND TM.TRAN_TYPE = ADJ.TYPE "
	END
	ELSE IF @RPT_TYPE =  2 
	BEGIN
		SET @TYPESQL = " AND TM.TRAN_TYPE = 'CP' "
	    SET @SQLADJJOIN = ""
	END
	
END

BEGIN
SET NOCOUNT ON;

SET @SQL =	"
SELECT DISTINCT TM.TRAN_ID,TM.TRAN_TYPE,TM.TRAN_MASTER_ID,TD.TRAN_DETAIL_ID,TM.TRAN_AMOUNT,
CONVERT(INT,TM.TRAN_DOCNO) AS TRAN_DOCNO,TM.TRAN_DATE,TD.CHEQUENO,TD.SRNO,TD.DDDATE,TD.ADJUST,TD.NARRATION,
LM.LGR_NAME AS PARTY,UPPER(LM.LGR_ADD1) AS ADD1,UPPER(LM.LGR_ADD2) AS ADD2,
UPPER(LM.LGR_ADD3) AS ADD3,UPPER(CM.CITY_NAME) AS PARTY_CITY,
LM.CITY_PINCODE,UPPER(SM.STATE_NAME) AS PARTY_STATE,ALM.LGR_NAME AS AGENT,
CMP_PHONE1,CMP_PHONE2,CMP_MOBILE,CMP_EMAIL,
PD.VCODE AS BILL_VCODE,ADJ.SRNO AS BILL_SRNO,ADJ.BILLNO AS BILL_BILLNO,ADJ.DATE AS BILL_DATE,
ADJ.AMOUNT AS BILL_AMOUNT,ADJ.DISCOUNT AS BILL_DISCOUNT,ADJ.DISC_PER AS BILL_DISC_PER,
ADJ.RD AS BILL_RD,ADJ.TOTAL AS BILL_TOTAL,ADJ.ADJUSTAMT AS BILL_ADJUSTAMT,ADJ.INTEREST AS BILL_INTEREST,
ADJ.INTREC AS BILL_INTREC,ADJ.FLAG AS BILL_FLAG,PD.PENDINGAMT AS BILL_PENDINGAMT,ADJ.PAID AS BILL_SETTLED,ISNULL(TM.AMT_WORD,'') AS AMT_WORD,
PD.TDSAMOUNT,TD.PARTAMOUNT,LM.Lgr_Mobile
FROM "+@DATABASENAME+"TRAN_MASTER TM
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID = TM.TRAN_ID AND TM.TRAN_TYPE = TD.TRAN_TYPE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = TD.TRAN_DETAIL_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID = LM.STATE_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = LD.AGENT_ID

 INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = TM.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"PURADJMASTER ADJ ON ADJ.ENTRYCODE =  TM.TRAN_ID "+@SQLADJJOIN+"
LEFT JOIN  "+@DATABASENAME+"PURPARTYDETAIL PD ON PD.BILLNO=ADJ.BILLNO AND ADJ.FLAG=PD.FLAG 
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.VCODE=PD.VCODE
 
WHERE TM.TRAN_DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+" 
"+@TYPESQL+" AND TM.CMP_CODE = "+@CMP_CODE+" ORDER BY TRAN_DOCNO
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL 





























GO

