/*
/*
ALTER_BY HIREN
PROC_PAYMENTRECEIPT_VOUCHER 1,'ACC2012_2013.DBO.',1,1
*/
*/

CREATE PROCEDURE [dbo].[PROC_PAYMENTRECEIPT_VOUCHER]
(
	@CMP_CODE	  AS NVARCHAR(20),
	@DATABASENAME AS NVARCHAR(50),
	@FROMNO		  AS NVARCHAR(20),
	@TONO		  AS NVARCHAR(20)
)
AS

DECLARE @SQL1 AS NVARCHAR(4000) 
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
SET @SQL1 = ""
SET @SQL2 = ""
SET @SQL3 = ""

BEGIN
	SET NOCOUNT ON;
	
	SET @SQL1 = " SELECT RM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				  SM.STATE_NAME,RM.DOCNO,CONVERT(NVARCHAR,RM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				  '' AS BILLNO,'' AS BILLDATE,0 AS CHEQUENO,0 AS DAYS,0 AS CRDAYS,0 AS AMOUNT,0  AS DIS,0 AS DISCOUNT,0 AS RD,
				  0 AS SR,0 AS SRAMT,0 AS INSURANCE,0 AS SCHEME,0 AS OLESS,0 AS TOTAL,0 AS ADJUST,0 AS INT,
				  0 AS INTREC,RM.REMARK,'M' AS FLAG,0 AS MAINAMOUNT,0 AS MAININTERESTTOTAL,0 AS FINALTOTAL,0 AS REBATEDAYS
				  
				  FROM "+@DATABASENAME+" RECEIPT_MASTER RM
                  INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=RM.LGR_ID
                  LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                  LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                  LEFT JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=RM.CMP_CODE
                  LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                  WHERE RM.CMP_CODE= "+@CMP_CODE+" AND RM.DOCNO BETWEEN "+@FROMNO+" AND "+@TONO+"
				  UNION ALL "
	
	SET @SQL2 = "SELECT RM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				 SM.STATE_NAME,RM.DOCNO,CONVERT(NVARCHAR,RM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				 RBD.BILLNO,RBD.DATE AS BILLDATE,0 AS CHEQUENO,DATEDIFF(DAY,RBD.DATE,RM.VCHDATE) AS DAYS,RBD.CRDAYS,RBD.AMOUNT,RBD.DISC_PER AS DIS,
				 RBD.DISCOUNT,RBD.SAL_RATEDIFFAMT AS RD,RBD.SAL_REB_PER AS SR,RBD.SAL_REBAMT AS SRAMT,
				 RBD.SAL_INSURANCEAMT AS INSURANCE,RBD.SCHEMEAMT AS SCHEME,RBD.OTHERLESS AS OLESS,
				 RBD.TOTAL,RBD.ADJUSTAMT AS ADJUST,RBD.INTEREST AS INT,RBD.INTREC AS INTREC,RBD.REMARK,
				 'D' AS FLAG,RM.AMOUNT AS MAINAMOUNT,RM.INTERESTTOTAL AS MAININTERESTTOTAL,RM.FINALTOTAL,0 AS REBATEDAYS

				 FROM "+@DATABASENAME+" RECEIPT_MASTER RM 
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = RM.LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
				 LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
				 LEFT JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=RM.CMP_CODE
				 LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
				 INNER JOIN "+@DATABASENAME+" RECEIPT_BILLDETAIL RBD ON RBD.RECEIPT_ID = RM.RECEIPT_ID 
				  WHERE RM.CMP_CODE= "+@CMP_CODE+" AND RM.DOCNO BETWEEN "+@FROMNO+" AND "+@TONO+"
				  UNION ALL "
	
	SET @SQL3 = "SELECT RM.LGR_ID,LM.LGR_NAME AS PARTY,LM.LGR_ADD1,LM.LGR_ADD2,CM.CITY_NAME,LM.CITY_PINCODE,
				 SM.STATE_NAME,RM.DOCNO,CONVERT(NVARCHAR,RM.VCHDATE,103) AS VCHDATE,ALM.LGR_NAME AS AGENT,
				 '' AS BILLNO,RAD.DATE AS BILLDATE,0 AS CHEQUENO,DATEDIFF(DAY,RAD.DATE,RM.VCHDATE) AS DAYS,
				 RAD.DAYS AS CRDAYS,RAD.AMOUNT,0 AS DIS,0 AS DISCOUNT,0 AS RD,0 AS SR,0 AS SRAMT,0 AS INSURANCE,
				 0 AS SCHEME,0 AS OLESS,0 AS TOTAL,0 AS ADJUST,RAD.INTEREST AS INT,0 AS INTREC,RM.REMARK,'P' AS FLAG,
				 0 AS MAINAMOUNT,0 AS MAININTERESTTOTAL,0 AS FINALTOTAL	,0 AS REBATEDAYS						

				 FROM "+@DATABASENAME+" RECEIPT_MASTER RM
                 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=RM.LGR_ID
                 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
                 LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
                 LEFT JOIN "+@DATABASENAME+" LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=RM.CMP_CODE
                 LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
                 INNER JOIN "+@DATABASENAME+" RECEIPT_AMOUNTDETAIL RAD ON RAD.RECEIPT_ID = RM.RECEIPT_ID
                 WHERE RM.CMP_CODE= "+@CMP_CODE+" AND RM.DOCNO BETWEEN "+@FROMNO+" AND "+@TONO+"
				 "


END

EXEC (@SQL1+@SQL2+@SQL3)
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PAYMENTREGISTER]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
