/* 
PROC_PAYMENTREGISTER '2','ACC2010_2011.DBO.','01/APR/2010','01/APR/2011','##1234',3
*/
CREATE PROCEDURE [dbo].[PROC_PAYMENTREGISTER]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),    
@TEMPTABLE NVARCHAR(100),
@FROMDATE NVARCHAR(20),
@TODATE NVARCHAR(20),        
@RPT_WISE INT,
@PREVDATABASE NVARCHAR(20)

)	
AS

DECLARE @SQL NVARCHAR(4000)
DECLARE @SQL1 NVARCHAR(4000)
DECLARE @SQL2 NVARCHAR(4000)
DECLARE @SQL3 NVARCHAR(4000)
DECLARE @SQL4 NVARCHAR(4000)
DECLARE @SQL5 NVARCHAR(4000)
DECLARE @SQL6 NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(4000)
DECLARE @ORDERBYSQL NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @JOINSQL=""
SET @ORDERBYSQL=""

BEGIN
IF @RPT_WISE=1 
BEGIN
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
SET @ORDERBYSQL="PARTY,PARTYID,"
END
ELSE IF @RPT_WISE=2
BEGIN
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL="AGENT,AGENTID,PARTY,PARTYID,"
END

END

BEGIN
SET @SQL=" SELECT VCODE,PARTY,PARTYCITY,AGENT,AGENTCITY,JOBFLAG,SALES_ORDERNO,ITEMDETAIL,BILL_NO ,BILLDATE,BILL_AMOUNT,DDDATE
,RECAMOUNT,DISC_PER,DISCOUNT,INTEREST,RECDATE ,NARRATION,PENDING_AMOUNT,TRAN_AMOUNT,PARTAMOUNT,CMP_ALIAS
,DRAMOUNT,CRAMOUNT,POST ,CITY_PINCODE,DISTRICT,STATE,STATION,LGR_PHONE1,LGR_PHONE2,LGR_MOBILE,LGR_CONT_PERSON,TRANSPORT_NAME
,LGR_ADD1,LGR_ADD2,LGR_ADD3,LGR_BANK,LGR_BRANCH
,DEPOACC,DEPOACCBAL,DEPOACCDRCR,FLAG ,TRAN_TYPE,PARTYID,AGENTID FROM(
"
SET @SQL1=" SELECT PD.VCODE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
PD.JOBFLAG,PD.SALES_ORDERNO,PD.ITEMDETAIL,PD.BILL_NO ,PD.DATE AS BILLDATE,PD.BILL_AMOUNT,TD.DDDATE
,(ISNULL(ADJ.ADJUSTAMT,0)+ISNULL(ADJ.INTREC,0)) AS RECAMOUNT,ISNULL(ADJ.DISC_PER,0) AS DISC_PER,ISNULL(ADJ.DISCOUNT,0)AS DISCOUNT
,ISNULL(ADJ.INTEREST,0) AS INTEREST,ADJ.RECDATE ,TD.NARRATION,PD.PENDING_AMOUNT,TD.TRAN_AMOUNT,TD.PARTAMOUNT,CMP.CMP_ALIAS
,CASE WHEN (PD.PENDING_AMOUNT+ISNULL(PD.INTEREST,0))>0 THEN (PD.PENDING_AMOUNT+ISNULL(PD.INTEREST,0)) ELSE 0 END AS DRAMOUNT
,CASE WHEN (PD.PENDING_AMOUNT+ISNULL(PD.INTEREST,0))<0 THEN ABS(PD.PENDING_AMOUNT+ISNULL(PD.INTEREST,0)) ELSE 0 END AS CRAMOUNT
,LM.LGR_POST AS POST ,LM.CITY_PINCODE,LM.LGR_DISTRICT AS DISTRICT,SM.STATE_NAME AS STATE,SCM.CITY_NAME AS STATION,LM.LGR_PHONE1,LM.LGR_PHONE2,LM.LGR_MOBILE,LM.LGR_CONT_PERSON,TM.TRANSPORT_NAME
,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_BANK,LM.LGR_BRANCH
,DLM.LGR_NAME AS DEPOACC,DLD.LGR_CL_BAL AS DEPOACCBAL,DLD.LGR_CL_DRCR AS DEPOACCDRCR
,'D' AS FLAG ,TD.TRAN_TYPE,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID
FROM "+@DATABASENAME+"PARTYDETAIL PD
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"ADJMASTER ADJ ON ADJ.FLAG=PD.JOBFLAG AND ADJ.BILLNO=PD.BILL_NO AND ADJ.VCODE=PD.VCODE AND ADJ.LGR_ID=PD.LGR_ID AND PD.CMP_CODE=ADJ.CMP_CODE
LEFT JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID=ADJ.ENTRYCODE AND TD.TRAN_TYPE=ADJ.TYPE AND TD.TRAN_DETAIL_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=LD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=LM.LGR_STATION_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER DLM ON DLM.LGR_ID=LD.ACCOUNT_ID 
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL DLD ON DLM.LGR_ID=DLD.LGR_ID AND DLD.CMP_CODE=PD.CMP_CODE
"+@JOINSQL+"
WHERE PD.CMP_CODE IN("+@CMP_CODE +")  AND PD.DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'                  
"



SET @SQL2=" UNION ALL
SELECT  0 AS VCODE,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS  PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITTY,'' AS JOBFLAG,
NULL AS SALES_ORDERNO,'' AS ITEMDETAIL,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_DATE AS BILLDATE
,0 AS BILL_AMOUNT,TD.DDDATE AS DDDATE,0 AS RECAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS INTEREST,TM.TRAN_DATE  AS RECDATE,'' AS NARRATION
,0 AS PENDING_AMOUNT,TD.TRAN_AMOUNT,
(CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)AS PARTAMOUNT
, CMP.CMP_ALIAS,0 AS DRAMOUNT,0 AS CRAMOUNT
,LM.LGR_POST AS POST ,LM.CITY_PINCODE,LM.LGR_DISTRICT AS DISTRICT,SM.STATE_NAME AS STATE,SCM.CITY_NAME AS STATION,LM.LGR_PHONE1,LM.LGR_PHONE2,LM.LGR_MOBILE,LM.LGR_CONT_PERSON,T_M.TRANSPORT_NAME
,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_BANK,LM.LGR_BRANCH
,DLM.LGR_NAME AS DEPOACC,DLD.LGR_CL_BAL AS DEPOACCBAL,DLD.LGR_CL_DRCR AS DEPOACCDRCR       
,'P' AS FLAG,TD.TRAN_TYPE,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID        
FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID        
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=LM.LGR_STATION_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER T_M ON T_M.TRANSPORT_ID=LD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER DLM ON DLM.LGR_ID=LD.ACCOUNT_ID 
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL DLD ON DLM.LGR_ID=DLD.LGR_ID AND DLD.CMP_CODE=TD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
"+@JOINSQL+"
WHERE TM.TRAN_DATE<='"+@TODATE +"' AND (CASE WHEN TD.TRAN_DRCR='C'THEN 0 ELSE 0-TD.PARTAMOUNT END)<>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL) 
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE +")
AND (CONVERT(NVARCHAR,TM.TRAN_ID)+TM.TRAN_DOCNO+'JR') NOT IN (SELECT CONVERT(NVARCHAR,VCODE)+BILL_NO+JOBFLAG FROM "+@DATABASENAME+"PARTYDETAIL WHERE JOBFLAG='JR')
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL)

"

SET @SQL3=" UNION ALL

SELECT  0 AS VCODE,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS  PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITTY,'' AS JOBFLAG,
NULL AS SALES_ORDERNO,'' AS ITEMDETAIL,TM.TRAN_DOCNO AS  BILL_NO,TM.TRAN_DATE AS BILLDATE
,0 AS BILL_AMOUNT,TD.DDDATE AS DDDATE,0 AS RECAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS INTEREST,TM.TRAN_DATE  AS RECDATE,'' AS NARRATION
,0 AS PENDING_AMOUNT,TD.TRAN_AMOUNT,
(CASE WHEN TD.TRAN_TYPE='J' THEN (CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
(CASE WHEN TD.TRAN_DRCR='C'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT
, CMP.CMP_ALIAS,0 AS DRAMOUNT,0 AS CRAMOUNT
,LM.LGR_POST AS POST ,LM.CITY_PINCODE,LM.LGR_DISTRICT AS DISTRICT,SM.STATE_NAME AS STATE,SCM.CITY_NAME AS STATION,LM.LGR_PHONE1,LM.LGR_PHONE2,LM.LGR_MOBILE,LM.LGR_CONT_PERSON,T_M.TRANSPORT_NAME
,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_BANK,LM.LGR_BRANCH
,DLM.LGR_NAME AS DEPOACC,DLD.LGR_CL_BAL AS DEPOACCBAL,DLD.LGR_CL_DRCR AS DEPOACCDRCR       
,'P' AS FLAG ,TD.TRAN_TYPE,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID       

FROM "+@DATABASENAME+"TRAN_DETAIL TD 
INNER JOIN "+@DATABASENAME+"TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=LM.LGR_STATION_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER T_M ON T_M.TRANSPORT_ID=LD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER DLM ON DLM.LGR_ID=LD.ACCOUNT_ID 
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL DLD ON DLM.LGR_ID=DLD.LGR_ID AND DLD.CMP_CODE=TD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
"+@JOINSQL+"
WHERE TM.TRAN_DATE<='"+@TODATE +"' AND TD.PARTAMOUNT>0 AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' OR TD.TRAN_TYPE='SR'OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN("+@CMP_CODE +")
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL)

"

SET @SQL4=" UNION ALL
SELECT  0 AS VCODE,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS  PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITTY,'' AS JOBFLAG,
NULL AS SALES_ORDERNO,'' AS ITEMDETAIL,'' AS  BILL_NO,AE.VDATE AS BILLDATE
,0 AS BILL_AMOUNT,AE.CHQDATE AS DDDATE,0 AS RECAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS INTEREST,AE.VDATE  AS RECDATE,'' AS NARRATION
,0 AS PENDING_AMOUNT,AE.AMOUNT AS TRAN_AMOUNT,AE.PARTAMOUNT
, CMP.CMP_ALIAS,0 AS DRAMOUNT,0 AS CRAMOUNT
,LM.LGR_POST AS POST ,LM.CITY_PINCODE,LM.LGR_DISTRICT AS DISTRICT,SM.STATE_NAME AS STATE,SCM.CITY_NAME AS STATION,LM.LGR_PHONE1,LM.LGR_PHONE2,LM.LGR_MOBILE,LM.LGR_CONT_PERSON,T_M.TRANSPORT_NAME
,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_BANK,LM.LGR_BRANCH
,DLM.LGR_NAME AS DEPOACC,DLD.LGR_CL_BAL AS DEPOACCBAL,DLD.LGR_CL_DRCR AS DEPOACCDRCR       
,'P' AS FLAG  ,AE.ENTRYTYPE AS TRAN_TYPE,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID      
FROM "+@DATABASENAME+"ADVANCE_ENTRY AE         
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID        
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SCM.CITY_ID=LM.LGR_STATION_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER T_M ON T_M.TRANSPORT_ID=LD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER DLM ON DLM.LGR_ID=LD.ACCOUNT_ID 
LEFT JOIN "+@DATABASENAME+"LEDGER_DETAIL DLD ON DLM.LGR_ID=DLD.LGR_ID AND DLD.CMP_CODE=AE.CMP_CODE
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
"+@JOINSQL+"
WHERE AE.VDATE<='"+@TODATE +"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE +")
"

BEGIN
IF @PREVDATABASE!=""
BEGIN
SET @SQL5=" UNION ALL
SELECT  0 AS VCODE,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS  PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITTY,'' AS JOBFLAG,
NULL AS SALES_ORDERNO,'' AS ITEMDETAIL,'' AS  BILL_NO,AE.VDATE AS BILLDATE
,0 AS BILL_AMOUNT,AE.CHQDATE AS DDDATE,0 AS RECAMOUNT,0 AS DISC_PER,0 AS DISCOUNT,0 AS INTEREST,AE.VDATE  AS RECDATE,'' AS NARRATION
,0 AS PENDING_AMOUNT,AE.AMOUNT AS TRAN_AMOUNT,AE.PARTAMOUNT
, CMP.CMP_ALIAS,0 AS DRAMOUNT,0 AS CRAMOUNT
,LM.LGR_POST AS POST ,LM.CITY_PINCODE,LM.LGR_DISTRICT AS DISTRICT,SM.STATE_NAME AS STATE,SCM.CITY_NAME AS STATION,LM.LGR_PHONE1,LM.LGR_PHONE2,LM.LGR_MOBILE,LM.LGR_CONT_PERSON,T_M.TRANSPORT_NAME
,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_BANK,LM.LGR_BRANCH
,DLM.LGR_NAME AS DEPOACC,DLD.LGR_CL_BAL AS DEPOACCBAL,DLD.LGR_CL_DRCR AS DEPOACCDRCR       
,'P' AS FLAG  ,AE.ENTRYTYPE AS TRAN_TYPE,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID      
FROM "+@PREVDATABASE+"ADVANCE_ENTRY AE         
INNER JOIN "+@PREVDATABASE+"LEDGER_MASTER LM ON LM.LGR_ID=AE.LGR_ID
LEFT JOIN "+@PREVDATABASE+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AE.CMP_CODE=LD.CMP_CODE
LEFT JOIN "+@PREVDATABASE+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID        
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@PREVDATABASE+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@PREVDATABASE+"CITY_MASTER SCM ON SCM.CITY_ID=LM.LGR_STATION_ID
LEFT JOIN "+@PREVDATABASE+"TRANSPORT_MASTER T_M ON T_M.TRANSPORT_ID=LD.TRANSPORT_ID
LEFT JOIN "+@PREVDATABASE+"LEDGER_MASTER DLM ON DLM.LGR_ID=LD.ACCOUNT_ID 
LEFT JOIN "+@PREVDATABASE+"LEDGER_DETAIL DLD ON DLM.LGR_ID=DLD.LGR_ID AND DLD.CMP_CODE=AE.CMP_CODE
LEFT JOIN "+@PREVDATABASE+"COMPANY_MASTER CMP ON CMP.CMP_CODE=AE.CMP_CODE
"+@JOINSQL+"
WHERE AE.VDATE<='"+@TODATE +"' AND AE.PARTAMOUNT>0 AND AE.CMP_CODE IN("+@CMP_CODE +")
"
END 
SET @SQL6=" ) AS DETAIL ORDER BY "+@ORDERBYSQL+"DETAIL.FLAG,DETAIL.BILLDATE,DETAIL.BILL_NO,DETAIL.RECDATE"
END
END
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6)

















GO

