/*
PROC_PENDING_STOCK_REGISTER 2,'Acc2010_2011.dbo.','31/Mar/2011',##4092,2,4
*/
CREATE PROCEDURE [dbo].[PROC_PENDING_STOCK_REGISTER]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@AsOnDate nvarchar(50),
@TempTable nvarchar(50), 
@RptWise int,
@RptType int
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @JOIN AS NVARCHAR (4000) SET @JOIN=""
DECLARE @COND AS NVARCHAR (4000) SET @COND=""

BEGIN
iF @RptWise=1 /*DocNo*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=STM.STOCKIN_ID"

ELSE IF @RptWise in (2,3)/*Item Wise*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IM.ITEM_ID"

ELSE IF @RptWise =4/*Screen wise */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=SM.SCREEN_ID"

ELSE IF @RptWise in (5,6)/*ITEM GRP WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IG.Item_Grp_Id"

ELSE IF @RptWise in (7,8)/* ITEM TYPE WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=IT.Item_Type_Id"

ELSE IF @RptWise in (9,10,11)/*TRANSPORT WISE */
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=TM.Transport_Id"

ELSE IF @RptWise =12/*LOT NO WISE*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=STD.LOTNO"

ELSE IF @RptWise =13/*FOLD NO*/
	SET @JOIN=" INNER JOIN "+@TempTable+" TT ON TT.CODE=STD.FOLD"

ELSE IF @RptWise =14/*DSESIGN NO/ COL CHART WIS E*/
	SET @JOIN="INNER JOIN "+@TempTable+" TT ON TT.CODE=STD.DESIGN_COL_CHART"

END

BEGIN
IF @RptType=1
	SET @COND=" AND STM.STOCKIN_TYPE='C'"
ELSE IF @RptType=2
	SET @COND=" AND STM.STOCKIN_TYPE='O'"
ELSE IF @RptType=3
	SET @COND=" AND STM.STOCKIN_TYPE='FP'"
ELSE IF @RptType=4
	SET @COND=" AND STM.STOCKIN_TYPE='E'"
ELSE SET @COND=" "

END

BEGIN
	
	SET NOCOUNT ON;
SET @SQL ="
select STM.DOCNO,STM.VCHDATE,IM.ITEM_NAME,SM.Screen_Name,IG.Item_Grp_Name,IT.Item_Type_Name,TM.Transport_Name,
STD.LRNO,STD.BALENO,STD.PENDINGPIECES,STD.PENDINGQUANTITY,STD.LOTNO,STD.FOLD,STD.DESIGN_COL_CHART,STM.STOCKIN_TYPE
from "+@DataBase+" STOCKIN_MASTER STM
inner join "+@DataBase+" STOCKIN_DETAIL STD on STM.STOCKIN_ID=STD.STOCKIN_ID AND STM.STOCKIN_TYPE=STD.STOCKIN_TYPE
left join "+@DataBase+" Item_Master IM on STD.Item_Id=IM.ITem_Id
left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
left join "+@DataBase+" Item_Type_Master IT on IT.Item_Type_Id=IM.Item_Type_Id
left join "+@DataBase+" Transport_Master TM on TM.Transport_Id=STM.Transport_Id
"+@JOIN+"
where STM.Cmp_Code in ("+@CmpCode+") and VCHDATE <='"+@AsOnDate+"'
and (STD.PENDINGQUANTITY>0 or  STD.PENDINGPIECES>0)
"+@COND+"
order by DocNo 
"
    
END
EXECUTE Sp_EXECUTESql @SQL 
PRINT @SQL 

set ANSI_NULLS ON
set QUOTED_IDENTIFIER ON




















GO

