GO




















/*
PROC_PENDING_TRANSPORT_DELV_REPORT 2,'Acc2010_2011.dbo.',1,'01/apr/2011','01/apr/2012',##2824
*/
CREATE PROCEDURE [dbo].[PROC_PENDING_TRANSPORT_DELV_REPORT]
(
@CMP_CODE nvarchar(50),
@DATABASENAME nvarchar(50),
@RPT_WISE int,
@FROMDATE nvarchar(50),
@TODATE nvarchar(50),
@TEMPTABLE nvarchar(50)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""

BEGIN
 IF @RPT_WISE=1 
	SET @JOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID "
 ELSE 
	SET @JOIN=""

END

BEGIN	
	SET NOCOUNT ON;
SET @STRSQL="
SELECT BALENO,VCH_DATE,LM.LGR_NAME,CM.CITY_NAME,IM.ITEM_NAME,SM.SCREEN_NAME,TOTALPCS,TOTAL AS TOTALMTR,
TRANSPORT_NAME
FROM  "+@DATABASENAME+" PACKINGSLIP PK
INNER JOIN "+@DATABASENAME+" PACKINGSLIP_DETAIL PKD ON PK.PACKINGSLIPID=PKD.PACKINGSLIPID and PK.Cmp_Code=PKD.Cmp_COde
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PK.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PKD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON PKD.SCREEN_ID=SM.SCREEN_ID
inner join "+@DATABASENAME+" TRANSPORT_MASTER TM on PK.TRANSPORT_Id=TM.TRANSPORT_ID		   
"+@JOIN+"
WHERE PK.CMP_CODE="+@CMP_CODE+" and isnull(RUKKANO,0)<=0
AND VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"
    
END
EXEC SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

