CREATE PROCEDURE [dbo].[PROC_PENDING_TRANSPORT_GATEPASS]
(
@CMP_CODE nvarchar(50),
@DATABASENAME nvarchar(50),
@RPT_WISE int,
@FROMDATE nvarchar(50),
@TODATE nvarchar(50),
@TEMPTABLE nvarchar(50)
)
AS

DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""

BEGIN
 IF @RPT_WISE=1 
	SET @JOIN="INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID "
 ELSE 
	SET @JOIN=""
END

BEGIN	
	SET NOCOUNT ON;
SET @STRSQL="  SELECT DOCNO AS RUKKANO,CMP.CMP_ALIAS AS ALIAS,VCH_DATE,TD.TRANSPORT_ID,TM.TRANSPORT_NAME AS TRANSPORT,TOTALBALES,
BALESSTRING,0 AS FLAG   
FROM "+@DATABASENAME+" TRANSPORT_DELIVERY TD  
INNER JOIN "+@DATABASENAME+" Transport_Master TM on TD.TRANSPORT_ID=TM.TRANSPORT_ID  
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=TD.CMP_CODE  
"+@JOIN+"
WHERE  GATEPASS=0 
AND VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"
    
END
