CREATE PROCEDURE [dbo].[PROC_PENDINGBANKSLIP]
(
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(50),
    @FROMDATE AS NVARCHAR(20),
    @TODATE AS NVARCHAR(20),
    @BANKID NVARCHAR(20)
)
AS
DECLARE @SQL  NVARCHAR(4000)

BEGIN
    	SET NOCOUNT ON;
        SET @SQL=" SELECT BS.SLIPNO,BS.SLIPDATE,LM.LGR_NAME AS BANKNAME,BS.DDNO,BS.DDDATE,
					BS.CITY_ID,CM.CITY_NAME,BS.TYPE,BS.AMOUNT
				    FROM "+@DATABASENAME+"BANKSLIP BS INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON BS.LGR_ID=LM.LGR_ID
					LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON BS.CITY_ID=CM.CITY_ID
				WHERE BS.CMP_CODE="+@CMP_CODE+" AND BS.USED=0 AND BS.LGR_ID="+@BANKID+" AND
					BS.SLIPDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
					"
        EXECUTE SP_EXECUTESQL @SQL
        PRINT @SQL
END




















