/* 
PROC_PENDINGGRAYSALESORDER '2','Acc2010_2011.dbo.','1','31/Mar/2011','##2892'
*/
CREATE PROCEDURE [dbo].[PROC_PENDINGGRAYSALESORDER]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @AsOnDate as Nvarchar(20),    
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.ITem_Type_ID"
if @Rpt_Wise=2
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;
set @Sql="
Select SO.Sal_Order_Id,SO.ConfNo,SOD.PendingQty,IGM.Item_Grp_Name  as MainGroup,LM.Lgr_Name,PCM.CITY_NAME AS PARTYCITY
FROM "+@DatabaseName+" Sales_Order SO
INNER JOIN "+@DatabaseName+" Sales_Order_Detail SOD on SO.Sal_Order_Id=SOD.Sal_Order_Id and SOD.Flag=SO.Flag
INNER JOIN "+@DatabaseName+" Ledger_Master LM on So.Lgr_Id=LM.Lgr_Id
Inner Join "+@DatabaseName+" Item_Master IM ON SOD.item_Id = IM.item_Id  
Inner Join "+@DatabaseName+" Item_Group_Master IGM ON IM.item_Grp_Id = IGM.item_Grp_Id  
LEFT Join "+@DatabaseName+" CITY_Master PCM ON PCM.CITY_ID=LM.CITY_ID
"+@JoinSql+"	
where  SO.vch_Date<='" + @AsOnDate + "' and SO.Cmp_Code in ("+ @Cmp_Code +") and SOD.PendingQty>0 and SO.Flag='GS'
" 

execute Sp_Executesql @sql
Print @sql
end




















GO

