-- REPORT_FORM    :	<RFRMPENDINGGREYRECEIPTREPORT.CS>
-- CRYSTAL_REPORT :	<PENDINGGREYRECEIPT.RPT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS

PROC_PENDINGGREYRECEIPT N'01/Apr/2018', N'31/Mar/2019', N'1', 1, N'Acc2018_2019.Dbo.', N'##4752', 2

*/
CREATE PROCEDURE [dbo].[PROC_PENDINGGREYRECEIPT]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(50),
@RPT_WISE INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE  INT

)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)
DECLARE @STRORDERBY AS NVARCHAR(100)
DECLARE @DATECONDSQL AS NVARCHAR(1000)


SET @SQL=""
SET @SELECTED=""
SET @CONDSQL=""
SET @STRORDERBY=""
SET @DATECONDSQL = ""

BEGIN
IF @RPT_TYPE = 1
SET @CONDSQL = " AND TLD.PENDING_BALES = 0 "
IF @RPT_TYPE = 2
SET @CONDSQL = " AND TLD.PENDING_BALES > 0 "
IF @RPT_TYPE = 3
SET @CONDSQL = ""
END


BEGIN
IF @RPT_WISE IN (11)
SET @DATECONDSQL = " AND GR.DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "
IF @RPT_WISE NOT IN (11)
SET @DATECONDSQL = " AND TLD.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "
END



BEGIN

BEGIN    
IF @RPT_WISE IN (1)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID = TT.CODE"
SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID ,"
END
IF @RPT_WISE IN (2)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TM.TRANSPORT_ID = TT.CODE"
SET @STRORDERBY=" TM.TRANSPORT_NAME,TM.TRANSPORT_ID,"
END
IF @RPT_WISE IN (3)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON LOM.LOT_ID = TT.CODE"
SET @STRORDERBY=" LOM.LOT_NAME,LOM.LOT_ID,"
END
IF @RPT_WISE IN (4)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IM.ITEM_ID= TT.CODE"
SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,"
END
IF @RPT_WISE IN (5)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON WM.WEAVER_ID= TT.CODE"
SET @STRORDERBY=" WM.WEAVER_NAME,WM.WEAVER_ID,"
END
IF @RPT_WISE IN (8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TLD.PURCHASEINVID= TT.CODE"
END
IF @RPT_WISE IN (9)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TLD.PURCHASEINVID= TT.CODE"
END
ELSE IF @RPT_WISE IN (6)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID = TT.CODE"
SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
END
ELSE IF @RPT_WISE IN (7)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID = TT.CODE"
SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,LOM.LOT_NAME,LOM.LOT_ID,"
END
ELSE IF @RPT_WISE IN (11)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.SERIES_ID=TT.CODE"
SET @STRORDERBY=" SM.SERIES_NAME,SM.SERIES_ID,"
END
END
SET @SQL="
SELECT TLD.PURCHASEINVID,TLD.DOCNO,TLD.BILL_NO AS BILLNO,TLD.VCHDATE AS BILLDATE,TLD.LRNO,
CONVERT(NVARCHAR,TLD.LRDATE,103) AS LRDATE,
TLD.BALENO,TLD.BALES,TLD.PENDING_BALES,TLD.RECEIVE_BALES,TLD.NETTOTAL,
LM.LGR_NAME AS PARTY,TM.TRANSPORT_NAME AS TRANSPORT,LOM.LOT_NAME AS GREYMARKA,
IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS WEAVER,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,
ISNULL(COMP.CMP_ALIAS,'') AS CMP_ALIAS,LM.LGR_ID,TM.TRANSPORT_ID,LOM.LOT_ID ,IM.ITEM_ID,WM.WEAVER_ID,ISNULL(CONVERT(NVARCHAR,GR.DATE,103),'')AS REC_DATE,GR.CHALLAN_NO,GR.MANUAL_RECEIPT_NO,TLD.PCS,TLD.METER,SM.SERIES_NAME,GR.DOC_NO AS GRDOCNO
FROM "+@DATABASENAME+"TRANSPORT_LR_DETAIL TLD 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = TLD.LGR_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TLD.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = TLD.LOT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = TLD.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = TLD.WEAVER_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
INNER JOIN  "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = TLD.CMP_CODE
LEFT JOIN  "+@DATABASENAME+"GRAYRECEIPT_DETAIL GRD ON GRD.BALENO= TLD.BALENO  AND GRD.LRNO = TLD.LRNO
LEFT JOIN  "+@DATABASENAME+"GRAYRECEIPT_MASTER GR ON GR.GrayReceipt_Id= GRD.GrayReceipt_Id
LEFT JOIN "+@DATABASENAME+"SERIES_MASTER SM ON SM.SERIES_ID=GR.SERIES_ID
"+ @SELECTED +"
WHERE TLD.CMP_CODE IN ("+@CMP_CODE+") 
"+@DATECONDSQL +" "+@CONDSQL+"
ORDER BY  "+@STRORDERBY+"TLD.VCHDATE,TLD.BILL_NO,TLD.DOCNO,TLD.LRNO"

END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

















GO

