CREATE PROCEDURE [dbo].[PROC_PENDINGPACKINGSLIP]
(
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(50),
    @RPT_WISE INT,
    @FROMDATE AS NVARCHAR(20),
    @TODATE AS NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
	@RptType int
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
SET @JOINSQL=""
SET @TYPESQL=""

IF @RPT_WISE=1
     SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PLM.LGR_ID"
IF @RPT_WISE=2
     SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
IF @RPT_WISE=3
     SET @JOINSQL=""
IF @RPT_WISE=4
     SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRANSPORT_ID"

BEGIN
    	SET NOCOUNT ON;
        SET @SQL=" SELECT PS.PACKINGSLIPID,PS.SERIALNO AS BALENO,PS.VCH_DATE,PS.LGR_ID,PLM.LGR_NAME AS PARTYNAME,
PS.CITY_ID,PCM.CITY_NAME AS PARTYCITY,PS.AGENT_ID,ALM.LGR_NAME AS AGENTNAME,
PSD.ITEM_ID,IM.ITEM_NAME,PSD.TOTALPCS,PSD.TOTAL AS TOTALMTR,TM.TRANSPORT_NAME AS TRANSPORT,CMP.CMP_ALIAS,PS.D_COLNO,SM.Screen_name
FROM " + @DATABASENAME + "PACKINGSLIP PS 
INNER JOIN " + @DATABASENAME + "PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER PLM ON PS.LGR_ID=PLM.LGR_ID
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON PS.AGENT_ID=ALM.LGR_ID
INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON PSD.ITEM_ID=IM.ITEM_ID
INNER JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON PSD.SCREEN_ID=SM.SCREEN_ID
LEFT JOIN " + @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID
"+@JOINSQL+"	
LEFT JOIN " + @DATABASENAME + "CITY_MASTER PCM ON PS.CITY_ID=PCM.CITY_ID                    
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
WHERE PS.VCH_DATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
AND (PS.INUSE=0 OR PS.INUSE IS NULL) AND PS.CMP_CODE IN (" + @CMP_CODE + ")"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END




















GO

