/* 
exec Proc_PendingPurchaseOrder '1','Acc2010_2011.dbo.','1','12/Oct/2010','##2704'
*/

CREATE PROCEDURE [dbo].[PROC_PENDINGPROCESS]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @AsOnDate as Nvarchar(20),    
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.ITem_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;

	    if @Rpt_Wise=0
		Begin
			set @sql="
			select ProcessName,MainGroup,SUM(InThan) as InThan,SUM(InMeter) as InMeter,SUM(OutThan) as OutThan,SUM(OutMeter) as OutMeter,SUM(InThan) - SUM(OutThan)  as PendThan,SUM(InMeter) - SUM(OutMeter)  as PendMeter  from
			(
			select PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter from processIn PIN 
			Inner Join Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			where PIN.VCHDate <='"+@AsOnDate+"' and PIN.Cmp_Code in ("+@Cmp_Code+")

			UNION

			select PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,0 as InThan,0 as OutThan,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter from processOut POUT 
			Inner Join Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner  Join Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			where POUT.VCHDate <='"+@AsOnDate+"' and POUT.Cmp_Code in ("+@Cmp_Code+")
			) as a
			Group By ProcessName,MainGroup "
		end 


  
    	if @Rpt_Wise=1
		Begin
		set @sql="
			select ProcessName,MainGroup,SUM(InThan) as InThan,SUM(InMeter) as InMeter,SUM(OutThan) as OutThan,SUM(OutMeter) as OutMeter,SUM(InThan) - SUM(OutThan)  as PendThan,SUM(InMeter) - SUM(OutMeter)  as PendMeter  from
			(
			select PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter 
			from " + @DatabaseName + "processIn PIN 
			Inner Join " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  
			"+@JoinSql+"	
			where PIN.VCHDate <='" + @AsOnDate + "' and PIN.Cmp_Code in ("+ @Cmp_Code +")

			UNION

			select PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,0 as InThan,0 as OutThan,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
			from " + @DatabaseName + "processOut POUT 
			Inner Join " + @DatabaseName + "Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  
			"+@JoinSql+"	
			where POUT.VCHDate <='" + @AsOnDate + "' and POUT.Cmp_Code in ("+ @Cmp_Code +")

			) as a
			Group By ProcessName,MainGroup "
		end 


		execute Sp_Executesql @sql
        Print @sql
end




















GO

