SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- ALTER_AUTHOR  :	<BIREN>
-- ALTER_DATE    : <29-08-2014 4:20 PM>
-- REPORT_FORM    :	<RFRMPENDINGBILLCHALLANREPORT.CS>
-- CRYSTAL_REPORT :	<PENDINGBILLCHALLANREPORT.RPT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_PENDINGPURCHASECHALLANREPORT '01/APR/2014','31/MAR/2015','1',5,'ACC2015_2016.DBO.','##5944',3,2
*/
CREATE PROCEDURE [dbo].[PROC_PENDINGPURCHASECHALLANREPORT]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@RPT_WISE INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE  INT,
@CHALLAN_TYPE  INT
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)
DECLARE @CHALLANSQL NVARCHAR(100)
DECLARE @STRORDERBY NVARCHAR(200)

SET @SQL=""
SET @SELECTED=""
SET @CONDSQL=""
SET @CHALLANSQL = ""
SET @STRORDERBY = ""
BEGIN
IF @RPT_TYPE = 1
SET @CONDSQL = " AND ISNULL(CCD.INUSE,0) = 1"
IF @RPT_TYPE = 2
SET @CONDSQL = " AND ISNULL(CCD.INUSE,0) <> 1"
IF @RPT_TYPE = 3
SET @CONDSQL = ""
END

IF @CHALLAN_TYPE = 1
	SET @CHALLANSQL = "AND CC.FLAG='CHP'"
ELSE IF @CHALLAN_TYPE = 2
	SET @CHALLANSQL = "AND CC.FLAG='MIP'"

BEGIN

BEGIN    
IF @RPT_WISE IN (1)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON SGM.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "  ISNULL(SGM.SUPP_GRP_NAME,''),ISNULL(SGM.SUPP_GRP_ID,0),"
END
IF @RPT_WISE IN (2)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON LM.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "  ISNULL(LM.LGR_NAME,''),ISNULL(LM.LGR_ID,0), "
END
IF @RPT_WISE IN (3)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IM.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "     ISNULL(IM.ITEM_NAME,'') , ISNULL(IM.ITEM_ID,0), "
END
IF @RPT_WISE IN (4)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IGM.ITEM_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "   ISNULL(IGM.ITEM_GRP_NAME,''),ISNULL(IGM.ITEM_GRP_ID,0), "
END
IF @RPT_WISE IN (5)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON CCD.SIZE_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = " ISNULL(SM.SIZE_NAME,''),ISNULL( CCD.SIZE_ID,0),"
END
IF @RPT_WISE IN (6)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON LM.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "  ISNULL(LM.LGR_NAME,''), ISNULL(LM.LGR_ID,0),ISNULL(IM.ITEM_NAME,''),ISNULL(IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (7)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IM.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "  ISNULL(IM.ITEM_NAME,''),ISNULL( IM.ITEM_ID,0),ISNULL(SM.SIZE_NAME,''),ISNULL( CCD.SIZE_ID,0),"
END
IF @RPT_WISE IN (8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IGM.ITEM_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = " ISNULL(IGM.ITEM_GRP_NAME,''),ISNULL(IGM.ITEM_GRP_ID,0),ISNULL(IM.ITEM_NAME,''),ISNULL( IM.ITEM_ID,0),"
END
IF @RPT_WISE IN (9)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON CC.DOCNO=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = " "
END
IF @RPT_WISE = 10
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON CC.CONFNO=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = "  CC.CONFNO,"
END
IF @RPT_WISE = 11
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON CC.PARTYCHALLAN_NO=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY = " CC.PARTYCHALLAN_NO,"
END
IF @RPT_WISE IN (12)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IM.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY =  "  ISNULL(IM.NICK_NAME,''),ISNULL(IM.ITEM_ID,0),"
END

END
SET @SQL="
SELECT CC.CHALLANID,CC.DOCNO,CC.VCHDATE,ISNULL(CC.CONFNO,0) AS CONFNO,ISNULL(CC.DATE,'') AS CONFDATE,
ISNULL(CC.ORDERDATE,'') AS ORDERDATE,ISNULL(CC.ORDERNO,'') AS ORDERNO,ISNULL(CC.CHALLANNO,'') AS CHALLANNO,
CC.FYEAR,ISNULL(CC.HEAD,'') AS HEAD,ISNULL(CC.WEIGHT_SLIPNO,0) AS WEIGHT_SLIPNO,
ISNULL(CC.VEHICLENO,'') AS VEHICLENO,
ISNULL(CC.OUT_GATEPASS_NO,0) AS OUT_GATEPASS_NO,ISNULL(CC.LRNO,'') AS LRNO,ISNULL(CC.CHECKEDBY,'') AS CHECKEDBY,
ISNULL(CC.APPROVEDBY,'') AS APPROVEDBY,ISNULL(CC.NARRATION,'') AS NARRATION,
ISNULL(CC.PARTYCHALLAN_NO,0) AS PARTYCHALLAN_NO,
CCD.SRNO,CCD.QUANTITY,CCD.RATE,ISNULL(CCD.INUSE,0) AS INUSE,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGRP,ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(UM.UNIT_NAME,'') AS UNIT,
ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP,COMP.CMP_ALIAS,
ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ISNULL(DM.DRIVER_NAME,'') AS DRIVER,
ISNULL(CC.CHALLAN_APPROVAL,0) AS CHALLAN_APPROVAL,ISNULL(SM.SIZE_NAME,'') AS SIZE,ISNULL(PACKING,0) AS PACKING,
ISNULL(BAGS,0) AS BAGS,ISNULL(IM.NICK_NAME,'') AS NICKNAME,
 ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(IM.ITEM_ID,0) AS ITEM_ID, ISNULL(IGM.ITEM_GRP_ID,0) AS ITEM_GRP_ID,ISNULL(SM.SIZE_ID,0)  AS SIZE_ID
FROM "+@DATABASENAME+"CHEMICALCHALLAN CC
INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CCD ON CCD.CHALLANID = CC.CHALLANID AND CCD.CMP_CODE = CC.CMP_CODE
LEFT  JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = CC.LGR_ID
LEFT  JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = CC.SUPP_GRP_ID
LEFT  JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = CCD.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = CCD.UNIT_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = CC.CMP_CODE
LEFT  JOIN "+@DATABASENAME+"DRIVER_MASTER DM ON DM.DRIVER_ID = CC.DRIVER_ID
LEFT  JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = CCD.SIZE_ID
"+ @SELECTED +"
WHERE CC.CMP_CODE IN ("+@CMP_CODE+") AND CC.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@CONDSQL+""+@CHALLANSQL+"
ORDER BY  "+@STRORDERBY+"CC.VCHDATE,CC.DOCNO"

END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

