/* 
edit date17/aug/2012 sanket
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE'##%'
 [PROC_PENDINGPURCHASEORDER] '1','Acc2014_2015.dbo.','1','31/mar/2014','##5420',2
*/


CREATE PROCEDURE [dbo].[PROC_PENDINGPURCHASEORDER]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @AsOnDate as Nvarchar(20),    
    @TempTable nvarchar(20),
	@OrderType int
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
Declare @StrOrderType Nvarchar(100)

set @JoinSql=""
Set @TypeSql=""
set @StrOrderType =""


if @Rpt_Wise=0
BEGIN	
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =ITM.ITem_Type_ID"
END
if @Rpt_Wise=1
BEGIN
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IGM.Item_Grp_ID"
END


if @OrderType=1
	set @StrOrderType =" AND PO.FLAG='P'"
else 
	set @StrOrderType =" AND PO.FLAG<>'P'"

begin
    	SET NOCOUNT ON;
	if @Rpt_Wise=1
		Begin
		set @sql="
			Select   PO.Pur_Order_Id as ID,Po.DocNo,POD.PendingQty,SGM.Supp_Grp_Name 
			,IGM.Item_Grp_Name  as MainGroup,SGM.Supp_Grp_ID, IGM.item_Grp_Id  AS MAIN_ID
			from  " + @DatabaseName + "PurchaseOrder PO 
			Inner Join " + @DatabaseName + "PurchaseOrder_Detail POD ON PO.Pur_Order_Id = POD.Pur_Order_Id  AND PO.FLAG=POD.FLAG
			Inner Join " + @DatabaseName + "Supplier_Group_Master SGM ON PO.Supp_Grp_ID = SGM.Supp_Grp_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POD.item_Id = IM.item_Id  
			Inner Join " + @DatabaseName + "Item_Group_Master IGM ON IM.item_Grp_Id = IGM.item_Grp_Id  
			"+@JoinSql+"	
			where  PO.GDate<='" + @AsOnDate + "' and PO.Cmp_Code in ("+ @Cmp_Code +")  and POD.PendingQty>0
			"+@StrOrderType +" ORDER BY IGM.Item_Grp_Name,IM.item_Grp_Id,SGM.Supp_Grp_Name,SGM.Supp_Grp_ID
			" 

		end 
	if @Rpt_Wise=0
		begin
			set @sql="
			Select   PO.Pur_Order_Id,Po.DocNo,POD.PendingQty,SGM.Supp_Grp_Name
			,ITM.Item_Type_Name as MainGroup,SGM.Supp_Grp_ID, ITM.Item_Type_Id   AS MAIN_ID
			from  " + @DatabaseName + "PurchaseOrder PO 
			Inner Join " + @DatabaseName + "PurchaseOrder_Detail POD ON PO.Pur_Order_Id = POD.Pur_Order_Id  AND PO.FLAG=POD.FLAG
			Inner Join " + @DatabaseName + "Supplier_Group_Master SGM ON PO.Supp_Grp_ID = SGM.Supp_Grp_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POD.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "ITEM_TYPE_MASTER ITM ON IM.Item_Type_Id = ITM.Item_Type_Id  
			"+@JoinSql+"	
			where  PO.GDate<='" + @AsOnDate + "' and PO.Cmp_Code in ("+ @Cmp_Code +") and POD.PendingQty>0
			"+@StrOrderType +" ORDER BY  ITM.Item_Type_Name,ITM.Item_Type_Id ,SGM.Supp_Grp_Name,SGM.Supp_Grp_ID
			" 
		end 
		execute Sp_Executesql @sql
        Print @sql
end


















GO

/****** Object:  StoredProcedure [dbo].[PROC_PENDINGSALESORDER]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
