CREATE PROCEDURE [dbo].[PROC_PENDINGSALESORDER]
(
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(50),
    @FROMDATE AS NVARCHAR(20),
    @TODATE AS NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
    @TEMPTABLE2 NVARCHAR(20),    
	@CRITERIA INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(1000)
DECLARE @TYPESQL NVARCHAR(100)
SET @JOINSQL=""
SET @TYPESQL=""

BEGIN
    IF @CRITERIA=1  /* PARTY WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
    ELSE IF @CRITERIA=2  /* AGENT WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID"
    ELSE IF @CRITERIA=3 /* AGENT-PARTY WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID" 
    ELSE  IF @CRITERIA=4 /* ITEM WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.ITEM_ID"
    ELSE IF @CRITERIA=5 /* SCREEN  WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.SCREEN_ID"
    ELSE IF @CRITERIA=6 /* SALES MAN WISE */
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
    ELSE IF @CRITERIA=7 /* SALES MAN-AGENT WISE */ 
         SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
    ELSE IF @CRITERIA=8  /* PARTY WISE */
         BEGIN
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
          SET @JOINSQL=@JOINSQL+" INNER JOIN "+ @TEMPTABLE2 + " TT1 ON TT1.CODE=IGM.ITEM_GRP_ID"
         END
    ELSE IF @CRITERIA=9 /* AGENT-ITEMGROUP WISE */
         BEGIN
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID" 
          SET @JOINSQL=@JOINSQL+" INNER JOIN "+ @TEMPTABLE2 + " TT1 ON TT1.CODE=IGM.ITEM_GRP_ID"
        END
	ELSE IF @CRITERIA=10 /* CUSTOMER GROUP */
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
END


BEGIN
    	SET NOCOUNT ON;
        SET @SQL="   
                 SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO,SO.ORDER_DATE,SOD.ITEM_ID,IM.ITEM_NAME,SOD.ITEM_CUT,
                 SOD.PENDINGBALES AS BALES,SOD.PENDINGPIECES AS PIECES,SOD.RATE,SO.COLOURS,
                 SOD.SCREEN_ID,SM.SCREEN_NAME,SO.TRANSPORT_ID,TM.TRANSPORT_NAME,      LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
                 SO.STATION_ID,SCM.CITY_NAME AS STATION   ,SAM.SALESMAN_NAME AS SALESMAN,IGM.ITEM_GRP_NAME AS ITEMGROUP
                 ,CMP.CMP_ALIAS, CGM.CUST_GRP_NAME AS CUSTOMEGROUP
                 FROM "+@DATABASENAME+"SALES_ORDER SO
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID 
                 LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON SO.TRANSPORT_ID=TM.TRANSPORT_ID
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SO.STATION_ID=SCM.CITY_ID
                 LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
                 LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID 
                INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
				LEFT JOIN " +@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                 "+ @JOINSQL +"    
                WHERE SO.CMP_CODE in("+@CMP_CODE+") AND SO.VCH_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' AND PENDINGBALES>0
                ORDER BY SO.VCH_DATE
				"
        EXECUTE SP_EXECUTESQL @SQL
        PRINT @SQL
END




















GO

/****** Object:  StoredProcedure [dbo].[Proc_PendingSalesOrder_Ageing]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*  
    PROC_PENDINGSALESORDER_AGEING '2', N'ACC2010_2011.DBO.', N'01/APR/2010', N'31/MAR/2011', N'##2808', 1,''
*/ 
CREATE PROCEDURE [dbo].[Proc_PendingSalesOrder_Ageing] 
(     
  @CMP_CODE NVARCHAR(10),
  @DATABASENAME NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),      
  @TODATE AS NVARCHAR(20),     
  @TEMPTABLE NVARCHAR(20),   
  @RPT_WISE INT,
  @GOODSTYPE NVARCHAR(4000)  
)  
AS  
DECLARE @SQL  NVARCHAR(4000)  
DECLARE @JOINSQL  NVARCHAR(100) 
DECLARE @TYPESQL NVARCHAR(100)  
DECLARE @GOODSTYPESQL NVARCHAR(2000)
SET @JOINSQL=""  
SET @TYPESQL=""    
SET @GOODSTYPESQL=""

BEGIN 
    IF @GOODSTYPE<>"" 
          BEGIN
              SET  @GOODSTYPESQL=" AND IM.ITEM_GOODS_TYPE IN("+@GOODSTYPE+") "
           END
END
BEGIN     
   IF @RPT_WISE=1 
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"   
   ELSE IF @RPT_WISE=2    
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID" 
   ELSE IF @RPT_WISE=3        
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID"    
   ELSE  IF @RPT_WISE=4 OR @RPT_WISE=8    
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.ITEM_ID"   
   ELSE IF @RPT_WISE=5       
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.SCREEN_ID"  
   ELSE IF @RPT_WISE=6 OR @RPT_WISE=7 
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"  
   ELSE IF       @RPT_WISE=9 
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ITT.ITEM_TYPE_ID"  
	ELSE IF @RPT_WISE = 10
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"  
END   

 BEGIN      
   SET NOCOUNT ON;    
      SET @SQL=" SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO,SO.ORDER_DATE,SOD.ITEM_ID,IM.ITEM_NAME,
                 SOD.PENDINGBALES AS BALES,SOD.SCREEN_ID,SM.SCREEN_NAME,SO.TRANSPORT_ID,TM.TRANSPORT_NAME,
                 LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,SO.STATION_ID,SCM.CITY_NAME AS STATION ,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY
                 ,SAM.SALESMAN_NAME AS SALESMAN,ITT.ITEM_TYPE_NAME AS ITEMTYPE,DATEDIFF(D,SO.VCH_DATE,'"+@TODATE+"') AS DAYSDIFF,IM.ITEM_GOODS_TYPE AS GOODSTYPE, CGM.CUST_GRP_NAME AS CUSTOMEGROUP
                 FROM "+@DATABASENAME+"SALES_ORDER SO   
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID 
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID 
                 LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITT ON IM.ITEM_TYPE_ID=ITT.ITEM_TYPE_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID   
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID   
                 LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON SO.TRANSPORT_ID=TM.TRANSPORT_ID  
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SO.STATION_ID=SCM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID 
                 LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
				 LEFT JOIN " +@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                 "+@JOINSQL +"                        
                 WHERE SO.CMP_CODE="+@CMP_CODE+" AND SO.VCH_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' AND PENDINGBALES>0 
                 "+@GOODSTYPESQL+"
                 ORDER BY SO.VCH_DATE     
              "
 PRINT @SQL 
 EXECUTE SP_EXECUTESQL @SQL      

 END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PENDINGSALESORDER_AGEING_SUMMARY]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*  
    PROC_PENDINGSALESORDER_AGEING '2', N'ACC2010_2011.DBO.', N'01/APR/2010', N'31/MAR/2011', N'##3260', 1,''
*/ 
CREATE PROCEDURE [dbo].[PROC_PENDINGSALESORDER_AGEING_SUMMARY] 
(     
  @CMP_CODE NVARCHAR(10),
  @DATABASENAME NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),      
  @TODATE AS NVARCHAR(20),     
  @TEMPTABLE NVARCHAR(20),   
  @RPT_WISE INT ,
  @GOODSTYPE NVARCHAR(4000)   
)  
AS  
DECLARE @SQL  NVARCHAR(4000)  
DECLARE @JOINSQL  NVARCHAR(100) 
DECLARE @TYPESQL NVARCHAR(100)  
DECLARE @MAIN_GROUP_PSQL NVARCHAR(4000)  
DECLARE @GROUBYPSQL NVARCHAR(4000)  
DECLARE @GOODSTYPESQL NVARCHAR(4000)  

SET @JOINSQL=""  
SET @TYPESQL=""    
SET @GOODSTYPESQL=""

BEGIN 
    IF @GOODSTYPE<>"" 
          BEGIN
              SET  @GOODSTYPESQL=" AND IM.ITEM_GOODS_TYPE IN("+@GOODSTYPE+") "
           END
END

BEGIN     
   IF @RPT_WISE=1 
            BEGIN
               SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"   
               SET @MAIN_GROUP_PSQL=" (PARTY + (CASE WHEN PARTYCITY IS NULL OR PARTYCITY='' THEN '' ELSE '-'+PARTYCITY END ))  AS FIRSTGROUP,(PARTY + (CASE WHEN PARTYCITY IS NULL OR PARTYCITY='' THEN '' ELSE '-'+PARTYCITY END )) AS SECONDGROUP"
               SET @GROUBYPSQL=" ,PARTY,PARTYCITY"
           END
   ELSE IF @RPT_WISE=2    
           BEGIN
              SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID" 
              SET @MAIN_GROUP_PSQL=" (AGENT + (CASE WHEN AGENTCITY IS NULL OR AGENTCITY='' THEN '' ELSE '-'+AGENTCITY END ))  AS FIRSTGROUP,(AGENT + (CASE WHEN AGENTCITY IS NULL OR AGENTCITY='' THEN '' ELSE '-'+AGENTCITY END ))   AS SECONDGROUP"
              SET @GROUBYPSQL=" ,AGENT,AGENTCITY"
           END
   ELSE IF @RPT_WISE=3   
           BEGIN     
             SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.AGENT_ID"    
             SET @MAIN_GROUP_PSQL=" (AGENT + (CASE WHEN AGENTCITY IS NULL OR AGENTCITY='' THEN '' ELSE '-'+AGENTCITY END ))  AS FIRSTGROUP,(PARTY + (CASE WHEN PARTYCITY IS NULL OR PARTYCITY='' THEN '' ELSE '-'+PARTYCITY END ))   AS SECONDGROUP"
             SET @GROUBYPSQL=" ,AGENT,AGENTCITY,PARTY,PARTYCITY"
           END
   ELSE  IF @RPT_WISE=4 
           BEGIN
             SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.ITEM_ID"   
              SET @MAIN_GROUP_PSQL=" ITEM   AS FIRSTGROUP,ITEM  AS SECONDGROUP"
              SET @GROUBYPSQL=" ,ITEM"
           END
   ELSE IF @RPT_WISE=5       
          BEGIN
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.SCREEN_ID"  
           SET @MAIN_GROUP_PSQL=" SCREEN AS FIRSTGROUP,SCREEN AS SECONDGROUP"
           SET @GROUBYPSQL=" ,SCREEN"
          END
   ELSE IF @RPT_WISE=6 
        BEGIN
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"  
          SET @MAIN_GROUP_PSQL=" SALESMAN AS FIRSTGROUP,SALESMAN AS SECONDGROUP"
          SET @GROUBYPSQL=" ,SALESMAN"
        END
ELSE IF @RPT_WISE=7 
         BEGIN
          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"  
          SET @MAIN_GROUP_PSQL=" SALESMAN AS FIRSTGROUP,(AGENT + (CASE WHEN AGENTCITY IS NULL OR AGENTCITY='' THEN '' ELSE '-'+AGENTCITY END ))   AS SECONDGROUP"
          SET @GROUBYPSQL=" ,SALESMAN ,AGENT,AGENTCITY"
        END
  ELSE  IF  @RPT_WISE=8    
           BEGIN 
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SOD.ITEM_ID"   
            SET @MAIN_GROUP_PSQL=" ITEM  AS FIRSTGROUP,(PARTY + (CASE WHEN PARTYCITY IS NULL OR PARTYCITY='' THEN '' ELSE '-'+PARTYCITY END ))   AS SECONDGROUP"
            SET @GROUBYPSQL=" ,ITEM,PARTY,PARTYCITY"
          END
   ELSE IF       @RPT_WISE=9 
          BEGIN
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ITT.ITEM_TYPE_ID"  
            SET @MAIN_GROUP_PSQL=" ITEMTYPE   AS FIRSTGROUP,ITEMTYPE AS SECONDGROUP"
            SET @GROUBYPSQL=" ,ITEMTYPE"
          END
	ELSE IF @RPT_WISE = 10
		BEGIN
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID" 
			SET @MAIN_GROUP_PSQL="  CUSTOMERGROUP AS FIRSTGROUP,CUSTOMERGROUP AS SECONDGROUP"
			SET @GROUBYPSQL=" ,CUSTOMERGROUP"
		END
END   

 BEGIN      
   SET NOCOUNT ON;    
      SET @SQL=" 
                 SELECT "+@MAIN_GROUP_PSQL +" ,SUM(BALES) AS BALES,DAYSDIFF,GOODSTYPE FROM (
                 SELECT IM.ITEM_NAME AS ITEM,SOD.PENDINGBALES AS BALES,SM.SCREEN_NAME AS SCREEN,
                 LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY
                 ,SAM.SALESMAN_NAME AS SALESMAN,ITT.ITEM_TYPE_NAME AS ITEMTYPE,DATEDIFF(D,SO.VCH_DATE,'"+@TODATE+"') AS DAYSDIFF
                 ,IM.ITEM_GOODS_TYPE AS GOODSTYPE,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
                 FROM "+@DATABASENAME+"SALES_ORDER SO   
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID 
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID 
                 LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITT ON IM.ITEM_TYPE_ID=ITT.ITEM_TYPE_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID   
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID   
                 LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON SO.TRANSPORT_ID=TM.TRANSPORT_ID  
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER SCM ON SO.STATION_ID=SCM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID   
                 LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID 
                 LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
				 LEFT JOIN " +@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
                 "+@JOINSQL +"                        
                 WHERE SO.CMP_CODE="+@CMP_CODE+" AND SO.VCH_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' AND PENDINGBALES>0 
                 "+@GOODSTYPESQL+"
                 ) AS DETAIL
                 GROUP BY GOODSTYPE,DAYSDIFF "+@GROUBYPSQL+"
              "
 PRINT @SQL 
 EXECUTE SP_EXECUTESQL @SQL      

 END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PENDPROCESSPRODUCTION]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
exec [Proc_PendProcessProduction] '10','Acc2010_2011.dbo.','0','12/Apr/2010','12/Aug/2010',''
*/

CREATE PROCEDURE [dbo].[PROC_PENDPROCESSPRODUCTION]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),    
	@ToDate as Nvarchar(20),    
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;

	    if @Rpt_Wise=0
		Begin
			set @sql="
			select ProcessName,MainGroup,SUM(OutThan) as OutThan,SUM(OutMeter) as OutMeter  from
			(
			select PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
			from  " + @DatabaseName + "processOut POUT 
			Inner Join  " + @DatabaseName + "Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join  " + @DatabaseName + "Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner Join  " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			" + @JoinSql + "
			where POUT.VCHDate >='" + @FromDate + "' and POUT.VCHDate <='" + @ToDate + "'  and POUT.Cmp_Code in ("+ @Cmp_Code +") 
			and PM.OutSide <> 1
            union all
            select PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,F2F.RecThan as OutThan,F2f.RecMeter as OutMeter 
			from  " + @DatabaseName + "finishtofolding f2f 
			Inner Join  " + @DatabaseName + "Process_Master PM ON PM.Process_ID = f2f.Process_ID
			Inner Join  " + @DatabaseName + "Item_Master IM ON f2f.item_Id = IM.item_Id  
			Inner Join  " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			" + @JoinSql + "
			where F2F.VCHDate >='" + @FromDate + "' and F2F.VCHDate <='" + @ToDate + "'  and F2F.Cmp_Code in ("+ @Cmp_Code +") 
            
           

           

			) as a
			Group By ProcessName,MainGroup 
			order by ProcessName,MainGroup 
			"
		end 
  
    	if @Rpt_Wise=1
		Begin
		set @sql="
			select ProcessName,MainGroup,SUM(OutThan) as OutThan,SUM(OutMeter) as OutMeter from
			(
			select PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
			from " + @DatabaseName + "processOut POUT 
			Inner Join " + @DatabaseName + "Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner Join " + @DatabaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			" + @JoinSql + "
			where POUT.VCHDate >='" + @FromDate + "' and POUT.VCHDate <='" + @ToDate + "' and POUT.Cmp_Code in ("+ @Cmp_Code +") and PM.OutSide <> 1

            union all


			select PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,F2F.RecThan as OutThan,F2f.RecMeter as OutMeter 
			from " + @DatabaseName + "finishtofolding F2F
			Inner Join  " + @DatabaseName + "Process_Master PM ON PM.Process_ID = f2f.Process_ID
			Inner Join  " + @DatabaseName + "Item_Master IM ON f2f.item_Id = IM.item_Id  
			Inner Join " + @DatabaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			 " + @JoinSql + "
			where F2F.VCHDate >='" + @FromDate + "' and F2F.VCHDate <='" + @ToDate + "'  and F2F.Cmp_Code in ("+ @Cmp_Code +") 

			) as a
			Group By ProcessName,MainGroup 
			order by ProcessName,MainGroup "
		end 

		execute Sp_Executesql @sql
        Print @sql
end




















GO

