/* 
-- =============================================
-- CREATE_AUTHOR	: <SANJAY>
-- CREATE_DATE		: <22/04/2019,2:28 PM>
-- EDIT_AUTHOR		: <SN>
-- EDIT_DATE		: <22/04/2019,2:28 PM>
-- REPORT_NAME		: <PERFORMA_INVOICE_MASTER>
-- REPORT_FORM		: <PERFORMA INVOICE MASTER>
-- =============================================
PROC_PERFORMA_INVOICE N'1', N'Acc2020_2021.Dbo.', 1,10

*/
CREATE PROCEDURE [dbo].[PROC_PERFORMA_INVOICE]
(
	@CMP_CODE NVARCHAR(10),
	@DATABASENAME NVARCHAR(50),
	@FROMDOC NVARCHAR(50),
	@TODOC NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQLSN AS NVARCHAR(3999)
BEGIN

SET @SQL=""
SET @SQLSN=""

BEGIN
SET @SQL="
		SELECT SI.PER_INV_BILL_NO AS BILLNO,SI.PER_INV_VDATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY
		,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2,UPPER(LM.LGR_ADD3)AS LGR_ADD3
		,UPPER(AGM.LGR_NAME) AS AGENTNAME ,SID.SAL_INV_BALENO AS BALENO,
		IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_METER AS METER,SAL_INV_AMOUNT AS AMOUNT
		,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
		,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3
		,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,
		SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,UPPER(SM.STATE_NAME) AS  PARTYSTATE,UPPER(SM.STATE_CODE)AS PARTYSTATECODE,
		UPPER(PCM.CITY_DISTRICT)AS CITY_DISTRICT,LM.CITY_PINCODE,UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,
		ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY,
		ISNULL(CMP.CMP_STATE,'') AS CMP_STATE,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.GSTINNO AS CMP_GSTINNO,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,
		CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,UPPER(ACM.CITY_NAME) AS AGENTCITY,LM.GSTINNO AS LGR_GSTINNO,LM.LGR_DISTRICT,CMP.cmp_StateCode as cmpStateCode,
		SI.AMT_WORD as AMT_WORD,ISNULL(SI.Sal_Inv_Less1_Set,0) AS Sal_Inv_Less1_Set,ISNULL(SI.Sal_Inv_Less2_Set,0) AS Sal_Inv_Less2_Set,
		ISNULL(SI.Sal_Inv_Less3_Set,0) AS Sal_Inv_Less3_Set,ISNULL(SI.Sal_Inv_Less4_Set,0) AS Sal_Inv_Less4_Set,ISNULL(SI.Sal_Inv_Less5_Set,0) AS Sal_Inv_Less5_Set,
		ISNULL(SI.Sal_Inv_Add1_Set,0)Sal_Inv_Add1_Set,ISNULL(SI.Sal_Inv_Add2_Set,0)Sal_Inv_Add2_Set,ISNULL(SI.Sal_Inv_Add3_Set,0)Sal_Inv_Add3_Set,
		ISNULL(SI.Sal_Inv_Add4_Set,0)Sal_Inv_Add4_Set,ISNULL(SI.Sal_Inv_Add5_Set,0)Sal_Inv_Add5_Set,(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)as ADDBEFOREVALUE,
		(SI.Sal_Inv_GrossTotal-SI.Sal_Inv_LessTotal+(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)) AS TAXABLEAMT,ISNULL(LM.IECODE,0)AS IECODE,ISNULL(SI.EXPTYPE,'')EXPTYPE
		,cmp_Fc_Add1,cmp_Fc_Add2,cmp_Fc_City,cmp_Fc_Pincode,cmp_Fc_State,ISNULL(CMP.BINNO,'') AS CMP_BINNO,ISNULL(CMP.IECNO,'') AS CMPIECNO,cmp_Email,CMP.CinNo as CinNo,
		EXP_TERM1,EXP_TERM2,EXP_TERM3,EXP_TERM4,EXP_TERM5,EXP_TERM6,EXP_TERM7,EXP_TERM8,EXP_TERM9,EXP_CUST_OFF,HM.HSN_NAME AS HSNCODE,EXP_HSN
		,ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,
		CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
		COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,
		CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,
		EBM.Bank_Name,EBM.Bank_BRANCH,EBM.Bank_AccNo,EBM.Bank_IfscCode,EBM.Bank_AdCode,EBM.SWIFTCODE,CMP.ARNNO 
		"
SET @SQLSN="
		FROM "+@DATABASENAME+"PERFORMA_INVOICE_MASTER SI
		INNER JOIN "+@DATABASENAME+"PERFORMA_INVOICE_DETAIL SID ON SID.PER_INV_ID=SI.PER_INV_ID AND SI.FLAG=SID.FLAG
		AND SI.CMP_CODE = SID.CMP_CODE AND SI.FLAG = SID.FLAG
		INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE 
		LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID	
		LEFT JOIN " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=IM.HSN_ID	
		LEFT JOIN " + @DATABASENAME +"CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=SI.Consignee_Id	
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id
		LEFT JOIN " + @DATABASENAME +"EXPORTBANK_MASTER EBM ON EBM.BANK_ID = SI.EXPORTBANK_ID
		WHERE SI.CMP_CODE="+ @CMP_CODE +" AND SI.PER_INV_BILL_NO BETWEEN "+@FROMDOC+" AND "+@TODOC+"
		ORDER BY   SI.PER_INV_BILL_NO,SID.SAL_INV_BALENO"	
END	

EXEC (@SQL+@SQLSN)
PRINT (@SQL+@SQLSN)
END



























GO

/****** Object:  StoredProcedure [dbo].[PROC_POPLINE_PRINT_FOLD_ENTRY]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author:		<Author,,Name>
-- ALTER date: 12/may/2012
-- Description:	FOR POPLIN AND PRINT FOLD ENTRY PRINT OUT
-- =============================================
PROC_POPLINE_PRINT_FOLD_ENTRY 2,'ACC2010_2011.DBO.','1','100',7
*/

CREATE PROCEDURE [dbo].[PROC_POPLINE_PRINT_FOLD_ENTRY]
(
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromBillNo NVARCHAR(50),
@ToBillNo NVARCHAR(50),
@RptType INT
)
AS

DECLARE @STRSQL NVARCHAR(4000) SET @STRSQL=""
DECLARE @STRCON NVARCHAR(4000) SET @STRCON=""

IF @RptType=6
	SET @STRCON=" AND FE.FormFlag='POPLIN' "
ELSE IF @RptType=7
	SET @STRCON=" AND FE.FormFlag='PRINT' "

BEGIN	
	SET NOCOUNT ON;
SET @STRSQL ="
SELECT FE.FOLDNO,FE.VCHDATE,FE.CONFNO,FE.CONFDATE,LM.LGR_NAME,TM.TRANSPORT_NAME,CM.CITY_NAME AS STATIONNAME
,IM.ITEM_NAME,SM.SCREEN_NAME,FE.BALES,FE.DELSCHEDULE,FE.SCHEDULESCHEMA,FE.FINISH,FE.FOLDING,FE.SAMPLE,FE.PROCESS,
FD.COLOR_NO,FD.COLOR_NAME,FD.PIECE,FE.RATE,
FD.DNo,KDNo,No1,No2,No3,No4,No5,No6,FD.BALES AS DETAILBALES,FE.NARRATION
FROM "+@DatabaseName +" FOLDENTRY FE
LEFT JOIN "+@DatabaseName +" FOLDENTRYDETAIL FD ON FE.FOLDENTRY_ID=FD.FOLDENTRY_ID
INNER JOIN "+@DatabaseName +" LEDGER_MASTER LM ON FE.LGR_ID=LM.LGR_ID
INNER JOIN "+@DatabaseName +" TRANSPORT_MASTER TM ON FE.TRANSPORT_ID=TM.TRANSPORT_ID
LEFT JOIN "+@DatabaseName +" CITY_MASTER CM ON FE.CITY_ID=CM.CITY_ID
INNER JOIN "+@DatabaseName +" ITEM_MASTER IM ON FE.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DatabaseName +" SCREEN_MASTER SM ON SM.SCREEN_ID=FE.SCREEN_ID
WHERE FE.CMP_CODE="+@Cmp_Code+" AND FE.FOLDNO BETWEEN "+@FromBillNo+" AND "+@ToBillNo+"
"+@STRCON+"
"
    
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PREVYEARDISCOUNT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_PREVYEARDISCOUNT]
(
@DATABASENAME AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(100),
@TEMPTABLE AS NVARCHAR(100),
@ASONDATE AS NVARCHAR(20),
@CRITERIA AS INT,
@STARTDATE AS NVARCHAR(20),
@ENDDATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)
SET @SQLJOIN=""
SET @ORDERBYSQL=""

BEGIN
IF @CRITERIA=1 
BEGIN
SET @SQLJOIN=" INNER JOIN  "+ @TEMPTABLE + " TT ON TT.CODE=PD.LGR_ID "        
SET @ORDERBYSQL="LM.LGR_NAME,LM.LGR_ID,"
END
ELSE IF @CRITERIA=2            
BEGIN
SET @SQLJOIN=" INNER JOIN  " + @TEMPTABLE + " TT ON TT.CODE=PD.AGENT_ID "
SET @ORDERBYSQL="ALM.LGR_NAME,ALM.LGR_ID,LM.LGR_NAME,LM.LGR_ID,"
END

ELSE IF @CRITERIA=3    
BEGIN
SET @SQLJOIN=""     
SET @ORDERBYSQL="LM.LGR_NAME,LM.LGR_ID,"
END 
END

SET @SQL=""
BEGIN
SET NOCOUNT ON;    
SET  @SQL="
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
PD.VCODE,PD.BILL_NO AS BILLNO,PD.DATE,PD.BILL_AMOUNT,PD.JOBFLAG ,
(SUM(ISNULL(ADJ.DISCOUNT,0))+SUM(ISNULL(ADJ.OTHERLESS,0))) AS DISCOUNT               --+SUM(ISNULL(ADJ.INTEREST,0)))
FROM  "+@DATABASENAME +"PARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME +"ADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILL_NO AND ADJ.FLAG=PD.JOBFLAG
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID "
+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'               
GROUP BY LM.LGR_NAME,LM.LGR_ID,ALM.LGR_NAME,ALM.LGR_ID,CM.CITY_NAME,ACM.CITY_NAME,
PD.VCODE,PD.BILL_NO,PD.DATE,PD.BILL_AMOUNT,PD.JOBFLAG 
HAVING (SUM(ISNULL(ADJ.DISCOUNT,0))+SUM(ISNULL(ADJ.OTHERLESS,0)))>0   --+SUM(ISNULL(ADJ.INTEREST,0))
ORDER BY "+@ORDERBYSQL+"PD.VCODE

"
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[Proc_PREVYEARDISCOUNT_DEBTOR]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
