SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_PREVYEARDISCOUNT_DEBTOR 'ACC2010_2011.DBO.',10,'','28/FEB/2011',4,'01/APR/2010'
*/
CREATE PROCEDURE [dbo].[Proc_PREVYEARDISCOUNT_DEBTOR]
(
@DATABASENAME AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(100),
@TEMPTABLE AS NVARCHAR(100),
@ASONDATE AS NVARCHAR(20),
@CRITERIA AS INT,
@STARTDATE AS NVARCHAR(20),
@ENDDATE AS NVARCHAR(20)
)	


AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)
SET @SQLJOIN=""
SET @SQL=""
SET @ORDERBYSQL=""

BEGIN
IF @CRITERIA=1 
BEGIN
SET @SQLJOIN=" INNER JOIN  "+ @TEMPTABLE + " TT ON TT.CODE=PD.LGR_ID "
SET @ORDERBYSQL="PARTY,PATRYID,"
END

ELSE IF @CRITERIA=2            
BEGIN
SET @SQLJOIN=" INNER JOIN  " + @TEMPTABLE + " TT ON TT.CODE=PD.AGENT_ID "
SET @ORDERBYSQL="AGENT,AGENTID,PARTY,PATRYID,"
END

ELSE IF @CRITERIA=4    
BEGIN
SET @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.SUPP_GRP_ID"     
SET @ORDERBYSQL="SUPPLIERNAME,SUPPGRPID,PARTY,PATRYID,"
END

ELSE IF @CRITERIA=3    
BEGIN
SET @SQLJOIN=""
SET @ORDERBYSQL="PARTY,PATRYID," 	
END
END 

BEGIN

SET NOCOUNT ON;
SET @SQL=" SELECT  PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,VCODE,BILLNO,DATE,AMOUNT,
SUM(DISCOUNT) AS DISCOUNT,SUPPLIERNAME,SUPPGRPID
FROM (
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,
CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
PD.VCODE,PD.BILLNO AS BILLNO,PD.DATE,PD.AMOUNT ,
(ISNULL(ADJ.DISCOUNT,0)+ ISNULL(ADJ.RD,0)) AS DISCOUNT,ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERNAME,
ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID
FROM  "+@DATABASENAME+"PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+"PURADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILLNO AND ADJ.FLAG=PD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
"+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN ("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'
) AS A GROUP BY PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,VCODE,BILLNO,DATE,AMOUNT,SUPPLIERNAME,SUPPGRPID  
HAVING SUM(DISCOUNT)>0
ORDER BY "+@ORDERBYSQL+"VCODE
"	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

