END	
IF @CRITERIA=3    
BEGIN
SET @SQLJOIN="" 	
SET @SQLORDER = " ORDER BY PARTY,PATRYID "
END
END 

BEGIN
SET NOCOUNT ON;
IF  @CRITERIA IN (1,3)
BEGIN 
SET @SQL=" SELECT  PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,
SUM(DISCOUNT) AS DISCOUNT,SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,SUM(BALANCE) AS BALANCE,
ISNULL(SUPPLIERNAME,'') AS SUPPLIERNAME,SUPPGRPID
FROM (
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
(ISNULL(PD.AMOUNT,0)) AS INVOICEAMOUNT ,(((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0))) AS DISCOUNT,
(ISNULL(ADJ.ADJUSTAMT,0)) AS RECEIVEAMOUNT,(((ISNULL(PD.AMOUNT,0))- (((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0)))) - (ISNULL(ADJ.ADJUSTAMT,0))) AS BALANCE,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERNAME,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID
FROM  "+@DATABASENAME+"PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+"PURADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILLNO AND ADJ.FLAG=PD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
"+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN ("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'
) AS A GROUP BY PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,SUPPLIERNAME,SUPPGRPID  
HAVING SUM(DISCOUNT)>0 "+@SQLORDER+" "	
END
ELSE IF @CRITERIA=2
BEGIN	
SET @SQL=" SELECT  MAX(PARTY) AS PARTY,MAX(PATRYID) AS PARTYID,AGENT,AGENTID,MAX(PARTYCITY) AS PARTYCITY,
AGENTCITY,SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,SUM(DISCOUNT) AS DISCOUNT,SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,
SUM(BALANCE) AS BALANCE,MAX(ISNULL(SUPPLIERNAME,'')) AS SUPPLIERNAME,MAX(SUPPGRPID) AS SUPPGRPID
FROM (
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
(ISNULL(PD.AMOUNT,0)) AS INVOICEAMOUNT ,(((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0))) AS DISCOUNT,
(ISNULL(ADJ.ADJUSTAMT,0)) AS RECEIVEAMOUNT,(((ISNULL(PD.AMOUNT,0))- (((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0)))) - (ISNULL(ADJ.ADJUSTAMT,0))) AS BALANCE,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERNAME,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID
FROM  "+@DATABASENAME+"PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+"PURADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILLNO AND ADJ.FLAG=PD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
"+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN ("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'
) AS A GROUP BY AGENT,AGENTID,AGENTCITY  
HAVING SUM(DISCOUNT)>0 "+@SQLORDER+" "	
END
ELSE IF @CRITERIA=4
BEGIN	
SET @SQL=" SELECT  MAX(PARTY) AS PARTY,MAX(PATRYID) AS PARTYID,MAX(AGENT) AS AGENT,MAX(AGENTID) AS AGENTID,
MAX(PARTYCITY) AS PARTYCITY,MAX(AGENTCITY) AS AGENTCITY,SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,
SUM(DISCOUNT) AS DISCOUNT,SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,SUM(BALANCE) AS BALANCE,
ISNULL(SUPPLIERNAME,'') AS SUPPLIERNAME,SUPPGRPID
FROM (
SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,
CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
(ISNULL(PD.AMOUNT,0)) AS INVOICEAMOUNT ,(((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0))) AS DISCOUNT,
(ISNULL(ADJ.ADJUSTAMT,0)) AS RECEIVEAMOUNT,(((ISNULL(PD.AMOUNT,0))- (((ISNULL(ADJ.DISCOUNT,0)))+ (ISNULL(ADJ.RD,0)))) - (ISNULL(ADJ.ADJUSTAMT,0))) AS BALANCE,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERNAME,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID
FROM  "+@DATABASENAME+"PURPARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME+"PURADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILLNO AND ADJ.FLAG=PD.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
"+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN ("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'
) AS A GROUP BY SUPPLIERNAME,SUPPGRPID
HAVING SUM(DISCOUNT)>0 "+@SQLORDER+" "
END

END
EXECUTE SP_EXECUTESQL @SQL
