/*
-- =============================================
-- AUTHOR:		HIREN B DOSHI
-- ALTER_DATE: 03/08/2013
-- DESCRIPTION:	THIS PROCEDURE USED FOR PREVIOUS YEARDISCOUNT DEBTORS SUMMARY
-- REPORTNAME : PREYEARDISCOUNTSUMM.RPT
-- =============================================
PROC_PREVYEARDISCOUNT_SUMMARY 'ACC2013_2014.DBO.', '1', '##1624', '03/AUG/2013', 1, '01/APR/2013','31/MARCH/2013'
*/
CREATE PROCEDURE [dbo].[PROC_PREVYEARDISCOUNT_SUMMARY]
(
@DATABASENAME AS NVARCHAR(100),
@CMP_CODE AS NVARCHAR(100),
@TEMPTABLE AS NVARCHAR(100),
@ASONDATE AS NVARCHAR(20),
@CRITERIA AS INT,
@STARTDATE AS NVARCHAR(20),
@ENDDATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLORDER AS NVARCHAR(1000)
DECLARE @SQLMAINGRP AS NVARCHAR(4000)

SET @SQLJOIN=""
SET @SQL=""
SET @SQLORDER = ""
SET @SQLMAINGRP = ""
BEGIN
IF @CRITERIA=1 
BEGIN
SET @SQLMAINGRP = " SELECT PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,MAX(BILLNO) AS BILLNO,MAX(DATE) AS DATE, 
SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,MAX(JOBFLAG) AS JOBFLAG,SUM(DISCOUNT) AS DISCOUNT,
SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,(SUM(INVOICEAMOUNT) - (SUM(RECEIVEAMOUNT)) -   SUM(DISCOUNT)) AS BALANCE FROM ( "
SET @SQLJOIN=" INNER JOIN  "+ @TEMPTABLE + " TT ON TT.CODE=PD.LGR_ID "        
SET @SQLORDER = " ORDER BY PARTY,PATRYID "
END
IF @CRITERIA=2            
BEGIN
SET @SQLMAINGRP = " SELECT MAX(PARTY) AS PARTY,MAX(PATRYID) AS PARTYID,AGENT,AGENTID,MAX(PARTYCITY) AS PARTYCITY,AGENTCITY,MAX(BILLNO) AS BILLNO,MAX(DATE) AS DATE, 
SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,MAX(JOBFLAG) AS JOBFLAG,SUM(DISCOUNT) AS DISCOUNT,
SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,(SUM(INVOICEAMOUNT) - (SUM(RECEIVEAMOUNT)) -   SUM(DISCOUNT)) AS BALANCE FROM ( "
SET @SQLJOIN=" INNER JOIN  " + @TEMPTABLE + " TT ON TT.CODE=PD.AGENT_ID "
SET @SQLORDER = " ORDER BY AGENT,AGENTID,PARTY,PARTYID "
END
IF @CRITERIA=3    
BEGIN
SET @SQLMAINGRP = " SELECT PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY,MAX(BILLNO) AS BILLNO,MAX(DATE) AS DATE, 
SUM(INVOICEAMOUNT) AS INVOICEAMOUNT,MAX(JOBFLAG) AS JOBFLAG,SUM(DISCOUNT) AS DISCOUNT,
SUM(RECEIVEAMOUNT) AS RECEIVEAMOUNT,(SUM(INVOICEAMOUNT) - (SUM(RECEIVEAMOUNT)) -   SUM(DISCOUNT)) AS BALANCE FROM ( "
SET @SQLJOIN=""
SET @SQLORDER = " ORDER BY PARTY,PATRYID "     
END
END 
BEGIN
SET NOCOUNT ON;    
IF @CRITERIA IN (1,3) 
BEGIN

SET  @SQL=" "+@SQLMAINGRP+" SELECT LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,CM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
(PD.BILL_NO) AS BILLNO,MAX(PD.DATE) AS DATE,(ISNULL(PD.BILL_AMOUNT,0)) AS INVOICEAMOUNT,(PD.JOBFLAG) AS JOBFLAG ,
(SUM(ISNULL(ADJ.DISCOUNT,0))+SUM(ISNULL(ADJ.OTHERLESS,0))) AS DISCOUNT,SUM(ISNULL(ADJ.ADJUSTAMT,0)) AS RECEIVEAMOUNT
FROM  "+@DATABASENAME +"PARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME +"ADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILL_NO AND ADJ.FLAG=PD.JOBFLAG
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID "
+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'               
GROUP BY LM.LGR_NAME,LM.LGR_ID,ALM.LGR_NAME,ALM.LGR_ID,CM.CITY_NAME,ACM.CITY_NAME,PD.BILL_NO,PD.JOBFLAG,PD.BILL_AMOUNT
) AS DETAIL
GROUP BY PARTY,PATRYID,AGENT,AGENTID,PARTYCITY,AGENTCITY "+@SQLORDER+"  "
END
ELSE IF @CRITERIA=2
BEGIN
SET  @SQL=" "+@SQLMAINGRP+" SELECT MAX(LM.LGR_NAME) AS PARTY,MAX(LM.LGR_ID) AS PATRYID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENTID,MAX(CM.CITY_NAME) AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,
(PD.BILL_NO) AS BILLNO,MAX(PD.DATE) AS DATE,(ISNULL(PD.BILL_AMOUNT,0)) AS INVOICEAMOUNT,MAX(PD.JOBFLAG) AS JOBFLAG ,
(SUM(ISNULL(ADJ.DISCOUNT,0))+SUM(ISNULL(ADJ.OTHERLESS,0))) AS DISCOUNT,SUM(ISNULL(ADJ.ADJUSTAMT,0)) AS RECEIVEAMOUNT

FROM  "+@DATABASENAME +"PARTYDETAIL PD 
LEFT JOIN "+@DATABASENAME +"ADJMASTER ADJ ON ADJ.VCODE=PD.VCODE AND ADJ.BILLNO=PD.BILL_NO AND ADJ.FLAG=PD.JOBFLAG
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME +"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID
LEFT JOIN "+@DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID "
+ @SQLJOIN + "
AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.LGR_ID=PD.LGR_ID               
WHERE ADJ.RECDATE BETWEEN '"+@STARTDATE+"' AND '"+@ASONDATE +"' AND PD.CMP_CODE IN("+@CMP_CODE + ")
AND PD.DATE<='"+@ENDDATE+"'               
GROUP BY ALM.LGR_NAME,ALM.LGR_ID,ACM.CITY_NAME,PD.BILL_NO,PD.JOBFLAG,PD.BILL_AMOUNT
) AS DETAIL
GROUP BY AGENT,AGENTID,AGENTCITY "+@SQLORDER+" "


END

END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

