CREATE PROCEDURE [dbo].[PROC_PRICELIST]
(
@DATABASENAME AS NVARCHAR(50),
@APPDATE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@CMP_CODE AS NVARCHAR(20)
)	
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
	SET NOCOUNT ON;
         SET @SQL="  SELECT PL.ITEM_GRP_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,PL.ITEM_ID ,IM.ITEM_NAME AS ITEM,
PL.ITEM_CUT,PL.RATE,UM.UNIT_NAME
FROM "+ @DATABASENAME+" PRICELIST PL
INNER JOIN "+ @DATABASENAME+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=PL.ITEM_GRP_ID
INNER JOIN "+ @DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=PL.ITEM_ID
INNER JOIN "+ @DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID	
INNER JOIN "+ @DATABASENAME+ @TEMPTABLE +" TT ON IGM.ITEM_GRP_ID=TT.CODE
WHERE PL.APPDATE='"+@APPDATE+"' AND PL.CMP_CODE IN('"+@CMP_CODE +"')
AND PL.RATE>0                     
"

EXEC SP_EXECUTESQL @SQL
PRINT @SQL

END




















