-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[PROC_PROCESS_ISSUE_RECEIVE_REGI_ASONDATE]
(
@Cmp_Code Nvarchar(100),
@DatabaseName Nvarchar(500),
@FromDate  Nvarchar(20),
@ToDate Nvarchar(20),
@TempTable Nvarchar(20),	
@RptWise Int,
@RptType Int,
@Status Int
)
AS
DECLARE @ISSUE AS NVARCHAR(3999)
DECLARE @ISSUE1 AS NVARCHAR(3999)
DECLARE @RECEIVE AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(3999)
DECLARE @STRORDERBY AS NVARCHAR(3999)
DECLARE @Stat as nvarchar(90)
SET @Stat=""
SET @ISSUE=""
SET @ISSUE1=""
SET @RECEIVE=""
SET @SELECTED=""
SET @STRORDERBY=""

IF @Status IN (1)
	BEGIN
		SET @Stat=" AND PID.PENDINGTHAN=0"
	END
ELSE IF @Status IN (2)
	BEGIN
		SET @Stat=" AND PID.PENDINGTHAN>0"
	END
ELSE
	BEGIN
		SET @Stat=""
	END

BEGIN
	IF @RptWise IN (1)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (2)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise IN (3)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,PM.PROCESS_NAME,PM.PROCESS_ID,"
		END
	ELSE IF @RptWise IN (4)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.LOT_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LOM.LOT_NAME,LOM.LOT_ID,"
		END
	ELSE IF @RptWise IN (5)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.LOT_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LOM.LOT_NAME,LOM.LOT_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (6)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise = 7
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (8)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,LOM.LOT_NAME,LOM.LOT_ID,"
		END
	ELSE IF @RptWise IN (9)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,PM.PROCESS_NAME,PM.PROCESS_ID,"
		END
	ELSE IF @RptWise IN (10)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.PROCESS_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  PM.PROCESS_NAME,PM.PROCESS_ID,"
		END
	ELSE IF @RptWise IN (11)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.PROCESS_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  PM.PROCESS_NAME,PM.PROCESS_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
		ELSE IF @RptWise IN (12)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.DOCNO=" + @TempTable + ".CODE"
			SET @STRORDERBY=" "
		END
		ELSE IF @RptWise IN (13)
		BEGIN 
		     IF @RptType=1
		     BEGIN
		     SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.FROMLGR_ID=" + @TempTable + ".CODE"
		     SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,"
		     END
		     ELSE IF @RptType=2
		     BEGIN
		     SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.TOLGR_ID=" + @TempTable + ".CODE"
		     SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,"
		     END
	    END

SET NOCOUNT ON;
SET @ISSUE="SELECT DOCNO as Docno,MAX(DATE) AS Date,LGR_NAME,LGR_ID,MAX(LOTNO) AS LOTNO,LOT_ID as LotId,
        MARKA as MARKA,MAX(FRPARTY) as FRPARTY,MAX(RECNO) AS RECNO,ITEM_ID as ItemId,
        ITEM_NAME as ItemName,HSN_ID as HsnId,HSN_NAME as HsnName,PROCESS_NAME,PROCESS_ID,
        SUM(PCS) AS PCS,SUM(ISSUEQTY) AS ISSUEQTY,SUM(RECQTY) AS RECQTY,SUM(RATE) AS RATE,SUM(AMOUNT)AS AMOUNT,
        MAX( LGR_NAME) AS TOPARTY,(SUM(ISSUEQTY)-SUM(RECQTY))AS PENDINGQTY
        FROM(
    	SELECT PI.DOCNO,CONVERT(NVARCHAR,PI.VCHDATE,103)DATE,LM.LGR_NAME,LM.LGR_ID,LOTNO,LOM.LOT_ID,LOM.LOT_NAME AS MARKA,FLM.Lgr_Name AS FRPARTY,PI.RecNo,
    	IM.ITEM_ID,IM.ITEM_NAME,HM.HSN_ID,HM.HSN_NAME,PM.PROCESS_NAME,PM.PROCESS_ID,PCS,ISNULL(PID.QTY,0) AS ISSUEQTY,0 AS RECQTY,RATE,AMOUNT,TLM.LGR_NAME AS TOPARTY
		FROM "+ @DATABASENAME+ "PROCESSISSUE PI
		INNER JOIN  "+ @DATABASENAME +"PROCESSISSUE_DETAIL PID ON PID.PROCESSISSUEID=PI.PROCESSISSUEID 
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
		INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
		LEFT  JOIN " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=PID.HSN_ID
		LEFT  JOIN " + @DATABASENAME +"LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
		LEFT  JOIN " + @DATABASENAME +"PROCESS_MASTER PM ON PI.PROCESS_ID=PM.PROCESS_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PI.CMP_CODE= CMP.CMP_CODE 
		LEFT  JOIN " + @DATABASENAME +"LEDGER_MASTER FLM ON PI.FromLgr_Id=FLM.Lgr_Id  
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER TLM ON TLM.LGR_ID = PI.TOLGR_ID   
		"+@SELECTED+"
		WHERE PI.CMP_CODE="+ @CMP_CODE +" "+@Stat+" AND PI.VchDate <= '" + @ToDate + "'
		UNION ALL
		"   
SET @ISSUE1 = "
        SELECT PID.CHALLNNO,CONVERT(NVARCHAR,PI.VCHDATE,103)DATE,LM.LGR_NAME,LM.LGR_ID,CHALLNNO AS LOTNO,LOM.LOT_ID,LOM.LOT_NAME AS MARKA,FLM.Lgr_Name AS FRPARTY,PI.RecNo,
    	IM.ITEM_ID,IM.ITEM_NAME,HM.HSN_ID,HM.HSN_NAME,PM.PROCESS_NAME,PM.PROCESS_ID,0 AS PCS,0 AS ISSUEQTY,ISNULL(PID.QTY,0) AS RECQTY,RATE,AMOUNT,TLM.LGR_NAME AS TOPARTY	
		FROM "+ @DATABASENAME+ "PROCESSRECEIVE PI
		INNER JOIN  "+ @DATABASENAME +"PROCESSRECEIVE_DETAIL PID ON PID.PROCESSRECEIVEID=PI.PROCESSRECEIVEID 
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
		INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
		LEFT  JOIN " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=PID.HSN_ID
		LEFT  JOIN " + @DATABASENAME +"LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PI.CMP_CODE= CMP.CMP_CODE     
		LEFT  JOIN " + @DATABASENAME +"PROCESS_MASTER PM ON PI.PROCESS_ID=PM.PROCESS_ID
		LEFT  JOIN " + @DATABASENAME +"LEDGER_MASTER FLM ON PI.FromLgr_Id=FLM.Lgr_Id 
	    LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER TLM ON TLM.LGR_ID = PI.TOLGR_ID
		"+@SELECTED+"
		WHERE PI.CMP_CODE="+ @CMP_CODE +" AND PI.VCHDATE <='" + @ToDate + "'
        ) AS DETAIL
        GROUP BY DOCNO,LGR_NAME,LGR_ID,PROCESS_ID,PROCESS_NAME,LOT_ID,MARKA,ITEM_ID,ITEM_NAME,HSN_ID,HSN_NAME
"   
END	


IF @RptType=1
	BEGIN		
		PRINT @ISSUE
		PRINT @ISSUE1
		EXEC (@ISSUE + @ISSUE1)
	END


GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSBILL]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 23/09/2013
-- Description:	THIS PROCEDURE USED FOR PROCESS BILL REPORT 
-- ReportName : PROCESSBILL.RPT
-- =============================================
PROC_PROCESSBILL 1,'ACC2013_2014.DBO.',0,'',1
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSBILL]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME  NVARCHAR(50),   
	@PROCESSID NVARCHAR(50),
	@TEMPTABLE  NVARCHAR(50),
	@RPT_WISE INT
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @PROCESSSQL AS NVARCHAR(1000)
DECLARE @SQLMAIN AS NVARCHAR(4000)
DECLARE @SQLGROUP AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""
SET @PROCESSSQL =""
SET @SQLMAIN = ""
SET @SQLGROUP = "" 
BEGIN
    IF @RPT_WISE=1
        BEGIN
             SET @JOINSQL="INNER JOIN " +@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
			 SET @SQLMAIN = " SELECT LOTNO,VCHDATE,PARTY,PARTYCITY,MAX(BILLNO) AS BILLNO,
							 PROCESS AS PROCESS,THAN AS THAN,SUM(AMOUNT) AS AMOUNT,MAX(CMP_ALIAS) AS CMP_ALIAS  FROM ( "
			 SET @SQLGROUP = " ) AS DETAIL
							 GROUP BY LOTNO,VCHDATE,PARTY,PARTYCITY,PROCESS,THAN
							 ORDER BY VCHDATE,LOTNO,PARTY,PROCESS"
        END


IF @PROCESSID!="0"
   BEGIN
        SET @PROCESSSQL =" AND PM.PROCESS_ID="+@PROCESSID
   END

END
BEGIN
	SET NOCOUNT ON;
	SET @SQL = " "+@SQLMAIN+" SELECT PRI.LOTNO,PRI.VCHDATE,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,
			     ISNULL(PUI.BILLNO,'') AS BILLNO,PM.PROCESS_NAME AS PROCESS,PRI.DELTHAN AS THAN,PID.AMOUNT,CMP.CMP_ALIAS
				 FROM "+@DATABASENAME+" PROCESSIN PRI
				 LEFT JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID ON PID.LOTNO = PRI.LOTNO AND PID.CMP_CODE = PRI.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PUI ON PUI.PURCHASEINVID = PID.PURCHASEINVID AND PID.FLAG = PUI.FLAG AND PUI.PROCESS_ID = PRI.IN_PROCESS_ID AND PUI.LGR_ID = PRI.IN_LGR_ID
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PRI.IN_LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID=PRI.IN_PROCESS_ID 
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PRI.CMP_CODE
				 "+@JOINSQL+"
			     WHERE PRI.CMP_CODE IN ("+@CMP_CODE+") "+@PROCESSSQL+"
				 UNION ALL
				 SELECT PRI.LOTNO,PRI.VCHDATE,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,
			     '' AS BILLNO,PM.PROCESS_NAME AS PROCESS,PRI.DELTHAN AS THAN,0 AS AMOUNT,CMP.CMP_ALIAS
				 FROM "+@DATABASENAME+" PROCESSIN PRI
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PRI.IN_LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID=PRI.IN_PROCESS_ID 
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE=PRI.CMP_CODE
				 "+@JOINSQL+"
			     WHERE PRI.CMP_CODE IN ("+@CMP_CODE+") "+@PROCESSSQL+" "+@SQLGROUP+"
				 "
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

