/* 
 exec Proc_ProcessByParty '10','Acc2010_2011.dbo.','12/Apr/2010','12/Aug/2010',''
*/

CREATE PROCEDURE [dbo].[PROC_PROCESSBYPARTY]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @FromDate as Nvarchar(20),    
	@ToDate as Nvarchar(20),    
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code = LM.LGR_ID"

begin
    	SET NOCOUNT ON;
		Begin
			set @sql="
				select PIN.LotNo AS LotNo,PIN.In_Process_ID,PM.Process_Name as ProcessName,LA.VchDate as LotDate,PIN.Item_ID as ItemID,IM.Item_name as ItemName,
				PIN.Weaver_ID as WeaverID, WM.Weaver_Name as WeaverName,PIN.VchDate as IssueDate,
				PIN.DelThan as Than, PIN.DelThan  as Total,PIN.In_GpassNo as Ref,LM.Lgr_Name as PartyName
				from "+ @DatabaseName+"ProcessIn PIN
				INNER JOIN "+ @DatabaseName+"LotAllocation LA ON PIN.LotNo = LA.LotNo and PIN.Cmp_Code = LA.Cmp_Code 
				Inner Join "+ @DatabaseName+"Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
				Inner Join "+ @DatabaseName+"Item_Master IM ON PIN.item_Id = IM.item_Id  
				Left Join "+ @DatabaseName+"Weaver_Master WM ON PIN.Weaver_ID = WM.Weaver_ID  
				Inner Join "+ @DatabaseName+"Ledger_Master LM ON PIN.In_LGR_ID = LM.LGR_ID 		
				" + @JoinSql + "
				where PIN.VCHDate >='" + @FromDate + "' and PIN.VCHDate <='" + @ToDate + "'  and PIN.Cmp_Code in ("+ @Cmp_Code +") 
				and PM.OutSide <> 1
				order By  LM.Lgr_Name ,PIN.In_Process_ID,PIN.LotNo
			"
		end       	
		execute Sp_Executesql @sql
        Print @sql
end




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSBYPARTYSUMMARY]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
