/* 
 exec Proc_ProcessByPartySummary '10','Acc2010_2011.dbo.','1','12/Apr/2010','12/Aug/2010','##3316'
*/

CREATE PROCEDURE [dbo].[PROC_PROCESSBYPARTYSUMMARY]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),    
	@ToDate as Nvarchar(20),    
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""


	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =LM.Lgr_ID"

begin
    	SET NOCOUNT ON;
	    if @Rpt_Wise=0
		Begin
			set @sql="
			select Process_ID,PartyName,ProcessName,MainGroup,MainGroup as ItemName,SUM(Than) as Than,SUM(Meter) as Meter  from
			(
			select PM.Process_ID, LM.Lgr_Name as PartyName,PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup , PIN.DelThan as Than,PIN.DelMeter as Meter 
			from  " + @DatabaseName + "processIn PIN 
			Inner Join  " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join  " + @DatabaseName + "Item_Master IM ON PIN.Item_Id = IM.Item_Id  
			Inner Join  " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			Inner Join  " + @DatabaseName + "Ledger_Master LM ON PIN.In_LGR_ID = LM.LGR_ID
			 " + @JoinSql + " 
			where PIN.VCHDate >='" + @FromDate + "' and PIN.VCHDate <='" + @ToDate + "'  and PIN.Cmp_Code in ("+ @Cmp_Code +") 
			and PM.OutSide <> 1
			) as a
			Group By PartyName,Process_ID,ProcessName,MainGroup
			order by PartyName,Process_ID
			"
		end 
  
    	if @Rpt_Wise=1
		Begin
		set @sql="
			select Process_ID,PartyName,ProcessName,MainGroup,MainGroup as ItemName,SUM(Than) as Than,SUM(Meter) as Meter from
			(
			select PM.Process_ID, LM.Lgr_Name as PartyName,PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,PIN.DelThan as Than,PIN.DelMeter as Meter 
			from " + @DatabaseName + "processIn PIN
			Inner Join " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner Join " + @DatabaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			Inner Join  " + @DatabaseName + "Ledger_Master LM ON PIN.In_LGR_ID = LM.LGR_ID
			" + @JoinSql + " 
			where PIN.VCHDate >='" + @FromDate + "' and PIN.VCHDate <='" + @ToDate + "' and PIN.Cmp_Code in ("+ @Cmp_Code +") and PM.OutSide <> 1
			) as a
			Group By PartyName,Process_ID,ProcessName,MainGroup 
			order by PartyName,Process_ID "
		end 

	if @Rpt_Wise=2
		Begin
			set @sql="
			select Process_ID,PartyName,ProcessName,ItemName as MainGroup,ItemName,SUM(Than) as Than,SUM(Meter) as Meter  from
			(
			select PM.Process_ID,LM.Lgr_Name as PartyName,PM.Process_Name as ProcessName,IM.Item_Name as ItemName,PIN.DelThan as Than,PIN.DelMeter as Meter 
			from  " + @DatabaseName + "processIn PIN 
			Inner Join  " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join  " + @DatabaseName + "Item_Master IM ON PIN.Item_Id = IM.Item_Id  			
			Inner Join  " + @DatabaseName + "Ledger_Master LM ON PIN.In_LGR_ID = LM.LGR_ID
			" + @JoinSql + " 
			where PIN.VCHDate >='" + @FromDate + "' and PIN.VCHDate <='" + @ToDate + "'  and PIN.Cmp_Code in ("+ @Cmp_Code +") 
			and PM.OutSide <> 1
			) as a
			Group By PartyName,Process_ID,ProcessName,ItemName
			order by PartyName,Process_ID,MainGroup,ItemName
			"
		end 
  
     
		execute Sp_Executesql @sql
        Print @sql
end




















