/* 
 PROC_PROCESSDETAIL 10,'ACC2010_2011.DBO.',0,'##2284' 
 
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSDETAIL]
( 
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @RPT_WISE INT,
   @TEMPTABLE NVARCHAR(20)
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @MAINGRPSQL AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @JOINSQL =""
SET @MAINGRPSQL=""


BEGIN
       IF @RPT_WISE=0 
          BEGIN
				SET @JOINSQL ="
                               INNER JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID= ITM.ITEM_TYPE_ID   
                               INNER JOIN "+@TEMPTABLE  +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
				SET @MAINGRPSQL="ITM.Item_Type_Name AS MAINGROUP"  
          END 
       ELSE IF @RPT_WISE=1 
          BEGIN
				SET @JOINSQL =" 
                                INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID= IGM.ITEM_GRP_ID   
                                INNER JOIN "+@TEMPTABLE  +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
				SET @MAINGRPSQL="IGM.ITEM_GRP_NAME AS MAINGROUP"  
          END 
   
END

	
BEGIN
   
   SET @SQL="		
             SELECT LOTNO,PROCESSID,PROCESSNAME,MAINGROUP,SUM(PENDINGTHAN) AS PENDINGTHAN FROM(
			select LA.LOTNO,1 as ProcessID,'GREY STOCK' as ProcessName, "+@MAINGRPSQL+" ,LA.PendingThan as PendingThan
			 from "+@DATABASENAME+"LotAllocation LA
			INNER Join "+@DATABASENAME+"Item_Master IM ON LA.item_Id = IM.item_Id  			
            "+@JOINSQL +"
			WHERE LA.Cmp_Code in ("+@CMP_CODE+")    and LA.PendingThan <>0									
           
            "

SET @SQL1="
     		UNION ALL
			select P2P.LOTNO,PM.Process_ID as ProcessID, PM.Process_Name as ProcessName, "+@MAINGRPSQL+" ,P2P.PendingThan as PendingThan
			from "+@DATABASENAME+"process2process P2P 
			Inner Join "+@DATABASENAME+"Process_Master PM ON P2P.To_Process_ID = PM.Process_ID
			Inner Join "+@DATABASENAME+"Item_Master IM ON P2P.item_Id = IM.item_Id  
			"+@JOINSQL +"
		    WHERE P2P.Cmp_Code in ("+@CMP_CODE+")   AND PM.OutSide<>1 and P2P.PendingThan <>0
			
			UNION ALL
			select FTF.LOTNO,20 as ProcessID, 'FINISHFOLDING' as ProcessName, "+@MAINGRPSQL+" ,FTF.PendingThan as PendingThan
			from "+@DATABASENAME+"FinishToFolding FTF
			Inner Join "+@DATABASENAME+"Item_Master IM ON FTF.item_Id = IM.item_Id  		    
			 "+@JOINSQL +"
			WHERE FTF.Cmp_Code in ("+@CMP_CODE+")   and FTF.PendingThan <>0
            ) AS DETAIL
            GROUP BY  LOTNO,PROCESSID,PROCESSNAME,MAINGROUP
            ORDER BY LOTNO,PROCESSID            
			"  
END

PRINT @SQL
PRINT @SQL1

EXEC (@SQL+@SQL1)




















GO

