CREATE PROCEDURE [dbo].[PROC_PROCESSDETAILPENDING]
(
    @Cmp_Code nvarchar(10),
    @DataBaseName  nvarchar(50),
	@Rpt_Wise    int,
	@AsOnDate nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql1  Nvarchar(4000)
declare @Sql2  Nvarchar(4000)
declare @Sql3  Nvarchar(4000)
declare @Sql4  Nvarchar(4000)
declare @Sql5  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""
set @sql1=""
set @sql2=""
set @sql3=""
set @sql4=""
set @sql5=""
if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;
if @Rpt_Wise=0
		begin
			set @sql1="
				select b.Cmp_Code,b.ProcessID,b.ProcessName,convert(nvarchar, b.LotNo) as LotNo,P.VchDate as LotDate, PendThan ,PendMeter 
				from(
				select Cmp_Code,ProcessID,ProcessName, LotNo, sum(LAThan) - sum(PThan) as PendThan ,sum(LAMeter) - sum(PMeter) as PendMeter 
				from (
				select LA.Cmp_Code as Cmp_Code,1 as ProcessID,'GREY STOCK' as ProcessName,  LA.LotNo  as LotNo,
				SUM(LA.TotalThan) as LAThan,0 as PThan,SUM(LA.TotalmETER) as LAMeter,0 as PMeter
				from  "+ @DataBaseName +"LotAllocation LA
				Inner Join "+ @DataBaseName +"Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner Join "+ @DataBaseName +"Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 			
				 "+@JoinSql+"	
				WHERE LA.Cmp_Code in ("+ @Cmp_Code +")  and  LA.VchDate <='"+@AsOnDate+"'				
				group by LA.Cmp_Code,LA.LotNo  
				UNION
				select P2P.Cmp_Code as Cmp_Code,1 as ProcessID,'Grey Stock' as ProcessName, P2P.LotNo  as LotNo,
				0 as LAThan, sum(P2P.DelThan) as PThan,0 as LAMeter, sum(P2P.DelMeter) as PMeter
				from "+  @DataBaseName +"Process2Process P2P
				Inner Join "+  @DataBaseName +"LotAllocation LA ON LA.LotNo = P2P.LotNo and LA.Cmp_Code = P2P.Cmp_Code 	
				Inner Join "+  @DataBaseName +"Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner Join "+  @DataBaseName +"Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 
				 "+@JoinSql+"	
				WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")  and P2P.From_Process_ID=1 and  P2P.VchDate <='"+@AsOnDate+"'				
				group by P2P.Cmp_Code,P2P.LotNo  

UNION
				select GS.Cmp_Code as Cmp_Code,1 as ProcessID,'Grey Stock' as ProcessName, GS.LotNo  as LotNo,
				0 as LAThan, sum(GS.PCS) as PThan,0 as LAMeter, sum(GS.GRAYMTRS) as PMeter
				from "+  @DataBaseName +"GRAYSTOCKOUT GS
				Inner Join "+  @DataBaseName +"LotAllocation LA ON LA.LotNo = GS.LotNo and LA.Cmp_Code = GS.Cmp_Code 	
				Inner Join "+  @DataBaseName +"Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner Join "+  @DataBaseName +"Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 
				 "+@JoinSql+"	
				WHERE GS.Cmp_Code in ("+ @Cmp_Code +")  and  GS.VchDate <='"+@AsOnDate+"'				
				group by GS.Cmp_Code,GS.LotNo  
				) as a
				group by a.Cmp_Code,a.ProcessID,a.ProcessName, a.LotNo
				having sum(a.LAThan) - sum(a.PThan) > 0 
				) as b
				Inner Join "+  @DataBaseName +"LotAllocation P on b.Cmp_Code = P.Cmp_Code and b.LotNo= P.LotNo				
				where PendThan <> 0
				"
		set @sql2=	"
				UNION ALL
--				select Cmp_Code,ProcessID,ProcessName,LotNo, LotDate,PendThan,PendMeter
--				from (
--				select m.Cmp_Code,m.ProcessID,m.ProcessName,m.LotNo, LA.VchDate as LotDate,SUM(PThan) - SUM(RThan) as PendThan,SUM(PMeter) - SUM(RMeter)  as PendMeter
--				from (
				select m.Cmp_Code , m.ProcessID,m.ProcessName ,m.LotNo, LA.VchDate as LotDate,SUM(PenThan) as PThan,SUM(PendMeter) as PMeter
				from (
