				from (
						select Cmp_Code,LotNo,ProcessID,ProcessName, MainGroup,SUM(InThan) - SUM(OutThan)  as PThan ,0 as RecThan,SUM(InMeter) - SUM(OutMeter)  as PMeter ,0 as RecMeter    
				from	(
						select POUT.Cmp_Code as Cmp_Code ,POUT.LotNo as LotNo,POUT.Out_Process_ID as ProcessID,PM.Process_Name as ProcessName,  ITM.Item_Type_Name as MainGroup ,0 as InThan,0 as InMeter,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
						from   "+  @DataBaseName +"processOut POUT 
