						select PIN.Cmp_Code as Cmp_Code ,PIN.LotNo as LotNo,PIN.In_Process_ID as ProcessID, PM.Process_Name as ProcessName,  ITM.Item_Type_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter 
						from   "+  @DataBaseName +"processIn PIN 
