						Having SUM(InThan) - SUM(OutThan) > 0			
				) as g
				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
				) as d
				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
				) as m
				Left Join "+  @DataBaseName +"LotAllocation LA ON m.LotNo =LA.LotNo
				Group By m.Cmp_Code,m.ProcessID,m.ProcessName ,m.LotNo,LA.VCHDATE
				having SUM(PenThan) <> 0
				UNION ALL "
--set @sql3="    				select Cmp_Code , ProcessID,ProcessName ,LotNo, 0 as RThan,0 as RMeter,SUM(RecThan) as RThan,SUM(RecMeter) as RMeter
--				from (
