			group by F2F.Cmp_Code,F2F.lotNo
			
			) as a
			Inner Join  "+  @DataBaseName +"LotAllocation P on a.Cmp_Code = P.Cmp_Code and a.LotNo= P.LotNo			
			group by a.Cmp_Code,a.ProcessID,a.ProcessName ,a.LotNo,P.VchDate					 
			) as s
			Where PendThan <> 0  
