				from "+  @DataBaseName +"Process2Process P2P
				Inner Join "+  @DataBaseName +"LotAllocation LA ON LA.LotNo = P2P.LotNo and LA.Cmp_Code = P2P.Cmp_Code 	
				Inner Join "+  @DataBaseName +"Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner Join "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  						 
				 "+@JoinSql+"	
				WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")  and P2P.From_Process_ID=1 and  P2P.VchDate <='"+@AsOnDate+"'				
				group by P2P.Cmp_Code,P2P.LotNo  
UNION
				select GS.Cmp_Code as Cmp_Code,1 as ProcessID,'Grey Stock' as ProcessName, GS.LotNo  as LotNo,
				0 as LAThan, sum(GS.PCS) as PThan,0 as LAMeter, sum(GS.GRAYMTRS) as PMeter
				from "+  @DataBaseName +"GRAYSTOCKOUT GS
				Inner Join "+  @DataBaseName +"LotAllocation LA ON LA.LotNo = GS.LotNo and LA.Cmp_Code = GS.Cmp_Code 	
				Inner Join "+  @DataBaseName +"Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner Join "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  						 
				 "+@JoinSql+"	
				WHERE GS.Cmp_Code in ("+ @Cmp_Code +")  and  GS.VchDate <='"+@AsOnDate+"'				
				group by GS.Cmp_Code,GS.LotNo  

				) as a
				group by a.Cmp_Code,a.ProcessID,a.ProcessName, a.LotNo
				having sum(a.LAThan) - sum(a.PThan) > 0 
