				from (
				 select Cmp_Code , ProcessID,ProcessName ,LotNo, SUM(PThan) as PThan,0  as RecThan ,SUM(PMeter) as PMeter,0  as RecMeter
				from (
						select Cmp_Code,LotNo,ProcessID,ProcessName, MainGroup,SUM(InThan) - SUM(OutThan)  as PThan ,0 as RecThan,SUM(InMeter) - SUM(OutMeter)  as PMeter ,0 as RecMeter    
				from	(
						select POUT.Cmp_Code as Cmp_Code ,POUT.LotNo as LotNo,POUT.Out_Process_ID as ProcessID,PM.Process_Name as ProcessName,  IGM.Item_Grp_Name as MainGroup ,0 as InThan,0 as InMeter,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
						from   "+  @DataBaseName +"processOut POUT 
						Inner Join   "+  @DataBaseName +"Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
						Inner Join   "+  @DataBaseName +"Item_Master IM ON POUT.item_Id = IM.item_Id  
						Inner  Join  "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			 
                        "+@JoinSql+"	
						where POUT.VCHDate <='"+@AsOnDate+"' and POUT.Cmp_Code in ("+ @Cmp_Code +")  AND PM.OutSide<>1 	  	
						UNION   ALL
						select PIN.Cmp_Code as Cmp_Code ,PIN.LotNo as LotNo,PIN.In_Process_ID as ProcessID, PM.Process_Name as ProcessName,  IGM.Item_Grp_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter 
						from   "+  @DataBaseName +"processIn PIN 
						Inner Join   "+  @DataBaseName +"Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
						Inner Join   "+  @DataBaseName +"Item_Master IM ON PIN.item_Id = IM.item_Id  
						Inner  Join   "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			 	
                        "+@JoinSql+"	
						where PIN.VCHDate <='"+@AsOnDate+"'  and PIN.Cmp_Code in ("+ @Cmp_Code +")  AND PM.OutSide<>1   
