						Group By Cmp_Code,LotNo,ProcessID,ProcessName, MainGroup
						Having SUM(InThan) - SUM(OutThan) > 0			
				) as g
				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
				) as d
				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
				) as m
				Left Join "+  @DataBaseName +"LotAllocation LA ON m.LotNo =LA.LotNo
				Group By m.Cmp_Code,m.ProcessID,m.ProcessName ,m.LotNo,LA.VCHDATE
				having SUM(PenThan) <> 0
				UNION  ALL"
--	set @sql3="  select Cmp_Code , ProcessID,ProcessName ,LotNo, 0 as RThan,0 as RMeter,SUM(RecThan) as RThan,SUM(RecMeter) as RMeter
--				from (
--				select Cmp_Code ,ProcessID,ProcessName, LotNo,0 as PThan,SUM(RecThan)  as RecThan ,0 as PMeter,SUM(RecMeter)  as RecMeter
--				from (
--				select FIF.Cmp_Code as Cmp_Code ,FIF.LotNo,FIF.Process_ID  as ProcessID,PM.Process_Name as ProcessName,   0 as PThan,SUM(RecThan)  as RecThan ,0 as PMeter,SUM(RecMeter)  as RecMeter
--							from "+  @DataBaseName +"FinishtoFolding  FIF
--							Inner Join "+  @DataBaseName +"Process_Master PM ON FIF.Process_ID = PM.Process_ID
--							Inner Join "+  @DataBaseName +"Item_Master IM ON FIF.item_Id = IM.item_Id  
--							Inner  Join "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID   			
--                            "+@JoinSql+"	
--							where FIF.VCHDate <='"+@AsOnDate+"' and FIF.Cmp_Code in ("+ @Cmp_Code +")    
--							group by FIF.Cmp_Code,FIF.LotNo,FIF.Process_ID ,PM.Process_Name
--					)  as l
--				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
--				) as n
--				Group By Cmp_Code,ProcessID,ProcessName ,LotNo
--				) as m
--				Left Join "+  @DataBaseName +"LotAllocation LA ON m.LotNo =LA.LotNo 
--				Group By m.Cmp_Code,m.ProcessID,m.ProcessName,m.LotNo,LA.VchDate				
--				) as jj
--				
--				Where PendThan <>0  UNION    	
--					"
		set @sql4="    
				 	
			select Cmp_Code,ProcessID,ProcessName,LotNo,LotDate, PendThan,PendMeter
			from ( 
			select a.Cmp_Code,a.ProcessID,a.ProcessName,a.LotNo,P.VchDate as LotDate , SUM(a.FThan)- SUM(a.GThan) as PendThan,SUM(a.FMeter)- SUM(a.GMeter) as PendMeter
			from (
			select FTF.Cmp_Code as Cmp_Code,20 as ProcessID,'FINISHFOLDING' as ProcessName, FTF.lotNo as LotNo , SUM(FTF.RecThan)  as FThan ,0 as GThan ,SUM(FTF.RecMeter)  as FMeter ,0 as GMeter
			from  "+  @DataBaseName +"FinishToFolding FTF
			Inner Join   "+  @DataBaseName +"Item_Master IM ON FTF.item_Id = IM.item_Id  
			Inner  Join   "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  						
			 "+@JoinSql+"	
			WHERE FTF.Cmp_Code in ("+ @Cmp_Code +")    and FTF.VchDate <='"+@AsOnDate+"'
			group by FTF.Cmp_Code,FTF.lotNo 
			UNION ALL
			select F2F.Cmp_Code as Cmp_Code,20 as ProcessID,'FINISHFOLDING' as ProcessName, F2F.lotNo as LotNo ,0 as FThan,SUM(FTG.GrayThan)  as GThan,0 as FMeter,SUM(FTG.GrayMeter)  as GMeter
			from "+  @DataBaseName +"FTGRecDetail FTG
			Inner Join "+  @DataBaseName +"Finish2Godown F2F ON F2F.LotNo = FTG.LotNo  and F2F.FTGID = FTG.FTGID   and F2F.Cmp_Code= FTG.Cmp_Code  
			Inner Join  "+  @DataBaseName +"Item_Master IM ON F2F.item_Id = IM.item_Id  
			Inner  Join   "+  @DataBaseName +"Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  						
		    "+@JoinSql+"	
			WHERE FTG.Cmp_Code in ("+ @Cmp_Code +") and FTG.RecDate  <='"+@AsOnDate+"'
			group by F2F.Cmp_Code,F2F.lotNo
			
			) as a
			Inner Join  "+  @DataBaseName +"LotAllocation P on a.Cmp_Code = P.Cmp_Code and a.LotNo= P.LotNo			
			group by a.Cmp_Code,a.ProcessID,a.ProcessName ,a.LotNo,P.VchDate					 
			) as s
			Where PendThan <> 0  
			"
		end
		
		exec (@sql1+@sql2+@sql3+@sql4)
		
        Print @sql1
		Print @sql2
		Print @sql3
        Print @sql4
end




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSDETAILRPT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

