/* 
PROC_PROCESSDETAILRPT '10','ACC2010_2011.DBO.','##3672',1,2
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSDETAILRPT]
( 
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @TEMPTABLE AS NVARCHAR(50),
  @RPT_WISE AS INT,
  @RPT_TYPE AS INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @JOINSQL=""
SET @CONDSQL=""

    BEGIN 
        IF @RPT_WISE=1
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
        ELSE IF @RPT_WISE=2
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID "
        ELSE IF @RPT_WISE=3
              SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
        ELSE IF @RPT_WISE=3
              SET @JOINSQL=""        
    END   
    BEGIN 
         IF @RPT_TYPE=1
            SET @CONDSQL=" HAVING (SUM(PROCESSTHAN)-SUM(FINISHTHAN))>0 OR (SUM(PROCESSMTRS)-SUM(FINISHMETER))>0"                  
    END

BEGIN
     SET @SQL="                			
           SELECT LOTNO,ITEM,ITEMGROUP,ITEMTYPE,SUM(PROCESSTHAN) AS PROCESSTHAN,SUM(FINISHTHAN)AS FINISHTHAN,SUM(PROCESSTHAN)-SUM(FINISHTHAN) AS DIFFTHAN
           ,SUM(PROCESSMTRS)AS PROCESSMTRS,SUM(FINISHMETER) AS FINISHMETER,SUM(PROCESSMTRS)-SUM(FINISHMETER) AS DIFFMTR,CMP_ALIAS
           FROM
            (
                SELECT P2P.LOTNO,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
				,P2P.DELTHAN AS PROCESSTHAN,P2P.DELMETER AS PROCESSMTRS,0 AS FINISHTHAN,0 AS FINISHMETER,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
				INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE                
                "+@JOINSQL+"               
				WHERE P2P.FROM_PROCESS_ID=1 AND P2P.CMP_CODE IN("+@CMP_CODE+") 
                UNION ALL
              SELECT FTGR.LOTNO,IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,0 AS PROCESSTHAN,0 AS PROCESSMETER,
				FTGR.GRAYTHAN AS FINISHTHAN,FTGR.GRAYMETER AS FINISHMETER,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"FINISH2GODOWN FTG
                INNER JOIN "+@DATABASENAME+"FTGRECDETAIL FTGR ON FTGR.FTGID=FTG.FTGID
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
				INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=FTGR.CMP_CODE                                               
                "+@JOINSQL+"               
				WHERE  FTGR.CMP_CODE IN("+@CMP_CODE+") 
  UNION ALL  "
SET @SQL1="                			
              SELECT P2P.LOTNO,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
				,0 AS PROCESSTHAN,0 AS PROCESSMTRS,P2P.DELTHAN AS FINISHTHAN,P2P.DELMETER AS FINISHMETER,CMP.CMP_ALIAS
				FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
                INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.TO_PROCESS_ID
				INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE                
                "+@JOINSQL+"               
				WHERE PM.OUTSIDE=1 AND P2P.CMP_CODE IN("+@CMP_CODE+") 
				) AS DETAIL
               GROUP BY  LOTNO,ITEM,ITEMGROUP,ITEMTYPE,CMP_ALIAS
               "+@CONDSQL+"
              "  
END

EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

