/*
   PROC_PROCESSGATEPASS_PRINT 1,'ACC2012_2013.DBO.',1,11,1
*/
 CREATE PROCEDURE [dbo].[PROC_PROCESSGATEPASS_PRINT]
(
  @CMP_CODE NVARCHAR(200),
  @DATABASENAME NVARCHAR(200),
  @FROMDOCNO NVARCHAR(20),
  @TODOCNO NVARCHAR(20),
  @PROCESS_ID  NVARCHAR(20)

)
AS
DECLARE @SQL NVARCHAR(4000)
BEGIN
      SET  @SQL="
SELECT P2P.PROCESSID,P2P.DOCNO,P2P.VCHDATE,P2P.GPASSNO,P2P.LOTNO,P2P.YEARFLAG
,FLM.LGR_NAME AS FROM_PARTY,FCM.CITY_NAME AS FP_CITY,TLM.LGR_NAME AS TO_PARTY,TCM.CITY_NAME AS TP_CITY
,FPM.PROCESS_NAME AS FROM_PROCESS,TPM.PROCESS_NAME AS TO_PROCESS,TGM.GODOWN_NAME AS TO_GODOWN
,P2P.DELTHAN,P2P.DELMETER,DM.DESIGN_NAME
FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER FLM ON FLM.LGR_ID=P2P.FROM_LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER FCM ON FCM.CITY_ID=FLM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER TLM ON TLM.LGR_ID=P2P.TO_LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER TCM ON TCM.CITY_ID=TLM.CITY_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER FPM ON FPM.PROCESS_ID=P2P.FROM_PROCESS_ID
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER TPM ON TPM.PROCESS_ID=P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+"GODOWN_MASTER FGM ON FGM.GODOWN_ID=P2P.FROM_GODOWN_ID
INNER JOIN "+@DATABASENAME+"GODOWN_MASTER TGM ON TGM.GODOWN_ID=P2P.TO_GODOWN_ID
LEFT JOIN "+@DATABASENAME+"DESIGN_MASTER DM ON DM.DESIGN_ID=P2P.DESIGN_ID
WHERE P2P.CMP_CODE IN("+@CMP_CODE+") AND P2P.DOCNO BETWEEN "+@FROMDOCNO +" AND "+@TODOCNO +"
AND P2P.FROM_PROCESS_ID="+@PROCESS_ID+"
         "

END

PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

