/*    
PROC_PROCESSISSUEPRINT '1','2','1','acc2017_2018.dbo.'
*/   

CREATE PROCEDURE [dbo].[PROC_PROCESSISSUEPRINT]
(
@FromBillNo  nvarchar(20),
@ToBillNo nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)

)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="	 
SELECT P2P.PROCESSISSUEID,CONVERT(NVARCHAR,P2P.DOCNO) AS DOCNO, CONVERT(NVARCHAR,P2PD.LOTNO) AS LOTNO,
CONVERT(NVARCHAR,P2P.VCHDATE,103) AS DATE,FPM.PROCESS_NAME AS PROCESS,ISNULL(FLM.LGR_NAME,'') AS PARTY,GMM.LOT_NAME AS GREYMARKA,
GMM.LOT_ID,SRNO,LOTNOENTRYID,THAN,METER,P2P.PENDINGTHAN,P2P.PENDINGMETER,P2PD.ITEM_ID,DETAILID,hm.HSN_ID,hm.HSN_NAME,P2PD.CGST_PER,P2PD.CGST_AMT,
P2PD.SGST_PER,P2PD.SGST_AMT,P2PD.IGST_PER,P2PD.IGST_AMT,NETAMT,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(FLM.LGR_ADD1) AS LGR_ADD1,UPPER(FLM.LGR_ADD2) AS LGR_ADD2 
,UPPER(FLM.LGR_ADD3)AS LGR_ADD3,
QTY,AMOUNT,RATE,CMP.GSTINNO AS CGSTINNO,FLM.GSTINNO AS LGSTINNO,UPPER(SM.STATE_NAME) AS  PATYSTATE,
UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATECODE,'') AS CMP_STATE
,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,IM.Item_Name,P2PD.Pcs,
ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,CONVERT(NVARCHAR,CMM.PINCODE) AS CONSIGNEE_PINCODE,CMM.DISTRICT AS CONSIGNEE_DISTRICT,
SM.STATE_CODE AS LGR_STATECODE,flm.Lgr_Pano,ISNULL(P2P.NARRATION,'') AS NARRATION , ISNULL(P2PD.REMARK,'')REMARK,P2P.RECNO, P2P.EWAYBILLNO,P2P.VEHICLENO,ISNULL(TM.Transport_Name,'') AS Transport_Name
FROM   "+ @DatabaseName +" PROCESSISSUE P2P 
INNER JOIN "+ @DatabaseName +" PROCESSISSUE_DETAIL P2PD ON P2P.PROCESSISSUEID = P2PD.PROCESSISSUEID  AND P2P.CMP_CODE = P2PD.CMP_CODE
LEFT JOIN  "+ @DatabaseName +" LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.LGR_ID
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID=FLM.STATE_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID=FLM.CITY_ID  
INNER JOIN "+ @DatabaseName +" ITEM_MASTER IM ON IM.Item_Id = P2PD.Item_Id
INNER JOIN "+ @DatabaseName +" PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2P.PROCESS_ID
INNER JOIN "+ @DatabaseName +" LOT_MASTER GMM ON GMM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+ @DatabaseName +" hsn_MASTER hm ON hm.HSN_ID = P2PD.HSN_ID
INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON P2P.CMP_CODE= CMP.CMP_CODE 
LEFT JOIN " + @DATABASENAME +"CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=P2P.Consignee_Id	
LEFT JOIN " + @DATABASENAME +"STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id 
LEFT JOIN " + @DATABASENAME +"TRANSPORT_MASTER TM on TM.Transport_Id=P2P.Transport_Id   
WHERE P2P.Cmp_Code="+ @Cmp_Code +" and  P2P.DOCNO BETWEEN '" + @FromBillNo + "' and '" + @ToBillNo + "'
ORDER BY CONVERT(INT,P2P.DOCNO),CONVERT(INT,P2PD.LOTNO),P2P.YEARFLAG 
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSISSUEREPORT]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*    
Proc_ProcessIssueReport 1,'Acc2010_2011.dbo.','01/apr/2011','31/mar/2012',##3540,1,1
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSISSUEREPORT]
	(
		@Cmp_Code as nvarchar(50),
		@DatabaseName as nvarchar(50),
		@FromDate as nvarchar(50),
		@ToDate as nvarchar(50),
		@TEMPTABLE as nvarchar(50),
		@RPT_WISE as int		
	)
AS
		Declare @StrSql as nvarchar(4000)
		Set @StrSql =""
		Declare @SqlJoin as nvarchar(4000)
		Set @SqlJoin =""

BEGIN
		if @RPT_WISE=1    /*    Item wise */
			begin 
				set	@SqlJoin=" inner join "+@TEMPTABLE+" TT on TT.Code=IM.Item_Id "
			end
		else if	@RPT_WISE=3    /*    Item Group wise */
			begin 
				set	@SqlJoin=" inner join "+@TEMPTABLE+" TT on TT.Code=ITM.Item_Type_Id "
			end
		else if	@RPT_WISE=2    /*    Item Type wise */
			begin 
				set	@SqlJoin=" inner join "+@TEMPTABLE+" TT on TT.Code=IGM.Item_Grp_Id  "
			end
		else if	@RPT_WISE=4    /*    All */
			begin 
				set	@SqlJoin=""
			end
END


BEGIN

	SET NOCOUNT ON;
		SET @StrSql="
			SELECT P2P.VCHDATE AS DATE, P2P.DELTHAN AS PRO_THAN,P2P.DELMETER AS PRO_MTRS,P2P.LOTNO,IM.Item_Name as ITEM_NAME,ITM.Item_Type_Name As ITEM_TYPE,IGM.Item_Grp_Name as ITEM_GROUP
           ,CMP.CMP_ALIAS
			FROM "+@DatabaseName+" PROCESS2PROCESS  P2P
			INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
			LEFT JOIN "+@DatabaseName+" ITEM_TYPE_MASTER ITM on IM.Item_Type_Id=ITM.Item_Type_Id
			LEFT JOIN "+@DatabaseName+" ITEM_GROUP_MASTER IGM on IM.Item_Grp_Id=IGM.Item_Grp_Id
            INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
			"+@SqlJoin+"
			WHERE  P2P.YEARFLAG='C' AND FROM_PROCESS_ID=1 AND  P2P.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"' 
			AND P2P.CMP_CODE IN ("+@Cmp_Code+")
            ORDER BY P2P.VCHDATE,P2P.LOTNO
			"
END
PRINT @StrSql
EXEC  (@StrSql)




















GO

