/*
-- =============================================
-- AUTHOR:		DEEPAL PATEL
-- ALTER_DATE: 09-02-2017
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESSJObORDER
-- REPORTNAME : PROCESSJObORDER.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_PROCESSJObORDER 1,'ACC2016_2017.DBO.',2,'01/APR/2016','31/MARCH/2017','',2
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSJObORDER]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(P2FD.PendingTHAN,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(P2FD.PendingTHAN,0) > 0 "
END



BEGIN
IF @RPT_WISE = 1 /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID "
END
ELSE IF @RPT_WISE = 2/*FinishType WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = FM.FinishType_Id "
END


ELSE IF @RPT_WISE =3 /*PARTY/FinishTypeWISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID "
END

ELSE IF @RPT_WISE = 4 /* DOC  NO */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2F.Process_Job_Order_ID "

END







END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = "
SELECT P2F.Process_Job_Order_ID,P2F.DOCNO,P2F.GDATE,FM.FinishType_Name,LM.LGR_NAME AS PARTY_NAME 
                ,CM.CITY_NAME AS PARTY_CITY,P2FD.RATE,P2FD.THAN,P2FD.METER,P2FD.DeliveredTHAN,P2FD.PendingTHAN,P2FD.DeliveredMETER,P2FD.PendingMETER,P2FD.ORDER_TYPE
FROM "+@DATABASENAME+" Process_Job_Order_Master P2F
INNER JOIN "+@DATABASENAME+" Process_Job_Order_Detail P2FD ON P2F.Process_Job_Order_ID = P2FD.Process_Job_Order_ID AND P2F.CMP_CODE = P2FD.CMP_CODE 
inner JOIN "+@DATABASENAME+" FINISHTYPE_MASTER FM ON FM.FinishType_Id = P2FD.FinishType_Id 
INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM ON LM.LGR_ID = P2F.PARTY_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID 
"+@SQLJOIN+"  
WHERE  P2FD.CMP_CODE IN ("+@CMP_CODE+") AND  P2F.GDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@STRCOND+"  
ORDER BY P2F.DOCNO "

END

EXEC (@STRSQL+@STRSQL1)

PRINT @STRSQL
PRINT @STRSQL1





















GO

