CREATE PROCEDURE [dbo].[PROC_PROCESSJOBOUT]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT

)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(P2FD.PENDINGTHAN,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(P2FD.PENDINGTHAN,0) > 0 "
END



BEGIN
IF @RPT_WISE = 1 /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),P2F.VCHDATE,P2FD.DocNo  "
END
ELSE IF @RPT_WISE = 2/*PARTY NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2F.VCHDATE,P2FD.DocNo "
END


ELSE IF @RPT_WISE =3 /*BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE =4/*GREY MARKA NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE =5 /*PROCESS / PARTY WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 6 /*PROCESS / BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL( PM.PROCESS_ID ,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 7 /*PROCESS / GREY MARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo "

END
ELSE IF @RPT_WISE = 8 /*PROCESS / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "

END
ELSE IF @RPT_WISE =9 /*PARTY / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 10 /*PARTY / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 11 /*PARTY / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 12/*PARTY / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 13 /*BUNCHNAME / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 14 /*BUNCHNAME / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 15 /*BUNCHNAME / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "
END



ELSE IF @RPT_WISE = 16 /*GREYMARKA / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 17 /*GREYMARKA / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo"
END

ELSE IF @RPT_WISE = 18 /*GREYMARKA / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF  @RPT_WISE = 19/*DESIGN / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 20 /*DESIGN / PARTY WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 21 /*DESIGN / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE =22/*DESIGN / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 23 /*PROCESS / PARTY / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF  @RPT_WISE = 24 /*PROCESS / PARTY / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF  @RPT_WISE = 25 /*PROCESS / PARTY / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PM.PROCESS_ID "
SET @STRORDERBY = " PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 26 /*PARTY / PROCESS / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 27 /*PARTY / PROCESS / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE =TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2F.VCHDATE,P2FD.DocNo"
END
ELSE IF @RPT_WISE = 28 /*PARTY / PROCESS / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),PM.PROCESS_NAME,ISNULL(PM.PROCESS_ID,0),CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 29 /* BUNCH NO */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2FD.BUNCHNO "
SET @STRORDERBY = " P2FD.BUNCHNO,BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 30 /*DESIGN NO WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DM.DESIGN_NAME),ISNULL(DM.DESIGN_ID,0),P2F.VCHDATE,P2FD.DocNo "
END
ELSE IF @RPT_WISE = 31 /* DOC  NO */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2F.ProcessJobOutID "
SET @STRORDERBY = "P2F.VCHDATE,P2FD.DocNo "
END








END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = "
SELECT P2F.ProcessJobOutID,P2F.DOCNO,P2F.VCHDATE, PM.PROCESS_NAME AS PROCESS,
ISNULL(TLM.LGR_NAME,'') AS PARTY

,LM.LOT_NAME,BM.BUNCHNAME,isnull (DM.DESIGN_NAME,'') as DESIGN_NAME,
 CMP.CMP_ALIAS,DM.DESIGN_NAME,P2FD.DocNo as DETAILDOCNO,P2FD.VchDate as DETAILDATE,P2FD.BUNCHNO,P2FD.Than,P2FD.Meter,P2FD.PENDINGTHAN,P2FD.PENDINGMETER,P2FD.ISSUETHAN,P2FD.ISSUEMETER,P2FD.PROCESS_JOB_ORDERNO,P2FD.PROCESS_JOB_RATE,P2FD.AVG_METER,P2F.TotalThan,P2F.TotalMeter,P2F.FINISHTYPE_ID
,ISNULL(PM.PROCESS_ID,0) AS PROCESS_ID,ISNULL(TLM.LGR_ID,0) AS PARTY_ID
,ISNULL(LM.LOT_ID ,0) AS LOT_ID ,FM.FinishType_Name AS Finish_Type ,
ISNULL(BM.BUNCHNAME_ID,0) AS BUNCHNAME_ID,ISNULL(DM.DESIGN_ID,0) AS DESIGN_ID,P2FD.SRNO

FROM "+@DATABASENAME+" ProcessJobOut P2F
INNER JOIN "+@DATABASENAME+" ProcessJobOut_Detail P2FD ON P2F.ProcessJobOutID = P2FD.ProcessJobOutID AND P2F.CMP_CODE = P2FD.CMP_CODE AND  P2F.FLAG = P2FD.FLAG
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID = P2F.PROCESS_ID
LEFT JOIN "+@DATABASENAME+"  LEDGER_MASTER TLM ON TLM.LGR_ID = P2F.LGR_ID 
INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.LOT_ID = P2FD.LOT_ID
INNER JOIN "+@DATABASENAME+" FINISHTYPE_MASTER FM ON FM.FinishType_Id = P2F.FINISHTYPE_ID
INNER JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = P2FD.BUNCHNAME_ID 
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2FD.CMP_CODE
LEFT JOIN "+@DATABASENAME+" DESIGN_MASTER DM ON DM.DESIGN_ID = P2FD.DESIGN_ID	
"+@SQLJOIN+" 
WHERE  P2FD.FLAG = 'PJO'AND  P2FD.CMP_CODE IN ("+@CMP_CODE+") AND  P2F.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@STRCOND+"  


 order by "+@STRORDERBY+" "

END

EXEC (@STRSQL+@STRSQL1)

PRINT @STRSQL
PRINT @STRSQL1





















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSLOTPENDINGSUMMARY]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_PROCESSLOTPENDINGSUMMARY]
(
    @Cmp_Code nvarchar(10),
    @DataBaseName  nvarchar(50),
	@Rpt_Wise    int,
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;
if @Rpt_Wise=0
		begin
			set @sql="
			select ProcessID,ProcessName, MainGroup , PendingThan
			from (
			select 1 as ProcessID,'GREY STOCK' as ProcessName, ITM.Item_Type_Name as MainGroup ,SUM(LA.PendingThan) as PendingThan
			 from "+ @DataBaseName + "LotAllocation LA
			Inner Join "+ @DataBaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
			Inner  Join "+ @DataBaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			"+@JoinSql+"				
			WHERE LA.Cmp_Code in ("+ @Cmp_Code +")    and LA.PendingThan <>0			
			group by ITM.Item_Type_Name 			
			UNION 
			select PM.Process_ID as ProcessID, PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,SUM(P2P.PendingThan) as PendingThan
			from "+ @DataBaseName + "process2process P2P 
			Inner Join "+ @DataBaseName + "Process_Master PM ON P2P.To_Process_ID = PM.Process_ID
			Inner Join "+ @DataBaseName + "Item_Master IM ON P2P.item_Id = IM.item_Id  
			Inner  Join "+ @DataBaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			"+@JoinSql+"	
			WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")   AND PM.OutSide<>1 and P2P.PendingThan <>0
			group by PM.Process_ID,PM.Process_Name , ITM.Item_Type_Name 
			UNION
			select 20 as ProcessID, 'FINISHFOLDING' as ProcessName, ITM.Item_Type_Name as MainGroup ,SUM(FTF.PendingThan) as PendingThan
			 from "+ @DataBaseName + "FinishToFolding FTF
			Inner Join "+ @DataBaseName + "Item_Master IM ON FTF.item_Id = IM.item_Id  
		    Inner Join "+ @DataBaseName + "Process_Master PM ON FTF.Process_ID = PM.Process_ID
			Inner  Join "+ @DataBaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			"+@JoinSql+"	
			WHERE FTF.Cmp_Code in ("+ @Cmp_Code +")   and FTF.PendingThan <>0
			group by PM.Process_ID,PM.Process_Name ,ITM.Item_Type_Name
			) as a
			order by ProcessID
			"
		end 
	
	if @Rpt_Wise=1
		Begin
		set @sql="
			select 1 as ProcessID,'GREY STOCK' as ProcessName, IGM.Item_Grp_Name as MainGroup ,SUM(LA.PendingThan) as PendingThan
			 from "+ @DataBaseName + "LotAllocation LA
			Inner Join "+ @DataBaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
			Inner  Join "+ @DataBaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			"+@JoinSql+"	
			WHERE LA.Cmp_Code in ("+ @Cmp_Code +")   and LA.PendingThan <>0
			group by IGM.Item_Grp_Name 
			UNION            
			select PM.Process_ID as ProcessID, PM.Process_Name as ProcessName, IGM.Item_Grp_Name as MainGroup ,SUM(P2P.PendingThan) as PendingThan
			from "+ @DataBaseName + "process2process P2P 
			Inner Join "+ @DataBaseName + "Process_Master PM ON P2P.To_Process_ID = PM.Process_ID
			Inner Join "+ @DataBaseName + "Item_Master IM ON P2P.item_Id = IM.item_Id  
			Inner  Join "+ @DataBaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			"+@JoinSql+"	
			WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")  AND PM.OutSide<>1 and P2P.PendingThan <>0			
			group by PM.Process_ID,PM.Process_Name , IGM.Item_Grp_Name 
			UNION
			select 20 as ProcessID,'FINISHFOLDING' as ProcessName, IGM.Item_Grp_Name as MainGroup ,SUM(FTF.PendingThan) as PendingThan
			 from "+ @DataBaseName + "FinishToFolding FTF
			Inner Join "+ @DataBaseName + "Process_Master PM ON FTF.Process_ID = PM.Process_ID
			Inner Join "+ @DataBaseName + "Item_Master IM ON FTF.item_Id = IM.item_Id  
			Inner  Join "+ @DataBaseName + "Item_Group_Master IGM ON IM.Item_Grp_ID = IGM.Item_Grp_ID  			
			"+@JoinSql+"	
			WHERE FTF.Cmp_Code in ("+ @Cmp_Code +")   and FTF.PendingThan <>0
			group by PM.Process_ID,PM.Process_Name ,IGM.Item_Grp_Name  
            order by ProcessID"			 
		end 

		execute Sp_Executesql @sql
        Print @sql
end




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSPENDING]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_PROCESSPENDING 1,'ACC2012_2013.DBO.',1,##4572,2
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSPENDING] 	
(
@Cmp_Code nvarchar(50),
@DatabaseName nvarchar(50),
@Rpt_Wise int,
@TempTable nvarchar(20),
@PendType int
)
AS
Declare @sql as nvarchar(4000)
declare @sqlJoin as nvarchar(4000)
declare @MainGrp as nvarchar(1000)
declare @PendSql as nvarchar(1000)
BEGIN	
	SET NOCOUNT ON;

Begin
if @Rpt_Wise=1     
        begin
	         SET @sqlJoin=" INNER JOIN " + @TempTable + " TT ON P2P.LotNo=TT.CODE"
             SET @MainGrp="'' AS MAINGROUP"
        END
else if @Rpt_Wise=2 
        BEGIN
    	     set @sqlJoin ="inner join  " +  @TempTable + " TT on TT.Code=PM.Process_Id"
             SET @MainGrp="'' AS MAINGROUP"
        END
else if @Rpt_Wise=3 
        BEGIN
    	     set @sqlJoin ="inner join " +  @TempTable + " TT on TT.Code=LM.Lgr_ID"
             SET @MainGrp="LM.LGR_NAME AS MAINGROUP"
        END
else if @Rpt_Wise=4 
        BEGIN
    	    set @sqlJoin ="inner join " + @TempTable + " TT on TT.Code=IM.Item_ID"
            SET @MainGrp="IM.Item_NAME AS MAINGROUP"
        END
else if @Rpt_Wise=5 
        BEGIN
    	    set @sqlJoin ="inner join " + @TempTable + " TT on TT.Code=IGM.Item_Grp_Id"
            SET @MainGrp="IGM.Item_Grp_Name AS MAINGROUP"
        END
else if @Rpt_Wise=6 
        BEGIN
    	    set @sqlJoin ="inner join " + @TempTable + " TT on TT.Code=VM.WEAVER_ID"
            SET @MainGrp="VM.WEAVER_NAME AS MAINGROUP"
        END
else if @Rpt_Wise=7
        BEGIN
    	     set @sqlJoin ="inner join " +  @TempTable + " TT on TT.Code=LM.Lgr_ID"
             SET @MainGrp="LM.LGR_NAME AS MAINGROUP"
        END
else if @Rpt_Wise=8
        BEGIN
    	     set @sqlJoin ="inner join " +  @TempTable + " TT on TT.Code=P2P.DESIGN_ID"
             SET @MainGrp="Convert(Nvarchar,DM.DESIGN_NAME) AS MAINGROUP"
        END
end

Begin
	if @PendType=1     
        begin
	         SET @PendSql = " And P2P.DelThan > P2P.PendingThan "
        END
	else if @PendType=2 
        BEGIN
    	     set @PendSql = ""
        END
End

 set @SQL=" select "+@MainGrp+", P2P.LotNo,LA.VchDate,IM.Item_Name,PM.Process_Name,
			P2P.PendingThan,Lm.Lgr_Name as Party,IGM.Item_Grp_Name as ItemGroup,
			CM.City_Name,PM.Process_ID,Convert(Nvarchar,DM.DESIGN_NAME) as Design 
            from  "+ @DatabaseName+"Process2Process P2P
            inner join "+ @DatabaseName+"Ledger_Master LM on P2P.To_Lgr_Id=LM.Lgr_Id
            Inner Join  "+ @DatabaseName+"LotAllocation LA on LA.LotNo=P2P.LotNo and LA.Cmp_Code=P2P.Cmp_Code
            Left join "+ @DatabaseName+"Process_Master PM on P2P.To_Process_Id=PM.Process_Id
            inner join "+ @DatabaseName+"Item_Master IM on IM.Item_Id=P2P.Item_Id
            inner join "+ @DatabaseName+"WEAVER_Master VM on VM.WEAVER_Id=P2P.WEAVER_ID
            Left join  "+ @DatabaseName+"City_Master CM on CM.City_Id=LM.City_Id
            inner join "+ @DatabaseName+"Item_Group_Master IGM on IGM.Item_Grp_Id=IM.Item_Grp_Id 
			left join "+ @DatabaseName+"Design_Master DM on DM.Design_Id = P2P.Design_Id
            " + @sqlJoin +"            
            where P2P.PendingThan>0 and P2P.Cmp_Code  in(" + @Cmp_Code +")
			AND PM.OUTSIDE<>1 "+@PendSql+"
            Order by P2P.LotNo "
	
END
exec sp_executesql @SQL 
print @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSPENDING_ASONDATE]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO




















CREATE PROCEDURE [dbo].[PROC_PROCESSPENDING_ASONDATE] 	
AS
BEGIN



SELECT B.CMP_CODE,B.PROCESSID,B.PROCESSNAME,CONVERT(NVARCHAR, B.LOTNO) AS LOTNO,P.VCHDATE AS LOTDATE, PENDTHAN ,PENDMETER,PARTY 
FROM(
			SELECT CMP_CODE,PROCESSID,PROCESSNAME, LOTNO, SUM(LATHAN) - SUM(PTHAN) AS PENDTHAN ,SUM(LAMETER) - SUM(PMETER) AS PENDMETER,PARTY 
			 FROM (
						SELECT LA.CMP_CODE AS CMP_CODE,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME,  LA.LOTNO  AS LOTNO,
						SUM(LA.TOTALTHAN) AS LATHAN,0 AS PTHAN,SUM(LA.TOTALMETER) AS LAMETER,0 AS PMETER,'LOT PARTY' AS PARTY
						FROM  ACC2010_2011.DBO.LOTALLOCATION LA
						INNER JOIN ACC2010_2011.DBO.ITEM_MASTER IM ON LA.ITEM_ID = IM.ITEM_ID  
						INNER JOIN ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  						 									  
						WHERE LA.CMP_CODE IN (10)  AND  LA.VCHDATE <='02/DEC/2011'				
						GROUP BY LA.CMP_CODE,LA.LOTNO  
			         UNION      
				        SELECT P2P.CMP_CODE AS CMP_CODE,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME, P2P.LOTNO  AS LOTNO,
	        			0 AS LATHAN, SUM(P2P.DELTHAN) AS PTHAN,0 AS LAMETER, SUM(P2P.DELMETER) AS PMETER,LM.LGR_NAME AS PARTY
			        	FROM ACC2010_2011.DBO.PROCESS2PROCESS P2P
				        INNER JOIN ACC2010_2011.DBO.LOTALLOCATION LA ON LA.LOTNO = P2P.LOTNO AND LA.CMP_CODE = P2P.CMP_CODE 	
				        INNER JOIN ACC2010_2011.DBO.ITEM_MASTER IM ON LA.ITEM_ID = IM.ITEM_ID  
				        INNER JOIN ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  						 				        
                        INNER JOIN ACC2010_2011.DBO.LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID
				        WHERE P2P.CMP_CODE IN (10)  AND P2P.FROM_PROCESS_ID=1 AND  P2P.VCHDATE <='02/DEC/2011'				
				        GROUP BY P2P.CMP_CODE,P2P.LOTNO  ,LM.LGR_NAME
                     UNION
				       SELECT GS.CMP_CODE AS CMP_CODE,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME, GS.LOTNO  AS LOTNO,
				       0 AS LATHAN, SUM(GS.PCS) AS PTHAN,0 AS LAMETER, SUM(GS.GRAYMTRS) AS PMETER,'GREY STOCK' AS PARTY
				       FROM ACC2010_2011.DBO.GRAYSTOCKOUT GS
				       INNER JOIN ACC2010_2011.DBO.LOTALLOCATION LA ON LA.LOTNO = GS.LOTNO AND LA.CMP_CODE = GS.CMP_CODE 	
				       INNER JOIN ACC2010_2011.DBO.ITEM_MASTER IM ON LA.ITEM_ID = IM.ITEM_ID  
				       INNER JOIN ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  						 				       
				       WHERE GS.CMP_CODE IN (10)  AND  GS.VCHDATE <='02/DEC/2011'				
				       GROUP BY GS.CMP_CODE,GS.LOTNO  
				) AS A
				GROUP BY A.CMP_CODE,A.PROCESSID,A.PROCESSNAME, A.LOTNO,PARTY
				HAVING SUM(A.LATHAN) - SUM(A.PTHAN) > 0 
	) AS B
	INNER JOIN ACC2010_2011.DBO.LOTALLOCATION P ON B.CMP_CODE = P.CMP_CODE AND B.LOTNO= P.LOTNO				
	WHERE PENDTHAN <> 0
				
UNION ALL
	SELECT CMP_CODE,PROCESSID,PROCESSNAME,LOTNO, LOTDATE,PENDTHAN,PENDMETER,PARTY
		FROM (
				  SELECT M.CMP_CODE,M.PROCESSID,M.PROCESSNAME,M.LOTNO, LA.VCHDATE AS LOTDATE,SUM(PTHAN) - SUM(RTHAN) AS PENDTHAN,SUM(PMETER) - SUM(RMETER)  AS PENDMETER,PARTY
				  FROM (
				           SELECT CMP_CODE , PROCESSID,PROCESSNAME ,LOTNO, SUM(PENTHAN) AS PTHAN,SUM(PENDMETER) AS PMETER,0 AS RTHAN,0 AS RMETER,PARTY
				                 FROM (
				                     SELECT CMP_CODE , PROCESSID,PROCESSNAME ,LOTNO, SUM(PTHAN) - SUM(RECTHAN) AS PENTHAN,SUM(PMETER) - SUM(RECMETER) AS PENDMETER,PARTY
				                     FROM (
				                         SELECT CMP_CODE , PROCESSID,PROCESSNAME ,LOTNO, SUM(PTHAN) AS PTHAN,0  AS RECTHAN ,SUM(PMETER) AS PMETER,0  AS RECMETER,PARTY
				                         FROM (
						                   SELECT CMP_CODE,LOTNO,PROCESSID,PROCESSNAME, MAINGROUP,SUM(INTHAN) - SUM(OUTTHAN)  AS PTHAN ,0 AS RECTHAN,SUM(INMETER) - SUM(OUTMETER)  AS PMETER ,0 AS RECMETER,PARTY    
            			                   FROM (
												SELECT POUT.CMP_CODE AS CMP_CODE ,POUT.LOTNO AS LOTNO,POUT.OUT_PROCESS_ID AS PROCESSID,PM.PROCESS_NAME AS PROCESSNAME,  IGM.ITEM_GRP_NAME AS MAINGROUP ,0 AS INTHAN,0 AS INMETER,POUT.DELTHAN AS OUTTHAN,POUT.DELMETER AS OUTMETER 
                                                ,LM.LGR_NAME AS PARTY
												FROM   ACC2010_2011.DBO.PROCESSOUT POUT 
												INNER JOIN   ACC2010_2011.DBO.PROCESS_MASTER PM ON POUT.OUT_PROCESS_ID = PM.PROCESS_ID
												INNER JOIN   ACC2010_2011.DBO.ITEM_MASTER IM ON POUT.ITEM_ID = IM.ITEM_ID  
												INNER  JOIN  ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  			 												
                                                INNER  JOIN  ACC2010_2011.DBO.LEDGER_MASTER LM ON LM.LGR_ID=POUT.OUT_LGR_ID
												WHERE POUT.VCHDATE <='02/DEC/2011' AND POUT.CMP_CODE IN (10)  AND PM.OUTSIDE<>1 	  	
												UNION   ALL
												SELECT PIN.CMP_CODE AS CMP_CODE ,PIN.LOTNO AS LOTNO,PIN.IN_PROCESS_ID AS PROCESSID, PM.PROCESS_NAME AS PROCESSNAME,  IGM.ITEM_GRP_NAME AS MAINGROUP ,PIN.DELTHAN AS INTHAN,PIN.DELMETER AS INMETER,0 AS OUTTHAN,0 AS OUTMETER 
                                                ,LM.LGR_NAME AS PARTY
												FROM   ACC2010_2011.DBO.PROCESSIN PIN 
												INNER JOIN   ACC2010_2011.DBO.PROCESS_MASTER PM ON PIN.IN_PROCESS_ID = PM.PROCESS_ID
												INNER JOIN   ACC2010_2011.DBO.ITEM_MASTER IM ON PIN.ITEM_ID = IM.ITEM_ID  
												INNER  JOIN   ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  			 	
												INNER  JOIN  ACC2010_2011.DBO.LEDGER_MASTER LM ON LM.LGR_ID=PIN.IN_LGR_ID
												WHERE PIN.VCHDATE <='02/DEC/2011'  AND PIN.CMP_CODE IN (10)  AND PM.OUTSIDE<>1   
			        			                ) AS A		    			
					            	            GROUP BY CMP_CODE,LOTNO,PROCESSID,PROCESSNAME, MAINGROUP,PARTY
						                        HAVING SUM(INTHAN) - SUM(OUTTHAN) > 0			
				                             ) AS G
				                               GROUP BY CMP_CODE,PROCESSID,PROCESSNAME ,LOTNO,PARTY
				                          ) AS D
				                            GROUP BY CMP_CODE,PROCESSID,PROCESSNAME ,LOTNO,PARTY
				                      ) AS M
				                        GROUP BY CMP_CODE,PROCESSID,PROCESSNAME ,LOTNO,PARTY
				           UNION ALL 
                           SELECT CMP_CODE , PROCESSID,PROCESSNAME ,LOTNO, 0 AS RTHAN,0 AS RMETER,SUM(RECTHAN) AS RTHAN,SUM(RECMETER) AS RMETER,PARTY
				             FROM (
				                SELECT CMP_CODE ,PROCESSID,PROCESSNAME, LOTNO,0 AS PTHAN,SUM(RECTHAN)  AS RECTHAN ,0 AS PMETER,SUM(RECMETER)  AS RECMETER,PARTY
				                   FROM (
											SELECT FIF.CMP_CODE AS CMP_CODE ,FIF.LOTNO,FIF.PROCESS_ID  AS PROCESSID,PM.PROCESS_NAME AS PROCESSNAME,   0 AS PTHAN,SUM(RECTHAN)  AS RECTHAN ,0 AS PMETER,SUM(RECMETER)  AS RECMETER
                                            ,LM.LGR_NAME AS PARTY
											FROM ACC2010_2011.DBO.FINISHTOFOLDING  FIF
											INNER JOIN ACC2010_2011.DBO.PROCESS_MASTER PM ON FIF.PROCESS_ID = PM.PROCESS_ID
											INNER JOIN ACC2010_2011.DBO.ITEM_MASTER IM ON FIF.ITEM_ID = IM.ITEM_ID  
											INNER  JOIN ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID   														
                                            INNER  JOIN  ACC2010_2011.DBO.LEDGER_MASTER LM ON LM.LGR_ID=FIF.LGR_ID
											WHERE FIF.VCHDATE <='02/DEC/2011' AND FIF.CMP_CODE IN (10)    
											GROUP BY FIF.CMP_CODE,FIF.LOTNO,FIF.PROCESS_ID ,PM.PROCESS_NAME,LM.LGR_NAME
									      )  AS L
				                             GROUP BY CMP_CODE,PROCESSID,PROCESSNAME ,LOTNO,PARTY
				                   ) AS N
				                     GROUP BY CMP_CODE,PROCESSID,PROCESSNAME ,LOTNO,PARTY
				) AS M
				LEFT JOIN ACC2010_2011.DBO.LOTALLOCATION LA ON M.LOTNO =LA.LOTNO 
				GROUP BY M.CMP_CODE,M.PROCESSID,M.PROCESSNAME,M.LOTNO,LA.VCHDATE,PARTY				
		     ) AS JJ				
			   WHERE PENDTHAN <>0  				
    	 UNION    		
			   SELECT CMP_CODE,PROCESSID,PROCESSNAME,LOTNO,LOTDATE, PENDTHAN,PENDMETER,PARTY
			   FROM ( 
			          SELECT A.CMP_CODE,A.PROCESSID,A.PROCESSNAME,A.LOTNO,P.VCHDATE AS LOTDATE , SUM(A.FTHAN)- SUM(A.GTHAN) AS PENDTHAN,SUM(A.FMETER)- SUM(A.GMETER) AS PENDMETER,PARTY
			          FROM (
								SELECT FTF.CMP_CODE AS CMP_CODE,20 AS PROCESSID,'FINISHFOLDING' AS PROCESSNAME, FTF.LOTNO AS LOTNO , SUM(FTF.RECTHAN)  AS FTHAN ,0 AS GTHAN ,SUM(FTF.RECMETER)  AS FMETER ,0 AS GMETER
								,LM.LGR_NAME AS PARTY
                                FROM  ACC2010_2011.DBO.FINISHTOFOLDING FTF
								INNER JOIN   ACC2010_2011.DBO.ITEM_MASTER IM ON FTF.ITEM_ID = IM.ITEM_ID  
								INNER  JOIN   ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  														  
                                INNER  JOIN  ACC2010_2011.DBO.LEDGER_MASTER LM ON LM.LGR_ID=FTF.LGR_ID
								WHERE FTF.CMP_CODE IN (10)  AND FTF.VCHDATE <='02/DEC/2011'
								GROUP BY FTF.CMP_CODE,FTF.LOTNO ,LM.LGR_NAME
								UNION ALL
								SELECT F2F.CMP_CODE AS CMP_CODE,20 AS PROCESSID,'FINISHFOLDING' AS PROCESSNAME, F2F.LOTNO AS LOTNO ,0 AS FTHAN,SUM(FTG.GRAYTHAN)  AS GTHAN,0 AS FMETER,SUM(FTG.GRAYMETER)  AS GMETER
                                ,'FINISHTOGODOWN' AS PARTY
								FROM ACC2010_2011.DBO.FTGRECDETAIL FTG
								INNER JOIN ACC2010_2011.DBO.FINISH2GODOWN F2F ON F2F.LOTNO = FTG.LOTNO  AND F2F.FTGID = FTG.FTGID   AND F2F.CMP_CODE= FTG.CMP_CODE  
								INNER JOIN  ACC2010_2011.DBO.ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID  
								INNER  JOIN   ACC2010_2011.DBO.ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID  														
								WHERE FTG.CMP_CODE IN (10) AND FTG.RECDATE  <='02/DEC/2011'
								GROUP BY F2F.CMP_CODE,F2F.LOTNO			
			               ) AS A
			               INNER JOIN  ACC2010_2011.DBO.LOTALLOCATION P ON A.CMP_CODE = P.CMP_CODE AND A.LOTNO= P.LOTNO			
			               GROUP BY A.CMP_CODE,A.PROCESSID,A.PROCESSNAME ,A.LOTNO,P.VCHDATE,PARTY					 
			       ) AS S
	    		WHERE PENDTHAN > 0  
			








	
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSPENDINGBUNCHREG]    Script Date: 03/30/2023 12:08:13 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
