/*
-- =============================================
-- AUTHOR:		HIREN DOSHI
-- ALTER_DATE: 25-11-2014
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESS PENDING REGISTER BUNCH NO WISE
-- REPORTNAME : PROCESSPENDING_BUNCHREG.RPT
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_PROCESSPENDINGBUNCHREG 1,'ACC2016_2017.DBO.',2,'01/APR/2016','31/MARCH/2017','##4404',2,1
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSPENDINGBUNCHREG]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT,
@INOUT_TYPE INT
)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRSQL1 AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""
SET @STRSQL1=""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(PENDINGTHAN,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(PENDINGTHAN,0) > 0 "
END

BEGIN
IF @INOUT_TYPE = 1 
SET @INOUTTYPE = ""
ELSE IF @INOUT_TYPE = 2 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'INHOUSE' "
ELSE IF @INOUT_TYPE = 3 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'INSIDE' "
ELSE IF @INOUT_TYPE = 4 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'OUTSIDE' "
END

BEGIN
IF @RPT_WISE = 1 /*PROCESS NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " PROCESS_NAME,ISNULL(PROCESS_ID,0),VCHDATE,BUNCHNO,SRNO "
END
ELSE IF @RPT_WISE = 2/*PARTY NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 3 /*CONTRACTOR NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = CM.CONTRACTOR_ID "
SET @STRORDERBY = " CM.CONTRACTOR_NAME,ISNULL(CM.CONTRACTOR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 4 /*MACHINE NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = MM.MACHINE_ID "
SET @STRORDERBY = " MM.MACHINE_NAME,ISNULL( MM.MACHINE_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE  = 5 /*LORRYWALA NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LRM.LORIWALA_ID "
SET @STRORDERBY = " LRM.LORIWALA_NAME,ISNULL(LRM.LORIWALA_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 6 /*BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 7 /*GREY MARKA NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 8 /*PROCESS / PARTY WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 9 /*PROCESS / BUNCH NAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL( TPM.PROCESS_ID ,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 10 /*PROCESS / GREY MARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 11 /*PARTY / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 12 /*BUNCHNAME / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 13 /* BUNCH NO */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2PD.BUNCHNO "
SET @STRORDERBY = " P2PD.BUNCHNO,BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 14 /*DESIGN NO WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 15 /* DOC  NO */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2P.PROCESSID "
SET @STRORDERBY = " P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 16 /*PROCESS / LORRYWALA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),LRM.LORIWALA_NAME,ISNULL(LRM.LORIWALA_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 17 /*PROCESS / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 18 /*PARTY / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 19 /*PARTY / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 20 /*PARTY / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 21 /*BUNCHNAME / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 22 /*BUNCHNAME / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
SET @STRORDERBY = " BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 23 /*GREYMARKA / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 24 /*GREYMARKA / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0),CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE  = 25 /*LORRYWALA / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LRM.LORIWALA_ID "
SET @STRORDERBY = " LRM.LORIWALA_NAME,ISNULL(LRM.LORIWALA_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 26 /*GREYMARKA / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LOT_ID "
SET @STRORDERBY = " LM.LOT_NAME,ISNULL(LM.LOT_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF  @RPT_WISE = 27 /*DESIGN / PROCESS WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 28 /*DESIGN / PARTY WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 29 /*DESIGN / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 30/*DESIGN / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = DEM.DESIGN_ID "
SET @STRORDERBY = " CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 31  /*PROCESS / PARTY / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF  @RPT_WISE = 32 /*PROCESS / PARTY / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF  @RPT_WISE = 33 /*PROCESS / PARTY / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),CONVERT(INT,DEM.DESIGN_NAME),ISNULL(DEM.DESIGN_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 34 /*PARTY / PROCESS / BUNCHNAME WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0), BM.BUNCHNAME,ISNULL(BM.BUNCHNAME_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 35 /*PARTY / PROCESS / GREYMARKA WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),LM.LOT_NAME,ISNULL(LM.LOT_ID,0),P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 36 /*PARTY / PROCESS / DESIGN WISE*/
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " LGR_NAME,ISNULL(LGR_ID,0),PROCESS_NAME,ISNULL(PROCESS_ID,0),CONVERT(INT,DESIGN_NAME),ISNULL(DESIGN_ID,0),VCHDATE,BUNCHNO,P2PD.SRNO "
END






--ELSE IF @RPT_WISE = 8 /* PROCESS - PARTY */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,TLM.LGR_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 9 /* PROCESS - BUNCH NAME */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,BM.BUNCHNAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 10 /* PROCESS - GREY MARKA */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,LM.LOT_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 11  /* PARTY - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
--SET @STRORDERBY = " TLM.LGR_NAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 12 /* BUNCH NAME - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
--SET @STRORDERBY = " BM.BUNCHNAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END


END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = " SELECT * FROM (
SELECT P2P.PROCESSID,P2P.DOCNO,P2P.VCHDATE,P2PD.LRNO,CONVERT(NVARCHAR,P2PD.LOTNO) AS LOTNO,FPM.PROCESS_NAME AS FROMPROCESS, TPM.PROCESS_NAME AS TOPROCESS,
ISNULL(FLM.LGR_NAME,'') AS FROMPARTY,ISNULL(TLM.LGR_NAME,'') AS TOPARTY,CM.CONTRACTOR_NAME AS CONTRACTOR,
MM.MACHINE_NAME AS MACHINE,LRM.LORIWALA_NAME AS LORIWALA,ISNULL(DM.DRIVER_NAME,'') AS DRIVERNAME,
LM.LOT_NAME AS GREYMARKA,BM.BUNCHNAME,P2PD.THAN,P2PD.METER,P2PD.ISSUETHAN,P2PD.ISSUEMETER,P2PD.PENDINGTHAN,P2PD.PENDINGMETER,
P2P.TOTALTHAN,P2P.TOTALMETER, CMP.CMP_ALIAS,DEM.DESIGN_NAME,P2PD.BUNCHNO,
ISNULL(TPM.PROCESS_ID,0) AS TOPROCESS_ID,ISNULL(FPM.PROCESS_ID,0) AS FROMPROCESS_ID,ISNULL(TLM.LGR_ID,0) AS TOPARTY_ID,ISNULL(CM.CONTRACTOR_ID,0) AS CONTRACTOR_ID,
ISNULL(MM.MACHINE_ID,0) AS MACHINE_ID,ISNULL(LRM.LORIWALA_ID,0) AS LORIWALA_ID,ISNULL(DM.DRIVER_ID,0) AS DRIVER_ID,ISNULL(LM.LOT_ID ,0) AS LOT_ID ,
ISNULL(BM.BUNCHNAME_ID,0) AS BUNCHNAME_ID,ISNULL(DEM.DESIGN_ID,0) AS DESIGN_ID,P2PD.SRNO

FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS_DETAIL P2PD ON P2P.PROCESSID = P2PD.PROCESSID AND P2P.CMP_CODE = P2PD.CMP_CODE AND P2P.FLAG = P2PD.FLAG
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON TPM.PROCESS_ID = P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2P.FROM_PROCESS_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER TLM ON TLM.LGR_ID = P2P.TO_LGR_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+" CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID = P2P.CONTRACTOR_ID
INNER JOIN "+@DATABASENAME+" MACHINE_MASTER MM ON MM.MACHINE_ID = P2P.MACHINE_ID 
INNER JOIN "+@DATABASENAME+" LORIWALA_MASTER LRM ON LRM.LORIWALA_ID = P2P.LORIWALA_ID
LEFT JOIN "+@DATABASENAME+" DRIVER_MASTER DM ON DM.DRIVER_ID = P2P.DRIVER_ID
INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2P.CMP_CODE
INNER JOIN "+@DATABASENAME+" DESIGN_MASTER DEM ON DEM.DESIGN_ID = P2PD.DESIGN_ID	
"+@SQLJOIN+"
WHERE P2P.CMP_CODE IN ("+@CMP_CODE+") AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND P2P.FLAG = 'P2PD' "+@STRCOND+@INOUTTYPE+"  "

SET @STRSQL1=" UNION ALL

  SELECT P2P.BunchPreId AS PROCESSID,P2P.BunchNo AS DOCNO,P2P.VCHDATE,'' AS LRNO,0 AS LOTNO,FPM.PROCESS_NAME AS FROMPROCESS, 
  TPM.PROCESS_NAME AS TOPROCESS,
ISNULL(FLM.LGR_NAME,'') AS FROMPARTY,ISNULL(TLM.LGR_NAME,'') AS TOPARTY,CM.CONTRACTOR_NAME AS CONTRACTOR,
MM.MACHINE_NAME AS MACHINE,LRM.LORIWALA_NAME AS LORIWALA,'' AS DRIVERNAME,
LM.LOT_NAME AS GREYMARKA,BM.BUNCHNAME,0 AS THAN,0 AS METER,P2P.PENDINGTHAN AS ISSUETHAN,P2P.PENDINGMETER AS ISSUEMETER,P2P.PENDINGTHAN,P2P.PENDINGMETER,
0 AS TOTALTHAN,0 AS TOTALMETER, CMP.CMP_ALIAS,DEM.DESIGN_NAME,P2PD.BUNCHNO,
ISNULL(TPM.PROCESS_ID,0) AS TOPROCESS_ID,ISNULL(FPM.PROCESS_ID,0) AS FROMPROCESS_ID,ISNULL(TLM.LGR_ID,0) AS TOPARTY_ID,ISNULL(CM.CONTRACTOR_ID,0) AS CONTRACTOR_ID,
ISNULL(MM.MACHINE_ID,0) AS MACHINE_ID,ISNULL(LRM.LORIWALA_ID,0) AS LORIWALA_ID,'' AS DRIVER_ID,ISNULL(LM.LOT_ID ,0) AS LOT_ID ,
ISNULL(BM.BUNCHNAME_ID,0) AS BUNCHNAME_ID,ISNULL(DEM.DESIGN_ID,0) AS DESIGN_ID,P2P.SrNo

FROM "+@DATABASENAME+" BUNCHPREPARATION_DESIGNDETAIL P2P
INNER JOIN "+@DATABASENAME+" BunchPreparation P2PD ON P2P.BunchPreId= P2PD.BunchPreId AND P2P.CMP_CODE = P2PD.CMP_CODE AND P2P.YearFlag= P2PD.YearFlag
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON TPM.PROCESS_ID = P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2PD.PROCESS_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER TLM ON TLM.LGR_ID = P2P.TO_LGR_ID
LEFT JOIN "+@DATABASENAME+" LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+" CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID = P2P.CONTRACTOR_ID
INNER JOIN "+@DATABASENAME+" MACHINE_MASTER MM ON MM.MACHINE_ID = P2P.MACHINE_ID 
INNER JOIN "+@DATABASENAME+" LORIWALA_MASTER LRM ON LRM.LORIWALA_ID = P2P.LORIWALA_ID
INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = P2P.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2P.CMP_CODE
INNER JOIN "+@DATABASENAME+" DESIGN_MASTER DEM ON DEM.DESIGN_ID = P2P.Design_Id	
"+@SQLJOIN+"
WHERE P2P.CMP_CODE IN ("+@CMP_CODE+") AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
"+@STRCOND+"
) AS DETAIL

/*ORDER BY "+@STRORDERBY+"*/ "
END

EXEC (@STRSQL+@STRSQL1)

PRINT @STRSQL
PRINT @STRSQL1




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSPENDINGDAYSREPORT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_PROCESSPENDINGDAYSREPORT '1','Acc2012_2013.Dbo.','0','##2096', 5,'0'
PROC_PROCESSPENDINGDAYSREPORT '1','Acc2012_2013.Dbo.',0,'##2096',1,0
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSPENDINGDAYSREPORT]
(
	@CMP_CODE AS NVARCHAR(100),
	@DATABASENAME AS NVARCHAR(100),
	@PROCESS_ID AS NVARCHAR(20),
	@TEMPTABLE AS NVARCHAR(20),
	@RPT_WISE AS INT,
	@DAYS AS NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @PROCESSSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @DAYSQL AS NVARCHAR(4000)
DECLARE @DESIGNSQL AS NVARCHAR(4000)

SET @SQL = ""
SET @PROCESSSQL = ""
SET @JOINSQL = ""
SET @DAYSQL = ""
SET @DESIGNSQL = ""

BEGIN
	IF @DAYS != "0"
		SET @DAYSQL = " WHERE DAYS>= " + @DAYS
END

BEGIN
	IF @PROCESS_ID != "0"
		SET @PROCESSSQL = "AND PM.PROCESS_ID IN ("+@PROCESS_ID+")"
	ELSE
		SET @PROCESSSQL = ""	
END

BEGIN 
	IF @RPT_WISE=1
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
		END
	ELSE IF @RPT_WISE=2
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID "
		END
	ELSE IF @RPT_WISE=3
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=P2P.LOTNO "
		END
	ELSE IF @RPT_WISE=4
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IGM.ITEM_GRP_ID "
		END
	ELSE IF @RPT_WISE=5
		BEGIN
			SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ITM.ITEM_TYPE_ID "
		END
	ELSE IF @RPT_WISE=6
		BEGIN
			SET @DESIGNSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=DM.DESIGN_ID "
			SET @JOINSQL = ""
		END
END

BEGIN
	SET NOCOUNT ON;
	SET @SQL = " SELECT LOTNO,DATE,PARTY,ISNULL(CITY,'') AS CITY,ITEM,ITEMGROUP,ITEMTYPE,PROCESS,PROCESSID,
				SUM(PENDINGTHAN) AS PENDINGTHAN ,DAYS,CMP_ALIAS,DESIGN
				FROM (

				SELECT P2P.LOTNO,P2P.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS CITY,
				IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,
				PM.PROCESS_NAME AS PROCESS,P2P.TO_PROCESS_ID AS PROCESSID,SUM(P2P.PENDINGTHAN) AS PENDINGTHAN,
				DATEDIFF(DAY,P2P.VCHDATE,P2P.VCHDATE) AS DAYS,CONVERT(NVARCHAR,DM.DESIGN_NAME) AS DESIGN,
				CMP.CMP_ALIAS 

				FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
				INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID = P2P.TO_PROCESS_ID
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = P2P.TO_LGR_ID
				LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
				INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = P2P.ITEM_ID
				INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID = IM.ITEM_TYPE_ID
--				INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS P2P1 ON P2P1.LOTNO=P2P.LOTNO AND P2P1.CMP_CODE=P2P.CMP_CODE 
--													AND P2P1.TO_PROCESS_ID = P2P.FROM_PROCESS_ID
				INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2P.CMP_CODE
				LEFT JOIN "+@DATABASENAME+" DESIGN_MASTER DM ON DM.DESIGN_ID = P2P.DESIGN_ID
				"+@JOINSQL+" "+@DESIGNSQL+"
				WHERE P2P.CMP_CODE IN ( "+@CMP_CODE+" )
				"+@PROCESSSQL+"	 	

				GROUP BY P2P.LOTNO,P2P.VCHDATE ,LM.LGR_NAME ,PCM.CITY_NAME,
				IM.ITEM_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME,DM.DESIGN_NAME,
				PM.PROCESS_NAME ,P2P.TO_PROCESS_ID ,P2P.VCHDATE ,CMP.CMP_ALIAS
				HAVING SUM(P2P.PENDINGTHAN) > 0

				UNION ALL

				SELECT F2F.LOTNO,F2F.VCHDATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS CITY,
				IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,
				'FOLDING' AS PROCESS,F2F.PROCESS_ID AS PROCESSID,SUM(F2F.PENDINGTHAN) AS PENDINGTHAN,
				DATEDIFF(DAY,P2P.VCHDATE,F2F.VCHDATE) AS DAYS,'' AS DESIGN,
				CMP.CMP_ALIAS

				FROM "+@DATABASENAME+" FINISHTOFOLDING F2F
				INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID = F2F.PROCESS_ID
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = F2F.LGR_ID
				LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
				INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = F2F.ITEM_ID
				INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
				LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID = IM.ITEM_TYPE_ID
				INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS P2P ON P2P.LOTNO = F2F.LOTNO AND P2P.GPASSNO = F2F.GPASSNO 
											AND P2P.TO_PROCESS_ID = F2F.PROCESS_ID AND P2P.CMP_CODE = F2F.CMP_CODE
				INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = F2F.CMP_CODE
				"+@JOINSQL+" 
				WHERE F2F.CMP_CODE IN ( "+@CMP_CODE+" )		
				"+@PROCESSSQL+"  
				GROUP BY F2F.LOTNO,F2F.VCHDATE,LM.LGR_NAME,PCM.CITY_NAME ,
				IM.ITEM_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME ,
				F2F.PROCESS_ID ,P2P.VCHDATE ,CMP.CMP_ALIAS 
				HAVING SUM(F2F.PENDINGTHAN) > 0
				
			 ) AS DETAIL "+@DAYSQL+"
			
			GROUP BY LOTNO,DATE,PARTY,CITY,ITEM,ITEMGROUP,ITEMTYPE,PROCESS,PROCESSID,DAYS,CMP_ALIAS,DESIGN
			ORDER BY LOTNO,PROCESSID "

END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSPENDINGLOTNOREG]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- AUTHOR:		HIREN DOSHI
-- ALTER_DATE: 25-11-2014
-- DESCRIPTION:	THIS PROCEDURE USED FOR PROCESS PENDING REGISTER LOT NO WISE
-- REPORTNAME : PROCESSPENDING_LOTNOREG.RPT
-- =============================================
SELECT NAME FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
[PROC_PROCESSPENDINGLOTNOREG] 1,'ACC2014_2015.DBO.',1,'01/APR/2013','31/MARCH/2015','##2584',1,0
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSPENDINGLOTNOREG]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT,
@INOUT_TYPE INT
)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(P2PD.PENDINGTHAN,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(P2PD.PENDINGTHAN,0) > 0 "
END

BEGIN
IF @INOUT_TYPE = 1 
SET @INOUTTYPE = ""
ELSE IF @INOUT_TYPE = 2 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'InHouse' "
ELSE IF @INOUT_TYPE = 3 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'InSide' "
ELSE IF @INOUT_TYPE = 4 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'OutSide' "
END


BEGIN
IF @RPT_WISE = 1 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
SET @STRORDERBY = " TPM.PROCESS_NAME,ISNULL(TPM.PROCESS_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 2 
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
SET @STRORDERBY = " TLM.LGR_NAME,ISNULL(TLM.LGR_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 3  
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = CM.CONTRACTOR_ID "
SET @STRORDERBY = " CM.CONTRACTOR_NAME,ISNULL(CM.CONTRACTOR_ID,0) ,P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 4  
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = MM.MACHINE_ID "
SET @STRORDERBY = " MM.MACHINE_NAME,ISNULL(MM.MACHINE_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE  = 5  
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LRM.LORIWALA_ID "
SET @STRORDERBY = " LRM.LORIWALA_NAME,ISNULL(LRM.LORIWALA_ID,0),P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 6 
BEGIN
