PROC_PROCESSPENDINGBUNCHREG 1,'ACC2014_2015.DBO.',13,'01/APR/2013','31/MARCH/2014','##5968',2,1
*/
CREATE PROCEDURE [dbo].[PROC_PROCESSPRODUCTIONBUNCHREG]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@RPT_TYPE INT,
@INOUT_TYPE INT
)
AS
DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @STRCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(500)
DECLARE @STRORDERBY AS NVARCHAR(300)
DECLARE @INOUTTYPE AS NVARCHAR(300)

SET @STRSQL = ""
SET @SQLJOIN=""
SET @STRCOND=""
SET @STRORDERBY = ""
SET @INOUTTYPE = ""

BEGIN
IF @RPT_TYPE = 0 /* PAID */
SET @STRCOND = " AND ISNULL(P2PD.PENDINGTHAN,0) = 0 "
ELSE IF @RPT_TYPE = 1 /* PENDING */
SET @STRCOND = " AND ISNULL(P2PD.PENDINGTHAN,0) > 0 "
END

BEGIN
IF @INOUT_TYPE = 1 
SET @INOUTTYPE = ""
ELSE IF @INOUT_TYPE = 2 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'INHOUSE' "
ELSE IF @INOUT_TYPE = 3 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'INSIDE' "
ELSE IF @INOUT_TYPE = 4 
SET @INOUTTYPE = " AND P2P.INOUT_TYPE = 'OUTSIDE' "
END

BEGIN
IF @RPT_WISE = 1 /* PROCESS NAME WISE */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2P.FROM_PROCESS_ID "
SET @STRORDERBY = " FPM.PROCESS_NAME,P2P.FROM_PROCESS_ID,P2P.VCHDATE,P2PD.BUNCHNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 2 /* PARTY NAME WISE */
