SET @STRORDERBY = " FLM.LGR_NAME,P2P.FROM_LGR_ID,FPM.PROCESS_NAME,P2P.FROM_PROCESS_ID,LM.LOT_NAME,LM.LOT_ID,P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
ELSE IF @RPT_WISE = 36  /*PARTY / PROCESS / DESIGN WISE */
BEGIN
SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = P2P.FROM_LGR_ID "
SET @STRORDERBY = " FLM.LGR_NAME,P2P.FROM_LGR_ID,FPM.PROCESS_NAME,P2P.FROM_PROCESS_ID,P2P.VCHDATE,P2PD.LOTNO,P2PD.SRNO "
END
--ELSE IF @RPT_WISE = 8 /* PROCESS - PARTY */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,TLM.LGR_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 9 /* PROCESS - BUNCH NAME */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,BM.BUNCHNAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 10 /* PROCESS - GREY MARKA */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TPM.PROCESS_ID "
--SET @STRORDERBY = " TPM.PROCESS_NAME,LM.LOT_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 11  /* PARTY - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = TLM.LGR_ID "
--SET @STRORDERBY = " TLM.LGR_NAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END
--ELSE IF @RPT_WISE = 12 /* BUNCH NAME - PROCESS */
--BEGIN
--SET @SQLJOIN = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = BM.BUNCHNAME_ID "
--SET @STRORDERBY = " BM.BUNCHNAME,TPM.PROCESS_NAME,P2P.VCHDATE,P2PD.SRNO "
--END

END
BEGIN
SET NOCOUNT ON;
SET @STRSQL = " SELECT P2P.PROCESSID,P2P.DOCNO,P2P.VCHDATE,P2PD.LRNO,CONVERT(NVARCHAR,P2PD.LOTNO) AS LOTNO,FPM.PROCESS_NAME AS FROMPROCESS, TPM.PROCESS_NAME AS TOPROCESS,
ISNULL(FLM.LGR_NAME,'') AS FROMPARTY,ISNULL(TLM.LGR_NAME,'') AS TOPARTY,CM.CONTRACTOR_NAME AS CONTRACTOR,
MM.MACHINE_NAME AS MACHINE,LRM.LORIWALA_NAME AS LORIWALA,ISNULL(DM.DRIVER_NAME,'') AS DRIVERNAME,
LM.LOT_NAME AS GREYMARKA,BM.BUNCHNAME,P2PD.THAN,P2PD.METER,P2PD.ISSUETHAN,P2PD.ISSUEMETER,P2PD.PENDINGTHAN,P2PD.PENDINGMETER,
P2P.TOTALTHAN,P2P.TOTALMETER, CMP.CMP_ALIAS,TPM.PROCESS_ID AS TOPROCESS_ID,FPM.PROCESS_ID AS FROMPROCESS_ID,TLM.LGR_ID AS TOPARTY_ID, FLM.LGR_ID as FromParty_Id,
CM.CONTRACTOR_ID ,MM.MACHINE_ID,LRM.LORIWALA_ID,DM.DRIVER_ID, LM.LOT_ID,BM.BUNCHNAME_ID

FROM "+@DATABASENAME+" PROCESS2PROCESS P2P
INNER JOIN "+@DATABASENAME+" PROCESS2PROCESS_DETAIL P2PD ON P2P.PROCESSID = P2PD.PROCESSID AND P2P.CMP_CODE = P2PD.CMP_CODE AND P2P.FLAG = P2PD.FLAG
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER TPM ON TPM.PROCESS_ID = P2P.TO_PROCESS_ID
INNER JOIN "+@DATABASENAME+" PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2P.FROM_PROCESS_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER TLM ON TLM.LGR_ID = P2P.TO_LGR_ID
LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.FROM_LGR_ID
INNER JOIN "+@DATABASENAME+" CONTRACTOR_MASTER CM ON CM.CONTRACTOR_ID = P2P.CONTRACTOR_ID
INNER JOIN "+@DATABASENAME+" MACHINE_MASTER MM ON MM.MACHINE_ID = P2P.MACHINE_ID 
INNER JOIN "+@DATABASENAME+" LORIWALA_MASTER LRM ON LRM.LORIWALA_ID = P2P.LORIWALA_ID
LEFT JOIN  "+@DATABASENAME+" DRIVER_MASTER DM ON DM.DRIVER_ID = P2P.DRIVER_ID
INNER JOIN "+@DATABASENAME+" LOT_MASTER LM ON LM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+@DATABASENAME+" BUNCHNAME_MASTER BM ON BM.BUNCHNAME_ID = P2PD.BUNCHNAME_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = P2P.CMP_CODE
"+@SQLJOIN+"
WHERE P2P.CMP_CODE IN ("+@CMP_CODE+") AND P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
AND P2P.FLAG IN ('P2P') "+@STRCOND+@INOUTTYPE+"  ORDER BY "+@STRORDERBY+" "
END
PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PROCESSRECEIVEPRINT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO



















/*    
PROC_PROCESSRECEIVEPRINT '1','2','1','acc2017_2018.dbo.'
*/   

CREATE PROCEDURE [dbo].[PROC_PROCESSRECEIVEPRINT]
(
@FromBillNo  nvarchar(20),
@ToBillNo nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)

)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="	 
SELECT P2P.PROCESSRECEIVEID,CONVERT(NVARCHAR,P2P.DOCNO) AS DOCNO, CONVERT(NVARCHAR,P2PD.LOTNO) AS LOTNO,
CONVERT(NVARCHAR,P2P.VCHDATE,103) AS DATE,FPM.PROCESS_NAME AS PROCESS,ISNULL(FLM.LGR_NAME,'') AS PARTY,GMM.LOT_NAME AS GREYMARKA,
GMM.LOT_ID,SRNO,THAN,METER,P2PD.ITEM_ID,hm.HSN_ID,hm.HSN_NAME,P2PD.CGST_PER,P2PD.CGST_AMT,
P2PD.SGST_PER,P2PD.SGST_AMT,P2PD.IGST_PER,P2PD.IGST_AMT,NETAMT,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(FLM.LGR_ADD1) AS LGR_ADD1,UPPER(FLM.LGR_ADD2) AS LGR_ADD2 
,UPPER(FLM.LGR_ADD3)AS LGR_ADD3,
QTY,AMOUNT,RATE,CMP.GSTINNO AS CGSTINNO,FLM.GSTINNO AS LGSTINNO,UPPER(SM.STATE_NAME) AS  PATYSTATE,
UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATECODE,'') AS CMP_STATE
,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,IM.Item_Name,P2PD.Pcs,
'C' AS CONSIGNEENAME,'' AS CONSIGNEE_ADD1,'' AS CONSIGNEE_ADD2,'' AS CONSIGNEE_ADD3,
'' AS CONSIGNEE_CITY,'' AS CONSIGNEE_STATE,''AS CONSIGNEE_STATECODE,'' AS CONSIGNEE_GSTNO,
'' AS  consingee_phone,'' AS CONSINGEE_MOBILE,'' AS CONSIGNEE_COUNTRY,
'' AS CONSIGNEE_PINCODE,'' AS CONSIGNEE_DISTRICT,SM.STATE_CODE AS LGR_STATECODE,flm.Lgr_Pano,ISNULL(P2P.NARRATION,'') AS NARRATION , ISNULL(P2PD.REMARK,'')REMARK,P2P.RECNO
FROM   "+ @DatabaseName +"PROCESSRECEIVE P2P 
INNER JOIN "+ @DatabaseName +"PROCESSRECEIVE_DETAIL P2PD ON P2P.PROCESSRECEIVEID = P2PD.PROCESSRECEIVEID AND P2P.CMP_CODE = P2PD.CMP_CODE
LEFT JOIN "+ @DatabaseName +"LEDGER_MASTER FLM ON FLM.LGR_ID = P2P.LGR_ID
LEFT JOIN "+ @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=FLM.STATE_ID
LEFT JOIN "+ @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=FLM.CITY_ID  
INNER JOIN "+ @DatabaseName +"ITEM_MASTER IM ON IM.Item_Id = P2PD.Item_Id
INNER JOIN "+ @DatabaseName +"PROCESS_MASTER FPM ON FPM.PROCESS_ID = P2P.PROCESS_ID
INNER JOIN "+ @DatabaseName +"LOT_MASTER GMM ON GMM.LOT_ID = P2PD.LOT_ID
INNER JOIN "+ @DatabaseName +"hsn_MASTER hm ON hm.HSN_ID = P2PD.HSN_ID
INNER JOIN "+ @DatabaseName +"COMPANY_MASTER CMP ON P2P.CMP_CODE= CMP.CMP_CODE 
WHERE P2P.Cmp_Code="+ @Cmp_Code +" and  P2P.DOCNO BETWEEN '" + @FromBillNo + "' and '" + @ToBillNo + "'
ORDER BY CONVERT(INT,P2P.DOCNO),CONVERT(INT,P2PD.LOTNO),P2P.YEARFLAG 
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL



















GO

