CREATE PROCEDURE [dbo].[PROC_PROCESSSUMMARY]
(
    @Cmp_Code nvarchar(10),
    @DataBaseName  nvarchar(50),
	@Rpt_Wise    int,
	@AsOnDate nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql1  Nvarchar(4000)
declare @Sql2  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""
set @sql1=""
set @sql2=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

begin
    	SET NOCOUNT ON;
if @Rpt_Wise=0
		begin
			set @sql1="
				select ProcessID,ProcessName, MainGroup ,sum(LAThan) - sum(PThan) as PendThan,0 as PendMeter
				from (select 1 as ProcessID,'GREY STOCK' as ProcessName,  Item_Type_Name as MainGroup ,
				SUM(LA.TotalThan) as LAThan,0 as PThan
				from   " + @DatabaseName + "LotAllocation LA
				Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 
				 "+@JoinSql+"	
				WHERE LA.Cmp_Code in ("+ @Cmp_Code +")  and  LA.VchDate <='"+ @AsOnDate +"'
				group by ITM.Item_Type_Name 
				 UNION
				select 1 as ProcessID,'GREY STOCK' as ProcessName, ITM.Item_Type_Name as MainGroup ,
				0 as LAThan, sum(P2P.DelThan) as PThan
				from   " + @DatabaseName + "LotAllocation LA
				left Join " + @DatabaseName + "Process2Process P2P ON LA.LotNo = P2P.LotNo and LA.Cmp_Code = P2P.Cmp_Code 	
				Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 
				"+@JoinSql+"	
				WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")  and P2P.From_Process_ID=1     and  P2P.VchDate <='"+ @AsOnDate +"'
				group by ITM.Item_Type_Name 
				UNION ALL
					select 1 as ProcessID,'GREY STOCK' as ProcessName, ITM.Item_Type_Name as MainGroup ,
				    0 as LAThan, sum(GS.PCS) as PThan                    
                    FROM   "+@DATABASENAME+"LOTALLOCATION LA 
					LEFT JOIN "+@DATABASENAME+"GRAYSTOCKOUT GS ON LA.LOTNO = GS.LOTNO AND LA.CMP_CODE = GS.CMP_CODE  
                    Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				    Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						 
				    "+@JoinSql+"						
					WHERE GS.CMP_CODE IN ("+@CMP_CODE+")  AND  GS.VCHDATE <='"+@ASONDATE+"'    
					group by ITM.Item_Type_Name 
				) as a
				group by ProcessID,ProcessName, MainGroup 

				"
			set @sql2="
			UNION   ALL			
			select ProcessID,ProcessName,MainGroup,SUM(PThan) - SUM(RecThan) PendThan,0 as PendMeter
			from	(
			select ProcessID,ProcessName,MainGroup,SUM(InThan) - SUM(OutThan)  as PThan ,0 as RecThan  from
			(
			select PM.Process_ID as ProcessID, PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter 
			from   " + @DatabaseName + "processIn PIN 
			Inner Join   " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join   " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			"+@JoinSql+"	
			where PIN.VCHDate <='"+ @AsOnDate +"'  and PIN.Cmp_Code in ("+ @Cmp_Code +")  AND PM.OutSide<>1 

		 UNION    ALL
				 
			select PM.Process_ID as ProcessID,PM.Process_Name as OutProcessName, ITM.Item_Type_Name as MainGroup ,0 as InThan,0 as InMeter,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
			from   " + @DatabaseName + "processOut POUT 
			Inner Join   " + @DatabaseName + "Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join   " + @DatabaseName + "Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner  Join  " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  
			"+@JoinSql+"	
			where POUT.VCHDate <='"+ @AsOnDate +"' and POUT.Cmp_Code in ("+ @Cmp_Code +") AND PM.OutSide<>1 
			) as a
			Group By ProcessID,ProcessName,MainGroup
			Having SUM(InThan) -  SUM(OutThan) <> 0			
			UNION ALL
			select PM.Process_ID  as ProcessID,PM.Process_Name as ProcessName, ITM.Item_Type_Name as MainGroup, 0 as PThan,SUM(RecThan)  as RecThan 
			from " + @DatabaseName + "FinishtoFolding  PIN
			Inner Join " + @DatabaseName + "Process_Master PM ON PIN.Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID   
				"+@JoinSql+"	
			where PIN.VCHDate <='"+ @AsOnDate +"' and PIN.Cmp_Code in ("+ @Cmp_Code +")  
			group by PM.Process_ID ,PM.Process_Name,ITM.Item_Type_Name
			  ) as  v 
			Group By ProcessID,ProcessName,MainGroup
			having SUM(PThan) -  SUM(RecThan)  <> 0

			UNION   ALL
			select ProcessID,ProcessName, MainGroup , SUM(FThan)- SUM(GThan) as PendThan,0 as PendMeter
			from (
			select 20 as ProcessID,'FINISHFOLDING' as ProcessName, ITM.Item_Type_Name as MainGroup , SUM(FTF.RecThan)  as FThan ,0 as GThan 
			from " + @DatabaseName + "FinishToFolding FTF
			Inner Join  " + @DatabaseName + "Item_Master IM ON FTF.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						
				"+@JoinSql+"	
			WHERE FTF.Cmp_Code in ("+ @Cmp_Code +")    and FTF.VchDate <='"+ @AsOnDate +"'
			group by ITM.Item_Type_Name
			UNION ALL
			select 20 as ProcessID,'FINISHFOLDING' as ProcessName, ITM.Item_Type_Name as MainGroup ,0 as FThan,SUM(FTG.GrayThan)  as GThan
			from " + @DatabaseName + "FTGRecDetail FTG
			Inner Join " + @DatabaseName + "Finish2Godown F2F ON F2F.LotNo = FTG.LotNo  and F2F.FTGID = FTG.FTGID   and F2F.Cmp_Code= FTG.Cmp_Code  
			Inner Join  " + @DatabaseName + "Item_Master IM ON F2F.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  						
				"+@JoinSql+"	
			WHERE FTG.Cmp_Code in ("+ @Cmp_Code +")   and FTG.RecDate  <='"+ @AsOnDate +"'
			group by ITM.Item_Type_Name
			) as a
			group by ProcessID,ProcessName,MainGroup 
			 "		   
		end 
	if @Rpt_Wise=1
		Begin
	set @sql1="
				select ProcessID,ProcessName, MainGroup ,sum(LAThan) - sum(PThan) as PendThan,0 as PendMeter
				from (select 1 as ProcessID,'GREY STOCK' as ProcessName,  Item_Grp_Name as MainGroup ,
				SUM(LA.TotalThan) as LAThan,0 as PThan
				from   " + @DatabaseName + "LotAllocation LA
				Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  						 
				 "+@JoinSql+"	
				WHERE LA.Cmp_Code in ("+ @Cmp_Code +")  and  LA.VchDate <='"+ @AsOnDate +"'
				group by ITM.Item_Grp_Name 
				 UNION
				select 1 as ProcessID,'GREY STOCK' as ProcessName, ITM.Item_Grp_Name as MainGroup ,
				0 as LAThan, sum(P2P.DelThan) as PThan
				from   " + @DatabaseName + "LotAllocation LA
				left Join " + @DatabaseName + "Process2Process P2P ON LA.LotNo = P2P.LotNo and LA.Cmp_Code = P2P.Cmp_Code 	
				Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  						 
				"+@JoinSql+"	
				WHERE P2P.Cmp_Code in ("+ @Cmp_Code +")  and P2P.From_Process_ID=1     and  P2P.VchDate <='"+ @AsOnDate +"'
				group by ITM.Item_Grp_Name 

UNION ALL
					select 1 as ProcessID,'GREY STOCK' as ProcessName, ITM.Item_Grp_Name as MainGroup ,
				    0 as LAThan, sum(GS.PCS) as PThan                    
                    FROM   "+@DATABASENAME+"LOTALLOCATION LA 
					LEFT JOIN "+@DATABASENAME+"GRAYSTOCKOUT GS ON LA.LOTNO = GS.LOTNO AND LA.CMP_CODE = GS.CMP_CODE  
                    Inner Join   " + @DatabaseName + "Item_Master IM ON LA.item_Id = IM.item_Id  
				    Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  						 
				    "+@JoinSql+"						
					WHERE GS.CMP_CODE IN ("+@CMP_CODE+")  AND  GS.VCHDATE <='"+@ASONDATE+"'    
					group by ITM.Item_Grp_Name 
				) as a
				group by ProcessID,ProcessName, MainGroup 

				"
			set @sql2="
			UNION   ALL			
			select ProcessID,ProcessName,MainGroup,SUM(PThan) - SUM(RecThan) PendThan,0 as PendMeter
			from	(
			select ProcessID,ProcessName,MainGroup,SUM(InThan) - SUM(OutThan)  as PThan ,0 as RecThan  from
			(
			select PM.Process_ID as ProcessID, PM.Process_Name as ProcessName, ITM.Item_Grp_Name as MainGroup ,PIN.DelThan as InThan,PIN.DelMeter as InMeter,0 as OutThan,0 as OutMeter 
			from   " + @DatabaseName + "processIn PIN 
			Inner Join   " + @DatabaseName + "Process_Master PM ON PIN.In_Process_ID = PM.Process_ID
			Inner Join   " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  
			"+@JoinSql+"	
			where PIN.VCHDate <='"+ @AsOnDate +"'  and PIN.Cmp_Code in ("+ @Cmp_Code +")  AND PM.OutSide<>1 

		 UNION    ALL
				 
			select PM.Process_ID as ProcessID,PM.Process_Name as OutProcessName, ITM.Item_Grp_Name as MainGroup ,0 as InThan,0 as InMeter,POUT.DelThan as OutThan,POUT.DelMeter as OutMeter 
			from   " + @DatabaseName + "processOut POUT 
			Inner Join   " + @DatabaseName + "Process_Master PM ON POUT.Out_Process_ID = PM.Process_ID
			Inner Join   " + @DatabaseName + "Item_Master IM ON POUT.item_Id = IM.item_Id  
			Inner  Join  " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  
			"+@JoinSql+"	
			where POUT.VCHDate <='"+ @AsOnDate +"' and POUT.Cmp_Code in ("+ @Cmp_Code +") AND PM.OutSide<>1 
			) as a
			Group By ProcessID,ProcessName,MainGroup
			Having SUM(InThan) -  SUM(OutThan) <> 0			
			UNION ALL
			select PM.Process_ID  as ProcessID,PM.Process_Name as ProcessName, ITM.Item_Grp_Name as MainGroup, 0 as PThan,SUM(RecThan)  as RecThan 
			from " + @DatabaseName + "FinishtoFolding  PIN
			Inner Join " + @DatabaseName + "Process_Master PM ON PIN.Process_ID = PM.Process_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON PIN.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID   
				"+@JoinSql+"	
			where PIN.VCHDate <='"+ @AsOnDate +"' and PIN.Cmp_Code in ("+ @Cmp_Code +")  
			group by PM.Process_ID ,PM.Process_Name,ITM.Item_Grp_Name
			  ) as  v 
			Group By ProcessID,ProcessName,MainGroup
			having SUM(PThan) -  SUM(RecThan)  <> 0

			UNION   ALL
			select ProcessID,ProcessName, MainGroup , SUM(FThan)- SUM(GThan) as PendThan,0 as PendMeter
			from (
			select 20 as ProcessID,'FINISHFOLDING' as ProcessName, ITM.Item_Grp_Name as MainGroup , SUM(FTF.RecThan)  as FThan ,0 as GThan 
			from " + @DatabaseName + "FinishToFolding FTF
			Inner Join  " + @DatabaseName + "Item_Master IM ON FTF.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  						
				"+@JoinSql+"	
			WHERE FTF.Cmp_Code in ("+ @Cmp_Code +")    and FTF.VchDate <='"+ @AsOnDate +"'
			group by ITM.Item_Grp_Name
			UNION ALL
			select 20 as ProcessID,'FINISHFOLDING' as ProcessName, ITM.Item_Grp_Name as MainGroup ,0 as FThan,SUM(FTG.GrayThan)  as GThan
			from " + @DatabaseName + "FTGRecDetail FTG
			Inner Join " + @DatabaseName + "Finish2Godown F2F ON F2F.LotNo = FTG.LotNo  and F2F.FTGID = FTG.FTGID   and F2F.Cmp_Code= FTG.Cmp_Code  
			Inner Join  " + @DatabaseName + "Item_Master IM ON F2F.item_Id = IM.item_Id  
			Inner  Join   " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  						
				"+@JoinSql+"	
			WHERE FTG.Cmp_Code in ("+ @Cmp_Code +")   and FTG.RecDate  <='"+ @AsOnDate +"'
			group by ITM.Item_Grp_Name
			) as a
			group by ProcessID,ProcessName,MainGroup 
			 "		   
		End
	
		exec (@sql1+@sql2)
        Print @sql1
		Print @sql2
end




















GO

