/*    
 PROC_PRODUCTIONDETAIL '10','ACC2012_2013.DBO.','01/APR/2012','31/MAR/2013','##1132','3',1
*/
CREATE PROCEDURE [dbo].[PROC_PRODUCTIONDETAIL]
(
  @CMP_CODE AS NVARCHAR(100),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @PROCESSID AS NVARCHAR(1000),
  @RPT_WISE AS INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @SELECTION AS NVARCHAR(1000)

SET @SQL=""
SET @JOINSQL=""
SET @SELECTION=""

			
               IF @RPT_WISE=0 
                  BEGIN
                   SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
                                 INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID  
                               "
                   SET @SELECTION=" ITM.ITEM_TYPE_NAME AS MAINGROUP"                   
			     END
              ELSE IF @RPT_WISE=1 
                  BEGIN
                   SET @JOINSQL=" INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
                                 INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID  
                               "
                   SET @SELECTION=" IGM.ITEM_GRP_NAME AS MAINGROUP"                   
			     END

BEGIN
		SET @SQL="SELECT "+@SELECTION+",POUT.LOTNO, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY, POUT.DELTHAN AS OUTTHAN ,POUT.DELMETER AS OUTMTRS
               	,PM.PROCESS_NAME AS PROCESSNAME,IM.ITEM_NAME,CMP.CMP_ALIAS
				FROM  "+@DATABASENAME +"PROCESSOUT POUT   
				INNER JOIN  "+@DATABASENAME +"PROCESS_MASTER PM ON POUT.OUT_PROCESS_ID = PM.PROCESS_ID 
				INNER JOIN  "+@DATABASENAME +"ITEM_MASTER IM ON POUT.ITEM_ID = IM.ITEM_ID  
				INNER JOIN  "+@DATABASENAME +"LEDGER_MASTER LM ON POUT.OUT_LGR_ID = LM.LGR_ID 		
                INNER JOIN "+@DATABASENAME +"COMPANY_MASTER CMP ON POUT.CMP_CODE = CMP.CMP_CODE 		
				LEFT JOIN CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
				"+@JOINSQL+"
				WHERE POUT.VCHDATE >='"+@FROMDATE+"' AND POUT.VCHDATE <='"+@TODATE+"' AND POUT.CMP_CODE IN ("+@CMP_CODE+")
				AND PM.OUTSIDE <> 1  AND PM.PROCESS_ID IN ("+@PROCESSID+") AND (POUT.DELTHAN>0 OR POUT.DELMETER>0)
--				UNION ALL 
--				SELECT "+@SELECTION+",F2F.LOTNO,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,F2F.RECTHAN AS OUTTHAN,F2F.RECMETER AS OUTMTRS 
--				, PM.PROCESS_NAME AS PROCESSNAME,IM.ITEM_NAME,CMP.CMP_ALIAS
--				 FROM  "+@DATABASENAME +"FINISHTOFOLDING F2F 
--				 INNER JOIN   "+@DATABASENAME +"PROCESS_MASTER PM ON PM.PROCESS_ID = F2F.PROCESS_ID  
--				 INNER JOIN   "+@DATABASENAME +"ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID   
--				 INNER JOIN   "+@DATABASENAME +"LEDGER_MASTER LM ON F2F.LGR_ID = LM.LGR_ID   		 
--                 INNER JOIN "+@DATABASENAME +"COMPANY_MASTER CMP ON F2F.CMP_CODE = CMP.CMP_CODE 		
--				 LEFT JOIN CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
--				
--				 WHERE F2F.VCHDATE >='"+@FROMDATE+"' AND F2F.VCHDATE <='"+@TODATE+"' AND F2F.CMP_CODE IN ("+@CMP_CODE+")
--				 AND PM.PROCESS_ID IN ("+@PROCESSID+")  
                 ORDER BY LOTNO
		 "		 
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

set ANSI_NULLS ON
set QUOTED_IDENTIFIER OFF




















GO

