/*
   PROC_PRODUSCTIONSUMM_PARTY_CROSSTAB 10,'ACC2012_2013.DBO.','01/APR/2010','03/JUN/2011','','',1
*/
CREATE PROCEDURE [dbo].[PROC_PRODUSCTIONSUMM_PARTY_CROSSTAB]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME  NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @PROCESSID  NVARCHAR(20),
   @TEMPTABLE  NVARCHAR(20),
   @RPT_WISE INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @MAINGRPSQL AS NVARCHAR(1000)
DECLARE @GRPSQL AS NVARCHAR(1000)
DECLARE @PROSQL AS NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL=""
SET @MAINGRPSQL=""
SET @GRPSQL=""
SET @PROSQL=""

BEGIN
    IF @PROCESSID<>""
         SET @PROSQL=" AND PM.PROCESS_ID=" +@PROCESSID
END
BEGIN
        IF @RPT_WISE=0 
            BEGIN
               SET @JOINSQL=" INNER JOIN " + @TEMPTABLE +" TT ON  TT.CODE=ITM.ITEM_TYPE_ID "
               SET @MAINGRPSQL="ITEMTYPE AS MAINGROUP"
               SET @GRPSQL="ITEMTYPE "
            END 
        ELSE IF @RPT_WISE=1 
            BEGIN
               SET @JOINSQL=" INNER JOIN " + @TEMPTABLE +" TT ON  TT.CODE=IGM.ITEM_GRP_ID "
               SET @MAINGRPSQL="ITEMGROUP AS MAINGROUP"
               SET @GRPSQL="ITEMGROUP "
            END 
END 




BEGIN		
SET @SQL="
          SELECT PROCESSNAME, LGRNAME,"+@MAINGRPSQL+",SUM(OUTTHAN) AS OUTTHAN FROM   (

           SELECT PM.PROCESS_NAME AS PROCESSNAME, POUT.OUT_LGR_ID AS LGRID,LM.LGR_NAME AS LGRNAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
           ,POUT.DELTHAN AS OUTTHAN 
           FROM  "+@DATABASENAME+"PROCESSOUT POUT 
           INNER JOIN "+@DATABASENAME+" PROCESS_MASTER PM ON POUT.OUT_PROCESS_ID = PM.PROCESS_ID  
           INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON POUT.ITEM_ID = IM.ITEM_ID 
           INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
           INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON POUT.OUT_LGR_ID = LM.LGR_ID 
           INNER JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID = ITM.ITEM_TYPE_ID             
           "+@JOINSQL+"
           WHERE POUT.VCHDATE >='"+@FROMDATE+"' AND POUT.VCHDATE <='"+@TODATE+"' AND POUT.CMP_CODE IN ("+@CMP_CODE+") AND PM.OUTSIDE <> 1 
           "+@PROSQL+"
--           UNION ALL 
--           SELECT PM.PROCESS_NAME AS PROCESSNAME, F2F.LGR_ID AS LGRID,LM.LGR_NAME AS LGRNAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
--           ,F2F.RECTHAN AS OUTTHAN   
--           FROM  "+@DATABASENAME+"FINISHTOFOLDING F2F  
--           INNER JOIN  "+@DATABASENAME+" PROCESS_MASTER PM ON PM.PROCESS_ID = F2F.PROCESS_ID  
--           INNER JOIN  "+@DATABASENAME+" ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID    
--           INNER JOIN "+@DATABASENAME+" ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID = IGM.ITEM_GRP_ID
--           INNER JOIN  "+@DATABASENAME+" LEDGER_MASTER LM ON F2F.LGR_ID = LM.LGR_ID   
--           INNER JOIN  "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID = ITM.ITEM_TYPE_ID             
--           "+@JOINSQL+"
--           WHERE F2F.VCHDATE >='"+@FROMDATE+"' AND F2F.VCHDATE <='"+@TODATE+"' AND F2F.CMP_CODE IN ("+@CMP_CODE+") 
--            "+@PROSQL+"
      ) AS A  GROUP BY PROCESSNAME,"+@GRPSQL+" ,LGRNAME 
"

    
END

PRINT @SQL
EXECUTE (@SQL)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PUR_INV_INSURANCE]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_PUR_INV_INSURANCE '01/APR/2010','31/MAR/2011',10,'ACC2010_2011.DBO.',3,'6047'
*/
CREATE PROCEDURE [dbo].[PROC_PUR_INV_INSURANCE]
(
@FromDate  nvarchar(20),
@ToDate nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50),
@RptType int,
@PURHEAD nvarchar(50)
)
AS
	
DECLARE @SQL NVARCHAR(4000) SET @SQL=""

BEGIN
	SET NOCOUNT ON;

	SET @SQL="
SELECT PI.DocNo  as DocNo,PI.BillNo,PI.VchDate as Date,PI.LrNo AS LRNO,PI.Lrdate AS LRDATE,
(CASE WHEN PI.Insured=1 THEN PI.NetTotal ELSE 0 END) AS NetTotal ,
TM.TRANSPORT_NAME AS TRANSPORT,COMP.CMP_CITY AS TOCITY,CM.CITY_NAME AS FROMCITY,SID.BALES as BALES,PI.PurAccId
FROM "+@DatabaseName+"  purchaseInvoice PI
INNER JOIN "+@DatabaseName+" purchaseInvoice_Detail SID On SID.PurchaseInvId = PI.PurchaseInvId and PI.Flag = SID.Flag and PI.Cmp_Code=SID.Cmp_Code
INNER JOIN "+@DatabaseName+" COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DatabaseName+" LEDGER_MASTER LM ON PI.LGR_ID=LM.LGR_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID	               
LEFT JOIN  "+@DatabaseName+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
WHERE PI.VchDate BETWEEN '"+@FromDate+"' and '"+@ToDate+"' AND PI.CMP_CODE IN ("+@Cmp_Code+") 
and PI.PurAccId="+@PURHEAD+" and PI.Flag='P'

union all

select GSM.DocNo,convert(nvarchar,GSM.DocNo) as BillNo,GSM.VchDate as DATE,GSM.LrNo,GSM.LrDate,GSM.NetTotal,
TM.TRANSPORT_NAME AS TRANSPORT,CM.CITY_NAME AS TOCITY,COMP.CMP_CITY AS FROMCITY,GSD.BALES as BALES,0 as PurAccId
from "+@DatabaseName+" GREYSTOCKTRANS_IN_MASTER GSM
inner join "+@DatabaseName+" GreyStockTrans_IN_Detail GSD on GSM.GreyStockTrans_Id=GSD.GreyStockTrans_Id
INNER JOIN "+@DatabaseName+" COMPANY_MASTER COMP ON COMP.CMP_CODE=GSM.CMP_CODE
INNER JOIN "+@DatabaseName+" LEDGER_MASTER LM ON GSM.LGR_ID=LM.LGR_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID	               
Left JOIN  "+@DatabaseName+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=GSM.TRANSPORT_ID
WHERE GSM.VchDate BETWEEN '"+@FromDate+"' and '"+@ToDate+"' AND GSM.CMP_CODE IN ("+@Cmp_Code+") 
ORDER BY DATE,BillNo,LrNo
"
END
EXEC SP_EXECUTESQL @SQL
PRINT @SQL




















GO

