/*    
PROC_PUR_RET_REGISTER '10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','1','##3265'
*/
 
CREATE PROCEDURE [dbo].[PROC_PUR_RET_REGISTER]
(
   @CMP_CODE nvarchar(20),
   @DATABASENAME nvarchar(50),
   @FROMDATE  nvarchar(20),
   @TODATE nvarchar(20),  
   @RPT_WISE int,   
   @TempTable nvarchar(20)
)



AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JOINSQL AS NVARCHAR(3999)

SET @SQL=""

BEGIN
set nocount on;


  BEGIN 
   IF @RPT_WISE=1 
	  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT  ON PR.LGR_ID=TT.CODE"   
   IF @RPT_WISE=2
	  SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PR.AGENT_ID=TT.CODE"
   IF @RPT_WISE=3
    SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PRD.ITEM_ID=TT.CODE"
   IF @RPT_WISE=4 
    SET @JOINSQL=" INNER JOIN " + @TempTable + "  TT ON CM.CITY_ID=TT.CODE"
   IF @RPT_WISE=5
    SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON SM.STATE_ID=TT.CODE"
   IF @RPT_WISE=6 
     SET @JOINSQL=" INNER JOIN " + @TempTable + " TT ON PR.STATION_ID=TT.CODE"   
END

SET @SQL="
	
	SELECT PR.PUR_RET_ID,PR.DOCNO,PR.PUR_RET_DATE AS DATE ,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
    DCM.CITY_NAME AS DESTINATION,SM.STATE_NAME AS STATE,IM.ITEM_NAME AS ITEMNAME,PRD.PUR_RET_PCS AS PCS,
    PRD.PUR_RET_QTY AS QTY,PRD.PUR_RET_RATE AS RATE,PRD.PUR_RET_AMOUNT AS AMOUNT,
	PR.GROSSTOTAL AS GROSSTOTAL,PR.PUR_RET_LESSTOTAL AS LESSTOTAL,PR.PUR_RET_ADDTOTAL AS ADDTOTAL,PR.ROUNDEDAMOUNT AS NETTOTAL
	FROM " + @DatabaseName +"PURCHASE_RETURN_MASTER PR
		INNER JOIN  " + @DatabaseName +"PURCHASE_RETURN_DETAIL PRD ON PRD.PUR_RET_ID=PR.PUR_RET_ID
		INNER JOIN  " + @DatabaseName +"LEDGER_MASTER LM ON PR.LGR_ID=LM.LGR_ID		
		LEFT JOIN  " + @DatabaseName +"LEDGER_MASTER ALM ON PR.AGENT_ID=ALM.LGR_ID		
		INNER JOIN  " + @DatabaseName +"ITEM_MASTER IM ON PRD.ITEM_ID=IM.ITEM_ID
		LEFT JOIN   " + @DatabaseName +"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
        LEFT JOIN   " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
        LEFT JOIN   " + @DatabaseName +"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
		LEFT JOIN   " + @DatabaseName +"CITY_MASTER DCM ON PR.STATION_ID=DCM.CITY_ID		
        "+@JOINSQL+"
		WHERE PR.CMP_CODE="+ @Cmp_Code +" AND PR.PUR_RET_DATE >= '" + @FromDate + "' AND PR.PUR_RET_DATE <='" + @ToDate + "'
		ORDER BY  PR.DOCNO,PR.PUR_RET_DATE
"
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

