              SET @ORDERSQL=" ORDER BY PARTY,ITEMTYPE"
              SET @MAINSQL= "SELECT PARTY AS PARTY,PARTYCITY AS PARTYCITY,AGENT,AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  PARTY,PARTYCITY,CMP_ALIAS ,AGENT,AGENTCITY,ITEMTYPE"
           END
    /*    ONE SUPPLIER GROUP */
       ELSE IF @RPT_WISE =13     /*     ITEM  */
           BEGIN              
              SET @MAINSQL= "SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,CMP_ALIAS,ITEM,UNIT "
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,ITEM,UNIT"
           END
       ELSE IF @RPT_WISE =14       /*     ITEM GROUP */
           BEGIN              
              SET @MAINSQL= "SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,CMP_ALIAS,ITEMGROUP"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,ITEMGROUP"
           END
    ELSE IF @RPT_WISE =15     /*     ITEM TYPE   */
           BEGIN              
              SET @MAINSQL= "SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,CMP_ALIAS,ITEMTYPE"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,ITEMTYPE"
           END
   ELSE IF @RPT_WISE =16     /*     ALL PARTY ITEM  */
           BEGIN              
              SET @MAINSQL= "SELECT PARTY AS PARTY,PARTYCITY AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,PARTY,PARTYCITY,CMP_ALIAS,ITEM,UNIT "
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,PARTY,ITEM,UNIT"
           END
       ELSE IF @RPT_WISE =17       /*     ALL PARTY ITEM GROUP */
           BEGIN              
              SET @MAINSQL= "SELECT PARTY AS PARTY,PARTYCITY AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,PARTY,PARTYCITY,CMP_ALIAS,ITEMGROUP"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,PARTY,ITEMGROUP"
           END
    ELSE IF @RPT_WISE =18     /*    ALL PARTY  ITEM TYPE */
           BEGIN              
              SET @MAINSQL= "SELECT PARTY AS PARTY,PARTYCITY AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,PARTY,PARTYCITY,CMP_ALIAS,ITEMTYPE"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,PARTY,ITEMTYPE"
           END
    ELSE IF @RPT_WISE =19           
           BEGIN                
               SET @ORDERSQL=" ORDER BY PARTY,ITEMGROUP"
               SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP ,MIN(VIEWER) AS VIEWER"
               SET @GRPSQL=" GROUP BY CMP_ALIAS ,PARTY,PARTYCITY,ITEMGROUP"
           END
         ELSE IF @RPT_WISE =20
           BEGIN			   
			   SET @ORDERSQL=" ORDER BY PARTY,ITEM"
               SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
               SET @GRPSQL=" GROUP BY UNIT,CMP_ALIAS ,PARTY,PARTYCITY,ITEM"
           END
         ELSE IF @RPT_WISE =21
           BEGIN			   
			   SET @ORDERSQL=" ORDER BY PARTY,ITEMTYPE"
               SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP) AS ITEMGROUP,ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT  ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,MIN(VIEWER) AS VIEWER"
               SET @GRPSQL=" GROUP BY CMP_ALIAS ,PARTY,PARTYCITY,ITEMTYPE"
           END  
        ELSE IF @RPT_WISE =22
           BEGIN
			   SET @CONDSQL=" AND VM.WEAVER_ID="+@ID         
			   SET @ORDERSQL=" ORDER BY PARTY "
               SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT  ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
               SET @GRPSQL=" GROUP BY CMP_ALIAS ,PARTY,PARTYCITY,VIEWER"
           END 
        ELSE IF @RPT_WISE =23
           BEGIN			   
			   SET @ORDERSQL=" ORDER BY PARTY,VIEWER"
               SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT  ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
               SET @GRPSQL=" GROUP BY CMP_ALIAS ,PARTY,PARTYCITY,VIEWER"
           END  
        ELSE IF @RPT_WISE =24
           BEGIN
              SET @CONDSQL=" AND LM.LGR_ID="+@ID
              SET @ORDERSQL=" ORDER BY VIEWER"
              SET @MAINSQL= "SELECT PARTY,PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP, MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT  ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP, VIEWER"
              SET @GRPSQL=" GROUP BY CMP_ALIAS ,PARTY,PARTYCITY,VIEWER"
           END
       ELSE IF @RPT_WISE =25
           BEGIN
              SET @CONDSQL=" AND ALM.LGR_ID="+@ID
              SET @ORDERSQL=" ORDER BY VIEWER"
              SET @MAINSQL= "SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,AGENT,AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP, MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT  ,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
              SET @GRPSQL=" GROUP BY  CMP_ALIAS ,AGENT,AGENTCITY,VIEWER"
           END
      ELSE IF @RPT_WISE =26     /*     ITEM TYPE */
           BEGIN              
              SET @MAINSQL= "SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,CMP_ALIAS,VIEWER"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,VIEWER"
           END
  

         ELSE IF @RPT_WISE =27
           BEGIN
              SET @CONDSQL=" AND ALM.LGR_ID="+@ID
              SET @ORDERSQL=" ORDER BY PARTY,VIEWER"
              SET @MAINSQL= "SELECT PARTY,PARTYCITY,AGENT,AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
              SET @GRPSQL=" GROUP BY  CMP_ALIAS ,AGENT,AGENTCITY,VIEWER,PARTY,PARTYCITY"
           END
        ELSE IF @RPT_WISE =28     /*    ALL PARTY  ITEM TYPE */
           BEGIN              
              SET @MAINSQL= "SELECT PARTY AS PARTY,PARTYCITY AS PARTYCITY,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MIN(ITEM)AS ITEM,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MIN(UNIT)AS UNIT,CMP_ALIAS,MAX(SUPPLIERGROUP) AS SUPPLIERGROUP,VIEWER"
              SET @GRPSQL=" GROUP BY  SUPPLIERGROUP,PARTY,PARTYCITY,CMP_ALIAS,VIEWER"
              SET @CONDSQL=" AND SGM.SUPP_GRP_ID="+@ID
              SET @ORDERSQL=" ORDER BY SUPPLIERGROUP,PARTY,ITEMTYPE,VIEWER"
           END

	END

BEGIN
    SET @SQL=@MAINSQL+"
     FROM(
     SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_NAME AS ITEM,VM.WEAVER_NAME AS VIEWER,IOS.PUR_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT, PID.QUANTITY AS QUANTITY,
     (PID.AMOUNT)+(((PID.AMOUNT)*(PI.NETTOTAL- PI.GROSSTOTAL))/PI.GROSSTOTAL) AS AMOUNT,
     (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
     ELSE  (PID.PIECES* (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,CMP.CMP_ALIAS,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP
     FROM  "+@DATABASENAME+"PURCHASEINVOICE PI "
   SET @SQL1="  INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PI.PURCHASEINVID AND PID.FLAG=PI.FLAG
     INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
     INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
     LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
     INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID                      
     INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE                      
     INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
     LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
     LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
     LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
     INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=PI.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
     LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
     LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER VM ON VM.WEAVER_ID=PID.WEAVER_ID
     WHERE    PI.VCHDATE>='"+@FROMDATE+"' AND PI.VCHDATE<='"+@TODATE+"'
     AND PI.CMP_CODE IN("+@CMP_CODE+")  "+@HEADSQL+" "+@CONDSQL +" 
       
     ) AS DETAIL   
     "+@GRPSQL
    + @ORDERSQL
	 
END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASEBILLDUE]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
