/*    
PROC_PURCHASEBILLDUE '2','ACC2010_2011.DBO.','30/NOV/2010','##2310',1
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASEBILLDUE]
 (
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(50),
   @DATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT
   
 )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""

BEGIN
    IF @RPT_WISE=1
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
    ELSE IF @RPT_WISE=2
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
    ELSE IF @RPT_WISE=3
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=GM.GRP_ID"
    ELSE IF @RPT_WISE=4
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SGM.SUPP_GRP_ID"
    ELSE IF @RPT_WISE=5
       SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CM.CATEGORY_ID"
END

BEGIN
	
	SET NOCOUNT ON;
     SET @SQL="
               SELECT  LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
               GM.GRP_NAME AS ACCGROUP ,               
               PD.BILLNO AS BILLNO,PD.DATE AS BILLDATE ,PD.AMOUNT AS BILLAMOUNT,PD.PAIDAMT AS RECAMT,CMP.CMP_ALIAS,
               SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,CM.CATEGORY_NAME AS CATEGORY
               FROM "+@DATABASENAME+"PURPARTYDETAIL PD
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID 
               INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PD.CMP_CODE 
               INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
               INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID 
               LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
               LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID     
               LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID                
               LEFT JOIN "+@DATABASENAME+"CATEGORY_MASTER CM ON LM.CATEGORY_ID=CM.CATEGORY_ID                
               LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
               "+@JOINSQL+"
               WHERE PD.CMP_CODE IN("+@CMP_CODE+") AND PD.PENDINGAMT>0 AND DATEDIFF(DAY,PD.DATE,'"+@DATE +"')>ISNULL(PD.CRDAYS,0) 
               AND PD.DATE<='"+@DATE+"'
               ORDER BY PD.DATE,PD.VCODE,PD.BILLNO 
              "
	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASECHARTMULTIYEAR]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

