CREATE PROCEDURE [dbo].[PROC_PURCHASECHARTMULTIYEAR]
(
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50),
@ACCID nvarchar(20),
@Criteria int,
@strYearMinus1 nvarchar(50),
@strYearMinus1Exist int,
@strYearMinus2 nvarchar(50),
@strYearMinus2Exist int,
@strCurrYear nvarchar(20),
@strYearMin1 nvarchar(20),
@strYearMin2 nvarchar(20),
@PURACCID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)

DECLARE @CondSql AS NVARCHAR(1000)

DECLARE @JoinSql AS NVARCHAR(1000)
DECLARE @JoinSql1 AS NVARCHAR(1000)
DECLARE @JoinSql2 AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @JoinSql=""
SET @JoinSql1=""
SET @JoinSql2=""
SET @CondSql=""



if @Criteria=0      /*    PartyWise */
   begin
		SET @JoinSql=""
		if @strYearMinus1Exist=1 or @strYearMinus1Exist=0
			SET @JoinSql1=""
		if @strYearMinus2Exist=1 or @strYearMinus2Exist=0
			SET @JoinSql2=""
	end
else if @Criteria=1      /*    SUPPLIER Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id Or LM.Lgr_Id=PIN.PURACCID"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id Or LM.Lgr_Id=PIN.PURACCID"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id Or LM.Lgr_Id=PIN.PURACCID"
	end
else if @Criteria=2      /*    City Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
	end
else if @Criteria=3      /*    State Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=PIN.Lgr_Id"
	end
else if @Criteria=4      /*    Item Wise  */
	begin
		SET @JoinSql=""
	end
else if @Criteria=5      /*    Item Group Wise  */
	begin
		SET @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=PID.Item_Id"
	if @strYearMinus1Exist=1
		SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Item_Master IM ON IM.Item_Id=PID.Item_Id"
	if @strYearMinus2Exist=1 						
		SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Item_Master IM ON IM.Item_Id=PID.Item_Id"
	end


if @Criteria=0      /*    PartyWise */
	SET @CondSql="And (PIN.Lgr_Id="+@ACCID+" Or PIN.PURACCID="+@ACCID+")"
else if @Criteria=1      /*    SUPPLIER Group */
	SET @CondSql="And LM.SUPP_Grp_Id="+@ACCID+""
else if @Criteria=2      /*    City Group    */   
	SET @CondSql="And LM.City_Id="+@ACCID+""
else if @Criteria=3      /*    State Group */
	SET @CondSql="And LM.State_Id="+@ACCID+""	
else if @Criteria=4      /*    Item Wise */
	SET @CondSql="And PID.Item_Id="+@ACCID+""	
else if @Criteria=5      /*    Item Group */
	SET @CondSql="And IM.Item_Grp_Id="+@ACCID+""	
			

BEGIN
set nocount on;


if @Criteria=4 or @Criteria=5
Begin
	SELECT @SQL="
				Select '"+@strCurrYear+"' As Mon,sum(Amount1) As Amount from(
				Select '"+@strCurrYear+"' As Mon,
					SUM(PID.Amount)+((SUM(PID.Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@DatabaseName+"PurchaseInvoice PIN INNER JOIN "+@DatabaseName+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvID=PID.PurchaseInvID
					INNER JOIN (SELECT PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal AS MainAmt, SUM(PID.Amount) AS SubAmt, 
									PIN.NetTotal-SUM(PID.Amount) AS EffectiveCost 
									FROM "+@DatabaseName+"PurchaseInvoice PIN INNER JOIN "+@DatabaseName+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvID=PID.PurchaseInvID
									Where PIN.PURACCID="+@PURACCID+" AND PIN.cmp_code = "+@Cmp_Code+" GROUP BY PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal) 
				ABC ON PIN.BillNo=ABC.BillNo 
					"+@JoinSql+"
					Where PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(PIN.VchDate),SubAmt,EffectiveCost) As XYZ 
					"
 if @strYearMinus1Exist=1
		SELECT @SQL1=" Union All
				Select '"+@strYearMin1+"' As Mon,sum(Amount1) As Amount from(
				Select '"+@strYearMin1+"' As Mon,
					SUM(PID.Amount)+((SUM(PID.Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@strYearMinus1+"PurchaseInvoice PIN INNER JOIN "+@strYearMinus1+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvId=PID.PurchaseInvId
					INNER JOIN (SELECT PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal AS MainAmt, SUM(PID.Amount) AS SubAmt, 
									PIN.NetTotal-SUM(PID.Amount) AS EffectiveCost 
									FROM "+@strYearMinus1+"PurchaseInvoice PIN INNER JOIN "+@strYearMinus1+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvId=PID.PurchaseInvId
									Where PIN.PURACCID="+@PURACCID+" AND PIN.cmp_code = "+@Cmp_Code+" GROUP BY PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal) 
				ABC ON PIN.BillNo=ABC.BillNo 
					"+@JoinSql1+"
					Where PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(PIN.VchDate),SubAmt,EffectiveCost) As XYZ 
					"
if @strYearMinus2Exist=1
	SELECT @SQL2=" Union All
				Select '"+@strYearMin2+"' As Mon,sum(Amount1) As Amount from(
				Select  '"+@strYearMin2+"' As Mon,
					SUM(PID.Amount)+((SUM(PID.Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@strYearMinus2+"PurchaseInvoice PIN INNER JOIN "+@strYearMinus2+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvId=PID.PurchaseInvId
					INNER JOIN (SELECT PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal AS MainAmt, SUM(PID.Amount) AS SubAmt, 
									PIN.NetTotal-SUM(PID.Amount) AS EffectiveCost 
									FROM "+@strYearMinus2+"PurchaseInvoice PIN INNER JOIN "+@strYearMinus2+"PurchaseInvoice_Detail PID ON PIN.PurchaseInvId= PID.PurchaseInvId 
									Where PIN.PURACCID="+@PURACCID+" AND PIN.cmp_code = "+@Cmp_Code+" GROUP BY PIN.Lgr_Id,PIN.BillNo, PIN.NetTotal) 
				ABC ON PIN.BillNo=ABC.BillNo 
					"+@JoinSql2+"
					Where PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(PIN.VchDate),SubAmt,EffectiveCost) As XYZ 
					"
	SELECT @SQL3="Order by Mon" 
end 
else     /*    -----------Part Except Item And Item Group Wise */
Begin
	SELECT @SQL="
				Select '"+@strCurrYear+"' As Mon,
					sum(PIN.NetTotal) As Amount
				From "+@DatabaseName+"PurchaseInvoice PIN "+@JoinSql+"
					Where PIN.PURACCID="+@PURACCID+" AND PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"		 
				"
	if @strYearMinus1Exist=1
		SELECT @SQL1=" Union All
				Select '"+@strYearMin1+"' As Mon,
					sum(PIN.NetTotal) As Amount
				From "+@strYearMinus1+"PurchaseInvoice PIN "+@JoinSql1+"
					Where PIN.PURACCID="+@PURACCID+" AND PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"		 
				"
	if @strYearMinus2Exist=1
		SELECT @SQL2=" Union All
				Select '"+@strYearMin2+"' As Mon,
					sum(PIN.NetTotal) As Amount
				From "+@strYearMinus2+"PurchaseInvoice PIN "+@JoinSql2+"
					Where PIN.PURACCID="+@PURACCID+" AND PIN.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"						 
				"
		SELECT @SQL3="Order by Mon" 
	End
END	

EXEC(@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

