/*     EXEC PROC_PURCHASEINVCHART  '01/APR/2010','30/AUG/2010','1,2,3,4,5,10','ACC2010_2011.DBO.',1792,'1','TOP20' */

CREATE PROCEDURE [dbo].[PROC_PURCHASEINVCHART]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@PURHEADACC NVARCHAR(20),
@RPT_TYPE NVARCHAR(20)

)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)


SET @SQL=""
SET @SELECTED=""




BEGIN
SET NOCOUNT ON;
IF @RPT_TYPE='1'       /*     PARTY */
BEGIN
SET @SQL="
SELECT  NAME  ,NETTOTAL,ID FROM (
SELECT DISTINCT LM.LGR_NAME AS NAME, SUM(PI.NETTOTAL) AS  NETTOTAL,ISNULL(LM.LGR_ID,0) AS ID
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI           
INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
WHERE PI.PURACCID="+ @PURHEADACC +" AND   PI.CMP_CODE IN ("+ @CMP_CODE +") AND  PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY LM.LGR_NAME,LM.LGR_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='2'       /*     AGENT     */   
BEGIN
SET @SQL="
SELECT  NAME  ,NETTOTAL,ID  FROM (
SELECT DISTINCT ALM.LGR_NAME AS NAME, SUM(PI.NETTOTAL) AS  NETTOTAL ,ISNULL(ALM.LGR_ID,0) AS ID
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI           
INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
WHERE PI.PURACCID="+ @PURHEADACC +" AND   PI.CMP_CODE IN ("+ @CMP_CODE +") AND  PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY ALM.LGR_NAME,ALM.LGR_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='3'       /*     SUPPLIER GROUP WISE    */   
BEGIN
SET @SQL="
SELECT  NAME  ,NETTOTAL,ID  FROM (
SELECT DISTINCT SGM.SUPP_GRP_NAME AS NAME, SUM(PI.NETTOTAL) AS  NETTOTAL,ISNULL(SGM.SUPP_GRP_ID,0) AS ID 
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI           
INNER  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
WHERE PI.PURACCID="+ @PURHEADACC +" AND   PI.CMP_CODE IN ("+ @CMP_CODE +") AND  PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY SGM.SUPP_GRP_NAME,SGM.SUPP_GRP_ID   ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='4'       /*     CITY WISE     */   
BEGIN
SET @SQL="
SELECT  NAME  ,NETTOTAL,ID  FROM (
SELECT DISTINCT CM.CITY_NAME AS NAME, SUM(PI.NETTOTAL) AS  NETTOTAL ,ISNULL(CM.CITY_ID,0) AS ID
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER  JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
WHERE PI.PURACCID="+ @PURHEADACC +" AND   PI.CMP_CODE IN ("+ @CMP_CODE +") AND  PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY CM.CITY_NAME,CM.CITY_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='5'       /*     STATE    */   
BEGIN
SET @SQL="
SELECT  NAME  ,NETTOTAL,ID  FROM (
SELECT DISTINCT SM.STATE_NAME AS NAME, SUM(PI.NETTOTAL) AS  NETTOTAL ,ISNULL(SM.STATE_ID,0) AS ID
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI           
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER  JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER  JOIN "+ @DATABASENAME + "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
WHERE PI.PURACCID="+ @PURHEADACC +" AND   PI.CMP_CODE IN ("+ @CMP_CODE +") AND  PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY SM.STATE_NAME,SM.STATE_ID ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

