-- Description:	Procedure for Purchase_Invoice..Discount>0
--PURCHASEINVOICEDISCOUNT
-- PROC_PURCHASEINVOICEDISC '1','Acc2013_2014.dbo.','01/Apr/2013','31/Mar/2014','##2236',4417
--PurchaseInvDisc.rpt
-- =============================================
CREATE PROCEDURE [dbo].[PROC_PURCHASEINVOICEDISC] 
	-- Add the parameters for the stored procedure here
(
@CompCode nvarchar(10),
@DatabaseName nvarchar(50),
@FROMDATE nvarchar(20),
@Todate nvarchar(20),
@TempTable nvarchar(20)
)
AS
Declare @Sql NVarchar(4000)
DECLARE @SELECTED AS NVARCHAR(1000)

set @Sql=""
SET @SELECTED=""
BEGIN
	
	SET NOCOUNT ON;
	set @SELECTED =" inner join " + @TempTable + " TT ON TT.CODE=PUD.PurACcId"

    -- Insert statements for procedure here
	set @Sql=" SELECT PUD.VCODE,PUD.CMP_CODE,LM1.LGR_NAME AS PURCHASE_ACC,
				PUD.BILLNO,PUD.DATE AS VCHDATE,PAM.TOTAL AS DISCOUNT,PUD.AMOUNT AS NETTOTAL,
				LM.LGR_NAME AS PARTY, CITYM.CITY_NAME,CM.CMP_ALIAS  
			FROM " +@DATABASENAME + "PURPARTYDETAIL PUD
			INNER JOIN " +@DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID = PUD.LGR_ID 
			 INNER JOIN " +@DATABASENAME + "COMPANY_MASTER CM ON PUD.CMP_CODE = CM.CMP_CODE
			INNER JOIN " +@DATABASENAME + " LEDGER_MASTER LM1 ON PUD.PURACCID = LM1.LGR_ID
			INNER JOIN " +@DATABASENAME + "PURADJMASTER PAM ON PUD.VCODE = PAM.VCODE AND PAM.FLAG = PUD.FLAG
			LEFT OUTER JOIN " +@DATABASENAME + "CITY_MASTER AS CITYM ON LM.CITY_ID = CITYM.CITY_ID "+ @SELECTED +"
			WHERE PAM.TOTAL >0 AND PUD.CMP_CODE=" + @COMPCODE + " AND PUD.DATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' 
			ORDER BY PUD.VCODE,PUD.CMP_CODE,PUD.PURACCID  "

Execute sp_ExecuteSql @sql
			PRINT @sql
END




















