/*    
exec Proc_PurchaseOrder '1','Acc2012_2013.dbo.','1','12/Apr/2010','12/Nov/2010','##3704'
   */   

CREATE PROCEDURE [dbo].[PROC_PURCHASEORDER]
(
    @Cmp_Code nvarchar(50),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),    
    @ToDate as Nvarchar(20),    
    @TempTable nvarchar(20),
	@OrderType int
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
Declare @StrOrderType Nvarchar(100) set @StrOrderType=""

set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

if @OrderType=1
	set @StrOrderType =" AND PO.FLAG='P'"
else 
	set @StrOrderType =" AND PO.FLAG<>'P'"

begin
    	SET NOCOUNT ON;
	if @Rpt_Wise=0
		Begin
		set @sql="
			Select   PO.Pur_Order_Id as ID,Po.DocNo,POD.Quantity,SGM.Supp_Grp_Name ,ITM.Item_Type_Name  as MainGroup
			from  " + @DatabaseName + "PurchaseOrder PO 
			Inner Join " + @DatabaseName + "PurchaseOrder_Detail POD ON PO.Pur_Order_Id = POD.Pur_Order_Id  AND PO.FLAG=POD.FLAG
			Inner Join " + @DatabaseName + "Supplier_Group_Master SGM ON PO.Supp_Grp_ID = SGM.Supp_Grp_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POD.item_Id = IM.item_Id  
			Inner Join " + @DatabaseName + "Item_Type_Master ITM ON IM.Item_Type_Id = ITM.Item_Type_Id  
			"+@JoinSql+"	
			where  PO.GDate>='" + @FromDate + "' and PO.GDate<='" + @ToDate + "' and PO.Cmp_Code in ("+ @Cmp_Code +") 
			"+@StrOrderType+"
" 
		end 
	if @Rpt_Wise=1
		begin
			set @sql="
			Select   PO.Pur_Order_Id,Po.DocNo,POD.Quantity,SGM.Supp_Grp_Name
			,ITM.Item_Grp_Name as MainGroup
			from  " + @DatabaseName + "PurchaseOrder PO 
			Inner Join " + @DatabaseName + "PurchaseOrder_Detail POD ON PO.Pur_Order_Id = POD.Pur_Order_Id  AND PO.FLAG=POD.FLAG
			Inner Join " + @DatabaseName + "Supplier_Group_Master SGM ON PO.Supp_Grp_ID = SGM.Supp_Grp_ID
			Inner Join " + @DatabaseName + "Item_Master IM ON POD.item_Id = IM.item_Id  
			Inner  Join " + @DatabaseName + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  
			"+@JoinSql+"	
			where  PO.GDate>='" + @FromDate + "' and PO.GDate<='" + @ToDate + "'  and PO.Cmp_Code in ("+ @Cmp_Code +") 
			"+@StrOrderType+"
" 
		end 
		execute Sp_Executesql @sql
        Print @sql
end




















