SET QUOTED_IDENTIFIER OFF
GO




















/*    
PROC_PURCHASEORDERREPORT '10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##3680',1,1
   */   
CREATE PROCEDURE [dbo].[PROC_PURCHASEORDERREPORT]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @RPT_WISE AS INT,
  @RPT_TYPE AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)

SET @SQL =""
SET @SQL1 =""
SET @SQL2 =""
SET @JOINSQL =""
SET @CONDSQL =""


BEGIN
        IF @RPT_WISE=1 
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=SGM.SUPP_GRP_ID "
        ELSE IF @RPT_WISE=2
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID "
        ELSE IF @RPT_WISE=3
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
       ELSE IF @RPT_WISE=4
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=PO.DOCNO "
END

BEGIN
        IF @RPT_TYPE=1 
          begin
           SET @CONDSQL=" AND PENDINGQTY=0"        
          end
        ELSE IF @RPT_TYPE=2
           begin
           SET @CONDSQL=" AND PENDINGQTY>0"           
           end
        ELSE IF @RPT_TYPE=3
             begin
           SET @CONDSQL=""
              end
END


BEGIN
SET @SQL  ="
            SELECT DOCNO,DATE,BILLNO,SUPPLIER,AGENT,AGENTCITY,ITEM,VIEWER,SUM(ORDERQTY)AS ORDERQTY,SUM(USEDQTY) AS USEDQTY,ORD,TYPE,SUM(PENDINGQTY) AS PENDINGQTY,FYEAR
            FROM ( 
			SELECT PO.DOCNO,PO.GDATE AS DATE,CONVERT(NVARCHAR,PO.DOCNO) AS BILLNO,SGM.SUPP_GRP_NAME SUPPLIER,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
			 ,IM.ITEM_NAME AS ITEM,VM.WEAVER_NAME AS VIEWER,POD.QUANTITY ORDERQTY, 0 AS USEDQTY,1 AS ORD,'ORDER' AS TYPE,POD.PENDINGQTY,PO.FYEAR
			 FROM "+@DATABASENAME+"PURCHASEORDER PO
			 INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID=POD.PUR_ORDER_ID AND PO.FLAG=POD.FLAG
			 INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON PO.SUPP_GRP_ID=SGM.SUPP_GRP_ID
			 LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PO.AGENT_ID
			 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
			 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=POD.ITEM_ID
			 INNER JOIN "+@DATABASENAME+"WEAVER_MASTER VM ON VM.WEAVER_ID=POD.WEAVER_ID
             "+@JOINSQL+"
             WHERE PO.CMP_CODE IN("+@CMP_CODE +") AND PO.GDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+"
           "	
SET @SQL1 =" UNION ALL 
             SELECT PI.CONFNO,PI.VCHDATE AS DATE,PI.BILLNO,SGM.SUPP_GRP_NAME SUPPLIER,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
			 ,IM.ITEM_NAME AS ITEM,VM.WEAVER_NAME AS VIEWER,0 AS ORDERQTY,
			 (CASE  POD.BALESPCSMTR WHEN 'BALES' THEN  PID.BALES WHEN 'PCS' THEN PID.PIECES WHEN 'MTR' THEN PID.QUANTITY ELSE 0 END) AS USEDQUANTITY, 
			  2 AS ORD,'USED' AS TYPE,0 AS PENDINGQTY,PI.FYEAR
			 FROM "+@DATABASENAME+"PURCHASEINVOICE PI
			 INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
			 INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON PI.SUPP_GRP_ID=SGM.SUPP_GRP_ID
			 LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
			 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID			 
			 INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.DOCNO=PI.CONFNO AND PO.SUPP_GRP_ID=PI.SUPP_GRP_ID AND PO.FYEAR=PI.FYEAR
			 INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID=POD.PUR_ORDER_ID AND PID.ITEM_ID=POD.ITEM_ID AND PID.WEAVER_ID=POD.WEAVER_ID
             INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
			 INNER JOIN WEAVER_MASTER VM ON VM.WEAVER_ID=PID.WEAVER_ID
             "+@JOINSQL+"
             WHERE PI.CMP_CODE IN("+@CMP_CODE +") AND PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+"
              "

SET @SQL2=" UNION ALL 
            SELECT PO.DOCNO,PC.CANCELLATION_DATE,CONVERT(NVARCHAR,PC.DOCNO) AS BILLNO,SGM.SUPP_GRP_NAME AS SUPPLIER,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCIYT,IM.ITEM_NAME AS ITEM,VM.WEAVER_NAME AS VIEWVER
             ,0 AS ORDERQTY,PCD.CANCELQUANTITY USEDQUANTITY,2 AS ORD,'CANCEL' AS TYPE,0 AS PENDINGQTY,PO.FYEAR
			FROM "+@DATABASENAME+"PURORDER_CANCELLATION_DETAIL PCD
			INNER JOIN "+@DATABASENAME+"PURORDER_CANCELLATION PC ON PCD.CANCELLATION_ID=PC.CANCELLATION_ID
			INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PCD.SUPP_GRP_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PCD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER VM ON VM.WEAVER_ID=PCD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.DOCNO=PCD.DOCNO AND PO.CMP_CODE=PCD.CMP_CODE AND PO.FYEAR=PCD.FYEAR 
            INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID=POD.PUR_ORDER_ID AND PCD.ITEM_ID=POD.ITEM_ID AND PCD.WEAVER_ID=POD.WEAVER_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PO.AGENT_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
            "+@JOINSQL+"
            WHERE PC.CMP_CODE IN("+@CMP_CODE +") AND PC.CANCELLATION_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+"
             ) AS DETAIL                         
             GROUP BY  DOCNO,DATE,BILLNO,SUPPLIER,AGENT,AGENTCITY,ITEM,VIEWER,ORD,TYPE,FYEAR
             ORDER BY DOCNO,FYEAR,ITEM,VIEWER,ORD
			 "
END

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASEPANDING]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/*
-- =============================================
-- Author:		GAMI DIPAK
-- Create_date: 28-05-2014
-- Description:	THIS  REPORT IS USED TO PURCHASE PENDING REPORT
PROC_PURCHASEPANDING '1','ACC2014_2015.DBO.','01/APR/2014','31/MAR/2015','##5420',4,3
SELECT * FROM TEMPDB..SYSOBJECTS
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASEPANDING]
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(100),
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20),
	@TEMPTABLE AS NVARCHAR(20),
	@RPT_WISE AS INT,
	@RPT_TYPE AS INT
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)
DECLARE @ORDERBY AS NVARCHAR(200)

SET @SQL =""
SET @JOINSQL =""
SET @CONDSQL =""
SET @ORDERBY =""

BEGIN
        IF @RPT_WISE=1 
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=SM.SUPP_GRP_ID "
           SET @ORDERBY =" SUPPLIER,ISNULL(SUPP_GRP_ID,0),"
        END
        ELSE IF @RPT_WISE=2
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=LGR.LGR_ID "
           SET @ORDERBY =" AGENT_NAME,ISNULL(LGR_ID,0),"
        END
        ELSE IF @RPT_WISE=3
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "
           SET @ORDERBY =" ITEM_NAME,ISNULL(ITEM_ID,0),"
        END
        ELSE IF @RPT_WISE=4
        BEGIN
            SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=LM.LOT_ID "
            SET @ORDERBY =" LOT_NAME,ISNULL(LOT_ID,0),"
        END
        ELSE IF @RPT_WISE=5
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=PO.DOCNO "
           SET @ORDERBY =" ISNULL(DOCNO,0),"
		END    
        END

BEGIN
        IF @RPT_TYPE=1 
          begin
           SET @CONDSQL=" AND PENDINGQTY=0"        
          end
        ELSE IF @RPT_TYPE=2
           begin
           SET @CONDSQL=" AND PENDINGQTY>0"           
           end
        ELSE IF @RPT_TYPE=3
             begin
           SET @CONDSQL=""
              end
END
BEGIN 

SET  @SQL ="SELECT ID,DOCNO,BILLNO,FYEAR ,VCHDATE ,SUPPLIER , AGENT_NAME,AGENT_CITY,LOT_NAME,ITEM_NAME,WEAVER_NAME,ORD,SUM (ORDERQTY) AS ORDERQTY,SUM( USEDQTY) AS USEDQTY,TYPE ,SUM (PENDING) AS PENDING,SUM(CANQTY) as CANQTY,
				ISNULL(ITEM_ID,0) AS ITEM_ID, ISNULL(LOT_ID,0) AS LOT_ID,ISNULL(WEAVER_ID,0) AS WEAVER_ID ,ISNULL(SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(LGR_ID,0) AS AGENTID, ISNULL(CITY_ID,0) AS CITY_ID  FROM(
				SELECT PO.PUR_ORDER_ID AS ID , PO.DOCNO ,CONVERT(NVARCHAR,PO.DOCNO) AS BILLNO,PO.FYEAR  ,PO.GDATE AS VCHDATE  ,SM.SUPP_GRP_NAME  AS SUPPLIER
				,LGR.LGR_NAME AS AGENT_NAME ,ACM.CITY_NAME  AS AGENT_CITY,
				LM.LOT_NAME ,IM.ITEM_NAME ,WM.WEAVER_NAME ,POD.QUANTITY AS ORDERQTY ,0 AS USEDQTY,POD.PendingQty AS PENDING,'ORDER' AS TYPE,1 as ord,0 AS CANQTY,
				ISNULL(IM.ITEM_ID,0) AS ITEM_ID, ISNULL(LM.Lot_Id,0) AS LOT_ID,ISNULL(WM.Weaver_Id,0) AS WEAVER_ID ,ISNULL(SM.Supp_Grp_Id,0) AS SUPP_GRP_ID,ISNULL(LGR.Lgr_Id,0) AS LGR_ID, ISNULL(ACM.City_Id,0) AS CITY_ID
				FROM "+@DATABASENAME+"PURCHASEORDER PO
				INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL  POD ON POD.PUR_ORDER_ID =PO.PUR_ORDER_ID 
				AND POD.CMP_CODE =PO.CMP_CODE AND POD.FLAG =PO.FLAG 
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =POD.ITEM_ID 
				INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID =POD.LOT_ID 
				LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID =POD.WEAVER_ID 
				INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SM ON SM.SUPP_GRP_ID =PO.SUPP_GRP_ID 
				LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LGR ON LGR.LGR_ID =PO.AGENT_ID 
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID =LGR.CITY_ID 
				"+@JOINSQL+"
				WHERE PO.CMP_CODE IN("+@CMP_CODE +") AND PO.GDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+""
SET  @SQL1  ="UNION ALL
				SELECT PI.PUR_ORDER_ID AS ID, PI.CONFNO ,PI.BILLNO ,PI.FYEAR,PI.PODATE ,SM.SUPP_GRP_NAME  AS SUPPLIER
				,LGR.LGR_NAME AS AGENT_NAME  ,ACM.CITY_NAME  AS AGENT_CITY, LM.LOT_NAME
				,IM.ITEM_NAME ,WM.WEAVER_NAME ,0 AS ORDERQTY ,ADJPCS AS USEDQTY,0 AS PENDING ,'USED' AS TYPE,2 AS ORD,0 AS CANQTY,
				IM.ITEM_ID, LM.LOT_ID ,WM.WEAVER_ID ,SM.SUPP_GRP_ID,LGR.LGR_ID, ACM.CITY_ID
				FROM "+@DATABASENAME+"PURCHASEINVOICE PI
				INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL  PID ON PID.PURCHASEINVID =PI.PURCHASEINVID 
				AND PI.CMP_CODE =PID.CMP_CODE AND PI.FLAG =PID.FLAG  and PID.Flag ='p'
				INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SM ON SM.SUPP_GRP_ID =PI.SUPP_GRP_ID 
				INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID =PID.LOT_ID 
				INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID =PID.WEAVER_ID 
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =PID.ITEM_ID 
				LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LGR ON LGR.LGR_ID =PI.AGENT_ID 
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID =LGR.CITY_ID
				INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.PUR_ORDER_ID =PI.PUR_ORDER_ID 
				AND PO.CMP_CODE =PI.CMP_CODE 
				INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON POD.PUR_ORDER_ID =PO.PUR_ORDER_ID 
				AND POD.CMP_CODE =PO.CMP_CODE  AND POD.FLAG =PO.FLAG   
				AND PI.CMP_CODE =PID.CMP_CODE  AND POD.LOT_ID =PID.LOT_ID 
				AND POD.ITEM_ID =PID.ITEM_ID  
				 "+@JOINSQL+"
				WHERE PO.CMP_CODE IN("+@CMP_CODE +") AND PO.GDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+""
SET  @SQL2  ="UNION ALL
				SELECT PO.PUR_ORDER_ID AS ID , PO.DOCNO ,CONVERT(NVARCHAR,PO.DOCNO) AS BILLNO,PO.FYEAR  ,PO.GDATE AS VCHDATE  ,SM.SUPP_GRP_NAME  AS SUPPLIER
				,LGR.LGR_NAME AS AGENT_NAME ,ACM.CITY_NAME  AS AGENT_CITY,
				LM.LOT_NAME ,IM.ITEM_NAME ,WM.WEAVER_NAME ,0 AS ORDERQTY ,
				CANCELQUANTITY AS USEDQTY,POD.PendingQty AS PENDING,'CAN' AS TYPE,3 as ord,CANCELQUANTITY AS CANQTY,
				IM.ITEM_ID, LM.LOT_ID ,WM.WEAVER_ID ,SM.SUPP_GRP_ID,LGR.LGR_ID, ACM.CITY_ID
				FROM "+@DATABASENAME+"PURORDER_CANCELLATION POC 
				inner join "+@DATABASENAME+"PURORDER_CANCELLATION_DETAIL POCD ON POC.Cancellation_Id =POCD.Cancellation_Id 
				AND POC.CMP_CODE =POCD.CMP_CODE AND POC.FLAG =POCD.FLAG 
				inner join "+@DATABASENAME+"PURCHASEORDER PO on PO.CMP_CODE =POCD.CMP_CODE AND PO.FLAG =POCD.FLAG AND PO.DOCNO =POCD.DOCNO
				and PO.Fyear =POCD.Fyear and PO.SUPP_GRP_ID =POCD.SUPP_GRP_ID
				INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL  POD ON POD.PUR_ORDER_ID =PO.PUR_ORDER_ID 
				AND POD.CMP_CODE =PO.CMP_CODE AND POD.FLAG =PO.FLAG AND POD.ITEM_ID =POCD.ITEM_ID
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =POD.ITEM_ID 
				INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID =POD.LOT_ID 
				LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID =POD.WEAVER_ID 
				INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SM ON SM.SUPP_GRP_ID =PO.SUPP_GRP_ID 
				LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LGR ON LGR.LGR_ID =PO.AGENT_ID 
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID =LGR.CITY_ID 
				 "+@JOINSQL+"
				WHERE PO.CMP_CODE IN("+@CMP_CODE +") AND PO.GDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@CONDSQL+"
			
				) AS DATA  GROUP BY ID,DOCNO,BILLNO,FYEAR ,VCHDATE ,SUPPLIER , AGENT_NAME,AGENT_CITY,LOT_NAME,ITEM_NAME,WEAVER_NAME,TYPE ,ORD,
				ISNULL(ITEM_ID,0), ISNULL(LOT_ID,0) ,ISNULL(WEAVER_ID,0)  ,ISNULL(SUPP_GRP_ID,0),ISNULL(LGR_ID,0) , ISNULL(CITY_ID,0)
				ORDER BY "+@ORDERBY+"FYEAR,DOCNO,ID,ORD,TYPE "				

END
EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2


















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASEREGISTER]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO













/*
select * from tempdb..sysobjects where name like '##%'

PROC_PURCHASEREGISTER N'01/Apr/2018', N'31/Mar/2019', N'1', 18, N'Acc2018_2019.Dbo.', N'##2068', 0, N'0', 1, 4,1

*/
CREATE PROCEDURE [dbo].[PROC_PURCHASEREGISTER]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@QUERYNO INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@SELALL  INT,
@PURACCID NVARCHAR(20),
@CONVERSION INT,
@INVTYPE INT,
@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQLA AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)
DECLARE @SQL4 AS NVARCHAR(3999)
DECLARE @SQL5 AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @SELECTED1 AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(1000)
DECLARE @PURACCSQL AS NVARCHAR(1000)
DECLARE @PURACCSQLTP AS NVARCHAR(1000)
DECLARE @STRINVOICE AS NVARCHAR(200)
DECLARE @STRORDERBY AS NVARCHAR(100)
DECLARE  @ID AS NVARCHAR(1000)
SET @ID=""
SET @SQL=""
SET @SQLA=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SELECTED=""
SET @SELECTED1=""
SET @QUANTITYSQL=""
SET @PURACCSQL=""
SET @PURACCSQLTP=""
SET @STRINVOICE=""
SET @STRORDERBY=""
/* TO GET QUANTITY WITH AND WITHOUT */
BEGIN

SET @QUANTITYSQL="  PID.QUANTITY AS QUANTITY "
IF @CONVERSION =1
SET @QUANTITYSQL=" (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "   

END

IF @INVTYPE =1
SET @STRINVOICE=" AND PI.FLAG='P' "
ELSE IF  @INVTYPE =2
SET @STRINVOICE=" AND PI.FLAG='CHP'"
ELSE IF  @INVTYPE =3
SET @STRINVOICE=" AND PI.FLAG='MIP' "
ELSE IF  @INVTYPE =4
SET @STRINVOICE="  "

BEGIN

IF @QUERYNO IN (1)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON TRM.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" LM.LGR_NAME,"
END
ELSE IF @QUERYNO IN (2)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON LM.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" SGM.SUPP_GRP_NAME,"
END
ELSE IF @QUERYNO IN (3)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON LD.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" ALM.LGR_NAME,"
END
ELSE IF @QUERYNO IN (4)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" IM.ITEM_NAME,"
END
ELSE IF @QUERYNO IN (5)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" "
END
ELSE IF @QUERYNO IN (6)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.WEAVER_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  WM.WEAVER_NAME,"
END
ELSE IF @QUERYNO = 7
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.SIZE_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=""
END
ELSE IF @QUERYNO IN (8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON TRM.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" LM.LGR_NAME,IM.ITEM_NAME,"
END
ELSE IF @QUERYNO IN (9)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" LEFT JOIN " + @TEMPTABLE + " ON LM.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  SGM.SUPP_GRP_NAME ,IM.ITEM_NAME,"
END
ELSE IF @QUERYNO IN (10)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON LD.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  ALM.LGR_NAME,IM.ITEM_NAME,"
END
ELSE IF @QUERYNO IN (11)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" IM.ITEM_NAME,SGM.SUPP_GRP_NAME,"
END
ELSE IF @QUERYNO IN (12)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PID.ITEM_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  IM.ITEM_NAME,LM.LGR_NAME,"
END
ELSE IF @QUERYNO IN (13)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON TRM.LGR_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,IGM.ITEM_GRP_NAME,IGM.ITEM_GRP_ID,"
END
ELSE IF @QUERYNO IN (14)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" LEFT JOIN " + @TEMPTABLE + " ON LM.SUPP_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" SGM.SUPP_GRP_NAME ,IGM.ITEM_GRP_NAME,"
END
ELSE IF @QUERYNO IN (15)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON LD.AGENT_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  ALM.LGR_NAME ,IGM.ITEM_GRP_NAME,"
END
ELSE IF @QUERYNO IN (16)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IGM.ITEM_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=" IGM.ITEM_GRP_NAME,SGM.SUPP_GRP_NAME,"
END
ELSE IF @QUERYNO IN (17)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON IGM.ITEM_GRP_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  IGM.ITEM_GRP_NAME,IGM.ITEM_GRP_ID,LM.LGR_NAME,LM.LGR_ID,"
END
ELSE IF @QUERYNO = 18
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON CONVERT(NVARCHAR,PI.BILLNO)=CONVERT(NVARCHAR," + @TEMPTABLE + ".CODE)"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON CONVERT(NVARCHAR,TRM.DOC_NO)=CONVERT(NVARCHAR," + @TEMPTABLE + ".CODE)"
END
ELSE IF @QUERYNO = 21
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON PI.PURACCID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON TRM.PurAccount_Id=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY="  PURM.LGR_NAME,"
END

ELSE IF @QUERYNO = 23
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON HSN.HSN_ID=" + @TEMPTABLE + ".CODE"
SET @SELECTED1=" INNER JOIN " + @TEMPTABLE + " ON HSN.HSN_ID=" + @TEMPTABLE + ".CODE"

SET @STRORDERBY=""
END

ELSE IF @QUERYNO IN (22)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " ON LOM.LOT_ID=" + @TEMPTABLE + ".CODE"
SET @STRORDERBY=""
END

IF @SELALL=1  /* FOR ALL OPTION SELECTION */
BEGIN    
SET @SELECTED=""
SET @SELECTED1=""
END

BEGIN
IF @QUERYNO = 21 
SET @PURACCSQL = ""
END

BEGIN
IF @PURACCID<>0
BEGIN
SET @PURACCSQL = "PI.PURACCID="+ @PURACCID +" AND "	
SET @PURACCSQLTP="TRM.PurAccount_Id="+ @PURACCID +" AND "	
END
ELSE
BEGIN
SET @PURACCSQL = ""
SET @PURACCSQLTP=""
END
END

SET @SQL="
SELECT PI.PURCHASEINVID,CONVERT(NVARCHAR,PI.BILLNO)BILLNO,PI.VCHDATE AS DATE,LM.LGR_NAME AS PARTYNAME,LM.LGR_ID,ALM.LGR_NAME AS AGENT,ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,SGM.SUPP_GRP_NAME AS SUPPLIER,PI.LOTNO,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
"+@QUANTITYSQL+" ,
PID.AMOUNT AS AMOUNT,PID.RATE,PI.NETTOTAL,(PI.ADDTOTAL-PI.LESSTOTAL+PI.PUR_INV_ROUNDOFF) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,PI.PURACCID,PURM.LGR_NAME AS PURACC_NAME,PI.FLAG,
ISNULL(LOM.LOT_NAME,'')AS GREYMARKA,ISNULL(SM.SIZE_NAME,'') AS SIZE_NAME,ISNULL(IM.NICK_NAME,'') AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(WM.WEAVER_ID,0) AS WEAVER_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
ISNULL( LOM.LOT_ID,0) AS LOT_ID,ISNULL(SM.SIZE_ID,0) AS SIZE_ID,IGM.ITEM_GRP_ID,
(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) + ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
PI.Pur_Inv_Add4 AS CGST,PI.Pur_Inv_Add5 AS SGST, PI.Pur_Inv_Add6 AS IGST,
PI.PUR_INV_ROUNDOFF,
UM.UQC,(ISNULL(PI.PUR_INV_ADD4_SET,0)+ISNULL(PI.PUR_INV_ADD5_SET,0)+ISNULL(PI.PUR_INV_ADD6_SET,0))GST_PER,0 AS CESSAMT,HSN.HSN_ID,HSN.HSN_NAME,PI.DOCNO
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
