'' AS GREYMARKA,'' AS SIZE_NAME,'' AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
0 AS ITEM_ID,0 AS WEAVER_ID,0 AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
0 AS LOT_ID,0 AS SIZE_ID,0 AS ITEM_GRP_ID,(ISNULL((TOTALFARE_AMOUNT),0)) AS TAXABLEAMT,
ISNULL((TRM.CGST),0) AS CGST,ISNULL((TRM.SGST ),0)  AS SGST ,ISNULL((TRM.IGST ),0)  AS IGST ,0 as PUR_INV_ROUNDOFF,
'' AS UQC,(ISNULL(TRM.CGSTPER,0)+ISNULL(TRM.SGSTPER,0)+ISNULL(TRM.IGSTPER,0))GST_PER,0 AS CESSAMT ,HSN.HSN_ID,HSN.HSN_NAME,TRM.DOC_NO     
