-- =============================================
-- Author:		<SHUBHAM RAVAL>
-- ALTER date: <12.08.2017>
-- Description:	<GST SALE REGISTER>
-- =============================================
/*
PROC_PURCHASEREGISTERGST '01/APR/2018', N'31/MAR/2019',  N'Acc2018_2019.Dbo.',N'1', N'', 1,0,0,2,2

PROC_PURCHASEREGISTERGST N'01/APR/2018', N'31/Jul/2018', N'Acc2018_2019.Dbo.', N'1', N'##5416', 0, N'2919', 2, 2, 2
SELECT * FROM Acc2016_2017.Dbo.LEDGER_MASTER WHERE LGR_NAME LIKE 'SALES%'
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'

*/
CREATE PROCEDURE [dbo].[PROC_PURCHASEREGISTERGST]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
	@SelAll  int,
    @HeadId nvarchar(20),
    @Rpt_Wise int,
    @Register_Dealer int,
    @InvoiceType int
  
    
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)
DECLARE @SQL4 AS NVARCHAR(3999)

DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @SELECTEDt AS NVARCHAR(1000)

DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE @REG_DEALERSQL AS NVARCHAR(4000)
DECLARE  @Type AS NVARCHAR(1000)
DECLARE  @ID AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""


SET @SELECTED=""
SET @QUANTITYSQL=""
SET @NET_SNETSQL=""
SET @Type=""
SET @ID=""
--set nocount on;





BEGIN
	IF @Register_Dealer=1 

		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='Registered Dealer'"
 
		else IF @Register_Dealer=2

		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='UnRegistered Dealer' "  

		else IF @Register_Dealer=3
	
		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='Composition Dealer' " 
		else IF @Register_Dealer=4
	
		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE= 'Export Dealer' " 
		else 
	
		set @REG_DEALERSQL=" " 
	
END


BEGIN    
  SET @QUANTITYSQL=" (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "    
END

BEGIN
	IF @SelAll=0
	  BEGIN 
		IF @Rpt_Wise in (1)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.AGENT_ID=TT.CODE"
			  SET @SELECTEDT=" INNER JOIN " + @TempTable + " TT ON LD.AGENT_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (2)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.LGR_ID=TT.CODE"
				SET @SELECTEDT=" INNER JOIN " + @TempTable + " TT ON TRM.LGR_ID=TT.CODE"
			 END 		
		ELSE IF @Rpt_Wise = 4
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.BILLNO=TT.CODE"
			   SET @SELECTEDT=" INNER JOIN " + @TempTable + " TT ON TRM.DOC_NO=TT.CODE"
			 END 
	    ELSE IF @Rpt_Wise = 3
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.AGENT_ID=TT.CODE"
			   SET @SELECTEDT=" INNER JOIN " + @TempTable + " TT ON LD.AGENT_ID=TT.CODE"
			 END 
	END


ELSE
 BEGIN 
SET @SELECTED=" "
			  SET @SELECTEDT=" "
END 
END
	BEGIN
	IF @HeadId<>0
	  BEGIN
			   SET @ID=" PI.PURACCID="+@HeadId+" AND "
	  END
	END

	BEGIN
SET @SQL="
SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT
,ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,
ISNULL(SM1.State_Code,0) AS STATECODE,
ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
SGM.SUPP_GRP_NAME AS SUPPLIER,PI.LOTNO,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
"+@QUANTITYSQL+" ,
PID.AMOUNT AS AMOUNT,PID.RATE,PI.NETTOTAL,(PI.ADDTOTAL-PI.LESSTOTAL+PI.PUR_INV_ROUNDOFF) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,PI.PURACCID,PURM.LGR_NAME AS PURACC_NAME,PI.FLAG,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,'' AS SIZE_NAME,'' AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(WM.WEAVER_ID,0) AS WEAVER_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
ISNULL( LOM.LOT_ID,0) AS LOT_ID,0 AS SIZE_ID,IGM.ITEM_GRP_ID,
(ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) as ADDLESSTOTAL,
(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) + ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
PI.Pur_Inv_Add4 AS CGST,
PI.Pur_Inv_Add5 AS SGST, 
PI.Pur_Inv_Add6 AS IGST,
PI.FLAG,PI.PUR_INV_ROUNDOFF,
UM.UQC,(ISNULL(PI.PUR_INV_ADD4_SET,0)+ISNULL(PI.PUR_INV_ADD5_SET,0)+ISNULL(PI.PUR_INV_ADD6_SET,0))GST_PER,0 AS CESSAMT
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
"+@SELECTED+"
WHERE   "+@ID+" PI.CMP_CODE IN ("+ @CMP_CODE +")  "+@REG_DEALERSQL+"AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'and PI.FLAG IN ('P','JP','FP')  
ORDER BY VCHDATE,BILLNO,LM.LGR_NAME  "
SET @SQL1="

SELECT PI.PURCHASEINVID,PI.BILLNO AS BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,
ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,
ISNULL(SM1.State_Code,0) AS STATECODE,
ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
SGM.SUPP_GRP_NAME AS SUPPLIER,PI.LOTNO,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
"+@QUANTITYSQL+" ,
ISNULL(PID.GROSSAMOUNT,0) AS AMOUNT,PID.RATE,PI.NETTOTAL,(PI.ADDTOTAL-PI.LESSTOTAL+PI.PUR_INV_ROUNDOFF) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,PI.PURACCID,PURM.LGR_NAME AS PURACC_NAME,PI.FLAG,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,'' AS SIZE_NAME,'' AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(WM.WEAVER_ID,0) AS WEAVER_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
ISNULL( LOM.LOT_ID,0) AS LOT_ID,0 AS SIZE_ID,IGM.ITEM_GRP_ID,
(ISNULL(PID.ADDAMOUNT,0) -ISNULL(PID.LESSAMOUNT,0))  as ADDLESSTOTAL,ISNULL(PID.amount,0) AS TAXABLEAMT,PID.VAT_AMT AS CGST,
PID.VATAMOUNT1 AS SGST,
PID.VATAMOUNT2 AS IGST,
PI.FLAG,PI.PUR_INV_ROUNDOFF,
UM.UQC,(ISNULL(PID.VAT_PER,0)+ISNULL(PID.VAT_PER1,0)+ISNULL(PID.VAT_PER2,0))GST_PER,0 AS CESSAMT
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
"+@SELECTED+"
WHERE   "+@ID+" PI.CMP_CODE IN ("+ @CMP_CODE +") "+@REG_DEALERSQL+" AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' and PI.FLAG ='RP' "+@Type+" 
--ORDER BY VCHDATE,BILLNO ,LM.LGR_NAME
"
SET @SQL3=" union all
SELECT TRM.TRANSPORTPAYMENTID as PURCHASEINVID,TRM.DOC_NO AS BILLNO,TRM.DATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME as agent,
ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,ISNULL(SM1.State_Code,0) AS STATECODE,ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
'' as SUPPLIER,'' as lotno,0 as BALENO,'' AS ITEM,0 AS PIECES, 0 AS QUANTITY, (TOTALFARE_AMOUNT ) AS AMOUNT, 0 AS RATE, 
		(ISNULL((TOTALFARE_AMOUNT),0)  + (ISNULL((TRM.CGST),0)   + ISNULL((TRM.SGST),0)
 + ISNULL((TRM.IGST),0))) AS NetTotal,0 AS addless,COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,'' AS WEAVER_NAME,'' AS ITEM_GRP_NAME,TRM.PurAccount_Id,PURM.LGR_NAME AS PURACC_NAME,'T'AS FLAG,
'' AS GREYMARKA,'' AS SIZE_NAME,'' AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
0 AS ITEM_ID,0 AS WEAVER_ID,0 AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
0 AS LOT_ID,0 AS SIZE_ID,0 AS ITEM_GRP_ID,0 as ADDLESSTOTAL,
(ISNULL((TOTALFARE_AMOUNT),0)) AS TAXABLEAMT,
ISNULL((TRM.CGST),0) AS CGST,ISNULL((TRM.SGST ),0)  AS SGST ,ISNULL((TRM.IGST ),0)  AS IGST ,'T'AS FLAG,0 as PUR_INV_ROUNDOFF,
'' AS UQC,(ISNULL(TRM.CGSTPER,0)+ISNULL(TRM.SGSTPER,0)+ISNULL(TRM.IGSTPER,0))GST_PER,0 AS CESSAMT

 FROM  "+ @DATABASENAME + "TRANSPORT_PAYMENT TRM
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TRM.PurAccount_Id
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TRM.CMP_CODE = LD.CMP_CODE
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=TRM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=TRM.PurAccount_Id
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN "+ @DATABASENAME + "Hsn_Master HSM ON HSM.Hsn_Id=TRM.Hsn_Id
LEFT JOIN "+ @DATABASENAME + "STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID 
"+@SELECTEDT+" 
WHERE  TRM.PurAccount_Id="+@HeadId+" AND TRM.CMP_CODE IN ("+ @CMP_CODE +") "+@REG_DEALERSQL+" AND
TRM.DATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' 
ORDER BY VCHDATE,BILLNO,LM.LGR_NAME"

SET @SQL2="

SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,
ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,
ISNULL(SM1.State_Code,0) AS STATECODE,
ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
SGM.SUPP_GRP_NAME AS SUPPLIER,PI.LOTNO,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (PID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY ,
ISNULL(PID.GROSSAMOUNT,0) AS AMOUNT,PID.RATE,PI.NETTOTAL,(PI.ADDTOTAL-PI.LESSTOTAL+PI.PUR_INV_ROUNDOFF) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,PI.PURACCID,PURM.LGR_NAME AS PURACC_NAME,PI.FLAG,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,'' AS SIZE_NAME,''AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(WM.WEAVER_ID,0) AS WEAVER_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
ISNULL( LOM.LOT_ID,0) AS LOT_ID,0 AS SIZE_ID,IGM.ITEM_GRP_ID,
(ISNULL(PID.ADDAMOUNT,0) -ISNULL(PID.LESSAMOUNT,0))  as ADDLESSTOTAL,
(ISNULL(PID.Amount,0)) AS TAXABLEAMT,PID.VAT_AMT AS CGST,
PID.VATAMOUNT1 AS SGST,
PID.VATAMOUNT2 AS IGST,
PI.FLAG,PI.PUR_INV_ROUNDOFF,
UM.UQC,(ISNULL(PID.VAT_PER,0)+ISNULL(PID.VAT_PER1,0)+ISNULL(PID.VAT_PER2,0))GST_PER,ISNULL(CESSAMT,0)CESSAMT
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
"+@SELECTED+"
WHERE "+@ID+" PI.CMP_CODE IN ("+ @CMP_CODE +")  "+@REG_DEALERSQL+" AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' and
PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B' ORDER BY PI.VCHDATE,PI.BILLNO,LM.LGR_NAME 
"

SET @SQL4="

SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,
ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,
ISNULL(SM1.State_Code,0) AS STATECODE,
ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
SGM.SUPP_GRP_NAME AS SUPPLIER,PI.LOTNO,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (PID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY ,
ISNULL(PID.GROSSAMOUNT,0) AS AMOUNT,PID.RATE,PI.NETTOTAL,(PI.ADDTOTAL-PI.LESSTOTAL+PI.PUR_INV_ROUNDOFF) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,PI.PURACCID,PURM.LGR_NAME AS PURACC_NAME,PI.FLAG,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,'' AS SIZE_NAME,''AS NICK_NAME,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(LM.LGR_ID,0) AS PARTY_ID,ISNULL(ALM.LGR_ID,0) AS AGENT_ID,
ISNULL(IM.ITEM_ID,0) AS ITEM_ID,ISNULL(WM.WEAVER_ID,0) AS WEAVER_ID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(PURM.LGR_ID,0) AS PURCHASEACC_ID,
ISNULL( LOM.LOT_ID,0) AS LOT_ID,0 AS SIZE_ID,IGM.ITEM_GRP_ID,
(ISNULL(PID.ADDAMOUNT,0) -ISNULL(PID.LESSAMOUNT,0))  as ADDLESSTOTAL,
(ISNULL(PID.Amount,0)) AS TAXABLEAMT,PID.VAT_AMT AS CGST,
PID.VATAMOUNT1 AS SGST,
PID.VATAMOUNT2 AS IGST,
PI.FLAG,PI.PUR_INV_ROUNDOFF,
UM.UQC,(ISNULL(PID.VAT_PER,0)+ISNULL(PID.VAT_PER1,0)+ISNULL(PID.VAT_PER2,0))GST_PER,ISNULL(CESSAMT,0)CESSAMT
FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
"+@SELECTED+"
WHERE "+@ID+" PI.CMP_CODE IN ("+ @CMP_CODE +")  "+@REG_DEALERSQL+" AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' and
PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'A' ORDER BY PI.VCHDATE,PI.BILLNO,LM.LGR_NAME 
"

END


IF @InvoiceType=1
	BEGIN
		EXEC SP_EXECUTESQL @SQL
		PRINT @SQL
	END	
ELSE IF @InvoiceType=2
	BEGIN
		EXEC (@SQL1+@SQL3)
		PRINT @SQL1
		PRINT @SQL3
	END		
ELSE IF @InvoiceType=3
	BEGIN
		EXEC SP_EXECUTESQL @SQL2
		PRINT @SQL2
	END	
	
ELSE IF @InvoiceType=4
BEGIN
EXEC SP_EXECUTESQL @SQL4
PRINT @SQL4
END		




















GO

