/*   PROC_PURCHASEREGISTERGSTEWAYBIL N'01/Apr/2022', N'12/JULY/2022', N'Acc2022_2023.Dbo.', N'1', N'##664', 0 */


CREATE PROCEDURE [dbo].[PROC_PURCHASEREGISTERGSTEWAYBIL]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
    @Rpt_Wise int
   
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)

DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @REG_DEALERSQL AS NVARCHAR(4000)
DECLARE @REG_DEALERTYPE AS NVARCHAR(4000)


SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SELECTED=""
SET @NET_SNETSQL=""	



	SET NOCOUNT ON;

       BEGIN 
		IF @Rpt_Wise in (1)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.AGENT_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (2)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PI.LGR_ID=TT.CODE"
			 END 		
		ELSE IF @Rpt_Wise = 3
			 BEGIN
				
		     SET @SELECTED=""
			 END 
	
	END	



SET @SQL=" SELECT PI.PurchaseInvId,PI.BillNo AS BILLNO,PI.VchDate AS PURDATE,LM.LGR_NAME AS PARTYNAME,AGM.Lgr_NAME AS AGENTNAME,PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,
    convert(nvarchar,ISNULL(LM.GSTINNO,0)) AS PARTYGSTNO ,(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0)+ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
    ISNULL(PI.Pur_Inv_Add4,0) as CGST,ISNULL(PI.Pur_Inv_Add5,0) as SGST,ISNULL(PI.Pur_Inv_Add6,0) as IGST,PI.PurAccId,PI.FLAG,PAC.LGR_NAME AS PURACC_NAME,PI.PUR_FORM_TYPE,PI.PUR_INV_ROUNDOFF,PI.NetTotal AS NETAMT,PI.EINVNO,PI.EWAYBILLNO
    FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
    INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID and PI.FLAG=PID.FLAG
    INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
    LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=PI.AGENT_ID
    LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
    LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
    LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID 
    INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
    INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER PAC ON PAC.LGR_ID=PI.PurAccId
    "+ @SELECTED +"
     WHERE  PI.Cmp_Code in ("+ @Cmp_Code +")  AND  PI.FLAG NOT IN ('CHP','RP')  AND PI.VCHDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "' "

SET @SQL1 = " UNION ALL  

--            SELECT PARTYNAME,PURCHASEINVID,BILLNO,CONVERT(NVARCHAR,VchDate,103) AS PURDATE,PARTYGSTNO,MAX(TAXABLEAMT),MAX(CGST),MAX(SGST),MAX(IGST),MAX(PurAccId),MAX(NETAMT),MAX(PURACC_NAME),MAX(PUR_FORM_TYPE),MAX(PUR_INV_ROUNDOFF),MAX(FLAG)
--            FROM (
            SELECT PI.PurchaseInvId,PI.BillNo AS BILLNO,PI.VchDate AS PURDATE,LM.LGR_NAME AS PARTYNAME,MAX(AGM.Lgr_NAME) AS AGENTNAME,MAX(PCM.CITY_NAME) AS PARTYCITY ,MAX(ACM.CITY_NAME) AS AGENTCITY,MAX(SM.STATE_NAME) AS STATE,convert(nvarchar,ISNULL(LM.GSTINNO,0)) AS PARTYGSTNO,MAX(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0) + ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,max(VAT_AMT) AS CGST,MAX(VATAMOUNT1) AS SGST,MAX(VATAMOUNT2) AS IGST,
            MAX(PI.PurAccId),MAX(PI.FLAG),MAX(PAC.LGR_NAME) AS PURACC_NAME,MAX(PI.PUR_FORM_TYPE),MAX(PI.PUR_INV_ROUNDOFF),MAX(PI.NetTotal) AS NETAMT,max(PI.EINVNO),MAX(PI.EWAYBILLNO)
            FROM "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID 
            INNER JOIN  "+ @DATABASENAME + " PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
            INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
            LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=PI.AGENT_ID
            LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
            LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
            LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID 
            left JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
            INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER PAC ON PAC.LGR_ID=PI.PurAccId
            "+ @SELECTED +"
            WHERE  PI.Cmp_Code in ("+ @Cmp_Code +")  AND PI.FLAG IN ('CHP') AND PI.PUR_FORM_TYPE = 'A' AND PI.VCHDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "' 
            GROUP BY   LM.LGR_NAME,PI.PURCHASEINVID,PI.BILLNO,PI.VchDate,LM.GSTINNO
            ORDER BY BILLNO,PURCHASEINVID,PURDATE
            
"

 
BEGIN
		EXEC(@SQL+@SQL1)
		PRINT @SQL
		PRINT @SQL1
		END







GO

