/*


-- =============================================
-- AUTHOR:		<MAYAL SADHU>
-- CREATE_DATE: <15/OCT/2020>
-- DESCRIPTION:	<FOR PURCHASEREGISTER TCS>
-- REPORT NAME: <PURCHASEREGISTERTCS.RPT>
-- =============================================
PROC_PURCHASEREGISTERTCS N'01/Apr/2020', N'31/Mar/2021', N'1', 1, N'Acc2020_2021.Dbo.', N'##5952', 0, N'2919', 1

select * from tempdb..sysobjects
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASEREGISTERTCS]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),
	@Cmp_Code nvarchar(100),
	@QueryNo int,
	@DatabaseName nvarchar(50),
	@TempTable nvarchar(20),
	@SelAll  int,
	@PurAccID nvarchar(20),
    @CONVERSION int
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)

DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(1000)
DECLARE  @ID AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""

SET @SELECTED=""
SET @QUANTITYSQL=""
SET @ID=""


/* TO GET QUANTITY WITH AND WITHOUT */
BEGIN

     SET @QUANTITYSQL="  PID.QUANTITY AS QUANTITY "
     IF @CONVERSION =1
     SET @QUANTITYSQL=" (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
                        ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) as QUANTITY "   
    
END

BEGIN
IF @SelAll=0  /* FOR ALL OPTION SELECTION */
  BEGIN    
	   IF @QueryNo IN (1,6,11)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LGR_ID=" + @TempTable + ".CODE"
	   IF @QueryNo IN (2,7,12)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.SUPP_GRP_ID=" + @TempTable + ".CODE"
	   IF @QueryNo IN (3,8,13)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.AGENT_ID=" + @TempTable + ".CODE"
	   IF @QueryNo IN (4,9,10)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.ITEM_ID=" + @TempTable + ".CODE"
       IF @QueryNo IN (5)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PID.WEAVER_ID=" + @TempTable + ".CODE"
       IF @QueryNo IN (14,15)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON IGM.ITEM_GRP_ID=" + @TempTable + ".CODE"
	   IF @QueryNo = 16
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.BILLNO=" + @TempTable + ".CODE"
		IF @QueryNo = 19
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON PI.LOTNO=" + @TempTable + ".CODE"
		IF @QueryNo IN (20,21)
	   SET @SELECTED=" INNER JOIN " + @TempTable + " ON GM.GODOWN_ID =" + @TempTable + ".CODE"

   END
	
BEGIN
	IF @PurAccID<>0
	  BEGIN
			   SET @ID=" PI.PURACCID="+@PurAccID+" AND "
	  END
	END


SET @SQL="
	       SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,SGM.SUPP_GRP_NAME AS SUPPLIER,PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,PI.LOTNO,
           "+@QUANTITYSQL+" ,
           PID.AMOUNT AS AMOUNT,PID.RATE,PI.NETTOTAL,(ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0)+ISNULL(PI.Pur_Inv_Add3,0)-PI.LESSTOTAL) AS ADDLESS,
           COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
           COMP.CMP_MOBILE,COMP.CMP_FAX,WM.WEAVER_NAME,IGM.ITEM_GRP_NAME,
			(ISNULL(PI.GrossTotal,0) +ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0)+ISNULL(PI.Pur_Inv_Add3,0) -( ISNULL(PI.Pur_Inv_Less1,0) + ISNULL(PI.Pur_Inv_Less2,0) + ISNULL(PI.Pur_Inv_Less3,0) + ISNULL(PI.Pur_Inv_Less4,0)+ ISNULL(PI.Pur_Inv_Less5,0))) AS TAXABLEAMT,
			ISNULL(PI.Pur_Inv_Add4,0) as CGST,ISNULL(PI.Pur_Inv_Add5,0) as SGST,ISNULL(PI.Pur_Inv_Add6,0) as IGST,
		    (ISNULL(PI.Pur_Inv_Add4,0) + ISNULL(PI.Pur_Inv_Add5,0) + ISNULL(PI.Pur_Inv_Add6,0)) AS GSTAMT,PI.PurAccId,PI.FLAG,PI.DOCNO,PAC.LGR_NAME AS PURACC_NAME,ISNULL(GM.GODOWN_NAME,'') AS GODOWN,PID.SRNO, PI.PUR_FORM_TYPE,PI.TCS_PER,PI.TCS_AMT,pi.Pur_Inv_RoundOff
           FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
           INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID and PI.FLAG=PID.FLAG
           INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
           LEFT  JOIN  "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
           INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
           INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
           LEFT JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
           LEFT JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
           LEFT JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
           INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
			LEFT JOIN "+ @DATABASENAME + "GODOWN_MASTER GM ON GM.GODOWN_ID = PI.GODOWN_ID
			INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER PAC ON PAC.LGR_ID=PI.PurAccId
            "+ @SELECTED +"
           WHERE "+@ID+"  PI.Cmp_Code in ("+ @Cmp_Code +")  AND  PI.FLAG NOT IN ('CHP','RP')  AND PI.VCHDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "' "
           
SET @SQL1 = " UNION ALL

		SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,SGM.SUPP_GRP_NAME AS SUPPLIER,(PID.BALENO) AS BALENO,(IM.ITEM_NAME) AS ITEM,(PID.PIECES) AS PIECES,PI.LOTNO,
		(PID.QUANTITY) AS QUANTITY ,
		(PID.AMOUNT) AS AMOUNT,(PID.RATE) RATE,(PI.NETTOTAL) NETTOTAL,(ISNULL(PI.Pur_Inv_Add1,0) + ISNULL(PI.Pur_Inv_Add2,0)+ISNULL(PI.Pur_Inv_Add3,0)-PI.LESSTOTAL) AS ADDLESS,
		COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
		COMP.CMP_MOBILE,COMP.CMP_FAX,(WM.WEAVER_NAME) AS WEAVER_NAME ,(IGM.ITEM_GRP_NAME) AS ITEM_GRP_NAME,
		(PI.NETTOTAL) AS TAXABLEAMT,(PID.VAT_AMT) AS CGST,
		(PID.VATAMOUNT1) AS SGST,(PID.VATAMOUNT2) AS IGST, ((ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))) AS GSTAMT,PI.PurAccId,PI.FLAG,PI.DOCNO,PAC.LGR_NAME AS PURACC_NAME,ISNULL(GM.GODOWN_NAME,'') AS GODOWN,PID.SRNO, PI.PUR_FORM_TYPE,PI.TCS_PER,PI.TCS_AMT,pi.Pur_Inv_RoundOff
		FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
		INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID and PI.FLAG=PID.FLAG
		INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
		LEFT  JOIN  "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
		INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
		INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
		LEFT JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
		LEFT JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
		LEFT JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
		INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
		INNER  JOIN "+ @DATABASENAME + "LEDGER_MASTER PAC ON PAC.LGR_ID=PI.PurAccId
		LEFT JOIN "+ @DATABASENAME + "GODOWN_MASTER GM ON GM.GODOWN_ID = PI.GODOWN_ID
		"+ @SELECTED +"
		WHERE  "+@ID+" PI.Cmp_Code in ("+ @Cmp_Code +")  AND PI.FLAG IN ('CHP') AND PI.PUR_FORM_TYPE = 'A' AND PI.VCHDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "' 
	
"


SET @SQL2="
UNION ALL

SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,
SGM.SUPP_GRP_NAME AS SUPPLIER,(PID.BALENO) AS BALENO ,(IM.ITEM_NAME) AS ITEM,(PID.PIECES) AS PIECES,PI.LOTNO,
(PID.QUANTITY) AS QUANTITY ,
(PID.GROSSAMOUNT) AS AMOUNT,(PID.RATE) RATE,(PI.NETTOTAL) NETTOTAL,(ISNULL(PID.ADDAMOUNT,0) - ISNULL(PID.LESSAMOUNT,0)) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,(WM.WEAVER_NAME) AS WEAVER_NAME ,(IGM.ITEM_GRP_NAME) AS ITEM_GRP_NAME,
(ISNULL(PID.Amount,0) - (ISNULL(PID.vat_amt,0) +  ISNULL(PID.VATAMOUNT1,0)  +  ISNULL(PID.VATAMOUNT2,0))) AS TAXABLEAMT,(PID.VAT_AMT) AS CGST,
(PID.VATAMOUNT1) AS SGST,(PID.VATAMOUNT2) AS IGST, ((ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))) AS GSTAMT,PI.PURACCID,PI.FLAG,PI.DOCNO,PURM.LGR_NAME AS PURACC_NAME,ISNULL(GM.GODOWN_NAME,'') AS GODOWN,PID.SRNO, PI.PUR_FORM_TYPE,PI.TCS_PER,PI.TCS_AMT,pi.Pur_Inv_RoundOff

FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
--LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
LEFT JOIN "+ @DATABASENAME + "GODOWN_MASTER GM ON GM.GODOWN_ID = PI.GODOWN_ID
"+@SELECTED+"
WHERE "+@ID+"  PI.CMP_CODE IN ("+ @CMP_CODE +") AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' and PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B' "


SET @SQL3="
UNION ALL

SELECT PI.PURCHASEINVID,PI.BILLNO,PI.VCHDATE  AS DATE,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENT,
SGM.SUPP_GRP_NAME AS SUPPLIER,(PID.BALENO) AS BALENO ,(IM.ITEM_NAME) AS ITEM,(PID.PIECES) AS PIECES,PI.LOTNO,
(PID.QUANTITY) AS QUANTITY ,
(PID.GROSSAMOUNT) AS AMOUNT,(PID.RATE) RATE,(PI.NETTOTAL) NETTOTAL,(ISNULL(PID.ADDAMOUNT,0) - ISNULL(PID.LESSAMOUNT,0)) AS ADDLESS,
COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
COMP.CMP_MOBILE,COMP.CMP_FAX,(WM.WEAVER_NAME) AS WEAVER_NAME ,(IGM.ITEM_GRP_NAME) AS ITEM_GRP_NAME,
(ISNULL(PID.Amount,0) - (ISNULL(PID.vat_amt,0) +  ISNULL(PID.VATAMOUNT1,0)  +  ISNULL(PID.VATAMOUNT2,0))) AS TAXABLEAMT,(PID.VAT_AMT) AS CGST,
(PID.VATAMOUNT1) AS SGST,(PID.VATAMOUNT2) AS IGST, ((ISNULL(PID.VAT_AMT,0) + ISNULL(PID.VATAMOUNT1,0) + ISNULL(PID.VATAMOUNT2,0))) AS GSTAMT,PI.PURACCID,PI.FLAG,PI.DOCNO,PURM.LGR_NAME AS PURACC_NAME,ISNULL(GM.GODOWN_NAME,'') AS GODOWN,PID.SRNO, PI.PUR_FORM_TYPE,PI.TCS_PER,PI.TCS_AMT,pi.Pur_Inv_RoundOff

FROM "+ @DATABASENAME + "PURCHASEINVOICE PI
INNER JOIN "+ @DATABASENAME + "PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
LEFT  JOIN "+ @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PI.AGENT_ID
INNER JOIN "+ @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
INNER JOIN "+ @DATABASENAME + "UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT  JOIN "+ @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT  JOIN "+ @DATABASENAME + "WEAVER_MASTER WM ON WM.WEAVER_ID=PID.WEAVER_ID
LEFT  JOIN "+ @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER PURM ON PURM.LGR_ID=PI.PURACCID
--LEFT  JOIN "+ @DATABASENAME + "LOT_MASTER LOM ON LOM.LOT_ID=PID.LOT_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT  JOIN "+ @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DatabaseName +"STATE_MASTER SM1 ON SM1.STATE_ID=PCM.STATE_ID     
left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = PI.TYPE_ID
LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
LEFT JOIN "+ @DATABASENAME + "GODOWN_MASTER GM ON GM.GODOWN_ID = PI.GODOWN_ID
"+@SELECTED+"
WHERE "+@ID+"  PI.CMP_CODE IN ("+ @CMP_CODE +") AND
PI.VCHDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "' and PI.FLAG ='RP' 
ORDER BY VCHDATE,BILLNO,LOTNO,PURCHASEINVID,PARTYNAME,ITEM "


      
END	
EXEC (@SQL+ @SQL1 +@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3


















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASESUMMARY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
