/*
PROC_PURCHASESUMMARY 1,'acc2014_2015.dbo.',1,'01/apr/2014','31/mar/2015','##3704',1
*/

CREATE PROCEDURE [dbo].[PROC_PURCHASESUMMARY]
(
    @Cmp_Code nvarchar(50),
    @DATABASENAME  nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),    
    @ToDate as Nvarchar(20),    
    @TempTable nvarchar(20),
	@OrderType int
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
Declare @StrOrderType Nvarchar(100) set @StrOrderType=""
set @JoinSql=""
Set @TypeSql=""

if @Rpt_Wise=0
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code =IM.Item_Type_ID"
if @Rpt_Wise=1
	set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_Grp_ID"

if @OrderType=1
	set @StrOrderType =" AND PRI.FLAG='P'"
else 
	set @StrOrderType =" AND PRI.FLAG<>'P' "

begin
    	SET NOCOUNT ON;
	if @Rpt_Wise=0
		Begin
		set @sql="
			select distinct PRI.PurchaseInvID,PRID.Pieces,SGM.Supp_Grp_Name,ITM.Item_Type_Name as MainGroup			
			from "+ @DATABASENAME + "PurchaseInvoice PRI
			Inner Join "+ @DATABASENAME + "PurchaseInvoice_Detail PRID ON PRI.PurchaseInvID = PRID.PurchaseInvID  and PRI.Flag=PRID.Flag
			LEFT Join "+ @DATABASENAME + "Supplier_Group_Master SGM ON PRI.Supp_Grp_ID = SGM.Supp_Grp_ID			
			Inner  Join "+ @DATABASENAME + "Item_Master IM ON PRID.Item_ID = IM.Item_ID  
			Inner Join "+ @DATABASENAME + "Item_Type_Master ITM ON IM.Item_Type_ID = ITM.Item_Type_ID  			  
		    "+ @JoinSql +"
			where  PRI.RecDate>='" + @FromDate + "' and PRI.RecDate<='" + @ToDate + "'  and PRI.Cmp_Code in ("+ @Cmp_Code +")  
			"+@StrOrderType+"
"
			
		end 
	if @Rpt_Wise=1
		begin
			set @sql="
			select distinct PRI.PurchaseInvID,PRID.Pieces,SGM.Supp_Grp_Name,ITM.Item_Grp_Name as MainGroup			
			from "+ @DATABASENAME + "PurchaseInvoice PRI
			Inner Join "+ @DATABASENAME + "PurchaseInvoice_Detail PRID ON PRI.PurchaseInvID = PRID.PurchaseInvID  and PRI.Flag=PRID.Flag
			Inner Join "+ @DATABASENAME + "Supplier_Group_Master SGM ON PRI.Supp_Grp_ID = SGM.Supp_Grp_ID			
			Inner  Join "+ @DATABASENAME + "Item_Master IM ON PRID.Item_ID = IM.Item_ID  
			Inner Join "+ @DATABASENAME + "Item_Group_Master ITM ON IM.Item_Grp_ID = ITM.Item_Grp_ID  			  
			"+ @JoinSql +"
			where  PRI.RecDate>='" + @FromDate + "' and PRI.RecDate<='" + @ToDate + "'  and PRI.Cmp_Code in ("+ @Cmp_Code +")  
			"+@StrOrderType+"
			"
		end 
		execute Sp_Executesql @sql
        Print @sql
end




















GO

