/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 26-02-2014
-- Description:	THIS PROCEDURE USED FOR PURCHASE TAX REPORT IN CHEMICAL PURCHASE INVOICE
-- ReportName : PURCHASETAX.RPT,PURCHASETAX_SUMMARY.RPT,PURCHASECATEGORYTAX.RPT
@R$
-- =============================================
PROC_PURCHASETAX '01-APR-2015','26-SEP-2016','2','ACC2015_2016.DBO.', 9,'##368',3
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASETAX]
(
	@FROMDATE NVARCHAR(50),
	@TODATE   NVARCHAR(50),
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@RPTWISE INT,
	@TEMPTABLE NVARCHAR(100),
	@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @SQLORDER AS NVARCHAR(1000)
DECLARE @SQLMAINGRP AS NVARCHAR(4000)
DECLARE @SQLGRP AS NVARCHAR(4000)
SET @SQL = ""
SET @SQLJOIN = ""
SET @SQLORDER = ""
SET @SQLMAINGRP = ""
SET @SQLGRP = ""

BEGIN
	IF @RPTWISE = 1 /* PURCHASE HEAD - ITEM */
	BEGIN	
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = PAM.LGR_ID "
		SET @SQLORDER = " ORDER BY PAM.LGR_NAME,IM.ITEM_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,MAX(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         IM.ITEM_NAME AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,IM.ITEM_NAME,CMP.CMP_ALIAS  ORDER BY PAM.LGR_NAME,IM.ITEM_NAME "
	END
	ELSE IF @RPTWISE = 2 /* ITEM - PURCHASE HEAD */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = IM.ITEM_ID "
		SET @SQLORDER = " ORDER BY IM.ITEM_NAME,PAM.LGR_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,MAX(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         IM.ITEM_NAME AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,IM.ITEM_NAME,CMP.CMP_ALIAS  ORDER BY IM.ITEM_NAME,PAM.LGR_NAME "
	END
	ELSE IF @RPTWISE = 3 /* VATECATEGORY */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = VC.DOCNO "
		SET @SQLORDER = " ORDER BY VC.NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 MAX(PAM.LGR_NAME) AS PURCHASEACCOUNT,(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         MAX(IM.ITEM_NAME) AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*PID.VATAMOUNT,PID.VAT_PER,IM.ITEM_NAME,LM.Lgr_name,PAM.LGR_NAME,VC.NAME,PID.CHALLANNO,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,PID.PIECES,PID.QUANTITY,PID.RATE,PID.AMOUNT,PID.LESSAMOUNT,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,*/VC.NAME,CMP.CMP_ALIAS  ORDER BY VC.NAME "
	END
	ELSE IF @RPTWISE = 4 /* ITEM-VATECATEGORY */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = IM.ITEM_ID "
		SET @SQLORDER = " ORDER BY IM.ITEM_NAME,VC.NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 MAX(PAM.LGR_NAME) AS PURCHASEACCOUNT,(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         IM.ITEM_NAME AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*PAM.LGR_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/IM.ITEM_NAME,VC.NAME,CMP.CMP_ALIAS  ORDER BY IM.ITEM_NAME,VC.NAME "
	END
	ELSE IF @RPTWISE = 5 /* VATECATEGORY - ITEM */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = VC.DOCNO "
		SET @SQLORDER = " ORDER BY VC.NAME,IM.ITEM_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 MAX(PAM.LGR_NAME) AS PURCHASEACCOUNT,(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         IM.ITEM_NAME AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*PAM.LGR_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/IM.ITEM_NAME,VC.NAME,CMP.CMP_ALIAS  ORDER BY VC.NAME,IM.ITEM_NAME "
	END
	ELSE IF @RPTWISE = 6 /* PURCHASEHEAD-VATECATEGORY  */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = PAM.LGR_ID "
		SET @SQLORDER = " ORDER BY PAM.LGR_NAME,VC.NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         MAX(IM.ITEM_NAME) AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*IM.ITEM_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,VC.NAME,CMP.CMP_ALIAS  ORDER BY PAM.LGR_NAME,VC.NAME "
	END
	ELSE IF @RPTWISE = 7 /* PURCHASEHEAD-VATECATEGORY-ITEM  */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = PAM.LGR_ID "
		SET @SQLORDER = " ORDER BY PAM.LGR_NAME,VC.NAME,IM.ITEM_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,MAX(LM.LGR_NAME) AS PARTY,MAX(ISNULL(CM.CITY_NAME,'')) AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         IM.ITEM_NAME AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*IM.ITEM_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,PAM.LGR_NAME,VC.NAME,IM.ITEM_NAME,CMP.CMP_ALIAS  ORDER BY PAM.LGR_NAME,VC.NAME,IM.ITEM_NAME "
	END
		ELSE IF @RPTWISE = 8 /* PURCHASEHEAD-PARTY  */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = PAM.LGR_ID "
		SET @SQLORDER = " ORDER BY PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,MAX(ISNULL(VC.NAME,'')) AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         MAX(IM.ITEM_NAME) AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*IM.ITEM_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME,CMP.CMP_ALIAS  ORDER BY PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME "
	END
	ELSE IF @RPTWISE = 9 /* PURCHASEHEAD-PARTY-VATECATEGORY */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = PAM.LGR_ID "
		SET @SQLORDER = " ORDER BY PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME,VC.NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,ISNULL(VC.NAME,'') AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         MAX(IM.ITEM_NAME) AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*IM.ITEM_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME,LM.Lgr_Cstno,VC.NAME,CMP.CMP_ALIAS  ORDER BY PAM.LGR_NAME,LM.LGR_NAME,CM.CITY_NAME,VC.NAME "
	END
	ELSE IF @RPTWISE = 10 /* VATECATEGORY-PARTY */
	BEGIN
		SET @SQLJOIN = " INNER JOIN  "+@TEMPTABLE+"  TT ON TT.CODE = VC.DOCNO"
		SET @SQLORDER = " ORDER BY VC.NAME,LM.LGR_NAME,CM.CITY_NAME,PUI.VCHDATE,PID.SRNO "
		SET @SQLMAINGRP = " MAX(PUI.DOCNO) AS DOCNO,MAX(PUI.BILLNO) AS BILLNO,
						MAX(PUI.VCHDATE) AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,MAX(LM.Lgr_Cstno) AS PARTY_TIN,
				 MAX(PAM.LGR_NAME) AS PURCHASEACCOUNT,ISNULL(VC.NAME,'') AS VATECATEGORY,MAX(PID.CHALLANNO) AS CHALLANNO,
		         MAX(IM.ITEM_NAME) AS ITEM,SUM(PID.PIECES) AS PIECES,SUM(PID.QUANTITY) AS QUANTITY,
				 SUM(PID.RATE) AS RATE,SUM(PID.AMOUNT) AS AMOUNT,SUM(ISNULL(PID.LESSAMOUNT,0)) AS LESSAMOUNT ,
				 SUM(PID.AMOUNT) AS NETAMOUNT,MAX(ISNULL(PID.VAT_PER,0)) AS VAT_PER,
				 SUM(ISNULL(PID.VATAMOUNT,0)) AS VATAMOUNT"
		SET @SQLGRP = "GROUP BY /*IM.ITEM_NAME,PID.VATAMOUNT,PID.VAT_PER,PID.LESSAMOUNT,PID.AMOUNT,PID.RATE,PID.QUANTITY,PID.PIECES,PID.CHALLANNO,VC.NAME,CM.CITY_NAME,PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE ,LM.LGR_NAME,*/VC.NAME,LM.LGR_NAME,CM.CITY_NAME,LM.Lgr_Cstno,CMP.CMP_ALIAS  ORDER BY VC.NAME,LM.LGR_NAME,CM.CITY_NAME "
	END
END
BEGIN
	SET NOCOUNT ON;
	IF @RPTTYPE = 1 /* DETAIL */
	BEGIN
	SET @SQL = " SELECT PUI.DOCNO,PUI.BILLNO,PUI.VCHDATE AS DATE,LM.LGR_NAME AS PARTY,ISNULL(CM.CITY_NAME,'') AS PARTYCITY,(LM.Lgr_Cstno) AS PARTY_TIN,
				 PAM.LGR_NAME AS PURCHASEACCOUNT,ISNULL(VC.NAME,'') AS VATECATEGORY,PID.CHALLANNO,
		         IM.ITEM_NAME AS ITEM,PID.PIECES,PID.QUANTITY,PID.RATE,PID.AMOUNT AS AMOUNT,ISNULL(PID.LESSAMOUNT,0) AS LESSAMOUNT ,
				 PID.AMOUNT AS NETAMOUNT,ISNULL(PID.VAT_PER,0) AS VAT_PER,ISNULL(PID.VATAMOUNT,0) AS VATAMOUNT,CMP.CMP_ALIAS 
				 
				 FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
				 INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PUI ON PUI.PURCHASEINVID = PID.PURCHASEINVID AND PUI.FLAG = PID.FLAG AND PUI.CMP_CODE = PID.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = PUI.LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER PAM ON PAM.LGR_ID = PUI.PURACCID
				 LEFT JOIN "+@DATABASENAME+" VATCATEGORYMASTER VC ON VC.DOCNO = PID./*SCREEN_ID*/VATCAT_ID  /*CHANGE BY DIPAL PATEL ON 27-040-2016*/
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = PUI.CMP_CODE
				 "+@SQLJOIN+"
				 WHERE PUI.CMP_CODE IN ("+@CMP_CODE+") 
				 AND PUI.FLAG IN ('CHP','MIP') 
				 AND PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
				 /*"+@SQLGRP+"*/ "
				/* "+@SQLORDER+"  "*/
	END
	ELSE IF @RPTTYPE = 2 /* SUMMARY */
	BEGIN
		SET @SQL = "SELECT "+@SQLMAINGRP+",CMP.CMP_ALIAS 
				 
				 FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
				 INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PUI ON PUI.PURCHASEINVID = PID.PURCHASEINVID AND PUI.FLAG = PID.FLAG AND PUI.CMP_CODE = PID.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = PUI.LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER PAM ON PAM.LGR_ID = PUI.PURACCID
				 LEFT JOIN "+@DATABASENAME+" VATCATEGORYMASTER VC ON VC.DOCNO = PID./*SCREEN_ID*/VATCAT_ID  /*CHANGE BY DIPAL PATEL ON 27-040-2016*/
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = PUI.CMP_CODE
				 "+@SQLJOIN+"
				 WHERE PUI.CMP_CODE IN ("+@CMP_CODE+") 
				 AND PUI.FLAG IN ('CHP','MIP') 
				 AND PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
				 "+@SQLGRP+" "
	END
	ELSE IF @RPTTYPE = 3 /* SUMMARY */
	BEGIN
		SET @SQL = "SELECT "+@SQLMAINGRP+",CMP.CMP_ALIAS ,SUM(CASE WHEN LM.Lgr_Pano IS NULL THEN 0 ELSE PID.AMOUNT END) VATDEALER ,SUM(CASE WHEN LM.Lgr_Pano IS NULL THEN PID.AMOUNT ELSE 0 END) NONVATDEALER
				 
				 FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
				 INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PUI ON PUI.PURCHASEINVID = PID.PURCHASEINVID AND PUI.FLAG = PID.FLAG AND PUI.CMP_CODE = PID.CMP_CODE
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = PUI.LGR_ID
				 LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
				 INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID = PID.ITEM_ID
				 INNER JOIN "+@DATABASENAME+" LEDGER_MASTER PAM ON PAM.LGR_ID = PUI.PURACCID
				 LEFT JOIN "+@DATABASENAME+" VATCATEGORYMASTER VC ON VC.DOCNO = PID./*SCREEN_ID*/VATCAT_ID  /*CHANGE BY DIPAL PATEL ON 27-040-2016*/
				 INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON CMP.CMP_CODE = PUI.CMP_CODE
					 "+@SQLJOIN+"
				 WHERE PUI.CMP_CODE IN ("+@CMP_CODE+") 
				 AND PUI.FLAG IN ('CHP','MIP') 
				 AND PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
				 "+@SQLGRP+" "
	END
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL































GO

