/*
-- =============================================
-- Author:		<SANJAY >
-- ALTER_date: <04/JULY/2017>
-- Description:	<PRINTTING INVOICE FOR WITHCUT>
-- REPORT NAME: SALESINVOICE_WITHCUT.rpt
-- =============================================
*/
/*
PROC_PURCHASETDSREPORT N'1', N'Acc2021_2022.Dbo.', N'Acc2020_2021.Dbo.', 1, N'##9240', N'01/Apr/2021', N'18/Jun/2021', 0, N'5000000'
select * from tempdb..sysobjects
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASETDSREPORT]
(
		@Cmp_Code NVARCHAR(100),
		@DATABASENAME NVARCHAR(50),
		@PreviousDatabaseName NVARCHAR(50),
		@RPT_WISE int,
		@TEMPTABLE NVARCHAR(20),		
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
		@RPTTYPE AS INT,
		@TotalAmt NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)
DECLARE @SQL4 AS NVARCHAR(3999)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)
DECLARE @SQLCOND NVARCHAR(3999)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL="" 
set @SQLCOND = ""
       IF @RPT_WISE = 1 
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		ELSE IF @RPT_WISE = 2
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AGM.LGR_ID"
		ELSE IF @RPT_WISE = 3
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"
		ELSE IF @RPT_WISE = 4
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.Supp_Grp_Id"
		BEGIN
			IF @RPTTYPE = 0 /* ALL */
				SET @SQLCOND = ""
			ELSE IF @RPTTYPE = 1 /* PENDING */
				SET @SQLCOND = " WHERE ReceviedAmtPRE + ReceviedAmtWithin > = "+ @TotalAmt +""

		END		


BEGIN
SET NOCOUNT ON;
SET @SQL="

		SELECT DISTINCT * FROM (
		SELECT  MAX(Lgr_Pano)Lgr_Pano,MAX(PARTYNAME)PARTYNAME,MAX(isnull(PARTYCITY,''))PARTYCITY,MAX(AGENTNAME)AGENTNAME,
		MAX(CUSTOMERGROUP)CUSTOMERGROUP,SUM(SalesAmtPRE)SalesAmtPRE,SUM(SalesAmtWhithin)SalesAmtWhithin,SUM(ReceviedAmtPRE )ReceviedAmtPRE,SUM(ReceviedAmtWithin)ReceviedAmtWithin,
		MAX(TCS_PER)TCS_PER,SUM(TCS_AMT)TCS_AMT,LGR_ID  FROM (

		SELECT CMP.CMP_CODE,LM.Lgr_Pano,UPPER(LM.LGR_NAME) AS PARTYNAME,
		UPPER(isnull(PCM.CITY_NAME,'')) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,
		PUI.NetTotal AS SalesAmtPRE, 0 as SalesAmtWhithin, 
		(ISNULL(PUI.GrossTotal,0) +ISNULL(PUI.Pur_Inv_Add1,0) + ISNULL(PUI.Pur_Inv_Add2,0)+ISNULL(PUI.Pur_Inv_Add3,0) -( ISNULL(PUI.Pur_Inv_Less1,0) + ISNULL(PUI.Pur_Inv_Less2,0) + ISNULL(PUI.Pur_Inv_Less3,0) + ISNULL(PUI.Pur_Inv_Less4,0)+ ISNULL(PUI.Pur_Inv_Less5,0))) as ReceviedAmtPRE,
		0 as ReceviedAmtWithin,PUI.TCS_PER,PUI.TCS_AMT ,LM.LGR_ID
		FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
		"+@JOINSQL+" 
		WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" )  AND PUI.FLAG IN ('P','FP','VAT') AND  PUI.VCHDATE<'"+@FROMDATE+"' "

		SET @SQL1="
		UNION ALL
		SELECT  CMP.CMP_CODE,LM.Lgr_Pano,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,
		UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,0 as SalesAmtPRE, 
		PUI.NetTotal as SalesAmtWhithin, 0 as ReceviedAmtPRE,
		(ISNULL(PUI.GrossTotal,0) +ISNULL(PUI.Pur_Inv_Add1,0) + ISNULL(PUI.Pur_Inv_Add2,0)+ISNULL(PUI.Pur_Inv_Add3,0) -( ISNULL(PUI.Pur_Inv_Less1,0) + ISNULL(PUI.Pur_Inv_Less2,0) + ISNULL(PUI.Pur_Inv_Less3,0) + ISNULL(PUI.Pur_Inv_Less4,0)+ ISNULL(PUI.Pur_Inv_Less5,0))) as ReceviedAmtWithin,
		PUI.TCS_PER,PUI.TCS_AMT ,LM.LGR_ID
		FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
		"+@JOINSQL+" 
		WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" ) AND PUI.FLAG IN ('P','FP','VAT') AND  PUI.VCHDATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "'"
		SET @SQL2="
		UNION ALL

		SELECT CMP.CMP_CODE,LM.Lgr_Pano,UPPER(LM.LGR_NAME) AS PARTYNAME,
		UPPER(isnull(PCM.CITY_NAME,'')) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,
		ISNULL(SUM(PURD.Amount),0) AS SalesAmtPRE, 0 as SalesAmtWhithin,ISNULL(SUM(PURD.finalAmount),0)-(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)) as ReceviedAmtPRE,
		0 as ReceviedAmtWithin,MAX(PUI.TCS_PER )TCS_PER ,MAX(PUI.TCS_AMT) TCS_AMT ,LM.LGR_ID
		FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUI.PurchaseInvId AND PURD.FLAG = PUI.FLAG
		INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
		"+@JOINSQL+" 
		WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" )  AND PUI.FLAG IN ('CHP') AND  PUI.VCHDATE<'"+@FROMDATE+"' 
		GROUP BY CMP.CMP_CODE,LM.Lgr_Pano,LM.LGR_NAME, PCM.CITY_NAME,AGM.LGR_NAME ,CGM.Supp_Grp_Name, LM.LGR_ID"

		SET @SQL3="
		UNION ALL
		SELECT  CMP.CMP_CODE,LM.Lgr_Pano,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,
		UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,0 as SalesAmtPRE, 
		ISNULL(SUM(PURD.Amount),0) as SalesAmtWhithin, 0 as ReceviedAmtPRE,
		ISNULL(SUM(PURD.finalAmount),0)-(ISNULL(SUM(PURD.vat_amt),0) +  ISNULL(SUM(PURD.VATAMOUNT1),0)  +  ISNULL(SUM(PURD.VATAMOUNT2),0)) as ReceviedAmtWithin,MAX(PUI.TCS_PER )TCS_PER ,MAX(PUI.TCS_AMT) TCS_AMT ,LM.LGR_ID
		FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
		INNER JOIN  "+@DATABASENAME+" PurchaseInvoice_Detail PURD ON  PURD.PurchaseInvId = PUI.PurchaseInvId AND PURD.FLAG = PUI.FLAG
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
		"+@JOINSQL+" 
		WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" ) AND PUI.FLAG IN ('CHP') AND  PUI.VCHDATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "'
		GROUP BY CMP.CMP_CODE,LM.Lgr_Pano,LM.LGR_NAME, PCM.CITY_NAME,AGM.LGR_NAME ,CGM.Supp_Grp_Name, LM.LGR_ID"
	SET @SQL4=" )AS DETAIL  GROUP BY Lgr_Pano,PARTYNAME,LGR_ID )as sd  
	inner join(
	SELECT  sum(PRESALE)PRESALE from ( select sum(PUI.Sal_inv_NetTotal )as PRESALE
	FROM "+ @PreviousDatabaseName+ "SALES_INVOICE PUI WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" ) 
	)pre ) c on  1=1  " + @SQLCOND + "
			"
      
END	

EXEC  (@SQL+@SQL1+@SQL2+@SQL3+@SQL4)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4


























GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASETRANS_REPORT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
  PROC_PURCHASETRANS_REPORT 1,'ACC2010_2011.DBO.','01/APR/2010','01/APR/2011','##230'
*/
CREATE PROCEDURE [dbo].[PROC_PURCHASETRANS_REPORT]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20)
   
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
SET @SQL=""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID"

BEGIN

SET @SQL="
        SELECT TVM.TRANSPORTVCH_ID,TM.TRANSPORT_NAME AS TRANSPORT,TVM.DOCNO AS BILLNO,TVM.VCHDATE,LM.LGR_NAME AS SUPPLIER
        ,PCM.CITY_NAME AS CITY,TVD.LRNO,TVD.LRDATE,TVD.BALES,TVD.RUKKANO,TVD.AMOUNT
        FROM "+@DATABASENAME+"TRANSPORTVOUCHER_MASTER  TVM
        INNER JOIN "+@DATABASENAME+"TRANSPORTVOUCHER_DETAIL TVD ON TVM.TRANSPORTVCH_ID=TVD.TRANSPORTVCH_ID
        INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TVM.ACCOUNT_ID
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
        INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=TVM.TRANSPORT_ID        
       "+@JOINSQL +"
        WHERE TVM.CMP_CODE="+@CMP_CODE +" AND TVM.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
       ORDER BY TVM.VCHDATE,TVD.SRNO
       "
END


EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURCHASRCHART]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_PURCHASRCHART]
(
     @DATABASENAME AS NVARCHAR(100),
     @CMP_CODE AS NVARCHAR(100),
     @CRITERIA AS INT,
     @ACCID AS NVARCHAR(50)    , 
     @PURACCID AS NVARCHAR(50)     
     
     
     
)		
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @GROUPBYNAME AS NVARCHAR(100)
DECLARE @CONDITION AS NVARCHAR(1000)
SET @SQL=""


SET @JOINSQL=""
SET @GROUPBYNAME =""

BEGIN  
         IF @CRITERIA=0     /*    PARTY WISE    */   
              BEGIN
                SET @JOINSQL=" INNER JOIN "+ @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PIN.LGR_ID"
                SET @GROUPBYNAME=" LM.LGR_NAME"
                SET @CONDITION =" (PIN.LGR_ID="+ @ACCID + " OR PIN.PURACCID="+ @ACCID + ")"
              END

         IF @CRITERIA=1     /*    SUPPLIER GROUP WISE    */   
              BEGIN
                SET @JOINSQL=" INNER JOIN "+ @DATABASENAME+"LEDGER_MASTER LM  ON LM.LGR_ID=PIN.LGR_ID
                           INNER JOIN "+ @DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID "
                SET @GROUPBYNAME=" LM.LGR_NAME"
                SET @CONDITION =" LM.SUPP_GRP_ID="+ @ACCID 
              END
         IF @CRITERIA=2     /*    CITY WISE    */   
             BEGIN
                  SET @JOINSQL=" INNER JOIN "+ @DATABASENAME+"LEDGER_MASTER LM  ON LM.LGR_ID=PIN.LGR_ID
                                 INNER JOIN "+ @DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID "
                  SET @GROUPBYNAME=" LM.LGR_NAME"
                  SET @CONDITION =" LM.CITY_ID="+ @ACCID 
             END
         IF @CRITERIA=3
            BEGIN
                  SET @JOINSQL=" INNER JOIN "+ @DATABASENAME+"LEDGER_MASTER LM  ON LM.LGR_ID=PIN.LGR_ID
                                 INNER JOIN "+ @DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID "
                  SET @GROUPBYNAME=" LM.LGR_NAME"
                  SET @CONDITION =" LM.STATE_ID="+ @ACCID 
            END
        
         IF @CRITERIA=4
            BEGIN
                   SET @JOINSQL=" INNER JOIN "+ @DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PIn.PURCHASEINVID
                          INNER JOIN "+ @DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID "
                   SET @GROUPBYNAME=" IM.ITEM_NAME "
                   SET @CONDITION =" IM.ITEM_ID="+@ACCID
            END
        IF @CRITERIA=5
           BEGIN
               SET @JOINSQL=" INNER JOIN "+ @DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PID.PURCHASEINVID=PIN.PURCHASEINVID
                              INNER JOIN "+ @DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
                              INNER JOIN "+ @DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID "
               SET @GROUPBYNAME=" IGM.ITEM_GRP_NAME "
               SET @CONDITION =" IGM.ITEM_GRP_ID="+@ACCID
           END       

END
BEGIN	
	SET NOCOUNT ON;

          SET @SQL="
                          SELECT CASE WHEN MONTH(PIN.VCHDATE)>3 THEN MONTH(PIN.VCHDATE) ELSE (MONTH(PIN.VCHDATE)+12)END  AS MON ,
                          SUM(NETTOTAL) AS AMOUNT,"+ @GROUPBYNAME +" AS REPORTER
                          FROM "+ @DATABASENAME+"PURCHASEINVOICE PIN "
                           + @JOINSQL + "
                          WHERE "+ @CONDITION + " AND PIN.CMP_CODE IN ("+ @CMP_CODE + ")
                          AND PIN.PURACCID="+@PURACCID+"
                          GROUP BY MONTH(PIN.VCHDATE),"+ @GROUPBYNAME +" 
                          ORDER BY CASE WHEN MONTH(PIN.VCHDATE)>3 THEN MONTH(PIN.VCHDATE) ELSE (MONTH(PIN.VCHDATE)+12)END 
                  "
           


EXECUTE SP_EXECUTESQL @SQL

PRINT @SQL
END




















GO

