/*    
exec Proc_PurInsuranceRpt '3','Acc2010_2011.dbo.','1792','01/Apr/2010','01/Aug/2010'
   */   
CREATE PROCEDURE [dbo].[PROC_PURINSURANCERPT]	
@CMP_CODE AS NVARCHAR(50),
@DATABASENAME AS  NVARCHAR(100),
@PURHEAD AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN	
	SET NOCOUNT ON;
SET @SQL="     

SELECT distinct PI.CMP_CODE,PI.DocNo  as DocNo ,PI.BillNo AS INVNO ,PI.LrNo AS LRNO,COMP.CMP_CITY AS FROMCITY,CM.CITY_NAME AS TOCITY,PI.Lrdate AS LRDATE,
PI.NETTOTAL AS AMOUNT,PI.NETTOTAL AS DECLAMOUNT,TM.TRANSPORT_NAME AS TRANSPORT,SID.BALES as BALES,0 AS POLICYAMT
FROM  "+ @DATABASENAME + "purchaseInvoice PI
INNER JOIN  "+ @DATABASENAME + "purchaseInvoice_Detail SID On SID.PurchaseInvId = PI.PurchaseInvId and PI.Flag = SID.Flag
INNER JOIN  "+ @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PI.CMP_CODE
INNER JOIN  "+ @DATABASENAME + "LEDGER_MASTER LM ON PI.LGR_ID=LM.LGR_ID
Inner JOIN  "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID	               
Left JOIN  "+ @DATABASENAME + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
WHERE PI.Lrdate BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE+ "' AND PI.CMP_CODE IN ("+ @CMP_CODE + ") 
and PI.PurAccId="+ @PURHEAD + "
ORDER BY PI.Lrdate,PI.BillNo,PI.LrNo
"

EXEC SP_EXECUTESQL @SQL
PRINT @SQL

END




















GO

