/*    
PROC_PURORDER_AVGRATE_SUMM '10','ACC2012_2013.DBO.','01/APR/2010','31/MAR/2011','##2310',4,2,'''P'''
   */   
CREATE PROCEDURE [dbo].[PROC_PURORDER_AVGRATE_SUMM]
(
    @CMP_CODE nvarchar(50),
    @DATABASENAME NVARCHAR(50),        
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
    @RPT_WISE INT,
    @RPT_TYPE INT,
    @TYPE NVARCHAR(5)
)
as
DECLARE @SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(1000)
DECLARE @FIELDSQL NVARCHAR(1000)
DECLARE @TYPESQL NVARCHAR(1000)
DECLARE @SELSQL AS NVARCHAR(2000)
DECLARE @GROUPSQL AS NVARCHAR(2000)

set @JOINSQL=""
Set @FIELDSQL=""
SET @TYPESQL=""
BEGIN
	IF @RPT_WISE=1
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=IM.ITEM_ID"
               SET @SELSQL=" SELECT  SUPPLIERGROUP,
                            ITEM_NAME,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,SUM(PENDINGQTY) AS PENDINGQTY, CASE WHEN SUM(PENDINGQTY)>0 THEN(SUM(AMOUNT)/SUM(PENDINGQTY)) ELSE 0 END  AS RATE FROM (  "
               SET @GROUPSQL=" GROUP BY SUPPLIERGROUP,ITEM_NAME"
            END
   ELSE IF @RPT_WISE=2
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=IGM.ITEM_GRP_ID"
               SET @SELSQL=" SELECT  SUPPLIERGROUP,
                            MIN(ITEM_NAME) AS ITEM_NAME  ,ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,SUM(PENDINGQTY) AS PENDINGQTY, CASE WHEN SUM(PENDINGQTY)>0 THEN(SUM(AMOUNT)/SUM(PENDINGQTY)) ELSE 0 END  AS RATE FROM (  "
               SET @GROUPSQL=" GROUP BY SUPPLIERGROUP,ITEMGROUP"
            END
  ELSE IF @RPT_WISE=3
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=ITM.ITEM_TYPE_ID"
               SET @SELSQL=" SELECT  SUPPLIERGROUP,
                            MIN(ITEM_NAME) AS ITEM_NAME  ,MIN(ITEMGROUP) AS ITEMGROUP,ITEMTYPE,SUM(PENDINGQTY) AS PENDINGQTY, (CASE WHEN SUM(PENDINGQTY)>0 THEN(SUM(AMOUNT)/SUM(PENDINGQTY)) ELSE 0 END ) AS RATE FROM (  "
               SET @GROUPSQL=" GROUP BY SUPPLIERGROUP,ITEMTYPE"
            END
	ELSE IF @RPT_WISE=4
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT on TT.CODE=SGM.SUPP_GRP_ID"
               SET @SELSQL=" SELECT SUPPLIERGROUP,
                             ITEM_NAME  ,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,SUM(PENDINGQTY) AS PENDINGQTY, (CASE WHEN SUM(PENDINGQTY)>0 THEN(SUM(AMOUNT)/SUM(PENDINGQTY)) ELSE 0 END ) AS RATE FROM ( "
               SET @GROUPSQL=" GROUP BY SUPPLIERGROUP,ITEM_NAME"
            END
END

BEGIN
	IF @RPT_TYPE=1	
       BEGIN
	      SET @FIELDSQL="  POD.PENDINGQTY "
          SET @TYPESQL=" AND POD.PENDINGQTY >0"
       END 
	ELSE IF @RPT_TYPE=2
       BEGIN
	    SET @FIELDSQL=" POD.QUANTITY" 
        SET @TYPESQL=" "
       END
END
--SET @JOINSQL=""
BEGIN
    	SET NOCOUNT ON;
        set @SQL= @SELSQL +" 
                   SELECT SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,
                   IM.ITEM_NAME ,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,"+@FIELDSQL+" AS PENDINGQTY,("+@FIELDSQL+"*POD.RATE) AS AMOUNT
                   FROM "+@DATABASENAME+"PURCHASEORDER PO
                   INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID=POD.PUR_ORDER_ID AND PO.FLAG=POD.FLAG                                      
                   INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PO.SUPP_GRP_ID
                   INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=POD.ITEM_ID
                   INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                   LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID                   
                   "+@JOINSQL +"
                   WHERE PO.CMP_CODE IN ("+@CMP_CODE+") AND PO.GDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                   AND PO.FLAG IN("+@TYPE+")  
                   "+@TYPESQL+"                
                    )AS DETAIL " + @GROUPSQL
                    


END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

