-- CRYSTAL_REPORT : <PURORDERRATESUMM.RPT>
-- =============================================  
PROC_PURORDERRATESUMM '10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011','##2310',4,1,'''P'''
*/
   
CREATE PROCEDURE [dbo].[PROC_PURORDERRATESUMM]
(
    @CMP_CODE NVARCHAR(50),
    @DATABASENAME NVARCHAR(50),        
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
    @RPT_WISE INT,
    @RPT_TYPE INT,
    @TYPE NVARCHAR(5)
)
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(1000)
DECLARE @TYPESQL NVARCHAR(1000)
DECLARE @FIELDSQL NVARCHAR(1000)
DECLARE @SELSQL AS NVARCHAR(2000)
DECLARE @GROUPSQL AS NVARCHAR(2000)

SET @JOINSQL=""
SET @TYPESQL=""
SET @FIELDSQL=""


BEGIN
	IF @RPT_TYPE=1	
       BEGIN
	      SET @FIELDSQL=" POD.PENDINGQTY "
          SET @TYPESQL=" AND POD.PENDINGQTY > 0"
       END 
	ELSE IF @RPT_TYPE=2
       BEGIN
	    SET @FIELDSQL=" POD.QUANTITY " 
        SET @TYPESQL=" "
       END
END



BEGIN
	IF @RPT_WISE=1
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
              SET @SELSQL=" SELECT ALM.LGR_NAME AS AGENT ,ACM.CITY_NAME AS AGENTCITY,MIN(SGM.SUPP_GRP_NAME) AS SUPPLIERGROUP,
                            IM.ITEM_NAME ,WM.WEAVER_NAME AS VIEWER,ISNULL(SUM("+@FIELDSQL+"),0) AS PENDINGQTY,POD.RATE "
              SET @GROUPSQL=" GROUP BY ALM.LGR_NAME ,ACM.CITY_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,POD.RATE"

            END
	ELSE IF @RPT_WISE=2
            BEGIN
	          SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
              SET @SELSQL=" SELECT MIN(ALM.LGR_NAME) AS AGENT ,MIN(ACM.CITY_NAME) AS AGENTCITY,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,
                            IM.ITEM_NAME ,WM.WEAVER_NAME AS VIEWER,ISNULL(SUM("+@FIELDSQL+"),0)  AS PENDINGQTY,POD.RATE "
              SET @GROUPSQL=" GROUP BY SGM.SUPP_GRP_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,POD.RATE"
            END
	ELSE IF @RPT_WISE=3
            BEGIN
	           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
               SET @SELSQL=" SELECT MIN(ALM.LGR_NAME) AS AGENT ,MIN(ACM.CITY_NAME) AS AGENTCITY,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,
                            IM.ITEM_NAME ,WM.WEAVER_NAME AS VIEWER,ISNULL(SUM("+@FIELDSQL+"),0) AS PENDINGQTY,POD.RATE "
               SET @GROUPSQL=" GROUP BY SGM.SUPP_GRP_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,POD.RATE"
            END
	ELSE IF @RPT_WISE=4
            BEGIN
	          SET @JOINSQL=""
              SET @SELSQL=" SELECT MIN(ALM.LGR_NAME) AS AGENT ,MIN(ACM.CITY_NAME) AS AGENTCITY,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP,
                            IM.ITEM_NAME ,WM.WEAVER_NAME AS VIEWER,ISNULL(SUM("+@FIELDSQL+"),0)  AS PENDINGQTY,POD.RATE "
              SET @GROUPSQL=" GROUP BY SGM.SUPP_GRP_NAME,IM.ITEM_NAME ,WM.WEAVER_NAME,POD.RATE"
             END
END


BEGIN
    	SET NOCOUNT ON;
        SET @SQL= @SELSQL +" 
                   FROM "+@DATABASENAME+"PURCHASEORDER PO
                   INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID=POD.PUR_ORDER_ID AND PO.FLAG=POD.FLAG
                   LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PO.AGENT_ID
                   LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                   INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PO.SUPP_GRP_ID
                   INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=POD.ITEM_ID
                   LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=POD.WEAVER_ID
                   "+@JOINSQL +"
                   WHERE PO.CMP_CODE IN ("+@CMP_CODE+") AND PO.GDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
                   AND PO.FLAG IN("+@TYPE+")
                   "+@TYPESQL +@GROUPSQL 


END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

