ISNULL(CLOTH_TYPE_ID,0) AS CLOTH_TYPE_ID,ISNULL(LOT_ID,0) AS LOT_ID,ISNULL(WEAVER_ID,0) AS WEAVER_ID,ISNULL(ITEM_GRP_ID,0) AS ITEM_GRP_ID,
