LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
"+ @JOINSQL +"
WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
UNION ALL
"
SET @SQL1 = "			
SELECT PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME AS SUPPLIERGRP,LM.LGR_NAME AS PARTY,
ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
