UNIT,WEAVER,LOT,SIZE,RATE,ITEMGRP,NICKNAME,ISNULL(SUPP_GRP_ID,0),ISNULL(AGENTID,0),ISNULL(ITEM_ID,0),ISNULL(UNIT_ID,0),
ISNULL(CLOTH_TYPE_ID,0),ISNULL(LOT_ID,0),ISNULL(WEAVER_ID,0),ISNULL(ITEM_GRP_ID,0),ISNULL(SIZE_ID,0),
ISNULL(PARTYID,0), ISNULL(PARTYCITY,''), ISNULL(AGENTCITY,''),ALIAS
ORDER BY "+@ORDERBY+""

END	

ELSE IF @ORDER_TYPE = 3
BEGIN
SET @SQL =  "
SELECT PUR_ORDER_ID,DOCNO,PONO,SUPPLIERGRP,PARTY,AGENT,CONFDATE,PO_DATE,CLOTHTYPE,ITEM,
UNIT,WEAVER,LOT,SIZE,RATE,SUM(ORDQTY) AS ORDQTY, 
SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,
(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,ITEMGRP,NICKNAME,
ISNULL(SUPP_GRP_ID,0) AS SUPP_GRP_ID,ISNULL(AGENTID,0) AS AGENTID,ISNULL(ITEM_ID,0) AS ITEM_ID,ISNULL(UNIT_ID,0) AS UNIT_ID,
ISNULL(CLOTH_TYPE_ID,0) AS CLOTH_TYPE_ID,ISNULL(LOT_ID,0) AS LOT_ID,ISNULL(WEAVER_ID,0) AS WEAVER_ID,ISNULL(ITEM_GRP_ID,0) AS ITEM_GRP_ID,
ISNULL(SIZE_ID,0) AS SIZE_ID,ISNULL(PARTYID,0) AS PARTYID, ISNULL(PARTYCITY,'') AS PARTYCITY,
ISNULL(AGENTCITY,'') AS AGENTCITY,ALIAS
FROM (
SELECT PO.PUR_ORDER_ID,PO.DOCNO,ISNULL(PO.PONO,0) AS PONO,ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGRP,
LM.LGR_NAME AS PARTY,
ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME  AS CLOTHTYPE,
IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
SM.SIZE_NAME AS SIZE ,POD.RATE, POD.QUANTITY AS ORDQTY,0 AS DELIQTY, 0 AS CANQTY 
,IGM.ITEM_GRP_NAME AS ITEMGRP,ISNULL(IM.NICK_NAME,'') AS NICKNAME,
SGM.SUPP_GRP_ID ,ALM.LGR_ID AS AGENTID,IM.ITEM_ID,UM.UNIT_ID,CTM.CLOTH_TYPE_ID,LOM.LOT_ID,WM.WEAVER_ID,IGM.ITEM_GRP_ID,
SM.SIZE_ID,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY
,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS

FROM "+@DATABASENAME+"PURCHASEORDER PO
INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID 
AND PO.CMP_CODE = POD.CMP_CODE AND PO.FLAG = POD.FLAG
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
INNER JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID= LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
"+ @JOINSQL +"
WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
UNION ALL
"
SET @SQL1 = "			
SELECT PO.PUR_ORDER_ID,PO.DOCNO,ISNULL(PO.PONO,0) AS PONO,ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGRP,
LM.LGR_NAME AS PARTY,
ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
SM.SIZE_NAME AS SIZE,POD.RATE, 0 AS ORDQTY,SUM(CCD.QUANTITY) AS DELIQTY, 0 AS CANQTY
,IGM.ITEM_GRP_NAME AS ITEMGRP,ISNULL(IM.NICK_NAME,'') AS NICKNAME,
SGM.SUPP_GRP_ID ,ALM.LGR_ID AS AGENTID,IM.ITEM_ID,UM.UNIT_ID,CTM.CLOTH_TYPE_ID,LOM.LOT_ID,WM.WEAVER_ID,IGM.ITEM_GRP_ID,
SM.SIZE_ID,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY
,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS

FROM "+@DATABASENAME+"CHEMICALCHALLAN CC
INNER JOIN "+@DATABASENAME+"CHEMICALCHALLAN_DETAIL CCD ON CC.CHALLANID = CCD.CHALLANID 
AND CC.CMP_CODE = CCD.CMP_CODE AND CC.FLAG = CCD.FLAG
INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.FYEAR = CC.FYEAR AND CC.CONFNO = PO.DOCNO
INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID AND PO.CMP_CODE = POD.CMP_CODE
AND PO.FLAG = POD.FLAG AND CCD.ITEM_ID = POD.ITEM_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
INNER JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID= LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
"+ @JOINSQL +"
WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
GROUP BY PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME,ALM.LGR_NAME,PO.GDATE,PO.PO_DATE,
IM.ITEM_NAME,UM.UNIT_NAME,POD.RATE,LM.LGR_NAME,SM.SIZE_NAME,WM.WEAVER_NAME,LOM.LOT_NAME,
CTM.CLOTH_TYPE_NAME,IGM.ITEM_GRP_NAME,ISNULL(IM.NICK_NAME,''),
SGM.SUPP_GRP_ID ,ALM.LGR_ID ,IM.ITEM_ID,UM.UNIT_ID,CTM.CLOTH_TYPE_ID,LOM.LOT_ID,WM.WEAVER_ID,
IGM.ITEM_GRP_ID,SM.SIZE_ID,LM.LGR_ID,PCM.CITY_NAME,ACM.CITY_NAME ,ISNULL(COMP.CMP_ALIAS,'')
UNION ALL
"
SET @SQL2 = "
SELECT PO.PUR_ORDER_ID,PO.DOCNO,ISNULL(PO.PONO,0) AS PONO,ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGRP,
LM.LGR_NAME AS PARTY,
ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
SM.SIZE_NAME AS SIZE,POD.RATE, 0 AS ORDQTY,0 AS DELIQTY,POCD.CANCELQUANTITY AS CANQTY 
,IGM.ITEM_GRP_NAME AS ITEMGRP,ISNULL(IM.NICK_NAME,'') AS NICKNAME,
SGM.SUPP_GRP_ID ,ALM.LGR_ID AS AGENTID,IM.ITEM_ID,UM.UNIT_ID,CTM.CLOTH_TYPE_ID,LOM.LOT_ID,WM.WEAVER_ID,IGM.ITEM_GRP_ID,
SM.SIZE_ID,LM.LGR_ID AS PARTYID,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY
,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS

FROM "+@DATABASENAME+"PURORDER_CANCELLATION POC
INNER JOIN "+@DATABASENAME+"PURORDER_CANCELLATION_DETAIL POCD ON POC.CANCELLATION_ID = POCD.CANCELLATION_ID 
AND POC.CMP_CODE = POCD.CMP_CODE AND POC.FLAG = POCD.FLAG
INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.FYEAR = POCD.FYEAR AND POCD.DOCNO = PO.DOCNO 
AND PO.CMP_CODE = POCD.CMP_CODE AND PO.FLAG = POCD.FLAG
INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID 
AND PO.CMP_CODE = POD.CMP_CODE AND PO.FLAG = POD.FLAG AND POCD.ITEM_ID = POD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
INNER JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
LEFT JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID= LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID = ACM.CITY_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
"+ @JOINSQL +"
WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
) AS DETAIL
GROUP BY PUR_ORDER_ID,DOCNO,PONO,SUPPLIERGRP,PARTY,AGENT,CONFDATE,PO_DATE,CLOTHTYPE,ITEM,
UNIT,WEAVER,LOT,SIZE,RATE,ITEMGRP,NICKNAME,ISNULL(SUPP_GRP_ID,0),ISNULL(AGENTID,0),ISNULL(ITEM_ID,0),ISNULL(UNIT_ID,0),
ISNULL(CLOTH_TYPE_ID,0),ISNULL(LOT_ID,0),ISNULL(WEAVER_ID,0),ISNULL(ITEM_GRP_ID,0),ISNULL(SIZE_ID,0),
ISNULL(PARTYID,0), ISNULL(PARTYCITY,''), ISNULL(AGENTCITY,''),ALIAS
ORDER BY "+@ORDERBY+""
END	
EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
END


















GO

