/*
-- =============================================
-- Author:		HIREN DOSHI
-- Create_date: 26-11-2014
-- Description:	THIS PROCEDURE USED FOR GREY ORDER SUMMARY REPORT
-- ReportName : GREYPURORDERSUMREG.RPT
-- Edit Author : Biren
-- Edit_Date   : 09-12-2014
-- Before Change Rate : (ISNULL(SUM(RATE),0) / COUNT(PUR_ORDER_ID)) AS AVGRATE
-- =============================================
PROC_PURORDERSUMREG '1','ACC2014_2015.dbo.',12,3,'01/APR/2013','31/MAR/2013','##3804',1

*/
CREATE PROCEDURE [dbo].[PROC_PURORDERSUMREG]
(
    @CMP_CODE NVARCHAR(10),
    @DATABASENAME NVARCHAR(50),
    @RPT_WISE INT,
    @RPT_TYPE INT,	
    @FROMDATE AS NVARCHAR(20),
    @TODATE AS NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
	@ORDER_TYPE INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)
DECLARE @SQLMAIN NVARCHAR(4000)
DECLARE @SQLGRP NVARCHAR(1000)
DECLARE @SQLORDERBY NVARCHAR(1000)

SET @SQL = ""
SET @SQL1=""
SET @SQL2=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL=""
SET @SQLMAIN = ""
SET @SQLGRP = ""
SET @SQLORDERBY=""

IF @RPT_WISE = 1 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
	SET @SQLMAIN = " SELECT COUNT(PUR_ORDER_ID) AS PUR_ORDER_ID,MAX(DOCNO) AS DOCNO,MAX(PONO) AS PONO,SUPPLIERGRP,
					MAX(PARTY) AS PARTY,MAX(AGENT) AS AGENT,MAX(CONFDATE) AS CONFDATE,MAX(PO_DATE) AS PO_DATE,
					MAX(CLOTHTYPE) AS CLOTHTYPE,MAX(ITEM) AS ITEM,MAX(UNIT) AS UNIT,MAX(WEAVER) AS WEAVER,
					(LOT) AS LOT,MAX(SIZE) AS SIZE,SUM(RATE) AS RATE,SUM(ORDQTY) AS ORDQTY, 
					SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,MAX(ITEMGRP) AS ITEMGRP,
					(SUM(AMOUNT))/
					(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS AVGRATE,
					ISNULL(MAX(PARTYCITY),'') AS PARTYCITY, ISNULL(MAX(AGENTCITY),'') AS AGENTCITY,
					ISNULL(MAX(SUPP_GRP_ID),0) AS SUPP_GRP_ID,ISNULL(MAX(AGENT_ID),0) AS AGENT_ID,ISNULL(MAX(ITEM_ID),0) AS ITEM_ID,
					ISNULL(MAX(CLOTH_TYPE_ID),0)  AS CLOTH_TYPE_ID ,ISNULL(LOT_ID,0)  AS LOT_ID,ISNULL(MAX(WEAVER_ID),0) AS WEAVER_ID,
					ISNULL(MAX(ITEM_GRP_ID),0) AS ITEM_GRP_ID,ISNULL(MAX(SIZE_ID),0) AS SIZE_ID,ISNULL(MAX(PARTY_ID),0) AS PARTY_ID,ALIAS FROM ("
	SET @SQLGRP = " GROUP BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),LOT,ISNULL(LOT_ID,0),ALIAS "
	SET @SQLORDERBY=" ORDER BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),LOT,ISNULL(LOT_ID,0) "
END
ELSE IF @RPT_WISE = 8 /* SUPPLIER GROUP - PARTY */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
	SET @SQLMAIN = " SELECT COUNT(PUR_ORDER_ID) AS PUR_ORDER_ID,MAX(DOCNO) AS DOCNO,MAX(PONO) AS PONO,SUPPLIERGRP,
					PARTY AS PARTY,MAX(AGENT) AS AGENT,MAX(CONFDATE) AS CONFDATE,MAX(PO_DATE) AS PO_DATE,
					MAX(CLOTHTYPE) AS CLOTHTYPE,MAX(ITEM) AS ITEM,MAX(UNIT) AS UNIT,MAX(WEAVER) AS WEAVER,
					MAX(LOT) AS LOT,MAX(SIZE) AS SIZE,SUM(RATE) AS RATE,SUM(ORDQTY) AS ORDQTY, 
					SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,MAX(ITEMGRP) AS ITEMGRP,
					(SUM(AMOUNT))/
					(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS AVGRATE,
					ISNULL(MAX(PARTYCITY),'') AS PARTYCITY, ISNULL(MAX(AGENTCITY),'') AS AGENTCITY,
					ISNULL(MAX(SUPP_GRP_ID),0) AS SUPP_GRP_ID,ISNULL(MAX(AGENT_ID),0) AS AGENT_ID,ISNULL(MAX(ITEM_ID),0) AS ITEM_ID,
					ISNULL(MAX(CLOTH_TYPE_ID),0)  AS CLOTH_TYPE_ID ,ISNULL(MAX(LOT_ID),0)  AS LOT_ID,ISNULL(MAX(WEAVER_ID),0) AS WEAVER_ID,
					ISNULL(MAX(ITEM_GRP_ID),0) AS ITEM_GRP_ID,ISNULL(MAX(SIZE_ID),0) AS SIZE_ID,ISNULL(MAX(PARTY_ID),0) AS PARTY_ID,ALIAS FROM ("
	SET @SQLGRP = " GROUP BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),PARTY,ISNULL(PARTY_ID,0),LOT,ISNULL(LOT_ID,0),ALIAS "
	SET @SQLORDERBY=" ORDER BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),PARTY,ISNULL(PARTY_ID,0),LOT,ISNULL(LOT_ID,0)"
END
ELSE IF @RPT_WISE = 9 /* SUPPLIER GROUP - ITEM */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
	SET @SQLMAIN = " SELECT COUNT(PUR_ORDER_ID) AS PUR_ORDER_ID,MAX(DOCNO) AS DOCNO,MAX(PONO) AS PONO,SUPPLIERGRP,
					MAX(PARTY) AS PARTY,MAX(AGENT) AS AGENT,MAX(CONFDATE) AS CONFDATE,MAX(PO_DATE) AS PO_DATE,
					MAX(CLOTHTYPE) AS CLOTHTYPE,ITEM AS ITEM,MAX(UNIT) AS UNIT,MAX(WEAVER) AS WEAVER,
					MAX(LOT) AS LOT,MAX(SIZE) AS SIZE,SUM(RATE) AS RATE,SUM(ORDQTY) AS ORDQTY, 
					SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,MAX(ITEMGRP) AS ITEMGRP,
					(SUM(AMOUNT))/
					(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS AVGRATE,
					ISNULL(MAX(PARTYCITY),'') AS PARTYCITY, ISNULL(MAX(AGENTCITY),'') AS AGENTCITY,
					ISNULL(MAX(SUPP_GRP_ID),0) AS SUPP_GRP_ID,ISNULL(MAX(AGENT_ID),0) AS AGENT_ID,ISNULL(MAX(ITEM_ID),0) AS ITEM_ID,
					ISNULL(MAX(CLOTH_TYPE_ID),0)  AS CLOTH_TYPE_ID ,ISNULL(MAX(LOT_ID),0)  AS LOT_ID,ISNULL(MAX(WEAVER_ID),0) AS WEAVER_ID,
					ISNULL(MAX(ITEM_GRP_ID),0) AS ITEM_GRP_ID,ISNULL(MAX(SIZE_ID),0) AS SIZE_ID,ISNULL(MAX(PARTY_ID),0) AS PARTY_ID,ALIAS FROM ("
	SET @SQLGRP = " GROUP BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),ITEM,ISNULL(ITEM_ID,0),LOT,ISNULL(LOT_ID,0),ALIAS "
	SET @SQLORDERBY=" ORDER BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),ITEM,ISNULL(ITEM_ID,0),LOT,ISNULL(LOT_ID,0)"
END
ELSE IF @RPT_WISE = 10 /* SUPPLIER GROUP - LOT MARKA */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
	SET @SQLMAIN = " SELECT COUNT(PUR_ORDER_ID) AS PUR_ORDER_ID,MAX(DOCNO) AS DOCNO,MAX(PONO) AS PONO,SUPPLIERGRP,
					MAX(PARTY) AS PARTY,MAX(AGENT) AS AGENT,MAX(CONFDATE) AS CONFDATE,MAX(PO_DATE) AS PO_DATE,
					MAX(CLOTHTYPE) AS CLOTHTYPE,MAX(ITEM) AS ITEM,MAX(UNIT) AS UNIT,MAX(WEAVER) AS WEAVER,
					LOT AS LOT,MAX(SIZE) AS SIZE,SUM(RATE) AS RATE,SUM(ORDQTY) AS ORDQTY, 
					SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,MAX(ITEMGRP) AS ITEMGRP,
					(SUM(AMOUNT))/
					(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS AVGRATE,
					ISNULL(MAX(PARTYCITY),'') AS PARTYCITY, ISNULL(MAX(AGENTCITY),'') AS AGENTCITY,
					ISNULL(MAX(SUPP_GRP_ID),0) AS SUPP_GRP_ID,ISNULL(MAX(AGENT_ID),0) AS AGENT_ID,ISNULL(MAX(ITEM_ID),0) AS ITEM_ID,
					ISNULL(MAX(CLOTH_TYPE_ID),0)  AS CLOTH_TYPE_ID ,ISNULL(MAX(LOT_ID),0)  AS LOT_ID,ISNULL(MAX(WEAVER_ID),0) AS WEAVER_ID,
					ISNULL(MAX(ITEM_GRP_ID),0) AS ITEM_GRP_ID,ISNULL(MAX(SIZE_ID),0) AS SIZE_ID,ISNULL(MAX(PARTY_ID),0) AS PARTY_ID,ALIAS FROM ("
	SET @SQLGRP = " GROUP BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),LOT,ISNULL(LOT_ID,0),ALIAS "
	SET @SQLORDERBY=" ORDER BY SUPPLIERGRP,ISNULL(SUPP_GRP_ID,0),LOT,ISNULL(LOT_ID,0)"
END
ELSE IF @RPT_WISE = 2 
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PO.LGR_ID"
	SET @SQLMAIN = " SELECT COUNT(PUR_ORDER_ID) AS PUR_ORDER_ID,MAX(DOCNO) AS DOCNO,MAX(PONO) AS PONO,MAX(SUPPLIERGRP) AS SUPPLIERGRP,
					PARTY AS PARTY,MAX(AGENT) AS AGENT,MAX(CONFDATE) AS CONFDATE,MAX(PO_DATE) AS PO_DATE,
					MAX(CLOTHTYPE) AS CLOTHTYPE,MAX(ITEM) AS ITEM,MAX(UNIT) AS UNIT,MAX(WEAVER) AS WEAVER,
					MAX(LOT) AS LOT,MAX(SIZE) AS SIZE,SUM(RATE) AS RATE,SUM(ORDQTY) AS ORDQTY, 
					SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,MAX(ITEMGRP) AS ITEMGRP,
					(SUM(AMOUNT))/
					(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS AVGRATE,
					ISNULL(MAX(PARTYCITY),'') AS PARTYCITY, ISNULL(MAX(AGENTCITY),'') AS AGENTCITY,
					ISNULL(MAX(SUPP_GRP_ID),0) AS SUPP_GRP_ID,ISNULL(MAX(AGENT_ID),0) AS AGENT_ID,ISNULL(MAX(ITEM_ID),0) AS ITEM_ID,
					ISNULL(MAX(CLOTH_TYPE_ID),0)  AS CLOTH_TYPE_ID ,ISNULL(MAX(LOT_ID),0)  AS LOT_ID,ISNULL(MAX(WEAVER_ID),0) AS WEAVER_ID,
					ISNULL(MAX(ITEM_GRP_ID),0) AS ITEM_GRP_ID,ISNULL(MAX(SIZE_ID),0) AS SIZE_ID,ISNULL(MAX(PARTY_ID),0) AS PARTY_ID,ALIAS FROM ("
	SET @SQLGRP = " GROUP BY PARTY,ISNULL(PARTY_ID,0),LOT,ISNULL(LOT_ID,0),ALIAS "
	SET @SQLORDERBY=" ORDER BY PARTY,ISNULL(PARTY_ID,0),LOT,ISNULL(LOT_ID,0) "
END
ELSE IF @RPT_WISE = 11 /* PARTY - ITEM */
BEGIN
