SET @TYPESQL=" AND POD.PENDINGQTY=0"
IF @RPT_TYPE=2
SET @TYPESQL="AND POD.PENDINGQTY>0"
IF @RPT_TYPE=3
SET @TYPESQL=""

IF @ORDER_TYPE = 1
	SET @ORDERSQL = "AND POD.FLAG='P'"


IF @ORDER_TYPE = 1 
BEGIN
SET @SQL =  " "+@SQLMAIN+"
			SELECT PUR_ORDER_ID,DOCNO,PONO,SUPPLIERGRP,PARTY,AGENT,CONFDATE,PO_DATE,CLOTHTYPE,ITEM,
			UNIT,WEAVER,LOT,SIZE,RATE,SUM(ORDQTY) AS ORDQTY, 
			SUM(ISNULL(DELIQTY,0)) AS DELIQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY,
			(SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,ITEMGRP,
			((SUM(ORDQTY)-SUM(ISNULL(DELIQTY,0))-SUM(ISNULL(CANQTY,0))) * RATE) AS AMOUNT,PARTYCITY, AGENTCITY,
			SUPP_GRP_ID,AGENT_ID,ITEM_ID,CLOTH_TYPE_ID ,LOT_ID ,WEAVER_ID,ITEM_GRP_ID,SIZE_ID,PARTY_ID,ALIAS
			FROM (
			SELECT PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME AS SUPPLIERGRP,LM.LGR_NAME AS PARTY,
			ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
			IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
			SM.SIZE_NAME AS SIZE ,POD.RATE, POD.QUANTITY AS ORDQTY,0 AS DELIQTY, 0 AS CANQTY
			,IGM.ITEM_GRP_NAME AS ITEMGRP ,PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,
			SGM.SUPP_GRP_ID,ALM.LGR_ID AS AGENT_ID,IM.ITEM_ID,CTM.CLOTH_TYPE_ID ,LOM.LOT_ID ,WM.WEAVER_ID,
			IGM.ITEM_GRP_ID,SM.SIZE_ID,LM.LGR_ID AS PARTY_ID
			,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS
			FROM "+@DATABASENAME+"PURCHASEORDER PO
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID 
			AND PO.CMP_CODE = POD.CMP_CODE AND PO.FLAG = POD.FLAG
			INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
			LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
			INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
			LEFT JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
			
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
			
			"+ @JOINSQL +"
			WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
			UNION ALL
			"
SET @SQL1 = "			
			SELECT PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME AS SUPPLIERGRP,LM.LGR_NAME AS PARTY,
			ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
			IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
			SM.SIZE_NAME AS SIZE,POD.RATE, 0 AS ORDQTY,SUM(ADJPCS) AS DELIQTY, 0 AS CANQTY
			,IGM.ITEM_GRP_NAME AS ITEMGRP,PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,
			SGM.SUPP_GRP_ID,ALM.LGR_ID AS AGENT_ID,IM.ITEM_ID,CTM.CLOTH_TYPE_ID ,LOM.LOT_ID ,WM.WEAVER_ID,
			IGM.ITEM_GRP_ID,SM.SIZE_ID,LM.LGR_ID AS PARTY_ID
			,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS
			FROM "+@DATABASENAME+"PURCHASEINVOICE PI
			INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID = PID.PURCHASEINVID 
				AND PI.CMP_CODE = PID.CMP_CODE AND PI.FLAG = PID.FLAG
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.FYEAR = PI.FYEAR AND PI.CONFNO = PO.DOCNO
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID AND PO.CMP_CODE = POD.CMP_CODE
				AND PO.FLAG = POD.FLAG AND PID.ITEM_ID = POD.ITEM_ID 
				AND PID.LOT_ID = POD.LOT_ID AND PID.WEAVER_ID = POD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
			LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
			INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
			LEFT JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
			
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
			"+ @JOINSQL +"
			WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
			GROUP BY PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME,ALM.LGR_NAME,PO.GDATE,PO.PO_DATE,
			CTM.CLOTH_TYPE_NAME,IM.ITEM_NAME,UM.UNIT_NAME,WM.WEAVER_NAME,LOM.LOT_NAME,POD.RATE,SM.SIZE_NAME,
			LM.LGR_NAME,IGM.ITEM_GRP_NAME,PCM.CITY_NAME  ,ACM.CITY_NAME,
			SGM.SUPP_GRP_ID,ALM.LGR_ID,IM.ITEM_ID,CTM.CLOTH_TYPE_ID ,LOM.LOT_ID ,WM.WEAVER_ID,IGM.ITEM_GRP_ID,
			SM.SIZE_ID,LM.LGR_ID,ISNULL(COMP.CMP_ALIAS,'')
			
			UNION ALL 
			"
SET @SQL2 = "
			SELECT PO.PUR_ORDER_ID,PO.DOCNO,PO.PONO,SGM.SUPP_GRP_NAME AS SUPPLIERGRP,LM.LGR_NAME AS PARTY,
			ALM.LGR_NAME AS AGENT,PO.GDATE AS CONFDATE,PO.PO_DATE,CTM.CLOTH_TYPE_NAME AS CLOTHTYPE,
			IM.ITEM_NAME AS ITEM,UM.UNIT_NAME AS UNIT,WM.WEAVER_NAME AS WEAVER,LOM.LOT_NAME AS LOT,
			SM.SIZE_NAME AS SIZE,POD.RATE, 0 AS ORDQTY,0 AS DELIQTY, CANCELQUANTITY AS CANQTY
			,IGM.ITEM_GRP_NAME AS ITEMGRP,PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,
			SGM.SUPP_GRP_ID,ALM.LGR_ID AS AGENT_ID,IM.ITEM_ID,CTM.CLOTH_TYPE_ID ,LOM.LOT_ID ,WM.WEAVER_ID,
			IGM.ITEM_GRP_ID,SM.SIZE_ID,LM.LGR_ID AS PARTY_ID
			,ISNULL(COMP.CMP_ALIAS,'') AS ALIAS
			FROM "+@DATABASENAME+"PURORDER_CANCELLATION POC
			INNER JOIN "+@DATABASENAME+"PURORDER_CANCELLATION_DETAIL POCD ON POC.CANCELLATION_ID = POCD.CANCELLATION_ID 
				AND POC.CMP_CODE = POCD.CMP_CODE AND POC.FLAG = POCD.FLAG
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER PO ON PO.FYEAR = POCD.FYEAR AND POCD.DOCNO = PO.DOCNO 
				AND POCD.SUPP_GRP_ID = PO.SUPP_GRP_ID AND PO.CMP_CODE = POCD.CMP_CODE AND PO.FLAG = POCD.FLAG
			INNER JOIN "+@DATABASENAME+"PURCHASEORDER_DETAIL POD ON PO.PUR_ORDER_ID = POD.PUR_ORDER_ID 
				AND PO.CMP_CODE = POD.CMP_CODE AND PO.FLAG = POD.FLAG 
				AND POCD.ITEM_ID = POD.ITEM_ID AND POCD.WEAVER_ID = POD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID = PO.SUPP_GRP_ID
			INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID = PO.AGENT_ID
			LEFT JOIN  "+@DATABASENAME+"CLOTH_TYPE_MASTER CTM ON CTM.CLOTH_TYPE_ID = PO.CLOTH_TYPE_ID
			INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID = POD.ITEM_ID
			INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
			INNER JOIN "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = POD.LOT_ID
			INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID = POD.WEAVER_ID
			INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
			LEFT JOIN "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = POD.SIZE_ID
			LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID = PO.LGR_ID
			
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
			LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
			INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PO.CMP_CODE
			"+ @JOINSQL +"
			WHERE PO.CMP_CODE IN ("+@CMP_CODE+") "+@TYPESQL+""+@ORDERSQL+"
			) AS DETAIL
			GROUP BY PUR_ORDER_ID,DOCNO,PONO,SUPPLIERGRP,PARTY,AGENT,CONFDATE,PO_DATE,CLOTHTYPE,ITEM,
			UNIT,WEAVER,LOT,SIZE,RATE,ITEMGRP,RATE,ISNULL(PARTYCITY,''),ISNULL(AGENTCITY,''),PARTYCITY, AGENTCITY,
			SUPP_GRP_ID,AGENT_ID,ITEM_ID,CLOTH_TYPE_ID ,LOT_ID ,WEAVER_ID,ITEM_GRP_ID,SIZE_ID,PARTY_ID,ALIAS
			
			 ) AS MAINDETAIL  "+@SQLGRP+" "+@SQLORDERBY+"
			"
END
EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2


















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURREG_DAILY_MONTHLY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO












/*    

PROC_PURREG_DAILY_MONTHLY N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'31/Mar/2019', N'0', 19, 1, 4

*/   
CREATE PROCEDURE [dbo].[PROC_PURREG_DAILY_MONTHLY]
(
    @CMP_CODE NVARCHAR(100),
    @DATABASENAME NVARCHAR(100),	
    @FROMDATE NVARCHAR(20),
    @TODATE NVARCHAR(20),
    @PURACCID NVARCHAR(20),
    @RPT_WISE INT,
    @CONVERSION int,
    @INVTYPE INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE @STRINVOICE AS NVARCHAR(200)
DECLARE @ID AS NVARCHAR(200)
PRINT 1
SET @SQL=""
SET @ID=""
SET @QUANTITYSQL=""
SET @STRINVOICE=""
BEGIN

IF @PURACCID <> 0
SET @ID="PI.PurAccId="+@PURACCID+" AND"
END

BEGIN
IF @INVTYPE =1
SET @STRINVOICE="  PI.FLAG='P' AND"
ELSE IF  @INVTYPE =2
SET @STRINVOICE="  PI.FLAG='CHP' AND"
ELSE IF  @INVTYPE =3
SET @STRINVOICE="  PI.FLAG='MIP' AND"
ELSE IF  @INVTYPE =4
SET @STRINVOICE=" "
END
BEGIN
  
     BEGIN
         SET @QUANTITYSQL=" PID.QUANTITY AS QUANTITY"
         IF @CONVERSION =1 
                  SET  @QUANTITYSQL= " ((CASE  WHEN UM.UNIT_NAME='PIECES' THEN (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
				     ELSE   PID.QUANTITY END ) )AS  QUANTITY "         
      END

	SET NOCOUNT ON;
     IF @RPT_WISE=19
      BEGIN
		SET @SQL=" SELECT MAX(MONTHNAME) AS MONTHNAME,VDATE,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT) AS AMOUNT,0 AS ORD FROM ( 
                     SELECT 'JANUARY' AS MONTHNAME,PI.VCHDATE AS VDATE ,
                     "+@QUANTITYSQL+",
				     ((PID.AMOUNT)+(((PID.AMOUNT)*(PI.NETTOTAL- PI.GROSSTOTAL))/PI.GROSSTOTAL)) AS AMOUNT
                     , 0 AS ORD
					 FROM "+@DATABASENAME+"PURCHASEINVOICE PI
				     INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID and PI.FLAG=PID.FLAG           
				     INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
				     INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID                      
				     WHERE "+@ID+"  "+@STRINVOICE+"  PI.Cmp_Code IN ("+@CMP_CODE+") and  PI.VCHDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
                     ) AS DETAIL
				     GROUP BY VDATE
				     ORDER BY  VDATE
		"
      END
	ELSE  IF @RPT_WISE=20
		  BEGIN
			SET @SQL="   SELECT MONTHNAME,GETDATE() AS VDATE,SUM(QUANTITY)AS QUANTITY,SUM(AMOUNT)AS AMOUNT,ORD FROM (
                         SELECT UPPER(DATENAME(MM,PI.VCHDATE)) AS MONTHNAME,NULL AS VDATE,
                         "+@QUANTITYSQL+",
						 (PID.AMOUNT)+(((PID.AMOUNT)*(PI.NETTOTAL- PI.GROSSTOTAL))/PI.GROSSTOTAL) AS AMOUNT
                         ,(CASE WHEN DATEPART(M,PI.VCHDATE)<=3 THEN  (DATEPART(M,PI.VCHDATE)+12)ELSE DATEPART(M,PI.VCHDATE) END) AS     ORD
						 FROM "+@DATABASENAME+"PURCHASEINVOICE PI
						 INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID and PI.FLAG=PID.FLAG           
						 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
						 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID                      
						 WHERE "+@ID+"  "+@STRINVOICE+"  PI.Cmp_Code IN ("+@CMP_CODE+") and  PI.VCHDATE BETWEEN '"+@FROMDATE+"' and '"+@TODATE+"'
                          ) AS DETAIL
						 GROUP BY MONTHNAME,ORD
						 ORDER BY  ORD
			"
		  END
 
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
 
END



SET ANSI_NULLS ON





















GO

/****** Object:  StoredProcedure [dbo].[PROC_PURRETPREPRINTED]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
