    /*    
 PROC_PURRETPREPRINTED_GST '1','3','1','acc2017_2018.dbo.'
   */   

CREATE PROCEDURE [dbo].[PROC_PURRETPREPRINTED_GST]
(
@FromBillNo  nvarchar(20),
@ToBillNo nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="	 
		SELECT PR.DOCNO AS BILLNO,PR.PUR_RET_DATE AS RETDATE,PR.PUR_RET_LRNO,
		PR.PUR_RET_LRDATE,upper(LM.LGR_NAME) AS PARTYNAME,upper(PCM.CITY_NAME) AS PARTYCITY,upper(LM.LGR_ADD1) as LGR_ADD1,
		upper(LM.LGR_ADD2) as LGR_ADD2,upper(LM.LGR_ADD3)as LGR_ADD3,upper(AGM.Lgr_NAME) AS AGENTNAME ,PRD.PUR_RET_BALE_NO AS BALENO,
		PRD.Item_Cut ,IM.ITEM_NAME AS ITEM,PRD.PUR_RET_PCS AS PCS,PRD.PUR_RET_QTY AS QUANTITY,PUR_RET_AMOUNT AS AMOUNT,PR.RoundedAmount as ROUNDEDAMOUNT,
		PRD.PUR_RET_RATE AS RATE,PR.NETTOTAL AS NETTOTAL,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,PR.PUR_RET_ADD1,
		PR.PUR_RET_ADD2,PR.PUR_RET_ADD3,PR.PUR_RET_ADD4,PR.PUR_RET_ADD5,PR.PUR_RET_ADD6,PR.PUR_RET_LESS1,PR.PUR_RET_LESS2,PR.PUR_RET_LESS3,PR.PUR_RET_LESS4,PR.PUR_RET_LESS5,PR.PUR_RET_AddTotal,PUR_RET_RoundOff ,
		PR.PUR_RET_LessTotal,PR.GROSSTotal,UM.UNIT_NAME,upper(SM.State_NAME) as  PatyState,upper(PCM.City_District)as City_District,
		CONVERT(NVARCHAR,LM.City_Pincode) AS City_Pincode,upper(CMp.Cmp_Name)as Cmp_Name,Cmp.cmp_tin_No,cmp.cmp_pan_no,cmp.cmp_jurisdiction,cmp.cmp_add1,cmp.cmp_add2,
		cmp.cmp_city,cmp.cmp_state,cmp.cmp_phone1,cmp.cmp_Phone2,CMP.cmp_Mobile,cmp.cmp_bank_accno1,cmp.cmp_bank_accno2,cmp.cmp_bank_accno3,
		upper(ACM.City_Name) As AgentCity,PRD.PUR_RET_Dtl_Id ,CMP.CMP_SERVICETAX_NO AS SERVICETAX,'' AS DESIGN,'' AS NARRATION,
		CMP.GSTINNO,lm.gstinno as PartyGstno,UPPER(SM.STATE_NAME) AS  PATYSTATE,sm.State_Code,
		(PR.Pur_Ret_Add1+PR.Pur_Ret_Add2)as ADDBEFOREVALUE,
		(PR.GROSSTotal-PR.Pur_Ret_LessTotal+(PR.Pur_Ret_Add1+PR.Pur_Ret_Add2)) AS TAXABLEAMT,
		PR.PUR_RET_ADD1_SET,PUR_RET_ADD2_SET,PUR_RET_ADD3_SET,PUR_RET_ADD4_SET,PUR_RET_ADD5_SET,PUR_RET_ADD6_SET,
		PR.PUR_RET_LESS1_SET,PR.PUR_RET_LESS2_SET,PR.PUR_RET_LESS3_SET,PR.PUR_RET_LESS4_SET,PR.PUR_RET_LESS5_SET,PURBILLNO,PURVCHDATE,HM.Hsn_Name,PR.EWAYBILLNO,PR.EwayBillDate,PR.VEHICLENO
		 FROM "+ @DatabaseName +"PURCHASE_RETURN_MASTER PR
		INNER JOIN "+ @DatabaseName +"PURCHASE_RETURN_DETAIL PRD ON PR.PUR_RET_ID = PRD.PUR_RET_Id AND PR.FLAG=PRD.FLAG
		INNER JOIN "+ @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=PR.LGR_ID
		left JOIN "+ @DatabaseName +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PR.TRANSPORT_ID
		LEFT JOIN "+ @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=PR.AGENT_ID
		INNER JOIN "+ @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
		INNER JOIN "+ @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=PRD.UNIT_ID
		Inner JOIN "+ @DatabaseName +"COMPANY_MASTER CMP ON PR.Cmp_Code= CMP.Cmp_Code     
		LEFT JOIN "+ @DatabaseName +"CITY_MASTER CM ON CM.CITY_ID=PR.STATION_ID
		LEFT JOIN "+ @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN "+ @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN "+ @DatabaseName +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+"HSN_MASTER HM ON HM.HSN_ID=IM.HSN_ID
		WHERE PR.Cmp_Code="+ @Cmp_Code +" and  PR.DOCNO BETWEEN '" + @FromBillNo + "' and '" + @ToBillNo + "'
		ORDER BY   PR.DOCNO, PRD.PUR_RET_BALE_NO,PRD.PUR_RET_DTL_ID
		"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL



























































































































GO

