PROC_PURRETURNREG N'1', N'Acc2018_2019.Dbo.', 1, N'01/Apr/2018', N'31/Mar/2019', N'##392',2

SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
*/   
CREATE PROCEDURE [dbo].[PROC_PURRETURNREG]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE NVARCHAR(20),
@RETURN_TYPE INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @SQL3  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)
DECLARE @ORDERBY NVARCHAR(200)

SET @SQL = ""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL=""
SET @ORDERBY=""

IF @RPT_WISE = 1 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PM.LGR_ID "
SET @ORDERBY="  PARTY,ISNULL(PM.LGR_ID,0) "
END
ELSE IF @RPT_WISE = 2 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AM.LGR_ID "
SET @ORDERBY="  AGENT,ISNULL(AM.LGR_ID,0) "
END	
ELSE IF @RPT_WISE = 3 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=TM.TRANSPORT_ID "
SET @ORDERBY="  TRANSPORT,ISNULL(TM.TRANSPORT_ID,0) "
END	
ELSE IF @RPT_WISE = 4
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=STM.CITY_ID "
SET @ORDERBY="  STATION,ISNULL(STM.CITY_ID,0) "
END	
ELSE IF @RPT_WISE = 5 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID "
SET @ORDERBY="  PARTYCITY,ISNULL(PCM.CITY_ID,0) "
END
ELSE IF @RPT_WISE = 6
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LOM.LOT_ID "
SET @ORDERBY="  GREYMARKA,ISNULL(LOM.LOT_ID,0) "
END
ELSE IF @RPT_WISE = 7
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID "
SET @ORDERBY="  ITEM,ISNULL(IM.ITEM_ID,0) "
END
ELSE IF @RPT_WISE = 8 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID "
SET @ORDERBY="  NICKNAME,ISNULL(IM.ITEM_ID,0) "
END
ELSE IF @RPT_WISE = 9
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM.SIZE_ID "
SET @ORDERBY="  SIZE,ISNULL(SM.SIZE_ID,0) "
END
IF @RPT_WISE = 10
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SCM.SCREEN_ID "
SET @ORDERBY="  SCREEN,ISNULL(SCM.SCREEN_ID,0) "
END

ELSE IF @RPT_WISE = 11
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID "
SET @ORDERBY="  ITEMGRP,ISNULL(IGM.ITEM_GRP_ID,0) "
END	
ELSE IF @RPT_WISE = 12
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PM.LGR_ID "
SET @ORDERBY="  PARTY,ISNULL(PM.LGR_ID,0),ITEM,ISNULL(IM.ITEM_ID,0) "
END	
ELSE IF  @RPT_WISE = 13
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AM.LGR_ID "
SET @ORDERBY="  AGENT,ISNULL(AM.LGR_ID,0),LOT,ISNULL(IM.ITEM_ID,0) "
END	
ELSE IF @RPT_WISE = 14 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID "
SET @ORDERBY="  ITEMGRP,ISNULL(IGM.ITEM_GRP_ID,0),ITEM,ISNULL(IM.ITEM_ID,0) "
END
ELSE IF @RPT_WISE = 15	
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LOM.LOT_ID "
SET @ORDERBY="  GREYMARKA,ISNULL(LOM.LOT_ID,0),ITEM,ISNULL(IM.ITEM_ID,0) "
END
ELSE IF @RPT_WISE = 16 
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID "
SET @ORDERBY="  ITEM,ISNULL(IM.ITEM_ID,0),SIZE,ISNULL(SM.SIZE_ID,0) "
END
ELSE IF @RPT_WISE = 17
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID "
SET @ORDERBY="  ITEM,ISNULL(IM.ITEM_ID,0),SCREEN,ISNULL(SCM.SCREEN_ID,0) "
END
ELSE IF   @RPT_WISE = 18
BEGIN
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PRM.DOCNO "
SET @ORDERBY=" ISNULL(PRM.DOCNO,0)"
END

IF @RETURN_TYPE = 1
SET @ORDERSQL = "AND PRM.FLAG='PR'"
ELSE IF @RETURN_TYPE = 3
SET @ORDERSQL = "AND PRM.FLAG='MPR'"
ELSE IF @RETURN_TYPE = 4
SET @ORDERSQL = "AND PRM.FLAG='FPR'"
ELSE IF @RETURN_TYPE = 5
SET @ORDERSQL = ""

BEGIN
SET NOCOUNT ON;


BEGIN
SET @SQL =  "
SELECT ISNULL(PRM.REFNO,'')REFNO,ISNULL(PRM.PUR_RET_ID,0) AS PURRETID,ISNULL(PRM.DOCNO,0) AS DOCNO,CONVERT(NVARCHAR,PRM.PUR_RET_DATE,103) AS RETURNDATE,
ISNULL(PRM.PUR_RET_LRNO,'') AS M_LRNO,CONVERT(NVARCHAR,PRM.PUR_RET_LRDATE,103) AS M_LRDATE,ISNULL(PRM.PUR_RET_ADD1,0) AS ADD1,
ISNULL(PRM.PUR_RET_ADD2,0) AS ADD2,ISNULL(PRM.PUR_RET_ADD3,0) AS ADD3,ISNULL(PRM.PUR_RET_ADDTOTAL,0) AS ADDTOTAL,
ISNULL(PRM.PUR_RET_LESS1,0) AS LESS1,ISNULL(PRM.PUR_RET_LESS2,0) AS LESS2,ISNULL(PRM.PUR_RET_LESS3,0) AS LESS3,
ISNULL(PRM.PUR_RET_LESSTOTAL,0) AS LESSTOTAL,ISNULL(PRM.PUR_RET_ROUNDOFF,0) AS ROUNDOFF,ISNULL(PRM.ROUNDEDAMOUNT,0) AS ROUNDEDAMOUNT,
ISNULL(PRM.GROSSTOTAL,0) AS GROSSTOTAL,ISNULL(PRM.NETTOTAL,0) AS NETTOTAL,ISNULL(PRM.FLAG,'') AS FLAG,
ISNULL(PRM.BILLNO,'') AS M_BILLNO,ISNULL(PRM.LOTNO,0) AS M_LOTNO,ISNULL(PRM.NARR,'') AS NARR,ISNULL(PRM.RETURN_TYPE,'') AS RETURN_TYPE,
ISNULL(PRD.PUR_RET_DTL_ID,0) AS SRNO,ISNULL(PRD.PUR_RET_BALE_NO,'') AS BALENO,ISNULL(PRD.ITEM_CUT,0) AS ITEMCUT,
ISNULL(PRD.PUR_RET_PCS,0) AS PCS,ISNULL(PRD.PUR_RET_QTY,0) AS QTY,ISNULL(PRD.PUR_RET_RATE,0) AS RATE,
ISNULL(PRD.PUR_RET_AMOUNT,0) AS AMOUNT,ISNULL(PRD.LRNO,'') AS D_LRNO,CONVERT(NVARCHAR,PRD.LRDATE,103) AS D_LRDATE,
ISNULL(PRD.BILLNO,'') AS D_BILLNO,ISNULL(PRD.LOTNO,0) AS D_LOTNO,
ISNULL(PRM.LGR_ID,0) AS LGRID,ISNULL(PRM.AGENT_ID,0) AS AGENTID,ISNULL(PRM.TRANSPORT_ID,0) AS TRANSPORTID,
ISNULL(PRM.STATION_ID,0) AS STATIONID,ISNULL(PCM.CITY_ID,0) AS PARTYCITYID,ISNULL(PRM.PUR_ACC_ID,0) AS PURACCID,
ISNULL(PRD.ITEM_ID,0) AS IETMID,ISNULL(PRD.UNIT_ID,0) AS UNITID,ISNULL(PRD.LOT_ID,0) AS LOTID,
ISNULL(PRD.SIZE_ID,0) AS SIZEID,ISNULL(PRD.SCREEN_ID,0) AS SCREEN_ID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEMGRPID,ISNULL(ACM.CITY_ID,0) AS AGENTCITYID,
ISNULL(PM.LGR_NAME,'') AS PARTY,ISNULL(AM.LGR_NAME,'') AS AGENT,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(STM.CITY_NAME,'') AS STATION,ISNULL(PUM.LGR_NAME,'') AS PURACC,
ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP,ISNULL(UM.UNIT_NAME,'') AS UNIT,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,ISNULL(SM.SIZE_NAME,'') AS SIZE,ISNULL(SCM.SCREEN_NAME,'') AS SCREEN,
ISNULL(COMP.CMP_ALIAS,'') AS ALIAS,ISNULL(IM.NICK_NAME,'') AS NICKNAME,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
(ISNULL(PRM.GrossTotal,0) +ISNULL(PRM.PUR_RET_Add1,0) + ISNULL(PRM.PUR_RET_Add2,0) + ISNULL(PRM.PUR_RET_Add3,0) -
( ISNULL(PRM.PUR_RET_Less1,0) + ISNULL(PRM.PUR_RET_Less2,0) + ISNULL(PRM.PUR_RET_Less3,0) + ISNULL(PRM.PUR_RET_Less4,0)+ ISNULL(PRM.PUR_RET_Less5,0))) AS TAXABLEAMT,
PRM.PUR_RET_Add4 AS CGST,PRM.PUR_RET_Add5 AS SGST,PRM.PUR_RET_Add6 AS IGST,PM.GSTINNO"
SET @SQL1="
FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PRM
INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID = PRD.PUR_RET_ID AND PRM.CMP_CODE = PRD.CMP_CODE AND PRM.FLAG = PRD.FLAG
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER PM ON PRM.LGR_ID = PM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER AM ON PRM.AGENT_ID = AM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"TRANSPORT_MASTER TM ON PRM.TRANSPORT_ID = TM.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PM.CITY_ID = PCM.CITY_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON AM.CITY_ID = ACM.CITY_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER STM ON PRM.STATION_ID = STM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER PUM ON PRM.PUR_ACC_ID = PUM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON PRD.ITEM_ID = IM.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
LEFT JOIN  "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = PRD.LOT_ID
LEFT JOIN  "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = PRD.SIZE_ID
LEFT JOIN  "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID = PRD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PRM.CMP_CODE
"+ @JOINSQL +"
WHERE PRM.CMP_CODE IN ("+@CMP_CODE+") "+@ORDERSQL+" ORDER BY PRM.DOCNO "

SET @SQL2 =  "
SELECT ISNULL(PRM.REFNO,'')REFNO,ISNULL(PRM.PUR_RET_ID,0) AS PURRETID,ISNULL(PRM.DOCNO,0) AS DOCNO,CONVERT(NVARCHAR,PRM.PUR_RET_DATE,103) AS RETURNDATE,
ISNULL(PRM.PUR_RET_LRNO,'') AS M_LRNO,CONVERT(NVARCHAR,PRM.PUR_RET_LRDATE,103) AS M_LRDATE,ISNULL(PRM.PUR_RET_ADD1,0) AS ADD1,
ISNULL(PRM.PUR_RET_ADD2,0) AS ADD2,ISNULL(PRM.PUR_RET_ADD3,0) AS ADD3,ISNULL(PRM.PUR_RET_ADDTOTAL,0) AS ADDTOTAL,
ISNULL(PRM.PUR_RET_LESS1,0) AS LESS1,ISNULL(PRM.PUR_RET_LESS2,0) AS LESS2,ISNULL(PRM.PUR_RET_LESS3,0) AS LESS3,
ISNULL(PRM.PUR_RET_LESSTOTAL,0) AS LESSTOTAL,ISNULL(PRM.PUR_RET_ROUNDOFF,0) AS ROUNDOFF,ISNULL(PRM.ROUNDEDAMOUNT,0) AS ROUNDEDAMOUNT,
ISNULL(PRM.GROSSTOTAL,0) AS GROSSTOTAL,ISNULL(PRM.NETTOTAL,0) AS NETTOTAL,ISNULL(PRM.FLAG,'') AS FLAG,
ISNULL(PRM.BILLNO,'') AS M_BILLNO,ISNULL(PRM.LOTNO,0) AS M_LOTNO,ISNULL(PRM.NARR,'') AS NARR,ISNULL(PRM.RETURN_TYPE,'') AS RETURN_TYPE,
ISNULL(PRD.PUR_RET_DTL_ID,0) AS SRNO,ISNULL(PRD.PUR_RET_BALE_NO,'') AS BALENO,ISNULL(PRD.ITEM_CUT,0) AS ITEMCUT,
ISNULL(PRD.PUR_RET_PCS,0) AS PCS,ISNULL(PRD.PUR_RET_QTY,0) AS QTY,ISNULL(PRD.PUR_RET_RATE,0) AS RATE,
ISNULL(PRD.PUR_RET_AMOUNT,0) AS AMOUNT,ISNULL(PRD.LRNO,'') AS D_LRNO,CONVERT(NVARCHAR,PRD.LRDATE,103) AS D_LRDATE,
ISNULL(PRD.BILLNO,'') AS D_BILLNO,ISNULL(PRD.LOTNO,0) AS D_LOTNO,
ISNULL(PRM.LGR_ID,0) AS LGRID,ISNULL(PRM.AGENT_ID,0) AS AGENTID,ISNULL(PRM.TRANSPORT_ID,0) AS TRANSPORTID,
ISNULL(PRM.STATION_ID,0) AS STATIONID,ISNULL(PCM.CITY_ID,0) AS PARTYCITYID,ISNULL(PRM.PUR_ACC_ID,0) AS PURACCID,
ISNULL(PRD.ITEM_ID,0) AS IETMID,ISNULL(PRD.UNIT_ID,0) AS UNITID,ISNULL(PRD.LOT_ID,0) AS LOTID,
ISNULL(PRD.SIZE_ID,0) AS SIZEID,ISNULL(PRD.SCREEN_ID,0) AS SCREEN_ID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEMGRPID,ISNULL(ACM.CITY_ID,0) AS AGENTCITYID,
ISNULL(PM.LGR_NAME,'') AS PARTY,ISNULL(AM.LGR_NAME,'') AS AGENT,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(STM.CITY_NAME,'') AS STATION,ISNULL(PUM.LGR_NAME,'') AS PURACC,
ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(IGM.ITEM_GRP_NAME,'') AS ITEMGRP,ISNULL(UM.UNIT_NAME,'') AS UNIT,
ISNULL(LOM.LOT_NAME,'') AS GREYMARKA,ISNULL(SM.SIZE_NAME,'') AS SIZE,ISNULL(SCM.SCREEN_NAME,'') AS SCREEN,
ISNULL(COMP.CMP_ALIAS,'') AS ALIAS,ISNULL(IM.NICK_NAME,'') AS NICKNAME,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
(ISNULL(PRD.Pur_Ret_Amount,0)) AS TAXABLEAMT,
ISNULL(PRD.VATAMOUNT,0)AS CGST,ISNULL(PRD.VATAMOUNT1,0)AS SGST,ISNULL(PRD.VATAMOUNT2,0)AS IGST,PM.GSTINNO"
SET @SQL3="
FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER PRM
INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID = PRD.PUR_RET_ID AND PRM.CMP_CODE = PRD.CMP_CODE AND PRM.FLAG = PRD.FLAG
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER PM ON PRM.LGR_ID = PM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER AM ON PRM.AGENT_ID = AM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"TRANSPORT_MASTER TM ON PRM.TRANSPORT_ID = TM.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PM.CITY_ID = PCM.CITY_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON AM.CITY_ID = ACM.CITY_ID 
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER STM ON PRM.STATION_ID = STM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER PUM ON PRM.PUR_ACC_ID = PUM.LGR_ID
LEFT JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON PRD.ITEM_ID = IM.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID = IM.ITEM_GRP_ID
LEFT JOIN  "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+"LOT_MASTER LOM ON LOM.LOT_ID = PRD.LOT_ID
LEFT JOIN  "+@DATABASENAME+"SIZE_MASTER SM ON SM.SIZE_ID = PRD.SIZE_ID
LEFT JOIN  "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID = PRD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER COMP ON COMP.CMP_CODE = PRM.CMP_CODE
"+ @JOINSQL +"
WHERE PRM.CMP_CODE IN ("+@CMP_CODE+") AND PRM.FLAG='CPR' ORDER BY PRM.DOCNO "
END

IF @RETURN_TYPE<>2
	BEGIN
		EXEC (@SQL+@SQL1)
		PRINT @SQL
		PRINT @SQL1
	END		
ELSE 
	BEGIN
		EXEC (@SQL2+@SQL3)
		PRINT @SQL2
		PRINT @SQL3
	END
END
		





















GO

