CREATE PROCEDURE [dbo].[PROC_QUALITYLIST]
(
@DATABASENAME AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN

	SET NOCOUNT ON;
           SET @SQL= " SELECT IM.ITEM_NAME AS ITEM ,IM.ITEM_ID,SM.SCREEN_ID,SM.SCREEN_NAME AS SCREEN,
                       CASE WHEN SM.SCHEME=1 THEN 'YES' ELSE 'NO' END AS SCHEME,
                       CASE WHEN SM.INCENTIVE=1 THEN 'YES' ELSE 'NO' END AS INCENTIVE,IM.ITEM_GOODS_TYPE
                       FROM "+ @DATABASENAME+"SCREEN_MASTER SM
                       INNER JOIN "+ @DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SM.ITEM_ID
                       INNER JOIN "+ @DATABASENAME+@TEMPTABLE +" TT ON IM.ITEM_ID=TT.CODE"
END

EXEC SP_EXECUTESQL @SQL
PRINT @SQL




















