/*    
PROC_RAW_STOCK_REPORT '10','ACC2010_2011.DBO.','01/APR/2010','07/OCT/2010','##3213','01/APR/2010'
   */   
CREATE PROCEDURE [dbo].[PROC_RAW_STOCK_REPORT]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @STARTDATE AS NVARCHAR(20)
  
)	
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "  

BEGIN	
SET @SQL=" SELECT   DATE, SUM(IT_OP_THAN_RM) AS IT_OP_THAN_RM,SUM(IT_OP_MTRS_RM )AS IT_OP_MTRS_RM ,SUM(PUR_THAN_RM) AS PUR_THAN_RM,SUM(PUR_MTRS_RM) AS PUR_MTRS_RM,
          SUM(PRO_THAN_RM) AS PRO_THAN_RM,SUM(PRO_MTRS_RM) AS PRO_MTRS_RM,SUM(PURRET_THAN_RM) AS PURRET_THAN_RM,SUM(PURRET_MTRS_RM ) AS PURRET_MTRS_RM ,
           SUM(IT_OP_THAN_SFG) AS IT_OP_THAN_SFG,SUM(IT_OP_MTRS_SFG) AS IT_OP_MTRS_SFG ,SUM(GM_THAN_SFG) AS GM_THAN_SFG,SUM(GM_MTRS_SFG) AS GM_MTRS_SFG,SUM(SHORTAGE_SFG) AS SHORTAGE_SFG
          FROM (
           SELECT '"+@STARTDATE+"' AS DATE, IOS.ITEM_OP_STOCK AS IT_OP_THAN_RM,IOS.ITEM_IN_QTY AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
           0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
           0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
           FROM "+@DATABASENAME+"ITEM_OPENING_STOCK IOS
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=IOS.ITEM_ID
           "+@JOINSQL+ "
           WHERE IOS.CMP_CODE="+@CMP_CODE +"           
     UNION ALL
         SELECT PI.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,PID.PIECES AS PUR_THAN_RM,PID.QUANTITY AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
         INNER JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
         "+@JOINSQL+"
         WHERE PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE +"
    UNION ALL
         SELECT PI.VCHDATE AS DATE, PID.PIECES  AS IT_OP_THAN_RM,PID.QUANTITY AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
         INNER JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
          "+@JOINSQL+"
         WHERE PI.VCHDATE<'"+@FROMDATE+"' AND PI.VCHDATE>='"+@STARTDATE+"'   AND PI.CMP_CODE="+@CMP_CODE +"
   UNION ALL "
SET @SQL1="
        SELECT P2P.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         P2P.DELTHAN AS PRO_THAN_RM,P2P.DELMETER AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE  P2P.YEARFLAG='C' AND FROM_PROCESS_ID=1 AND  P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE="+@CMP_CODE +"
UNION ALL 
        SELECT P2P.VCHDATE AS DATE,(0- P2P.DELTHAN)  AS IT_OP_THAN_RM,(0-P2P.DELMETER) AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         P2P.DELTHAN AS IT_OP_THAN_SFG,P2P.DELMETER AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE FROM_PROCESS_ID=1 AND P2P.VCHDATE <'"+@FROMDATE+"' AND P2P.VCHDATE>'="+@STARTDATE+"'  AND P2P.CMP_CODE="+@CMP_CODE + " AND P2P.YEARFLAG='C'
UNION ALL 
      
SELECT GS.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         GS.PCS AS PRO_THAN_RM,GS.GRAYMTRS AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"GRAYSTOCKOUT  GS
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID 
         "+@JOINSQL+"          
         WHERE  GS.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND GS.CMP_CODE="+@CMP_CODE +"
 UNION ALL
SELECT GS.VCHDATE AS DATE,(0- GS.PCS)  AS IT_OP_THAN_RM,(0-GS.GRAYMTRS) AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         GS.PCS AS IT_OP_THAN_SFG,GS.GRAYMTRS AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"GRAYSTOCKOUT  GS
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID
          "+@JOINSQL+"          
         WHERE GS.VCHDATE <'"+@FROMDATE+"'  AND GS.VCHDATE>='"+@STARTDATE+"'  AND GS.CMP_CODE="+@CMP_CODE +"
UNION ALL  "

SET @SQL2= "
        SELECT PRM.PUR_RET_DATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,PRD.PUR_RET_PCS AS PURRET_THAN_RM,PRD.PUR_RET_QTY AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER  PRM
         INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
         "+@JOINSQL+"
         WHERE PRM.PUR_RET_DATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PRM.CMP_CODE="+@CMP_CODE +"
UNION ALL 
        SELECT PRM.PUR_RET_DATE AS DATE,(0- PRD.PUR_RET_PCS) AS IT_OP_THAN_RM,(0-PRD.PUR_RET_QTY ) AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
         FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER  PRM
         INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
         "+@JOINSQL+"
         WHERE PRM.PUR_RET_DATE<'"+@FROMDATE+"' AND PRM.PUR_RET_DATE>='"+@STARTDATE+"' AND PRM.CMP_CODE="+@CMP_CODE +"
         UNION ALL 

         SELECT '"+@STARTDATE+"' AS DATE, 0 AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_TM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
           0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
           PS.THAN AS IT_OP_THAN_SFG,PS.MTRS AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG
           FROM "+@DATABASENAME+"PROCESSSTOCK PS
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PS.ITEM_ID
           "+@JOINSQL+ "
           WHERE PS.CMP_CODE="+@CMP_CODE + "
          

 UNION ALL "
SET @SQL3= "
           SELECT FTGD.RECDATE AS DATE, 0 AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_TM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
           0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
           0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,FTGD.FINISHTHAN AS GM_THAN_SFG,FTGD.FINISHMETER AS GM_MTRS_SFG,FTGD.SHORTMTR AS SHORTAGE_SFG          
           FROM "+@DATABASENAME+"FTGRECDETAIL FTGD
           INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FTGD.FTGID
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGD.RECDATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND FTG.CMP_CODE="+@CMP_CODE +"
UNION ALL
           SELECT FTGD.RECDATE AS DATE, 0 AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_TM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
           0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
           (0-FTGD.FINISHTHAN) AS IT_OP_THAN_SFG,(0-FTGD.FINISHMETER) AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG          
           FROM "+@DATABASENAME+"FTGRECDETAIL FTGD
           INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FTGD.FTGID
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGD.RECDATE  <'"+@FROMDATE+"'   AND FTGD.RECDATE  >='"+@STARTDATE+"'  AND FTG.CMP_CODE="+@CMP_CODE +"
         

 ) AS DETAIL
GROUP BY  DATE  ORDER BY DATE "
    
END
EXEC (@SQL+@SQL1+@SQL2+@SQL3)

PRINT @SQL 
PRINT @SQL1 
PRINT @SQL2 
PRINT @SQL3




















GO

/****** Object:  StoredProcedure [dbo].[PROC_RAW_STOCK_REPORT_RM]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
