/*    
PROC_RAW_STOCK_REPORT_RM '10','ACC2010_2011.DBO.','01/APR/2010','30/aug/2010','##2824','01/APR/2010','01/APR/2010'
   */   
CREATE PROCEDURE [dbo].[PROC_RAW_STOCK_REPORT_RM]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @STARTDATE AS NVARCHAR(20),
  @OPENINGDATE AS NVARCHAR(20)
  
)	
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @SQL7=""
SET @SQL8=""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "  

BEGIN	
SET @SQL=" SELECT   DATE, SUM(IT_OP_THAN_RM) AS IT_OP_THAN_RM,SUM(IT_OP_MTRS_RM )AS IT_OP_MTRS_RM ,SUM(PUR_THAN_RM) AS PUR_THAN_RM,SUM(PUR_MTRS_RM) AS PUR_MTRS_RM,
          SUM(PRO_THAN_RM) AS PRO_THAN_RM,SUM(PRO_MTRS_RM) AS PRO_MTRS_RM,SUM(PURRET_THAN_RM) AS PURRET_THAN_RM,SUM(PURRET_MTRS_RM ) AS PURRET_MTRS_RM            
           ,SUM(SALES_THAN_RM) AS SALES_THAN_RM,SUM(SALES_MTRS_RM) AS SALES_MTRS_RM,SUM(GS_THAN_RM)AS GS_THAN_RM,SUM(GS_MTRS_RM)AS GS_MTRS_RM
          FROM (
           SELECT '"+@OPENINGDATE+"' AS DATE, IOS.ITEM_OP_THAN AS IT_OP_THAN_RM,IOS.ITEM_OP_STOCK AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0.00 AS PUR_MTRS_RM,
           0 AS PRO_THAN_RM,0.00 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0.00 AS PURRET_MTRS_RM,
           0 AS SALES_THAN_RM,0.00 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0.00 AS GS_MTRS_RM
           FROM "+@DATABASENAME+"ITEM_OPENING_STOCK IOS
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=IOS.ITEM_ID
           "+@JOINSQL+ "
           WHERE IOS.CMP_CODE="+@CMP_CODE +"           
     UNION ALL
         SELECT PI.RECDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,PID.PIECES AS PUR_THAN_RM,PID.QUANTITY AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
         INNER JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
         "+@JOINSQL+"
         WHERE PI.RECDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE +"
    UNION ALL
         SELECT '"+@OPENINGDATE+"' AS DATE, PID.PIECES  AS IT_OP_THAN_RM,PID.QUANTITY AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
         INNER JOIN  "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
          "+@JOINSQL+"
         WHERE PI.RECDATE<'"+@FROMDATE+"' AND PI.RECDATE>='"+@STARTDATE+"'   AND PI.CMP_CODE="+@CMP_CODE +"
   UNION ALL "
SET @SQL1="
         SELECT SI.SAL_INV_VDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         SID.SAL_INV_PCS AS SALES_THAN_RM,SID.SAL_INV_QTY AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"SALES_INVOICE_DETAIL SID
         INNER JOIN  "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
         "+@JOINSQL+"
         WHERE SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE="+@CMP_CODE +"
    UNION ALL
         SELECT '"+@OPENINGDATE+"'  AS DATE,(0- SID.SAL_INV_PCS)  AS IT_OP_THAN_RM,(0-SID.SAL_INV_QTY)AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"SALES_INVOICE_DETAIL SID
         INNER JOIN  "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
         "+@JOINSQL+"
         WHERE SI.SAL_INV_VDATE<'"+@FROMDATE+"'  AND SI.SAL_INV_VDATE>='"+@STARTDATE+"' AND SI.CMP_CODE="+@CMP_CODE +"
   UNION ALL "
SET @SQL2="
        SELECT P2P.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         P2P.DELTHAN AS PRO_THAN_RM,P2P.DELMETER AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE  P2P.YEARFLAG='C' AND FROM_PROCESS_ID=1 AND  P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE="+@CMP_CODE +"
UNION ALL 
        SELECT '"+@OPENINGDATE+"' AS DATE,(0- P2P.DELTHAN)  AS IT_OP_THAN_RM,(0-P2P.DELMETER) AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE FROM_PROCESS_ID=1 AND P2P.VCHDATE <'"+@FROMDATE+"' AND P2P.VCHDATE>='"+@STARTDATE+"'  AND P2P.CMP_CODE="+@CMP_CODE + " AND P2P.YEARFLAG='C'
UNION ALL 
      
SELECT GS.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,GS.PCS AS GS_THAN_RM,GS.GRAYMTRS AS GS_MTRS_RM
         FROM "+@DATABASENAME+"GRAYSTOCKOUT  GS
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID 
         "+@JOINSQL+"          
         WHERE  GS.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND GS.CMP_CODE="+@CMP_CODE +" AND GS.STOCKOUT NOT IN('RETURN','SOLD')
 UNION ALL
SELECT '"+@OPENINGDATE+"' AS DATE,(0- GS.PCS)  AS IT_OP_THAN_RM,(0-GS.GRAYMTRS) AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"GRAYSTOCKOUT  GS
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID
          "+@JOINSQL+"          
         WHERE GS.VCHDATE <'"+@FROMDATE+"'  AND GS.VCHDATE>='"+@STARTDATE+"'  AND GS.CMP_CODE="+@CMP_CODE +" AND GS.STOCKOUT NOT IN('RETURN','SOLD')
UNION ALL  "

SET @SQL3= "
        SELECT PRM.PUR_RET_DATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,PRD.PUR_RET_PCS AS PURRET_THAN_RM,PRD.PUR_RET_QTY AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER  PRM
         INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
         "+@JOINSQL+"
         WHERE PRM.PUR_RET_DATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PRM.CMP_CODE="+@CMP_CODE +"
UNION ALL 
        SELECT '"+@OPENINGDATE+"' AS DATE,(0- PRD.PUR_RET_PCS) AS IT_OP_THAN_RM,(0-PRD.PUR_RET_QTY)  AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"PURCHASE_RETURN_MASTER  PRM
         INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
         "+@JOINSQL+"
         WHERE PRM.PUR_RET_DATE<'"+@FROMDATE+"' AND PRM.PUR_RET_DATE>='"+@STARTDATE+"' AND PRM.CMP_CODE="+@CMP_CODE +"          

"
SET @SQL4="
         UNION ALL
         SELECT '"+@OPENINGDATE+"' AS DATE, SID.PIECES  AS IT_OP_THAN_RM,SID.QUANTITY AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"STOCKIN_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"STOCKIN_MASTER SI ON SI.STOCKIN_ID=SID.STOCKIN_ID
          "+@JOINSQL+"
         WHERE SI.VCHDATE<'"+@FROMDATE+"' AND SI.VCHDATE>='"+@STARTDATE+"'   AND SI.CMP_CODE="+@CMP_CODE +"
   UNION ALL
         SELECT '"+@OPENINGDATE+"' AS DATE, GID.PIECES  AS IT_OP_THAN_RM,GID.QUANTITY AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_DETAIL GID ON GID.ITEM_ID=IM.ITEM_ID
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_MASTER GIM ON GIM.GreyStockTrans_Id=GID.GreyStockTrans_Id
          "+@JOINSQL+"
         WHERE GIM.VCHDATE<'"+@FROMDATE+"' AND GIM.VCHDATE>='"+@STARTDATE+"'   AND GIM.CMP_CODE="+@CMP_CODE +"
"
SET @SQL5="
UNION ALL
         SELECT SI.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,SID.PIECES AS PUR_THAN_RM,SID.QUANTITY AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"STOCKIN_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"STOCKIN_MASTER SI ON SI.STOCKIN_ID=SID.STOCKIN_ID
         "+@JOINSQL+"
         WHERE SI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE="+@CMP_CODE +"
UNION ALL
         SELECT GIM.VCHDATE AS DATE, 0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,GID.PIECES AS PUR_THAN_RM,GID.QUANTITY AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_DETAIL GID ON GID.ITEM_ID=IM.ITEM_ID
                INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_IN_MASTER GIM ON GIM.GreyStockTrans_Id=GID.GreyStockTrans_Id
         "+@JOINSQL+"
         WHERE GIM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND GIM.CMP_CODE="+@CMP_CODE +"

"
SET  @SQL6="
    UNION ALL
         SELECT '"+@OPENINGDATE+"'  AS DATE,(0- SD.PIECES)  AS IT_OP_THAN_RM,(0-SD.QUANTITY)AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"STOCKOUT_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"STOCKOUT_MASTER SM ON SM.STOCKOUT_ID=SD.STOCKOUT_ID
         "+@JOINSQL+"
         WHERE SM.VCHDATE<'"+@FROMDATE+"'  AND SM.VCHDATE>='"+@STARTDATE+"' AND SM.CMP_CODE="+@CMP_CODE +"
UNION ALL
         SELECT '"+@OPENINGDATE+"'  AS DATE,(0- GD.PIECES)  AS IT_OP_THAN_RM,(0-GD.QUANTITY)AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         0 AS SALES_THAN_RM,0 AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_DETAIL GD ON GD.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_MASTER GM ON GM.GreyStockTrans_Id=GD.GreyStockTrans_Id
         "+@JOINSQL+"
         WHERE GM.VCHDATE<'"+@FROMDATE+"'  AND GM.VCHDATE>='"+@STARTDATE+"' AND GM.CMP_CODE="+@CMP_CODE +"
"
SET  @SQL7="
    UNION ALL
         SELECT SM.VCHDATE AS DATE,0  AS IT_OP_THAN_RM,0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         SD.PIECES AS SALES_THAN_RM,SD.QUANTITY AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"STOCKOUT_DETAIL SD ON SD.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"STOCKOUT_MASTER SM ON SM.STOCKOUT_ID=SD.STOCKOUT_ID
         "+@JOINSQL+"
         WHERE SM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SM.CMP_CODE="+@CMP_CODE +"
UNION ALL
         SELECT GM.VCHDATE   AS DATE,0   AS IT_OP_THAN_RM, 0 AS IT_OP_MTRS_RM ,0 AS PUR_THAN_RM,0 AS PUR_MTRS_RM,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,0 AS PURRET_THAN_RM,0 AS PURRET_MTRS_RM,
         GD.PIECES AS SALES_THAN_RM,GD.QUANTITY AS SALES_MTRS_RM,0 AS GS_THAN_RM,0 AS GS_MTRS_RM
         FROM "+@DATABASENAME+"ITEM_MASTER IM
         INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_DETAIL GD ON GD.ITEM_ID=IM.ITEM_ID
         INNER JOIN "+@DATABASENAME+"GREYSTOCKTRANS_MASTER GM ON GM.GreyStockTrans_Id=GD.GreyStockTrans_Id
         "+@JOINSQL+"
         WHERE GM.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND GM.CMP_CODE="+@CMP_CODE +"


 ) AS DETAIL
GROUP BY  DATE  ORDER BY DATE 
"
    
END
EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQL4+@SQL5+@SQL6+@SQL7)
PRINT @SQL 
PRINT @SQL1 
PRINT @SQL2 
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5 
PRINT @SQL6
PRINT @SQL7




















GO

/****** Object:  StoredProcedure [dbo].[PROC_RAW_STOCK_REPORT_SFG]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*    
PROC_RAW_STOCK_REPORT_SFG '10','ACC2010_2011.DBO.','01/APR/2010','30/aug/2010','##2824','01/APR/2010','01/APR/2010'
   */   
CREATE PROCEDURE [dbo].[PROC_RAW_STOCK_REPORT_SFG]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(20),
  @STARTDATE AS NVARCHAR(20),
  @OPENINGDATE AS NVARCHAR(20)
  
)	
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @JOINSQL=""

SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID "  

BEGIN	
SET @SQL=" SELECT   DATE,SUM(PRO_THAN_RM) AS PRO_THAN_RM,SUM(PRO_MTRS_RM) AS PRO_MTRS_RM,
           SUM(IT_OP_THAN_SFG) AS IT_OP_THAN_SFG,SUM(IT_OP_MTRS_SFG) AS IT_OP_MTRS_SFG ,SUM(GM_THAN_SFG) AS GM_THAN_SFG,SUM(GM_MTRS_SFG) AS GM_MTRS_SFG
           ,SUM(SHORTAGE_SFG) AS SHORTAGE_SFG,SUM(STK_THAN_SFG)AS STK_THAN_SFG,SUM(STK_MTRS_SFG)AS STK_MTRS_SFG
          FROM (                           
        SELECT P2P.VCHDATE AS DATE,
         P2P.DELTHAN AS PRO_THAN_RM,P2P.DELMETER AS PRO_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE  P2P.YEARFLAG='C' AND FROM_PROCESS_ID=1 AND  P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE="+@CMP_CODE +"
UNION ALL 
        SELECT '"+@OPENINGDATE+"' AS DATE,0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
         P2P.DELTHAN AS IT_OP_THAN_SFG,P2P.DELMETER AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
         FROM "+@DATABASENAME+"PROCESS2PROCESS  P2P
         INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE FROM_PROCESS_ID=1 AND P2P.VCHDATE <'"+@FROMDATE+"' AND P2P.VCHDATE>='"+@STARTDATE+"'  AND P2P.CMP_CODE="+@CMP_CODE + " AND P2P.YEARFLAG='C'
UNION ALL  "

SET @SQL2="
          SELECT '"+@OPENINGDATE+"' AS DATE,0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
         (0-P2P.DELTHAN) AS IT_OP_THAN_SFG,(0-P2P.DELMETER) AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
         FROM  "+@DATABASENAME+"PROCESS2PROCESS P2P
         INNER JOIN  "+@DATABASENAME+"PROCESS_MASTER PM ON P2P.TO_PROCESS_ID=PM.PROCESS_ID
         INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE PM.OUTSIDE=1 AND P2P.VCHDATE <'"+@FROMDATE+"' AND P2P.VCHDATE>='"+@STARTDATE+"'  AND P2P.CMP_CODE="+@CMP_CODE + " AND P2P.YEARFLAG='C'
         UNION ALL

         SELECT P2P.VCHDATE AS DATE,
         0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
         0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,P2P.DELTHAN  AS STK_THAN_SFG,P2P.DELMETER AS STK_MTRS_SFG
         FROM  "+@DATABASENAME+"PROCESS2PROCESS P2P
         INNER JOIN  "+@DATABASENAME+"PROCESS_MASTER PM ON P2P.TO_PROCESS_ID=PM.PROCESS_ID
         INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
         "+@JOINSQL+"
         WHERE  P2P.YEARFLAG='C' AND PM.OUTSIDE=1 AND  P2P.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND P2P.CMP_CODE="+@CMP_CODE +"
UNION ALL
"


SET @SQL3= "       

         SELECT '"+@OPENINGDATE+"' AS DATE,0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
           PS.THAN AS IT_OP_THAN_SFG,PS.MTRS AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
           FROM "+@DATABASENAME+"PROCESSSTOCK PS
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PS.ITEM_ID
           "+@JOINSQL+ "
           WHERE PS.CMP_CODE="+@CMP_CODE + "
          

 UNION ALL "
SET @SQL4= "
           SELECT FTGD.RECDATE AS DATE,       0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
           0 AS IT_OP_THAN_SFG,0 AS IT_OP_MTRS_SFG ,FTGD.GRAYTHAN AS GM_THAN_SFG,FTGD.GRAYMETER AS GM_MTRS_SFG,FTGD.SHORTMTR AS SHORTAGE_SFG ,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
           FROM "+@DATABASENAME+"FTGRECDETAIL FTGD
           INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FTGD.FTGID
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGD.RECDATE  BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND FTG.CMP_CODE="+@CMP_CODE +"
UNION ALL
           SELECT '"+@OPENINGDATE+"' AS DATE,
           0 AS PRO_THAN_RM,0 AS PRO_MTRS_RM,
           (0-FTGD.GRAYTHAN) AS IT_OP_THAN_SFG,(0-FTGD.GRAYMETER) AS IT_OP_MTRS_SFG ,0 AS GM_THAN_SFG,0 AS GM_MTRS_SFG,0 AS SHORTAGE_SFG,0 AS STK_THAN_SFG,0 AS STK_MTRS_SFG
           FROM "+@DATABASENAME+"FTGRECDETAIL FTGD
           INNER JOIN "+@DATABASENAME+"FINISH2GODOWN FTG ON FTG.FTGID=FTGD.FTGID
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=FTG.ITEM_ID
           "+@JOINSQL+"
           WHERE FTGD.RECDATE  <'"+@FROMDATE+"'   AND FTGD.RECDATE  >='"+@STARTDATE+"'  AND FTG.CMP_CODE="+@CMP_CODE +"
         

 ) AS DETAIL
GROUP BY  DATE  ORDER BY DATE "
    
END
EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQL4)
PRINT @SQL 
PRINT @SQL1 
PRINT @SQL2 
PRINT @SQL3
PRINT @SQL4




















GO

