/*
-- =============================================
-- Author:		HIREN DOSHI
-- Create_date: 16-12-2013
-- Description:	THIS PROCEDURE USED FOR BANK PAYMENT SHOW DATA
-- ReportName : RECEIPT_NOTE_HALF_PRINT.RPT,RECEIPT_NOTE_FULL_PRINT.RPT
-- =============================================
PROC_RECEIPT_NOTE_PRINT 1,'ACC2014_2015.DBO.',71,71,1
*/
CREATE PROCEDURE [dbo].[PROC_RECEIPT_NOTE_PRINT]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@FROMDOCNO NVARCHAR(50),
	@TODOCNO NVARCHAR(50),
	@RPT_TYPE NVARCHAR(10)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @TYPESQL AS NVARCHAR(4000)
SET @SQL=""
SET @TYPESQL=""
BEGIN 
IF @RPT_TYPE =  1 
		SET @TYPESQL = " AND TM.TRAN_TYPE = 'BR' "
	ELSE IF @RPT_TYPE =  2 
		SET @TYPESQL = " AND TM.TRAN_TYPE = 'CR' "
END
BEGIN
	SET NOCOUNT ON;
	SET @SQL = "SELECT DISTINCT TM.TRAN_ID,TM.TRAN_TYPE,TM.TRAN_MASTER_ID,TD.TRAN_DETAIL_ID,TM.TRAN_AMOUNT,
				CONVERT(INT,TM.TRAN_DOCNO) AS TRAN_DOCNO,TM.TRAN_DATE,TD.CHEQUENO,TD.SRNO,TD.DDDATE,TD.ADJUST,
				TD.NARRATION,LM.LGR_NAME AS PARTY,UPPER(LM.LGR_ADD1) AS ADD1,UPPER(LM.LGR_ADD2) AS ADD2,
			    UPPER(LM.LGR_ADD3) AS ADD3,UPPER(CM.CITY_NAME) AS PARTY_CITY,LM.CITY_PINCODE,
				UPPER(SM.STATE_NAME) AS PARTY_STATE,ALM.LGR_NAME AS AGENT,CMP_PHONE1,CMP_PHONE2,CMP_MOBILE,
				CMP_EMAIL,PD.VCODE AS BILL_VCODE,ADJ.SRNO AS BILL_SRNO,ADJ.BILLNO AS BILL_BILLNO,
				ADJ.DATE AS BILL_DATE,ADJ.AMOUNT AS BILL_AMOUNT,ADJ.DISCOUNT AS BILL_DISCOUNT,
				ADJ.DISC_PER AS BILL_DISC_PER,ADJ.OTHERLESS AS BILL_RD,ADJ.TOTAL AS BILL_TOTAL,
				ADJ.ADJUSTAMT AS BILL_ADJUSTAMT,ADJ.INTEREST AS BILL_INTEREST,ADJ.INTREC AS BILL_INTREC,
				ADJ.FLAG AS BILL_FLAG,0 AS BILL_PENDINGAMT,ADJ.PAID AS BILL_SETTLED,ISNULL(ADJ.TDS_AMOUNT,0) AS TDS_AMOUNT,LM.LGR_MOBILE
				FROM "+@DATABASENAME+" TRAN_MASTER TM
				INNER JOIN "+@DATABASENAME+" TRAN_DETAIL TD ON TD.TRAN_ID = TM.TRAN_ID AND TM.TRAN_TYPE = TD.TRAN_TYPE
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID = TD.TRAN_DETAIL_ID
				LEFT JOIN  "+@DATABASENAME+" LEDGER_DETAIL LD ON LM.LGR_ID = LD.LGR_ID AND TM.CMP_CODE = LD.CMP_CODE
				LEFT JOIN  "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID = LM.CITY_ID
				LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON SM.STATE_ID = LM.STATE_ID
				LEFT JOIN  "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID = LD.AGENT_ID
				INNER JOIN "+@DATABASENAME+" COMPANY_MASTER COMP ON COMP.CMP_CODE = TM.CMP_CODE
				LEFT JOIN  "+@DATABASENAME+" ADJMASTER ADJ ON ADJ.ENTRYCODE =  TM.TRAN_ID AND ADJ.TYPE = TM.TRAN_TYPE
				LEFT JOIN  "+@DATABASENAME+" PARTYDETAIL PD ON PD.BILL_NO=ADJ.BILLNO AND ADJ.FLAG=PD.JOBFLAG 
				AND PD.CMP_CODE=ADJ.CMP_CODE AND ADJ.VCODE=PD.VCODE
				WHERE TM.TRAN_DOCNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+" 
				"+@TYPESQL+" AND TM.CMP_CODE = "+@CMP_CODE+" ORDER BY TRAN_DOCNO,ADJ.SRNO "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL 

























GO

/****** Object:  StoredProcedure [dbo].[PROC_RECEIVEDPAYTMENTTCS22]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
