/*
-- =============================================S
-- Author:		<SANJAY >
-- ALTER_date: <04/JULY/2017>
-- Description:	<PRINTTING INVOICE FOR WITHCUT>
-- REPORT NAME: SALESINVOICE_WITHCUT.rpt
-- =============================================
*/
/*
PROC_RECEIVEDPAYTMENTTCS22 1,'ACC2020_2021.DBO.','ACC2019_2020.DBO.',1,##3708,'01/APR/2020','05/oct/2020',0,5000000
select * from tempdb..sysobjects
*/
CREATE PROCEDURE [dbo].[PROC_RECEIVEDPAYTMENTTCS22]
(
		@Cmp_Code NVARCHAR(100),
		@DATABASENAME NVARCHAR(50),
		@PreviousDatabaseName NVARCHAR(50),
		@RPT_WISE int,
		@TEMPTABLE NVARCHAR(20),		
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
		@RPTTYPE AS INT,
		@TotalAmt NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)
DECLARE @SQLP NVARCHAR(3999)
DECLARE @SQLL NVARCHAR(3999)
DECLARE @SQLCOND NVARCHAR(3999)

SET @SQL=""
SET @SQL1=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL="" 
set @SQLP=""
set @SQLL=""
set @SQLCOND = ""
       IF @RPT_WISE = 1 
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		ELSE IF @RPT_WISE = 2
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AGM.LGR_ID"
		ELSE IF @RPT_WISE = 3
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"
		ELSE IF @RPT_WISE = 4
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"

		BEGIN
			IF @RPTTYPE = 0 /* ALL */
				SET @SQLCOND = ""
			ELSE IF @RPTTYPE = 1 /* PENDING */
				SET @SQLCOND = " WHERE ReceviedAmtPRE + ReceviedAmtWithin > = "+ @TotalAmt +""

		END		




BEGIN
SET NOCOUNT ON;
SET @SQLP="

SELECT  * FROM (
			SELECT  MAX(Lgr_Pano)Lgr_Pano,MAX(VDATE)VDATE,MAX(PARTYNAME)PARTYNAME,MAX(isnull(PARTYCITY,''))PARTYCITY,MAX(AGENTNAME)AGENTNAME,MAX(CUSTOMERGROUP)CUSTOMERGROUP,SUM(SalesAmtPRE)SalesAmtPRE,SUM(SalesAmtWhithin)SalesAmtWhithin,SUM(ReceviedAmtPRE )ReceviedAmtPRE,SUM(ReceviedAmtWithin)ReceviedAmtWithin,MAX(TCS_PER)TCS_PER,SUM(TCS_AMT)TCS_AMT,LGR_ID  FROM (
						SELECT  CMP.CMP_CODE,LM.Lgr_Pano,SI.SAL_INV_VDATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
UPPER(isnull(PCM.CITY_NAME,'')) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,Si.Sal_Inv_NetTotal as SalesAmtPRE, 0 as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
SI.TCS_PER,SI.TCS_AMT ,LM.LGR_ID
			 FROM "+ @DATABASENAME+ "SALES_INVOICE SI
			INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
			INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+" 
			WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +" )   AND  SI.SAL_INV_VDATE<'"+@FROMDATE+"' 
UNION ALL

		SELECT  CMP.CMP_CODE,LM.Lgr_Pano,SI.Job_Sal_Inv_VDate AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,Si.NetAmt as SalesAmtPRE, 0 as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
SI.TCS_PER,SI.TCS_AMT ,LM.LGR_ID
			 FROM "+ @DATABASENAME+ "Job_SalesInvoice_Master SI
			INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
			
			INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
			
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+" 
			WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +" )   AND  SI.Job_Sal_Inv_VDate<'"+@FROMDATE+"' 
			
"
SET @SQL="
UNION ALL
			SELECT  CMP.CMP_CODE,LM.Lgr_Pano,SI.SAL_INV_VDATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,0 as SalesAmtPRE, Si.Sal_Inv_NetTotal as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
SI.TCS_PER,SI.TCS_AMT ,LM.LGR_ID
			 FROM "+ @DATABASENAME+ "SALES_INVOICE SI
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
			INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
			LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+" 
			WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +" ) AND  SI.SAL_INV_VDATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' 
union all
SELECT  CMP.CMP_CODE,LM.Lgr_Pano,SI.Job_Sal_Inv_VDate AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME, 
UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,0 as SalesAmtPRE, Si.NetAmt as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
SI.TCS_PER,SI.TCS_AMT ,LM.LGR_ID
			 FROM "+ @DATABASENAME+ "Job_SalesInvoice_Master SI
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
			INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
			
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
			LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+" 
			WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +" ) AND  SI.Job_Sal_Inv_VDate BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' 
"
SET @SQL1=" 
	UNION ALL
	SELECT  CMP.CMP_CODE,LM.Lgr_Pano,TM.TRAN_DATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
	UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
	0 as SalesAmtPRE, 0 as SalesAmtWhithin, TD.TRAN_AMOUNT - ISNULL(TM.TCS_AMT,0) as ReceviedAmtPRE,0 as ReceviedAmtWithin,
	0 as TCS_PER,0 as TCS_AMT,LM.LGR_ID
	FROM " + @DATABASENAME + "TRAN_DETAIL TD 
	INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
	INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
	LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
	LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER AgM ON AgM.LGR_ID=LD.AGENT_ID         
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER pCM ON LM.CITY_ID=pCM.CITY_ID
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON AgM.CITY_ID=ACM.CITY_ID
	LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
	INNER JOIN "+@DATABASENAME +"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
	"+@JOINSQL+" 
	WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +" ) AND TM.TRAN_DATE   <'"+@FROMDATE+"'  and  TD.TRAN_TYPE IN('BR','CR')

UNION ALL "
SET @SQLL="  SELECT  CMP.CMP_CODE,LM.Lgr_Pano,TM.TRAN_DATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
0 as SalesAmtPRE,0 as SalesAmtWhithin, 0 as ReceviedAmtPRE,TD.TRAN_AMOUNT - ISNULL(TM.TCS_AMT,0)  as ReceviedAmtWithin,
0 as TCS_PER,0 as TCS_AMT,LM.LGR_ID
FROM " + @DATABASENAME + "TRAN_DETAIL TD 
INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER AgM ON AgM.LGR_ID=LD.AGENT_ID         
LEFT JOIN " + @DATABASENAME + "CITY_MASTER pCM ON LM.CITY_ID=pCM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON AgM.CITY_ID=ACM.CITY_ID

LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME +"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
"+@JOINSQL+" 
WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +" ) AND TM.TRAN_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "'  and  TD.TRAN_TYPE IN('BR','CR')

			)AS DETAIL  GROUP BY Lgr_Pano,PARTYNAME,LGR_ID )as sd  
inner join 
(
SELECT  sum(PRESALE)PRESALE from ( select sum(Si.Sal_Inv_NetTotal )as PRESALE
			 FROM "+ @PreviousDatabaseName+ "SALES_INVOICE SI WHERE SI.CMP_CODE IN  ("+ @CMP_CODE +" ) 
			
)pre
			  ) c on  1=1  " + @SQLCOND + "

			"
      
END	

EXEC  (@SQLP+@SQL+@SQL1+@SQLL)
PRINT @SQLP
PRINT @SQL
PRINT @SQL1
PRINT @SQLL

























GO

/****** Object:  StoredProcedure [dbo].[PROC_RECONCILIATION]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















CREATE PROCEDURE [dbo].[PROC_RECONCILIATION]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@ACCID AS NVARCHAR(20),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20)
)
AS

DECLARE @SQL AS VARCHAR(4000)
DECLARE @SQL1 AS VARCHAR(4000)
DECLARE @SQL2 AS VARCHAR(4000)
DECLARE @SQL3 AS VARCHAR(4000)
DECLARE @SQL4 AS VARCHAR(4000)
DECLARE @SQL5 AS VARCHAR(4000)
DECLARE @SQL6 AS VARCHAR(4000)
DECLARE @SQL7 AS VARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL7=""

BEGIN
	SET NOCOUNT ON;

        set @SQL="  SELECT Detail.Vcode, Detail.DocNo,CHEQUENO,Detail.PartyName, Detail.PartyId, Detail.voucher_date, Detail.DrAMOUNT, Detail.CrAMOUNT, Detail.type, Detail.AccountName,Detail.ACC_ID,Remark,ClearingDate,CLEARED,PartyCity,0 AS PREVDRAMOUNT,0 AS PREVCRAMOUNT,'C' AS FLAG from( 
                    Select   TM.Tran_DocNo as DocNo,Td.Chequeno,LM1.Lgr_Name as PartyName,TM.Tran_Master_ID as PartyId,
                    TM.TRan_ID as Vcode,TM.Tran_Date as Voucher_Date,
                    (CASE WHEN TM.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT ,
                    (CASE WHEN TM.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT,
                    TM.Tran_Type as Type,LM.Lgr_Name as AccountName,LM.Lgr_ID as ACC_ID,TD.Remark,TD.ClearingDate,
                    (CASE WHEN  TD.ClearingDate IS NULL THEN 'NOT CLEARED' when (TD.ClearingDate Between  '"+ @FROMDATE+ "' And '"+ @TODATE+ "') then 'CLEARED'  ELSE 'NODISPLAY'  END )AS  CLEARED
                    ,CM.City_Name as PartyCITY
                    From "+@DATABASENAME+"Tran_Master TM 
                    Inner Join "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_Id = TD.Tran_Id And TM.Cmp_Code= TD.Cmp_Code AND TM.Tran_Type = TD.Tran_Type  
                    INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_ID= LM.Lgr_Id 
                    INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON TM.TRan_Master_Id = LM1.Lgr_Id 
                    Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID
                    Where TM.Cmp_Code ="+@CMP_CODE +" And TM.Tran_Type <> 'J' And 
                    TM.Tran_Master_Id ="+@ACCID+" And TM.TRan_Date Between '"+ @FROMDATE+ "' And '"+ @TODATE+ "' "
        set @SQL1=" Union All 
                    Select TM.Tran_DocNo as DocNo,Td.Chequeno,  LM1.Lgr_Name as PartyName,TD.Tran_Detail_ID as PartyId,
                    TM.Tran_Id as Vcode,TM.Tran_Date as Voucher_Date,
                    (CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT ,
                    (CASE WHEN TD.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT,  TD.Tran_Type as Type,
                    LM.Lgr_Name as AccountName,LM.Lgr_ID as ACC_ID,TD.Remark,TD.ClearingDate,
                    (CASE WHEN  TD.ClearingDate IS NULL THEN 'NOT CLEARED' when (TD.ClearingDate Between  '"+ @FROMDATE+ "' And '"+ @TODATE+ "') then 'CLEARED'  ELSE 'NODISPLAY'  END )AS  CLEARED
                    ,CM.CITY_NAME AS PARTYCIT
                    From "+@DATABASENAME+"Tran_Master TM 
                    INNER JOIN  "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_ID= TD.Tran_ID AND TM.Tran_Type= TD.Tran_Type AND TM.Cmp_Code= TD.Cmp_Code 
                    INNER JOIN  "+@DATABASENAME+"Ledger_Master LM ON TM.Tran_Master_Id= LM.Lgr_Id  
                    INNER JOIN  "+@DATABASENAME+"Ledger_Master LM1 ON TD.Tran_Detail_Id= LM1.Lgr_Id
                    Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID
                    Where TM.Cmp_Code="+@CMP_CODE +" And TM.Tran_Type<> 'J'  And TD.Tran_Detail_ID="+@ACCID+" And 
                    TM.Tran_Date Between '"+ @FROMDATE+ "' And '"+ @TODATE+ "'  "        
         set @SQL2="union all 
                    Select TM.Tran_DocNo AS DocNo,Td.Chequeno, Ledger_Master.Lgr_Name as PartyName,Ledger_Master.Lgr_ID AS PartyId,TD.TRan_ID,TM.Tran_Date,
                   (CASE WHEN TD.Tran_DrCr = 'D' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS DrAMOUNT, 
                   (CASE WHEN TD.Tran_drcr = 'C' THEN CASE WHEN TD.Tran_Amount < Jd.Tran_amount THEN TD.Tran_Amount ELSE Jd.Tran_Amount END ELSE 0 END ) AS CrAMOUNT,
                   TM.Tran_Type as TranType, LM1.Lgr_Name AS AccountName,LM1.Lgr_ID as ACC_ID,TD.Remark,TD.ClearingDate,
                   (CASE WHEN  TD.ClearingDate IS NULL THEN 'NOT CLEARED' when (TD.ClearingDate Between  '"+ @FROMDATE+ "' And '"+ @TODATE+ "') then 'CLEARED'  ELSE 'NODISPLAY'  END )AS  CLEARED
                   ,CM.CITY_NAME AS PARTYCITY
                   From  "+@DATABASENAME+"Tran_Master TM 
                   INNER JOIN  "+@DATABASENAME+"Tran_Detail TD ON TD.TRan_Id= TM.TRan_Id And TD.Tran_Type = TM.Tran_Type AND TD.Cmp_Code= TM.Cmp_Code 
                   INNER JOIN  "+@DATABASENAME+"Tran_Detail as Jd ON TD.Tran_Type = JD.Tran_Type AND TD.Tran_Id= Jd.Tran_Id and TD.Tran_Detail_Id<> Jd.Tran_Detail_Id And TD.Tran_DrCr <> Jd.Tran_DrCr  AND JD.Cmp_Code= TM.Cmp_Code 
                   INNER JOIN  "+@DATABASENAME+"Ledger_Master ON TD.Tran_Detail_Id= Ledger_Master.Lgr_Id 
                   INNER JOIN Ledger_Master LM1 ON Jd.Tran_Detail_Id = LM1.Lgr_Id 
                   Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=Ledger_Master.City_ID
                   Where TM.Cmp_Code="+@CMP_CODE +" And TM.Tran_Date Between '"+ @FROMDATE+ "' And  '"+ @TODATE+ "'  And TD.Tran_Detail_Id="+@ACCID+" And TM.Tran_Type  In ('J','DN','CN')  "
        set @SQL3="UNION ALL 
                   SELECT  OB.VCHNO AS DOCNO,OB.CHEQUENO,LM.LGR_NAME AS PARTY,OB.BANK_ID,OB.VCH_ID,OB.VCHDATE,(CASE WHEN DRCR='D' THEN ISNULL(OB.AMOUNT,0) ELSE 0 END)AS DrAMOUNT,(CASE WHEN DRCR='C' THEN ISNULL(OB.AMOUNT,0)ELSE 0 END) AS CrAMOUNT, 'OLDBR' AS TYPE,
                   PM.LGR_NAME AS ACCOUNTNAME,OB.LGR_ID AS ACC_ID,'' AS REMARK,OB.CLRDATE ,
                   (CASE WHEN  OB.CLRDATE IS NULL THEN 'NOT CLEARED' when (OB.CLRDATE Between  '"+ @FROMDATE+ "' And '"+ @TODATE+ "') then 'CLEARED'  ELSE 'NODISPLAY'  END )AS  CLEARED
                   ,cm.city_name as partycity
                   FROM  "+@DATABASENAME+"OLDBANKRECEIPT  OB 
                   INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=OB.BANK_ID 
                   INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PM ON PM.LGR_ID=OB.LGR_ID 
                   Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID
                   Where OB.Cmp_Code="+@CMP_CODE +" And OB.VchDate Between '"+ @FROMDATE+ "' And  '"+ @TODATE+ "' And OB.Bank_ID="+@ACCID
                 

      
       set @SQL5=" UNION ALL 
                  SELECT '' AS DOCNO,'' AS CHEQUENO,LM.LGR_NAME AS PARTY,LM.LGR_ID ,0 AS VCH_ID,'"+ @FROMDATE+ "' AS VCHDATE,
                  CASE WHEN (SUM(OPDrAMT)-SUM(OPCrAMT)>0) THEN ABS(SUM(OPDrAMT)-SUM(OPCrAMT)) ELSE 0 END AS DrAMOUNT,
                  CASE WHEN (SUM(OPDrAMT)-SUM(OPCrAMT)<0) THEN ABS(SUM(OPDrAMT)-SUM(OPCrAMT)) ELSE 0 END AS CrAMOUNT,
                  'OPBAL'  AS TYPE,'' AS ACCOUNTNAME,0 AS ACC_ID,'' AS REMARK,'"+ @FROMDATE+ "' AS CLRDATE,'CLEARED' AS CLEARED,CM.CITY_NAME AS PARTYCITY
                  FROM "+@DATABASENAME+"OPENINGSTOCK OS
                  INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=OS.LEDGERCODE 
                  Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID
                  GROUP BY LM.LGR_NAME,LM.LGR_ID,CM.CITY_NAME
                   ) as Detail "
      set @SQL6=" UNION ALL 
                 SELECT 0 as Vcode, '' as DocNo,CHEQUENO,'' PartyName, 0 PartyId, null voucher_date, PREVDETAIL.DrAMOUNT, PREVDETAIL.CrAMOUNT, '' type, '' AccountName,0 as ACC_ID,'' as Remark,ClearingDate,CLEARED,'' as PartyCity,
                 PREVDETAIL.DRAMOUNT AS PREVDRAMOUNT,PREVDETAIL.CRAMOUNT AS PREVCRAMOUNT,'P' AS FLAG from( 
                 SELECT CHEQUENO,ClearingDate, SUM(PreDetail.DrAMOUNT) AS DrAMOUNT, SUM(PreDetail.CrAMOUNT)AS CrAMOUNT, CLEARED
                 from(  
                 Select Td.Chequeno,TD.ClearingDate,  (CASE WHEN TM.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT , (CASE WHEN TM.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT, 
                 (CASE WHEN  TD.ClearingDate IS NULL THEN 'NOT CLEARED' ELSE 'CLEARED'  END )AS  CLEARED 
                 From "+@DATABASENAME+"Tran_Master TM  
                 Inner Join "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_Id = TD.Tran_Id And TM.Cmp_Code= TD.Cmp_Code AND TM.Tran_Type = TD.Tran_Type 
                 INNER JOIN "+@DATABASENAME+"Ledger_Master LM ON TD.Tran_Detail_ID= LM.Lgr_Id  
                 INNER JOIN "+@DATABASENAME+"Ledger_Master LM1 ON TM.TRan_Master_Id = LM1.Lgr_Id 
                 Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID Where TM.Cmp_Code ="+@CMP_CODE +" And TM.Tran_Type <> 'J' And  TM.Tran_Master_Id ="+@ACCID+" And TM.TRan_Date < '"+ @FROMDATE+ "' 
                 Union All  
                 Select Td.Chequeno,TD.ClearingDate, (CASE WHEN TD.Tran_DrCr = 'D' THEN  TD.Tran_Amount ELSE 0 END) as DrAMOUNT , (CASE WHEN TD.Tran_DrCr= 'C' THEN TD.Tran_Amount ELSE 0 END) as CrAMOUNT, (CASE WHEN  TD.ClearingDate IS NULL THEN 'NOT CLEARED' ELSE 'CLEARED'  END )AS  CLEARED
                 From "+@DATABASENAME+"Tran_Master TM 
                 INNER JOIN  "+@DATABASENAME+"Tran_Detail TD ON TM.Tran_ID= TD.Tran_ID AND TM.Tran_Type= TD.Tran_Type AND TM.Cmp_Code= TD.Cmp_Code  
                 INNER JOIN  "+@DATABASENAME+"Ledger_Master LM ON TM.Tran_Master_Id= LM.Lgr_Id  
                 INNER JOIN  "+@DATABASENAME+"Ledger_Master LM1 ON TD.Tran_Detail_Id= LM1.Lgr_Id
                 Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID 
                 Where TM.Cmp_Code="+@CMP_CODE +" And TM.Tran_Type<> 'J'  And TD.Tran_Detail_ID="+@ACCID+" And  TM.Tran_Date < '"+ @FROMDATE+ "' "
     set @SQL7=" UNION ALL 
                 SELECT OB.CHEQUENO,OB.CLRDATE AS ClearingDate, (CASE WHEN DRCR='D' THEN ISNULL(OB.AMOUNT,0) ELSE 0 END)AS DrAMOUNT,(CASE WHEN DRCR='C' THEN ISNULL(OB.AMOUNT,0)ELSE 0 END) AS CrAMOUNT, (CASE WHEN  OB.CLRDATE IS NULL THEN 'NOT CLEARED'  ELSE 'CLEARED'  END )AS  CLEARED 
                 FROM  "+@DATABASENAME+"OLDBANKRECEIPT  OB  
                 INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=OB.BANK_ID 
                 INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PM ON PM.LGR_ID=OB.LGR_ID  
                 Left JOIN  "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID 
                 Where OB.Cmp_Code="+@CMP_CODE +" And OB.VchDate <'"+ @FROMDATE+ "' And OB.Bank_ID="+@ACCID+" 
                 ) as PreDetail  WHERE  CLEARED='NOT CLEARED' GROUP BY CLEARED ,CHEQUENO,ClearingDate
                 ) as PrevDetail
                Order By voucher_date,Vcode,AccountName,Type "




END

PRINT @SQL
PRINT @SQL1
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @SQL7
EXEC(@SQL+@SQL1+@SQL3+@SQL5+@SQL6+@SQL7)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_RECONCILIATION_WITH_DEPOSIT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO



















/*
PROC_RECONCILIATION_WITH_DEPOSIT '1','ACC2016_2017.DBO. ' ,'30','01/APR/2016','30/APR/2016','2'
*/


CREATE PROCEDURE [dbo].[PROC_RECONCILIATION_WITH_DEPOSIT]
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@ACCID AS NVARCHAR(20),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@RPT_TYPE AS NVARCHAR(20)
)
AS

DECLARE @SQL AS VARCHAR(4000)
DECLARE @SQL1 AS VARCHAR(4000)
DECLARE @SQL2 AS VARCHAR(4000)
DECLARE @SQL3 AS VARCHAR(4000)
DECLARE @SQL4 AS VARCHAR(4000)
DECLARE @SQL5 AS VARCHAR(4000)
DECLARE @SQL6 AS VARCHAR(4000)
DECLARE @SQL7 AS VARCHAR(4000)
DECLARE @STRRPTTYPE AS VARCHAR(4000)
DECLARE @STROLDBANLSQL AS VARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL7=""
SET @STRRPTTYPE=""
SET @STROLDBANLSQL=""

BEGIN

IF @RPT_TYPE=1 
	BEGIN
		SET @STRRPTTYPE="  WHERE DRAMOUNT >0 "
		SET @STROLDBANLSQL=" AND DRCR='D'"
	END 
ELSE IF @RPT_TYPE=2
	BEGIN
		SET @STRRPTTYPE="  WHERE CRAMOUNT >0 "
		SET @STROLDBANLSQL=" AND DRCR='C'"
	END

END

BEGIN
	SET NOCOUNT ON;


        set @SQL=" SELECT DETAIL.VCODE, DETAIL.DOCNO,CHEQUENO,DETAIL.PARTYNAME, DETAIL.PARTYID, DETAIL.VOUCHER_DATE, DETAIL.DRAMOUNT, DETAIL.CRAMOUNT, 
DETAIL.TYPE, DETAIL.ACCOUNTNAME,DETAIL.ACC_ID,REMARK,CLEARINGDATE,PARTYCITY,CLEARED,0 AS PREVDRAMOUNT,0 AS PREVCRAMOUNT,'C' AS FLAG 
FROM(

					SELECT    TM.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS DOCNO,TD.CHEQUENO ,LM1.LGR_NAME AS PARTYNAME,TM.TRAN_MASTER_ID AS PARTYID,
					TM.TRAN_DATE AS VOUCHER_DATE,(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
					TM.TRAN_TYPE AS TYPE,LM.LGR_NAME AS ACCOUNTNAME,LM.LGR_ID AS ACC_ID,TD.NARRATION AS REMARK,CONVERT(NVARCHAR,TD.CLEARINGDATE,103)CLEARINGDATE,CM.CITY_NAME AS PARTYCITY,
					'NOT CLEARED' AS CLEARED	
					FROM "+@DATABASENAME+"TRAN_MASTER TM
					INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE 
					INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
					INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID
					LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
					WHERE TM.CMP_CODE = "+@CMP_CODE +" AND TM.TRAN_TYPE <> 'J' AND TM.TRAN_MASTER_ID ="+@ACCID+" 
					AND TM.TRAN_DATE BETWEEN '"+ @FROMDATE+ "'  AND '"+ @TODATE+ "' 
					AND ISNULL(TD.CLEARINGDATE,'')='' 
                "
                    

        set @SQL1=" UNION ALL 
        
					 SELECT AJ.ENTRYCODE AS VCODE,0 AS DOCNO,'' AS CHEQUENO,LM.LGR_NAME,LM.LGR_ID AS PARTYID,AJ.VDATE AS VOUCHER_DATE,AJ.DRAMOUNT AS DRAMOUNT,
					 AJ.CRAMOUNT AS CRAMOUNT,AJ.ENTRYTYPE AS TYPE, LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,'' AS REMARK,'' AS CLEARINGDATE,CM.CITY_NAME AS PARTYCITY,
					 'NOT CLEARED' AS CLEARED	
					 FROM "+@DATABASENAME+"AUTOJOURNAL AJ
					 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
					 INNER JOIN "+@DATABASENAME+"AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ.ENTRYMATCH=AJ1.ENTRYMATCH
					 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON AJ1.LGR_ID= LM1.LGR_ID 
					  LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
					 WHERE AJ.VDATE BETWEEN '"+ @FROMDATE+ "' AND '"+ @TODATE+ "' AND AJ.CMP_CODE="+@CMP_CODE +" AND LM.LGR_ID="+@ACCID+"
					                    
                    
                    "        
         set @SQL2=" UNION ALL 
         
					SELECT TD.TRAN_ID,TM.TRAN_DOCNO AS DOCNO,TD.CHEQUENO  ,
					LEDGER_MASTER.LGR_NAME AS PARTYNAME,LEDGER_MASTER.LGR_ID AS PARTYID,TM.TRAN_DATE,
					(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT,
					(CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT,
					TM.TRAN_TYPE AS TYPE, LM1.LGR_NAME AS ACCOUNTNAME,LM1.LGR_ID AS ACC_ID,TD.NARRATION AS REMARK,
					CONVERT(NVARCHAR,TD.CLEARINGDATE,103)CLEARINGDATE,CM.CITY_NAME AS PARTYCITY,'NOT CLEARED' AS CLEARED	
					FROM "+@DATABASENAME+"TRAN_MASTER TM
					INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
					INNER JOIN "+@DATABASENAME+"TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR 
					INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ON TD.TRAN_DETAIL_ID= LEDGER_MASTER.LGR_ID
					INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID 
					LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LEDGER_MASTER.CITY_ID
					WHERE TM.CMP_CODE="+@CMP_CODE +" AND TM.TRAN_DATE BETWEEN '"+ @FROMDATE+ "' AND  '"+ @TODATE+ "' 
					AND TD.TRAN_DETAIL_ID="+@ACCID+" AND TM.TRAN_TYPE  IN ('J','DN','CN') 
					AND ISNULL(TD.CLEARINGDATE,'')='' 
                   
                   "
        set @SQL3="UNION ALL 
                   SELECT  OB.VCH_ID AS VCODE,OB.VCHNO AS DOCNO,OB.CHEQUENO,LM.LGR_NAME AS PARTYNAME,OB.BANK_ID AS PARTYID,OB.VCHDATE,
                   (CASE WHEN DRCR='D' THEN ISNULL(OB.AMOUNT,0) ELSE 0 END)AS DrAMOUNT,
                   (CASE WHEN DRCR='C' THEN ISNULL(OB.AMOUNT,0)ELSE 0 END) AS CrAMOUNT, 'OLDBR' AS TYPE,
                   PM.LGR_NAME AS ACCOUNTNAME,OB.LGR_ID AS ACC_ID,'' AS REMARK,OB.CLRDATE, 
                   cm.city_name as partycity,
                   (CASE WHEN  OB.CLRDATE IS NULL THEN 'NOT CLEARED' when (OB.CLRDATE Between  '"+ @FROMDATE+ "' And '"+ @TODATE+ "') then 'CLEARED'  ELSE 'NODISPLAY'  END )AS  CLEARED
                   FROM  "+@DATABASENAME+"OLDBANKRECEIPT  OB 
                   INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=OB.BANK_ID 
                   INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER PM ON PM.LGR_ID=OB.LGR_ID 
                   Left JOIN "+@DATABASENAME+"City_Master CM ON CM.City_Id=LM.City_ID
                   Where OB.Cmp_Code="+@CMP_CODE +" And OB.VchDate Between '"+ @FROMDATE+ "' And  '"+ @TODATE+ "' And OB.Bank_ID="+@ACCID+"
                   AND ISNULL(OB.CLRDATE,'')=''
                   "+@STROLDBANLSQL+""
                  

      
       set @SQL5=" UNION ALL
       
					SELECT TD.TRAN_ID AS VCODE,TM.TRAN_DOCNO AS DOCNO,TD.CHEQUENO  ,
					LEDGER_MASTER.LGR_NAME AS PARTYNAME,LEDGER_MASTER.LGR_ID AS PARTYID,TM.TRAN_DATE,
					(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
					(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
					TM.TRAN_TYPE AS TYPE, LEDGER_MASTER.LGR_NAME AS ACCOUNTNAME,LEDGER_MASTER.LGR_ID AS ACC_ID,TD.NARRATION AS REMARK,
					CONVERT(NVARCHAR,TD.CLEARINGDATE,103)CLEARINGDATE,CM.CITY_NAME AS PARTYCITY,'NOT CLEARED' AS CLEARED	
					FROM "+@DATABASENAME+"TRAN_MASTER TM
					INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE 
					INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ON TD.TRAN_DETAIL_ID= LEDGER_MASTER.LGR_ID
					LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LEDGER_MASTER.CITY_ID
					WHERE TM.CMP_CODE="+@CMP_CODE +" AND TM.TRAN_DATE BETWEEN '"+ @FROMDATE+ "' AND  '"+ @TODATE+ "' AND TD.TRAN_DETAIL_ID="+@ACCID+" AND TM.TRAN_TYPE  <> 'J'
					AND ISNULL(TD.CLEARINGDATE,'')='' 
                   ) as Detail
                   "+@STRRPTTYPE+"
                    ORDER BY VOUCHER_DATE,VCODE,ACCOUNTNAME,TYPE
                   "
     




END

PRINT @SQL
PRINT @SQL1
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
PRINT @SQL6
PRINT @SQL7
EXEC(@SQL+@SQL1+@SQL3+@SQL5+@SQL6+@SQL7)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_REV_CHALLAN_PRINT_OUT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO

















/*
-- =============================================
-- Author:		<SANKET>
-- Create_date: <30/JULY/2012>
-- Description:	<SALES ORDER PRINT OUT CONF NO FROM TO NO>
-- ========================	=====================
PROC_REV_CHALLAN_PRINT_OUT 1,'acc2017_2018.dbo.','1',10
*/
CREATE PROCEDURE [dbo].[PROC_REV_CHALLAN_PRINT_OUT]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMDOCNO NVARCHAR(50),
@TODOCNO NVARCHAR(50)

)
AS
DECLARE @STRSQL AS NVARCHAR(4000) SET @STRSQL=""

BEGIN	
	SET NOCOUNT ON;
    SET @STRSQL ="
SELECT PIN.DocNo ,PIN.PurchaseinvId,Cast(PIN.BillNo as Nvarchar) BILLNO,CONVERT(NVARCHAR,PIN.VCHDATE,103) AS DATE,
LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTY_CITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENT_CITY,TM.TRANSPORT_NAME,
IM.ITEM_NAME,PID.ChallanNo,PID.Item_cut,PID.Quantity,PID.RATE,PID.AMOUNT AS TAXABLE,PID.LESSAMOUNT,PID.GrossAmount AS AMOUNT,
PID.ADDAMOUNT,PID.VAT_PER,PID.vat_amt,VAT_PER1,PID.VATAMOUNT1,PID.VAT_PER2,PID.VATAMOUNT2,PID.amount as  FINALAMOUNT,PID.VAT_AMT AS CGST,PID.VATAMOUNT1 AS SGST,PID.VATAMOUNT2 AS IGST,
PIN.AfterLessTotal,PIN.AddTotal,PIN.LessTotal,PIN.GrossTotal,PIN.NetTotal,'' AS TOTALBALES,PIN.Pur_Inv_RoundOff,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2 
,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(SM.STATE_NAME) AS  PATYSTATE,LM.LGR_DISTRICT,LM.CITY_PINCODE,SM.STATE_CODE AS LGR_STATECODE,UPPER(UM.UNIT_NAME) AS UNIT,
ISNULL(CMP.GSTINNO,'') AS CMP_GSTINNO,ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,CMP.CMP_STATECODE,HM.HSN_NAME AS HSN
FROM "+@DATABASENAME+" PurchaseInvoice PIN
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID ON PID.PurchaseInvId=PIN.PurchaseInvId AND PIN.CMP_CODE=PID.CMP_CODE AND PIN.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=PIN.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=PIN.AGENT_ID 
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PIN.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" HSN_MASTER HM ON IM.HSN_ID=HM.HSN_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON PIN.CMP_CODE= CMP.CMP_CODE
LEFT JOIN "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
LEFT JOIN  "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID

WHERE PIN.CMP_CODE IN ("+@CMP_CODE+")  AND PIN.FLAG='RP'
AND PIN.DocNo BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
"
END
PRINT @STRSQL 
EXECUTE SP_EXECUTESQL @STRSQL


















GO

/****** Object:  StoredProcedure [dbo].[PROC_RMFG_STOCK_REPORT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 11/SEP/2012
-- Description:	THIS PROCEDURE USED FOR RAM AND FINISH MATERIAL STOCK REPORT DETAIL
-- Report_Name: RMFG_STOCK_REPORT.RPT
-- =============================================

/*
	PROC_RMFG_STOCK_REPORT 1,'ACC2012_2013.DBO.','30/SEP/2012',1,1,'##420'
*/
CREATE PROCEDURE [dbo].[PROC_RMFG_STOCK_REPORT]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @TODATE AS NVARCHAR(20),
  @RPT_WISE AS INT,
  @RPT_TYPE AS INT,
  @TEMPTABLE	AS NVARCHAR(50)	
  
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @ORDERBY AS NVARCHAR(1000)
DECLARE @CRITERIASQL AS NVARCHAR(3000)

SET @SQL = ""
SET @SQL1 = ""
SET @SQL2 = ""
SET @SQL3 = ""
SET @SQL4 = ""
SET @SQL5 = ""
SET @SQLJOIN = ""
SET @ORDERBY = ""
SET @CRITERIASQL = ""

BEGIN
	IF @RPT_WISE IN (0) /* ITEM WISE */
	BEGIN
		SET @CRITERIASQL = " ,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,  "
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = IM.ITEM_ID "
		SET @ORDERBY = " ORDER BY ITEM,DATE "
	END
	ELSE IF @RPT_WISE IN (1,2)  /* ITEM GROUP WISE ,ITEMGROUP - ITEM WISE */
	BEGIN
		IF @RPT_WISE IN (1)
		BEGIN
			SET @CRITERIASQL = " ,'' AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,  "
		END
		ELSE IF @RPT_WISE IN (2)
		BEGIN
			SET @CRITERIASQL = " ,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,  "
		END
		
		SET @SQLJOIN = " INNER JOIN " +@TEMPTABLE+ " TT ON TT.CODE = IGM.ITEM_GRP_ID "
		SET @ORDERBY = " ORDER BY ITEMGROUP,ITEM,DATE "
		
	END
	ELSE IF @RPT_WISE IN (3) /* ALL */
	BEGIN
		SET @CRITERIASQL = " ,'' AS ITEM,'' AS ITEMGROUP, "
		SET @SQLJOIN = ""
		SET @ORDERBY = " ORDER BY DATE "
	END
END
BEGIN
	SET NOCOUNT ON;
	
	IF @RPT_TYPE IN (1)  /* DAILY */
	BEGIN
		SET @SQL = " SELECT   MONTHNAME,DATE,ITEM,ITEMGROUP, SUM(IT_OP_MTRS) AS IT_OP_MTRS,SUM(GREY_PUR_MTRS)AS GREY_PUR_MTRS ,
				SUM(FINISH_PUR_MTRS) AS FINISH_PUR_MTRS,SUM(SALES_RETURN_MTRS) AS SALES_RETURN_MTRS,
				SUM(GREY_SALES_RETURN_MTRS) AS GREY_SALES_RETURN_MTRS,
				SUM(SALES_MTRS) AS SALES_MTRS,SUM(SALES_KG) AS SALES_KG,SUM(FENT_SALES_MTRS) AS FENT_SALES_MTRS,
				SUM(GREY_SALES_MTRS) AS GREY_SALES_MTRS,SUM(PUR_RETURN_MTRS) AS PUR_RETURN_MTRS,   
				SUM(GREY_PUR_RETURN_MTRS) AS GREY_PUR_RETURN_MTRS FROM (

				SELECT 'SEPTEMBER' AS MONTHNAME,'01/APR/2012' AS DATE "+@CRITERIASQL+"
				IOS.ITEM_OP_STOCK AS IT_OP_MTRS,0 AS GREY_PUR_MTRS,
				0 AS FINISH_PUR_MTRS,0 AS SALES_RETURN_MTRS,0 AS GREY_SALES_RETURN_MTRS,
				0 AS SALES_MTRS,0 AS SALES_KG,0 AS FENT_SALES_MTRS,
				0 AS GREY_SALES_MTRS,0 AS PUR_RETURN_MTRS,0 AS GREY_PUR_RETURN_MTRS
				
				FROM "+@DATABASENAME+" ITEM_OPENING_STOCK IOS
				INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IOS.ITEM_ID = IM.ITEM_ID
