CREATE PROCEDURE [dbo].[PROC_RMISSERPT]
	(
      @CMP_CODE  NVARCHAR(400), 
      @DATABASENAME NVARCHAR(400),
      @FROMDATE NVARCHAR(20),
      @TODATE NVARCHAR(20),
      @TEMPTABLE NVARCHAR(100)

)
AS
/*
PROC_RMISSERPT 2,'ACC2010_2011.DBO.','01/APR/2010','01/APR/2011','##5249'
*/

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN

	SET @SQL=" SELECT  RM.DOCNO,RM.VCHDATE,RM.LOT_NO,LM.LGR_NAME AS PURCHASEPARTY,ILM.LGR_NAME AS ISSUEPARTY
               ,IM.ITEM_NAME AS QUALITY,RD.BAGS,RD.QTY AS QUANTITY,UM.UNIT_NAME AS UNIT
                FROM "+@DATABASENAME+"RMISSUE_MASTER  RM
				INNER JOIN "+@DATABASENAME+"RMISSUE_DETAIL RD ON RM.RMISSUE_ID=RD.RMISSUE_ID
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=RM.LGR_ID
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ILM ON ILM.LGR_ID=RM.TO_LGR_ID
				INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=RD.ITEM_ID
				INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=RD.UNIT_ID
                INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=RM.DOCNO
                WHERE RM.CMP_CODE IN (" + @CMP_CODE +") AND RM.VCHDATE BETWEEN '"+@FROMDATE +"' AND  '"+@TODATE +"'
                ORDER BY RD.SRNO
"
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















