/*
-- =============================================
-- Author:		DIAPK GAMI
-- Create_date: 08/04/2014
-- Description:	SalesInvoicePrintOut
-- =============================================
THIS PROC USED IN (salinvoice_Rubia_Fold_PlainPrint),SALINVOICE_GRAY_NORMAL_NAVKAR_PREPRINT.RPT
PROC_SALES_INV_RUBIA_FOLD_GST_PRINTOUT 1,'ACC2016_2017.dbo.','1','8',2
*/
CREATE PROCEDURE [dbo].[PROC_SALES_INV_RUBIA_FOLD_GST_PRINTOUT]
(
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromBillNo NVARCHAR(50),
@ToBillNo NVARCHAR(50),
@RPT_TYPE NVARCHAR(50)
)	
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @SQL1 AS NVARCHAR(4000) SET @SQL1=""
DECLARE @JOIN AS NVARCHAR(4000) SET @JOIN=""
DECLARE @SQLBALENO AS NVARCHAR(1000) SET @SQLBALENO = ""
DECLARE @SQLCOND AS NVARCHAR(1000)
SET @SQLCOND = " "
BEGIN	

IF @RPT_TYPE =1
BEGIN
	SET @JOIN =" AND SI.FLAG='S' AND SI.Sal_Inv_Type IN ('FO') "
	SET @SQLBALENO = " SID.SAL_INV_BALENO AS BALENO "
	SET @SQLCOND = " AND  convert(int,SI.SAL_INV_BILL_NO) BETWEEN '"+@FromBillNo+"' AND '"+@ToBillNo+"' "
END
ELSE IF @RPT_TYPE = 2
BEGIN
	SET @JOIN =" AND SI.FLAG='GSN' AND SI.Sal_Inv_Type IN ('N') "
	SET @SQLBALENO = "SID.Sal_Inv_ChallanNo AS BALENO "
	SET @SQLCOND = " AND  convert(int,SI.SAL_INV_BILL_NO) BETWEEN '"+@FromBillNo+"' AND '"+@ToBillNo+"' "
END
IF @RPT_TYPE =3
BEGIN
	SET @JOIN =" AND SI.FLAG='S' AND SI.Sal_Inv_Type IN ('FO') "
	SET @SQLBALENO = " SID.SAL_INV_BALENO AS BALENO "
	SET @SQLCOND = " AND  convert(int,SI.SAL_INV_BILL_NO) IN ('"+@FromBillNo+"')"
END

END

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,SI.CONFNO,SI.CONFDATE,LM.CITY_PINCODE,
UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2 
,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(SM.STATE_NAME) AS  PATYSTATE,LM.Lgr_District,LM.LGR_CSTNO
,UPPER(AGM.LGR_NAME) AS AGENTNAME,UPPER(ACM.CITY_NAME) AS AGENTCITY
,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE
,"+@SQLBALENO+",IM.ITEM_NAME AS ITEM,SCM.SCREEN_NAME,ISNULL(PKM.PACKINGSTYLE_NAME,'') AS  PACKINGSTYLE_NAME
,SID.FOLD AS FOLD,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SID.SAL_INV_NETQTY AS NETQTY,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
,SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL
,CTM.Conversion,CTM.CUT_NAME,UPPER(UM.Unit_Name) as UNIT,SI.AMT_WORD
,SI.ORDERNO,SI.ORDERDATE
,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,
UPPER(CMP.CMP_NAME)AS CMP_NAME,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATE,'') AS CMP_STATE
,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,CMP.CMP_EMAIL,SI.WEIGHT,SI.FREIGHT,SID.COLOR_CHART,
CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,SID.DESCREPTION,SI.SAL_CRDAYS,(SAL_INV_VDATE + SAL_CRDAYS) as DUEDATE,
LM.LGR_INTERESTRATE,CMP.CMP_INTERESTRATE,SI.SAL_INV_ADD1_SET AS ADDPER1,SI.SAL_INV_ADD2_SET AS ADDPER2,
SI.SAL_INV_ADD3_SET AS ADDPER3,SI.SAL_INV_ADD4_SET AS ADDPER4,SI.SAL_INV_ADD5_SET AS ADDPER5,SI.Sal_Inv_Less1_Set AS LESSPER1,SI.Sal_Inv_Less2_Set AS LESSPER2,SI.Sal_Inv_Less3_Set AS LESSPER3
,SI.Sal_Inv_Less4_Set AS LESSPER4,SI.Sal_Inv_Less5_Set AS LESSPER5,
SID.SAL_INV_DTL_ID AS SRNO,SAL_REMARK,IM.ITEM_CUT,DOCUMENTS,ISNULL(SI.NET_SNET,'') AS NET_SNET,IM.RATE_PER,ISNULL(CURM.COURIERMASTER_NAME,'') AS COURIERNAME,CMP.GSTINNO AS CGSTINNO ,SM.STATE_CODE AS CMP_STATECODE,LM.GSTINNO AS LGSTINNO,HMM.Hsn_Name,cmp.cmp_Jurisdiction,(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)as ADDBEFOREVALUE,(SI.Sal_Inv_GrossTotal-SI.Sal_Inv_LessTotal+(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)) AS TAXABLEAMT"
SET @SQL1="
,CMP.cmp_stateCode As CmpStateCOde,ISNULL(CMM.Name,'C') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,CMM.Pincode AS CONSIGNEEPINCODE,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY
FROM "+@DatabaseName+" SALES_INVOICE SI
INNER JOIN "+@DatabaseName+" SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID and SI.FLag=SID.FLAG
INNER JOIN "+@DatabaseName+" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DatabaseName+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
LEFT JOIN "+@DatabaseName+" LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN "+@DATABASENAME+" hsn_MASTER HMM ON HMM.Hsn_Id=IM.HSN_ID
LEFT JOIN  "+@DatabaseName+" UNIT_MASTER UM on IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN "+@DatabaseName+" SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
LEFT JOIN "+@DatabaseName+" CUT_MASTER CTM on CTM.CUT_ID=SID.CUT_ID
INNER JOIN "+@DatabaseName+" COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
LEFT JOIN "+@DatabaseName+" CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
LEFT JOIN "+@DatabaseName+" CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
LEFT JOIN "+@DatabaseName+" STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
left join "+@DatabaseName+" PACKINGSTYLE_MASTER PKM on PKM.PACKINGSTYLE_ID=SID.PACKINGSTYLE_ID
LEFT JOIN "+@DatabaseName+" CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=SI.Consignee_Id	
LEFT JOIN "+@DatabaseName+" STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
LEFT JOIN "+@DatabaseName+" CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id
LEFT JOIN "+@DatabaseName+" COURIER_MASTER CURM ON CURM.COURIERMASTER_ID = SI.COURIERMASTER_ID
WHERE SI.CMP_CODE="+@Cmp_Code+" "+@SQLCOND+"
"+@JOIN+"
ORDER BY   CONVERT(INT,SI.SAL_INV_BILL_NO),SID.SAL_INV_DTL_ID, SID.SAL_INV_BALENO
"
    
END
PRINT @SQL
PRINT @SQL1
EXEC ( @SQL + @SQL1)






























GO

