FROM "+@DATABASENAME+" SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SI.FLAG=SID.FLAG AND SI.CMP_CODE=SID.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
