,upper(SM.State_NAME) as  PatyState,LM.City_Pincode,LM.Lgr_District,upper(AGM.Lgr_NAME) AS AGENTNAME,ACM.CITY_NAME as AGENTCITY,SID.SAL_INV_BALENO AS BALENO,SID.PBALENO,SID.Item_Cut as FOLD,SID.SAL_INV_BALES,
