,CM.CITY_NAME AS STATION,TM.TRANSPORT_NAME,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
