SI.Sal_Inv_LessTotal,SI.Sal_Inv_GROSSTotal,UM.UNIT_NAME,upper(SI.Documents) as Documents,upper(PCM.City_District)as City_District,upper(SI.Our_Branch) as OurBranch,upper(SI.LGr_Branch) as LgrBranch,Si.Sal_Inv_Days,
upper(CMp.Cmp_Name)as Cmp_Name,Cmp.cmp_tin_No,cmp.cmp_pan_no,cmp.cmp_jurisdiction,ISNULL(cmp.cmp_add1,'') AS cmp_add1,ISNULL(cmp.cmp_add2,'')AS cmp_add2,ISNULL(cmp.cmp_city,'') AS cmp_city ,ISNULL(cmp.cmp_state,'') AS cmp_state
,cmp.cmp_phone1,cmp.cmp_Phone2,cmp.cmp_Mobile,cmp.cmp_bank_accno1,cmp.cmp_bank_accno2,cmp.cmp_bank_accno3,cmp.cmp_Email,upper(ACM.City_Name) As AgentCity,SID.SerialNo,CU.COURIERMASTER_NAME,SI.Net_Snet,SI.WEIGHT,SI.FREIGHT,SI.LGR_BANK,
