	SET NOCOUNT ON;
    SET @STRSQL ="
SELECT SO.CONFNO,SO.SALES_ORDERNO,SO.THROUGH,SO.VCH_DATE,SO.ORDER_DATE,SO.START_DATE,SO.END_DATE,
LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTY_CITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENT_CITY,TM.TRANSPORT_NAME,
HM.HASTE_NAME,IM.ITEM_NAME,SM.SCREEN_NAME,SOD.BALES,SOD.RATE,SOD.RATEDIFF,SOD.REMARK
FROM "+@DATABASENAME+" SALES_ORDER SO
INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SO.CMP_CODE=SOD.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID 
LEFT JOIN "+@DATABASENAME+" CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SO.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+" HASTE_MASTER HM ON SO.HASTE_ID=HM.HASTE_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SOD.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
WHERE SO.CMP_CODE IN ("+@CMP_CODE+") AND SO.ORDER_TYPE='B' AND SO.FLAG='S'
AND SO.CONFNO BETWEEN "+@FROMDOCNO+" AND "+@TODOCNO+"
"
END
PRINT @STRSQL 
EXECUTE SP_EXECUTESQL @STRSQL




















GO

