-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'

PROC_SALES_RET_REGISTERGST N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'27/Dec/2018', 1, N'', N''

*/ 
CREATE PROCEDURE [dbo].[PROC_SALES_RET_REGISTERGST]
(
@CMP_CODE NVARCHAR(20),
@DATABASENAME NVARCHAR(50),
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),  
@RPT_WISE INT,   
@TEMPTABLE NVARCHAR(20),
@SAL_ACC_ID  NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @ACCSQL AS NVARCHAR(4000)
DECLARE @ORDERSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL=""
SET @ACCSQL=""
SET @ORDERSQL=""

BEGIN
SET NOCOUNT ON;

BEGIN
IF @SAL_ACC_ID!=""
SET @ACCSQL=" AND SR.SAL_ACC_ID="+@SAL_ACC_ID
END

BEGIN 
IF @RPT_WISE=1 
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT  ON SR.LGR_ID=TT.CODE"   
SET @ORDERSQL="LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END

ELSE IF @RPT_WISE=2
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SR.AGENT_ID=TT.CODE"
SET @ORDERSQL="ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),"
END

ELSE IF @RPT_WISE=3
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SRD.ITEM_ID=TT.CODE"
SET @ORDERSQL="IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END

ELSE IF @RPT_WISE=4 
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + "  TT ON CM.CITY_ID=TT.CODE"
SET @ORDERSQL="ISNULL(CM.CITY_NAME,'') ,ISNULL(CM.CITY_ID,0),"
END

ELSE IF @RPT_WISE=5
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SM.STATE_ID=TT.CODE"
SET @ORDERSQL="SM.STATE_NAME,ISNULL(SM.STATE_ID,0),"
END

ELSE IF @RPT_WISE= 6
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SR.STATION_ID=TT.CODE"   
SET @ORDERSQL="DCM.CITY_NAME,ISNULL(DCM.CITY_ID,0),"
END

ELSE IF @RPT_WISE=7 
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SRD.SCREEN_ID=TT.CODE"   
SET @ORDERSQL="SC.SCREEN_NAME,ISNULL(SC.SCREEN_ID,0),"
END

ELSE IF @RPT_WISE IN (8)
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SAM.SALESMAN_ID=TT.CODE" 
SET @ORDERSQL="SAM.SALESMAN_NAME,ISNULL(SAM.SALESMAN_ID,0),"
END

ELSE IF @RPT_WISE IN (9)
BEGIN
SET @JOINSQL=" INNER JOIN " + @TEMPTABLE + " TT ON SAM.SALESMAN_ID=TT.CODE"   
SET @ORDERSQL="SAM.SALESMAN_NAME,ISNULL(SAM.SALESMAN_ID,0),ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0),"
END

ELSE IF @RPT_WISE =10
BEGIN
SET @JOINSQL=" "
SET @ORDERSQL=""
END
END

SET @SQL="
SELECT ISNULL(SR.REFNO,'')AS REFNO,SR.SAL_RET_ID,SR.DOCNO,SR.SAL_RET_DATE AS SRDATE ,ISNULL(LM.GSTINNO,'')AS GSTINNO,LM.LGR_NAME AS PARTYNAME,ALM.LGR_NAME AS AGENTNAME,
ISNULL(CM.CITY_NAME,'') AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,DCM.CITY_NAME AS DESTCITY,
SM.STATE_NAME AS STATENAME,SM.STATE_CODE,IM.ITEM_NAME AS ITEMNAME,SC.SCREEN_NAME AS SCREENNAME,SRD.SAL_RET_PCS AS PCS,
SRD.SAL_RET_QTY AS QTY,SRD.SAL_RET_RATE AS RATE,SRD.SAL_RET_AMOUNT AS AMOUNT,SR.GROSSTOTAL AS GROSSTOTAL,
SR.SAL_RET_LESSTOTAL AS LESSTOTAL,SR.SAL_RET_ADDTOTAL AS ADDTOTAL,SR.ROUNDEDAMOUNT AS NETTOTAL,
SAM.SALESMAN_NAME AS SALESMAN,SRD.ITEM_CUT,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,ISNULL(DCM.CITY_ID,0) AS DESTINATIONID,
ISNULL(SM.STATE_ID,0) AS STATEID,ISNULL(SC.SCREEN_ID,0) AS SCREENID,ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,HM.HSN_NAME,
(SR.GrossTotal + SR.SAL_Ret_ADD1 + SR.SAL_Ret_ADD2 -( ISNULL(SR.SAL_Ret_LESS1,0) + ISNULL(SR.SAL_Ret_LESS2,0) + ISNULL(SR.SAL_Ret_LESS3,0) + ISNULL(SR.SAL_Ret_LESS4,0)+ ISNULL(SR.SAL_Ret_LESS5,0))) AS TAXABLEAMT,
isnull(SR.SAL_Ret_ADD3,0) AS CGST, ISNULL(SR.SAL_Ret_ADD4,0) as SGST ,ISNULL(SR.SAL_Ret_ADD5,0) AS IGST ,SR.NetTotal AS NETTOTALFINAL,SR.ALIAS
FROM " + @DATABASENAME +"SALES_RETURN_MASTER SR
INNER JOIN  " + @DATABASENAME +"SALES_RETURN_DETAIL SRD ON SRD.SAL_RET_ID=SR.SAL_RET_ID
INNER JOIN  " + @DATABASENAME +"LEDGER_MASTER LM ON SR.LGR_ID=LM.LGR_ID		
INNER JOIN  " + @DATABASENAME +"LEDGER_MASTER ALM ON SR.AGENT_ID=ALM.LGR_ID		
INNER JOIN  " + @DATABASENAME +"ITEM_MASTER IM ON SRD.ITEM_ID=IM.ITEM_ID
INNER JOIN  " + @DATABASENAME +"HSN_MASTER HM ON HM.HSN_ID=IM.HSN_ID
LEFT JOIN   " + @DATABASENAME +"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN   " + @DATABASENAME +"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN   " + @DATABASENAME +"CITY_MASTER DCM ON SR.STATION_ID=DCM.CITY_ID
LEFT JOIN   " + @DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN   " + @DATABASENAME +"SCREEN_MASTER SC ON SC.SCREEN_ID=SRD.SCREEN_ID
LEFT JOIN   " + @DATABASENAME +"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
--"+@JOINSQL+"
WHERE SR.CMP_CODE="+ @CMP_CODE +" AND SR.SAL_RET_DATE >= '" + @FROMDATE + "' AND SR.SAL_RET_DATE <='" + @TODATE + "'
"+@ACCSQL +"
ORDER BY "+@ORDERSQL+"SR.DOCNO,SR.SAL_RET_DATE       
"
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















