/*
PROC_SALES_STOCK_REGISTER '2','Acc2010_2011.dbo.','01/apr/2010','31/mar/2012',##3332,1,1
*/
CREATE PROCEDURE [dbo].[PROC_SALES_STOCK_REGISTER]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int,
@RptType int
)
AS

DECLARE @STRSQL as NVARCHAR(4000) set @STRSQL=""
DECLARE @JOIN as NVARCHAR(4000) set @JOIN=""
DECLARE @COND as NVARCHAR(4000) set @COND=""

BEGIN 
	IF 	@RptWise=1 
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID "
	else IF @RptWise=2
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id"
	else IF @RptWise=3 
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id"
else IF @RptWise=4
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IT.Item_Type_Id "
else IF @RptWise=5
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IT.Item_Type_Id"
else IF @RptWise=6
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=SM.Screen_Id "
else IF @RptWise=7
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.Item_Id"
else IF @RptWise=8
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
else IF @RptWise=9
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
else IF @RptWise=10
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
else IF @RptWise=11
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.LOTNO "
else IF @RptWise=12
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.FOLD"
else IF @RptWise=13
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.DESIGN_COL_CHART"
else IF @RptWise=14
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STM.STOCKIN_ID"
END

BEGIN
if @RptType=1
	SET @COND=" AND STM.STOCKIN_TYPE='C'"
else if @RptType=2
	SET @COND=" AND STM.STOCKIN_TYPE='O'"
else if @RptType=3
	SET @COND=" AND STM.STOCKIN_TYPE='FP' "
else if @RptType=4
	SET @COND=" "
END

BEGIN
	
	SET NOCOUNT ON;
SET @STRSQL ="
select STM.DOCNO,STM.VCHDATE,STM.STOCKIN_TYPE,TM.TRANSPORT_NAME,STD.LRNO,SM.SCREEN_NAME,STD.BALENO,STD.PIECES,STD.QUANTITY AS MTR,
IM.Item_Name,IG.Item_Grp_Name,IT.Item_Type_Name,STD.fold as FOLDNO,STD.DESIGN_COL_CHART,SAL_INV_BILL_NO,SAL_INV_VDATE as BILLDATE,STD.LOTNO
from "+@DataBase+" STOCKIN_MASTER STM
INNER JOIN "+@DataBase+" STOCKIN_DETAIL STD ON STD.STOCKIN_ID=STM.STOCKIN_ID and STM.CMP_CODE=STD.CMP_CODE
LEFT JOIN "+@DataBase+" TRANSPORT_MASTER TM ON STM.TRANSPORT_ID=TM.TRANSPORT_ID
LEFT JOIN "+@DataBase+" SCREEN_MASTER SM ON SM.SCREEN_ID=STD.SCREEN_ID
LEFT JOIN "+@DataBase+" ITEM_Master IM on STD.Item_Id=IM.Item_Id
left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
left join "+@DataBase+" Item_Type_Master IT on IM.Item_Type_Id=IT.Item_Type_Id
left join "+@DataBase+" Sales_Invoice_Detail SIVD on SIVD.Sal_Inv_BaleNo=STD.BALENO and SIVD.ITEM_ID=STD.ITEM_ID and SIVD.SCREEN_ID=STD.SCREEN_ID and SIVD.CMP_CODE=STD.CMP_CODE
left join "+@DataBase+" Sales_Invoice SIV on SIVD.Sal_Inv_Id=SIV.Sal_Inv_Id and SIVD.CMP_CODE=SIV.CMP_CODE and SIV.FLAG=SIVD.FLag
"+@JOIN+"
where STM.Cmp_Code in ("+@CmpCode+")  and STM.VCHDATE between '"+@FromDate+"' and '"+@ToDate+"'
"+@COND+"
order by STM.VCHDATE,STM.DOCNO,STD.BALENO 
"
    
END
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL




















GO

