               SET @MAINSQL="SELECT PARTY,PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM, SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY CUSTOMERGROUP,PARTY,PARTYCITY,SCREEN,CMP_ALIAS" 
               SET @CONDSQL=" CGM.CUST_GRP_ID="+@ID+" AND "          
               SET @ORDERSQL=" ORDER BY PARTY,SCREEN"               
           END
ELSE IF @RPT_WISE =31
           BEGIN
             SET @MAINSQL="SELECT PARTY,PARTYCITY,STATION,''AS AGENT,''AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,'' AS ITEMGROUP,'' AS ITEMTYPE,'' AS ITEM, MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT) AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
              SET @GRPSQL=" GROUP BY PARTY,PARTYCITY,CMP_ALIAS, STATION" 
              SET @CONDSQL=" LM.LGR_ID="+@ID+" AND "
              SET @ORDERSQL=" ORDER BY STATION"
           END
ELSE IF @RPT_WISE =32
           BEGIN
              SET @MAINSQL="SELECT '' AS PARTY,'' AS PARTYCITY,STATION, AGENT,AGENTCITY,MIN(SALESMAN) AS SALESMAN,'' AS ITEMGROUP,'' AS ITEMTYPE,MAX(ITEM) AS ITEM,'' AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT) AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES" 
              SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,CMP_ALIAS,STATION" 
              SET @CONDSQL=" ALM.LGR_ID="+@ID+" AND "
              SET @ORDERSQL=" ORDER BY STATION "
           END
	
ELSE IF @RPT_WISE =33
           BEGIN
              SET @MAINSQL="SELECT PARTY ,PARTYCITY,STATION, AGENT,AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE)AS ITEMTYPE,MAX(ITEM) AS ITEM, MIN(SCREEN)AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT) AS UNIT ,CMP_ALIAS ,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
              SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,CMP_ALIAS,STATION,PARTY,PARTYCITY" 
              SET @CONDSQL=" ALM.LGR_ID="+@ID+" AND "
              SET @ORDERSQL=" ORDER BY PARTY,STATION"
           END
ELSE IF @RPT_WISE =34 
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP)AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS ,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,ITEM,UNIT,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,ITEM"               
           END
ELSE IF @RPT_WISE =35  
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT  ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,ITEMGROUP,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,ITEMGROUP"               
           END
ELSE IF @RPT_WISE =36 
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,ITEMTYPE,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,ITEMTYPE"               
           END
ELSE IF @RPT_WISE =37  
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,SCREEN,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,SCREEN"               
           END
ELSE IF @RPT_WISE =38  
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,PARTY,PARTYCITY,ITEM,UNIT,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,PARTY,ITEM"               
           END
ELSE IF @RPT_WISE =39 
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS ,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,PARTY,PARTYCITY,ITEMGROUP,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,PARTY,ITEMGROUP"               
           END
ELSE IF @RPT_WISE =40 
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,PARTY,PARTYCITY,ITEMTYPE,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,PARTY"               
           END
ELSE IF @RPT_WISE =41
           BEGIN 
               SET @MAINSQL="SELECT MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,MAX(STATION) AS STATION,MIN(AGENT)AS AGENT,MIN(AGENTCITY) AS AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMGROUP) AS ITEMGROUP,MIN(ITEMTYPE) AS ITEMTYPE,MIN(ITEM) AS ITEM,MIN(SCREEN) AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT)AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
               SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,PARTY,PARTYCITY,SCREEN,CMP_ALIAS" 
               SET @ORDERSQL=" ORDER BY AGENT,PARTY,SCREEN"               
           END
--ALL ITEMGROUP ALL station
ELSE IF @RPT_WISE =42
           BEGIN
--             SET @MAINSQL="SELECT ITEMGROUP,MIN(PARTY)AS PARTY,MIN(PARTYCITY)AS PARTYCITY,STATION, AGENT,AGENTCITY,MIN(SALESMAN) AS SALESMAN,MIN(ITEMTYPE)AS ITEMTYPE,MAX(ITEM) AS ITEM, MIN(SCREEN)AS SCREEN
--                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT) AS UNIT ,CMP_ALIAS ,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
--              SET @GRPSQL=" GROUP BY ITEMGROUP,AGENT,AGENTCITY,CMP_ALIAS,STATION,PARTY,PARTYCITY" 
--              SET @CONDSQL=" ALM.LGR_ID="+@ID+" AND "
--              SET @ORDERSQL=" ORDER BY ITEMGROUP,STATION"
				SET @MAINSQL="SELECT '' AS PARTY,'' AS PARTYCITY,STATION, AGENT,AGENTCITY,MIN(SALESMAN) AS SALESMAN,ITEMGROUP,'' AS ITEMTYPE,MIN(ITEM) AS ITEM,'' AS SCREEN
                             ,SUM(QUANTITY) AS QUANTITY,SUM(AMOUNT)AS AMOUNT,SUM(CONVERSION) AS CONVERSION,MAX(UNIT) AS UNIT ,CMP_ALIAS,MAX(CUSTOMERGROUP) AS CUSTOMERGROUP,COUNT(*) AS BALES"
              SET @GRPSQL=" GROUP BY AGENT,AGENTCITY,CMP_ALIAS,ITEMGROUP,STATION" 
             SET @CONDSQL=" ALM.LGR_ID="+@ID+" AND "
             SET @ORDERSQL=" ORDER BY ITEMGROUP,STATION "
           END			
			
	END
BEGIN
    SET @SQL=@MAINSQL+" 
     FROM(
			 SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,STM.CITY_NAME AS STATION,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,S_M.SALESMAN_NAME AS SALESMAN, IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IOS.SAL_RATE AS ITEMRATE, UM.UNIT_NAME AS UNIT,
			   (CASE WHEN UM.UNIT_NAME='PIECES' THEN SID.SAL_INV_PCS ELSE SID.SAL_INV_QTY END)AS QUANTITY,
			 (SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
			 (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
			 ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION,CMP.CMP_ALIAS                      
             ,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
			 FROM  "+@DATABASENAME+"SALES_INVOICE SI 
         "

 SET @SQL1="
			 INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
			 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
			 INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
			 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
			 LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
			 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID                      
			 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE                      
			 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
			 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
			 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"CITY_MASTER STM ON STM.CITY_ID=SI.STATION_ID
             LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=ALM.SALESMAN_ID
             LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
			 INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=SI.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
			 WHERE   "+@CONDSQL +" SI.SAL_INV_VDATE>='"+@FROMDATE+"' AND SI.SAL_INV_VDATE<='"+@TODATE+"'
			 AND SI.CMP_CODE IN("+@CMP_CODE+")  AND SI.SAL_ACCID="+@HEADID + "
	         ) AS DETAIL        
     "
     +@GRPSQL
     + @ORDERSQL
	 
END
PRINT @SQL
PRINT @SQL1

EXEC (@SQL+@SQL1)




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESANALYSIS_MONTHLY]    Script Date: 03/30/2023 12:08:14 ******/
