/*    
PROC_SALESANALYSIS_MONTHLY '1','ACC2012_2013.DBO.','ACC2012_2013','','','','','##2508','1',1,'01/APR/2012','31/MAR/2013'
*/
CREATE PROCEDURE [dbo].[PROC_SALESANALYSIS_MONTHLY]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@CURRDBNAME NVARCHAR(100),
@FIRSTLASTDB NVARCHAR(100),
@FIRSTLASTDBNAME NVARCHAR(100),
@SECONDLASTDB NVARCHAR(100),
@SECONDLASTDBNAME NVARCHAR(100),
@TEMPTABLE  NVARCHAR(20),
@RPT_WISE INT,
@HEADID NVARCHAR(20),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQLEND AS NVARCHAR(4000)
DECLARE @MAINSQL AS NVARCHAR(1000)
DECLARE @JOINSQL1 AS NVARCHAR(2000)
DECLARE @JOINSQL2 AS NVARCHAR(2000)
DECLARE @JOINSQL3 AS NVARCHAR(2000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQLEND=""
SET @MAINSQL=""
SET @SQL="  SELECT DBNAME,MONTHNAME,MON,MONTHORD,MAINGROUP,MAINGROUPID,ITEMGROUP,ITEMGRPID,SUM(QUANTITY) AS	
			QUANTITY,SUM(AMOUNT)AS AMOUNT,CMP_ALIAS,COUNT(BALENO) AS BALES,CITY,CITYID FROM ("
SET @SQLEND=") AS DETAIL GROUP BY DBNAME,MAINGROUP,MAINGROUPID,ITEMGROUP,ITEMGRPID,CMP_ALIAS,MONTHNAME,MON,
			MONTHORD,CITY,CITYID 
			ORDER BY DBNAME,MAINGROUP,MAINGROUPID,ITEMGROUP,ITEMGRPID,CMP_ALIAS,MONTHNAME,MON,
			MONTHORD,CITY,CITYID"

SET @JOINSQL1=""
SET @JOINSQL2=""
SET @JOINSQL3=""
BEGIN 
IF @RPT_WISE=1
BEGIN
SET @MAINSQL="ALM.LGR_NAME AS MAINGROUP,ALM.LGR_ID AS MAINGROUPID,ACM.CITY_NAME AS CITY,ACM.CITY_ID AS CITYID "
SET @JOINSQL1=" LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.AGENT_ID
"
SET @JOINSQL2=" LEFT JOIN "+@FIRSTLASTDB+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@FIRSTLASTDB+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.AGENT_ID
"
SET @JOINSQL3=" LEFT JOIN "+@SECONDLASTDB+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@SECONDLASTDB+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.AGENT_ID
"
END
ELSE IF @RPT_WISE=2
BEGIN
SET @MAINSQL="LM.LGR_NAME AS MAINGROUP,LM.LGR_ID AS MAINGROUPID,PCM.CITY_NAME AS CITY,PCM.CITY_ID AS CITYID "
SET @JOINSQL1=" INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.LGR_ID
"
SET @JOINSQL2=" INNER JOIN "+@FIRSTLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@FIRSTLASTDB+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.LGR_ID
"
SET @JOINSQL3=" INNER JOIN "+@SECONDLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@SECONDLASTDB+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.LGR_ID
"		
END
ELSE IF @RPT_WISE=3
BEGIN
SET @MAINSQL="SM.STATE_NAME AS MAINGROUP,SM.STATE_ID AS MAINGROUPID,'' AS CITY,0 AS CITYID "
SET @JOINSQL1=" 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
INNER JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.STATE_ID
"
SET @JOINSQL2=" 
INNER JOIN "+@FIRSTLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
INNER JOIN "+@FIRSTLASTDB+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.STATE_ID
"
SET @JOINSQL3=" 
INNER JOIN "+@SECONDLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
INNER JOIN "+@SECONDLASTDB+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.STATE_ID
"
END
ELSE IF @RPT_WISE=4
BEGIN
SET @MAINSQL="PCM.CITY_NAME AS MAINGROUP,PCM.CITY_ID AS MAINGROUPID,'' AS CITY,0 AS CITYID "
SET @JOINSQL1=" 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PCM.CITY_ID
"

SET @JOINSQL2=" 
INNER JOIN "+@FIRSTLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@FIRSTLASTDB+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PCM.CITY_ID
"

SET @JOINSQL3=" 
INNER JOIN "+@SECONDLASTDB+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN "+@SECONDLASTDB+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PCM.CITY_ID
"
END
ELSE IF @RPT_WISE=5
BEGIN
SET @MAINSQL="SM.CITY_NAME AS MAINGROUP,SM.CITY_ID AS MAINGROUPID,'' AS CITY,0 AS CITYID "
SET @JOINSQL1=" 						
INNER JOIN "+@DATABASENAME+"CITY_MASTER SM ON SM.CITY_ID=SI.STATION_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.STATION_ID
"

SET @JOINSQL2=" 						
INNER JOIN "+@FIRSTLASTDB+"CITY_MASTER SM ON SM.CITY_ID=SI.STATION_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.STATION_ID
"

SET @JOINSQL3=" 						
INNER JOIN "+@SECONDLASTDB+"CITY_MASTER SM ON SM.CITY_ID=SI.STATION_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SI.STATION_ID
"
END

ELSE IF @RPT_WISE=6
BEGIN
SET @MAINSQL="SLM.SALESMAN_NAME AS MAINGROUP,SLM.SALESMAN_ID AS MAINGROUPID,'' AS CITY,0 AS CITYID "
SET @JOINSQL1=" LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SLM ON SLM.SALESMAN_ID=ALM.SALESMAN_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SLM.SALESMAN_ID
"
SET @JOINSQL2=" LEFT JOIN "+@FIRSTLASTDB+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@FIRSTLASTDB+"SALESMAN_MASTER SLM ON SLM.SALESMAN_ID=ALM.SALESMAN_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SLM.SALESMAN_ID
"
SET @JOINSQL3=" LEFT JOIN "+@SECONDLASTDB+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@SECONDLASTDB+"SALESMAN_MASTER SLM ON SLM.SALESMAN_ID=ALM.SALESMAN_ID
INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SLM.SALESMAN_ID
"
END

END


BEGIN
IF @CURRDBNAME!="" 
BEGIN
SET @SQL1="    
SELECT '"+@CURRDBNAME+"' AS DBNAME,"+@MAINSQL+",UPPER(DATENAME(MONTH,SI.SAL_INV_VDATE)) AS MONTHNAME,MONTH(SI.SAL_INV_VDATE) AS MON,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT							   
,IGM.ITEM_GRP_NAME AS ITEMGROUP,CMP.CMP_ALIAS
,(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS MONTHORD
,SID.SAL_INV_BALENO AS BALENO,IGM.ITEM_GRP_ID as ITEMGRPID
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID                                                             
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL1+"
WHERE SI.SAL_ACCID="+@HEADID +" AND SI.CMP_CODE IN ("+@CMP_CODE+")
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
"
END 
IF @FIRSTLASTDBNAME!="" 
BEGIN
SET @SQL2="   UNION ALL 
SELECT '"+@FIRSTLASTDBNAME+"' AS DBNAME,"+@MAINSQL+",UPPER(DATENAME(MONTH,SI.SAL_INV_VDATE)) AS MONTHNAME,MONTH(SI.SAL_INV_VDATE) AS MON,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
IGM.ITEM_GRP_NAME AS ITEMGROUP,CMP.CMP_ALIAS
,(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS MONTHORD
,SID.SAL_INV_BALENO AS BALENO,IGM.ITEM_GRP_ID as ITEMGRPID
FROM "+@FIRSTLASTDB+"SALES_INVOICE SI
INNER JOIN  "+@FIRSTLASTDB+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
INNER JOIN "+@FIRSTLASTDB+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+@FIRSTLASTDB+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@FIRSTLASTDB+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN "+@FIRSTLASTDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL2+"
WHERE SI.SAL_ACCID="+@HEADID +" AND SI.CMP_CODE IN ("+@CMP_CODE+") 
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
"
END 

IF @SECONDLASTDBNAME!="" 
BEGIN
SET @SQL3="   UNION ALL 
SELECT '"+@SECONDLASTDBNAME+"' AS DBNAME,"+@MAINSQL+",UPPER(DATENAME(MONTH,SI.SAL_INV_VDATE)) AS MONTHNAME,MONTH(SI.SAL_INV_VDATE) AS MON,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION=NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS AMOUNT,
IGM.ITEM_GRP_NAME AS ITEMGROUP,CMP.CMP_ALIAS
,(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS MONTHORD
,SID.SAL_INV_BALENO AS BALENO,IGM.ITEM_GRP_ID as ITEMGRPID
FROM "+@SECONDLASTDB+"SALES_INVOICE SI
INNER JOIN  "+@SECONDLASTDB+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
INNER JOIN "+@SECONDLASTDB+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+@SECONDLASTDB+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
INNER JOIN "+@SECONDLASTDB+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN "+@SECONDLASTDB+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE
"+@JOINSQL3+"
WHERE SI.SAL_ACCID="+@HEADID +" AND SI.CMP_CODE IN ("+@CMP_CODE+") 
AND SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 
"
END 



END
EXEC (@SQL+@SQL1+@SQL2+@SQL3+@SQLEND)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQLEND




















GO

