CREATE PROCEDURE [dbo].[PROC_SALESCHART]
(
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50),
	@PartyId nvarchar(20),
	@Criteria int
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @CondSql AS NVARCHAR(1000)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""
SET @CondSql=""


if @Criteria=0      /*    PartyWise */
	SET @JoinSql=""
else if @Criteria=1      /*     AgentWise */
	SET @JoinSql=""
else if @Criteria=2      /*    Customer Group */
	SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id Or LM.Lgr_Id=SIM.Sal_AccID"
else if @Criteria=3      /*    City Group */
	SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
else if @Criteria=4      /*    State Group */
	SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
else if @Criteria=5      /*    Item Wise  */
	SET @JoinSql=""
else if @Criteria=6      /*    Item Group Wise  */
	SET @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=SID.Item_Id"							

if @Criteria=0      /*    PartyWise */
	SET @CondSql="And (SIM.Lgr_Id="+@PartyId+" Or Sal_AccID="+@PartyId+")"
else if @Criteria=1      /*    AgentWise */
	SET @CondSql="And SIM.Agent_Id="+@PartyId+""
else if @Criteria=2      /*    Customer Group */
	SET @CondSql="And LM.Cust_Grp_Id="+@PartyId+""
else if @Criteria=3      /*    City Group */
	SET @CondSql="And LM.City_Id="+@PartyId+""
else if @Criteria=4      /*    State Group */
	SET @CondSql="And LM.State_Id="+@PartyId+""	
else if @Criteria=5      /*    Item Wise */
	SET @CondSql="And SID.Item_Id="+@PartyId+""	
else if @Criteria=6      /*    Item Group */
	SET @CondSql="And IM.Item_Grp_Id="+@PartyId+""	
			

BEGIN
set nocount on;


if @Criteria=5 or @Criteria=6
SELECT @SQL="
				Select Mon,sum(Amount1) As Amount from(
				Select case When Month(SIM.Sal_Inv_Vdate)>3 Then Month(SIM.Sal_Inv_Vdate) Else Month(SIM.Sal_Inv_Vdate)+12 End  As Mon,
					SUM(SID.Sal_Inv_Amount)+((SUM(SID.Sal_Inv_Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
					INNER JOIN (SELECT SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal AS MainAmt, SUM(SID.Sal_Inv_Amount) AS SubAmt, 
									SIM.Sal_Inv_NetTotal-SUM(SID.Sal_Inv_Amount) AS EffectiveCost 
									FROM "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id 
									Where SIM.cmp_code = "+@Cmp_Code+" GROUP BY SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal) 
				ABC ON SIM.Sal_Inv_Bill_No=ABC.Sal_Inv_Bill_No 
					"+@JoinSql+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(SIM.Sal_Inv_Vdate),SubAmt,EffectiveCost) As XYZ Group by Mon
					Order by Mon"
 

else
	SELECT @SQL="
				Select case When Month(SIM.Sal_Inv_Vdate)>3 Then Month(SIM.Sal_Inv_Vdate) Else Month(SIM.Sal_Inv_Vdate)+12 End  As Mon,
					sum(SIM.Sal_Inv_NetTotal) As Amount
				From "+@DatabaseName+"Sales_Invoice SIM "+@JoinSql+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(SIM.Sal_Inv_Vdate)
					Order by Mon
			"
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

