CREATE PROCEDURE [dbo].[PROC_SALESCHARTMULTIYEAR]
(
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50),
	@PartyId nvarchar(20),
	@Criteria int,
	@strYearMinus1 nvarchar(50),
	@strYearMinus1Exist int,
	@strYearMinus2 nvarchar(50),
	@strYearMinus2Exist int,
	@strCurrYear nvarchar(20),
	@strYearMin1 nvarchar(20),
	@strYearMin2 nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)

DECLARE @CondSql AS NVARCHAR(1000)

DECLARE @JoinSql AS NVARCHAR(1000)
DECLARE @JoinSql1 AS NVARCHAR(1000)
DECLARE @JoinSql2 AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @JoinSql=""
SET @JoinSql1=""
SET @JoinSql2=""
SET @CondSql=""



if @Criteria=0      /*    PartyWise */
   begin
		SET @JoinSql=""
		if @strYearMinus1Exist=1 or @strYearMinus1Exist=0
			SET @JoinSql1=""
		if @strYearMinus2Exist=1 or @strYearMinus2Exist=0
			SET @JoinSql2=""
	end
else if @Criteria=1      /*    AgentWise */
	begin
		SET @JoinSql=""
		if @strYearMinus1Exist=1  or @strYearMinus1Exist=0
			SET @JoinSql1=""
		if @strYearMinus2Exist=1 or @strYearMinus2Exist=0
			SET @JoinSql2=""
	end
else if @Criteria=2      /*    Customer Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id Or LM.Lgr_Id=SIM.Sal_AccID"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id Or LM.Lgr_Id=SIM.Sal_AccID"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id Or LM.Lgr_Id=SIM.Sal_AccID"
	end
else if @Criteria=3      /*    City Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
	end
else if @Criteria=4      /*    State Group */
	begin
			SET @JoinSql="INNER JOIN "+@DatabaseName+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
		if @strYearMinus1Exist=1 
			SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
		if @strYearMinus2Exist=1 
			SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Ledger_Master LM ON LM.Lgr_Id=SIM.Lgr_Id"
	end
else if @Criteria=5      /*    Item Wise  */
	begin
		SET @JoinSql=""
	end
else if @Criteria=6      /*    Item Group Wise  */
	begin
		SET @JoinSql="INNER JOIN "+@DatabaseName+"Item_Master IM ON IM.Item_Id=SID.Item_Id"
	if @strYearMinus1Exist=1
		SET @JoinSql1="INNER JOIN "+@strYearMinus1+"Item_Master IM ON IM.Item_Id=SID.Item_Id"
	if @strYearMinus2Exist=1 						
		SET @JoinSql2="INNER JOIN "+@strYearMinus2+"Item_Master IM ON IM.Item_Id=SID.Item_Id"
	end
if @Criteria=0      /*    PartyWise */
	SET @CondSql="And (SIM.Lgr_Id="+@PartyId+" Or Sal_AccID="+@PartyId+")"
else if @Criteria=1      /*    AgentWise */
	SET @CondSql="And SIM.Agent_Id="+@PartyId+""
else if @Criteria=2      /*    Customer Group */

	SET @CondSql="And LM.Cust_Grp_Id="+@PartyId+""
else if @Criteria=3      /*    City Group */
	SET @CondSql="And LM.City_Id="+@PartyId+""
else if @Criteria=4      /*    State Group */
	SET @CondSql="And LM.State_Id="+@PartyId+""	
else if @Criteria=5      /*    Item Wise */
	SET @CondSql="And SID.Item_Id="+@PartyId+""	
else if @Criteria=6      /*    Item Group */
	SET @CondSql="And IM.Item_Grp_Id="+@PartyId+""	
			

BEGIN
set nocount on;


if @Criteria=5 or @Criteria=6
Begin
	SELECT @SQL="
				Select '"+@strCurrYear+"' As Mon,sum(Amount1) As Amount from(
				Select '"+@strCurrYear+"' As Mon,
					SUM(SID.Sal_Inv_Amount)+((SUM(SID.Sal_Inv_Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
					INNER JOIN (SELECT SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal AS MainAmt, SUM(SID.Sal_Inv_Amount) AS SubAmt, 
									SIM.Sal_Inv_NetTotal-SUM(SID.Sal_Inv_Amount) AS EffectiveCost 
									FROM "+@DatabaseName+"Sales_Invoice SIM INNER JOIN "+@DatabaseName+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id 
									Where SIM.cmp_code = "+@Cmp_Code+" GROUP BY SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal) 
				ABC ON SIM.Sal_Inv_Bill_No=ABC.Sal_Inv_Bill_No 
					"+@JoinSql+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(SIM.Sal_Inv_Vdate),SubAmt,EffectiveCost) As XYZ 
					"
 if @strYearMinus1Exist=1
		SELECT @SQL1=" Union All
				Select '"+@strYearMin1+"' As Mon,sum(Amount1) As Amount from(
				Select '"+@strYearMin1+"' As Mon,
					SUM(SID.Sal_Inv_Amount)+((SUM(SID.Sal_Inv_Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@strYearMinus1+"Sales_Invoice SIM INNER JOIN "+@strYearMinus1+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
					INNER JOIN (SELECT SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal AS MainAmt, SUM(SID.Sal_Inv_Amount) AS SubAmt, 
									SIM.Sal_Inv_NetTotal-SUM(SID.Sal_Inv_Amount) AS EffectiveCost 
									FROM "+@strYearMinus1+"Sales_Invoice SIM INNER JOIN "+@strYearMinus1+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id 
									Where SIM.cmp_code = "+@Cmp_Code+" GROUP BY SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal) 
				ABC ON SIM.Sal_Inv_Bill_No=ABC.Sal_Inv_Bill_No 
					"+@JoinSql1+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(SIM.Sal_Inv_Vdate),SubAmt,EffectiveCost) As XYZ 
					"
if @strYearMinus2Exist=1
	SELECT @SQL2=" Union All
				Select '"+@strYearMin2+"' As Mon,sum(Amount1) As Amount from(
				Select  '"+@strYearMin2+"' As Mon,
					SUM(SID.Sal_Inv_Amount)+((SUM(SID.Sal_Inv_Amount)/SubAmt)*EffectiveCost) AS Amount1
				From "+@strYearMinus2+"Sales_Invoice SIM INNER JOIN "+@strYearMinus2+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id=SID.Sal_Inv_Id
					INNER JOIN (SELECT SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal AS MainAmt, SUM(SID.Sal_Inv_Amount) AS SubAmt, 
									SIM.Sal_Inv_NetTotal-SUM(SID.Sal_Inv_Amount) AS EffectiveCost 
									FROM "+@strYearMinus2+"Sales_Invoice SIM INNER JOIN "+@strYearMinus2+"Sales_Invoice_Detail SID ON SIM.Sal_Inv_Id = SID.Sal_Inv_Id 
									Where SIM.cmp_code = "+@Cmp_Code+" GROUP BY SIM.Lgr_Id,SIM.Sal_Inv_Bill_No, SIM.Sal_Inv_NetTotal) 
				ABC ON SIM.Sal_Inv_Bill_No=ABC.Sal_Inv_Bill_No 
					"+@JoinSql2+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"
					Group by Month(SIM.Sal_Inv_Vdate),SubAmt,EffectiveCost) As XYZ 
					"
	SELECT @SQL3="Order by Mon" 
end 
else     /*    -----------Part Except Item And Item Group Wise */
Begin
	SELECT @SQL="
				Select '"+@strCurrYear+"' As Mon,
					sum(SIM.Sal_Inv_NetTotal) As Amount
				From "+@DatabaseName+"Sales_Invoice SIM "+@JoinSql+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"		 
				"
	if @strYearMinus1Exist=1
		SELECT @SQL1=" Union All
				Select '"+@strYearMin1+"' As Mon,
					sum(SIM.Sal_Inv_NetTotal) As Amount
				From "+@strYearMinus1+"Sales_Invoice SIM "+@JoinSql1+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"		 
				"
	if @strYearMinus2Exist=1
		SELECT @SQL2=" Union All
				Select '"+@strYearMin2+"' As Mon,
					sum(SIM.Sal_Inv_NetTotal) As Amount
				From "+@strYearMinus2+"Sales_Invoice SIM "+@JoinSql2+"
					Where SIM.Cmp_Code="+@Cmp_Code+"
					"+@CondSql+"						 
				"
		SELECT @SQL3="Order by Mon" 
	End
END	
EXEC(@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3




















GO

