/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 03/11/2014
-- DESCRIPTION:	THIS PROCEDURE IS USED TO SALESORDERCONFIRMATIONREPORT
-- REPORT_NAME: 
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_SALESCONFORDERREPORT 'ACC2014_2015.DBO.','1','01/APR/2014','31/MAR/2015',1,1,'##400',''
*/
CREATE PROCEDURE [dbo].[PROC_SALESCONFORDERREPORT]
(
@DATABASENAME AS NVARCHAR(50),
@CMP_CODE AS NVARCHAR(20),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@RPT_WISE AS INT,
@RPT_TYPE AS INT,
@TEMPTABLE AS NVARCHAR(100),
@INVTYPE  AS NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)

DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLSCREEN AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000) SET @SQL2=""
DECLARE @SQL3 AS NVARCHAR(4000) SET @SQL3=""
DECLARE @SQLINVOICE AS NVARCHAR(1000)
DECLARE @SQLORDERJOIN AS NVARCHAR(1000)

DECLARE @SQLORDERBY AS NVARCHAR(1000)

SET @SQL = ""
SET @SQL1 = ""

SET @SQLJOIN = ""
SET @SQLSCREEN = ""
SET @SQLINVOICE = ""
SET @SQLORDERJOIN = ""

SET @SQLORDERBY = ""

BEGIN
IF @RPT_WISE=1 /* PARTY WISE */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
SET @SQLORDERBY=" LM.LGR_NAME,PARTYID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=2 /* AGENT WISE  */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
SET @SQLORDERBY=" ALM.LGR_NAME,AGENTID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=3 /* AGENT-PARTY WISE */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
SET @SQLORDERBY=" ALM.LGR_NAME,AGENTID,PARTY,PARTYID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=4 /* ITEM WISE */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
SET @SQLORDERBY=" IM.ITEM_NAME,ITEM_ID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=5 /* SCREEN WISE */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
SET @SQLORDERBY=" SM.SCREEN_NAME,SCREEN_ID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=6 /* SALES MAN */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
SET @SQLORDERBY=" SAM.SALESMAN_NAME,SALESMANID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=7 /* SALES MAN - AGENT */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
SET @SQLORDERBY=" SAM.SALESMAN_NAME,SALESMANID,AGENT,AGENTID,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=8 /* CONFO NO WISE */
BEGIN
SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SO.SAL_ORDER_ID"
SET @SQLORDERBY=" SO.CONFNO,SO.VCH_DATE"
END
ELSE IF @RPT_WISE=9 /* CONFO NO WISE */
BEGIN
SET @SQLJOIN =""
SET @SQLORDERBY=" SO.CONFNO,SO.VCH_DATE"
END

END
BEGIN
IF @INVTYPE = "COTTON"
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
ELSE IF @INVTYPE = "RUBIA"
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID AND SOD.SCREEN_ID = SID.SCREEN_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
ELSE 
BEGIN
SET @SQLSCREEN = " LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID "
SET @SQLINVOICE = "LEFT JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO  AND SOD.ITEM_ID=SID.ITEM_ID AND SO.SAL_ORDER_ID=SID.SAL_ORDER_ID "
SET @SQLORDERJOIN = " INNER JOIN "+@DATABASENAME+" SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID "

END
END

BEGIN
SET NOCOUNT ON;
SET @SQL = " 

SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,
CM.CITY_NAME AS STATION,SO.CONFNO AS DOCNO,SO.VCH_DATE AS DATE,
SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_ID,IM.ITEM_NAME AS ITEM,ISNULL(SM.SCREEN_ID,0) AS SCREEN_ID,SM.SCREEN_NAME AS SCREEN,
SOD.Item_Cut ,SAM.SALESMAN_NAME AS SALESMAN, /*SOD.BALES AS ORDERBALES,*/
(CASE SOD.BALESPCSMTR WHEN 'BALES' THEN SOD.BALES WHEN 'PCS' THEN SOD.PIECES ELSE SOD.QUANTITY END) AS  ORDERBALES,
(CASE SOD.BALESPCSMTR WHEN 'BALES' THEN SOD.PendingBales 
WHEN 'PCS' THEN SOD.PendingPieces ELSE SOD.PendingQty END) AS  PENDING,
/*,SOD.PENDINGBALES AS PENDING,*/
SO.CMP_CODE
,'SALES' AS O_FLAG,1 AS ORD,SOD.REMARK,ISNULL(CGM.CUST_GRP_NAME,'') AS CUST_GRP_NAME,SOD.COLOR_CHART,SGM.STAMPGRP_NAME,PSM.PACKINGSTYLE_NAME,RATE
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,CMP.CMP_ALIAS

FROM "+@DATABASENAME+"  SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"  SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SO.FLAG=SOD.FLAG AND SOD.Cmp_Code=SO.Cmp_Code
INNER JOIN "+@DATABASENAME+"  LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID 
 LEFT JOIN "+@DATABASENAME+"  LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
INNER JOIN "+@DATABASENAME+"  CITY_MASTER CM ON CM.CITY_ID=SO.STATION_ID
INNER JOIN "+@DATABASENAME+"  ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
 LEFT JOIN "+@DATABASENAME+"  SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID 
LEFT JOIN "+@DATABASENAME+"  CITY_MASTER PCM ON PCM.CITY_ID = LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"  CITY_MASTER ACM ON ACM.CITY_ID = ALM.CITY_ID
LEFT JOIN "+@DATABASENAME+"  SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+"  CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
LEFT JOIN  "+@DATABASENAME+"  STAMPGROUP_MASTER SGM ON SGM.STAMPGRP_ID=SO.STAMPGRP_ID	
LEFT JOIN  "+@DATABASENAME+"  PACKINGSTYLE_Master PSM ON PSM.PACKINGSTYLE_Id =SOD.PACKINGSTYLE_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON  SO.CMP_CODE = CMP.CMP_CODE
"+@SQLJOIN+"
WHERE SO.VCH_DATE BETWEEN ' "+@FROMDATE+" ' AND ' "+@TODATE+"' 
 AND SO.ORDER_TYPE = 'B' 
GROUP BY LM.LGR_NAME,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME,
CM.CITY_NAME,SO.CONFNO,SO.VCH_DATE,
SO.SALES_ORDERNO,SO.ORDER_DATE,IM.ITEM_ID,IM.ITEM_NAME,ISNULL(SM.SCREEN_ID,0),SM.SCREEN_NAME,SAM.SALESMAN_NAME,SOD.BALES,SOD.PENDINGBALES,
SO.CMP_CODE,SOD.REMARK,SOD.BALESPCSMTR,CGM.CUST_GRP_NAME,
SOD.BALES,SOD.PIECES,SOD.QUANTITY,SOD.PENDINGBALES,SOD.PENDINGPIECES,SOD.PENDINGQTY,SOD.Item_Cut,SOD.COLOR_CHART,SGM.STAMPGRP_NAME,PSM.PACKINGSTYLE_NAME,RATE,SOD.SRNO,
LM.LGR_ID,ALM.LGR_ID,SAM.SALESMAN_ID,CMP.CMP_ALIAS
ORDER BY "+@SQLORDERBY+" "

EXEC (@SQL+@SQL1)
PRINT @SQL    
PRINT @SQL1


END






















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESINCENTIVE2]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*    PROC_AGENTCOMMISSION1 '2','ACC2009_2010.DBO.','','01/APR/2010','31/MAR/2011','',2,2,'''CR''',19,1 */
CREATE PROCEDURE [dbo].[PROC_SALESINCENTIVE2] 
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME  NVARCHAR(100),
   @NEXTDB NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @AGCOND INT,
   @ORDCOND INT,   
   @YEARCODE  NVARCHAR(10),
   @RPT_WISE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @NEXTSQL AS NVARCHAR(4000)
DECLARE @AGSQL AS NVARCHAR(1000)
DECLARE @ORDSQL AS NVARCHAR(1000)
DECLARE @JOINSQL AS NVARCHAR(4000)


SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @NEXTSQL=""
SET @AGSQL=""
SET @ORDSQL=""
SET @JOINSQL=""


IF @RPT_WISE=1 
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.AGENT_ID"
  END
ELSE IF @RPT_WISE=2
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.LGR_ID"
  END
ELSE IF @RPT_WISE=3
  BEGIN
   SET @JOINSQL="INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PD.AGENT_ID"
  END


    /*     TO GET RECORD FROM NEXT DATABASE */

BEGIN
   IF @NEXTDB!=""     
      BEGIN
	    SET @NEXTSQL="  UNION ALL
						SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,SUM(ISNULL(ADJ.ADJUSTAMT,0))AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT
                       ,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
						FROM "+@NEXTDB+"ADJMASTER ADJ
						INNER JOIN "+@NEXTDB+"PARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.JOBFLAG=ADJ.FLAG AND PD.BILL_NO=ADJ.BILLNO
                        "+@JOINSQL+"
						WHERE PD.CMP_CODE IN ("+@CMP_CODE+") AND ADJ.TYPE IN('BR') AND SUBSTRING(CONVERT(NVARCHAR,ADJ.ENTRYCODE),3,2)>"+@YEARCODE+"
						GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID                             
                      "              
 
     END
END




    /*    TO GET AGENT FROM SALES/LEDGER */
BEGIN
	IF @AGCOND=1 
	   BEGIN
		   SET @AGSQL="INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID "                   
	   END 
	ELSE IF @AGCOND=2
	   BEGIN
		   SET @AGSQL=" INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE=PD.CMP_CODE
					   INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID "                   
	   END 
END

    /*    -- TO SET ORDER BY COND */
BEGIN
    IF @ORDCOND=1 
      SET @ORDSQL="ORDER BY BILLNO"
    ELSE IF @ORDCOND=2
      SET @ORDSQL="ORDER BY LM.LGR_NAME,BILLDATE,BILLNO"
END 


BEGIN	
SET @SQL="
         SELECT DISTINCT PD.LGR_ID,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
         PD.BILL_NO AS BILLNO,PD.DATE AS BILLDATE,PD.BILL_AMOUNT AS BILLAMOUNT ,ISNULL(DETAIL.ADJUSTAMT,0) AS RECAMOUNT
         ,ISNULL(DETAIL.DISCOUNT,0) AS DISCOUNT,ISNULL(PD.COMMISSION,0)AS COMMISSION,ISNULL(PD.INTEREST,0) AS PDINTEREST,ISNULL(DETAIL.INTEREST,0) AS ADJINTEREST
         ,ISNULL(PD.INTERESTREC,0) AS PDINTREC,ISNULL(DETAIL.INTREC,0) AS ADJINTREC
         ,PD.JOBFLAG,PD.VCODE,CMP.CMP_ALIAS  
         FROM "+@DATABASENAME+"PARTYDETAIL PD
         LEFT JOIN ( 
                	SELECT BILLNO ,BILLDATE,SUM(ADJUSTAMT)AS ADJUSTAMT,FLAG,VCODE ,LGR_ID,SUM(DISCOUNT)AS DISCOUNT,SUM(INTEREST)AS INTEREST,SUM(INTREC)AS INTREC
                    FROM(
           			SELECT ADJ.BILLNO ,ADJ.DATE AS BILLDATE,SUM(ISNULL(ADJ.ADJUSTAMT,0))AS ADJUSTAMT,ADJ.FLAG ,ADJ.VCODE,ADJ.LGR_ID 
                    ,SUM(ISNULL(ADJ.DISCOUNT,0)+ISNULL(ADJ.OTHERLESS,0)) AS DISCOUNT,SUM(ISNULL(ADJ.INTEREST,0))AS INTEREST,SUM(ISNULL(ADJ.INTREC,0)) AS INTREC
					FROM "+@DATABASENAME+"ADJMASTER ADJ
					INNER JOIN "+@DATABASENAME+"PARTYDETAIL PD ON PD.VCODE=ADJ.VCODE AND PD.JOBFLAG=ADJ.FLAG AND PD.BILL_NO=ADJ.BILLNO
                    WHERE PD.CMP_CODE IN ("+@CMP_CODE +") AND ADJ.TYPE IN('BR')
					GROUP BY ADJ.BILLNO ,ADJ.DATE,ADJ.FLAG,ADJ.VCODE ,ADJ.LGR_ID                    
                    "+@NEXTSQL+"                    
                  ) AS DETAIL
                 GROUP BY BILLNO ,BILLDATE,FLAG,VCODE ,LGR_ID
				   ) "
SET @SQL1="  DETAIL ON DETAIL.VCODE=PD.VCODE  AND DETAIL.FLAG=PD.JOBFLAG AND PD.BILL_NO=DETAIL.BILLNO AND PD.LGR_ID=DETAIL.LGR_ID
			 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
			 LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PD.CMP_CODE
             "+@AGSQL +"
             LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
             "+@JOINSQL+"
             INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.LGR_ID=PD.LGR_ID AND SI.SAL_INV_ID=PD.VCODE AND SI.FLAG=PD.JOBFLAG
             INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG 
             INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID AND SM.INCENTIVE=1
			 WHERE PD.JOBFLAG  IN('S') AND PD.CMP_CODE IN("+@CMP_CODE +") AND SUBSTRING(CONVERT(NVARCHAR,PD.VCODE),3,2)="+@YEARCODE+"
             AND PD.DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'
         "+@ORDSQL+"

"
END
EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESINV_TRADING]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

