/*
PROC_SALESINV_TRADING 4,'ACC2010_2011.DBO.',2,3
*/
CREATE PROCEDURE [dbo].[PROC_SALESINV_TRADING]
(
        @CMP_CODE NVARCHAR(100),
        @DATABASENAME NVARCHAR(500),
		@FROMBILLNO  NVARCHAR(20),
		@TOBILLNO NVARCHAR(20)		
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
SET NOCOUNT ON;
SET @SQL="
    	SELECT SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,SI.ORDERNO,SI.ORDERDATE,SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(AGM.LGR_NAME) AS AGENTNAME ,SID.SAL_INV_BALENO AS BALENO,SID.ITEM_CUT,
     IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
     ,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
     SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,
	 SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,UM.UNIT_NAME,UPPER(SM.STATE_NAME) AS  PATYSTATE,UPPER(SI.DOCUMENTS) AS DOCUMENTS,UPPER(PCM.CITY_DISTRICT)AS CITY_DISTRICT, LM.CITY_PINCODE,UPPER(SI.OUR_BRANCH) AS OURBRANCH,UPPER(SI.LGR_BRANCH) AS LGRBRANCH,SI.SAL_INV_DAYS,
	 UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATE,'') AS CMP_STATE
     ,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,UPPER(ACM.CITY_NAME) AS AGENTCITY,SID.SERIALNO,
     SCM.SCREEN_NAME,CU.COURIERMASTER_NAME,SI.NET_SNET,NM.NOTES,SI.WEIGHT,SI.FREIGHT,SI.CONFNO,SI.CONFDATE,SI.LGR_BANK,LM.LGR_CSTNO
    ,SID.COLOR_CHART AS DESIGNNO
    
     
    FROM "+ @DATABASENAME+ "SALES_INVOICE SI
     INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
     INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DATABASENAME +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
     LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DATABASENAME +"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
     INNER JOIN " + @DATABASENAME +"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID
	 INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
     LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
     LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
	 LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
	 LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
     LEFT JOIN " + @DATABASENAME +"COURIER_MASTER CU ON CU.COURIERMASTER_ID=SI.COURIERMASTER_ID
     LEFT JOIN " + @DATABASENAME +"NARRATION_MASTER NM ON NM.CMP_CODE=SI.CMP_CODE AND NM.TYPE='BILL'
   
	  WHERE SI.CMP_CODE="+ @CMP_CODE +" AND   SI.SAL_INV_BILL_NO BETWEEN " + @FROMBILLNO + " AND " + @TOBILLNO + "
     ORDER BY   SI.SAL_INV_BILL_NO, SID.SAL_INV_BALENO"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESINVOICECHART]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*     PROC_SALESINVOICECHART '15/APR/2010','20/AUG/2010','1,2,3,4,5,6,7,10','ACC2010_2011.DBO.','1','200','TOP20' */
CREATE PROCEDURE [dbo].[PROC_SALESINVOICECHART]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_TYPE NVARCHAR(10),
@SALACCID NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)

SET @SQL=""
SET @SELECTED=""




BEGIN 
SET NOCOUNT ON;
BEGIN 
IF @RPT_TYPE='1'       /*     PARTY */
BEGIN
SET @SQL="
SELECT NAME,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT DISTINCT LM.LGR_NAME AS NAME  ,SUM(SAL_INV_NETTOTAL) AS NETTOTAL,ISNULL(LM.LGR_ID,0) AS ID
FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY LM.LGR_NAME,LM.LGR_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC
"
END

IF @RPT_TYPE='2'     /*     AGENT */
BEGIN
SET @SQL="
SELECT  NAME  ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT AGM.LGR_NAME AS NAME  ,SUM(SAL_INV_NETTOTAL) AS NETTOTAL,ISNULL(AGM.LGR_ID,0) AS ID    
FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY AGM.LGR_NAME,AGM.LGR_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='3'       /*    ITEM WISE */
BEGIN
SET @SQL="
SELECT NAME ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT IM.ITEM_NAME AS NAME 
,SUM((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) ) AS NETTOTAL,
ISNULL(IM.ITEM_ID,0) AS ID    
FROM "+ @DATABASENAME+ "SALES_INVOICE SI  
INNER JOIN " + @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG   
INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY IM.ITEM_NAME,IM.ITEM_ID    ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='4'      /*     CITY */
BEGIN
SET @SQL="
SELECT NAME  ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT PCM.CITY_NAME AS NAME  ,SUM(SAL_INV_NETTOTAL) AS NETTOTAL,ISNULL(PCM.CITY_ID,0) AS ID     
FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.LGR_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=AGM.CITY_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY PCM.CITY_NAME,PCM.CITY_ID ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='5'      /*     STATE */
BEGIN
SET @SQL="
SELECT  NAME  ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT SM.STATE_NAME AS NAME  ,SUM(SAL_INV_NETTOTAL) AS NETTOTAL,ISNULL(SM.STATE_ID,0) AS ID     
FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.LGR_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=AGM.CITY_ID
LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID " + @SELECTED +"
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY SM.STATE_NAME,SM.STATE_ID ) AS A   	 
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='6'     /*     ITEM GROUP */
BEGIN
SET @SQL="
SELECT  NAME ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT IGM.ITEM_GRP_NAME AS NAME , 
SUM((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) )AS NETTOTAL,
ISNULL(IM.ITEM_ID,0) AS ID    
FROM "+ @DATABASENAME+ "SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID
INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN " + @DATABASENAME +"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE  IN ("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY IGM.ITEM_GRP_NAME,IGM.ITEM_GRP_ID  ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END
IF @RPT_TYPE='7'     /*     DESTINATION */
BEGIN
SET @SQL="
SELECT  NAME ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT PCM.CITY_NAME AS NAME  ,SUM(SAL_INV_NETTOTAL) AS NETTOTAL,ISNULL(PCM.CITY_ID,0) AS ID   
FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON SI.STATION_ID=PCM.CITY_ID
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +")AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY PCM.CITY_NAME,PCM.CITY_ID ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END

IF @RPT_TYPE='8'     /*     SCREEN */
BEGIN
SET @SQL="
SELECT  NAME ,CONVERT(NUMERIC(18,2),NETTOTAL) AS NETTOTAL,ID FROM (
SELECT SCM.SCREEN_NAME AS NAME  ,
SUM((SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) ) AS NETTOTAL,
ISNULL(SCM.SCREEN_ID,0) AS ID     
FROM "+ @DATABASENAME+ "SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID
INNER JOIN  "+ @DATABASENAME +"SCREEN_MASTER SCM ON SCM.SCREEN_ID = SID.SCREEN_ID	
WHERE SI.SAL_ACCID="+@SALACCID+" AND SI.CMP_CODE IN ("+ @CMP_CODE +")AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
GROUP BY SCM.SCREEN_NAME,SCM.SCREEN_ID  ) AS A
WHERE NAME IS NOT NULL
ORDER BY NETTOTAL DESC "
END


END	
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESINVOICEEMAIL]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/* 
-- =============================================
-- ALTER_AUTHOR	: <BIREN>
-- ALTER_DATE		: <20/12/2012,5:00>
-- EDIT_AUTHOR		: <BIREN>
-- EDIT_DATE		: <29/10/2013,5:00>
-- REPORT_NAME		: <SALESINVOICEEMAIL>
-- REPORT_FORM		: <RFRMSALESINVOICEEMAIL>
-- =============================================
   
PROC_SALESINVOICEEMAIL '1','ACC2012_2013.DBO.','31/MAR/2013',2,221,1,1,'21385'
*/
CREATE PROCEDURE [dbo].[PROC_SALESINVOICEEMAIL]
(
	@CMP_CODE NVARCHAR(10),
	@DATABASENAME NVARCHAR(50),
	@DATE NVARCHAR(20),
	@CRITERIA INT,
	@ACCID NVARCHAR(20),
	@RPTWISE INT,
	@BILL_WISE INT,
	@BILL_NO NVARCHAR(4000)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @BILLNOQL AS NVARCHAR(100)
DECLARE @ORDERSQL AS NVARCHAR(100)
DECLARE @RPTSQL AS NVARCHAR(100)

BEGIN

SET @SQL=""
SET @SQL1=""
SET @BILLNOQL=""
SET @RPTSQL=""

BEGIN
	IF @RPTWISE = 1 
		BEGIN
			IF @BILL_WISE = 0 
				BEGIN
					IF @CRITERIA = 1 
						BEGIN		
							SET @RPTSQL = " AND SI.LGR_ID = "+@ACCID
						END
					ELSE IF @CRITERIA = 2
						BEGIN
							SET @RPTSQL = " AND SI.AGENT_ID = "+@ACCID
						END
				END
			ELSE IF @BILL_WISE = 1
				BEGIN 
					SET @BILLNOQL = " AND SI.SAL_INV_BILL_NO IN ("+@BILL_NO+") "
				END
		END
END

BEGIN
SET @SQL="
		SELECT SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,SI.ORDERNO,SI.ORDERDATE,
		SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY
		,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2,UPPER(LM.LGR_ADD3)AS LGR_ADD3
		,UPPER(AGM.LGR_NAME) AS AGENTNAME ,SID.SAL_INV_BALENO AS BALENO,SID.ITEM_CUT,
		IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT
		,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
		,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3
		,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
		SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,
		SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,
		SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,UM.UNIT_NAME,UPPER(SM.STATE_NAME) AS  PATYSTATE,
		UPPER(SI.DOCUMENTS) AS DOCUMENTS,UPPER(PCM.CITY_DISTRICT)AS CITY_DISTRICT,
		LM.CITY_PINCODE,UPPER(SI.OUR_BRANCH) AS OURBRANCH,UPPER(SI.LGR_BRANCH) AS LGRBRANCH,
		SI.SAL_INV_DAYS,UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,
		ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY,
		ISNULL(CMP.CMP_STATE,'') AS CMP_STATE,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,
		CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,UPPER(ACM.CITY_NAME) AS AGENTCITY,SID.SERIALNO,
		SCM.SCREEN_NAME,CU.COURIERMASTER_NAME,SI.NET_SNET,SI.WEIGHT,SI.FREIGHT,SI.CONFNO,SI.CONFDATE,
		SI.LGR_BANK,LM.LGR_CSTNO 
		FROM "+@DATABASENAME+"SALES_INVOICE SI
		INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
			AND SI.CMP_CODE = SID.CMP_CODE AND SI.FLAG = SID.FLAG
		INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
		INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
		INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID
		INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE 
		LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
		LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+"COURIER_MASTER CU ON CU.COURIERMASTER_ID=SI.COURIERMASTER_ID
		WHERE SI.CMP_CODE IN ("+@CMP_CODE+") AND SI.SAL_INV_VDATE ='"+@DATE+"' "+@RPTSQL+"
		"
SET @SQL1 = ""+@BILLNOQL+""
END	

EXEC (@SQL+@SQL1)
PRINT @SQL
PRINT @SQL1

END




















GO

