CREATE PROCEDURE [dbo].[PROC_SALESINVOICEPREPRINTED]
(
		@FROMBILLNO  NVARCHAR(20),
		@TOBILLNO NVARCHAR(20),
		@CMP_CODE NVARCHAR(10),
		@DATABASENAME NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
SET NOCOUNT ON;
SET @SQL="
    	SELECT SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,SI.ORDERNO,SI.ORDERDATE,SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(LM.LGR_ADD1) AS LGR_ADD1,UPPER(LM.LGR_ADD2) AS LGR_ADD2,UPPER(LM.LGR_ADD3)AS LGR_ADD3,UPPER(AGM.LGR_NAME) AS AGENTNAME ,SID.SAL_INV_BALENO AS BALENO,SID.ITEM_CUT,
     IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,SID.SAL_INV_QTY AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL
     ,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
     SI.SAL_INV_LESS1,SI.SAL_INV_LESS2,SI.SAL_INV_LESS3,SI.SAL_INV_LESS4,SI.SAL_INV_LESS5,SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,
	 SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,UM.UNIT_NAME,UPPER(SM.STATE_NAME) AS  PATYSTATE,UPPER(SI.DOCUMENTS) AS DOCUMENTS,UPPER(PCM.CITY_DISTRICT)AS CITY_DISTRICT, LM.CITY_PINCODE,UPPER(SI.OUR_BRANCH) AS OURBRANCH,UPPER(SI.LGR_BRANCH) AS LGRBRANCH,SI.SAL_INV_DAYS,
	 UPPER(CMP.CMP_NAME)AS CMP_NAME,CMP.CMP_TIN_NO,CMP.CMP_PAN_NO,CMP.CMP_JURISDICTION,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATE,'') AS CMP_STATE
     ,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,CMP.CMP_BANK_ACCNO1,CMP.CMP_BANK_ACCNO2,CMP.CMP_BANK_ACCNO3,UPPER(ACM.CITY_NAME) AS AGENTCITY,SID.SERIALNO,
     SCM.SCREEN_NAME,CU.COURIERMASTER_NAME,SI.NET_SNET,NM.NOTES,SI.WEIGHT,SI.FREIGHT,SI.CONFNO,SI.CONFDATE,SI.LGR_BANK,LM.LGR_CSTNO
    
    
     
    FROM "+ @DATABASENAME+ "SALES_INVOICE SI
     INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID 
     INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DATABASENAME +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
     LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DATABASENAME +"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
     INNER JOIN " + @DATABASENAME +"UNIT_MASTER UM ON UM.UNIT_ID=SID.UNIT_ID
	 INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
     LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
     LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
	 LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
	 LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
     LEFT JOIN " + @DATABASENAME +"COURIER_MASTER CU ON CU.COURIERMASTER_ID=SI.COURIERMASTER_ID
     LEFT JOIN " + @DATABASENAME +"NARRATION_MASTER NM ON NM.CMP_CODE=SI.CMP_CODE AND NM.TYPE='BILL'
   
	  WHERE SI.CMP_CODE="+ @CMP_CODE +" AND   SI.SAL_INV_BILL_NO BETWEEN " + @FROMBILLNO + " AND " + @TOBILLNO + "
     ORDER BY   SI.SAL_INV_BILL_NO, SID.SAL_INV_BALENO"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESMETER_DAILYMONTHLY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*
=============================================
Author:		HIREN B DOSHI
Create_date: 06/02/2013
Description:	THIS PROCEDURE USED FOR SALES METER DAILY,MONTHLY DETAILS
ReportName : SALESMETERDAILYMONTHLY.RPT
=============================================
PROC_SALESMETER_DAILYMONTHLY '22/May/2013',2,3055,'2.5',1,'ACC2012_2013.DBO.',1
PROC_SALESMETER_DAILYMONTHLY '23/JUNE/2017',1,5,0,1,'Acc2017_2018.dbo.',1
*/
CREATE PROCEDURE [dbo].[PROC_SALESMETER_DAILYMONTHLY]
(
	@ASONDATE   NVARCHAR(20),
	@RPTTYPE    INT,
	@SALACCID   NVARCHAR(50),
	@SHORTAGE   NUMERIC(18,2),
	@CMP_CODE   NVARCHAR(50),
	@DATABASENAME NVARCHAR(50),
	@Pcs_Conversion AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQLPCSCONVERSI AS NVARCHAR(4000)
DECLARE @SQLPCSCONVERSI_FRCMTR AS NVARCHAR(4000)
DECLARE @SQLPCSCONVERSR AS NVARCHAR(4000)

SET @SQL = ""
SET @SQL1 = ""
SET @SQL2 = ""
SET @SQLPCSCONVERSI = ""
SET @SQLPCSCONVERSR = ""
SET @SQLPCSCONVERSI_FRCMTR = ""

BEGIN
	IF @Pcs_Conversion = 1 /*  PCS CONVERSION YES */
	BEGIN
		SET @SQLPCSCONVERSI = "(CASE WHEN UM.UNIT_NAME = 'METERS' THEN SID.SAL_INV_QTY  WHEN UM.UNIT_NAME IN ('DOZEN') THEN 
								(SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
								WHEN UM.UNIT_NAME = 'PIECES' THEN  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL 
								THEN 1 ELSE IM.ITEM_CONVERSION END)) ELSE 0  END) "
		SET @SQLPCSCONVERSI_FRCMTR = " (CASE WHEN UM.UNIT_NAME = 'KILOGRAMS'  THEN (SID.SAL_INV_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 
		1 ELSE IM.ITEM_CONVERSION END))ELSE 0 END )"
		SET @SQLPCSCONVERSR = " (CASE WHEN UM.UNIT_NAME = 'METERS' THEN SRD.SAL_RET_QTY WHEN UM.UNIT_NAME IN ('KILOGRAMS','DOZEN') THEN (SRD.SAL_RET_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) ELSE  (SRD.Sal_Ret_Pcs * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )  "
	END
	ELSE IF @Pcs_Conversion = 0 /* PCS CONVERSION NO */
	BEGIN
	SET @SQLPCSCONVERSI = "(CASE WHEN UM.UNIT_NAME = 'METERS' THEN SID.SAL_INV_QTY  WHEN UM.UNIT_NAME IN ('DOZEN') THEN 
								(SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
								 WHEN UM.UNIT_NAME = 'PIECES' THEN  (SID.SAL_INV_QTY) ELSE 0  END) "
		SET @SQLPCSCONVERSI_FRCMTR = " (CASE WHEN UM.UNIT_NAME = 'KILOGRAMS'  THEN (SID.SAL_INV_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 
		1 ELSE IM.ITEM_CONVERSION END))ELSE 0 END )"
		SET @SQLPCSCONVERSR = " (CASE WHEN UM.UNIT_NAME = 'METERS' THEN SRD.SAL_RET_QTY WHEN UM.UNIT_NAME IN ('KILOGRAMS','DOZEN') THEN (SRD.SAL_RET_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) ELSE  (SRD.SAL_RET_QTY) END )  "
	END
END
BEGIN
	SET NOCOUNT ON;
	IF @RPTTYPE = 2	/* DAILY */
	BEGIN
		SET @SQL = " SELECT MONTHNAME,DATE,SUM(OPENING) AS OPENING,SUM(GREY_PURCHASE) AS GREY_PURCHASE
	,SUM(FINISH_PURCHASE) AS FINISH_PURCHASE,
	SUM(SALES_RETURN) AS SALES_RETURN,SUM(SALES_METER) AS SALES_METER,
	SUM(SALES_FRCKG) AS SALES_FRCKG,SUM(SALES_FRCMTR) AS SALES_FRCMTR,MAX(ITEM_CONVERSION) AS ITEM_CONVERSION, SUM(GREY_SALES) AS GREY_SALES,SUM(PURCHASE_RETURN) AS PURCHASE_RETURN,MAX(ORD) AS ORD	FROM ( 
	 SELECT 'SEPTEMBER' AS MONTHNAME,CONVERT(NVARCHAR,'01/APR/2012') AS DATE, SUM(IOS.ITEM_OP_STOCK) AS OPENING,
	0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN
	,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,1 AS ORD
	FROM "+@DATABASENAME+" ITEM_OPENING_STOCK AS IOS
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IOS.ITEM_ID = IM.ITEM_ID
	WHERE IOS.CMP_CODE IN ( "+@CMP_CODE+" ) AND IM.ITEM_TYPE IN ('RM','FG')
	UNION ALL
	SELECT 'SEPTEMBER' AS MONTHNAME,PIM.VCHDATE AS DATE,0 AS OPENING,
	SUM(PID.QUANTITY) AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN
	,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,2 AS ORD
	FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
	INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PIM ON PID.PURCHASEINVID = PIM.PURCHASEINVID AND PID.FLAG = PIM.FLAG
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID = IM.ITEM_ID
	WHERE PIM.VCHDATE <= '"+@ASONDATE+"'  AND PIM.CMP_CODE IN ( "+@CMP_CODE+" ) AND PIM.FLAG != 'JP'
	AND IM.ITEM_TYPE IN ('RM') GROUP BY PIM.VCHDATE
	UNION ALL"

	SET @SQL1 = " 
	SELECT 'SEPTEMBER' AS MONTHNAME,PIM.VCHDATE AS DATE,0 AS OPENING,
	0 AS GREY_PURCHASE,(CASE WHEN UM.UNIT_NAME = 'METERS' THEN PID.QUANTITY
	  WHEN UM.UNIT_NAME IN ('KILOGRAMS','DOZEN') THEN (PID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
 ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )   AS FINISH_PURCHASE,0 AS SALES_RETURN
	,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,2 AS ORD
	FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
	INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PIM ON PID.PURCHASEINVID = PIM.PURCHASEINVID AND PID.FLAG = PIM.FLAG
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID = IM.ITEM_ID
	INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
	WHERE PIM.VCHDATE <= '"+@ASONDATE+"'  AND PIM.CMP_CODE IN ( "+@CMP_CODE+" )
	AND IM.ITEM_TYPE IN ('FG') AND PIM.FLAG != 'JP' 

	 UNION ALL SELECT 'SEPTEMBER' AS MONTHNAME,SRM.SAL_RET_DATE AS DATE,0 AS OPENING,
	0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,"+@SQLPCSCONVERSR+"  AS SALES_RETURN
	,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,2 AS ORD
	FROM "+@DATABASENAME+" SALES_RETURN_DETAIL SRD
	INNER JOIN "+@DATABASENAME+" SALES_RETURN_MASTER SRM ON SRD.SAL_RET_ID = SRM.SAL_RET_ID AND SRD.CMP_CODE = SRM.CMP_CODE
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SRD.ITEM_ID = IM.ITEM_ID
	INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
	WHERE SRM.SAL_RET_DATE  <= '"+@ASONDATE+"' AND SRM.CMP_CODE IN ( "+@CMP_CODE+" ) "
--	GROUP BY SRM.SAL_RET_DATE "
	SET @SQL2 = " UNION ALL
	SELECT 'SEPTEMBER' AS MONTHNAME,SI.SAL_INV_VDATE AS DATE,0 AS OPENING,
	0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,
	 "+@SQLPCSCONVERSI+" AS SALES_METER,(CASE WHEN UM.UNIT_NAME = 'KILOGRAMS'  THEN (SID.SAL_INV_QTY) ELSE 0  END) AS SALES_FRCKG,
	"+@SQLPCSCONVERSI_FRCMTR+"    AS SALES_FRCMTR,IM.ITEM_CONVERSION AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,2 AS ORD
	FROM "+@DATABASENAME+" SALES_INVOICE_DETAIL SID
	INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI  ON SID.SAL_INV_ID = SI.SAL_INV_ID AND SID.FLAG = SI.FLAG AND SID.CMP_CODE = SI.CMP_CODE
	INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.SAL_ACCID = LM.LGR_ID
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SID.ITEM_ID = IM.ITEM_ID
	INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
	WHERE SI.SAL_INV_VDATE <= '"+@ASONDATE+"' AND SI.FLAG NOT IN ('MS') AND SI.CMP_CODE IN ( "+@CMP_CODE+" )
	 AND IM.ITEM_TYPE IN ('FG')	AND SI.SAL_ACCID IN("+@SALACCID+") 
	
	UNION ALL  SELECT 'SEPTEMBER' AS MONTHNAME,SI.SAL_INV_VDATE AS DATE,0 AS OPENING,
	0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,
	0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,SUM(SID.SAL_INV_QTY) AS GREY_SALES,0 AS PURCHASE_RETURN,2 AS ORD
	FROM "+@DATABASENAME+" SALES_INVOICE_DETAIL SID
	INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI  ON SID.SAL_INV_ID = SI.SAL_INV_ID AND SID.FLAG = SI.FLAG AND SID.CMP_CODE = SI.CMP_CODE
	INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.SAL_ACCID = LM.LGR_ID
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SID.ITEM_ID = IM.ITEM_ID
	WHERE SI.SAL_INV_VDATE <= '"+@ASONDATE+"' AND SI.FLAG NOT IN ('MS') AND SI.CMP_CODE IN ( "+@CMP_CODE+" )
	AND SI.SAL_ACCID = "+@SALACCID+" AND IM.ITEM_TYPE IN ('RM') GROUP BY SI.SAL_INV_VDATE 
	UNION ALL
	SELECT 'SEPTEMBER' AS MONTHNAME,PRM.PUR_RET_DATE AS DATE,0 AS OPENING,
	0 AS GREY_PURCHASE,0  AS FINISH_PURCHASE,0 AS SALES_RETURN
	,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,SUM(PRD.PUR_RET_QTY) AS PURCHASE_RETURN, 2 AS ORD
	FROM "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD
	INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRD.PUR_RET_ID = PRM.PUR_RET_ID AND PRD.FLAG = PRM.FLAG
	INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
	WHERE PRM.PUR_RET_DATE <= '"+@ASONDATE+"'  AND PRM.CMP_CODE IN ( "+@CMP_CODE+" ) AND IM.ITEM_TYPE IN ('RM','FG')
	 GROUP BY PRM.PUR_RET_DATE
	) AS DETAIL   GROUP BY MONTHNAME,DATE
	ORDER BY DATE "
	END
	ELSE IF @RPTTYPE = 1	/* MONTHLY */
	BEGIN
		SET @SQL = "SELECT MONTHNAME,GETDATE() AS DATE,SUM(OPENING) AS OPENING,SUM(GREY_PURCHASE) AS GREY_PURCHASE
,SUM(FINISH_PURCHASE) AS FINISH_PURCHASE,
SUM(SALES_RETURN) AS SALES_RETURN,MAX(ITEM_CONVERSION) AS ITEM_CONVERSION,SUM(SALES_METER) AS SALES_METER,
SUM(SALES_FRCKG) AS SALES_FRCKG,SUM(SALES_FRCMTR) AS SALES_FRCMTR,SUM(GREY_SALES) AS GREY_SALES,SUM(PURCHASE_RETURN) AS PURCHASE_RETURN,ORD FROM (
SELECT  UPPER(DATENAME(MM,'01/APR/2012')) AS MONTHNAME,'' AS DATE, 
SUM(IOS.ITEM_OP_STOCK) AS OPENING,0 AS GREY_PURCHASE,
0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,'01/APR/2012') <= 3 THEN (DATEPART(M,'01/APR/2012')+12) ELSE DATEPART(M,'01/APR/2012') END) AS ORD
FROM "+@DATABASENAME+" ITEM_OPENING_STOCK AS IOS
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IOS.ITEM_ID = IM.ITEM_ID
	WHERE IOS.CMP_CODE IN ( "+@CMP_CODE+" ) AND IM.ITEM_TYPE IN ('RM','FG')
UNION ALL
SELECT UPPER(DATENAME(MM,PIM.VCHDATE)) AS MONTHNAME,PIM.VCHDATE AS DATE,0 AS OPENING,SUM(PID.QUANTITY) AS GREY_PURCHASE,
0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,PIM.VCHDATE) <= 3 THEN (DATEPART(M,PIM.VCHDATE)+12) ELSE DATEPART(M,PIM.VCHDATE) END) AS ORD
FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PIM ON PID.PURCHASEINVID = PIM.PURCHASEINVID AND PID.FLAG = PIM.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID = IM.ITEM_ID
WHERE PIM.VCHDATE <= '"+@ASONDATE+"'  AND PIM.CMP_CODE IN ( "+@CMP_CODE+" ) AND PIM.FLAG != 'JP'
AND IM.ITEM_TYPE IN ('RM') GROUP BY PIM.VCHDATE
UNION ALL
SELECT UPPER(DATENAME(MM,PIM.VCHDATE)) AS MONTHNAME,PIM.VCHDATE AS DATE,0 AS OPENING,0 AS GREY_PURCHASE,
0  AS FINISH_PURCHASE,0 AS SALES_RETURN,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,PIM.VCHDATE) <= 3 THEN (DATEPART(M,PIM.VCHDATE)+12) ELSE DATEPART(M,PIM.VCHDATE) END) AS ORD
FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PIM ON PID.PURCHASEINVID = PIM.PURCHASEINVID AND PID.FLAG = PIM.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID = IM.ITEM_ID
WHERE PIM.VCHDATE <= '"+@ASONDATE+"'  AND PIM.CMP_CODE IN ( "+@CMP_CODE+" ) AND PIM.FLAG != 'JP'
AND IM.ITEM_TYPE NOT IN ('RM','FG') GROUP BY PIM.VCHDATE
UNION ALL
SELECT UPPER(DATENAME(MM,PIM.VCHDATE)) AS MONTHNAME,PIM.VCHDATE AS DATE,0 AS OPENING,0 AS GREY_PURCHASE,
(CASE WHEN UM.UNIT_NAME = 'METERS' THEN PID.QUANTITY
	  WHEN UM.UNIT_NAME IN ('KILOGRAMS','DOZEN') THEN (PID.QUANTITY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
 ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )   AS FINISH_PURCHASE,0 AS SALES_RETURN,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,PIM.VCHDATE) <= 3 THEN (DATEPART(M,PIM.VCHDATE)+12) ELSE DATEPART(M,PIM.VCHDATE) END) AS ORD
FROM "+@DATABASENAME+" PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+" PURCHASEINVOICE PIM ON PID.PURCHASEINVID = PIM.PURCHASEINVID AND PID.FLAG = PIM.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON PID.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
WHERE PIM.VCHDATE <= '"+@ASONDATE+"'  AND PIM.CMP_CODE IN ( "+@CMP_CODE+" )
AND IM.ITEM_TYPE IN ('FG') AND PIM.FLAG != 'JP'  "

	  SET @SQL1 = " UNION ALL
SELECT UPPER(DATENAME(MM,SRM.SAL_RET_DATE)) AS MONTHNAME,SRM.SAL_RET_DATE AS DATE,0 AS OPENING,0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,"+@SQLPCSCONVERSR+"  AS SALES_RETURN
,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,SRM.SAL_RET_DATE) <= 3 THEN (DATEPART(M,SRM.SAL_RET_DATE)+12) ELSE DATEPART(M,SRM.SAL_RET_DATE) END) AS ORD
FROM "+@DATABASENAME+" SALES_RETURN_DETAIL SRD
INNER JOIN "+@DATABASENAME+" SALES_RETURN_MASTER SRM ON SRD.SAL_RET_ID = SRM.SAL_RET_ID AND SRD.CMP_CODE = SRM.CMP_CODE
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SRD.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON UM.UNIT_ID = IM.UNIT_ID
WHERE SRM.SAL_RET_DATE  <= '"+@ASONDATE+"' AND SRM.CMP_CODE IN ( "+@CMP_CODE+" )
UNION ALL
SELECT UPPER(DATENAME(MM,SI.SAL_INV_VDATE)) AS MONTHNAME,SI.SAL_INV_VDATE AS DATE,
0 AS OPENING,0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,
"+@SQLPCSCONVERSI+"  AS SALES_METER,(CASE WHEN UM.UNIT_NAME = 'KILOGRAMS'  THEN (SID.SAL_INV_QTY) ELSE 0 END	
) AS SALES_FRCKG,   "+@SQLPCSCONVERSI_FRCMTR+"  AS SALES_FRCMTR,IM.ITEM_CONVERSION AS ITEM_CONVERSION,0 AS GREY_SALES,0 AS PURCHASE_RETURN,(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE) <= 3 THEN (DATEPART(M,SI.SAL_INV_VDATE)+12) ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS ORD
FROM "+@DATABASENAME+" SALES_INVOICE_DETAIL SID
INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI  ON SID.SAL_INV_ID = SI.SAL_INV_ID AND SID.FLAG = SI.FLAG AND SID.CMP_CODE = SI.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.SAL_ACCID = LM.LGR_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SID.ITEM_ID = IM.ITEM_ID
INNER JOIN "+@DATABASENAME+" UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
WHERE SI.SAL_INV_VDATE <= '"+@ASONDATE+"' AND SI.CMP_CODE IN ( "+@CMP_CODE+" )
AND SI.SAL_ACCID = "+@SALACCID+" AND IM.ITEM_TYPE IN ('FG') AND SI.FLAG NOT IN ('MS')
UNION ALL
SELECT UPPER(DATENAME(MM,SI.SAL_INV_VDATE)) AS MONTHNAME,SI.SAL_INV_VDATE AS DATE,0 AS OPENING,0 AS GREY_PURCHASE,0 AS  FINISH_PURCHASE,0 AS SALES_RETURN,
0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCMTR,0 AS ITEM_CONVERSION,SUM(SID.SAL_INV_QTY) AS GREY_SALES,0 AS PURCHASE_RETURN
,(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE) <= 3 THEN (DATEPART(M,SI.SAL_INV_VDATE)+12) ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS ORD
FROM "+@DATABASENAME+" SALES_INVOICE_DETAIL SID
INNER JOIN "+@DATABASENAME+" SALES_INVOICE SI  ON SID.SAL_INV_ID = SI.SAL_INV_ID AND SID.FLAG = SI.FLAG AND SID.CMP_CODE = SI.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.SAL_ACCID = LM.LGR_ID
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SID.ITEM_ID = IM.ITEM_ID
WHERE SI.SAL_INV_VDATE <= '"+@ASONDATE+"' AND SI.FLAG NOT IN ('MS') AND SI.CMP_CODE IN ( "+@CMP_CODE+" )
AND SI.SAL_ACCID = "+@SALACCID+" AND IM.ITEM_TYPE IN ('RM') GROUP BY SI.SAL_INV_VDATE "
SET @SQL2 = " UNION ALL
SELECT UPPER(DATENAME(MM,PRM.PUR_RET_DATE)) AS MONTHNAME,PRM.PUR_RET_DATE AS DATE,0 AS OPENING,0 AS GREY_PURCHASE,0  AS FINISH_PURCHASE,0 AS SALES_RETURN
,0 AS SALES_METER,0 AS SALES_FRCKG,0 AS SALES_FRCKG,0 AS ITEM_CONVERSION,0 AS GREY_SALES,SUM(PRD.PUR_RET_QTY) AS PURCHASE_RETURN, 
(CASE WHEN DATEPART(M,PRM.PUR_RET_DATE) <= 3 THEN (DATEPART(M,PRM.PUR_RET_DATE)+12) ELSE DATEPART(M,PRM.PUR_RET_DATE) END) AS ORD
FROM "+@DATABASENAME+" PURCHASE_RETURN_DETAIL PRD
INNER JOIN "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM ON PRD.PUR_RET_ID = PRM.PUR_RET_ID AND PRD.FLAG = PRM.FLAG
INNER JOIN "+@DATABASENAME+" ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
WHERE PRM.PUR_RET_DATE <= '"+@ASONDATE+"'  AND PRM.CMP_CODE IN ( "+@CMP_CODE+" ) AND IM.ITEM_TYPE IN ('RM','FG')
GROUP BY PRM.PUR_RET_DATE
) AS DETAIL GROUP BY MONTHNAME,ORD
ORDER BY ORD "
	END
END
EXEC (@SQL+@SQL1+@SQL2)

PRINT @SQL
PRINT @SQL1
PRINT @SQL2





















GO

