/*
PROC_SALESORDER_ASONDATE '2','ACC2010_2011.DBO.','01/APR/2010','25/JUL/2010','##2310'
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDER_ASONDATE] 
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(50),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT,
   @RPT_TYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(2000)
DECLARE @TYPESQL AS NVARCHAR(2000)

SET @SQL="" 
SET @SQL1="" 
SET @SQL2="" 
SET @JOINSQL=""
SET @TYPESQL=""


BEGIN 
       IF @RPT_WISE=1
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
       ELSE IF @RPT_WISE=2
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
       ELSE IF @RPT_WISE=3
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
       ELSE IF @RPT_WISE=4
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
       ELSE IF @RPT_WISE=5
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IGM.ITEM_GRP_ID"
       ELSE IF @RPT_WISE=6
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
       ELSE IF @RPT_WISE=7
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SM.SCREEN_ID"
      ELSE IF @RPT_WISE=8
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"
      ELSE IF @RPT_WISE=9
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"
	  ELSE IF @RPT_WISE = 10
		  SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CGM.CUST_GRP_ID"
END

BEGIN
    IF @RPT_TYPE=1 
         SET @TYPESQL=" HAVING (SUM(ORDQTY)-SUM(DELQTY)-SUM(CANQTY)) >0 "
    ELSE IF @RPT_TYPE=2 
         SET @TYPESQL=""
END



BEGIN
SET  @SQL="
SELECT  CONFNO,DATE,ORDNO,ORDDATE,PARTY,PARTYCITY,AGENT,AGENTCITY,ITEM,SCREEN,ITEMGROUP,ITEMTYPE
,SUM(ORDQTY)AS ORDQTY,SUM(DELQTY) AS DELQTY,SUM(CANQTY) AS CANQTY
,(SUM(ORDQTY)-SUM(DELQTY)-SUM(CANQTY)) AS PENDQTY,CMP_ALIAS,RATE,SALESMAN,CUSTOMERGROUP
FROM(
SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,SOD.BALES AS ORDQTY,0 AS DELQTY,0 AS CANQTY
,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE   SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"' AND SO.CMP_CODE IN("+@CMP_CODE+")
UNION ALL   "
SET @SQL1="
SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,
0 AS ORDQTY,
(CASE WHEN BALESPCSMTR='MTR' THEN SUM(TOTAL) WHEN BALESPCSMTR='PCS' THEN SUM(TOTALPCS) WHEN BALESPCSMTR='BALES' THEN COUNT(PS.PACKINGSLIPID) END )AS DELQTY,0 AS CANQTY
,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"PACKINGSLIP PS 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN  "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=PS.CONFNO AND SO.FYEAR=PS.FYEAR AND SO.CMP_CODE=PS.CMP_CODE
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND PSD.ITEM_ID=SOD.ITEM_ID AND PSD.SCREEN_ID=SOD.SCREEN_ID           
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PS.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE PS.CONFNO>0 AND PS.VCH_DATE<='"+@TODATE+"' AND PS.CMP_CODE IN("+@CMP_CODE+")
GROUP BY SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO ,SO.ORDER_DATE ,LM.LGR_NAME ,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME
,IM.ITEM_NAME ,SM.SCREEN_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME,CMP.CMP_ALIAS,SOD.RATE ,SAM.SALESMAN_NAME,BALESPCSMTR,CGM.CUST_GRP_NAME

UNION ALL   "
SET @SQL2="
           SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
           ,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
           ,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,0 AS ORDQTY,0 AS DELQTY,SOCD.CANCELBALES AS CANQTY
           ,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
           FROM "+@DATABASENAME+"SALESORDER_CANCELLATION SOC
           INNER JOIN "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID 
           INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.CMP_CODE=SOCD.CMP_CODE AND SO.FYEAR=SOCD.FYEAR
           INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID
           INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
           LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
           LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
           LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
           INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
           INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
           LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
           LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SOC.CMP_CODE
           LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
			 LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
           "+@JOINSQL+"
           WHERE SOC.CANCELLATION_DATE<='"+@TODATE+"' AND SOC.CMP_CODE IN("+@CMP_CODE+")
      )
        AS DETAIL
         GROUP BY CONFNO,DATE,ORDNO,ORDDATE,PARTY,PARTYCITY,AGENT,AGENTCITY,ITEM,SCREEN,ITEMGROUP,ITEMTYPE,CMP_ALIAS,RATE,SALESMAN,CUSTOMERGROUP
         "+@TYPESQL+"
"


END

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDER_ASONDATE_SUMMARY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
PROC_SALESORDER_ASONDATE '2','ACC2010_2011.DBO.','01/APR/2010','25/JUL/2010','##2310'
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDER_ASONDATE_SUMMARY] 
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(50),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20),
   @RPT_WISE INT,
   @RPT_TYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(2000)
DECLARE @TYPESQL AS NVARCHAR(2000)
DECLARE @SQLMAINGROUP AS NVARCHAR(2000)
DECLARE @SQLGROUP AS NVARCHAR(2000)
SET @SQL="" 
SET @SQL1="" 
SET @SQL2="" 
SET @JOINSQL=""
SET @TYPESQL=""
SET @SQLGROUP=""
SET @SQLMAINGROUP=""


BEGIN 
       IF @RPT_WISE=1
          BEGIN
            SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"
            SET @SQLMAINGROUP=" PARTY AS MAINGROUP,PARTYCITY AS MAINGROUPCITY,PARTY AS SECONDGROUP,PARTYCITY AS SECONDGROUPCITY"
            SET @SQLGROUP=" PARTY ,PARTYCITY "
           END
       ELSE IF @RPT_WISE=2
          BEGIN
            SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
            SET @SQLMAINGROUP=" AGENT AS MAINGROUP,AGENTCITY AS MAINGROUPCITY,AGENT AS SECONDGROUP,AGENTCITY AS SECONDGROUPCITY"
            SET @SQLGROUP=" AGENT,AGENTCITY"
          END
       ELSE IF @RPT_WISE=3
          BEGIN
            SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"
            SET @SQLMAINGROUP=" AGENT AS MAINGROUP,AGENTCITY AS MAINGROUPCITY,PARTY AS SECONDGROUP,PARTYCITY AS SECONDGROUPCITY"
            SET @SQLGROUP=" AGENT,AGENTCITY,PARTY ,PARTYCITY "
          END
       ELSE IF @RPT_WISE=4
          BEGIN
             SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
             SET @SQLMAINGROUP=" ITEM AS MAINGROUP,NULL AS MAINGROUPCITY,ITEM AS SECONDGROUP,NULL AS SECONDGROUPCITY"
            SET @SQLGROUP=" ITEM "
          END
       ELSE IF @RPT_WISE=5
		 BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IGM.ITEM_GRP_ID"
            SET @SQLMAINGROUP=" ITEMGROUP AS MAINGROUP,NULL AS MAINGROUPCITY,ITEMGROUP AS SECONDGROUP,NULL AS SECONDGROUPCITY"
            SET @SQLGROUP=" ITEMGROUP "
         END
       ELSE IF @RPT_WISE=6
		 BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
          SET @SQLMAINGROUP=" ITEMTYPE AS MAINGROUP,NULL AS MAINGROUPCITY,ITEMTYPE AS SECONDGROUP,NULL AS SECONDGROUPCITY"
          SET @SQLGROUP=" ITEMTYPE "
         END
       ELSE IF @RPT_WISE=7
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SM.SCREEN_ID"
          SET @SQLMAINGROUP=" SCREEN AS MAINGROUP,NULL AS MAINGROUPCITY,SCREEN  AS SECONDGROUP,NULL AS SECONDGROUPCITY"
          SET @SQLGROUP=" SCREEN  "
         END
      ELSE IF @RPT_WISE=8
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"
          SET @SQLMAINGROUP=" SALESMAN AS MAINGROUP,NULL AS MAINGROUPCITY,SALESMAN  AS SECONDGROUP,NULL AS SECONDGROUPCITY"
          SET @SQLGROUP=" SALESMAN  "
         END
      ELSE IF @RPT_WISE=9
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"
          SET @SQLMAINGROUP=" SALESMAN AS MAINGROUP,NULL AS MAINGROUPCITY,AGENT  AS SECONDGROUP,AGENTCITY AS SECONDGROUPCITY"
          SET @SQLGROUP=" SALESMAN ,AGENTCITY, AGENT"
         END
	 ELSE IF @RPT_WISE = 10
		BEGIN
			SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CGM.CUST_GRP_ID"
			SET @SQLMAINGROUP=" CUSTOMERGROUP AS MAINGROUP,CUSTOMERGROUP AS MAINGROUPCITY,CUSTOMERGROUP  AS SECONDGROUP,CUSTOMERGROUP AS SECONDGROUPCITY"
			SET @SQLGROUP=" CUSTOMERGROUP"
		END
END

BEGIN
    IF @RPT_TYPE=1 
         SET @TYPESQL=" HAVING (SUM(ORDQTY)-SUM(DELQTY)-SUM(CANQTY)) >0 "
    ELSE IF @RPT_TYPE=2 
         SET @TYPESQL=""
END



BEGIN
SET  @SQL="
SELECT  "+@SQLMAINGROUP +"
,SUM(ISNULL(ORDQTY,0))AS ORDQTY,SUM(ISNULL(DELQTY,0)) AS DELQTY,SUM(ISNULL(CANQTY,0)) AS CANQTY
,(SUM(ISNULL(ORDQTY,0))-SUM(ISNULL(DELQTY,0))-SUM(ISNULL(CANQTY,0))) AS PENDQTY,CMP_ALIAS
FROM(
SELECT  CONFNO,DATE,ORDNO,ORDDATE,PARTY,PARTYCITY,AGENT,AGENTCITY,ITEM,SCREEN,ITEMGROUP,ITEMTYPE
,SUM(ORDQTY)AS ORDQTY,SUM(DELQTY) AS DELQTY,SUM(CANQTY) AS CANQTY
,(SUM(ORDQTY)-SUM(DELQTY)-SUM(CANQTY)) AS PENDQTY,CMP_ALIAS,RATE,SALESMAN,CUSTOMERGROUP
FROM(
SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,SOD.BALES AS ORDQTY,0 AS DELQTY,0 AS CANQTY
,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE   SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE+"' AND SO.CMP_CODE IN("+@CMP_CODE+")
UNION ALL   "
SET @SQL1="
SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,0 AS ORDQTY,
(CASE WHEN BALESPCSMTR='MTR' THEN SUM(Total) WHEN BALESPCSMTR='PCS' THEN SUM(TotalPcs) WHEN BALESPCSMTR='BALES' THEN COUNT(PS.PACKINGSLIPID) END )AS DELQTY
,0 AS CANQTY
,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"PACKINGSLIP PS 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN  "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=PS.CONFNO AND SO.FYEAR=PS.FYEAR AND SO.CMP_CODE=PS.CMP_CODE
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND PSD.ITEM_ID=SOD.ITEM_ID AND PSD.SCREEN_ID=SOD.SCREEN_ID           
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=PS.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE PS.CONFNO>0 AND PS.VCH_DATE<='"+@TODATE+"' AND PS.CMP_CODE IN("+@CMP_CODE+")
GROUP BY SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO ,SO.ORDER_DATE ,LM.LGR_NAME ,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME
,IM.ITEM_NAME ,SM.SCREEN_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME,CMP.CMP_ALIAS,SOD.RATE ,SAM.SALESMAN_NAME,BALESPCSMTR,CGM.CUST_GRP_NAME 

UNION ALL   "
SET @SQL2="
SELECT  SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE
,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,IM.ITEM_NAME AS ITEM,SM.SCREEN_NAME AS SCREEN,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,0 AS ORDQTY,0 AS DELQTY,SOCD.CANCELBALES AS CANQTY
,CMP.CMP_ALIAS,SOD.RATE,SAM.SALESMAN_NAME,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALESORDER_CANCELLATION SOC
INNER JOIN "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID 
INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.CMP_CODE=SOCD.CMP_CODE AND SO.FYEAR=SOCD.FYEAR
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SOC.CMP_CODE
LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@JOINSQL+"
WHERE SOC.CANCELLATION_DATE<='"+@TODATE+"' AND SOC.CMP_CODE IN("+@CMP_CODE+")
)
AS DETAIL
GROUP BY CONFNO,DATE,ORDNO,ORDDATE,PARTY,PARTYCITY,AGENT,AGENTCITY,ITEM,SCREEN,ITEMGROUP,ITEMTYPE,CMP_ALIAS,RATE,SALESMAN,CUSTOMERGROUP
"+@TYPESQL+"
) AS D GROUP BY CMP_ALIAS ,"+ @SQLGROUP+"
"


END

EXEC (@SQL+@SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDER_ASSORT_PENDINGREPORT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*
Author : Sanju Parmar
Created Date : 28/03/2019,4:15 PM.
PROC_SALESORDER_ASSORT_PENDINGREPORT 1,'ACC2018_2019.DBO.','01/APR/2018','31/MAR/2019','##4508',3
Select * from TempDb..SysObjects
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDER_ASSORT_PENDINGREPORT]
(
@Cmp_Code Nvarchar(100),
@DatabaseName Nvarchar(500),
@FromDate  Nvarchar(20),
@ToDate Nvarchar(20),
@TempTable Nvarchar(20),	
@RptWise Int
)
AS
DECLARE @STRSQL1 AS NVARCHAR(3999)
DECLARE @RECEIVE AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(3999)
DECLARE @STRORDERBY AS NVARCHAR(3999)
SET @STRSQL1=""
SET @SELECTED=""
SET @STRORDERBY=""


BEGIN
	IF @RptWise IN (1)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON SO.CONFNO=" + @TempTable + ".CODE"
			SET @STRORDERBY="  "
		END
	ELSE  IF @RptWise IN (2)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="  LM.LGR_NAME,LM.LGR_ID,"
		END
	ELSE IF @RptWise = 3
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON IM.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (4)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON LM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" LM.LGR_NAME,LM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END
	ELSE IF @RptWise IN (5)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON IM.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY="IM.ITEM_NAME,IM.ITEM_ID,LM.LGR_NAME,LM.LGR_ID,"
		END	
	ELSE IF @RptWise IN (6)
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON ALM.LGR_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" ALM.LGR_NAME,ALM.LGR_ID,IM.ITEM_NAME,IM.ITEM_ID,"
		END		
	ELSE
		BEGIN
			SET @SELECTED=" INNER JOIN " + @TempTable + " ON IM.ITEM_ID=" + @TempTable + ".CODE"
			SET @STRORDERBY=" IM.ITEM_NAME,IM.ITEM_ID,ALM.LGR_NAME,ALM.LGR_ID,"
		END
		

SET NOCOUNT ON;
SET @STRSQL1="
SELECT SO.CONFNO AS DOCNO,CONVERT(NVARCHAR,SO.VCH_DATE,103)AS DATE,LM.LGR_NAME AS PARTY,LM.LGR_ID AS PATRY_ID,ALM.LGR_NAME AS AGENT,ALM.LGR_ID AS AGENT_ID,
IM.ITEM_NAME AS ITEM,IM.ITEM_ID,DM.DESIGN_NAME,DM.DESIGN_ID,SOA.PCS,SOA.PENDINGPCS
FROM "+ @DATABASENAME+ "SALES_ORDER SO
INNER JOIN  "+ @DATABASENAME+ "SALES_ORDER_DETAIL SID ON SID.SAL_ORDER_ID=SO.SAL_ORDER_ID
LEFT JOIN  "+ @DATABASENAME+ "SALES_ORDER_ASSORT SOA ON SOA.ITEM_ID=SID.ITEM_ID AND SOA.SAL_ORDER_ID=SO.SAL_ORDER_ID 
INNER JOIN "+ @DATABASENAME+ "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN "+ @DATABASENAME+ "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
INNER JOIN "+ @DATABASENAME+ "ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+ @DATABASENAME+ "DESIGN_MASTER DM ON DM.DESIGN_ID=SOA.DESIGN_ID
INNER JOIN "+ @DATABASENAME+ "COMPANY_MASTER CMP ON SO.CMP_CODE= CMP.CMP_CODE     	
"+@SELECTED+"
WHERE SO.CMP_CODE="+ @CMP_CODE +" AND SO.vch_Date BETWEEN '" + @FromDate + "' AND '" + @ToDate + "'
ORDER BY "+@STRORDERBY+"SO.CONFNO,SO.VCH_DATE"      
END	
PRINT @STRSQL1
EXEC (@STRSQL1)




















GO

