/*    
PROC_SALESORDER_RATEREPORT 2,'ACC2010_2011.DBO.','01/APR/2010','15/DEC/2010',1,1,'##5249','##5249',1
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDER_RATEREPORT]
(
	@CMP_CODE AS NVARCHAR(20),
	@DATABASENAME AS NVARCHAR(50),
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20),
	@RPT_WISE AS INT,
	@RPT_TYPE AS INT,
	@TEMPTABLE AS NVARCHAR(100),
    @TEMPTABLE_ITEM AS NVARCHAR(100),
    @ITEMRATE AS NVARCHAR(20)
)
AS
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @JOINCOND AS NVARCHAR(1000)
DECLARE @SQLJOIN AS NVARCHAR(1000)
DECLARE @RATESQL AS NVARCHAR(1000)
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @JOINCOND=""
SET @SQLJOIN="" 
SET @RATESQL=""
   BEGIN
       IF @RPT_TYPE=1
            SET @JOINCOND=" AND SOD.PENDINGBALES>0"       
       ELSE IF @RPT_TYPE=2
            SET @JOINCOND=""            

   END 
   BEGIN 
          IF @RPT_WISE=1
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
          ELSE IF @RPT_WISE=2 
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
          ELSE IF @RPT_WISE=3
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
          ELSE IF @RPT_WISE=4
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
          ELSE IF @RPT_WISE=5
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
          ELSE IF @RPT_WISE=6
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID"
           ELSE IF @RPT_WISE=7
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
          ELSE IF @RPT_WISE=8
            SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
		  ELSE IF @RPT_WISE = 9
			SET @SQLJOIN =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=CGM.CUST_GRP_ID"
   END

    
BEGIN
     IF @ITEMRATE="" OR @ITEMRATE="0" 
       SET @RATESQL=""
     ELSE
       SET @RATESQL="  AND SOD.RATE="+@ITEMRATE
END



BEGIN	
	SET NOCOUNT ON;
    SET  @SQL1="

SELECT  PARTY,PARTYCITY,AGENT,AGENTCITY,
CONFNO,DATE,ORDERNO,ORDERDATE, INVNO,INVDATE,SUM(BILLAMOUNT)AS BILLAMOUNT, SUM(TOTALBALES)AS TOTALBALES,
SUM(ORDERBALES)AS ORDERBALES,(SUM(DESPATCHBALES)-SUM(CANCELBALES)) AS DESPATCHBALES,SUM(CANCELBALES) AS CANCELBALES,SUM(PENDINGBALES)AS PENDINGBALES,
ITEM,ITEMGROUP,ITEMTYPE,FLAG,CMP_ALIAS,FYEAR,SALESMAN,CUSTOMERGROUP
FROM(
SELECT distinct LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE, '' AS INVNO,NULL AS INVDATE,0 AS BILLAMOUNT,0 AS TOTALBALES,                 
SOD.BALES AS ORDERBALES,SOD.DELIVEREDBALES AS DESPATCHBALES,SOD.PENDINGBALES,0 as CANCELBALES
,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,'OD' AS FLAG,CMP.CMP_ALIAS
,SO.FYEAR,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID				  
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=IM.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
" + @SQLJOIN + "
WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+ @TODATE +"' AND SO.CMP_CODE IN ("+@CMP_CODE +")"                                
+ @JOINCOND +  @RATESQL +
                  "                    
            UNION ALL   "
SET @SQL2="
SELECT  LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,SO.CONFNO,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDNO,SO.ORDER_DATE AS ORDDATE, '' AS INVNO,NULL AS INVDATE,0 AS BILLAMOUNT,0 AS TOTALBALES
,0 AS ORDERBALES,0 AS DESPATCHBALES,0 AS PENDINGBALES,SOCD.CANCELBALES AS CANCELBALES
,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,'OD' AS FLAG,CMP.CMP_ALIAS
,SO.FYEAR,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALESORDER_CANCELLATION SOC
INNER JOIN "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID 
INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.CMP_CODE=SOCD.CMP_CODE AND SO.FYEAR=SOCD.FYEAR
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID           
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SOC.CMP_CODE
INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=IM.ITEM_ID
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
"+@SQLJOIN+"
WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+ @TODATE +"' AND SO.CMP_CODE IN("+@CMP_CODE+")
"+ @JOINCOND + @RATESQL +
           "
          UNION ALL       "
SET  @SQL3="

SELECT distinct LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ALM.LGR_NAME AS AGENT,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,
SO.CONFNO ,SO.VCH_DATE AS DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,
SI.SAL_INV_BILL_NO AS INVNO,SI.SAL_INV_VDATE AS INVDATE,SI.SAL_INV_NETTOTAL AS BILLAMOUNT,SID.Sal_Inv_Qty AS TOTALBALES
,0 AS ORDERBALES,0 AS DESPATCHBALES,0 AS PENDINGBALES,0 AS CANCELBALES
,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE,'INV' AS FLAG,CMP.CMP_ALIAS,SO.FYEAR,SAM.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
FROM "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID				  
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID				  
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_CONFNO=SO.CONFNO AND SID.CMP_CODE=SO.CMP_CODE AND SOD.SCREEN_ID=SID.SCREEN_ID AND SOD.ITEM_ID=SOD.ITEM_ID
INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID	AND SO.FYEAR=SI.SAL_FYEAR
INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID	
LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE		  
LEFT JOIN  "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
INNER JOIN "+@TEMPTABLE_ITEM +" TT_I ON TT_I.CODE=IM.ITEM_ID
LEFT JOIN "+@DATABASENAME+" CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID = LM.CUST_GRP_ID
" + @SQLJOIN + "
WHERE SO.VCH_DATE BETWEEN '"+@FROMDATE +"' AND '"+ @TODATE +"' AND SO.CMP_CODE IN ("+@CMP_CODE +")
" + @JOINCOND + @RATESQL +"
) AS DETAIL
GROUP BY  PARTY,PARTYCITY,AGENT,AGENTCITY,CONFNO,DATE,ORDERNO,ORDERDATE, INVNO,INVDATE,ITEM,ITEMGROUP,ITEMTYPE,FLAG,CMP_ALIAS,FYEAR,SALESMAN,CUSTOMERGROUP
ORDER BY DATE,CONFNO,INVDATE,INVNO

"

    
	EXEC(@SQL1+@SQL2+@SQL3)
    PRINT @SQL1    
    PRINT @SQL2
    PRINT @SQL3
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDER_SCHEME]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*    
PROC_SALESORDER_SCHEME '2,1', N'ACC2010_2011.DBO.', 46, 1, N'01/APR/2010', N'31/DEC/2010', N'##384','''FRESH''','',''
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDER_SCHEME]
(
     @CMP_CODE NVARCHAR(1000),
     @DATABASENAME NVARCHAR(50),
     @RPT_WISE INT,
     @RPT_TYPE INT,
     @FROMDATE AS NVARCHAR(20),
     @TODATE AS NVARCHAR(20), 
     @TEMPTABLE NVARCHAR(20),
     @GOODSTYPE NVARCHAR(1000),
     @SCHEMETYPE NVARCHAR(1000),
     @PRICE_ID NVARCHAR(200)
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @SQL3  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @MAINGRPSQL NVARCHAR(4000)
DECLARE @GOODSTYPESQL NVARCHAR(2000)
DECLARE @SCHEMETYPESQL NVARCHAR(1000)
DECLARE @PRICEID_COND  NVARCHAR(1000)
SET @JOINSQL=""
SET @TYPESQL=""
SET @MAINGRPSQL =""
SET @GOODSTYPESQL=""
SET @SCHEMETYPESQL=""
SET @PRICEID_COND=""
BEGIN 
    IF @GOODSTYPE<>"" 
          BEGIN
              SET  @GOODSTYPESQL=" AND IM.ITEM_GOODS_TYPE IN("+@GOODSTYPE+") "
           END
END
BEGIN
    IF @PRICE_ID<>"0" AND @PRICE_ID<>""
        BEGIN
            SET @PRICEID_COND=" AND SO.PRICE_ID IN("+@PRICE_ID+")"
        END
END
BEGIN
    IF @SCHEMETYPE<>"" 
        BEGIN
            SET @SCHEMETYPESQL=" AND SO.SCHEME_PER IN("+@SCHEMETYPE+")"
        END
END
BEGIN
		IF  @RPT_WISE>=1 and @RPT_WISE<=5
		   SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		ELSE IF @RPT_WISE>=6 AND @RPT_WISE<=15
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
        ELSE IF @RPT_WISE>=16 AND @RPT_WISE<=21
             SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
        ELSE IF @RPT_WISE>=22 AND @RPT_WISE<=26
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"  
		ELSE IF @RPT_WISE>=27 AND @RPT_WISE<=29
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"  
        ELSE IF @RPT_WISE>=30 AND @RPT_WISE<=32
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ST.CITY_ID"  
        ELSE IF @RPT_WISE>=33 AND @RPT_WISE<=35
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
        ELSE IF @RPT_WISE>=36 AND @RPT_WISE<=38
            SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ITT.ITEM_TYPE_ID"
        ELSE IF @RPT_WISE>=39 AND @RPT_WISE<=41
             SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"		   
		ELSE IF @RPT_WISE=42
		   SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM.SCREEN_ID"
		ELSE IF @RPT_WISE=43
		   SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.CONFNO"
        ELSE IF @RPT_WISE=44
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.SALES_ORDERNO"
        ELSE IF @RPT_WISE=45
           SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ISNULL(SO.SCHEME,0)"
		ELSE IF @RPT_WISE=46
		   SET @JOINSQL=" "
  
       
END

IF @RPT_TYPE=1
       SET @TYPESQL=" AND SOD.PENDINGBALES=0"
IF @RPT_TYPE=2
       SET @TYPESQL=" AND SOD.PENDINGBALES>0"
IF @RPT_TYPE=3
       SET @TYPESQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
BEGIN
    	SET NOCOUNT ON;
SET @SQL= " SELECT CONFNO,VCH_DATE,ORDERNO,ORDERDATE,ITEM,ITEMGROUP,ITEM_CUT,SCREEN ,SUM(ORDERBALES) AS ORDERBALES,SUM(ISNULL(DELIVEREDBALES,0)) AS DELIVEREDBALES,SUM(ISNULL(CANCELBALES,0)) AS CANCELBALES
            ,(SUM(ORDERBALES)-SUM(ISNULL(DELIVEREDBALES,0))-SUM(ISNULL(CANCELBALES,0))) AS PENDINGBALES
            ,PARTY,AGENT,CUSTOMEGROUP,SALESMAN,RATE,STATION,PARTYCITY,AGENTCITY,ITEMTYPE,CMP_ALIAS,GOODSTYPE,ISNULL(SCHEME,0) AS SCHEME,ISNULL(SCHEME_PER,'') AS SCHEME_PER,FYEAR FROM ("
        set @SQL1=" 
                   SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,SOD.BALES AS ORDERBALES,0 AS DELIVEREDBALES,0 AS CANCELBALES
                   ,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT, CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,ST.CITY_NAME AS STATION,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,ITT.ITEM_TYPE_NAME AS ITEMTYPE,CMP.CMP_ALIAS
                   ,IM.ITEM_GOODS_TYPE AS GOODSTYPE,ISNULL(SO.SCHEME,0) AS SCHEME,ISNULL(SO.SCHEME_PER,'') AS SCHEME_PER,ISNULL(SO.FYEAR,'') AS FYEAR
                   FROM " + @DATABASENAME + "SALES_ORDER SO
                   INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID
                   INNER JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
                   INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
                   INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
                   LEFT JOIN " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON ITT.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
                   INNER JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
                   INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
                   INNER JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
                   LEFT JOIN " + @DATABASENAME + "CITY_MASTER ST ON ST.CITY_ID=SO.STATION_ID
                   LEFT JOIN " + @DATABASENAME + "CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
                   LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
                   LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
                   LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID"
                   + @JoinSql +"
                   WHERE SO.CMP_CODE IN (" + @CMP_CODE + ") AND SO.VCH_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' " + @TYPESQL + "
                   "+@GOODSTYPESQL+"
                   "+@SCHEMETYPESQL+"
                   "+@PRICEID_COND+"
                   "
SET @SQL2= " UNION ALL 
                 SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,0 AS ORDERBALES,COUNT(*) AS DELIVEREDBALES,0 AS CANCELBALES
                 ,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT, CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,ST.CITY_NAME AS STATION,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,ITT.ITEM_TYPE_NAME AS ITEMTYPE,CMP.CMP_ALIAS
                 ,IM.ITEM_GOODS_TYPE AS GOODSTYPE,ISNULL(SO.SCHEME,0) AS SCHEME,ISNULL(SO.SCHEME_PER,'') AS SCHEME_PER,ISNULL(SO.FYEAR,'') AS FYEAR
                 FROM " + @DATABASENAME + "PACKINGSLIP PS 
                 INNER JOIN " + @DATABASENAME + "PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
                 INNER JOIN  " + @DATABASENAME + "SALES_ORDER SO ON SO.CONFNO=PS.CONFNO AND SO.FYEAR=PS.FYEAR AND SO.CMP_CODE=PS.CMP_CODE
                 INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND PSD.ITEM_ID=SOD.ITEM_ID AND PSD.SCREEN_ID=SOD.SCREEN_ID           
                 INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PS.LGR_ID
                 LEFT JOIN " + @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                 LEFT JOIN " + @DATABASENAME + "CITY_MASTER ST ON ST.CITY_ID=SO.STATION_ID
                 LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PS.AGENT_ID
                 LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                 INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
                 INNER JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
                 INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                 LEFT JOIN " + @DATABASENAME + "ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
                 LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=PS.CMP_CODE
                 LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
                 LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
                 LEFT JOIN " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON ITT.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
                 "+ @JoinSql +"
                 WHERE SO.CMP_CODE IN (" + @CMP_CODE + ") AND SO.VCH_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' " + @TYPESQL + "
                 "+@GOODSTYPESQL+"
                 "+@SCHEMETYPESQL+"
                 "+@PRICEID_COND+"
            GROUP BY SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO ,SO.ORDER_DATE ,LM.LGR_NAME ,PCM.CITY_NAME,ALM.LGR_NAME,ACM.CITY_NAME
            ,IM.ITEM_NAME ,SM.SCREEN_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME,CMP.CMP_ALIAS,SOD.RATE 
            ,SAM.SALESMAN_NAME,SOD.ITEM_CUT,CGM.CUST_GRP_NAME,ITT.ITEM_TYPE_NAME,IM.ITEM_GOODS_TYPE,ISNULL(SO.SCHEME,0),ISNULL(SO.SCHEME_PER,''),ISNULL(SO.FYEAR,'') ,ST.CITY_NAME   "


SET @SQL3 = " UNION ALL
                    SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,0 AS ORDERBALES,0 AS DELIVEREDBALES,SOCD.CANCELBALES AS CANCELBALES
                   ,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT, CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,ST.CITY_NAME AS STATION,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,ITT.ITEM_TYPE_NAME AS ITEMTYPE,CMP.CMP_ALIAS
                   ,IM.ITEM_GOODS_TYPE AS GOODSTYPE,ISNULL(SO.SCHEME,0) AS SCHEME,ISNULL(SO.SCHEME_PER,'') AS SCHEME_PER,ISNULL(SO.FYEAR,'') AS FYEAR
 FROM " + @DATABASENAME + "SALESORDER_CANCELLATION SOC
           INNER JOIN " + @DATABASENAME + "SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID 
           INNER JOIN " + @DATABASENAME + "SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.CMP_CODE=SOCD.CMP_CODE AND SO.FYEAR=SOCD.FYEAR
           INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID
           INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
           LEFT JOIN " + @DATABASENAME + "CITY_MASTER ST ON ST.CITY_ID=SO.STATION_ID
           LEFT JOIN " + @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
           LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
           LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
           INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
           INNER JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
           INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
           LEFT JOIN " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON IM.ITEM_TYPE_ID=ITT.ITEM_TYPE_ID
           LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SOC.CMP_CODE
           LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
           LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
            "+ @JoinSql +"
                 WHERE SO.CMP_CODE IN (" + @CMP_CODE + ") AND SO.VCH_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' " + @TYPESQL + "
                 "+@GOODSTYPESQL+"
                 "+@SCHEMETYPESQL+"
                  "+@PRICEID_COND+"
 "
SET @MAINGRPSQL =") AS DETAIL GROUP BY CONFNO,VCH_DATE,ORDERNO,ORDERDATE,ITEM,ITEMGROUP,ITEM_CUT,SCREEN    
                  ,PARTY,AGENT,CUSTOMEGROUP,SALESMAN,RATE,PARTYCITY,AGENTCITY,ITEMTYPE,CMP_ALIAS
                  ,GOODSTYPE,ISNULL(SCHEME,0),ISNULL(SCHEME_PER,'') ,FYEAR,STATION 
                 ORDER BY CONFNO,VCH_DATE,ORDERNO"
   EXEC (@SQL+@SQL1+@SQL2+@SQL3+@MAINGRPSQL )    
   PRINT @SQL
   PRINT @SQL1 
   PRINT @SQL2 
   PRINT @SQL3
PRINT @MAINGRPSQL 


END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDERCANCELLATION]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/*    
SELECT  * FROM ##404
PROC_SALESORDERCANCELLATION '1', N'ACC2015_2016.DBO.', 8, 2, N'01/APR/2014', N'31/MAR/2015', N'##2100',''
select * from tempdb..sysobjects where name like '##%'
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDERCANCELLATION]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@RPT_TYPE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@TEMPTABLE NVARCHAR(20),
@GOODSTYPE NVARCHAR(4000)
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @SQL3  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(4000)
DECLARE @TYPESQL NVARCHAR(4000)
DECLARE @MAINGRPSQL NVARCHAR(4000)
DECLARE @GOODSTYPESQL NVARCHAR(2000)
DECLARE @SQLORDER NVARCHAR(1000)
SET @JOINSQL=""
SET @TYPESQL=""
SET @MAINGRPSQL =""
SET @GOODSTYPESQL=""
SET @SQLORDER = ""
BEGIN 
IF @GOODSTYPE<>"" 
BEGIN
SET  @GOODSTYPESQL=" AND IM.ITEM_GOODS_TYPE IN("+@GOODSTYPE+") "
END
END

BEGIN
IF @RPT_WISE=1 /* PARTY */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
	SET @SQLORDER = " PARTY,PARTYID,"
END
ELSE IF @RPT_WISE=2 /* AGENT */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
	SET @SQLORDER = " AGENT,AGENTID,"
END
ELSE IF @RPT_WISE=3
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
ELSE IF @RPT_WISE=4 /* CUSTOMERGROUP */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
	SET @SQLORDER = " CUSTOMEGROUP,CUSTGRPID,"
END
ELSE IF @RPT_WISE=5 /* ITEM */
BEGIN 
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET @SQLORDER = " ITEM,ITEMID,"
END
ELSE IF @RPT_WISE=7 /* ITEM - SCREEN */
BEGIN 
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET @SQLORDER = " ITEM,ITEMID,SCREEN,SCREENID,"
END
ELSE IF @RPT_WISE=12 /* ITEM - PARTY */
BEGIN 
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
	SET @SQLORDER = " ITEM,ITEMID,PARTY,PARTYID,"
END
ELSE IF @RPT_WISE=6 /* SCREEN */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM.SCREEN_ID"
	SET @SQLORDER = " SCREEN,SCREENID,"
END
ELSE IF @RPT_WISE=8 /* ITEM GROUP */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
	SET @SQLORDER = " ITEMGROUP,ITEMGRPID,"
END
ELSE IF @RPT_WISE=9 
SET @JOINSQL=" "
ELSE IF @RPT_WISE=10 /* SALES MAN */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
	SET @SQLORDER = " SALESMAN,SALESMANID,"
END
ELSE IF @RPT_WISE=11 /* SALES MAN - AGENT */
BEGIN 
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
	SET @SQLORDER = " SALESMAN,SALESMANID,AGENT,AGENTID,"
END
ELSE IF @RPT_WISE=13 /* ITEM TYPE */
BEGIN
	SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ITT.ITEM_TYPE_ID"
	SET @SQLORDER = " ITEMTYPE,ITEMTYPEID,"
END
ELSE IF @RPT_WISE=14
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.CONFNO"
ELSE IF @RPT_WISE=15
SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SO.SAL_ORDER_ID"

END

IF @RPT_TYPE=1
SET @TYPESQL=" AND (CASE WHEN SOD.BALESPCSMTR='BALES' THEN SOD.PENDINGBALES WHEN SOD.BALESPCSMTR='PCS' 
				   THEN SOD.PENDINGPIECES WHEN SOD.BALESPCSMTR='MTR' THEN SOD.PENDINGQTY ELSE 0 END) = 0 "
IF @RPT_TYPE=2
SET @TYPESQL=" AND (CASE WHEN SOD.BALESPCSMTR='BALES' THEN SOD.PENDINGBALES WHEN SOD.BALESPCSMTR='PCS'
				   THEN SOD.PENDINGPIECES WHEN SOD.BALESPCSMTR='MTR' THEN SOD.PENDINGQTY ELSE 0 END) > 0 "
IF @RPT_TYPE=3
SET @TYPESQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
BEGIN
SET NOCOUNT ON;
SET    @SQL=" SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,
IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,SM.SCREEN_NAME AS SCREEN ,
/*SOD.BALES AS ORDERBALES,*/
(CASE SOD.BALESPCSMTR WHEN 'BALES' THEN SOD.BALES WHEN 'PCS'
THEN SOD.PIECES ELSE SOD.QUANTITY END) AS  ORDERBALES,
SUM(SOCD.CANCELBALES) AS CANCELBALES,SOCD.REMARK
,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT, CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,ITT.ITEM_TYPE_NAME AS ITEMTYPE,CMP.CMP_ALIAS,SOC.CANCELLATION_DATE
,IM.ITEM_GOODS_TYPE AS GOODSTYPE,SOCD.ITEM_CUT,SOC.DOCNO,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(SM.SCREEN_ID,0) AS SCREENID,ISNULL(IM.ITEM_GRP_ID,0) AS ITEMGRPID,ISNULL(ITT.ITEM_TYPE_ID,0) AS ITEMTYPEID,
ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID
FROM " + @DATABASENAME + "SALESORDER_CANCELLATION SOC
INNER JOIN " + @DATABASENAME + "SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID 
LEFT JOIN " + @DATABASENAME + "SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.CMP_CODE=SOCD.CMP_CODE AND SO.FYEAR=SOCD.FYEAR
LEFT JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID 
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
LEFT JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
LEFT JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID

LEFT JOIN " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON IM.ITEM_TYPE_ID=ITT.ITEM_TYPE_ID
LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SOC.CMP_CODE
LEFT JOIN " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
"+ @JOINSQL +"
WHERE SO.CMP_CODE IN (" + @CMP_CODE + ") AND SOC.CANCELLATION_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' " + @TYPESQL + "
AND SOC.FLAG='S' 
"+@GOODSTYPESQL+"
GROUP BY SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO ,SO.ORDER_DATE ,IM.ITEM_NAME ,IGM.ITEM_GRP_NAME,SM.SCREEN_NAME ,SOD.BALES 
,LM.LGR_NAME ,ALM.LGR_NAME ,CGM.CUST_GRP_NAME,SAM.SALESMAN_NAME,SOD.RATE,PCM.CITY_NAME,ACM.CITY_NAME,ITT.ITEM_TYPE_NAME,CMP.CMP_ALIAS
,IM.ITEM_GOODS_TYPE,SOCD.REMARK,SOCD.ITEM_CUT,SOD.BALES,SOD.PIECES,SOD.QUANTITY,SOD.BALESPCSMTR,soc.Cancellation_Date ,SOC.DOCNO
,LM.LGR_ID,ALM.LGR_ID,IM.ITEM_ID,SM.SCREEN_ID,IM.ITEM_GRP_ID,ITT.ITEM_TYPE_ID,SAM.SALESMAN_ID,CGM.CUST_GRP_ID
ORDER BY "+@SQLORDER+" CONFNO,VCH_DATE,ORDERNO"
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL
END






















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDERPRINTOUT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
-- =============================================
-- Author     :		<PRATIK PATEL>
-- Create_date: 08/06/2013
-- Description:	rfrmSalesOrderPrintOut
-- CryStalReport : SalesOrderPrintout.rpt
-- =============================================
PROC_SALESORDERPRINTOUT 1,'ACC2012_2013.DBO.',1,2
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDERPRINTOUT]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@FROMCONFNO NVARCHAR(50),
@TOCONFNO NVARCHAR(50)
)
AS

DECLARE @SQL NVARCHAR(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
SELECT SOD.SRNO,LM.LGR_NAME,AGM.LGR_NAME AS AGENT,PCM.CITY_NAME AS PARTYCITY,
CONFNO,CONVERT(NVARCHAR,VCH_DATE,103) AS CONFDATE,SALES_ORDERNO,CONVERT(NVARCHAR,ORDER_DATE,103) AS ORDERDATE,TM.TRANSPORT_NAME,
IM.ITEM_NAME,SCM.SCREEN_NAME,SOD.BALES,'BALES' AS UNIT,SOD.RATE,RATE_PER AS ITEMPER,STM.CITY_NAME AS STATION
,NARRATION1,NARRATION2,ACM.CITY_NAME AS AGENTCITY,SOD.REMARK,
LM.LGR_ADD1 AS ADRESS1,LM.LGR_ADD2 AS ADRESS2,LM.LGR_ADD3 AS ADRESS3,LM.LGR_CSTNO AS LGRTINNO,STATE_NAME AS STATE,
PACKINGSTYLE_NAME,SOD.COLOR_CHART,LM.CITY_PINCODE,SOD.PIECES,SO.THROUGH,SO.SCHEME,SO.SCHEME_PER,PRICE_NAME,LM.LGR_DISTRICT,
CMP_PHONE1,CMP_PHONE2,CMP_MOBILE,CMP_TIN_NO AS CMPTINNO
FROM  "+@DATABASENAME+"SALES_ORDER SO
INNER JOIN  "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SO.FLAG=SOD.FLAG
INNER JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
LEFT JOIN  "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SO.TRANSPORT_ID
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SO.AGENT_ID
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
LEFT JOIN   "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
LEFT JOIN  "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SOD.SCREEN_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER STM ON SO.STATION_ID=STM.CITY_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER ACM ON AGM.CITY_ID=ACM.CITY_ID
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
LEFT JOIN "+@DATABASENAME+"PACKINGSTYLE_MASTER PKM ON PKM.PACKINGSTYLE_ID=SOD.PACKINGSTYLE_ID
LEFT JOIN  "+@DATABASENAME+"PRICELIST PL ON PL.PRICE_ID=SO.PRICE_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMPM ON CMPM.CMP_CODE=SO.CMP_CODE
WHERE SO.CMP_CODE IN ('"+@CMP_CODE+"') AND CONFNO BETWEEN '"+@FROMCONFNO+"' AND '"+@TOCONFNO+"' 
AND SO.FLAG='S' AND ORDER_TYPE='B'
"
    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

