/*    
-- =============================================
-- AUTHOR      : <SANKET>
--MODIFY : SHUBHAM RAVAL (21/06/2016)
-- ALTER_DATE : <02/OCT/2012>
-- DESCRIPTION : <REPORT FOR RUBIA SALES ORDER>
-- REPORT NAME : SALESORDERREG.RPT
-- FORM_NAME   : <RFRMSALESORDERREG.CS>
-- =============================================
PROC_SALESORDERREG '2', N'ACC2015_2016.DBO.',26,3,N'01/APR/2015', N'31/MAR/2016','##3744','',0
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
select * from ##3744
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDERREG]
(
	@CMP_CODE NVARCHAR(1000),
	@DATABASENAME NVARCHAR(50),
	@RPT_WISE INT,
	@RPT_TYPE INT,
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20), 
	@TEMPTABLE NVARCHAR(20),
	@GOODSTYPE NVARCHAR(4000),
	@RPT_DATE INT
)
AS
DECLARE @SQL  NVARCHAR(4000)
DECLARE @SQL1  NVARCHAR(4000)
DECLARE @SQL2  NVARCHAR(4000)
DECLARE @SQL3  NVARCHAR(4000)
DECLARE @JOINSQL  NVARCHAR(4000)
DECLARE @TYPESQL NVARCHAR(400)
DECLARE @MAINGRPSQL NVARCHAR(4000)
DECLARE @GOODSTYPESQL NVARCHAR(4000)
DECLARE @SQLDATE  NVARCHAR(4000)
DECLARE @SQLORDER NVARCHAR(1000)

SET @JOINSQL=""
SET @TYPESQL=""
SET @MAINGRPSQL =""
SET @GOODSTYPESQL=""
SET @SQLDATE = ""
SET @SQLORDER = ""
BEGIN 
	IF @GOODSTYPE<>"" 
		BEGIN
			SET @GOODSTYPESQL=" AND IM.ITEM_GOODS_TYPE IN("+@GOODSTYPE+") "
		END
END

BEGIN
	IF @RPT_WISE=1 /* AGENT */
	BEGIN	    
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,"
	END
	ELSE IF @RPT_WISE=11 /* AGENT - PARTY */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,PARTY,PARTYID,"
	END
	ELSE IF @RPT_WISE=12 /* AGENT - ITEM */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,ITEM,ITEMID,"
	END
	ELSE IF @RPT_WISE=13 /* AGENT - SCREEN */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,SCREEN,SCREENID,"
	END
	ELSE IF @RPT_WISE=21 /* AGENT - PARTY - ITEM */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,PARTY,PARTYID,ITEM,ITEMID,"
	END
	ELSE IF @RPT_WISE=22 /* AGENT - PARTY - SCREEN */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"		
		SET @SQLORDER = " AGENT,AGENTID,PARTY,PARTYID,SCREEN,SCREENID,"
	END
	ELSE IF @RPT_WISE=2 /* PARTY */
	BEGIN	 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		SET @SQLORDER = " PARTY,PARTYID,"
	END
	ELSE IF @RPT_WISE=14 /* PARTY - ITEM */
	BEGIN	
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		SET @SQLORDER = " PARTY,PARTYID,ITEM,ITEMID,"
	END
	ELSE IF @RPT_WISE=15 /* PARTY - SCREEN */
	BEGIN	
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		SET @SQLORDER = " PARTY,PARTYID,SCREEN,SCREENID,"
	END
	ELSE IF @RPT_WISE=3 /* ITEM */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
		SET @SQLORDER = " ITEM,ITEMID,"
	END
	
	ELSE IF @RPT_WISE=26 /* ITEM -AGENT */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
		SET @SQLORDER = " ITEM,ITEMID,AGENT,AGENTID,"
	END
	
	
	ELSE IF @RPT_WISE=16 /* ITEM - PARTY */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
		SET @SQLORDER = " ITEM,ITEMID,PARTY,PARTYID,"
	END
	ELSE IF @RPT_WISE=17 /* ITEM - SCREEN */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IM.ITEM_ID"
		SET @SQLORDER = " ITEM,ITEMID,SCREEN,SCREENID,"
	END
	ELSE IF @RPT_WISE=4 /* SCREEN */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SM.SCREEN_ID"
		SET @SQLORDER = " SCREEN,SCREENID,"
	END
	ELSE IF @RPT_WISE=5 /* SALESMAN */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
		SET @SQLORDER = " SALESMAN,SALESMANID,"
	END
	ELSE IF @RPT_WISE=20 /* SALESMAN - AGENT  */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=SAM.SALESMAN_ID"
		SET @SQLORDER = " SALESMAN,SALESMANID,AGENT,AGENTID,"
	END
	ELSE IF @RPT_WISE=6 /* ITEM GROUP */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
		SET @SQLORDER = " ITEMGROUP,ITEMGRPID,"
		END
		ELSE IF @RPT_WISE=18 /* ITEM GROUP - ITEM */
	BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=IGM.ITEM_GRP_ID"
		SET @SQLORDER = " ITEMGROUP,ITEMGRPID,ITEM,ITEMID,"
		END
	ELSE IF @RPT_WISE=7 /* ITEM TYPE */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=ITT.ITEM_TYPE_ID"
		SET @SQLORDER = " ITEMTYPE,ITEMTYPEID,"
		END
	ELSE IF @RPT_WISE=8 /* CUSTOMER GROUP */
	BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.CUST_GRP_ID"
		SET @SQLORDER = " CUSTOMEGROUP,CUSTGRPID,"
		END
	ELSE IF @RPT_WISE = 9 /* CITY */
	 BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"
		SET @SQLORDER = " PARTYCITY,PARTY_CITYID,"
		END
		ELSE IF @RPT_WISE = 19 /* CITY PARTY  */
	 BEGIN 
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"
		SET @SQLORDER = " PARTYCITY,PARTY_CITYID,PARTY,PARTYID,"
		END
	ELSE IF @RPT_WISE = 10 /* STATE */
		BEGIN
		SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=STM.STATE_ID"
		SET @SQLORDER = " STATE,STATEID,"
		END
	ELSE IF @RPT_WISE=23 /*  CONFNO */
		 SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CONVERT(NVARCHAR,SO.CONFNO)+'@'+SO.FYEAR"
	ELSE IF @RPT_WISE=25
		SET @JOINSQL=" "
END

IF @RPT_TYPE=1
	SET @TYPESQL=" AND (CASE WHEN SOD.BALESPCSMTR='BALES' THEN SOD.PENDINGBALES WHEN SOD.BALESPCSMTR='PCS' 
				   THEN SOD.PENDINGPIECES WHEN SOD.BALESPCSMTR='MTR' THEN SOD.PENDINGQTY ELSE 0 END) = 0 "
IF @RPT_TYPE=2
	SET @TYPESQL=" AND (CASE WHEN SOD.BALESPCSMTR='BALES' THEN SOD.PENDINGBALES WHEN SOD.BALESPCSMTR='PCS'
				   THEN SOD.PENDINGPIECES WHEN SOD.BALESPCSMTR='MTR' THEN SOD.PENDINGQTY ELSE 0 END) > 0 "
IF @RPT_TYPE=3
	SET @TYPESQL=""
	
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""

BEGIN
IF @RPT_DATE = 0 /* FROM DATE */
SET @SQLDATE = " SO.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "
ELSE IF @RPT_DATE = 1 /* AS ON DATE */
SET @SQLDATE = " SO.VCH_DATE <= '" + @TODATE + "'"
END
BEGIN
SET NOCOUNT ON;

SET @SQL = " 
SELECT CONFNO,VCH_DATE,ORDERNO,ORDERDATE,ITEM,ITEMGROUP,ITEM_CUT,SCREEN ,SUM(ORDERBALES) AS ORDERBALES,
SUM(ISNULL(DELIVEREDBALES,0)) AS DELIVEREDBALES,SUM(ISNULL(CANCELBALES,0)) AS CANCELBALES,
(SUM(ORDERBALES)-SUM(ISNULL(DELIVEREDBALES,0))-SUM(ISNULL(CANCELBALES,0))) AS PENDINGBALES,
PARTY,AGENT,CUSTOMEGROUP,SALESMAN,RATE,PARTYCITY,AGENTCITY,STATE,ITEMTYPE,GOODSTYPE,CMP_ALIAS,
PACKSTYLE,COLOR_CHART,REMARK ,ITEMID,ITEMGRPID,SCREENID,PARTYID,AGENTID, ITEMTYPEID, PARTY_CITYID, 
SALESMANID, AGENT_CITYID,CUSTGRPID,STATEID, PACKINGSTYLEID
FROM ("

SET @SQL1=" 
SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,
IM.ITEM_NAME AS ITEM,IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,
(CASE WHEN SOD.BALESPCSMTR='BALES' THEN SOD.BALES WHEN SOD.BALESPCSMTR='PCS' THEN SOD.PIECES 
WHEN SOD.BALESPCSMTR='MTR' THEN SOD.QUANTITY ELSE 0 END) AS ORDERBALES ,
0 AS DELIVEREDBALES,0 AS CANCELBALES,LM.LGR_NAME AS PARTY,
ALM.LGR_NAME AS AGENT, CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,
PCM.CITY_NAME AS PARTYCITY,ACM.CITY_NAME AS AGENTCITY,STM.STATE_NAME AS STATE,
ITT.ITEM_TYPE_NAME AS ITEMTYPE,IM.ITEM_GOODS_TYPE AS GOODSTYPE,CMP.CMP_ALIAS,
PCKM.PACKINGSTYLE_NAME AS PACKSTYLE,SOD.COLOR_CHART,SOD.REMARK
,ISNULL(IM.Item_Id,0) AS ITEMID,ISNULL(IGM.Item_Grp_Id,0) AS ITEMGRPID,ISNULL(SM.Screen_ID,0) AS SCREENID,
ISNULL(LM.Lgr_Id,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(ITT.ITEM_TYPE_ID,0) AS ITEMTYPEID,
ISNULL(LM.CITY_ID,0) AS PARTY_CITYID,ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(STM.STATE_ID,0) AS STATEID,ISNULL(PCKM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID

FROM " + @DATABASENAME + "SALES_ORDER SO
INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SO.FLAG=SOD.FLAG AND SOD.CMP_CODE=SO.CMP_CODE
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
LEFT JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN  " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON ITT.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID

LEFT JOIN  " + @DATABASENAME + "STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
LEFT JOIN  " + @DATABASENAME + "PACKINGSTYLE_MASTER PCKM ON PCKM.PACKINGSTYLE_ID=SOD.PACKINGSTYLE_ID
"+ @JOINSQL +"
WHERE SO.ORDER_TYPE IN ('B') AND SO.FLAG='S' AND "+@SQLDATE+" "+@TYPESQL+ "
"+@GOODSTYPESQL+"
AND SO.CMP_CODE IN ("+@CMP_CODE+") 
"

SET @SQL2= " UNION ALL 
SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_NAME AS	ITEM,
IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,0 AS ORDERBALES,
(CASE WHEN SOD.BALESPCSMTR='BALES' THEN COUNT(*) WHEN SOD.BALESPCSMTR='PCS' THEN SUM(PSD.TOTALPCS) 
WHEN SOD.BALESPCSMTR='MTR' THEN SUM(PSD.TOTAL) ELSE 0 END) AS DELIVEREDBALES ,
0 AS CANCELBALES,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT, 
CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,STM.STATE_NAME AS STATE,ITT.ITEM_TYPE_NAME AS ITEMTYPE,
IM.ITEM_GOODS_TYPE AS GOODSTYPE,CMP.CMP_ALIAS,
PCKM.PACKINGSTYLE_NAME AS PACKSTYLE,SOD.COLOR_CHART,SOD.REMARK
,ISNULL(IM.Item_Id,0) AS ITEMID,ISNULL(IGM.Item_Grp_Id,0) AS ITEMGRPID,ISNULL(SM.Screen_ID,0) AS SCREENID,
ISNULL(LM.Lgr_Id,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(ITT.ITEM_TYPE_ID,0) AS ITEMTYPEID,
ISNULL(LM.CITY_ID,0) AS PARTY_CITYID,ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(STM.STATE_ID,0) AS STATEID,ISNULL(PCKM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID

FROM " + @DATABASENAME + "PACKINGSLIP PS 
INNER JOIN " + @DATABASENAME + "PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID=PSD.PACKINGSLIPID
INNER JOIN " + @DATABASENAME + "SALES_ORDER SO ON SO.CONFNO=PS.CONFNO AND SO.FYEAR=PS.FYEAR /*AND ps.CMP_CODE=SO.CMP_CODE */
INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID
AND PSD.ITEM_ID=SOD.ITEM_ID AND PSD.SCREEN_ID=SOD.SCREEN_ID AND SO.FLAG=SOD.FLAG  AND SOD.CMP_CODE=SO.CMP_CODE 	
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=PSD.ITEM_ID
LEFT JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=PSD.SCREEN_ID
INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
LEFT JOIN  " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
LEFT JOIN  " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON ITT.ITEM_TYPE_ID=IM.ITEM_TYPE_ID

LEFT JOIN  " + @DATABASENAME + "STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
LEFT JOIN  " + @DATABASENAME + "PACKINGSTYLE_MASTER PCKM ON PCKM.PACKINGSTYLE_ID=SOD.PACKINGSTYLE_ID
"+ @JOINSQL +"
WHERE SO.ORDER_TYPE IN ('B') AND SO.FLAG='S' AND "+@SQLDATE+" " + @TYPESQL + "
"+@GOODSTYPESQL+"
AND SO.CMP_CODE IN ("+@CMP_CODE+")
GROUP BY SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO ,SO.ORDER_DATE ,LM.LGR_NAME ,PCM.CITY_NAME,ALM.LGR_NAME,
ACM.CITY_NAME,IM.ITEM_NAME ,SM.SCREEN_NAME ,IGM.ITEM_GRP_NAME ,ITM.ITEM_TYPE_NAME,SOD.RATE, 
SAM.SALESMAN_NAME,SOD.ITEM_CUT,CGM.CUST_GRP_NAME,ITT.ITEM_TYPE_NAME,IM.ITEM_GOODS_TYPE,
CMP.CMP_ALIAS,STM.STATE_NAME,PCKM.PACKINGSTYLE_NAME,SOD.COLOR_CHART,SOD.REMARK,SOD.BALESPCSMTR 
,IM.Item_Id,IGM.Item_Grp_Id,SM.Screen_ID,LM.Lgr_Id,ALM.LGR_ID,ITT.ITEM_TYPE_ID,
LM.CITY_ID,SAM.SALESMAN_ID,ALM.CITY_ID,CGM.CUST_GRP_ID,STM.STATE_ID ,PCKM.PACKINGSTYLE_ID "

SET @SQL3 = " UNION ALL
SELECT SO.CONFNO,SO.VCH_DATE,SO.SALES_ORDERNO AS ORDERNO,SO.ORDER_DATE AS ORDERDATE,IM.ITEM_NAME AS ITEM,
IGM.ITEM_GRP_NAME AS ITEMGROUP,SOD.ITEM_CUT,SM.SCREEN_NAME AS SCREEN ,0 AS ORDERBALES,0 AS DELIVEREDBALES,
SOCD.CANCELBALES AS CANCELBALES,LM.LGR_NAME AS PARTY,ALM.LGR_NAME AS AGENT,
CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,SOD.RATE,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,STM.STATE_NAME AS STATE,ITT.ITEM_TYPE_NAME AS ITEMTYPE,
IM.ITEM_GOODS_TYPE AS GOODSTYPE,CMP.CMP_ALIAS,
PCKM.PACKINGSTYLE_NAME AS PACKSTYLE,SOD.COLOR_CHART,SOD.REMARK  
,ISNULL(IM.Item_Id,0) AS ITEMID,ISNULL(IGM.Item_Grp_Id,0) AS ITEMGRPID,ISNULL(SM.Screen_ID,0) AS SCREENID,
ISNULL(LM.Lgr_Id,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,ISNULL(ITT.ITEM_TYPE_ID,0) AS ITEMTYPEID,
ISNULL(LM.CITY_ID,0) AS PARTY_CITYID,ISNULL(SAM.SALESMAN_ID,0) AS SALESMANID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID
,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(STM.STATE_ID,0) AS STATEID,ISNULL(PCKM.PACKINGSTYLE_ID,0) AS PACKINGSTYLEID
FROM " + @DATABASENAME + "SALESORDER_CANCELLATION SOC
INNER JOIN " + @DATABASENAME + "SALESORDER_CANCELLATION_DETAIL SOCD ON SOC.CANCELLATION_ID=SOCD.CANCELLATION_ID AND SOC.FLAG=SOCD.FLAG AND SOC.CMP_CODE=SOCD.CMP_CODE
INNER JOIN " + @DATABASENAME + "SALES_ORDER SO ON SO.CONFNO=SOCD.CONFNO  AND SO.FYEAR=SOCD.FYEAR  AND SO.FLAG=SOCD.FLAG   AND SO.CMP_CODE = SOCD.CMP_CODE
INNER JOIN " + @DATABASENAME + "SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID AND SOD.ITEM_ID=SOCD.ITEM_ID AND SOD.SCREEN_ID=SOCD.SCREEN_ID AND SO.FLAG=SOD.FLAG AND SOD.CMP_CODE=SO.CMP_CODE
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
INNER JOIN " + @DATABASENAME + "ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
LEFT JOIN " + @DATABASENAME + "SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
INNER JOIN " + @DATABASENAME + "ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID
LEFT JOIN  " + @DATABASENAME + "CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  " + @DATABASENAME + "ITEM_TYPE_MASTER ITT ON IM.ITEM_TYPE_ID=ITT.ITEM_TYPE_ID
LEFT JOIN  " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
LEFT JOIN  " + @DATABASENAME + "SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
LEFT JOIN  " + @DATABASENAME + "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 

LEFT JOIN  " + @DATABASENAME + "STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
LEFT JOIN  " + @DATABASENAME + "PACKINGSTYLE_MASTER PCKM ON PCKM.PACKINGSTYLE_ID=SOD.PACKINGSTYLE_ID
"+ @JOINSQL +"
WHERE SO.ORDER_TYPE IN ('B') AND SO.FLAG='S' AND "+@SQLDATE+" " + @TYPESQL + "
"+@GOODSTYPESQL+"
AND SO.CMP_CODE IN ("+@CMP_CODE+")"

SET @MAINGRPSQL =") AS DETAIL GROUP BY CONFNO,VCH_DATE,ORDERNO,ORDERDATE,ITEM,ITEMGROUP,ITEM_CUT,SCREEN,    
PARTY,AGENT,CUSTOMEGROUP,SALESMAN,RATE,PARTYCITY,AGENTCITY,ITEMTYPE,GOODSTYPE,CMP_ALIAS,STATE,
PACKSTYLE,COLOR_CHART,REMARK ,ITEMID,ITEMGRPID, SCREENID,PARTYID,AGENTID, ITEMTYPEID,PARTY_CITYID, SALESMANID, AGENT_CITYID
, CUSTGRPID, STATEID, PACKINGSTYLEID
ORDER BY "+@SQLORDER+" CONFNO,VCH_DATE,ORDERNO "

EXEC (@SQL+@SQL1+@SQL2+@SQL3+@MAINGRPSQL )    
PRINT @SQL
PRINT @SQL1 
PRINT @SQL2 
PRINT @SQL3
PRINT @MAINGRPSQL 

END

























GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESORDERREGSUMMARY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
