CREATE PROCEDURE [dbo].[PROC_SALESORDERREGSUMMARY]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @Rpt_Type int,
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(4000)
declare @GrpSql  Nvarchar(4000)
declare @SelSql  Nvarchar(4000)
Declare @TypeSql Nvarchar(4000)
set @JoinSql=""
Set @TypeSql=""
set @GrpSql=""
set @SelSql=""
if @Rpt_Wise=1
     begin
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=LM.Lgr_ID"       
       SET @SELSQL="SELECT LM.LGR_NAME AS PARTY,min(ALM.LGR_NAME) AS AGENT,IM.ITEM_NAME AS ITEM ,SM.SCREEN_NAME AS SCREEN ,sum(SOD.PENDINGBALES)as PENDINGBALES,min(IGM.ITEM_GRP_NAME) AS ITEMGROUP"
       set @GrpSql=" GROUP BY IM.ITEM_NAME ,SM.SCREEN_NAME,LM.LGR_NAME"
     end
if @Rpt_Wise=2
    BEGIN
      set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=ALM.Lgr_ID"
      SET @SELSQL="SELECT min(LM.LGR_NAME) AS PARTY,ALM.LGR_NAME AS AGENT,IM.ITEM_NAME AS ITEM ,SM.SCREEN_NAME AS SCREEN,sum(SOD.PENDINGBALES)as PENDINGBALES,min(IGM.ITEM_GRP_NAME) AS ITEMGROUP"
      set @GrpSql=" GROUP BY IM.ITEM_NAME ,SM.SCREEN_NAME,ALM.LGR_NAME"
    END
if @Rpt_Wise=3
    BEGIN
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=CGM.Cust_Grp_Id"
       
    END
if @Rpt_Wise=4
   BEGIN
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_ID"
       SET @SELSQL="SELECT LM.LGR_NAME AS PARTY,min(ALM.LGR_NAME) AS AGENT,IM.ITEM_NAME  AS ITEM ,SM.SCREEN_NAME AS SCREEN,sum(SOD.PENDINGBALES)as PENDINGBALES,min(IGM.ITEM_GRP_NAME) AS ITEMGROUP"
       set @GrpSql=" GROUP BY LM.LGR_NAME ,SM.SCREEN_NAME,IM.ITEM_NAME"
  END
if @Rpt_Wise=5
 BEGIN
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=SM.Screen_ID"
       SET @SELSQL="SELECT LM.LGR_NAME AS PARTY,min(ALM.LGR_NAME) AS AGENT,IM.ITEM_NAME AS ITEM ,SM.SCREEN_NAME AS SCREEN,sum(SOD.PENDINGBALES)as PENDINGBALES,min(IGM.ITEM_GRP_NAME) AS ITEMGROUP"
       set @GrpSql=" GROUP BY LM.LGR_NAME ,IM.Item_NAME,SM.SCREEN_NAME"
  END

if @Rpt_Wise=6
   BEGIN
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IM.Item_ID"
       SET @SELSQL="SELECT LM.LGR_NAME AS PARTY,min(ALM.LGR_NAME) AS AGENT,IM.ITEM_NAME AS ITEM ,SM.SCREEN_NAME AS SCREEN ,sum(SOD.PENDINGBALES)as PENDINGBALES,min(IGM.ITEM_GRP_NAME) AS ITEMGROUP"
       set @GrpSql=" GROUP BY LM.LGR_NAME ,SM.SCREEN_NAME,IM.ITEM_NAME"
  END
if @Rpt_Wise=7
   BEGIN
       set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=IGM.Item_GRP_ID"
       SET @SELSQL="SELECT MIN(LM.LGR_NAME)  AS PARTY,min(ALM.LGR_NAME) AS AGENT,IM.ITEM_NAME AS ITEM ,MIN(SM.SCREEN_NAME)AS SCREEN,sum(SOD.PENDINGBALES)as PENDINGBALES,IGM.ITEM_GRP_NAME AS ITEMGROUP"
       set @GrpSql=" GROUP BY IM.ITEM_NAME,IGM.ITEM_GRP_NAME"
  END



if @Rpt_Type=1
set @TypeSql=" and SOD.PendingBales=0"
if @Rpt_Type=2
set @TypeSql="and SOD.PendingBales>0"
if @Rpt_Type=3
set @TypeSql=""
set @Sql=""
begin
    	SET NOCOUNT ON;
        set @sql= @SELSQL + "
                   from " + @DatabaseName + "Sales_Order SO
                   inner join " + @DatabaseName + "Sales_Order_Detail SOD on SOD.Sal_Order_ID=SO.Sal_Order_ID
                   inner join " + @DatabaseName + "Item_Master IM on IM.Item_ID=SOD.Item_ID
                   inner join " + @DatabaseName + "Item_GROUP_Master IGM on IM.Item_GRP_ID=IGM.Item_GRP_ID
                   left join " + @DatabaseName + "Screen_Master SM on SM.Screen_ID=SOD.Screen_ID
                   inner join " + @DatabaseName + "Ledger_Master LM on LM.Lgr_ID=SO.Lgr_ID
                   inner join " + @DatabaseName + "Ledger_Master ALM on ALM.Lgr_ID=SO.Agent_ID
                   left join " + @DatabaseName + "Customer_Group_Master CGM on CGM.Cust_Grp_ID=LM.Cust_Grp_ID"
                   + @JoinSql +"
                   where SO.Cmp_Code=" + @Cmp_Code + " and SO.Vch_Date between  '" + @FromDate + "' and '" + @ToDate + "'" + @TypeSql + 
                   + @GrpSql                   

                 execute Sp_Executesql @sql
        Print @sql
end




















GO

