/*    
PROC_SALESORDRATESUMM '2','ACC2010_2011.DBO.','01/APR/2010','23/NOV/2010','##1728',1,1,''
*/
CREATE PROCEDURE [dbo].[PROC_SALESORDRATESUMM]
(
  @CMP_CODE AS NVARCHAR(500),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @TEMPTABLE AS NVARCHAR(50),
  @RPT_WISE INT,
  @RPT_TYPE INT,
  @TempTable_ITEMGRP AS NVARCHAR(50)

)
AS
DECLARE @SQL AS NVArchar(4000)
DECLARE @SQL1 AS NVArchar(4000)
DECLARE @TYPESQL AS NVArchar(1000)
DECLARE @JOINSQL AS NVArchar(1000)
DECLARE @SELSQL AS NVArchar(2000)
DECLARE @GRPSQL AS NVArchar(2000)
DECLARE @ITEMGRPJOINSQL AS NVArchar(2000)

set @SQL=""
set @SQL1=""
SET @TYPESQL=""
SET @JOINSQL=""
SET @SELSQL=""
SET @GRPSQL=""
SET @ITEMGRPJOINSQL=""

   BEGIN 
        IF @TempTable_ITEMGRP!="" 
           SET @ITEMGRPJOINSQL=" INNER JOIN "+@TempTable_ITEMGRP +" TT1 ON TT1.CODE=IGM.ITEM_GRP_ID"
   END
BEGIN 
    IF @RPT_WISE=1 
       BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LGR_ID"          
          SET @GRPSQL=" ,PARTY,PARTYCITY "
       END
    ELSE IF @RPT_WISE=2 
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"           
          SET @GRPSQL=" ,AGENT,AGENTCITY"
         END
   ELSE IF @RPT_WISE=3
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=ALM.LGR_ID"           
          SET @GRPSQL=" ,AGENT,AGENTCITY,PARTY ,PARTYCITY"
         END
    ELSE IF @RPT_WISE=4
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=CGM.CUST_GRP_ID"                       
          SET @GRPSQL=" ,CUSTOMERGROUP"
         END
    ELSE IF @RPT_WISE=5
         BEGIN
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"            
           SET @GRPSQL=" ,PARTY ,PARTYCITY"
         END
    ELSE IF @RPT_WISE=6
         BEGIN
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SM.SCREEN_ID"           
           SET @GRPSQL=" ,PARTY ,PARTYCITY"
         END
    ELSE IF @RPT_WISE=7
         BEGIN  
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"            
           SET @GRPSQL=" ,PARTY ,PARTYCITY"
         END
    ELSE IF @RPT_WISE=8
       BEGIN
           SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IGM.ITEM_GRP_ID"            
           SET @GRPSQL=" ,ITEMGROUP"
       END
    ELSE IF @RPT_WISE=9
       BEGIN
           SET @JOINSQL=""            
              SET @GRPSQL=""
       END
ELSE IF @RPT_WISE=10
       BEGIN
            SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"            
            SET @GRPSQL=" ,SALESMAN"
       END
ELSE IF @RPT_WISE=11
       BEGIN
            SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=SAM.SALESMAN_ID"            
           SET @GRPSQL=" ,SALESMAN,AGENT,AGENTCITY"
       END

END
BEGIN
     IF @RPT_TYPE=1
       SET @TYPESQL=" AND  SOD.PENDINGBALES>0"
     ELSE IF @RPT_TYPE=2
       SET @TYPESQL=""
END
BEGIN
	set @SQL= "  SELECT MIN(ITEM_NAME) AS ITEM_NAME,MIN(ITEMGROUP) AS ITEMGROUP,MIN(SCREEN_NAME) AS SCREEN_NAME, sum(BALES) as BALES,SUM(DELIVEREDBALES)AS DELIVEREDBALES,SUM(CANCELBALES) AS CANCELBALES,SUM(PENDINGBALES) AS PENDINGBALES,MAX(RATE)AS RATE,MAX(PARTY)AS PARTY,MAX(PARTYCITY)AS PARTYCITY
                 ,MAX(AGENT)AS AGENT,MAX(AGENTCITY)aS AGENTCITY,MAX(CUSTOMERGROUP)AS CUSTOMERGROUP,MAX(SALESMAN) AS SALESMAN,MAX(CMP_ALIAS)AS CMP_ALIAS  FROM (
                  SELECT IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,SM.SCREEN_NAME,SOD.BALES,SOD.DELIVEREDBALES AS DELIVEREDBALES,0 AS CANCELBALES,SOD.PENDINGBALES AS PENDINGBALES,SOD.RATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                 ,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,SAM.SALESMAN_NAME AS SALESMAN,CMP.CMP_ALIAS
                 FROM "+@DATABASENAME+"SALES_ORDER SO 
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                 inner JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID 
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID    
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID        
                 LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID                 
                 LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
                 INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
                 "+@JOINSQL+"
                 "+@ITEMGRPJOINSQL+"
                 WHERE SO.CMP_CODE in("+@CMP_CODE +") AND SO.VCH_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"' "+@TYPESQL+"                    
            "   
SET @SQL1="    
                 UNION ALL
                 SELECT IM.ITEM_NAME,IGM.ITEM_GRP_NAME AS ITEMGROUP,SM.SCREEN_NAME,0 as BALES,0 AS DELIVEREDBALES,SOCD.CANCELBALES,0 AS PENDINGBALES,SOD.RATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                 ,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,CGM.CUST_GRP_NAME AS CUSTOMEGROUP,SAM.SALESMAN_NAME AS SALESMAN,CMP.CMP_ALIAS
                 FROM "+@DATABASENAME+"SALESORDER_CANCELLATION_DETAIL SOCD
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CMP_CODE=SOCD.CMP_CODE AND SO.CONFNO=SOCD.CONFNO AND SO.FYEAR=SOCD.FYEAR 
                 INNER JOIN "+@DATABASENAME+"SALES_ORDER_DETAIL SOD ON SOD.SAL_ORDER_ID=SO.SAL_ORDER_ID AND SOCD.ITEM_ID=SOD.ITEM_ID AND SOCD.SCREEN_ID=SOD.SCREEN_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
                 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                 inner JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SOD.SCREEN_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SO.LGR_ID
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SO.AGENT_ID 
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID    
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID        
                 LEFT JOIN "+@DATABASENAME+"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID                 
                 LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
                 INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SO.CMP_CODE
                 "+@JOINSQL+"
                 "+@ITEMGRPJOINSQL+"
                 WHERE SO.CMP_CODE in("+@CMP_CODE +") AND SO.VCH_DATE BETWEEN  '"+@FROMDATE+"' AND '"+@TODATE+"'    "+@TYPESQL+"
) AS DETAIL
GROUP BY ITEM_NAME,SCREEN_NAME,RATE,CMP_ALIAS
"+@GRPSQL+"

" 
END
EXEC (@SQL +@SQL1)
PRINT @SQL
PRINT @SQL1




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESQUERY]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/*
-- =============================================
-- AUTHOR:		SUMIT
-- ALTER_DATE: 02-08-2013
-- DESCRIPTION:	SP FOR SALESQUERY..RETRIVE SALES DATA
--REPORT_NAME : Sales_Purchase.rpt
-- =============================================
PROC_SALESQUERY 1,'ACC2014_2015.DBO.',5000,'01/APR/2014','31/MAR/2015',1
*/
CREATE PROCEDURE [dbo].[PROC_SALESQUERY] 
(
	@CMP_CODE NVARCHAR(20),
	@DATABASENAME NVARCHAR(50),
	@TOTALAMT NVARCHAR(20),
	@FROMDATE NVARCHAR(20),
	@TODATE NVARCHAR(20),
	@RPTTYPE INT
)
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @MAINSQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @MAINENDSQL AS NVARCHAR(4000)

SET @SQL=""
SET @MAINSQL=""
SET @SQL1=""
SET @MAINENDSQL=""

--IF @RPTTYPE = 1
--	SET @MAINSQL=" SELECT SUM((SALEAMOUNT)-(RETURNAMOUNT)) AS TOTALAMT,MAX(CMPCODE) AS CMPCODE,PARTY,SUM(SALEAMOUNT) AS SALEAMOUNT,SUM(RETURNAMOUNT) AS RETURNAMOUNT,
--		MAX(ADD1) AS ADD1,MAX(ADD2) AS ADD2,MAX(ADD3) AS ADD3,
--		MAX(CITY) AS CITY,MAX(DISTRICT) AS DISTRICT,MAX(STATE) AS STATE,MAX(PANNO) AS PANNO  
--		FROM (" 

BEGIN
	
	SET NOCOUNT ON;
	
	IF @RPTTYPE = 1
	BEGIN
	SET @MAINSQL=" SELECT SUM((SALEAMOUNT)-(RETURNAMOUNT)) AS TOTALAMT,MAX(CMPCODE) AS CMPCODE,PARTY,SUM(SALEAMOUNT) AS SALEAMOUNT,SUM(RETURNAMOUNT) AS RETURNAMOUNT,
		ISNULL(MAX(ADD1),'') AS ADD1,ISNULL(MAX(ADD2),'') AS ADD2,ISNULL(MAX(ADD3),'') AS ADD3,
		ISNULL(MAX(CITY),'') AS CITY,ISNULL(MAX(DISTRICT),'') AS DISTRICT,ISNULL(MAX(STATE),'') AS STATE,
		MAX(PANNO) AS PANNO  ,PARTYID
		FROM (" 

	SET @SQL= " SELECT ''AS TOTALAMT, 
				MAX(SI.CMP_CODE) AS CMPCODE,
				LM.LGR_NAME AS PARTY,SUM(CONVERT(FLOAT,SI.SAL_INV_NETTOTAL)) AS SALEAMOUNT,'' AS RETURNAMOUNT,
				MAX(LM.LGR_ADD1) AS ADD1,MAX(LM.LGR_ADD2) AS ADD2,MAX(LM.LGR_ADD3)AS ADD3,
				MAX(CM.CITY_NAME)AS CITY,MAX(CM.CITY_DISTRICT) AS DISTRICT,
				MAX(SM.STATE_NAME) AS STATE,MAX(LM.LGR_PANO) AS PANNO,ISNULL(LM.LGR_ID,0) AS PARTYID
				FROM "+@DATABASENAME+" SALES_INVOICE SI
				INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.LGR_ID = LM.LGR_ID
				LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
				LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID = SM.STATE_ID		
				WHERE  SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND SI.CMP_CODE IN ("+@CMP_CODE+")
				GROUP BY LM.LGR_NAME,LM.LGR_ID		 
			
	UNION ALL"

SET @SQL1 = " SELECT ''AS TOTALAMT,MAX(SRM.CMP_CODE) AS  CMPCODE,
			LM.LGR_NAME AS PARTY,'' AS SALEAMOUNT,SUM(SRM.ROUNDEDAMOUNT) AS RETURNAMOUNT,
			''AS ADD1,'' AS ADD2,''AS ADD3,''AS CITY,'' AS DISTRICT,'' AS STATE,'' AS PANNO,ISNULL(LM.LGR_ID,0) AS PARTYID 
			FROM "+@DATABASENAME+" SALES_RETURN_MASTER SRM
			INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SRM.LGR_ID = LM.LGR_ID
			GROUP BY LM.LGR_NAME,LM.LGR_ID "

SET @MAINENDSQL=") AS A
				GROUP BY PARTY,PARTYID 
				HAVING SUM((SALEAMOUNT)-(RETURNAMOUNT)) >="+@TOTALAMT+" ORDER BY PARTY,PARTYID "
	END
	
ELSE IF @RPTTYPE = 2
BEGIN
SET @MAINSQL=" SELECT SUM((PURCHASEAMOUNT)-(RETURNAMOUNT)) AS TOTALAMT,MAX(CMPCODE) AS CMPCODE,PARTY,
		SUM(PURCHASEAMOUNT) AS PURCHASEAMOUNT,SUM(RETURNAMOUNT) AS RETURNAMOUNT,
		ISNULL(MAX(ADD1),'') AS ADD1,ISNULL(MAX(ADD2),'') AS ADD2,ISNULL(MAX(ADD3),'') AS ADD3,
		ISNULL(MAX(CITY),'') AS CITY,ISNULL(MAX(DISTRICT),'') AS DISTRICT,ISNULL(MAX(STATE),'') AS STATE,
		MAX(PANNO) AS PANNO,PARTYID 
		FROM ("

SET @SQL= " SELECT '' AS TOTALAMT,MAX(CMP_CODE) AS CMPCODE,LM.LGR_NAME AS PARTY,
			SUM(NETTOTAL) AS PURCHASEAMOUNT,'' AS RETURNAMOUNT,
			MAX(LM.LGR_ADD1) AS ADD1,MAX(LM.LGR_ADD2) AS ADD2,MAX(LM.LGR_ADD3)AS ADD3,
			MAX(CM.CITY_NAME)AS CITY,MAX(CM.CITY_DISTRICT) AS DISTRICT,
			MAX(SM.STATE_NAME) AS STATE,MAX(LM.LGR_PANO) AS PANNO,ISNULL(LM.LGR_ID,0) AS PARTYID
			FROM "+@DATABASENAME+" PURCHASEINVOICE PI
			INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON PI.LGR_ID = LM.LGR_ID
			LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON LM.CITY_ID = CM.CITY_ID
			LEFT JOIN  "+@DATABASENAME+" STATE_MASTER SM ON LM.STATE_ID = SM.STATE_ID		
			WHERE  PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE IN ("+@CMP_CODE+")
			GROUP BY LM.LGR_NAME,LM.LGR_ID	
UNION ALL"

SET @SQL1 = " SELECT '' AS TOTALAMT,MAX(CMP_CODE) AS CMPCODE,LM.LGR_NAME AS PARTY,
			0 AS PURCHASEAMOUNT,SUM(ROUNDEDAMOUNT) AS RETURNAMOUNT,
			''AS ADD1,'' AS ADD2,''AS ADD3,''AS CITY,'' AS DISTRICT,'' AS STATE ,'' AS PANNO,ISNULL(LM.LGR_ID,0) AS PARTYID
			FROM "+@DATABASENAME+" PURCHASE_RETURN_MASTER PRM
			INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON PRM.LGR_ID = LM.LGR_ID
			GROUP BY LM.LGR_NAME,LM.LGR_ID "

SET @MAINENDSQL=") AS A
				GROUP BY PARTY,PARTYID 
				HAVING SUM((PURCHASEAMOUNT)-(RETURNAMOUNT)) >="+@TOTALAMT+" ORDER BY PARTY,PARTYID"
END

EXEC (@MAINSQL+@SQL+@SQL1+@MAINENDSQL)
PRINT @MAINSQL
PRINT @SQL
PRINT @SQL1
PRINT @MAINENDSQL
END






















GO

