CREATE PROCEDURE [dbo].[PROC_SALESREG_COTTON]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(20),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL =""
BEGIN
          SELECT @SQL=" SELECT CSM.COT_SAL_INV_BILL_NO AS BILLNO,CSM.COT_SAL_INV_VDATE AS DATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                        ,FTM.FINISHTYPE_NAME ,CSD.THAN,CSD.RATE,CSD.AMOUNT
                        FROM "+@DATABASENAME +"COTTON_SALESINVOICE_MASTER CSM
                        INNER JOIN "+@DATABASENAME +"COTTON_SALESINVOICE_DETAIL CSD ON CSD.COT_SAL_INV_ID=CSM.COT_SAL_INV_ID
                        INNER JOIN "+@DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=CSM.LGR_ID
                        LEFT JOIN "+@DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                        INNER JOIN "+@DATABASENAME +"FINISHTYPE_MASTER FTM ON FTM.FINISHTYPE_ID=CSD.FINISHTYPE_ID
                        WHERE CSM.CMP_CODE IN("+@CMP_CODE +") AND CSM.COT_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"'  AND '"+@TODATE+"'
                      "
EXECUTE SP_EXECUTESQL @SQL

END




















