SET @ORDERBYSQL = "IG.ITEM_GRP_NAME,ISNULL(IG.ITEM_GRP_ID,0),"
END 

ELSE IF @RPT_WISE IN (16)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IG.ITEM_GRP_ID=TT.CODE"
SET @ORDERBYSQL = "IG.ITEM_GRP_NAME,ISNULL(IG.ITEM_GRP_ID,0),IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0),"
END 

ELSE IF @RPT_WISE = 7
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON CGM.CUST_GRP_ID=TT.CODE"
SET @ORDERBYSQL = "CGM.CUST_GRP_NAME,ISNULL(CGM.CUST_GRP_ID,0),"
END 

ELSE IF @RPT_WISE IN (8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON PCM.CITY_ID=TT.CODE"
SET @ORDERBYSQL = "PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),"
END

ELSE IF @RPT_WISE IN (17)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON PCM.CITY_ID=TT.CODE"
SET @ORDERBYSQL = "PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END 

ELSE IF @RPT_WISE = 9
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.STATE_ID=TT.CODE"
SET @ORDERBYSQL = "SM.STATE_NAME,ISNULL(SM.STATE_ID,0),"
END 

ELSE IF @RPT_WISE = 21
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
SET @ORDERBYSQL = ""
END 

ELSE IF @RPT_WISE = 28
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON IM.HSN_ID=TT.CODE"
SET @ORDERBYSQL = "HSN.HSN_NAME,ISNULL(HSN.HSN_ID,0),"
END 

END

BEGIN
IF @SELALL = 1
SET @SELECTED=""
END
begin
SET @SQL="
SELECT SI.SAL_INV_ID,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME,
AGM.LGR_NAME AS AGENTNAME,SID.SAL_INV_BALENO AS BALENO,
(CASE WHEN SID.SERIALNO IS NULL THEN SID.SAL_INV_BALENO ELSE SID.SERIALNO END) AS SERIALNO,IM.ITEM_NAME AS ITEM,
SID.SAL_INV_PCS AS PCS,"+@QUANTITYSQL+",SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,
SAL_INV_NETTOTAL AS NETTOTAL,PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,
(SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) as ADDLESSTOTAL,COMP.CMP_NAME,COMP.CMP_ADD1,
COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,COMP.CMP_MOBILE,
COMP.CMP_FAX,SC.SCREEN_NAME AS SCREEN,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,
COMP.CMP_ALIAS,SI.NET_SNET,IG.ITEM_GRP_NAME,SID.ITEM_CUT,SAL_INV_LRNO,ISNULL(SAL_INV_LRDATE,'') AS SAL_INV_LRDATE,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(AGM.LGR_ID,0) AS AGENTID,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(UM.UNIT_ID,0) AS UNITID,ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,ISNULL(SC.SCREEN_ID,0) AS SCREENID,
ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,ISNULL(SM.STATE_ID,0) AS STATEID,ISNULL(S_M.SALESMAN_ID,0) AS SALESMANID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,ISNULL(IG.ITEM_GRP_ID,0) AS ITEMGRPID,
ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(TM.TRANSPORT_NAME,0) AS TRANSPORT,ISNULL(CONFNO,0) AS CONFNO,
(SI.Sal_Inv_GrossTotal + SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
isnull(SI.SAL_INV_ADD3,0) AS CGST, ISNULL(SI.SAL_INV_ADD4,0) as SGST ,ISNULL(SI.SAL_INV_ADD5,0) AS IGST ,SI.SAL_INV_NETTOTAL AS NETTOTAL,HSN.HSN_ID,HSN.HSN_NAME,SID.REMARK"
SET @SQL1 = "
FROM "+ @DATABASENAME+ "SALES_INVOICE SI
INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG 
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
INNER JOIN " + @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN " + @DATABASENAME +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN  " + @DATABASENAME +"COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN  " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  " + @DATABASENAME +"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
LEFT JOIN  " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN  " + @DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID     
LEFT JOIN  " + @DATABASENAME +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AGM.SALESMAN_ID
LEFT JOIN  " + @DATABASENAME +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN  "+ @DATABASENAME +"ITEM_GROUP_MASTER IG ON IM.ITEM_GRP_ID =IG.ITEM_GRP_ID
LEFT JOIN  "+ @DATABASENAME +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID =SI.TRANSPORT_ID 
LEFT JOIN  "+ @DATABASENAME +"HSN_MASTER HSN ON HSN.HSN_ID =IM.HSN_ID 
" + @SELECTED +"
WHERE "+@ID+" SI.CMP_CODE IN("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
AND SI.FLAG in ('S','MS','GSN') /*AND SI.SAL_INV_TYPE IN('F','FO') " + @NET_SNETSQL + " */
ORDER BY "+@ORDERBYSQL+"CONVERT(INT,SI.SAL_INV_BILL_NO),SI.SAL_INV_VDATE,SID.SAL_INV_DTL_ID"      
END	
PRINT (@SQL+@SQL1)
EXEC (@SQL+@SQL1)





















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESREGISTER_CASH_CREDIT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*
 PROC_SALESREGISTER_CASH_CREDIT '01/Apr/2010', N'25/Oct/2014',  N'Acc2012_2013.Dbo.',N'2', N'##5832', 0,29,14,1,3
*/
CREATE PROCEDURE [dbo].[PROC_SALESREGISTER_CASH_CREDIT]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
	@SelAll  int,
    @HeadId nvarchar(20),
    @Rpt_Wise int,
    @CONVERSION int,
    @RPT_TYPE INT
    
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE @SQLRPT_TYPE AS NVARCHAR(1000)
SET @SQL=""
SET @SELECTED=""
SET @QUANTITYSQL=""
SET @SQLRPT_TYPE=""
set nocount on;
BEGIN    
   SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "
   
   IF @CONVERSION=1 
   SET @QUANTITYSQL="
                    (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
                     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "

END
BEGIN
   IF @RPT_TYPE=1 
       SET @SQLRPT_TYPE=" AND SI.FLAG='CRS'"
   ELSE IF @RPT_TYPE=2 
       SET @SQLRPT_TYPE=" AND SI.FLAG='CS'"
   ELSE IF @RPT_TYPE=3
       SET @SQLRPT_TYPE=" AND SI.FLAG='S' AND SI.SAL_INV_TYPE='E'"
END

BEGIN
	IF @SelAll=0
	  BEGIN 
	   IF @Rpt_Wise in(1,2)
                 BEGIN
				  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
                 END
       ELSE IF @Rpt_Wise in (3,4,5)
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON S_M.SALESMAN_ID=TT.CODE"
                END  
	   ELSE IF @Rpt_Wise=6
                 BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
                 END 
      ELSE IF @Rpt_Wise in(7,8)
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON CGM.CUST_GRP_ID=TT.CODE"
                END 
	   ELSE IF @Rpt_Wise in (9,10)
                 BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PCM.CITY_ID=TT.CODE"
                 END 
       ELSE IF @Rpt_Wise=11
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SID.ITEM_ID=TT.CODE"
                END 
       ELSE IF @Rpt_Wise in(12,13)
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON IG.Item_Grp_Id=TT.CODE"
                END
      ELSE IF @Rpt_Wise in(14,15)
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON ITM.ITEM_TYPE_ID=TT.CODE"
                END
      ELSE IF @Rpt_Wise=16
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SC.SCREEN_ID=TT.CODE"
                END 
     ELSE IF @Rpt_Wise=17
                BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SM.STATE_ID=TT.CODE"
                END 
	 ELSE IF @Rpt_Wise=18
                 BEGIN
				   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
                 END 	   
	   
	   
	    	          
	END
SET @SQL="
	 SELECT SI.SAL_INV_ID ,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME,AGM.Lgr_NAME AS AGENTNAME 
     ,SID.SAL_INV_BALENO AS BALENO,(CASE WHEN SID.SERIALNO IS NULL THEN SID.SAL_INV_BALENO ELSE SID.SERIALNO END) AS SERIALNO,
     IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,"+@QUANTITYSQL+"      
     ,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL,
     PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,(SI.Sal_Inv_AddTotal-SI.Sal_Inv_LessTotal) as ADDLESSTOTAL,
     SC.SCREEN_NAME AS SCREEN,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,IG.Item_Grp_Name,ITM.ITEM_TYPE_NAME,SID.INTYPE,SID.COLOR_CHART
,STM.CITY_NAME AS STATION_NAME
     FROM "+ @DatabaseName+ "SALES_INVOICE SI
     INNER JOIN  "+ @DatabaseName +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
     INNER JOIN " + @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
     LEFT JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
     LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
     LEFT JOIN " + @DatabaseName +"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
     LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
     LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID     
     LEFT JOIN " + @DatabaseName +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AgM.SALESMAN_ID
     LEFT JOIN " + @DatabaseName +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	 LEFT JOIN "+ @DatabaseName +" ITEM_GROUP_MASTER IG ON IM.ITEM_GRP_ID =IG.ITEM_GRP_ID 
     LEFT JOIN "+ @DatabaseName +" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID =IM.ITEM_TYPE_ID 
	 LEFT JOIN "+ @DatabaseName +" CITY_MASTER STM ON STM.CITY_ID=SI.STATION_ID
     " + @SELECTED +"     
     WHERE SI.SAL_ACCID="+@HeadId+" AND SI.Cmp_Code IN("+ @Cmp_Code +") and  SI.SAL_INV_VDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'     
     " + @SQLRPT_TYPE +"
     ORDER BY SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO),SID.SAL_INV_DTL_ID"      
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESREGISTER_SORT]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















-- =============================================
-- AUTHOR:		<SUMIT>
-- ALTER_DATE: <12/AUG/2013>
-- DESCRIPTION:	<SP FOR SALESREGISTER_SORT>
--REPORT NAME: <SALESREGISTER_SORT.RPT>
--PROC_SALESREGISTER_SORT '01/APR/2012', N'31/MAR/2013',  N'ACC2012_2013.DBO.',N'1', N'##700', 1,4457,1,1
-- =============================================
CREATE PROCEDURE [dbo].[PROC_SALESREGISTER_SORT]

(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),    
@DATABASENAME NVARCHAR(50),
@CMP_CODE NVARCHAR(100),    
@TEMPTABLE NVARCHAR(20),
@SELALL  INT,
@HEADID NVARCHAR(20),
@RPT_WISE INT,  
@NET_SNET INT   
)

AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(1000)
--DECLARE @QUANTITYSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SELECTED=""
--SET @QUANTITYSQL=""
SET @NET_SNETSQL=""
SET @ORDERBYSQL=""

SET NOCOUNT ON;


BEGIN
IF @NET_SNET=1  /* SNET BILL*/
SET @NET_SNETSQL=" AND SI.NET_SNET='S.NET'"      
ELSE IF @NET_SNET=2 /*WITHOUT SNET BILL*/
SET @NET_SNETSQL=" AND SI.NET_SNET !='S.NET'"          
ELSE IF @NET_SNET=3 /*ALL*/
SET @NET_SNETSQL=""      
END 

BEGIN 
IF @RPT_WISE IN (1,7,11)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @ORDERBYSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),"
	IF @RPT_WISE IN (7)
	BEGIN
		SET @ORDERBYSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
	END
	ELSE IF @RPT_WISE IN (11)
	BEGIN
		SET @ORDERBYSQL="AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),"
	END
END 
ELSE IF @RPT_WISE =2
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @ORDERBYSQL="LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
END 
ELSE IF @RPT_WISE IN (3,9)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON S_M.SALESMAN_ID=TT.CODE"
SET @ORDERBYSQL="S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),"
	IF @RPT_WISE IN (9)
	BEGIN
		SET @ORDERBYSQL="S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),AGM.LGR_NAME,ISNULL(AGM.LGR_ID,0),"
	END
END 
ELSE IF @RPT_WISE = 4
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON CGM.CUST_GRP_ID=TT.CODE"
SET @ORDERBYSQL="CGM.CUST_GRP_NAME,ISNULL(CGM.CUST_GRP_ID,0),"
END 
ELSE IF @RPT_WISE IN (5,8)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON PCM.CITY_ID=TT.CODE"
SET @ORDERBYSQL="PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),"
	IF @RPT_WISE IN (8)
	BEGIN
		SET @ORDERBYSQL="PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0),LM.LGR_NAME,ISNULL(LM.LGR_ID,0),"
	END
END 
ELSE IF @RPT_WISE = 6
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.STATE_ID=TT.CODE"
SET @ORDERBYSQL="SM.STATE_NAME,ISNULL(SM.STATE_ID,0),"
END 
ELSE IF @RPT_WISE = 10
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
END 


BEGIN
IF @SELALL = 1
SET @SELECTED=""
END

SET @SQL="
SELECT SI.SAL_INV_ID,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME,
AGM.LGR_NAME AS AGENTNAME,SAL_INV_GROSSTOTAL,SAL_INV_NETTOTAL AS NETTOTAL,PCM.CITY_NAME AS PARTYCITY,
ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,
((SI.SAL_INV_ADDTOTAL-SI.SAL_INV_LESSTOTAL)+SI.SAL_INV_ROUNDOFF) AS ADDLESSTOTAL,COMP.CMP_NAME,COMP.CMP_ADD1,
COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,COMP.CMP_MOBILE,
COMP.CMP_FAX,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,SI.NET_SNET,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(AGM.LGR_ID,0) AS AGENTID,ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,ISNULL(SM.STATE_ID,0) AS STATEID,ISNULL(S_M.SALESMAN_ID,0) AS SALESMANID,
ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID

FROM "+ @DATABASENAME+ "SALES_INVOICE SI     
INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID     
LEFT JOIN  " + @DATABASENAME +"COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN  " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     
LEFT JOIN  " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN  " + @DATABASENAME +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID     
LEFT JOIN  " + @DATABASENAME +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AGM.SALESMAN_ID
LEFT JOIN  " + @DATABASENAME +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID	 
" + @SELECTED +"
WHERE SI.SAL_ACCID="+@HEADID+" AND SI.CMP_CODE IN("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
AND SI.FLAG='S' " + @NET_SNETSQL + " 
ORDER BY "+@ORDERBYSQL+"CONVERT(INT,SI.SAL_INV_BILL_NO),SI.SAL_INV_VDATE"      
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL

















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESREGISTERGST]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















-- =============================================
-- Author:		<SHUBHAM RAVAL>
-- ALTER date: <12.08.2017>
-- Description:	<GST SALE REGISTER>
-- =============================================
/*
PROC_SALESREGISTERGST N'01/Apr/2018', N'30/Mar/2019', N'Acc2018_2019.Dbo.', N'1', N##6476', 0, N'8963', 2, 5

SELECT * FROM Acc2017_2018.Dbo.LEDGER_MASTER WHERE LGR_NAME LIKE 'SALES%'
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'

*/
CREATE PROCEDURE [dbo].[PROC_SALESREGISTERGST]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
	@SelAll  int,
    @HeadId nvarchar(20),
    @Rpt_Wise int,
    @Register_Dealer int
    
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @SELECTED1 AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE @REG_DEALERSQL AS NVARCHAR(4000)
DECLARE  @ID AS NVARCHAR(1000)
DECLARE  @ID1 AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @SELECTED=""
SET @SELECTED1=""
SET @QUANTITYSQL=""
SET @NET_SNETSQL=""
SET @ID=""
SET @ID1=""

set nocount on;

BEGIN
		IF @Register_Dealer=1 

		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='Registered Dealer'"
 
		else IF @Register_Dealer=2

		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='Unregistred Dealer' "  

		else IF @Register_Dealer=3
	
		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE='Composition Dealer' " 
		else IF @Register_Dealer=4
	
		set @REG_DEALERSQL=" AND LM.REGISTER_DEALER_TYPE= 'Export Dealer' " 
		else 
	
		set @REG_DEALERSQL=" " 
		

END

BEGIN    
   SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "     
END

BEGIN
	IF @SelAll=0
	  BEGIN 
		IF @Rpt_Wise in (1)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			  SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (2)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
			     SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
			 END 		
		ELSE IF @Rpt_Wise = 4
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
			   SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.Job_Sal_Inv_Bill_No=TT.CODE"
			 END 
			 ELSE IF @Rpt_Wise = 3
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			    SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			 END 
			 ELSE IF @Rpt_Wise =5
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SM.STATE_ID=TT.CODE"
			    SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SM.STATE_ID=TT.CODE"
			 END 
	END
	ELSE
 BEGIN 
SET @SELECTED=" "
			  
END 
END
	BEGIN
	IF @HeadId<>0
	  BEGIN
			   SET @ID=" SI.Sal_AccID="+@HeadId+" AND "
	  END
	END
	
	BEGIN
	IF @HeadId<>0
	  BEGIN
			   SET @ID1=" SI.JOB_SALACCID="+@HeadId+" AND "
	  END
	END

	BEGIN
	
	
	
SET @SQL="
	 SELECT SI.SALES_ALIAS,SI.Sal_Inv_Id,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME
,ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,
ISNULL(SM.State_Code,0) AS STATECODE,
ISNULL(HSM.Hsn_Name,0) AS HSNCODE,
SID.SAL_INV_BALENO AS BALENO,
SID.SAL_INV_PCS AS PCS, 
SID.SAL_INV_QTY   AS QUANTITY ,
SI.Sal_Inv_GrossTotal AS GROSSAMT,
(SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) as ADDLESSTOTAL,
(SI.Sal_Inv_GrossTotal + SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SI.SAL_INV_ADD3,0) 
	    ELSE 0 END) AS CGST,		(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SI.SAL_INV_ADD4,0)
        ELSE 0 END) AS SGST ,(CASE WHEN VATR.ADDTAX1EFFECTFIELD ='ADD 5' THEN ISNULL(SI.SAL_INV_ADD5,0)
        ELSE 0 END) AS IGST ,SI.SAL_INV_NETTOTAL AS NETTOTAL,AGM.Lgr_NAME AS AGENTNAME 
     ,(CASE WHEN SID.SERIALNO IS NULL THEN SID.SAL_INV_BALENO ELSE SID.SERIALNO END) AS SERIALNO,
     IM.ITEM_NAME AS ITEM,SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,
     PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,(SI.Sal_Inv_AddTotal-( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)))- ISNULL(SI.SAL_INV_LESS5,0) as ADDLESSTOTAL,
     COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
     COMP.CMP_MOBILE,COMP.CMP_FAX,SC.SCREEN_NAME AS SCREEN,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,SI.NET_SNET,
	IG.Item_Grp_Name,ISNULL(SI.SAL_INV_LESS5,0) AS SCHEME,ISNULL(SI.SAL_INV_LESS5_SET,0) AS SCHEMEPER,SI.SAL_INV_ROUNDOFF AS ROFF,ISNULL(SI.SAL_INV_ADD3_SET,0) as ADDPER3,ISNULL(SI.SAL_INV_ADD4_SET,0)as ADDPER4,ISNULL(SI.SAL_INV_ADD5_SET,0)as ADDPER5,SI.FLAG
     FROM "+ @DatabaseName+ "SALES_INVOICE SI
     INNER JOIN  "+ @DatabaseName +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
     INNER JOIN " + @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
     LEFT JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
     LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
     LEFT JOIN " + @DatabaseName +"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
     LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
     LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID     
	left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
	LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
     LEFT JOIN " + @DatabaseName +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AgM.SALESMAN_ID
     LEFT JOIN " + @DatabaseName +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	 left join "+ @DatabaseName +" Item_Group_Master IG on IM.Item_Grp_Id =IG.Item_Grp_Id 
     " + @SELECTED +"
     WHERE "+@ID+"   SI.Cmp_Code IN("+ @Cmp_Code +") and  SI.SAL_INV_VDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
     and SI.FLAG IN ('S','JS','GSN','MS')
     "+@REG_DEALERSQL+"
	-- "+@NET_SNETSQL+"
     
     "
     SET @SQL1=" union all  SELECT SI.SALES_ALIAS,SI.Job_Sal_Inv_Id as Sal_Inv_Id,SI.Job_Sal_Inv_Bill_No AS BILLNO,SI.Job_Sal_Inv_VDate AS VDATE,LM.LGR_NAME AS PARTYNAME
,ISNULL(LM.GSTINNO,'') AS PARTYGSTNO,ISNULL(SM.State_Code,0) AS STATECODE,ISNULL(HSM.Hsn_Name,0) AS HSNCODE,''  AS BALENO,'' AS PCS, 
 sid.QTY AS QUANTITY ,SI.TOTAL AS GROSSAMT,
(SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) as ADDLESSTOTAL,
(SI.TOTAL + SI.SAL_INV_ADD1 + SI.SAL_INV_ADD2 -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) AS TAXABLEAMT,
(CASE WHEN VATR.EFFECTFIELD ='ADD 3' THEN ISNULL(SI.SAL_INV_ADD3,0) ELSE 0 END) AS CGST,
(CASE WHEN VATR.ADDTAXEFFECTFIELD ='ADD 4' THEN ISNULL(SI.SAL_INV_ADD4,0)ELSE 0 END) AS SGST ,
(CASE WHEN VATR.AddTax1EffectField ='ADD 5' THEN ISNULL(SI.SAL_INV_ADD5,0)ELSE 0 END) AS IGST ,SI.NETAMT AS NETTOTAL,
AGM.Lgr_NAME AS AGENTNAME ,SID.SrNo AS SERIALNO,IM.ITEM_NAME AS ITEM,SID.Amount AS AMOUNT,SID.Rate AS RATE,
     PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,(SI.AddTotal-( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)))- ISNULL(SI.SAL_INV_LESS5,0) as ADDLESSTOTAL,
     COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
     COMP.CMP_MOBILE,COMP.CMP_FAX,'' AS SCREEN,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,'' as NET_SNET,
	IG.Item_Grp_Name,ISNULL(SI.SAL_INV_LESS5,0) AS SCHEME,ISNULL(SI.SAL_INV_LESS5_SET,0) AS SCHEMEPER,SI.Roff AS ROFF,ISNULL(SI.SAL_INV_ADD3_SET,0) as ADDPER3,ISNULL(SI.SAL_INV_ADD4_SET,0)as ADDPER4,ISNULL(SI.SAL_INV_ADD5_SET,0)as ADDPER5 , 'JS' AS FLAG
     FROM "+ @DatabaseName+ "Job_SalesInvoice_Master SI
	INNER JOIN  "+ @DatabaseName +"Job_SalesInvoice_Detail SID ON SID.Job_Sal_Inv_Id=SI.Job_Sal_Inv_Id 
     INNER JOIN " + @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
     LEFT JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
     LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
--   LEFT JOIN " + @DatabaseName +"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
     LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
     LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID     
	left JOIN " + @DatabaseName +" VATCATEGORYMASTER VATR ON  VATR.DOCNO = SI.VATTYPE_ID
	LEFT JOIN " + @DatabaseName +" Hsn_Master HSM ON HSM.Hsn_Id=IM.Hsn_Id
     LEFT JOIN " + @DatabaseName +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AgM.SALESMAN_ID
     LEFT JOIN " + @DatabaseName +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	 left join "+ @DatabaseName +" Item_Group_Master IG on IM.Item_Grp_Id =IG.Item_Grp_Id 
    " + @SELECTED1 +"
     WHERE "+@ID1+"  SI.Cmp_Code IN("+ @Cmp_Code +") and  SI.Job_Sal_Inv_VDate BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
  

	    "+@REG_DEALERSQL+"
     order by BILLNO,VDATE
"       
END	
     
     
     
     

PRINT @SQL
PRINT @SQL1
EXEC(@SQL+@SQL1)


















GO

