-- =============================================
-- Author:		<SHUBHAM RAVAL>
-- ALTER date: <12.08.2017>
-- Description:	<GST SALE REGISTER>
-- =============================================
/*
PROC_SALESREGISTERGSTNEW '01/Apr/2021', N'04/jun/2022',  N'Acc2021_2022.Dbo.',N'1', N'##4904', 0,8963,3
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'

*/
CREATE PROCEDURE [dbo].[PROC_SALESREGISTERGSTNEW]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
	@SelAll  int,
    @HeadId nvarchar(20),
    @Rpt_Wise int    
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL2 AS NVARCHAR(3999)
DECLARE @SQL3 AS NVARCHAR(3999)
DECLARE @SQL4 AS NVARCHAR(3999)
DECLARE @SQL5 AS NVARCHAR(3999)


DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @SELECTED1 AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)
DECLARE  @ID AS NVARCHAR(1000)
DECLARE  @ID1 AS NVARCHAR(1000)



SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""

SET @SELECTED=""
SET @SELECTED1=""
SET @QUANTITYSQL=""
SET @NET_SNETSQL=""
SET @ID=""
SET @ID1=""


set nocount on;

BEGIN    
   SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "     
END

BEGIN
	IF @SelAll=0
	  BEGIN 
		IF @Rpt_Wise in (1)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			  SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (2)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
			   SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
			 END 		
		ELSE IF @Rpt_Wise = 3
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
			   SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON SI.JOB_SAL_INV_BILL_NO=TT.CODE"
			 END 
			 ELSE IF @Rpt_Wise = 4
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON IM.HSN_ID =TT.CODE"
			   SET @SELECTED1=" INNER JOIN " + @TempTable + " TT ON IM.HSN_ID =TT.CODE"
			   
			 END 
	END
	
	BEGIN
	IF @HeadId<>0
	  BEGIN
			   SET @ID=" SI.Sal_AccID="+@HeadId+" AND "
			   SET @ID1=" SI.JOB_SALACCID="+@HeadId+" AND "
	  END
	END

	
SET @SQL=" SELECT *,
(SAL_INV_ADD1 + SAL_INV_ADD2 -( ISNULL(SAL_INV_LESS1,0) + ISNULL(SAL_INV_LESS2,0) + ISNULL(SAL_INV_LESS3,0) + ISNULL(SAL_INV_LESS4,0)+ ISNULL(SAL_INV_LESS5,0))) AS ADDLESSTOTAL,
SAL_INV_AMOUNT AS GROSS_TOTAL,
((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL)ITEM_DISCOUNT ,(SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))ITEM_TAXABLEVAL
, ((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL)) +(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*IGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  +(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*CGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  +(((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*SGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  )AS NETTOTAL, (((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*IGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS IGST_AMT, (((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*CGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS CGST_AMT, (((SAL_INV_AMOUNT-((SAL_INV_AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*SGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS SGST_AMT from (
"
SET @SQL1= "
 
SELECT MAX(SALES_ALIAS) AS SALES_ALIAS,MAX(SAL_INV_ID)SAL_INV_ID,MAX(BILLDATE)BILLDATE,MAX(BILLNO)BILLNO,MAX(PARTY_STATECODE)PARTY_STATECODE,MAX(CMPSTATECODE)CMPSTATECODE,MAX(SUPPLY_TYPE)SUPPLY_TYPE,MAX(AGENTNAME)AGENTNAME,MAX(AGENTCITY)AGENTCITY,MAX(PARTYNAME)PARTYNAME,MAX(PARTY_ADDRESS)PARTY_ADDRESS,MAX(PARTY_CITY)PARTY_CITY,MAX(CITY_PINCODE)CITY_PINCODE ,MAX(LGR_STATENAME)LGR_STATENAME,MAX(LGR_GSTINNO)LGR_GSTINNO, MAX(CONSIGNEE_NAME)CONSIGNEE_NAME ,MAX(CONSIGNEE_ADDRESS)CONSIGNEE_ADDRESS,MAX(CONSIGNEE_CITY)CONSIGNEE_CITY,MAX(CONSIGNEE_PINCODE)CONSIGNEE_PINCODE,MAX(CONSIGNEE_STATE)CONSIGNEE_STATE,MAX(CONSIGNEE_STATECODE)CONSIGNEE_STATECODE ,MAX(CONSIGNEE_GSTINNO)CONSIGNEE_GSTINNO, MAX(ITEMCATEGORY)ITEMCATEGORY,MAX(ITEMNAME) AS ITEMNAME,HSN_CODE,MAX(BALENO)BALENO,SUM(QTY)QTY,SUM(PCS)PCS,MAX(RATE_PER)RATE_PER,MAX(RATE) RATE ,MAX(CGST_PER)CGST_PER,SUM(CGST_AMT1)CGST_AMT1,MAX(SGST_PER)SGST_PER,SUM(SGST_AMT1)SGST_AMT1,
MAX(IGST_PER)IGST_PER,SUM(IGST_AMT1)IGST_AMT1,SUM(ITEM_B4_DISCOUNT)ITEM_B4_DISCOUNT, SUM(SAL_INV_AMOUNT )AS SAL_INV_AMOUNT,
SUM(SAL_INV_LESSTOTAL)SAL_INV_LESSTOTAL, SUM(SAL_INV_ADD1)SAL_INV_ADD1,SUM(SAL_INV_ADD2)SAL_INV_ADD2,SUM(SAL_INV_GROSSTOTAL)SAL_INV_GROSSTOTAL, SUM(SAL_INV_ADD3)SAL_INV_ADD3,MAX(SAL_INV_ADD4)SAL_INV_ADD4,SUM(SAL_INV_ADD5)SAL_INV_ADD5 ,
 SUM(SAL_INV_LESS1)SAL_INV_LESS1, SUM(SAL_INV_LESS2)SAL_INV_LESS2, SUM(SAL_INV_LESS3)SAL_INV_LESS3, SUM(SAL_INV_LESS4)SAL_INV_LESS4,SUM(SAL_INV_LESS5)SAL_INV_LESS5,
 MAX(FLAG_REVERSE_CHARGE)FLAG_REVERSE_CHARGE,MAX(PERCENT_REVERSE_CHARGE_RATE )PERCENT_REVERSE_CHARGE_RATE,MAX(GOODSSUPPLY)GOODSSUPPLY_TYPE  FROM ( 
 SELECT SI.SALES_ALIAS,SI.SAL_INV_ID,  SI.SAL_INV_VDATE AS BILLDATE,SI.SAL_INV_BILL_NO AS BILLNO,SM.STATE_CODE AS PARTY_STATECODE,CMP.CMP_STATECODE AS CMPSTATECODE,(CASE WHEN  SM.STATE_CODE=CMP.CMP_STATECODE THEN 'INTRA_STATE' ELSE 'INTER_STATE' END) AS SUPPLY_TYPE, AGM.LGR_NAME AS AGENTNAME ,ACM.CITY_NAME AS AGENTCITY,LM.LGR_NAME AS PARTYNAME,(LM.LGR_ADD1+','+LM.LGR_ADD2+','+LM.LGR_ADD3)PARTY_ADDRESS,CM.CITY_NAME AS PARTY_CITY,LM.CITY_PINCODE, SM.STATE_NAME AS LGR_STATENAME,LM.GSTINNO AS LGR_GSTINNO,CMS.NAME AS CONSIGNEE_NAME, 
(CMS.ADD1+','+CMS.ADD2+','+CMS.ADD3) AS CONSIGNEE_ADDRESS,CCM.CITY_NAME AS CONSIGNEE_CITY,CMS.PINCODE AS CONSIGNEE_PINCODE,
 CSM.STATE_NAME AS CONSIGNEE_STATE,CSM.STATE_CODE AS CONSIGNEE_STATECODE,CMS.GSTINNO AS CONSIGNEE_GSTINNO,VM.Name as ITEMCATEGORY,IM.ITEM_NAME AS ITEMNAME, HSM.HSN_NAME AS HSN_CODE,SID.SAL_INV_BALENO AS BALENO,  	"      
SET @SQL2 =" 
(CASE WHEN UM.UNIT_NAME ='KILOGRAMS' THEN SID.SAL_INV_QTY*(CASE WHEN ISNULL(ITEM_CONVERSION,0)=0 THEN 1 ELSE  ISNULL(ITEM_CONVERSION,0)END) ELSE SID.SAL_INV_QTY END)QTY,SID.SAL_INV_PCS AS PCS, RATE_PER, (SID.SAL_INV_AMOUNT/(CASE WHEN UM.UNIT_NAME ='KILOGRAMS' THEN SID.SAL_INV_QTY*(CASE WHEN ISNULL(ITEM_CONVERSION,0)=0 THEN 1 ELSE  ISNULL(ITEM_CONVERSION,0)END) ELSE SID.SAL_INV_QTY END))RATE, 
ISNULL(SI.SAL_INV_ADD3_SET,0) AS CGST_PER,ISNULL(SI.SAL_INV_ADD3,0) AS CGST_AMT1, ISNULL(SI.SAL_INV_ADD4_SET,0) AS SGST_PER,
ISNULL(SI.SAL_INV_ADD4,0) AS SGST_AMT1, ISNULL(SI.SAL_INV_ADD5_SET,0) AS IGST_PER,
ISNULL(SI.SAL_INV_ADD5,0) AS IGST_AMT1,SID.SAL_INV_AMOUNT AS ITEM_B4_DISCOUNT, SID.SAL_INV_AMOUNT,SAL_INV_LESSTOTAL,ISNULL(SAL_INV_ADD1,0)SAL_INV_ADD1,ISNULL(SAL_INV_ADD2,0)SAL_INV_ADD2,SAL_INV_GROSSTOTAL,ISNULL(SI.Sal_Inv_Add3,0)Sal_Inv_Add3,ISNULL(SI.Sal_Inv_Add4,0)Sal_Inv_Add4,ISNULL(SI.Sal_Inv_Add5,0)Sal_Inv_Add5 ,
ISNULL(SI.Sal_Inv_LESS1,0)Sal_Inv_LESS1 ,ISNULL(SI.Sal_Inv_LESS2,0)Sal_Inv_LESS2 ,ISNULL(SI.Sal_Inv_LESS3,0)Sal_Inv_LESS3 ,
ISNULL(SI.Sal_Inv_LESS4,0)Sal_Inv_LESS4 ,ISNULL(SI.Sal_Inv_LESS5,0)Sal_Inv_LESS5 ,
'N'as Flag_Reverse_Charge ,'N' as Percent_Reverse_Charge_Rate,GRM.SUPPLY_TYPE AS GOODSSUPPLY 
FROM "+ @DatabaseName +"  SALES_INVOICE SI 
INNER JOIN "+ @DatabaseName +" SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG 
INNER JOIN "+ @DatabaseName +" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID 
LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+ @DatabaseName +" STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID 
INNER JOIN "+ @DatabaseName +" COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE 
LEFT JOIN "+ @DatabaseName +" CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN "+ @DatabaseName +" CONSIGNEE_MASTER CMS ON CMS.CONSIGNEE_ID=SI.CONSIGNEE_ID 
LEFT JOIN "+ @DatabaseName +" CITY_MASTER CCM ON CCM.CITY_ID=CMS.CITY_ID 
LEFT JOIN "+ @DatabaseName +" STATE_MASTER CSM ON CSM.STATE_ID=CMS.STATE_ID 
INNER JOIN "+ @DatabaseName +" ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID 
LEFT JOIN "+ @DatabaseName +" HSN_MASTER HSM ON HSM.HSN_ID=IM.HSN_ID 
LEFT JOIN "+ @DatabaseName +" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
LEFT JOIN "+ @DatabaseName +" VATCATEGORYMASTER VM ON VM.DOCNO =SI.VATTYPE_ID 
LEFT JOIN " + @DatabaseName +"LEDGER_MASTER GRM ON GRM.LGR_ID=SI.Sal_AccID
" + @SELECTED +"
WHERE  "+@ID+"  SI.SAL_INV_VDATE  BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
and SI.CMP_CODE IN("+ @Cmp_Code +") 
 )as detail   
group by HSN_CODE ,SAL_INV_ID,SALES_ALIAS,BILLDATE,BILLNO,PARTY_STATECODE) as d "

SET @SQL3= " UNION ALL
select *,
(SAL_INV_ADD1 + SAL_INV_ADD2 -( ISNULL(SAL_INV_LESS1,0) + ISNULL(SAL_INV_LESS2,0) + ISNULL(SAL_INV_LESS3,0) + ISNULL(SAL_INV_LESS4,0)+ ISNULL(SAL_INV_LESS5,0))) as ADDLESSTOTAL,
AMOUNT AS GROSS_TOTAL,
((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL)ITEM_DISCOUNT ,(AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))ITEM_TAXABLEVAL
, ((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL)) +(((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*IGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  +(((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*CGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  +(((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*SGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0)))))  )AS NETTOTAL, (((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*IGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS IGST_AMT, (((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*CGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS CGST_AMT, (((AMOUNT-((AMOUNT*(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))/SAL_INV_GROSSTOTAL))*SGST_AMT1)/ (SAL_INV_GROSSTOTAL-(SAL_INV_LESSTOTAL-(ISNULL(SAL_INV_ADD1,0)+ISNULL(SAL_INV_ADD2,0))))) AS SGST_AMT
 from ( "
SET @SQL4= " select max(SALES_ALIAS) as SALES_ALIAS,MAX(Sal_Inv_Id)Sal_Inv_Id,max(BILLDATE)BILLDATE,max(BILLNO)BILLNO,max(PARTY_STATECODE)PARTY_STATECODE,max(CmpStateCode)CmpStateCode,max(SUPPLY_TYPE)SUPPLY_TYPE,MAX(AGENTNAME)AGENTNAME,MAX(AGENTCITY)AGENTCITY,max(PARTYNAME)PARTYNAME,max(PARTY_ADDRESS)PARTY_ADDRESS,max(PARTY_CITY)PARTY_CITY,max(CITY_PINCODE)CITY_PINCODE ,max(LGR_STATENAME)LGR_STATENAME,max(LGR_GSTINNO)LGR_GSTINNO, max(CONSIGNEE_NAME)CONSIGNEE_NAME ,max(CONSIGNEE_ADDRESS)CONSIGNEE_ADDRESS,max(CONSIGNEE_CITY)CONSIGNEE_CITY,max(CONSIGNEE_PINCODE)CONSIGNEE_PINCODE,max(CONSIGNEE_STATE)CONSIGNEE_STATE,max(CONSIGNEE_STATECODE)CONSIGNEE_STATECODE ,max(CONSIGNEE_GSTINNO)CONSIGNEE_GSTINNO, max(ITEMCATEGORY)ITEMCATEGORY,MAX(ITEMNAME) AS ITEMNAME,HSN_CODE,MAX(BALENO)BALENO,sum(QTY)QTY,SUM(PCS)PCS,max(RATE_PER)RATE_PER,max(RATE) RATE ,max(CGST_PER)CGST_PER,max(CGST_AMT1)CGST_AMT1,max(SGST_PER)SGST_PER,max(SGST_AMT1)SGST_AMT1,
max(IGST_PER)IGST_PER,max(IGST_AMT1)IGST_AMT1,sum(ITEM_B4_DISCOUNT)ITEM_B4_DISCOUNT, SUM(AMOUNT )as AMOUNT,
max(SAL_INV_LESSTOTAL)SAL_INV_LESSTOTAL, max(SAL_INV_ADD1)SAL_INV_ADD1,max(SAL_INV_ADD2)SAL_INV_ADD2,max(SAL_INV_GROSSTOTAL)SAL_INV_GROSSTOTAL, max(Sal_Inv_Add3)Sal_Inv_Add3,max(Sal_Inv_Add4)Sal_Inv_Add4,max(Sal_Inv_Add5)Sal_Inv_Add5 ,
max(SAL_INV_LESS1)SAL_INV_LESS1, max(SAL_INV_LESS2)SAL_INV_LESS2, max(SAL_INV_LESS3)SAL_INV_LESS3, max(SAL_INV_LESS4)SAL_INV_LESS4,max(SAL_INV_LESS5)SAL_INV_LESS5,
max(Flag_Reverse_Charge)Flag_Reverse_Charge,max(Percent_Reverse_Charge_Rate )Percent_Reverse_Charge_Rate,max(GOODSSUPPLY)GOODSSUPPLY_TYPE  from ( 
SELECT SI.SALES_ALIAS,SI.JOB_SAL_INV_ID as Sal_Inv_Id,  SI.JOB_SAL_INV_VDATE AS BILLDATE,SI.JOB_SAL_INV_BILL_NO AS BILLNO,
SM.STATE_CODE AS PARTY_STATECODE,CMP.CMP_STATECODE as CmpStateCode,(CASE WHEN  SM.STATE_CODE=CMP.CMP_STATECODE THEN 'INTRA_STATE' ELSE 'INTER_STATE' END) AS SUPPLY_TYPE, AGM.Lgr_NAME AS AGENTNAME ,ACM.CITY_NAME AS AGENTCITY,
LM.LGR_NAME AS PARTYNAME,(LM.LGR_ADD1+','+LM.LGR_ADD2+','+LM.LGR_ADD3)PARTY_ADDRESS,CM.CITY_NAME AS PARTY_CITY,
LM.CITY_PINCODE, SM.STATE_NAME AS LGR_STATENAME,LM.GSTINNO AS LGR_GSTINNO,CMS.NAME AS CONSIGNEE_NAME, 
(CMS.ADD1+','+CMS.ADD2+','+CMS.ADD3) AS CONSIGNEE_ADDRESS,CCM.CITY_NAME AS CONSIGNEE_CITY,CMS.PINCODE AS CONSIGNEE_PINCODE,
CSM.STATE_NAME AS CONSIGNEE_STATE,CSM.STATE_CODE AS CONSIGNEE_STATECODE,CMS.GSTINNO AS CONSIGNEE_GSTINNO,
VM.Name as ITEMCATEGORY,IM.ITEM_NAME AS ITEMNAME, HSM.HSN_NAME AS HSN_CODE,SID.LOTNO AS BALENO,  	
(CASE WHEN UM.UNIT_NAME ='KILOGRAMS' THEN SID.MTRS*(CASE WHEN ISNULL(ITEM_CONVERSION,0)=0 THEN 1 ELSE  
ISNULL(ITEM_CONVERSION,0)END) ELSE SID.MTRS END)QTY,SID.THAN AS PCS, RATE_PER, 
SID.RATE AS RATE, 
ISNULL(SI.SAL_INV_ADD3_SET,0) AS CGST_PER,ISNULL(SI.SAL_INV_ADD3,0) AS CGST_AMT1, ISNULL(SI.SAL_INV_ADD4_SET,0) AS SGST_PER,
ISNULL(SI.SAL_INV_ADD4,0) AS SGST_AMT1, ISNULL(SI.SAL_INV_ADD5_SET,0) AS IGST_PER,
ISNULL(SI.SAL_INV_ADD5,0) AS IGST_AMT1,SID.AMOUNT AS ITEM_B4_DISCOUNT, SID.AMOUNT,LESSTOTAL AS SAL_INV_LESSTOTAL,
ISNULL(SAL_INV_ADD1,0)SAL_INV_ADD1,ISNULL(SAL_INV_ADD2,0)SAL_INV_ADD2,TOTAL AS SAL_INV_GROSSTOTAL,
ISNULL(SI.Sal_Inv_Add3,0)Sal_Inv_Add3,ISNULL(SI.Sal_Inv_Add4,0)Sal_Inv_Add4,
ISNULL(SI.Sal_Inv_Add5,0)Sal_Inv_Add5 ,
ISNULL(SI.Sal_Inv_LESS1,0)Sal_Inv_LESS1 ,ISNULL(SI.Sal_Inv_LESS2,0)Sal_Inv_LESS2 ,
ISNULL(SI.Sal_Inv_LESS3,0)Sal_Inv_LESS3 ,
ISNULL(SI.Sal_Inv_LESS4,0)Sal_Inv_LESS4 ,ISNULL(SI.Sal_Inv_LESS5,0)Sal_Inv_LESS5 ,
'N'as Flag_Reverse_Charge ,'N' as Percent_Reverse_Charge_Rate,GRM.SUPPLY_TYPE AS GOODSSUPPLY  
 FROM "+ @DatabaseName +"JOB_SALESINVOICE_MASTER SI "
 SET @SQL5= " 
INNER JOIN "+ @DatabaseName +"JOB_SALESINVOICE_DETAIL SID ON SID.JOB_SAL_INV_ID=SI.JOB_SAL_INV_ID 
INNER JOIN "+ @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID 
LEFT JOIN "+ @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+ @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID 
INNER JOIN "+ @DatabaseName +"COMPANY_MASTER CMP ON CMP.CMP_CODE=SI.CMP_CODE 
LEFT JOIN "+ @DatabaseName +"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
LEFT JOIN "+ @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN "+ @DatabaseName +" CONSIGNEE_MASTER CMS ON CMS.CONSIGNEE_ID=SI.CONSIGNEE_ID 
LEFT JOIN "+ @DatabaseName +"CITY_MASTER CCM ON CCM.CITY_ID=CMS.CITY_ID 
LEFT JOIN "+ @DatabaseName +" STATE_MASTER CSM ON CSM.STATE_ID=CMS.STATE_ID 
INNER JOIN "+ @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID 
LEFT JOIN "+ @DatabaseName +"HSN_MASTER HSM ON HSM.HSN_ID=IM.HSN_ID 
LEFT JOIN "+ @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
LEFT JOIN "+ @DatabaseName +" VATCATEGORYMASTER VM ON VM.DOCNO =SI.VATTYPE_ID 
LEFT JOIN "+ @DatabaseName +"LEDGER_MASTER GRM ON GRM.LGR_ID=SI.JOB_SALACCID
" + @SELECTED1 +"
WHERE  "+@ID1+" SI.JOB_SAL_INV_VDATE  BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
and SI.CMP_CODE IN ("+ @Cmp_Code +") 
)as detail   
group by HSN_CODE ,Sal_Inv_Id ,SAL_INV_ID,SALES_ALIAS,BILLDATE,BILLNO,PARTY_STATECODE) as d ORDER BY  BILLDATE,BILLNO  "

END	
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3
PRINT @SQL4
PRINT @SQL5
EXEC (@SQL + @SQL1 + @SQL2+ @SQL3+ @SQL4 + @SQL5)




















