/*    proc_SalesRegisterNew '2','ACC2010_2011.DBO.','01/APR/2010','25/FEB/2011',4,'##5249',4457
*/
CREATE PROCEDURE [dbo].[PROC_SALESREGISTERNEW]
(
	@CMP_CODE AS NVARCHAR(50),
    @DATABASENAME AS NVARCHAR(200),
    @FROMDATE  AS NVARCHAR(50),
    @TODATE  AS NVARCHAR(50),
    @RPT_WISE AS INT,
    @TempTable  AS NVARCHAR(50),
    @HEADID NVARCHAR(20)
 )  
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @ORDERBY AS  NVARCHAR(100)
DECLARE @JoinSql AS  NVARCHAR(100)
SET @SQL=""
SET  @JoinSql=""

BEGIN
		IF @RPT_WISE=1    /*   AGENT WISE */
			 begin
				 set @JoinSql="INNER JOIN "+ @TempTable + " TT on TT.Code=ALM.Lgr_Id"
				 SET @ORDERBY= " ORDER BY  ALM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			 end
       ELSE IF @RPT_WISE=2    /*    AGENT,PARTY WISE */
			 begin
				 set @JoinSql="INNER JOIN "+ @TempTable + " TT on TT.Code=ALM.Lgr_Id"
				 SET @ORDERBY= " ORDER BY  ALM.LGR_NAME,LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			 end
		ELSE IF @RPT_WISE=3   /*   PARTY WISE */
			begin
				set @JoinSql="INNER JOIN "+ @TempTable + " TT on TT.Code=LM.Lgr_Id"
				SET @ORDERBY= " ORDER BY LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			end
      ELSE  IF @RPT_WISE in (4,10)   /*   SALES MAN WISE */
			begin
				set @JoinSql="INNER JOIN "+ @TempTable + " TT on TT.Code=S_M.SALESMAN_Id"
				SET @ORDERBY= " ORDER BY S_M.SALESMAN_NAME,LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			end
		ELSE IF @RPT_WISE=5   /*   ALL PARTY WISE */
			BEGIN
			  SET @ORDERBY= " ORDER BY LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			END
		ELSE  IF @RPT_WISE=6   /*   BILL BY BILL */
			BEGIN
			   SET @ORDERBY= " ORDER BY SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
			END
       ELSE IF @Rpt_Wise=7   /*   CUSTOMER GROUP WISE */
            BEGIN
				SET @JoinSql=" INNER JOIN " + @TempTable + " TT ON CGM.CUST_GRP_ID=TT.CODE"
                SET @ORDERBY= " ORDER BY CGM.CUST_GRP_NAME,LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
            END
       ELSE IF @Rpt_Wise IN (8, 9)   /*   CUSTOMER GROUP WISE */
            BEGIN
				SET @JoinSql=" INNER JOIN " + @TempTable + " TT ON PCM.CITY_ID=TT.CODE"
                SET @ORDERBY= " ORDER BY PCM.CITY_NAME,LM.LGR_NAME,SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO) "
            END
		
 END

BEGIN	
	SET NOCOUNT ON;

SET @SQL="
            SELECT LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY, SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS BILLDATE,SAL_INV_LRNO AS LRNO,SAL_INV_LRDATE AS LRDATE,
            IM.ITEM_NAME AS ITEM,SID.SAL_INV_BALENO AS BALENO,(CASE WHEN SID.SERIALNO IS NULL THEN SID.SAL_INV_BALENO ELSE SID.SERIALNO END) AS SERIALNO,
            (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
            ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY
           ,SI.SAL_INV_GROSSTOTAL AS GROSSTOTAL,
            SI.SAL_INV_NETTOTAL AS NETTOTAL,TM.TRANSPORT_NAME AS TRANSPORT,SI.ORDERNO,SI.ORDERDATE,SCM.SCREEN_NAME,ST.CITY_NAME AS STATION
            ,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
            FROM  "+ @DATABASENAME +"SALES_INVOICE SI 
            INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID
            INNER JOIN  "+ @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
            INNER JOIN " + @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
            INNER JOIN  "+ @DATABASENAME +"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
            INNER JOIN  "+ @DATABASENAME +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
            INNER JOIN  "+ @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
            LEFT  JOIN  "+ @DATABASENAME +"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
            LEFT JOIN "+ @DATABASENAME +"CITY_MASTER PCM  ON PCM.CITY_ID=LM.CITY_ID
            LEFT JOIN "+ @DATABASENAME +"CITY_MASTER ST  ON ST.CITY_ID=SI.STATION_ID
            LEFT JOIN "+ @DATABASENAME +"CITY_MASTER ACM  ON ACM.CITY_ID=ALM.CITY_ID 
            LEFT JOIN "+ @DATABASENAME +"SALESMAN_MASTER S_M  ON S_M.SALESMAN_ID=ALM.SALESMAN_ID 
            LEFT JOIN " + @DatabaseName +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
            " + @JoinSql + "
            WHERE SI.SAL_ACCID="+@HEADID+" AND SI.SAL_INV_VDATE BETWEEN  '"+ @FROMDATE + "' AND '"+ @TODATE + "'  AND SI.CMP_CODE IN (" +@CMP_CODE + ")

" + @ORDERBY 

EXEC SP_EXECUTESQL @SQL
    PRINT @SQL
	
END




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESREGISTERTCS]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO










CREATE PROCEDURE [dbo].[PROC_SALESREGISTERTCS]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),    
    @DatabaseName nvarchar(50),
	@Cmp_Code nvarchar(100),    
    @TempTable nvarchar(20),
	@SelAll  int,
    @HeadId nvarchar(20),
    @Rpt_Wise int,
    @CONVERSION int,
    @NET_SNET INT   
)
AS

DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @NET_SNETSQL AS NVARCHAR(1000)
DECLARE @QUANTITYSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SELECTED=""
SET @QUANTITYSQL=""
SET @NET_SNETSQL=""

set nocount on;

BEGIN    
   SET @QUANTITYSQL=" SID.SAL_INV_QTY   AS QUANTITY "
   
   IF @CONVERSION=1 
   SET @QUANTITYSQL="
                    (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
                     ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS QUANTITY "
END

BEGIN
    IF @NET_SNET=1  /* SNET BILL*/
      SET @NET_SNETSQL=" AND SI.NET_SNET='S.NET'"      
   ELSE IF @NET_SNET=2 /*WITHOUT SNET BILL*/
      SET @NET_SNETSQL=" AND SI.NET_SNET !='S.NET'"          
   ELSE IF @NET_SNET=3 /*ALL*/
      SET @NET_SNETSQL=""      
END 

BEGIN
	IF @SelAll=0
	  BEGIN 
		IF @Rpt_Wise in (1,10,11,12,19,20,24)
			 BEGIN
			  SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.AGENT_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (2,13,14)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.LGR_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise in (3,15)
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SID.ITEM_ID=TT.CODE"
			END 
		ELSE IF @Rpt_Wise = 4
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SC.SCREEN_ID=TT.CODE"
			END 
		ELSE IF @Rpt_Wise in (5,18)
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON S_M.SALESMAN_ID=TT.CODE"
			END 
		ELSE IF @Rpt_Wise in (6,16)
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON IG.Item_Grp_Id=TT.CODE"
			END 
		ELSE IF @Rpt_Wise = 7
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON CGM.CUST_GRP_ID=TT.CODE"
			END 
		ELSE IF @Rpt_Wise in (8,17)
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON PCM.CITY_ID=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise = 9
			BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SM.STATE_ID=TT.CODE"
			END 
		ELSE IF @Rpt_Wise = 21
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
			 END 
		ELSE IF @Rpt_Wise = 25
			 BEGIN
			   SET @SELECTED=" INNER JOIN " + @TempTable + " TT ON SI.CONFNO=TT.CODE"
			 END 
	END
SET @SQL="
	 SELECT SI.Sal_Inv_Id,SI.SAL_INV_BILL_NO AS BILLNO,SI.SAL_INV_VDATE AS VDATE,LM.LGR_NAME AS PARTYNAME,AGM.Lgr_NAME AS AGENTNAME 
     ,CONVERT(NVARCHAR,SID.SAL_INV_BALENO) AS BALENO,(CASE WHEN SID.SERIALNO IS NULL THEN CONVERT(NVARCHAR,SID.SAL_INV_BALENO) ELSE CONVERT(NVARCHAR,
	SID.SERIALNO) END) AS SERIALNO,IM.ITEM_NAME AS ITEM,SID.SAL_INV_PCS AS PCS,"+@QUANTITYSQL+",SAL_INV_AMOUNT AS AMOUNT,SID.SAL_INV_RATE AS RATE,
	ISNULL(SI.SAL_INV_ADD3,0)AS CGST,ISNULL(SI.SAL_INV_ADD4,0)AS SGST,ISNULL(SI.SAL_INV_ADD5,0)AS IGST,
	(SI.Sal_Inv_GrossTotal + ISNULL(SI.SAL_INV_ADD1,0) + ISNULL(SI.SAL_INV_ADD2,0) -( ISNULL(SI.SAL_INV_LESS1,0) + ISNULL(SI.SAL_INV_LESS2,0) + ISNULL(SI.SAL_INV_LESS3,0) + ISNULL(SI.SAL_INV_LESS4,0)+ ISNULL(SI.SAL_INV_LESS5,0))) AS TAXABLE,SAL_INV_NETTOTAL AS NETTOTAL,
     PCM.CITY_NAME AS PARTYCITY ,ACM.CITY_NAME AS AGENTCITY,SM.STATE_NAME AS STATE,(SI.Sal_Inv_AddTotal-SI.Sal_Inv_LessTotal) as ADDLESSTOTAL,
     COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
     COMP.CMP_MOBILE,COMP.CMP_FAX,SC.SCREEN_NAME AS SCREEN,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP,COMP.CMP_ALIAS,SI.NET_SNET,
	IG.Item_Grp_Name ,SI.ORDERNO,SI.ORDERDATE,SI.CONFNO,SI.TCS_AMT,SI.TCS_PER,Si.Sal_Inv_RoundOff
     FROM "+ @DatabaseName+ "SALES_INVOICE SI
     INNER JOIN  "+ @DatabaseName +"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG
     INNER JOIN " + @DatabaseName +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
     LEFT JOIN " + @DatabaseName +"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
     INNER JOIN " + @DatabaseName +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
     INNER JOIN " + @DatabaseName +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
     LEFT JOIN " + @DatabaseName + "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
     LEFT JOIN " + @DatabaseName +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
     LEFT JOIN " + @DatabaseName +"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
     LEFT JOIN " + @DatabaseName +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
     LEFT JOIN " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=PCM.STATE_ID     
     LEFT JOIN " + @DatabaseName +"SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AgM.SALESMAN_ID
     LEFT JOIN " + @DatabaseName +"CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
	 left join "+ @DatabaseName +" Item_Group_Master IG on IM.Item_Grp_Id =IG.Item_Grp_Id 
--     " + @SELECTED +"
     WHERE SI.SAL_ACCID="+@HeadId+" AND SI.Cmp_Code IN("+ @Cmp_Code +") and  SI.SAL_INV_VDATE BETWEEN '" + @FromDate + "' and '" + @ToDate + "'
     and SI.FLAG IN ('S','YS','GS','CSM','MS')
	 "+@NET_SNETSQL+"
     ORDER BY CONVERT(INT,SI.SAL_INV_BILL_NO),SI.SAL_INV_VDATE,SID.SAL_INV_DTL_ID"      
END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL

--SELECT * FROM SALES_INVOICE








GO

