PROC_SALESREGISTERWITHMONTHLY '01/APR/2014', N'31/MAR/2015', N'ACC2014_2015.DBO.',N'1', N'##2256',1,8963,24,1,1
*/
CREATE PROCEDURE [dbo].[PROC_SALESREGISTERWITHMONTHLY]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),    
@DATABASENAME NVARCHAR(50),
@CMP_CODE NVARCHAR(100),    
@TEMPTABLE NVARCHAR(20),
@SELALL  INT,
@HEADID NVARCHAR(20),
@RPT_WISE INT,
@CONVERSION INT,
@NET_SNET INT   
)
AS

DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)
DECLARE @MAINFILEDSQL AS NVARCHAR(4000)
DECLARE @GROUPBYSQL AS NVARCHAR(4000)

SET @SQL=""
SET @SELECTED=""
SET @ORDERBYSQL=""
SET @MAINFILEDSQL=""
SET @GROUPBYSQL=""

SET NOCOUNT ON;

BEGIN 
IF @RPT_WISE IN (1) /* AGENT WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
MAX(PARTY) AS PARTY,MAX(PARTYID) AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,"
SET @ORDERBYSQL = "AGENT,AGENTID,"
END
IF @RPT_WISE IN (10) /* AGENT/PARTY WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,PARTY,PARTYID,"
SET @ORDERBYSQL = "AGENT,AGENTID,PARTY,PARTYID,"
END 
IF @RPT_WISE IN (11) /* AGENT/ITEM WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
MAX(PARTY) AS PARTY,MAX(PARTYID) AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
ITEM AS ITEM,ITEMID AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,ITEM,ITEMID,"
SET @ORDERBYSQL = "AGENT,AGENTID,ITEM,ITEMID,"
END 
IF @RPT_WISE IN (12) /* AGENT/SCREEN WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
MAX(PARTY) AS PARTY,MAX(PARTYID) AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
SCREEN AS SCREEN,SCREENID AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,SCREEN,SCREENID,"
SET @ORDERBYSQL = "AGENT,AGENTID,SCREEN,SCREENID,"
END 
IF @RPT_WISE IN (19) /* AGENT/PARTY/ITEM WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
ITEM AS ITEM,ITEMID AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,PARTY,PARTYID,ITEM,ITEMID,"
SET @ORDERBYSQL = "AGENT,AGENTID,PARTY,PARTYID,ITEM,ITEMID,"
END 
IF @RPT_WISE IN (20) /* AGENT/PARTY/SCREEN WISE */ 
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
SCREEN AS SCREEN,SCREENID AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,PARTY,PARTYID,SCREEN,SCREENID,"
SET @ORDERBYSQL = "AGENT,AGENTID,PARTY,PARTYID,SCREEN,SCREENID,"
END 
IF @RPT_WISE IN (24) /* AGENT/SALESMAN WISE */	
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.AGENT_ID=TT.CODE"
SET @MAINFILEDSQL = "
MAX(PARTY) AS PARTY,MAX(PARTYID) AS PARTYID,
AGENT AS AGENT,AGENTID AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
SALESMAN AS SALESMAN,SALESMANID AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "AGENT,AGENTID,SALESMAN,SALESMANID,"
SET @ORDERBYSQL = "AGENT,AGENTID,SALESMAN,SALESMANID,"
END 


ELSE IF @RPT_WISE IN (2) /* PARTY WISE */	
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
MAX(AGENT) AS AGENT,MAX(AGENTID) AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "PARTY,PARTYID,"
SET @ORDERBYSQL = "PARTY,PARTYID,"
END 
ELSE IF @RPT_WISE IN (13) /* PARTY/ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
MAX(AGENT) AS AGENT,MAX(AGENTID) AS AGENTID,
ITEM AS ITEM,ITEMID AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "PARTY,PARTYID,ITEM,ITEMID,"
SET @ORDERBYSQL = "PARTY,PARTYID,ITEM,ITEMID,"
END 
ELSE IF @RPT_WISE IN (14) /* PARTY/SCREEN WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.LGR_ID=TT.CODE"
SET @MAINFILEDSQL = "
PARTY AS PARTY,PARTYID AS PARTYID,
MAX(AGENT) AS AGENT,MAX(AGENTID) AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
SCREEN AS SCREEN,SCREENID AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = "PARTY,PARTYID,SCREEN,SCREENID,"
SET @ORDERBYSQL = "PARTY,PARTYID,SCREEN,SCREENID,"
END 

ELSE IF @RPT_WISE IN (3) /* ITEM WISE */
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SID.ITEM_ID=TT.CODE"
SET @MAINFILEDSQL = "
