SET @GROUPBYSQL = "STATENAME,STATEID,"
SET @ORDERBYSQL = "STATENAME,STATEID,"
END 
ELSE IF @RPT_WISE = 21
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SI.SAL_INV_BILL_NO=TT.CODE"
SET @MAINFILEDSQL = "
MAX(PARTY) AS PARTY,MAX(PARTYID) AS PARTYID,
MAX(AGENT) AS AGENT,MAX(AGENTID) AS AGENTID,
MAX(ITEM) AS ITEM,MAX(ITEMID) AS ITEMID,
MAX(PARTYCITY) AS PARTYCITY,MAX(PARTY_CITYID) AS PARTY_CITYID,
MAX(SCREEN) AS SCREEN,MAX(SCREENID) AS SCREENID,
MAX(AGENTCITY) AS AGENTCITY,MAX(AGENT_CITYID) AS AGENT_CITYID,
MAX(STATENAME) AS STATENAME,MAX(STATEID) AS STATEID,
MAX(SALESMAN) AS SALESMAN,MAX(SALESMANID) AS SALESMANID, 
MAX(CUSTGRP) AS CUSTGRP,MAX(CUSTGRPID) AS CUSTGRPID,
MAX(ITEMGRP) AS ITEMGRP,MAX(ITEMGRPID) AS ITEMGRPID, "
SET @GROUPBYSQL = ""
SET @ORDERBYSQL = ""
END 

BEGIN
IF @SELALL = 1
SET @SELECTED=""
END

SET @SQL="
SELECT MONTHNAME,"+@MAINFILEDSQL+"SUM(NETTOTAL) AS NETTOTAL,ORD,CMP_ALIAS AS CMP_ALIAS
FROM
(
SELECT ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(LM.LGR_ID,0) AS PARTYID,
ISNULL(AGM.LGR_NAME,'') AS AGENT,ISNULL(AGM.LGR_ID,0) AS AGENTID,
ISNULL(IM.ITEM_NAME,'') AS ITEM,ISNULL(IM.ITEM_ID,0) AS ITEMID,
ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,
ISNULL(SC.SCREEN_NAME,'') AS SCREEN,ISNULL(SC.SCREEN_ID,0) AS SCREENID,
ISNULL(ACM.CITY_NAME,'') AS AGENTCITY,ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(SM.STATE_NAME,'') AS STATENAME,ISNULL(SM.STATE_ID,0) AS STATEID,
ISNULL(S_M.SALESMAN_NAME,'') AS SALESMAN,ISNULL(S_M.SALESMAN_ID,0) AS SALESMANID,
ISNULL(CGM.CUST_GRP_NAME,'') AS CUSTGRP,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(IG.ITEM_GRP_NAME,'') AS ITEMGRP,ISNULL(IG.ITEM_GRP_ID,0) AS ITEMGRPID,
UPPER(DATENAME(MM,SI.SAL_INV_VDATE)) AS MONTHNAME,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS NETTOTAL,
(CASE WHEN DATEPART(M,SI.SAL_INV_VDATE)<=3 THEN  (DATEPART(M,SI.SAL_INV_VDATE)+12)ELSE DATEPART(M,SI.SAL_INV_VDATE) END) AS ORD,
COMP.CMP_ALIAS
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+ @DATABASENAME+ "SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SID.FLAG=SI.FLAG 
INNER JOIN "+ @DATABASENAME+ "LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+ @DATABASENAME+ "LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
INNER JOIN "+ @DATABASENAME+ "ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
LEFT JOIN  "+ @DATABASENAME+ "UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN  "+ @DATABASENAME+ "COMPANY_MASTER COMP ON COMP.CMP_CODE=SI.CMP_CODE
LEFT JOIN  "+ @DATABASENAME+ "CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+ @DATABASENAME+ "SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
LEFT JOIN  "+ @DATABASENAME+ "CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID
LEFT JOIN  "+ @DATABASENAME+ "STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID     
LEFT JOIN  "+ @DATABASENAME+ "SALESMAN_MASTER S_M ON S_M.SALESMAN_ID=AGM.SALESMAN_ID
LEFT JOIN  "+ @DATABASENAME+ "CUSTOMER_GROUP_MASTER CGM ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID
LEFT JOIN  "+ @DATABASENAME+ "ITEM_GROUP_MASTER IG ON IM.ITEM_GRP_ID =IG.ITEM_GRP_ID 
" + @SELECTED +"
WHERE SI.SAL_ACCID="+@HEADID+" AND SI.CMP_CODE IN("+ @CMP_CODE +") AND  SI.SAL_INV_VDATE BETWEEN '" + @FROMDATE + "' AND '" + @TODATE + "'
AND SI.FLAG='S'
) AS DETAIL
GROUP BY "+@GROUPBYSQL+"MONTHNAME,ORD,CMP_ALIAS
ORDER BY "+@ORDERBYSQL+"ORD
"

END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

