/*   
PROC_SALESRETURN_PRINT 1,'ACC2012_2013.DBO.','1','2'
*/
CREATE PROCEDURE [dbo].[PROC_SALESRETURN_PRINT] 
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(100),
   @FROMDOCNO NVARCHAR(20), 
   @TODOCNO NVARCHAR(20)
 )
AS
DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN
SET @SQL="
       
SELECT SRM.DOCNO AS BILLNO,SRM.SAL_RET_DATE AS VDATE,SRM.SAL_RET_LRNO,SRM.SAL_RET_LRDATE,upper(LM.LGR_NAME) AS PARTYNAME,upper(PCM.CITY_NAME) AS PARTYCITY
        ,upper(LM.LGR_ADD1) as LGR_ADD1,upper(LM.LGR_ADD2) as LGR_ADD2,upper(LM.LGR_ADD3)as LGR_ADD3,upper(AGM.Lgr_NAME) AS AGENTNAME ,SRD.SAL_RET_BALE_NO AS BALENO,SRD.Item_Cut
        ,IM.ITEM_NAME AS ITEM,SRD.SAL_RET_PCS AS PCS,SRD.SAL_RET_QTY AS QUANTITY,SRD.SAL_RET_AMOUNT AS AMOUNT,SRD.SAL_RET_RATE AS RATE,SRM.NETTOTAL AS NETTOTAL,SRM.ROUNDEDAMOUNT
        ,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SRM.SAL_RET_ADD1,SRM.SAL_RET_ADD2,SRM.SAL_RET_ADD3
        ,SRM.SAL_RET_LESS1,SRM.SAL_RET_LESS2,SRM.SAL_RET_LESS3,SRM.Sal_RET_AddTotal,SRM.Sal_RET_LessTotal,Sal_RET_RoundOff
    	 ,SRM.GROSSTotal,UM.UNIT_NAME,upper(SM.State_NAME) as  PatyState,upper(PCM.City_District)as City_District,LM.City_Pincode
	    ,upper(CMp.Cmp_Name)as Cmp_Name,Cmp.cmp_tin_No,cmp.cmp_pan_no,cmp.cmp_jurisdiction,cmp.cmp_add1,cmp.cmp_add2,cmp.cmp_city,cmp.cmp_state,cmp.cmp_phone1,cmp.cmp_Phone2,cmp.cmp_Mobile,cmp.cmp_bank_accno1,cmp.cmp_bank_accno2,cmp.cmp_bank_accno3,upper(ACM.City_Name) As AgentCity
        ,SCM.SCREEN_NAME
        FROM "+@DATABASENAME+"SALES_RETURN_MASTER SRM
        INNER JOIN "+@DATABASENAME+"SALES_RETURN_DETAIL SRD ON SRD.SAL_RET_ID=SRM.SAL_RET_ID
        INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
        LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SRM.TRANSPORT_ID
        LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SRM.AGENT_ID
        INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SRD.ITEM_ID
        INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SRD.SCREEN_ID
        INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SRD.UNIT_ID
        Inner JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON SRM.Cmp_Code= CMP.Cmp_Code     
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SRM.STATION_ID
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
        LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID        
        WHERE  SRM.DOCNO BETWEEN "+@FROMDOCNO +" AND "+ @TODOCNO +" AND SRM.CMP_CODE="+@CMP_CODE+"
		ORDER BY SRM.DOCNO,SRD.SAL_RET_DTL_ID "
END

EXECUTE SP_EXECUTESQL @SQL
print @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SALESRETURNPREPRINTED_GST]    Script Date: 03/30/2023 12:08:14 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO
































  /*   
PROC_SALESRETURNPREPRINTED_GST 1,'ACC2017_2018.DBO.','1','1',1
*/CREATE PROCEDURE [dbo].[PROC_SALESRETURNPREPRINTED_GST] 
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME NVARCHAR(100),
   @FROMDOCNO NVARCHAR(20), 
   @TODOCNO NVARCHAR(20),
   @FLAG INT
 )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLCON AS NVARCHAR(1000)
SET @SQL=""
SET @SQLCON = ""

BEGIN
	IF @FLAG = 1 /* GRAY SALES NORMAL RETURN */
		SET @SQLCON = " AND SRM.FLAG = 'GSR'"
	ELSE IF @FLAG = 0
		SET @SQLCON = " AND SRM.FLAG <> 'GSR'"
END
BEGIN
SET @SQL="
       SELECT A.* , SR.SIGNED_QR_CODE FROM (
		SELECT SRM.DOCNO AS BILLNO,SRM.SAL_RET_DATE AS VDATE,SRM.SAL_RET_LRNO,SRM.SAL_RET_LRDATE,upper(LM.LGR_NAME) AS PARTYNAME,upper(PCM.CITY_NAME) AS PARTYCITY
        ,upper(LM.LGR_ADD1) as LGR_ADD1,upper(LM.LGR_ADD2) as LGR_ADD2,upper(LM.LGR_ADD3)as LGR_ADD3,upper(AGM.Lgr_NAME) AS AGENTNAME ,SRD.SAL_RET_BALE_NO AS BALENO,SRD.Item_Cut
        ,IM.ITEM_NAME AS ITEM,SRD.SAL_RET_PCS AS PCS,ISNULL(SRD.SAL_RET_QTY,0) AS QUANTITY,SRD.SAL_RET_AMOUNT AS AMOUNT,SRD.SAL_RET_RATE AS RATE,SRM.NETTOTAL AS NETTOTAL,SRM.ROUNDEDAMOUNT
        ,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SRM.SAL_RET_ADD1,SRM.SAL_RET_ADD2,SRM.SAL_RET_ADD3
        ,SRM.SAL_RET_LESS1,SRM.SAL_RET_LESS2,SRM.SAL_RET_LESS3,SRM.Sal_RET_AddTotal,SRM.Sal_RET_LessTotal,Sal_RET_RoundOff
    	 ,SRM.GROSSTotal,UM.UNIT_NAME,upper(SM.State_NAME) as  PatyState,upper(PCM.City_District)as City_District,LM.City_Pincode
	    ,upper(CMp.Cmp_Name)as Cmp_Name,Cmp.cmp_tin_No,cmp.cmp_pan_no,cmp.cmp_jurisdiction,cmp.cmp_add1,cmp.cmp_add2,cmp.cmp_city,cmp.cmp_state,cmp.cmp_phone1,cmp.cmp_Phone2,cmp.cmp_Mobile,cmp.cmp_bank_accno1,cmp.cmp_bank_accno2,cmp.cmp_bank_accno3,upper(ACM.City_Name) As AgentCity 
		,SCM.SCREEN_NAME,LM.LGR_CSTNO AS PARTYTINNO ,CMP.CMP_SERVICETAX_NO AS SERVICETAX,'' AS CUTNAME,'' AS DESIGN,'' AS NARR,
		SRM.CMP_CODE,SRM.IRN,SRM.ACK_DATE,SRM.EINVNO
		,CMP.GSTINNO,lm.gstinno as PartyGstno,sm.State_Code
		,SRM.Sal_Ret_Add4,SRM.Sal_Ret_Add5,SRM.Sal_Ret_Less4,SRM.Sal_Ret_Less5
		,SRM.SAL_RET_ADD1_SET,SRM.SAL_RET_ADD2_SET,SRM.SAL_RET_ADD3_SET,SRM.SAL_RET_ADD4_SET,SRM.SAL_RET_ADD5_SET
		,(SRM.Sal_Ret_Add1+SRM.Sal_Ret_Add2)as ADDBEFOREVALUE
		,(SRM.GrossTotal-SRM.Sal_Ret_LessTotal+(SRM.Sal_Ret_Add1+SRM.Sal_Ret_Add2)) AS TAXABLEAMT,salebillno,salevchdate,HM.Hsn_Name

        FROM "+@DATABASENAME+"SALES_RETURN_MASTER SRM
        INNER JOIN "+@DATABASENAME+"SALES_RETURN_DETAIL SRD ON SRD.SAL_RET_ID=SRM.SAL_RET_ID AND SRM.FLAG = SRD.FLAG
        INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SRM.LGR_ID
        INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SRM.TRANSPORT_ID
        LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SRM.AGENT_ID
        INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SRD.ITEM_ID
        LEFT JOIN "+@DATABASENAME+"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SRD.SCREEN_ID
        INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=SRD.UNIT_ID
        Inner JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON SRM.Cmp_Code= CMP.Cmp_Code     
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SRM.STATION_ID
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
        LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+"HSN_MASTER HM ON HM.HSN_ID=IM.HSN_ID        
--		LEFT JOIN "+@DATABASENAME+"CUT_MASTER CUM ON CUM.CUT_ID = SRD.CUT_ID
        WHERE  SRM.DOCNO BETWEEN "+@FROMDOCNO +" AND "+ @TODOCNO +" AND SRM.CMP_CODE="+@CMP_CODE+"
		"+@SQLCON+") AS A
		INNER JOIN "+@DATABASENAME+"SALES_RETURN_MASTER SR ON A.BILLNO = SR.DOCNO AND A.CMP_CODE = SR.CMP_CODE
		ORDER BY VDATE,BILLNO,BALENO "
END

EXECUTE SP_EXECUTESQL @SQL
print @SQL

































































































































GO

