/*   
PROC_SCHEMEREG '2','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011'
*/
CREATE PROCEDURE [dbo].[PROC_SCHEMEREG]
(
   @CMP_CODE AS NVARCHAR(50),
   @DATABASENAME AS NVARCHAR(100),
   @FROMDATE AS NVARCHAR(20),
   @TODATE AS NVARCHAR(20),
   @TEMPTABLE AS NVARCHAR(20),
   @RPT_WISE AS INT
)
	
AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS  NVARCHAR(1000)
SET @SQL=""
SET @JOINSQL =""


				IF @RPT_WISE=1 
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ALM.LGR_ID"
				   END 
				ELSE IF @RPT_WISE=2 or @RPT_WISE=3
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
				   END 
				ELSE IF @RPT_WISE=4
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID"
				   END 
				ELSE IF @RPT_WISE=5
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID"
				   END 
				ELSE IF @RPT_WISE=6
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SM.SCREEN_ID"
				   END 
                ELSE IF @RPT_WISE IN (7,8)
				   BEGIN  
						SET @JOINSQL =" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=SAM.SALESMAN_ID"
				   END 




BEGIN
	SET NOCOUNT ON;
      SET @SQL="SELECT CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO,SI.SAL_INV_VDATE AS BILLDATE,SI.ORDERNO,SI.ORDERDATE,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY
                ,ALM.LGR_NAME AS AGENT,ACM.CITY_NAME AS AGENTCITY,SID.SAL_INV_BALENO AS BALENO,IM.ITEM_NAME,SM.SCREEN_NAME,SID.SAL_INV_QTY AS MTRS,SID.SAL_INV_PCS AS PCS,UM.UNIT_NAME
                ,IGM.ITEM_GRP_NAME AS ITEMGROUP,SAM.SALESMAN_NAME AS SALESMAN
                FROM "+@DATABASENAME+"SALES_INVOICE SI
                INNER JOIN  "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID
                INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
                LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
                LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=ALM.CITY_ID
                INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
                INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SM ON SM.SCREEN_ID=SID.SCREEN_ID
                INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
                LEFT JOIN "+@DATABASENAME+"SALESMAN_MASTER SAM ON SAM.SALESMAN_ID=ALM.SALESMAN_ID
                "+ @JOINSQL + "
                WHERE SM.SCHEME='1' AND SI.CMP_CODE="+@CMP_CODE+"  AND((SI.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"')  OR (SI.ORDERDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"') )
                ORDER BY CONVERT(INT,SI.SAL_INV_BILL_NO) "
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

