/*   
PROC_TDSREG 10,'ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011',1,'##2772'
*/
CREATE PROCEDURE [dbo].[PROC_SERVICETAXREG]
	(
          @CMP_CODE AS NVARCHAR(50),
          @DATABASENAME AS NVARCHAR(100),
          @FROMDATE AS NVARCHAR(20),
          @TODATE AS NVARCHAR(20),
          @RPT_WISE AS INT,
          @TEMPTABLE AS NVARCHAR(20)
    )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL =""

       IF @RPT_WISE=1 
           BEGIN 
             SET @JOINSQL="INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
           END

         
BEGIN

      SET @SQL=" 
                 
                 SELECT LM.LGR_NAME AS ACCOUNTNAME,CM.CITY_NAME AS PARTYCITY,CONVERT(NVARCHAR,TVM.DOCNO) AS BILLNO,TVM.VCHDATE AS BILLDATE,TVM.TOTAL_FREIGHT AS AMOUNT,TVM.SERTAXAMOUNT
                 FROM "+@DATABASENAME+"TRANSPORTVOUCHER_MASTER TVM
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TVM.ACCOUNT_ID
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                 "+@JOINSQL+"
                 WHERE TVM.SERTAXAMOUNT>0 AND TVM.CMP_CODE IN("+@CMP_CODE+") AND TVM.VCHDATE BETWEEN '"+ @FROMDATE +"' AND '"+@TODATE+"'
                 ORDER BY LM.LGR_NAME,BILLDATE,BILLNO
               "

	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

