SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/*
-- =============================================
-- ALTER_AUTHOR	: BIREN
-- ALTER_DATE		: 21-06-2014 3:45 PM
-- CRYSTAL_REPORT   : SESKARREGISTER.RPT
-- REPORT_FORM		: RFRMSESKARREGISTER.CS 
PROC_SESKARREGISTER '1','ACC2014_2015.DBO.','01/APR/2013','31/MAR/2014','##876',1
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_SESKARREGISTER]
(
	@CMP_CODE AS NVARCHAR(50),
	@DATABASENAME AS NVARCHAR(100),
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20),
	@TEMPTABLE AS NVARCHAR(20),
	@RPT_WISE AS INT
	)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @STRORDERBY AS NVARCHAR(100)


SET @SQL =""
SET @JOINSQL =""
BEGIN

        IF @RPT_WISE=1 
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CRM.LGR_ID "
           SET @STRORDERBY=" ORDER BY CRM.LGR_NAME,CRM.LGR_ID"
		END           
        ELSE IF @RPT_WISE=2
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=DRM.LGR_ID "
           SET @STRORDERBY=" ORDER BY DRM.LGR_NAME,DRM.LGR_ID"
        END
        ELSE IF @RPT_WISE=3 
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID "
           SET @STRORDERBY=" ORDER BY TM.TRANSPORT_NAME,TM.TRANSPORT_ID"
        END   
		ELSE IF @RPT_WISE=4 OR @RPT_WISE=8
		BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CM.CITY_ID "
           SET @STRORDERBY=" ORDER BY CM.CITY_NAME,CM.CITY_ID"
        END   
		ELSE IF @RPT_WISE=5 
		BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=SVD.LRNO "
           SET @STRORDERBY=" ORDER BY SVD.LRNO"
        END   
		ELSE IF @RPT_WISE=6
		BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=SVM.DOCNO "
           SET @STRORDERBY=" ORDER BY SVM.DOCNO"
        END   
        ELSE IF @RPT_WISE=7
        BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID "
           SET @STRORDERBY=" ORDER BY TM.TRANSPORT_NAME,TM.TRANSPORT_ID, CM.CITY_NAME,CM.CITY_ID"
        END   
        ELSE IF @RPT_WISE=8
		BEGIN
           SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CM.CITY_ID "
           SET @STRORDERBY=" ORDER BY CM.CITY_NAME,CM.CITY_ID,TM.TRANSPORT_NAME,TM.TRANSPORT_ID"
        END   
        
END

BEGIN 

SET  @SQL =	  " SELECT SVM.DOCNO,CONVERT(NVARCHAR,SVM.DOCDATE,103) AS DOCDATE,SVM.PAYMODE,SVD.LRNO,
				CONVERT(NVARCHAR,SVD.LRDATE,103) AS LRDATE,SVD.BALES,SVD.WEIGHT,SVD.RATE,SVD.AMOUNT,
				CRM.LGR_NAME AS CREDIT_ACC,DRM.LGR_NAME AS DEBIT_ACC,TM.TRANSPORT_NAME AS TRANSPORT,
				CM.CITY_NAME AS STATION,SVM.SESKARVOUCHER_ID,CRM.LGR_ID AS CRMPARTY_ID,DRM.LGR_ID AS DRMPARTY_ID,TM.TRANSPORT_ID,CM.CITY_ID
				FROM "+@DATABASENAME+"SESKARVOUCHER_MASTER SVM
				INNER JOIN "+@DATABASENAME+"SESKARVOUCHER_DETAIL SVD ON SVM.SESKARVOUCHER_ID = SVD.SESKARVOUCHER_ID AND
				SVM.CMP_CODE = SVD.CMP_CODE
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER CRM ON CRM.LGR_ID = SVM.CRACCID
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER DRM ON DRM.LGR_ID = SVM.DRACCID
				INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = SVD.TRANSPORT_ID
				INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = SVD.CITY_ID
				"+@JOINSQL+"
				WHERE SVM.CMP_CODE IN("+@CMP_CODE +") AND SVM.DOCDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@STRORDERBY+""
				
		

END
EXECUTE SP_EXECUTESQL @SQL
	
PRINT @SQL


















GO

