/****** Object:  StoredProcedure [dbo].[PROC_SPECIALGRAYSALESREGISTER]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*   
PROC_SPECIALGRAYSALESREGISTER '01/APR/2010','31/MAR/2011',2,'ACC2010_2011.DBO.',4457,19
*/

CREATE PROCEDURE [dbo].[PROC_SPECIALGRAYSALESREGISTER]
(		
@FromDate  nvarchar(20),
@ToDate nvarchar(20),		
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50),        
@SalesAccID nvarchar(20),
@PartyID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""

	BEGIN
set nocount on;
if @PartyID>0
SET @JoinSql="And SI.LGR_ID="+@PartyID+""


SELECT @SQL="
	        select SI.Lgr_Id,SI.Sal_Inv_Vdate,SI.Sal_Inv_Bill_No,SI.Sal_Inv_GrossTotal as GrossTotal,SI.Sal_Inv_NetTotal as NetTotal
,SI.Sal_Inv_Add1 as ADD1,SI.Sal_Inv_Add2 as ADD2,SI.Sal_Inv_Add3 as ADD3,SI.Sal_Inv_Add4 as ADD4,SI.Sal_Inv_Add5 as ADD5
,SI.Sal_Inv_Less1 as LESS1,SI.Sal_Inv_Less2 as LESS2,SI.Sal_Inv_Less3 as LESS3,SI.Sal_Inv_Less4 as LESS4,SI.Sal_Inv_Less5 as LESS5,
SI.Sal_Inv_LrNo,SalesLM.Lgr_Name as SalesAccName,LM.Lgr_Name as PartyName,ALM.Lgr_Name as AgentName,IM.Item_Name,
IGM.ITEM_GRP_NAME,UM.Unit_Name,PCM.City_Name as PartyCity,ACM.City_Name as AgentCity,VM.Weaver_Name,CGM.Cust_Grp_Name
,SID.Sal_Inv_BaleNo as BaleNo,SID.Sal_Inv_Pcs as PCS,
(CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.Sal_Inv_Qty   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.Sal_Inv_Qty  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
ELSE  (SID.Sal_Inv_Pcs * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )  AS QUANTITY
,SID.SAL_INV_BALES as BALES,SID.Sal_Inv_Pcs as THAN,Sal_Inv_Qty as QTY,
(SID.Sal_Inv_Amount)+(((SID.Sal_Inv_Amount)*(SI.Sal_Inv_NetTotal- SI.Sal_Inv_GrossTotal))/SI.Sal_Inv_GrossTotal) AS AMOUNT,
SID.SAL_INV_RATE as RATE,(SI.Sal_Inv_AddTotal-SI.Sal_Inv_LessTotal) AS ADDLESS
FROM "+@DatabaseName+" SALES_INVOICE SI
INNER JOIN "+@DatabaseName+" SALES_INVOICE_DETAIL SID on SI.Sal_Inv_Id=SID.Sal_Inv_Id AND SI.FLAG=SID.FLAG
INNER  JOIN "+@DatabaseName+" LEDGER_MASTER SalesLM ON SI.Sal_AccID=SalesLM.LGR_ID
INNER JOIN "+@DatabaseName+" LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+@DatabaseName+" LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
INNER JOIN "+@DatabaseName+" ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
INNER JOIN "+@DatabaseName+" ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
INNER JOIN "+@DatabaseName+" UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
LEFT JOIN "+@DatabaseName+" City_Master PCM ON LM.City_Id=PCM.City_Id
LEFT JOIN "+@DatabaseName+" City_Master ACM ON ALM.City_Id=ACM.City_Id
LEFT JOIN "+@DatabaseName+" Weaver_Master VM ON SID.Weaver_Id=VM.Weaver_Id         
LEFT JOIN "+@DatabaseName+" CUSTOMER_GROUP_MASTER CGM ON LM.Cust_Grp_Id=CGM.Cust_Grp_Id
where SI.Cmp_Code="+@Cmp_Code+" and SI.Flag='GS' and SI.Sal_AccID="+@SalesAccID+"			
"+@JoinSql+"
AND  SI.Sal_Inv_Vdate BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
Order by SI.Sal_Inv_Vdate,SI.Sal_Inv_Id,SI.Sal_Inv_Bill_No,PARTYNAME
			"
      
END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SPECIALPUR_RET_ITEMSUMMARY]    Script Date: 03/30/2023 12:08:15 ******/
