/*   
Proc_SpecialPur_Ret_ItemSummary '01/apr/2010','31/mar/2011','10','acc2010_2011.dbo.',10,10
*/
CREATE PROCEDURE [dbo].[PROC_SPECIALPUR_RET_ITEMSUMMARY]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50),
	@PurAccID nvarchar(20),
	@PartyID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""

	BEGIN
set nocount on;
if @PartyID>0
SET @JoinSql="And PRM.LGR_ID="+@PartyID+""


SELECT @SQL="
			Select IGM.Item_Grp_Name,IM.Item_Name,
			Sum(PRD.PUR_RET_PCS) As Than,sum(PRD.PUR_RET_QTY) As Qty,
			sum(CASE When UM.Unit_Name='Bales' or UM.Unit_Name='Dozen' or UM.Unit_Name='Kilograms' or UM.Unit_Name='Meters' Then (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*PRD.PUR_RET_QTY Else IM.Item_conversion*PRD.PUR_RET_QTY End)
			Else (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*PRD.PUR_RET_PCS Else IM.Item_conversion*PRD.PUR_RET_PCS End) End) As NetQty,
			sum(PRD.PUR_RET_Amount) As GTotal
			From "+@DatabaseName+"PURCHASE_RETURN_MASTER PRM 
			INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID
			INNER JOIN "+@DatabaseName+"Item_Master IM ON PRD.Item_Id=IM.Item_Id
			INNER JOIN "+@DatabaseName+"Item_Group_Master IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id
			INNER JOIN "+@DatabaseName+"Unit_Master UM ON IM.Unit_Id=UM.Unit_Id
			WHERE PRM.PUR_ACC_ID="+@PurAccID+" AND  PRM.Cmp_Code="+@Cmp_Code+"
			"+@JoinSql+"
			AND PRM.PUR_RET_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
			Group By IGM.Item_Grp_Name,IM.Item_Name
			"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SPECIALPUR_RET_REGISTER]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
