/*   
Proc_SpecialPur_Ret_Register '01/apr/2010','31/mar/2011',10,'acc2010_2011.dbo.',10,10
*/

CREATE PROCEDURE [dbo].[PROC_SPECIALPUR_RET_REGISTER]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50),
	@PurAccID nvarchar(20),
	@PartyID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""

	BEGIN
set nocount on;
if @PartyID>0
SET @JoinSql="And PRM.LGR_ID="+@PartyID+""


SELECT @SQL="
	        SELECT PRM.*,PurLM.Lgr_Name As PurAccName,LM.LGR_NAME AS PARTYNAME,PCM.City_Name As PartyCity,ALM.LGR_NAME AS AGENT,ACM.City_Name As AgentCity,
			PRD.PUR_RET_BALE_NO AS BALENO,IM.ITEM_NAME AS ITEM,PRD.PUR_RET_PCS AS PIECES,PRD.PUR_RET_QTY AS QUANTITY,
			PRD.PUR_RET_AMOUNT AS AMOUNT,PRD.PUR_RET_RATE AS RATE,(PRM.PUR_RET_ADDTOTAL-PRM.PUR_RET_LESSTOTAL) AS ADDLESS,
			COMP.CMP_NAME,COMP.CMP_ADD1,COMP.CMP_ADD2,COMP.CMP_CITY,COMP.CMP_STATE,COMP.CMP_PINCODE,COMP.CMP_PHONE1,COMP.CMP_PHONE2,
			COMP.CMP_MOBILE,COMP.CMP_FAX,SM.STATE_NAME AS STATE,DCM.CITY_NAME AS STATION
			FROM "+@DatabaseName+"PURCHASE_RETURN_MASTER PRM
			INNER JOIN "+@DatabaseName+"PURCHASE_RETURN_DETAIL PRD ON PRM.PUR_RET_ID=PRD.PUR_RET_ID 
			INNER  JOIN "+@DatabaseName+"LEDGER_MASTER PurLM ON PRM.PUR_ACC_ID=PurLM.LGR_ID
			INNER  JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PRM.LGR_ID
			LEFT  JOIN  "+@DatabaseName+"LEDGER_MASTER ALM ON ALM.LGR_ID=PRM.AGENT_ID
			INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID=PRD.ITEM_ID
			INNER JOIN "+@DatabaseName+"COMPANY_MASTER COMP ON COMP.CMP_CODE=PRM.CMP_CODE
			LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_Id=PCM.City_Id
			LEFT JOIN "+@DatabaseName+"City_Master ACM ON ALM.City_Id=ACM.City_Id			
            LEFT JOIN   " + @DatabaseName +"STATE_MASTER SM ON SM.STATE_ID=LM.STATE_ID
            LEFT JOIN   " + @DatabaseName +"CITY_MASTER DCM ON PRM.STATION_ID=DCM.CITY_ID		
			WHERE PRM.PUR_ACC_ID="+@PurAccID+"  AND  PRM.Cmp_Code="+@Cmp_Code+" 
			"+@JoinSql+"
			AND  PRM.PUR_RET_DATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
			Order by PRM.PUR_RET_DATE,PRM.DOCNO,PARTYNAME
			"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[PROC_SPECIALPURCHASEITEMSUMMARY]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
