CREATE PROCEDURE [dbo].[PROC_SPECIALPURCHASEITEMSUMMARY]
(
	@FromDate  nvarchar(20),
	@ToDate nvarchar(20),
	@Cmp_Code nvarchar(10),
	@DatabaseName nvarchar(50),
	@PurAccID nvarchar(20),
	@PartyID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""

	BEGIN
set nocount on;
if @PartyID>0
SET @JoinSql="And PIM.LGR_ID="+@PartyID+""


SELECT @SQL="
			Select IGM.Item_Grp_Name,IM.Item_Name,
			sum(PID.Bales) As Bale,Sum(PID.Pieces) As Than,sum(PID.Quantity) As Qty,
			sum(CASE When UM.Unit_Name='Bales' or UM.Unit_Name='Dozen' or UM.Unit_Name='Kilograms' or UM.Unit_Name='Meters' Then (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*PID.Quantity Else IM.Item_conversion*PID.Quantity End)
			Else (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*PID.Pieces Else IM.Item_conversion*PID.Pieces End) End) As NetQty,
			sum(PID.Amount) As GTotal
			From "+@DatabaseName+"PurchaseInvoice PIM 
			INNER JOIN "+@DatabaseName+"PurchaseInvoice_Detail PID ON PIM.PURCHASEINVID=PID.PURCHASEINVID And PIM.Flag=PID.Flag
			INNER JOIN "+@DatabaseName+"Item_Master IM ON PID.Item_Id=IM.Item_Id
			INNER JOIN "+@DatabaseName+"Item_Group_Master IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id
			INNER JOIN "+@DatabaseName+"Unit_Master UM ON IM.Unit_Id=UM.Unit_Id
			WHERE PIM.Flag='P' AND PIM.PurAccId="+@PurAccID+" AND  PIM.Cmp_Code="+@Cmp_Code+"
			"+@JoinSql+"
			AND PIM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
			Group By IGM.Item_Grp_Name,IM.Item_Name
			"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

