/*   
Proc_SpecialPurchaseRegister '01/APR/2010','28/DEC/2010',10,'ACC2010_2011.DBO.',1,1
*/

CREATE PROCEDURE [dbo].[PROC_SPECIALPURCHASEREGISTER]
(
		
        @FromDate  nvarchar(20),
		@ToDate nvarchar(20),		
        @Cmp_Code nvarchar(10),
		@DatabaseName nvarchar(50),        
		@PurAccID nvarchar(20),
		@PartyID nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @JoinSql AS NVARCHAR(1000)
SET @SQL=""
SET @JoinSql=""

	BEGIN
set nocount on;
if @PartyID>0
SET @JoinSql="And PIM.LGR_ID="+@PartyID+""


SELECT @SQL="
	        SELECT PIM.LGR_ID,PIM.VCHDATE,PIM.BILLNO,PIM.GROSSTOTAL,PIM.NETTOTAL,PUR_INV_ADD1 AS ADD1,PUR_INV_ADD2 AS ADD2,PUR_INV_ADD3 AS ADD3,PUR_INV_ADD4 AS ADD4,PUR_INV_ADD5 AS ADD5,PUR_INV_ADD6 AS ADD6
            ,PUR_INV_LESS1 AS LESS1,PUR_INV_LESS2 AS LESS2,PUR_INV_LESS3 AS LESS3,PUR_INV_LESS4 AS LESS4,PUR_INV_LESS5 AS LESS5,
            PIM.LOTNO,
            PurLM.Lgr_Name As PurAccName,LM.LGR_NAME AS PARTYNAME,PCM.City_Name As PartyCity,ALM.LGR_NAME AS AGENT,ACM.City_Name As AgentCity,
			PID.BALENO,IM.ITEM_NAME AS ITEM,PID.PIECES,
            (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
            ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END )  AS QUANTITY
            ,PID.Bales As BALES,PID.Pieces As THAN,PID.Quantity As QTY,
			(PID.AMOUNT)+(((PID.AMOUNT)*(PIM.NETTOTAL- PIM.GROSSTOTAL))/PIM.GROSSTOTAL) AS AMOUNT
            ,PID.RATE,(PIM.ADDTOTAL-PIM.LESSTOTAL) AS ADDLESS,VM.Weaver_Name,
            CMP.CMP_ALIAS,IGM.ITEM_GRP_NAME AS ITEMGROUP,SGM.SUPP_GRP_NAME AS SUPPLIERGROUP			
			FROM "+@DatabaseName+"PURCHASEINVOICE PIM
			INNER JOIN "+@DatabaseName+"PURCHASEINVOICE_DETAIL PID ON PIM.PURCHASEINVID=PID.PURCHASEINVID AND PIM.Flag=PID.Flag
			INNER  JOIN "+@DatabaseName+"LEDGER_MASTER PurLM ON PIM.PurAccId=PurLM.LGR_ID
			INNER  JOIN "+@DatabaseName+"LEDGER_MASTER LM ON LM.LGR_ID=PIM.LGR_ID
			LEFT  JOIN  "+@DatabaseName+"LEDGER_MASTER ALM ON ALM.LGR_ID=PIM.AGENT_ID
			INNER JOIN "+@DatabaseName+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
            INNER JOIN "+@DatabaseName+"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
            INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
			LEFT JOIN "+@DatabaseName+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PIM.CMP_CODE
			LEFT JOIN "+@DatabaseName+"City_Master PCM ON LM.City_Id=PCM.City_Id
			LEFT JOIN "+@DatabaseName+"City_Master ACM ON ALM.City_Id=ACM.City_Id
			LEFT JOIN "+@DatabaseName+"Weaver_Master VM ON PID.Weaver_Id=VM.Weaver_Id         
            LEFT JOIN "+@DatabaseName+"SUPPLIER_GROUP_MASTER SGM ON LM.SUPP_GRP_ID=SGM.SUPP_GRP_ID
			WHERE PIM.PurAccId="+@PurAccID+"  AND  PIM.Cmp_Code="+@Cmp_Code+" 
			"+@JoinSql+"
			AND  PIM.VCHDATE BETWEEN '"+@FromDate+"' AND '"+@ToDate+"'
			Order by PIM.VchDate,PIM.PURCHASEINVID,PIM.BillNo,PARTYNAME
			"
      
END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

