CREATE PROCEDURE [dbo].[PROC_SPSALES_ITEM] 
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@SALACCID AS NVARCHAR(20),
@PARTYID AS NVARCHAR(20),
@AGENTID AS NVARCHAR(20),
@PARTYSUMM AS INT,
@AGENTSUMM AS INT,
@PRINTREG AS INT,
@ITEMSUM AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @PARTYCOND AS NVARCHAR(4000)
DECLARE @AGENTCOND AS NVARCHAR(4000)
SET @SQL=""
SET @PARTYCOND=""
SET @AGENTCOND=""


     BEGIN
        IF @PARTYID>0 
          SET   @PARTYCOND=" AND SI.LGR_ID="+ @PARTYID 
     END
     BEGIN
         IF @AGENTID>0      
         SET @AGENTCOND=" AND SI.AGENT_ID="+@AGENTID
     END

	SET NOCOUNT ON;

BEGIN
SET @SQL="
          

Select IGM.Item_Grp_Name,IM.Item_Name,
			Sum(SID.SAL_INV_PCS) As Than,
			sum(CASE When UM.Unit_Name='Bales' or UM.Unit_Name='Dozen' or UM.Unit_Name='Kilograms' or UM.Unit_Name='Meters' Then (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*SID.SAL_INV_QTY Else IM.Item_conversion*SID.SAL_INV_QTY End)
			Else (CASE WHEN IM.Item_Conversion=0 or IM.Item_Conversion is null Then 1*SID.SAL_INV_PCS Else IM.Item_conversion*SID.SAL_INV_PCS End) End) As METER,SUM(SID.SAL_INV_AMOUNT )AS ITEMVALUE
			
			From "+@DatabaseName+"SALES_INVOICE SI
			INNER JOIN  "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID
			INNER JOIN "+@DatabaseName+"Item_Master IM ON SID.Item_Id=IM.Item_Id
			INNER JOIN "+@DatabaseName+"Item_Group_Master IGM ON IM.Item_Grp_Id=IGM.Item_Grp_Id
			INNER JOIN "+@DatabaseName+"Unit_Master UM ON IM.Unit_Id=UM.Unit_Id
            WHERE  SI.SAL_ACCID="+ @SALACCID + " AND SI.SAL_INV_VDATE BETWEEN + '"+ @FROMDATE + "' AND '"+ @TODATE + "'  AND SI.CMP_CODE IN (" +@CMP_CODE + ")
            " + @PARTYCOND   + @AGENTCOND   + " 
             Group By IGM.Item_Grp_Name,IM.Item_Name

"


EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

END




















GO

