/*   
PROC_SPSALES_PRINTREG 1,'ACC2015_2016.DBO.','01/APR/2015','28/DEC/2016','8963','0','0',4,'##2716',1
*/

CREATE PROCEDURE [dbo].[PROC_SPSALES_PRINTREG] 
(
@CMP_CODE AS NVARCHAR(100),
@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@SALACCID AS NVARCHAR(20),
@PARTYID AS NVARCHAR(20),
@AGENTID AS NVARCHAR(20),
@RPTWISE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@CRITERIA AS NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @PARTYCOND AS NVARCHAR(4000)
DECLARE @AGENTCOND AS NVARCHAR(4000)
DECLARE @ORDERBYSQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)
DECLARE @CRIORDERBYSQL AS NVARCHAR(4000)

SET @SQL=""
SET @PARTYCOND=""
SET @AGENTCOND=""
SET @ORDERBYSQL=""
SET @JOINSQL=""
SET @CRIORDERBYSQL=""

BEGIN
IF @PARTYID>0 
SET @PARTYCOND=" AND SI.LGR_ID="+ @PARTYID 
END
BEGIN
IF @AGENTID>0      
SET @AGENTCOND=" AND SI.AGENT_ID="+@AGENTID
END

IF @RPTWISE = 1 
BEGIN 
	IF @CRITERIA = 1 /* SELECTED AGENT WISE */
	BEGIN
		SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = SI.AGENT_ID "
			IF @RPTWISE <> 4
			BEGIN
				SET @CRIORDERBYSQL = " ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0), "
			END
			ELSE
			BEGIN
				SET @CRIORDERBYSQL = ""
			END
	END	
	ELSE IF @CRITERIA = 2 /* SELECTED PARTY WISE */
	BEGIN
		SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = SI.LGR_ID "
		IF @RPTWISE <> 3
			BEGIN
				SET @CRIORDERBYSQL = " LM.LGR_NAME,ISNULL(LM.LGR_ID,0), "
			END
		ELSE
			BEGIN
				SET @CRIORDERBYSQL = " "
			END
	END
END

ELSE IF @RPTWISE = 2 /* ITEM WISE */
BEGIN
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = IM.ITEM_ID "
SET @ORDERBYSQL = " IM.ITEM_NAME,ISNULL(IM.ITEM_ID,0), "
END

ELSE IF @RPTWISE = 3 /* PARTY WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = LM.LGR_ID "
SET @ORDERBYSQL = " LM.LGR_NAME,ISNULL(LM.LGR_ID,0), "
END

ELSE IF @RPTWISE = 4 /* AGENT WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = ALM.LGR_ID "
SET @ORDERBYSQL = " ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0), "
END

ELSE IF @RPTWISE = 5 /* PARTYCITY WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = PCM.CITY_ID "
SET @ORDERBYSQL = " PCM.CITY_NAME,ISNULL(PCM.CITY_ID,0), "
END

ELSE IF @RPTWISE = 6 /* STATION WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = STA.CITY_ID "
SET @ORDERBYSQL = " STA.CITY_NAME,ISNULL(STA.CITY_ID,0), "
END

ELSE IF @RPTWISE = 7 /* STATE WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = STM.STATE_ID "
SET @ORDERBYSQL = " STM.STATE_NAME,ISNULL(STM.STATE_ID,0), "
END

ELSE IF @RPTWISE = 8 /* AGENT WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = S_M.SALESMAN_ID "
SET @ORDERBYSQL = " S_M.SALESMAN_NAME,ISNULL(S_M.SALESMAN_ID,0),ALM.LGR_NAME,ISNULL(ALM.LGR_ID,0), "
END

ELSE IF @RPTWISE = 9 /* CUSTOMERGROUP WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = CGM.CUST_GRP_ID "
SET @ORDERBYSQL = " CGM.CUST_GRP_NAME,ISNULL(CGM.CUST_GRP_ID,0), "
END

ELSE IF @RPTWISE = 10 /* SCREEN WISE */
BEGIN    
SET @JOINSQL = " INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE = SCM.SCREEN_ID "
SET @ORDERBYSQL = " SCM.SCREEN_NAME,ISNULL(SCM.SCREEN_ID,0),"
END

SET NOCOUNT ON;

BEGIN
SET @SQL="
SELECT SAC.LGR_NAME AS SALESACCOUNT,SAC.LGR_ID AS SALESACCID, LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENT,
ACM.CITY_NAME AS AGENTCITY, SI.SAL_INV_BILL_NO AS BILLNO,SAL_INV_VDATE AS BILLDATE,SAL_INV_LRNO AS LRNO,SAL_INV_LRDATE AS LRDATE,
IM.ITEM_NAME AS ITEM,SID.SAL_INV_BALENO AS BALENO,SID.SAL_INV_QTY AS QUANTITY,SID.SAL_INV_RATE AS RATE,SI.SAL_INV_GROSSTOTAL AS GROSSTOTAL,
SI.SAL_INV_ROUNDOFF AS RO,
SI.SAL_INV_NETTOTAL AS NETTOTAL,TM.TRANSPORT_NAME AS TRANSPORT,SI.ORDERNO,SI.ORDERDATE,
SI.SAL_INV_ADD1 AS ADD1,SI.SAL_INV_ADD2 AS ADD2,SI.SAL_INV_ADD3 AS ADD3,SI.SAL_INV_ADD4 AS ADD4,SI.SAL_INV_ADD5 AS ADD5,
SI.SAL_INV_LESS1 AS LESS1,SI.SAL_INV_LESS2 AS LESS2,SI.SAL_INV_LESS3 AS LESS3,SI.SAL_INV_LESS4 AS LESS4,SI.SAL_INV_LESS5 AS LESS5,
SI.SAL_INV_ADDTOTAL AS ADDTOTAL,SI.SAL_INV_LESSTOTAL AS LESSTOTAL,
(CASE  WHEN UM.UNIT_NAME='PIECES' THEN SID.SAL_INV_PCS ELSE SID.SAL_INV_QTY END)  AS METER,
SID.SAL_INV_PCS AS THAN,IGM.ITEM_GRP_NAME AS ITEMGROUP,
(SID.SAL_INV_AMOUNT)+(((SID.SAL_INV_AMOUNT)*(SI.SAL_INV_NETTOTAL- SI.SAL_INV_GROSSTOTAL))/SI.SAL_INV_GROSSTOTAL) AS ITEMVALUE			
,STM.STATE_NAME AS STATE,STA.CITY_NAME AS STATION,S_M.SALESMAN_NAME AS SALESMAN,CGM.CUST_GRP_NAME AS CUSTOMERGROUP
,SCM.SCREEN_NAME AS SCREEN,CT.CUT_NAME,
ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(PCM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ACM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(IM.ITEM_ID,0) AS ITEMID,ISNULL(SCM.SCREEN_ID,0) AS SCREENID,
ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(IGM.ITEM_GRP_ID,0) AS ITEMGRPID,
ISNULL(STM.STATE_ID,0) AS STATEID,ISNULL(STA.CITY_ID,0) AS STATIONID,
ISNULL(S_M.SALESMAN_ID,0) AS SALESMANID,ISNULL(CGM.CUST_GRP_ID,0) AS CUSTGRPID,
ISNULL(SI.CONFNO,0) AS CONFNO,CONFDATE

FROM  "+ @DATABASENAME +"LEDGER_MASTER SAC
INNER JOIN "+ @DATABASENAME +"SALES_INVOICE SI ON SAC.LGR_ID=SI.SAL_ACCID
INNER JOIN "+ @DATABASENAME +"SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID
INNER JOIN "+ @DATABASENAME +"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID            
LEFT JOIN  "+ @DATABASENAME +"SCREEN_MASTER SCM ON SCM.SCREEN_ID=SID.SCREEN_ID
INNER JOIN "+ @DATABASENAME +"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID 
INNER JOIN "+ @DATABASENAME +"ITEM_GROUP_MASTER IGM ON IGM.ITEM_GRP_ID=IM.ITEM_GRP_ID
INNER JOIN "+ @DATABASENAME +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
INNER JOIN "+ @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
LEFT JOIN  "+ @DATABASENAME +"LEDGER_MASTER ALM ON ALM.LGR_ID=SI.AGENT_ID
LEFT JOIN  "+ @DATABASENAME +"CITY_MASTER PCM  ON PCM.CITY_ID=LM.CITY_ID
LEFT JOIN  "+ @DATABASENAME +"CITY_MASTER ACM  ON ACM.CITY_ID=ALM.CITY_ID
LEFT JOIN  "+ @DATABASENAME +"STATE_MASTER STM ON STM.STATE_ID=LM.STATE_ID
LEFT JOIN  "+ @DATABASENAME +"CITY_MASTER STA  ON STA.CITY_ID=SI.STATION_ID
LEFT JOIN  "+ @DATABASENAME +"SALESMAN_MASTER S_M  ON S_M.SALESMAN_ID=ALM.SALESMAN_ID            
LEFT JOIN  "+ @DATABASENAME +"CUSTOMER_GROUP_MASTER CGM  ON CGM.CUST_GRP_ID=LM.CUST_GRP_ID 
LEFT JOIN  "+ @DATABASENAME +"CUT_MASTER CT ON CT.CUT_ID=SID.CUT_ID
"+@JOINSQL+"
WHERE  SI.SAL_ACCID="+ @SALACCID + " AND SI.SAL_INV_VDATE BETWEEN '"+ @FROMDATE + "' AND '"+ @TODATE + "'  AND SI.CMP_CODE IN (" +@CMP_CODE + ")
/*" + @PARTYCOND   + @AGENTCOND   + " */
AND SI.FLAG='S' AND SI.SAL_INV_TYPE='B'
ORDER BY "+@ORDERBYSQL+@CRIORDERBYSQL+"SI.SAL_INV_VDATE,CONVERT(INT,SI.SAL_INV_BILL_NO),SID.SAL_INV_BALENO
"
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL
END

















GO

