CREATE PROCEDURE [dbo].[PROC_SPSALES_RET_PRINTREG] 
(
	@CMP_CODE AS NVARCHAR(100),
	@DATABASENAME AS NVARCHAR(100),
	@FROMDATE AS NVARCHAR(20),
	@TODATE AS NVARCHAR(20),
	@PARTYID AS NVARCHAR(20),
	@AGENTID AS NVARCHAR(20),
    @HEADID  NVARCHAR(10)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @PARTYCOND AS NVARCHAR(4000)
DECLARE @AGENTCOND AS NVARCHAR(4000)
SET @SQL=""
SET @PARTYCOND=""
SET @AGENTCOND=""


     BEGIN
        IF @PARTYID>0 
          SET   @PARTYCOND=" AND SR.LGR_ID="+ @PARTYID 
     END
     BEGIN
         IF @AGENTID>0      
         SET @AGENTCOND=" AND SR.AGENT_ID="+@AGENTID
     END
 
BEGIN
SET @SQL="
SELECT SR.SAL_RET_ID,SR.DOCNO,SR.SAL_RET_DATE AS SRDATE ,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS PARTYCITY,ALM.LGR_NAME AS AGENTNAME,ACM.CITY_NAME AS AGENTCITY,
       DCM.CITY_NAME AS DESTCITY,
       SM.STATE_NAME as STATENAME, IM.ITEM_NAME AS ITEMNAME,SC.SCREEN_NAME AS SCREENNAME,SRD.SAL_RET_PCS AS PCS,SRD.SAL_RET_QTY AS QUANTITY
       ,(CASE  WHEN UM.UNIT_NAME='METERS' THEN SRD.SAL_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SRD.SAL_RET_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END))
        ELSE  (SRD.SAL_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION=NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) AS CONVERSION
       ,SRD.SAL_RET_RATE AS RATE,SRD.SAL_RET_AMOUNT AS ITEMVALUE
	   ,SR.GROSSTOTAL AS GROSSTOTAL,SR.SAL_RET_LESSTOTAL AS LESSTOTAL,SR.SAL_RET_ADDTOTAL AS ADDTOTAL,SR.RoundedAmount AS NETVALUE
        ,SAM.SALESMAN_NAME AS SALESMAN
	   FROM " + @DatabaseName +"SALES_RETURN_MASTER SR
	   INNER JOIN  " + @DatabaseName +"SALES_RETURN_DETAIL SRD ON SRD.SAL_RET_ID=SR.SAL_RET_ID
	   INNER JOIN  " + @DatabaseName +"LEDGER_MASTER LM ON SR.LGR_ID=LM.LGR_ID		
       INNER JOIN  " + @DatabaseName +"LEDGER_MASTER ALM ON SR.AGENT_ID=ALM.LGR_ID		
	   INNER JOIN  " + @DatabaseName +"ITEM_MASTER IM ON SRD.ITEM_ID=IM.ITEM_ID
        INNER JOIN  " + @DatabaseName +"UNIT_MASTER UM ON IM.UNIT_ID=UM.UNIT_ID
		LEFT JOIN   " + @DatabaseName +"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
        LEFT JOIN   " + @DatabaseName +"CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID
		LEFT JOIN   " + @DatabaseName +"STATE_MASTER SM ON LM.STATE_ID=SM.STATE_ID
		LEFT JOIN   " + @DatabaseName +"CITY_MASTER DCM ON SR.STATION_ID=DCM.CITY_ID
		LEFT JOIN   " + @DatabaseName +"SCREEN_MASTER SC ON SC.SCREEN_ID=SRD.SCREEN_ID
        LEFT JOIN   " + @DatabaseName +"SALESMAN_MASTER SAM ON ALM.SALESMAN_ID=SAM.SALESMAN_ID
		WHERE SR.SAL_ACC_ID="+@HEADID+" AND  SR.CMP_CODE IN (" +@CMP_CODE + ") AND SR.SAL_RET_DATE >= '" + @FROMDATE + "' AND SR.SAL_RET_DATE <='" + @TODATE + "'
		" + @PARTYCOND   + @AGENTCOND   + " ORDER BY SR.DOCNO "
 
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL

END




















GO

