/*
-- =============================================
-- AUTHOR :		<PATEL PRATIK>
-- EDIT_DATE : <03/07/2018,16:52PM>
-- REPORT_FORM : <rfrmStatement1A>
-- CRYSTAL_REPORT : <STATEMENT1A.RPT>
-- =============================================
SELECT * FROM ACC2018_2019.DBO.LEDGER_MASTER WHERE LGR_NAME LIKE 'JOB%'
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_STATEMENT1AREPORT N'1', N'Acc2018_2019.Dbo.', N'01/Apr/2018', N'31/Mar/2019', 2, '##1920'
*/ 
CREATE PROCEDURE [dbo].[PROC_STATEMENT1AREPORT]
(
@CMP_CODE NVARCHAR(20),
@DATABASENAME NVARCHAR(50),
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),  
@RPT_WISE INT,
@SAL_ACC_ID NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @ACCSQL AS NVARCHAR(4000)

SET @SQL=""
SET @ACCSQL=""

BEGIN	
	IF @RPT_WISE=1 
		SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=PI.PURACCID"
	ELSE IF @RPT_WISE=2 
		SET @ACCSQL="INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=JM.JOB_SALACCID"
END

BEGIN
SET NOCOUNT ON;
IF @RPT_WISE=1
SET @SQL="
SELECT ROW_NUMBER() over(order by VCHDATE,BILLNO)SRNO,PARTYNAME,PARTY_GSTINNO,BILLNO,VCHDATE,TAXABLEAMT,CGST,SGST,IGST,FLAG,CESSAMT,SUPPLY_TYPE,GST_TYPE,PURCHSEACC FROM (

SELECT LM.LGR_NAME AS PARTYNAME,LM.GSTINNO AS PARTY_GSTINNO,PI.BILLNO,PI.VCHDATE ,
(ISNULL(PI.GROSSTOTAL,0) +ISNULL(PI.PUR_INV_ADD1,0) + ISNULL(PI.PUR_INV_ADD2,0) + ISNULL(PI.PUR_INV_ADD3,0) -( ISNULL(PI.PUR_INV_LESS1,0) + ISNULL(PI.PUR_INV_LESS2,0) + ISNULL(PI.PUR_INV_LESS3,0) + ISNULL(PI.PUR_INV_LESS4,0)+ ISNULL(PI.PUR_INV_LESS5,0))) AS TAXABLEAMT,
PI.PUR_INV_ADD4 AS CGST,
PI.PUR_INV_ADD5 AS SGST, 
PI.PUR_INV_ADD6 AS IGST,
PI.FLAG,ISNULL(TOTALCESS,0) AS CESSAMT,LM1.SUPPLY_TYPE AS SUPPLY_TYPE,'Eligible ITC' AS GST_TYPE,LM1.LGR_NAME AS PURCHSEACC
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurACcId
"+@ACCSQL+"
WHERE PI.CMP_CODE IN ("+@CMP_CODE+")   AND
PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.FLAG IN ('P','JP','FP')  
AND (ISNULL(LM.GSTINNO,'')<>'' AND ISNULL(LM.GSTINNO,'')<>'0') AND ISNULL(LM.REGISTER_DEALER_TYPE,'') <> 'Composition Dealer'

UNION ALL

SELECT LM.LGR_NAME AS PARTYNAME,LM.GSTINNO AS PARTY_GSTINNO,PI.BILLNO,PI.VCHDATE ,SUM(ISNULL(PID.AMOUNT,0)) AS TAXABLEAMT,SUM(PID.VAT_AMT) AS CGST,SUM(PID.VATAMOUNT1) AS SGST,
SUM(PID.VATAMOUNT2) AS IGST,PI.FLAG ,SUM(ISNULL(PID.CESSAMT,0)) AS CESSAMT,LM1.SUPPLY_TYPE AS SUPPLY_TYPE,PI.GST_TYPE,LM1.LGR_NAME AS PURCHSEACC
FROM "+@DATABASENAME+"PURCHASEINVOICE PI
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=PI.PurAccID
"+@ACCSQL+"
WHERE  PI.CMP_CODE IN ("+@CMP_CODE+")  AND
PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND
((PI.FLAG ='CHP' AND PI.PUR_FORM_TYPE = 'B' )) 
AND (ISNULL(LM.GSTINNO,'')<>'' AND ISNULL(LM.GSTINNO,'')<>'0') AND ISNULL(LM.REGISTER_DEALER_TYPE,'') <> 'Composition Dealer'

GROUP BY PI.PURCHASEINVID,PI.BILLNO,LM.LGR_NAME,LM.GSTINNO,PI.VCHDATE,PI.FLAG,LM1.SUPPLY_TYPE,PI.GST_TYPE,LM1.LGR_NAME
) AS DETAIL
ORDER BY VCHDATE,BILLNO
"
ELSE
SET @SQL="
SELECT ROW_NUMBER() over(order by JOB_SAL_INV_BILL_NO)SRNO,LM.LGR_NAME AS PARTYNAME,LM.GSTINNO AS PARTY_GSTINNO,
(CASE WHEN ISNULL(JM.SALES_ALIAS,'')='' THEN CONVERT(NVARCHAR, JM.JOB_SAL_INV_BILL_NO) ELSE (ISNULL(JM.SALES_ALIAS,'') + '/' +CONVERT(NVARCHAR, JM.JOB_SAL_INV_BILL_NO)) END) AS BILLNO,
JM.JOB_SAL_INV_VDATE as VCHDATE, 
(ISNULL(JM.TOTAL,0) +ISNULL(JM.SAL_INV_ADD1,0) + ISNULL(JM.SAL_INV_ADD2,0) -( ISNULL(JM.SAL_INV_LESS1,0) + ISNULL(JM.SAL_INV_LESS2,0) + ISNULL(JM.SAL_INV_LESS3,0) + ISNULL(JM.SAL_INV_LESS4,0)+ ISNULL(JM.SAL_INV_LESS5,0))) AS TAXABLEAMT,
JM.SAL_INV_ADD3 AS CGST,
JM.SAL_INV_ADD4 AS SGST, 
JM.SAL_INV_ADD5 AS IGST,SALES_ALIAS ,  0 AS CESSAMT,JM.FORM_FLAG as SUPPLY_TYPE,'Eligible ITC' AS GST_TYPE,LM1.LGR_NAME AS PURCHSEACC
FROM "+@DATABASENAME+"JOB_SALESINVOICE_MASTER JM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=JM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=JM.JOB_SALACCID
"+@ACCSQL+"
WHERE  JM.CMP_CODE IN ("+@CMP_CODE+")  AND JM.FORM_FLAG='JS' AND 
JM.JOB_SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' 

UNION ALL

SELECT ROW_NUMBER() over(order by SAL_INV_BILL_NO)SRNO,LM.LGR_NAME AS PARTYNAME,LM.GSTINNO AS PARTY_GSTINNO,
(CASE WHEN ISNULL(JM.SALES_ALIAS,'')='' THEN CONVERT(NVARCHAR, JM.SAL_INV_BILL_NO) ELSE (ISNULL(JM.SALES_ALIAS,'') + '/' +CONVERT(NVARCHAR, JM.SAL_INV_BILL_NO)) END) AS BILLNO,
JM.SAL_INV_VDATE as VCHDATE, 
(ISNULL(JM.Sal_Inv_GrossTotal,0) +ISNULL(JM.SAL_INV_ADD1,0) + ISNULL(JM.SAL_INV_ADD2,0) -
( ISNULL(JM.SAL_INV_LESS1,0) + ISNULL(JM.SAL_INV_LESS2,0) + ISNULL(JM.SAL_INV_LESS3,0) + 
ISNULL(JM.SAL_INV_LESS4,0)+ ISNULL(JM.SAL_INV_LESS5,0))) AS TAXABLEAMT,
JM.SAL_INV_ADD3 AS CGST,
JM.SAL_INV_ADD4 AS SGST, 
JM.SAL_INV_ADD5 AS IGST,SALES_ALIAS,0 AS CESSAMT,JM.Flag as SUPPLY_TYPE,'Eligible ITC' AS GST_TYPE,LM1.LGR_NAME AS PURCHSEACC
FROM "+@DATABASENAME+"SALES_INVOICE JM
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=JM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM1 ON LM1.LGR_ID=JM.Sal_AccID
INNER JOIN "+@SAL_ACC_ID+" TT ON TT.CODE=JM.Sal_AccID
WHERE  JM.CMP_CODE IN ("+@CMP_CODE+")   AND JM.FLAG IN ('S','GSN','MS') AND 
JM.SAL_INV_VDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'

ORDER BY VCHDATE,BILLNO
"

END	
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL












GO

