/*
PROC_STOCK_OUT_REPORT   1,'ACC2012_2013.dbo.','01/apr/2012','31/mar/2013',##1452,6,1,2
*/
CREATE PROCEDURE [dbo].[PROC_STOCK_OUT_REPORT]
(
@CmpCode nvarchar(50),
@DataBase nvarchar(50),
@FromDate nvarchar(50),
@ToDate nvarchar(50),
@TempTable nvarchar(50),
@RptWise int,
@RptType int,
@SumDel int
)
AS

DECLARE @STRSQL as NVARCHAR(4000) set @STRSQL=""
DECLARE @JOIN as NVARCHAR(4000) set @JOIN=""
DECLARE @COND as NVARCHAR(4000) set @COND=""
DECLARE @GRPBY as NVARCHAR(4000) set @GRPBY=""

BEGIN 
IF 	@RptWise=1 
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.ITEM_ID "
		SET @GRPBY=" "
		END	
else IF @RptWise=2
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id"
		SET @GRPBY=" ,Item_Grp_Name "
		END
else IF @RptWise=3 
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IG.Item_Grp_Id"
		SET @GRPBY=" ,Item_Grp_Name "
		END
else IF @RptWise=4
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IT.Item_Type_Id "
		SET @GRPBY=" ,Item_Type_Name "
		END
else IF @RptWise=5
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IT.Item_Type_Id"
		SET @GRPBY=" ,Item_Type_Name "
		END
else IF @RptWise=6
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=SM.Screen_Id "
		SET @GRPBY=" ,Screen_Name "
		END
else IF @RptWise=7
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=IM.Item_Id"
		SET @GRPBY=" ,Screen_Name "
		END
else IF @RptWise=8
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
		SET @GRPBY=" ,TRANSPORT_NAME "
		END
else IF @RptWise=9
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
		SET @GRPBY=" ,TRANSPORT_NAME "
		END
else IF @RptWise=10
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=TM.Transport_Id"
		SET @GRPBY=" ,TRANSPORT_NAME "
		END
else IF @RptWise=11
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.STOCKOUT_ID "
		SET @GRPBY=" ,STD.LOTNO "
		END
else IF @RptWise=12
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.STOCKOUT_ID"
		SET @GRPBY=" ,FOLD "
		END
else IF @RptWise=13
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.STOCKOUT_ID"
		SET @GRPBY=" ,STD.DESIGN_COL_CHART "
		END	
else IF @RptWise=14
		BEGIN
		SET  @JOIN=" INNER JOIN "+@TempTable+" TT on TT.CODE=STD.STOCKOUT_ID"
		SET @GRPBY=" ,STM.DOCNO "
		END	
END

BEGIN
if @RptType=1
	SET @COND=" AND STM.STOCKOUT_TYPE='C'"
else if @RptType=2
	SET @COND=" AND STM.STOCKOUT_TYPE='O'"
else if @RptType=3
	SET @COND=" AND STM.STOCKOUT_TYPE='FP' "
else if @RptType=4
	SET @COND=" "
END

BEGIN
	
	SET NOCOUNT ON;
if @SumDel=1 
BEGIN
SET @STRSQL="
select STM.DOCNO,STM.VCHDATE,IM.Item_Name,SM.Screen_Name,BALENO,Pieces,Quantity,Rate,Amount,IG.Item_Grp_Name
,IT.Item_Type_Name,TM.TRANSPORT_NAME,STD.LOTNO,STD.DESIGN_COL_CHART,FOLD as FOLDNO
,STD.LRNO
from "+@DataBase+" STOCKOUT_MASTER STM
inner join "+@DataBase+" STOCKOUT_DETAIL STD on STM.STOCKOUT_ID=STD.STOCKOUT_ID
left join "+@DataBase+" Item_Master IM on STD.Item_Id=IM.Item_Id
left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
left join "+@DataBase+" Item_Type_Master IT on IT.Item_Type_Id=IM.Item_Type_Id
left join "+@DataBase+" Transport_Master TM on STM.TRANSPORT_ID=TM.TRANSPORT_ID
"+@JOIN+"
WHERE STM.CMP_CODE in ("+@CmpCode+") and STM.VCHDATE BETWEEN '"+@FromDate+"' and '"+@ToDate+"'
"+@COND+"
ORDER BY STM.DOCNO,BALENO
"
END
else if @SumDel=2 
BEGIN
	SET @STRSQL="
select max(STM.DOCNO) as DOCNO,max(STM.VCHDATE) as VCHDATE,IM.Item_Name,SM.Screen_Name,count(BALENO) as BALENO
,sum(Pieces) as Pieces,sum(Quantity) as Quantity,max(Rate)as Rate,max(Amount) as Amount,max(IG.Item_Grp_Name) as Item_Grp_Name
,max(IT.Item_Type_Name) as Item_Type_Name,max(TM.TRANSPORT_NAME) as TRANSPORT_NAME,max(STD.LOTNO) as LOTNO,
max(STD.DESIGN_COL_CHART) as DESIGN_COL_CHART,max(FOLD) as FOLDNO
,MAX(STD.LRNO) AS LRNO,MAX(STD.LOTNO) AS LOTNO
from "+@DataBase+" STOCKOUT_MASTER STM
inner join "+@DataBase+" STOCKOUT_DETAIL STD on STM.STOCKOUT_ID=STD.STOCKOUT_ID
left join "+@DataBase+" Item_Master IM on STD.Item_Id=IM.Item_Id
left join "+@DataBase+" Screen_Master SM on STD.Screen_Id=SM.Screen_Id
left join "+@DataBase+" Item_Group_Master IG on IM.Item_Grp_Id=IG.Item_Grp_Id
left join "+@DataBase+" Item_Type_Master IT on IT.Item_Type_Id=IM.Item_Type_Id
left join "+@DataBase+" Transport_Master TM on STM.TRANSPORT_ID=TM.TRANSPORT_ID
"+@JOIN+"
WHERE STM.CMP_CODE in ("+@CmpCode+") and STM.VCHDATE BETWEEN '"+@FromDate+"' and '"+@ToDate+"'
"+@COND+"
Group by IM.Item_Name,SM.Screen_Name
"+@GRPBY+"
"
END
END

EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL

set ANSI_NULLS ON
set QUOTED_IDENTIFIER OFF




















GO

