/*
PROC_STOCKINREGISTER 2,'ACC2010_2011.DBO.',1,'01/APR/2010','01/APR/2011','''C''',''
*/
CREATE PROCEDURE [dbo].[PROC_STOCKINREGISTER]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @RPT_WISE INT,
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @ENT_TYPE NVARCHAR(200),
   @TEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @ENTTYPE_SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(1000)
set @SQL=""
set @ENTTYPE_SQL=""
set @JOINSQL=""
begin
		IF @RPT_WISE=1 
			BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SIM.TRANSPORT_ID "
			END
		ELSE IF @RPT_WISE=2
		   BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SID.ITEM_ID "
			END
		ELSE IF @RPT_WISE=3
		   BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SID.SCREEN_ID "
	end		END
BEGIN

	SET @SQL="	SELECT SIM.DOCNO,SIM.VCHDATE,TM.TRANSPORT_NAME,IM.ITEM_NAME,SC.SCREEN_NAME 
		,SID.BALENO,SID.PIECES,SID.QUANTITY,SID.RATE,SID.AMOUNT,CMP.CMP_ALIAS
		FROM "+@DATABASENAME+"STOCKIN_MASTER SIM
		INNER JOIN "+@DATABASENAME+"STOCKIN_DETAIL SID ON SID.STOCKIN_ID=SIM.STOCKIN_ID
        INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SIM.TRANSPORT_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SID.ITEM_ID
		INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SC ON SC.SCREEN_ID=SID.SCREEN_ID
        INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SIM.CMP_CODE
        "+ @JOINSQL +"
        WHERE SIM.CMP_CODE IN ("+@CMP_CODE +") AND SIM.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'       
        AND SIM.STOCKIN_TYPE IN ("+@ENT_TYPE+")  
        ORDER BY SIM.DOCNO "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

