/*
  PROC_STOCKOUTPRINTREPORT 1,'ACC2012_2013.DBO.',1,1
*/
CREATE PROCEDURE [dbo].[PROC_STOCKOUTPRINTREPORT]
(
	@Cmp_Code nvarchar(50), 
	@DatabaseName nvarchar(50),
	@FromBillNo nvarchar(50),
	@ToBillNo nvarchar(50)
)
AS
DECLARE @SQL nvarchar(4000) SET @SQL=""

BEGIN	
	SET NOCOUNT ON;
SET @SQL="
select SM.DocNo,SM.vchDate,SM.LOTNO,SM.OUT_LOCAL,SM.PRINT_POPLIN,TM.Transport_Name,LM.lgr_Name as PartyName,
SCM.City_Name as StationName,PCm.City_Name as PartyCity,SM.TinNo,SM.Remark,SM.LrDate,SM.Narration,SM.PIECESTOTAL,
SM.QUANTITYTOTAL,SM.GROSSTOTAL,SM.ADD1,SM.ADD2,SM.ADDTotal,SM.LESS1,SM.LESS2,SM.LESSTOTAL,SM.ROUNDOFF,SM.NETTOTAL,SM.RESULT,
SD.BALENo,SD.LRNO as DetailLrNo,IM.Item_Name,SSM.screen_Name,UM.Unit_Name,SD.LotNO as DetailLOtNo,SD.DESIGN_COL_CHART,
SD.FOLD,SD.PIECES,SD.QUANTITY,SD.RATE,SD.AMOUNT,LM.LGR_ADD1,LM.LGR_ADD2,LM.LGR_ADD3,LM.LGR_DISTRICT,LM.CITY_PINCODE,st.state_name
FROM "+@DatabaseName+" STOCKOUT_MASTER SM
INNER JOIN "+@DatabaseName+" STOCKOUT_DETAIL SD ON SM.STOCKOUT_ID=SD.STOCKOUT_ID
LEFT JOIN "+@DatabaseName+" Transport_Master TM ON SM.TRANSPORT_Id=TM.TRANSPORT_Id
left join "+@DatabaseName+" Ledger_Master LM on LM.lgr_Id=SM.Lgr_Id
left join "+@DatabaseName+" City_Master PCM on PCM.City_Id=LM.City_Id
left join "+@DatabaseName+" City_Master SCM on SM.station_Id=SCM.City_Id
left join "+@DatabaseName+" Item_Master IM on SD.Item_Id=IM.Item_Id
left join "+@DatabaseName+" Screen_Master SSM on SSM.Screen_Id=SD.Screen_Id
left join "+@DatabaseName+" Unit_Master UM on SD.Unit_Id=UM.Unit_Id
left join "+@DatabaseName+" State_Master St on St.state_Id=lm.state_Id
where SM.Cmp_Code in ("+@Cmp_Code+") and SM.DocNo between "+@FromBillNo+" and "+@ToBillNo+"

"

    
END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

