/*   
PROC_STOCKOUTPROCESS '10','ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011',1,2,'##2010','30/JUN/2010'
*/
CREATE PROCEDURE [dbo].[PROC_STOCKOUTPROCESS]
(
   @CMP_CODE NVARCHAR(50),
   @DATABASENAME  NVARCHAR(100),
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @RPT_WISE  INT,
   @RPT_TYPE  INT,
   @TEMPTABLE  NVARCHAR(20),
   @DATE NVARCHAR(20)
 )
	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @DATESQL AS NVARCHAR(1000)

SET @SQL="" 
SET @JOINSQL="" 
SET @DATESQL="" 
  /*   - DATE CONDITION FOR PROCESS AND GREY */ 

SET @DATESQL=" AND VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE +"'"
 BEGIN 
        IF @RPT_WISE=1          
          SET @DATESQL=" AND VCHDATE='"+@DATE+"'"
        ELSE IF @RPT_WISE=2
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID" 
        ELSE IF @RPT_WISE=3
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID" 
        ELSE IF @RPT_WISE=4
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=PM.PROCESS_ID" 
        ELSE IF @RPT_WISE=5
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=P2P.LOTNO" 
        ELSE IF @RPT_WISE=6
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID" 
        ELSE IF @RPT_WISE=7        
          SET @JOINSQL=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID" 
 END
BEGIN
IF @RPT_TYPE=1 
     BEGIN
       SET  @SQL=" SELECT P2P.LOTNO,IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS VIEWER,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
           ,LM.LGR_NAME AS PARTY,ISNULL(PCM.CITY_NAME,'') AS PARTYCITY,PM.PROCESS_NAME AS PROCESS,P2P.DELTHAN AS THAN,DELMETER AS METER,ISNULL(OUTSIDE_TYPE,'') AS TYPE,CMP.CMP_ALIAS
           FROM "+@DATABASENAME+"PROCESS2PROCESS P2P
           INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=P2P.ITEM_ID
           INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=P2P.WEAVER_ID
           INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=P2P.TO_LGR_ID
           LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
           INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.PROCESS_ID=P2P.FROM_PROCESS_ID
           INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PMO ON PMO.PROCESS_ID=P2P.TO_PROCESS_ID
           INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
           LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
           LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=P2P.CMP_CODE
           "+@JOINSQL+"
           WHERE  PMO.OUTSIDE=1 AND P2P.CMP_CODE IN ("+@CMP_CODE+")" +@DATESQL+" 
           ORDER BY P2P.LOTNO"
     END
ELSE IF @RPT_TYPE=2
     BEGIN
          SET @SQL=" SELECT GS.LOTNO,IM.ITEM_NAME AS ITEM,WM.WEAVER_NAME AS VIEWER,IGM.ITEM_GRP_NAME AS ITEMGROUP,ITM.ITEM_TYPE_NAME AS ITEMTYPE
                    ,'' AS PARTY,'' AS PARTYCITY,'' AS PROCESS,GS.PCS AS THAN,GS.GRAYMTRS AS METER,ISNULL(STOCKOUT,'') AS TYPE,CMP.CMP_ALIAS
                    FROM "+@DATABASENAME+"GRAYSTOCKOUT GS
                    INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=GS.ITEM_ID
                    INNER JOIN "+@DATABASENAME+"WEAVER_MASTER WM ON WM.WEAVER_ID=GS.WEAVER_ID
                    INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
                    LEFT JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER ITM ON IM.ITEM_TYPE_ID=ITM.ITEM_TYPE_ID
                    LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=GS.CMP_CODE
                    WHERE   GS.CMP_CODE IN ("+@CMP_CODE+")" +@DATESQL+" 
                    ORDER BY GS.LOTNO
                 "  
     END
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

