/*
PROC_STOCKOUTREGISTER 2,'ACC2010_2011.DBO.',4,'01/APR/2010','01/APR/2011','''C''',''
*/
CREATE PROCEDURE [dbo].[PROC_STOCKOUTREGISTER]
(
   @CMP_CODE NVARCHAR(100),
   @DATABASENAME NVARCHAR(100),
   @RPT_WISE INT,
   @FROMDATE NVARCHAR(20),
   @TODATE NVARCHAR(20),
   @ENT_TYPE NVARCHAR(200),
   @TEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @ENTTYPE_SQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(1000)
set @SQL=""
set @ENTTYPE_SQL=""
set @JOINSQL=""
begin
		IF @RPT_WISE=1 
			BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SOM.TRANSPORT_ID "
			END
		ELSE IF @RPT_WISE=2
		   BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SOD.ITEM_ID "
			END
		ELSE IF @RPT_WISE=3
		   BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SOD.SCREEN_ID "
	       END
        ELSE IF @RPT_WISE=4
		   BEGIN
			  SET @JOINSQL=""
	       END
        ELSE IF @RPT_WISE=5
		   BEGIN
			  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SOM.LGR_ID "
	       END
		ELSE IF @RPT_WISE=6
				   BEGIN
					  SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE + " TT ON TT.CODE=SOM.STATION_ID "
				   END

end		
BEGIN

	SET @SQL="	SELECT SOM.DOCNO,SOM.VCHDATE,TM.TRANSPORT_NAME,LM.LGR_NAME,ST.CITY_NAME AS STATION,IM.ITEM_NAME,SC.SCREEN_NAME 
		,SOD.BALENO,SOD.PIECES,SOD.QUANTITY,SOD.RATE,SOD.AMOUNT,CMP.CMP_ALIAS
		FROM "+@DATABASENAME+"STOCKOUT_MASTER SOM
		INNER JOIN "+@DATABASENAME+"STOCKOUT_DETAIL SOD ON SOD.STOCKOUT_ID=SOM.STOCKOUT_ID
        LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SOM.TRANSPORT_ID
        LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SOM.LGR_ID
        LEFT JOIN "+@DATABASENAME+"CITY_MASTER ST ON ST.CITY_ID=SOM.STATION_ID
		INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=SOD.ITEM_ID
		INNER JOIN "+@DATABASENAME+"SCREEN_MASTER SC ON SC.SCREEN_ID=SOD.SCREEN_ID
        INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=SOM.CMP_CODE
        "+ @JOINSQL +"
        WHERE SOM.CMP_CODE IN ("+@CMP_CODE +") AND SOM.VCHDATE BETWEEN '"+@FROMDATE +"' AND '"+@TODATE +"'       
        AND SOM.STOCKOUT_TYPE IN ("+@ENT_TYPE+")  
        ORDER BY SOM.DOCNO "

END
PRINT @SQL
EXECUTE SP_EXECUTESQL @SQL




















GO

