/* -- ============================================= 
-- AUTHOR : PRATIK 
-- ALTER_DATE	: 10/06/2014 
-- REPORT_FORM	: RFRMSTOCKPAPERREPORT.CS 
-- REPORT_NAME	: STOCKPAPERREPORT.RPT 
-- ============================================= 


SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_STOCKPAPERREPORT N'ACC2014_2015.DBO.', N'1', N'01/APR/2014', N'09/JUL/2016', 1, N'##3416' 
*/ 



CREATE PROCEDURE [dbo].[PROC_STOCKPAPERREPORT] 
( 
@DATABASENAME NVARCHAR(50), 
@CMP_CODE NVARCHAR(50), 
@FROMDATE NVARCHAR(20), 
@TODATE NVARCHAR(20), 
@RPT_TYPE INT, 
@TEMPTABLE NVARCHAR(50)
) 
AS 

DECLARE @STRSQL AS NVARCHAR(4000)
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @STRJOIN AS NVARCHAR(4000) 
DECLARE @ORDERBYSQL AS NVARCHAR(4000) 
DECLARE @STRGROUPBY_PI AS NVARCHAR(4000) 
DECLARE @STRGROUPBY_GR AS NVARCHAR(4000) 
DECLARE @STRFIELDNAME AS NVARCHAR(4000)
DECLARE @STRMAINFILEDNAME AS NVARCHAR(4000) 
DECLARE @STRMAINGRPBY AS NVARCHAR(4000) 
DECLARE @STRSUPPLIER_PI AS NVARCHAR(4000) 
DECLARE @STRSUPPLIER_GR AS NVARCHAR(4000) 
DECLARE @STRSQL2 AS NVARCHAR(4000)

SET @STRSQL = "" 
SET @SQL = "" 
SET @STRJOIN= "" 
SET @ORDERBYSQL="" 
SET @STRGROUPBY_PI=""
SET @STRGROUPBY_GR=""
SET @STRFIELDNAME=""
SET @STRSUPPLIER_PI=""
SET @STRSUPPLIER_GR=""
SET @STRSQL2=""

IF @RPT_TYPE=1 /* DATE */
BEGIN SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PI.VCHDATE" 
SET @ORDERBYSQL=" VCHDATE " 

SET @STRGROUPBY_PI=" PI.VCHDATE"
SET @STRGROUPBY_GR=" PI.VCHDATE"

SET @STRMAINGRPBY=" VCHDATE"
SET @STRSUPPLIER_PI = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"
SET @STRSUPPLIER_GR = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"

SET @STRFIELDNAME=" PI.VCHDATE as VCHDATE,MAX(IM.ITEM_NAME) AS ITEM,MAX(LM.LOT_NAME)MARKA,MAX(TM.TRANSPORT_NAME)TRANSPORT,MAX(IM.ITEM_ID) AS ITEM_ID,MAX(LM.LOT_ID) AS LOT_ID,MAX(TM.TRANSPORT_ID) AS TRANSPORT_ID, "
SET @STRMAINFILEDNAME=" VCHDATE AS VCHDATE,MAX(ITEM) AS ITEM,MAX(MARKA)MARKA,MAX(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP)  AS SUPPLIERGRP,MAX(ITEM_ID) AS ITEM_ID,MAX(LOT_ID) AS LOT_ID,MAX(TRANSPORT_ID) AS TRANSPORT_ID, "
END 
IF @RPT_TYPE=2  /* MARKA */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LOT_ID" 
SET @ORDERBYSQL="MARKA,LOT_ID,SUPPLIERGRP,SUPP_GRP_ID " 

SET @STRGROUPBY_PI=" LM.LOT_NAME,LM.LOT_ID,(ISNULL(SGM.SUPP_GRP_NAME,'')),ISNULL(SGM.SUPP_GRP_ID,0)  "
SET @STRGROUPBY_GR=" LM.LOT_NAME,LM.LOT_ID,(ISNULL(SGM.SUPP_GRP_NAME,'')),ISNULL(SGM.SUPP_GRP_ID,0)  "

SET @STRMAINGRPBY=" MARKA,LOT_ID,SUPPLIERGRP,SUPP_GRP_ID "
SET @STRSUPPLIER_PI = " (ISNULL(SGM.SUPP_GRP_NAME,'')) AS SUPPLIERGRP,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID, "
SET @STRSUPPLIER_GR = " (ISNULL(SGM.SUPP_GRP_NAME,'')) AS SUPPLIERGRP,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPP_GRP_ID,"

SET @STRFIELDNAME="MAX(CONVERT(NVARCHAR,PI.VCHDATE,103))VCHDATE,MAX(IM.ITEM_NAME) AS ITEM,(LM.LOT_NAME)MARKA,MAX(TM.TRANSPORT_NAME)TRANSPORT,MAX(IM.ITEM_ID) AS ITEM_ID,LM.LOT_ID AS LOT_ID,MAX(TM.TRANSPORT_ID) AS TRANSPORT_ID,"
SET @STRMAINFILEDNAME="MAX(CONVERT(NVARCHAR,VCHDATE,103))VCHDATE,MAX(ITEM) AS ITEM,(MARKA)MARKA,MAX(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP) AS SUPPLIERGRP,MAX(ITEM_ID) AS ITEM_ID,LOT_ID AS LOT_ID,MAX(TRANSPORT_ID) AS TRANSPORT_ID, "
END 
IF @RPT_TYPE=3 /* ITEM(QUALITY) */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID" 
SET @ORDERBYSQL=" ITEM,ITEM_ID " 

SET @STRGROUPBY_PI=" IM.ITEM_NAME,IM.ITEM_ID "
SET @STRGROUPBY_GR=" IM.ITEM_NAME,IM.ITEM_ID "

SET @STRMAINGRPBY=" ITEM,ITEM_ID " 
SET @STRSUPPLIER_PI = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"
SET @STRSUPPLIER_GR = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"

SET @STRFIELDNAME="MAX(CONVERT(NVARCHAR,PI.VCHDATE,103))VCHDATE,IM.ITEM_NAME AS ITEM,MAX(LM.LOT_NAME)MARKA,MAX(TM.TRANSPORT_NAME)TRANSPORT,IM.ITEM_ID AS ITEM_ID,MAX(LM.LOT_ID) AS LOT_ID,MAX(TM.TRANSPORT_ID) AS TRANSPORT_ID, "
SET @STRMAINFILEDNAME="MAX(CONVERT(NVARCHAR,VCHDATE,103))VCHDATE,ITEM AS ITEM,MAX(MARKA)MARKA,MAX(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP)  AS SUPPLIERGRP,ITEM_ID AS ITEM_ID,MAX(LOT_ID) AS LOT_ID,MAX(TRANSPORT_ID) AS TRANSPORT_ID, "
END 
IF @RPT_TYPE=4 /* TRANSPORT */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID" 
SET @ORDERBYSQL="TRANSPORT,TRANSPORT_ID,MARKA,LOT_ID " 

SET @STRGROUPBY_PI=" TM.TRANSPORT_NAME,TM.TRANSPORT_ID,LM.LOT_NAME,LM.LOT_ID "
SET @STRGROUPBY_GR=" TM.TRANSPORT_NAME,TM.TRANSPORT_ID,LM.LOT_NAME,LM.LOT_ID "

SET @STRMAINGRPBY=" TRANSPORT,TRANSPORT_ID,MARKA,LOT_ID "
SET @STRSUPPLIER_PI = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"
SET @STRSUPPLIER_GR = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"

SET @STRFIELDNAME="MAX(CONVERT(NVARCHAR,PI.VCHDATE,103))VCHDATE,MAX(IM.ITEM_NAME) AS ITEM,LM.LOT_NAME AS MARKA,(TM.TRANSPORT_NAME)TRANSPORT,MAX(IM.ITEM_ID) AS ITEM_ID,MAX(LM.LOT_ID) AS LOT_ID,TM.TRANSPORT_ID AS TRANSPORT_ID, "
SET @STRMAINFILEDNAME="MAX(CONVERT(NVARCHAR,VCHDATE,103))VCHDATE,MAX(ITEM) AS ITEM,MARKA,(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP) AS SUPPLIERGRP,MAX(ITEM_ID) AS ITEM_ID,MAX(LOT_ID) AS LOT_ID,TRANSPORT_ID AS TRANSPORT_ID, "
END 
IF @RPT_TYPE=5 /* MARKA/ITEM */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LOT_ID" 
SET @ORDERBYSQL="MARKA,LOT_ID,ITEM ,ITEM_ID " 

SET @STRGROUPBY_PI=" LM.LOT_NAME,LM.LOT_ID,IM.ITEM_NAME,IM.ITEM_ID "
SET @STRGROUPBY_GR=" LM.LOT_NAME,LM.LOT_ID,IM.ITEM_NAME,IM.ITEM_ID "

SET @STRMAINGRPBY=" MARKA,LOT_ID,ITEM,ITEM_ID "
SET @STRSUPPLIER_PI = " MAX(ISNULL(SGM.SUPP_GRP_NAME,'')) AS SUPPLIERGRP,MAX(ISNULL(SGM.SUPP_GRP_ID,0)) AS SUPP_GRP_ID, "
SET @STRSUPPLIER_GR = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"
SET @STRFIELDNAME="MAX(CONVERT(NVARCHAR,PI.VCHDATE,103))VCHDATE,(IM.ITEM_NAME) AS ITEM,(LM.LOT_NAME)MARKA,MAX(TM.TRANSPORT_NAME)TRANSPORT,IM.ITEM_ID AS ITEM_ID,LM.LOT_ID AS LOT_ID,MAX(TM.TRANSPORT_ID) AS TRANSPORT_ID, " 
SET @STRMAINFILEDNAME="MAX(CONVERT(NVARCHAR,VCHDATE,103))VCHDATE,(ITEM) AS ITEM,(MARKA)MARKA,MAX(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP) AS SUPPLIERGRP,ITEM_ID AS ITEM_ID,LOT_ID AS LOT_ID,MAX(TRANSPORT_ID) AS TRANSPORT_ID, " 
END 
IF @RPT_TYPE=6 /* ITEM/MARKA */
BEGIN 
SET @STRJOIN=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID" 
SET @ORDERBYSQL="MARKA,LOT_ID,ITEM,ITEM_ID " 

SET @STRGROUPBY_PI=" IM.ITEM_NAME,IM.ITEM_ID,LM.LOT_NAME ,LM.LOT_ID"
SET @STRGROUPBY_GR=" IM.ITEM_NAME,IM.ITEM_ID,LM.LOT_NAME,LM.LOT_ID "

SET @STRMAINGRPBY=" MARKA,LOT_ID,ITEM,ITEM_ID  "
SET @STRSUPPLIER_PI = " MAX(ISNULL(SGM.SUPP_GRP_NAME,'')) AS SUPPLIERGRP,MAX(ISNULL(SGM.SUPP_GRP_ID,0)) AS SUPP_GRP_ID, "
SET @STRSUPPLIER_GR = " '' AS SUPPLIERGRP,0 AS SUPP_GRP_ID,"

SET @STRFIELDNAME="MAX(CONVERT(NVARCHAR,PI.VCHDATE,103))VCHDATE,(IM.ITEM_NAME) AS ITEM,(LM.LOT_NAME)MARKA,MAX(TM.TRANSPORT_NAME)TRANSPORT,IM.ITEM_ID AS ITEM_ID,LM.LOT_ID AS LOT_ID,MAX(TM.TRANSPORT_ID) AS TRANSPORT_ID, " 
SET @STRMAINFILEDNAME="MAX(CONVERT(NVARCHAR,VCHDATE,103))VCHDATE,(ITEM) AS ITEM,(MARKA)MARKA,MAX(TRANSPORT)TRANSPORT,MAX(SUPPLIERGRP) AS SUPPLIERGRP,ITEM_ID AS ITEM_ID,LOT_ID AS LOT_ID,MAX(TRANSPORT_ID) AS TRANSPORT_ID, " 
END 



BEGIN 
SET NOCOUNT ON; 

SET @SQL = "SELECT "+@STRMAINFILEDNAME+"
(SUM(TRANSPORT_PCS)- SUM(BUNCH_PCS)) AS BALES,
(SUM(TRANSPORT_PCS)-SUM(GODOWN_PCS)) AS TRANSPORTBALES,(SUM(GODOWN_PCS)-SUM(BUNCH_PCS)) AS GODOWN
FROM(
SELECT "+@STRFIELDNAME+@STRSUPPLIER_PI+" SUM(PID.PIECES) AS TRANSPORT_PCS ,0 AS  GODOWN_PCS,0 AS BUNCH_PCS
FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG 
	AND PI.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"TRANSPORT_LR_DETAIL TLD ON TLD.PURCHASEINVID=PID.PURCHASEINVID AND TLD.LRNO=PID.LRNO 
	AND  TLD.TRANSPORT_ID=PID.TRANSPORT_ID AND  TLD.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID=PID.LOT_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
"+@STRJOIN+"
WHERE PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE+"
GROUP BY "+@STRGROUPBY_PI+"

UNION ALL 

SELECT "+@STRFIELDNAME+@STRSUPPLIER_GR+" 0 AS TRANSPORT_PCS,SUM(GRD.PIECES) AS GODOWN_PCS,0 AS BUNCH_PCS

FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG 
	AND PI.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"GRAYRECEIPT_DETAIL GRD ON GRD.PURCHASEINVID = PID.PURCHASEINVID
	AND GRD.LRNO=PI.LRNO AND GRD.TRANSPORT_ID=PID.TRANSPORT_ID AND  GRD.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID=PID.LOT_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
"+@STRJOIN+"
WHERE PI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PI.CMP_CODE="+@CMP_CODE+"
GROUP BY "+@STRGROUPBY_GR+" "
SET @STRSQL2="
UNION ALL

SELECT "+@STRFIELDNAME+@STRSUPPLIER_GR+" 0 AS TRANSPORT_PCS,0 AS GODOWN_PCS,
SUM(GRD.PIECES) AS BUNCH_PCS
FROM "+@DATABASENAME+"PURCHASEINVOICE_DETAIL PID
INNER JOIN "+@DATABASENAME+"PURCHASEINVOICE PI ON PI.PURCHASEINVID=PID.PURCHASEINVID AND PI.FLAG=PID.FLAG 
	AND PI.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"GRAYRECEIPT_DETAIL GRD ON GRD.PURCHASEINVID = PID.PURCHASEINVID
	AND GRD.LRNO=PI.LRNO AND GRD.TRANSPORT_ID=PID.TRANSPORT_ID AND  GRD.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"BUNCHPREPARATION_LRDETAIL BPD ON GRD.PURCHASEINVID = BPD.PURCHASEINVID
	AND GRD.LRNO=BPD.LRNO AND  GRD.CMP_CODE=PID.CMP_CODE
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID=PID.ITEM_ID
LEFT JOIN "+@DATABASENAME+"LOT_MASTER LM ON LM.LOT_ID=PID.LOT_ID
LEFT JOIN "+@DATABASENAME+"SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=PI.SUPP_GRP_ID
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PI.TRANSPORT_ID
 "+@STRJOIN+"
WHERE BPD.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND BPD.CMP_CODE="+@CMP_CODE+"
GROUP BY  "+@STRGROUPBY_GR+" 
) AS DETAIL GROUP BY "+@STRMAINGRPBY+" 
HAVING (SUM(TRANSPORT_PCS)-SUM(GODOWN_PCS)) != 0 OR (SUM(GODOWN_PCS)-SUM(BUNCH_PCS)) != 0
ORDER BY "+@ORDERBYSQL+"
"
 
END 
PRINT @SQL 
PRINT @STRSQL2
EXEC (@SQL +@STRSQL2)



















GO

