/*   
select * from tempdb..sysobjects where name like '##%'
PROC_STOCKRPT '1', N'Acc2015_2016.Dbo.', N'01/Apr/2014', N'23/JUNE/2016', N'##2332', 6,'',0 
*/
CREATE PROCEDURE [dbo].[PROC_STOCKRPT]
(
   @CMP_CODE AS NVARCHAR(50),
   @DATABASENAME AS NVARCHAR(100),
   @FROMDATE AS NVARCHAR(20),
   @TODATE AS NVARCHAR(20),
   @TEMPTABLE AS NVARCHAR(50),
   @RPT_WISE AS INT,
   @ItemType AS NVARCHAR(50),
   @Pcs_Conversion AS INT
)
AS

DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @SQL4 AS NVARCHAR(4000)
DECLARE @SQL5 AS NVARCHAR(4000)
DECLARE @SQL6 AS NVARCHAR(4000)
DECLARE @SQL7 AS NVARCHAR(4000)
DECLARE @SQL8 AS NVARCHAR(4000)
DECLARE @SQL9 AS NVARCHAR(4000)
DECLARE @SQL10 AS NVARCHAR(4000)
DECLARE @SQL11 AS NVARCHAR(4000)
DECLARE @SQL12 AS NVARCHAR(4000)
DECLARE @SQL13 AS NVARCHAR(4000)
DECLARE @SQL14 AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLSELECTION AS NVARCHAR(4000)
DECLARE @SQLGROUPBY AS NVARCHAR(4000)
DECLARE @STRITEMTYPE AS NVARCHAR(4000)
DECLARE @SQLPCSCONVERSI AS NVARCHAR(4000)
DECLARE @SQLPCSCONVERSR AS NVARCHAR(4000)
DECLARE @SQLORDERBY AS NVARCHAR(500)

SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @SQL4=""
SET @SQL5=""
SET @SQL6=""
SET @SQL7=""
SET @SQL8=""
SET @SQL9=""
SET @SQL10=""
SET @SQL11=""
SET @SQL12=""
SET @SQL13=""
SET @SQLJOIN=""
SET @SQLSELECTION =""
SET @SQLGROUPBY =""
SET @STRITEMTYPE=""
SET @SQLPCSCONVERSI = ""
SET @SQLPCSCONVERSR = ""
SET @SQLORDERBY=""

BEGIN 
     IF @RPT_WISE=1
           BEGIN 
              SET  @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IM.ITEM_ID" 
              SET @SQLSELECTION ="SELECT  ITEM ,ITEM_ID ,ITEMGROUP,ITEM_GRP_ID,max(ITEM_TYPE_ID) as ITEM_TYPE_ID,max(ITEM_TYPE_NAME) as ITEM_TYPE_NAME,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,SUM(PRODUCTION) AS PRODUCTION,SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(ISSUE2PRO) AS ISSUE2PRO,SUM(PURRETURN) AS PURRETURN"
              SET @SQLGROUPBY=" GROUP BY ITEM ,ITEM_ID , ITEMGROUP,ITEM_GRP_ID  HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(PRODUCTION)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(ISSUE2PRO)<>0 OR SUM(PURRETURN)<>0) ORDER BY ITEM ,ITEM_ID "
              
           END
     ELSE IF @RPT_WISE=2 
          BEGIN
             SET  @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID" 
             SET  @SQLSELECTION ="SELECT  ITEM ,ITEM_ID ,ITEMGROUP,ITEM_GRP_ID,max(ITEM_TYPE_ID) as ITEM_TYPE_ID,max(ITEM_TYPE_NAME) as ITEM_TYPE_NAME,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,SUM(PRODUCTION) AS PRODUCTION,SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(ISSUE2PRO) AS ISSUE2PRO,SUM(PURRETURN) AS PURRETURN"
             SET @SQLGROUPBY=" GROUP BY ITEM ,ITEM_ID , ITEMGROUP,ITEM_GRP_ID  HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(PRODUCTION)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(ISSUE2PRO)<>0 OR SUM(PURRETURN)<>0) ORDER BY ITEMGROUP,ITEM_GRP_ID , ITEM ,ITEM_ID "
              
          END
     ELSE IF @RPT_WISE=3
          BEGIN  
             SET  @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=IGM.ITEM_GRP_ID" 
             SET  @SQLSELECTION ="SELECT MIN(ITEM) AS ITEM  ,MIN(ITEM_ID) AS ITEM_ID, ITEMGROUP,ITEM_GRP_ID,max(ITEM_TYPE_ID)AS ITEM_TYPE_ID,max(ITEM_TYPE_NAME) AS ITEM_TYPE_NAME,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,SUM(PRODUCTION) AS PRODUCTION,SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(ISSUE2PRO) AS ISSUE2PRO,SUM(PURRETURN) AS PURRETURN"
             SET @SQLGROUPBY=" GROUP BY ITEMGROUP,ITEM_GRP_ID  HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(PRODUCTION)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(ISSUE2PRO)<>0 OR SUM(PURRETURN)<>0) ORDER BY ITEMGROUP,ITEM_GRP_ID "
              
          END
		 ELSE IF @RPT_WISE=4
          BEGIN
             SET  @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID" 
             SET  @SQLSELECTION ="SELECT  ITEM ,ITEM_ID ,MAX(ITEMGROUP)ITEMGROUP,MAX(ITEM_GRP_ID)ITEM_GRP_ID,ITEM_TYPE_ID,ITEM_TYPE_NAME,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,SUM(PRODUCTION) AS PRODUCTION,SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(ISSUE2PRO) AS ISSUE2PRO,SUM(PURRETURN) AS PURRETURN"
             SET @SQLGROUPBY=" GROUP BY ITEM ,ITEM_ID , ITEM_TYPE_ID,ITEM_TYPE_NAME  HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(PRODUCTION)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(ISSUE2PRO)<>0 OR SUM(PURRETURN)<>0) ORDER BY  ITEM_TYPE_NAME,ITEM_TYPE_ID,ITEM ,ITEM_ID "
             
          END
     ELSE IF @RPT_WISE=5
          BEGIN  
             SET  @SQLJOIN=" INNER JOIN "+@TEMPTABLE +" TT ON TT.CODE=ITM.ITEM_TYPE_ID" 
             SET  @SQLSELECTION ="SELECT MIN(ITEM) AS ITEM  ,MIN(ITEM_ID) AS ITEM_ID, MAX(ITEMGROUP)ITEMGROUP,MAX(ITEM_GRP_ID)ITEM_GRP_ID,ITEM_TYPE_ID,ITEM_TYPE_NAME,SUM(OPSTOCK) AS OPSTOCK,SUM(PURCHASE) AS PURCHASE,SUM(PRODUCTION) AS PRODUCTION,SUM(SALESRETURN)AS SALESRETURN,SUM(SALES) AS SALES,SUM(ISSUE2PRO) AS ISSUE2PRO,SUM(PURRETURN) AS PURRETURN"
             SET @SQLGROUPBY=" GROUP BY ITEM_TYPE_ID,ITEM_TYPE_NAME  HAVING (SUM(OPSTOCK)<>0 OR SUM(PURCHASE)<>0 OR SUM(PRODUCTION)<>0 OR SUM(SALESRETURN)<>0 OR SUM(SALES)<>0 OR SUM(ISSUE2PRO)<>0 OR SUM(PURRETURN)<>0) ORDER BY ITEM_TYPE_NAME,ITEM_TYPE_ID "
                 
          END
END
BEGIN
IF @ItemType="''"
	SET @STRITEMTYPE=""
ELSE IF @ItemType!=""
	SET @STRITEMTYPE=" AND IM.ITEM_TYPE IN ("+@ItemType+")"
END

BEGIN
	IF @Pcs_Conversion = 1 /*  PCS CONVERSION YES */
	BEGIN
		SET @SQLPCSCONVERSI = " (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION  IS  NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
		ELSE  (SID.SAL_INV_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) "

	SET @SQLPCSCONVERSR = " (CASE  WHEN UM.UNIT_NAME='METERS' THEN SAL_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SAL_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) 
	ELSE  (SAL_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 THEN 1 WHEN IM.ITEM_CONVERSION IS NULL THEN 1 ELSE IM.ITEM_CONVERSION END)) END ) "

	END
	ELSE IF @Pcs_Conversion = 0 /* PCS CONVERSION NO */
	BEGIN
		SET @SQLPCSCONVERSI = " (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.SAL_INV_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.SAL_INV_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION  IS  NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
		ELSE  (SID.SAL_INV_QTY)  END ) "

	SET @SQLPCSCONVERSR = " (CASE  WHEN UM.UNIT_NAME='METERS' THEN SAL_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SAL_RET_QTY * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
	ELSE  (SAL_RET_QTY) END )"
	END
END
BEGIN
	
           
 SET @SQL1=  @SQLSELECTION +" FROM
(
 SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,IOS.ITEM_OP_STOCK AS OPSTOCK
 ,0.00 AS PURCHASE,0.00 AS PRODUCTION,0.00 AS  SALESRETURN,0.00 AS SALES,0.00 AS ISSUE2PRO,0.00 AS PURRETURN,ITM.ITEM_TYPE_NAME,ITM.ITEM_TYPE_ID 
 FROM "+@DATABASENAME+"ITEM_MASTER IM 
 INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=IM.ITEM_ID
 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
 LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
 "+@SQLJOIN+"
 WHERE IOS.CMP_CODE IN ("+@CMP_CODE +") "+@STRITEMTYPE+"
 UNION ALL 
 SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID, 
 (CASE  WHEN UM.UNIT_NAME='METERS' THEN SID.MTRS  WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (SID.MTRS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
  ELSE  (SID.PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION  IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS OPSTOCK
 ,0 AS PURCHASE,0 AS PRODUCTION,0 AS  SALESRETURN,0 AS SALES,0 AS ISSUE2PRO,0 AS PURRETURN,ITM.ITEM_TYPE_NAME,ITM.ITEM_TYPE_ID  
 FROM "+@DATABASENAME+"ITEM_MASTER IM
 INNER JOIN "+@DATABASENAME+"STOCKINWARD_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
 INNER JOIN "+@DATABASENAME+"STOCKINWARD_MASTER SIM ON SID.STOCKINWARD_ID=SIM.STOCKINWARD_ID
 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
 LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
 "+@SQLJOIN+"
 WHERE SIM.CMP_CODE IN ("+@CMP_CODE +") AND SIM.VCHDATE<'"+@FROMDATE+"' "+@STRITEMTYPE+"
 UNION ALL   "

SET @SQL2="     SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID, 
 (0-"+@SQLPCSCONVERSI+")AS OPSTOCK
 ,0 AS PURCHASE,0 AS PRODUCTION,0 AS  SALESRETURN,0 AS SALES,0 AS ISSUE2PRO,0 AS PURRETURN,ITM.ITEM_TYPE_NAME,ITM.ITEM_TYPE_ID  
 FROM "+@DATABASENAME+"ITEM_MASTER IM
 INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.ITEM_ID=IM.ITEM_ID
 INNER JOIN "+@DATABASENAME+"SALES_INVOICE SI ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG
 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
 LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
 "+@SQLJOIN+"
 WHERE SI.CMP_CODE IN ("+@CMP_CODE +")  AND SI.SAL_INV_VDATE<'"+@FROMDATE+"' "+@STRITEMTYPE+" 
 UNION ALL   
 SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID, 
 (0-(CASE  WHEN UM.UNIT_NAME='METERS' THEN PUR_RET_QTY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PUR_RET_QTY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
 ELSE  (PRD.PUR_RET_PCS * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION  IS NULL  THEN 1  ELSE IM.ITEM_CONVERSION END)) END )) AS OPSTOCK
 ,0 AS PURCHASE,0 AS PRODUCTION,0 AS  SALESRETURN,0 AS SALES,0 AS ISSUE2PRO,0 AS PURRETURN,ITM.ITEM_TYPE_NAME,ITM.ITEM_TYPE_ID  
 FROM "+@DATABASENAME+"ITEM_MASTER IM
 INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_DETAIL PRD ON PRD.ITEM_ID=IM.ITEM_ID
 INNER JOIN "+@DATABASENAME+"PURCHASE_RETURN_MASTER PRM ON PRD.PUR_RET_ID=PRM.PUR_RET_ID AND PRM.FLAG = PRD.FLAG
 INNER JOIN "+@DATABASENAME+"ITEM_GROUP_MASTER IGM ON IM.ITEM_GRP_ID=IGM.ITEM_GRP_ID
 INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON UM.UNIT_ID=IM.UNIT_ID
 LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
 "+@SQLJOIN+"
 WHERE PRM.CMP_CODE IN ("+@CMP_CODE +") AND PRM.PUR_RET_DATE < '"+@FROMDATE+"' "+@STRITEMTYPE+"
 UNION ALL   "

SET @SQL3="     SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
 (CASE  WHEN UM.UNIT_NAME='METERS' THEN PID.QUANTITY   WHEN UM.UNIT_NAME IN('KILOGRAMS','DOZEN') THEN (PID.QUANTITY  * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END))
  ELSE  (PID.PIECES * (CASE WHEN IM.ITEM_CONVERSION=0 OR IM.ITEM_CONVERSION IS NULL THEN 1  ELSE IM.ITEM_CONVERSION END)) END ) AS OPSTOCK 
 ,0 AS PURCHASE,0 AS PRODUCTION,0 AS  SALESRETURN,0 AS SALES,0 AS ISSUE2PRO,0 AS PURRETURN ,ITM.ITEM_TYPE_NAME,ITM.ITEM_TYPE_ID  
