 LEFT JOIN "+@DATABASENAME+" ITEM_TYPE_MASTER ITM ON ITM.ITEM_TYPE_ID=IM.ITEM_TYPE_ID
 "+@SQLJOIN+"
 WHERE SRM.CMP_CODE IN("+@CMP_CODE +") AND SRM.SAL_RET_DATE <'"+@FROMDATE+"' "+@STRITEMTYPE+"
 UNION ALL  
 " 
SET @SQL4="     SELECT IM.ITEM_NAME AS ITEM,IM.ITEM_ID,IGM.ITEM_GRP_NAME AS ITEMGROUP,IGM.ITEM_GRP_ID,
