CREATE PROCEDURE [dbo].[PROC_STOCKVALUATION_PROCESS]
(
@CMP_CODE NVARCHAR(50), 
@DATABASENAME  NVARCHAR(100),
@ASONDATE NVARCHAR(20),
@TEMPTABLE NVARCHAR(100),   
@RPT_WISE INT,
@RPTPROCESS INT
)	
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @MAINGRPSQL AS NVARCHAR(1000)
DECLARE @GRPBYSQL AS NVARCHAR(1000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @PROCESSSQL AS NVARCHAR(1000)
DECLARE @JOINSQL2 AS NVARCHAR(1000)
DECLARE @MAINGRPSQL2 AS NVARCHAR(1000)
DECLARE @GRPBYSQL2 AS NVARCHAR(1000)
DECLARE @MAINGRPSQL3 AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @MAINGRPSQL=""
SET @JOINSQL=""
SET @JOINSQL2=""
SET @MAINGRPSQL2=""
SET @GRPBYSQL2=""
SET @MAINGRPSQL3=""
SET @PROCESSSQL=""

BEGIN
IF @RPT_WISE=1 
BEGIN
SET @MAINGRPSQL =" IT.ITEM_TYPE_NAME AS MAINGROUP,'' AS SECOUNTGRP"		
SET @GRPBYSQL="IT.ITEM_TYPE_NAME"
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IT.ITEM_TYPE_ID"
SET @JOINSQL2=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IT.ITEM_TYPE_ID"
SET @MAINGRPSQL2 =" IT.ITEM_TYPE_NAME AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL2="IT.ITEM_TYPE_NAME"
SET @MAINGRPSQL3 =" IT.ITEM_TYPE_NAME AS MAINGROUP,'' AS SECOUNTGRP"
END
ELSE IF @RPT_WISE=2 
BEGIN
SET @MAINGRPSQL =" LM.LOT_NAME AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL="LM.LOT_NAME"
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LOT_ID"
SET @MAINGRPSQL2 =" LM.LOT_NAME AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL2="LM.LOT_NAME"
SET @JOINSQL2=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LM.LOT_ID"
SET @MAINGRPSQL3 =" LM.LOT_NAME AS MAINGROUP,'' AS SECOUNTGRP"
END
ELSE IF @RPT_WISE=3 
BEGIN
SET @MAINGRPSQL =" IM.ITEM_NAME AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL="IM.ITEM_NAME "
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
SET @MAINGRPSQL2 =" IM.ITEM_NAME AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL2="IM.ITEM_NAME "
SET @JOINSQL2=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=IM.ITEM_ID"
SET @MAINGRPSQL3 =" IM.ITEM_NAME AS MAINGROUP,'' AS SECOUNTGRP"
END
ELSE IF @RPT_WISE=4
BEGIN
SET @MAINGRPSQL =" LE.LOTNO AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL="LE.LOTNO "
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LE.LOTNO"
SET @MAINGRPSQL2 =" LE.LOTNO AS MAINGROUP,'' AS SECOUNTGRP"
SET @GRPBYSQL2="LE.LOTNO "         
SET @JOINSQL2=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=LE.LOTNO "
SET @MAINGRPSQL3 =" LE.LOTNO AS MAINGROUP,'' AS SECOUNTGRP"
END
ELSE IF @RPT_WISE=5
BEGIN
SET @MAINGRPSQL =" PROCESS_NAME AS MAINGROUP,CONVERT(NVARCHAR,LE.LOTNO) AS SECOUNTGRP"
SET @GRPBYSQL="LE.LOTNO "
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PM.PROCESS_ID"
SET @MAINGRPSQL2 =" 'GREY STOCK' AS MAINGROUP,LE.LOTNO AS SECOUNTGRP"
SET @GRPBYSQL2="LE.LOTNO "
SET @JOINSQL2="  "
SET @MAINGRPSQL3 =" 'FINISHFOLDING' AS MAINGROUP,CONVERT(NVARCHAR,LE.LOTNO) AS SECOUNTGRP"
END
ELSE IF @RPT_WISE=6
BEGIN
SET @MAINGRPSQL =" PROCESS_NAME AS MAINGROUP,LM.LOT_NAME AS SECOUNTGRP"
SET @GRPBYSQL="LE.LOTNO,LM.LOT_NAME  "
SET @JOINSQL=" INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=PM.PROCESS_ID"
SET @MAINGRPSQL2 =" 'GREY STOCK' AS MAINGROUP,LM.LOT_NAME AS SECOUNTGRP"
SET @GRPBYSQL2="LE.LOTNO,LM.LOT_NAME "
SET @JOINSQL2="  "
SET @MAINGRPSQL3 =" 'FINISHFOLDING' AS MAINGROUP,LM.LOT_NAME AS SECOUNTGRP"
END
END 

BEGIN
IF @RPTPROCESS = 1 /* CURRENT PROCESS */
SET @PROCESSSQL = " PM.PROCESS_ID "
ELSE IF @RPTPROCESS = 2 /* PREVIOUS PROCESS */
SET @PROCESSSQL = " (PM.PROCESS_ID-1) "
END

BEGIN
SET @SQL=" SELECT LOTNO,PROCESSID,PROCESSNAME,ITEM,MAINGROUP,SECOUNTGRP,SUM(PENDTHAN)AS PENDTHAN,
SUM(PENDMETER) AS PENDMETER,RATE AS RATE,SUM(PENDMETER)*RATE AS AMOUNT,ISNULL(CMP_ALIAS,'') AS CMP_ALIAS  
FROM  (  
SELECT LOTNO,PROCESSID,PROCESSNAME,ITEM,MAINGROUP,SECOUNTGRP,SUM(LATHAN) - SUM(PTHAN) AS PENDTHAN,
SUM(LAMETER) - SUM(PMETER) AS PENDMETER,RATE AS RATE,CMP_ALIAS           
FROM (   
SELECT LE.LOTNO,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME,IM.ITEM_NAME AS ITEM,"+@MAINGRPSQL2+",
SUM(LE.AccThan) AS LATHAN,SUM(LE.NetMeter) AS LAMETER,0 AS PTHAN,0 AS PMETER,ISNULL(LE.RATE,0) AS RATE
,CMP.CMP_ALIAS
FROM  "+@DATABASENAME+"LOTNOENTRY LE     
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON LE.ITEM_ID = IM.ITEM_ID   
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID  
LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LE.CMP_CODE
"+@JOINSQL2+"
WHERE LE.CMP_CODE IN ("+@CMP_CODE+")  AND  LE.VCHDATE <='"+@ASONDATE+"'     
GROUP BY "+@GRPBYSQL2+",LE.RATE ,LE.LOTNO,CMP_ALIAS,IM.ITEM_NAME       
UNION  
SELECT LE.LOTNO,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME,IM.ITEM_NAME AS ITEM,"+ @MAINGRPSQL2+" ,0 AS LATHAN,0 AS LAMETER, SUM(P2P.ISSUETHAN) AS PTHAN, SUM(P2P.ISSUEMETER) AS PMETER,ISNULL(LE.RATE,0) AS RATE 
,CMP.CMP_ALIAS                     
FROM   "+@DATABASENAME+"LOTNOENTRY LE 
LEFT  JOIN "+@DATABASENAME+"PROCESS2PROCESS_DETAIL P2P ON LE.LOTNO = P2P.LOTNO AND LE.CMP_CODE = P2P.CMP_CODE  
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON LE.ITEM_ID = IM.ITEM_ID   
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID  
LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LE.CMP_CODE
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PM.Process_Id=P2P.FROM_PROCESS_ID
"+@JOINSQL2+"    
WHERE P2P.CMP_CODE IN ("+@CMP_CODE+")  AND PM.PROCESSNO=1     AND  P2P.VCHDATE <='"+@ASONDATE+"'    
GROUP BY "+@GRPBYSQL2+" ,LE.LOTNO ,LE.RATE,CMP.CMP_ALIAS,IM.ITEM_NAME  
--UNION 
--SELECT LE.LOTNO,1 AS PROCESSID,'GREY STOCK' AS PROCESSNAME,IM.ITEM_NAME AS ITEM, "+ @MAINGRPSQL2+" ,0 AS LATHAN,0 AS LAMETER, SUM(GS.PCS) AS PTHAN, SUM(GS.GRAYMTRS) AS PMETER,ISNULL(LE.RATE,0) AS RATE 
--,CMP.CMP_ALIAS                     
--FROM   "+@DATABASENAME+"LOTNOENTRY LE 
--LEFT  JOIN "+@DATABASENAME+"GRAYSTOCKOUT GS ON LE.LOTNO = GS.LOTNO AND LE.CMP_CODE = GS.CMP_CODE  
--INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON LE.ITEM_ID = IM.ITEM_ID   
--INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID  
--LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
--INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=LE.CMP_CODE
--"+@JOINSQL2+"    
--WHERE GS.CMP_CODE IN ("+@CMP_CODE+")  AND  GS.VCHDATE <='"+@ASONDATE+"'    
--GROUP BY "+@GRPBYSQL2+" ,LM.LOT_NAME ,LE.LOTNO ,LE.RATE,CMP.CMP_ALIAS,IM.ITEM_NAME  
) AS A GROUP BY PROCESSID,PROCESSNAME, MAINGROUP,SECOUNTGRP,RATE,LOTNO ,CMP_ALIAS,ITEM          
HAVING SUM(LATHAN) - SUM(PTHAN)<>0 OR SUM(LAMETER) - SUM(PMETER)<>0       "

SET @SQL1="     UNION   ALL       
SELECT LOTNO,PROCESSID,PROCESSNAME,ITEM,MAINGROUP,SECOUNTGRP,SUM(PTHAN) - SUM(RECTHAN) PENDTHAN,SUM(PMETER) - SUM(RECMETER) AS PENDMETER,RATE,CMP_ALIAS    
FROM (     
SELECT LOTNO,PROCESSID,PROCESSNAME,ITEM,MAINGROUP,SECOUNTGRP,SUM(INTHAN) - SUM(OUTTHAN)  AS PTHAN ,0 AS RECTHAN,SUM(INMETER) - SUM(OUTMETER)  AS PMETER ,0 AS RECMETER,RATE,CMP_ALIAS  
FROM (  
SELECT LE.LOTNO,PM.PROCESS_ID AS PROCESSID, PM.PROCESS_NAME AS PROCESSNAME,IM.ITEM_NAME AS ITEM, "+ @MAINGRPSQL+" ,PIN.ISSUETHAN AS INTHAN,PIN.ISSUEMETER AS INMETER,0 AS OUTTHAN,0 AS OUTMETER
,ISNULL(LE.RATE,0)+(SELECT ISNULL(SUM(RATE),0) +ISNULL(MAX(GREY_MARKA_RATE),0)  
FROM "+@DATABASENAME+"GREYMARKA_PROCESS_DETAIL IPD 
WHERE IPD.PROCESS_ID<="+@PROCESSSQL+" AND IPD.LOT_ID=LM.LOT_ID) AS RATE  
,CMP.CMP_ALIAS
FROM   "+@DATABASENAME+"PROCESSIN PIN    
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON PIN.IN_PROCESS_ID = PM.PROCESS_ID 
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON PIN.ITEM_ID = IM.ITEM_ID   
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID 
LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
INNER JOIN "+@DATABASENAME+"LOTNOENTRY LE ON LE.CMP_CODE=PIN.CMP_CODE AND PIN.LOTNO=LE.LOTNO  
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PIN.CMP_CODE
"+@JOINSQL+"   
WHERE PIN.VCHDATE <='"+@ASONDATE+"'  AND PIN.CMP_CODE IN ("+@CMP_CODE+")  AND PM.OUTSIDE<>1   
UNION    ALL  
SELECT LE.LOTNO,PM.PROCESS_ID AS PROCESSID,PM.PROCESS_NAME AS OUTPROCESSNAME,IM.ITEM_NAME, "+ @MAINGRPSQL+",0 AS INTHAN,0 AS INMETER,POUT.ISSUETHAN AS OUTTHAN,POUT.ISSUEMETER AS OUTMETER 
,ISNULL(LE.RATE,0)+(SELECT ISNULL(SUM(RATE),0)+ISNULL(MAX(GREY_MARKA_RATE),0)  
FROM "+@DATABASENAME+"GREYMARKA_PROCESS_DETAIL IPD 						
WHERE IPD.PROCESS_ID<="+@PROCESSSQL+" AND IPD.LOT_ID=LM.LOT_ID) AS RATE  
,CMP.CMP_ALIAS
FROM   "+@DATABASENAME+"PROCESSOUT POUT
INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON POUT.OUT_PROCESS_ID = PM.PROCESS_ID     
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON POUT.ITEM_ID = IM.ITEM_ID   
INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID
INNER JOIN "+@DATABASENAME+"LOTNOENTRY LE ON LE.CMP_CODE=POUT.CMP_CODE AND POUT.LOTNO=LE.LOTNO  
LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=POUT.CMP_CODE
"+@JOINSQL+"   
WHERE POUT.VCHDATE <='"+@ASONDATE+"' AND POUT.CMP_CODE IN ("+@CMP_CODE+") AND PM.OUTSIDE<>1 
) AS INOUT
GROUP BY PROCESSID,PROCESSNAME,MAINGROUP,SECOUNTGRP,RATE,LOTNO,CMP_ALIAS,ITEM 
HAVING SUM(INTHAN) -  SUM(OUTTHAN) <> 0   OR SUM(INMETER) -  SUM(OUTMETER) <> 0       "
SET @SQL2="               
--				UNION ALL  
--               SELECT LE.LOTNO,PM.PROCESS_ID  AS PROCESSID,PM.PROCESS_NAME AS PROCESSNAME,IM.ITEM_NAME AS ITEM, "+ @MAINGRPSQL+", 0 AS PTHAN,SUM(RECTHAN)  AS RECTHAN,0 AS PMETER ,SUM(RECMETER)  AS RECMETER
--               ,LE.RATE+(SELECT ISNULL(SUM(RATE),0)+ISNULL(MAX(GREY_MARKA_RATE),0)   FROM "+@DATABASENAME+"GREYMARKA_PROCESS_DETAIL IPD WHERE IPD.PROCESS_ID<=PM.PROCESS_ID AND IPD.LOT_ID=LM.LOT_ID) AS RATE 
--               ,CMP.CMP_ALIAS
--                FROM "+@DATABASENAME+"FINISHTOFOLDING  F2F   
--               INNER JOIN "+@DATABASENAME+"PROCESS_MASTER PM ON F2F.PROCESS_ID = PM.PROCESS_ID    
--               INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID   
--               INNER  JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID 
--               INNER JOIN "+@DATABASENAME+"LOTNOENTRY LE ON LE.CMP_CODE=F2F.CMP_CODE AND F2F.LOTNO=LE.LOTNO  
--               LEFT JOIN   "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
--               INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=F2F.CMP_CODE
--               "+@JOINSQL+"     
--               WHERE F2F.VCHDATE <='"+@ASONDATE+"' AND F2F.CMP_CODE IN ("+@CMP_CODE+")  
--               GROUP BY PM.PROCESS_ID ,PM.PROCESS_NAME,"+@GRPBYSQL+",RATE,LE.LOTNO ,LM.LOT_ID,CMP.CMP_ALIAS,IM.ITEM_NAME 
) AS  P2P     
GROUP BY PROCESSID,PROCESSNAME,MAINGROUP,SECOUNTGRP,RATE,LOTNO,CMP_ALIAS,ITEM  
HAVING SUM(PTHAN) -  SUM(RECTHAN)  <> 0 OR SUM(PMETER) -  SUM(RECMETER)  <> 0    "
SET @SQL3="
--   UNION   ALL   
--SELECT LOTNO,PROCESSID,PROCESSNAME,ITEM, MAINGROUP,SECOUNTGRP , SUM(FTHAN)- SUM(GTHAN) AS PENDTHAN,SUM(FMETER)- SUM(GMETER) AS PENDMETER, RATE  
--,CMP_ALIAS
--FROM ( 
--SELECT FTF.LOTNO,20 AS PROCESSID,'FINISHFOLDING' AS PROCESSNAME,IM.ITEM_NAME AS ITEM, "+ @MAINGRPSQL3+", SUM(FTF.RECTHAN)  AS FTHAN ,0 AS GTHAN, SUM(FTF.RECMETER)  AS FMETER ,0 AS GMETER
--,ISNULL(LE.RATE,0)+(SELECT ISNULL(SUM(RATE),0)+ISNULL(MAX(GREY_MARKA_RATE),0)   FROM "+@DATABASENAME+"GREYMARKA_PROCESS_DETAIL IPD WHERE IPD.LOT_ID=LM.LOT_ID) AS RATE 
--,CMP.CMP_ALIAS
--FROM "+@DATABASENAME+"FINISHTOFOLDING FTF    
--INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON FTF.ITEM_ID = IM.ITEM_ID    
--INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID  
--INNER JOIN "+@DATABASENAME+"LOTNOENTRY LE ON LE.CMP_CODE=FTF.CMP_CODE AND FTF.LOTNO=LE.LOTNO 
--LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
--INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=FTF.CMP_CODE
--"+@JOINSQL2+"
--WHERE FTF.CMP_CODE IN ("+@CMP_CODE+")    AND FTF.VCHDATE <='"+@ASONDATE+"'    
--GROUP BY "+@GRPBYSQL2+",FTF.LOTNO,LE.RATE,CMP.CMP_ALIAS,IM.ITEM_NAME,LM.LOT_ID    
--UNION ALL     
--SELECT FTG.LOTNO,20 AS PROCESSID,'FINISHFOLDING' AS PROCESSNAME,IM.ITEM_NAME AS ITEM, "+ @MAINGRPSQL3+",0 AS FTHAN,SUM(FTG.GRAYTHAN)  AS GTHAN,0 AS FMETER,SUM(FTG.GRAYMETER)  AS GMETER
--,ISNULL(LE.RATE,0)+(SELECT ISNULL(SUM(RATE),0)+ISNULL(MAX(GREY_MARKA_RATE),0)   FROM "+@DATABASENAME+"GREYMARKA_PROCESS_DETAIL IPD WHERE IPD.LOT_ID=LM.LOT_ID) AS RATE 
--,CMP.CMP_ALIAS
--FROM "+@DATABASENAME+"FTGRECDETAIL FTG  
--INNER JOIN "+@DATABASENAME+"FINISH2GODOWN F2F ON F2F.LOTNO = FTG.LOTNO  AND F2F.FTGID = FTG.FTGID   AND F2F.CMP_CODE= FTG.CMP_CODE
--INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON F2F.ITEM_ID = IM.ITEM_ID    
--INNER JOIN "+@DATABASENAME+"LOT_MASTER LM ON IM.LOT_ID = LM.LOT_ID  
--INNER JOIN "+@DATABASENAME+"LOTNOENTRY LE ON LE.CMP_CODE=F2F.CMP_CODE AND F2F.LOTNO=LE.LOTNO   
--LEFT  JOIN "+@DATABASENAME+"ITEM_TYPE_MASTER IT ON IM.ITEM_TYPE_ID = IT.ITEM_TYPE_ID  
--INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=FTG.CMP_CODE
--"+@JOINSQL2+"       
--WHERE FTG.CMP_CODE IN ("+@CMP_CODE+")   AND FTG.RECDATE  <='"+@ASONDATE+"'       
--GROUP BY "+@GRPBYSQL2+",FTG.LOTNO,LE.RATE,CMP.CMP_ALIAS,IM.ITEM_NAME,LM.LOT_ID  
--) AS FINISH
--GROUP BY PROCESSID,PROCESSNAME,MAINGROUP,SECOUNTGRP ,LOTNO,RATE,CMP_ALIAS,ITEM             
--HAVING SUM(FTHAN)- SUM(GTHAN)>0 OR  SUM(FMETER)- SUM(GMETER)<>0    
) AS DETAIL  GROUP BY  PROCESSID,PROCESSNAME, MAINGROUP,SECOUNTGRP ,LOTNO,RATE,CMP_ALIAS,ITEM 
HAVING SUM(PENDTHAN) > 0 
ORDER BY PROCESSID,LOTNO  "
END   
EXECUTE (@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3

















GO

/****** Object:  StoredProcedure [dbo].[PROC_SUPPOUTSTANDING]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO











/*  
-- =============================================
-- EDIT_AUTHOR    :	<BIREN>
-- EDIT_DATE      : <08-08-2013 12:23 PM>
-- REPORT_FORM    :	<RFRMOUTSTANDING_SUPPLIER.CS>
-- CRYSTAL_REPORT : <SUPPOUTSTANDING.RPT> 
-- =============================================
select * from tempdb..sysobjects where name like '##%'
PROC_SUPPOUTSTANDING N'1', N'ACC2014_2015.DBO.', 1, 3, N'##888', N'31/MAR/2015', 1, 0, N'', N'0' 
PROC_SUPPOUTSTANDING N'1', N'ACC2015_2016.DBO.', 1, 1, N'##4980', N'31/MAR/2016', 1, 1, N'', N'0' 
*/
CREATE PROCEDURE [dbo].[PROC_SUPPOUTSTANDING]
(
@CMP_CODE NVARCHAR(50),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@RPT_TYPE INT,
@TEMPTABLE NVARCHAR(20),
@ASONDATE  NVARCHAR(20),
@ONACCOUNT  INT,
@DUEPENDING  INT,
@PREVDATABASE NVARCHAR(50),
@DAYS NVARCHAR(4)
)
AS

/*   
-- @RPT_WISE =1 MEANS PARTY WISE
-- @RPT_WISE =2 MEANS AGNET WISE
-- @RPT_WISE =3 MEANS ACCOUNT WISE
-- @RPT_WISE =4 MEANS CATEGORY WISE
-- @RPT_WISE =5 MEANS SUPPLIER GROUP WISE

--@RPT_TYPE=1 MEANS PAID
--@RPT_TYPE=2 MEANS PENDING
--@RPT_TYPE=3 MEANS ALL
*/
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQLJOIN AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT1 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT2 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT3 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT4 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT5 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT6 AS NVARCHAR(4000)
DECLARE @SQLONACCOUNT7 AS NVARCHAR(4000)
DECLARE @CONDITION AS NVARCHAR(4000)
DECLARE @ALL AS NVARCHAR(50)
DECLARE @ORDERBYSQL AS NVARCHAR(100)


SET @CONDITION=""
SET @SQLJOIN =""
SET @ALL=""
SET @ORDERBYSQL=""

BEGIN

IF @RPT_WISE=1     
BEGIN
SET @SQLJOIN=" INNER JOIN " + @TEMPTABLE + " TT ON LM.LGR_ID=TT.CODE"
SET @ORDERBYSQL=" CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=2 
BEGIN
SET @SQLJOIN ="INNER JOIN  " +  @TEMPTABLE + " TT ON TT.CODE=ALM.LGR_ID"
SET @ORDERBYSQL=" AGENT,AGENTID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=3 
BEGIN
SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=LD.GRP_ID"
SET @ORDERBYSQL=" ACCGROUP,MAIN_GRPID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=4
BEGIN
SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=CTM.CATEGORY_ID"
SET @ORDERBYSQL=" CATEGORY,CATEGORYID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

ELSE IF @RPT_WISE=5 
BEGIN
SET @SQLJOIN ="INNER JOIN " +  @TEMPTABLE + " TT ON TT.CODE=SGM.SUPP_GRP_ID"
SET @ORDERBYSQL=" SUPPLIERGROUP,SUPPGRPID,CITY,PARTY_CITYID,PARTY,PARTYID,"
END

END


BEGIN 
IF @ONACCOUNT=1
BEGIN
SET @SQLONACCOUNT =" 
UNION ALL
SELECT 0 AS VCODE,'' AS  BILL_NO,'' AS JOBFLAG,'' DATE,0 AS BILL_AMOUNT,0 AS REC_AMOUNT,TM.TRAN_DATE  AS RECDATE,0 AS DISCOUNT,0 AS INTEREST,
0 AS INTREC,'P' AS FLAG, TD.CHEQUENO,TD.DDDATE AS CHEQUEDATE,
(CASE WHEN TD.TRAN_TYPE ='J' THEN (CASE WHEN TD.TRAN_DRCR='D'THEN (TD.PARTAMOUNT) ELSE 0 END) ELSE
(CASE WHEN TD.TRAN_DRCR='D'THEN (TD.PARTAMOUNT) ELSE 0 END) END)AS PARTAMOUNT
,TD.TRAN_ID,
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(CM.CITY_NAME,'') AS  CITY,TD.TRAN_TYPE,TD.TRAN_AMOUNT,COMP.CMP_ALIAS AS ALIAS,
'' AS LRNO,'' AS LRDATE,'' AS REMARK,ISNULL(GM.GRP_NAME,'') AS ACCGROUP,ISNULL(CTM.CATEGORY_NAME,'') AS CATEGORY,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGROUP,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,(CASE WHEN TM.TRAN_DATE IS NULL THEN DATEDIFF(DAY,0,'"+@ASONDATE+"') ELSE DATEDIFF(DAY,0,TM.TRAN_DATE) END) AS DAYS,0 AS RD
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(GM.GRP_ID,0) AS MAIN_GRPID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID,
ISNULL(CTM.CATEGORY_ID,0) AS CATEGORYID
FROM " + @DATABASENAME + "TRAN_DETAIL TD 
INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=LD.AGENT_ID AND TD.TRAN_DETAIL_ID=ALM.LGR_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID  
LEFT JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID      
LEFT JOIN " + @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
LEFT JOIN " + @DATABASENAME + "CATEGORY_MASTER CTM ON CTM.CATEGORY_ID=LM.CATEGORY_ID
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=TD.CMP_CODE       
" +  @SQLJOIN + "
WHERE TM.TRAN_DATE<='"+@ASONDATE+"' AND TD.PARTAMOUNT>0 AND TD.CMP_CODE IN(" + @CMP_CODE +")        
AND (TD.TRAN_TYPE='BR'OR TD.TRAN_TYPE='CR' /*OR TD.TRAN_TYPE='SR' OR TD.TRAN_TYPE='PR'*/ OR TD.TRAN_TYPE='YSR' OR TD.TRAN_TYPE='BP' OR TD.TRAN_TYPE='CP'  OR TD.TRAN_TYPE='DN' OR TD.TRAN_TYPE='CN' OR TD.TRAN_TYPE='J' )  AND TD.CMP_CODE IN(" + @CMP_CODE +")        
AND (TD.REC_TRANS=0 OR   TD.REC_TRANS IS NULL) AND (TD.SHOWPARTAMT=1 OR TD.SHOWPARTAMT IS NULL)  
"

SET @SQLONACCOUNT1 =" 
