END
SET @SQL="
SELECT VCODE,BILL_NO,DATE,JOBFLAG,BILL_AMOUNT,REC_AMOUNT,RECDATE,DISCOUNT,INTEREST,INTREC,FLAG,CHEQUENO,
CHEQUEDATE,PARTAMOUNT,TRAN_ID,PARTY,AGENT,CITY,TRAN_TYPE,TRAN_AMOUNT,ALIAS,LRNO,LRDATE,REMARK,ACCGROUP,
CATEGORY, SUPPLIERGROUP,AGENTCITY,DAYS,RD,PARTYID,AGENTID,PARTY_CITYID,AGENT_CITYID,MAIN_GRPID,SUPPGRPID,
CATEGORYID
FROM(
SELECT PD.VCODE,PD.BILLNO AS BILL_NO,PD.FLAG AS JOBFLAG,PD.DATE,PD.AMOUNT AS BILL_AMOUNT,AM.ADJUSTAMT AS REC_AMOUNT,AM.RECDATE,ISNULL(AM.DISCOUNT,0) AS DISCOUNT,AM.INTEREST,AM.INTREC,'D' AS FLAG,AM.CHEQUENO AS CHEQUENO,AM.CHEQUEDATE AS CHEQUEDATE, 0 AS PARTAMOUNT,0 AS TRAN_ID,
ISNULL(LM.LGR_NAME,'') AS PARTY,ISNULL(ALM.LGR_NAME,'') AS AGENT,ISNULL(CM.CITY_NAME,'') AS CITY,'AA' AS TRAN_TYPE,0 AS TRAN_AMOUNT,COMP.CMP_ALIAS AS ALIAS,
'' AS LRNO,'' AS LRDATE,'' AS REMARK,ISNULL(GM.GRP_NAME,'') AS ACCGROUP,ISNULL(CTM.CATEGORY_NAME,'') AS CATEGORY,
ISNULL(SGM.SUPP_GRP_NAME,'') AS SUPPLIERGROUP,ISNULL(ACM.CITY_NAME,'') AS AGENTCITY
,(CASE WHEN AM.RECDATE IS NULL THEN DATEDIFF(DAY,PD.DATE,'"+@ASONDATE+"') ELSE DATEDIFF(DAY,PD.DATE,AM.RECDATE) END) AS DAYS,ISNULL(AM.RD,0) AS RD
,ISNULL(LM.LGR_ID,0) AS PARTYID,ISNULL(ALM.LGR_ID,0) AS AGENTID,
ISNULL(CM.CITY_ID,0) AS PARTY_CITYID,ISNULL(ALM.CITY_ID,0) AS AGENT_CITYID,
ISNULL(GM.GRP_ID,0) AS MAIN_GRPID,ISNULL(SGM.SUPP_GRP_ID,0) AS SUPPGRPID,
ISNULL(CTM.CATEGORY_ID,0) AS CATEGORYID
FROM " + @DATABASENAME + " PURPARTYDETAIL PD 
LEFT JOIN " + @DATABASENAME + " PURADJMASTER AM ON AM.BILLNO=PD.BILLNO AND AM.FLAG=PD.FLAG AND AM.CMP_CODE=PD.CMP_CODE AND PD.VCODE=AM.VCODE  AND AM.RECDATE<='"+ @ASONDATE +"'
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=PD.LGR_ID
LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER ALM ON ALM.LGR_ID=PD.AGENT_ID           
LEFT JOIN " + @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID  
LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON ALM.CITY_ID=ACM.CITY_ID          
INNER JOIN " + @DATABASENAME + "COMPANY_MASTER COMP ON COMP.CMP_CODE=PD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND PD.CMP_CODE=LD.CMP_CODE
LEFT JOIN " + @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN " + @DATABASENAME + "SUPPLIER_GROUP_MASTER SGM ON SGM.SUPP_GRP_ID=LM.SUPP_GRP_ID
LEFT JOIN " + @DATABASENAME + "CATEGORY_MASTER CTM ON CTM.CATEGORY_ID=LM.CATEGORY_ID
" +  @SQLJOIN + "
WHERE  PD.DATE<='"+@ASONDATE+"' AND PD.CMP_CODE IN("+ @CMP_CODE +")" +  @CONDITION + " "

PRINT @SQL
PRINT @SQLONACCOUNT
PRINT @SQLONACCOUNT1
PRINT @SQLONACCOUNT2
PRINT @SQLONACCOUNT6
PRINT @SQLONACCOUNT3
PRINT @SQLONACCOUNT4
PRINT @SQLONACCOUNT5
PRINT @SQLONACCOUNT7
PRINT ') AS DETAIL ORDER BY'
PRINT @ORDERBYSQL
PRINT 'FLAG,DATE'
EXEC(@SQL+ @SQLONACCOUNT+@SQLONACCOUNT1+@SQLONACCOUNT2+@SQLONACCOUNT6+@SQLONACCOUNT3+@SQLONACCOUNT4+@SQLONACCOUNT5+@SQLONACCOUNT7 + ") AS DETAIL ORDER BY "+@ORDERBYSQL+"FLAG,DATE ")



















GO

