/*
-- =============================================
-- Author:		<SANJAY >
-- ALTER_date: <04/JULY/2017>
-- Description:	<PRINTTING INVOICE FOR WITHCUT>
-- REPORT NAME: SALESINVOICE_WITHCUT.rpt
-- =============================================
*/
/*
PROC_TCSONBANKPAYMENT 1,'ACC2020_2021.DBO.','ACC2020_2021.DBO.',1,##3708,' ','05/oct/2020',0,5000000
select * from tempdb..sysobjects
*/
CREATE PROCEDURE [dbo].[PROC_TCSONBANKPAYMENT]
(
		@Cmp_Code NVARCHAR(100),
		@DATABASENAME NVARCHAR(50),
		@PreviousDatabaseName NVARCHAR(50),
		@RPT_WISE int,
		@TEMPTABLE NVARCHAR(20),		
        @FROMDATE AS NVARCHAR(20),
        @TODATE AS NVARCHAR(20),
		@RPTTYPE AS INT,
		@TotalAmt NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SQL1 AS NVARCHAR(3999)
DECLARE @SQL12 AS NVARCHAR(3999)
DECLARE @JOINSQL  NVARCHAR(100)
DECLARE @TYPESQL NVARCHAR(100)
DECLARE @ORDERSQL NVARCHAR(100)
DECLARE @SQLP NVARCHAR(3999)
DECLARE @SQLL NVARCHAR(3999)
DECLARE @SQLSD NVARCHAR(3999)
DECLARE @SQLCOND NVARCHAR(3999)

SET @SQL=""
SET @SQL1=""
SET @SQL12=""
SET @ORDERSQL = ""
SET @JOINSQL=""
SET @TYPESQL="" 
set @SQLP=""
set @SQLL=""
set @SQLSD=""
set @SQLCOND = ""
       IF @RPT_WISE = 1 
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=LM.LGR_ID"
		ELSE IF @RPT_WISE = 2
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=AGM.LGR_ID"
		ELSE IF @RPT_WISE = 3
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=PCM.CITY_ID"
		ELSE IF @RPT_WISE = 4
			SET @JOINSQL=" INNER JOIN "+ @TEMPTABLE + " TT ON TT.CODE=CGM.Supp_Grp_Id"

		BEGIN
			IF @RPTTYPE = 0 /* ALL */
				SET @SQLCOND = ""
			ELSE IF @RPTTYPE = 1 /* PENDING */
				SET @SQLCOND = " WHERE ReceviedAmtPRE + ReceviedAmtWithin > = "+ @TotalAmt +""

		END		




BEGIN
SET NOCOUNT ON;
SET @SQLP="

SELECT DISTINCT * FROM (
			SELECT  MAX(Lgr_Pano)Lgr_Pano,MAX(VDATE)VDATE,MAX(PARTYNAME)PARTYNAME,MAX(isnull(PARTYCITY,''))PARTYCITY,MAX(AGENTNAME)AGENTNAME,MAX(CUSTOMERGROUP)CUSTOMERGROUP,SUM(SalesAmtPRE)SalesAmtPRE,SUM(SalesAmtWhithin)SalesAmtWhithin,SUM(ReceviedAmtPRE )ReceviedAmtPRE,SUM(ReceviedAmtWithin)ReceviedAmtWithin,MAX(TCS_PER)TCS_PER,SUM(TCS_AMT)TCS_AMT,LGR_ID  FROM (
			SELECT CMP.CMP_CODE,LM.Lgr_Pano,PUI.VCHDATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
			UPPER(isnull(PCM.CITY_NAME,'')) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,PUI.NetTotal as SalesAmtPRE, 0 as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
			PUI.TCS_PER,PUI.TCS_AMT ,LM.LGR_ID
			FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
			INNER JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
			LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
			INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
			LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		  LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
            "+@JOINSQL+" 
			WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" )   AND  PUI.VCHDATE<'"+@FROMDATE+"' 

"
	SET @SQL="
		UNION ALL
		SELECT  CMP.CMP_CODE,LM.Lgr_Pano,PUI.VCHDATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
		UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,0 as SalesAmtPRE, PUI.NetTotal as SalesAmtWhithin, 0 as ReceviedAmtPRE,0 as ReceviedAmtWithin,
		PUI.TCS_PER,PUI.TCS_AMT ,LM.LGR_ID
		FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER LM ON LM.LGR_ID=PUI.LGR_ID
		LEFT JOIN " + @DATABASENAME +"LEDGER_MASTER AGM ON AGM.LGR_ID=PUI.AGENT_ID
		INNER JOIN " + @DATABASENAME +"COMPANY_MASTER CMP ON PUI.CMP_CODE= CMP.CMP_CODE     
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER CM ON CM.CITY_ID=PUI.STATION_ID
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
		LEFT JOIN " + @DATABASENAME +"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
		LEFT JOIN "+@DATABASENAME+" Supplier_Group_Master CGM ON CGM.Supp_Grp_Id = LM.Supp_Grp_Id
		"+@JOINSQL+" 
		WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" ) AND  PUI.VCHDATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "' 

"
SET @SQL1=" 
	UNION ALL
	SELECT  CMP.CMP_CODE,LM.Lgr_Pano,TM.TRAN_DATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
	UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,
	0 as SalesAmtPRE, 0 as SalesAmtWhithin, ( TD.TRAN_AMOUNT - ISNULL(TM.TCS_AMT , 0)) as ReceviedAmtPRE,0 as ReceviedAmtWithin,
	0 as TCS_PER,0 as TCS_AMT,LM.LGR_ID
	FROM " + @DATABASENAME + "TRAN_DETAIL TD "
SET @SQL12=" 
	
	INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
	INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
	LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
	LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER AgM ON AgM.LGR_ID=LD.AGENT_ID         
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER pCM ON LM.CITY_ID=pCM.CITY_ID
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON AgM.CITY_ID=ACM.CITY_ID
	LEFT JOIN " + @DATABASENAME + "Supplier_Group_Master CGM ON CGM.Supp_Grp_Id=LM.Supp_Grp_Id
	LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
	INNER JOIN "+@DATABASENAME +"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
	"+@JOINSQL+" 
	WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +" ) AND TM.TRAN_DATE   <'"+@FROMDATE+"'  and  TD.TRAN_TYPE IN('BP','CP')

UNION ALL "
SET @SQLL=" 
	SELECT  CMP.CMP_CODE,LM.Lgr_Pano,TM.TRAN_DATE AS VDATE,UPPER(LM.LGR_NAME) AS PARTYNAME,
	UPPER(PCM.CITY_NAME) AS PARTYCITY,UPPER(AGM.LGR_NAME) AS AGENTNAME ,CGM.Supp_Grp_Name AS CUSTOMERGROUP,
	0 as SalesAmtPRE,0 as SalesAmtWhithin, 0 as ReceviedAmtPRE, (TD.TRAN_AMOUNT - ISNULL(TM.TCS_AMT , 0) )  as ReceviedAmtWithin,
	0 as TCS_PER,0 as TCS_AMT,LM.LGR_ID FROM " + @DATABASENAME + "TRAN_DETAIL TD 
	INNER JOIN " + @DATABASENAME + "TRAN_MASTER TM ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TD.CMP_CODE=TM.CMP_CODE
	INNER JOIN " + @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID AND LM.LGR_TYPE='L'
	LEFT JOIN " + @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TD.CMP_CODE=LD.CMP_CODE
	LEFT JOIN " + @DATABASENAME + "LEDGER_MASTER AgM ON AgM.LGR_ID=LD.AGENT_ID         
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER pCM ON LM.CITY_ID=pCM.CITY_ID
	LEFT JOIN " + @DATABASENAME + "CITY_MASTER ACM ON AgM.CITY_ID=ACM.CITY_ID
 "
SET @SQLSD="  
	LEFT JOIN " + @DATABASENAME + "Supplier_Group_Master CGM ON CGM.Supp_Grp_Id=LM.Supp_Grp_Id
	LEFT JOIN " + @DATABASENAME + "COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
	INNER JOIN "+@DATABASENAME +"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID 
	"+@JOINSQL+" 
	WHERE TM.CMP_CODE IN  ("+ @CMP_CODE +" ) AND TM.TRAN_DATE BETWEEN  '" + @FROMDATE + "' AND '" + @TODATE + "'  and  TD.TRAN_TYPE IN('BP','CP')
				)AS DETAIL  GROUP BY Lgr_Pano,PARTYNAME,LGR_ID )as sd  
	inner join 
	(
	SELECT  sum(PRESALE)PRESALE from ( select sum(PUI.SAL_INV_NETTOTAL )as PRESALE
	FROM "+ @PreviousDatabaseName+ "Sales_invoice PUI WHERE PUI.CMP_CODE IN  ("+ @CMP_CODE +" ) 
	)pre ) c on  1=1  " + @SQLCOND + "
			"
      
END	

EXEC  (@SQLP+@SQL+@SQL1+@SQL12+@SQLL+@SQLSD)
PRINT @SQLP
PRINT @SQL
PRINT @SQL1
PRINT @SQL12
PRINT @SQLL
PRINT @SQLSD

























GO

/****** Object:  StoredProcedure [dbo].[PROC_TDSREG]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO





















/*   
PROC_TDSREG 10,'ACC2010_2011.DBO.','01/APR/2010','31/MAR/2011',1,'##2772'
*/
CREATE PROCEDURE [dbo].[PROC_TDSREG]
	(
          @CMP_CODE AS NVARCHAR(50),
          @DATABASENAME AS NVARCHAR(100),
          @FROMDATE AS NVARCHAR(20),
          @TODATE AS NVARCHAR(20),
          @RPT_WISE AS INT,
          @TEMPTABLE AS NVARCHAR(20)
    )
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(4000)

SET @SQL=""
SET @JOINSQL =""

       IF @RPT_WISE=1 
           BEGIN 
             SET @JOINSQL="INNER JOIN "+ @TEMPTABLE +" TT ON TT.CODE=LM.LGR_ID"
           END

         
BEGIN

      SET @SQL=" 
                 
                 SELECT LM.LGR_NAME AS ACCOUNTNAME,CM.CITY_NAME AS PARTYCITY,CONVERT(NVARCHAR,TVM.DOCNO) AS BILLNO,TVM.VCHDATE AS BILLDATE,
                 TVM.NETTOTAL AS AMOUNT,TVM.TDSAMOUNT,0 AS TDSPER,ISNULL(UPPER(LM.LGR_PANO),'') AS LGR_PANO
                 FROM "+@DATABASENAME+"TRANSPORTVOUCHER_MASTER TVM
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TVM.ACCOUNT_ID
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                 "+@JOINSQL+"
                 WHERE TVM.TDSAMOUNT>0 AND TVM.CMP_CODE IN("+@CMP_CODE+") AND TVM.CURRDATE BETWEEN '"+ @FROMDATE +"' AND '"+@TODATE+"'
                 UNION ALL
                 SELECT LM.LGR_NAME AS ACCOUNTNAME,CM.CITY_NAME AS PARTYCITY, PI.BILLNO,PI.VCHDATE AS BILLDATE,PI.NETTOTAL AS AMOUNT,PI.TDSAMOUNT,ISNULL(PI.TDSPER,0) AS TDSPER,ISNULL(UPPER(LM.LGR_PANO),'') AS LGR_PANO
                 FROM "+@DATABASENAME+"PURCHASEINVOICE PI
                 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID
                 LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON LM.CITY_ID=CM.CITY_ID
                 "+@JOINSQL+"
                 WHERE PI.TDSAMOUNT>0 AND PI.FLAG IN ('JP','CHP') AND PI.CMP_CODE IN("+@CMP_CODE+") AND PI.CURRENTDATE BETWEEN '"+ @FROMDATE +"' AND '"+@TODATE+"'
                 UNION ALL

				SELECT LM.LGR_NAME AS PARTY,CM.CITY_NAME AS CITY,CONVERT(NVARCHAR,TM.TRAN_DOCNO) AS BILLNO,TM.Tran_Date AS BILLDATE,
				TM.REC_AMT AS AMOUNT,(ISNULL(TM.TCS_AMT,0)) AS TDSAMOUNT,(ISNULL(TM.TCS_PER,0)) AS TDSPER,ISNULL(LM.Lgr_Pano,'') AS LGR_PANO
				FROM "+@DATABASENAME+"Tran_Master TM  
				INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD  ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
				INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID  
				LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
				"+@JOINSQL+"
				WHERE TD.TRAN_TYPE='DN' AND TD.TRAN_DrCr='D' AND TM.Tran_Date  BETWEEN '"+ @FROMDATE +"' AND '"+@TODATE+"'
				AND TM.CMP_CODE  IN ("+@CMP_CODE+") AND (ISNULL(TM.TCS_AMT,0)) > 0 AND NOTE = 'TDS'

                 ORDER BY LM.LGR_NAME,BILLDATE,BILLNO
               "

	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL





















GO

/****** Object:  StoredProcedure [dbo].[PROC_TDSREGISTER]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO















/*
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_TDSREGISTER N'1', N'Acc2018_2019.DBO.', N'31/Mar/2019', N'##3648', 2, N'###3648', 1

REPORT NAME : TDSREGISTER_CATEGORY.RPT,TDSREGISTER_CATEGORY_SUMMARY.RPT
*/
CREATE PROCEDURE [dbo].[PROC_TDSREGISTER]
(
    @CMP_CODE NVARCHAR(200),
    @DATABASENAME NVARCHAR(200),
    @ASONDATE NVARCHAR(20),
    @TEMPTABLE NVARCHAR(20),
	@RPT_TYPE INT,
	@PYEEE_TABLE NVARCHAR(20),
	@TDS_PARTY INT
)
AS
DECLARE @SQL NVARCHAR(3999) SET @SQL=""
DECLARE @SQL1 NVARCHAR(3999) SET @SQL1=""
DECLARE @SQL2 NVARCHAR(3999) SET @SQL2=""

DECLARE @STRTDS_PARTY NVARCHAR(4000) SET @STRTDS_PARTY=""
DECLARE @STRTDS_TDS NVARCHAR(4000) SET @STRTDS_TDS=""

IF @TDS_PARTY=1/* NON TDS PARTY*/
	SET @STRTDS_PARTY="";
ELSE IF @TDS_PARTY=2/*TDS PARTY*/
	SET @STRTDS_PARTY=" AND ISNULL(PI.TDSAMOUNT,0)>0";
	
IF @TDS_PARTY=1/* NON TDS PARTY*/
	SET @STRTDS_TDS="";
ELSE IF @TDS_PARTY=2/*TDS PARTY*/
	SET @STRTDS_TDS=" AND ISNULL(TDS_AMOUNT,0)>0";


	IF @RPT_TYPE=1
  BEGIN
		SET @SQL=" SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,PI.BILLNO,PI.VCHDATE AS BILLDATE,PI.CURRENTDATE
,(PI.NETTOTAL - (isnull(Pur_Inv_Add4,0) + isnull(Pur_Inv_Add5,0) + isnull(Pur_Inv_Add6,0))) AS BILl_AMT,ISNULL(PI.TDSAMOUNT,0) AS TDS_AMOUNT,PI.TDSPER ,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,PI.FLAG AS ENTRYFLAG
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE (PI.FLAG = 'JP' OR  (PI.FLAG = 'CHP' AND PI.PUR_FORM_TYPE = 'A')) AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.VCHDATE<='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0 
"+@STRTDS_PARTY+" 

UNION ALL

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS CITY,LM.LGR_PANO,CONVERT(NVARCHAR,TE.DOCNO) AS BILLNO,TE.VCHDATE AS BILLDATE,TE.VCHDATE AS  CURRENTDATE,
TED.INTEREST AS BILL_AMT,TED.TDS_AMOUNT AS  TDS_AMOUNT,TED.TDS_PER AS TDS_PER,ISNULL(TE.TDSACC_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'TDS' AS FLAG,'' AS ENTRYFLAG
 FROM "+@DATABASENAME+"TDSENTRY_DETAIL  TED 
 INNER JOIN "+@DATABASENAME+"TDSENTRY TE ON TE.TDSENTRY_ID=TED.TDSENTRY_ID 
 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TED.LGR_ID 
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE IN ("+@CMP_CODE+")
 LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
 INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
 INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
 WHERE  TE.VCHDATE <='"+@ASONDATE+"'
 AND TED.CMP_CODE IN ("+@CMP_CODE+") 
 "+@STRTDS_TDS+"
 AND ISNULL(TED.JOB_CHALLAN_USED,0)=0  "
 
 
SET @SQL1 = "

UNION ALL

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,maX(PI.BILLNO)BILLNO,
max(PI.VCHDATE) AS BILLDATE,max(PI.CURRENTDATE)CURRENTDATE
,SUM(PI.NETTOTAL)- (SUM(isnull(PI.CGST,0))+ SUM(isnull(PI.SGST,0))+ SUM(isnull(PI.IGST,0))) AS BILl_AMT,SUM(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,PI.TDSPER,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,PI.FLAG AS ENTRYFLAG
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.FLAG='RP' AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.VCHDATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.BILLNO,PI.VCHDATE,PI.CURRENTDATE,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID,PI.FLAG

UNION ALL

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,(PI.BILLNO)BILLNO,
(PI.VCHDATE) AS BILLDATE,(PI.CURRENTDATE)CURRENTDATE
,SUM(PI.NETTOTAL)- (SUM(isnull(PI.CGST,0))+ SUM(isnull(PI.SGST,0))+ SUM(isnull(PI.IGST,0))) AS BILl_AMT,SUM(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,PI.TDSPER ,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,PI.FLAG AS ENTRYFLAG
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.FLAG='CHP' AND PI.PUR_FORM_TYPE = 'B'  AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.VCHDATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.BILLNO,PI.VCHDATE,PI.CURRENTDATE,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID,PI.FLAG 
UNION ALL 

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,CONVERT(NVARCHAR,PI.TRAN_DOCNO)BILLNO,
(PI.TRAN_DATE) AS BILLDATE,(PI.TRAN_DATE)CURRENTDATE
,MAX(PI.TRAN_AMOUNT) AS BILl_AMT ,MAX(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,PI.TDSPER,
ISNULL(TCM.TDS_ID,0) AS TDSID,ISNULL(LM.LGR_ID,0) AS PARTYID,'GCN' AS FLAG,PI.TRAN_TYPE AS ENTRYFLAG
FROM "+@DATABASENAME+"CreditNoteAcc_Master PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.TRAN_TYPE='GCN' AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.TRAN_DATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.TRAN_DOCNO,PI.TRAN_DATE,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID,PI.TRAN_TYPE,cmp_Tds_No" 

SET @SQL2 = "
UNION ALL

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS CITY,ISNULL(LM.Lgr_Pano,'') AS LGR_PANO,
CONVERT(NVARCHAR,TM.TRAN_DOCNO) AS BILLNO,TM.Tran_Date AS BILLDATE,
TM.TRAN_DATE CURRENTDATE,TM.REC_AMT AS BILl_AMT,(ISNULL(TM.TCS_AMT,0)) AS TDS_AMOUNT,(ISNULL(TM.TCS_PER,0)) AS TDSPER,
ISNULL(TCM.TDS_ID,0) AS TDSID,ISNULL(LM.LGR_ID,0) AS PARTYID,'DN' AS FLAG,TD.TRAN_TYPE AS ENTRYFLAG
FROM "+@DATABASENAME+"Tran_Master TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD  ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE = TM.CMP_CODE 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
