END
ELSE 
BEGIN
	SET @SQL=" 
SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,maX(PI.BILLNO)BILLNO,max(PI.VCHDATE) AS BILLDATE,max(PI.CURRENTDATE)CURRENTDATE
,sum(PI.NETTOTAL - (isnull(Pur_Inv_Add4,0) + isnull(Pur_Inv_Add5,0) + isnull(Pur_Inv_Add6,0))) AS BILl_AMT,PI.TDSPER ,sum(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,ISNULL(TCM.TDS_ID,0) AS TDSID,
