AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
"+@STRTDS_PARTY+"
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID 
UNION ALL
SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS CITY,LM.LGR_PANO,MAX(CONVERT(NVARCHAR,TE.DOCNO)) AS BILLNO,MAX(TE.VCHDATE)BILLDATE,MAX(TE.VCHDATE) CURRENTDATE,
SUM(TED.INTEREST) AS BILL_AMT,TED.TDS_PER AS TDS_PER,SUM(TED.TDS_AMOUNT) TDS_AMOUNT,ISNULL(TE.TDSACC_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'TDS' AS FLAG,'' AS ENTRYFLAG
 FROM "+@DATABASENAME+"TDSENTRY_DETAIL  TED 
 INNER JOIN "+@DATABASENAME+"TDSENTRY TE ON TE.TDSENTRY_ID=TED.TDSENTRY_ID 
 INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TED.LGR_ID 
 INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LD.LGR_ID=LM.LGR_ID AND LD.CMP_CODE IN ("+@CMP_CODE+")
 LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
 INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
 WHERE  TE.VCHDATE <='"+@ASONDATE+"'
 AND TED.CMP_CODE IN ("+@CMP_CODE+") 
  "+@STRTDS_TDS+"
AND ISNULL(TED.JOB_CHALLAN_USED,0)=0  
GROUP BY TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,TED.TDS_PER,TE.TDSACC_ID,LM.LGR_ID 
UNION ALL
SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,maX(PI.BILLNO)BILLNO,
max(PI.VCHDATE) AS BILLDATE,max(PI.CURRENTDATE)CURRENTDATE
,SUM(PI.NETTOTAL)- (SUM(isnull(PI.CGST,0))+ SUM(isnull(PI.SGST,0))+ SUM(isnull(PI.IGST,0))) AS BILl_AMT,PI.TDSPER,SUM(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,MAX(PI.FLAG) AS ENTRYFLAG
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.FLAG='RP' AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.VCHDATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID"
SET @SQL1 = " UNION ALL
SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,MAX(PI.BILLNO)BILLNO,
MAX(PI.VCHDATE) AS BILLDATE,MAX(PI.CURRENTDATE)CURRENTDATE
,SUM(PI.NETTOTAL)- (SUM(isnull(PI.CGST,0))+ SUM(isnull(PI.SGST,0))+ SUM(isnull(PI.IGST,0))) AS BILl_AMT,PI.TDSPER ,SUM(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,MAX(PI.FLAG) AS ENTRYFLAG
FROM "+@DATABASENAME+"PURCHASEINVOICE PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.FLAG='CHP' AND PI.PUR_FORM_TYPE = 'B'  AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.VCHDATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.TDSPER,TCM.TDS_ID,LM.LGR_ID
UNION ALL
SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME PARTY ,CM.CITY_NAME AS CITY,LM.LGR_PANO,CONVERT(NVARCHAR,PI.TRAN_DOCNO)BILLNO,
(PI.TRAN_DATE) AS BILLDATE,(PI.TRAN_DATE)CURRENTDATE,MAX(PI.TRAN_AMOUNT) AS BILl_AMT ,PI.TDSPER,
SUM(ISNULL(PI.TDSAMOUNT,0)) AS TDS_AMOUNT,ISNULL(TCM.TDS_ID,0) AS TDSID,
ISNULL(LM.LGR_ID,0) AS PARTYID,'PURCHASE' AS FLAG,MAX(PI.TRAN_TYPE) AS ENTRYFLAG
FROM "+@DATABASENAME+"CreditNoteAcc_Master PI 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=PI.LGR_ID 
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=PI.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=PI.CMP_CODE 
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE PI.TRAN_TYPE='GCN' AND PI.CMP_CODE IN ("+@CMP_CODE+") AND PI.TRAN_DATE <='"+@ASONDATE+"'
AND ISNULL(PI.JOB_CHALLAN_USED,0)=0  
group by TCM.TDS_NAME ,LM.LGR_NAME,CM.CITY_NAME,LM.LGR_PANO,PI.TRAN_DOCNO,PI.TRAN_DATE,PI.TDSPER,CMP.CMP_TDS_NO,TCM.TDS_ID,LM.LGR_ID "
SET @SQL2 = "
UNION ALL

SELECT TCM.TDS_NAME AS TDSCATEGORY,LM.LGR_NAME AS PARTY,CM.CITY_NAME AS CITY,ISNULL(LM.Lgr_Pano,'') AS LGR_PANO,
MAX(CONVERT(NVARCHAR,TM.TRAN_DOCNO)) AS BILLNO,MAX(TM.Tran_Date) AS BILLDATE,
MAX(TM.TRAN_DATE) CURRENTDATE,SUM(ISNULL(TM.REC_AMT,0)) AS BILl_AMT,(ISNULL(TM.TCS_PER,0)) AS TDS_PER,SUM(ISNULL(TM.TCS_AMT,0)) AS TDS_AMOUNT
,ISNULL(TCM.TDS_ID,0) AS TDSID,ISNULL(LM.LGR_ID,0) AS PARTYID,'DN' AS FLAG,MAX(TD.TRAN_TYPE) AS ENTRYFLAG
FROM "+@DATABASENAME+"Tran_Master TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD  ON TM.TRAN_ID=TD.TRAN_ID AND TM.TRAN_TYPE=TD.TRAN_TYPE AND TM.CMP_CODE=TD.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TD.TRAN_DETAIL_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE = TM.CMP_CODE 
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TM.CMP_CODE
INNER JOIN "+@DATABASENAME+"TDSCATEGORY_MASTER TCM ON TCM.TDS_ID=LD.TDS_ID 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
INNER JOIN "+@TEMPTABLE+"  TT ON TT.CODE=TCM.TDS_ID
INNER JOIN "+@PYEEE_TABLE+" TT1 ON TT1.CODE=LD.PAYEE_ID
WHERE TD.TRAN_TYPE='DN' AND TD.TRAN_DrCr='D' 
AND TM.Tran_Date  <='"+@ASONDATE+"'
AND TM.CMP_CODE  IN ("+@CMP_CODE+")
AND (TM.JOB_CHALLAN_USED IS NULL OR TM.JOB_CHALLAN_USED=0) AND NOTE = 'TDS' 
GROUP BY TCM.TDS_NAME,CMP.CMP_TDS_NO,LM.LGR_NAME,LM.LGR_ID ,LM.Lgr_Pano,CM.CITY_NAME,TM.TCS_PER,TCM.TDS_ID
ORDER BY TDSCATEGORY,TDSID,PARTY,PARTYID,BILLDATE "
END
