/****** Object:  StoredProcedure [dbo].[PROC_TRADINGACCOUNTNEW]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO


















/* 
-- =============================================
-- EDIT_AUTHOR    : <BIREN>
-- EDIT_DATE      : <02/09/2013 7:20 PM>
-- REPORT_FORM    : <RFRMTRADINGAC.CS>
-- CRYSTAL_REPORT : <TRADINGACCOUNTNEW.RPT>
-- =============================================
PROC_TRADINGACCOUNTNEW '1','ACC2015_2016.DBO.','31/MAR/2013'
*/
CREATE PROCEDURE [dbo].[PROC_TRADINGACCOUNTNEW]
(
@CMP_CODE NVARCHAR(10),
@DATABASENAME NVARCHAR(50),
@TODATE AS NVARCHAR(20)

)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS  NVARCHAR(4000)
DECLARE @SQL2 AS  NVARCHAR(4000)
DECLARE @SQL3 AS  NVARCHAR(4000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
BEGIN
SET NOCOUNT ON;

SELECT @SQL="

SELECT (CASE WHEN SUBGRP = MAINGRP THEN PARTYNAME ELSE SUBGRP END) AS  SUBGRP,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY,
CONVERT(NUMERIC(18,2),ABS(SUM(DRAMOUNT)-SUM(CRAMOUNT))) AS BALANCE,
(CASE WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='EXPENSES(INDIRECT/ADMN)' THEN 'INCOME(INDIRECT)' 
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='EXPENSES(DIRECT/MFGR.)' THEN 'INCOME(DIRECT/OPERATIONAL)'
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='PURCHASE' THEN 'PURCHASERETURN'
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='SALES' THEN 'SALESRETURN'
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='INCOME(INDIRECT)' THEN 'EXPENSES(INDIRECT/ADMN)' 
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='INCOME(DIRECT/OPERATIONAL)' THEN 'EXPENSES(DIRECT/MFGR.)'
WHEN SUBGRP ='STOCK IN HAND' THEN 'STOCK IN HAND'
ELSE MAINGRP END ) AS MAINGRP,
/* ADD BY BIREN */
(CASE WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='EXPENSES(INDIRECT/ADMN)' THEN 9 
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='EXPENSES(DIRECT/MFGR.)' THEN 7
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)<0 AND  MAINGRP='PURCHASE' THEN 3
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='SALES' THEN 5
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='INCOME(INDIRECT)' THEN 8 
WHEN SUM(DRAMOUNT)-SUM(CRAMOUNT)>0 AND  MAINGRP='INCOME(DIRECT/OPERATIONAL)' THEN 6
ELSE FLAG END ) AS FLAG,(CASE WHEN SUBGRP = PARTYNAME THEN 1 ELSE 0 END) AS  SAMEFLAG
FROM(
SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,
LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
CASE WHEN LGR_OP_DRCR='D' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
CASE WHEN LGR_OP_DRCR='C' THEN LGR_OP_BAL WHEN LGR_OP_DRCR='' THEN LGR_OP_BAL ELSE 0 END AS CRAMOUNT,
1 AS FLAG
FROM "+@DATABASENAME+"LEDGER_MASTER LM INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE LD.CMP_CODE="+@CMP_CODE+" AND LD.LGR_OP_BAL>0 AND GM.GRP_NAME IN ('STOCK IN HAND')

UNION ALL

SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE,
TM.TRAN_MASTER_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
(CASE WHEN GM.GRP_MAIN_NAME='PURCHASE' THEN 2 WHEN GM.GRP_MAIN_NAME='PURCHASERETURN' THEN 3 WHEN GM.GRP_MAIN_NAME='SALES' THEN 4
WHEN GM.GRP_MAIN_NAME='SALESRETURN' THEN 5 WHEN GM.GRP_MAIN_NAME='EXPENSES(DIRECT/MFGR.)' THEN 6 WHEN GM.GRP_MAIN_NAME='INCOME(DIRECT/OPERATIONAL)' THEN 7
WHEN GM.GRP_MAIN_NAME='EXPENSES(INDIRECT/ADMN)' THEN 8 WHEN GM.GRP_MAIN_NAME='INCOME(INDIRECT)' THEN 9  WHEN GM.GRP_MAIN_NAME='CURRENT ASSETS' THEN 10  ELSE 0 END)AS FLAG
FROM "+@DATABASENAME+"TRAN_MASTER TM  
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID = TD.TRAN_ID AND TM.CMP_CODE= TD.CMP_CODE AND TM.TRAN_TYPE = TD.TRAN_TYPE   
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TM.TRAN_MASTER_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE TM.CMP_CODE ="+@CMP_CODE+"   
AND TM.TRAN_DATE <= '"+@TODATE+"' AND GM.GRP_ACC_TYPE IN ('P','T') AND TD.TRAN_AMOUNT>0

UNION ALL "

SELECT @SQL1="		SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, 					
TD.TRAN_DETAIL_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,
(CASE WHEN GM.GRP_MAIN_NAME='PURCHASE' THEN 2 WHEN GM.GRP_MAIN_NAME='PURCHASERETURN' THEN 3 WHEN GM.GRP_MAIN_NAME='SALES' THEN 4
WHEN GM.GRP_MAIN_NAME='SALESRETURN' THEN 5 WHEN GM.GRP_MAIN_NAME='EXPENSES(DIRECT/MFGR.)' THEN 6 WHEN GM.GRP_MAIN_NAME='INCOME(DIRECT/OPERATIONAL)' THEN 7
WHEN GM.GRP_MAIN_NAME='EXPENSES(INDIRECT/ADMN)' THEN 8 WHEN GM.GRP_MAIN_NAME='INCOME(INDIRECT)' THEN 9  WHEN GM.GRP_MAIN_NAME='CURRENT ASSETS' THEN 10  ELSE 0 END)AS FLAG

FROM "+@DATABASENAME+"TRAN_MASTER TM 
INNER JOIN "+@DATABASENAME+"TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND TM.CMP_CODE=LD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE TM.CMP_CODE="+@CMP_CODE+"   
AND TM.TRAN_DATE <= '"+@TODATE+"' AND  GM.GRP_ACC_TYPE IN ('P','T') AND TD.TRAN_AMOUNT>0

UNION ALL
"


SELECT @SQL2="	SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, 
AJ.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY,
AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT,
(CASE WHEN GM.GRP_MAIN_NAME='PURCHASE' THEN 2 WHEN GM.GRP_MAIN_NAME='PURCHASERETURN' THEN 3 WHEN GM.GRP_MAIN_NAME='SALES' THEN 4
WHEN GM.GRP_MAIN_NAME='SALESRETURN' THEN 5 WHEN GM.GRP_MAIN_NAME='EXPENSES(DIRECT/MFGR.)' THEN 6 WHEN GM.GRP_MAIN_NAME='INCOME(DIRECT/OPERATIONAL)' THEN 7
WHEN GM.GRP_MAIN_NAME='EXPENSES(INDIRECT/ADMN)' THEN 8 WHEN GM.GRP_MAIN_NAME='INCOME(INDIRECT)' THEN 9  WHEN GM.GRP_MAIN_NAME='CURRENT ASSETS' THEN 10 ELSE 0 END)AS FLAG

FROM "+@DATABASENAME+"AUTOJOURNAL AJ 
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID  
INNER JOIN "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND AJ.CMP_CODE=LD.CMP_CODE
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
WHERE AJ.VDATE <='"+@TODATE+"'
AND AJ.CMP_CODE ="+@CMP_CODE+" AND GM.GRP_ACC_TYPE IN ('P','T') AND (AJ.DRAMOUNT>0  OR  AJ.CRAMOUNT > 0)
UNION ALL
"

SELECT @SQL3="	 SELECT GM.GRP_MAIN_NAME AS MAINGRP,GM.GRP_NAME AS SUBGRP,GM.GRP_ACC_TYPE AS GRPTYPE, LM.LGR_ID AS PARTYID,LM.LGR_NAME AS PARTYNAME,PCM.CITY_NAME AS PARTYCITY, 0 AS DRAMOUNT, VE.AMOUNT AS CRAMOUNT,
(CASE WHEN GM.GRP_MAIN_NAME='PURCHASE' THEN 2 WHEN GM.GRP_MAIN_NAME='PURCHASERETURN' THEN 3 WHEN GM.GRP_MAIN_NAME='SALES' THEN 4
WHEN GM.GRP_MAIN_NAME='SALESRETURN' THEN 5 WHEN GM.GRP_MAIN_NAME='EXPENSES(DIRECT/MFGR.)' THEN 6 WHEN GM.GRP_MAIN_NAME='INCOME(DIRECT/OPERATIONAL)' THEN 7
WHEN GM.GRP_MAIN_NAME='EXPENSES(INDIRECT/ADMN)' THEN 8 WHEN GM.GRP_MAIN_NAME='INCOME(INDIRECT)' THEN 9 WHEN GM.GRP_MAIN_NAME='CURRENT ASSETS' THEN 10 ELSE 0 END)AS FLAG
FROM  "+@DATABASENAME+"LEDGER_MASTER LM
INNER JOIN  "+@DATABASENAME+"LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN  "+@DATABASENAME+"VALUATIONENTRY VE ON LD.LGR_ID=VE.LGR_ID AND LD.CMP_CODE=VE.CMP_CODE 
INNER JOIN  "+@DATABASENAME+"GROUP_MASTER GM ON LD.GRP_ID=GM.GRP_ID 
LEFT JOIN   "+@DATABASENAME+"CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID 
WHERE LD.CMP_CODE="+@CMP_CODE+" AND GM.GRP_NAME IN ('STOCK IN HAND')  AND  VE.MONTH  = MONTH('"+@TODATE+"') AND VE.AMOUNT>0
) AS DETAIL 
GROUP BY  MAINGRP,SUBGRP,GRPTYPE,PARTYID,PARTYNAME,PARTYCITY,FLAG
HAVING CONVERT(NUMERIC(18,2),ABS(SUM(DRAMOUNT)-SUM(CRAMOUNT))) != 0
ORDER BY MAINGRP,SUBGRP,GRPTYPE,PARTYNAME,PARTYCITY,PARTYID,FLAG
"
END
EXEC(@SQL+@SQL1+@SQL2+@SQL3)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2
PRINT @SQL3

















GO

