/*
PROC_TRASPORT_SALES_BILL 2,'ACC2010_2011.DBO.',50001,50002,1
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORT_SALES_BILL]
(
@Cmp_Code NVARCHAR(50),
@DatabaseName NVARCHAR(50),
@FromBillNo NVARCHAR(50),
@ToBillNo NVARCHAR(50),
@RptType INT
)
AS

DECLARE @SQL AS NVARCHAR(4000) SET @SQL=""
DECLARE @RptType_Sql AS NVARCHAR(4000) SET @RptType_Sql=""

BEGIN
	SET NOCOUNT ON;
SET @SQL=" SELECT SAL_INV_BILL_NO AS BILLNO,SAL_INV_VDATE AS BILLDATE,LM.LGR_NAME,PCM.CITY_NAME AS PARTYCIY,LGR_CSTNO AS PARTYTINNO,
SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,TM.TRANSPORT_NAME,CM.CITY_NAME AS DESTINATION,IM.ITEM_NAME,SM.SCREEN_NAME
,SID.SAL_INV_BALENO,SAL_INV_QTY,SAL_INV_RATE,SAL_INV_AMOUNT,Cmp.cmp_tin_No,Sal_Inv_NetTotal,Sal_Inv_Pcs
FROM "+@DATABASENAME+" SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+" SALES_INVOICE_DETAIL SID ON SI.SAL_INV_ID=SID.SAL_INV_ID AND SI.FLAG=SID.FLAG AND SI.CMP_CODE=SID.CMP_CODE
INNER JOIN "+@DATABASENAME+" LEDGER_MASTER LM ON SI.LGR_ID=LM.LGR_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER PCM ON LM.CITY_ID=PCM.CITY_ID
LEFT JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+" CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
LEFT JOIN "+@DATABASENAME+" ITEM_MASTER IM ON SID.ITEM_ID=IM.ITEM_ID
LEFT JOIN "+@DATABASENAME+" SCREEN_MASTER SM ON SID.SCREEN_ID=SM.SCREEN_ID
INNER JOIN "+@DATABASENAME+" COMPANY_MASTER CMP ON SI.Cmp_Code= CMP.Cmp_Code     
WHERE SI.CMP_CODE IN ("+@CMP_CODE+") AND   SI.SAL_INV_BILL_NO BETWEEN "+@FROMBILLNO+" AND "+@TOBILLNO+"
AND SI.FLAG='S'
"
    
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

