/*   --PROC_TRANSPORTBILL '29/SEP/2010',2,'ACC2010_2011.DBO.','##3696'*/

CREATE PROCEDURE [dbo].[PROC_TRANSPORTBILL]
(
  @FROMDATE  NVARCHAR(20),  
  @CMP_CODE NVARCHAR(10),
  @DATABASENAME NVARCHAR(50),
  @TEMPTABLE  NVARCHAR(50)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
SET NOCOUNT ON;
SET @SQL="

SELECT  PSM.PACKINGSLIPID, PSM.TRANSPORT_BILL AS BILLNO, PSM.VCH_DATE AS VCHDATE, 
PSM.LGR_ID AS ACCCODE, LM.LGR_NAME AS PNAME, CM.CITY_NAME AS DESTINATION,CM_1.CITY_NAME AS STATION ,PSM.TRANSPORT_ID, 
TR.TRANSPORT_NAME AS TRNAME,PSD.ITEM_ID, IM.ITEM_NAME AS ITNAME,PSM.BALENO,PSM.SERIALNO,
CASE WHEN IM.RATE_PER='P' THEN PSD.TOTALPCS ELSE TOTAL END AS QTY,		            
CASE WHEN IOS.SAL_RATE=0 OR IOS.SAL_RATE IS NULL  THEN (SOD.RATE * (PSM.RATE_PER/100)) ELSE (IOS.SAL_RATE * (PSM.RATE_PER/100)) END AS RATE,
(CASE WHEN IM.RATE_PER='P' THEN PSD.TOTALPCS ELSE TOTAL END * 
ISNULL((IOS.SAL_RATE *  (PSM.RATE_PER/100) ) ,0)) AS AMOUNT,
LM.LGR_CSTNO AS CSTNO,PSM.WEIGHT AS WEIGHT,CMP.CMP_NAME,CMP_STATE,CMP_ADD1,CMP_ADD2,PSM.TRANSPORTBILL_DATE,TT.SELF,PSM.OTHER
,SM.SCREEN_NAME,CMP_PHONE1,CMP_MOBILE,TOTALPCS AS THAN,CMP_CITY,CMP_TIN_NO
FROM   "+ @DATABASENAME +"PACKINGSLIP PSM 
INNER JOIN "+ @DATABASENAME +"PACKINGSLIP_DETAIL PSD ON PSM.PACKINGSLIPID = PSD.PACKINGSLIPID 
INNER JOIN  "+ @DATABASENAME +"ITEM_MASTER IM ON PSD.ITEM_ID = IM.ITEM_ID
INNER JOIN  "+ @DATABASENAME +"SCREEN_MASTER SM ON PSD.SCREEN_ID = SM.SCREEN_ID
INNER JOIN  "+ @DATABASENAME +"COMPANY_MASTER CMP ON PSD.CMP_CODE = CMP.CMP_CODE
LEFT OUTER JOIN  "+ @DATABASENAME +"LEDGER_MASTER LM ON PSM.LGR_ID = LM.LGR_ID 
LEFT OUTER JOIN "+ @DATABASENAME +"TRANSPORT_MASTER TR ON PSM.TRANSPORT_ID = TR.TRANSPORT_ID
LEFT OUTER JOIN "+ @DATABASENAME +"CITY_MASTER CM ON PSM.STATION_ID = CM.CITY_ID
LEFT OUTER JOIN "+ @DATABASENAME +"CITY_MASTER CM_1 ON LM.CITY_ID = CM_1.CITY_ID		
INNER JOIN "+ @TEMPTABLE +" TT ON TT.BILLNO=PSM.TRANSPORT_BILL
LEFT JOIN "+ @DATABASENAME +"SALES_ORDER SO ON SO.CONFNO=PSM.CONFNO AND SO.CMP_CODE=PSM.CMP_CODE AND SO.FYEAR=PSM.FYEAR
LEFT JOIN "+ @DATABASENAME +"SALES_ORDER_DETAIL SOD ON SO.SAL_ORDER_ID=SOD.SAL_ORDER_ID  AND SOD.ITEM_ID=PSD.ITEM_ID AND SOD.SCREEN_ID=PSD.SCREEN_ID
INNER JOIN "+ @DATABASENAME +"ITEM_OPENING_STOCK IOS ON IOS.CMP_CODE=PSM.CMP_CODE AND IOS.ITEM_ID=IM.ITEM_ID
WHERE PSM.CMP_CODE="+ @CMP_CODE +"  AND PSM.TRANSPORTBILL_DATE='" + @FROMDATE + "' AND PSM.TRANSPORT_BILL > 0 
ORDER BY PSM.TRANSPORT_BILL
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

