/*
-- =============================================
-- AUTHOR:		<GAMI DIPAK>
-- ALTER_DATE: <17,10,2014>
-- DESCRIPTION:	<THIS REPORT IS USED TO >
-- =============================================
PROC_TRANSPORTBILL_NEW '1','ACC2015_2016.DBO.','01/04/2015','01/04/2016',1,'##5112'
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTBILL_NEW]
(
@CMP_CODE NVARCHAR(100),
@DATABASENAME NVARCHAR(100),
@FROMDATE NVARCHAR(50),
@TODATE NVARCHAR(50),
@TRANSPORT_ID NVARCHAR(10),
@TEMPTABLE NVARCHAR(20),
@RPTWISE INT,
@FROM_BALENO NVARCHAR(20),
@TO_BALENO NVARCHAR(20)
)
AS
BEGIN
DECLARE @STRSQL NVARCHAR(4000)
DECLARE @JOINSQL NVARCHAR(4000)
DECLARE @FROM_TOSQL NVARCHAR(4000)
DECLARE @ORDERBYSQL NVARCHAR(4000)

SET @STRSQL=""
SET @JOINSQL=""
SET @FROM_TOSQL=""

IF @RPTWISE = 1 
BEGIN
SET @JOINSQL = "INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE = PSM.TRANSPORT_ID "
SET @ORDERBYSQL = "PSM.TRANSPORTBILL_DATE,TR.TRANSPORT_NAME,TR.TRANSPORT_ID,PSM.TRANSPORT_BILL"
SET @FROM_TOSQL =""
END
ELSE IF @RPTWISE = 2
BEGIN
SET @JOINSQL = "INNER JOIN "+@TEMPTABLE + " TT ON TT.CODE = PSM.BALENO "
SET @ORDERBYSQL = "PSM.TRANSPORTBILL_DATE,TR.TRANSPORT_NAME,TR.TRANSPORT_ID,PSM.TRANSPORT_BILL"
SET @FROM_TOSQL =""
END
ELSE IF @RPTWISE = 3
BEGIN
SET @JOINSQL = ""
SET @FROM_TOSQL =" AND ISNULL(PSM.TRANSPORT_BILL,0) BETWEEN "+@FROM_BALENO+" AND "+@TO_BALENO+" "
SET @ORDERBYSQL = "PSM.TRANSPORT_BILL,PSM.TRANSPORTBILL_DATE"
END

SET @STRSQL=" SELECT PSM.PACKINGSLIPID, PSM.TRANSPORT_BILL AS BILLNO, PSM.TRANSPORTBILL_DATE AS VCHDATE, LM.LGR_NAME AS PNAME, CM_1.CITY_NAME AS PARTYCITY ,CM.CITY_NAME AS DESTINATION ,
TR.TRANSPORT_NAME AS TRNAME,IM.ITEM_NAME AS ITEM,PSM.BALENO,CASE WHEN IM.RATE_PER='P' THEN PSD.TOTALPCS ELSE TOTAL END AS QTY,
/* ISNULL((IOS.SAL_RATE * (LM.TRANS_PER/100)),0)  AS RATE,
(CASE WHEN IM.RATE_PER='P' THEN PSD.TOTALPCS ELSE TOTAL END * ISNULL((IOS.SAL_RATE *  (LM.TRANS_PER/100) ) ,0)) AS AMOUNT, */
CONVERT(NUMERIC(18,2),CASE WHEN IOS.SAL_RATE=0 OR IOS.SAL_RATE IS NULL  THEN (PSD.ITEM_RATE * (PSM.RATE_PER/100)) ELSE (IOS.SAL_RATE * (PSM.RATE_PER/100)) END) AS RATE,
(CASE WHEN IM.RATE_PER='P' THEN PSD.TOTALPCS ELSE TOTAL END * 
CASE WHEN IOS.SAL_RATE=0 OR IOS.SAL_RATE IS NULL  THEN (PSD.ITEM_RATE * (PSM.RATE_PER/100)) ELSE (IOS.SAL_RATE * (PSM.RATE_PER/100)) END) AS AMOUNT,
ISNULL(LM.LGR_CSTNO,'') AS STNO,PSM.WEIGHT AS TOTWT,ISNULL(PSM.NARRATION,'') AS NARRATION,ISNULL(LM.LGR_PASSWORD,'') AS LGR_PASSWORD,
ISNULL(GM.GODOWN_NAME,'') AS GODOWN,ISNULL(GM.GODOWN_ID,0) AS GODOWNID /*LGR_STNO*/
FROM  "+@DATABASENAME+"PACKINGSLIP PSM 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PSM.PACKINGSLIPID = PSD.PACKINGSLIPID  AND PSD.CMP_CODE=PSM.CMP_CODE
INNER JOIN  "+@DATABASENAME+"ITEM_MASTER IM ON PSD.ITEM_ID = IM.ITEM_ID 
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=IM.ITEM_ID AND IOS.CMP_CODE="+@CMP_CODE+"
LEFT JOIN  "+@DATABASENAME+"LEDGER_MASTER LM ON PSM.LGR_ID = LM.LGR_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TR ON PSM.TRANSPORT_ID = TR.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON PSM.STATION_ID= CM.CITY_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM_1 ON LM.CITY_ID = CM_1.CITY_ID
LEFT JOIN "+@DATABASENAME+"GODOWN_MASTER GM ON PSM.GODOWN_ID = GM.GODOWN_ID
"+@JOINSQL+"

WHERE PSM.CMP_CODE="+ @CMP_CODE +"   AND PSM.TRANSPORTBILL_DATE BETWEEN '"+@FROMDATE+"'  AND '"+@TODATE+"' AND ISNULL(PSM.TRANSPORT_BILL,0) > 0 
"+@FROM_TOSQL+"
ORDER BY "+@ORDERBYSQL+""
/*AND PSM.TRANSPORT_ID="+@TRANSPORT_ID+" */

END
--PRINT @STRSQL
EXECUTE SP_EXECUTESQL @STRSQL
PRINT @STRSQL



















GO

