CREATE PROCEDURE [dbo].[PROC_TRANSPORTGATEPASS]
@FromDocNo  nvarchar(20),
@ToDocNo  nvarchar(20),
@Cmp_Code nvarchar(10),
@DatabaseName nvarchar(50)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="			
SELECT TG.DOCNO,TG.VCH_DATE,TGD.RUKKANO,TGD.ALIAS,TGD.RUKKA_DATE,TGD.BALES,TGD.BALENOSTRING,TM.TRANSPORT_NAME,LM.LORIWALA_NAME 
   FROM  "+ @DatabaseName +"TRANSPORT_GATEPASS_DETAIL TGD
   INNER JOIN  "+ @DatabaseName +"TRANSPORT_GATEPASS TG ON TG.TRANS_GATEPASS_ID=TGD.TRANS_GATEPASS_ID 
   INNER JOIN "+ @DatabaseName +"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=TGD.TRANSPORT_ID
   INNER JOIN "+ @DatabaseName +"LORIWALA_MASTER LM ON LM.LORIWALA_ID=TG.LORIWALA_ID
WHERE  TG.DOCNO BETWEEN "+ @FromDocNo +" AND "+ @ToDocNo +"
ORDER BY TG.DOCNO,TGD.RUKKANO
"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

