/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 09-04-2016
-- DESCRIPTION:	thisreport is used in transport invoice pending report

-- =============================================

PROC_TRANSPORTINV_PENDING 'ACC2015_2016.DBO.','1', '',1,'01/APR/2015','31/MAR/2016'
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTINV_PENDING]
(
@DATABASENAME AS NVARCHAR(30),
@CMP_CODE AS NVARCHAR(20),
@TEMPTB AS NVARCHAR(20),
@RPTWISE AS INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20)
)	
AS
BEGIN
 
 
 
 DECLARE @STRSQL  NVARCHAR(4000)
 DECLARE @STRJOIN NVARCHAR(300)
 
 SET @STRJOIN=""
 SET @STRSQL =""
 IF @RPTWISE=1 
 BEGIN
 SET @STRJOIN=" INNER JOIN "+ @TEMPTB  +" TT ON TT.CODE=TM.TRANSPORT_ID"
 END
 
 
 IF @TEMPTB='' 
 BEGIN
 SET @STRJOIN=''
 END
 
 SET @STRSQL ="SELECT  TLD.LRNO,TLD.BILL_DATE,TLD.LR_DATE,TLD.BILL_NO, 
TM.TRANSPORT_NAME,TM.TRANSPORT_ID, TI.INVOICE_NO,CASE WHEN ISNULL(SESKAR_INCLUDE,0)=1 THEN SESKAR_REGISTER_NO ELSE CONVERT(NVARCHAR, SVD.DOCNO) END SESKARDOCNO
FROM "+@DATABASENAME+"TRANSPORT_LR_DETAIL TLD
INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TLD.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_INVOICE TI ON TI.TRANSPORT_ID =TLD.TRANSPORT_ID AND TI.CMP_CODE=TLD.CMP_CODE AND TI.PURCHASEINVID=TLD.PURCHASEINVID
AND TI.LRNO =TLD.LRNO AND TI.ENTRYTYPE=TLD.ENTRYTYPE
LEFT JOIN "+@DATABASENAME+"SESKARVOUCHER_DETAIL SVD ON SVD.PURCHASEINVID=TLD.PURCHASEINVID AND SVD.TRANSPORT_ID=TLD.TRANSPORT_ID
AND SVD.LRNO =TLD.LRNO AND SVD.CMP_CODE=TLD.CMP_CODE AND SVD.ENTRYTYPE=TLD.ENTRYTYPE 
"+@STRJOIN+"
WHERE TLD.CMP_CODE="+ @CMP_CODE  +" AND TLD.BILL_DATE BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE  +"'
ORDER BY TM.TRANSPORT_NAME,TLD.LRNO,TLD.BILL_DATE " 
 PRINT @STRSQL
 EXECUTE SP_EXECUTESQL @STRSQL
END



















GO

