/*
-- =============================================
-- Author:		<PRATIK PATEL>
-- Create_date: 27/MAY/2013
-- Description:	TRANSPORT_INVOICE_PRINT.RPT
-- =============================================

PROC_TRANSPORTINVOICE 1,'ACC2020_2021.DBO.','1','1','B'
*/

CREATE PROCEDURE [dbo].[PROC_TRANSPORTINVOICE]
(
  
  @CMP_CODE nvarchar(10),
  @DATABASENAME nvarchar(50),
  @FROMBILLNO  nvarchar(20),  
  @TOBILLNO  nvarchar(20),
  @TYPE nvarchar(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
SET @SQL=""
BEGIN
set nocount on;
SET @SQL="SELECT CONVERT(INT,SI.SAL_INV_BILL_NO) AS BILLNO,SI.SAL_INV_VDATE AS VDATE,
UPPER(LM.LGR_NAME) AS PARTYNAME,UPPER(PCM.CITY_NAME) AS PARTYCITY,
LM.LGR_CSTNO,CM.CITY_NAME AS DESTINATION,TM.TRANSPORT_NAME,SI.SAL_INV_LRNO,SI.SAL_INV_LRDATE
,SID.SAL_INV_BALENO AS BALENO,SID.SAL_INV_PCS AS PCS,(CASE WHEN SID.SAL_INV_NETQTY = 0  THEN SID.SAL_INV_QTY WHEN SID.SAL_INV_NETQTY IS NULL THEN SID.SAL_INV_QTY ELSE SID.SAL_INV_NETQTY END) AS QUANTITY,SAL_INV_AMOUNT AS AMOUNT,
SID.SAL_INV_RATE AS RATE,SAL_INV_NETTOTAL AS NETTOTAL,SI.SAL_INV_ADDTOTAL,SAL_INV_ROUNDOFF,
SI.SAL_INV_LESSTOTAL,SI.SAL_INV_GROSSTOTAL,CTM.CONVERSION,CTM.CUT_NAME,SI.AMT_WORD
,UPPER(CMP.CMP_NAME)AS CMP_NAME,ISNULL(CMP.CMP_ADD1,'') AS CMP_ADD1,ISNULL(CMP.CMP_ADD2,'')AS CMP_ADD2,
ISNULL(CMP.CMP_CITY,'') AS CMP_CITY ,ISNULL(CMP.CMP_STATE,'') AS CMP_STATE
,CMP.CMP_PHONE1,CMP.CMP_PHONE2,CMP.CMP_MOBILE,
(CASE  WHEN isnull(SI.WEIGHT,0) > 0 THEN SI.WEIGHT  ELSE (CASE when um.unit_name = 'PIECES'  then (IM.Item_Weight *Sal_Inv_PcsTotal * ( CASE WHEN IM.Item_Conversion = 0 THEN 1 ELSE IM.Item_Conversion END)) ELSE   (IM.Item_Weight *Sal_Inv_QuantityTotal * ( CASE WHEN IM.Item_Conversion = 0 THEN 1 ELSE IM.Item_Conversion END))END) END) as WEIGHT,
SI.FREIGHT,CMP.CMP_TIN_NO,(SAL_INV_VDATE + SAL_CRDAYS) AS DUEDATE,
SID.SAL_INV_DTL_ID AS SRNO,SAL_REMARK,DOCUMENTS,LM.LGR_ADD1,UPPER(AGM.LGR_NAME) AS AGENTNAME,UPPER(ISNULL(ACM.CITY_NAME,'')) AS AGENTCITY,
CONVERT(NVARCHAR,LM.CITY_PINCODE) AS CITY_PINCODE,ISNULL(CMP.CMP_JURISDICTION,'') AS CMP_JURISDICTION,
LM.GSTINNO,LM.ADHARNO,HSN.Hsn_Name as  HSNCODE,LM.Lgr_Pano AS LGRPANNO,CMP.GSTINNO AS CMP_GSTINNO,
SM.State_Code,SM.STATE_NAME AS PSTATE,(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)as ADDBEFOREVALUE ,(SI.Sal_Inv_GrossTotal-SI.Sal_Inv_LessTotal+(SI.SAL_INV_ADD1+SI.SAL_INV_ADD2)) AS TAXABLEAMT,SI.SAL_INV_ADD1,SI.SAL_INV_ADD2,SI.SAL_INV_ADD3,SI.SAL_INV_ADD4,SI.SAL_INV_ADD5,
SI.SAL_INV_ADD1_SET,SI.Sal_Inv_Add2_Set,SI.Sal_Inv_Add3_Set,SI.Sal_Inv_Add4_Set,SI.Sal_Inv_Add5_Set,SI.SALES_ALIAS,ISNULL(SI.EWAYBILLNO,'') AS EWAYBILLNO,TM.TRANSEW_ID,
ISNULL(CMM.Name,'') AS CONSIGNEENAME,CMM.Add1 AS CONSIGNEE_ADD1,CMM.Add2 AS CONSIGNEE_ADD2,CMM.Add3 AS CONSIGNEE_ADD3,
COCM.CITY_NAME AS CONSIGNEE_CITY,COSM.STATE_NAME AS CONSIGNEE_STATE,COSM.State_Code AS CONSIGNEE_STATECODE,CMM.GSTINNO AS CONSIGNEE_GSTNO,CMM.PhoneNo AS  consingee_phone,CMM.MobileNo AS CONSINGEE_MOBILE,CMM.Contry AS CONSIGNEE_COUNTRY,SI.EINVNO,SI.TCS_PER,SI.TCS_AMT
FROM "+@DATABASENAME+"SALES_INVOICE SI
INNER JOIN "+@DATABASENAME+"SALES_INVOICE_DETAIL SID ON SID.SAL_INV_ID=SI.SAL_INV_ID AND SI.FLAG=SID.FLAG
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=SI.LGR_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON SID.ITEM_ID=IM.ITEM_ID
INNER JOIN "+@DATABASENAME+"UNIT_MASTER UM ON IM.UNIT_ID = UM.UNIT_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER AGM ON AGM.LGR_ID=SI.AGENT_ID
LEFT JOIN "+@DATABASENAME+"CUT_MASTER CTM ON CTM.CUT_ID=SID.CUT_ID
INNER JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON SI.CMP_CODE= CMP.CMP_CODE     
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID     	 
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ACM ON ACM.CITY_ID=AGM.CITY_ID     	 
LEFT JOIN "+@DATABASENAME+"STATE_MASTER SM ON PCM.STATE_ID=SM.STATE_ID
LEFT JOIN "+@DATABASENAME+"hsn_master HSN ON HSN.Hsn_Id=IM.Hsn_Id
LEFT JOIN " + @DATABASENAME +"CONSIGNEE_MASTER CMM ON CMM.Consignee_Id=SI.Consignee_Id	
LEFT JOIN " + @DATABASENAME +"STATE_MASTER COSM ON CMM.STATE_ID=COSM.STATE_ID
LEFT JOIN " + @DATABASENAME +"CITY_MASTER COCM ON COCM.CITY_ID=CMM.City_Id

WHERE SI.CMP_CODE='"+@CMP_CODE+"' AND  CONVERT(INT,SI.SAL_INV_BILL_NO) BETWEEN '"+@FROMBILLNO+"' AND '"+@TOBILLNO+"' AND SI.FLAG IN ('S','GS')
--AND SAL_INV_TYPE='"+@TYPE+"'
ORDER BY   CONVERT(INT,SI.SAL_INV_BILL_NO),(SID.SAL_INV_BALENO),SAL_INV_DTL_ID

"
      
END	

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




























































































































































GO

