@DATABASENAME AS NVARCHAR(100),
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20),
@TEMPTABLE AS NVARCHAR(20),
@RPT_WISE AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
DECLARE @STRORDERBY AS NVARCHAR(200)


SET @SQL =""
SET @JOINSQL =""
SET @STRORDERBY=""
BEGIN
IF @RPT_WISE=1
BEGIN
SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID "
SET @STRORDERBY="  ORDER BY TM.TRANSPORT_NAME,TM.TRANSPORT_ID,TP.TRANSPORTINVOICEID,TP.INVOICE_NO,LRNO"
END

ELSE IF @RPT_WISE=2
BEGIN
SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CM.CITY_ID "
SET @STRORDERBY= " ORDER BY CM.CITY_NAME,CM.CITY_ID,TP.TRANSPORTINVOICEID,TP.INVOICE_NO,LRNO "
END

ELSE IF @RPT_WISE=3
BEGIN
SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=TP.INVOICE_NO "
SET @STRORDERBY= " ORDER BY TP.TRANSPORTINVOICEID,TP.INVOICE_NO,LRNO "
END

ELSE IF @RPT_WISE=4
BEGIN
SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=TM.TRANSPORT_ID "
SET @STRORDERBY="  ORDER BY TM.TRANSPORT_NAME,TM.TRANSPORT_ID,CM.CITY_NAME,CM.CITY_ID,TP.TRANSPORTINVOICEID,TP.INVOICE_NO,LRNO"
END

ELSE IF @RPT_WISE=5
BEGIN
SET @JOINSQL=" INNER JOIN  "+@TEMPTABLE +" TT ON TT.CODE=CM.CITY_ID "
SET @STRORDERBY= " ORDER BY CM.CITY_NAME,CM.CITY_ID,TM.TRANSPORT_NAME,TM.TRANSPORT_ID,TP.TRANSPORTINVOICEID,TP.INVOICE_NO,LRNO "
END

END

BEGIN 

SET  @SQL =	  " SELECT TP.TRANSPORTINVOICEID,TP.LRDATE AS DATE,TP.TRANSPORT_ID,TP.REMARKS,
LRNO,BALES,LRDATE,TP.CITY_ID,CHALLAN_NO,RECEIPT_NO,SESKAR_REGISTER_NO,FREIGHT,
LC,DC,ST,TAXI_FARE,SESKAR_AMT,DALALI,TOTAL_FARE,INVOICE_NO,FREIGHT1,
BILLAMOUNT,TM.TRANSPORT_NAME AS TRANSPORT,CM.CITY_NAME AS STATION
FROM "+@DATABASENAME+"TRANSPORT_INVOICE TP

INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TP.TRANSPORT_ID
INNER JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID = TP.CITY_ID
"+@JOINSQL+"
WHERE TP.CMP_CODE IN("+@CMP_CODE +") AND TP.LRDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' "+@STRORDERBY+""


END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL



















GO

