/*   --PROC_TRANSPORTNOTICE '2','ACC2010_2011.DBO.','1','10'*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTNOTICE]
(
    @CMP_CODE AS NVARCHAR(50),
    @DATABASENAME AS NVARCHAR(50),
    @FROMDOCNO AS NVARCHAR(20),
    @TODOCNO AS NVARCHAR(20)
)
AS

DECLARE @SQL AS NVARCHAR(4000)
SET @SQL=""
BEGIN

SET @SQL="
            SELECT TN.DOCNO,TN.VCHDATE AS DATE,TN.LRNO,TN.LRDATE,TN.BILLNO,TN.BILLDATE,TN.BILLAMOUNT
            ,TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANS_ADD1,TM.TRANS_ADD2,TM.TRANS_ADD3
            ,LM.LGR_NAME AS PARTY,PCM.CITY_NAME AS PARTYCITY,SM.CITY_NAME AS STATION
            ,TCM.CITY_NAME AS TRANSPORTCITY,TS.STATE_NAME AS TRANSPORTSTATE,TM.PINCODE,TM.DISTRICT
            FROM "+@DATABASENAME+"TRANSPORTNOTICE TN
            INNER JOIN "+@DATABASENAME+"TRANSPORT_MASTER  TM ON TM.TRANSPORT_ID=TN.TRANSPORT_ID
            LEFT JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=TN.LGR_ID
            LEFT JOIN "+@DATABASENAME+"CITY_MASTER SM ON SM.CITY_ID=TN.CITY_ID
            LEFT JOIN "+@DATABASENAME+"CITY_MASTER PCM ON PCM.CITY_ID=LM.CITY_ID
            LEFT JOIN "+@DATABASENAME+"CITY_MASTER TCM ON TCM.CITY_ID=TM.CITY_ID
            LEFT JOIN "+@DATABASENAME+"STATE_MASTER TS ON TS.STATE_ID=TM.STATE_ID
            WHERE TN.CMP_CODE IN ("+@CMP_CODE+") AND TN.DOCNO BETWEEN "+@FROMDOCNO +" AND "+ @TODOCNO + "
"
	
END

EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

