/*
-- =============================================
-- ALTER_AUTHOR  :	<BIREN>
-- ALTER_DATE    : <16-01-2015 6:49 PM>
-- REPORT_FORM    :	<rfrmTransportRateReport.CS>
-- CRYSTAL_REPORT :	<TRANSPORTRATEREPORT.RPT>
-- =============================================
SELECT * FROM TEMPDB..SYSOBJECTS WHERE NAME LIKE '##%'
PROC_TRANSPORTRATEREPORT '01/APR/2014','31/MAR/2015','1',1,'ACC2014_2015.DBO.','##2072'
',1
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTRATEREPORT]
(
@FROMDATE  NVARCHAR(20),
@TODATE NVARCHAR(20),
@CMP_CODE NVARCHAR(10),
@RPT_WISE INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(3999)
DECLARE @SELECTED AS NVARCHAR(1000)
DECLARE @CONDSQL AS NVARCHAR(1000)
DECLARE @ORDERBY AS NVARCHAR(200)


SET @SQL=""
SET @SELECTED=""
SET @CONDSQL=""
SET @ORDERBY =""

BEGIN

BEGIN    
IF @RPT_WISE IN (1)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TRM.DATE = TT.CODE "
SET @ORDERBY =" ORDER BY TRM.DATE,TRM.DOC_NO"
END
ELSE IF @RPT_WISE IN (2)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TM.TRANSPORT_ID = TT.CODE "
SET @ORDERBY =" ORDER BY TM.TRANSPORT_NAME ,TM.TRANSPORT_ID "
END
ELSE IF @RPT_WISE IN (3)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.CITY_ID = TT.CODE "
SET @ORDERBY =" ORDER BY SM.CITY_NAME ,SM.CITY_ID "
END
ELSE IF @RPT_WISE IN (4)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON TM.TRANSPORT_ID = TT.CODE "
SET @ORDERBY =" ORDER BY TM.TRANSPORT_NAME ,TM.TRANSPORT_ID,SM.CITY_NAME ,SM.CITY_ID "
END
ELSE IF @RPT_WISE IN (5)
BEGIN
SET @SELECTED=" INNER JOIN " + @TEMPTABLE + " TT ON SM.CITY_ID = TT.CODE "
SET @ORDERBY =" ORDER BY SM.CITY_NAME ,SM.CITY_ID,TM.TRANSPORT_NAME ,TM.TRANSPORT_ID "
END
END

SET @SQL="
SELECT TRM.TRANSPORTRATEID,TRM.CMP_CODE,TRM.DOC_NO,
CONVERT(NVARCHAR,TRM.DATE,103) AS DATE,
ISNULL(TRM.FREIGHT,0) AS FREIGHT,ISNULL(TRM.FREIGHT_TYPE,'') AS FREIGHT_TYPE,
ISNULL(TRM.LC,0) AS LC,ISNULL(TRM.LC_TYPE,'') AS LC_TYPE,
ISNULL(TRM.DC,0) AS DC,ISNULL(TRM.DC_TYPE,'') AS DC_TYPE,
ISNULL(TRM.ST,0) AS ST,ISNULL(TRM.ST_TYPE,'') AS ST_TYPE,
ISNULL(TRM.SESKAR_AMT,0) AS SESKAR_AMT,ISNULL(TRM.SESKAR_AMT_TYPE,'') AS SESKAR_AMT_TYPE,
ISNULL(TRM.TEXIFARE,0) AS TEXIFARE,ISNULL(TRM.TEXIFARE_TYPE,'') AS TEXIFARE_TYPE,
ISNULL(TRM.DALALI,0) AS DALALI,ISNULL(TRM.DALALI_TYPE,'') AS DALALI_TYPE,
ISNULL(TRM.FREIGHT1,0) AS FREIGHT1,ISNULL(TRM.FREIGHT_TYPE1,'') AS FREIGHT_TYPE1,
ISNULL(TRM.EXTEXIFARE,0) AS EXTEXIFARE,ISNULL(TRM.EXTEXIFARE_TYPE,'') AS EXTEXIFARE_TYPE,
ISNULL(SM.CITY_NAME, '') AS STATION,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORT_ID,ISNULL(SM.CITY_ID,0) AS CITY_ID
FROM "+@DATABASENAME+"TRANSPORT_RATE_MASTER TRM
LEFT JOIN "+@DATABASENAME+"CITY_MASTER SM ON TRM.STATION_ID = SM.CITY_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TRM.TRANSPORT_ID = TM.TRANSPORT_ID
"+ @SELECTED +"
WHERE TRM.CMP_CODE IN ("+@CMP_CODE+") AND TRM.DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
 "+@ORDERBY+""

END	
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL



















GO

