CREATE PROCEDURE [dbo].[PROC_TRANSPORTREPORT]
(
  @cmp_Code as nvarchar(20),
  @DatabaseName as nvarchar(100),
  @FromDate as nvarchar(20),
  @ToDate as nvarchar(20),
  @TempTable	as nvarchar(100),
  @Detail_Summary as int
)
AS
Declare @Sql as Nvarchar(4000)
Declare @SqlJOIN as Nvarchar(4000)
set @Sql=""                
SET @SqlJOIN=""
SET @SqlJOIN=" INNER JOIN "+ @TempTable + " TT ON TT.CODE=TM.TRANSPORT_ID"
BEGIN	
	SET NOCOUNT ON;
    if @Detail_Summary=1 
        begin 
              set @Sql=" SELECT SI.SAL_INV_BILL_NO AS  BILLNO,SI.SAL_INV_LRNO AS LRNO,SI.SAL_INV_LRDATE AS LRDATE,SI.SAL_INV_BALESTOTAL AS BALES
                        ,CM.CITY_NAME AS STATION,TM.TRANSPORT_NAME AS TRANSPORT
                         FROM "+ @DatabaseName + "SALES_INVOICE SI
                         INNER JOIN  "+ @DatabaseName + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
                         LEFT JOIN  "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID "+  @SQLJOIN + "
                         WHERE SI.CMP_CODE="+@cmp_Code + "  AND SI.SAL_INV_VDATE BETWEEN '"+ @FromDate +"' AND '"+ @ToDate +"'        
                         ORDER BY TM.TRANSPORT_NAME"
        end
     if @Detail_Summary=0
        begin 
              set @Sql=" SELECT min(SI.SAL_INV_BILL_NO) AS  BILLNO,min(SI.SAL_INV_LRNO) AS LRNO,'01/04/2009' AS LRDATE,COUNT(SI.SAL_INV_BALESTOTAL) AS BALES
                        ,CM.CITY_NAME AS STATION,TM.TRANSPORT_NAME AS TRANSPORT
                         FROM "+ @DatabaseName + "SALES_INVOICE SI
                         INNER JOIN  "+ @DatabaseName + "TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=SI.TRANSPORT_ID
                         LEFT JOIN  "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=SI.STATION_ID "+  @SQLJOIN + "
                         WHERE SI.CMP_CODE="+@cmp_Code + "  AND SI.SAL_INV_VDATE BETWEEN '"+ @FromDate +"' AND '"+ @ToDate +"'        
                         GROUP BY CM.CITY_NAME ,TM.TRANSPORT_NAME
                         ORDER BY TM.TRANSPORT_NAME"
        end
	exec sp_executesql @Sql
    print @Sql
END




















GO

