/*
PROC_TRANSPORTRUKAREPORT 1,'ACC2012_2013.DBO.','1','01/Apr/2012', '24/Aug/2012', '##3472' 
*/

CREATE PROCEDURE [dbo].[PROC_TRANSPORTRUKAREPORT]
(
    @Cmp_Code nvarchar(10),
    @DatabaseName nvarchar(50),
    @Rpt_Wise int,
    @FromDate as Nvarchar(20),
    @ToDate as Nvarchar(20),
    @TempTable nvarchar(20)
)
as
declare @Sql  Nvarchar(4000)
declare @JoinSql  Nvarchar(100)
Declare @TypeSql Nvarchar(100)
set @JoinSql=""
Set @TypeSql=""
if @Rpt_Wise=1
set @JoinSql=" inner join "+ @TempTable + " TT on TT.Code=TD.DOCNO"

begin

    	SET NOCOUNT ON;
set @sql=" SELECT TDD.Trans_Delivery_ID,TDD.BaleNo,TD.DOCNO AS RukkaNo, TDD.Weight,TrM.Transport_Name ,
CM.City_Name as DestinationName,LM.Lgr_Name As PartyName,PCM.City_Name as PCity
,TDD.Self_Party,TDD.SerialNo,TDD.Godown,TDD.OTHER
FROM "+@DatabaseName+" Transport_Delivery_Detail TDD
INNER JOIN "+@DatabaseName+" TRANSPORT_DELIVERY TD ON TDD.Trans_delivery_id=TD.Trans_delivery_id
INNER JOIN "+@DatabaseName+" Ledger_Master LM ON TDD.Lgr_Id=LM.Lgr_Id
"+@JoinSql+"
LEFT OUTER JOIN "+@DatabaseName+"Transport_Master TrM ON TD.Transport_Id=TrM.Transport_Id
LEFT OUTER JOIN "+@DatabaseName+"City_Master CM ON CM.City_ID=TDD.Station_Id
LEFT OUTER JOIN "+@DatabaseName+"City_Master PCM ON PCM.City_Id=LM.City_Id
WHERE TD.Cmp_Code="+@Cmp_Code+" 
ORDER BY TDD.SerialNo
"
        execute Sp_Executesql @sql
        Print @sql
end




















