SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO






















/*
-- =============================================
-- AUTHOR:		GAMI DIPAK
-- ALTER_DATE: 08-11-2014
-- DESCRIPTION:	THIS PROCEDURE IS USED TO TRANSPORT RUKKA REPORT
PROC_TRANSPORTRUKKA  '1','ACC2014_2015.DBO.',1,'01/MAR/2014','31/MAR/2015',0,0,0,1
-- =============================================
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTRUKKA]
(
@CMP_CODE NVARCHAR(1000),
@DATABASENAME NVARCHAR(50),
@RPT_WISE INT,
@FROMDATE AS NVARCHAR(20),
@TODATE AS NVARCHAR(20), 
@ID AS NVARCHAR(50),
@FROMBALENO AS NVARCHAR(20),
@TOBALENO AS NVARCHAR(20),
@ORDERBY AS INT
)
AS
DECLARE @SQL NVARCHAR(4000)
DECLARE @CONDITION NVARCHAR(200)
DECLARE @STRORDERBY NVARCHAR(100)

SET @SQL=""
SET @CONDITION=""



IF @ORDERBY=1 
SET @STRORDERBY='TRANSPORT,TRANSPORTID,PARTY,PARTYID'
ELSE
SET @STRORDERBY='TRANSPORT,TRANSPORTID,BALENO'

IF @RPT_WISE =2 AND @ID <>''
BEGIN
SET @CONDITION=" AND PS.TRANSPORT_ID="+@ID+""



END
ELSE IF (@RPT_WISE =3  OR @RPT_WISE =7) AND @FROMBALENO <>'' AND @TOBALENO<>''
BEGIN
SET @CONDITION=" AND PS.BALENO>="+@FROMBALENO+" AND PS.BALENO<="+@TOBALENO+""



END
ELSE IF (@RPT_WISE =4  OR @RPT_WISE =5 ) AND @ID <>''
BEGIN
SET @CONDITION=" AND PS.GODOWN_ID="+@ID+""


END

BEGIN

SET @SQL=" SELECT BALENO,PARTY ,PCITY,LGR_STNO,STATION,TRANSPORT,GODOWN,SUM(TOTAMT) AS TOTAMT,
WEIGHT,MAX(ITEM_NAME) AS ITEM_NAME,NARRATION1,LGR_PASSWORD,PARTYID,TRANSPORTID,GODOWNID
FROM(
SELECT PS.BALENO,LM.LGR_NAME AS PARTY ,CM.CITY_NAME AS PCITY,ISNULL(LM.LGR_STNO,'') AS LGR_STNO,
ST.CITY_NAME AS STATION,ISNULL(TM.TRANSPORT_NAME,'') AS TRANSPORT,ISNULL(GM.GODOWN_NAME,'') AS GODOWN,
(PSD.TOTALPCS * ISNULL((ISNULL(IOS.SAL_RATE,0) *(LM.TRANS_PER/100)),0)) AS TOTAMT,PS.WEIGHT,IM.ITEM_NAME,
ISNULL(SO.NARRATION1,'') AS NARRATION1,ISNULL(LM.LGR_PASSWORD,'') AS LGR_PASSWORD,ISNULL(LM.LGR_ID,0) AS PARTYID,
ISNULL(TM.TRANSPORT_ID,0) AS TRANSPORTID,ISNULL(GM.GODOWN_ID,0) AS GODOWNID
FROM "+@DATABASENAME+"PACKINGSLIP PS 
INNER JOIN "+@DATABASENAME+"PACKINGSLIP_DETAIL PSD ON PS.PACKINGSLIPID =PSD.PACKINGSLIPID AND PSD.CMP_CODE=PS.CMP_CODE
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID =PS.LGR_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID =LM.CITY_ID
LEFT JOIN "+@DATABASENAME+"TRANSPORT_MASTER TM ON TM.TRANSPORT_ID=PS.TRANSPORT_ID 
LEFT JOIN "+@DATABASENAME+"GODOWN_MASTER GM ON GM.GODOWN_ID=PS.GODOWN_ID
INNER JOIN "+@DATABASENAME+"ITEM_MASTER IM ON IM.ITEM_ID =PSD.ITEM_ID
LEFT JOIN "+@DATABASENAME+"CITY_MASTER ST ON ST.CITY_ID=PS.STATION_ID
INNER JOIN "+@DATABASENAME+"ITEM_OPENING_STOCK IOS ON IOS.ITEM_ID=IM.ITEM_ID AND PS.CMP_CODE=IOS.CMP_CODE AND IOS.CMP_CODE="+@CMP_CODE+"
LEFT JOIN "+@DATABASENAME+"SALES_ORDER SO ON SO.CONFNO =PS.CONFNO /*AND PS.CMP_CODE=SO.CMP_CODE*/ AND SO.FYEAR =PS.FYEAR  AND SO.SALES_ORDERNO=PS.ORDERNO
WHERE PS.CMP_CODE="+@CMP_CODE+" "+@CONDITION+" AND PS.FORMFLAG='WC' AND PS.VCH_DATE BETWEEN '"+ @FROMDATE +"' AND '"+ @TODATE +"') AS DETAIL
GROUP BY BALENO,PARTY ,PCITY,LGR_STNO,STATION,TRANSPORT,GODOWN,
WEIGHT,NARRATION1,LGR_PASSWORD,PARTYID,TRANSPORTID,GODOWNID
ORDER BY "+@STRORDERBY+""  


END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL






















GO

