/*
Proc_TransportVoucherReport 10,'Acc2010_2011.dbo.',1,10
*/
CREATE PROCEDURE [dbo].[Proc_TransportVoucherReport]
	(
		@CMP_CODE nvarchar(50),
		@DATEBASENAME nvarchar(50),
		@FROM_DOCNO nvarchar(50),
		@TO_DOCNO nvarchar(50)
	)
AS
BEGIN
	DECLARE @STR_SQL NVARCHAR(4000)

	SET NOCOUNT ON;
	SET @STR_SQL="  select DocNo,VchDate,CurrDate,TRM.Transport_Name,PM.Lgr_Name as AccountName,PPM.Lgr_Name as PurAccountName,
					CM.City_Name,GrossTotal,SerTaxPer,SerTaxAmount,Add_Amount,Less_Amount,RoundOff,NetTotal,TdsAmount,TOTALBALES,
					TD.LrNo,TD.LrDate,TD.Bales,TD.RukkaNo,TD.Amount,TM.TOTAL_WP,TM.TOTAL_FREIGHT,TD.WATER_POLL,TD.NET_AMOUNT
					from "+@DATEBASENAME+" TransportVoucher_Master TM
					inner join "+@DATEBASENAME+" TransportVoucher_Detail TD on TD.TransportVch_Id=TM.TransportVch_Id
					left join "+@DATEBASENAME+" Transport_Master TRM on TM.Transport_Id=TRM.Transport_Id
					left join "+@DATEBASENAME+" ledger_Master PM on TM.Account_Id=PM.lgr_Id
					left join "+@DATEBASENAME+" ledger_Master PPM on PPM.Lgr_Id=TM.PurAccount_Id
					left join "+@DATEBASENAME+" City_Master CM on PM.CIty_Id=CM.City_Id
					where TM.Cmp_Code in ("+@CMP_CODE+") and TM.DocNo between ("+@FROM_DOCNO+") and ("+@TO_DOCNO+")
					order by DocNo
   "
    
END
Execute Sp_ExecuteSql @STR_SQL
print @STR_SQL




















