/*
-- =============================================
-- Author:		HIREN B DOSHI
-- Create_date: 24/09/2013
-- Description:	THIS PROCEDURED USED FOR TRANSPORT RUKKA PENDING AND ALL REPORT SHOW
-- ReportName : TRANSPORTVOUCHERRUKKAPEND.RPT
-- =============================================
PROC_TRANSPORTVOUCHERRUKKAPEND 1,'ACC2013_2014.DBO.','01/APR/2013','24/SEP/2013','',1
*/
CREATE PROCEDURE [dbo].[PROC_TRANSPORTVOUCHERRUKKAPEND]
(
	@CMP_CODE NVARCHAR(50),
	@DATABASENAME NVARCHAR(100),
	@FROMDATE NVARCHAR(50),
	@TODATE NVARCHAR(50),
	@TEMPTABLE NVARCHAR(100),
	@RPTTYPE INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)

SET @SQL = ""

BEGIN
	IF @RPTTYPE = 1  /* PAID */
	BEGIN
		SET @SQL = " SELECT PUI.BILLNO,PUI.VCHDATE AS BILLDATE,PUI.LRNO,PUI.FREIGHT,PUI.WEIGHT,
					 TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANSPORT_ID,TVD.RUKKANO AS RUKKANO,TVD.AMOUNT AS AMOUNT,TVM.DOCNO
					 FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
					 INNER JOIN "+@DATABASENAME+" TRANSPORTVOUCHER_DETAIL TVD ON TVD.LRNO = PUI.LRNO AND PUI.CMP_CODE = TVD.CMP_CODE
					 INNER JOIN "+@DATABASENAME+" TRANSPORTVOUCHER_MASTER TVM ON TVD.TRANSPORTVCH_ID = TVM.TRANSPORTVCH_ID
					 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TVM.TRANSPORT_ID
					 INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID
					 WHERE PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PUI.CMP_CODE IN ("+@CMP_CODE+")
					 ORDER BY PUI.VCHDATE,TM.TRANSPORT_NAME,PUI.BILLNO"
	END
	ELSE IF @RPTTYPE = 2  /* PENDING */
	BEGIN
		SET @SQL = " SELECT PUI.BILLNO,PUI.VCHDATE AS BILLDATE,PUI.LRNO,PUI.FREIGHT,PUI.WEIGHT,
					 TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANSPORT_ID,0 AS RUKKANO,0 AS AMOUNT,0 AS DOCNO
					 FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
					 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = PUI.TRANSPORT_ID
					 INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID
					 WHERE PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PUI.CMP_CODE IN ("+@CMP_CODE+")
					 AND PUI.LRNO NOT IN (SELECT TVD.LRNO FROM "+@DATABASENAME+" TRANSPORTVOUCHER_DETAIL TVD) 
					 ORDER BY PUI.VCHDATE,TM.TRANSPORT_NAME"
	END
	ELSE IF @RPTTYPE = 3 /* ALL */
	BEGIN
		SET @SQL = " SELECT PUI.BILLNO,PUI.VCHDATE AS BILLDATE,PUI.LRNO,PUI.FREIGHT,PUI.WEIGHT,
					 TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANSPORT_ID,TVD.RUKKANO AS RUKKANO,TVD.AMOUNT AS AMOUNT,TVM.DOCNO
					 FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
					 INNER JOIN "+@DATABASENAME+" TRANSPORTVOUCHER_DETAIL TVD ON TVD.LRNO = PUI.LRNO AND PUI.CMP_CODE = TVD.CMP_CODE
					 INNER JOIN "+@DATABASENAME+" TRANSPORTVOUCHER_MASTER TVM ON TVD.TRANSPORTVCH_ID = TVM.TRANSPORTVCH_ID
					 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = TVM.TRANSPORT_ID
					 INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID
					 WHERE PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PUI.CMP_CODE IN ("+@CMP_CODE+")
					 UNION ALL
					 SELECT PUI.BILLNO,PUI.VCHDATE AS BILLDATE,PUI.LRNO,PUI.FREIGHT,PUI.WEIGHT,
					 TM.TRANSPORT_NAME AS TRANSPORT,TM.TRANSPORT_ID,0 AS RUKKANO,0 AS AMOUNT,0 AS DOCNO
					 FROM "+@DATABASENAME+" PURCHASEINVOICE PUI
					 INNER JOIN "+@DATABASENAME+" TRANSPORT_MASTER TM ON TM.TRANSPORT_ID = PUI.TRANSPORT_ID
					 INNER JOIN "+@TEMPTABLE+" TT ON TT.CODE=TM.TRANSPORT_ID
					 WHERE PUI.VCHDATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"' AND PUI.CMP_CODE IN ("+@CMP_CODE+")
					 AND PUI.LRNO NOT IN (SELECT TVD.LRNO FROM "+@DATABASENAME+" TRANSPORTVOUCHER_DETAIL TVD)
					 ORDER BY BILLDATE,TRANSPORT,BILLNO"
	END
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

