/*   --PROC_TRANSRUKKARECSYS '2,3','acc2010_2011.dbo.','01/apr/2010','31/DEC/2010',1*/
CREATE PROCEDURE [dbo].[PROC_TRANSRUKKARECSYS]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(100),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @RPT_TYPE AS INT
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @PENDSQL AS NVARCHAR(4000)
SET @PENDSQL=""
SET @SQL=""
BEGIN
      IF @RPT_TYPE =0 
                BEGIN
                    SET @PENDSQL=""
                END
      ELSE IF @RPT_TYPE =1 
                BEGIN
                    SET @PENDSQL=" AND (TD.RECNO='' OR TD.RECNO IS NULL)"
                END

END


BEGIN
          SET @SQL=" SELECT TD.TRANS_DELIVERY_ID AS RUKKAID,TD.DOCNO AS RUKKANO,ISNULL(RECDATE,TD.VCH_DATE )AS  RecDate
                     ,TD.RECNO,CMP.CMP_ALIAS  
                     FROM "+@DATABASENAME+"TRANSPORT_DELIVERY TD 
                     LEFT JOIN "+@DATABASENAME+"COMPANY_MASTER CMP ON CMP.CMP_CODE=TD.CMP_CODE 
                     WHERE TD.CMP_CODE IN ("+@CMP_CODE +") AND TD.VCH_DATE BETWEEN '"+@FROMDATE+"' AND '"+@TODATE+"'
                     "+@PENDSQL+"
                     ORDER BY TD.DOCNO
                     "
END
EXEC SP_EXECUTESQL @SQL
PRINT @SQL




















GO

