/*
-- =============================================
-- EDIT_AUTHOR    : <BIREN>
-- EDIT_DATE      : <07-08-2013>
-- REPORT_FORM    :	<RFRMTRIALBALANCE>
-- CRYSTAL_REPORT : <TRIALBALANCE.RPT>
-- =============================================
PROC_TRIALBALANCE '31/MAR/2014',1,'2',2,'ACC2013_2014.DBO.','',1
*/
CREATE PROCEDURE [dbo].[PROC_TRIALBALANCE]
(
@TODATE NVARCHAR(20),
@OPENING_CLSOING INT,
@CMP_CODE NVARCHAR(10),
@QUERYNO INT,
@DATABASENAME NVARCHAR(50),
@TEMPTABLE NVARCHAR(20),
@SELALL  INT
)

AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SELECTED AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SELECTED=""

BEGIN
SET NOCOUNT ON;
BEGIN       
IF @SELALL=0
SET @SELECTED="  INNER JOIN " + @TEMPTABLE + " ON GM.GRP_ID=" + @TEMPTABLE + ".CODE"
END
BEGIN
IF @OPENING_CLSOING=1 
SELECT @SQL="SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY, 
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN CONVERT(NUMERIC(18,2),ISNULL(LD.LGR_OP_BAL,0)) WHEN LD.LGR_OP_DRCR = '' 
THEN ISNULL(LD.LGR_OP_BAL,0) ELSE 0 END AS DRAMOUNT, 
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN CONVERT(NUMERIC(18,2),ISNULL(LD.LGR_OP_BAL,0)) WHEN LD.LGR_OP_DRCR = ''
THEN ISNULL(LD.LGR_OP_BAL,0) ELSE 0 END AS CRAMOUNT 
FROM "+ @DATABASENAME + "LEDGER_DETAIL LD
INNER JOIN "+@DATABASENAME+"LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN "+@DATABASENAME+"GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN  "+@DATABASENAME+"CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID  
"+ @SELECTED  + " 
WHERE LD.CMP_CODE =" + @CMP_CODE  +" AND CONVERT(NUMERIC(18,2),ISNULL(LD.LGR_OP_BAL,0)) > 0 ORDER BY LM.LGR_NAME 
"
END
BEGIN
IF @OPENING_CLSOING=2

SELECT @SQL1 = " 
SELECT GROUPNAME,PARTYNAME,CITY,(CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))>0 THEN  
CONVERT(NUMERIC(18,2),SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))<0 THEN  
CONVERT(NUMERIC(18,2),SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END) AS CRAMOUNT FROM(

SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = ''
THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT,
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' 
THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT,LM.LGR_ID 
FROM "+ @DATABASENAME + "LEDGER_DETAIL LD
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID           
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
"+ @SELECTED  + " 
WHERE LD.CMP_CODE =" + @CMP_CODE+"  
/*
CHANGE FOR SHAILJA
10/OCT/2012 SANKET
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM1.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID  
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID  
"+ @SELECTED  + "
WHERE TM.CMP_CODE =" + @CMP_CODE  +" AND TM.TRAN_TYPE NOT IN ('J','DN','DN') AND TM.TRAN_DATE<='"+ @TODATE +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT,LM1.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID           
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID 
"+ @SELECTED  + "
WHERE TM.CMP_CODE=" + @CMP_CODE  +" AND TM.TRAN_TYPE NOT IN('J','DN','CN') AND  TM.TRAN_DATE<='"+ @TODATE +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL "
IF @OPENING_CLSOING=2

SELECT  @SQL2="
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT ,LM1.LGR_ID
FROM "+ @DATABASENAME + "AUTOJOURNAL AJ 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
/*INNER JOIN "+ @DATABASENAME + "AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH = AJ.ENTRYMATCH*/
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON AJ.LGR_ID= LM1.LGR_ID
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID  
"+ @SELECTED  + "
WHERE AJ.VDATE<='"+ @TODATE +"'   AND AJ.CMP_CODE=" + @CMP_CODE  +"  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, (CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT ,LM.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  AND JD.CMP_CODE= TM.CMP_CODE 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
--INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON JD.TRAN_DETAIL_ID = LM1.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID     
"+ @SELECTED  + "
WHERE TM.CMP_CODE=" + @CMP_CODE  +" AND TM.TRAN_DATE<='"+ @TODATE +"'   AND TM.TRAN_TYPE  IN ('J','DN','CN')	
/*
AND GM.GRP_ID<>24 
CHANGE FOR SHAILJA
10/OCT/2012 SANKET
UNION ALL
SELECT GM.GRP_NAME AS GROUPNAME,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AMOUNT AS DRAMOUNT,0.00 AS CRAMOUNT
FROM "+ @DATABASENAME + "VALUATIONENTRY VT
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON VT.LGR_ID= LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=VT.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID    
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID   
"+ @SELECTED  + " 
WHERE VT.CMP_CODE="+@CMP_CODE+"  AND MONTH=MONTH('"+@TODATE+"')
*/

) AS DETAIL  
GROUP BY GROUPNAME,PARTYNAME,CITY,LGR_ID HAVING CONVERT(NUMERIC(18,2),SUM(DRAMOUNT)-SUM(CRAMOUNT)) != 0 ORDER BY PARTYNAME "
END   
END	
EXEC(@SQL+ @SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2





















GO

