/*   
PROC_TRIALBALANCE_GRPWISE_WITH_OPEFFECT '1','ACC2012_2013.DBO.','31/mar/2013','##748'
*/
CREATE PROCEDURE [dbo].[PROC_TRIALBALANCE_GRPWISE_WITH_OPEFFECT]
(
   @CMP_CODE NVARCHAR(10),  
   @DATABASENAME NVARCHAR(50),  
   @TODATE NVARCHAR(20),
   @TEMPTABLE NVARCHAR(20)
)
AS
DECLARE @SQL AS NVARCHAR(4000)
DECLARE @SQL1 AS NVARCHAR(4000)
DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SQL3 AS NVARCHAR(4000)
DECLARE @JOINSQL AS NVARCHAR(1000)
SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SQL3=""
SET @JOINSQL=""
BEGIN
SET @JOINSQL="  INNER JOIN " + @TempTable + " TT ON AA.MAIN_GROUP_CODE=TT.CODE"
            
SET @SQL=" 

SELECT GROUPNAME,PARTYNAME,CITY,DRAMOUNT,CRAMOUNT,OPENINGDRCR,OPENINGBAL,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE 
,(CASE WHEN ISNULL(MAIN_GROUP_CODE,'')='' THEN MAIN_GROUP_CODE ELSE MAIN_GROUP_CODE END) AS MAIN_GROUP_CODE
,(CASE WHEN ISNULL(MAIN_GROUP,'')='' THEN GROUPNAME ELSE MAIN_GROUP END) AS MAIN_GROUP
FROM (
SELECT GROUPNAME,PARTYNAME,CITY,DRAMOUNT,CRAMOUNT,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN GRP_ACC_TYPE IN ('L') AND GRP_MAIN_ID IN (5,3,30,8,11,13) AND 
((CRAMOUNT+CR_OPENINGBAL)-(DRAMOUNT+DR_OPENINGBAL)) >0 THEN  GROUPNAME
WHEN GRP_ACC_TYPE IN ('L') AND GRP_MAIN_ID IN (5,3,30,8,11,13) AND 
((CRAMOUNT+CR_OPENINGBAL)-(DRAMOUNT+DR_OPENINGBAL)) <= 0 THEN  OP_GROUP_NAME
WHEN GRP_ACC_TYPE IN ('A')  AND GRP_MAIN_ID IN (4,1,29,7,9,10) 
AND ((DRAMOUNT+DR_OPENINGBAL)-(CRAMOUNT+CR_OPENINGBAL))>0 THEN GROUPNAME 
WHEN GRP_ACC_TYPE IN ('A')  AND GRP_MAIN_ID IN (4,1,29,7,9,10) 
AND ((DRAMOUNT+DR_OPENINGBAL)-(CRAMOUNT+CR_OPENINGBAL))<0 THEN OP_GROUP_NAME
ELSE  GROUPNAME
END ) AS MAIN_GROUP

,(CASE WHEN GRP_ACC_TYPE IN ('L') AND ((CRAMOUNT+CR_OPENINGBAL)-(DRAMOUNT+DR_OPENINGBAL))>0 THEN GROUP_CODE
WHEN GRP_ACC_TYPE IN ('L') AND ((CRAMOUNT+CR_OPENINGBAL)-(DRAMOUNT+DR_OPENINGBAL))<=0 THEN OP_GROUP_CODE 
WHEN GRP_ACC_TYPE IN ('A') AND ((DRAMOUNT+DR_OPENINGBAL)-(CRAMOUNT+CR_OPENINGBAL))>0 THEN GROUP_CODE 
WHEN GRP_ACC_TYPE IN ('A') AND ((DRAMOUNT+DR_OPENINGBAL)-(CRAMOUNT+CR_OPENINGBAL))<0 THEN OP_GROUP_CODE 
ELSE GROUP_CODE  
END ) AS MAIN_GROUP_CODE,GRP_MAIN_ID
,OPENINGDRCR,OPENINGBAL FROM (

SELECT GROUPNAME,PARTYNAME,CITY,DRAMOUNT,CRAMOUNT,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN GRP_ACC_TYPE IN ('L') AND GRP_MAIN_ID IN (5,3,30,8,11,13) AND ((CRAMOUNT)-(DRAMOUNT))<=0 THEN OP_GROUP_NAME 
WHEN GRP_ACC_TYPE IN ('A')  AND GRP_MAIN_ID IN (4,1,29,7,9,10) AND ((DRAMOUNT)-(CRAMOUNT))<=0 THEN OP_GROUP_NAME ELSE  GROUPNAME END ) AS MAIN_GROUP
,(CASE WHEN GRP_ACC_TYPE IN ('L') AND ((CRAMOUNT)-(DRAMOUNT))<=0 THEN OP_GROUP_CODE 
WHEN GRP_ACC_TYPE IN ('A') AND ((DRAMOUNT)-(CRAMOUNT))<=0 THEN OP_GROUP_CODE ELSE  GROUP_CODE END ) AS MAIN_GROUP_CODE,GRP_MAIN_ID
,OPENINGDRCR,OPENINGBAL,
(CASE WHEN OPENINGDRCR = 'C' THEN OPENINGBAL ELSE 0 END) AS CR_OPENINGBAL,
(CASE WHEN OPENINGDRCR = 'D' THEN OPENINGBAL ELSE 0 END) AS DR_OPENINGBAL
FROM (       
SELECT GROUPNAME,PARTYNAME,CITY,SUM(OPENINGBAL) AS OPENINGBAL,MAX(OPENINGDRCR) AS OPENINGDRCR,
ABS(SUM(DRAMOUNT))AS DRAMOUNT,ABS(SUM(CRAMOUNT)) AS CRAMOUNT ,GROUP_CODE,GRP_MAIN_ID,OP_GROUP_CODE,OP_GROUP_NAME,
GRP_ACC_TYPE,LGR_ID
FROM ("
SET @SQL3=" 
 SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY
,0 AS DRAMOUNT
,0 AS CRAMOUNT,
CONVERT(NUMERIC(18,2),ISNULL(LD.LGR_OP_BAL,0)) AS OPENINGBAL,LD.LGR_OP_DRCR AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DatabaseName + "Ledger_Detail LD
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @DatabaseName + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID           
LEFT JOIN "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
LEFT JOIN "+ @DatabaseName + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE LD.CMP_CODE =" + @Cmp_Code  +" AND LD.LGR_OP_BAL>0 
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,0 AS OPENINGBAL,'' AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM1.LGR_ID
FROM "+ @DatabaseName + "TRAN_MASTER TM  
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID 
INNER JOIN "+ @DatabaseName + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DatabaseName + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID  
LEFT JOIN "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID 
LEFT JOIN "+ @DatabaseName + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE TM.CMP_CODE =" + @Cmp_Code  +" AND TM.TRAN_TYPE NOT IN ('J','DN','DN') AND TM.TRAN_DATE<='"+ @ToDate +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
"
SET @SQL1=" 
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,0 AS OPENINGBAL,'' AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM1.LGR_ID
FROM "+ @DatabaseName + "TRAN_MASTER TM 
INNER JOIN "+ @DatabaseName + "TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
INNER JOIN "+ @DatabaseName + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DatabaseName + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID
LEFT JOIN "+ @DatabaseName + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE TM.CMP_CODE=" + @Cmp_Code  +" AND TM.TRAN_TYPE NOT IN('J','DN','CN') AND  TM.TRAN_DATE<='"+ @ToDate +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AJ.DRAMOUNT AS DRAMOUNT,AJ.CRAMOUNT AS CRAMOUNT 
,0 AS OPENINGBAL,'' AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DatabaseName + "AUTOJOURNAL AJ 
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
/*INNER JOIN "+ @DatabaseName + "AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH = AJ.ENTRYMATCH
*/
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM1 ON AJ.LGR_ID= LM1.LGR_ID
INNER JOIN "+ @DatabaseName + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+ @DatabaseName + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+ @DatabaseName + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID 
WHERE AJ.VDATE<='"+ @ToDate +"'   AND AJ.CMP_CODE=" + @Cmp_Code  +"  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
"
select  @SQL2="
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,(CASE WHEN TD.TRAN_DRCR = 'D' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, (CASE WHEN TD.TRAN_DRCR = 'C' THEN CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT 
,0 AS OPENINGBAL,'' AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DatabaseName + "TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+ @DatabaseName + "TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  AND JD.CMP_CODE= TM.CMP_CODE 
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+ @DatabaseName + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DatabaseName + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DatabaseName + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+ @DatabaseName + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE TM.CMP_CODE=" + @Cmp_Code  +" AND TM.TRAN_DATE<='"+ @ToDate +"'   AND TM.TRAN_TYPE  IN ('J','DN','CN') 
/*
AND GM.GRP_ID<>24

UNION ALL

SELECT GM.grp_Name AS GROUPNAME,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AMOUNT AS DRAMOUNT,0.00 AS CrAMOUNT
,LD.Lgr_Op_Bal AS OPENINGBAL,Lgr_Op_DrCr AS OPENINGDRCR
,OPG.Grp_Name AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.Grp_id AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DatabaseName + "VALUATIONENTRY VT
INNER JOIN "+ @DatabaseName + "LEDGER_MASTER LM ON VT.LGR_ID= LM.LGR_ID 
