*/
) AS DETAIL
GROUP BY GROUPNAME,PARTYNAME,CITY,OP_GROUP_NAME,GROUP_CODE,GRP_MAIN_ID,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE
,LGR_ID
) AS A
) AS A_DETAIL
) AS AA
"+@JOINSQL+"
ORDER BY PARTYNAME
 "
  end   

