DECLARE @SQL2 AS NVARCHAR(4000)
DECLARE @SELECTED AS NVARCHAR(1000)

SET @SQL=""
SET @SQL1=""
SET @SQL2=""
SET @SELECTED=""

BEGIN
SET NOCOUNT ON;

BEGIN       
IF @SELALL=0
SET @SELECTED="  INNER JOIN " + @TEMPTABLE + " ON A_DETAIL.MAIN_GROUP_CODE=" + @TEMPTABLE + ".CODE"
END

BEGIN
IF @OPENING_CLSOING=1 
SELECT @SQL="
SELECT GROUPNAME,PARTYNAME,CITY,CONVERT(NUMERIC(18,2),DRAMOUNT) AS DRAMOUNT,
CONVERT(NUMERIC(18,2),CRAMOUNT) AS CRAMOUNT,
OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN ISNULL(MAIN_GROUP_CODE,'')='' THEN MAIN_GROUP_CODE ELSE MAIN_GROUP_CODE END) AS MAIN_GROUP_CODE
,(CASE WHEN ISNULL(MAIN_GROUP,'')='' THEN GROUPNAME ELSE MAIN_GROUP END) AS MAIN_GROUP
FROM (
SELECT GROUPNAME,PARTYNAME,CITY,DRAMOUNT,CRAMOUNT,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN GRP_ACC_TYPE IN ('L') AND GRP_MAIN_ID IN (5,3,30,8,11,13)  AND (ABS(CRAMOUNT)-ABS(DRAMOUNT))<=0 THEN OP_GROUP_NAME 
WHEN GRP_ACC_TYPE IN ('A') AND GRP_MAIN_ID IN (4,1,29,7,9,10) AND (ABS(DRAMOUNT)-ABS(CRAMOUNT))<=0 THEN OP_GROUP_NAME ELSE  GROUPNAME END ) AS MAIN_GROUP
,(CASE WHEN GRP_ACC_TYPE IN ('L')AND GRP_MAIN_ID IN (5,3,30,8,11,13) AND (ABS(CRAMOUNT)-ABS(DRAMOUNT))<=0 THEN OP_GROUP_CODE 
WHEN GRP_ACC_TYPE IN ('A') AND GRP_MAIN_ID IN (4,1,29,7,9,10) AND (ABS(DRAMOUNT)-ABS(CRAMOUNT))<=0 THEN OP_GROUP_CODE ELSE  GROUP_CODE END ) AS MAIN_GROUP_CODE,GRP_MAIN_ID
FROM (
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT, 
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
FROM "+ @DATABASENAME + "LEDGER_DETAIL LD
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE LD.CMP_CODE =" + @CMP_CODE  +" 
) AS DETAIL
) AS A_DETAIL
"+ @SELECTED  + "
WHERE CONVERT(NUMERIC(18,2),DRAMOUNT) != 0 OR CONVERT(NUMERIC(18,2),CRAMOUNT) != 0
ORDER BY PARTYNAME "
END

BEGIN
IF @OPENING_CLSOING=2
SELECT  @SQL="
SELECT GROUPNAME,PARTYNAME,CITY,CONVERT(NUMERIC(18,2),DRAMOUNT) AS DRAMOUNT,
CONVERT(NUMERIC(18,2),CRAMOUNT) AS CRAMOUNT,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN ISNULL(MAIN_GROUP_CODE,'')='' THEN MAIN_GROUP_CODE ELSE MAIN_GROUP_CODE END) AS MAIN_GROUP_CODE
,(CASE WHEN ISNULL(MAIN_GROUP,'')='' THEN GROUPNAME ELSE MAIN_GROUP END) AS MAIN_GROUP
FROM (

SELECT GROUPNAME,PARTYNAME,CITY,DRAMOUNT,CRAMOUNT,OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE
,(CASE WHEN GRP_ACC_TYPE IN ('L') AND GRP_MAIN_ID IN (5,3,30,8,11,13)  AND (ABS(CRAMOUNT)-ABS(DRAMOUNT))<=0 THEN OP_GROUP_NAME 
WHEN GRP_ACC_TYPE IN ('A') AND GRP_MAIN_ID IN (4,1,29,7,9,10,26) AND (ABS(DRAMOUNT)-ABS(CRAMOUNT))<=0 THEN OP_GROUP_NAME ELSE  GROUPNAME END ) AS MAIN_GROUP
,(CASE WHEN GRP_ACC_TYPE IN ('L')AND GRP_MAIN_ID IN (5,3,30,8,11,13) AND (ABS(CRAMOUNT)-ABS(DRAMOUNT))<=0 THEN OP_GROUP_CODE 
WHEN GRP_ACC_TYPE IN ('A') AND GRP_MAIN_ID IN (4,1,29,7,9,10,26) AND (ABS(DRAMOUNT)-ABS(CRAMOUNT))<=0 THEN OP_GROUP_CODE ELSE  GROUP_CODE END ) AS MAIN_GROUP_CODE,GRP_MAIN_ID,LGR_ID
FROM (

SELECT GROUPNAME,PARTYNAME,CITY,
CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))>0 THEN  (SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END AS DRAMOUNT ,
CASE WHEN (SUM(DRAMOUNT)-SUM(CRAMOUNT))<0 THEN  (SUM(DRAMOUNT)-SUM(CRAMOUNT)) ELSE 0 END AS CRAMOUNT 
,OP_GROUP_NAME,GRP_ACC_TYPE,OP_GROUP_CODE,SUM(DRAMOUNT)A_DRAMOUNT,SUM(CRAMOUNT)A_CRAMOUNT,GROUP_CODE,GRP_MAIN_ID
,LGR_ID
FROM(

SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
CASE WHEN LD.LGR_OP_DRCR = 'D' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS DRAMOUNT, 
CASE WHEN LD.LGR_OP_DRCR = 'C' THEN LD.LGR_OP_BAL WHEN LD.LGR_OP_DRCR = '' THEN LD.LGR_OP_BAL ELSE 0 END AS CRAMOUNT
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DATABASENAME + "LEDGER_DETAIL LD
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON LM.LGR_ID=LD.LGR_ID 
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID 
WHERE LD.CMP_CODE =" + @CMP_CODE  +" 
/*
CHANGE FOR SHAILJA
10/OCT/2012 SANKET
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
(CASE WHEN TM.TRAN_DRCR = 'D' THEN  TM.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TM.TRAN_DRCR= 'C' THEN TM.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM1.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON TM.TRAN_MASTER_ID = LM1.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID  
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID  
WHERE TM.CMP_CODE =" + @CMP_CODE  +" AND TM.TRAN_TYPE NOT IN ('J','DN','DN') AND TM.TRAN_DATE<='"+ @TODATE +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL "
IF @OPENING_CLSOING=2
SELECT @SQL1="
SELECT GM.GRP_NAME AS GROUPNAME, LM1.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN  TD.TRAN_AMOUNT ELSE 0 END) AS DRAMOUNT ,
(CASE WHEN TD.TRAN_DRCR= 'C' THEN TD.TRAN_AMOUNT ELSE 0 END) AS CRAMOUNT
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM1.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TM.TRAN_ID= TD.TRAN_ID AND TM.TRAN_TYPE= TD.TRAN_TYPE AND TM.CMP_CODE= TD.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON TD.TRAN_DETAIL_ID= LM1.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM1.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM1.CITY_ID 
WHERE TM.CMP_CODE=" + @CMP_CODE  +" AND TM.TRAN_TYPE NOT IN('J','DN','CN') AND  TM.TRAN_DATE<='"+ @TODATE +"'  
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AJ.DRAMOUNT AS DRAMOUNT
,AJ.CRAMOUNT AS CRAMOUNT 
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DATABASENAME + "AUTOJOURNAL AJ 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON AJ.LGR_ID = LM.LGR_ID 
/*INNER JOIN "+ @DATABASENAME + "AUTOJOURNAL AJ1 ON AJ.CMP_CODE=AJ1.CMP_CODE AND AJ.ENTRYCODE=AJ1.ENTRYCODE AND AJ.ENTRYTYPE = AJ1.ENTRYTYPE  AND AJ.LGR_ID<> AJ1.LGR_ID AND AJ1.VCODE = AJ.VCODE AND AJ1.ENTRYMATCH = AJ.ENTRYMATCH
*/
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM1 ON AJ.LGR_ID= LM1.LGR_ID
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=AJ.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID  
WHERE AJ.VDATE<='"+ @TODATE +"'   AND AJ.CMP_CODE=" + @CMP_CODE  +"
/*
AND GM.GRP_ID<>24
*/
UNION ALL 
"
IF @OPENING_CLSOING=2

SELECT  @SQL2="
SELECT GM.GRP_NAME AS GROUPNAME, LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,
(CASE WHEN TD.TRAN_DRCR = 'D' THEN 
CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS DRAMOUNT, 
(CASE WHEN TD.TRAN_DRCR = 'C' THEN 
CASE WHEN TD.TRAN_AMOUNT < JD.TRAN_AMOUNT THEN TD.TRAN_AMOUNT ELSE JD.TRAN_AMOUNT END ELSE 0 END ) AS CRAMOUNT 
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DATABASENAME + "TRAN_MASTER TM 
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL TD ON TD.TRAN_ID= TM.TRAN_ID AND TD.TRAN_TYPE = TM.TRAN_TYPE AND TD.CMP_CODE= TM.CMP_CODE  
INNER JOIN "+ @DATABASENAME + "TRAN_DETAIL AS JD ON TD.TRAN_TYPE = JD.TRAN_TYPE AND TD.TRAN_ID= JD.TRAN_ID AND TD.TRAN_DETAIL_ID<> JD.TRAN_DETAIL_ID AND TD.TRAN_DRCR <> JD.TRAN_DRCR  AND JD.CMP_CODE= TM.CMP_CODE 
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON TD.TRAN_DETAIL_ID= LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=TM.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID     
WHERE TM.CMP_CODE=" + @CMP_CODE  +" AND TM.TRAN_DATE<='"+ @TODATE +"'   AND TM.TRAN_TYPE  IN ('J','DN','CN') 
/*
AND GM.GRP_ID<>24
CHANGE FOR SHAILJA
10/OCT/2012 SANKET
UNION ALL
SELECT GM.GRP_NAME AS GROUPNAME,LM.LGR_NAME AS PARTYNAME,CM.CITY_NAME AS CITY,AMOUNT AS DRAMOUNT,0.00 AS CRAMOUNT
,OPG.GRP_NAME AS OP_GROUP_NAME,GM.GRP_ACC_TYPE,OPG.GRP_ID AS OP_GROUP_CODE,GM.GRP_ID AS GROUP_CODE,GM.GRP_MAIN_ID
,LM.LGR_ID
FROM "+ @DATABASENAME + "VALUATIONENTRY VT
INNER JOIN "+ @DATABASENAME + "LEDGER_MASTER LM ON VT.LGR_ID= LM.LGR_ID 
INNER JOIN "+ @DATABASENAME + "LEDGER_DETAIL LD ON LM.LGR_ID=LD.LGR_ID AND LD.CMP_CODE=VT.CMP_CODE
INNER JOIN "+ @DATABASENAME + "GROUP_MASTER GM ON GM.GRP_ID=LD.GRP_ID
LEFT JOIN "+ @DATABASENAME + "CITY_MASTER CM ON CM.CITY_ID=LM.CITY_ID
LEFT JOIN "+ @DATABASENAME + "GROUP_MASTER OPG ON OPG.GRP_ID=GM.OP_GRP_MAIN_ID
WHERE VT.CMP_CODE=" + @CMP_CODE  +"  AND MONTH=MONTH('"+@TODATE+"')
*/
) AS DETAIL
GROUP BY GROUPNAME,PARTYNAME,CITY,OP_GROUP_NAME,GRP_ACC_TYPE,OP_GROUP_CODE,GROUP_CODE,GRP_MAIN_ID,LGR_ID
) AS A
) AS A_DETAIL
"+ @SELECTED  + "
GROUP BY GROUPNAME,PARTYNAME,CITY,CONVERT(NUMERIC(18,2),DRAMOUNT),MAIN_GROUP,
CONVERT(NUMERIC(18,2),CRAMOUNT),OP_GROUP_NAME,OP_GROUP_CODE,GRP_ACC_TYPE,GROUP_CODE,MAIN_GROUP_CODE,LGR_ID
HAVING CONVERT(NUMERIC(18,2),DRAMOUNT) <> 0 OR CONVERT(NUMERIC(18,2),CRAMOUNT) <> 0
ORDER BY PARTYNAME 
"
END   
END	
EXEC(@SQL+ @SQL1+@SQL2)
PRINT @SQL
PRINT @SQL1
PRINT @SQL2





















GO

/****** Object:  StoredProcedure [dbo].[PROC_USERREPORT]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER OFF
GO




















/*   --PROC_USERREPORT '2','ACC2010_2011.DBO.','01/APR/2010','01/APR/2010','ADMIN','LEDGER','ALL'*/
CREATE PROCEDURE [dbo].[PROC_USERREPORT]
(
  @CMP_CODE AS NVARCHAR(50),
  @DATABASENAME AS NVARCHAR(50),
  @FROMDATE AS NVARCHAR(20),
  @TODATE AS NVARCHAR(20),
  @USENAME AS NVARCHAR(100),
  @ENTRYTYPE AS  NVARCHAR(100),
  @ENTRYMODE AS  NVARCHAR(20)
)

AS

DECLARE @SQL AS NVARCHAR(4000)
DECLARE @CHKENTMODE AS NVARCHAR(500)
DECLARE @CHKENTTYPEMODE AS NVARCHAR(500)
DECLARE @CMPSEL AS NVARCHAR(500)
DECLARE @USERMODE AS NVARCHAR(500)

SET @CHKENTMODE =""
SET @CHKENTTYPEMODE =""
SET @CMPSEL =""
SET @USERMODE =""

BEGIN
IF @ENTRYMODE="ALL"
   SET @CHKENTMODE =""
ELSE
 SET @CHKENTMODE =" AND ENTRYMODE='"+@ENTRYMODE+"'"
END


BEGIN
IF @ENTRYTYPE="ALL"
   SET @CHKENTTYPEMODE =""
ELSE
 SET @CHKENTTYPEMODE =" AND ENTRYTYPE='"+@ENTRYTYPE+"'"
END

BEGIN
IF @USENAME="ALL"
   SET @USERMODE =""
ELSE
 SET @USERMODE ="  AND USER_NAME='"+@USENAME+"'"
END


BEGIN
IF @CMP_CODE="0"
   SET @CMPSEL =""
ELSE
 SET @CMPSEL =" AND  TT.CMP_CODE ="+@CMP_CODE
END


SET @SQL=""
BEGIN	 
  SET  @SQL="SELECT TT.*,CMP.CMP_ALIAS 
             FROM "+@DATABASENAME +"TRANSACTIONTABLE TT
             LEFT JOIN  "+@DATABASENAME +"COMPANY_MASTER CMP ON CMP.CMP_CODE=TT.CMP_CODE
             WHERE TT.COMPU_DATE BETWEEN '"+ @FROMDATE +"' AND '"+@TODATE +"'"+@CHKENTMODE + @CHKENTTYPEMODE
             +  @USERMODE + @CMPSEL +"
             
             "
            	
END
EXECUTE SP_EXECUTESQL @SQL
PRINT @SQL




















GO

/****** Object:  StoredProcedure [dbo].[sp_ScriptTable]    Script Date: 03/30/2023 12:08:15 ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO












CREATE PROCEDURE [dbo].[sp_ScriptTable]  
(  
    @TableName SYSNAME,  
    @IncludeConstraints BIT = 1,  
    @IncludeIndexes BIT = 1,  
    @NewTableName SYSNAME = NULL,  
    @UseSystemDataTypes BIT = 0  
)  
AS  
BEGIN   
    DECLARE @MainDefinition TABLE  
    (  
        FieldValue VARCHAR(200)  
    )  
    DECLARE @DBName SYSNAME  
    DECLARE @ClusteredPK BIT  
    DECLARE @TableSchema NVARCHAR(255)  
    SET @DBName = DB_NAME(DB_ID())  
    SELECT @TableName = name FROM sysobjects WHERE id = OBJECT_ID(@TableName)  
    DECLARE @ShowFields TABLE  
    (  
        FieldID INT IDENTITY(1,1),  
        DatabaseName VARCHAR(100),  
        TableOwner VARCHAR(100),  
        TableName VARCHAR(100),  
        FieldName VARCHAR(100),  
        ColumnPosition INT,  
        ColumnDefaultValue VARCHAR(100),  
        ColumnDefaultName VARCHAR(100),  
        IsNullable BIT,  
        DataType VARCHAR(100),  
        MaxLength INT,  
        NumericPrecision INT,  
        NumericScale INT,  
        DomainName VARCHAR(100),  
        FieldListingName VARCHAR(110),  
        FieldDefinition CHAR(1),  
        IdentityColumn BIT,  
        IdentitySeed INT,  
        IdentityIncrement INT,  
        IsCharColumn BIT  
    )  
    DECLARE @HoldingArea TABLE  
    (  
        FldID SMALLINT IDENTITY(1,1),  
        Flds VARCHAR(4000),  
        FldValue CHAR(1) DEFAULT(0)  
    )  
    DECLARE @PKObjectID TABLE  
    (  
        ObjectID INT  
    )  
    DECLARE @Uniques TABLE  
    (  
        ObjectID INT  
    )  
    DECLARE @HoldingAreaValues TABLE  
    (  
        FldID SMALLINT IDENTITY(1,1),  
        Flds VARCHAR(4000),  
        FldValue CHAR(1) DEFAULT(0)  
    )  
    DECLARE @Definition TABLE  
    (  
        DefinitionID SMALLINT IDENTITY(1,1),  
        FieldValue VARCHAR(200)  
    )  
    INSERT INTO @ShowFields  
    (         
        DatabaseName,  
        TableOwner,  
        TableName,  
        FieldName,  
        ColumnPosition,  
        ColumnDefaultValue,  
        ColumnDefaultName,  
        IsNullable,  
        DataType,  
        MaxLength,  
        NumericPrecision,  
        NumericScale,  
        DomainName,  
        FieldListingName,  
        FieldDefinition,  
        IdentityColumn,  
        IdentitySeed,  
        IdentityIncrement,  
        IsCharColumn  
    )  
    SELECT  
        DB_NAME(),  
        TABLE_SCHEMA,  
        TABLE_NAME,  
        COLUMN_NAME,  
        CAST(ORDINAL_POSITION AS INT),  
        COLUMN_DEFAULT,  
        dobj.name AS ColumnDefaultName,  
        CASE WHEN c.IS_NULLABLE = 'YES' THEN 1 ELSE 0 END,  
        DATA_TYPE,  
        CAST(CHARACTER_MAXIMUM_LENGTH AS INT),  
        CAST(NUMERIC_PRECISION AS INT),  
        CAST(NUMERIC_SCALE AS INT),  
        DOMAIN_NAME,  
        COLUMN_NAME + ',','' AS FieldDefinition,  
        CASE WHEN ic.object_id IS NULL THEN 0 ELSE 1 END AS IdentityColumn,  
        CAST(ISNULL(ic.seed_value,0) AS INT) AS IdentitySeed,  
        CAST(ISNULL(ic.increment_value,0) AS INT) AS IdentityIncrement,  
        CASE WHEN st.collation_name IS NOT NULL THEN 1 ELSE 0 END AS IsCharColumn  
    FROM  
        INFORMATION_SCHEMA.COLUMNS c  
        JOIN sys.columns sc ON  c.TABLE_NAME = OBJECT_NAME(sc.object_id) AND c.COLUMN_NAME = sc.Name  
        LEFT JOIN sys.identity_columns ic ON c.TABLE_NAME = OBJECT_NAME(ic.object_id) AND c.COLUMN_NAME = ic.Name  
        JOIN sys.types st ON COALESCE(c.DOMAIN_NAME,c.DATA_TYPE) = st.name  
        LEFT OUTER JOIN sys.objects dobj ON dobj.object_id = sc.default_object_id AND dobj.type = 'D'  
    WHERE c.TABLE_NAME = @TableName  
    ORDER BY  
        c.TABLE_NAME, c.ORDINAL_POSITION  
    SELECT TOP 1 @TableSchema = TableOwner  
    FROM @ShowFields  
    INSERT INTO @HoldingArea (Flds) VALUES('(')  
    INSERT INTO @Definition(FieldValue)  
    VALUES('ALTER TABLE ' + CASE WHEN @NewTableName IS NOT NULL THEN @NewTableName ELSE @DBName + '.' + @TableSchema + '.' + @TableName END)  
    INSERT INTO @Definition(FieldValue)  
    VALUES('(')  
    INSERT INTO @Definition(FieldValue)  
        SELECT  
           CHAR(10) + FieldName + ' ' +  
               CASE  
                   WHEN DomainName IS NOT NULL AND @UseSystemDataTypes = 0 THEN 
                        DomainName + CASE WHEN IsNullable = 1 THEN ' NULL ' ELSE ' NOT NULL ' END  
                   ELSE UPPER(DataType) +  
                      CASE WHEN IsCharColumn = 1 THEN '(' + CAST(MaxLength AS VARCHAR(10)) + ')' ELSE '' END +  
                      CASE WHEN IdentityColumn = 1 THEN 
                                ' IDENTITY(' + CAST(IdentitySeed AS VARCHAR(5))+ ',' + CAST(IdentityIncrement AS VARCHAR(5)) + ')' ELSE '' END +  
                      CASE WHEN IsNullable = 1 THEN ' NULL ' ELSE ' NOT NULL ' END +  
                      CASE WHEN ColumnDefaultName IS NOT NULL AND @IncludeConstraints = 1 THEN
                                'CONSTRAINT [' + ColumnDefaultName + '] DEFAULT' + UPPER(ColumnDefaultValue) ELSE '' END  
                   END +   
               CASE WHEN FieldID = (SELECT MAX(FieldID) FROM @ShowFields) THEN '' ELSE ',' END  
        FROM    @ShowFields   
        IF @IncludeConstraints = 1  
        BEGIN  
            INSERT INTO @Definition(FieldValue)  
            SELECT  
            ',CONSTRAINT [' + name + '] FOREIGN KEY (' + ParentColumns + ') REFERENCES [' + ReferencedObject + '](' + ReferencedColumns + ')'  
            FROM  
            (  
                SELECT  
                ReferencedObject = OBJECT_NAME(fk.referenced_object_id), ParentObject = OBJECT_NAME(parent_object_id),fk.name,  
                REVERSE(SUBSTRING(REVERSE((  
                SELECT cp.name + ','  
                FROM  
                sys.foreign_key_columns fkc  
                JOIN sys.columns cp ON fkc.parent_object_id = cp.object_id AND fkc.parent_column_id = cp.column_id  
                WHERE fkc.constraint_object_id = fk.object_id  
                FOR XML PATH('')  
                )), 2, 8000)) ParentColumns,  
                REVERSE(SUBSTRING(REVERSE((  
                SELECT cr.name + ','  
                FROM  
                sys.foreign_key_columns fkc  
                JOIN sys.columns cr ON fkc.referenced_object_id = cr.object_id AND fkc.referenced_column_id = cr.column_id  
                WHERE fkc.constraint_object_id = fk.object_id  
                FOR XML PATH('')  
                )), 2, 8000)) ReferencedColumns  
                FROM sys.foreign_keys fk  
            ) a  
            WHERE ParentObject = @TableName  
            INSERT INTO @Definition(FieldValue)  
            SELECT',CONSTRAINT [' + name + '] CHECK ' + definition FROM sys.check_constraints  
            WHERE OBJECT_NAME(parent_object_id) = @TableName  
        INSERT INTO @PKObjectID(ObjectID)  
        SELECT DISTINCT  
            PKObject = cco.object_id  
        FROM  
            sys.key_constraints cco  
            JOIN sys.index_columns cc ON cco.parent_object_id = cc.object_id AND cco.unique_index_id = cc.index_id  
            JOIN sys.indexes i ON cc.object_id = i.object_id AND cc.index_id = i.index_id  
        WHERE  
            OBJECT_NAME(parent_object_id) = @TableName    AND     
            i.type = 1 AND  
            is_primary_key = 1  
        INSERT INTO @Uniques(ObjectID)  
        SELECT DISTINCT  
            PKObject = cco.object_id  
        FROM  
            sys.key_constraints cco  
            JOIN sys.index_columns cc ON cco.parent_object_id = cc.object_id AND cco.unique_index_id = cc.index_id  
            JOIN sys.indexes i ON cc.object_id = i.object_id AND cc.index_id = i.index_id  
        WHERE  
            OBJECT_NAME(parent_object_id) = @TableName AND         
            i.type = 2 AND  
            is_primary_key = 0 AND  
            is_unique_constraint = 1   
        SET @ClusteredPK = CASE WHEN @@ROWCOUNT > 0 THEN 1 ELSE 0 END  
        INSERT INTO @Definition(FieldValue)  
        SELECT    ',CONSTRAINT ' + name + CASE type WHEN 'PK' THEN 
                  ' PRIMARY KEY ' + CASE WHEN pk.ObjectID IS NULL THEN ' NONCLUSTERED ' ELSE ' CLUSTERED ' END  
                            WHEN 'UQ' THEN ' UNIQUE ' END + CASE WHEN u.ObjectID IS NOT NULL THEN ' NONCLUSTERED ' ELSE '' END + '(' +  
        REVERSE(SUBSTRING(REVERSE((  
            SELECT  
                c.name +  + CASE WHEN cc.is_descending_key = 1 THEN ' DESC' ELSE ' ASC' END + ','  
            FROM  
                sys.key_constraints ccok  
                LEFT JOIN sys.index_columns cc ON ccok.parent_object_id = cc.object_id AND cco.unique_index_id = cc.index_id  
                LEFT JOIN sys.columns c ON cc.object_id = c.object_id AND cc.column_id = c.column_id  
                LEFT JOIN sys.indexes i ON cc.object_id = i.object_id AND cc.index_id = i.index_id  
            WHERE  
                i.object_id = ccok.parent_object_id AND  
                ccok.object_id = cco.object_id  
            FOR XML PATH('')  
        )), 2, 8000)) + ')'  
        FROM  
            sys.key_constraints cco  
            LEFT JOIN @PKObjectID pk ON cco.object_id = pk.ObjectID  
            LEFT JOIN @Uniques u ON cco.object_id = u.objectID  
        WHERE  
            OBJECT_NAME(cco.parent_object_id) = @TableName  
        END  
        INSERT INTO @Definition(FieldValue)  
        VALUES(')')  
        IF @IncludeIndexes = 1  
        BEGIN  
            INSERT INTO @Definition(FieldValue)  
            SELECT  
                'ALTER ' + type_desc + ' INDEX [' + [name] COLLATE SQL_Latin1_General_CP1_CI_AS + '] ON [' +  OBJECT_NAME(object_id) + '] (' +  
                REVERSE(SUBSTRING(REVERSE((  
                    SELECT name + CASE WHEN sc.is_descending_key = 1 THEN ' DESC' ELSE ' ASC' END + ','  
                    FROM  
                        sys.index_columns sc  
                        JOIN sys.columns c ON sc.object_id = c.object_id AND sc.column_id = c.column_id  
                    WHERE  
                        OBJECT_NAME(sc.object_id) = @TableName AND  
                        sc.object_id = i.object_id AND  
                        sc.index_id = i.index_id  
                    ORDER BY index_column_id ASC  
                    FOR XML PATH('')  
            )), 2, 8000)) + ')'  
            FROM sys.indexes i  
            WHERE  
                OBJECT_NAME(object_id) = @TableName  
                AND CASE WHEN @ClusteredPK = 1 AND is_primary_key = 1 AND type = 1 THEN 0 ELSE 1 END = 1  
                AND is_unique_constraint = 0  
                AND is_primary_key = 0  
        END  
            INSERT INTO @MainDefinition(FieldValue)  
            SELECT FieldValue FROM @Definition  
            ORDER BY DefinitionID ASC  
        SELECT * FROM @MainDefinition  
END      











GO


